-- =====================================================================
-- Step 1. organization
-- =====================================================================
INSERT INTO organization (identifier_value, name, type_code, active, created_at, updated_at)
VALUES ('BIZ-001', '해피너스병원', 'hospital', true, NOW(), NOW());


