-- ⭐ P001 (TKR) — 주요 투약 5건
INSERT INTO medication_administration (patient_id, encounter_id, practitioner_id, tagging_id,
  medication_order_id, medication_id, status,
  effective_datetime, nfc_tag_verified, created_at, updated_at)
SELECT
  (SELECT patient_id FROM patient WHERE identifier_value='P001'),
  (SELECT encounter_id FROM encounter e JOIN patient p ON e.patient_id=p.patient_id WHERE p.identifier_value='P001' LIMIT 1),
  (SELECT practitioner_id FROM practitioner WHERE employee_number='nur01'),
  'NFC-' || LPAD(mo.medication_order_id::text, 6, '0'), mo.medication_order_id, mo.medication_id, 'confirmed',
  mo.date_written + INTERVAL '30 minutes', true,
  NOW(), NOW()
FROM medication_order mo
WHERE mo.patient_id = (SELECT patient_id FROM patient WHERE identifier_value='P001')
  AND mo.medication_id IS NOT NULL
  AND mo.order_type = 'MEDICATION'
LIMIT 5;

