-- Step 15. notification (수간호사 admin에게 가는 알림)
--
-- 실제 스키마:
--   notification_id (PK, auto)
--   recipient_practitioner_id (NOT NULL)
--   source_type (NOT NULL) — self_report / iv_alert / timer / order_change / vital_alert / web_login / web_logout
--   title (NOT NULL), body, priority — CRITICAL/HIGH/MEDIUM/LOW
--   patient_id (nullable)
--   source_self_report_id (FK), source_iv_infusion_id (FK), source_stt_reminder_id (FK)
--   created_at (NOT NULL)
--
-- 'self_report' 알림 → source_self_report_id 채움
-- 'iv_alert' 알림 → source_iv_infusion_id 채움
-- 'order_change' 알림 → 모두 NULL (별도 FK 없음)
-- =====================================================================

-- ===== self_report 기반 알림 =====

-- P001 self_report 알림 (3건)
INSERT INTO notification (recipient_practitioner_id, source_type, title, body,
  patient_id, source_self_report_id, priority, created_at)
VALUES
  ((SELECT practitioner_id FROM practitioner WHERE employee_number='admin'),
   'self_report', '환자 증상 보고', '수술 부위가 너무 아파요. 참을 수가 없어요.',
   (SELECT patient_id FROM patient WHERE identifier_value='P001'),
   (SELECT self_report_id FROM patient_self_report psr JOIN patient p ON psr.patient_id=p.patient_id
    WHERE p.identifier_value='P001' ORDER BY psr.submitted_at LIMIT 1),
   'HIGH', '2026-05-16 16:00:00'),

  ((SELECT practitioner_id FROM practitioner WHERE employee_number='admin'),
   'self_report', '환자 증상 보고', '속이 울렁거리고 토할 것 같아요.',
   (SELECT patient_id FROM patient WHERE identifier_value='P001'),
   (SELECT self_report_id FROM patient_self_report psr JOIN patient p ON psr.patient_id=p.patient_id
    WHERE p.identifier_value='P001' ORDER BY psr.submitted_at OFFSET 1 LIMIT 1),
   'MEDIUM', '2026-05-16 19:00:00'),

  ((SELECT practitioner_id FROM practitioner WHERE employee_number='admin'),
   'self_report', '환자 증상 보고', '아침에 무릎이 좀 뻣뻣한데 정상인가요?',
   (SELECT patient_id FROM patient WHERE identifier_value='P001'),
   (SELECT self_report_id FROM patient_self_report psr JOIN patient p ON psr.patient_id=p.patient_id
    WHERE p.identifier_value='P001' ORDER BY psr.submitted_at DESC LIMIT 1),
   'LOW', '2026-05-22 07:30:00');


-- P002 호출 폭주 — 10건 전체 알림 (신호 테스트용)
INSERT INTO notification (recipient_practitioner_id, source_type, title, body,
  patient_id, source_self_report_id, priority, created_at)
SELECT
  (SELECT practitioner_id FROM practitioner WHERE employee_number='admin'),
  'self_report',
  '환자 증상 보고',
  psr.symptom_text,
  p.patient_id,
  psr.self_report_id,
  CASE
    WHEN psr.symptom_text LIKE '%아파%' OR psr.symptom_text LIKE '%못 참%' THEN 'HIGH'
    WHEN psr.symptom_text LIKE '%소변%' OR psr.symptom_text LIKE '%얼얼%' OR psr.symptom_text LIKE '%감각%' THEN 'HIGH'
    WHEN psr.symptom_text LIKE '%변비%' OR psr.symptom_text LIKE '%쥐%' THEN 'MEDIUM'
    ELSE 'LOW'
  END,
  psr.submitted_at
FROM patient_self_report psr
JOIN patient p ON psr.patient_id=p.patient_id
WHERE p.identifier_value='P002';


