INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', 'HIV 감염', 'hiv감염', 'CHECKUP', 'HIV 감염 여부는 혈액검사(항체검사)로 확인합니다. 성 접촉 후 2~4주 이후 보건소, 익명검진센터, 감염내과에서 무료 익명 검사를 받을 수 있습니다. 감염 직후에는 항체가 형성되지 않아 창문 기간(4~12주) 이후 재검사가 권장됩니다.', 1, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', 'HIV 감염', 'hiv감염', 'DIET_LIFE', '콘돔 사용 외에도 PrEP(노출 전 예방요법) 복용, 성 파트너 수 제한, 마약 주사 바늘 공유 금지, 정기적인 성병 검진이 효과적인 HIV 및 성병 예방 수단입니다.', 2, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', 'HIV 감염', 'hiv감염', 'MEDICATION', 'HIV 치료제(항레트로바이러스제)는 전문의약품으로 반드시 의사 처방이 필요하며 약국에서 일반 구매가 불가합니다. 노출 후 예방요법(PEP)은 응급 상황 시 72시간 내 감염내과·응급실에서 처방받을 수 있습니다.', 3, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', 'HIV 감염', 'hiv감염', 'PREVENTION', 'HIV는 감염된 사람의 혈액, 정액, 질 분비물, 모유를 통해 전파됩니다. 혈액 접촉(수혈, 주사 바늘 공유)으로도 감염될 수 있습니다. 그러나 악수, 대화, 식기 공유 등 일상 접촉으로는 전파되지 않으므로 함께 생활한다고 해서 감염되지 않습니다.', 4, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', 'HIV 감염', 'hiv감염', 'EXERCISE', '땀 자체는 HIV를 전파하지 않습니다. HIV는 혈액·정액·질 분비물·모유를 통해서만 전파되며 땀이나 피부 접촉만으로는 감염되지 않습니다. HIV 감염인도 건강 상태에 맞는 유산소·근력 운동이 권장되며 타인에게 감염 위험을 주지 않습니다.', 5, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', 'HIV 감염', 'hiv감염', 'CAUSE', 'HIV는 보호되지 않은 성관계, 감염된 혈액·주사 바늘 공유, 감염된 산모에서 아기로의 수직감염(임신·출산·모유 수유) 등으로 감염됩니다. 키스·악수·기침·음식 공유 등 일상 접촉으로는 전파되지 않습니다.', 6, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', 'HIV 감염', 'hiv감염', 'REHAB', 'HIV 감염인은 면역 저하로 합병증 위험이 높아 재활치료 시 주치의 평가가 필수입니다. 의사 소견서는 현재 면역 수치(CD4), 바이러스 수치, 복용 중인 항바이러스제 정보를 재활팀과 공유해 안전한 재활 프로그램을 설계하기 위해 필요합니다.', 7, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', 'HIV 감염', 'hiv감염', 'DEFINITION', 'HIV는 면역세포(CD4+ T세포)를 파괴해 면역력을 낮추는 바이러스입니다. 산모에서 아기로의 수직감염은 임신 중 태반 통과, 분만 시 혈액·분비물 접촉, 모유 수유를 통해 발생합니다. 항바이러스제 치료로 수직감염율을 1% 미만으로 낮출 수 있습니다.', 8, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', 'HIV 감염', 'hiv감염', 'SYMPTOM', 'HIV 감염 초기(2~4주)에는 발열, 두통, 피로감, 림프절 부종, 인후통, 근육통, 피부 발진 등 감기 유사 증상이 1~2주 지속됩니다. 이후 수년간 무증상 잠복기가 이어지며, 치료받지 않으면 AIDS로 진행됩니다.', 9, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', 'HIV 감염', 'hiv감염', 'DIAGNOSIS', 'HIV 감염 의심 시 보건소(무료 익명 검사), 대학병원·종합병원 감염내과, 에이즈 전문 진료기관에서 진단받을 수 있습니다. 피부 발진·발열·구토 증상이 있으면 즉시 방문하여 HIV 항체검사 및 PCR 검사를 받으시기 바랍니다.', 10, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', 'HIV 감염', 'hiv감염', 'TREATMENT', 'HIV 감염 치료는 감염내과 또는 HIV 전문 클리닉에서 받습니다. 주치의가 혈액검사(CD4 수치, 바이러스 수치)를 기반으로 항레트로바이러스요법(ART)을 처방하며, 꾸준히 치료받으면 바이러스 수치를 감지 불가 수준으로 유지할 수 있습니다.', 11, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '결핵', '결핵', 'CHECKUP', '결핵 검사는 보건소(무료)와 병원(흉부내과, 감염내과) 모두에서 받을 수 있습니다. 보건소는 흉부 X선 검사와 객담 검사를 무료로 제공하며, 결핵 확진 시 치료비도 지원됩니다. 증상이 심하거나 면역저하 상태라면 병원 전문의 진료를 권장합니다.', 12, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '결핵', '결핵', 'DIET_LIFE', '폐결핵 환자는 항결핵제 복용과 함께 고단백·고칼로리 식사(생선, 두부, 달걀, 살코기), 신선한 채소·과일 섭취, 금주·금연, 충분한 휴식이 필요합니다. 영양 결핍은 면역력을 떨어뜨려 치료 효과를 감소시키므로 균형 잡힌 식단 유지가 중요합니다.', 13, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '결핵', '결핵', 'MEDICATION', '결핵 치료에는 이소니아지드·리팜핀·에탐부톨·피라진아미드 4가지 항결핵제를 병용합니다. 초기 2개월 4제 병용 후 4개월 2제 유지하는 총 6개월 치료가 표준입니다. 증상이 좋아져도 약을 끊으면 내성결핵으로 발전할 수 있으므로 반드시 완료해야 합니다.', 14, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '결핵', '결핵', 'PREVENTION', '결핵 예방을 위해 BCG 예방접종(신생아), 환기가 잘 되는 실내 환경 유지, 기침 예절(마스크 착용), 면역력 강화(균형 잡힌 식사·규칙적 운동·금연·금주), 결핵 환자와 장기 접촉 후 잠복결핵 검사가 권장됩니다.', 15, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '결핵', '결핵', 'CAUSE', '결핵은 결핵균이 포함된 비말핵을 통해 공기로 전파됩니다. 활동성 폐결핵 환자의 기침·재채기 시 배출한 균을 밀폐 공간에서 흡입하면 감염됩니다. 악수·식기 공유·피부 접촉으로는 전파되지 않으며, 감염자 중 약 10%만 발병하고 나머지는 잠복결핵 상태로 지냅니다.', 16, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '결핵', '결핵', 'REHAB', '결핵 치료 후 재활에는 호흡 재활(횡격막 호흡, 흉곽 가동 운동), 유산소 운동(걷기, 수영)으로 폐 기능 회복, 영양 상태 개선, 금연, 정기적 폐 기능 검사가 포함됩니다. 폐 손상이 심한 경우 호흡기내과와 재활의학과 협진을 통한 체계적 재활이 도움됩니다.', 17, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '결핵', '결핵', 'DEFINITION', '결핵은 결핵균에 의한 만성 감염 질환으로 주로 폐를 침범합니다. 주요 증상은 2주 이상 지속되는 기침, 가래, 객혈, 발열, 야간 발한, 체중 감소, 피로감입니다. 흉통·호흡곤란이 있으면 흉부 X선, 객담 검사, 결핵균 배양 검사로 확진합니다.', 18, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '결핵', '결핵', 'SYMPTOM', '2주 이상 지속되는 기침, 가래, 체중 감소는 결핵의 대표적인 증상입니다. 구토와 설사는 결핵 자체보다 항결핵제 부작용으로 나타날 수 있습니다. 이러한 증상이 지속된다면 흉부 X선과 객담 검사를 통해 결핵 여부를 확인하는 것이 좋습니다.', 19, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '결핵', '결핵', 'DIAGNOSIS', '기관지 내시경 검사는 기침·객혈·X선 이상 소견 시 기관지·폐 병변을 직접 관찰하고 조직 검사·세균 배양 검체를 채취하는 방법입니다. 결핵 진단은 객담 도말·배양 검사가 우선이며, 객담 채취가 어렵거나 비전형적인 경우 기관지 내시경이 활용됩니다.', 20, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '결핵', '결핵', 'TREATMENT', '폐결핵의 표준 치료는 항결핵제 병용 요법입니다. 이소니아지드·리팜핀·에탐부톨·피라진아미드를 2개월 복용 후 이소니아지드·리팜핀을 4개월 더 복용하는 6개월 치료가 기본입니다. 내성결핵은 2차 약제를 사용하며 치료 기간이 18~24개월로 길어집니다.', 21, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '곰팡이 감염', '곰팡이감염', 'CHECKUP', '발바닥 가려움증과 각질은 무좀(발백선)을 의심할 수 있습니다. 피부과를 방문하여 피부 조각을 채취한 후 KOH 도말 검사(진균 검사)를 받으면 곰팡이 감염 여부를 확인할 수 있습니다. 자가 진단보다 정확한 진단 후 적절한 항진균제를 처방받는 것이 중요합니다.', 22, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '곰팡이 감염', '곰팡이감염', 'MEDICATION', '곰팡이 감염에는 국소 항진균제(클로트리마졸, 미코나졸 등)가 효과적입니다. 경미한 경우 약국에서 항진균 크림·연고를 구입할 수 있으며, 증상이 심하거나 넓게 퍼진 경우 피부과에서 경구 항진균제(플루코나졸, 이트라코나졸 등)를 처방받아야 합니다.', 23, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '곰팡이 감염', '곰팡이감염', 'PREVENTION', '습도가 높은 환경에서 곰팡이 감염을 예방하려면 몸을 청결히 하고 완전히 건조시키기, 통기성이 좋은 옷·신발 착용, 공용 시설 이용 후 발 씻기, 실내 습도 50% 이하 유지, 당뇨 등 기저질환 관리가 중요합니다.', 24, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '곰팡이 감염', '곰팡이감염', 'CAUSE', '꽉 끼는 신발 착용과 과도한 발 땀은 무좀의 주요 원인입니다. 추가 원인으로는 공용 목욕탕·수영장 이용, 면역력 저하(당뇨, 스테로이드 복용), 발을 오래 젖은 상태로 방치, 가족 중 무좀 환자와 수건·신발 공유 등이 있습니다.', 25, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '곰팡이 감염', '곰팡이감염', 'DEFINITION', '곰팡이 감염(진균증)은 진균이 피부, 손·발톱, 점막, 내부 장기 등에 침범하는 감염 질환입니다. 피부사상균, 칸디다, 아스페르길루스 등이 원인이며, 면역 저하 상태, 고온·다습한 환경, 장기간 항생제 복용 시 발생 위험이 높아집니다.', 26, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '곰팡이 감염', '곰팡이감염', 'SYMPTOM', '곰팡이 감염은 주로 피부, 손·발톱, 사타구니, 두피 등 국소 부위에 발생하지만, 면역이 저하된 환자에서는 혈류를 타고 전신으로 퍼지는 침습성 진균증이 발생할 수 있습니다. 건강한 성인에서는 대부분 국소 감염에 그치며 항진균제 치료로 호전됩니다.', 27, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '곰팡이 감염', '곰팡이감염', 'DIAGNOSIS', '피부에 딱지, 가려움증, 통증이 있는 경우 피부과 전문의를 방문하시기 바랍니다. KOH 도말 검사나 진균 배양 검사를 통해 곰팡이 감염 여부를 정확히 진단할 수 있습니다. 손·발톱 감염 의심 시 피부과, 전신 감염 의심 시에는 감염내과를 방문하세요.', 28, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '곰팡이 감염', '곰팡이감염', 'TREATMENT', '간지럽고 얼룩덜룩한 피부의 곰팡이 감염(어루러기, 백선)은 국소 항진균제(미코나졸, 클로트리마졸, 테르비나핀 크림)로 치료합니다. 2~4주 꾸준히 도포해야 하며, 범위가 넓거나 재발이 잦으면 피부과에서 경구 항진균제를 처방받는 것이 효과적입니다.', 29, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '광우병', '광우병', 'PREVENTION', '광우병 개인 예방을 위해 검역을 통과한 안전한 소고기만 구입, 뇌·척수 등 특정 위험 물질(SRM) 부위 섭취 피하기, 육류 완전히 익혀 섭취, 해외 여행 시 현지 소고기 제품 섭취 주의 등의 방법이 있습니다.', 30, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '광우병', '광우병', 'CAUSE', '광우병(BSE)은 변형 프리온 단백질이 소의 뇌에 축적되어 신경세포를 파괴하는 질환입니다. 주요 원인은 감염된 소의 뇌·척수를 포함한 육골분을 사료로 사용한 것이며, 인간이 감염된 소의 특정 부위를 섭취하면 변형 크로이츠펠트-야코프병(vCJD)으로 이어질 수 있습니다.', 31, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '광우병', '광우병', 'DEFINITION', '광우병은 주로 감염된 소의 뇌·척수·내장 등 특정 위험 물질(SRM)을 섭취할 때 전파됩니다. 소고기 외에도 감염 소의 젤라틴, 특정 의약품·화장품 성분을 통한 전파 가능성이 있습니다. 일반 근육육을 통한 감염 위험은 매우 낮습니다.', 32, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '광우병', '광우병', 'SYMPTOM', '변형 크로이츠펠트-야코프병(vCJD)의 잠복기는 수년~수십 년으로, 초기 증상은 우울·불안·행동 변화이며 이후 운동 실조·치매·근육 경련 등이 나타납니다. 진단은 MRI, 뇌척수액 검사, 뇌 조직 검사로 이루어지며 현재 치료법이 없습니다.', 33, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '광우병', '광우병', 'DIAGNOSIS', '광우병(vCJD) 의심 증상이 있다면 신경과가 있는 대학병원을 방문하시기 바랍니다. 도축업 종사자임을 의사에게 알리고, MRI·뇌척수액 검사·신경심리 검사를 통해 정밀 평가를 받으시기 바랍니다.', 34, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '광우병', '광우병', 'TREATMENT', '국내에서 광우병은 국내산 소에서 공식 발생 사례가 없으며 수입 소고기는 검역을 통해 관리됩니다. 광우병 의심 소 발생 시 즉각 격리·살처분, 역학조사, 해당 지역 소고기 유통 차단 등의 조치가 시행됩니다.', 35, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '구순염', '구순염', 'DIET_LIFE', '보습제 사용은 구순염 증상 완화에 도움이 됩니다. 바셀린, 쉐어버터, 비타민E 성분의 립밤이 효과적이며, 향료·색소가 포함된 제품은 자극을 줄 수 있으므로 성분이 단순한 제품을 선택하세요.', 36, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '구순염', '구순염', 'PREVENTION', '건조 계절 입술 트임 예방을 위해 순수 성분 립밤으로 보습 유지, 입술 핥는 습관 교정, 충분한 수분 섭취, 실내 가습기 사용, 비타민B2·B6·아연이 풍부한 식품(달걀, 견과류, 생선) 섭취가 도움됩니다.', 37, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '구순염', '구순염', 'CAUSE', '면역력 저하는 구순염의 주요 원인 중 하나입니다. 면역력이 떨어지면 헤르페스 바이러스 재활성화, 칸디다균 증식, 피부 장벽 기능 저하로 입술 주변에 염증이 발생할 수 있습니다. 스트레스, 피로, 영양 불균형도 관여합니다.', 38, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '구순염', '구순염', 'DEFINITION', '구순염은 입술에 주로 발생하지만, 입꼬리(구각염), 입 주변 피부, 구강 점막 내부에도 발생할 수 있습니다. 구각염은 입꼬리에 균열·딱지가 생기는 형태이며 칸디다 감염이나 영양 결핍(B2, B12, 철분)과 관련이 있습니다.', 39, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '구순염', '구순염', 'SYMPTOM', '구순염의 주요 증상으로 입술의 가려움증과 따가움, 붉어짐, 건조·균열, 각질, 부종 등이 있습니다. 가려움증이나 따가움이 느껴지면 입술을 핥거나 뜯지 말고 무향 보습제를 바르고, 증상이 지속되면 피부과 또는 구강내과를 방문하세요.', 40, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '구순염', '구순염', 'DIAGNOSIS', '구순염 진단은 피부과 또는 구강내과에서 받을 수 있습니다. 건강보험심사평가원 홈페이지나 포털 사이트에서 피부과 또는 구강내과를 검색하여 가까운 전문의를 찾을 수 있습니다.', 41, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '구순염', '구순염', 'TREATMENT', '구순염 치료는 원인에 따라 다릅니다. 건성 구순염은 보습제로 호전되고, 헤르페스성이면 항바이러스 연고, 습진성이면 스테로이드 연고, 칸디다성이면 항진균제를 사용합니다. 반복 재발 시 피부과에서 정확한 원인 파악이 필요합니다.', 42, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '구순포진', '구순포진', 'PREVENTION', '스트레스는 구순포진의 주요 유발 요인입니다. 예방을 위해 충분한 수면과 스트레스 관리, 면역력 강화(균형 잡힌 식단), 외출 시 자외선 차단 립밤 사용이 도움되며, 재발이 잦으면 항바이러스제 예방 복용을 의사와 상담하세요.', 43, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '구순포진', '구순포진', 'CAUSE', '구순포진은 헤르페스 단순 바이러스 1형(HSV-1)에 의해 발생합니다. 어린 시절 감염되어 신경절에 잠복하다가 면역력 저하·스트레스·피로·자외선 노출 시 재활성화됩니다. 간혹 HSV-2도 구순포진을 일으킬 수 있습니다.', 44, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '구순포진', '구순포진', 'DEFINITION', '구순포진은 HSV-1이 최초 감염 후 삼차신경절에 잠복하다가 면역 저하·스트레스·자외선·발열 등으로 재활성화되는 바이러스성 질환입니다. 재활성화 시 바이러스가 신경을 따라 입술 주변으로 이동해 물집과 통증을 유발하며, 치료해도 잠복 상태는 지속되어 재발이 가능합니다.', 45, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '구순포진', '구순포진', 'SYMPTOM', '구순포진의 물집은 전염성이 있습니다. 물집이 있는 동안 키스 금지, 수건·식기·립밤 공유 금지, 손 자주 씻기, 물집 만진 손으로 눈·생식기 만지지 않기가 중요합니다. 물집이 완전히 딱지로 덮일 때까지 전염 위험이 있습니다.', 46, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '구순포진', '구순포진', 'DIAGNOSIS', '바이러스 배양 검사는 물집 내 삼출물로 HSV를 직접 확인하고, 혈액 항체 검사(IgM·IgG)는 감염력과 이전 감염 여부를 확인합니다. 두 검사를 병행하면 현재 감염 여부, 감염 시기(초감염 vs 재활성화), 바이러스 유형(HSV-1/2)을 파악할 수 있습니다.', 47, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '구순포진', '구순포진', 'TREATMENT', '구순포진은 HSV-1 바이러스 원인으로 항바이러스제(아시클로버·발라시클로버)로 치료합니다. 구내염은 원인이 다양(아프타성·바이러스·세균·외상 등)하여 원인에 따라 스테로이드 연고, 항균 가글, 진통 성분 연고 등이 사용됩니다. 증상이 비슷해 보여도 원인이 다르므로 정확한 진단 후 치료가 중요합니다.', 48, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '뎅기열', '뎅기열', 'MEDICATION', '현재 뎅기열 예방 백신은 국내에서 일반적으로 접종되지 않습니다. 약물 예방보다 모기 차단이 핵심이며, 유행 지역 방문 시 DEET 성분 기피제, 긴 옷 착용, 모기장 사용이 필수입니다. 해열제는 아세트아미노펜만 사용하고 아스피린·이부프로펜은 출혈 위험으로 금기입니다.', 49, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '뎅기열', '뎅기열', 'PREVENTION', '뎅기열 예방을 위한 모기 차단 방법은 DEET 성분 모기 기피제 도포, 긴 소매·긴 바지 착용, 모기장 사용, 숙소 방충망 확인, 고인 물 제거입니다. 모기에 물린 후 2주 내 발열·심한 두통·관절통이 발생하면 즉시 의료기관을 방문하세요.', 50, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '뎅기열', '뎅기열', 'CAUSE', '뎅기 바이러스는 뎅기열(dengue fever), 중증 뎅기열(뎅기 출혈열 및 뎅기 쇼크 증후군) 등을 유발합니다. 뎅기 바이러스에는 1~4형의 혈청형이 있으며, 각 혈청형에 감염될 때마다 다른 형의 바이러스에 대한 면역이 생기지 않아 최대 4번 감염될 수 있습니다. 증상의 중증도는 초감염보다 재감염 시 더 심하게 나타날 수 있습니다.', 51, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '뎅기열', '뎅기열', 'DEFINITION', '뎅기열은 1~4형의 혈청형을 가진 뎅기 바이러스에 의해 발생하며, 모든 혈청형에서 공통적으로 고열, 두통, 근육통, 관절통, 발진 등이 나타납니다. 혈청형 간 증상의 차이는 뚜렷하지 않으나, 재감염 시(특히 2형 감염) 중증 뎅기열(출혈열, 쇼크 증후군)로 발전할 위험이 높습니다. 증상 발현 시 반드시 감염내과 전문의의 진료를 받으시기 바랍니다.', 52, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '뎅기열', '뎅기열', 'SYMPTOM', '뎅기열의 가장 심각한 원인 요소는 이집트숲모기(Aedes aegypti) 등 매개 모기의 서식 환경입니다. 열대·아열대 기후의 고온다습한 환경, 고인 물(폐타이어, 화분, 웅덩이 등)은 모기 번식을 촉진하며, 도시 집중화와 불충분한 위생 환경이 전파를 가속화합니다. 뎅기열 유행 지역 방문 시 모기 노출을 최소화하는 예방 조치가 필수적입니다.', 53, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '뎅기열', '뎅기열', 'DIAGNOSIS', '아프리카 여행 후 고열과 두통이 지속된다면 말라리아, 뎅기열, 장티푸스 등 열대 감염병을 감별해야 합니다. 감염내과 또는 여행의학 전문의를 찾아 혈액검사 및 관련 검사를 받으시기 바랍니다. 국가지정 입원치료병원이나 대학병원 감염내과에서 신속한 진단이 가능합니다.', 54, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '뎅기열', '뎅기열', 'TREATMENT', '동남아 여행 후 고열, 두통, 근육통이 나타난다면 뎅기열 가능성을 고려해야 합니다. 뎅기열 진단은 혈액검사를 통한 뎅기 NS1 항원검사, IgM/IgG 항체검사, RT-PCR 검사 등으로 이루어집니다. 증상 발현 즉시 감염내과 또는 응급실을 방문하여 전문의의 진료를 받으시기 바랍니다.', 55, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '디프테리아', '디프테리아', 'DIET_LIFE', '디프테리아 발생이 높은 국가들은 주로 백신 접종률이 낮은 개발도상국으로, 식습관보다는 위생 환경과 예방접종 체계가 더 중요한 요인입니다. 이들 국가에서는 영양 불균형, 열악한 위생 환경, 과밀 주거 환경 등이 감염 취약성을 높입니다. 해당 지역 방문 전 DTaP 또는 Td 백신 접종 여부를 확인하고 여행의학과 상담을 권장합니다.', 56, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '디프테리아', '디프테리아', 'MEDICATION', '디프테리아 치료에 페니실린과 에리스로마이신은 효과적이고 안전한 항생제로 사용됩니다. 페니실린은 디프테리아균(Corynebacterium diphtheriae)에 대한 1차 선택 항생제이며, 페니실린 알레르기 환자에게는 에리스로마이신을 대체 사용합니다. 다만 항생제만으로는 독소를 중화할 수 없어 항독소(antitoxin)와 병행 투여가 반드시 필요하므로 전문의 처방에 따라야 합니다.', 57, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '디프테리아', '디프테리아', 'PREVENTION', '디프테리아 예방을 위해 DTaP 백신(디프테리아·파상풍·백일해 혼합)을 생후 2, 4, 6개월에 기초접종 3회, 생후 15~18개월과 만 4~6세에 추가접종하여 총 5회 맞습니다. 한 번의 접종만으로는 충분한 면역이 유지되지 않으므로 반드시 권장 일정대로 완전 접종이 필요합니다. 성인도 10년마다 Td 또는 Tdap 추가접종이 권고됩니다.', 58, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '디프테리아', '디프테리아', 'CAUSE', '디프테리아는 비말 감염이 주요 전파 경로이지만 유일한 원인은 아닙니다. 감염자의 피부 병변과의 직접 접촉이나 오염된 물건을 통한 간접 접촉으로도 전파될 수 있습니다. 비말 차단만으로는 완전한 예방이 어려우므로, 예방접종 완료와 손 위생이 가장 효과적인 예방 방법입니다.', 59, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '디프테리아', '디프테리아', 'DEFINITION', '디프테리아는 인후통, 저급열, 인두·편도에 형성되는 회백색의 위막(pseudomembrane)이 특징적인 증상입니다. 일반 감기와 달리 위막을 억지로 제거하면 출혈이 생기고, 심한 경우 기도 폐쇄, 심근염, 신경마비가 올 수 있습니다. 의심 증상 시 인후 도말 배양검사를 포함한 검사를 위해 즉시 감염내과 또는 이비인후과를 방문하시기 바랍니다.', 60, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '디프테리아', '디프테리아', 'SYMPTOM', '디프테리아의 주요 증상은 발열, 인후통, 목 림프절 종창(''황소 목''), 그리고 인두·편도·코·후두 등에 생기는 회백색 위막 형성입니다. 위막이 기도를 막으면 호흡 곤란이 올 수 있으며, 심근염(부정맥, 심부전)이나 신경 합병증(연하 곤란, 안면 마비)도 나타날 수 있습니다. 구내염이나 식욕 저하만으로 디프테리아를 확진하기는 어려우므로 전문의 진료가 필요합니다.', 61, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '디프테리아', '디프테리아', 'DIAGNOSIS', '코 안에 백색 막이 생겼다면 비(鼻) 디프테리아 가능성을 배제할 수 없으므로, 즉시 가까운 종합병원 감염내과 또는 응급실을 방문하시기 바랍니다. 디프테리아는 제2급 법정 감염병으로, 의심 시 인후·비강 도말 배양검사 및 독소 검사로 진단합니다. 항독소 치료는 조기에 시작할수록 예후가 좋으므로 지체 없이 진료를 받으시기 바랍니다.', 62, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '디프테리아', '디프테리아', 'TREATMENT', '디프테리아는 중증 감염병으로 반드시 병원에 입원하여 치료해야 하며, 가정에서의 자가 치료는 불가능합니다. 치료는 항독소(antitoxin) 투여와 페니실린 또는 에리스로마이신 항생제 치료를 병행하며, 격리 입원이 필요합니다. 즉시 감염내과 전문의 또는 응급실을 방문하시기 바랍니다.', 63, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '라임병', '라임병', 'MEDICATION', '라임병 치료에는 독시사이클린(doxycycline), 아목시실린(amoxicillin), 세푸록심(cefuroxime) 등의 항생제가 1차적으로 사용됩니다. 중증 또는 신경계 침범 시에는 정맥 주사용 세프트리악손(ceftriaxone)이 사용됩니다. 할아버지의 구체적인 복용 약물은 담당 의사만 확인 가능하므로, 진료 기록 확인을 위해 담당 의사 또는 약사에게 문의하시기 바랍니다.', 64, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '라임병', '라임병', 'PREVENTION', '산행 시 진드기 예방을 위해 긴 소매와 긴 바지 착용, DEET 성분 기피제 사용, 밝은 색 옷 착용(진드기 발견 용이)이 효과적입니다. 귀가 후에는 몸 전체를 꼼꼼히 확인하고, 진드기 발견 시 핀셋으로 천천히 제거한 후 즉시 의료기관을 방문하는 것이 중요합니다. 풀밭에 직접 앉는 행위를 피하고, 등산로를 벗어나지 않는 것도 라임병 예방에 도움이 됩니다.', 65, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '라임병', '라임병', 'CAUSE', '라임병은 보렐리아(Borrelia burgdorferi) 세균에 감염된 참진드기(Ixodes 속)에 물려 발생하는 감염질환입니다. 감염된 진드기에 물린 후 수일~수주 내에 물린 부위를 중심으로 서서히 퍼지는 유주성 홍반(erythema migrans)이 나타나는 것이 특징적입니다. 이후 발열, 두통, 근육통이 동반될 수 있으며, 치료하지 않으면 심장, 신경계, 관절 합병증으로 진행할 수 있습니다.', 66, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '라임병', '라임병', 'DEFINITION', '벌초 후 진드기에 물린 자리에서 점차 퍼지는 큰 홍반이 생겼다면 라임병의 대표 증상인 유주성 홍반(erythema migrans)일 가능성이 있습니다. 유주성 홍반은 보통 진드기 물린 자리를 중심으로 5cm 이상 퍼지는 과녁 모양의 홍반으로, 수주에 걸쳐 확대됩니다. 즉시 피부과 또는 감염내과를 방문하여 혈청검사(ELISA, 웨스턴블롯) 등의 확인 검사를 받으시기 바랍니다.', 67, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '라임병', '라임병', 'SYMPTOM', '진드기에 물린 후 수일~수주 내에 물린 부위 주변으로 홍반이 퍼지면서 중앙이 옅어지는 과녁 모양(bull''s-eye rash)이 생길 수 있으며, 이는 라임병의 대표적 초기 증상입니다. 통증은 경미한 경우가 많으나 가려움이나 작열감이 동반될 수 있습니다. 이러한 증상이 나타나면 즉시 감염내과 또는 피부과 전문의를 방문하여 진단 및 항생제 치료를 받으시기 바랍니다.', 68, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '라임병', '라임병', 'DIAGNOSIS', '라임병의 피부 증상은 유주성 홍반으로, 진드기 물린 부위에서 시작해 점차 확대되는 원형 또는 타원형의 붉은 반점입니다. 가려움과 통증은 개인차가 있어 무증상부터 경도의 작열감, 가려움까지 다양하게 나타납니다. 피부 증상 외에 발열, 피로감, 근육통 등 전신 증상이 동반될 수 있으며, 정확한 진단을 위해 감염내과 또는 피부과 전문의 상담을 권장합니다.', 69, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '라임병', '라임병', 'TREATMENT', '라임병 치료에는 일반적으로 독시사이클린(doxycycline), 아목시실린(amoxicillin), 세푸록심 아세틸(cefuroxime axetil) 등의 경구 항생제가 2~4주간 사용됩니다. 신경계 또는 심장 침범 등 중증 라임병에는 세프트리악손(ceftriaxone) 정맥 투여를 2~4주간 시행합니다. 치료 기간과 약물 선택은 증상의 중증도와 감염 단계에 따라 달라지므로 감염내과 전문의의 처방을 따르시기 바랍니다.', 70, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '말라리아', '말라리아', 'MEDICATION', '말라리아 치료에는 클로로퀸(chloroquine), 아르테미시닌 병용요법(ACT), 아토바쿠온-프로구아닐(atovaquone-proguanil), 메플로퀸(mefloquine) 등이 사용됩니다. 열대열 말라리아(P. falciparum)에는 클로로퀸 내성이 흔하여 주로 ACT가 사용되며, 삼일열 말라리아(P. vivax)에는 클로로퀸과 재발 방지를 위한 프리마퀸(primaquine)이 병용됩니다. 약물 선택은 말라리아 종류와 지역적 내성 패턴에 따라 달라지므로 감염내과 전문의의 처방이 필요합니다.', 71, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '말라리아', '말라리아', 'PREVENTION', '말라리아 예방을 위해 위험 지역 여행 전부터 예방약(아토바쿠온-프로구아닐, 독시사이클린, 메플로퀸 등)을 복용할 수 있습니다. 또한 DEET 성분 모기 기피제 사용, 긴 소매·긴 바지 착용, 방충망 설치, 살충제 처리된 모기장 사용 등 모기 노출을 줄이는 방법이 효과적입니다. 예방약은 여행 전 여행의학과 또는 감염내과 전문의와 상담하여 처방받으시기 바랍니다.', 72, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '말라리아', '말라리아', 'CAUSE', '말라리아가 열대 지방에서 주로 발생하는 이유는 말라리아 매개 모기인 아노펠레스(Anopheles)가 고온다습한 환경에서 번식하기 때문입니다. 25~30도의 기온과 충분한 강수량은 모기의 생존과 번식을 촉진하고, 말라리아 원충의 모기 내 성숙 주기를 완성시킵니다. 아울러 열대 지방의 취약한 의료 인프라와 낮은 예방접종률도 유행에 기여합니다.', 73, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '말라리아', '말라리아', 'DEFINITION', '열대·아열대 지역 여행 후 발열, 오한, 두통, 근육통 등이 나타나면 말라리아를 포함한 열대 감염병을 우선적으로 의심해야 합니다. 말라리아는 증상이 비특이적이어서 독감과 혼동될 수 있으며, 열대열 말라리아의 경우 치료가 늦어지면 뇌말라리아, 다발성 장기 부전 등 치명적 합병증으로 이어질 수 있습니다. 귀국 후 즉시 감염내과를 방문하여 혈액 말라리아 도말 검사를 받으시기 바랍니다.', 74, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '말라리아', '말라리아', 'SYMPTOM', '말라리아로 인한 발열과 오한은 말라리아 원충의 적혈구 파괴 주기에 따라 주기적으로 나타나는 것이 특징입니다. 삼일열 말라리아는 48시간 주기, 사일열 말라리아는 72시간 주기로 고열과 오한이 반복됩니다. 이러한 증상이 있을 때는 감염내과 전문의와 상담이 필요하며, 열대 여행력이 있는 경우 응급 혈액 검사를 통해 신속하게 진단받아야 합니다.', 75, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '말라리아', '말라리아', 'DIAGNOSIS', '열대·아열대 지역 여행 후 말라리아 의심 증상(발열, 오한, 두통 등)이 나타나면 귀국 즉시 감염내과 또는 응급실을 방문하시기 바랍니다. 진단은 혈액 도말검사(thick/thin smear), 신속 항원검사(RDT), PCR 검사 등으로 이루어지며, 여행 지역과 증상 발현 시기에 대한 정보가 진단에 중요합니다. 증상 발현 후 빠른 시일 내에 검사를 받는 것이 예후에 중요합니다.', 76, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '말라리아', '말라리아', 'TREATMENT', '한 달 이상 지속되는 미열이나 간헐적 발열 등 말라리아 증상이 있다면 약물 치료가 기본이나, 충분한 수분 섭취와 해열제(아세트아미노펜 권장, 아스피린 금지) 복용으로 증상을 완화할 수 있습니다. 삼일열 말라리아의 경우 재발 방지를 위해 클로로퀸과 프리마퀸 병합 치료가 필요합니다. 장기간 증상이 지속되고 있으므로 반드시 감염내과 전문의를 방문하여 적절한 치료를 받으시기 바랍니다.', 77, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '매독', '매독', 'MEDICATION', '매독 치료의 1차 약물은 페니실린 G(benzathine penicillin G) 근육주사이며, 조기 매독에는 1회, 만기 잠복 매독에는 3주에 걸쳐 3회 투여합니다. 페니실린 알레르기가 있는 경우 독시사이클린(doxycycline)이나 테트라사이클린이 대체로 사용됩니다. 치료 후 1~2일 내에 발열, 오한, 두통 등 야리쉬-헤르크스하이머 반응이 일시적으로 나타날 수 있으므로 전문의와 상담이 필요합니다.', 78, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '매독', '매독', 'PREVENTION', '매독 등 성병 예방을 위해 콘돔을 올바르고 일관되게 사용하는 것이 가장 효과적인 방법입니다. 성 파트너 수를 줄이고, 정기적인 성병 검사를 받으며, 파트너와 함께 치료받는 것이 중요합니다. 의심 증상 발생 시 즉시 비뇨의학과, 피부과 또는 산부인과 전문의를 방문하여 조기에 진단과 치료를 받으시기 바랍니다.', 79, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '매독', '매독', 'CAUSE', '매독은 성별과 무관하게 Treponema pallidum 세균에 감염된 사람과의 성 접촉(구강, 질, 항문성교 포함)을 통해 전파되며, 건강 상태와 관계없이 누구나 감염될 수 있습니다. 감염자의 피부 병변이나 점막과 직접 접촉할 때 전파되므로, 남성 동성 간 성접촉도 주요 전파 경로 중 하나입니다. 성적으로 활발한 성인은 정기적인 성병 검사와 콘돔 사용이 권장됩니다.', 80, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '매독', '매독', 'DEFINITION', '매독은 Treponema pallidum이라는 나선균에 의한 성 매개 감염병으로, 1기(무통성 경결, 하감), 2기(전신 발진, 점막 병변), 잠복기, 3기(심혈관, 신경계 합병증) 순으로 진행합니다. 진단은 RPR, VDRL 등 비트레포네마 검사와 FTA-ABS, TPHA 등 트레포네마 검사를 통해 이루어집니다. 증상이 다양하고 무증상기가 길어 정기적인 검사가 중요하며, 의심 시 즉시 전문의를 방문하시기 바랍니다.', 81, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '매독', '매독', 'SYMPTOM', '매독 1기 증상은 감염 후 10~90일(평균 3주) 내에 감염 부위에 무통성 궤양(하감, chancre)이 생기는 것이며, 소변 시 통증은 매독보다 임질이나 클라미디아에서 더 흔합니다. 2기 매독에서는 손발바닥을 포함한 전신 발진, 점막 궤양, 탈모, 림프절 종창 등이 나타납니다. 성 접촉 후 이상 증상이 있으면 비뇨의학과, 피부과 또는 산부인과를 방문하여 성병 검사를 받으시기 바랍니다.', 82, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '매독', '매독', 'DIAGNOSIS', '성 접촉 후 생식기 부위의 가려움, 통증, 궤양 등 이상 증상이 있다면 매독, 임질, 클라미디아, 헤르페스 등 다양한 성병을 감별해야 합니다. 비뇨의학과, 피부과, 또는 산부인과(여성의 경우)를 방문하여 혈액검사(RPR, VDRL 등)와 도말검사, 배양검사 등을 통해 진단을 받으시기 바랍니다. 치료하지 않으면 만성화되어 중증 합병증으로 이어질 수 있으므로 조기 진단이 중요합니다.', 83, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '매독', '매독', 'TREATMENT', '매독의 치료 성공률은 1기와 2기에서는 페니실린 치료 후 95% 이상으로 매우 높습니다. 1기·2기 매독의 치료 기간은 보통 1~3주 이내이며, 잠복 매독이나 3기 매독은 치료 기간이 더 길어질 수 있습니다. 치료 후에도 추적 혈액검사(RPR 등)로 치료 반응을 확인해야 하며, 성 파트너도 함께 치료를 받는 것이 재감염 방지를 위해 중요합니다.', 84, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '반코마이신 내성 장알균 감염증', '반코마이신내성장알균감염증', 'PREVENTION', '반코마이신 내성 장알균(VRE) 감염증 환자는 1인실 격리 또는 코호트 격리가 필요하며, 의료진은 장갑과 가운을 착용하는 접촉주의 지침을 따라야 합니다. 환자와 접촉한 모든 물품과 환경 표면을 소독하고, 방문객도 격리 지침을 준수해야 합니다. 격리 해제는 적어도 1주일 이상의 간격으로 시행한 3회 이상의 배양검사에서 음성이 확인된 후 가능하며, 구체적인 지침은 담당 감염관리팀을 통해 확인하시기 바랍니다.', 85, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '반코마이신 내성 장알균 감염증', '반코마이신내성장알균감염증', 'CAUSE', '반코마이신 내성 장알균(VRE)은 장내에 정상적으로 존재하는 장알균(Enterococcus)이 반코마이신에 내성을 갖게 된 것으로, 건강한 사람에게는 대개 무증상입니다. 면역력이 저하된 환자에서는 발열, 오한, 요로 감염, 혈류 감염, 복막염 등을 일으킬 수 있습니다. 발열과 오한이 지속된다면 혈액배양검사 등을 위해 즉시 담당 의사와 상담하시기 바랍니다.', 86, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '반코마이신 내성 장알균 감염증', '반코마이신내성장알균감염증', 'DEFINITION', '반코마이신 내성 장알균(VRE) 감염증은 장알균이 반코마이신에 내성을 획득하여 발생하는 감염으로, 주로 면역력이 저하된 입원 환자에서 문제가 됩니다. 무증상 보균 상태로 지내는 경우가 많으나, 면역 저하 시 요로 감염, 혈류 감염(패혈증), 복막염, 심내막염 등 중증 합병증으로 발전할 수 있습니다. 치료에 사용할 수 있는 항생제가 제한적이어서 치료가 어려울 수 있습니다.', 87, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '반코마이신 내성 장알균 감염증', '반코마이신내성장알균감염증', 'SYMPTOM', '반코마이신 내성 장알균(VRE) 감염 의심 시 혈액배양검사, 소변배양검사, 상처 배양검사 등 감염 부위에 따른 배양검사가 필요합니다. 발열과 흉부 통증이 동반된다면 심내막염이나 폐렴 가능성도 배제하기 위해 심초음파, 흉부 X선, CT 등 영상 검사도 필요할 수 있습니다. 즉시 담당 의사 또는 감염내과 전문의와 상담하시기 바랍니다.', 88, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '반코마이신 내성 장알균 감염증', '반코마이신내성장알균감염증', 'DIAGNOSIS', 'VRE 감염증 진단을 위해서는 직장 도말 배양검사, 혈액배양검사, 소변배양검사 등 감염 부위에 따른 세균배양 및 항생제 감수성 검사가 필요합니다. 일반적으로 대학병원 또는 종합병원의 감염내과를 방문하여 진료를 받으시면 됩니다. 병원 감염 관련 문제이므로 입원 중이라면 담당 의사 또는 병원 감염관리실에 문의하시기 바랍니다.', 89, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '반코마이신 내성 장알균 감염증', '반코마이신내성장알균감염증', 'TREATMENT', 'VRE에 감수성 있는 항생제가 없는 경우 리네졸리드(linezolid), 다프토마이신(daptomycin), 티게사이클린(tigecycline) 등 VRE에 효과적인 대체 항생제가 사용될 수 있습니다. 이들 약제는 강력하지만 부작용이 있어 전문의의 면밀한 모니터링이 필요합니다. 약물 선택은 감수성 검사 결과와 감염 부위, 환자 상태에 따라 달라지므로 반드시 감염내과 전문의의 지시에 따라야 합니다.', 90, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '발진티푸스', '발진티푸스', 'DIET_LIFE', '발진티푸스 환자는 충분한 수분 보충(물, 이온음료, 맑은 국물 등)이 중요하며, 고단백·고칼로리의 균형 잡힌 식사를 통해 체력 회복을 돕는 것이 권장됩니다. 개인위생 철저히 유지하고 이(이, lice)가 서식하지 않도록 청결한 환경을 유지하는 것이 중요합니다. 발열 중에는 충분한 안정과 휴식을 취하고, 증상 변화 시 담당 의사와 즉시 상담하시기 바랍니다.', 91, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '발진티푸스', '발진티푸스', 'MEDICATION', '발진티푸스는 리케차(Rickettsia prowazekii) 감염으로, 독시사이클린(doxycycline)이 1차 치료제로 발열 소실 후 2~3일까지 투여하면 대부분 완치됩니다. 독시사이클린을 사용할 수 없는 경우(임산부, 어린이)에는 클로람페니콜이 대체 사용됩니다. 조기에 항생제를 시작하면 예후가 좋으며, 담당 감염내과 전문의의 처방에 따라 치료받으시기 바랍니다.', 92, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '발진티푸스', '발진티푸스', 'PREVENTION', '발진티푸스의 주된 감염 요인은 리케차(Rickettsia prowazekii)에 감염된 체이(body louse)에 물리거나, 이의 분변이 피부 상처를 통해 침투하는 것입니다. 개인위생 철저히 유지하고, 목욕 및 의복 세탁, 이를 제거하는 것이 가장 효과적인 예방 방법입니다. 위생 환경이 열악한 지역이나 밀집된 환경에서의 집단 감염에 주의해야 합니다.', 93, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '발진티푸스', '발진티푸스', 'CAUSE', '발진티푸스 환자의 혈액을 흡혈한 이(louse)는 내장에 리케차를 보유하게 되며, 이 이가 다른 사람을 물 때 분변을 피부에 남깁니다. 피부 상처나 긁힌 자리를 통해 이의 분변에 있는 리케차가 침투하여 감염이 이루어지며, 이의 분변을 직접 흡입하는 경우에도 전파가 가능합니다. 이(louse) 자체를 짓이기거나 비비는 행위도 감염 위험이 있으므로 주의가 필요합니다.', 94, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '발진티푸스', '발진티푸스', 'DEFINITION', '발진티푸스는 체이(body louse)를 통해 전파되는 리케차 감염병으로, 갑작스러운 고열(39~40도), 심한 두통, 오한, 근육통, 그리고 발병 후 4~6일째부터 몸통에서 시작하여 사지로 퍼지는 발진이 특징입니다. 두통, 오한, 발열만으로는 발진티푸스를 확정하기 어렵지만, 발진이 동반되고 위생 환경이 열악한 지역에서 생활했다면 가능성이 있습니다. 즉시 감염내과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 95, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '발진티푸스', '발진티푸스', 'SYMPTOM', '발진티푸스의 주요 증상은 갑작스러운 고열(39~40도)과 함께 심한 두통, 오한, 근육통이 나타나는 것입니다. 발병 4~6일 후 몸통에서 시작해 사지로 퍼지는 홍반성 발진이 특징적으로 나타나며, 메스꺼움, 구토, 기침, 결막 충혈도 동반될 수 있습니다. 치료하지 않으면 혼수, 신부전, 심근염 등 중증 합병증으로 이어질 수 있으므로 조기 전문의 진료가 필요합니다.', 96, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '발진티푸스', '발진티푸스', 'DIAGNOSIS', '이에 물린 후 전신 발진, 홍반, 점상 출혈이 생겼다면 발진티푸스 또는 다른 리케차 감염을 의심해야 합니다. 가까운 대학병원이나 종합병원의 감염내과를 즉시 방문하시기 바랍니다. 발진티푸스는 제3급 법정 감염병으로, 혈청검사(Weil-Felix 반응, 형광항체검사 등)로 진단하며 조기에 독시사이클린 치료를 시작하는 것이 중요합니다.', 97, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '발진티푸스', '발진티푸스', 'TREATMENT', '아프리카 여행 후 발진티푸스 진단을 받은 경우 독시사이클린(doxycycline)이 1차 치료제로 사용됩니다. 보통 발열이 소실된 후 2~3일까지 투여하며, 조기 치료 시 48~72시간 내에 급격한 증상 호전을 기대할 수 있습니다. 독시사이클린 사용이 어려운 경우 클로람페니콜이 대안으로 사용되며, 반드시 담당 감염내과 전문의의 처방에 따라 치료받으시기 바랍니다.', 98, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '불명열', '불명열', 'CAUSE', '불명열의 원인은 크게 감염(결핵, 심내막염, 복강 내 농양 등), 악성 종양(림프종, 백혈병 등), 자가면역 질환(류마티스 관절염, 루푸스, 성인 스틸병 등), 기타(약물 열, 혈전증 등)로 분류됩니다. 드물게 원인을 끝내 밝히지 못하는 경우도 있습니다. 장기간 발열이 지속될 경우 반드시 내과 또는 감염내과 전문의를 방문하여 체계적인 검사를 받으시기 바랍니다.', 99, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '불명열', '불명열', 'DEFINITION', '불명열은 38.3도 이상의 발열이 3주 이상 지속되고, 1주일간의 적절한 검사에도 원인이 밝혀지지 않는 경우를 말합니다. 생리 전 증후군에서도 체온이 약간 상승할 수 있으나, 불명열과는 구분됩니다. 피검사에서 염증 수치가 있다면 다른 원인 가능성을 배제하기 위해 내과 전문의를 방문하여 추가 정밀 검사를 받으시기 바랍니다.', 100, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '불명열', '불명열', 'SYMPTOM', '불명열에서 발열은 감염, 염증, 종양 등 다양한 원인에 의해 면역 세포에서 사이토카인(IL-1, IL-6, TNF 등)이 분비되고, 이것이 시상하부의 체온 조절 중추에 작용하여 프로스타글란딘 E2를 생성하면서 체온 설정점이 높아집니다. 이에 따라 오한, 근육 수축, 피부 혈관 수축 등으로 열 생산이 증가하고 열 소실이 감소하여 체온이 상승합니다. 불명열의 경우 원인 파악이 중요하므로 내과 또는 감염내과 전문의와 상담하시기 바랍니다.', 101, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '불명열', '불명열', 'DIAGNOSIS', '불명열 진단을 위해서는 상세한 병력 청취와 신체 검진 후, 혈액검사(CBC, ESR, CRP, 혈액배양, ANA, 종양 표지자 등), 소변검사, 흉부 X선, 복부 CT 또는 PET-CT 등 단계적 검사를 시행합니다. 체온이 39도 이상으로 지속된다면 먼저 내과 또는 감염내과 전문의를 방문하시기 바랍니다. 일반 진료 중 원인이 불명확하면 상급 종합병원으로 의뢰될 수 있습니다.', 102, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '불명열', '불명열', 'TREATMENT', '3주 이상 고열과 구토가 지속되는 경우 불명열의 원인으로 결핵, 심내막염, 복강 내 감염 등 감염성 질환, 림프종 등 혈액 종양, 자가면역 질환(루푸스, 성인 스틸병 등) 등을 고려해야 합니다. 치료는 원인 질환에 따라 달라지므로 원인 규명이 선행되어야 합니다. 즉시 내과 또는 감염내과 전문의를 방문하여 체계적인 진단 검사를 받으시기 바랍니다.', 103, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '성병', '성병', 'DIET_LIFE', '성병은 성 접촉을 통해 전파되는 감염병으로, 특정 파트너와의 성관계라도 파트너가 성병에 감염되어 있다면 감염될 수 있습니다. 성병 예방의 핵심은 파트너 수 제한보다 콘돔의 올바른 사용, 정기적인 성병 검사, 파트너와의 성병 상태 확인이 더 중요합니다. 성병이 의심되거나 노출된 경우 즉시 비뇨의학과, 산부인과 또는 성병 클리닉을 방문하시기 바랍니다.', 104, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '성병', '성병', 'PREVENTION', '일부 성병에 대해서는 예방접종이 가능합니다. 인유두종 바이러스(HPV)에 대한 가다실 등 HPV 백신과 B형 간염 백신이 대표적입니다. 성 접촉 후 성병 예방을 위해 콘돔을 항상 사용하고, 정기적인 성병 검사를 받으며, 이상 증상 발생 시 즉시 비뇨의학과, 산부인과 또는 감염내과 전문의를 방문하는 것이 중요합니다.', 105, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '성병', '성병', 'CAUSE', '성병의 주요 전파 경로는 질 성교, 구강 성교, 항문 성교 등 직접적인 성 접촉입니다. 일부 성병(HIV, 매독, B형 간염)은 혈액 접촉(오염된 주사기 공유), 수혈, 모자 수직 감염을 통해서도 전파됩니다. 위험 요인으로는 다수의 성 파트너, 콘돔 미사용, 음주·약물 상태에서의 성관계, 과거 성병 감염력 등이 있으며, 콘돔 사용과 정기 검진이 가장 효과적인 예방법입니다.', 106, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '성병', '성병', 'DEFINITION', '성병은 세균, 바이러스, 기생충 등 다양한 병원체에 의해 성 접촉으로 전파되는 감염병으로, 외음부 가려움, 분비물 증가, 이상한 냄새, 통증, 궤양 등이 주요 증상입니다. 질 분비물 증가와 악취는 세균성 질증, 트리코모나스증, 임질 등에서 흔히 나타납니다. 이러한 증상이 있다면 산부인과 또는 성병 클리닉에서 정확한 진단과 치료를 받으시기 바랍니다.', 107, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '성병', '성병', 'SYMPTOM', '성기 부위의 가려움, 따끔거림, 통증은 클라미디아, 임질, 헤르페스, 트리코모나스증, 칸디다 질염 등 성병 또는 비성병성 감염의 증상일 수 있습니다. 성접촉 경험이 있는 경우 성병 검사가 필요하며, 방치하면 만성 골반 염증 질환, 불임 등으로 이어질 수 있습니다. 즉시 비뇨의학과(남성) 또는 산부인과(여성)를 방문하여 정확한 진단을 받으시기 바랍니다.', 108, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '성병', '성병', 'DIAGNOSIS', '새로운 성 파트너와의 성관계는 상대방의 성병 감염 여부를 알 수 없어 감염 위험이 높아집니다. 특히 급성 질염이 있는 경우 점막 방어 기능이 약해져 성병 감염에 더 취약할 수 있습니다. 새로운 파트너와의 성관계 전 상호 성병 검사, 콘돔 사용, 그리고 의심 증상 발생 시 즉시 전문의 진료를 받는 것이 중요합니다.', 109, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '성병', '성병', 'TREATMENT', '성기 주변 가려움과 배뇨 통증 완화를 위해 원인에 따른 치료가 필요합니다. 클라미디아, 임질 등 세균성 성병에는 항생제가 사용되며, 헤르페스에는 항바이러스제, 칸디다 감염에는 항진균제가 처방됩니다. 자가 진단이나 자가 치료는 위험할 수 있으므로, 즉시 비뇨의학과(남성) 또는 산부인과(여성)를 방문하여 정확한 진단 후 치료를 받으시기 바랍니다.', 110, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '수두', '수두', 'PREVENTION', '수두 백신은 1세 이상 면역력이 없는 사람에게 1~2회 접종하며, 1회 접종 시 약 70~85%, 2회 접종 시 약 98%의 예방 효과를 보입니다. 백신은 약독화된 수두 바이러스를 이용해 면역 반응을 유도하여 항체를 형성시키므로, 이후 수두 바이러스에 노출되어도 발병을 예방하거나 증상을 경감시킵니다. 소아기에 2회 접종을 완료하는 것이 가장 효과적인 예방법입니다.', 111, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '수두', '수두', 'CAUSE', '라이 증후군(Reye syndrome)은 주로 바이러스 감염(특히 수두, 인플루엔자) 중 또는 회복기에 아스피린을 복용한 소아에서 발생하는 드문 질환입니다. 수두가 회복되는 시기에 갑작스러운 구토, 의식 변화, 간 기능 이상이 나타나면 라이 증후군 가능성을 고려해야 합니다. 바이러스 감염 중 소아에게 아스피린을 투여하지 않는 것이 라이 증후군 예방의 핵심이며, 의심 증상 시 즉시 응급실을 방문하시기 바랍니다.', 112, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '수두', '수두', 'DEFINITION', '수두는 수두-대상포진 바이러스(VZV)에 의한 고도 전염성 질환으로, 감염자의 기침·재채기·호흡(비말 및 공기 전파)을 통해 또는 수포 내용물과의 직접 접촉으로 감염됩니다. 면역력이 없는 사람은 환자와 같은 공간에 있거나 수포를 접촉한 경우 감염 위험이 높으며, 특히 임산부, 신생아, 면역 저하 환자에서 중증으로 진행할 수 있습니다. 예방을 위해 수두 백신 접종이 권장됩니다.', 113, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '수두', '수두', 'SYMPTOM', '수두와 두창(천연두)은 다른 바이러스에 의한 별개의 질환입니다. 수두는 수두-대상포진 바이러스(VZV, 헤르페스바이러스과)에 의해 발생하고, 두창은 천연두 바이러스(Variola virus, 폭스바이러스과)에 의해 발생합니다. 두창은 현재 전 세계적으로 박멸된 질병이며, 두 질병 모두 발진과 수포를 특징으로 하지만 두창은 훨씬 더 심각하고 치명률이 높았습니다.', 114, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '수두', '수두', 'DIAGNOSIS', '수두에 걸린 후 바이러스(VZV)는 신경절에 잠복하여 평생 체내에 존재합니다. 면역력이 저하되면(고령, 스트레스, 면역억제제 사용 등) 잠복해 있던 바이러스가 재활성화하여 대상포진으로 나타날 수 있습니다. 대상포진 의심 시 피부과 또는 내과 전문의를 방문하여 진단 및 항바이러스 치료를 받으시고, 50세 이상에서는 대상포진 예방백신 접종이 권장됩니다.', 115, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '수두', '수두', 'TREATMENT', '경증 수두는 가정에서 대증 치료가 가능하며, 충분한 수분 섭취, 휴식, 칼라민 로션 도포, 항히스타민제 복용으로 가려움증을 완화할 수 있습니다. 단, 수포를 긁지 않도록 손톱을 짧게 자르고 소독하는 것이 중요하며, 아스피린은 라이 증후군 위험으로 금기입니다. 면역 저하자, 임산부, 신생아, 성인이거나 증상이 중증인 경우에는 즉시 병원을 방문하여 전문의 처방에 따른 항바이러스제 치료를 받아야 합니다.', 116, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '수족구병', '수족구병', 'CHECKUP', '수족구병은 임상 증상(손, 발, 입안의 수포성 발진)으로 진단하는 경우가 많으며, 특별한 혈액검사 없이 진찰로 확진이 가능합니다. 중증이 의심되거나 원인 바이러스 확인이 필요한 경우 인후 도말·대변·수포액에서 바이러스 배양검사 또는 PCR 검사를 시행합니다. 증상이 있으면 소아과(소아의 경우) 또는 내과 전문의를 방문하여 진단과 치료를 받으시기 바랍니다.', 117, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '수족구병', '수족구병', 'DIET_LIFE', '어린이집에서의 수족구병 예방을 위해 손 씻기(비누로 20초 이상, 특히 기저귀 교환 후, 식사 전후), 장난감·시설물 정기적 소독, 감염 아동의 즉시 격리가 가장 중요합니다. 수족구병은 콕사키 바이러스 등 장바이러스를 통해 분변-구강 경로, 호흡기 비말, 접촉을 통해 전파되므로, 집단생활 환경에서 위생 관리가 감염 확산을 막는 핵심입니다. 증상이 완전히 사라지기 전까지 등원을 자제하는 것이 권장됩니다.', 118, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '수족구병', '수족구병', 'MEDICATION', '수족구병에는 특이적인 항바이러스제가 없으며, 증상 완화를 위한 대증 치료가 주를 이룹니다. 발열과 통증에는 아세트아미노펜 또는 이부프로펜(아스피린 금기)이 사용되며, 구내염으로 인한 식사 어려움 시에는 차가운 유동식이나 아이스크림이 도움됩니다. 현재 복용 중인 약물이 있다면 담당 의사와 상호 작용 여부를 상담하시고, 소아과 또는 내과 전문의의 지도에 따라 치료를 받으시기 바랍니다.', 119, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '수족구병', '수족구병', 'PREVENTION', '수족구병과 입이 헐고 먹기 불편한 증상은 직접적인 연관이 있습니다. 수족구병의 주요 증상 중 하나가 구내 수포와 궤양으로, 이로 인해 통증과 식욕 감소가 생깁니다. 입안이 헐어 영양 섭취가 줄면 면역력이 저하될 수 있어 다른 감염에 취약해질 수 있으나, 수족구병 자체가 직접 감기를 유발하지는 않습니다. 의심 증상 시 소아과 전문의 진료를 권장합니다.', 120, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '수족구병', '수족구병', 'CAUSE', '수족구병은 주로 콕사키 바이러스 A16형과 엔테로바이러스 71형 등 장바이러스에 의해 발생합니다. 전파 경로는 감염자의 대변-구강 경로(오염된 손, 물, 음식), 호흡기 비말, 수포 내용물과의 직접 접촉 등이 있습니다. 주로 5세 미만 영유아에서 호발하며, 감염 후 3~6일의 잠복기를 거쳐 발열, 구내 수포, 손발 발진이 나타납니다.', 121, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '수족구병', '수족구병', 'DEFINITION', '수족구병은 주로 영유아에서 발생하는 바이러스성 질환으로, 발열과 함께 입안(구강 점막, 혀, 잇몸)에 수포성 궤양, 손과 발(발바닥 포함)에 붉은 반점이나 수포가 나타나는 것이 특징입니다. 대부분 7~10일 내 자연 회복하지만, 드물게 엔테로바이러스 71형 감염 시 뇌수막염, 뇌염, 심근염 등 중증 합병증이 발생할 수 있습니다. 증상 발생 시 소아과 전문의 진료를 권장합니다.', 122, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '수족구병', '수족구병', 'SYMPTOM', '입안 수포와 손발의 부종은 수족구병의 전형적인 초기 증상입니다. 수족구병의 조기 발견을 위해서는 발열(38도 이상)과 함께 입안의 작은 빨간 반점이나 수포, 손발 또는 엉덩이에 붉은 반점이나 수포가 나타나는지 확인해야 합니다. 이러한 증상이 보이면 즉시 소아과 전문의를 방문하여 진단을 받고, 다른 아이들과의 접촉을 제한하여 전파를 예방하시기 바랍니다.', 123, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '수족구병', '수족구병', 'DIAGNOSIS', '수족구병 진단 시 피부 병변(손, 발, 엉덩이의 수포성 발진) 외에도 구강 내 수포와 궤양, 발열 여부, 연하 곤란, 식욕 감소 등을 함께 확인합니다. 중증 합병증(뇌수막염, 뇌염)이 의심될 경우에는 두통, 구토, 고열, 경련, 의식 변화, 사지 마비 등의 신경계 증상도 중요한 판단 기준이 됩니다. 모든 증상을 종합적으로 확인하여 소아과 전문의의 진단을 받으시기 바랍니다.', 124, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '수족구병', '수족구병', 'TREATMENT', '수족구병 치료는 소아과(소아의 경우) 또는 내과 전문의에게 받을 수 있으며, 대부분의 1·2차 의료기관(의원, 병원)에서 진료가 가능합니다. 특이 치료제는 없으며 대증 치료(해열제, 진통제, 수분 보충)가 주된 치료입니다. 경련, 고열 지속, 의식 저하 등 중증 증상이 있으면 즉시 응급실을 방문하시고, 건강보험심사평가원 병원 찾기(www.hira.or.kr) 또는 129(보건복지부 콜센터)를 통해 가까운 의료기관을 찾으실 수 있습니다.', 125, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '심내막염', '심내막염', 'CHECKUP', '심내막염이 의심된다면 먼저 순환기내과(심장내과) 전문의의 진료를 받아야 합니다. 정확한 진단을 위해 혈액배양검사(발열 시 시행), 심초음파(경흉부 또는 경식도), 혈액검사(CBC, CRP, ESR) 등이 필요합니다. 고열, 심잡음, 피로감 등 심내막염 의심 증상이 있으면 지체 없이 병원을 방문하시기 바랍니다.', 126, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '심내막염', '심내막염', 'PREVENTION', '심내막염 예방을 위해 심장 판막 질환이나 선천성 심장 질환 등 고위험군 환자는 치과 시술, 상기도 시술, 일부 소화기·비뇨기 시술 전에 예방적 항생제(아목시실린 등)를 투여할 수 있습니다. 구강 위생을 철저히 하고 정기적인 치과 검진을 받는 것이 중요하며, 피부 감염이나 정맥 주사 시 무균 술기를 준수해야 합니다. 심장 질환을 가진 분은 담당 심장내과 전문의와 예방적 항생제 사용 여부를 상담하시기 바랍니다.', 127, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '심내막염', '심내막염', 'CAUSE', '심내막염은 세균이나 진균 등 미생물이 혈류를 통해 심장 내막(특히 심장 판막)에 도달하여 증식하고 염증을 일으키는 질환입니다. 주로 치과 치료, 피부 감염, 정맥 주사 등으로 세균이 혈류에 유입되어 손상된 판막 또는 이물질(인공 판막, 심장 장치)에 부착하면서 감염이 시작됩니다. 황색포도알균(S. aureus), 연쇄상구균(Streptococcus) 등이 주요 원인균입니다.', 128, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '심내막염', '심내막염', 'DEFINITION', '심내막염에서 출혈성 피부 소견은 중요한 임상 징후입니다. 손·발가락 끝의 작은 적갈색 반점(Janeway lesion), 손발톱 아래의 선상 출혈(splinter hemorrhage), 손발가락 끝 통증성 결절(Osler node) 등이 나타날 수 있습니다. 이는 세균 색전(emboli)이나 면역 복합체 침착에 의한 혈관 손상으로 발생하며, 고열과 함께 이러한 소견이 있으면 즉시 심장내과 전문의 진료를 받으시기 바랍니다.', 129, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '심내막염', '심내막염', 'SYMPTOM', '심내막염에서 식욕 감퇴와 체중 감소는 전신적인 감염에 의한 사이토카인 분비로 인한 비특이적 증상입니다. 이러한 증상이 발열, 심잡음, 피로감 등과 함께 나타나면 심내막염을 포함한 만성 감염 또는 악성 종양을 의심할 수 있습니다. 심내막염 진단에서 식욕 부진과 체중 감소 자체는 특이적이지 않지만, 다른 임상 소견과 함께 종합적으로 판단되므로 전문의 진료가 필요합니다.', 130, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '심내막염', '심내막염', 'DIAGNOSIS', '발열, 부종(특히 발), 손발바닥의 빨간 반점(Janeway lesion, Osler node 등)은 심내막염의 특징적인 임상 소견입니다. 이러한 소견들은 심내막염의 진단 기준(Duke criteria)에 포함되는 중요한 임상 지표입니다. 이러한 증상이 동시에 나타난다면 즉시 심장내과(순환기내과)를 방문하여 혈액배양검사와 심초음파를 포함한 정밀 검사를 받으시기 바랍니다.', 131, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '심내막염', '심내막염', 'TREATMENT', '심내막염의 치료는 원인균에 따른 장기간(4~6주) 항생제 정맥 투여가 기본입니다. 황색포도알균 심내막염에는 반코마이신 또는 나프실린이, 연쇄상구균에는 페니실린이 사용됩니다. 판막 파괴, 난치성 감염, 색전증 재발 등의 경우에는 수술적 치료(판막 수리 또는 교체)가 필요할 수 있으며, 고위험군의 경우 예방적 항생제와 구강 위생 관리가 예방의 핵심입니다.', 132, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '요충증', '요충증', 'DIET_LIFE', '요충증 환자가 있는 가족은 모든 가족이 동시에 구충제를 복용하는 것이 권장됩니다. 매일 아침 샤워를 통해 항문 주위의 알을 제거하고, 속옷과 침구를 자주 세탁(뜨거운 물 사용)해야 합니다. 손 씻기를 철저히 하고 손톱을 짧게 자르며, 항문을 긁지 않도록 주의하고 음식은 항상 씻어서 섭취하는 것이 전파 예방에 중요합니다.', 133, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '요충증', '요충증', 'MEDICATION', '요충증 치료에는 피란텔 파모에이트(pyrantel pamoate) 또는 알벤다졸(albendazole), 메벤다졸(mebendazole) 등의 구충제가 사용됩니다. 재감염이 흔하므로 2주 후 1회 추가 복용을 권장하며, 가족 모두가 동시에 복용하는 것이 효과적입니다. 영유아, 임산부, 수유부, 다른 약물을 복용 중인 환자는 반드시 소아과 또는 내과 전문의와 상담 후 적절한 약물과 용량을 처방받으시기 바랍니다.', 134, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '요충증', '요충증', 'PREVENTION', '개인위생 유지는 요충증 예방에 매우 중요한 역할을 합니다. 요충의 알은 손, 음식, 먼지 등을 통해 구강으로 들어오므로, 식사 전·화장실 사용 후 손 씻기, 손톱 아래 위생 관리, 음식 씻어 먹기 등이 감염 예방에 효과적입니다. 또한 속옷과 침구의 정기적 세탁, 환기와 청소를 통해 환경 내 알의 수를 줄이는 것도 중요합니다.', 135, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '요충증', '요충증', 'CAUSE', '요충증은 요충(Enterobius vermicularis) 알이 오염된 손, 음식, 물건 등을 통해 입으로 들어가 소장에서 부화하여 대장에 기생하는 감염입니다. 항문 주위 가려움증은 암컷 요충이 야간에 항문 주위에 알을 낳으면서 발생하는 것이 특징입니다. 집단 생활, 개인위생 불량, 손톱 아래 알 오염, 침구나 의류를 통한 간접 전파 등이 주요 원인이며, 내과 또는 가정의학과 전문의 진료를 권장합니다.', 136, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '요충증', '요충증', 'DEFINITION', '요충증의 초기 증상은 주로 야간 항문 가려움증(소양증)이며, 이는 요충 암컷이 밤에 항문 주위에 알을 낳으면서 발생합니다. 심한 가려움으로 인한 수면 장애, 흥분, 불안이 나타날 수 있으며, 긁은 자리에 2차 세균 감염이 생길 수 있습니다. 여아에서는 요충이 외음부로 이동하여 외음질염을 일으킬 수 있고, 드물게 복통, 식욕 부진, 오심이 동반되기도 합니다.', 137, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '요충증', '요충증', 'SYMPTOM', '요충증의 항문 주위 가려움증은 요충 암컷이 야간에 항문 밖으로 나와 알을 낳을 때 분비하는 점액 물질 때문에 발생하므로, 주로 수면 중 또는 이른 아침에 심합니다. 배변 시 통증이 심하게 동반되는 경우는 드물지만, 심한 소양증으로 긁어 피부가 손상되면 통증이 발생할 수 있습니다. 항문 가려움증이 지속된다면 내과 또는 소아과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 138, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '요충증', '요충증', 'DIAGNOSIS', '의사에게 항문 가려움증의 발생 시기(특히 야간 여부), 가려움의 특성, 항문 주위에서 작은 실 같은 벌레를 육안으로 보았는지 여부, 가족 중 같은 증상이 있는 사람이 있는지, 손 씻기 등 위생 습관, 집단생활 여부 등을 알려주어야 합니다. 진단은 투명 셀로판 테이프를 아침에 일어나자마자 항문 주위에 붙인 후 현미경으로 요충 알을 확인하는 방법(테이프 검사법)으로 이루어집니다.', 139, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '요충증', '요충증', 'TREATMENT', '대부분의 감염내과, 소아과, 내과, 가정의학과 전문의들은 요충증 환자가 있는 경우 가족 전체를 동시에 치료할 것을 권고합니다. 이는 요충이 가족 내에서 재감염이 쉽게 일어나기 때문이며, 한 명만 치료해서는 치료 효과가 지속되기 어렵습니다. 가족 중 임산부, 수유부, 영유아가 있을 경우 안전한 약물 선택을 위해 전문의와 상담하시기 바랍니다.', 140, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '인유두종 바이러스 감염증', '인유두종바이러스감염증', 'DIET_LIFE', '인유두종 바이러스(HPV) 감염증은 주로 성 접촉을 통해 전파되므로, 성적으로 활발한 성인의 경우 일생 중 감염될 가능성이 매우 높습니다. 면역력이 건강한 경우 대부분 자연 소멸되지만, 고위험형 HPV(16, 18형 등)가 지속 감염되면 자궁경부암 등 암으로 발전할 수 있습니다. HPV 백신 미접종자, 다수의 성 파트너, 면역력 저하 시 감염 및 지속 감염 위험이 높아집니다.', 141, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '인유두종 바이러스 감염증', '인유두종바이러스감염증', 'PREVENTION', '인유두종 바이러스(HPV) 예방을 위한 백신으로는 2가(서바릭스), 4가(가다실4), 9가(가다실9) 백신이 있습니다. 국내에서는 만 12세 여학생에게 9가 또는 4가 HPV 백신이 국가 예방접종으로 지원되며, 남성에게도 접종이 권장됩니다. 성 경험 전에 접종하는 것이 가장 효과적이나, 성 경험 후에도 접종이 가능하므로 산부인과 또는 가정의학과 전문의와 상담하시기 바랍니다.', 142, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '인유두종 바이러스 감염증', '인유두종바이러스감염증', 'CAUSE', '인유두종 바이러스(HPV) 감염증은 HPV 바이러스가 성 접촉(피부 또는 점막 접촉)을 통해 전파되어 발생합니다. HPV가 자궁경부, 외음부, 항문, 구강 인두 등의 상피 세포에 침투하여 세포 내 DNA에 통합되면, 바이러스 단백질(E6, E7)이 세포 주기 조절 단백질을 억제하여 세포 증식이 비정상적으로 일어나면서 사마귀나 암으로 발전할 수 있습니다.', 143, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '인유두종 바이러스 감염증', '인유두종바이러스감염증', 'REHAB', '인유두종 바이러스(HPV) 감염증은 주로 피부 또는 생식기 병변이 나타나는 질환으로, 신경계 기능 장애를 직접적으로 유발하지 않아 신경학적 재활이 필요한 경우는 거의 없습니다. HPV 감염 후 자궁경부암, 항문암, 두경부암 등으로 진행하여 암 치료 후 재활이 필요할 수 있으나, 이는 암 치료 후의 재활 문제입니다. 구체적인 재활 필요성에 대해서는 담당 전문의와 상담하시기 바랍니다.', 144, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '인유두종 바이러스 감염증', '인유두종바이러스감염증', 'DEFINITION', '인유두종 바이러스(HPV)는 주로 감염된 사람과의 성 접촉(질, 구강, 항문)을 통해 전파되며, 생식기 점막이나 피부의 미세한 상처를 통해 바이러스가 침투합니다. 자궁경부암의 99% 이상이 HPV 감염(특히 16, 18형)과 관련이 있으며, 여성은 주기적인 자궁경부 세포 검사(팹 스미어)와 HPV 백신 접종을 통해 자궁경부암을 예방할 수 있습니다.', 145, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '인유두종 바이러스 감염증', '인유두종바이러스감염증', 'SYMPTOM', 'HPV 감염으로 인한 생식기 사마귀(첨형 콘딜로마) 외에도 편평 사마귀, 항문 주위 사마귀 등이 나타날 수 있으며, 고위험형 HPV 지속 감염 시 자궁경부, 질, 외음부, 항문, 음경, 구강 인두 등에 이형성증(전암 병변)이 생길 수 있습니다. 대부분 무증상이지만 사마귀 부위에 가려움, 출혈, 불쾌감이 동반될 수 있습니다. 정확한 확인을 위해 산부인과 또는 비뇨의학과 전문의의 진료를 받으시기 바랍니다.', 146, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '인유두종 바이러스 감염증', '인유두종바이러스감염증', 'DIAGNOSIS', '성 접촉 후 생식기에 사마귀가 생겼다면, 여성의 경우 산부인과, 남성의 경우 비뇨의학과 또는 피부과 전문의를 방문하시기 바랍니다. HPV 감염 확인을 위해 육안 관찰, 아세토백 반응 검사, HPV DNA 검사(여성의 경우 자궁경부 세포검사와 병행) 등을 시행할 수 있습니다. 조기에 전문의를 찾아 치료와 함께 정기적인 추적 관찰을 받는 것이 중요합니다.', 147, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '인유두종 바이러스 감염증', '인유두종바이러스감염증', 'TREATMENT', 'HPV 감염 자체에 대한 항바이러스제나 항생제는 존재하지 않습니다. 생식기 사마귀 치료에는 국소 도포제(포도필로톡신, 이미퀴모드, 삼염화아세트산), 냉동 요법, 레이저 치료, 전기 소작술 등이 사용됩니다. 자궁경부 이형성증의 경우 단순 관찰부터 루프 전기 소작 절제술(LEEP), 원추형 절제술 등 단계에 따른 치료가 이루어지며, 산부인과 또는 비뇨의학과 전문의의 처방에 따라 치료를 받으시기 바랍니다.', 148, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '일본 뇌염', '일본뇌염', 'MEDICATION', '일본 뇌염은 특이적 항바이러스제가 없어 주로 증상에 따른 지지 치료가 이루어집니다. 수액 치료는 탈수 교정, 뇌부종 관리, 전해질 균형 유지를 위해 시행되며, 이는 발열 조절, 항경련제 투여, 인공호흡기 치료 등 다른 지지 요법과 병행하여 환자의 전신 상태를 안정시키는 데 목적이 있습니다. 수액 단독으로 치료 효과를 기대하기보다 종합적인 집중 치료의 일부로 이해하시면 됩니다.', 149, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '일본 뇌염', '일본뇌염', 'PREVENTION', '일본 뇌염 예방을 위해 불활성화 백신(사노피 JE-VC)과 약독화 생백신(녹십자 CD.JEVAX) 두 종류가 사용됩니다. 국가 예방접종으로 생후 12개월부터 시작하여 권장 일정에 따라 총 4~5회 접종합니다. 백신 접종 외에도 모기에 물리지 않도록 기피제 사용, 긴 옷 착용, 야간 외출 자제, 방충망 사용 등의 모기 예방 조치를 병행하는 것이 효과적이며, 자세한 접종 일정은 소아과 전문의와 상담하시기 바랍니다.', 150, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '일본 뇌염', '일본뇌염', 'CAUSE', '일본 뇌염은 일본 뇌염 바이러스(JEV)를 보유한 작은빨간집모기(Culex tritaeniorhynchus)에 물렸을 때 바이러스가 혈액 내로 유입되어 발생합니다. 바이러스는 혈액-뇌 장벽을 통과해 중추신경계를 침범하며, 감염자의 약 1%에서만 뇌염으로 진행됩니다. 모기에 물린 후 5~15일의 잠복기를 거쳐 증상이 나타나며, 사람 간 직접 전파는 되지 않습니다.', 151, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '일본 뇌염', '일본뇌염', 'DEFINITION', '일본 뇌염은 일본 뇌염 바이러스를 보유한 모기가 감염된 돼지 등 동물의 피를 빤 후 사람을 물 때 전파됩니다. 사람-사람 간 직접 전파는 일어나지 않으며, 모기에 물려도 대부분(99%)은 무증상이거나 경미한 증상에 그칩니다. 바이러스가 중추신경계를 침범할 경우에만 뇌염으로 진행되며, 이는 소수에서만 발생합니다.', 152, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '일본 뇌염', '일본뇌염', 'SYMPTOM', '일본 뇌염의 주요 증상은 갑작스러운 고열(39~40°C), 두통, 구토, 의식장애, 경련으로 나타나며 가려움증은 일본 뇌염의 특징적 증상이 아닙니다. 초기에는 발열, 두통, 오한이 나타나고 이후 의식 혼탁, 혼수, 근육 강직, 경련 등 신경학적 증상이 동반될 수 있습니다. 증상이 의심될 경우 즉시 전문의 진료를 받으시기 바랍니다.', 153, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '일본 뇌염', '일본뇌염', 'DIAGNOSIS', '두통, 발열, 구토 증상이 동시에 나타날 경우 일본 뇌염을 포함한 뇌수막염 등 중추신경계 감염을 의심해볼 수 있으며, 신경과 또는 감염내과 전문의를 즉시 방문하는 것이 좋습니다. 소아의 경우 소아청소년과에서 초기 진료 후 신경과로 의뢰될 수 있습니다. 증상이 갑자기 발생했거나 의식 변화가 동반된다면 응급실 방문을 권장합니다.', 154, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '일본 뇌염', '일본뇌염', 'TREATMENT', '일본 뇌염은 현재 특이적 항바이러스제가 없어 증상 완화를 위한 대증 치료가 중심입니다. 고열에는 해열제, 경련에는 항경련제를 사용하며, 뇌부종 조절을 위한 삼투압 이뇨제 투여와 집중 치료실에서의 호흡 및 활력징후 모니터링이 필요합니다. 구체적인 치료 계획은 반드시 신경과 또는 감염내과 전문의와 상의하시기 바랍니다.', 155, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '임파선염', '임파선염', 'CHECKUP', '목에 멍울이 생기고 누를 때 통증이 있는 것은 임파선염(림프절염)의 전형적인 증상일 수 있습니다. 이비인후과 방문이 적절하며, 특히 목 부위 림프절 이상은 상기도 감염, 편도염 등과 관련이 깊어 이비인후과에서 원인 감별 및 검진이 가능합니다. 증상이 2주 이상 지속되거나 크기가 커진다면 빠른 진료를 권장합니다.', 156, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '임파선염', '임파선염', 'DIET_LIFE', '임파선염 회복 후에도 올바른 식습관과 생활 습관을 유지하는 것은 면역력 강화와 재발 방지에 중요합니다. 균형 잡힌 영양 섭취와 충분한 수면은 림프계 기능을 정상적으로 유지하는 데 도움이 되며, 과로나 스트레스는 면역력을 저하시켜 재감염 위험을 높입니다. 건강한 생활 습관은 전반적인 감염 예방에도 기여합니다.', 157, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '임파선염', '임파선염', 'MEDICATION', '종합비타민과 고함량 비타민 제제를 동시에 복용하면 지용성 비타민(A, D, E, K)의 경우 체내 축적으로 과다증이 발생할 수 있으며, 특히 비타민 A 과잉 시 두통·간독성, 비타민 D 과잉 시 고칼슘혈증이 나타날 수 있습니다. 수용성 비타민(B군, C)은 과잉 섭취 시 대부분 소변으로 배출되지만 고용량에서는 위장 장애가 생길 수 있습니다. 복용 전 반드시 의사 또는 약사와 상담하시기 바랍니다.', 158, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '임파선염', '임파선염', 'PREVENTION', '임파선염의 예방을 위해서는 손 씻기 등 철저한 개인위생 유지, 감기·편도염 등 상기도 감염의 조기 치료, 충분한 수면과 균형 잡힌 식이를 통한 면역력 관리가 중요합니다. 진단을 위해서는 혈액검사(CBC, ESR, CRP), 초음파 검사, 필요시 림프절 생검 등이 시행됩니다. 정확한 진단과 예방 계획은 내과 또는 이비인후과 전문의와 상담하시기 바랍니다.', 159, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '임파선염', '임파선염', 'EXERCISE', '임파선염으로 인한 부종과 통증 완화에는 가벼운 림프 마사지(림프드레나지)와 스트레칭이 도움이 될 수 있으며, 부위를 압박하지 않는 범위 내에서 가벼운 걷기 운동도 림프 순환에 유익합니다. 급성 염증기에는 격렬한 운동을 피하고 충분한 휴식이 우선입니다. 적절한 운동 방법과 강도는 담당 전문의와 상의 후 결정하시기 바랍니다.', 160, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '임파선염', '임파선염', 'CAUSE', '임파선염은 주로 세균(포도상구균, 연쇄상구균 등)이나 바이러스 감염에 의해 림프절에 염증이 생겨 발생하며, 피로와 과로로 면역력이 저하되면 감염에 대한 저항력이 약해져 림프절염이 더 쉽게 발생할 수 있습니다. 만성 피로는 면역계 기능을 억제하여 기존 감염의 악화 또는 신규 감염 위험을 높입니다. 피로가 지속될 경우 내과 전문의 진료를 권장합니다.', 161, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '임파선염', '임파선염', 'REHAB', '림프드레나지는 림프 순환을 촉진하여 부종을 줄이는 특수 마사지 기법이며, 압박 스타킹은 림프액이 다시 축적되지 않도록 지속적인 외부 압력을 제공합니다. 두 치료법은 서로 보완적으로 사용되며, 림프드레나지로 부종을 감소시킨 후 압박 스타킹으로 그 효과를 유지하는 복합 림프부종 치료(CDT)의 핵심 요소입니다. 적용 방법은 재활의학과 또는 림프부종 전문팀과 상담하시기 바랍니다.', 162, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '임파선염', '임파선염', 'DEFINITION', '15세 아이의 턱밑이 붓고 열감이 느껴진다면 턱밑 림프절염(악하 림프절염) 또는 침샘염을 의심할 수 있으며, 임파선염의 진단을 위해서는 압통이 있는 림프절 종대, 발열, 관련 부위의 감염 병력 등이 주요 소견입니다. 증상이 있다면 소아청소년과 또는 이비인후과 전문의의 진찰을 받아 원인균 확인 및 적절한 치료를 받으시기 바랍니다.', 163, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '임파선염', '임파선염', 'SYMPTOM', '림프절을 누를 때 통증이 있는 것은 급성 임파선염의 전형적인 증상입니다. 이와 함께 림프절의 크기 증가, 발열, 발적이 동반되면 세균성 또는 바이러스성 임파선염일 가능성이 높으며, 주변 부위의 감염(편도염, 피부 감염 등)이 원인인 경우가 많습니다. 정확한 원인 감별을 위해 이비인후과 또는 내과 전문의 진료를 권장합니다.', 164, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '임파선염', '임파선염', 'DIAGNOSIS', '임파선염은 일차적으로 내과, 소아청소년과, 이비인후과에서 진단 및 치료를 받을 수 있습니다. 수술이 필요한 경우(농양 형성, 림프절 생검 등)에는 외과 또는 이비인후과 전문의와 상담해야 합니다. 원인이 불명확하거나 악성 질환이 의심될 경우 혈액종양내과 전문의의 협진이 필요할 수 있습니다.', 165, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '임파선염', '임파선염', 'TREATMENT', '임파선염 치료는 원인에 따라 달라지며, 세균성인 경우 항생제 치료가 핵심이고 바이러스성인 경우 충분한 휴식과 대증 치료가 기본입니다. 통증과 발열에는 소염진통제가 도움이 되며, 농양이 형성된 경우 절개 배농이 필요할 수 있습니다. 원인 및 중증도에 따른 정확한 치료법은 전문의 진찰 후 결정되어야 합니다.', 166, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '장티푸스', '장티푸스', 'PREVENTION', '장티푸스 환자와 함께 생활할 때는 환자의 대변, 소변, 구토물에 의한 오염을 철저히 차단해야 하며, 손 씻기를 철저히 하고 화장실 공동 사용 시 소독을 철저히 해야 합니다. 음식과 식기는 환자와 반드시 분리하고, 음식은 충분히 가열 조리 후 섭취하며 끓인 물이나 정수된 물만 마십니다. 예방 접종(장티푸스 백신)도 고려할 수 있으니 의료기관에 문의하시기 바랍니다.', 167, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '장티푸스', '장티푸스', 'CAUSE', '장티푸스는 살모넬라 타이피(Salmonella Typhi) 균에 의한 감염으로, 초기 고열(39~40°C)과 피부의 장미색 반점이 특징적입니다. 치료 없이 방치할 경우 장출혈, 장천공 등 생명을 위협하는 합병증으로 진행될 수 있어 위험성이 높습니다. 의심 증상이 있으면 즉시 감염내과 전문의의 진료를 받으시기 바랍니다.', 168, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '장티푸스', '장티푸스', 'DEFINITION', '장티푸스는 오염된 물과 음식을 통해 전파되므로, 흐르는 물에 손을 30초 이상 씻기, 음식 충분히 익혀먹기, 안전한 식수 사용이 핵심 예방법입니다. 또한 장티푸스 예방 백신 접종을 통해 감염 위험을 크게 줄일 수 있으며, 유행 지역 여행 전 접종이 권장됩니다. 위생적인 음식 관리와 개인위생 유지가 환자와의 접촉 외 가장 중요한 예방 방법입니다.', 169, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '장티푸스', '장티푸스', 'SYMPTOM', '장티푸스의 주요 증상은 고열, 두통, 전신 권태감, 복통, 설사 또는 변비이며, 피부에 장미색 반점이 나타날 수 있습니다. 등산 중 오염된 물이나 음식 섭취 후 복통과 설사가 발생했다면 감염성 장염과 함께 장티푸스를 감별해야 합니다. 증상이 지속되거나 고열이 동반되면 즉시 의료기관을 방문하여 전문의 진료를 받으시기 바랍니다.', 170, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '장티푸스', '장티푸스', 'DIAGNOSIS', '장티푸스 진단을 위한 배양 검사는 혈액배양(발병 1~2주), 대변배양(발병 2~3주)이 주로 사용되며, 결과는 보통 3~5일이 소요됩니다. 빠른 진단을 위해 비달(Widal) 혈청 검사를 보조적으로 시행하기도 하나 민감도가 낮아 배양 검사를 우선합니다. 정확한 진단 시기와 방법은 감염내과 전문의와 상담하시기 바랍니다.', 171, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '장티푸스', '장티푸스', 'TREATMENT', '장티푸스의 고열과 설사 치료를 위해 항생제(플루오로퀴놀론계, 세팔로스포린계, 아지스로마이신 등)가 사용됩니다. 탈수 예방을 위한 경구 또는 정맥 수액 보충이 중요하며, 고열에는 해열제를 사용합니다. 항생제 선택과 투약 기간은 내성 여부를 고려해야 하므로 반드시 감염내과 전문의의 처방에 따라 치료받으시기 바랍니다.', 172, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '조류 인플루엔자 인체감염증', '조류인플루엔자인체감염증', 'MEDICATION', '조류 인플루엔자 치료에는 항바이러스제인 오셀타미비르(타미플루)와 자나미비르가 주로 사용되며, 이 약물들은 조류와 사람 모두에게 적용되는 경우가 있으나 용량과 제형이 다릅니다. 동물용 약품을 사람에게 그대로 사용하는 것은 안전성과 효능이 검증되지 않아 위험할 수 있습니다. 반드시 의료기관에서 처방받은 인체용 항바이러스제를 사용하시기 바랍니다.', 173, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '조류 인플루엔자 인체감염증', '조류인플루엔자인체감염증', 'PREVENTION', '조류 인플루엔자 예방을 위해 새와의 접촉 회피 외에도 가금류 농장 방문 후 손발을 철저히 씻고 마스크를 착용하는 것이 중요합니다. 조류 인플루엔자 발생 지역에서는 가금류 및 야생조류의 배설물, 분비물과의 접촉을 피하고, 가금류 제품은 충분히 가열 조리 후 섭취해야 합니다. 의심 증상(발열, 기침, 호흡곤란) 발생 시 즉시 보건소 또는 의료기관을 방문하시기 바랍니다.', 174, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '조류 인플루엔자 인체감염증', '조류인플루엔자인체감염증', 'CAUSE', '조류 인플루엔자에 감염된 조류(특히 H5N1, H7N9 등)와 밀접 접촉하면 인체 감염 위험이 높아지며, 바이러스에 노출된 양과 노출 시간, 개인 면역력에 따라 감염 확률이 달라집니다. 현재까지 사람 간 지속적 전파는 드물어 일반인의 감염 위험은 낮으나, 가금류 밀접 종사자나 발생 지역 방문자는 주의가 필요합니다. 정확한 위험도 평가는 감염내과 전문의와 상담하시기 바랍니다.', 175, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '조류 인플루엔자 인체감염증', '조류인플루엔자인체감염증', 'DEFINITION', '조류 인플루엔자 인체감염증은 H5N1, H7N9 등 조류 인플루엔자 바이러스가 감염된 조류와의 직접 접촉(배설물, 체액, 분비물 등)이나 오염된 환경 접촉을 통해 호흡기로 유입되어 발생합니다. 바이러스가 인체 호흡기 세포에 결합하여 증식하면서 폐렴 등 심각한 호흡기 질환을 유발합니다. 사람-사람 간 전파는 현재까지 매우 드문 것으로 알려져 있습니다.', 176, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '조류 인플루엔자 인체감염증', '조류인플루엔자인체감염증', 'SYMPTOM', '조류 인플루엔자 인체감염증의 주요 증상은 갑작스러운 고열(38°C 이상), 기침, 호흡곤란이며, 이는 조류 인플루엔자의 전형적인 증상에 해당합니다. 결막염, 근육통, 두통도 동반될 수 있으며, 중증으로 진행 시 바이러스성 폐렴, 급성 호흡곤란 증후군(ARDS)이 발생할 수 있습니다. 조류 접촉력이 있고 이러한 증상이 나타나면 즉시 보건소에 신고하고 의료기관을 방문하시기 바랍니다.', 177, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '조류 인플루엔자 인체감염증', '조류인플루엔자인체감염증', 'DIAGNOSIS', '조류 인플루엔자 인체감염증의 진단 검사에는 RT-PCR(비인두 도말 검체), 바이러스 배양, 항체 검사 등이 있으며, 이는 개인별 검체를 채취하여 진행되므로 일반적인 단체 검사 방식은 적용되지 않습니다. 다만 집단 발생이 의심되는 경우 보건당국 주도하에 역학조사 차원의 단체 검진이 시행될 수 있습니다. 검사는 가까운 보건소 또는 감염병 지정 의료기관에서 받으시기 바랍니다.', 178, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '조류 인플루엔자 인체감염증', '조류인플루엔자인체감염증', 'TREATMENT', '조류 인플루엔자 인체감염증은 빠르게 중증 폐렴과 급성 호흡곤란 증후군(ARDS)으로 진행될 수 있어 약물 치료만으로는 부족하며, 호흡 기능 지원을 위한 산소 요법이나 인공호흡기 치료가 필요할 수 있습니다. 중증 환자의 경우 집중치료실(ICU)에서 활력징후 모니터링과 전신 상태 관리를 위한 입원 치료가 필수적입니다. 치료 방침은 감염내과 및 호흡기내과 전문의의 판단에 따라 결정됩니다.', 179, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '첨형 콘딜로마', '첨형콘딜로마', 'PREVENTION', '첨형 콘딜로마 예방을 위해 HPV(인유두종바이러스) 백신 접종이 가장 효과적이며, 가다실 9가 백신이 널리 사용됩니다. 접종은 9~26세에서 권장되며 2~3회 접종으로 진행되고, 성 경험 전 접종 시 효과가 가장 높습니다. 백신 접종과 함께 콘돔 사용 등 안전한 성생활 유지가 예방에 도움이 되며, 자세한 접종 절차는 산부인과 또는 비뇨의학과 전문의와 상담하시기 바랍니다.', 180, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '첨형 콘딜로마', '첨형콘딜로마', 'CAUSE', '첨형 콘딜로마는 대부분 성적 접촉을 통해 전파되지만, 드물게 오염된 수건이나 속옷 등 간접 접촉, 출산 시 감염된 산도를 통한 신생아 감염(후두 유두종), 면역력이 극도로 저하된 경우 자가 접종 등이 발생할 수 있습니다. 그러나 이러한 비성적 경로를 통한 전파는 매우 드뭅니다. 증상이 의심되면 산부인과 또는 비뇨의학과 전문의의 진료를 받으시기 바랍니다.', 181, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '첨형 콘딜로마', '첨형콘딜로마', 'DEFINITION', '첨형 콘딜로마는 증상이 나타나는 즉시 치료를 시작하는 것이 좋으며, 방치 시 병변이 커지거나 전파될 수 있습니다. 레이저 치료는 CO2 레이저를 이용해 병변 조직을 직접 기화·제거하는 방법으로, 크기가 크거나 다발성인 경우, 다른 치료에 반응하지 않는 경우에 효과적으로 사용됩니다. 치료 시기와 방법은 산부인과 또는 비뇨의학과 전문의와 상담하여 결정하시기 바랍니다.', 182, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '첨형 콘딜로마', '첨형콘딜로마', 'SYMPTOM', '첨형 콘딜로마의 주요 증상은 외음부, 항문 주위, 질 내부 등에 생기는 닭벼슬 또는 꽃양배추 모양의 사마귀성 병변이며, 가려움증, 따가움, 불쾌감을 동반할 수 있습니다. 병변이 질 내부나 자궁경부에 발생한 경우 무증상인 경우도 많으며, 드물게 출혈이나 분비물이 증가할 수 있습니다. 증상이 의심되면 산부인과 또는 비뇨의학과에서 전문의 진료를 받으시기 바랍니다.', 183, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '첨형 콘딜로마', '첨형콘딜로마', 'DIAGNOSIS', '생식기에 사마귀 같은 증상이 나타난 경우 첨형 콘딜로마 감별을 위해 여성은 산부인과, 남성은 비뇨의학과 전문의를 찾는 것이 적절합니다. 피부과에서도 진단이 가능하며, 필요시 HPV 유전자형 검사, 조직 생검 등 추가 검사가 진행될 수 있습니다. 정확한 진단 후 개인 상황에 맞는 치료를 받으시기 바랍니다.', 184, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '첨형 콘딜로마', '첨형콘딜로마', 'TREATMENT', '첨형 콘딜로마 치료 중에는 성적 접촉을 피하는 것이 파트너에게 전파 위험을 줄이는 데 매우 중요합니다. 치료 후에도 바이러스가 완전히 제거되지 않을 수 있으므로 콘돔 사용을 꾸준히 유지해야 하며, 파트너도 함께 검사와 치료를 받는 것이 권장됩니다. 피부 접촉, 오염된 물품을 통해서도 전파될 수 있으므로 개인위생을 철저히 유지하시기 바랍니다.', 185, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '칸디다성 구내염', '칸디다성구내염', 'CHECKUP', '혀와 볼 안쪽에 하얀 반점이나 백태 같은 증상이 있으면 칸디다성 구내염이 의심되며, 구강내과 또는 내과, 이비인후과에서 진료를 받을 수 있습니다. 면봉으로 병변 부위를 채취해 현미경 검사나 진균 배양 검사를 통해 확진합니다. 면역 저하 상태(당뇨, 스테로이드 복용 등)가 의심되는 경우 추가 검사도 병행할 수 있으니 전문의 진료를 권장합니다.', 186, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '칸디다성 구내염', '칸디다성구내염', 'DIET_LIFE', '칸디다성 구내염 예방을 위해 당분이 많은 음식(단 음식, 정제 탄수화물)의 과다 섭취를 줄이는 것이 도움이 되는데, 칸디다균이 당분을 먹고 과증식하기 때문입니다. 스트레스 관리를 위해 규칙적인 식사, 요거트 등 유산균이 풍부한 식품 섭취, 비타민 C와 아연이 풍부한 식품을 통한 면역력 강화가 도움이 됩니다. 항생제 복용 후에는 특히 주의가 필요합니다.', 187, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '칸디다성 구내염', '칸디다성구내염', 'MEDICATION', '칸디다성 구내염 치료에서 나이스타틴 현탁액은 병변 부위에 직접 접촉할 수 있어 국소 치료에 효과적이며, 연고 형태는 입술 주변 등 도포 가능한 부위에 사용됩니다. 현탁액은 구강 내 넓은 부위에 고르게 적용 가능하고, 연고는 보습 효과와 함께 점막 부착성이 높아 특정 부위에 집중 치료가 가능합니다. 적합한 제형 선택은 담당 전문의 또는 약사와 상담하시기 바랍니다.', 188, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '칸디다성 구내염', '칸디다성구내염', 'PREVENTION', '칸디다성 구내염 예방을 위해 충분한 수면 외에도 식후 칫솔질과 구강 위생 철저히 관리, 항생제나 스테로이드 사용 후 구강 세정, 틀니 착용자는 매일 틀니 세척 및 소독이 중요합니다. 당분 섭취를 줄이고 면역력을 떨어뜨리는 과도한 음주와 흡연을 삼가는 것도 도움이 됩니다. 자주 재발한다면 내과 또는 구강내과 전문의 진료를 통해 기저 원인을 확인하시기 바랍니다.', 189, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '칸디다성 구내염', '칸디다성구내염', 'EXERCISE', '규칙적인 중등도 운동은 면역력을 강화하여 칸디다균의 과증식을 억제하는 데 간접적으로 도움을 줄 수 있습니다. 운동 후 구강 위생 관리(양치질 등)를 철저히 하고 수분을 충분히 섭취하는 것이 구강 내 환경 유지에 유익합니다. 그러나 운동 자체가 구내염을 직접 치료하지는 않으므로 증상이 있다면 구강내과 또는 내과 전문의 진료를 받으시기 바랍니다.', 190, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '칸디다성 구내염', '칸디다성구내염', 'CAUSE', '암환자, 당뇨병환자, 후천성 면역결핍증 환자에서 칸디다성 구내염이 자주 발생하는 이유는 이들 질환 자체 또는 치료(항암제, 방사선, 스테로이드)로 인해 세포면역 기능이 크게 저하되기 때문입니다. 면역기능이 정상이면 소량의 칸디다균은 억제되지만, 면역이 저하되면 구강 내 정상 균총의 균형이 깨지고 칸디다균이 과증식합니다. 또한 항생제 사용이 정상 세균총을 파괴해 칸디다균 증식을 촉진하는 역할도 합니다.', 191, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '칸디다성 구내염', '칸디다성구내염', 'REHAB', '구강 청결을 유지하면 칸디다균의 과증식 환경을 제거하여 치료에 긍정적인 영향을 미치며, 식후 칫솔질과 정기적인 구강 세정제 사용이 도움이 됩니다. 반면 과로는 면역력을 저하시켜 칸디다균에 대한 저항력을 약화시키므로 치료 기간 중 충분한 휴식을 취하는 것이 회복에 중요합니다. 구강 청결 유지와 충분한 휴식을 병행하면 항진균제 치료의 효과를 높일 수 있습니다.', 192, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '칸디다성 구내염', '칸디다성구내염', 'DEFINITION', '칸디다성 구내염과 칸디다성 질염은 모두 같은 원인균(Candida albicans 등)에 의해 발생하지만, 발병 부위가 다른 별개의 질환입니다. 칸디다성 구내염은 구강 점막에, 칸디다성 질염은 질 점막에 발생하며, 면역력 저하나 항생제 사용 등의 위험 요인은 공통적입니다. 동시에 두 부위에 발생할 수도 있으므로 한 부위 진단 시 다른 부위 확인도 필요할 수 있습니다.', 193, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '칸디다성 구내염', '칸디다성구내염', 'SYMPTOM', '혀나 구강 점막에 하얀 반점이나 백색 막이 생기는 것은 칸디다성 구내염의 특징적인 증상입니다. 이 하얀 병변은 긁으면 제거되며 그 아래 붉은 점막이 드러나는 것이 특징으로, 단순한 식잔류와 구별됩니다. 이러한 증상이 나타나면 구강내과, 이비인후과 또는 내과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 194, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '칸디다성 구내염', '칸디다성구내염', 'DIAGNOSIS', '칸디다성 구내염은 구강내과, 이비인후과, 내과, 가정의학과에서 진단과 치료가 가능합니다. 구강 내벽에 심한 염증이 있다면 구강내과 또는 이비인후과를 우선적으로 방문하는 것이 좋으며, 면역 저하 질환이 기저에 있다면 해당 질환을 전문으로 하는 내과 전문의와 함께 치료하는 것이 바람직합니다. 가까운 1차 의료기관에서도 초기 진단과 처방이 가능합니다.', 195, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '칸디다성 구내염', '칸디다성구내염', 'TREATMENT', '칸디다성 구내염의 치료는 증상의 중증도와 면역 상태에 따라 국소 항진균제(나이스타틴 현탁액, 클로트리마졸 트로키)부터 전신 항진균제(플루코나졸 등)까지 단계적으로 선택됩니다. 치료 시기는 증상 발생 시 가능한 빨리 시작하는 것이 좋으며, 면역저하 환자는 더 적극적인 치료가 필요합니다. 치료 방침과 기간은 담당 전문의의 처방에 따르시기 바랍니다.', 196, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '콜레라', '콜레라', 'PREVENTION', '손 씻기는 콜레라 예방의 기본이나 이것만으로는 충분하지 않으며, 오염된 물과 음식 섭취를 차단하는 것이 가장 중요합니다. 음식은 반드시 충분히 가열 조리하고, 식수는 끓인 물이나 정수된 물만 사용해야 합니다. 유행 지역 방문 시 콜레라 예방 백신 접종도 고려할 수 있으며, 채소와 과일은 깨끗이 씻어 껍질을 벗겨 먹는 것이 안전합니다.', 197, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '콜레라', '콜레라', 'CAUSE', '콜레라는 주로 오염된 물과 음식을 통해 경구로 전파되며, 대중 목욕탕의 물이 콜레라균에 오염되어 있다면 이론적으로 전파 가능성이 있습니다. 그러나 실질적인 위험은 오염된 수영장이나 개방 수역에서 더 높으며, 목욕탕 이용 시 물을 마시지 않도록 주의하고 이용 후 손을 깨끗이 씻는 것이 중요합니다. 위생적으로 관리된 시설에서의 위험은 낮으나 유행 시기에는 주의가 필요합니다.', 198, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '콜레라', '콜레라', 'DEFINITION', '콜레라는 콜레라균(Vibrio cholerae)에 오염된 물이나 음식 섭취로 감염되는 급성 수양성 설사 질환으로, 수 시간 내에 심각한 탈수를 일으킬 수 있습니다. 특징적인 증상으로 갑자기 시작되는 쌀뜨물 같은 대량의 물설사와 구토가 나타나며, 복통과 발열은 비교적 드뭅니다. 적절한 수액 보충 없이 방치하면 전해질 불균형으로 생명을 위협할 수 있으므로 즉시 의료기관을 방문해야 합니다.', 199, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '콜레라', '콜레라', 'SYMPTOM', '갑작스러운 구토와 쌀뜨물 같은 대량의 물설사는 콜레라의 가장 전형적인 증상으로, 콜레라를 강력히 의심해야 합니다. 유사한 증상을 보이는 질환으로 노로바이러스 감염증, 비브리오장염 등이 있으나 대량의 쌀뜨물 설사가 특징적입니다. 증상 발생 즉시 의료기관을 방문하고, 음식이나 물을 통한 전파를 막기 위해 격리 조치가 필요합니다.', 200, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '콜레라', '콜레라', 'DIAGNOSIS', '콜레라의 가장 확실한 진단법은 대변 배양 검사로 콜레라균(Vibrio cholerae)을 분리 동정하는 것입니다. 신속 항원 검사(RDT)는 빠른 초기 선별에 유용하지만 확진에는 배양 검사가 필요합니다. 유행 지역 방문력, 오염된 식수 섭취력 등의 역학적 정보와 함께 대변 검체 배양으로 진단하며, 감염내과 전문의 진료를 권장합니다.', 201, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '콜레라', '콜레라', 'TREATMENT', '콜레라 치료 중 가장 중요한 것은 신속한 수액 보충을 통한 탈수 교정이며, 중증인 경우 정맥 수액 투여가 필요합니다. 항생제(독시사이클린, 아지스로마이신 등) 투여로 이환 기간을 단축할 수 있으며, 환자의 대변과 구토물을 철저히 소독하고 손 씻기를 철저히 하는 것이 주변인에 대한 전파 예방의 핵심입니다. 치료는 반드시 의료기관에서 전문의 지도하에 진행해야 합니다.', 202, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '파상풍', '파상풍', 'PREVENTION', '파상풍 예방에서 상처를 깨끗이 소독하고 비위생적 물질이 닿지 않도록 하는 것은 파상풍균(Clostridium tetani)의 아포가 상처 부위에서 증식하는 것을 막아 독소 생성을 차단하는 중요한 역할을 합니다. 비위생적 화장품이나 약품 도포를 피하면 혐기성 환경 형성을 방지하여 파상풍균 증식 억제에 도움이 됩니다. 그러나 파상풍 예방의 핵심은 정기적인 파상풍 예방접종이므로 접종 여부를 반드시 확인하시기 바랍니다.', 203, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '파상풍', '파상풍', 'CAUSE', '파상풍에서 발열과 경련이 동반되는 것은 파상풍 독소(테타노스파스민)가 신경계에 작용하여 근육 강직과 경련을 일으키고, 이 과정에서 체온 조절 중추에도 영향을 미치기 때문입니다. 발열 자체는 파상풍의 직접 원인이 아니라 감염에 따른 전신 염증 반응의 결과입니다. 발열과 경련이 동시에 나타나고 개구 장애나 근육 강직이 동반된다면 파상풍을 의심하고 즉시 응급실을 방문하시기 바랍니다.', 204, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '파상풍', '파상풍', 'DEFINITION', '파상풍은 파상풍균(Clostridium tetani)이 오염된 상처 부위에서 증식하면서 분비하는 신경독소(테타노스파스민)가 운동 신경계를 침범하여 경련성 마비와 통증을 동반한 근육 수축을 일으키는 감염병입니다. 초기 증상으로 개구 장애(트리스무스)가 나타나고 이후 전신 근육 강직, 활(궁상긴장, opisthotonus) 자세, 자율신경계 이상으로 진행될 수 있습니다. 예방을 위해 파상풍 예방접종(Td 또는 Tdap)이 필수적입니다.', 205, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '파상풍', '파상풍', 'SYMPTOM', '전신적 통증과 연하 곤란(음식을 삼키지 못함), 근육 강직은 파상풍의 대표적인 증상으로, 이러한 증상이 상처 발생 후 수일~수주 내에 나타난다면 파상풍을 강하게 의심해야 합니다. 특히 개구 장애(입을 벌리기 어려움)와 연하 곤란이 동시에 나타나는 경우 파상풍의 전형적인 소견입니다. 즉시 응급실을 방문하여 신경과 또는 감염내과 전문의의 진료를 받으시기 바랍니다.', 206, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '파상풍', '파상풍', 'DIAGNOSIS', '녹슨 못에 찔린 경우 먼저 상처를 흐르는 물과 비누로 충분히 세척하고, 즉시 외과 또는 응급실을 방문하여 상처 처치와 파상풍 예방 여부를 확인받아야 합니다. 마지막 파상풍 접종 후 5년 이상 경과했다면 파상풍 톡소이드 추가 접종이 필요하며, 상처가 깊거나 오염이 심한 경우 파상풍 면역 글로불린(TIG) 투여도 고려됩니다. 통증 및 감염 예방을 위한 적절한 처치는 반드시 전문의와 상담하시기 바랍니다.', 207, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '파상풍', '파상풍', 'TREATMENT', '파상풍 치료 후 회복 속도는 독소의 양, 감염 부위, 치료 시작 시기, 연령, 기저 질환, 면역 상태 등 개인차에 따라 크게 다릅니다. 경증 환자는 수 주 내에 회복될 수 있으나, 중증 환자는 수개월이 소요되거나 후유증이 남을 수 있습니다. 입원 치료 중 근이완제, 항독소, 항생제 등 복합 치료를 통해 회복을 도모하며, 구체적인 예후는 담당 전문의와 상담하시기 바랍니다.', 208, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '패혈증', '패혈증', 'CHECKUP', '고열과 저체온증을 포함한 패혈증 의심 증상이 나타나면 응급실 또는 내과(감염내과) 전문의를 즉시 방문해야 합니다. 패혈증은 빠르게 진행되어 생명을 위협할 수 있으므로 지체 없이 응급 처치를 받는 것이 중요합니다. 중환자의학과, 감염내과, 응급의학과에서 협진으로 치료가 이루어지는 경우가 많습니다.', 209, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '패혈증', '패혈증', 'DIET_LIFE', '비브리오 패혈증 예방을 위해 어패류 생식 금지 외에도 간 질환, 당뇨, 면역저하 상태의 고위험군은 해산물의 완전한 가열 조리를 철저히 지켜야 합니다. 피부에 상처가 있는 경우 바닷물과의 접촉을 피해야 하며, 어패류 손질 후 손과 식기를 청결히 유지해야 합니다. 생굴, 조개 등 날 해산물은 비브리오균 오염 위험이 높으므로 특히 여름철에는 반드시 익혀 먹으시기 바랍니다.', 210, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '패혈증', '패혈증', 'MEDICATION', '패혈증 초기에는 원인균이 불명확하므로 광범위 항생제를 먼저 투여하여 균이 더 번식하기 전에 신속히 치료를 시작하는 것이 생존율을 높이는 데 중요합니다. 배양 검사는 결과가 나오는 데 24~72시간이 걸리므로, 결과를 기다리는 동안 경험적 항생제 치료를 우선 진행하고 균 동정 후 감수성에 따라 치료를 조정합니다. 진균 감염이 의심되는 경우 항진균제를 추가 투여하며, 이는 반드시 전문의의 판단하에 이루어져야 합니다.', 211, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '패혈증', '패혈증', 'PREVENTION', '패혈증 예방을 위해 면역력을 저하시키는 기저 질환(당뇨, 만성 간질환 등)을 철저히 관리하고, 발생한 감염(피부 상처, 폐렴, 요로감염 등)은 조기에 치료하는 것이 핵심입니다. 독감·폐렴구균 등의 예방접종을 통해 주요 감염 위험을 낮추고, 철저한 손 위생 유지가 중요합니다. 의료 시술 시 무균 처치를 준수하는 것도 패혈증 예방에 필수적입니다.', 212, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '패혈증', '패혈증', 'EXERCISE', '패혈증 급성기에는 휴식이 최우선이며, 심한 운동은 금지됩니다. 호흡수 증가는 감염에 대한 신체 반응으로 급성기 치료(항생제, 수액 등) 후 원인이 해결되면 호전됩니다. 회복기에는 호흡 기능 강화를 위한 심호흡 운동이나 가벼운 걷기가 도움이 될 수 있으나, 운동 처방은 반드시 담당 전문의와 상담 후 시행하시기 바랍니다.', 213, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '패혈증', '패혈증', 'CAUSE', '비브리오 패혈증은 수온이 18°C 이상인 여름철(7~9월)에 해수 내 비브리오 불니피쿠스균의 농도가 높아질 때 주로 발생하여 환경 요인과 밀접한 연관이 있습니다. 피부에 상처가 있는 상태에서 오염된 바닷물에서 수영하거나 어패류를 손질할 경우 균이 상처를 통해 침입할 수 있어 비브리오 패혈증 위험이 높아집니다. 고위험군(간 질환자, 당뇨, 면역저하자)은 여름철 바닷물 접촉 및 어패류 생식을 특히 주의해야 합니다.', 214, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '패혈증', '패혈증', 'DEFINITION', '패혈증은 감염에 대한 생체의 조절 불능 반응으로 인해 생명을 위협하는 장기 기능 이상이 발생하는 응급 질환입니다. 주요 증상으로는 발열 또는 저체온증, 빠른 호흡수(분당 22회 이상), 혈압 저하, 정신 착란(인지 장애), 빠른 맥박, 소변량 감소 등이 있습니다. 이러한 증상이 나타나면 즉시 응급실을 방문하여 감염내과 또는 응급의학과 전문의의 치료를 받으시기 바랍니다.', 215, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '패혈증', '패혈증', 'SYMPTOM', '패혈증의 초기 증상으로 빠른 호흡, 인지력 저하 외에도 고열 또는 저체온(36°C 미만), 빠른 맥박(분당 90회 이상), 혈압 저하, 소변량 감소, 피부 얼룩덜룩한 변색(mottling), 극심한 피로와 쇠약감이 나타날 수 있습니다. 중증으로 진행되면 장기 부전(신부전, 간부전, 응고 장애)이 발생할 수 있습니다. 이러한 증상이 의심되면 즉시 응급실을 방문하시기 바랍니다.', 216, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '패혈증', '패혈증', 'DIAGNOSIS', '회 등 날 해산물 섭취 후 발열, 오한, 피부 병변(수포, 괴사) 등이 나타난다면 비브리오 패혈증을 의심해야 하며, 즉시 응급실 또는 감염내과를 방문해야 합니다. 비브리오 패혈증은 빠르게 진행되어 생명을 위협할 수 있으므로 지체 없는 진료가 중요합니다. 특히 간 질환, 당뇨, 면역저하 환자는 고위험군으로 더욱 신속한 의료 처치가 필요합니다.', 217, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '패혈증', '패혈증', 'TREATMENT', '비브리오 패혈증 치료에는 두 가지 이상의 항생제 병용 요법이 표준으로, 주로 3세대 세팔로스포린계 또는 플루오로퀴놀론계 항생제와 독시사이클린을 병용합니다. 조기에 항생제 치료를 시작할수록 예후가 좋으며, 중증의 경우 집중치료실 입원 및 피부 괴사 부위에 대한 외과적 절제가 필요할 수 있습니다. 치료 방침은 반드시 감염내과 전문의의 판단에 따라 신속히 진행되어야 합니다.', 218, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '풍진', '풍진', 'PREVENTION', '풍진 백신(MMR 포함)은 1, 2차 접종을 완료할 경우 약 97% 이상의 면역 획득률을 보이며, 100% 예방은 아니지만 매우 높은 수준의 보호 효과가 있습니다. 접종은 생후 12~15개월에 1차, 만 4~6세에 2차 접종을 시행하며 성인도 항체가 없다면 접종이 권고됩니다. 가임 여성은 접종 후 4주간 임신을 피해야 하며, 임신 중에는 접종이 금지되므로 산부인과 전문의와 상담하시기 바랍니다.', 219, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '풍진', '풍진', 'CAUSE', '풍진 바이러스가 임신 초기(특히 첫 12주 이내) 임산부를 감염시키면 태반을 통해 태아에게 전달되어 선천성 풍진 증후군을 유발할 수 있습니다. 이로 인해 태아의 심장 기형, 백내장, 청각 장애, 소두증, 지적 장애 등 다발성 선천성 기형이 발생할 수 있으며, 임신 초기일수록 태아 손상 위험이 더 높습니다. 임신 전 풍진 항체 검사와 필요시 예방 접종을 통해 예방하는 것이 가장 중요합니다.', 220, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '풍진', '풍진', 'DEFINITION', '홍역, 볼거리(유행성 이하선염), 풍진은 각각 다른 바이러스(홍역 바이러스, 볼거리 바이러스, 풍진 바이러스)에 의해 발생하는 서로 다른 질환으로, 임상 증상도 각기 다릅니다. 다만 MMR 백신으로 세 가지 질환을 동시에 예방하기 때문에 함께 언급되는 경우가 많습니다. 각 질환의 증상과 전파 경로가 다르므로, 의심 증상 발생 시 소아청소년과 또는 감염내과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 221, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '풍진', '풍진', 'SYMPTOM', '풍진의 주요 증상은 귀 뒤, 얼굴에서 시작하여 전신으로 퍼지는 작은 분홍색~붉은색 반점(구진성 발진), 경부 및 후두부 림프절 종대, 미열, 관절통입니다. 소아에서는 발진 전에 미열, 경한 상기도 증상이 나타날 수 있고, 성인에서는 관절통이 더 두드러질 수 있습니다. 혈소판 감소에 의한 점상 출혈이 드물게 나타날 수 있으며, 증상이 의심되면 즉시 전문의 진료를 받으시기 바랍니다.', 222, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '풍진', '풍진', 'DIAGNOSIS', '풍진과 감기는 초기 증상(콧물, 미열)이 유사하여 감별이 어려울 수 있으나, 풍진은 특징적인 분홍색 발진이 귀 뒤에서 시작해 전신으로 퍼지는 것이 감별 포인트입니다. 또한 풍진에서는 귀 뒤와 목 뒤 림프절이 크게 붓는 것이 특징적입니다. 발진이 동반되거나 임산부와 접촉이 있었다면 즉시 의료기관을 방문하여 혈액 검사(풍진 IgM 항체)를 통한 확진이 필요합니다.', 223, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '풍진', '풍진', 'TREATMENT', '풍진은 대부분 자연 치유되는 질환으로 특별한 항바이러스 치료제는 없으며, 주로 증상 완화를 위한 대증 치료(해열제, 충분한 수분 섭취, 휴식)를 시행합니다. 그러나 임산부나 면역저하자, 합병증이 의심되는 경우에는 반드시 의료기관을 방문해야 합니다. 집에서 휴식을 취할 경우에도 주변 사람들에 대한 전파 예방을 위해 발진 소실 후 최소 5일간 격리가 권장됩니다.', 224, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '헤르페스 바이러스 감염', '헤르페스바이러스감염', 'CHECKUP', '입술 포진(구순 헤르페스) 등 헤르페스 바이러스 감염이 의심되면 피부과 또는 감염내과를 방문하는 것이 좋습니다. 생식기 헤르페스가 의심되는 경우 여성은 산부인과, 남성은 비뇨의학과나 피부과를 방문하시기 바랍니다. 정확한 진단을 위해 병변 부위의 바이러스 배양 검사, PCR 검사, 또는 혈청 항체 검사 등이 시행될 수 있습니다.', 225, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '헤르페스 바이러스 감염', '헤르페스바이러스감염', 'DIET_LIFE', '헤르페스 바이러스 감염의 주요 원인은 감염자와의 직접 접촉(키스, 성 접촉, 피부 접촉)으로, 바이러스는 신체에 잠복하다가 면역력이 저하될 때(스트레스, 과로, 발열, 자외선 노출 등) 재활성화됩니다. 주요 증상으로는 입술이나 구강 주위의 물집과 통증(HSV-1), 생식기 주변의 수포와 궤양(HSV-2)이 대표적이며, 초감염 시 발열과 전신 증상이 동반될 수 있습니다. 증상 발현 시 피부과 또는 전문의 진료를 권장합니다.', 226, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '헤르페스 바이러스 감염', '헤르페스바이러스감염', 'MEDICATION', '헤르페스 바이러스 감염 치료에 사용되는 항바이러스 연고(아시클로버 등)는 증상 발현 초기(수포 형성 전, 전구 증상 단계)에 병변 부위에 하루 5~6회 도포하는 것이 권장됩니다. 조기에 자주 도포할수록 수포 크기를 줄이고 치유 기간을 단축하는 효과가 있습니다. 그러나 연고 단독으로는 바이러스 잠복 상태를 제거하지 못하므로, 재발이 잦다면 경구 항바이러스제에 대해 전문의와 상담하시기 바랍니다.', 227, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '헤르페스 바이러스 감염', '헤르페스바이러스감염', 'PREVENTION', '헤르페스 바이러스 감염 예방을 위해 개인위생 외에도 감염자와의 수포 접촉을 피하고, 수건·식기 등 개인 용품을 철저히 분리 사용해야 합니다. 면역력 관리를 위해 충분한 수면, 스트레스 감소, 균형 잡힌 식이를 유지하는 것이 재발 억제에 도움이 됩니다. 생식기 헤르페스의 경우 콘돔 사용과 파트너와의 감염 사실 공유가 전파 예방에 중요합니다.', 228, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '헤르페스 바이러스 감염', '헤르페스바이러스감염', 'EXERCISE', '헤르페스 바이러스 감염을 가진 60대 여성에게는 면역력을 강화하면서 과도한 피로를 피할 수 있는 운동이 적합합니다. 첫째, 주 3~5회 30분 걷기는 심폐 기능과 면역력 향상에 효과적입니다. 둘째, 가벼운 요가나 스트레칭은 스트레스 완화와 유연성 향상에 도움이 됩니다. 셋째, 수중 운동(아쿠아로빅)은 관절에 부담 없이 전신 운동이 가능하며, 운동 강도는 전문의와 상담 후 결정하시기 바랍니다.', 229, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '헤르페스 바이러스 감염', '헤르페스바이러스감염', 'CAUSE', '골반 통증과 발열은 성적으로 활발한 여성에서 골반염(PID, 클라미디아·임질균 등에 의한), 또는 생식기 헤르페스(HSV-2)의 초감염 시 발생하는 증상일 수 있습니다. 생식기 헤르페스는 성 접촉을 통해 전파되며, 초기 감염 시 심한 국소 통증, 수포, 발열, 서혜부 림프절 종대를 동반합니다. 정확한 원인 감별을 위해 산부인과 또는 비뇨의학과 전문의를 방문하여 검사를 받으시기 바랍니다.', 230, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '헤르페스 바이러스 감염', '헤르페스바이러스감염', 'REHAB', '헤르페스로 인한 입술 물집 증상 완화를 위해 아시클로버 등 항바이러스 연고를 조기 도포하고, 냉찜질로 통증과 부종을 줄이는 것이 도움이 됩니다. 회복 기간에는 물집을 건드리지 않도록 하고 자외선 차단제를 사용하며, 충분한 수분 섭취와 영양 관리로 면역력을 지원하는 것이 중요합니다. 증상이 심하거나 자주 재발한다면 피부과 전문의와 경구 항바이러스제 복용에 대해 상담하시기 바랍니다.', 231, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '헤르페스 바이러스 감염', '헤르페스바이러스감염', 'DEFINITION', '헤르페스 바이러스는 주로 감염된 사람과의 직접적인 피부 및 점막 접촉(키스, 성 접촉)을 통해 전파됩니다. 수포 내 분비물이나 구강·생식기 분비물을 통한 전파가 주요 경로이며, 증상이 없는 잠복기에도 바이러스 탈락(무증상 배출)이 일어나 전파될 수 있습니다. 감염자의 타액이 묻은 식기나 개인 용품을 통한 간접 전파는 가능하나 상대적으로 드뭅니다.', 232, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '헤르페스 바이러스 감염', '헤르페스바이러스감염', 'SYMPTOM', '헤르페스 바이러스 감염 시 입 주변에 포진이 생기기 전 먼저 해당 부위에 가려움, 따끔거림, 화끈거리는 전구 증상이 나타납니다. 이후 작은 수포(물집)가 군집으로 형성되고, 수포가 터지면 얕은 궤양과 딱지가 형성되며 홍반(붉은 발적)이 동반됩니다. 초감염 시에는 발열, 두통, 전신 권태감, 림프절 종대가 동반될 수 있으며, 증상이 의심되면 피부과 전문의 진료를 권장합니다.', 233, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '헤르페스 바이러스 감염', '헤르페스바이러스감염', 'DIAGNOSIS', '입술 주위 반복적인 물집, 가려움증, 쓰라림은 헤르페스 바이러스(HSV-1) 감염을 강하게 시사합니다. 확진을 위해 병변 활성기에 수포 내 분비물의 바이러스 PCR 검사 또는 배양 검사를 시행하거나, 혈액 검사로 HSV 특이 IgG/IgM 항체를 측정합니다. 피부과 또는 감염내과 전문의를 방문하여 정확한 검사와 치료 계획을 상담하시기 바랍니다.', 234, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '헤르페스 바이러스 감염', '헤르페스바이러스감염', 'TREATMENT', '헤르페스 바이러스 감염 진단 후 치료 경과 확인을 위한 정기 검진 주기는 증상의 빈도와 중증도에 따라 결정됩니다. 재발이 잦은 경우(연 6회 이상)에는 장기 억제 요법을 시행하며 3~6개월 간격으로 추적 관찰을 권장합니다. 증상이 없는 경우에도 면역저하 상태나 임신 등 상황 변화 시 추가 검진이 필요하며, 구체적인 검진 주기는 담당 전문의와 상담하시기 바랍니다.', 235, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '호산구 증가증', '호산구증가증', 'CAUSE', '호산구 증가증은 기생충 감염(회충, 개회충, 아니사키스 등), 알레르기 질환(천식, 아토피, 두드러기), 자가면역 질환, 특정 약물(항생제, NSAIDs, 항경련제 등) 부작용, 악성 종양(림프종, 호산구성 백혈병) 등이 주요 원인입니다. 약물의 경우 면역 매개 반응을 통해 골수에서 호산구 생성을 촉진합니다. 정확한 원인 파악을 위해 혈액내과 전문의 진료를 권장합니다.', 236, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '호산구 증가증', '호산구증가증', 'DEFINITION', '호산구 증가증은 혈액 내 호산구 수치가 정상(0.1~0.5×10⁹/L)보다 지속적으로 높은 상태로, 기생충 감염, 알레르기, 약물 반응, 악성 종양 등이 주요 원인입니다. 중증 또는 장기간 지속되는 경우 심장, 폐, 피부, 신경계 등 주요 장기 손상의 위험 요인이 됩니다. 증상이나 수치 이상이 발견되면 혈액내과 전문의의 정밀 검사를 통해 원인 감별과 치료를 받으시기 바랍니다.', 237, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '호산구 증가증', '호산구증가증', 'SYMPTOM', '호산구 증가증에서 알레르기 반응은 IgE 매개 과민반응이 호산구 활성화를 촉진하여 발생하며, 천식의 기도 염증, 아토피 피부염의 피부 병변, 두드러기 등의 형태로 나타납니다. 기생충 감염도 Th2 면역 반응을 자극하여 호산구를 증가시키고 알레르기 유사 반응을 유발합니다. 정확한 원인과 알레르기 반응 여부는 알레르기내과 또는 혈액내과 전문의의 검사를 통해 확인하시기 바랍니다.', 238, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '호산구 증가증', '호산구증가증', 'DIAGNOSIS', '호산구 수치가 15.8%로 상승했다면 절대 호산구 수(AEC)를 확인해야 하며, 일반적으로 AEC가 500/μL 이상이면 호산구 증가증, 1500/μL 이상이면 중등도 이상으로 분류됩니다. 수치 상승 자체보다 동반 증상(피부 발진, 천식, 복통, 발열, 체중 감소 등)과 기저 원인이 진단에 더 중요합니다. 정확한 진단을 위해 혈액내과 전문의를 방문하여 추가 검사를 받으시기 바랍니다.', 239, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '호산구 증가증', '호산구증가증', 'TREATMENT', '호산구 증가증이 의심되면 일반 혈액 검사(CBC with differential)로 호산구 수를 확인하고, 기생충 감염 여부(대변 기생충 검사, 혈청 기생충 항체 검사), 알레르기 검사(IgE 수치), 흉부 X선, 심전도 등의 검사가 필요합니다. 원인이 불명확하거나 장기 침범이 의심되면 골수 검사, CT, 심장 초음파 등 추가 정밀 검사가 시행될 수 있습니다. 정확한 진단과 치료는 혈액내과 전문의와 상담하시기 바랍니다.', 240, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '홍역', '홍역', 'MEDICATION', '홍역은 특이적인 항바이러스 치료제가 없어 증상 완화를 위한 대증 치료제가 사용됩니다. 고열에는 아세트아미노펜 또는 이부프로펜 등 해열제, 비타민 A 결핍이 있는 경우 고용량 비타민 A 투여가 합병증 예방에 효과적입니다. 세균성 합병증(폐렴, 중이염 등)이 동반된 경우 항생제를 추가 사용하며, 증상 지속 시 소아청소년과 또는 감염내과 전문의와 상담하시기 바랍니다.', 241, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '홍역', '홍역', 'PREVENTION', '홍역 예방 접종(MMR 백신)은 면역이 없는 사람들에게 매우 효과적인 예방 수단으로, 2회 접종 완료 시 97% 이상의 예방 효과를 제공합니다. 예방 접종을 통해 면역력이 없는 사람들도 홍역으로부터 대부분 보호받을 수 있으며, 접종자 대부분은 충분한 면역을 획득합니다. 접종 여부가 불분명하다면 항체 검사 후 필요시 접종하며, 구체적인 접종 일정은 소아청소년과 또는 내과 전문의와 상담하시기 바랍니다.', 242, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '홍역', '홍역', 'CAUSE', '예방 접종을 받지 않았거나 면역력이 저하된 상태에서 홍역 바이러스(Paramyxovirus)에 노출되면 감염되는 것은 홍역이 백신 접종으로 예방 가능한 감염병임을 의미합니다. 면역이 없는 사람이 홍역 환자와 같은 공간에 있을 경우 약 90% 이상의 높은 전파율로 감염될 수 있으며, 이는 예방 접종의 중요성을 강조합니다. 접종력이 불확실하다면 의료기관에서 항체 검사 및 접종 여부를 확인하시기 바랍니다.', 243, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '홍역', '홍역', 'DEFINITION', '홍역은 홍역 바이러스에 면역이 없는 사람이 환자의 비말이나 공기 중 바이러스에 노출될 때 발생하는 고전파력 감염병입니다. 초기 증상으로 3~5일간 고열, 기침, 콧물, 결막염이 나타나고(전구기), 구강 내 코플릭 반점이 특징적으로 관찰됩니다. 이후 얼굴에서 시작하여 전신으로 퍼지는 붉은 반점 구진성 발진이 3~4일간 지속됩니다.', 244, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '홍역', '홍역', 'SYMPTOM', '홍역의 초기 증상은 3~5일간 지속되는 고열, 기침, 콧물, 결막염이며, 이후 전형적인 발진이 나타납니다. 동일한 증상이 반복적으로 나타나는 경우 홍역보다는 다른 반복성 바이러스 감염이나 알레르기를 먼저 고려해야 합니다. 홍역은 한번 감염되거나 예방 접종을 완료하면 평생 면역이 생기므로, 증상이 의심되면 소아청소년과 또는 감염내과 전문의를 방문하여 확인하시기 바랍니다.', 245, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '홍역', '홍역', 'DIAGNOSIS', '아기의 얼굴에 고열과 붉은 발진이 생겼다면 홍역, 풍진, 수두, 돌발진(로제올라), 성홍열 등 다양한 감염병을 감별해야 합니다. 홍역의 경우 발진 전 3~5일간 고열, 기침, 콧물, 결막염이 선행되는 것이 특징적이며, 발진이 얼굴에서 몸통으로 퍼지는 양상을 보입니다. 소아에서 발열과 발진이 동반되면 즉시 소아청소년과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 246, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '홍역', '홍역', 'TREATMENT', '홍역의 고열에는 아세트아미노펜(타이레놀) 또는 이부프로펜 해열제를 사용하며, 아스피린은 라이 증후군 위험으로 소아에서 금기입니다. 붉은 반점에 사용하는 특별한 연고는 없으며 발진은 자연 소실됩니다. 가려움증이 심한 경우 항히스타민제를 고려할 수 있으며, 비타민 A 결핍이 있는 경우 고용량 비타민 A 투여가 합병증 예방에 도움이 됩니다. 소아청소년과 전문의의 처방에 따라 치료하시기 바랍니다.', 247, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '후천성 면역결핍증', '후천성면역결핍증', 'CHECKUP', '후천성 면역결핍증(AIDS) 확인을 위한 검사로는 먼저 HIV 항체 검사(면역 크로마토그래피법, ELISA)를 시행하고, 양성 반응 시 웨스턴 블롯 확인 검사를 통해 확진합니다. 익명으로 검사받기 원하는 경우 보건소에서 무료로 검사가 가능합니다. 면역기능 저하가 의심되는 다른 원인도 배제해야 하므로, 감염내과 전문의와 상담하여 정확한 원인 파악과 치료 계획을 수립하시기 바랍니다.', 248, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '후천성 면역결핍증', '후천성면역결핍증', 'DIET_LIFE', '후천성 면역결핍증 환자는 항레트로바이러스 치료(ART)를 규칙적으로 복용하면서 충분한 수면, 균형 잡힌 영양 섭취, 금연 및 과음 자제가 기본 생활 습관으로 중요합니다. 감염 예방을 위해 손 씻기, 식품 안전 관리, 정기 예방 접종(독감, 폐렴구균 등)을 철저히 이행해야 합니다. 규칙적인 중등도 운동(주 3~5회 30분 유산소 운동)은 면역기능 유지와 심리적 건강에 도움이 되나, 운동 계획은 담당 전문의와 상담 후 결정하시기 바랍니다.', 249, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '후천성 면역결핍증', '후천성면역결핍증', 'MEDICATION', '후천성 면역결핍증 치료를 위한 항레트로바이러스제(ART)는 하루 1~2회 정해진 시간에 복용해야 하며, 복약 순응도가 치료 성패를 결정하는 핵심입니다. 약물 복용으로 인한 오심, 피로, 두통 등의 초기 부작용은 대개 수 주 내에 호전되나, 일부 장기 복용 시 신장 기능, 골밀도, 지질 대사에 영향을 줄 수 있습니다. ART를 충실히 복용하면 정상에 가까운 일상생활이 가능하므로, 부작용 발생 시 스스로 중단하지 말고 반드시 감염내과 전문의와 상담하시기 바랍니다.', 250, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '후천성 면역결핍증', '후천성면역결핍증', 'PREVENTION', '면역력이 저하된 상태에서는 균형 잡힌 영양 섭취가 매우 중요하며, 단백질·비타민·미네랄이 풍부한 식단을 유지해야 합니다. 날것의 음식, 비위생적인 물 섭취를 피하고 철저한 손 씻기 등 개인위생을 준수해야 합니다. HIV는 혈액, 성 접촉, 수직 감염(모자간)으로 전파되므로 안전한 성관계와 멸균 주사기 사용이 필수적이며, 정기적인 검진을 통해 조기 발견이 중요합니다. 구체적인 생활 관리는 감염내과 전문의와 상담하시기 바랍니다.', 251, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '후천성 면역결핍증', '후천성면역결핍증', 'EXERCISE', '면역력이 저하된 상태에서는 과격한 운동보다 가벼운 유산소 운동(걷기, 수영 등)을 규칙적으로 시행하는 것이 면역 기능 유지에 도움이 됩니다. 충분한 수면(7~8시간), 스트레스 관리, 금연·금주와 함께 균형 잡힌 식사를 병행하면 더 효과적입니다. 운동 강도와 종류는 현재 건강 상태에 따라 달라지므로 반드시 담당 전문의의 지도 아래 운동 계획을 세우시기 바랍니다.', 252, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '후천성 면역결핍증', '후천성면역결핍증', 'CAUSE', 'HIV는 감염자의 혈액, 정액, 질 분비물, 모유 등 체액을 통해 전파되며, 성 접촉 시 점막을 통해 바이러스가 침투합니다. 콘돔 없는 성관계, 특히 항문 성교에서 감염 위험이 가장 높으며, 점막 손상이 있을수록 전파 위험이 증가합니다. HIV 감염 후 면역세포(CD4+ T세포)가 점진적으로 파괴되어 면역력이 극도로 저하되면 에이즈(AIDS)로 진행됩니다. 예방을 위해 콘돔 사용, 노출 전·후 예방요법(PrEP/PEP)을 감염내과 전문의와 상담하시기 바랍니다.', 253, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '후천성 면역결핍증', '후천성면역결핍증', 'REHAB', '후천성 면역결핍증(AIDS) 환자의 근육통과 피부 발진은 HIV 자체 또는 기회감염, 항레트로바이러스 치료제의 부작용과 관련될 수 있습니다. 재활 치료보다는 우선 항레트로바이러스 치료(ART)를 통해 바이러스 수치를 억제하는 것이 가장 중요한 치료 원칙입니다. 근육통에는 가벼운 스트레칭과 물리치료, 피부 발진에는 원인에 따른 약물 치료가 병행될 수 있습니다. 정확한 원인 감별과 치료 계획 수립을 위해 감염내과 전문의 상담이 반드시 필요합니다.', 254, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '후천성 면역결핍증', '후천성면역결핍증', 'DEFINITION', 'HIV/AIDS는 혈액, 체액(정액·질 분비물) 등 직접적 경로로만 전파되며, 일상적인 악수, 포옹, 기침, 식기 공유 등으로는 전염되지 않습니다. 항레트로바이러스 치료(ART)로 혈중 바이러스 수치를 감지 불가 수준으로 유지하면 성적 전파 위험이 사실상 없어집니다(U=U 원칙). 현재 HIV/AIDS는 완치는 어렵지만, 꾸준한 ART로 정상에 가까운 수명과 삶의 질을 유지할 수 있는 만성 질환으로 관리됩니다. 치료 및 전염 예방에 대한 자세한 사항은 감염내과 전문의와 상담하시기 바랍니다.', 255, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '후천성 면역결핍증', '후천성면역결핍증', 'SYMPTOM', 'HIV 감염 초기(급성기)에는 발열, 인후통 외에도 림프절 부종, 두통, 피부 발진, 근육통, 관절통, 구강 궤양, 설사 등 독감 유사 증상이 나타날 수 있습니다. 면역력이 심각하게 저하되는 에이즈 단계에서는 폐포자충 폐렴, 결핵, 칸디다증, 카포시 육종, 거대세포바이러스 감염 등 기회감염과 기회 종양이 발생합니다. 체중 감소, 만성 설사, 야간 발한, 지속적인 피로감도 흔히 나타납니다. 이러한 증상이 지속되면 감염내과 전문의의 진료를 받으시기 바랍니다.', 256, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '후천성 면역결핍증', '후천성면역결핍증', 'DIAGNOSIS', '발열과 피부 발진이 있을 때 후천성 면역결핍증 진단을 위해서는 HIV 노출 위험 요인(성 접촉력, 수혈, 약물 주사 등) 병력 청취가 우선 필요합니다. HIV 항체 검사(ELISA) 및 확진 검사(Western blot), HIV RNA 정량 검사(바이러스 수치)를 시행합니다. 식이나 생활 습관 자체가 HIV 진단 기준은 아니며, 검사 결과와 임상 증상을 종합적으로 평가합니다. 정확한 진단을 위해 감염내과 또는 보건소 익명 검사를 통한 전문의 상담을 권장합니다.', 257, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '후천성 면역결핍증', '후천성면역결핍증', 'TREATMENT', '후천성 면역결핍증의 표준 치료는 항레트로바이러스 치료제(ART) 복용이며, 이를 대체할 수 있는 자연요법이나 홈 레메디는 과학적으로 입증된 것이 없습니다. 자연요법이나 민간요법은 ART의 효과를 방해하거나 약물 상호작용을 일으킬 수 있어 위험할 수 있습니다. 보완적으로 균형 잡힌 식사, 규칙적인 운동, 충분한 수면, 스트레스 관리는 면역력 유지에 도움이 됩니다. ART 치료 및 보조 관리법에 대해서는 반드시 감염내과 전문의와 상담하시기 바랍니다.', 258, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '고막염', '고막염', 'CHECKUP', '수영 후 귀에 염증과 통증이 생기면 고막염 또는 외이염을 의심할 수 있으며, 이비인후과를 방문하여 이경 검사를 받는 것이 좋습니다. 이비인후과에서는 고막 및 외이도 상태를 직접 관찰하여 염증 여부와 원인을 확인할 수 있습니다. 증상이 지속되거나 악화될 경우 청력 검사, 삼출액 배양 검사 등 추가 검사가 필요할 수 있습니다. 정확한 진단과 치료를 위해 이비인후과 전문의의 진료를 받으시기 바랍니다.', 259, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '고막염', '고막염', 'MEDICATION', '스테로이드 주사 후 피부가 약해지고 고막염 유사 증상이 나타나는 경우, 스테로이드의 면역 억제 효과로 인한 국소 감염(세균성 또는 진균성) 가능성을 고려해야 합니다. 이는 고막 자체의 염증(고막염)과 유사한 증상을 보일 수 있으며, 스테로이드 사용 부위의 피부 위축이나 감염과도 관련될 수 있습니다. 정확한 원인 파악을 위해 이비인후과 전문의의 진찰과 필요시 배양 검사가 필요합니다. 스테로이드 주사의 지속 여부와 치료 방향은 반드시 담당 전문의와 상담하시기 바랍니다.', 260, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '고막염', '고막염', 'PREVENTION', '고막염이 있는 경우 중이와 상기도가 유스타키오관으로 연결되어 있어 감기나 비염이 악화되면 중이염이나 부비동염으로 전이될 가능성이 있습니다. 호흡기 감염으로의 전이 여부를 확인하기 위해 이비인후과에서 이경 검사, 비강 내시경, 필요시 부비동 CT 검사를 받을 수 있습니다. 예방을 위해서는 코를 세게 풀지 않고, 상기도 감염 시 조기 치료가 중요합니다. 증상이 지속되면 이비인후과 전문의의 진료를 받으시기 바랍니다.', 261, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '고막염', '고막염', 'CAUSE', '고막염은 물이 귀에 들어가는 것 외에도, 귀를 손가락이나 면봉으로 후비는 행동, 이물질 삽입, 타격이나 폭발에 의한 기압 변화(압력성 손상), 중이염의 합병증으로 고막 천공 등 다양한 외상이 원인이 될 수 있습니다. 또한 세균이나 바이러스 감염, 알레르기 반응도 고막염을 유발할 수 있습니다. 외상성 고막 손상은 청력 저하와 통증을 유발할 수 있으므로 이비인후과 전문의의 진료가 필요합니다.', 262, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '고막염', '고막염', 'DEFINITION', '고막염은 고막에 염증이 발생하는 질환으로, 귀 통증, 이명(귀울림), 청력 저하, 귀 충만감, 이루(귀에서 분비물) 등의 증상을 유발합니다. 진단은 이비인후과에서 이경 또는 내시경을 통한 고막 직접 관찰로 이루어지며, 필요시 청력 검사와 배양 검사를 시행합니다. 치료는 원인에 따라 항생제 점이액, 항진균제, 스테로이드 점이액 등 약물 치료를 우선 시행하며, 심한 경우 수술적 치료(고막성형술)가 필요할 수 있습니다. 정확한 진단과 치료를 위해 이비인후과 전문의 상담을 권장합니다.', 263, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '고막염', '고막염', 'SYMPTOM', '고막염은 고막 자체의 염증으로 심한 귀 통증, 이루, 청력 저하, 이명이 주요 증상이며, 고막 천공이 동반될 수 있습니다. 외이염은 외이도(귀 입구~고막 사이) 피부의 염증으로 귀 통증, 가려움증, 외이도 부종, 분비물이 특징이며 귀를 당기거나 누를 때 통증이 심해집니다. 두 질환의 가장 큰 구분 기준은 염증 위치로, 고막염은 고막에, 외이염은 외이도에 주로 병변이 있습니다. 정확한 감별 진단은 이비인후과에서 이경 검사로 확인할 수 있습니다.', 264, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '고막염', '고막염', 'DIAGNOSIS', '고막염이 있을 때 수영은 귀에 물이 들어가 감염을 악화시킬 수 있어 권장되지 않습니다. 수영 외에도 귀에 충격이 가해지는 격투기, 압력 변화가 생기는 스쿠버다이빙, 큰 소리에 노출되는 환경에서의 운동도 고막 손상을 악화시킬 수 있어 주의가 필요합니다. 걷기, 실내 자전거 등 귀에 영향이 적은 유산소 운동은 일반적으로 가능하나, 치료 기간 중에는 담당 이비인후과 전문의와 운동 가능 여부를 상담하시기 바랍니다.', 265, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '고막염', '고막염', 'TREATMENT', '고막성형술은 천공되거나 손상된 고막을 복원하여 청력을 회복하고 반복적인 감염을 예방하는 목적으로 시행됩니다. 심한 고막 염증으로 약물 치료만으로 치료가 불충분할 때 피부 이식을 통한 고막성형술이 고려되며, 수술 후 외부 감염 경로를 차단해 재발을 줄이는 장점이 있습니다. 그러나 수술의 적응증과 안전성은 고막 손상 정도, 중이 상태, 전신 건강 상태에 따라 다르므로 이비인후과 전문의와 충분히 상담 후 결정해야 합니다.', 266, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '구강암', '구강암', 'CHECKUP', '구강암 검진 시 육안으로 확인이 어려운 경우 조직 검사(생검)를 통해 암을 확진합니다. 의심 병변 부위에서 국소마취 후 소량의 조직을 채취하여 병리과에서 현미경으로 세포 이상 여부를 검사합니다. 추가적으로 CT, MRI, PET-CT 등 영상 검사를 통해 종양의 크기, 위치, 전이 여부를 평가합니다. 구강 내 지속되는 궤양, 흰 반점, 덩어리 등이 있으면 구강악안면외과 또는 이비인후과 전문의의 진료를 받으시기 바랍니다.', 267, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '구강암', '구강암', 'DIET_LIFE', '입안 염증이 잦고 입냄새가 심할 때는 하루 2~3회 규칙적인 양치질과 치실 사용으로 구강 위생을 철저히 관리해야 합니다. 금연과 절주는 구강암 예방에 가장 중요한 생활 습관이며, 과일·채소·녹황색 식품 등 항산화 영양소가 풍부한 식단이 도움이 됩니다. 가공육, 짠 음식, 과도한 자극성 식품 섭취는 줄이고, 충분한 수분 섭취로 구강을 촉촉하게 유지하는 것이 좋습니다. 증상이 2주 이상 지속되면 구강악안면외과나 이비인후과 전문의의 진료를 받으시기 바랍니다.', 268, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '구강암', '구강암', 'MEDICATION', '구강암의 화학요법(항암 화학요법)에는 시스플라틴(Cisplatin)이 가장 기본적으로 사용되며, 5-플루오로우라실(5-FU), 카보플라틴(Carboplatin), 도세탁셀(Docetaxel), 파클리탁셀(Paclitaxel) 등이 병용 요법으로 사용됩니다. 최근에는 표적 치료제인 세툭시맙(Cetuximab, EGFR 억제제)이 재발·전이성 두경부암에 사용되고 있으며, 면역 항암제(니볼루맙, 펨브롤리주맙)도 사용됩니다. 약물 선택과 용량은 암의 병기, 전신 상태, 다른 치료와의 병용 여부에 따라 결정되므로 종양내과 전문의의 지도 아래 치료받으시기 바랍니다.', 269, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '구강암', '구강암', 'PREVENTION', '구강암 예방을 위해 금연과 절주 외에도 인유두종바이러스(HPV) 백신 접종이 구강인두암 예방에 도움이 됩니다. 정기적인 구강 검진(연 1~2회)을 통해 이상 병변을 조기 발견하는 것이 중요하며, 잘 맞지 않는 틀니나 날카로운 치아로 인한 만성 자극을 제거해야 합니다. 과일, 채소 위주의 균형 잡힌 식단을 유지하고 자외선 노출 시 입술 보호제를 사용하는 것도 도움이 됩니다. 구강 내 변화(궤양, 반점, 덩어리)가 2주 이상 지속되면 즉시 전문의 진료를 받으시기 바랍니다.', 270, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '구강암', '구강암', 'EXERCISE', '구강암이 있거나 치료 중인 경우 운동을 시작하기 전에 반드시 담당 주치의와 상담하여 현재 건강 상태와 치료 단계에 맞는 운동 계획을 수립해야 합니다. 수술 후나 방사선·항암 치료 중에는 면역력 저하, 피로, 영양 불량 상태일 수 있어 격렬한 운동은 피해야 합니다. 가벼운 걷기나 스트레칭은 피로 감소와 체력 유지에 도움이 되나, 구강 주변에 외상이 가해지는 운동은 피해야 합니다. 구강암 관련 운동 재활 계획은 종양내과 또는 재활의학과 전문의와 협의하시기 바랍니다.', 271, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '구강암', '구강암', 'CAUSE', '구강 위생 불량으로 세균이 과도하게 증식하면 만성 구강 점막 자극과 염증이 지속되며, 이는 구강 세포의 DNA 손상과 암세포 발생 위험을 높입니다. 특히 구강 내 세균(예: 스트렙토코쿠스 뮤탄스 등)이 생성하는 독소와 염증 매개 물질이 점막을 지속적으로 손상시켜 암 전구 병변으로 진행될 수 있습니다. 그러나 구강암의 가장 중요한 위험 요인은 흡연과 음주이며, 구강 위생 불량은 보조적 위험 요인입니다. 구강 건강 유지를 위해 규칙적인 양치질과 정기 치과 검진을 받으시기 바랍니다.', 272, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '구강암', '구강암', 'REHAB', '구강암 수술 후에는 절제 범위와 부위에 따라 저작(씹기), 연하(삼키기), 발음 기능 장애가 나타날 수 있어 재활치료가 중요합니다. 언어치료(연하 훈련, 발음 훈련), 물리치료(경부 운동, 관절 운동), 영양 지원(영양사와 협력한 식이 재활)이 핵심 재활 프로그램입니다. 방사선 치료 후 개구 장애가 있을 경우 개구 훈련 기구를 이용한 재활 운동도 시행합니다. 구강암 재활은 다학제팀(구강악안면외과, 재활의학과, 언어치료사, 영양사)의 협력이 필요하므로 전문 의료기관에서 상담받으시기 바랍니다.', 273, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '구강암', '구강암', 'DEFINITION', '구강암은 혀, 잇몸, 구강저, 볼 점막, 입천장, 입술 등 구강 내 어느 부위에서나 발생할 수 있으며, 혀와 잇몸에 볼록한 덩어리(종괴)가 느껴지는 것은 구강암의 주요 증상 중 하나입니다. 이 외에도 2주 이상 낫지 않는 구강 궤양, 붉거나 흰 반점(홍반증·백반증), 입안의 통증, 씹거나 삼키기 어려움, 혀 움직임 제한, 이가 흔들리는 증상 등이 나타날 수 있습니다. 이러한 증상이 지속되면 구강악안면외과나 이비인후과 전문의의 조기 진료가 매우 중요합니다.', 274, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '구강암', '구강암', 'SYMPTOM', '구강암은 주로 혀(특히 혀의 측면과 아랫면), 구강저(혀 아래 바닥), 볼 점막, 잇몸, 입천장, 입술에서 발생하므로 이 부위들을 정기적으로 확인해야 합니다. 확인 방법으로는 거울 앞에서 입을 크게 벌려 혀를 올리고 내리며 전체 구강 점막을 육안으로 관찰하는 것이 좋습니다. 낫지 않는 궤양, 색 변화(흰색·붉은색 반점), 덩어리, 부종, 출혈이 있는 부위는 즉시 전문의 진료가 필요합니다. 구강암 자가 검진은 월 1회 정기적으로 시행하고, 연 1~2회 치과 검진을 받으시기 바랍니다.', 275, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '구강암', '구강암', 'DIAGNOSIS', '구강암이 의심되거나 구강 병변 제거 후에는 전신 전이 여부를 평가하기 위해 경부 CT 또는 MRI로 경부 림프절 전이를 확인합니다. 흉부 CT로 폐 전이, PET-CT로 전신 전이 여부를 평가하며, 혈액 검사로 종양표지자와 전신 상태를 확인합니다. 조직 생검을 통한 병리 확진이 최종 진단에 필수적이며, 병기 결정 후 치료 방향을 수립합니다. 모든 검사와 치료 계획은 구강악안면외과, 이비인후과, 종양내과의 다학제 협진으로 진행됩니다.', 276, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '구강암', '구강암', 'TREATMENT', '구강암의 가장 효과적인 치료 방법은 병기와 위치에 따라 다르며, 초기(1~2기)에는 수술적 절제가 표준 치료입니다. 진행된 경우(3~4기)에는 수술 후 방사선 치료, 또는 방사선+항암화학요법 병합 치료가 시행됩니다. 통증 조절을 위해 진통제(NSAIDs, 아편계 진통제), 스테로이드, 신경 차단술 등이 병행될 수 있습니다. 구강암 치료는 병기, 전신 상태, 기능 보존 여부를 고려하여 구강악안면외과·종양내과 등 다학제팀의 전문 상담을 통해 결정해야 합니다.', 277, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '급성 중이염', '급성중이염', 'CHECKUP', '귀가 아픈 증상이 있을 때 이비인후과에서 이경 검사, 청력 검사(순음청력검사), 고막 운동성 검사(임피던스 검사) 등을 받으면 중이염, 외이염, 고막 천공 등을 감별하고 예방적 조치를 취할 수 있습니다. 귀 통증이 턱관절 이상이나 인후 질환과 관련될 수 있으므로 필요시 영상 검사도 추가됩니다. 귀 통증은 다양한 원인이 있으므로 증상이 48시간 이상 지속되거나 고열, 청력 저하가 동반되면 이비인후과 전문의의 진료를 받으시기 바랍니다.', 278, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '급성 중이염', '급성중이염', 'DIET_LIFE', '급성 중이염으로 인한 귀 통증과 염증 완화를 위해 충분한 수분 섭취와 균형 잡힌 영양 섭취가 중요하며, 특히 비타민 C와 아연이 풍부한 식품이 면역력 회복에 도움이 됩니다. 코를 세게 풀지 않고 한쪽씩 부드럽게 풀어야 유스타키오관을 통한 세균의 중이 침투를 막을 수 있습니다. 수영이나 물에 귀가 닿는 활동을 피하고, 금연·간접흡연 노출을 차단하는 것이 회복에 도움이 됩니다. 귀에서 고름이 나오거나 증상이 악화되면 이비인후과 전문의의 진료를 받으시기 바랍니다.', 279, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '급성 중이염', '급성중이염', 'MEDICATION', '급성 중이염 약물 치료 후 회복 경과 모니터링을 위해 항생제 치료 시작 48~72시간 후 증상 호전 여부(발열, 귀 통증 감소)를 확인하는 것이 중요합니다. 치료 종료 후 2~4주 뒤 이비인후과 재방문을 통해 이경 검사와 고막 운동성 검사(임피던스 검사)로 삼출액 잔존 여부 및 청력을 평가합니다. 증상이 호전되지 않거나 72시간 내 악화될 경우 항생제 변경 또는 고막 절개술을 고려해야 합니다. 정기적인 추적 관찰과 치료 반응 평가는 이비인후과 전문의와 함께 진행하시기 바랍니다.', 280, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '급성 중이염', '급성중이염', 'PREVENTION', '건강한 생활 습관, 충분한 수면, 균형 잡힌 식단은 면역력을 강화하여 상기도 감염(감기, 독감)으로 인한 유스타키오관 기능 장애를 예방하는 데 도움이 됩니다. 상기도 감염은 급성 중이염의 가장 흔한 원인이므로 면역력 유지가 중이염 예방의 핵심입니다. 특히 소아에서는 모유 수유, 폐구균·인플루엔자 백신 접종, 수동 흡연 노출 차단이 중이염 예방에 중요합니다. 중이염이 반복되거나 지속될 경우 이비인후과 전문의의 진료와 상담을 받으시기 바랍니다.', 281, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '급성 중이염', '급성중이염', 'EXERCISE', '급성 중이염으로 고름이 나올 때 축구 등 격렬한 운동을 하면, 신체 활동으로 인한 압력 변화와 진동이 염증이 있는 중이에 자극을 주어 통증이 악화될 수 있습니다. 또한 발한으로 인한 탈수, 면역력 소모, 외이도로 땀이 유입되어 감염이 악화될 수 있습니다. 고막 천공이 동반된 경우 외부 오염물질이 중이로 침투하는 위험이 증가합니다. 증상이 완전히 회복되고 이비인후과 전문의의 운동 허가를 받은 후 운동을 재개하시기 바랍니다.', 282, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '급성 중이염', '급성중이염', 'CAUSE', '급성 중이염은 주로 세균(폐구균, 헤모필루스 인플루엔자균 등) 또는 바이러스에 의한 중이 감염으로 발생하며, 감염으로 인해 중이 내 고름(삼출액)이 축적됩니다. 고름이 많아져 고막 내 압력이 높아지면 고막이 파열되어 외이도로 고름이 흘러나오게 됩니다. 이때 귀 통증이 갑자기 완화되고, 귀에서 노란색 또는 녹색 분비물이 나오며, 청력 저하와 이명이 동반될 수 있습니다. 이러한 증상이 나타나면 즉시 이비인후과 전문의의 진료를 받으시기 바랍니다.', 283, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '급성 중이염', '급성중이염', 'REHAB', '급성 중이염 회복 후 재활을 위해 항생제 치료로 감염을 제어하는 것이 가장 기본적인 치료이며, 증상 완화를 위해 진통제(아세트아미노펜, 이부프로펜)를 사용할 수 있습니다. 청력 저하가 지속되는 경우 청력 재활로 보청기 사용이나 청각 훈련이 필요할 수 있습니다. 삼출성 중이염이 지속될 경우 환기관 삽입술이 청력 회복에 도움이 됩니다. 발열, 분비물, 청력 저하 등의 증상이 치료 후에도 지속되면 이비인후과 전문의의 추적 진료가 필요합니다.', 284, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '급성 중이염', '급성중이염', 'DEFINITION', '중이염은 고막 안쪽 공간인 중이에 세균이나 바이러스 감염으로 염증이 발생하는 질환으로, 주로 코와 중이를 연결하는 유스타키오관 기능 장애로 인해 발생합니다. 상기도 감염(감기, 독감) 후 세균이 유스타키오관을 통해 중이로 침투하거나, 관이 막혀 중이 내 압력이 변화하면서 삼출액이 고이게 됩니다. 주요 증상으로는 귀 통증, 발열, 청력 저하, 귀 충만감, 이루(고막 천공 시 분비물) 등이 있습니다. 증상이 지속되거나 악화되면 이비인후과 전문의의 진료를 받으시기 바랍니다.', 285, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '급성 중이염', '급성중이염', 'SYMPTOM', '급성 중이염의 귀 통증은 중이 내 압력 상승으로 인해 발생하며, 특히 밤에 심해지는 경향이 있습니다. 청력 저하는 중이 내 삼출액이 고막과 이소골의 진동을 방해하여 발생하는 전음성 난청입니다. 이 외에도 38도 이상의 발열, 이명, 귀 충만감(먹먹함), 영유아에서는 보챔·귀 잡아당기기·수유 거부 등의 증상이 나타날 수 있습니다. 이러한 증상이 나타나면 이비인후과 전문의의 진료를 받으시기 바랍니다.', 286, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '급성 중이염', '급성중이염', 'DIAGNOSIS', '감기와 관련된 귀 통증과 고열로 이비인후과를 방문하면 우선 이경 검사 또는 비디오 이경 검사를 통해 고막 상태(발적, 팽윤, 천공, 삼출액 여부)를 확인합니다. 고막 운동성 검사(임피던스 검사, 티폼패니메트리)로 중이 내 삼출액과 유스타키오관 기능을 평가하며, 청력 검사로 청력 손실 정도를 확인합니다. 필요에 따라 비강 내시경, 혈액 검사(염증 수치), 배양 검사를 추가로 시행할 수 있습니다. 검사 결과에 따라 항생제 처방 여부와 치료 방향이 결정됩니다.', 287, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '급성 중이염', '급성중이염', 'TREATMENT', '급성 중이염의 경우 모든 환자에게 항생제가 반드시 필요한 것은 아닙니다. 2세 이상의 소아나 성인에서 증상이 경미하고 양측성이 아닌 경우, 48~72시간 경과 관찰(watchful waiting)을 먼저 시행할 수 있습니다. 이 기간 동안 충분한 수분 섭취, 진통·해열제(아세트아미노펜, 이부프로펜) 사용, 충분한 휴식을 취하면 면역력으로 자연 치유가 가능합니다. 단, 2세 미만 영아, 양측성 중이염, 고막 천공, 심한 증상에서는 항생제 치료가 필요하므로 이비인후과 전문의와 상담하시기 바랍니다.', 288, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '꽃가루 알레르기', '꽃가루알레르기', 'DIET_LIFE', '꽃가루 알레르기는 면역 과민 반응으로 코막힘, 재채기, 콧물 등 호흡기 증상과 눈 충혈 등을 유발하며, 영양 불균형 상태에서 더 악화될 수 있습니다. 알레르기 반응 관리에 도움이 되는 식단으로는 항염 효과가 있는 오메가-3 지방산(등 푸른 생선, 아마씨), 비타민 C(감귤류, 파프리카), 비타민 D, 퀘르세틴(양파, 사과)이 풍부한 식품을 권장합니다. 유제품, 밀가루, 인공 첨가물 등 염증을 촉진할 수 있는 식품은 개인에 따라 제한이 도움이 될 수 있습니다. 구체적인 식이 및 영양제 계획은 알레르기내과 전문의와 상담하시기 바랍니다.', 289, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '꽃가루 알레르기', '꽃가루알레르기', 'MEDICATION', '꽃가루 알레르기 증상 치료에는 2세대 항히스타민제(로라타딘, 세티리진, 펙소페나딘 등)가 재채기, 콧물, 가려움증에 효과적이며, 졸음 부작용이 적습니다. 코막힘에는 비강 내 스테로이드 스프레이(플루티카손, 부데소나이드 등)가 가장 효과적인 약물로 권장됩니다. 근본적인 치료로는 알레르기 면역요법(탈감작 치료)이 있으며, 피하 주사(SCIT) 또는 설하 투여(SLIT) 방식으로 3~5년간 시행합니다. 약물 선택과 면역요법 적응증은 알레르기내과 또는 이비인후과 전문의와 상담하시기 바랍니다.', 290, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '꽃가루 알레르기', '꽃가루알레르기', 'PREVENTION', '봄에 꽃가루 알레르기가 심한 이유는 수목류(자작나무, 오리나무, 삼나무 등)의 꽃가루가 봄철(2~5월)에 대량으로 비산하며, 건조하고 바람이 많은 날씨에 공기 중 농도가 높아지기 때문입니다. 예방을 위해 꽃가루 농도가 높은 날(건조하고 바람이 강한 맑은 날 오전)에는 외출을 자제하고, 외출 시 마스크와 안경을 착용해야 합니다. 귀가 후 세안·세발·양치질로 꽃가루를 제거하고, 환기보다는 공기청정기 사용을 권장합니다. 증상이 심한 경우 알레르기내과 전문의의 처방에 따라 봄 시즌 전부터 예방 약물을 시작하는 것이 효과적입니다.', 291, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '꽃가루 알레르기', '꽃가루알레르기', 'CAUSE', '삼나무, 오리나무, 자작나무의 꽃가루는 입자가 매우 작고 가벼워 공기 중에 넓게 퍼지며, 이 꽃가루에 포함된 단백질이 알레르기 환자의 면역계를 자극하여 과민 반응을 일으키는 항원(알레르겐)으로 작용합니다. 삼나무(Cry j 1, Cry j 2), 오리나무(Aln g 1), 자작나무(Bet v 1) 꽃가루 단백질이 주요 알레르겐이며, 구조적 유사성으로 인해 교차 반응이 나타나 사과, 복숭아, 헤이즐넛 등 일부 식품 알레르기와도 연관될 수 있습니다. 꽃가루 알레르기 원인 검사(피부반응 검사 또는 혈청 특이 IgE 검사)를 통해 알레르겐을 확인하고 전문의와 상담하시기 바랍니다.', 292, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '꽃가루 알레르기', '꽃가루알레르기', 'DEFINITION', '꽃가루 알레르기(화분증)는 나무, 잡초, 풀의 꽃가루가 호흡기와 눈의 점막에 닿아 면역 과민 반응(IgE 매개 반응)을 일으키는 계절성 알레르기 질환입니다. 주요 증상으로는 재채기, 맑은 콧물, 코막힘, 눈 가려움증·충혈(알레르기 결막염), 코·목·귀의 가려움증 등이 있으며, 특정 꽃가루 계절에 반복적으로 나타나는 것이 특징입니다. 봄(수목류), 여름(잔디), 가을(돼지풀 등 잡초) 등 계절별로 원인 꽃가루가 다릅니다. 알레르기내과 또는 이비인후과에서 알레르기 검사를 통해 원인 알레르겐을 확인하시기 바랍니다.', 293, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '꽃가루 알레르기', '꽃가루알레르기', 'SYMPTOM', '재채기가 계속되는 것은 꽃가루 알레르기의 대표적인 증상 중 하나입니다. 꽃가루 알레르기의 특징적인 증상에는 반복적인 연속 재채기, 맑고 묽은 콧물, 코막힘, 눈·코·목·귀의 가려움증, 눈의 충혈과 눈물, 후비루(코 뒤로 넘어감)로 인한 기침 등이 있습니다. 증상이 특정 계절에 반복적으로 나타나고 꽃가루 농도가 높은 날 악화되는 패턴이 특징적입니다. 증상이 심하거나 일상생활에 지장이 있을 경우 알레르기내과 전문의의 진료를 받으시기 바랍니다.', 294, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '꽃가루 알레르기', '꽃가루알레르기', 'DIAGNOSIS', '꽃가루 알레르기 진단 시 모든 종류의 꽃가루에서 반응이 나타나야 하는 것은 아닙니다. 피부반응 검사(SPT)나 혈청 특이 IgE 검사에서 증상을 유발하는 특정 꽃가루 알레르겐에 대한 양성 반응과 임상 증상이 일치할 때 진단됩니다. 한 가지 이상의 알레르겐에 감작될 수 있으며, 진단을 위해 반드시 모든 꽃가루에 반응할 필요는 없습니다. 정확한 알레르겐 파악을 위해 알레르기내과 또는 이비인후과 전문의에서 표준화된 알레르기 검사를 받으시기 바랍니다.', 295, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '꽃가루 알레르기', '꽃가루알레르기', 'TREATMENT', '봄에 재채기와 콧물이 지속된다면 꽃가루 알레르기 가능성이 높으며, 특히 특정 계절에만 반복된다면 더욱 의심할 수 있습니다. 치료 방법으로는 원인 알레르겐 회피(외출 자제, 마스크 착용), 약물 치료(항히스타민제, 비강 내 스테로이드 스프레이, 류코트리엔 수용체 길항제), 면역 치료(3~5년간 알레르기 주사 또는 설하 면역요법)가 있습니다. 면역 치료는 알레르기 반응 자체를 근본적으로 줄여주는 유일한 치료법입니다. 정확한 원인 알레르겐 확인과 치료 계획은 알레르기내과 전문의와 상담하시기 바랍니다.', 296, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '난청', '난청', 'CHECKUP', '전신 가려움증과 청력 저하(난청)가 동시에 나타났을 때는 전신 질환(자가면역 질환, 신장 질환, 갑상선 질환 등)의 가능성을 고려해야 하므로 이비인후과와 내과(류마티스내과, 신장내과 등) 협진이 필요합니다. 청력 저하가 주 증상이라면 이비인후과에서 청력 검사, 이경 검사, 뇌간 유발 반응 검사 등을 먼저 시행하는 것이 좋습니다. 전신 가려움증의 원인 파악을 위해 피부과 진료도 병행하는 것이 도움이 됩니다. 다양한 원인이 있을 수 있으므로 이비인후과 및 관련 전문의의 진료를 받으시기 바랍니다.', 297, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '난청', '난청', 'DIET_LIFE', '난청 자체를 식이나 생활습관만으로 완전히 회복시키기는 어렵지만, 혈관 건강 유지가 달팽이관(내이) 기능에 중요합니다. 포화지방, 나트륨 섭취를 줄이고 오메가-3 지방산(등 푸른 생선), 항산화 식품(과일, 채소), 마그네슘이 풍부한 식품(견과류, 통곡물)을 섭취하면 내이 혈류 개선에 도움이 될 수 있습니다. 과도한 소음 노출을 피하고, 금연, 규칙적인 유산소 운동, 혈압·혈당·콜레스테롤 관리가 난청 악화 예방에 중요합니다. 난청의 원인과 종류에 따라 적합한 치료가 다르므로 이비인후과 전문의의 진료를 받으시기 바랍니다.', 298, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '난청', '난청', 'MEDICATION', '전음성 난청은 외이도 폐쇄, 고막 천공, 중이 삼출액, 이소골 이상 등으로 인해 소리 전달 경로에 문제가 생긴 경우로, 원인에 따라 항생제, 항염증제(스테로이드 포함) 등 약물 치료가 효과적일 수 있습니다. 그러나 단순 비스테로이드 항염증제(NSAIDs)만으로는 한계가 있으며, 원인에 따라 환기관 삽입술, 고막 성형술, 이소골 성형술 등 수술적 치료가 근본적인 해결 방법이 됩니다. 감각신경성 난청의 경우 보청기나 인공와우 이식이 주요 치료 수단입니다. 난청의 유형과 원인에 따른 적절한 치료 방향은 이비인후과 전문의와 상담하시기 바랍니다.', 299, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '난청', '난청', 'PREVENTION', '공장 등 소음이 심한 환경에서 장시간 노출되면 달팽이관(코르티 기관)의 유모세포가 손상되어 소음성 난청(직업성 난청)이 발생할 수 있습니다. 예방을 위해 소음이 85dB(A) 이상인 작업 환경에서는 청력 보호구(귀마개, 귀덮개)를 반드시 착용해야 합니다. 1일 소음 노출 시간을 줄이고, 청력 보호구 미착용 시 연속 노출 시간을 제한하는 것이 중요합니다. 정기적인 청력 검사(연 1회 이상)를 통해 조기 이상 신호를 발견하고, 이상이 있으면 이비인후과 전문의와 상담하시기 바랍니다.', 300, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '난청', '난청', 'EXERCISE', '메니에르병의 어지럼증 발작이 없는 안정기에는 균형 재활 운동, 걷기, 수영(물이 귀에 들어가지 않도록 귀마개 착용), 요가, 태극권 등이 전정 기능 회복과 증상 완화에 도움이 됩니다. 돌발성 난청의 경우 급성기에는 충분한 안정과 스트레스 관리가 중요하며, 치료 후 회복기에 가벼운 유산소 운동을 점진적으로 시작할 수 있습니다. 수중 훈련이나 평형 훈련이 전정 재활에 효과적입니다. 운동 시작과 강도 조절은 반드시 이비인후과 전문의와 상담 후 진행하시기 바랍니다.', 301, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '난청', '난청', 'CAUSE', '지속적인 소음(85dB 이상)에 장시간 노출되면 달팽이관 유모세포가 물리적·화학적으로 손상되어 소음성 난청이 심화됩니다. 소음은 내이 혈관 수축과 산화 스트레스를 유발하여 유모세포를 파괴하며, 이미 손상된 유모세포는 재생되지 않아 누적적으로 청력이 악화됩니다. 고주파수(4000Hz) 영역의 청력 손실이 먼저 나타나다가 점차 전 주파수로 확대됩니다. 청력 보호구 착용, 소음 노출 시간 제한, 정기 청력 검사가 필수적이며, 이상 시 이비인후과 전문의의 진료를 받으시기 바랍니다.', 302, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '난청', '난청', 'REHAB', '난청 자체를 운동으로 직접 치료하기는 어렵지만, 유산소 운동(걷기, 자전거, 수영)은 내이 혈류를 개선하고 심혈관 건강을 유지하여 감각신경성 난청 진행을 늦추는 데 도움이 될 수 있습니다. 메니에르병이나 전정 기능 장애가 동반된 경우 균형 훈련, 전정 재활 운동(Vestibular rehabilitation therapy)이 어지럼증과 불균형 완화에 효과적입니다. 보청기를 사용하는 경우 청각 훈련 프로그램을 병행하면 언어 이해 능력 향상에 도움이 됩니다. 난청의 종류에 맞는 적절한 재활 계획은 이비인후과 또는 청각학 전문가와 상담하시기 바랍니다.', 303, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '난청', '난청', 'DEFINITION', '노인성 난청은 나이가 들면서 달팽이관과 청신경의 퇴행성 변화로 인해 발생하는 감각신경성 난청으로, 주로 고주파수 대역의 청력이 먼저 저하됩니다. 주요 원인으로는 유모세포와 청신경의 점진적 소실, 내이 혈관 경화(혈류 감소), 중추 청각 처리 능력 저하, 장기간 소음 노출 누적, 동맥경화, 당뇨병 등 혈관 질환이 있습니다. 나이가 들수록 산화 스트레스 축적, 세포 재생 능력 감소, 만성 질환 증가로 인해 발생 빈도가 높아집니다. 정기적인 청력 검사로 조기 발견하고 이비인후과 전문의와 상담하시기 바랍니다.', 304, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '난청', '난청', 'SYMPTOM', '이명(귀울림)과 소리가 작게 들리는 증상은 감각신경성 난청의 대표적인 증상으로, 달팽이관이나 청신경 손상과 관련이 있습니다. 이러한 증상은 노인성 난청, 소음성 난청, 돌발성 난청, 메니에르병, 청신경종 등 다양한 귀 질환에서 나타날 수 있습니다. 특히 돌발성 난청은 수일 내에 갑자기 한쪽 청력이 저하되며 이명이 동반되는 응급 상황으로 즉각적인 치료가 필요합니다. 정확한 원인 파악을 위해 이비인후과 전문의의 진료와 청력 검사를 받으시기 바랍니다.', 305, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '난청', '난청', 'DIAGNOSIS', '청력 저하 없이 이명만 나타나는 경우도 있으며, 이는 반드시 난청을 의미하지는 않습니다. 그러나 이명은 초기 난청의 전조 증상일 수 있으므로 순음청력검사, 고주파 청력 검사, 이명 검사(이명 주파수 및 강도 측정)를 통해 난청 여부를 확인하는 것이 중요합니다. 이명의 원인은 난청 외에도 청신경종, 혈관성 이명, 턱관절 이상, 약물 부작용 등 다양하므로 청력 정상이어도 이비인후과 전문의의 진료가 필요합니다. 이명이 2주 이상 지속되거나 갑자기 발생했다면 빠른 시일 내에 이비인후과를 방문하시기 바랍니다.', 306, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '난청', '난청', 'TREATMENT', '이명과 대화 소리가 잘 들리지 않는 난청 증상이 있을 때는 이비인후과(이비인후과 전문 클리닉, 대학병원 이비인후과)를 방문하면 됩니다. 이비인후과에서 순음청력검사, 어음청력검사, 임피던스 검사, 이명 검사 등을 통해 난청의 종류와 정도를 정확히 파악합니다. 감각신경성 난청 진단 시 보청기 전문가(청각사)와 협력하여 보청기 처방, 청각 재활 훈련 계획을 수립합니다. 증상이 갑자기 발생하거나 급격히 악화될 경우 응급 상황일 수 있으므로 즉시 이비인후과 전문의를 방문하시기 바랍니다.', 307, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '노인성 난청', '노인성난청', 'CHECKUP', '노인성 난청 검진을 위해 이비인후과를 방문하면 기본 청력 검사인 순음청력검사(PTA)를 시행하여 주파수별 청력 역치를 측정합니다. 어음청력검사(SRT, SDS)로 언어 이해 능력을 평가하며, 이경 검사로 외이와 고막 상태, 임피던스 검사로 중이 기능을 확인합니다. 노인성 난청은 일반 청력 검사 외에도 고주파 청력 검사가 초기 변화를 발견하는 데 유용합니다. 65세 이상 어르신은 정기적인 청력 검진을 받고, 이상 발견 시 이비인후과 전문의와 상담하시기 바랍니다.', 308, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '노인성 난청', '노인성난청', 'DIET_LIFE', '노인성 난청 환자가 TV 볼륨을 크게(85dB 이상) 틀고 장시간 시청하면 이미 손상된 달팽이관에 추가적인 소음 손상이 누적되어 청력이 더 빠르게 악화될 수 있습니다. 또한 가족이나 동거인이 과도한 소음에 노출되어 청력에 영향을 받을 수 있습니다. 자막 활용, 보청기 착용으로 적정 볼륨에서도 내용을 이해할 수 있도록 하는 것이 청력 보호에 도움이 됩니다. 적절한 보청기 처방을 위해 이비인후과 전문의와 청각사의 상담을 권장합니다.', 309, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '노인성 난청', '노인성난청', 'MEDICATION', '일부 혈압약(이뇨제 중 루프 이뇨제: 푸로세미드, 에타크린산 등)은 이독성(귀 독성)이 있어 달팽이관 기능에 영향을 줄 수 있으며, 노인성 난청이 있는 경우 청력 악화에 기여할 수 있습니다. 그러나 일반적인 혈압약(칼슘 길항제, ACE 억제제, 안지오텐신 수용체 차단제 등)은 직접적인 이독성이 없으며, 오히려 심혈관 건강 관리가 내이 혈류 유지에 도움이 됩니다. 복용 중인 약물의 이독성 여부와 청력에 미치는 영향은 담당 내과 및 이비인후과 전문의와 반드시 상담하시기 바랍니다.', 310, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '노인성 난청', '노인성난청', 'PREVENTION', '노인성 난청 예방에서 배우자의 코골이보다는 본인의 소음 노출 차단이 더 직접적인 예방 요소입니다. 다만 코골이로 인한 수면 장애는 수면의 질을 저하시켜 전반적인 건강과 내이 혈류 유지에 부정적인 영향을 줄 수 있습니다. 배우자의 코골이 소음이 85dB 이상이 되는 경우는 드물지만, 수면 환경 개선을 위해 코골이 치료(수면무호흡 검사, 구강내 장치, 양압기 등)를 권장합니다. 노인성 난청 예방의 핵심은 소음 회피, 심혈관 위험 인자 관리, 정기 청력 검진이며, 이비인후과 전문의와 상담하시기 바랍니다.', 311, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '노인성 난청', '노인성난청', 'EXERCISE', '노인성 난청 진단을 받으신 할아버지께는 청력에 무리를 주지 않으면서 전반적인 건강 유지에 도움이 되는 운동이 좋습니다. 걷기, 가벼운 조깅, 수중 걷기(아쿠아 워킹), 태극권, 실내 자전거, 스트레칭 등 낙상 위험이 낮고 심혈관 건강에 좋은 유산소 운동을 권장합니다. 균형 감각 훈련(한 발 서기, 균형 보드 운동)은 노인에서 흔히 동반되는 전정 기능 저하와 낙상 예방에도 도움이 됩니다. 운동 시작 전에 내과 및 이비인후과 전문의의 진료를 받아 건강 상태에 맞는 운동 계획을 세우시기 바랍니다.', 312, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '노인성 난청', '노인성난청', 'CAUSE', '노인성 난청은 달팽이관 내 유모세포의 퇴행성 소실로 인해 소리 자극을 전기 신호로 변환하는 능력이 저하되어 소리가 잘 들리지 않게 됩니다. 특히 고주파수(고음역) 소리를 먼저 듣지 못하게 되며, 이는 자음 구별 능력 저하로 이어져 말소리는 들리지만 내용을 이해하기 어려운 특징을 보입니다. 배경 소음이 있는 환경에서 특히 대화 이해가 어려워지며, 이는 일상생활과 사회적 교류에 큰 영향을 미칩니다. 적절한 시기에 보청기를 착용하면 의사소통과 삶의 질 향상에 크게 도움이 되므로 이비인후과 전문의와 상담하시기 바랍니다.', 313, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '노인성 난청', '노인성난청', 'REHAB', '노인성 난청의 초기 증상을 식별하기 위한 가장 기본적인 검진은 이비인후과에서의 순음청력검사(PTA)이며, 주파수별 청력 역치를 측정하여 이상 여부를 확인합니다. 초기 노인성 난청의 주요 증상으로는 TV 볼륨을 높이는 경향, 전화 통화의 어려움, 배경 소음 속 대화 이해 곤란, 타인의 말을 자주 되묻는 것, 특정 고음(초인종, 새소리 등)이 안 들리는 것 등이 있습니다. 65세 이상에서는 연 1회 청력 검진을 권장하며, 이러한 증상이 나타나면 이비인후과 전문의의 진료를 받으시기 바랍니다.', 314, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '노인성 난청', '노인성난청', 'DEFINITION', '노인성 난청(presbycusis)은 나이 들면서 청각 기관의 퇴행성 변화로 인해 점진적으로 청력이 저하되는 질환으로, 65세 이상 인구의 약 30%, 75세 이상에서는 약 50%에서 나타나는 흔한 노화 관련 질환입니다. 특징으로는 양측 귀에 대칭적으로 발생하고, 고주파수(4000~8000Hz) 청력이 먼저 저하되어 점차 저주파수로 진행되며, 말소리는 들리지만 내용을 이해하기 어렵다는 점이 있습니다. 이명이 동반되는 경우가 많으며, 완치는 어렵지만 보청기와 청각 재활로 의사소통 능력을 향상시킬 수 있습니다.', 315, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '노인성 난청', '노인성난청', 'SYMPTOM', '직장에서 소음에 많이 노출되어 귀가 먹먹하고 어지러움을 느끼는 경우, 소음성 난청의 초기 증상일 가능성이 있으나 노인성 난청과는 구별이 필요합니다. 노인성 난청은 나이에 따른 퇴행성 변화가 주 원인이며, 소음성 난청은 소음 누적 노출이 주 원인으로 두 가지가 복합적으로 나타날 수 있습니다. 귀 먹먹함과 어지러움이 동반될 경우 메니에르병이나 전정 기능 이상도 감별 진단이 필요합니다. 증상 감별을 위해 이비인후과 전문의의 청력 검사와 전정 기능 검사를 받으시기 바랍니다.', 316, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '노인성 난청', '노인성난청', 'DIAGNOSIS', '노인성 난청 의심 시에는 이비인후과 전문의에게 진단받는 것이 가장 정확합니다. 이비인후과에서는 이경 검사, 순음청력검사, 어음청력검사, 임피던스 검사 등을 통해 난청의 유형(감각신경성, 전음성, 혼합성)과 정도를 종합적으로 평가합니다. 필요한 경우 뇌간 유발 전위 검사(ABR), 이음향 방사 검사(OAE) 등 추가 검사로 달팽이관과 청신경의 기능을 정밀하게 평가합니다. 진단 후 보청기 처방이 필요한 경우 청각사(audiologist)와 협력하여 최적의 보청기를 선택하게 됩니다.', 317, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '노인성 난청', '노인성난청', 'TREATMENT', '노인성 난청으로 인한 청력 저하와 이명 치료에는 현재까지 청력을 완전히 회복시키는 약물 치료는 없습니다. 가장 효과적인 치료는 보청기 착용으로, 잔존 청력을 증폭하여 의사소통 능력을 향상시킵니다. 고도~심도 난청으로 보청기로 효과가 없는 경우 인공와우(cochlear implant) 이식 수술을 고려할 수 있습니다. 이명 완화를 위해서는 이명 재훈련 치료(TRT), 소리 치료(음향 요법), 인지행동치료가 도움이 되며, 이비인후과 전문의와 상담하여 개인 상태에 맞는 치료 계획을 수립하시기 바랍니다.', 318, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 부비동염', '만성부비동염', 'CHECKUP', '만성 부비동염 확인을 위해 이비인후과를 방문하면 비강 내시경 검사로 비강 내 점막 상태, 부비동 개구부 폐쇄, 용종 여부를 직접 관찰합니다. 부비동 CT 촬영은 만성 부비동염의 병변 범위, 해부학적 이상, 부비동 내 점막 비후 및 삼출액 여부를 가장 정확하게 평가하는 표준 검사입니다. 알레르기가 의심되는 경우 알레르기 피부반응 검사나 혈청 특이 IgE 검사를 추가합니다. 증상이 12주 이상 지속되면 만성 부비동염을 의심하고 이비인후과 전문의의 진료를 받으시기 바랍니다.', 319, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 부비동염', '만성부비동염', 'DIET_LIFE', '알레르기성 비염이 있는 경우 알레르기 반응을 촉진할 수 있는 히스타민이 풍부한 음식(발효식품, 알코올, 치즈, 훈제 식품), 인공 색소·방부제가 많은 가공식품, 아황산염이 포함된 식품(말린 과일, 와인) 등은 주의가 필요합니다. 개인에 따라 유제품이나 밀가루 섭취 후 비염 증상이 악화될 수 있으므로 식이 일지를 기록하여 유발 식품을 파악하는 것이 도움이 됩니다. 실내 알레르겐(집먼지 진드기, 반려동물 비듬, 곰팡이) 제거, 금연, 충분한 수분 섭취, 규칙적인 코 세척도 비염 관리에 중요합니다. 알레르기 검사를 통한 원인 파악과 치료 계획은 이비인후과 또는 알레르기내과 전문의와 상담하시기 바랍니다.', 320, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 부비동염', '만성부비동염', 'MEDICATION', '만성 부비동염에서 비강 내 스테로이드 스프레이(플루티카손, 모메타손 등)는 부비동 점막의 염증과 부종을 효과적으로 감소시켜 배농 통로를 확보하고 코막힘을 완화하는 데 권장됩니다. 식염수 코 세척(비강 세척)은 부비동 내 분비물과 염증 물질, 알레르겐을 물리적으로 제거하여 점막 섬모 기능 회복을 돕습니다. 세균 감염이 동반된 경우 항생제(아목시실린-클라부란산, 독시사이클린 등)가 사용됩니다. 약물 선택과 기간은 증상 정도와 원인에 따라 달라지므로 이비인후과 전문의와 상담하시기 바랍니다.', 321, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 부비동염', '만성부비동염', 'PREVENTION', '알레르기 질환으로 인한 만성 부비동염 예방을 위해서는 원인 알레르겐(집먼지 진드기, 꽃가루, 반려동물 등)을 파악하고 노출을 최소화하는 것이 가장 중요합니다. 알레르기성 비염 치료(항히스타민제, 비강 스테로이드, 면역요법)를 적극적으로 시행하여 비강 점막 염증과 유스타키오관 기능 장애를 예방합니다. 규칙적인 식염수 코 세척, 실내 습도(40~60%) 및 온도 유지, 공기청정기 사용, 금연이 도움이 됩니다. 알레르기 및 만성 부비동염의 체계적인 관리는 이비인후과 또는 알레르기내과 전문의와 상담하시기 바랍니다.', 322, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 부비동염', '만성부비동염', 'EXERCISE', '만성 부비동염으로 인한 코막힘, 안면 압박감, 권태감 완화에 도움이 되는 운동으로는 가벼운 유산소 운동(걷기, 자전거 타기)이 비강 혈류를 개선하고 점막 부종을 줄이는 데 도움이 됩니다. 요가의 호흡 운동(복식호흡, 교호 호흡)과 비강 세척 요법은 코 통기 개선에 효과적입니다. 수영은 습한 환경으로 코 점막을 촉촉하게 유지해 주나, 염소 자극이 증상을 악화시킬 수 있으므로 주의가 필요합니다. 과격한 운동은 부비동 압력을 높일 수 있으므로 증상이 심할 때는 피하고, 이비인후과 전문의의 지도 아래 적절한 운동을 선택하시기 바랍니다.', 323, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 부비동염', '만성부비동염', 'CAUSE', '만성 부비동염과 급성 부비동염은 증상의 지속 기간과 정도에서 차이가 납니다. 급성 부비동염은 주로 세균이나 바이러스 감염 후 갑자기 발생하며, 심한 안면 통증, 발열, 화농성 비루가 특징으로 4주 이내에 해결됩니다. 만성 부비동염은 증상이 12주 이상 지속되며, 알레르기, 해부학적 이상(비중격 만곡, 비용종), 면역 이상, 반복 감염 등 다양한 원인으로 발생하고 점막 비후와 지속적인 코막힘·후비루가 특징입니다. 정확한 원인 파악과 적절한 치료를 위해 이비인후과 전문의의 진료를 받으시기 바랍니다.', 324, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 부비동염', '만성부비동염', 'REHAB', '만성 부비동염 환자의 재활 과정에서는 약물 치료(비강 스테로이드, 식염수 세척)와 함께 비강 세척 요법을 병행하는 것이 분비물 제거와 점막 기능 회복에 매우 효과적입니다. 내시경 부비동 수술(FESS) 후에는 정기적인 비강 내시경 추적 관찰과 식염수 세척을 통해 유착 방지와 부비동 개방 유지가 중요합니다. 알레르기가 원인인 경우 알레르기 면역요법을 병행하고, 구강 호흡을 줄이기 위한 비강 통기 개선 치료와 호흡 훈련도 도움이 됩니다. 수술 후 재활 계획은 이비인후과 전문의와 충분히 상담하시기 바랍니다.', 325, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 부비동염', '만성부비동염', 'DEFINITION', '만성 부비동염은 코 주변의 부비동(공기로 채워진 뼈 속 공간)에 12주 이상 지속적인 염증이 발생하는 질환으로, 코막힘, 화농성 후비루(코 뒤로 넘어가는 분비물), 안면 압박감·통증, 후각 저하 등이 주요 증상입니다. 검진을 위해서는 이비인후과를 방문하여 비강 내시경 검사와 부비동 CT 촬영을 받는 것이 표준 절차입니다. 알레르기가 의심되는 경우 알레르기 검사를 추가로 시행하며, 검사 결과에 따라 약물 치료 또는 수술 치료 계획을 수립합니다. 증상이 2~3주 이상 지속되면 이비인후과 전문의의 진료를 받으시기 바랍니다.', 326, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 부비동염', '만성부비동염', 'SYMPTOM', '만성 부비동염의 녹색 또는 황색 농성 콧물은 세균 감염과 백혈구의 과산화물 효소 반응으로 나타나며, 만성 부비동염에서는 12주 이상 지속될 수 있습니다. 치료 없이 방치하면 수개월~수년간 증상이 지속될 수 있으며, 반복적인 급성 악화 기간에는 증상이 더 심해집니다. 적절한 항생제, 비강 스테로이드, 코 세척 치료를 받으면 수주 내 증상이 호전될 수 있지만, 재발 방지를 위한 지속적 관리가 필요합니다. 녹색 콧물이 2주 이상 지속되면 이비인후과 전문의의 진료를 받으시기 바랍니다.', 327, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 부비동염', '만성부비동염', 'DIAGNOSIS', '만성 부비동염의 정확한 진단을 위해서는 이비인후과를 방문하여 비강 내시경 검사와 부비동 CT 검사를 받는 것이 표준입니다. 식이와 생활습관은 진단 기준에 포함되지 않으나, 알레르기 여부 확인을 위해 알레르기 검사도 함께 시행될 수 있습니다. 전국 이비인후과 의원 및 종합병원 이비인후과에서 검진 및 치료를 받을 수 있으며, 지역 건강보험 공단의 의료기관 찾기 서비스를 통해 가까운 이비인후과를 확인하실 수 있습니다. 증상이 12주 이상 지속된다면 조기에 전문의의 진료를 받으시기 바랍니다.', 328, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 부비동염', '만성부비동염', 'TREATMENT', '만성 부비동염의 약물 외 치료법으로 가장 우선적으로 권장되는 것은 식염수 비강 세척으로, 분비물과 염증 물질 제거에 매우 효과적입니다. 내시경 부비동 수술(FESS, 기능적 내시경 부비동 수술)은 약물 치료에 반응하지 않는 만성 부비동염에서 부비동 개구부를 넓히고 병변을 제거하여 효과적인 치료 효과를 보입니다. 알레르기가 원인인 경우 알레르기 면역요법(탈감작 치료)을 병행하면 재발을 줄일 수 있습니다. 수술적 치료 적응증 판단과 방법은 이비인후과 전문의와 충분히 상담 후 결정하시기 바랍니다.', 329, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 비염', '만성비염', 'CHECKUP', '알레르기 테스트(피부반응 검사 또는 혈청 특이 IgE 검사)를 통해 만성 비염의 알레르기 원인(집먼지 진드기, 꽃가루, 반려동물 등)을 파악하는 데 도움이 됩니다. 알레르기 원인이 확인되면 해당 알레르겐을 회피하고, 알레르기 면역요법을 시행하여 비염 증상을 근본적으로 줄일 수 있습니다. 그러나 만성 비염의 원인이 알레르기 외에도 혈관운동성, 약물 유발성, 감염성 등 다양하므로 알레르기 검사와 함께 이비인후과 전문의의 종합적인 평가가 필요합니다. 알레르기 검사는 이비인후과 또는 알레르기내과에서 받으실 수 있습니다.', 330, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 비염', '만성비염', 'DIET_LIFE', '만성 비염 환자는 히스타민이 많이 함유된 발효식품, 알코올, 훈제 식품, 자극적인 향신료를 피하고, 충분한 수분 섭취로 점막을 촉촉하게 유지하는 것이 도움이 됩니다. 수면 시에는 머리를 약간 높인 자세(15~30도)로 자는 것이 후비루로 인한 기침과 불편감을 줄이는 데 도움이 됩니다. 식사 후 바로 눕는 것은 위산 역류로 인한 비강 자극을 유발할 수 있어, 식후 최소 2~3시간은 앉거나 서 있는 자세를 유지하는 것이 좋습니다. 증상 조절을 위한 식이 및 생활 관리는 이비인후과 전문의와 상담하시기 바랍니다.', 331, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 비염', '만성비염', 'MEDICATION', '만성 비염 약물 치료에서 비강 내 스테로이드 스프레이(플루티카손, 모메타손 등)는 코 점막의 염증을 억제하고 부종을 줄여 코막힘, 콧물, 재채기를 효과적으로 완화하며, 장기 사용이 가능한 안전한 약물입니다. 항히스타민제는 알레르기성 비염에서 재채기, 콧물, 가려움증에 효과적입니다. 비강 수축제(옥시메타졸린 등)는 즉각적인 코막힘 완화 효과가 있지만 3일 이상 사용 시 반동성 비강 충혈(약물성 비염)을 유발할 수 있어 주의가 필요합니다. 약물 사용 방법과 기간은 이비인후과 전문의의 처방에 따라 결정하시기 바랍니다.', 332, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 비염', '만성비염', 'PREVENTION', '만성 비염에서 코막힘, 재채기, 기침은 알레르기 반응, 자율신경계 이상(혈관운동성 비염), 만성 감염, 환경적 자극 등 다양한 원인으로 발생합니다. 알레르기성 비염의 경우 특정 알레르겐(집먼지 진드기, 꽃가루)에 의한 IgE 매개 면역 반응으로 점막 부종과 분비물이 증가합니다. 예방을 위해 알레르겐 회피, 실내 환경 개선(환기, 청소, 공기청정기 사용), 습도 조절, 금연이 중요하며, 알레르기 면역요법이 근본적 예방에 도움이 됩니다. 만성 비염의 원인 파악과 맞춤 치료를 위해 이비인후과 전문의의 진료를 받으시기 바랍니다.', 333, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 비염', '만성비염', 'EXERCISE', '만성 비염이 있으면 코 점막 부종과 기능 저하로 비강 통기가 감소하여 구강 호흡이 증가하고, 이로 인해 기관지 점막이 건조해져 천식이나 만성 기관지염 등 하기도 질환 위험이 높아질 수 있습니다. 식이에서 알레르겐 유발 식품(히스타민 풍부 식품, 알코올)을 피하고, 가공식품과 자극적인 음식을 줄이는 것이 도움이 됩니다. 규칙적인 유산소 운동은 호흡기 기능 개선에 도움이 되지만, 꽃가루 계절이나 미세먼지 농도가 높을 때는 실내 운동을 권장합니다. 호흡기 합병증이 우려될 경우 이비인후과 및 호흡기내과 전문의의 진료를 받으시기 바랍니다.', 334, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 비염', '만성비염', 'CAUSE', '만성 비염의 원인으로는 알레르기(집먼지 진드기, 꽃가루, 반려동물), 자율신경계 과민(혈관운동성 비염), 반복적인 상기도 감염, 비중격 만곡, 비용종, 환경적 자극(오염, 담배 연기, 자극적 화학물질), 호르몬 변화 등이 있습니다. 급성 비염이 적절히 치료되지 않고 장기간 지속되면 점막 구조가 변화하여 만성으로 진행될 수 있으며, 반복적인 감염, 알레르기 지속, 비강 구조적 이상이 만성화에 기여합니다. 정확한 원인 파악과 개인 맞춤 치료를 위해 이비인후과 전문의의 진료를 받으시기 바랍니다.', 335, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 비염', '만성비염', 'REHAB', '만성 비염의 코막힘 완화를 위한 재활 치료로는 온식염수 비강 세척(코 세척)이 점막 습윤 유지와 분비물 제거에 가장 효과적이며, 하루 1~2회 시행을 권장합니다. 비강 통기 개선을 위한 비강 스트레칭(코 마사지, 코 옆 점혈 자극), 호흡 훈련(복식호흡, 코 호흡 훈련)도 도움이 됩니다. 스팀 흡입(따뜻한 증기 흡입)은 점막 부종을 일시적으로 줄이는 데 효과적입니다. 구조적 이상(비중격 만곡, 하비갑개 비후)이 원인인 경우 수술적 교정이 근본적 해결책이 될 수 있으므로 이비인후과 전문의와 상담하시기 바랍니다.', 336, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 비염', '만성비염', 'DEFINITION', '만성 비염은 코 점막의 만성 염증으로 재채기, 콧물(맑거나 진한 분비물), 코막힘, 코 가려움증이 주요 증상이며, 이 외에도 후비루(코가 목 뒤로 넘어감), 후각 감소, 두통(안면 압박감), 이관 기능 장애로 인한 귀 먹먹함이나 이명, 수면 장애, 만성 피로, 구강 건조(구강 호흡) 등의 증상도 나타날 수 있습니다. 증상이 수개월~수년간 지속되며 계절적 변화나 환경 변화에 따라 악화될 수 있습니다. 만성 비염이 의심되면 이비인후과 전문의의 진료를 받으시기 바랍니다.', 337, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 비염', '만성비염', 'SYMPTOM', '코막힘이 양쪽 번갈아 가며 나타나고 심할 때 양쪽이 모두 막히는 증상은 만성 비염의 전형적인 증상입니다. 이는 비강 내 자율신경 지배로 인한 하비갑개의 주기적 팽창·수축(鼻週期, nasal cycle)이 만성 비염에서 과도하게 나타나기 때문이며, 점막 비후와 함께 코막힘이 양측으로 심해집니다. 이러한 증상이 3개월 이상 지속된다면 만성 비염 외에도 비중격 만곡, 비용종, 알레르기 등을 감별하기 위해 이비인후과 전문의의 비강 내시경 검사와 알레르기 검사를 받으시기 바랍니다.', 338, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 비염', '만성비염', 'DIAGNOSIS', '만성 비염 진단 후 증상을 완화하는 약물(비강 수축제, 항히스타민제)을 갑자기 중단하면 반동 효과로 증상이 일시적으로 악화될 수 있으나, 근본 치료 없이 증상 완화제를 장기 사용하면 약물 의존성이나 부작용이 생길 수 있습니다. 특히 비강 수축제 스프레이를 3일 이상 사용하면 약물성 비염(반동성 충혈)이 발생할 수 있어 점진적인 감량이 필요합니다. 비강 스테로이드는 장기 사용이 안전하며, 만성 비염의 염증 자체를 조절하는 데 권장됩니다. 약물 조정과 치료 계획은 반드시 이비인후과 전문의와 상담하여 결정하시기 바랍니다.', 339, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 비염', '만성비염', 'TREATMENT', '비염이 심하게 진행되어 수면을 방해하고 몸이 아플 정도라면, 우선 이비인후과 전문의를 방문하여 정확한 원인(알레르기성, 혈관운동성, 비용종 동반 여부 등)을 파악하는 것이 중요합니다. 알레르기성 비염에는 비강 스테로이드와 항히스타민제 병용이 가장 효과적이며, 심한 코막힘에는 비강 수축제를 단기간 사용할 수 있습니다. 약물 치료에 반응하지 않거나 구조적 이상(비중격 만곡, 하비갑개 비후)이 있는 경우 하비갑개 수술, 비중격 교정 등 수술적 치료를 고려할 수 있습니다. 수면의 질 저하가 동반될 경우 수면무호흡 여부도 함께 평가받으시기 바랍니다.', 340, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 중이염', '만성중이염', 'CHECKUP', '귀에서 고름이 나오고 통증이 지속되는 경우 만성 중이염이 의심되며, 이비인후과에서 검진을 받을 수 있습니다. 전국 이비인후과 의원 및 종합병원 이비인후과에서 이경 검사, 비디오 이경 검사, 청력 검사, 고막 운동성 검사를 통해 만성 중이염을 진단합니다. 분비물 배양 검사로 원인균을 파악하여 적절한 항생제를 선택하고, 고막 천공이 있는 경우 수술적 치료(고막성형술, 유양동 삭개술) 여부를 평가합니다. 증상이 지속될 경우 지체 없이 이비인후과 전문의의 진료를 받으시기 바랍니다.', 341, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 중이염', '만성중이염', 'DIET_LIFE', '만성 중이염으로 청력이 저하된 경우 보청기를 사용하거나 상대방 쪽으로 청력이 좋은 귀를 향하여 대화하는 것이 도움이 됩니다. 귀에 물이 들어가지 않도록 목욕·세발 시 귀마개나 방수 귀마개를 사용하고, 수영이나 잠수는 피해야 합니다. 코를 세게 풀지 않고, 비행기 탑승 시 귀 압력 평형 조작(씹기, 삼키기)을 하여 중이 압력 변화를 최소화합니다. 규칙적인 이비인후과 추적 관찰을 통해 분비물 처치와 감염 악화 여부를 모니터링하시기 바랍니다.', 342, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 중이염', '만성중이염', 'MEDICATION', '만성 중이염의 세균 감염에는 슈도모나스 에어루기노사(Pseudomonas aeruginosa)와 황색 포도상구균(Staphylococcus aureus)이 흔한 원인균이며, 배양 감수성 검사 결과에 따른 맞춤형 항생제 치료가 중요합니다. 국소 치료로는 항생제 점이액(시프로플록사신 등)과 스테로이드 점이액을 직접 귀에 투여하여 염증을 감소시킵니다. 전신 항생제는 심한 감염이나 국소 치료가 불충분할 때 사용합니다. 항생제 종류와 기간은 반드시 이비인후과 전문의의 처방에 따라 결정해야 내성균 발생을 예방할 수 있습니다.', 343, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 중이염', '만성중이염', 'PREVENTION', '손 씻기 외에 만성 중이염 예방을 위해 감기, 독감 등 상기도 감염을 조기에 치료하여 중이로의 세균 침투를 막는 것이 중요합니다. 코를 세게 풀지 않고, 귀에 물이 들어가지 않도록 주의하며, 수영 시 귀마개를 착용합니다. 금연과 간접흡연 차단(특히 소아에서)은 상기도 및 중이 점막 기능 보호에 중요하며, 모유 수유가 영아의 중이염 예방에 도움이 됩니다. 폐구균, 인플루엔자 백신 접종도 중이염 예방에 기여하므로 이비인후과 전문의와 상담하시기 바랍니다.', 344, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 중이염', '만성중이염', 'EXERCISE', '만성 중이염 환자에게는 귀에 물이 들어가는 수영은 피해야 하지만, 육상 운동은 대부분 가능합니다. 걷기, 가벼운 조깅, 실내 자전거, 스트레칭, 요가 등 귀에 직접 충격이나 압력 변화가 없는 운동을 권장합니다. 귀에 물이 들어가거나 압력 변화가 큰 스쿠버다이빙, 수영, 높은 고도 등반 등은 피해야 합니다. 어지러움이나 청력 저하가 심한 경우 낙상 위험이 있으므로 균형 훈련을 병행하고, 운동 시작 전에 이비인후과 전문의와 상담하시기 바랍니다.', 345, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 중이염', '만성중이염', 'CAUSE', '만성 중이염은 급성 중이염이 적절히 치료되지 않아 만성화되거나, 반복적인 중이 감염으로 고막에 천공이 발생하여 외부 세균이 지속적으로 중이로 침투하면서 만성 염증이 지속되는 질환입니다. 코와 중이를 연결하는 유스타키오관 기능 장애(상기도 감염, 알레르기, 비염 등)로 중이 환기가 불량해지면 세균 증식과 삼출액 축적이 반복됩니다. 특히 진주종성 중이염은 고막 함몰로 중이 내에 케라틴 덩어리가 축적되어 주변 뼈를 파괴하는 심각한 형태로 수술이 필요합니다. 증상이 지속되면 이비인후과 전문의의 진료를 받으시기 바랍니다.', 346, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 중이염', '만성중이염', 'REHAB', '만성 중이염으로 인한 청력 장애 재활에는 보청기 착용이 가장 기본적인 치료이며, 청력 손실 정도에 따라 적합한 보청기를 처방받습니다. 어지러움이 동반된 경우 전정 재활 운동(균형 훈련, Cawthorne-Cooksey 운동, 시각-전정 통합 훈련)이 효과적입니다. 수술(고막성형술, 유양동 삭개술) 후 재활로는 규칙적인 세척, 청각 훈련, 언어치료가 포함될 수 있습니다. 재활 운동 프로그램은 청력 손실 정도, 어지러움 유무, 수술 여부에 따라 이비인후과 및 재활의학과 전문의와 협의하여 개인 맞춤으로 구성됩니다.', 347, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 중이염', '만성중이염', 'DEFINITION', '귀에 공기가 가득 찬 느낌이나 압력감은 유스타키오관 기능 장애 또는 중이 내 삼출액 축적과 관련된 만성 중이염의 증상일 수 있습니다. 이 경우 코를 막고 숨을 불어넣는 발살바 조작(Valsalva maneuver)을 시도해볼 수 있으나, 염증이 있을 때는 세균을 중이로 밀어넣는 위험이 있어 주의가 필요합니다. 증상이 지속되면 이비인후과에서 이경 검사와 임피던스 검사를 받아 중이 상태를 확인해야 합니다. 만성 중이염은 자가 치료보다 이비인후과 전문의의 진료와 치료 지도가 필요합니다.', 348, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 중이염', '만성중이염', 'SYMPTOM', '만성 중이염의 초기 증상으로는 귀 먹먹함(이충만감), 가벼운 청력 저하, 간헐적인 귀 통증, 이명(귀울림), 그리고 귀에서 간헐적인 분비물(이루)이 있을 수 있습니다. 귀를 막는 듯한 느낌(이충만감)은 만성 중이염의 초기 단계에서 나타날 수 있는 증상이며, 중이 내 삼출액 축적이나 고막 변화와 관련될 수 있습니다. 그러나 이충만감 단독으로 만성 중이염을 확진하기는 어려우므로 이비인후과 전문의의 이경 검사, 청력 검사, 임피던스 검사가 필요합니다. 증상이 지속되면 이비인후과 전문의의 진료를 받으시기 바랍니다.', 349, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 중이염', '만성중이염', 'DIAGNOSIS', '만성 중이염 진단 시 청력 저하와 이명 외에도 지속적이거나 간헐적인 귀 분비물(화농성 또는 악취), 귀 통증(특히 급성 악화 시), 어지러움(특히 진주종이 내이를 침범한 경우), 두통, 안면 신경 마비(진주종성 중이염의 심각한 합병증)가 나타날 수 있습니다. 염증이 뇌수막이나 뇌로 파급되는 드문 합병증(뇌수막염, 뇌농양)도 발생할 수 있으므로 고열, 심한 두통, 경부 강직이 동반되면 즉시 응급 진료가 필요합니다. 다양한 증상의 변화는 이비인후과 전문의의 정기 추적 관찰로 관리하시기 바랍니다.', 350, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '만성 중이염', '만성중이염', 'TREATMENT', '만성 중이염은 약물이나 수술 없이 완치하기는 어렵지만, 귀를 건조하게 유지하고 수영이나 샤워 시 귀에 물이 들어가지 않도록 귀마개를 사용하는 것이 중요합니다. 코를 세게 풀지 않고, 금연하며 실내 공기를 청결하게 유지하는 것이 증상 악화를 막는 데 도움이 됩니다. 반드시 이비인후과 전문의의 정기적인 진료를 받으시기 바랍니다.', 351, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '메니에르병', '메니에르병', 'DIET_LIFE', '메니에르병 환자는 저염식을 실천하여 하루 나트륨 섭취량을 2,000mg 이하로 제한하는 것이 내림프 수종 완화에 도움이 됩니다. 카페인, 알코올, 담배를 피하고 충분한 수분 섭취와 규칙적인 수면 습관을 유지하며 스트레스 관리를 철저히 해야 합니다. 증상이 지속되면 이비인후과 전문의와 상담하여 개인에 맞는 관리 계획을 수립하시기 바랍니다.', 352, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '메니에르병', '메니에르병', 'MEDICATION', '메니에르병으로 인한 어지럼증 완화에는 항히스타민제(메클리진, 디멘하이드리네이트), 벤조디아제핀계 약물(디아제팜), 항구토제 등이 급성 발작 시 사용됩니다. 이뇨제(하이드로클로로티아지드 등)는 내림프액 압력을 낮춰 발작 빈도를 줄이는 데 장기적으로 활용됩니다. 약물 선택과 용량은 반드시 이비인후과 전문의와 상담 후 결정하시기 바랍니다.', 353, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '메니에르병', '메니에르병', 'CAUSE', '메니에르병은 내이의 내림프액 과잉 축적(내림프 수종)으로 발생하며, 고도가 높아지면 기압 변화로 중이와 내이의 압력 균형이 깨져 증상이 악화될 수 있습니다. 기압 변화는 내림프압에 영향을 미쳐 귀 먹먹함과 어지럼증을 유발하거나 심화시킵니다. 등산 시 천천히 고도를 높이고, 증상이 심해지면 즉시 이비인후과 전문의의 진료를 받으시기 바랍니다.', 354, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '메니에르병', '메니에르병', 'DEFINITION', '메니에르병은 내이의 내림프액 과잉 축적으로 인해 반복적인 어지럼증 발작, 변동성 감각신경성 난청, 이명, 귀 충만감이 동시에 나타나는 만성 질환입니다. 발작은 수십 분에서 수 시간 지속되며, 시간이 지남에 따라 청력 손실이 영구적으로 남을 수 있음을 의미합니다. 조기 진단과 치료가 청력 보전에 중요하므로 이비인후과 전문의 진료를 권고드립니다.', 355, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '메니에르병', '메니에르병', 'SYMPTOM', '메니에르병의 주요 증상은 어지럼증, 이명, 청력 감소, 귀 충만감이며, 심한 두통 자체는 메니에르병의 전형적인 증상이 아닙니다. 그러나 심한 어지럼증 발작 시 동반되는 오심·구토, 발작으로 인한 긴장 및 스트레스로 인해 두통이 유발될 수 있습니다. 두통이 심하거나 지속된다면 다른 원인의 가능성도 있으므로 신경과 또는 이비인후과 전문의 진료를 받으시기 바랍니다.', 356, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '메니에르병', '메니에르병', 'DIAGNOSIS', '이명과 어지럼증이 동반되는 경우 메니에르병을 포함한 내이 질환이 의심되므로, 우선 이비인후과 전문의를 방문하는 것이 적절합니다. 이비인후과에서 청력 검사, 전정 기능 검사, 이경 검사 등을 통해 정확한 진단이 이루어집니다. 증상이 심하거나 다른 신경학적 증상이 동반된다면 신경과 전문의와의 협진이 필요할 수 있습니다.', 357, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '메니에르병', '메니에르병', 'TREATMENT', '메니에르병 환자에게는 전정 재활 운동이 어지럼증 완화에 도움이 됩니다. 브란트-다로프 운동, 시선 안정화 운동, 균형 훈련 등이 대표적이며, 걷기와 같은 유산소 운동도 전반적인 증상 관리에 유익합니다. 운동 방법과 강도는 이비인후과 또는 재활의학과 전문의의 지도하에 시작하시기 바랍니다.', 358, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '부비동염', '부비동염', 'DIET_LIFE', '부비동염 예방 및 관리를 위한 면역력 강화에는 비타민 C가 풍부한 채소·과일 섭취, 규칙적인 운동, 충분한 수면이 중요합니다. 실내 습도를 40~60%로 유지하고, 생리식염수 코 세척을 통해 비강을 청결히 하며, 손 씻기를 철저히 하는 것도 효과적입니다. 흡연과 대기오염 노출을 피하고 증상이 지속되면 이비인후과 전문의와 상담하시기 바랍니다.', 359, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '부비동염', '부비동염', 'MEDICATION', '부비동염 치료에 사용되는 항생제의 주요 부작용으로는 위장장애(오심, 설사, 복통), 장내 정상균총 파괴로 인한 항생제 연관 설사 또는 클로스트리디오이데스 디피실 감염이 있습니다. 피부 발진, 두드러기, 드물게 아나필락시스 같은 알레르기 반응도 나타날 수 있습니다. 부작용이 발생하면 즉시 처방 의사와 상담하여 약물 교체 여부를 결정하시기 바랍니다.', 360, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '부비동염', '부비동염', 'PREVENTION', '담배 연기, 대기오염, 알레르기 유발 물질 노출을 피하는 것은 부비동 점막을 보호하고 부비동염 예방에 실질적인 도움이 됩니다. 흡연과 간접흡연은 비강 점막의 섬모 기능을 손상시켜 부비동염 발생 위험을 높이므로 금연이 매우 중요합니다. 외부 활동 제한만으로는 충분하지 않으며, 손 위생 관리와 실내 환경 관리를 병행하는 것이 효과적입니다.', 361, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '부비동염', '부비동염', 'CAUSE', '바이러스성 상기도 감염 후 2차 세균 감염을 진단하는 방법으로는 임상 증상 평가(10일 이상 지속되는 화농성 콧물, 안면 통증, 발열 등), 비강 내시경 검사, 부비동 CT 촬영이 주로 사용됩니다. 필요 시 비강 분비물 배양 검사로 원인균과 항생제 감수성을 확인합니다. 정확한 진단을 위해 이비인후과 전문의의 진찰을 받으시기 바랍니다.', 362, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '부비동염', '부비동염', 'REHAB', '부비동염 치료 후에도 비강 점막의 기능 회복, 알레르기 관리, 생활 습관 개선이 필요하며 이를 소홀히 하면 재발 위험이 높아집니다. 재발 예방을 위해 정기적인 이비인후과 추적 관찰, 생리식염수 비강 세척, 알레르기 원인 물질 회피, 면역력 강리가 중요합니다. 만성 재발성 부비동염의 경우 기능적 내시경 부비동 수술(FESS)이 대안이 될 수 있으므로 전문의와 상담하시기 바랍니다.', 363, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '부비동염', '부비동염', 'DEFINITION', '부비동염은 반드시 발열이나 감기 증상 없이도 발생할 수 있으며, 알레르기성 비염, 해부학적 이상(비중격 만곡), 치아 감염 등 다양한 원인으로 유발될 수 있습니다. 주요 증상으로는 안면 통증 및 압박감, 코막힘, 화농성 비루, 후비루, 후각 감소 등이 있습니다. 발열 없이도 이러한 증상이 지속된다면 이비인후과 전문의 진료를 받으시기 바랍니다.', 364, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '부비동염', '부비동염', 'SYMPTOM', '후비루(코가 목 뒤로 넘어가는 증상)와 눈 주변 부종은 부비동염의 증상에 해당할 수 있습니다. 부비동염의 주요 증상으로는 코막힘, 화농성 콧물, 안면 압박감 및 통증, 후각 감소, 두통, 발열, 치통 등이 있습니다. 눈 주변 부종이 심하다면 안와 합병증 가능성이 있으므로 즉시 이비인후과 또는 응급실을 방문하시기 바랍니다.', 365, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '부비동염', '부비동염', 'DIAGNOSIS', '임플란트 수술 전 부비동염(특히 상악동염) 확인을 위해서는 치과 또는 구강악안면외과, 이비인후과를 방문하면 됩니다. 파노라마 X-선 또는 치과용 CT(CBCT)로 상악동 상태를 확인하며, 필요 시 이비인후과에서 부비동 내시경 검사나 부비동 CT를 추가로 시행합니다. 임플란트 시술 예정이라면 담당 치과의사와 이비인후과 전문의의 협진을 권고드립니다.', 366, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '부비동염', '부비동염', 'TREATMENT', '비염이나 부비동염으로 인한 두통과 지속적인 콧물은 이비인후과 전문의의 진료가 필요합니다. 치료 방법으로는 원인에 따라 항생제(세균성), 항히스타민제 및 비강 스테로이드 스프레이(알레르기성), 충혈 완화제, 생리식염수 비강 세척 등이 사용됩니다. 만성화된 경우 내시경 수술을 고려할 수 있으므로 전문의 진료를 통해 적절한 치료를 받으시기 바랍니다.', 367, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비중격 만곡', '비중격만곡', 'CHECKUP', '비중격 만곡은 비염 외에도 코막힘(한쪽 또는 양쪽), 구강 호흡, 코골이 및 수면무호흡증, 반복적인 부비동염, 두통, 후각 감소 등 다양한 증상을 유발할 수 있습니다. 비중격 만곡 자체로 인한 증상과 동반된 알레르기 비염, 부비동염 증상이 복합적으로 나타나는 경우가 많습니다. 정확한 평가를 위해 이비인후과 전문의의 내시경 검사를 받으시기 바랍니다.', 368, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비중격 만곡', '비중격만곡', 'DIET_LIFE', '비중격 만곡으로 인한 호흡 불편 시, 잠잘 때는 막히지 않은 쪽 코가 위로 오도록 옆으로 누워 자면 호흡이 편해질 수 있습니다. 머리를 약간 높게 유지하는 자세도 비강 충혈 완화에 도움이 됩니다. 자세 교정만으로는 근본적인 해결이 어렵기 때문에 증상이 심하다면 이비인후과 전문의와 비중격 교정술 등 적극적인 치료를 상담하시기 바랍니다.', 369, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비중격 만곡', '비중격만곡', 'MEDICATION', '비중격 만곡증의 근본적 치료는 수술(비중격 교정술)이며, 약물로는 완치가 되지 않습니다. 증상 완화를 위해 비강 스테로이드 스프레이(플루티카손, 모메타손 등)로 점막 부종을 줄이거나, 동반된 알레르기 비염이 있는 경우 항히스타민제, 충혈 완화제(옥시메타졸린 등, 단기 사용)가 사용됩니다. 적절한 약물 선택과 수술 여부는 이비인후과 전문의와 상담하여 결정하시기 바랍니다.', 370, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비중격 만곡', '비중격만곡', 'PREVENTION', '비중격 만곡 수술(비중격 교정술) 후 합병증 예방을 위해 코를 세게 풀지 않고, 코를 건드리거나 자극하는 행동을 피해야 합니다. 수술 후 며칠간은 팩킹(packing) 제거 전까지 구강 호흡을 하며, 의사가 처방한 항생제와 소염제를 지시대로 복용해야 합니다. 격렬한 운동, 수영, 코에 압력이 가해지는 행위는 최소 2~4주간 삼가고 정기적인 외래 추적 관찰을 받으시기 바랍니다.', 371, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비중격 만곡', '비중격만곡', 'EXERCISE', '비중격 만곡 자체는 배드민턴이나 테니스 같은 운동으로 교정되거나 증상이 직접 개선되지는 않습니다. 다만 유산소 운동은 전반적인 면역력 향상과 체중 조절에 도움이 되며, 코로 호흡하는 연습을 통해 비강 기능 강화에 간접적으로 기여할 수 있습니다. 코막힘이 심한 상태에서 격렬한 운동은 호흡 불편을 악화시킬 수 있으므로 이비인후과 전문의의 진료 후 운동 여부를 결정하시기 바랍니다.', 372, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비중격 만곡', '비중격만곡', 'CAUSE', '비중격 만곡의 원인으로는 태어날 때부터의 선천적 요인, 성장 과정에서의 코뼈와 연골의 불균형 성장, 외상(코 골절 또는 충격)이 대표적입니다. 만곡된 비중격이 비강 통로를 좁혀 코막힘, 후비루, 코골이 및 수면장애를 유발합니다. 증상이 지속된다면 이비인후과 전문의의 진찰을 통해 정확한 원인 평가와 치료 계획을 수립하시기 바랍니다.', 373, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비중격 만곡', '비중격만곡', 'REHAB', '비중격 교정술 후 회복 기간은 일반적으로 1~2주면 일상 복귀가 가능하며, 완전한 회복은 수술 후 3~6개월이 소요됩니다. 수술 결과는 환자의 술 후 관리(금연, 코 자극 회피, 외래 방문 준수)와 동반 질환(알레르기 비염 관리) 여부에 따라 달라질 수 있습니다. 재활 기간 중 의사의 지시를 충실히 따르는 것이 성공적인 회복에 중요하며, 지속적인 증상은 전문의와 상담하시기 바랍니다.', 374, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비중격 만곡', '비중격만곡', 'DEFINITION', '비중격 만곡은 코뼈와 연골이 중앙에서 벗어나 휘어진 상태로, 코막힘 외에도 선천적 발달 이상, 출생 시 산도를 통과하면서 받은 압력, 외상, 성장기 불균형 발육 등이 원인이 될 수 있습니다. 드물게 연골 및 골 종양, 폴립 등에 의해 비중격이 편위되어 보일 수도 있습니다. 정확한 진단을 위해 이비인후과 전문의의 내시경 검사와 CT 촬영이 필요할 수 있습니다.', 375, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비중격 만곡', '비중격만곡', 'SYMPTOM', '비중격 만곡의 주요 증상으로 한쪽 또는 양쪽 코막힘이 나타나며, 이로 인해 구강 호흡, 코골이, 후각 감소, 반복적인 부비동염, 두통 등이 동반될 수 있습니다. 비강 통기가 나빠지면 비강 방어 기능이 약화되어 감기나 상기도 감염에 더 자주 걸릴 수 있습니다. 지속적인 코막힘과 반복적인 감염 증상이 있다면 이비인후과 전문의의 진료를 받으시기 바랍니다.', 376, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비중격 만곡', '비중격만곡', 'DIAGNOSIS', '비중격 만곡의 진단 및 치료는 이비인후과 전문의가 담당합니다. 이비인후과 전문의는 비강 내시경 검사, CT 촬영으로 만곡 정도를 평가하고 비중격 교정술을 시행합니다. 증상과 수술 여부를 정확히 평가받기 위해 이비인후과 전문의가 있는 병원 또는 의원을 방문하시기 바랍니다.', 377, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비중격 만곡', '비중격만곡', 'TREATMENT', '비중격 교정술 후 재발 방지를 위해 수술 후 정기적인 외래 추적 관찰을 받고, 비강에 충격이나 압력이 가해지지 않도록 주의해야 합니다. 동반된 알레르기 비염이 있다면 항알레르기 치료를 병행하고, 코를 세게 푸는 습관을 피해야 합니다. 식단은 균형 잡힌 식사를 유지하며, 자극적인 음식이나 술·담배는 회복에 방해가 되므로 삼가시고 전문의의 지시를 따르시기 바랍니다.', 378, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비출혈', '비출혈', 'MEDICATION', '비출혈 예방을 위해 약국에서 구입할 수 있는 제품으로는 코 안을 촉촉하게 유지하는 생리식염수 비강 스프레이나 비강용 보습 연고(바셀린 등)가 도움이 됩니다. 충혈 완화 스프레이는 장기 사용 시 반동성 충혈을 일으키므로 주의가 필요합니다. 잦은 비출혈은 기저 원인(고혈압, 혈액 질환 등)이 있을 수 있으므로 이비인후과 전문의의 진료를 받으시기 바랍니다.', 379, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비출혈', '비출혈', 'PREVENTION', '환절기 소아 비출혈 예방을 위해 실내 습도를 50~60%로 유지하고, 생리식염수 비강 스프레이로 비강 점막을 촉촉하게 관리하는 것이 중요합니다. 코를 세게 풀거나 코를 후비는 습관을 교정하고, 손톱을 짧게 유지해야 합니다. 반복적이고 심한 비출혈이 지속된다면 이비인후과 전문의를 통해 정확한 원인 평가와 필요시 코 점막 지혈 치료(전기 소작술)를 받으시기 바랍니다.', 380, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비출혈', '비출혈', 'CAUSE', '수면 중 또는 기상 직후 소아에서 비출혈이 발생하는 주된 원인은 수면 중 비강 점막이 건조해지면서 키셀바흐(Kiesselbach) 부위의 혈관이 취약해지기 때문입니다. 자면서 코를 후비거나 코를 문지르는 경우도 원인이 될 수 있습니다. 이는 비출혈의 흔한 원인 중 하나이므로 습도 관리와 비강 보습으로 예방하며, 반복 시 이비인후과 전문의 진료를 권고드립니다.', 381, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비출혈', '비출혈', 'DEFINITION', '코피가 지혈되지 않는 경우, 먼저 고개를 앞으로 숙이고 콧등을 10~15분간 압박하는 응급처치를 시행합니다. 이후에도 멈추지 않거나, 30분 이상 지속되거나, 대량 출혈, 삼킴이 심하거나, 고혈압·항응고제 복용 등의 위험 요인이 있다면 응급실을 방문해야 합니다. 반복적인 비출혈이 있다면 혈액 질환, 혈관 기형 등 기저 원인 평가를 위해 이비인후과 전문의 진료를 받으시기 바랍니다.', 382, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비출혈', '비출혈', 'SYMPTOM', '비출혈은 코 안의 혈관이 손상되어 코에서 피가 나는 증상으로, 전방 비출혈과 후방 비출혈로 구분됩니다. 주요 증상은 코에서의 출혈이며, 후방 비출혈 시 혈액이 목 뒤로 넘어가 객혈처럼 보이거나 오심을 유발할 수 있습니다. 객혈, 발열, 오한, 호흡곤란이 동반된다면 비출혈 외 다른 질환 가능성이 있으므로 즉시 의료기관을 방문하시기 바랍니다.', 383, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비출혈', '비출혈', 'DIAGNOSIS', '전방 비출혈은 키셀바흐 부위에서 발생하며 코 앞쪽으로 피가 흘러나오고, 대부분 양이 적고 압박으로 지혈이 됩니다. 후방 비출혈은 코 뒤쪽의 큰 혈관에서 발생하여 혈액이 목 뒤로 넘어가 삼킴이 심하고 출혈량이 많으며 지혈이 어렵습니다. 대량 출혈이거나 후방 비출혈이 의심되면 즉시 이비인후과 전문의 또는 응급실을 방문하시기 바랍니다.', 384, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '비출혈', '비출혈', 'TREATMENT', '비출혈 치료 방법으로는 우선 비강 압박(콧등을 10~15분 압박)이 기본이며, 지혈이 안 되면 비강 팩킹(거즈 또는 팽창성 스폰지 삽입)을 시행합니다. 재발 방지를 위해 출혈 부위 혈관을 전기 소작술이나 화학적 소작술(질산은)로 치료하는 것이 효과적입니다. 기저 원인(고혈압, 항응고제 복용, 혈액 질환)이 있다면 이를 함께 치료하는 것이 재발 예방에 가장 중요하므로 전문의와 상담하시기 바랍니다.', 385, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '상기도 감염', '상기도감염', 'CHECKUP', '콧물, 코막힘, 구강 호흡으로 인한 구강 건조가 지속된다면 상기도 감염이나 알레르기 비염의 가능성이 있으며, 이비인후과 또는 내과(가정의학과)를 방문하여 진찰을 받는 것이 좋습니다. 진찰 시 비강 내시경, 혈액 검사, 알레르기 검사 등이 시행될 수 있습니다. 고열, 호흡 곤란, 삼킴 장애 등의 증상이 동반된다면 즉시 의료기관을 방문하시기 바랍니다.', 386, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '상기도 감염', '상기도감염', 'DIET_LIFE', '영아의 상기도 감염 시 모유 수유를 유지하여 면역 성분을 제공하고, 충분한 수분을 공급하는 것이 중요합니다. 비강에 생리식염수 스프레이를 뿌린 후 코 흡입기로 코를 부드럽게 흡입해 주면 코막힘 해소에 도움이 됩니다. 발열이나 증상이 악화되면 소아청소년과 전문의의 진료를 받아 적절한 치료를 받으시기 바랍니다.', 387, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '상기도 감염', '상기도감염', 'MEDICATION', '상기도 감염은 대부분 바이러스(리노바이러스, 코로나바이러스 등)에 의해 발생하며, 항바이러스제의 역할이 제한적이어서 약물 복용으로 완전히 사라지기보다는 증상을 완화하고 회복을 돕는 것이 목적입니다. 세균 감염이 동반된 경우에는 항생제가 효과적이나, 바이러스성인 경우 항생제는 효과가 없습니다. 증상 완화에는 충분한 휴식, 수분 섭취, 해열진통제 등이 사용되며 진료 후 적절한 치료를 받으시기 바랍니다.', 388, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '상기도 감염', '상기도감염', 'PREVENTION', '실내 습도를 40~60%로 유지하면 비강 점막의 방어 기능을 지키고 바이러스 생존율을 낮출 수 있어 상기도 감염 예방에 효과적입니다. 금연과 금주는 기도 점막 손상을 예방하고 면역력을 유지하는 데 도움이 됩니다. 이러한 생활 습관 개선과 함께 규칙적인 손 씻기, 충분한 수면, 균형 잡힌 식사를 병행하면 감염 예방 효과가 더욱 높아집니다.', 389, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '상기도 감염', '상기도감염', 'EXERCISE', '코막힘과 호흡 불편이 있는 경우 복식 호흡 연습과 코 세척(생리식염수)이 비강 통기 개선에 도움이 됩니다. 요가의 호흡법(프라나야마), 수영(비강 점막 습윤 효과), 걷기 등의 유산소 운동도 상기도 기능 강화에 유익합니다. 급성 감염기에는 격렬한 운동을 삼가고, 회복 후 점진적으로 운동을 재개하며 지속적인 증상은 이비인후과 전문의와 상담하시기 바랍니다.', 390, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '상기도 감염', '상기도감염', 'CAUSE', '상기도 감염(감기)은 주로 리노바이러스, 코로나바이러스, 아데노바이러스, RSV 등 다양한 바이러스에 의해 발생합니다. 주된 감염 경로는 감염자의 비말 흡입이나 오염된 물체를 만진 손으로 눈·코·입을 접촉하는 것이며, 면역력 저하, 추운 날씨, 밀집 환경 등이 발병을 촉진합니다. 바이러스 외에 드물게 세균(연쇄구균 등)도 상기도 감염을 일으킬 수 있으며 이 경우 항생제 치료가 필요합니다.', 391, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '상기도 감염', '상기도감염', 'REHAB', '상기도 감염으로 인한 고열과 두통은 일반적으로 충분한 휴식, 수분 섭취, 해열진통제(아세트아미노펜, 이부프로펜) 투여로 관리하며, 특별한 재활 프로그램이 필요하지 않은 경우가 대부분입니다. 대부분 7~14일 내 자연 회복되며, 이후 점진적으로 일상 활동과 운동량을 늘려가는 것이 권장됩니다. 증상이 2주 이상 지속되거나 합병증이 의심된다면 이비인후과 또는 내과 전문의의 진료를 받으시기 바랍니다.', 392, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '상기도 감염', '상기도감염', 'DEFINITION', '상기도 감염은 코(비강), 부비동, 인두(목), 후두 등 상부 기도 부위에서 발생하는 감염 질환입니다. 주요 증상으로는 콧물, 코막힘, 재채기, 인후통, 기침, 발열, 두통, 피로감 등이 있으며, 원인 부위에 따라 비염, 인후염, 후두염 등으로 구분됩니다. 대부분 바이러스성이며 충분한 휴식과 수분 섭취로 호전되나 증상이 심하면 전문의 진료를 받으시기 바랍니다.', 393, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '상기도 감염', '상기도감염', 'SYMPTOM', '숨쉬기 곤란, 콧물, 코막힘이 지속된다면 상기도 감염이나 알레르기 비염 가능성이 있으므로, 충분한 휴식과 수분 섭취를 유지하고 증상이 악화된다면 의료기관을 방문해야 합니다. 호흡 곤란이 심하거나 빠른 호흡, 청색증, 고열이 동반되면 하기도 감염(폐렴, 기관지염) 또는 다른 원인 가능성이 있어 즉시 응급 진료가 필요합니다. 증상의 지속 기간과 심한 정도에 따라 이비인후과 또는 내과 전문의 진료를 받으시기 바랍니다.', 394, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '상기도 감염', '상기도감염', 'DIAGNOSIS', '급성 비염 및 부비동염은 비강 내시경 검사와 부비동 CT, 인후염은 인두 시진 및 인후 도말 배양 검사, 중이염은 이경 검사 및 고막 운동성 검사(임피던스 청력 검사), 기관지염은 흉부 X-선 및 폐 청진이 각각 주로 사용됩니다. 여러 부위 감염이 동시에 의심될 경우 혈액 검사(CBC, CRP)와 원인균 확인을 위한 배양 검사가 추가됩니다. 정확한 진단을 위해 이비인후과 전문의의 종합적인 평가가 필요합니다.', 395, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '상기도 감염', '상기도감염', 'TREATMENT', '비를 맞은 후 인후통, 콧물, 코막힘이 발생하면 상기도 바이러스 감염(감기)의 초기 증상일 가능성이 높습니다. 충분한 수분과 휴식을 취하고, 따뜻한 물과 꿀물이 인후 통증 완화에 도움이 되며, 증상에 따라 해열진통제, 충혈 완화제 등을 사용할 수 있습니다. 증상이 일주일 이상 지속되거나 고열, 호흡 곤란이 동반되면 이비인후과 또는 내과 전문의를 방문하시기 바랍니다.', 396, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '수면 무호흡증', '수면무호흡증', 'CHECKUP', '수면 중 코골이와 호흡 곤란이 반복된다면 수면무호흡증이 의심되므로, 이비인후과 또는 수면 전문 클리닉(수면검사실)이 있는 병원에서 검진을 받는 것이 좋습니다. 수면다원검사(PSG)는 수면무호흡증 진단의 표준 검사이며, 이비인후과에서 상기도 구조 평가와 함께 시행됩니다. 조기 진단과 치료가 심혈관 합병증 예방에 중요하므로 전문의 진료를 권고드립니다.', 397, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '수면 무호흡증', '수면무호흡증', 'DIET_LIFE', '비만으로 인한 수면무호흡증 관리를 위해 저칼로리 균형식(채소, 통곡물, 단백질 위주)을 통한 체중 감량이 가장 효과적입니다. 취침 3시간 전 식사를 마치고, 알코올과 수면제 복용을 피하며, 옆으로 자는 자세(측와위)를 유지하면 증상 완화에 도움이 됩니다. 체중을 10% 감량하면 무호흡 지수가 현저히 개선될 수 있으므로 규칙적인 운동과 식이 조절을 병행하고 전문의 지도를 받으시기 바랍니다.', 398, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '수면 무호흡증', '수면무호흡증', 'MEDICATION', '수면무호흡증은 대부분 약물만으로 완전한 증상 소실이 어렵습니다. 현재 수면무호흡증에 특이적으로 승인된 약물은 없으며, 동반된 비충혈이나 알레르기 비염에 대한 약물 치료가 보조적으로 사용됩니다. 중등도 이상의 수면무호흡증은 양압 호흡기(CPAP) 치료가 가장 효과적이므로 이비인후과 또는 수면 전문의와 상담하여 적절한 치료 방법을 결정하시기 바랍니다.', 399, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '수면 무호흡증', '수면무호흡증', 'PREVENTION', '수면무호흡증 예방을 위해 가장 중요한 것은 정상 체중 유지와 비만 예방입니다. 금주, 금연, 수면제 및 진정제 복용 자제, 취침 전 과식 금지, 옆으로 자는 자세 유지가 예방에 효과적입니다. 코막힘이 있다면 비강 질환(알레르기 비염, 비중격 만곡 등) 치료를 받는 것도 예방에 도움이 되며, 지속되는 수면 문제는 이비인후과 또는 수면 전문의와 상담하시기 바랍니다.', 400, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '수면 무호흡증', '수면무호흡증', 'EXERCISE', '수면무호흡증 개선에는 주 3~5회, 회당 30분 이상의 중강도 유산소 운동(걷기, 조깅, 수영, 자전거)이 체중 감량과 상기도 근육 강화에 효과적입니다. 구강 및 인후 근육 강화 운동(혀 운동, 구강 근기능 훈련)도 무호흡 빈도를 줄이는 데 도움이 됩니다. 운동 강도와 종류는 개인 건강 상태에 맞게 수면 전문의 또는 운동 전문가와 상담하여 결정하시기 바랍니다.', 401, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '수면 무호흡증', '수면무호흡증', 'CAUSE', '비만은 수면무호흡증의 가장 중요한 위험 요인으로, 목 주변 지방 축적이 상기도를 좁히고 기도 주변 지지 구조를 약화시켜 수면 중 기도 허탈을 유발합니다. 복부 비만은 횡격막을 눌러 폐 용량을 감소시키고 호흡 근육의 효율성을 저하시켜 무호흡을 악화시킵니다. 체중 감량이 수면무호흡증 개선에 매우 효과적이므로 이비인후과 또는 수면 전문의의 지도 아래 체중 관리 프로그램을 시작하시기 바랍니다.', 402, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '수면 무호흡증', '수면무호흡증', 'REHAB', '수면 재활 치료(CPAP, 구강 내 장치, 위치 치료 등) 시작 전에는 수면다원검사로 무호흡의 중증도(AHI 지수)를 정확히 평가하고, 자신의 수면무호흡 유형(폐쇄성/중추성/혼합성)을 파악해야 합니다. 재활 치료 시 기대 효과, 순응도, 기기 사용법, 부작용 관리 방법을 숙지하는 것이 중요하며, 꾸준한 사용이 치료 성공의 핵심입니다. 수면 전문의와 충분한 상담 후 자신에게 맞는 치료법을 선택하시기 바랍니다.', 403, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '수면 무호흡증', '수면무호흡증', 'DEFINITION', '수면무호흡증의 특징적인 증상은 수면 중 코골이, 반복적인 호흡 정지, 수면 중 각성, 주간 졸림증, 피로감, 아침 두통, 집중력 저하 등입니다. 호흡이 불편해지고 산소 포화도가 떨어지면서 반복적으로 잠에서 깨는 수면 분절이 나타납니다. 이러한 증상이 지속되면 고혈압, 부정맥, 뇌졸중 등 심혈관 합병증 위험이 높아지므로 이비인후과 또는 수면 전문의의 진료를 받으시기 바랍니다.', 404, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '수면 무호흡증', '수면무호흡증', 'SYMPTOM', '수면 중 숨이 막히다가 갑자기 크게 숨을 몰아쉬는 것은 폐쇄성 수면무호흡증의 전형적인 증상입니다. 이는 수면 중 상기도 근육이 이완되어 기도가 막히고, 산소 포화도가 떨어지면서 뇌가 각성하여 호흡을 재개시키는 과정에서 나타납니다. 이러한 증상이 반복된다면 수면다원검사를 통한 정확한 진단과 치료를 위해 이비인후과 또는 수면 전문의를 방문하시기 바랍니다.', 405, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '수면 무호흡증', '수면무호흡증', 'DIAGNOSIS', '수면무호흡증이 의심될 때는 우선 이비인후과 전문의를 방문하는 것이 적절합니다. 이비인후과에서 상기도 구조 평가와 수면다원검사를 통해 진단하며, 비만이 주 원인인 경우 내과(비만 클리닉)와 협진이 이루어질 수 있습니다. 심혈관 합병증이 동반된 경우 순환기내과, 신경학적 증상이 있는 경우 신경과 전문의와의 협진도 필요할 수 있습니다.', 406, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '수면 무호흡증', '수면무호흡증', 'TREATMENT', '수면무호흡증 치료 중 가장 부작용이 적고 효과적인 방법은 CPAP(지속적 양압 호흡기) 치료입니다. CPAP의 주요 부작용은 마스크 불편감, 코 건조증, 피부 압박, 복부 팽만감 등이며, 기기 조정이나 가습기 장착으로 대부분 해결됩니다. 경도 수면무호흡증에는 구강 내 장치(하악 전진 장치)도 비교적 부작용이 적은 대안이 될 수 있으며, 전문의와 상담 후 개인에 맞는 치료를 선택하시기 바랍니다.', 407, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '알레르기 비염', '알레르기비염', 'CHECKUP', '알레르기 비염 진단을 위한 의학적 검사로는 피부 단자 검사(skin prick test)와 혈청 특이 IgE 검사(RAST)가 알레르겐 확인에 사용됩니다. 비강 내시경 검사로 점막 상태를 확인하고, 필요 시 비강 분비물 세포 검사(호산구 증가 확인)가 추가될 수 있습니다. 꽃가루 등 알레르겐에 따른 계절성 증상이 있다면 이비인후과 또는 알레르기 내과 전문의를 방문하시기 바랍니다.', 408, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '알레르기 비염', '알레르기비염', 'DIET_LIFE', '알레르기 비염 증상 완화에는 항염증 효과가 있는 오메가-3 지방산(등 푸른 생선), 비타민 C, 비타민 D가 풍부한 식품 섭취가 도움이 됩니다. 알레르겐 노출을 줄이기 위해 침구류 세탁, 실내 환기, 공기청정기 사용, 외출 후 세안 및 손 씻기를 생활화하는 것이 효과적입니다. 꽃가루 시즌에는 외출 시 마스크를 착용하고, 귀가 후 샤워를 하는 습관도 증상 완화에 도움이 됩니다.', 409, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '알레르기 비염', '알레르기비염', 'MEDICATION', '비강 스테로이드 스프레이(플루티카손, 모메타손, 부데소니드 등)는 알레르기 비염의 코막힘, 콧물, 재채기를 억제하는 데 가장 효과적인 1차 치료제로, 매일 규칙적으로 사용해야 효과가 나타납니다. 항히스타민제(세티리진, 펙소페나딘 등)는 히스타민 수용체를 차단하여 재채기, 콧물, 가려움증을 신속하게 완화하며, 경구 또는 비강 스프레이 형태로 사용됩니다. 두 약물을 병용하면 더 효과적이며, 처방 및 사용법은 이비인후과 또는 알레르기 전문의와 상담하시기 바랍니다.', 410, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '알레르기 비염', '알레르기비염', 'PREVENTION', '가족 중 알레르기 비염 환자가 있다면 집 먼지 진드기, 곰팡이, 반려동물 비듬 등 공통 알레르겐 노출을 가족 모두가 함께 줄이는 것이 중요합니다. 침구류를 주 1회 이상 60도 이상의 물로 세탁하고, 방진 커버를 사용하며, 카펫 사용을 줄이고 정기적으로 환기와 청소를 하는 것이 효과적입니다. 알레르기 비염 환자가 있는 가정에서는 반려동물을 침실에 들이지 않고, 흡연을 삼가는 것도 알레르겐 관리에 필수적입니다.', 411, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '알레르기 비염', '알레르기비염', 'EXERCISE', '알레르기 비염으로 인한 호흡 곤란과 기침이 심한 경우, 알레르겐 노출을 최소화한 환경에서 운동하는 것이 중요합니다. 꽃가루 농도가 높은 날은 실외 운동을 자제하고 실내 운동(수영, 실내 자전거 등)을 선택하며, 운동 전 코 세척과 항히스타민제 복용이 도움이 될 수 있습니다. 운동 유발 증상이 심하다면 이비인후과 또는 알레르기 전문의와 상담하여 운동 전 예방 치료 및 개인에 맞는 운동 계획을 수립하시기 바랍니다.', 412, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '알레르기 비염', '알레르기비염', 'CAUSE', '알레르기 비염은 집 먼지 진드기와 꽃가루 외에도 반려동물 비듬(개, 고양이), 바퀴벌레 알레르겐, 곰팡이 포자, 음식물 알레르겐, 직업적 화학물질 노출 등 다양한 원인으로 발생할 수 있습니다. 또한 대기오염, 담배 연기, 강한 향수 등의 비알레르기성 자극도 비염 증상을 유발하거나 악화시킬 수 있습니다. 정확한 알레르겐 확인을 위해 알레르기 피부 단자 검사나 혈청 IgE 검사를 이비인후과 또는 알레르기 내과에서 받으시기 바랍니다.', 413, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '알레르기 비염', '알레르기비염', 'REHAB', '알레르기 비염으로 인한 심한 콧물과 재채기의 경우 병원에서 비강 스테로이드 스프레이와 경구 항히스타민제를 처방하여 급성 증상을 조절합니다. 원인 알레르겐 확인 후 장기적으로는 면역 치료(알레르겐 면역요법, 피하주사 또는 설하 면역치료)를 통해 알레르기 반응 자체를 약화시키는 재활적 접근도 시행됩니다. 증상이 심하거나 약물 치료에 반응이 없는 경우 전문의와 상담하여 면역 치료 적응증 여부를 평가받으시기 바랍니다.', 414, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '알레르기 비염', '알레르기비염', 'DEFINITION', '알레르기 비염은 특정 알레르겐에 노출될 때 과도한 면역 반응이 일어나 비강 점막에 염증이 생기는 질환으로, 봄의 꽃가루뿐만 아니라 가을에는 쑥, 돼지풀 등의 꽃가루와 집 먼지 진드기 증가로 증상이 나타납니다. 차가운 바람과 건조한 공기는 비강 점막을 자극하여 비알레르기성 증상을 유발하거나 알레르기 반응을 악화시킬 수 있습니다. 계절에 관계없이 증상이 지속된다면 이비인후과 또는 알레르기 전문의 진료를 받으시기 바랍니다.', 415, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '알레르기 비염', '알레르기비염', 'SYMPTOM', '알레르기 비염의 주요 증상에는 재채기, 맑은 콧물, 코막힘이 포함되며, 눈과 코의 가려움증(소양감)도 전형적인 증상입니다. 눈 주위 가려움(알레르기 결막염 동반), 코막힘으로 인한 구강 호흡, 눈물, 눈 충혈도 흔히 나타납니다. 이러한 증상들이 반복된다면 이비인후과 또는 알레르기 전문의를 방문하여 알레르기 검사를 받으시기 바랍니다.', 416, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '알레르기 비염', '알레르기비염', 'DIAGNOSIS', '코의 가려움증(소양감)과 부종(점막 부종으로 인한 코막힘)은 알레르기 비염의 대표적인 증상에 해당합니다. 알레르겐 노출 시 비만세포에서 히스타민이 분비되어 점막 혈관 확장, 부종, 가려움증, 분비물 증가가 일어납니다. 이러한 증상이 반복적으로 나타난다면 이비인후과 또는 알레르기 내과 전문의를 방문하여 정확한 진단과 치료를 받으시기 바랍니다.', 417, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '알레르기 비염', '알레르기비염', 'TREATMENT', '알레르기 비염 환자에게 환절기 증상 완화를 위해 병원에서는 비강 스테로이드 스프레이(플루티카손, 모메타손 등)와 경구 항히스타민제(세티리진, 펙소페나딘, 레보세티리진 등)가 주로 처방됩니다. 코막힘이 심한 경우 단기간 충혈 완화제 또는 항류코트리엔제(몬테루카스트)가 추가될 수 있습니다. 증상과 원인 알레르겐에 따라 처방이 달라질 수 있으므로 이비인후과 또는 알레르기 전문의와 상담하시기 바랍니다.', 418, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '외이도염', '외이도염', 'CHECKUP', '외이도염 검진 시 의사에게 귀의 가려움증 외에도 귀 통증(특히 귓바퀴를 당기거나 아래턱을 움직일 때 악화되는 통증), 귀에서 나오는 분비물(진물, 고름), 청력 저하, 귀 충만감 등을 구체적으로 설명하면 진단에 도움이 됩니다. 증상 시작 시기, 물 접촉(수영, 샤워) 여부, 귀 후비는 습관, 보청기나 이어폰 사용 여부도 함께 알려주세요. 이비인후과 전문의의 이경 검사를 통해 정확한 진단이 이루어집니다.', 419, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '외이도염', '외이도염', 'DIET_LIFE', '외이도염 환자 돌봄 시 간호자는 귀에 물이 들어가지 않도록 주의하고, 귀를 면봉이나 손가락으로 후비지 않아야 합니다. 면역력 저하(당뇨, 면역억제제 복용 등)가 있는 경우 악성 외이도염으로 발전할 수 있으므로 각별히 주의해야 합니다. 규칙적인 손 씻기와 환자 귀 분비물 처리 시 위생장갑 착용으로 감염을 예방하고, 증상 변화 시 이비인후과 전문의의 진료를 받으시기 바랍니다.', 420, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '외이도염', '외이도염', 'MEDICATION', '외이도염으로 항생제 복용 시 처방된 용량과 기간을 정확히 지켜야 하며, 증상이 호전되더라도 임의로 중단하면 안 됩니다. 복용 중 위장장애, 알레르기 반응(두드러기, 호흡 곤란)이 나타나면 즉시 처방 의사에게 연락하고, 항생제 복용 중에는 귀에 물이 들어가지 않도록 수영이나 목욕 시 주의해야 합니다. 처방된 귀 점이액(항생제 이어드롭)이 함께 있다면 사용법에 따라 정확히 점이하시기 바랍니다.', 421, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '외이도염', '외이도염', 'PREVENTION', '외이도염 자체를 예방하는 특정 영양제는 없으나, 전반적인 면역력 강화를 위해 비타민 C, 비타민 D, 아연 보충이 감염 저항력에 도움이 될 수 있습니다. 당뇨 환자는 혈당 조절이 외이도염(특히 악성 외이도염) 예방에 중요합니다. 가장 중요한 예방법은 귀를 건조하게 유지하고, 귀를 후비지 않으며, 오염된 물 접촉을 피하는 것이므로 전문의와 상담하시기 바랍니다.', 422, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '외이도염', '외이도염', 'EXERCISE', '달리기나 유산소 운동 자체가 외이도염 발생이나 예방에 직접적인 관련은 없습니다. 외이도염의 주된 예방법은 이어폰 사용 시간 줄이기, 귀 후비는 습관 금지, 귀를 건조하게 유지하기입니다. 이어폰은 외이도를 습하게 만들고 외이도 피부를 자극하여 감염 위험을 높이므로, 사용 시간을 줄이고 이어폰을 주기적으로 소독하며 증상이 있으면 이비인후과 전문의 진료를 받으시기 바랍니다.', 423, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '외이도염', '외이도염', 'CAUSE', '외이도염은 외이도 피부에 세균(주로 녹농균, 황색포도알균) 또는 진균(곰팡이)이 감염되어 발생합니다. 귀에 물이 자주 들어가는 경우(수영), 면봉이나 손가락으로 귀를 후비는 행위, 이어폰·보청기 장기 착용, 습한 환경, 면역력 저하(당뇨) 등이 주요 위험 요인입니다. 정확한 원인 파악과 재발 방지를 위해 이비인후과 전문의의 진찰을 통해 원인균 확인 및 적절한 치료를 받으시기 바랍니다.', 424, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '외이도염', '외이도염', 'REHAB', '외이도염 치료 후 재활 기간 중 수영은 권장하지 않습니다. 물은 외이도 환경을 습하게 만들어 세균 및 진균 증식을 촉진하고, 치료 중인 외이도 피부를 자극하여 회복을 지연시킬 수 있습니다. 완전한 회복이 확인된 후 이비인후과 전문의의 허가를 받아 수영을 재개하고, 수영 시에는 귀마개를 착용하고 후 귀를 충분히 건조시키시기 바랍니다.', 425, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '외이도염', '외이도염', 'DEFINITION', '외이도염은 귓바퀴에서 고막 사이의 외이도(바깥 귀 통로) 피부에 세균 또는 진균이 감염되어 발생하는 염증 질환입니다. 외이도 전체에 걸쳐 염증이 생길 수 있으며, 특히 귀 연골 부위와 외이도 입구 부근에 호발합니다. 귀 통증, 가려움증, 분비물, 청력 저하 등의 증상이 나타나면 이비인후과 전문의의 이경 검사를 통해 정확히 진단받으시기 바랍니다.', 426, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '외이도염', '외이도염', 'SYMPTOM', '외이도염의 주요 증상으로는 귀 통증(귓바퀴를 당길 때 심해짐), 가려움증, 외이도 부종, 분비물(투명하거나 화농성), 청력 감소, 귀 충만감이 있습니다. 귀 안의 딱지와 비늘 같은 피부 박리도 나타날 수 있으며, 심한 경우 턱 아래 림프절 종대나 발열이 동반될 수 있습니다. 증상이 지속되거나 악화된다면 이비인후과 전문의의 진료를 받으시기 바랍니다.', 427, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '외이도염', '외이도염', 'DIAGNOSIS', '외이도염 진단은 주로 이경 검사(귀 내시경)를 통해 외이도 피부의 발적, 부종, 분비물, 딱지 등을 확인하여 이루어집니다. 귀 안의 가려움증과 진물(분비물)은 외이도염의 전형적인 증상으로, 이러한 소견과 증상이 일치하면 외이도염으로 진단할 수 있습니다. 고막 천공이나 중이염과의 감별이 필요한 경우 추가 검사가 시행되므로 이비인후과 전문의를 방문하시기 바랍니다.', 428, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '외이도염', '외이도염', 'TREATMENT', '외이도염 치료의 핵심은 외이도 세척(귀 청소)과 항생제 또는 항진균제 이어드롭(귀 점이액) 사용입니다. 통증이 심한 경우 구강 진통제가 처방되며, 심한 세균 감염이나 주변 조직으로 염증이 퍼진 경우 경구 항생제가 추가될 수 있습니다. 만성 또는 재발성 외이도염의 경우 이비인후과 전문의의 외래 치료(귀 세척, 이어드롭 치료)를 통해 적절한 관리를 받으시기 바랍니다.', 429, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이명', '이명', 'CHECKUP', '이명 검진을 위해 이비인후과에서 순음 청력 검사, 어음 청력 검사, 이명 주파수 및 강도 측정 검사(이명도 검사), 뇌간 유발 반응 검사(ABR)가 시행됩니다. 이명의 원인이 혈관성(박동성 이명)인 경우 MRI 또는 혈관 조영술이 추가될 수 있습니다. 이명의 원인은 다양하므로 이비인후과 전문의를 방문하여 청력 검사와 이명 평가를 받으시기 바랍니다.', 430, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이명', '이명', 'DIET_LIFE', '이명 완화를 위한 식이 요법으로는 혈액 순환에 좋은 음식(오메가-3, 마그네슘이 풍부한 견과류, 녹색 채소)을 섭취하고, 카페인(커피, 녹차), 알코올, 고염식, 퀴닌 함유 음료를 줄이는 것이 도움이 됩니다. 충분한 수분 섭취와 규칙적인 식사로 혈당을 안정적으로 유지하는 것도 이명 악화를 예방합니다. 식이 개선과 함께 지속적인 이명은 이비인후과 전문의의 진료와 치료를 받으시기 바랍니다.', 431, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이명', '이명', 'MEDICATION', '이명 치료에 사용되는 약물로는 혈액 순환 개선제(은행나무 추출물, 베타히스틴), 항불안제 및 진정제(단기 사용), 항우울제(아미트리프틸린, 삼환계 항우울제)가 이명 관련 불안과 수면 장애 개선에 사용됩니다. 원인 질환이 있는 경우(고혈압, 메니에르병 등)에는 해당 질환 치료 약물이 이명 완화에 도움이 됩니다. 약물은 반드시 이비인후과 또는 신경과 전문의의 처방에 따라 복용하시기 바랍니다.', 432, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이명', '이명', 'PREVENTION', '이명의 주요 원인 중 하나는 소음성 난청으로, 지속적인 소음 노출이 내이 유모세포를 손상시켜 이명을 유발합니다. 귀마개나 귀 보호 장비(이어머프)를 착용하면 과도한 소음으로 인한 내이 손상을 예방하여 소음성 이명 발생을 억제할 수 있습니다. 공사장, 콘서트, 사격장 등 소음이 큰 환경에서는 반드시 청력 보호 장비를 착용하는 것이 이명 예방의 중요한 방법입니다.', 433, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이명', '이명', 'EXERCISE', '이명은 재활 치료(이명 재훈련 치료, TRT)와 인지행동 치료(CBT)를 통해 이명에 대한 뇌의 반응을 재조건화하여 생활 불편을 크게 줄일 수 있으나 완전한 치유가 보장되지는 않습니다. 음향 치료(소리 발생기, 백색 소음 사용), 이완 요법, 바이오피드백도 증상 완화에 효과적입니다. 약물 치료와 재활 치료의 병행이 효과적이며, 이비인후과 또는 이명 전문 클리닉에서 개인에 맞는 치료 계획을 세우시기 바랍니다.', 434, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이명', '이명', 'CAUSE', '이명을 악화시키는 환경 요인으로는 소음(공사 소음, 음악 큰 소리, 이어폰 장시간 사용), 정적(완전히 조용한 환경에서 이명이 더 크게 인지됨), 스트레스와 수면 부족이 대표적입니다. 카페인과 알코올 과다 섭취, 혈압 변동, 특정 이독성 약물(아스피린 고용량, 특정 항생제, 이뇨제) 복용도 이명을 유발하거나 악화시킬 수 있습니다. 이러한 요인들을 피하고 이비인후과 전문의와 상담하여 개인에 맞는 이명 관리를 받으시기 바랍니다.', 435, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이명', '이명', 'REHAB', '부신 종양(크롬친화세포종 등) 수술 후 이명이 발생하거나 지속된다면, 수술과 관련된 혈압 변동, 마취 약물, 수술 중 소음, 출혈 등 여러 원인이 관련될 수 있습니다. 수술 후 이명이 지속된다면 이비인후과 전문의에게 반드시 알리고 청력 검사와 이명 평가를 받아야 합니다. 혈압 조절 및 기저 질환 관리가 이명 개선에 중요하므로 담당 내분비외과 및 이비인후과 전문의와 긴밀히 협진하시기 바랍니다.', 436, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이명', '이명', 'DEFINITION', '이명은 외부 소리 없이 귀나 머리에서 소리가 들리는 증상으로, 귀울림, 삐소리, 윙윙거림, 맥박음 등 다양한 형태로 나타납니다. 주관적 이명(본인만 들을 수 있음)이 대부분이며, 지속적 또는 간헐적으로 나타날 수 있습니다. 난청, 내이 손상, 중이 질환, 혈관 문제 등 다양한 원인에 의해 발생하므로 증상이 지속되면 이비인후과 전문의의 정확한 진단을 받으시기 바랍니다.', 437, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이명', '이명', 'SYMPTOM', '이석증(양성 돌발성 두위성 현훈, BPPV)의 전형적인 증상은 특정 두부 자세 변경 시 갑자기 발생하는 수십 초 내의 심한 어지럼증(현훈)이며, 이명과 귀 먹먹함이 동반될 수 있습니다. 그러나 지속적인 이명과 귀 먹먹함이 뚜렷하다면 메니에르병과의 감별이 필요합니다. 이석증은 이비인후과에서 이석 정복술(Epley maneuver 등)로 효과적으로 치료할 수 있으므로 전문의 진료를 받으시기 바랍니다.', 438, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이명', '이명', 'DIAGNOSIS', '이명 진단은 이비인후과에서 받을 수 있으며, 특정 병원이나 의료기관의 주소와 연락처는 제공하기 어렵습니다. 가까운 이비인후과 의원이나 대학병원 이비인후과를 방문하거나, 건강보험심사평가원 홈페이지(www.hira.or.kr) 또는 병원 찾기 서비스를 이용하여 근처 이비인후과를 검색하실 수 있습니다. 청력 검사와 이명 평가를 통해 정확한 원인을 파악하는 것이 치료의 첫 단계입니다.', 439, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이명', '이명', 'TREATMENT', '이명을 치료하지 않고 방치하면 수면 장애, 집중력 저하, 불안, 우울증으로 발전할 수 있으며, 삶의 질이 크게 저하될 수 있습니다. 이명의 원인 질환(소음성 난청, 메니에르병, 청신경 종양 등)이 있는 경우 조기 치료를 받지 않으면 해당 질환이 악화되어 영구적 청력 손실로 이어질 수 있습니다. 이명이 지속된다면 조기에 이비인후과 전문의를 방문하여 원인 파악과 적절한 치료를 받으시기 바랍니다.', 440, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이석증', '이석증', 'CHECKUP', '어지럼증이 지속되거나 호전되지 않는다면, 특히 특정 자세 변경 시 수십 초 내로 심한 어지럼증이 나타난다면 이석증(BPPV)의 가능성이 높아 이비인후과 또는 신경과 검진을 받는 것이 필요합니다. 어지럼증의 원인은 이석증 외에도 메니에르병, 전정신경염, 뇌혈관 질환 등 다양하므로 정확한 진단이 중요합니다. 어지럼증이 지속되거나 구토, 청력 저하, 두통, 복시 등이 동반된다면 즉시 의료기관을 방문하시기 바랍니다.', 441, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이석증', '이석증', 'DIET_LIFE', '이석증 치료 후에는 갑작스럽게 머리를 빠르게 움직이는 것을 피하고, 치료 당일에는 머리를 가능한 한 세운 자세(앉거나 서 있는 자세)를 유지하는 것이 권장됩니다. 식사는 특별한 제한이 없으나 어지럼증으로 인한 오심·구토 시에는 소량씩 자주 먹고 자극적인 음식을 피하는 것이 편합니다. 어지럼증이 완전히 호전될 때까지 운전이나 고소 작업을 삼가고, 증상이 재발하면 이비인후과 전문의를 다시 방문하시기 바랍니다.', 442, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이석증', '이석증', 'MEDICATION', '이석증으로 인한 어지럼증에는 항히스타민제(메클리진), 항구토제(메토클로프라미드), 벤조디아제핀(디아제팜)이 급성기 증상 완화에 사용됩니다. 그러나 이석증의 근본 치료는 이석 정복술(에플리 수기, Semont 법 등)이며, 약물은 보조적 역할에 그칩니다. 메니에르병이 동반된 경우에는 이뇨제와 저염식 등의 추가 치료가 필요하므로 이비인후과 전문의와 정확한 진단 후 치료 계획을 수립하시기 바랍니다.', 443, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이석증', '이석증', 'PREVENTION', '이석증의 어지럼증은 예고 없이 발작적으로 나타나므로, 갑작스러운 두부 자세 변경(빠르게 눕거나 일어나기, 고개를 급히 돌리기)을 피하고 천천히 움직이는 것이 낙상 예방에 중요합니다. 반복적인 이석증 환자는 전정 재활 운동을 통해 평형 기능을 강화하고, 재발 시 빠르게 이비인후과를 방문하여 이석 정복술을 받는 것이 중요합니다. 어지럼증 발생 시 안전한 장소에 앉거나 눕고, 운전 중에는 즉시 멈추시기 바랍니다.', 444, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이석증', '이석증', 'EXERCISE', '이석증으로 인한 어지럼증과 오심 개선을 위해 이비인후과 전문의의 지도 하에 브란트-다로프 운동(Brandt-Daroff exercise)이나 이석 정복술 후 전정 재활 운동이 효과적입니다. 이는 반고리관의 이석 제거와 전정 기능 재적응을 돕습니다. 이비인후과 전문의와 상담하여 본인의 이석증 유형(후반고리관, 수평반고리관 등)에 맞는 맞춤형 운동요법을 처방받는 것을 권고드립니다.', 445, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이석증', '이석증', 'CAUSE', '이석증은 주로 내이의 이석(이석기관의 탄산칼슘 결정)이 반고리관으로 이탈하여 발생하는 질환으로, 신장 질환이 직접적인 원인이 되는 경우는 드뭅니다. 다만 신장 질환으로 인한 칼슘 대사 이상(저칼슘혈증, 골다공증)이 이석 불안정화에 영향을 줄 수 있다는 일부 연구가 있습니다. 이석증은 이비인후과 전문의가 진단하고 치료하는 질환이므로, 신장 기능 이상이 있다면 내과와 이비인후과를 함께 진료받으시기 바랍니다.', 446, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이석증', '이석증', 'REHAB', '이석증으로 인한 어지럼증 재활 치료 중 가장 효과적인 방법은 이석 정복술(에플리 수기, Semont 수기 등)로, 이비인후과 전문의가 시행하며 1~3회 시술로 높은 완치율을 보입니다. 이후 전정 재활 운동(브란트-다로프 운동, 균형 훈련)을 통해 재발 방지와 전정 기능 강화를 도모합니다. 재활 치료의 효과는 조기 치료와 꾸준한 운동 참여에 따라 달라질 수 있으며, 이비인후과 전문의의 지속적인 추적 관찰을 권고드립니다.', 447, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이석증', '이석증', 'DEFINITION', '이석(otolith)은 내이 전정기관의 난형낭과 구형낭에 있는 탄산칼슘(calcium carbonate) 결정체로 구성되어 있습니다. 이석이 반고리관으로 이탈하면 두부 자세 변경 시 비정상적인 내림프액 흐름을 유발하여 어지럼증(현훈)이 발생합니다. 힘빠짐(전신 무력감)은 이석증의 직접적인 증상이 아니며, 지속적인 피로나 힘빠짐이 있다면 다른 원인을 감별하기 위해 전문의 진료를 받으시기 바랍니다.', 448, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이석증', '이석증', 'SYMPTOM', '미각 및 후각 소실, 특정 음식 섭취 후 구토는 이석증의 전형적인 증상이 아닙니다. 이석증의 주요 증상은 특정 두위 변경 시 발생하는 수십 초 내의 심한 회전성 어지럼증과 안진(눈의 빠른 떨림)이며, 오심과 구토는 심한 어지럼증에 동반될 수 있습니다. 미각·후각 소실이 있다면 코나 신경 문제를 의심하여 이비인후과 또는 신경과 전문의 진료를 받으시기 바랍니다.', 449, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이석증', '이석증', 'DIAGNOSIS', '놀이기구를 탄 것처럼 간헐적으로 나타나는 심한 회전성 어지럼증은 이석증(BPPV)의 전형적인 증상일 수 있습니다. 이석증 진단을 위해서는 이비인후과 전문의를 방문하는 것이 가장 적절하며, 딕스-홀파이크 검사(Dix-Hallpike test)나 롤 검사 등을 통해 진단합니다. 어지럼증에 청력 감소, 이명, 두통, 신경학적 증상이 동반된다면 신경과와의 협진도 필요할 수 있습니다.', 450, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이석증', '이석증', 'TREATMENT', '이석증 진단 후 응급 상황에서 현장 처치로는 ''에플리 기법(Epley maneuver)''이 가장 대표적입니다. 환자를 앉힌 상태에서 머리를 45도 돌린 뒤 빠르게 눕히고, 이후 반대편으로 머리를 돌리는 방법으로 이석을 원래 위치로 유도합니다. 단, 정확한 시술 방법을 사전에 전문의에게 익혀야 하며, 증상이 지속되면 반드시 이비인후과 또는 신경과 전문의 진료를 받으시기 바랍니다.', 451, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '인후두염', '인후두염', 'CHECKUP', '기침이 오래되고 목에 이물감이 있는 경우 이비인후과를 우선 방문하는 것이 적합합니다. 이비인후과에서는 후두경 검사 등을 통해 인후두 상태를 직접 확인할 수 있습니다. 증상이 심하거나 장기간 지속될 경우 대학병원 이비인후과를 방문하면 보다 정밀한 검사를 받을 수 있으며, 전문의 상담을 통해 정확한 원인을 파악하시기 바랍니다.', 452, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '인후두염', '인후두염', 'DIET_LIFE', '인후두염 회복에 도움이 되는 생활습관으로는 충분한 수분 섭취, 금연, 음주 자제, 실내 적정 습도(50~60%) 유지가 있습니다. 자극적인 음식과 찬 음식을 피하고, 충분한 수면과 휴식을 취하는 것이 중요합니다. 목에 무리가 가는 큰 소리나 장시간 대화를 자제하고, 손 씻기 등 개인위생 관리도 감염 예방과 회복에 도움이 됩니다.', 453, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '인후두염', '인후두염', 'MEDICATION', '인후두염으로 목이 간질거리고 아플 때는 따뜻한 꿀물, 생강차, 도라지차 등이 증상 완화에 도움이 될 수 있습니다. 따뜻한 물에 소금을 약간 녹여 가글하면 인후 염증 완화에 효과적입니다. 차갑거나 자극적인 음식, 탄산음료는 피하고, 증상이 심하거나 지속되면 이비인후과 전문의 상담을 받으시기 바랍니다.', 454, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '인후두염', '인후두염', 'PREVENTION', '가습기를 사용해 실내 습도를 50~60%로 유지하면 인후두 점막이 건조해지는 것을 막아 인후두염 예방에 도움이 됩니다. 건조한 환경은 점막 방어 기능을 약화시켜 바이러스·세균 감염에 취약하게 만들므로, 적절한 습도 조절은 효과적인 예방 수단 중 하나입니다. 단, 가습기 내부를 정기적으로 세척하지 않으면 세균이나 곰팡이가 번식할 수 있으므로 청결 유지가 필수적입니다.', 455, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '인후두염', '인후두염', 'EXERCISE', '인후두염으로 호흡 곤란이 있을 때는 격렬한 운동보다 천천히 걷기, 복식호흡 등 가벼운 유산소 운동이 권장됩니다. 호흡이 곤란한 상태에서 무리한 운동은 오히려 증상을 악화시킬 수 있습니다. 급성기에는 충분한 안정이 우선이며, 호흡 곤란 증상이 심하면 즉시 이비인후과 또는 응급실 전문의 진료를 받으시기 바랍니다.', 456, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '인후두염', '인후두염', 'CAUSE', '입을 벌리고 자는 습관은 인후두 점막을 건조하게 만들어 염증을 유발하거나 악화시킬 수 있습니다. 이를 개선하기 위해 비염이나 코막힘 등 구강호흡의 원인 질환을 먼저 치료하고, 옆으로 자는 자세를 취하거나 구강 테이프를 활용해 볼 수 있습니다. 구강호흡이 지속되면 이비인후과 전문의를 찾아 원인 질환 여부를 확인하시기 바랍니다.', 457, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '인후두염', '인후두염', 'REHAB', '목이 따갑고 삼키기 어려운 증상은 인후두염의 대표적인 증상 중 하나로, 인후두 점막에 염증이 생겼을 때 나타납니다. 이러한 증상이 수일 이상 지속되거나 고열, 호흡 곤란이 동반되면 인후두염을 의심할 수 있습니다. 정확한 진단을 위해서는 이비인후과 전문의 진찰과 후두경 검사 등이 필요하며, 자가 진단보다 전문의 상담을 권장합니다.', 458, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '인후두염', '인후두염', 'DEFINITION', '인후두염은 인두와 후두를 포함한 상기도 점막에 염증이 생기는 질환으로, 주요 증상으로는 목의 통증, 삼킴 곤란, 이물감, 쉰 목소리, 기침 등이 있습니다. 삼킴이 어려울 때는 따뜻한 물이나 부드러운 음식을 섭취하고 충분한 수분을 유지하는 것이 도움이 됩니다. 증상이 심하거나 고열이 동반되면 이비인후과 전문의 진료를 받으시기 바랍니다.', 459, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '인후두염', '인후두염', 'SYMPTOM', '음식물이나 침을 삼킬 때 이물감과 통증이 나타나는 것은 인후두 점막의 염증으로 인한 인후두염의 주요 증상입니다. 인후두염에서는 점막이 부어오르고 자극에 민감해지기 때문에 연하 시 불편감이 발생합니다. 이러한 증상이 지속되거나 악화되면 이비인후과 전문의 진찰을 통해 정확한 원인 파악과 적절한 치료를 받으시기 바랍니다.', 460, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '인후두염', '인후두염', 'DIAGNOSIS', '목소리가 자주 쉬고 만성 기침이 있는 경우, 이비인후과 방문은 매우 적합한 선택입니다. 이비인후과에서는 후두경 등을 통해 성대 및 후두 상태를 직접 관찰하고 인후두 역류, 만성 인후두염, 성대 질환 등을 감별할 수 있습니다. 증상이 2주 이상 지속될 경우 조기에 전문의 진찰을 받는 것이 중요하며, 필요 시 추가 검사를 권장합니다.', 461, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '인후두염', '인후두염', 'TREATMENT', '인후두염 치료에는 원인에 따라 세균 감염 시 항생제(아목시실린 등 페니실린계 등)가 사용되며, 바이러스성인 경우 항생제는 효과가 없습니다. 항생제 외에도 소염진통제, 해열제, 점액 용해제, 항히스타민제 등이 증상 완화를 위해 함께 사용됩니다. 약물 선택과 복용은 반드시 이비인후과 전문의 처방에 따라야 하며, 임의로 항생제를 복용하는 것은 삼가시기 바랍니다.', 462, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도결석', '편도결석', 'CHECKUP', '구강이나 식도, 후두 등에서 노란 알갱이(편도결석)가 나오는 경우, 이비인후과 전문의에게 진단을 받는 것이 가장 적합합니다. 이비인후과에서는 편도와 주변 구조를 직접 확인하고 편도결석의 유무, 위치, 크기 등을 정확히 평가할 수 있습니다. 증상이 반복되거나 구취, 목 이물감이 심하면 전문의 상담을 통해 적절한 치료 방향을 결정하시기 바랍니다.', 463, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도결석', '편도결석', 'DIET_LIFE', '양치 후 가글은 구강 내 세균과 음식물 찌꺼기를 제거하여 편도 소와(편도 표면의 작은 구멍)에 이물질이 축적되는 것을 방지합니다. 편도결석은 세균, 음식물 잔사, 탈락된 상피세포 등이 편도 소와에 쌓여 굳어지는 것이므로, 가글로 이 환경을 개선하면 결석 재발 예방에 도움이 됩니다. 단, 가글만으로 완전한 예방이 어려울 수 있으므로 증상이 반복되면 이비인후과 전문의 상담을 권장합니다.', 464, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도결석', '편도결석', 'MEDICATION', '편도결석은 약물로 직접 용해하는 치료법은 없으며, 주로 가글이나 식염수로 세척하는 방법이 사용됩니다. 세균 감염이 동반된 경우 항생제가 처방될 수 있으나, 장기적으로 반복 발생하면 편도선 절제술이 고려됩니다. 항생제 사용은 내성 문제가 있으므로 반드시 전문의 처방에 따라야 하며, 자의적 약물 복용은 삼가시기 바랍니다.', 465, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도결석', '편도결석', 'PREVENTION', '편도결석 제거를 위해 면봉 대신 식염수 구강 세척기(오럴 세정기)를 사용하면 보다 효과적으로 결석을 제거할 수 있습니다. 또한 식염수 가글을 규칙적으로 시행하면 결석 형성을 억제하는 데 도움이 됩니다. 결석이 자주 재발하거나 심한 구취, 반복적 편도 감염이 동반되면 이비인후과 전문의와 편도절제술 여부를 상담하시기 바랍니다.', 466, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도결석', '편도결석', 'EXERCISE', '편도결석은 편도 소와에 이물질이 쌓여 발생하는 것으로, 운동 자체가 편도결석을 직접 예방하지는 않습니다. 다만 규칙적인 유산소 운동으로 면역 기능을 강화하면 편도 염증 발생을 줄이는 데 간접적으로 도움이 될 수 있습니다. 편도결석 예방에는 구강 위생 관리, 충분한 수분 섭취, 금연이 더욱 직접적으로 효과적이며, 반복 발생 시 이비인후과 전문의 상담을 권장합니다.', 467, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도결석', '편도결석', 'CAUSE', '편도결석 제거 후에도 이물감과 통증이 지속되는 것은 편도 조직에 남은 염증이나 세균 감염, 혹은 새로운 결석 형성 때문일 수 있습니다. 편도결석 자체는 직접적인 통증의 원인이기보다는 편도 주변 염증이나 감염이 불편감을 유발합니다. 증상이 지속된다면 이비인후과 전문의를 방문하여 정확한 원인을 파악하고 적절한 치료를 받으시기 바랍니다.', 468, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도결석', '편도결석', 'REHAB', '식도에 구멍(천공)이 생긴 경우는 편도결석과는 직접적인 관련이 없으며, 식도 천공은 내시경 시술, 외상, 이물질 삽입 등에 의해 발생하는 심각한 상태입니다. 식도에 한번 천공이 생겼다면 치료 후에도 구조적 약화로 재발 가능성이 있으므로 반드시 소화기내과 또는 흉부외과 전문의의 관리를 받아야 합니다. 음식물이 잘못 넘어가거나 삼킴 장애가 있을 경우 즉시 전문의 진료를 받으시기 바랍니다.', 469, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도결석', '편도결석', 'DEFINITION', '편도결석(tonsillolith)은 편도 표면에 있는 작은 구멍(편도 소와)에 세균, 음식 찌꺼기, 점액 등이 쌓여 굳어진 흰색 또는 노란색 알갱이 형태의 물질입니다. 편도결석은 신장 결석 등의 ''결석''과는 다른 개념으로, 석회화된 잔해물이 편도에 축적된 것입니다. 주요 증상으로는 구취, 목 이물감, 경미한 인후 통증 등이 있으며, 정확한 진단과 치료는 이비인후과 전문의와 상담하시기 바랍니다.', 470, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도결석', '편도결석', 'SYMPTOM', '편도결석의 증상으로는 목 이물감, 심한 구취, 삼킬 때 불편감이 대표적이며, 침을 삼킬 때 이상한 느낌이나 약한 인후 통증이 나타날 수 있습니다. 결석의 크기가 크거나 염증이 동반된 경우 목 통증이 더욱 심해질 수 있습니다. 이러한 증상이 지속되거나 반복된다면 이비인후과 전문의를 방문하여 정확한 진단과 치료를 받으시기 바랍니다.', 471, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도결석', '편도결석', 'DIAGNOSIS', '편도결석의 진단과 치료는 이비인후과가 가장 적합한 전문과입니다. 이비인후과에서 편도 및 구강 구조를 직접 확인하고 결석 제거, 세척 등의 처치가 가능합니다. 내과나 가정의학과에서도 초기 평가는 가능하지만, 편도결석이 의심된다면 이비인후과 전문의에게 직접 진단받는 것이 가장 정확하고 효과적입니다.', 472, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도결석', '편도결석', 'TREATMENT', '편도선 절제술은 편도결석이 반복적으로 재발하거나 만성 편도염을 동반하는 경우에 고려되는 치료법으로, 편도 소와 자체를 제거하여 결석 재발을 근본적으로 방지합니다. 수술은 전신마취 하에 시행되며, 수술 후 회복 기간 동안 통증 관리가 필요합니다. 수술 여부는 증상의 빈도와 심각도, 환자 상태를 종합적으로 고려하여 이비인후과 전문의와 충분히 상담 후 결정하시기 바랍니다.', 473, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도선염', '편도선염', 'CHECKUP', '편도선이 부어 침을 삼키기 어려울 때는 이비인후과가 가장 적합한 진료과입니다. 이비인후과에서 편도 부종의 원인(세균성, 바이러스성 등)을 감별하고 적절한 치료를 시행합니다. 증상이 심하거나 호흡 곤란, 고열이 동반되는 경우에는 즉시 응급실을 방문하거나 이비인후과 전문의에게 진료를 받으시기 바랍니다.', 474, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도선염', '편도선염', 'DIET_LIFE', '아이스크림과 같은 차갑고 부드러운 음식은 편도선염으로 인한 목 부종과 통증을 일시적으로 완화하는 데 도움이 될 수 있습니다. 냉기가 인후 점막의 혈관을 수축시켜 부종을 일시적으로 줄여주는 효과가 있습니다. 다만 이는 증상 완화에 도움이 될 뿐 치료는 아니므로, 고열이나 삼킴 장애 등 심한 증상이 있으면 이비인후과 전문의 진료를 받아 적절한 치료를 받으시기 바랍니다.', 475, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도선염', '편도선염', 'MEDICATION', '편도선염의 통증과 발열 완화를 위해 아세트아미노펜(타이레놀)이나 이부프로펜(부루펜) 같은 비스테로이드성 소염진통제(NSAIDs)가 일반적으로 사용됩니다. 세균성 편도선염의 경우 의사 처방에 따라 페니실린계 또는 세팔로스포린계 항생제가 추가됩니다. 모든 약물은 의사 또는 약사의 지도 하에 복용해야 하며, 증상이 3일 이상 지속되면 이비인후과 전문의 진료를 권장합니다.', 476, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도선염', '편도선염', 'PREVENTION', '편도선염으로 침을 삼키기 어려울 때는 따뜻하거나 시원한 물을 조금씩 자주 마시고, 아이스크림이나 죽처럼 부드러운 음식을 섭취하는 것이 도움이 됩니다. 인후 통증이 심할 경우 의사 처방에 따른 소염진통제 복용도 고려할 수 있습니다. 삼킴이 극도로 어렵거나 호흡 곤란이 동반되면 즉시 이비인후과 또는 응급실을 방문하시기 바랍니다.', 477, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도선염', '편도선염', 'EXERCISE', '편도선염 급성기에는 충분한 휴식이 우선이며, 격렬한 운동은 피해야 합니다. 회복 후에는 가벼운 걷기, 요가, 스트레칭 등 강도가 낮은 운동부터 시작하는 것이 좋습니다. 삼킬 때 따끔거리는 증상은 운동으로 직접 완화되기보다 충분한 수분 섭취와 안정이 더욱 중요하며, 증상이 지속되면 이비인후과 전문의 상담을 받으시기 바랍니다.', 478, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도선염', '편도선염', 'CAUSE', '갑자기 추운 환경에 노출되면 인후 점막 혈류가 감소하고 면역 기능이 일시적으로 저하되어 세균이나 바이러스에 대한 저항력이 약해질 수 있어 편도선염 발생 위험이 높아집니다. 편도선염의 주요 원인으로는 A군 연쇄상구균, 아데노바이러스, 엡스타인-바 바이러스 감염이 있으며, 피로 누적과 면역력 저하도 중요한 요인입니다. 반복적인 편도선염이 있다면 이비인후과 전문의 상담을 권장합니다.', 479, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도선염', '편도선염', 'DEFINITION', '편도선염은 구개편도에 세균이나 바이러스가 감염되어 발생하는 급성 또는 만성 염증 질환입니다. 주요 원인균은 A군 베타 용혈성 연쇄상구균이며, 아데노바이러스 등 바이러스도 원인이 됩니다. 주요 증상으로는 심한 인후 통증, 연하 곤란, 발열, 편도 발적 및 삼출물 등이 있으며, 정확한 진단과 치료를 위해 이비인후과 전문의 진료를 받으시기 바랍니다.', 480, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도선염', '편도선염', 'SYMPTOM', '편도선염의 주요 증상으로는 심한 인후 통증, 연하 곤란, 고열, 편도 발적 및 삼출물 등이 있으며, 쉰 목소리와 가래, 목 부종도 나타날 수 있습니다. 특히 만성 편도선염의 경우 목소리 변화와 지속적인 가래, 목 이물감이 반복적으로 발생할 수 있습니다. 증상이 지속되거나 반복된다면 이비인후과 전문의 진찰을 통해 만성화 여부와 치료 방향을 결정하시기 바랍니다.', 481, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도선염', '편도선염', 'DIAGNOSIS', '목과 편도선의 부종이 있을 경우 이비인후과에서 인후 시진 및 편도 관찰, 인후 도말 배양 검사, 신속 연쇄상구균 검사 등을 통해 편도선염 여부를 진단합니다. 부종의 정도와 삼출물 유무, 발열 등의 전신 증상을 종합적으로 평가합니다. 증상이 있다면 이비인후과 전문의를 방문하여 정확한 진단과 그에 맞는 치료를 받으시기 바랍니다.', 482, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도선염', '편도선염', 'TREATMENT', '목감기(인후염)와 편도선염 모두 이비인후과에서 진료 및 치료를 받는 것이 가장 적합합니다. 세균성인 경우 항생제, 바이러스성인 경우 소염진통제, 해열제 등 대증요법이 주된 치료입니다. 반복적인 편도선염이나 편도 비대로 호흡 및 수면 장애가 동반될 경우 편도절제술을 고려할 수 있으며, 전문의와 충분히 상담하시기 바랍니다.', 483, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도암', '편도암', 'CHECKUP', '편도암 진단을 위해서는 이비인후과에서 시행하는 구강 및 인두 시진, 경부 촉진, 후두경 검사가 먼저 이루어집니다. 의심 병변에 대해 조직 생검(병리 조직 검사)이 확진의 핵심 검사이며, CT·MRI·PET-CT 등 영상 검사로 병기 결정 및 전이 여부를 평가합니다. 편도암이 의심되면 지체 없이 이비인후과 두경부 전문의를 방문하시기 바랍니다.', 484, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도암', '편도암', 'DIET_LIFE', '흡연은 담배 연기 속의 발암물질이 편도를 포함한 구강·인두 점막에 직접 접촉하여 DNA 손상과 세포 변이를 유발하고, 면역 기능을 저하시켜 편도암 발병 위험을 높입니다. 따라서 금연이 가장 중요한 예방 및 위험 감소 방법이며, 절주와 건강한 식습관도 함께 권장됩니다. HPV(인유두종 바이러스) 감염도 편도암의 중요한 원인이므로 HPV 백신 접종도 고려할 수 있습니다.', 485, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도암', '편도암', 'MEDICATION', '편도암 치료에 사용되는 주요 항암제로는 시스플라틴, 카보플라틴, 5-플루오로우라실(5-FU) 등이 있으며, 표적치료제인 세툭시맙(Cetuximab)도 사용됩니다. 이들 약물의 주요 부작용으로는 오심, 구토, 구내염, 신장 독성, 청력 손실, 면역 저하 등이 있습니다. 항암 치료는 반드시 종양내과 또는 두경부 전문 이비인후과 전문의의 처방과 관리 하에 시행되어야 합니다.', 486, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도암', '편도암', 'PREVENTION', '편도선이 약하다는 진단을 받은 경우 편도암 예방을 위해 금연, 절주, 구강 위생 관리가 중요합니다. HPV 감염 예방을 위한 HPV 백신 접종도 고려할 수 있으며, 정기적인 이비인후과 검진을 통해 구강 및 편도 상태를 모니터링하는 것이 권장됩니다. 목 이물감, 삼킴 장애, 경부 종물 등 이상 증상이 나타나면 즉시 전문의 진료를 받으시기 바랍니다.', 487, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도암', '편도암', 'EXERCISE', '편도암 환자에게는 치료 부작용으로 인한 체력 저하를 고려하여 무리하지 않는 범위에서 가벼운 걷기나 스트레칭 등 저강도 운동이 도움이 됩니다. 목 통증과 구역질, 목 부종이 있는 경우 격렬한 운동은 삼가고, 구강 및 경부 근육 이완 운동이 삼킴 기능 유지에 도움이 될 수 있습니다. 운동 계획은 담당 종양내과 또는 재활의학과 전문의와 상의하여 환자 상태에 맞게 조정하시기 바랍니다.', 488, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도암', '편도암', 'CAUSE', '편도암의 주요 원인으로는 흡연, 과도한 음주, HPV(인유두종 바이러스) 16형·18형 감염이 있습니다. HPV 감염은 특히 구인두암과 편도암 발생과 강한 연관성이 있으며, 유전적 요인도 일부 역할을 합니다. 편도암의 위험 요인이 있는 경우 정기적인 이비인후과 검진을 받고, 이상 증상 발생 시 지체 없이 전문의 진료를 받으시기 바랍니다.', 489, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도암', '편도암', 'REHAB', '편도암 환자가 항암 치료 전 요양병원에 입원할 때는 기본 혈액검사(혈구수, 간·신장 기능), 심전도, 흉부 X선, 영양 상태 평가, 구강 상태 점검 등이 이루어질 수 있습니다. 또한 기존에 시행된 CT·MRI·PET-CT 결과 검토와 전신 수행 능력 평가도 포함됩니다. 항암 전 준비와 검사는 담당 의료진의 지시에 따르며, 궁금한 사항은 담당 전문의에게 문의하시기 바랍니다.', 490, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도암', '편도암', 'DEFINITION', '흡연자는 담배의 발암물질에 의한 지속적인 점막 손상, 면역 기능 저하, 만성 염증 등으로 인해 편도암을 포함한 두경부암 발생 위험이 비흡연자에 비해 현저히 높습니다. 흡연 기간이 길고 흡연량이 많을수록 위험도는 더욱 증가하며, 음주와 병행할 경우 위험이 상승합니다. 금연은 편도암 예방을 위한 가장 중요한 조치이므로, 금연 치료 및 금연 클리닉 이용을 강력히 권장합니다.', 491, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도암', '편도암', 'SYMPTOM', '편도암에서 침 삼키기 어려움(연하 곤란)은 종양이 편도 및 인두벽을 침범하여 정상적인 삼킴 기능을 방해하기 때문에 나타납니다. 귀의 통증(이통)은 설인신경이나 미주신경을 통한 연관통으로 발생하며, 고열은 종양에 의한 이차 감염이나 조직 괴사로 인한 것입니다. 이러한 증상들이 지속될 경우 즉시 이비인후과 두경부 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 492, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도암', '편도암', 'DIAGNOSIS', '편도암이 의심될 경우 이비인후과(두경부외과) 전문의와 상담하는 것이 가장 적합합니다. 진단을 위해 구강·인두 시진, 경부 림프절 촉진, 내시경 검사, 조직 생검, CT·MRI 등 영상 검사가 필요합니다. 증상이 2주 이상 지속되거나 경부 종물, 체중 감소 등이 동반되면 지체 없이 이비인후과 전문의 진료를 받으시기 바랍니다.', 493, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '편도암', '편도암', 'TREATMENT', '편도암으로 인해 목에서 출혈이 있거나 삼킬 때 이물감이 있는 경우, 수술적 치료(편도 절제 및 경부 림프절 절제), 방사선 치료, 항암화학요법 또는 이들을 병합하는 치료가 주로 사용됩니다. 최근에는 로봇 수술(TORS)이나 표적치료제, 면역항암제 등도 적용됩니다. 치료 방법은 종양의 병기와 환자 상태에 따라 결정되므로, 두경부 전문 이비인후과 및 종양내과 전문의와 상담하시기 바랍니다.', 494, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후두암', '후두암', 'CHECKUP', '목쉼, 목의 덩이 촉지, 삼킴 어려움은 후두암의 대표적인 증상으로, 이러한 증상이 2주 이상 지속될 경우 후두암을 포함한 두경부 악성 종양을 조기에 발견하기 위해 검진이 권장됩니다. 후두암은 조기 발견 시 치료 성적이 현저히 좋아지므로, 증상 초기에 이비인후과 전문의를 방문하여 후두경 검사를 받는 것이 중요합니다. 흡연력이 있거나 증상이 지속된다면 지체 없이 검진을 받으시기 바랍니다.', 495, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후두암', '후두암', 'DIET_LIFE', '흡연과 과도한 음주는 후두 점막에 직접적인 발암물질을 노출시키고 만성 염증을 유발하여 후두암 발생 위험을 크게 높입니다. 다수의 역학 연구에서 흡연자는 비흡연자보다 후두암 위험이 5~10배 이상 높으며, 흡연과 음주를 병행할 경우 위험이 상승하는 것으로 보고되어 있습니다. 후두암 예방을 위해 금연과 절주가 가장 효과적인 방법임이 의학적으로 확립되어 있습니다.', 496, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후두암', '후두암', 'MEDICATION', '후두암 수술 후 통증 관리에는 아세트아미노펜, NSAIDs(이부프로펜 등), 필요 시 오피오이드계 진통제가 사용될 수 있습니다. 통증 정도와 수술 범위에 따라 처방이 달라지므로, 반드시 담당 주치의의 처방에 따라 복용해야 합니다. 자의적으로 진통제를 추가 복용하거나 중단하면 위험할 수 있으므로, 통증 조절에 대해 담당 의료진과 충분히 상의하시기 바랍니다.', 497, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후두암', '후두암', 'PREVENTION', '흡연 외에도 후두암 발생에 영향을 미치는 환경적 요인으로는 과도한 음주, 석면·포름알데하이드·화학물질 등 직업적 발암물질 노출, 만성 인후두 역류(GERD), 방사선 노출 등이 있습니다. HPV 감염도 일부 후두암과 관련이 있다는 연구가 있습니다. 이러한 위험 요인을 줄이는 것이 예방에 중요하며, 위험 요인이 있다면 정기적인 이비인후과 검진을 받으시기 바랍니다.', 498, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후두암', '후두암', 'EXERCISE', '후두암 수술(특히 후두전절제술) 후 발성 재활을 위해 식도발성, 전기후두(electrolarynx) 사용, 기관-식도 천공술(TEP)을 통한 보조기 발성 훈련 등이 활용됩니다. 언어재활사와 함께 구강·인두 근육 강화 운동, 정확한 조음 훈련, 호흡 조절 훈련을 시행합니다. 재활 방법은 수술 종류와 환자 상태에 따라 달라지므로, 담당 이비인후과 및 언어재활 전문가의 지도 하에 진행하시기 바랍니다.', 499, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후두암', '후두암', 'CAUSE', '비흡연자가 후두암에 걸리는 주요 원인으로는 과도한 음주, 직업적 발암물질(석면, 화학물질 등) 노출, 만성 위식도 역류, HPV 감염, 방사선 노출 등이 있습니다. 가족 중 흡연자가 있는 경우 간접흡연에 지속적으로 노출되면 후두암 발생 위험이 높아질 수 있습니다. 따라서 간접흡연 차단, 실내 환기, 건강한 생활습관 유지가 중요하며 이상 증상 발생 시 이비인후과 전문의 진료를 받으시기 바랍니다.', 500, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후두암', '후두암', 'REHAB', '후두암 환자를 위한 재활 서비스(발성 재활, 연하 재활, 호흡 재활)를 전문적으로 제공하는 대학병원의 이비인후과 또는 재활의학과를 선택하는 것이 권장됩니다. 언어재활사, 작업치료사 등 다학제 팀이 있는 의료기관이 적합하며, 담당 이비인후과 전문의에게 재활 프로그램이 있는 기관을 추천받는 것이 가장 좋습니다. 재활 계획은 수술 방식과 환자 상태에 따라 개인화되어야 합니다.', 501, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후두암', '후두암', 'DEFINITION', '후두암은 후두(성대를 포함한 목 부위의 기관)에 발생하는 악성 종양으로, 흡연과 음주가 주요 원인입니다. 대표적인 증상으로는 2주 이상 지속되는 쉰 목소리·음성 변화, 삼킴 장애, 목의 종물, 만성 기침, 호흡 곤란, 이통 등이 있습니다. 이러한 증상이 지속되면 즉시 이비인후과 전문의를 방문하여 후두경 검사 및 조직 검사를 받으시기 바랍니다.', 502, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후두암', '후두암', 'SYMPTOM', '목소리가 잘 나오지 않거나 본인 목소리가 아닌 것 같은 증상이 지속되면 이비인후과에서 후두 내시경(후두경) 검사를 받아 성대와 후두 상태를 직접 확인하는 것이 필요합니다. 후두암 외에도 성대 결절, 성대 폴립, 성대 마비 등 다양한 원인이 있을 수 있습니다. 증상이 2주 이상 지속되면 지체 없이 이비인후과 전문의 진료를 받으시기 바랍니다.', 503, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후두암', '후두암', 'DIAGNOSIS', '쉰 목소리와 후두암 의심 증상이 있을 경우 이비인후과(두경부 전문)를 방문하는 것이 가장 적합합니다. 대학병원의 이비인후과 두경부외과에서 후두경 검사, 조직 생검, CT·MRI 등 정밀 검사를 시행합니다. 가까운 이비인후과 의원에서 초기 진찰 후 필요 시 상급 의료기관으로 의뢰받는 방법도 있으며, 증상이 의심되면 빠른 시일 내에 전문의 진료를 받으시기 바랍니다.', 504, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후두암', '후두암', 'TREATMENT', '후두암의 치료 방법은 병기에 따라 수술, 방사선 치료, 항암화학요법 또는 복합 치료가 시행됩니다. 조기(1~2기)에는 방사선 단독 치료 또는 내시경 레이저 수술로 성공률이 높으며, 진행된 경우 후두 부분·전절제술과 방사선·항암 병합 치료가 이루어집니다. 치료 과정 단축을 위해서는 조기 발견이 가장 중요하며, 이상 증상 발생 시 즉시 이비인후과 전문의를 방문하시기 바랍니다.', 505, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후비루', '후비루', 'CHECKUP', '후비루 검진은 이비인후과에서 이루어지며, 비강 내시경 검사를 통해 콧속 상태와 분비물의 양상을 직접 확인합니다. 필요에 따라 부비동 CT 촬영, 알레르기 피부 반응 검사 또는 혈액 알레르기 검사(MAST 등)를 시행하여 원인을 파악합니다. 기침이나 목 이물감이 오래 지속될 경우 이비인후과 전문의 진료를 받아 정확한 원인 질환을 진단받으시기 바랍니다.', 506, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후비루', '후비루', 'DIET_LIFE', '후비루 개선을 위해 자극적인 음식(맵고 짠 음식), 알코올, 흡연을 피하고 충분한 수분을 섭취하는 것이 중요합니다. 실내 습도를 적절히 유지하고 먼지·꽃가루·반려동물 털 등 알레르겐 노출을 줄이는 것도 도움이 됩니다. 자기 전 머리를 약간 높이고, 식후 바로 눕는 것을 피해 역류로 인한 자극을 줄이는 것도 증상 완화에 효과적입니다.', 507, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후비루', '후비루', 'MEDICATION', '후비루 치료에는 원인에 따라 항히스타민제, 비강 내 스테로이드 스프레이, 충혈완화제, 비강 세척(생리식염수) 등이 사용됩니다. 기침을 완전히 없애기 위해서는 원인 질환(알레르기 비염, 부비동염 등)을 근본적으로 치료하는 것이 중요합니다. 약물 치료 외에도 알레르기 면역요법, 부비동 수술 등이 고려될 수 있으며, 정확한 치료 방법은 이비인후과 전문의와 상담하시기 바랍니다.', 508, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후비루', '후비루', 'PREVENTION', '목에 가래가 끼고 넘어가는 증상(후비루) 예방을 위해 규칙적인 손 씻기, 충분한 수분 섭취, 실내 적정 습도 유지가 중요합니다. 알레르겐(먼지, 꽃가루, 반려동물 털 등) 노출을 줄이고, 금연 및 공기 오염 환경을 피하는 것도 도움이 됩니다. 알레르기 비염이나 부비동염이 있다면 정기적으로 이비인후과 전문의에게 관리를 받으시기 바랍니다.', 509, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후비루', '후비루', 'CAUSE', '후비루는 코 점막에서 과도하게 생성된 점액이 코 뒤쪽으로 넘어가 목으로 흘러내리는 상태로, 비염, 부비동염, 알레르기 등이 주요 원인입니다. 이로 인해 목 뒤로 끈적한 점액이 흐르는 느낌, 잦은 헛기침, 목 이물감, 목 답답함, 만성 기침 등이 나타납니다. 증상이 지속되면 원인 질환을 정확히 파악하기 위해 이비인후과 전문의 진료를 받으시기 바랍니다.', 510, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후비루', '후비루', 'DEFINITION', '후비루는 코에서 과도하게 생성된 점액이 목 뒤로 넘어가는 증상(증후군)이며, 비염은 코 점막의 염증 질환입니다. 비염(알레르기 비염, 만성 비염 등)이 후비루의 주요 원인 중 하나이지만, 후비루는 부비동염, 위식도 역류, 기타 코 질환 등 다양한 원인으로도 발생할 수 있어 비염과 구별되는 별개의 증후군입니다. 두 질환이 함께 있을 수 있으므로 이비인후과 전문의 진료로 정확히 감별하시기 바랍니다.', 511, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후비루', '후비루', 'SYMPTOM', '후비루의 증상으로는 콧물이 목 뒤로 지속적으로 넘어가는 느낌, 목이 답답하고 불편한 이물감, 반복적인 헛기침, 만성 기침 등이 있으며, 이는 매우 전형적인 후비루 증상입니다. 특히 아침에 기상 후 증상이 심해지거나 눕는 자세에서 악화되는 경향이 있습니다. 이러한 증상이 지속된다면 이비인후과 전문의를 방문하여 원인 질환을 파악하고 적절한 치료를 받으시기 바랍니다.', 512, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후비루', '후비루', 'DIAGNOSIS', '후비루 진단의 경우 대부분 동네 이비인후과에서도 비강 내시경, 알레르기 검사 등 기본 진단이 가능하며, 처음에는 가까운 이비인후과를 방문하는 것이 적합합니다. 증상이 복잡하거나 치료에 반응이 없거나 부비동 수술 등 전문 치료가 필요한 경우 종합병원 이비인후과로 의뢰받는 것이 좋습니다. 증상 기간과 정도에 따라 전문의와 상담 후 적절한 의료기관을 선택하시기 바랍니다.', 513, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '후비루', '후비루', 'TREATMENT', '후비루의 가장 흔한 원인 질환은 알레르기 비염과 만성 부비동염(축농증)이며, 그 외 비알레르기성 혈관운동성 비염, 위식도 역류 등도 원인이 됩니다. 알레르기 비염에는 항히스타민제와 비강 스테로이드 스프레이, 부비동염에는 항생제와 부비동 세척, 역류 질환에는 위산 억제제가 각각 주된 치료로 사용됩니다. 원인에 따라 치료가 다르므로 이비인후과 전문의 진찰을 통해 정확한 원인을 파악하는 것이 중요합니다.', 514, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', 'VDT 증후군', 'vdt증후군', 'PREVENTION', 'VDT(영상표시단말기) 증후군 예방을 위해 작업 중 50분마다 10분 정도 휴식을 취하고, 먼 곳을 바라보며 눈 피로를 줄이는 것이 권장됩니다. 모니터는 눈높이보다 약간 아래에, 눈에서 50~70cm 거리에 두고 화면 밝기와 대비를 적절히 조정하며, 방음 및 눈 높이에 맞는 의자·책상을 갖춥니다. 작업 중 의식적으로 눈 깜빡임을 늘리고, 정기적인 스트레칭으로 목·어깨 근육 긴장을 완화하는 것도 중요합니다.', 515, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', 'VDT 증후군', 'vdt증후군', 'EXERCISE', 'VDT 증후군으로 인한 눈 피로 개선을 위해서는 눈 주위 근육 스트레칭(눈 크게 뜨기, 감기 반복), 눈동자를 상하좌우로 굴리는 운동, 멀리 보기 등이 도움이 됩니다. 어깨 통증 완화를 위해서는 어깨 으쓱하기, 목 좌우 기울이기, 팔 뒤로 젖히기 등 간단한 스트레칭을 작업 중 규칙적으로 시행하는 것이 권장됩니다. 증상이 심하면 안과 또는 정형외과 전문의 진료를 받으시기 바랍니다.', 516, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', 'VDT 증후군', 'vdt증후군', 'CAUSE', 'VDT 증후군에서 장시간 앉아있는 습관이 문제가 되는 이유는 목과 어깨 근육이 장시간 긴장 상태를 유지하면서 혈액순환이 감소하고 근육 피로와 통증이 축적되기 때문입니다. 또한 잘못된 앉는 자세는 경추에 부담을 주어 디스크 압력을 높이고 신경을 압박합니다. 규칙적인 자세 교정과 스트레칭, 작업 환경 개선이 VDT 증후군 예방과 치료에 필수적입니다.', 517, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', 'VDT 증후군', 'vdt증후군', 'DEFINITION', 'VDT 증후군의 증상으로는 눈의 피로·건조·충혈, 두통, 목·어깨·손목 통증, 집중력 저하 등이 있으며, 증상에 따라 적합한 전문과가 다릅니다. 눈 증상은 안과, 목·어깨·손목 통증은 정형외과 또는 재활의학과, 두통과 전신 피로는 가정의학과에서 상담받을 수 있습니다. 복합적인 증상이 있다면 가정의학과에서 초기 평가 후 해당 전문과로 의뢰받는 것이 효율적입니다.', 518, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', 'VDT 증후군', 'vdt증후군', 'SYMPTOM', 'VDT 증후군으로 인한 눈 뻐근함, 두통, 목·어깨 통증이 나타나면 즉시 화면에서 눈을 떼고 눈을 감거나 먼 곳을 바라보며 휴식을 취해야 합니다. 경직된 목·어깨는 가볍게 스트레칭하고, 목과 어깨에 온찜질을 적용하면 도움이 됩니다. 증상이 반복되거나 업무에 지장을 줄 정도면 안과·정형외과·재활의학과 전문의 진료를 받아 정확한 원인을 파악하고 치료받으시기 바랍니다.', 519, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', 'VDT 증후군', 'vdt증후군', 'TREATMENT', 'VDT 증후군 재활에 체조(스트레칭 체조)는 경직된 목, 어깨, 허리 근육을 이완시키고 혈액순환을 개선하여 통증 감소와 자세 교정에 효과적입니다. 특히 경추·흉추 신전 운동, 어깨 회전 운동, 손목·팔목 스트레칭은 VDT 관련 근골격 증상 완화에 근거가 있습니다. 규칙적으로 시행하되, 통증이 심하거나 동작 중 악화되면 재활의학과 전문의의 지도 하에 진행하시기 바랍니다.', 520, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '강직성 척추염', '강직성척추염', 'MEDICATION', '강직성 척추염 치료에는 NSAIDs(비스테로이드성 소염진통제)가 1차 약물로 사용되며, 인도메타신, 디클로페낙, 세레콕시브 등이 대표적입니다. NSAIDs에 반응이 부족하거나 부작용이 있는 경우 TNF-알파 억제제(에타너셉트, 아달리무맙 등) 또는 IL-17 억제제(세쿠키누맙) 같은 생물학적 제제가 사용됩니다. 약물 선택과 복용은 반드시 류마티스내과 전문의의 처방과 지속적 모니터링 하에 이루어져야 합니다.', 521, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '강직성 척추염', '강직성척추염', 'CAUSE', '강직성 척추염에서 기상 후 허리 뻣뻣함과 통증은 이 질환의 가장 특징적인 증상 중 하나로, 척추와 천장관절에 만성 염증이 발생하고 야간에 활동이 줄어들며 염증성 삼출물이 축적되기 때문입니다. 이 조조강직은 움직임을 시작한 후 30분~수 시간에 걸쳐 완화되는 것이 특징이며, 안정 시 악화되고 운동 후 호전되는 점이 기계적 허리 통증과 구별됩니다. 이러한 증상이 지속된다면 류마티스내과 전문의 진료를 받으시기 바랍니다.', 522, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '강직성 척추염', '강직성척추염', 'REHAB', '강직성 척추염 재활을 위해 수중 치료(수영, 아쿠아 운동), 척추 신전 운동, 자세 교정 운동, 심호흡 운동 등이 권장됩니다. 물리치료(열 치료, 전기 치료)와 함께 규칙적인 스트레칭으로 척추 유연성을 유지하는 것이 중요합니다. 재활 프로그램은 류마티스내과 및 재활의학과 전문의와 물리치료사의 협력 하에 개인 맞춤형으로 진행하시기 바랍니다.', 523, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '강직성 척추염', '강직성척추염', 'DEFINITION', '강직성 척추염에 걸리면 척추와 천장관절에 만성 염증이 발생하여 허리와 엉덩이의 통증, 조조강직이 나타나며, 장기적으로 척추 골 형성과 유합이 진행되어 척추가 대나무 형태로 굳는 신체 변화가 올 수 있습니다. 허리와 엉덩이의 지속적인 통증과 뻣뻣함, 움직임 제한이 주요 증상이며, 안정 시 악화되고 운동 후 호전되는 특징이 있습니다. 류마티스내과 전문의 진료를 통해 정확한 진단과 치료를 받으시기 바랍니다.', 524, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '강직성 척추염', '강직성척추염', 'SYMPTOM', '강직성 척추염에서 허리·등의 지속적 통증과 흉통은 척추 및 늑골-척추 관절에 염증이 생긴 것을 시사하며, 아침에 심하고 운동 후 호전되며 야간에 악화되는 패턴이 특징적입니다. 이러한 증상이 3개월 이상 지속되고 45세 이전에 발생한 경우 강직성 척추염을 강력히 의심할 수 있습니다. 정확한 진단을 위해 류마티스내과 전문의를 방문하여 MRI, 방사선 검사, HLA-B27 혈액 검사 등을 받으시기 바랍니다.', 525, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '강직성 척추염', '강직성척추염', 'DIAGNOSIS', '척추 염증으로 움직임이 둔해진 경우 강직성 척추염을 포함한 척추관절병증을 진단하기 위해 류마티스내과 전문의를 방문하는 것이 가장 적합합니다. 류마티스내과에서 HLA-B27 검사, 척추·천장관절 MRI 및 방사선 검사, 염증 수치(ESR, CRP) 등을 통해 정확한 진단이 이루어집니다. 대학병원 류마티스내과 또는 류마티스 전문 클리닉에서 진료를 받으시기 바랍니다.', 526, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '강직성 척추염', '강직성척추염', 'TREATMENT', '강직성 척추염은 완치보다는 장기적인 관리가 필요한 만성 질환으로, 치료 반응은 염증의 정도, HLA-B27 양성 여부, 발병 연령, 치료 시작 시기 등에 따라 개인차가 큽니다. 조기에 진단받고 적절한 약물 치료(NSAIDs, 생물학적 제제)와 규칙적인 운동 재활을 병행하면 증상 조절과 진행 억제 효과가 더 좋습니다. 꾸준한 전문의 추적 관찰과 치료가 중요하며, 담당 류마티스내과 의사와 장기 치료 계획을 상의하시기 바랍니다.', 527, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '거북목 증후군', '거북목증후군', 'CHECKUP', '거북목 증후군 검진은 정형외과, 재활의학과, 신경외과 등에서 받을 수 있으며, 정형외과 또는 재활의학과를 우선 방문하는 것이 일반적입니다. X선 촬영을 통해 경추의 정렬 상태를 확인하고, 필요에 따라 MRI 검사를 시행합니다. 목·어깨 통증이나 두통, 손 저림 등 신경 증상이 동반된 경우 신경외과나 재활의학과 전문의 진료가 적합할 수 있습니다.', 528, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '거북목 증후군', '거북목증후군', 'DIET_LIFE', '거북목 증후군 예방을 위해 컴퓨터 작업 시 모니터를 눈높이에 맞추고, 허리를 등받이에 밀착한 바른 자세를 유지해야 합니다. 50분 작업 후 10분 휴식을 취하며 목·어깨 스트레칭을 시행하고, 충분한 수분 섭취와 칼슘·마그네슘이 풍부한 식사가 근육 건강에 도움이 됩니다. 베개 높이를 적절히 조정하고 엎드려 자는 자세를 피하는 것도 중요합니다.', 529, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '거북목 증후군', '거북목증후군', 'MEDICATION', '거북목 증후군의 근본 치료는 자세 교정과 운동이 핵심이며, 약물은 증상 완화를 위한 보조 수단으로 사용됩니다. 근육 긴장과 통증에는 NSAIDs(이부프로펜 등 소염진통제)나 근육 이완제가 처방될 수 있습니다. 약물 복용은 의사 처방에 따라야 하며, 자세 교정과 물리치료, 운동 치료를 병행하는 것이 더욱 효과적이므로 정형외과 또는 재활의학과 전문의 상담을 권장합니다.', 530, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '거북목 증후군', '거북목증후군', 'PREVENTION', '스마트폰 사용 시 거북목 예방을 위해 스마트폰 화면을 눈높이로 올려 목을 앞으로 구부리지 않도록 하고, 30분 이상 연속 사용을 피하는 것이 중요합니다. 사용 중 목·어깨 스트레칭을 규칙적으로 시행하고, 사용하지 않을 때는 스마트폰을 내려놓는 습관을 들이는 것이 도움이 됩니다. 거북목이 이미 진행됐다면 정형외과나 재활의학과 전문의에게 자세 평가와 교정 치료를 받으시기 바랍니다.', 531, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '거북목 증후군', '거북목증후군', 'EXERCISE', '거북목 증후군 예방 및 개선을 위해 경추 신전 운동(턱 당기기, 목 뒤로 젖히기), 어깨 회전 운동, 흉추 신전 스트레칭이 효과적입니다. 수영(특히 배영)은 경추와 흉추를 바르게 신전시켜 도움이 되며, 요가와 필라테스도 자세 교정에 유익합니다. 운동 중 통증이 심해지면 즉시 중단하고, 정형외과 또는 재활의학과 전문의의 지도 하에 운동 계획을 세우시기 바랍니다.', 532, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '거북목 증후군', '거북목증후군', 'CAUSE', '시력이 나빠 사물을 가까이 보려고 목을 앞으로 내미는 자세가 반복되면 경추가 전방으로 이동하고 목 뒤 근육이 만성적으로 긴장하여 거북목 증후군을 유발합니다. 이 자세는 경추 정렬을 변형시키고 디스크 압력을 높여 두통, 목·어깨 통증, 손 저림 등 다양한 증상을 유발할 수 있습니다. 시력 교정(안경, 렌즈 착용)과 자세 교정을 병행하는 것이 거북목 증후군 예방에 중요합니다.', 533, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '거북목 증후군', '거북목증후군', 'REHAB', '거북목 증후군의 재활 치료는 주로 재활의학과 전문의와 물리치료사, 작업치료사가 협력하여 시행합니다. 주요 방법으로는 자세 교정 훈련, 경추 근육 강화 운동, 도수 치료(관절 가동화), 전기 치료, 열 치료 등이 있습니다. 증상의 정도에 따라 전문의가 개인화된 재활 계획을 수립하며, 재활의학과나 정형외과 전문의와 상담하시기 바랍니다.', 534, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '거북목 증후군', '거북목증후군', 'DEFINITION', '거북목 증후군은 목이 앞으로 튀어나온 자세 이상으로, 목덜미 근육이 딱딱하게 굳어지는 것과 어깨 통증은 이 증후군의 대표적인 증상에 해당합니다. 경추 정렬 이상으로 인해 목, 어깨, 등 근육에 과도한 부담이 가해져 통증, 뻐근함, 두통 등이 유발됩니다. 이러한 증상이 지속된다면 정형외과 또는 재활의학과 전문의를 방문하여 정확한 평가와 치료를 받으시기 바랍니다.', 535, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '거북목 증후군', '거북목증후군', 'SYMPTOM', '거북목 증후군에서 목과 어깨의 뻐근함은 가장 흔한 증상이며, 목이 어깨보다 앞으로 나오는(전방 전위) 것이 특징입니다. 목이 어깨보다 뒤로 빠진 경우는 거북목과는 다른 자세 이상일 수 있으므로, 정확한 자세 평가가 필요합니다. 목·어깨 불편감이 지속된다면 정형외과 또는 재활의학과 전문의를 방문하여 경추 X선 등으로 정확한 자세 이상 여부를 확인하시기 바랍니다.', 536, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '거북목 증후군', '거북목증후군', 'DIAGNOSIS', '목이 굽어지는 증상이 거북목 증후군인지 확인하기 위해서는 측면에서 봤을 때 귀 외이도가 어깨 끝보다 앞에 위치하는지 관찰하는 자가 체크가 가능합니다. 정확한 진단을 위해서는 정형외과 또는 재활의학과에서 자세 평가와 경추 X선 촬영을 통해 경추 전만각 감소 여부를 확인합니다. 목·어깨 통증이나 두통, 손 저림 등이 동반된다면 전문의 진료를 받으시기 바랍니다.', 537, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '거북목 증후군', '거북목증후군', 'TREATMENT', '거북목 증후군에서 목이 앞으로 튀어나온 증상의 치료 방법으로는 자세 교정 훈련, 물리치료, 도수 치료(카이로프랙틱, 도수 교정), 경추 근육 강화 운동, 경추 보조기 착용 등이 있습니다. 통증이 심한 경우 소염진통제 처방이나 근육 이완 주사 치료가 병행될 수 있으며, 심한 경우 신경 차단술이 고려됩니다. 정형외과 또는 재활의학과 전문의와 상담하여 개인 상태에 맞는 치료 방법을 선택하시기 바랍니다.', 538, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '건초염', '건초염', 'MEDICATION', '재채기, 콧물, 코막힘은 건초염(건초의 염증)의 증상이 아니며, 이는 알레르기 비염 또는 감기(상기도 감염)의 증상입니다. 알레르기 비염의 경우 항히스타민제(세티리진, 로라타딘 등)와 비강 내 스테로이드 스프레이가 처방되며, 감기는 증상에 따른 대증 치료가 이루어집니다. 정확한 진단을 위해 이비인후과 또는 내과 전문의를 방문하시기 바랍니다.', 539, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '건초염', '건초염', 'PREVENTION', '건초염 예방을 위해 손목 사용을 줄이는 것 외에도, 작업 전후 손목·전완 스트레칭을 시행하고, 반복적인 동작 시 중간 휴식을 취하는 것이 중요합니다. 손목 보호대(스플린트) 착용이 과도한 관절 부하를 줄여주며, 업무 환경의 인체공학적 개선(키보드·마우스 높이 조정 등)도 효과적입니다. 증상이 나타나면 즉시 안정과 냉찜질을 시행하고, 정형외과 전문의 진료를 받는 것을 권장합니다.', 540, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '건초염', '건초염', 'EXERCISE', '어깨 건초염으로 인해 운동이 제한된 경우, 통증 없는 범위 내에서 진자 운동(Pendulum exercise), 가벼운 벽 기어오르기(Wall walking) 등 저강도 관절 가동 운동이 권장됩니다. 탄성 밴드를 이용한 회전근개 강화 운동은 어깨 안정성 향상에 효과적이나, 통증이 악화되면 즉시 중단해야 합니다. 운동 계획은 정형외과 또는 재활의학과 전문의 및 물리치료사의 지도 하에 시행하시기 바랍니다.', 541, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '건초염', '건초염', 'CAUSE', '건초염과 무릎 통증의 연관성은 직접적이지는 않으나, 슬개건(무릎 힘줄)의 건초 또는 건 주위 조직에 염증이 생기는 슬개건건초염이 발생하면 무릎 앞쪽에 통증이 나타날 수 있습니다. 등산 후 무릎 통증은 주로 슬개건이나 장경인대에 반복적인 마찰과 부하가 가해져 발생하는 경우가 많습니다. 지속적인 무릎 통증이 있다면 정형외과 전문의를 방문하여 정확한 원인을 파악하시기 바랍니다.', 542, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '건초염', '건초염', 'REHAB', '어깨 건초염 재활을 전문으로 하는 시설로는 대학병원 및 종합병원의 재활의학과, 스포츠의학센터, 정형외과 부설 물리치료 센터 등이 있습니다. 재활의학과에서 전문 물리치료사의 지도 하에 운동 치료, 도수 치료, 물리 치료를 시행합니다. 정확한 어깨 손상 평가 후 담당 정형외과 또는 재활의학과 전문의에게 재활 기관을 추천받는 것이 가장 좋습니다.', 543, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '건초염', '건초염', 'DEFINITION', '건초염은 힘줄을 둘러싸는 건초(건막)에 염증이 생기는 질환으로, 염증은 주로 해당 건초 부위에 집중되어 국소적인 통증, 부종, 압통, 움직임 시 통증을 유발합니다. 염증이 심해지면 주변 연부조직이나 인근 신경을 간접적으로 자극하여 더 넓은 범위에 불편감이 생길 수 있습니다. 건초염의 부위와 범위는 정형외과 전문의의 진찰과 초음파 또는 MRI 검사로 정확히 파악할 수 있습니다.', 544, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '건초염', '건초염', 'SYMPTOM', '손목의 돌출 부위(요골 경상돌기) 주변 통증은 드퀘르벵 건초염의 특징적인 증상으로, 이 부위의 건초에 염증이 생긴 것입니다. 진단과 치료 확인을 위해 핀켈스타인 검사(엄지손가락 말아 쥐고 손목 굴곡)가 활용되며 통증이 있으면 양성입니다. 치료는 안정, 부목 고정, 소염진통제 복용, 스테로이드 주사 등이 사용되며, 정형외과 전문의와 상담하시기 바랍니다.', 545, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '건초염', '건초염', 'DIAGNOSIS', '손목건초염(드퀘르벵 건초염) 진단에 핀켈스타인 검사(엄지손가락을 손가락으로 감싸 쥔 후 손목을 새끼손가락 방향으로 굴곡)가 사용됩니다. 이 검사에서 통증이 유발되면 양성으로 건초염을 의심하며, 증상이 미미하더라도 통증이 재현되면 진단에 도움이 됩니다. 최종 진단은 정형외과 전문의가 임상 소견과 초음파 검사를 종합하여 결정하므로 전문의 진료를 받으시기 바랍니다.', 546, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '건초염', '건초염', 'TREATMENT', '건초염으로 인한 엄지손가락 통증과 손목 불편감은 건초 염증이 힘줄 활동을 방해하고 주변 조직을 자극하기 때문이며, 치료하지 않고 방치하면 만성화되어 기능 장애로 이어질 수 있습니다. 치료를 통해 염증을 줄이고 힘줄 손상을 예방하며, 일상 생활과 직업 활동의 회복이 가능합니다. 증상이 지속된다면 정형외과 전문의를 방문하여 안정, 부목, 소염제, 스테로이드 주사 등 적절한 치료를 받으시기 바랍니다.', 547, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '결절종', '결절종', 'CAUSE', '결절종은 관절 주변 또는 힘줄 건초에서 발생하는 낭종으로, 반복적인 손목 사용이나 무거운 물건을 자주 드는 행동이 관절 및 건초에 반복적 자극을 주어 점액이 축적되는 낭종 형성에 기여하는 것으로 알려져 있습니다. 다만 결절종의 정확한 발생 기전은 완전히 밝혀지지 않았으며 외상, 반복적 스트레스 등이 복합적으로 작용합니다. 증상이 있거나 크기가 커진다면 정형외과 전문의 진료를 받으시기 바랍니다.', 548, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '결절종', '결절종', 'DEFINITION', '결절종(ganglion cyst)은 관절 주변이나 힘줄 건초에서 발생하는 점액성 물질이 차 있는 낭종(물혹)으로, 섬유성 피막으로 둘러싸여 있습니다. 작은 결절들의 집합체라기보다는 단일 낭종 또는 여러 소낭이 연결된 형태로 다양한 크기로 나타납니다. 결절종은 손목, 발, 손가락 관절 주변에 가장 흔하게 발생하며, 정형외과 전문의의 진찰과 초음파 검사로 정확한 진단을 받으시기 바랍니다.', 549, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '결절종', '결절종', 'SYMPTOM', '결절종은 피부 아래 관절이나 힘줄 건초에 발생하는 양성 낭종으로, 피부 내 결절 형성 질환 중 손목과 손에서 가장 흔한 종류에 해당합니다. 외관상 부드럽고 둥근 혹 형태로 나타나며, 크기는 수 mm에서 수 cm까지 다양하고, 누르면 물렁물렁한 질감이 느껴지는 것이 특징입니다. 대부분 양성이나 통증이나 크기 증가가 있다면 정형외과 전문의 진료를 받아 치료 여부를 결정하시기 바랍니다.', 550, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '결절종', '결절종', 'DIAGNOSIS', '결절종 진단은 주로 정형외과에서 이루어지며, 초음파나 MRI 검사를 통해 확인합니다. 한의원은 통증 완화나 보조적 치료 목적으로 방문할 수 있으나, 정확한 진단과 치료 계획 수립은 정형외과 전문의를 통해 받는 것이 권장됩니다.', 551, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '결절종', '결절종', 'TREATMENT', '결절종 수술 후 4주가 지나도 튀어나온 부위가 남아 있다면 결절종의 재발 가능성이 가장 높습니다. 재발률은 수술 방법에 따라 약 10~40%로 알려져 있으며, 성장 제한 질환과의 연관성보다는 수술 시 낭종 기저부가 완전히 제거되지 않은 경우가 대부분이므로 담당 정형외과 전문의와 상담이 필요합니다.', 552, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골감소증', '골감소증', 'CHECKUP', '골감소증 검진은 DEXA(이중 에너지 X선 흡수계측법) 골밀도 검사를 통해 이루어지며, 결과에 따라 T-score -1.0~-2.5이면 골감소증으로 진단합니다. 다른 병원에서 재검진을 받는 것은 충분히 합리적인 선택이며, 폐경 후 여성, 65세 이상 남성, 골절 위험 인자가 있는 경우 정기적인 검진이 권장됩니다.', 553, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골감소증', '골감소증', 'DIET_LIFE', '골감소증 및 골다공증에서는 뼈의 밀도(양)가 감소하여 골조직이 약해지고, 이로 인해 작은 충격에도 골절이 발생하기 쉬워지는 것이 맞습니다. 뼈에 구멍이 생기는 것처럼 내부 구조(골소주)가 얇아지고 성기게 되어 골절 위험이 높아지며, 특히 척추, 고관절, 손목 골절이 흔합니다. 정확한 진단과 치료를 위해 내과 또는 정형외과 전문의 상담을 권장합니다.', 554, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골감소증', '골감소증', 'MEDICATION', '골감소증 환자에게 권장되는 주요 영양소는 칼슘, 비타민D, 마그네슘이며, 이 세 가지는 함께 복용해도 일반적으로 안전합니다. 오히려 비타민D는 칼슘 흡수를 돕고, 마그네슘은 칼슘 대사에 관여하므로 병용이 효과적입니다. 다만 개인 건강 상태에 따라 용량 조절이 필요할 수 있으니 전문의 또는 약사와 상담 후 복용하시기 바랍니다.', 555, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골감소증', '골감소증', 'PREVENTION', '골감소증 예방을 위해서는 체중 부하 운동(걷기, 조깅, 계단 오르기)과 근력 운동을 주 3~5회, 1회 30~60분 정도 꾸준히 하는 것이 권장됩니다. 수영이나 자전거는 심폐 기능에는 좋으나 골밀도 증가 효과는 제한적이므로, 중력을 활용하는 체중 부하 운동 위주로 구성하는 것이 효과적입니다. 운동 시작 전 전문의와 상담하여 본인에게 적합한 운동 프로그램을 설계받으시길 권장합니다.', 556, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골감소증', '골감소증', 'EXERCISE', '골밀도 향상에 가장 효과적인 운동은 걷기, 조깅, 계단 오르기 등 체중 부하 운동과 스쿼트, 레그프레스 등 근력 운동입니다. 주 3~5회 이상 규칙적으로 시행하면 골밀도 유지 및 증가에 도움이 되며, 균형 훈련(한 발 서기, 태극권 등)을 병행하면 낙상 예방에도 효과적입니다. 골감소증 진단을 받은 경우 운동 시작 전 전문의와 상담하여 안전한 운동 범위를 확인하시기 바랍니다.', 557, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골감소증', '골감소증', 'CAUSE', '골감소증 및 골다공증은 가족력과 밀접한 관련이 있으며, 부모나 조부모가 골다공증을 앓은 경우 발병 위험이 유의하게 높아집니다. 유전적 요인은 최대 골밀도 형성에 영향을 미치는 것으로 알려져 있습니다. 가족력이 있다면 조기에 골밀도 검사를 받고, 칼슘과 비타민D 섭취 및 규칙적인 운동으로 예방 관리를 시작하는 것이 중요합니다.', 558, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골감소증', '골감소증', 'DEFINITION', '골다공증은 뼈의 양과 질이 감소하여 골밀도가 낮아지고 뼈가 약해지는 질환으로, T-score -2.5 이하일 때 진단합니다. 골감소증(-1.0~-2.5)은 골다공증의 전 단계이며, 50대 이후 여성에서 에스트로겐 감소로 급격히 진행됩니다. 다리 통증과 골다공증이 의심된다면 정형외과 또는 내과에서 DEXA 골밀도 검사를 받아보시길 권장합니다.', 559, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골감소증', '골감소증', 'SYMPTOM', '골감소증 및 골다공증은 대부분 증상이 없다가 골절이 발생하면서 처음 발견되는 경우가 많습니다. 진행 시 허리나 등의 둔한 통증, 척추 압박골절로 인한 키 감소와 척추 후만(등 굽음), 만성 요통 등이 나타날 수 있습니다. 증상이 없어도 위험 인자가 있다면 정기적인 골밀도 검진이 권장됩니다.', 560, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골감소증', '골감소증', 'DIAGNOSIS', '허리와 척추 통증이 있을 때 골감소증 진단은 DEXA(이중 에너지 X선 흡수계측법) 골밀도 검사를 통해 이루어지며, 정형외과, 내과, 산부인과 등에서 시행할 수 있습니다. T-score 수치로 정상, 골감소증, 골다공증을 구분하며 혈액 검사(칼슘, 비타민D, 부갑상선호르몬 등)도 병행합니다. 증상이 있다면 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 561, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골감소증', '골감소증', 'TREATMENT', '골감소증의 골밀도 향상을 위한 치료는 칼슘 및 비타민D 보충, 규칙적인 체중 부하 운동이 기본이며, 필요 시 비스포스포네이트 계열 약물(알렌드로네이트 등)을 사용합니다. 비스포스포네이트는 뼈 흡수를 억제하여 골밀도 감소를 막고 골절 위험을 줄이는 데 가장 근거가 많은 치료법입니다. 치료 방법은 골밀도 수치, 연령, 골절 위험도에 따라 달라지므로 내과 또는 정형외과 전문의와 상담하시기 바랍니다.', 562, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골관절염', '골관절염', 'DIET_LIFE', '발목 골관절염 재활 시 조심해야 할 음식으로는 염증을 악화시킬 수 있는 가공식품, 정제 탄수화물, 과도한 음주, 붉은 고기 등이 있습니다. 운동 측면에서는 충격이 큰 점프 동작, 과도한 달리기, 경사면 보행은 발목 부담을 증가시킬 수 있어 주의가 필요합니다. 구체적인 재활 계획은 정형외과 또는 재활의학과 전문의와 상담하시기 바랍니다.', 563, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골관절염', '골관절염', 'MEDICATION', '골관절염 치료는 약물 치료(비스테로이드성 항염증제, 진통제, 히알루론산 주사) 외에도 물리치료, 운동치료, 체중 감량, 보조기 착용, 온열 및 냉찜질 등의 비약물 치료가 있습니다. 증상이 심하고 보존적 치료에 반응하지 않는 경우 관절경 수술이나 인공관절 치환술을 고려할 수 있습니다. 담당 정형외과 전문의와 상의하여 본인 상태에 맞는 치료 방법을 선택하시기 바랍니다.', 564, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골관절염', '골관절염', 'PREVENTION', '비타민D는 칼슘 흡수를 도와 관절 건강과 골밀도 유지에 중요하며, 성인 기준 하루 권장 섭취량은 600~800 IU이고, 결핍 위험군은 1,000~2,000 IU까지 권고되기도 합니다. 과도한 비타민D는 고칼슘혈증 등 부작용을 유발할 수 있으므로 무작정 고용량 복용은 피해야 합니다. 개인의 혈중 비타민D 수치에 따라 적절한 용량이 달라지므로 전문의와 상담 후 복용량을 결정하시기 바랍니다.', 565, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골관절염', '골관절염', 'EXERCISE', '골관절염 환자에게 무릎에 해로운 운동으로는 쪼그려 앉기, 무릎을 과도하게 구부리는 운동, 계단 오르내리기 반복, 무거운 중량 스쿼트, 달리기나 줄넘기 등 충격이 강한 고강도 운동이 있습니다. 이러한 운동들은 관절 연골에 과부하를 주어 통증을 악화시킬 수 있습니다. 수중 운동이나 자전거 타기, 스트레칭 등 관절에 부담이 적은 운동을 권장하며, 구체적인 운동 계획은 전문의와 상의하시기 바랍니다.', 566, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골관절염', '골관절염', 'CAUSE', '과도한 음주는 뼈 형성 세포(조골세포) 기능을 억제하고 칼슘 흡수를 방해하여 골다공증 위험을 높이며, 흡연은 에스트로겐 대사를 방해하고 혈류를 감소시켜 골밀도 저하와 관절 연골 손상을 촉진합니다. 골관절염의 경우 흡연은 관절 조직의 산소 공급을 줄이고 염증 반응을 악화시켜 진행을 빠르게 할 수 있습니다. 따라서 금연과 절주는 뼈 및 관절 건강을 위해 반드시 권장되는 생활 습관 개선 사항입니다.', 567, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골관절염', '골관절염', 'REHAB', '골관절염 환자의 연골 보호를 위한 효과적인 재활 운동으로는 대퇴사두근 강화 운동(직하지 거상, 앉아서 무릎 펴기), 수중 운동, 자전거 타기, 스트레칭이 권장됩니다. 관절 주변 근육을 강화하면 관절에 가해지는 부하가 분산되어 연골 손상 진행을 늦출 수 있습니다. 재활 운동은 재활의학과 또는 정형외과 전문의의 지도 하에 개인 상태에 맞게 시행하는 것이 가장 효과적입니다.', 568, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골관절염', '골관절염', 'DEFINITION', '골관절염은 관절 연골이 점진적으로 마모되어 뼈와 뼈 사이의 완충 역할이 소실되는 퇴행성 질환입니다. 주로 무릎, 고관절, 손가락, 척추 등 체중 부하가 많은 관절에 발생하며, 통증은 대개 국소적이고 발열이나 전신 피로 같은 전신 증상은 나타나지 않는 것이 특징입니다. 류마티스 관절염과 달리 전신 염증 반응이 없는 점이 감별 포인트입니다.', 569, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골관절염', '골관절염', 'SYMPTOM', '골관절염의 관절 뻣뻣함(강직)은 주로 활동 후나 저녁에 심해지는 경향이 있으며, 아침 강직은 30분 이내로 짧은 것이 특징입니다(류마티스 관절염은 1시간 이상). 관절을 움직일 때 삐걱거리거나 뚝뚝 소리가 나는 관절잡음(크레피투스)은 골관절염의 주요 증상 중 하나로, 연골 마모로 인해 발생합니다. 이러한 증상이 지속된다면 정형외과 전문의의 진료를 받으시기 바랍니다.', 570, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골관절염', '골관절염', 'DIAGNOSIS', '골관절염 환자의 MRI에서는 관절 연골 두께 감소, 연골 결손 부위, 골극(골돌기) 형성, 반월상 연골 손상, 관절 내 삼출액 증가, 연골하골 부종 등이 관찰됩니다. 정상인의 MRI에서는 연골 두께가 균일하게 유지되고 골극이나 관절 변형이 없으며, 관절 공간이 정상 범위로 유지됩니다. 이러한 영상 소견의 차이가 골관절염 진단과 중증도 평가에 중요한 기준이 됩니다.', 571, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골관절염', '골관절염', 'TREATMENT', '골관절염의 물리치료 중 가장 효과적인 방법은 치료적 운동(근력 강화 및 유연성 훈련)이며, 통증 완화를 위해 온열치료(핫팩, 초음파 치료)와 전기 치료(TENS)도 많이 사용됩니다. 수중 치료(수치료)는 관절 부담 없이 근력을 키울 수 있어 효과적이며, 냉찜질은 급성 통증 및 부종 완화에 도움이 됩니다. 물리치료는 재활의학과 또는 정형외과 전문의의 처방 하에 진행하는 것이 가장 효과적입니다.', 572, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골수염', '골수염', 'CAUSE', '골수염은 주로 혈행성 감염(혈관을 통해 균이 이동)으로 발생하며, 황색포도상구균이 가장 흔한 원인균입니다. 혈류를 통해 세균이 뼈의 혈관이 풍부한 부위(특히 성장판 근처)에 정착하여 염증을 일으키며, 외상이나 수술 후 직접 감염으로도 발생할 수 있습니다. 혈행성 감염은 다른 부위의 감염원(피부 감염, 폐렴 등)에서 균이 혈관을 타고 이동하는 경로가 성립 조건입니다.', 573, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골수염', '골수염', 'DEFINITION', '골수염은 뼈의 내부, 즉 골수(골수강)와 주변 피질골에 세균이나 균에 의한 감염성 염증이 발생하는 질환입니다. 주로 장골(대퇴골, 경골, 상완골)의 골간단부에 잘 발생하며, 척추골수염의 경우 척추뼈에 염증이 생깁니다. 방치할 경우 뼈 괴사나 만성 골수염으로 진행할 수 있어 조기 치료가 중요합니다.', 574, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골수염', '골수염', 'SYMPTOM', '골수염의 주요 증상으로는 감염 부위의 심한 통증, 발적, 부종, 국소 열감이 있으며, 고열(38도 이상), 오한, 전신 피로감 등 전신 증상이 동반됩니다. 만성 골수염으로 진행 시 배농(고름이 흘러나오는 누공 형성), 뼈 괴사, 병적 골절이 나타날 수 있으며, 소아에서는 움직임 제한과 보행 거부가 특징적입니다. 이러한 증상이 있다면 즉시 정형외과나 감염내과 전문의를 방문하시기 바랍니다.', 575, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골수염', '골수염', 'DIAGNOSIS', '발목 통증, 고열, 극심한 피로가 동반된 골수염이 의심되면 정형외과 또는 응급의학과를 방문하는 것이 우선입니다. 진단을 위해 혈액 검사(CBC, CRP, ESR, 혈액 배양), X선, MRI 등의 검사가 시행되며, 빠른 진단과 치료가 중요합니다. 증상이 급격히 악화되거나 고열이 지속된다면 응급실 방문을 권장합니다.', 576, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골수염', '골수염', 'TREATMENT', '골수염 치료 중 항생제를 복용하는 상태에서 다른 질환으로 추가 항생제가 필요한 경우, 반드시 담당 의사와 상의해야 합니다. 항생제를 무분별하게 병용하면 내성균 발생, 장내 균형 교란, 약물 상호작용 등의 부작용이 생길 수 있습니다. 다른 질병의 치료 필요성이 있다면 골수염 담당 전문의와 협의하여 항생제 선택과 용량을 조정하는 것이 안전합니다.', 577, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골육종', '골육종', 'CAUSE', '골육종의 발생 위험 인자로는 유전적 요인(망막모세포종, Li-Fraumeni 증후군, Rothmund-Thomson 증후군 등) 외에도 방사선 조사 이력, 파제트병(골 변형성 골염), 뼈 경색, 이전 항암 치료력이 있습니다. 특히 급격한 성장기인 10~20대 청소년기에 발병률이 높으며, 이는 빠른 뼈 성장과 관련이 있는 것으로 알려져 있습니다. 대부분은 특별한 원인 없이 발생하는 산발성이 많습니다.', 578, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골육종', '골육종', 'DEFINITION', '골육종은 뼈에서 발생하는 악성 원발성 골종양으로, 주로 무릎 주변(대퇴골 원위부, 경골 근위부)과 상완골 근위부에 잘 발생합니다. 치료는 수술 전 항암화학요법, 광범위 절제술(사지 보존 수술 또는 절단술), 수술 후 항암화학요법의 병합 치료가 표준입니다. 현재는 면역 치료제, 표적 치료제, 항체 약물 접합체 등이 연구 중이며, 5년 생존율은 국소 질환의 경우 약 60~70%입니다.', 579, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골육종', '골육종', 'SYMPTOM', '골육종의 주요 증상은 점진적으로 악화되는 뼈 통증으로, 처음에는 간헐적이지만 점차 지속적이고 야간에도 심해집니다. 종양 부위의 국소 부종, 열감, 촉지되는 종괴가 나타날 수 있으며, 병적 골절이 초기 증상으로 나타나기도 합니다. 골반이나 허리 통증이 지속된다면 단순한 근육통과 감별을 위해 정형외과나 종양내과 전문의를 방문하시기 바랍니다.', 580, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골육종', '골육종', 'DIAGNOSIS', '개를 포함한 반려동물도 골육종이 발생할 수 있으며, 특히 대형견(그레이트데인, 골든 리트리버, 독일셰퍼드 등)에서 발병률이 높고 인간보다 훨씬 흔합니다. 개의 골육종은 주로 긴 뼈의 끝부분에 발생하며 증상은 절뚝거림, 부종, 통증 등으로 나타납니다. 반려견에서 이러한 증상이 있다면 수의사를 방문하여 X선 촬영 및 조직 검사를 받아보시기 바랍니다.', 581, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '골육종', '골육종', 'TREATMENT', '골육종의 가장 효과적인 치료는 수술 전 항암화학요법(고용량 메토트렉세이트, 독소루비신, 시스플라틴 등)과 광범위 절제 수술을 결합한 병합 치료입니다. 수술 전 항암 치료로 종양 크기를 줄인 후 사지 보존 수술을 시행하면 절단술 없이도 치료가 가능한 경우가 많아졌습니다. 수술 후 항암화학요법의 반응률(종양 괴사율)이 높을수록 예후가 좋으며, 조기 발견이 회복과 생존율에 가장 중요합니다.', 582, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '관절염', '관절염', 'CHECKUP', '류마티스 관절염이 의심된다는 검진 결과가 나온 경우, 실제 정밀 검사에서 다른 질환이 발견될 수 있습니다. 류마티스 관절염과 증상이 유사한 질환으로 건선 관절염, 통풍, 반응성 관절염, 전신 홍반 루푸스(SLE), 쇼그렌 증후군 등이 있습니다. 류마티스내과 전문의를 방문하여 항CCP항체, 류마티스인자(RF), ESR, CRP 등의 혈액 검사와 영상 검사를 통해 정확한 진단을 받으시길 권장합니다.', 583, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '관절염', '관절염', 'DIET_LIFE', '류마티스 관절염 예방을 위한 식이 측면에서는 오메가3가 풍부한 등 푸른 생선, 항산화 성분이 많은 채소와 과일, 올리브오일 등 지중해식 식단이 권장됩니다. 생활 습관으로는 금연(흡연은 발병 위험을 2배 이상 높임), 적정 체중 유지, 규칙적인 저강도 운동, 스트레스 관리가 중요합니다. 붉은 고기와 가공식품, 과당 음료는 염증을 악화시킬 수 있어 제한하는 것이 좋습니다.', 584, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '관절염', '관절염', 'MEDICATION', '퇴행성 관절염 치료에 사용되는 히알루론산 주사(관절 내 주사)의 부작용으로는 주사 후 일시적인 통증 증가, 부종, 주사 부위 감염 등이 있을 수 있습니다. 스테로이드 주사는 혈당 상승, 관절 내 감염, 장기 사용 시 연골 손상 등의 위험이 있습니다. 주사제와 유사한 효과를 나타내는 약물로는 비스테로이드성 항염증제(NSAIDs)가 있으나, 위장관 부작용이 있을 수 있어 전문의와 상담 후 사용하시기 바랍니다.', 585, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '관절염', '관절염', 'PREVENTION', '손가락 관절 붓기와 통증을 예방하는 조치만으로 류마티스 관절염을 완전히 예방하기는 어렵습니다. 류마티스 관절염은 자가면역 기전으로 발생하므로 유전적 소인이 있는 경우 생활 습관 개선으로 발병 위험을 낮출 수는 있지만 완전 예방은 불가능합니다. 그러나 금연, 구강 위생 관리, 규칙적인 운동, 스트레스 관리 등은 발병 위험을 줄이는 데 도움이 되므로 꾸준히 실천하시기 바랍니다.', 586, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '관절염', '관절염', 'EXERCISE', '류마티스 관절염으로 인한 손가락 증상이 다른 부위로 확대되고 있다면 조기에 류마티스내과 전문의를 방문하는 것이 우선입니다. 관절 보호를 위한 운동으로는 관절 가동 범위 운동(손가락 굽히기, 펴기), 수중 운동, 부드러운 스트레칭이 도움이 됩니다. 증상이 활성화된 시기에는 무리한 운동을 피하고 온열 치료를 활용하며, 완화기에 점진적으로 운동량을 늘리는 것이 권장됩니다.', 587, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '관절염', '관절염', 'CAUSE', '운동 부족과 영양 불균형은 관절염 발생의 위험 인자가 될 수 있습니다. 운동 부족은 관절 주변 근육을 약화시켜 관절에 과부하를 주고, 영양 불량은 연골 재생과 뼈 건강에 부정적인 영향을 미칩니다. 다만 관절염은 나이, 유전, 체중, 직업적 요인 등 복합적인 원인으로 발생하므로, 정확한 원인 파악을 위해 류마티스내과 또는 정형외과 전문의의 진료를 받아보시기 바랍니다.', 588, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '관절염', '관절염', 'REHAB', '관절염 수술 후 통증 완화와 기능 회복에는 개인차가 크며, 무릎 인공관절 치환술의 경우 수술 후 3~6개월이 지나야 일상생활이 가능해지고, 완전한 회복까지 1년 이상 소요되기도 합니다. 수술 후 3개월에 통증이 완전히 사라지는 경우도 있지만, 재활 운동의 지속 여부와 개인 상태에 따라 회복 속도가 다릅니다. 담당 정형외과 전문의와 상담하여 재활 진행 상황을 정기적으로 확인하시기 바랍니다.', 589, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '관절염', '관절염', 'DEFINITION', '런닝머신 달리기 후 무릎 부종과 통증이 반복된다면 퇴행성 관절염, 슬개대퇴 증후군, 반월상 연골 손상 등을 의심할 수 있습니다. 진단을 위해 정형외과에서 무릎 X선 촬영과 신체 검사를 우선 시행하며, 필요에 따라 MRI 검사를 추가합니다. 무릎 퇴행성 관절염은 내측 관절 공간 감소, 골극 형성, 연골하골 경화 등으로 진단하므로 전문의 진료를 받으시기 바랍니다.', 590, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '관절염', '관절염', 'SYMPTOM', '손가락 관절이 튀어나오고 통증과 변형이 있다면 관절염에 의한 골극 형성(헤베르덴 결절, 부샤르 결절) 또는 류마티스 관절염에 의한 관절 변형을 의심할 수 있습니다. 퇴행성 관절염에서는 손가락 원위지관절에 골극이 형성되고, 류마티스 관절염에서는 손가락이 척골 쪽으로 편향되는 변형이 나타납니다. 정확한 감별 진단을 위해 류마티스내과 또는 정형외과 전문의의 진료를 받으시기 바랍니다.', 591, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '관절염', '관절염', 'DIAGNOSIS', '걸을 때 발목 통증과 시큰거림이 있다면 발목 퇴행성 관절염, 인대 손상, 힘줄 병증 등을 의심할 수 있습니다. 발목 관절염 진단을 위해 정형외과에서 X선 촬영(관절 공간 감소, 골극 확인)을 시행하며, 필요 시 MRI나 CT 검사를 추가합니다. 증상 기간, 외상 병력, 활동 시 악화 여부 등을 함께 확인하므로 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 592, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '관절염', '관절염', 'TREATMENT', '퇴행성 관절염 초기에는 통증이 경미하고 간헐적인 경우 생활 습관 개선(체중 감량, 운동)과 경과 관찰을 병행하는 것이 적합할 수 있습니다. 그러나 치료를 무작정 미루면 연골 손상이 진행되어 나중에 더 복잡한 치료가 필요해질 수 있습니다. 증상의 정도, 직업 활동, 연골 손상 범위 등에 따라 치료 시작 시기가 달라지므로 정형외과 전문의와 상의하여 적절한 치료 계획을 수립하시기 바랍니다.', 593, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '구루병', '구루병', 'CHECKUP', 'O자형 다리(내반슬)의 구조적 변형 검사를 위해서는 정형외과를 방문하여 하지 전장 X선 촬영(서서 찍는 하지 전체 방사선 검사)을 시행합니다. 검사 결과로 대퇴경골각(FTA)을 측정하여 변형 정도를 평가하며, 필요에 따라 CT나 MRI 검사도 추가할 수 있습니다. 성인의 경우 구루병에 의한 O자 다리 외에도 골관절염, 발달성 기형 등이 원인일 수 있으므로 정확한 진단이 중요합니다.', 594, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '구루병', '구루병', 'DIET_LIFE', '비타민D를 식이로 섭취하려면 연어, 고등어, 참치, 달걀노른자, 비타민D 강화 우유 등을 섭취하는 것이 좋습니다. 자외선 B를 통한 피부 합성이 주요 공급원이므로, 하루 10~20분 정도 팔이나 다리를 노출하여 햇빛을 쬐는 것이 효과적입니다. 식이와 햇빛으로 충분한 비타민D를 얻기 어려운 경우, 의사 처방이나 약사 상담 후 보충제를 복용하는 것을 권장합니다.', 595, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '구루병', '구루병', 'MEDICATION', '현재 복용 중인 구루병 치료 약물(비타민D 및 칼슘 보충제)이 효과적이지 않다고 느껴진다면, 우선 담당 의사에게 이를 알리고 혈액 검사를 통해 비타민D 수치와 칼슘·인 대사를 재평가하는 것이 필요합니다. 저인산혈증성 구루병 등 특수 형태의 경우 일반 비타민D 외에 활성형 비타민D(칼시트리올)나 부스로수맙 등 새로운 치료제가 사용될 수 있습니다. 임의로 새로운 약을 변경하지 말고 반드시 전문의와 상담 후 치료 방향을 조정하시기 바랍니다.', 596, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '구루병', '구루병', 'PREVENTION', '주 4~5회 1시간 이상 야외 활동을 하면 피부에서 햇빛을 통해 충분한 비타민D가 합성될 가능성이 높아 구루병 예방에 도움이 됩니다. 다만 계절, 위도, 피부색, 자외선 차단제 사용 여부에 따라 합성량이 다를 수 있으며, 흐린 날씨나 겨울철에는 합성이 부족할 수 있습니다. 아이의 성장과 뼈 건강을 정기적으로 모니터링하고, 소아과 전문의와 상담하여 비타민D 상태를 확인하는 것이 권장됩니다.', 597, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '구루병', '구루병', 'EXERCISE', '구루병 예방을 위한 운동으로는 야외 활동(햇빛을 통한 비타민D 합성 촉진)과 함께 걷기, 가볍게 뛰기, 줄넘기 등 체중 부하 운동이 뼈 형성에 도움이 됩니다. 운동만으로 구루병을 완전히 예방하기 어려우며, 칼슘과 비타민D의 충분한 섭취가 병행되어야 합니다. 칼슘은 유제품, 두부, 뼈째 먹는 생선 등에서, 비타민D는 햇빛 노출과 등 푸른 생선, 달걀노른자 등으로 보충할 수 있습니다.', 598, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '구루병', '구루병', 'CAUSE', '구루병은 비타민D, 칼슘, 인의 대사 이상으로 뼈 무기질화가 충분히 이루어지지 않아 발생하는 뼈 연화증입니다. 생후 4개월~2세는 뼈 성장이 가장 빠른 시기로, 이 시기에 비타민D 결핍이 발생하면 두개골 연화(두개골 무름), 갈비뼈 변형(염주흉), 전완부 및 하지의 만곡 변형 등 성장 부위 전반에 골격 이상이 나타납니다. 이 시기의 구루병은 성장판에 영향을 주어 뼈 전체의 성장 방향과 모양에 지속적인 변형을 초래할 수 있습니다.', 599, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '구루병', '구루병', 'REHAB', '구루병 재활에서 비타민D는 핵심적인 역할을 합니다. 고용량 비타민D(의사 처방)와 칼슘 보충을 통해 뼈 무기질화를 촉진하고, 근육 기능 개선에도 비타민D가 직접적으로 관여합니다. 창백한 피부, 다한증, 근육 이완 등의 증상이 있다면 소아과 또는 내분비내과 전문의를 방문하여 혈중 비타민D, 칼슘, 인, 부갑상선호르몬 수치를 확인하고 적절한 보충 용량을 처방받으시기 바랍니다.', 600, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '구루병', '구루병', 'DEFINITION', '구루병은 주로 성장 중인 소아의 뼈, 특히 성장판(장골의 골단판)이 있는 부위에서 발생합니다. 손목, 발목, 무릎, 갈비뼈, 두개골 등 성장이 빠른 부위에서 변형이 잘 나타나며, 발생 원인은 비타민D 결핍(가장 흔함), 칼슘 또는 인 섭취 부족, 일부 유전성 대사 질환(저인산혈증성 구루병)에 의한 뼈 무기질화 장애입니다. 성인에서 유사 질환은 골연화증(osteomalacia)이라고 합니다.', 601, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '구루병', '구루병', 'SYMPTOM', '대천문(앞숫구멍)은 일반적으로 생후 18~24개월에 닫히며, 두 돌이 지나도 닫히지 않는다면 구루병, 갑상선기능저하증, 두개내압 상승, 선천성 유전 질환(다운증후군, 아킬라 증후군 등) 등을 의심할 수 있습니다. 구루병에서는 비타민D 결핍으로 뼈 무기질화가 지연되어 대천문이 늦게 닫힐 수 있습니다. 소아과 전문의를 방문하여 정확한 원인 감별 검사를 받아보시기 바랍니다.', 602, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '구루병', '구루병', 'DIAGNOSIS', '구루병이 의심될 때는 소아과(소아청소년과) 또는 소아내분비내과 전문의를 방문하는 것이 적합합니다. 진단 과정은 혈액 검사(비타민D, 칼슘, 인, 알칼리성 인산분해효소, 부갑상선호르몬 측정)와 손목 및 무릎 X선 촬영으로 이루어집니다. 비타민D 결핍이 확인되면 고용량 비타민D 치료를 시작하며, 유전성 구루병이 의심될 경우 유전자 검사도 진행될 수 있습니다.', 603, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '구루병', '구루병', 'TREATMENT', '구루병 치료에 고함량 비타민D 의약품을 사용하는 이유는 일반 보충제 수준의 용량으로는 심각한 결핍 상태를 빠르게 교정하기 어렵기 때문입니다. 특히 영양성 구루병에서는 초기 집중 치료로 고용량 비타민D(스토스요법: 1회 대용량 투여 또는 수주간 고용량 투여)를 사용하여 혈중 수치를 신속히 정상화하고 뼈 무기질화를 촉진합니다. 고함량 비타민D는 반드시 의사의 처방과 지도 하에 사용해야 하며, 과다 복용 시 고칼슘혈증 등 부작용이 생길 수 있습니다.', 604, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '근감소증', '근감소증', 'CHECKUP', '나이에 비해 기력이 약해지고 다리에 힘이 없어지는 증상은 근감소증의 주요 증상과 일치합니다. 근감소증은 악력 저하, 보행 속도 감소, 근육량 감소로 진단하며, 낙상과 골절 위험을 높입니다. 65세 이상이거나 급격한 근력 저하가 느껴진다면 내과 또는 노인의학과에서 근감소증 선별 검사(SARC-F 설문, 악력 측정, 보행 속도 측정)를 받아보시기 바랍니다.', 605, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '근감소증', '근감소증', 'DIET_LIFE', '근감소증 치료 중 집에서 지켜야 할 식이요법으로는 단백질을 체중 1kg당 1.2~1.5g 이상 충분히 섭취하고, 칼슘과 비타민D가 풍부한 식품을 꾸준히 먹는 것이 중요합니다. 생활 습관으로는 규칙적인 저항 운동(스쿼트, 아령 등)을 주 2~3회 이상 시행하고, 장시간 앉아 있는 생활을 피하며 일상적인 신체 활동을 늘리는 것이 권장됩니다. 과도한 음주와 흡연은 근육 합성을 방해하므로 삼가시기 바랍니다.', 606, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '근감소증', '근감소증', 'MEDICATION', '60대 이상에서 근감소증으로 운동이 어려운 경우, 현재까지 근감소증 치료를 위해 단독으로 승인된 약물은 없으나, 비타민D 보충(결핍 시), 단백질 보충제(필수아미노산, 류신 함유 제품), 오메가3 지방산 등이 보조적으로 사용됩니다. 호르몬 요법(테스토스테론, 성장호르몬)은 일부 연구에서 효과가 보고되지만 부작용 위험으로 일반적으로 사용되지 않습니다. 전문의와 상담하여 운동 능력을 고려한 맞춤형 치료 계획을 수립하시기 바랍니다.', 607, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '근감소증', '근감소증', 'PREVENTION', '갱년기 이후 에스트로겐 감소로 인해 근육량과 근력이 빠르게 감소하므로, 예방을 위해 가장 중요한 것은 저항 운동(근력 운동)을 꾸준히 하는 것입니다. 주 2~3회 이상의 스쿼트, 레그프레스, 탄력 밴드 운동 등과 함께 단백질(체중 1kg당 1.2g 이상) 및 비타민D 충분 섭취를 병행해야 합니다. 갱년기 전후부터 근육 건강 관리를 시작하면 근감소증 예방에 큰 효과가 있으며, 필요 시 내과 또는 산부인과 전문의와 상담하시기 바랍니다.', 608, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '근감소증', '근감소증', 'EXERCISE', '근감소증 환자에게는 근력 운동(저항 운동)이 근육량 증가에 가장 효과적이며, 주 2~3회 이상 스쿼트, 레그프레스, 덤벨 운동 등을 시행하는 것이 권장됩니다. 유산소 운동(걷기, 자전거 타기)은 심폐 기능과 근지구력 향상에 도움이 되므로 근력 운동과 병행하면 더 효과적입니다. 운동 후 30분 이내에 단백질을 섭취하면 근육 합성을 극대화할 수 있으며, 운동 강도는 전문가와 상담하여 개인 체력에 맞게 조절하시기 바랍니다.', 609, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '근감소증', '근감소증', 'CAUSE', '근감소증의 주요 원인 중 단백질 섭취 부족과 신체 활동 감소(운동 부족)는 핵심적인 위험 요인입니다. 단백질 부족은 근육 합성을 저하시키고 근육 분해를 촉진하며, 운동 부족은 근육 자극 감소로 근위축을 유발합니다. 이 외에도 노화에 따른 호르몬 변화(성장호르몬, 테스토스테론, 에스트로겐 감소), 만성 질환, 염증 증가, 미토콘드리아 기능 저하 등이 복합적으로 작용합니다.', 610, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '근감소증', '근감소증', 'REHAB', '근감소증 재활 과정에서 심리적 지원은 치료 순응도와 회복 결과에 중요한 영향을 미칩니다. 근력 저하와 보행 어려움으로 인한 자신감 감소, 우울감, 사회 고립감에 대해 상담 치료나 인지행동치료(CBT)가 도움이 될 수 있습니다. 규칙적인 그룹 운동 프로그램 참여는 사회적 연결감을 높이고 운동 지속 동기를 부여하므로, 지역 복지관이나 병원 재활 프로그램을 적극 활용하시기 바랍니다.', 611, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '근감소증', '근감소증', 'DEFINITION', '근감소증은 노화, 신체 활동 부족, 단백질 섭취 부족, 호르몬 변화(성장호르몬·성호르몬 감소), 만성 염증, 만성 질환(당뇨병, 심부전 등) 등 복합적인 원인으로 근육량과 근력이 감소하는 질환입니다. 위험 요인으로는 65세 이상 고령, 여성(폐경 후), 낮은 신체 활동 수준, 영양 불량, 장기간 침상 안정, 악성 종양 등이 있습니다. 조기 발견과 운동 및 영양 중재가 진행을 늦추는 데 가장 효과적입니다.', 612, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '근감소증', '근감소증', 'SYMPTOM', '근감소증이 진행되면 낙상과 골절 위험 증가, 입원율 상승, 일상생활 수행 능력 저하 등의 합병증이 발생할 수 있습니다. 신체 기능 측면에서는 보행 속도 감소, 균형 능력 저하, 계단 오르기 어려움 등이 나타나며, 삶의 질 측면에서는 사회 활동 감소, 우울감, 의존성 증가로 이어질 수 있습니다. 특히 심혈관 질환, 당뇨병, 인슐린 저항성 등 대사 질환 위험도 함께 높아지므로 조기 관리가 중요합니다.', 613, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '근감소증', '근감소증', 'DIAGNOSIS', '일어날 때 힘들고 한 발짝 떼기 어려운 증상은 근감소증의 대표적인 기능 저하 소견입니다. 진단을 위한 주요 평가 지표로는 악력 측정(남성 28kg, 여성 18kg 미만 시 이상), 보행 속도(4m 보행에 5초 이상 소요 시 이상), 의자에서 5회 일어서기 시간, 그리고 이중에너지 X선 흡수계측법(DEXA)이나 생체전기임피던스법(BIA)으로 측정한 근육량 감소가 있습니다. 내과 또는 노인의학과에서 종합 평가를 받아보시기 바랍니다.', 614, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '근감소증', '근감소증', 'TREATMENT', '다이어트 없이 근력이 감소한 경우 근감소증 가능성이 있으며, 특히 50세 이상이라면 더욱 의심해 볼 수 있습니다. 치료의 핵심은 저항 운동(근력 운동)과 충분한 단백질 섭취(체중 1kg당 1.2~1.5g)이며, 비타민D 결핍이 확인되면 보충하는 것이 도움됩니다. 다만 갑상선 기능 저하증, 당뇨병, 심부전 등 근력 저하를 유발하는 다른 원인도 배제해야 하므로 내과 전문의의 진료를 받아보시기 바랍니다.', 615, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '내반슬', '내반슬', 'PREVENTION', '내반슬(O자 다리) 예방을 위해 권장되는 운동으로는 고관절 외전근과 내전근 균형 강화 운동(사이드 레그레이즈, 클램쉘 운동), 대퇴사두근 및 햄스트링 강화 스쿼트, 발목과 무릎 정렬을 의식하는 런지 등이 있습니다. 무릎이 안쪽으로 쏠리지 않도록 정렬을 유지하는 동작 교정이 중요하며, 평소 바른 자세와 걸음걸이 교정도 예방에 도움이 됩니다. 심한 경우 정형외과 전문의에게 교정 인솔이나 물리치료를 처방받는 것을 권장합니다.', 616, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '내반슬', '내반슬', 'CAUSE', '내반슬(O자 다리)의 원인은 다양하며, 유아기에는 대부분 정상 발달 과정으로 나타나지만 지속 시 구루병(비타민D 결핍), 블라운트병(경골 내반 성장 장애), 골격 이형성증 등이 원인일 수 있습니다. 성인에서는 퇴행성 관절염으로 인한 내측 관절 공간 협착, 골절 후 변형 유합, 장기간 잘못된 자세(양반다리 습관)가 원인이 될 수 있습니다. 유전적 요인도 관여할 수 있으며, 정확한 원인 파악을 위해 정형외과 전문의 진료가 필요합니다.', 617, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '내반슬', '내반슬', 'DEFINITION', '내반슬은 모든 연령에서 발생할 수 있으나, 생리적 내반슬은 주로 만 2세 이하 영유아에서 정상적으로 나타나고 대부분 자연 교정됩니다. 만 2세 이후에도 지속되거나 성인에서 병적으로 발생한 경우 치료가 필요하며, 담당 전문의는 정형외과(소아정형외과 또는 성인 정형외과) 전문의입니다. 성장기 아동의 경우 소아정형외과, 성인의 경우 슬관절 전문 정형외과를 방문하시기 바랍니다.', 618, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '내반슬', '내반슬', 'SYMPTOM', '내반슬(O자 다리)과 관련된 동반 증상으로는 무릎 내측 통증, 무릎 관절 내측 연골과 인대의 과부하로 인한 퇴행 가속화, 보행 이상(오리걸음, 발이 안쪽으로 향하는 내족지 보행), 발목과 발의 과내전 등이 있습니다. 장기적으로는 무릎 내측 골관절염 발생 위험이 높아지고, 고관절과 척추에도 이차적인 부담이 생길 수 있습니다. 증상이 있다면 정형외과 전문의의 진료를 받아 정렬 교정 여부를 평가받으시기 바랍니다.', 619, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '내반슬', '내반슬', 'DIAGNOSIS', '내반슬 진단에서 자세(서있는 자세, 누운 자세, 보행 중)에 따라 측정값이 다를 수 있으며, 특히 서서 찍은 하지 전장 X선이 실제 하중 부하 상태의 정렬을 평가하는 데 가장 정확합니다. 다른 결과가 나온다면 이는 기능적(비고정적) 변형 가능성을 시사하며, 재평가가 의미 있을 수 있습니다. 소아정형외과나 성인 정형외과 전문의가 있는 병원을 방문하여 하중 부하 X선 촬영과 함께 정밀 평가를 받으시기 바랍니다.', 620, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '내반슬', '내반슬', 'TREATMENT', '내반슬로 인한 무릎 이개(벌어짐)와 보행 이상을 개선하기 위해 경도~중등도는 보조기(교정 인솔, 무릎 교정 보조기), 물리치료, 근력 강화 운동으로 보존적 치료를 시도합니다. 변형이 심하거나 보존 치료 효과가 없는 경우 경골 근위부 교정 절골술(HTO, 근위 경골 절골술)을 통해 하지 정렬을 교정하는 수술적 치료를 시행합니다. 치료 방법 선택은 변형 정도, 연령, 관절염 동반 여부 등에 따라 결정되므로 정형외과 전문의와 상담하시기 바랍니다.', 621, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '류마티스 관절염', '류마티스관절염', 'CHECKUP', '류마티스 관절염 진단에는 혈액 검사(류마티스인자 RF, 항CCP항체, CRP, ESR), 관절 X선 촬영, 신체 검진이 기본적으로 사용됩니다. 항CCP항체는 류마티스 관절염에 비교적 특이적인 검사로, 이 검사가 양성이고 임상 증상이 부합하면 다른 추가 검사 없이 진단이 가능한 경우도 있습니다. 그러나 혈청 음성 류마티스 관절염도 있으므로 류마티스내과 전문의의 임상적 판단이 가장 중요합니다.', 622, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '류마티스 관절염', '류마티스관절염', 'DIET_LIFE', '류마티스 관절염 환자에게 권장되는 식이요법은 항염증 식품(오메가3 지방산이 풍부한 생선, 베리류, 올리브오일, 녹색 채소)을 중심으로 한 지중해식 식단입니다. 생활 습관으로는 관절에 무리가 가지 않는 수영, 수중 운동, 걷기 등 저충격 운동을 규칙적으로 하고, 흡연은 반드시 금해야 합니다. 관절이 부은 급성기에는 무리한 관절 사용을 피하고 냉찜질, 부목 고정 등으로 관절을 보호하는 것이 중요합니다.', 623, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '류마티스 관절염', '류마티스관절염', 'MEDICATION', '류마티스 관절염에서 면역 세포 기능 조절을 위해 주로 사용되는 약물은 메토트렉세이트(MTX, 1차 선택 항류마티스약물), 하이드록시클로로퀸, 설파살라진, 레플루노마이드 등의 항류마티스약물(DMARDs)과 TNF-α 억제제, IL-6 억제제, JAK 억제제 등의 생물학적 제제 및 표적 합성 DMARDs가 있습니다. 면역 조절을 중점으로 하는 대표 약물은 메토트렉세이트이며, 반응이 불충분한 경우 생물학적 제제를 추가합니다. 약물 선택과 용량은 류마티스내과 전문의가 결정합니다.', 624, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '류마티스 관절염', '류마티스관절염', 'PREVENTION', '류마티스 관절염 예방을 위한 권장 사항으로는 금연(가장 중요한 환경적 위험 요소), 구강 위생 관리(치주 질환이 발병 위험 증가와 연관), 적정 체중 유지, 정기적인 저강도 운동, 균형 잡힌 식이(항산화 식품, 오메가3 섭취)가 포함됩니다. 명확한 발병 전 예방법은 확립되어 있지 않으나, 이러한 생활 습관 개선이 자가면역 반응을 줄이는 데 도움이 될 수 있습니다. 가족력이 있다면 류마티스내과에서 정기적인 관리를 받는 것이 좋습니다.', 625, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '류마티스 관절염', '류마티스관절염', 'EXERCISE', '류마티스 관절염 환자가 운동할 때는 관절 염증이 활성화된 급성기에는 격렬한 운동을 피하고 안정을 취하는 것이 중요합니다. 완화기에는 수영, 수중 운동, 걷기, 자전거 타기 등 관절에 부담이 적은 유산소 운동과 가벼운 근력 운동을 권장하며, 무리한 동작이나 반복적인 충격 운동은 관절 손상을 악화시킬 수 있어 주의가 필요합니다. 운동 전 관절 워밍업(온열 찜질 후 가벼운 스트레칭)을 시행하고, 운동 후 통증이 2시간 이상 지속되면 강도를 줄이시기 바랍니다.', 626, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '류마티스 관절염', '류마티스관절염', 'CAUSE', '류마티스 관절염은 유전적 요인이 중요하게 작용하며, 특히 HLA-DR4 유전형을 가진 사람에서 발병 위험이 높습니다. 그러나 유전 외에도 흡연(가장 강력한 환경적 위험 요소), 구강 감염(치주 질환), 호르몬 요인(여성에서 3배 높은 발병률), 스트레스, 장내 미생물 불균형 등이 복합적으로 발병에 관여합니다. 따라서 유전적 소인이 있더라도 생활 습관 개선으로 발병 위험을 낮출 수 있습니다.', 627, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '류마티스 관절염', '류마티스관절염', 'REHAB', '류마티스 관절염 환자의 손목 통증 재활 치료는 우선 약물 치료(항류마티스약물)로 염증을 조절한 후, 작업 치료사 주도의 관절 보호 기법 교육과 손목 보조기 착용을 병행합니다. 재활 운동으로는 손목과 손가락의 가동 범위 운동, 쥐기 근력 강화 운동, 온열 치료 후 스트레칭 등이 포함됩니다. 재활 프로그램은 재활의학과 또는 류마티스내과와 협력하여 진행하며, 급성 염증기에는 운동보다 관절 보호와 안정이 우선입니다.', 628, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '류마티스 관절염', '류마티스관절염', 'DEFINITION', '류마티스 관절염은 면역 체계의 이상으로 관절 활막에 만성 염증이 발생하는 자가면역 질환입니다. 아침에 1시간 이상 지속되는 손가락 등 관절 뻣뻣함(조조강직), 3개 이상 관절의 부종과 통증, 좌우 대칭적인 관절 침범이 특징적이며, 혈액 검사(RF, 항CCP항체 양성)와 X선 소견(관절 침식 등)을 종합하여 진단합니다. 이러한 증상이 있다면 류마티스내과 전문의를 방문하시기 바랍니다.', 629, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '류마티스 관절염', '류마티스관절염', 'SYMPTOM', '양쪽 손가락 관절의 대칭적인 부종과 심한 통증은 류마티스 관절염의 전형적인 증상 중 하나입니다. 특히 아침 강직이 1시간 이상 지속되고 손가락 근위지관절(PIP)이나 중수지관절(MCP)이 대칭적으로 침범된다면 류마티스 관절염 가능성이 높습니다. 빠른 진단과 치료 시작이 관절 손상을 예방하는 데 중요하므로 류마티스내과 전문의 진료를 받으시기 바랍니다.', 630, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '류마티스 관절염', '류마티스관절염', 'DIAGNOSIS', '손가락 마디가 굵어지고 아침에 붓는 증상으로 류마티스 관절염을 의심할 때는 류마티스내과 전문의에게 진료를 받는 것이 가장 적합합니다. 류마티스내과는 대학병원, 종합병원, 류마티스 전문 병의원에서 진료를 받을 수 있으며, 혈액 검사(RF, 항CCP항체, 염증 수치)와 손가락 관절 X선 촬영을 통해 진단합니다. 조기 진단과 치료가 관절 변형을 예방하는 데 매우 중요합니다.', 631, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '류마티스 관절염', '류마티스관절염', 'TREATMENT', '류마티스 관절염 치료에서 스테로이드를 사용하지 않는 경우, 대표적인 대안으로는 메토트렉세이트를 중심으로 한 항류마티스약물(DMARDs) 단독 또는 병합 요법이 있습니다. 메토트렉세이트에 반응이 불충분하면 TNF-α 억제제(에타너셉트, 아달리무맙), IL-6 억제제(토실리주맙), JAK 억제제(바리시티닙, 우파다시티닙) 등의 생물학적 제제 및 표적 합성 DMARDs로 치료를 강화할 수 있습니다. 치료 전략은 류마티스내과 전문의와 상담하여 결정하시기 바랍니다.', 632, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '무지외반증', '무지외반증', 'CHECKUP', '무지외반증은 통증이 없어도 엄지발가락의 변형이 진행 중이라면 조기에 검진을 받아보는 것이 좋습니다. 변형이 진행되면 나중에 교정이 더 어려워지고, 증상이 없는 초기에 교정 인솔, 적절한 신발 선택, 보조기 등으로 진행을 늦출 수 있기 때문입니다. 정형외과 전문의에서 발 X선 촬영을 통해 변형 각도(외반각)를 측정하고 치료 필요 여부를 평가받으시기 바랍니다.', 633, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '무지외반증', '무지외반증', 'DIET_LIFE', '무지외반증은 유전적 요인이 중요한 역할을 하며, 가족력이 있는 경우 발생 위험이 약 2~3배 높아집니다. 발의 인대 이완성, 발의 형태(평발, 넓은 앞발바닥), 엄지발가락의 굴절 패턴 등 유전적 특성이 무지외반증 발생에 직접 영향을 미칩니다. 유전적 요인 외에도 좁고 앞이 뾰족한 신발 착용, 하이힐 등 환경적 요인이 발병을 촉진하므로 유전적 소인이 있다면 특히 신발 선택에 주의하시기 바랍니다.', 634, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '무지외반증', '무지외반증', 'MEDICATION', '무지외반증 초기 보존적 치료를 시작하기 전에 올바른 신발 선택이 필수적입니다. 앞이 넓고 볼이 넉넉하며 굽이 낮은 신발을 착용해야 엄지발가락에 가해지는 압박을 줄이고 변형의 진행을 늦출 수 있습니다. 약물 처방(진통 소염제)은 통증 완화를 위한 보조 수단이며, 신발 교정 없이 약물만으로는 근본적인 개선이 어렵습니다.', 635, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '무지외반증', '무지외반증', 'PREVENTION', '교정용 보조기(bunion splint, 무지외반 교정기)와 교정 인솔은 엄지발가락의 변형 진행을 늦추고 통증을 줄이는 데 도움이 됩니다. 특히 야간에 착용하는 교정기는 엄지발가락을 정상 위치로 유지시켜 주며, 신발 내부에 삽입하는 교정 인솔은 발의 하중 분산을 도와 통증을 완화합니다. 하이힐과 앞이 좁은 신발 착용을 줄이고 이러한 교정 도구를 함께 사용하면 예방 효과를 높일 수 있습니다.', 636, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '무지외반증', '무지외반증', 'EXERCISE', '무지외반증 증상 완화와 발목 안정성 향상에 효과적인 운동으로는 발가락 스트레칭(엄지발가락을 손으로 정상 위치로 당기기), 수건 집기 운동(발가락으로 수건을 집는 동작), 발가락 벌리기 및 모으기 운동이 있습니다. 장무지굴근과 단무지외전근 강화 운동도 발 아치와 엄지발가락 정렬 유지에 도움이 되며, 발목 강화를 위한 까치발 들기 운동도 병행하면 효과적입니다. 운동 방법은 정형외과 또는 재활의학과에서 지도받으시기 바랍니다.', 637, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '무지외반증', '무지외반증', 'CAUSE', '무지외반증의 유전적 원인 자체를 없애는 것은 현재 의학적으로 불가능합니다. 유전적 소인이 있더라도 앞볼이 넓은 신발 착용, 굽이 낮은 신발 선택, 발가락 강화 운동, 교정 인솔 사용 등으로 발병과 진행을 늦출 수 있습니다. 변형이 이미 진행된 경우에는 수술적 교정이 유일한 근본적 치료이므로, 정형외과 전문의와 상담하여 적절한 관리 방법을 결정하시기 바랍니다.', 638, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '무지외반증', '무지외반증', 'REHAB', '무지외반증으로 인한 발 피로를 줄이기 위해서는 발 앞부분이 넓고 볼 공간이 충분하며, 쿠션이 좋고 아치 지지대가 있는 신발을 선택하는 것이 중요합니다. 굽은 2cm 이하의 낮은 굽이 권장되며, 신발 내부에 맞춤형 교정 인솔(orthotics)을 삽입하면 발의 하중 분산과 통증 완화에 도움이 됩니다. 가능하면 정형외과 또는 재활의학과에서 발 검사 후 개인 발 형태에 맞는 맞춤 인솔을 처방받는 것을 권장합니다.', 639, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '무지외반증', '무지외반증', 'DEFINITION', '무지외반증 수술은 변형이 심하고 보존적 치료에 반응하지 않을 때 시행합니다. 수술 방법은 변형 정도에 따라 연부 조직 교정술, 근위/원위 경골 절골술(절제 후 정렬 교정, 예: 갈비 절골술, Chevron 절골술), 근관절 유합술 등 다양하며, 뼈를 절단하여 엄지발가락의 각도를 교정하고 금속 핀이나 나사로 고정하는 방법이 흔합니다. 수술의 목적은 통증 감소와 기능 개선이며, 수술 후 4~8주 정도 보행 제한과 재활이 필요합니다.', 640, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '무지외반증', '무지외반증', 'SYMPTOM', '무지외반증의 증상으로 엄지발가락 외측 돌출부의 통증과 압박 외에도, 두 번째·세 번째 발가락으로의 압박 이동으로 인한 망치 발가락(hammer toe) 변형, 발바닥 굳은살(callus) 형성, 발바닥 통증(족저근막염 유발 가능), 발 피로 증가 등이 나타날 수 있습니다. 새끼발가락이 엄지발가락 쪽으로 휘는 소지외반증(내반 소지)이 동반되기도 합니다. 여러 발가락에 변형이 동반되는 경우 정형외과 전문의의 포괄적인 평가가 필요합니다.', 641, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '무지외반증', '무지외반증', 'DIAGNOSIS', '엄지발가락 옆의 통증과 발 크기 증가(돌출부로 인한 넓이 증가)가 있더라도 수술 없이 보존적 치료를 먼저 시도할 수 있습니다. 볼 넓은 신발 착용, 교정 인솔과 야간 교정기 사용, 진통 소염제 복용, 발가락 패드 사용으로 통증을 관리할 수 있습니다. 변형 각도가 크지 않거나 통증이 조절되는 경우 보존적 치료가 효과적이므로, 정형외과 전문의와 상담하여 수술 여부를 결정하시기 바랍니다.', 642, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '무지외반증', '무지외반증', 'TREATMENT', '무지외반증은 치료 없이 단순히 지켜보기만 하면 대부분 변형이 서서히 진행되므로, 진단 후 적극적인 관리가 권장됩니다. 수술 외 보존적 치료 방법으로는 올바른 신발 선택, 교정 인솔, 야간 교정기, 발가락 간격 유지 패드 착용, 발가락 강화 운동 등이 있으며 이는 진행을 늦추고 통증을 관리하는 데 도움이 됩니다. 보존적 치료로 조절되지 않거나 변형이 심하면 수술을 고려하며, 전문의와 상담하시기 바랍니다.', 643, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '선천성 편평발', '선천성편평발', 'CHECKUP', '선천성 편평발(선천성 수직 거골 또는 유연성 편평발) 진단을 위해서는 발 X선 촬영(서서 찍는 체중 부하 촬영)으로 거골-제1중족골 각도(Meary''s angle), 종골 경사각 등을 측정합니다. 신체 검사에서 발 아치의 유연성 여부를 확인(유연성 편평발은 발꿈치 들기 시 아치 형성)하며, 초음파나 MRI는 연부 조직 평가에 사용됩니다. 소아정형외과 전문의의 진료를 통해 병적 편평발과 정상 발달 과정의 편평발을 감별하는 것이 중요합니다.', 644, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '선천성 편평발', '선천성편평발', 'DIET_LIFE', '선천성 편평발 환자가 장시간 걷기 후 피로를 줄이기 위해서는 항염증 식품(오메가3, 항산화 식품)을 충분히 섭취하고 건강 체중을 유지하는 것이 중요합니다. 생활 습관으로는 아치 지지대가 있는 교정 인솔 신발을 착용하고, 장시간 서 있거나 걷는 시간을 분산시키며, 발과 종아리 스트레칭을 규칙적으로 시행하는 것이 도움이 됩니다. 피로가 심하거나 통증이 동반된다면 정형외과 또는 재활의학과에서 전문적인 인솔 처방을 받으시기 바랍니다.', 645, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '선천성 편평발', '선천성편평발', 'MEDICATION', '선천성 편평발로 인한 활동 시 통증 완화를 위해 아세트아미노펜(타이레놀)이나 비스테로이드성 항염증제(이부프로펜, 나프록센 등)를 단기적으로 사용할 수 있습니다. 통증이 심한 경우 족부 전문의 처방으로 국소 주사(스테로이드)나 외용 진통제를 고려할 수 있습니다. 약물은 근본 치료가 아닌 증상 완화 수단이므로, 교정 인솔과 물리치료를 병행하는 것이 더 효과적이며 정형외과 전문의와 상담하시기 바랍니다.', 646, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '선천성 편평발', '선천성편평발', 'PREVENTION', '생후 6개월 영아의 발바닥에서 편평발처럼 보이는 것은 지방 패드와 미성숙한 아치로 인해 정상적으로 나타나는 현상이며, 대부분 만 3~6세까지 아치가 자연스럽게 형성됩니다. 예방보다는 정상 발달을 지원하기 위해 아이가 맨발로 다양한 지면에서 걷고 뛰는 기회를 많이 주는 것이 중요합니다. 만 3세 이후에도 아치가 형성되지 않거나 통증, 보행 이상이 있다면 소아정형외과 전문의의 진료를 받아보시기 바랍니다.', 647, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '선천성 편평발', '선천성편평발', 'EXERCISE', '선천성 편평발 환자에게 도움이 되는 운동으로는 발가락 들어 올리기(발바닥 아치 강화), 수건 집기(발가락으로 바닥의 수건을 집는 동작), 까치발 들기(종아리와 발 아치 강화), 발바닥 마사지 및 스트레칭이 있습니다. 아이의 경우 맨발 걷기와 모래나 잔디 위 걷기가 발 아치 발달에 도움이 되며, 성인은 발 내재근 강화 운동을 꾸준히 하면 발의 지지력을 높일 수 있습니다. 운동 시작 전 정형외과 또는 재활의학과에서 본인 상태에 맞는 운동 처방을 받는 것이 권장됩니다.', 648, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '선천성 편평발', '선천성편평발', 'CAUSE', '선천성 편평발의 원인은 대부분 유전적 요인으로 발 인대의 이완성 및 뼈 구조적 특성이 유전됩니다. 그 외에도 태아 발달 과정 중의 뼈 형성 이상(수직 거골 등), 신경근육 질환(뇌성마비, 척수이분증), 결합 조직 질환(말판 증후군 등)이 원인이 될 수 있습니다. 임신 중 일반적인 부주의(자세, 생활 습관)가 선천성 편평발의 직접적 원인이 되는 것은 아니며, 임신 중 영양 관리와 기형 발생 원인 노출을 피하는 것이 전반적인 태아 건강에 도움이 됩니다.', 649, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '선천성 편평발', '선천성편평발', 'REHAB', '선천성 편평발 재활 프로그램은 개인의 연령, 변형 정도, 통증 유무, 동반 질환에 따라 맞춤 구성됩니다. 일반적으로 교정 인솔 처방, 발 내재근 및 종아리 근육 강화 운동, 스트레칭, 보행 훈련, 필요 시 보조기 착용으로 이루어지며, 소아는 성장에 따른 아치 발달을 모니터링하면서 단계적으로 진행합니다. 재활의학과 또는 소아정형외과 전문의와 물리치료사가 협력하여 진행하며, 정기적인 추적 관찰이 중요합니다.', 650, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '선천성 편평발', '선천성편평발', 'DEFINITION', '영유아 검진에서 선천성 편평발이 의심되면 소아정형외과 전문의가 시각적 관찰과 보행 분석을 통해 1차 평가를 시행합니다. 발바닥 압력 분포를 확인하는 족저압 검사, X선 촬영으로 발의 뼈 구조와 종아치 각도를 측정하며, 필요시 MRI나 초음파 검사로 인대 및 연부조직 상태를 평가합니다. 정확한 진단을 위해 소아정형외과 전문의의 진찰을 받으시기 바랍니다.', 651, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '선천성 편평발', '선천성편평발', 'SYMPTOM', '선천성 편평발이 있으면 발의 종아치가 소실되어 걷거나 운동할 때 발바닥 전체에 하중이 고르게 분산되지 않아 통증이 발생할 수 있습니다. 이 통증은 운동량 증가나 장시간 보행 시 악화되는 경향이 있으며, 발목, 무릎, 허리 통증으로 이어질 수 있습니다. 운동 관련 통증이 지속된다면 정형외과 전문의 상담을 권장합니다.', 652, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '선천성 편평발', '선천성편평발', 'DIAGNOSIS', '선천성 편평발은 정형외과 또는 소아정형외과 전문의에게 진단받을 수 있습니다. 성인의 경우 정형외과 전문의가, 소아·청소년의 경우 소아정형외과 전문의가 발의 구조적 이상 여부를 정확히 평가합니다. 양측 발 모두 전문의에게 체계적인 검사를 받으시기 바랍니다.', 653, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '선천성 편평발', '선천성편평발', 'TREATMENT', '선천성 편평발의 가장 일반적인 치료는 보존적 치료로, 족저 보조기(교정 깔창) 착용과 발의 아치를 지지하는 기능성 신발 사용이 기본입니다. 스트레칭과 근력 강화 운동을 병행하며, 증상이 심하거나 보존적 치료에 반응하지 않는 경우 수술적 교정을 고려할 수 있습니다. 치료 방법은 정형외과 전문의와 상담 후 결정하는 것이 중요합니다.', 654, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '소아마비', '소아마비', 'CHECKUP', '소아마비(폴리오) 예방을 위한 백신 접종은 소아청소년과에서 받을 수 있으며, 국가예방접종 사업의 일환으로 시행됩니다. 소아마비 검진이 필요한 경우에는 소아청소년과 또는 신경과 전문의를 방문하여 진찰 및 필요한 검사를 받을 수 있습니다. 접종 일정이나 검진에 대한 자세한 사항은 담당 의사와 상담하시기 바랍니다.', 655, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '소아마비', '소아마비', 'DIET_LIFE', '소아마비 아동은 균형 잡힌 영양 섭취를 통해 면역력과 근육 기능 유지에 도움을 줄 수 있으며, 단백질, 칼슘, 비타민 D가 풍부한 식단이 권장됩니다. 물리치료사의 지도 아래 규칙적인 재활 운동을 시행하고, 피로를 피하며 충분한 수면을 취하는 것이 중요합니다. 아동의 상태에 맞는 구체적인 관리 방법은 소아청소년과 및 재활의학과 전문의와 상의하시기 바랍니다.', 656, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '소아마비', '소아마비', 'MEDICATION', '소아마비는 현재 완치 약물이 없으며, 약물치료는 주로 증상 완화를 목적으로 합니다. 근육통과 경련에는 진통제와 근이완제, 발열에는 해열제를 사용하며, 재활치료와 병행하여 기능 회복을 도모합니다. 소아마비가 의심될 경우 즉시 신경과 또는 소아청소년과 전문의의 진료를 받으시기 바랍니다.', 657, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '소아마비', '소아마비', 'PREVENTION', '소아마비 예방을 위한 폴리오 백신은 국가예방접종 일정에 따라 생후 2개월, 4개월, 6개월에 기초접종 3회, 생후 15~18개월에 추가접종 1회, 만 4~6세에 마지막 추가접종을 실시합니다. 총 5회 접종으로 완전한 면역이 형성되며, 불활성화 폴리오 백신(IPV)이 주로 사용됩니다. 접종 일정은 소아청소년과 전문의와 확인하시기 바랍니다.', 658, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '소아마비', '소아마비', 'CAUSE', '소아마비는 폴리오바이러스에 오염된 음식, 물, 분변-구강 경로로 전파되므로 철저한 손 위생과 안전한 식수 및 음식 관리가 중요합니다. 성인도 예방접종력이 불확실하거나 고위험 지역 여행 시 예방접종을 받는 것이 권장됩니다. 개인위생 관리와 예방접종이 소아마비 예방의 핵심이므로 감염내과 또는 예방의학 전문가와 상담하시기 바랍니다.', 659, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '소아마비', '소아마비', 'DEFINITION', '소아마비는 폴리오바이러스 감염으로 발생하는 급성 감염병으로, 주로 소아에서 척수 전각세포를 침범해 하지 마비를 유발합니다. 주요 증상은 발열, 두통, 근육통, 비대칭성 이완성 마비이며, 대부분은 무증상이나 일부에서 영구적 마비가 남을 수 있습니다. 치료는 완치 방법이 없어 증상 완화와 재활치료가 주를 이루며, 예방접종이 가장 효과적인 예방법입니다.', 660, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '소아마비', '소아마비', 'SYMPTOM', '소아마비에 감염된 아기의 초기 증상은 발열, 피로감, 두통, 구토, 목 경직 등 감기와 유사한 증상으로 시작됩니다. 이후 근육 약화, 팔다리 통증, 반사 소실이 나타날 수 있으며, 일부에서는 급격한 비대칭성 사지 마비로 진행됩니다. 이러한 증상이 관찰되면 즉시 소아청소년과 전문의를 방문하여 진찰받으시기 바랍니다.', 661, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '소아마비', '소아마비', 'DIAGNOSIS', '소아 운동 기능 마비(소아마비) 진단은 소아청소년과 또는 소아신경과 전문의를 통해 받을 수 있습니다. 증상, 병력 청취와 신경학적 검사를 시행하고, 바이러스 검출을 위한 대변·인후도말 검사, 혈청 항체 검사, 필요시 뇌척수액 검사와 MRI를 시행합니다. 의심 증상이 있으면 빠른 시일 내에 소아청소년과 전문의의 진료를 받으시기 바랍니다.', 662, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '소아마비', '소아마비', 'TREATMENT', '소아마비 치료는 소아청소년과, 소아신경과, 재활의학과 전문의가 협력하여 담당합니다. 급성기에는 안정, 진통제, 물리치료를 시행하고, 마비 증상이 남은 경우 재활의학과에서 체계적인 재활치료를 통해 근력 회복과 기능 유지를 도모합니다. 증상 완화와 기능 회복을 위해 해당 전문의들과 긴밀히 협력하는 것이 중요합니다.', 663, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '손목 수근관 증후군', '손목수근관증후군', 'CHECKUP', '손목 수근관 증후군 진단에 가장 정확한 검사는 신경전도 검사(NCS)와 근전도 검사(EMG)로, 정중신경의 전도 속도 저하와 신경 손상 정도를 객관적으로 평가합니다. 임상적으로는 팔렌 검사, 티넬 징후 등 이학적 검사를 시행하며, 초음파 검사로 신경과 터널 구조를 영상으로 확인할 수 있습니다. 정확한 진단을 위해 정형외과 또는 신경과 전문의의 진찰을 받으시기 바랍니다.', 664, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '손목 수근관 증후군', '손목수근관증후군', 'DIET_LIFE', '장시간 타이핑 작업 시 손목 수근관 증후군 예방을 위해 항염 효과가 있는 오메가-3 지방산(등 푸른 생선, 아마씨 등)과 비타민 B6가 풍부한 식품(닭가슴살, 바나나, 감자)을 충분히 섭취하는 것이 도움이 될 수 있습니다. 과체중은 수근관 내 압력을 높이므로 적정 체중 유지를 위한 균형 잡힌 식단이 중요하며, 짠 음식과 과도한 당분 섭취는 부종을 악화시킬 수 있어 주의가 필요합니다. 구체적인 영양 상담은 전문의와 함께 진행하시기 바랍니다.', 665, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '손목 수근관 증후군', '손목수근관증후군', 'MEDICATION', '손목 수근관 증후군으로 인한 통증 완화를 위해 이부프로펜, 나프록센 등 비스테로이드성 항염증제(NSAIDs)가 일반적으로 사용됩니다. 심한 통증이나 염증에는 스테로이드 국소 주사를 시행하기도 하며, 이는 일시적 증상 완화에 효과적입니다. 약물 사용 전에 반드시 정형외과 또는 신경과 전문의의 처방과 지도 아래 복용하시기 바랍니다.', 666, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '손목 수근관 증후군', '손목수근관증후군', 'PREVENTION', '마우스 과다 사용으로 인한 손목 보호를 위해 1시간마다 5~10분 휴식을 취하고, 손목 스트레칭과 굴곡·신전 운동을 규칙적으로 시행하는 것이 중요합니다. 인체공학적 마우스와 손목 받침대를 사용하여 손목이 중립 위치를 유지하도록 하고, 키보드와 마우스 높이를 팔꿈치 높이에 맞게 조정하는 것이 권장됩니다. 통증이 지속되면 정형외과 전문의의 진찰을 받으시기 바랍니다.', 667, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '손목 수근관 증후군', '손목수근관증후군', 'CAUSE', '손목 수근관 증후군은 수근관 내 정중신경이 압박되어 발생하는 질환으로, 직접적으로 손목 골절을 일으키지는 않습니다. 다만 손목 골절(특히 콜레스 골절) 후 수근관이 좁아지면서 이차적으로 수근관 증후군이 발생할 수 있어 골절이 원인이 되는 관계입니다. 두 질환의 연관성에 대해서는 정형외과 전문의의 정확한 진단과 상담을 받으시기 바랍니다.', 668, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '손목 수근관 증후군', '손목수근관증후군', 'DEFINITION', '손목 수근관 증후군은 손목의 수근관 안을 지나는 정중신경이 압박되어 발생하는 질환으로, 엄지·검지·중지·약지 절반에 저린 느낌과 통증이 특징입니다. 야간에 증상이 악화되고 손을 흔들면 일시적으로 완화되는 것이 특징적이며, 팔렌 검사나 티넬 검사로 초기 선별이 가능합니다. 정확한 진단을 위해 정형외과 전문의를 방문하여 신경전도 검사를 받으시기 바랍니다.', 669, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '손목 수근관 증후군', '손목수근관증후군', 'SYMPTOM', '손목 수근관 증후군에서 엄지, 검지, 중지, 약지 요측 절반의 저림 증상이 대표적이며, 특히 야간에 심하게 저려 잠에서 깨는 경우가 흔합니다. 이는 수면 중 손목이 굴곡 자세를 취하면서 수근관 내 압력이 높아지기 때문입니다. 야간 저림 증상이 지속된다면 정형외과 전문의의 진찰과 신경전도 검사를 받으시기 바랍니다.', 670, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '손목 수근관 증후군', '손목수근관증후군', 'DIAGNOSIS', '손목 수근관 증후군 진단에는 CT보다 신경전도 검사와 근전도 검사가 가장 중요한 표준 검사입니다. 초음파 검사는 수근관 내 정중신경 단면적 측정과 압박 원인 파악에 유용하며, MRI는 종양이나 구조적 이상이 의심될 때 활용됩니다. 임상 증상과 함께 이학적 검사(팔렌, 티넬)를 종합하여 진단하므로 정형외과 또는 신경과 전문의와 상담하시기 바랍니다.', 671, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '손목 수근관 증후군', '손목수근관증후군', 'TREATMENT', '운동 중 수근관 증후군 증상이 악화되면 즉시 운동을 중단하고 손목을 중립 위치로 고정하는 것이 먼저입니다. 냉찜질로 부종과 통증을 완화하고, 손목 보조기를 착용하여 안정을 취하며, 이부프로펜 등 소염진통제를 단기 복용할 수 있습니다. 증상이 지속되거나 악화되면 정형외과 전문의의 진찰을 통해 주사치료 또는 수술적 치료를 검토하시기 바랍니다.', 672, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '십자 인대 손상', '십자인대손상', 'CHECKUP', '인대가 끊어지는 소리(팝 소리)와 함께 무릎 통증이 발생하면 즉시 응급처치(RICE: 안정, 냉찜질, 압박, 거상) 후 정형외과 전문의를 방문해야 합니다. 정형외과 또는 스포츠의학과에서 이학적 검사(라크만 검사, 전방 당김 검사 등)와 MRI 검사를 통해 십자 인대 손상 여부를 확인합니다. 가까운 정형외과 응급실 또는 외래를 방문하여 신속히 검진받으시기 바랍니다.', 673, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '십자 인대 손상', '십자인대손상', 'DIET_LIFE', '십자 인대 손상 후 적절한 수술과 재활치료를 완료하면 대부분 이전과 유사한 수준의 운동 기능 회복이 가능합니다. 그러나 완전한 기능 회복에는 통상 6~12개월 이상이 소요되며, 재활 종료 후에도 무릎 안정성 강화 운동을 꾸준히 유지하는 것이 중요합니다. 잔존 증상이 있다면 정형외과 전문의 및 재활의학과 전문의와 추가 치료를 상담하시기 바랍니다.', 674, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '십자 인대 손상', '십자인대손상', 'MEDICATION', '고혈압 약을 복용 중인 경우, 십자 인대 손상 치료에 사용되는 소염진통제(NSAIDs)가 혈압 상승 및 신장 기능에 영향을 줄 수 있어 주의가 필요합니다. 또한 일부 항응고제나 근이완제와 고혈압 약의 병용 시 상호작용이 발생할 수 있으므로 반드시 처방 의사에게 현재 복용 중인 모든 약물을 알려야 합니다. 복약 전 반드시 정형외과 및 내과 전문의와 약물 병용에 대한 상담을 받으시기 바랍니다.', 675, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '십자 인대 손상', '십자인대손상', 'PREVENTION', '십자 인대 손상 재발 예방을 위해 대퇴사두근과 햄스트링 근력 강화 운동을 꾸준히 시행하는 것이 중요합니다. 스포츠 활동 전 충분한 준비 운동과 스트레칭을 하고, 무릎 보호대 착용을 고려하며, 무릎에 갑작스러운 충격이나 비틀림이 가해지는 동작을 주의해야 합니다. 구체적인 예방 운동 프로그램은 재활의학과 또는 스포츠의학과 전문의와 상담하시기 바랍니다.', 676, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '십자 인대 손상', '십자인대손상', 'EXERCISE', '십자 인대 손상 후에는 무릎 관절의 안정성이 저하되어 있어 땀이 많이 나는 격렬한 운동은 피해야 합니다. 과도한 발한을 유발하는 고강도 운동은 주로 급격한 방향 전환, 점프, 충격이 동반되어 손상 부위에 추가적인 부하를 주고 회복을 방해할 수 있습니다. 재활 단계에 맞는 운동 강도를 정형외과 또는 재활의학과 전문의와 상담하여 결정하시기 바랍니다.', 677, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '십자 인대 손상', '십자인대손상', 'CAUSE', '십자 인대 손상은 급격한 방향 전환, 점프 후 착지, 충돌 등이 빈번한 축구, 농구, 스키, 배드민턴 등의 스포츠에서 특히 많이 발생합니다. 이러한 운동은 무릎에 비틀림이나 과신전 하중을 가해 전방십자인대(ACL) 또는 후방십자인대(PCL) 파열을 초래합니다. 운동 전 충분한 워밍업과 근력 강화 훈련을 통해 위험을 줄일 수 있습니다.', 678, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '십자 인대 손상', '십자인대손상', 'REHAB', '60대 남성의 십자 인대 손상 재활에는 수영, 수중 보행 등 관절 부하가 적은 유산소 운동과 함께 대퇴사두근 강화를 위한 레그 프레스, 스트레이트 레그 레이즈가 효과적입니다. 의자에 앉아 발목에 모래주머니를 달고 무릎을 펴는 운동과 누운 자세에서 다리 들기 운동도 무리 없이 시행할 수 있습니다. 연령과 회복 단계를 고려한 맞춤형 재활 프로그램은 재활의학과 전문의와 상담하여 설계하시기 바랍니다.', 679, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '십자 인대 손상', '십자인대손상', 'DEFINITION', '운동 중 들리는 파열음(팝 소리)은 인대, 힘줄 또는 연골이 갑자기 끊어지거나 손상될 때 발생하는 소리로 의학적으로 중요한 징후입니다. 십자 인대 손상에서 이 파열음은 전방십자인대가 파열되면서 나는 소리이며, 즉각적인 통증, 부종, 관절 불안정이 동반됩니다. 파열음 이후 무릎 이상이 느껴진다면 즉시 정형외과 전문의를 방문하여 정확한 검사를 받으시기 바랍니다.', 680, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '십자 인대 손상', '십자인대손상', 'SYMPTOM', '무릎의 이상한 감각(불안정감, 무력감, 걸림)이 지속된다면 십자 인대 손상의 만성적 증상일 수 있습니다. 십자 인대가 불완전하게 회복되거나 손상이 방치된 경우 무릎 관절이 불안정해져 이러한 감각이 수개월 이후에도 지속될 수 있습니다. 지속적인 무릎 이상 감각이 있다면 정형외과 전문의를 방문하여 MRI 검사 등 정밀 평가를 받으시기 바랍니다.', 681, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '십자 인대 손상', '십자인대손상', 'DIAGNOSIS', '농구 중 접질린 후 십자 인대 손상이 의심된다면 정형외과 전문의 또는 스포츠의학과 전문의에게 진단을 받아야 합니다. 이학적 검사(전방 당김 검사, 라크만 검사, 피벗 시프트 검사)와 함께 MRI 검사를 시행하여 인대 손상 여부와 정도를 정확히 평가합니다. 빠른 시일 내에 정형외과 외래를 방문하여 적절한 치료 방향을 결정하시기 바랍니다.', 682, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '십자 인대 손상', '십자인대손상', 'TREATMENT', '축구 중 무릎을 다쳐 십자 인대 손상이 의심되는 경우 이송 중에는 RICE 처치(안정, 냉찜질, 압박, 거상)를 시행합니다. 병원에서는 X선으로 골절 여부를 확인하고, MRI로 인대 손상 정도를 평가하며, 부분 파열은 보조기 고정과 재활치료를, 완전 파열은 관절경 수술(전방십자인대 재건술)을 시행합니다. 정형외과 전문의가 손상 정도에 따라 적절한 치료 방법을 결정합니다.', 683, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건 파열', '아킬레스건파열', 'CHECKUP', '발을 제대로 디디지 못하고 종아리 통증이 심한 경우 아킬레스 건 파열이 의심되므로 즉시 정형외과 전문의를 방문해야 합니다. 톰슨 검사(엎드려 종아리를 쥐었을 때 발목이 굴곡되지 않으면 양성)로 임상 진단하며, 초음파 또는 MRI 검사로 파열 위치와 정도를 확인합니다. 신속한 진단과 치료가 예후에 중요하므로 가능한 빨리 정형외과 응급실 또는 외래를 방문하시기 바랍니다.', 684, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건 파열', '아킬레스건파열', 'DIET_LIFE', '아킬레스 건 파열 치료 중 충분한 단백질(닭가슴살, 생선, 두부 등)과 콜라겐 합성에 필요한 비타민 C(과일, 채소) 섭취가 건 조직 회복에 도움이 됩니다. 항염 효과가 있는 오메가-3 지방산과 아연이 풍부한 식품도 조직 회복을 촉진할 수 있습니다. 식이 요법만으로 파열된 건이 치유되지는 않으므로 전문의의 지시에 따른 치료를 병행하시기 바랍니다.', 685, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건 파열', '아킬레스건파열', 'MEDICATION', '아킬레스 건 파열로 인한 보행장애와 부종 완화를 위해 이부프로펜, 나프록센 등 비스테로이드성 항염증제(NSAIDs)가 주로 사용됩니다. 통증이 심한 경우 의사의 처방에 따라 더 강한 진통제를 사용할 수 있으며, 부종 감소를 위해 냉찜질과 거상을 병행합니다. 아킬레스 건 파열은 수술적 또는 보존적 치료가 필요한 심각한 손상이므로 반드시 정형외과 전문의의 진료를 받으시기 바랍니다.', 686, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건 파열', '아킬레스건파열', 'PREVENTION', '아킬레스건과 종아리 근육(비복근, 가자미근)을 규칙적으로 강화하면 건에 가해지는 충격을 분산시켜 파열 위험을 낮출 수 있습니다. 강화된 근육은 갑작스러운 부하 발생 시 충격을 흡수하는 역할을 하며, 준비 운동과 스트레칭을 통해 건의 유연성을 유지하는 것도 중요합니다. 점진적인 운동 강도 증가와 함께 체계적인 강화 훈련 프로그램은 재활의학과 또는 스포츠의학과 전문의와 상담하시기 바랍니다.', 687, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건 파열', '아킬레스건파열', 'EXERCISE', '석고고정 중에는 고정 부위에 체중을 싣거나 충격을 가하는 모든 운동을 피해야 합니다. 특히 달리기, 점프, 스쿼트 등 발목에 하중이 집중되는 운동은 절대 금지이며, 수영도 물속에서 발차기를 하면 아킬레스건에 부담이 됩니다. 석고고정 기간 중 허용 가능한 운동(상체 운동, 대퇴부 근력 운동 등)은 담당 정형외과 전문의와 상의하시기 바랍니다.', 688, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건 파열', '아킬레스건파열', 'CAUSE', '아킬레스 건 파열은 운동을 거의 하지 않는 사람에게도 발생할 수 있습니다. 건의 퇴행성 변화, 스테로이드 투여, 불소퀴놀론계 항생제 복용 등이 건을 약화시켜 가벼운 동작에도 파열이 일어날 수 있습니다. 또한 갑작스럽게 운동을 시작하거나 일상적인 계단 오르기, 점프 동작에서도 발생할 수 있으므로 이상 증상 시 정형외과 전문의의 진찰을 받으시기 바랍니다.', 689, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건 파열', '아킬레스건파열', 'REHAB', '아킬레스 건 파열 재활 중 냉찜질은 부종과 염증을 줄이고 통증을 완화하는 데 도움이 됩니다. 만성 발 통증 환자에서도 냉찜질은 통증 수용체의 신호를 억제하여 일시적 통증 감소 효과를 제공합니다. 단, 냉찜질은 보조적 수단이며 근본적 치료를 대체하지 못하므로 재활치료와 병행하고 재활의학과 전문의의 지도에 따라 시행하시기 바랍니다.', 690, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건 파열', '아킬레스건파열', 'DEFINITION', '아킬레스 건 파열은 발뒤꿈치와 종아리를 연결하는 아킬레스건이 갑작스러운 부하나 외상으로 인해 부분 또는 완전히 끊어지는 손상입니다. 파열 순간 종아리에서 강한 충격이나 찢어지는 느낌과 함께 날카로운 통증이 발생하며, 발목 굴곡이 불가능해집니다. 정확한 진단을 위해 정형외과 전문의를 방문하여 톰슨 검사와 영상 검사를 받으시기 바랍니다.', 691, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건 파열', '아킬레스건파열', 'SYMPTOM', '아킬레스 건 파열의 주요 증상에는 종아리 뒤쪽에서 찢어지거나 맞은 듯한 강한 통증, 파열 순간의 팝 소리, 즉각적인 보행 불능이 포함됩니다. 발목의 능동적 족저굴곡(발끝을 아래로 내리는 동작)이 불가능하거나 크게 약해지며, 파열 부위에 움푹 들어간 부분이 촉진될 수 있습니다. 이러한 증상이 나타나면 즉시 정형외과 전문의의 진찰을 받으시기 바랍니다.', 692, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건 파열', '아킬레스건파열', 'DIAGNOSIS', '아킬레스건 불편함과 통증이 있다면 먼저 정형외과 전문의를 방문하여 이학적 검사를 받아야 합니다. 파열 진단에는 톰슨 검사를 시행하고, 초음파 검사로 건의 연속성과 손상 정도를 실시간으로 확인하며, MRI로 정확한 파열 위치와 범위를 평가합니다. 자가 진단을 피하고 전문의의 정확한 진단을 통해 적절한 치료를 받으시기 바랍니다.', 693, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건 파열', '아킬레스건파열', 'TREATMENT', '아킬레스 건 파열의 치료는 보존적 치료와 수술적 치료로 나뉩니다. 보존적 치료는 석고 또는 보조기로 발목을 고정하고 단계적 재활을 시행하며, 수술적 치료는 관혈적 봉합술 또는 최소침습 봉합술로 파열된 건을 직접 봉합합니다. 수술 여부는 환자의 나이, 활동 수준, 파열 정도에 따라 정형외과 전문의와 충분히 상의하여 결정하시기 바랍니다.', 694, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건염', '아킬레스건염', 'CHECKUP', '발뒤꿈치 통증으로 아킬레스 건염이 의심된다면 정형외과 전문의 또는 스포츠의학과 전문의를 방문하여 진찰받는 것이 권장됩니다. 정형외과에서 이학적 검사와 초음파, MRI 검사를 통해 건염의 위치와 정도를 평가하고 적절한 치료 방향을 제시합니다. 통증이 지속되거나 악화된다면 전문의에게 조기에 진찰을 받으시기 바랍니다.', 695, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건염', '아킬레스건염', 'DIET_LIFE', '아킬레스 건염 증상 완화를 위해 염증을 유발할 수 있는 정제 탄수화물, 튀긴 음식, 과도한 음주를 줄이고 항염증 식품인 오메가-3(생선, 견과류), 비타민 C(과일, 채소), 콜라겐(사골국물, 젤라틴)을 충분히 섭취하는 것이 도움이 됩니다. 생활 습관면에서는 충격을 흡수하는 적절한 운동화 착용, 하이힐 자제, 운동 전후 충분한 스트레칭, 아킬레스건을 무리하게 사용하는 활동 자제가 중요합니다. 구체적인 관리 방법은 정형외과 전문의와 상담하시기 바랍니다.', 696, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건염', '아킬레스건염', 'MEDICATION', '아킬레스 건염 치료에서 소염진통제(NSAIDs) 약물치료는 단기적 통증과 염증 완화에 효과적이며, 물리치료(체외충격파, 초음파 치료, 운동치료)는 건의 실질적 치유와 기능 회복에 더 근본적인 효과를 제공합니다. 약물치료와 물리치료를 병행하면 단독 치료보다 효과가 우수하므로 두 가지를 함께 받는 것이 권장됩니다. 치료 방법과 기간은 정형외과 또는 재활의학과 전문의와 상담하여 결정하시기 바랍니다.', 697, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건염', '아킬레스건염', 'PREVENTION', '아킬레스 건염 예방을 위해 적절한 쿠션이 있는 운동화를 착용하고 딱딱한 바닥에서의 장시간 활동을 피하는 것이 중요합니다. 운동 강도를 급격히 올리지 않고 점진적으로 증가시키며, 종아리 근육 스트레칭과 아킬레스건 이심성 운동(eccentric exercise)을 꾸준히 시행하는 것이 효과적입니다. 체중 관리를 통해 건에 가해지는 부하를 줄이는 것도 예방에 도움이 됩니다.', 698, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건염', '아킬레스건염', 'EXERCISE', '아킬레스 건염으로 하지 운동이 제한되더라도 상체 운동(덤벨, 바벨 운동, 케이블 운동 등)은 일반적으로 직접적인 영향을 받지 않습니다. 다만 서서 하는 운동이나 아킬레스건에 부담을 주는 자세는 피해야 하므로 앉거나 누운 자세에서 상체 운동을 시행하는 것이 안전합니다. 운동 종류와 강도에 대해서는 정형외과 또는 재활의학과 전문의와 상담하여 적절한 운동 계획을 세우시기 바랍니다.', 699, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건염', '아킬레스건염', 'CAUSE', '아킬레스 건염의 내적 요인으로는 건의 퇴행성 변화, 과내전(과도한 발 안쪽 회전), 하지 정렬 이상, 유연성 부족 등이 있으며, 외적 요인으로는 갑작스러운 운동 강도 증가, 부적절한 신발, 딱딱한 운동 표면, 과도한 훈련량이 있습니다. 두 요인이 함께 작용하면 건에 반복적인 미세 손상이 축적되어 염증과 변성이 진행되면서 건염으로 발전합니다. 정형외과 전문의를 통해 개인의 위험 요인을 파악하고 적절한 예방 조치를 취하시기 바랍니다.', 700, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건염', '아킬레스건염', 'REHAB', '아킬레스 건염으로 기능이 제한된 경우 재활치료를 통해 통증 완화, 건의 유연성 및 근력 회복, 보행 기능 정상화를 도모할 수 있습니다. 체외충격파 치료, 초음파 치료, 레이저 치료 등 물리적 방법과 함께 이심성 운동(eccentric exercise) 프로그램이 건 치유에 매우 효과적입니다. 재활의학과 전문의와 물리치료사의 지도 아래 개인 맞춤형 재활 프로그램을 시행하는 것을 권장합니다.', 701, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건염', '아킬레스건염', 'DEFINITION', '아킬레스 건염은 발뒤꿈치 위쪽 아킬레스건 부위에 염증이 발생하는 질환으로, 주로 과도한 운동이나 반복적인 부하로 인해 발생합니다. 아킬레스건의 삽입부(발뒤꿈치 뼈에 붙는 부분)나 건 중간 부위에 통증과 부종이 생기며, 아침 첫 보행 시 통증이 심하고 활동 후 악화되는 것이 특징입니다. 의심 증상이 있다면 정형외과 전문의를 통해 정확한 진단과 치료를 받으시기 바랍니다.', 702, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건염', '아킬레스건염', 'SYMPTOM', '아킬레스 건염에서 운동이나 활동 후 지속되는 통증은 건 내 미세 손상과 염증 반응이 완전히 회복되지 않은 상태에서 반복적인 부하가 가해지기 때문에 발생합니다. 이 통증은 주로 운동 시작 시와 종료 후에 심해지며, 만성화되면 휴식 중에도 지속될 수 있어 일상 활동에 지장을 줍니다. 지속적인 통증이 있다면 활동을 줄이고 정형외과 전문의의 진찰을 받으시기 바랍니다.', 703, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건염', '아킬레스건염', 'DIAGNOSIS', '아킬레스 건염 진단을 위해 먼저 병력 청취와 이학적 검사(건 압통, 부종 확인, 족저굴곡 강도 평가)를 시행합니다. 초음파 검사로 건의 비후, 염증, 건내 변성 여부를 실시간 확인하며, MRI는 더 정밀한 평가가 필요할 때 시행합니다. X선 검사로 골극(뼈돌기) 등 동반된 뼈 병변 여부를 확인하며, 종합적 판단으로 진단하므로 정형외과 전문의의 진찰을 받으시기 바랍니다.', 704, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '아킬레스 건염', '아킬레스건염', 'TREATMENT', '아킬레스 건염의 수술적 치료는 보존적 치료(6개월 이상)에 반응하지 않는 경우에 시행합니다. 수술은 병변 건 조직 절제술(건병증 부위 제거), 건내 석회화 제거, 건 삽입부 골극 절제 등을 관절경 또는 개방적 방법으로 시행합니다. 수술 후에는 석고 고정과 단계적 재활치료가 필요하며, 완전 회복까지 수개월이 소요되므로 정형외과 전문의와 수술 여부와 방법을 충분히 상의하시기 바랍니다.', 705, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '염좌', '염좌', 'CHECKUP', '염좌로 인해 신경에 문제가 생겼다면 신경외과보다는 정형외과가 우선 방문처로 적합합니다. 정형외과에서 인대, 힘줄, 뼈 손상과 함께 신경 압박 여부를 함께 평가하며, 신경 압박이나 손상이 심하게 의심되는 경우에는 신경외과와 협진하여 치료합니다. 정확한 진단과 치료 방향 결정을 위해 정형외과 전문의를 먼저 방문하시기 바랍니다.', 706, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '염좌', '염좌', 'DIET_LIFE', '염좌 회복을 위해 항염 효과가 있는 오메가-3 지방산(등 푸른 생선, 아마씨), 항산화 물질이 풍부한 과일과 채소, 조직 재생에 도움이 되는 단백질과 비타민 C 섭취를 늘리는 것이 권장됩니다. 반면 염증을 악화시킬 수 있는 술, 가공식품, 정제 당류, 트랜스 지방은 줄이는 것이 좋습니다. 급성 염좌의 경우 RICE 처치를 우선하고 회복기 식단에 대해서는 의료진과 상담하시기 바랍니다.', 707, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '염좌', '염좌', 'MEDICATION', '염좌 치료에 사용되는 비스테로이드성 항염증제(NSAIDs)는 프로스타글란딘 합성을 억제하여 혈관 수축과 혈소판 기능에 영향을 줄 수 있습니다. 염증성 장 질환(IBD) 환자에서 NSAIDs 사용은 장 점막 손상을 악화시키고 소화기 출혈 위험을 높일 수 있으며, 혈액 순환에도 영향을 미칠 수 있습니다. IBD를 가진 환자에서 염좌 약물 선택은 반드시 소화기내과 및 정형외과 전문의와 상의하시기 바랍니다.', 708, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '염좌', '염좌', 'PREVENTION', '반복적인 염좌 예방을 위해 해당 관절 주변 근육 강화 운동(발목은 종아리, 전경골근 운동; 허리는 코어 운동)을 꾸준히 시행하는 것이 중요합니다. 활동 전 충분한 준비 운동과 스트레칭을 하고, 적절한 신발(발목 지지대 있는 신발)과 보조기 착용을 고려하며, 불안정한 지면에서의 활동을 주의해야 합니다. 재발이 잦다면 정형외과 전문의와 상담하여 근본 원인을 파악하고 관리하시기 바랍니다.', 709, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '염좌', '염좌', 'EXERCISE', '염좌가 완전히 치유된 후에는 고유감각 훈련(밸런스 보드, 외발서기), 관절 주변 근력 강화 운동(저항 밴드 운동, 종아리 강화), 관절 가동 범위 회복 운동을 단계적으로 시행합니다. 수영, 자전거 타기 등 관절에 부담이 적은 유산소 운동으로 심폐 기능과 전반적인 기능 회복을 도모합니다. 재활 운동 프로그램은 재활의학과 전문의와 물리치료사의 지도 아래 단계적으로 시행하시기 바랍니다.', 710, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '염좌', '염좌', 'CAUSE', '인대가 자주 늘어나는 것은 인대 이완증, 관절 과가동성, 반복적인 미세 손상으로 인한 인대 약화, 또는 근육 불균형이 원인일 수 있습니다. 근력 부족으로 관절을 충분히 보호하지 못하거나 고유감각(위치감각) 기능이 저하된 경우에도 인대 손상이 반복될 수 있습니다. 잦은 인대 손상이 있다면 정형외과 전문의에게 진찰을 받고 근본 원인에 맞는 치료 및 예방 운동 계획을 수립하시기 바랍니다.', 711, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '염좌', '염좌', 'REHAB', '염좌로 인한 부종과 발적 완화를 위한 재활치료로는 RICE 처치(안정, 냉찜질, 압박 붕대, 거상)가 기본입니다. 이후 회복 단계에 따라 초음파 치료, 레이저 치료 등 물리치료를 시행하여 염증 감소와 조직 회복을 도모합니다. 부종이 가라앉으면 관절 가동 범위 운동과 근력 강화 운동을 단계적으로 추가하며, 정형외과 또는 재활의학과 전문의의 지도 아래 재활을 진행하시기 바랍니다.', 712, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '염좌', '염좌', 'DEFINITION', '늑골염좌는 늑골이 틀어지는 것이 아니라 늑골과 척추(흉추) 또는 늑골 연골 사이의 관절을 지지하는 인대가 과도하게 늘어나거나 부분 손상된 상태를 말합니다. 주로 외상, 갑작스러운 비틀림, 기침, 재채기로 인해 발생하며, 심호흡이나 몸통 움직임 시 통증이 악화됩니다. 정확한 진단과 치료를 위해 정형외과 또는 흉부외과 전문의의 진찰을 받으시기 바랍니다.', 713, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '염좌', '염좌', 'SYMPTOM', '염좌는 관절을 지지하는 인대가 허용 범위를 벗어난 외력에 의해 과도하게 늘어나거나 부분·완전 파열된 상태로, 탈구와는 구별됩니다. 가장 흔한 발생 부위는 발목, 무릎, 손목이며, 주요 증상으로는 손상 부위의 통증, 부종, 피부 변색(멍), 압통, 관절 불안정감이 있습니다. 증상 정도에 따라 1도(경미한 인대 늘어남)에서 3도(완전 파열)까지 분류되며, 3도 손상은 전문적 치료가 필요합니다.', 714, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '염좌', '염좌', 'DIAGNOSIS', '이삿짐 운반 중 발목 부상이 발생했다면 즉시 RICE 처치를 시행한 후 정형외과를 방문합니다. 의사의 이학적 검사(압통, 부종 확인, 스트레스 검사)와 X선으로 골절 여부를 감별하며, 인대 손상이 의심되면 초음파 또는 MRI로 정밀 평가합니다. 정확한 부위와 손상 정도를 파악해야 적절한 치료 방법이 결정되므로 가능한 빨리 정형외과 전문의의 진찰을 받으시기 바랍니다.', 715, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '염좌', '염좌', 'TREATMENT', '발목 부종과 열감 완화를 위해 냉찜질(첫 48~72시간)과 안정이 기본이며, 이부프로펜 등 NSAIDs 복용으로 통증과 염증을 추가 조절할 수 있습니다. 탄력 붕대로 압박하고 발목을 심장보다 높게 거상하면 부종 감소에 효과적이며, 필요시 보조기나 목발을 사용합니다. 48시간 후에도 심한 부종이나 체중 부하 시 극심한 통증이 있으면 정형외과 전문의의 진찰을 받아 골절 여부를 확인하시기 바랍니다.', 716, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '외반슬', '외반슬', 'DIET_LIFE', '외반슬 환자는 칼슘(유제품, 두부, 녹색 채소)과 비타민 D(지방 생선, 달걀, 햇빛 노출)를 충분히 섭취하여 뼈 건강을 유지하는 것이 중요합니다. 비만은 무릎에 추가적인 하중을 주어 변형을 악화시킬 수 있으므로 적절한 체중 유지가 권장됩니다. 생활 습관면에서는 무릎에 부담이 적은 수영, 자전거 타기를 권장하며, 생활 습관 개선과 함께 정형외과 전문의의 지도를 받으시기 바랍니다.', 717, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '외반슬', '외반슬', 'CAUSE', '외반슬(X자 다리)을 유발하는 뼈의 변형으로는 대퇴골의 외반 변형, 경골의 외반 변형, 발달성 고관절 이형성증, 구루병에 의한 뼈 연화증 등이 있습니다. 성장기에 비타민 D 결핍이나 칼슘 부족으로 뼈가 충분히 경화되지 않으면 체중 하중에 의해 다리뼈가 외측으로 휘어질 수 있습니다. 정확한 원인 파악을 위해 소아정형외과 또는 정형외과 전문의의 진찰이 필요합니다.', 718, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '외반슬', '외반슬', 'DEFINITION', '외반슬은 양쪽 무릎을 붙였을 때 두 발목 사이가 벌어지는 X자 다리 변형을 말합니다. 진단을 위해 소아정형외과 전문의가 시각적 관찰과 이학적 검사를 시행하고, X선으로 하지 정렬 각도(Q각도, 대퇴경골각)를 측정하여 변형의 정도를 정량화합니다. 영유아에서는 생리적 외반슬이 정상적으로 있을 수 있으므로 나이와 변형 정도를 고려한 전문의의 판단이 중요합니다.', 719, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '외반슬', '외반슬', 'SYMPTOM', '외반슬의 특징적인 증상 중 하나로 양쪽 무릎을 붙이고 서면 발목이 벌어지는 X자 모양의 다리 변형이 나타나며, 걷거나 서 있을 때 이 변형이 더 뚜렷해집니다. 심한 경우 무릎 내측 통증, 보행 불안정감, 양쪽 무릎이 서로 부딪히는 증상도 나타날 수 있습니다. 정확한 진단과 경과 관찰을 위해 소아정형외과 전문의를 방문하시기 바랍니다.', 720, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '외반슬', '외반슬', 'DIAGNOSIS', '외반슬 진단은 정형외과 또는 소아정형외과 전문의에게 받는 것이 가장 정확합니다. 전문의는 이학적 검사와 X선 촬영으로 하지 정렬 각도를 정밀 측정하고, 변형의 원인(생리적 vs 병적)과 중증도를 평가하여 치료 방향을 결정합니다. 증상이 지속되거나 걸음걸이에 이상이 있다면 소아정형외과 전문의의 진찰을 받으시기 바랍니다.', 721, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '외반슬', '외반슬', 'TREATMENT', '외반슬 치료는 정형외과 전문의가 주도하며, 경증의 경우 성장을 지켜보는 경과 관찰을 하고 증상이 있으면 물리치료와 교정 보조기를 사용합니다. 심한 변형이나 통증이 있는 경우 성장판 교정술(성장판 고정술) 또는 교정 절골술 등의 수술적 치료를 시행합니다. 병원 외 대안으로는 맞춤 교정 깔창, 근력 강화 운동, 체중 관리 등이 있으나 반드시 전문의 지도하에 진행하시기 바랍니다.', 722, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '요추 추간판 탈출증', '요추추간판탈출증', 'PREVENTION', '버스 기사처럼 장시간 운전하는 직업군에서는 올바른 운전 자세가 요추 추간판 탈출증 예방의 핵심입니다. 좌석을 페달에 편하게 닿는 거리로 조정하고, 등받이를 100~110도로 유지하며 허리 받침대(요추 지지대)를 사용해 허리의 자연스러운 곡선을 지지해야 합니다. 1~2시간마다 5~10분씩 휴식을 취하며 스트레칭을 하고, 운전석 진동 방지 시트 사용도 도움이 됩니다.', 723, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '요추 추간판 탈출증', '요추추간판탈출증', 'EXERCISE', '요추 추간판 탈출증 진단 후 허리를 앞으로 굽히거나 옆으로 굽히는 운동은 추간판 내 압력을 높여 신경 압박을 악화시킬 수 있으므로 초기에는 피해야 합니다. 특히 앉아서 상체를 앞으로 구부리는 동작, 무거운 물건을 들면서 굽히는 행동은 재발이나 악화 위험이 큽니다. 운동 종류와 허용 범위는 신경외과 또는 정형외과 전문의, 재활의학과 전문의와 상담하여 단계적으로 시행하시기 바랍니다.', 724, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '요추 추간판 탈출증', '요추추간판탈출증', 'CAUSE', '요추 추간판 탈출증은 주로 30~50대에 많이 발생하며, 이는 추간판이 최대 수분 함량을 유지하다가 이 시기부터 노화로 인해 수핵의 수분이 감소하기 시작하기 때문입니다. 노화가 진행될수록 추간판의 탄력성이 떨어지고 섬유륜이 약해져 수핵이 돌출되기 쉬워집니다. 다만 젊은 연령층에서도 외상이나 과도한 부하로 발생할 수 있으며, 정확한 평가는 신경외과 또는 정형외과 전문의와 상담하시기 바랍니다.', 725, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '요추 추간판 탈출증', '요추추간판탈출증', 'DEFINITION', '요추 추간판 탈출증은 척추 뼈 사이에 있는 추간판(디스크)의 외부 섬유륜이 손상되어 내부 수핵이 밖으로 돌출되고, 이것이 주변 신경을 압박하여 통증과 신경 증상을 유발하는 질환입니다. 주로 요추 4-5번 또는 요추 5번-천추 1번 사이에서 발생하며, 허리 통증과 함께 하지 방사통(다리로 내려가는 통증)이 특징입니다. 정확한 진단을 위해 신경외과 또는 정형외과 전문의의 진찰과 MRI 검사가 필요합니다.', 726, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '요추 추간판 탈출증', '요추추간판탈출증', 'SYMPTOM', '다리가 저리는 증상이 밤에 잠자기 불편할 정도로 나타난다면 요추 추간판 탈출증의 신경 압박 증상일 수 있습니다. 이는 누운 자세에서도 특정 척추 자세가 신경을 자극하거나, 신경의 혈액순환이 감소하면서 저림 증상이 악화되는 것입니다. 야간 저림이 지속된다면 신경외과 또는 정형외과 전문의를 방문하여 MRI 검사 등을 통해 정확한 진단을 받으시기 바랍니다.', 727, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '요추 추간판 탈출증', '요추추간판탈출증', 'DIAGNOSIS', '허리와 다리의 통증 및 저림으로 요추 추간판 탈출증이 의심된다면 신경외과 또는 정형외과 전문의를 방문하여 진찰받는 것이 권장됩니다. 두 진료과 모두 이 질환의 전문적 진단과 치료가 가능하며, MRI 검사를 통해 탈출 부위와 신경 압박 정도를 정확히 확인합니다. 가까운 병원의 신경외과 또는 정형외과 외래를 방문하시기 바랍니다.', 728, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '요추 추간판 탈출증', '요추추간판탈출증', 'TREATMENT', '요추 추간판 탈출증으로 보행이 어려운 경우 재활치료 프로그램에는 물리치료(온열 치료, 초음파 치료, 견인 치료), 도수치료, 체외충격파 치료가 포함됩니다. 보행 재활을 위해 수중 보행 훈련, 코어 근육 강화 운동(맥켄지 운동, 윌리엄스 운동), 균형 훈련이 단계적으로 시행됩니다. 개인의 상태에 맞는 재활 프로그램은 재활의학과 전문의와 함께 수립하시기 바랍니다.', 729, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '요추관 협착증', '요추관협착증', 'PREVENTION', '요추관 협착증 예방을 위해 허리를 과도하게 신전(뒤로 젖히는 자세)시키는 동작과 장시간 서 있거나 걷는 것을 피해야 합니다. 복부 근육과 허리 주변 근육을 강화하는 코어 운동을 규칙적으로 시행하고, 허리에 부담을 주는 무거운 물건 들기와 급격한 자세 변화를 삼가야 합니다. 증상 악화를 방지하기 위해 정형외과 또는 신경외과 전문의와 상담하여 적절한 활동 제한과 관리 방법을 확인하시기 바랍니다.', 730, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '요추관 협착증', '요추관협착증', 'CAUSE', '요추관 협착증은 주로 50대 이상 노년층에서 퇴행성 변화로 발생하지만, 드물게 선천성 척추관 협착, 척추 골절, 척추 종양 등으로 인해 젊은 연령층에서도 발생할 수 있습니다. 젊은 사람에게 발생할 경우 허리 통증, 하지 방사통, 신경인성 파행(걸을수록 다리가 저리고 아픔) 등의 증상이 나타날 수 있습니다. 이러한 증상이 있다면 신경외과 또는 정형외과 전문의의 정밀 검사를 받으시기 바랍니다.', 731, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '요추관 협착증', '요추관협착증', 'DEFINITION', '오래 서 있으면 다리가 무겁고 불편한 증상은 요추관 협착증의 전형적인 신경인성 파행 증상과 일치합니다. 요추관 협착증에서는 서 있거나 걸을 때 척추관이 더 좁아져 신경이 압박되므로 증상이 심해지고, 허리를 앞으로 구부리거나 앉으면 증상이 완화되는 특징이 있습니다. 그러나 정확한 진단을 위해 MRI를 포함한 검사가 필요하므로 신경외과 또는 정형외과 전문의를 방문하시기 바랍니다.', 732, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '요추관 협착증', '요추관협착증', 'SYMPTOM', '요추관 협착증의 주요 증상으로 오래 서 있거나 걸을수록 허리와 엉덩이, 다리가 저리고 무거워지는 신경인성 파행이 포함됩니다. 이는 협착된 척추관 내에서 신경이 압박되어 혈류가 감소하기 때문이며, 앉거나 허리를 앞으로 구부리면 증상이 일시적으로 완화됩니다. 이러한 증상이 반복된다면 신경외과 또는 정형외과 전문의를 방문하여 MRI 등 정밀 검사를 받으시기 바랍니다.', 733, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '요추관 협착증', '요추관협착증', 'DIAGNOSIS', '요추관 협착증 진단을 위해 이학적 검사 후 X선으로 척추 정렬과 퇴행성 변화를 확인하고, MRI로 척추관의 협착 정도와 신경 압박 위치를 정밀 평가합니다. CT 척수조영술은 MRI 촬영이 불가한 경우 대안으로 활용됩니다. 서 있거나 걸을 때 척추 통증과 하지 저림이 있다면 신경외과 또는 정형외과 전문의를 방문하여 적절한 검사를 받으시기 바랍니다.', 734, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '요추관 협착증', '요추관협착증', 'TREATMENT', '요추관 협착증은 증상의 정도에 따라 통원 치료와 입원 치료를 선택합니다. 경도~중등도의 경우 통원으로 약물치료, 물리치료, 도수치료, 신경 차단술 등의 보존적 치료가 가능하며, 증상이 심하거나 보존적 치료 후에도 개선이 없으면 수술적 치료를 고려합니다. 통원 치료 대 입원 수술의 선택은 증상 중증도에 따라 결정되므로 신경외과 또는 정형외과 전문의와 충분히 상의하시기 바랍니다.', 735, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '족저 근막염', '족저근막염', 'CHECKUP', '아침에 첫 걸음을 내딛을 때 발바닥 통증이 심하고 발목까지 아프다면 족저근막염이 의심됩니다. 정형외과 전문의의 이학적 검사(발뒤꿈치 압통 확인, 발가락 신전 검사)와 함께 초음파 검사로 근막 두께와 염증 여부를 확인하며, X선으로 종골 골극 유무를 평가합니다. 증상이 지속된다면 정형외과 또는 재활의학과 전문의를 방문하여 정확한 진단과 치료를 받으시기 바랍니다.', 736, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '족저 근막염', '족저근막염', 'DIET_LIFE', '족저근막염 전용 쿠션화나 아치 지지 기능이 있는 신발은 발바닥에 가해지는 충격을 분산시키고 근막에 가해지는 긴장을 줄여 보행 시 통증을 완화하는 데 도움이 됩니다. 맞춤 교정 깔창과 함께 사용하면 효과가 더 좋으며, 딱딱한 바닥이나 신발 없이 걷는 것을 피하는 것도 중요합니다. 단, 신발만으로 완치를 기대하기 어려우므로 정형외과 전문의의 치료와 병행하시기 바랍니다.', 737, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '족저 근막염', '족저근막염', 'MEDICATION', '족저근막염으로 인한 발바닥 통증 완화를 위해 이부프로펜, 나프록센 등 비스테로이드성 항염증제(NSAIDs)가 1차적으로 사용됩니다. 경구 약물로 충분한 효과가 없는 경우 스테로이드 국소 주사를 고려할 수 있으나, 반복 주사는 족저근막 파열 위험이 있어 주의가 필요합니다. 약물 사용 전 반드시 정형외과 전문의의 처방과 지도를 받으시기 바랍니다.', 738, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '족저 근막염', '족저근막염', 'PREVENTION', '족저근막염 예방에 가장 효과적인 방법은 종아리 근육과 족저근막 스트레칭을 꾸준히 시행하는 것입니다. 매일 아침 일어나기 전, 앉아서 발가락을 당기는 족저근막 스트레칭을 3세트 이상 시행하면 아침 첫 발의 통증을 크게 줄일 수 있습니다. 추가로 쿠션이 좋은 신발 착용, 적절한 체중 유지, 딱딱한 바닥 장시간 보행 피하기를 병행하는 것이 권장됩니다.', 739, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '족저 근막염', '족저근막염', 'EXERCISE', '족저근막염 환자에게는 발에 충격이 적은 수영과 수중 걷기가 증상 개선에 도움이 됩니다. 이 외에도 자전거 타기(실내 자전거)와 함께 발가락 타월 집기, 발가락 굽히기 등의 발 내재근 강화 운동이 효과적입니다. 달리기, 점프 등 발바닥에 충격이 가해지는 운동은 피하고, 운동 전후 족저근막 스트레칭을 반드시 시행하며 재활의학과 전문의와 상담하시기 바랍니다.', 740, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '족저 근막염', '족저근막염', 'CAUSE', '족저근막염의 원인 교정과 약물 외 치료로는 체외충격파 치료(ESWT), 물리치료(초음파, 레이저), 도수치료, 맞춤 교정 깔창이 효과적으로 사용됩니다. 족저근막과 종아리 스트레칭 운동을 꾸준히 시행하는 것만으로도 많은 환자에서 증상이 개선됩니다. 대부분의 경우 6~12개월의 보존적 치료로 회복되며, 수술 없이 치료되는 경우가 많으므로 정형외과 전문의와 치료 계획을 상의하시기 바랍니다.', 741, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '족저 근막염', '족저근막염', 'REHAB', '바닥에 골프공이나 테니스공을 놓고 발바닥으로 굴리며 마사지하는 방법은 족저근막의 유연성을 높이고 근막 조직의 경직을 완화하는 데 도움이 됩니다. 이 재활치료는 통증이 심하지 않은 아급성기 또는 회복기에 효과적이며, 하루 10~15분씩 꾸준히 시행하면 증상 완화에 도움이 됩니다. 급성기에는 오히려 자극이 될 수 있으므로 재활의학과 전문의 또는 물리치료사의 지도에 따라 시행하시기 바랍니다.', 742, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '족저 근막염', '족저근막염', 'DEFINITION', '하이힐을 자주 착용하면 족저근막에 지속적인 과도한 긴장이 가해지고 아킬레스건이 단축되어 발뒤꿈치와 발 내측 아치 부위에 통증이 나타날 수 있습니다. 이는 족저근막염의 발생 원인이자 증상에 포함되는 상황으로, 하이힐 착용이 반복되면 만성 족저근막염으로 발전할 수 있습니다. 증상이 있다면 하이힐 착용을 줄이고 쿠션이 좋은 신발로 교체하며 정형외과 전문의의 진찰을 받으시기 바랍니다.', 743, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '족저 근막염', '족저근막염', 'SYMPTOM', '족저근막염의 증상으로 아침 첫 발걸음 통증 외에도 오랜 시간 앉아 있다가 처음 걸을 때의 심한 통증, 발뒤꿈치 내측 압통, 장시간 서 있거나 걷고 난 후의 통증 악화가 있습니다. 계단 오르기, 발끝서기, 울퉁불퉁한 지면 보행 시 통증이 심해질 수 있으며, 만성화되면 지속적인 발바닥 뻣뻣함도 나타납니다. 이러한 증상이 지속된다면 정형외과 전문의를 방문하시기 바랍니다.', 744, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '족저 근막염', '족저근막염', 'DIAGNOSIS', '족저근막염의 정확한 진단을 위해 정형외과 전문의가 이학적 검사(발뒤꿈치 내측 압통점 촉진, 발가락 배굴 시 통증 증가 확인)를 시행합니다. 초음파 검사는 근막의 두께 증가와 염증 여부를 실시간으로 확인하는 유용한 영상 검사이며, X선으로 골극(종골 골돌기) 동반 여부를 평가합니다. 특이한 신발이나 보행 자세로 인한 발바닥 통증도 족저근막염일 수 있으므로 전문의의 진찰을 받으시기 바랍니다.', 745, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '족저 근막염', '족저근막염', 'TREATMENT', '족저근막염의 일반적인 치료는 충분한 휴식, 냉찜질, 소염진통제 복용, 족저근막 스트레칭, 맞춤 교정 깔창 착용 등 보존적 치료가 기본입니다. 보존적 치료에 반응하지 않으면 스테로이드 주사 또는 체외충격파 치료를 시행하며, 통증 관리를 위해 테이핑, 야간 보조기 착용도 효과적입니다. 대부분 6~12개월 내 회복되므로 정형외과 전문의의 지도 아래 꾸준한 치료를 받으시기 바랍니다.', 746, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '좌골신경통', '좌골신경통', 'CHECKUP', '50대 여성의 엉덩이와 다리 저림 및 통증이 좌골신경통인지 확인하기 위해 정형외과 또는 신경외과 전문의의 이학적 검사(하지 직거상 검사, 굴곡-내전-내회전 검사)를 우선 시행합니다. MRI로 요추 추간판 탈출증, 척추관 협착증, 이상근 증후군 등 원인을 확인하며, 신경전도 검사와 근전도 검사로 신경 손상 여부와 범위를 객관적으로 평가합니다. 해당 증상이 지속된다면 신경외과 또는 정형외과 전문의를 방문하시기 바랍니다.', 747, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '좌골신경통', '좌골신경통', 'DIET_LIFE', '좌골신경통 예방을 위한 근력 운동으로는 코어 근육(복횡근, 다열근)을 강화하는 플랭크, 브리지 운동이 척추 안정성 향상에 효과적입니다. 이상근 스트레칭과 함께 대둔근, 햄스트링, 고관절 외회전근 강화 운동을 병행하면 신경 압박 예방과 기능 향상에 도움이 됩니다. 운동 강도와 종류는 재활의학과 전문의 또는 물리치료사의 지도 아래 개인 상태에 맞게 조정하시기 바랍니다.', 748, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '좌골신경통', '좌골신경통', 'MEDICATION', '좌골신경통 치료에는 이부프로펜, 나프록센 등 NSAIDs가 1차 약물로 사용되며, 신경통에는 가바펜틴(신경안정제), 프레가발린이 효과적입니다. 근육 경련이 동반되면 근이완제를, 심한 통증에는 단기간 스테로이드 경구 투여 또는 경막외 스테로이드 주사를 고려합니다. 약물 선택과 용량은 원인과 증상 정도에 따라 달라지므로 반드시 신경외과 또는 정형외과 전문의의 처방에 따라 복용하시기 바랍니다.', 749, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '좌골신경통', '좌골신경통', 'CAUSE', '좌골신경통은 주로 요추 추간판 탈출증, 요추관 협착증, 이상근 증후군, 골반 내 종양 등으로 인해 좌골신경이 압박되거나 자극을 받을 때 발생합니다. 이로 인해 허리에서 엉덩이, 허벅지 뒤쪽, 종아리, 발끝까지 이어지는 방사통과 저림, 화끈거림이 나타납니다. 좌골신경(sciatic nerve)은 인체에서 가장 굵고 긴 신경으로, 압박 원인에 따라 치료가 달라지므로 신경외과 또는 정형외과 전문의의 정밀 검사가 필요합니다.', 750, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '좌골신경통', '좌골신경통', 'DEFINITION', '좌골신경통은 요추 4~5번 또는 천추 1번에서 기원한 좌골신경이 압박·자극되어 발생하는 신경통으로, 허리에서 시작해 엉덩이·대퇴 후면·종아리·발까지 이어지는 방사통이 특징입니다. 추간판 탈출증(허리 디스크), 척추관 협착증, 이상근 증후군 등이 주요 원인이며, 정확한 진단과 치료를 위해 신경외과 또는 정형외과 전문의 상담을 권고드립니다.', 751, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '좌골신경통', '좌골신경통', 'SYMPTOM', '종아리·발의 통증과 다리 근력 저하가 지속되면 보행 장애, 계단 오르내리기 어려움 등 일상생활 제한이 생길 수 있으며, 심해지면 발처짐(족하수)이나 배뇨·배변 장애까지 나타날 수 있습니다. 이러한 증상은 신경 손상이 진행되고 있다는 신호일 수 있으므로, 즉시 신경외과 또는 정형외과 전문의를 방문하여 정확한 평가를 받으시기 바랍니다.', 752, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '좌골신경통', '좌골신경통', 'DIAGNOSIS', '좌골신경통이 의심될 때는 신경외과 또는 정형외과 전문의와 상담하는 것이 가장 적합합니다. 두 과 모두 요추 MRI, 신경전도 검사 등을 통해 원인 질환을 감별하고 치료 방향을 결정할 수 있으며, 통증이 심하거나 신경학적 이상 소견이 동반되면 신속히 전문의 진료를 받으시기 바랍니다.', 753, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '좌골신경통', '좌골신경통', 'TREATMENT', '좌골신경통의 원인이 기능적 불균형(골반 틀어짐, 이상근 긴장 등)인 경우 도수치료·교정 치료가 증상 완화에 도움이 될 수 있습니다. 그러나 추간판 탈출증이나 척추관 협착증처럼 구조적 문제가 원인인 경우 잘못된 교정은 오히려 신경 손상을 악화시킬 수 있으므로, 반드시 신경외과 또는 정형외과 전문의의 정확한 진단 후 치료 방법을 결정하시기 바랍니다.', 754, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '지체장애', '지체장애', 'CHECKUP', '지체장애 검진 및 진단은 재활의학과, 정형외과, 신경외과 전문의에게 받을 수 있으며, 대학병원이나 종합병원의 재활의학과를 방문하시면 기능 평가와 장애 등록 관련 절차를 안내받을 수 있습니다. 국민건강보험공단의 장애인 건강검진 제도나 지역 보건소를 통해서도 관련 서비스를 이용할 수 있으니 참고하시기 바랍니다.', 755, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '지체장애', '지체장애', 'DIET_LIFE', '지체장애인은 균형 잡힌 영양 섭취가 중요하며, 고단백 식품(두부, 생선, 닭고기)과 칼슘·비타민D가 풍부한 식품으로 근골격계 건강을 유지하고, 과체중이 되지 않도록 적절한 열량을 조절하는 것이 좋습니다. 생활 습관으로는 규칙적인 재활 운동, 욕창 예방을 위한 자세 변환, 금연·금주, 정기적인 의료 검진을 유지하는 것이 중요하며, 구체적인 식이·재활 계획은 재활의학과 전문의 및 영양사와 상담하시기 바랍니다.', 756, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '지체장애', '지체장애', 'MEDICATION', '지체장애 자체를 완치하는 약물은 없으나, 원인 질환(뇌졸중, 근이영양증 등)과 동반 증상에 따라 근이완제, 항경직제(바클로펜 등), 통증 조절 약물, 골다공증 치료제 등이 사용될 수 있습니다. 수술은 척추 기형 교정, 관절 구축 해소, 신경 압박 해제 등 특정 경우에 시행되며, 약물 및 수술 여부는 반드시 재활의학과 또는 해당 전문과 전문의의 판단에 따라 결정되어야 합니다.', 757, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '지체장애', '지체장애', 'PREVENTION', '임신 중 지체장애 예방을 위해서는 임신 초기부터 엽산(하루 400~800mcg)을 충분히 복용하여 신경관 결손을 예방하고, 풍진·거대세포바이러스 등 선천성 감염을 예방하기 위한 예방 접종력 확인 및 위생 관리가 중요합니다. 음주·흡연·약물 남용을 삼가고, 정기 산전 검사를 통해 태아 이상을 조기 발견하는 것이 권고되며, 구체적인 관리 방법은 담당 산부인과 전문의와 상담하시기 바랍니다.', 758, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '지체장애', '지체장애', 'EXERCISE', '지체장애 환자는 본인의 장애 유형과 정도에 맞는 운동 강도를 설정하는 것이 중요하며, 과도한 운동은 낙상·골절·근육 손상의 위험을 높일 수 있습니다. 일반적으로 관절 가동범위 운동, 저항 운동, 수중 운동 등이 권장되며, 운동 전 충분한 준비 운동과 보조 기구 사용 여부, 통증 발생 시 즉시 중단 등을 지켜야 합니다. 개인별 운동 계획은 재활의학과 전문의 및 물리치료사와 협력하여 수립하시기 바랍니다.', 759, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '지체장애', '지체장애', 'CAUSE', '지체장애의 원인 중 가장 흔한 것은 뇌졸중 등 뇌혈관 질환으로 인한 뇌 손상이며, 그 다음으로 사고에 의한 척수 손상, 근이영양증 등 근신경계 질환 순으로 알려져 있습니다. 선천적 원인(뇌성마비, 척추이분증)도 상당한 비율을 차지하며, 원인에 따라 치료 및 재활 방향이 달라지므로 재활의학과 전문의의 정확한 평가가 필요합니다.', 760, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '지체장애', '지체장애', 'REHAB', '사고 후 다리 지체장애에 대한 재활 운동을 꾸준히 시행하면 근력 회복, 보행 능력 향상, 관절 구축 예방, 일상생활 동작 독립성 증가 등의 긍정적인 변화를 기대할 수 있습니다. 재활의 효과는 손상 부위·정도, 치료 시작 시기, 환자의 의지와 참여도에 따라 달라지므로, 재활의학과 전문의와 물리·작업치료사로 구성된 다학제 팀과 함께 체계적인 재활 프로그램을 진행하시기 바랍니다.', 761, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '지체장애', '지체장애', 'DEFINITION', '지체장애는 사지(팔·다리)와 척추의 기능 이상으로 일상생활 동작에 제한이 생기는 상태를 총칭하며, 원인에 따라 뇌성마비형, 척수 손상형, 근육병형 등 다양한 유형이 있습니다. 소아마비(폴리오)는 폴리오바이러스 감염으로 인한 척수 전각 손상이 원인인 특정 감염 질환으로, 지체장애의 원인 중 하나이지만 지체장애 전체와는 구별되는 개념입니다. 정확한 유형 분류와 치료 방향은 재활의학과 전문의 상담을 통해 결정하시기 바랍니다.', 762, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '지체장애', '지체장애', 'SYMPTOM', '지체장애는 운동 장애 외에도 감각 이상(저림, 통증, 감각 둔화), 욕창, 관절 구축, 골다공증, 방광·장 기능 장애, 호흡 기능 저하 등의 합병증이 동반될 수 있습니다. 또한 사회적 참여 제한으로 인한 우울증, 불안 등 심리적 문제도 흔하게 나타날 수 있어 신체적 재활과 함께 정신건강 관리도 중요합니다. 동반 증상에 대한 종합적인 평가는 재활의학과 전문의에게 받으시기 바랍니다.', 763, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '지체장애', '지체장애', 'DIAGNOSIS', '지체장애 진단은 부상 직후보다는 급성기 치료가 완료된 후 기능적 회복이 어느 정도 진행된 시점(보통 부상 후 6개월~1년 경과 후)에 장애 상태가 안정화되었을 때 이루어집니다. 장애 등록을 위해서는 재활의학과, 정형외과, 신경외과 전문의의 장애 진단서가 필요하며, 읍·면·동 주민센터에 장애인 등록 신청을 통해 절차를 진행할 수 있습니다.', 764, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '지체장애', '지체장애', 'TREATMENT', '지체장애 치료는 원인·유형·정도에 따라 달라지며, 물리치료(근력 강화, 보행 훈련), 작업치료(일상생활 동작 훈련), 보조 기구 처방(휠체어, 보행 보조기), 약물 치료(근이완제, 항경직제)가 주로 사용됩니다. 구조적 문제(척추 변형, 관절 구축)가 심한 경우 수술적 교정이 필요할 수 있으며, 재활의학과를 중심으로 신경외과, 정형외과, 사회복지사 등이 협력하는 다학제적 접근이 가장 효과적입니다.', 765, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '척추측만증', '척추측만증', 'CHECKUP', '척추측만증이 의심될 때는 먼저 전방굴곡검사(Adams test)로 늑골 융기 여부를 확인하고, 전후·측면 전척추 X선 촬영으로 Cobb 각도를 측정하여 만곡 정도를 평가합니다. 신경학적 이상이 동반되거나 특이한 통증이 있을 경우 MRI 검사를 추가로 시행하며, 정형외과 또는 척추 전문 외과 전문의에게 정확한 검진을 받으시기 바랍니다.', 766, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '척추측만증', '척추측만증', 'DIET_LIFE', '급성장기에는 척추를 지지하는 근육이 따라가지 못해 척추측만증이 악화될 수 있으므로 규칙적인 코어 근육 강화 운동이 중요합니다. 식이 면에서는 뼈 건강을 위해 칼슘(유제품, 뼈째 먹는 생선)과 비타민D를 충분히 섭취하고, 올바른 자세 유지, 무거운 가방 한쪽으로만 메지 않기, 정기적인 척추 검진을 생활화하는 것이 도움이 됩니다. 만곡이 진행되는 경우 정형외과 전문의 상담 후 보조기 착용 여부를 결정하시기 바랍니다.', 767, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '척추측만증', '척추측만증', 'MEDICATION', '현재까지 약물만으로 척추측만증의 만곡 자체를 완치하는 치료법은 없습니다. 통증 완화를 위해 소염진통제나 근이완제를 일시적으로 사용할 수 있지만, 이는 증상 관리에 불과합니다. 척추측만증의 근본 치료는 만곡 정도에 따라 관찰·운동 치료·보조기 착용·수술로 결정되므로, 정형외과 전문의와 상담하여 적절한 치료 방향을 결정하시기 바랍니다.', 768, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '척추측만증', '척추측만증', 'PREVENTION', '허리 통증이 있을 경우 무리한 동작을 피하고, 올바른 자세로 앉기, 규칙적인 스트레칭과 코어 근육 강화 운동을 실시하는 것이 도움이 됩니다. 예방을 위해서는 평소 좌우 균형 잡힌 자세 유지, 가방을 번갈아 메기, 정기적인 척추 검진(특히 성장기 청소년), 과체중 방지가 중요합니다. 통증이 지속되거나 만곡이 의심되면 정형외과 전문의에게 조기에 평가받으시기 바랍니다.', 769, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '척추측만증', '척추측만증', 'EXERCISE', '필라테스는 척추 안정화 근육(심부 코어 근육)을 강화하고 자세 교정에 도움을 주어 경도~중등도 척추측만증 환자의 증상 완화와 만곡 진행 억제에 긍정적인 효과가 보고되어 있습니다. 다만 만곡의 방향과 정도에 따라 특정 동작이 오히려 악화시킬 수 있으므로, 반드시 척추측만증 치료 경험이 있는 물리치료사나 전문 강사 지도 하에 시행하고, 정형외과 전문의와 치료 계획을 함께 조율하시기 바랍니다.', 770, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '척추측만증', '척추측만증', 'CAUSE', '장시간 앉아서 일하는 자세 자체가 척추측만증의 직접적인 원인은 아니나, 구부정한 자세와 코어 근육 약화, 척추 주변 근육 불균형을 유발하여 기존 만곡을 악화시키는 요인이 됩니다. 스트레칭 없이 장시간 동일 자세를 유지하면 근육이 불균형하게 긴장·단축되어 척추에 비대칭적 하중이 가해지므로, 1시간마다 기립·스트레칭을 시행하고 인체공학적 의자 사용과 올바른 자세 교육을 병행하는 것이 권고됩니다.', 771, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '척추측만증', '척추측만증', 'REHAB', '척추측만증이 진행되면 외관상 체형 비대칭(어깨 높이 차이, 골반 불균형), 만성 요통, 보행 이상 등이 발생할 수 있습니다. 만곡이 40~50도 이상으로 심해지면 흉곽 변형으로 인한 심폐 기능 저하(호흡 곤란, 심장 압박)가 나타날 수 있고, 척수 신경 압박으로 인한 하지 마비·감각 이상 등 신경학적 합병증도 발생할 수 있습니다. 정기적인 정형외과 전문의 추적 관찰을 통해 만곡 진행을 조기에 발견하고 관리하시기 바랍니다.', 772, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '척추측만증', '척추측만증', 'DEFINITION', '척추측만증은 척추가 정면에서 보았을 때 S자 또는 C자 형태로 10도 이상 옆으로 휘어진 상태를 말하며, 원인 불명의 특발성이 80% 이상을 차지하고 그 외 선천성, 신경근육성 원인도 있습니다. 주요 증상으로는 어깨·골반 높이 불균형, 요통, 한쪽 견갑골 돌출, 몸통 비대칭 등이 있으며, 심한 경우 호흡 곤란이 동반될 수 있습니다. 정확한 진단과 치료 계획은 정형외과 전문의에게 받으시기 바랍니다.', 773, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '척추측만증', '척추측만증', 'SYMPTOM', '앉아 있을 때 허리 통증이 심한 증상은 척추측만증으로 인한 척추 주변 근육의 비대칭적 과부하와 근육 피로가 원인일 수 있습니다. 다만 허리 통증만으로는 척추측만증을 확정할 수 없고, 추간판 탈출증, 근막 통증 증후군 등 다른 원인도 가능하므로 전척추 X선 검사를 포함한 정형외과 전문의의 정확한 진단이 필요합니다.', 774, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '척추측만증', '척추측만증', 'DIAGNOSIS', '척추측만증 진단 및 치료에는 정형외과와 신경외과 모두 전문성을 갖추고 있습니다. 일반적으로 성장기 청소년의 특발성 척추측만증은 정형외과가 주로 담당하며, 신경학적 이상 증상(하지 마비, 감각 이상)이 동반된 경우에는 신경외과의 협진이 필요합니다. 두 과 모두 척추 전문 클리닉을 운영하는 경우가 많으니, 가까운 대학병원이나 척추 전문 병원을 방문하여 상담받으시기 바랍니다.', 775, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '척추측만증', '척추측만증', 'TREATMENT', '기능적 척추측만증(다리 길이 차이, 근육 경련 등이 원인)은 원인 교정(굽높이 조절, 물리치료)으로 개선이 가능하며, 구조적 척추측만증(척추 자체의 구조적 변형)은 Cobb 각도에 따라 운동 치료(20도 미만), 보조기 착용(20~40도), 수술(40~50도 이상)을 시행합니다. 두 원인이 복합된 경우 기능적 요인 교정 후 잔여 구조적 만곡을 평가하여 추가 치료를 결정하며, 정형외과 전문의의 종합적인 평가와 치료 계획이 필수적입니다.', 776, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍', '통풍', 'CHECKUP', '통풍이 의심되면 혈액 검사로 혈중 요산 수치(7mg/dL 이상이면 고요산혈증), 신기능(크레아티닌, eGFR), 염증 수치(CRP, ESR), 전혈구 검사를 시행합니다. 가족력이 있는 경우 유전적 요인에 의한 요산 대사 이상 가능성이 있으므로, 내과 또는 류마티스내과 전문의에게 정기적인 혈액 검사와 함께 정확한 평가를 받으시기 바랍니다.', 777, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍', '통풍', 'DIET_LIFE', '통풍 환자는 퓨린이 많은 내장류(간, 심장), 붉은 육류, 등푸른 생선, 갑각류, 알코올(특히 맥주)을 제한해야 합니다. 반면 저지방 유제품, 달걀, 채소, 체리·베리류 등은 요산 수치 감소에 도움이 된다고 알려져 있으며, 하루 2~3리터의 충분한 수분 섭취가 신장을 통한 요산 배출을 촉진합니다. 구체적인 식단 조절 계획은 류마티스내과 또는 내과 전문의 상담을 통해 수립하시기 바랍니다.', 778, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍', '통풍', 'MEDICATION', '통풍 급성 발작 시에는 콜히친, 비스테로이드성 소염진통제(NSAIDs: 인도메타신, 나프록센 등), 스테로이드(경구 또는 관절 내 주사)가 통증 완화에 사용됩니다. 재발 예방을 위한 요산 저하제로는 잔틴산화효소 억제제(알로퓨리놀, 페북소스타트)와 요산 배설 촉진제(벤즈브로마론)가 사용되며, 약물 선택과 용량은 신기능, 동반 질환 등을 고려하여 류마티스내과 또는 내과 전문의의 처방에 따라 결정됩니다.', 779, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍', '통풍', 'PREVENTION', '통풍 예방을 위해서는 퓨린이 많은 음식·알코올 제한, 충분한 수분 섭취(하루 2리터 이상), 적정 체중 유지, 규칙적인 유산소 운동이 기본입니다. 체리, 블루베리 등 안토시아닌이 풍부한 과일이 요산 수치 감소에 도움이 된다는 연구가 있으나, 사과·바나나의 직접적인 요산 저하 효과는 제한적입니다. 요산 수치와 식이 조절 계획은 류마티스내과 또는 내과 전문의와 상담하여 개인에 맞게 수립하시기 바랍니다.', 780, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍', '통풍', 'EXERCISE', '통풍 발작기에는 관절에 무리가 가는 운동을 삼가고, 완화기에는 수영, 자전거, 수중 운동 등 관절에 충격이 적은 저강도 유산소 운동이 요산 수치 관리와 체중 조절에 효과적입니다. 갑작스러운 고강도 운동은 오히려 요산 수치를 급격히 올려 통풍 발작을 유발할 수 있으므로 점진적으로 운동 강도를 높이는 것이 중요하며, 운동 프로그램은 류마티스내과 전문의와 상의 후 결정하시기 바랍니다.', 781, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍', '통풍', 'CAUSE', '통풍의 유전적 원인으로는 신장의 요산 배설 관련 유전자(ABCG2, SLC22A12 등)의 변이가 대표적이며, 이로 인해 요산 배설 능력이 저하되거나 생성이 과다해집니다. 유전적 요인은 고퓨린 식이, 음주, 비만, 이뇨제 사용 등 환경적 요인과 상호작용하여 통풍 발병 위험을 높이므로, 가족력이 있다면 정기적인 혈중 요산 검사와 생활 습관 관리가 특히 중요합니다.', 782, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍', '통풍', 'REHAB', '통풍 재활을 위해서는 발작이 없는 완화기에 수영, 아쿠아로빅, 자전거 타기 등 관절에 부담이 적은 저충격 유산소 운동과 하지 근력 강화 운동을 꾸준히 시행하는 것이 도움이 됩니다. 식습관으로는 퓨린 저함유 식품 중심의 식단, 충분한 수분 섭취, 알코올·과당 제한, 적정 체중 유지가 중요하며, 정기적인 혈중 요산 모니터링과 약물 치료 병행 여부는 류마티스내과 전문의와 상담하시기 바랍니다.', 783, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍', '통풍', 'DEFINITION', '통풍은 혈중 요산(요산나트륨)이 과포화되어 관절 내에 결정으로 침착되면서 발생하는 염증성 관절 질환으로, 엄지발가락 관절(제1중족지관절)에 갑작스러운 극심한 통증, 발적, 열감, 부종이 특징적으로 나타납니다. 초기에는 수시간 내에 증상이 최고조에 달하고 수일 내 호전되는 양상을 보이며, 재발을 반복하면 만성 통풍성 관절염으로 진행할 수 있습니다. 정확한 진단과 치료는 류마티스내과 또는 내과 전문의에게 받으시기 바랍니다.', 784, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍', '통풍', 'SYMPTOM', '통풍에서 무릎 관절 통증은 요산나트륨 결정이 무릎 관절 내 연골, 활막, 윤활낭 등에 침착되어 면역 세포(호중구)가 이를 이물질로 인식하고 공격하면서 발생하는 급성 염증 반응입니다. 무릎은 엄지발가락 다음으로 통풍이 잘 발생하는 부위이며, 관절액이 증가하여 부종과 열감이 동반됩니다. 무릎 통증이 지속되면 류마티스내과 또는 정형외과 전문의의 진료를 받으시기 바랍니다.', 785, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍', '통풍', 'DIAGNOSIS', '통풍 진단을 위해서는 내과, 류마티스내과, 정형외과를 방문하여 혈중 요산 검사, 관절액 흡인 후 편광현미경을 이용한 요산나트륨 결정 확인(가장 확진적), X선 및 초음파 검사를 받을 수 있습니다. 지역 내 내과 또는 류마티스내과가 있는 병·의원이나 대학병원을 방문하시면 되며, 발작 중에 관절액을 채취하면 진단율이 가장 높습니다.', 786, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍', '통풍', 'TREATMENT', '통풍으로 인한 관절 통증과 부종 치료를 위해서는 류마티스내과, 내과, 정형외과를 방문하시면 됩니다. 급성 발작 시에는 콜히친, 비스테로이드성 소염진통제, 스테로이드 등으로 염증을 조절하고, 만성 통풍 관리를 위해 요산 저하 약물 치료 및 생활 습관 교정을 병행하는 것이 원칙입니다. 가까운 내과 또는 류마티스내과에 방문하여 적절한 치료를 받으시기 바랍니다.', 787, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍성 관절염', '통풍성관절염', 'CHECKUP', '통풍성 관절염이 의심되면 혈중 요산 수치 측정(혈액 검사), 관절액 흡인 후 편광현미경으로 요산나트륨 결정 확인(가장 확진적인 방법), 관절 X선 촬영(만성 결절 또는 골미란 확인), 관절 초음파 검사(''이중윤곽 징후'' 등 요산 침착 확인)를 시행합니다. 류마티스내과 또는 내과 전문의를 방문하시면 적절한 검사와 진단을 받으실 수 있습니다.', 788, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍성 관절염', '통풍성관절염', 'DIET_LIFE', '통풍성 관절염의 주요 원인은 혈중 요산 수치 상승(고요산혈증)으로, 퓨린 함량이 높은 육류·내장류·해산물 과다 섭취와 알코올(특히 맥주, 소주)은 요산 생성을 증가시키고 신장 배설을 억제하여 통풍 발작을 유발합니다. 과당이 많은 음료나 비만, 고혈압, 신장 기능 저하, 이뇨제 사용 등도 고요산혈증을 악화시키는 요인이므로, 식이 및 생활 습관 개선이 통풍 관리의 핵심입니다.', 789, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍성 관절염', '통풍성관절염', 'MEDICATION', '통풍성 관절염의 급성 발작기에는 콜히친(발작 초기 빠른 효과), 비스테로이드성 소염진통제(NSAIDs), 스테로이드(경구 또는 관절 내 주사)가 증상 완화에 효과적입니다. 만성 통풍 관리를 위한 요산 저하제로는 알로퓨리놀, 페북소스타트(잔틴산화효소 억제제)와 벤즈브로마론(요산 배설 촉진제)이 사용되며, 약물 선택과 용량은 신장 기능, 동반 질환 등을 고려하여 류마티스내과 전문의의 처방에 따라야 합니다.', 790, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍성 관절염', '통풍성관절염', 'PREVENTION', '붉은 육류와 해산물(특히 조개류, 갑각류, 등푸른 생선)에는 퓨린이 다량 함유되어 있어, 섭취 시 체내에서 요산으로 분해·생성되는 양이 증가하여 혈중 요산 수치가 상승합니다. 또한 고단백 식이는 신장의 요산 배설 능력을 저하시킬 수 있으며, 이로 인해 관절 내 요산나트륨 결정 침착 위험이 높아져 통풍성 관절염 발작이 유발됩니다. 퓨린 섭취를 줄이는 것은 통풍 예방의 핵심적인 식이 전략이므로, 류마티스내과 전문의와 상담하여 구체적인 식단을 계획하시기 바랍니다.', 791, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍성 관절염', '통풍성관절염', 'EXERCISE', '통풍성 관절염 환자는 발작이 없는 완화기에 수영, 수중 에어로빅, 고정식 자전거, 걷기 등 관절에 충격이 적은 저강도 유산소 운동이 체중 관리와 요산 수치 감소에 효과적입니다. 주 3~5회, 30분 이상의 규칙적인 운동이 권장되며, 급격한 고강도 운동이나 탈수를 유발하는 운동은 요산 수치를 급상승시켜 발작을 유발할 수 있으므로 피해야 합니다. 운동 계획은 류마티스내과 전문의와 상담 후 결정하시기 바랍니다.', 792, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍성 관절염', '통풍성관절염', 'CAUSE', '통풍성 관절염은 고요산혈증이 핵심 원인이며, 환경적 요인(고퓨린 식이, 음주, 과당 음료) 외에도 유전적 요인(요산 배설 관련 유전자 변이), 비만·대사 증후군, 고혈압, 신장 기능 저하, 이뇨제·아스피린·면역억제제 등 특정 약물 복용, 납 노출 등이 발병에 영향을 미칩니다. 이러한 복합적 요인을 고려한 통합적 평가와 치료가 필요하며, 류마티스내과 전문의와 상담하시기 바랍니다.', 793, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍성 관절염', '통풍성관절염', 'REHAB', '통풍성 관절염 환자의 재활 운동은 급성 발작기에는 관절 휴식과 냉찜질을 우선으로 하고, 발작이 가라앉은 후 관절 가동범위 운동(발목 돌리기, 발가락 굴신 운동)을 부드럽게 시작합니다. 통증이 완화되면 점진적으로 하지 근력 강화 운동과 균형 훈련을 추가하고, 수중 운동이 관절 부담을 줄이면서 재활하는 데 효과적입니다. 구체적인 재활 운동 프로그램은 재활의학과 또는 물리치료사의 지도 하에 시행하시기 바랍니다.', 794, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍성 관절염', '통풍성관절염', 'DEFINITION', '혈중 요산 수치가 7mg/dL 이상이면 고요산혈증으로 정의되며, 이는 통풍성 관절염 발생의 주요 위험 인자입니다. 그러나 고요산혈증이 있다고 해서 반드시 통풍 증상이 나타나는 것은 아니며, 실제 통풍성 관절염 진단은 전형적인 임상 증상(급성 관절염 발작)과 관절액에서 요산나트륨 결정 확인을 통해 이루어집니다. 류마티스내과 또는 내과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 795, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍성 관절염', '통풍성관절염', 'SYMPTOM', '통풍성 관절염에서 화상을 입은 것처럼 따갑고 극심한 통증, 발적, 열감, 부종이 갑작스럽게 발생하는 것은 관절 내 요산나트륨 결정에 대한 급성 염증 반응의 전형적인 증상입니다. 특히 엄지발가락, 발목, 무릎 등에서 이러한 증상이 나타나며, 밤에 갑자기 시작되어 24~48시간 내에 최고조에 달하는 양상을 보이는 것이 통풍성 관절염의 특징입니다. 이러한 증상이 발생하면 류마티스내과 또는 내과 전문의의 진료를 받으시기 바랍니다.', 796, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍성 관절염', '통풍성관절염', 'DIAGNOSIS', '겨울철 등산 후 엄지발가락 통증은 추운 날씨로 인한 요산 결정 형성 촉진, 탈수에 의한 혈중 요산 농도 상승, 발에 가해지는 반복적 충격 등이 복합적으로 작용하여 통풍 발작을 유발할 수 있습니다. 다만 등산화로 인한 압박, 동상, 무지외반증 등 다른 원인도 감별해야 하므로, 혈중 요산 검사와 영상 검사를 포함한 류마티스내과 또는 내과 전문의의 정확한 진단이 필요합니다.', 797, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '통풍성 관절염', '통풍성관절염', 'TREATMENT', '통풍성 관절염으로 인한 엄지발가락 통증 치료는 급성기에 안정, 발 거상, 냉찜질과 함께 콜히친이나 비스테로이드성 소염진통제를 복용하는 것이 효과적입니다. 증상 호전 후에는 혈중 요산 수치를 6mg/dL 이하로 유지하기 위한 요산 저하제 복용과 함께 퓨린 제한 식이, 충분한 수분 섭취, 알코올 제한 등 생활 습관 교정을 병행해야 재발을 예방할 수 있습니다. 정확한 치료 방향은 류마티스내과 전문의와 상담하시기 바랍니다.', 798, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '괴혈병', '괴혈병', 'DIET_LIFE', '괴혈병 초기에는 비타민C가 풍부한 음식(오렌지, 레몬, 키위, 브로콜리, 파프리카, 딸기 등)을 매일 충분히 섭취하는 것이 가장 중요한 생활 습관입니다. 신선한 과채류 섭취를 늘리고, 흡연(비타민C 파괴 촉진)을 중단하며, 조리 시 열과 산소에 의한 비타민C 손실을 줄이기 위해 생식이나 단시간 조리를 권장합니다. 증상이 의심되면 내과 전문의를 방문하여 정확한 진단 및 치료를 받으시기 바랍니다.', 799, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '괴혈병', '괴혈병', 'MEDICATION', '괴혈병의 주된 치료는 비타민C(아스코르브산) 보충이며, 경증에서는 하루 300~1000mg의 경구 비타민C 보충제를 수주간 복용하면 결합 조직 합성이 회복되어 출혈, 잇몸 부종, 피부 증상이 호전됩니다. 심한 경우 정맥 주사로 비타민C를 투여하기도 하며, 괴혈병의 원인인 비타민C 결핍이 해소되면 증상이 빠르게 개선됩니다. 정확한 용량과 투여 방법은 내과 또는 영양 전문 의사와 상담하여 결정하시기 바랍니다.', 800, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '괴혈병', '괴혈병', 'PREVENTION', '비타민C 결핍에 의한 괴혈병 예방을 위해서는 식단 개선 외에 흡연자나 흡수 장애 환자에게 비타민C 보충제 복용이 권장됩니다. 스트레스, 수술, 외상, 감염 시 비타민C 소모가 증가하므로 이 시기에 충분한 보충이 필요하며, 노인·알코올 의존증 환자·영양 불량자는 정기적인 영양 상태 점검이 중요합니다. 장기 총정맥영양 환자는 비타민C를 포함한 미량 영양소를 반드시 보충해야 하며, 내과 전문의의 지도 하에 관리하시기 바랍니다.', 801, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '괴혈병', '괴혈병', 'CAUSE', '비타민C는 콜라겐 합성에 필수적이며, 과일·채소를 통한 비타민C 섭취가 부족하면 콜라겐 구조가 약해져 혈관 벽 취약, 출혈 경향, 상처 치유 지연, 잇몸 출혈 등 괴혈병 증상이 발생합니다. 과일을 좋아하지 않더라도 브로콜리, 파프리카, 감자, 토마토 등 채소류를 통해 비타민C를 보충할 수 있으며, 매일 성인 기준 75~100mg(흡연자는 135mg 이상) 섭취를 권고드립니다.', 802, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '괴혈병', '괴혈병', 'DEFINITION', '괴혈병(Scurvy)은 비타민C(아스코르브산) 결핍으로 인해 콜라겐 합성이 저하되어 결합 조직이 약해지는 영양 결핍 질환으로, 피부 출혈, 잇몸 출혈·부종, 상처 치유 지연, 피로, 관절 통증 등이 특징입니다. 과거에는 장기 항해 선원들에게 흔했으나, 현재는 극단적인 식이 제한·흡수 장애·알코올 의존증 환자에서 주로 발생하며, 비타민C 결핍이 공통 원인인 만큼 비타민C 보충으로 빠르게 치료됩니다.', 803, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '괴혈병', '괴혈병', 'SYMPTOM', '식욕부진과 출혈 경향(피가 잘 멎지 않음)은 모두 괴혈병의 증상일 수 있습니다. 괴혈병의 주요 증상으로는 잇몸 출혈 및 부종, 피부 점상 출혈, 피하 출혈(멍), 모낭 주위 출혈, 관절 통증 및 부종, 피로감, 빈혈, 상처 치유 지연, 탈모 등이 있습니다. 이러한 증상이 여러 개 동시에 나타나면 내과 전문의에게 비타민C 혈중 농도 검사를 포함한 정확한 진단을 받으시기 바랍니다.', 804, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '괴혈병', '괴혈병', 'DIAGNOSIS', '괴혈병이 의심되는 출혈과 골 변화(소아에서 성장판 이상, 골막하 출혈 등)가 나타나면 내과 또는 소아과(소아의 경우)를 방문하시면 됩니다. 혈중 비타민C 농도 측정, 전혈구 검사, X선 검사(골 변화 확인) 등을 통해 진단이 이루어지며, 영양 결핍이 의심되면 소화기내과 또는 영양 집중 지원팀이 있는 종합병원을 방문하는 것이 권고됩니다.', 805, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '괴혈병', '괴혈병', 'TREATMENT', '비타민C 보충으로 치료를 시작하면 대부분의 괴혈병 증상은 수일~수주 내에 빠르게 호전되며, 심각한 후유증은 드뭅니다. 다만 치료가 많이 늦어진 경우 잇몸 손상·치아 손실, 골막하 출혈로 인한 골 변형, 심한 빈혈로 인한 합병증이 남을 수 있으며, 소아에서는 성장 장애가 지속될 수 있습니다. 정확한 예후는 내과 전문의와 상담하시고, 조기 치료가 예후에 가장 중요합니다.', 806, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '납 중독', '납중독', 'CHECKUP', '납 중독이 의심될 때는 혈중 납 농도 측정(혈액 검사, 가장 중요한 진단 검사)을 우선 시행하며, 소변 납 농도, 전혈구 검사(빈혈·호염기성 반점 적혈구 확인), 신장 기능 검사, 복부 X선(납 이물질 확인), 뇌 영상 검사(신경 증상 동반 시)를 추가로 시행할 수 있습니다. 직업성 납 노출이 의심되면 산업의학과, 그 외에는 내과 또는 소아과(소아의 경우) 전문의에게 검진을 받으시기 바랍니다.', 807, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '납 중독', '납중독', 'DIET_LIFE', '납은 뼈에서 칼슘과 경쟁적으로 작용하여 납이 뼈에 축적되는 성질이 있으며, 혈중 칼슘 농도가 높게 유지되면 상대적으로 납이 뼈에서 혈액으로 재용출되는 것을 억제하는 효과가 있습니다. 따라서 칼슘과 비타민D가 풍부한 식이는 납 축적을 줄이는 데 간접적으로 도움이 될 수 있으나, 근본적인 납 중독 예방은 납 노출 환경 자체를 차단하는 것이 가장 중요하며, 납 중독 치료는 산업의학과 또는 내과 전문의와 상담하시기 바랍니다.', 808, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '납 중독', '납중독', 'PREVENTION', '납 중독 예방을 위해서는 납이 함유된 환경(오래된 페인트, 납 수도관, 납 함유 직업 환경, 납 유약 도자기)에 대한 노출을 최소화하는 것이 가장 중요합니다. 작업 환경에서는 적절한 환기, 보호 장갑·마스크 착용, 작업 후 철저한 손씻기가 필수이며, 어린이는 납 페인트 가루나 오래된 토양에 노출되지 않도록 주의해야 합니다. 납 노출 위험이 높은 직업군은 정기적인 혈중 납 농도 검사를 산업의학과에서 받으시기 바랍니다.', 809, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '납 중독', '납중독', 'CAUSE', '납 중독은 직접 납 접촉 외에도 납이 함유된 먼지나 토양 흡입, 납이 용출된 식수(오래된 납 수도관), 납 유약 도자기·식기 사용, 납 함유 민간 처방(납 함유 한약·수입 보충제), 임신 중 모체의 뼈에서 재용출된 납이 태반을 통해 태아에게 전달되는 경우, 흡연 간접 노출(납 오염 담배) 등이 원인이 될 수 있습니다. 다양한 경로를 파악하여 포괄적인 노출 차단이 필요하며, 산업의학과 또는 내과 전문의와 상담하시기 바랍니다.', 810, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '납 중독', '납중독', 'DEFINITION', '납 중독은 납(Pb)이 체내에 과잉 축적되어 신경계, 조혈계, 신장, 소화기계 등 다양한 장기에 독성을 일으키는 질환입니다. 주요 증상으로는 두통, 피로감, 인지·기억 장애, 말초 신경병증(손발 마비·근력 저하), 복통, 변비, 빈혈(호염기성 반점 적혈구), 고혈압, 신기능 저하 등이 있으며, 소아에서는 특히 뇌 발달 장애와 IQ 저하가 심각한 문제입니다. 증상이 의심되면 산업의학과 또는 내과 전문의에게 혈중 납 농도 검사를 받으시기 바랍니다.', 811, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '납 중독', '납중독', 'SYMPTOM', '납 중독 증상의 발현과 중증도는 혈중 납 농도, 노출 기간, 연령(소아가 특히 취약)에 따라 달라지며, 철분·칼슘·아연 결핍이 있으면 소화관에서 납 흡수가 증가하여 증상이 더 심해질 수 있습니다. 또한 알코올 섭취는 납의 신경 독성을 가중시키고, 신장 기능 저하 시 납 배출이 감소하여 체내 납 축적이 촉진됩니다. 납 노출 환경 차단과 함께 철분·칼슘·비타민C 등 영양 상태를 개선하는 것이 납 독성 경감에 도움이 됩니다.', 812, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '납 중독', '납중독', 'DIAGNOSIS', '납 중독 진단을 위한 혈중 납 농도 검사는 일반 내과 또는 산업의학과에서 시행할 수 있으며, 건강보험이 적용되는 경우 비용이 크게 낮아질 수 있습니다. 직업성 납 노출이 확인된 경우 산업안전보건법에 따른 특수 건강진단 대상이 되어 사업주 부담으로 검진을 받을 수 있으며, 직업 관련이 아닌 경우에도 지역 보건소나 국민건강보험 건강검진 프로그램을 통해 기본 혈액 검사를 받아볼 수 있습니다.', 813, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '납 중독', '납중독', 'TREATMENT', '납 중독 치료는 무엇보다 납 노출 환경에서 즉시 벗어나는 것이 최우선이며, 혈중 납 농도가 높거나(성인 45μg/dL 이상, 소아 35~45μg/dL 이상) 심각한 증상이 있는 경우 킬레이션 치료(DMSA 경구 또는 EDTA 정맥주사)를 시행합니다. 킬레이션 치료는 납을 소변으로 배출시키는 효과가 있으나, 부작용도 있으므로 반드시 산업의학과 또는 내과 전문의의 지도 하에 시행해야 하며, 치료 후에도 정기적인 혈중 납 농도 모니터링이 필요합니다.', 814, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '냉방병', '냉방병', 'PREVENTION', '노약자의 냉방병 예방을 위해서는 실내외 온도 차를 5도 이내로 유지하고, 에어컨 바람을 직접 맞지 않도록 위치를 조정하며, 얇은 긴 옷이나 담요로 체온 유지를 도와야 합니다. 2시간마다 10~15분 이상 실내 환기를 시행하고, 에어컨 필터를 정기적으로 청소하여 레지오넬라균 등 세균 오염을 예방하며, 수분을 충분히 섭취하고 규칙적인 가벼운 활동으로 혈액 순환을 유지하는 것이 중요합니다.', 815, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '냉방병', '냉방병', 'CAUSE', '냉방병은 주로 에어컨에 의한 과도한 냉방 환경, 실내외 급격한 온도 차(7도 이상), 장시간 밀폐 공간에서의 냉방 노출이 원인입니다. 에어컨 냉각수 및 필터에 번식하는 레지오넬라균에 의한 레지오넬라증, 밀폐 공간의 건조한 공기로 인한 호흡기 점막 건조, 체온 조절 기능 저하 등이 냉방병 발생에 관여하며, 면역력이 낮은 노약자·만성 질환자에서 더 취약합니다.', 816, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '냉방병', '냉방병', 'DEFINITION', '냉방병은 의학적으로 명확히 정의된 단일 질환은 아니나, 냉방 환경에 장시간 노출될 때 발생하는 두통, 피로감, 근육통, 소화불량, 코막힘, 인후통 등 감기와 유사한 증상군을 통칭합니다. 에어컨의 과도한 냉기로 인한 체온 조절 기능 장애, 밀폐 공간의 냉풍에 의한 호흡기 점막 건조, 에어컨 필터의 세균·곰팡이 오염이 주요 원인이며, 에어컨·공기청정기의 주기적 필터 청소와 적절한 환기가 예방에 중요합니다.', 817, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '냉방병', '냉방병', 'SYMPTOM', '에어컨을 자주 사용하고 하루 종일 냉방 환경에 있으면 과도한 냉기에 의한 체온 조절 저하, 밀폐 공간의 건조한 공기로 인한 호흡기 자극, 오염된 에어컨 필터의 유해 물질 흡입 등으로 인해 냉방병 증상이 나타날 수 있습니다. 몸살 기운, 두통, 코막힘, 근육통, 소화불량 등이 냉방병의 전형적인 증상이며, 증상이 지속되거나 고열이 동반되면 레지오넬라증 등 다른 질환의 가능성도 있으므로 내과 전문의의 진료를 받으시기 바랍니다.', 818, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '냉방병', '냉방병', 'DIAGNOSIS', '냉방병은 에어컨 냉방 환경 노출 후 두통, 피로, 근육통, 코막힘, 소화불량 등 비특이적 증상이 나타나다 냉방 환경에서 벗어나면 호전되는 특징이 있습니다. 반면 감기·독감은 바이러스 감염으로 발열이 주 증상이고 접촉 감염 전파가 가능하며, 레지오넬라증은 고열·심한 폐렴 증상이 동반되고, 코로나19는 발열·기침·후각·미각 소실 등이 특징입니다. 증상이 3~4일 이상 지속되거나 고열·호흡 곤란이 동반되면 내과 전문의의 진료를 받으시기 바랍니다.', 819, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '냉방병', '냉방병', 'TREATMENT', '냉방병 치료는 주로 증상 완화를 위한 대증 치료로, 두통과 근육통에는 해열진통제(아세트아미노펜, NSAIDs), 소화불량에는 소화제, 코막힘에는 코세척이나 항히스타민제를 사용할 수 있습니다. 자가 치료로는 냉방 환경에서 벗어나 따뜻한 환경에서 휴식, 따뜻한 수분 섭취, 반신욕 등 체온 회복이 효과적이며, 증상이 3일 이상 지속되거나 고열이 동반되면 내과 전문의의 진료를 받으시기 바랍니다.', 820, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '대사 증후군', '대사증후군', 'CHECKUP', '대사 증후군 검진을 위한 혈액 검사(공복 혈당, 중성지방, HDL 콜레스테롤)는 정확한 결과를 위해 최소 8~12시간 공복 상태에서 채혈해야 하며, 식후 혈당과 지질 수치가 검사 결과에 영향을 미치기 때문입니다. 검진 항목으로는 공복 혈당, 혈중 지질(총 콜레스테롤, LDL·HDL 콜레스테롤, 중성지방), 혈압, 복부 둘레 측정이 포함되며, 이러한 검진은 내과 또는 건강검진센터에서 받을 수 있습니다.', 821, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '대사 증후군', '대사증후군', 'DIET_LIFE', '대사 증후군이 있으면 인슐린 저항성과 지방 대사 이상으로 기초 대사율이 저하되고 지방 축적이 용이해져 체중 감량이 어려울 수 있습니다. 개선을 위해서는 정제 탄수화물(흰밥, 빵, 설탕)과 포화지방을 줄이고, 채소·통곡물·단백질 중심의 식단으로 전환하며, 하루 30분 이상의 규칙적인 유산소 운동을 병행하는 것이 중요합니다. 구체적인 식이·운동 계획은 내과 또는 내분비내과 전문의 상담 후 수립하시기 바랍니다.', 822, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '대사 증후군', '대사증후군', 'MEDICATION', '경증 대사 증후군의 경우 약물 없이 식단 조절(정제 탄수화물·포화지방·당분 제한, 채소·통곡물·불포화지방 중심 식단)과 규칙적인 운동(주 5회 이상 30분 유산소 운동)만으로도 혈당, 혈압, 지질 수치를 개선하고 복부 비만을 줄일 수 있습니다. 그러나 각 요소(당뇨, 고혈압, 이상지질혈증)가 심한 경우에는 약물 치료가 필요할 수 있으므로, 정기적인 내과 또는 내분비내과 전문의 추적 관찰이 중요합니다.', 823, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '대사 증후군', '대사증후군', 'PREVENTION', '밥을 적게 먹어도 정제 탄수화물, 당분, 포화지방 위주의 식사, 신체 활동 부족, 복부 비만 경향, 유전적 인슐린 저항성 등이 있으면 대사 증후군 위험이 높습니다. 예방을 위해서는 혈당 지수(GI)가 낮은 통곡물·채소·콩류 중심으로 식단을 구성하고, 단순 당(과자, 음료수)을 제한하며, 하루 7~8시간 충분한 수면과 스트레스 관리, 규칙적인 유산소·근력 운동을 생활화하는 것이 권고됩니다.', 824, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '대사 증후군', '대사증후군', 'EXERCISE', '대사 증후군 예방을 위해 간헐적 단식(16:8 방법 등)과 함께 주 3~5회 30분 이상의 중강도 유산소 운동(빠른 걷기, 자전거, 수영)과 주 2~3회의 근력 운동을 병행하면 내장 지방 감소, 인슐린 민감성 향상, 혈압·혈당·지질 수치 개선에 효과적입니다. 간헐적 단식 중 운동 시 저혈당 위험을 고려하여 식사 직후 운동하는 것이 안전하며, 개인별 건강 상태에 맞는 운동 계획은 내과 또는 내분비내과 전문의와 상담하시기 바랍니다.', 825, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '대사 증후군', '대사증후군', 'CAUSE', '인슐린 저항성은 세포가 인슐린에 반응하지 않아 혈당이 높아지는 상태이고, 렙틴 저항성은 지방세포에서 분비된 식욕 억제 호르몬인 렙틴에 시상하부가 반응하지 않아 과식·비만이 지속되는 상태입니다. 비만(특히 내장 지방 축적)은 두 저항성의 공통 원인이자 결과로, 지방 조직의 염증 사이토카인(TNF-α, IL-6) 분비가 인슐린 신호 전달과 렙틴 수용체 기능을 모두 방해하여 악순환을 형성합니다. 두 저항성 개선을 위해 식이 조절, 운동, 체중 감량이 가장 효과적이며, 내분비내과 전문의와 상담하시기 바랍니다.', 826, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '대사 증후군', '대사증후군', 'DEFINITION', '소화불량만으로는 대사 증후군을 진단할 수 없습니다. 대사 증후군은 복부 비만(허리둘레 남성 90cm, 여성 85cm 이상), 공복 혈당 상승(100mg/dL 이상), 혈압 상승(130/85mmHg 이상), 중성지방 증가(150mg/dL 이상), HDL 콜레스테롤 감소 중 3가지 이상이 해당될 때 진단됩니다. 소화불량은 대사 증후군의 동반 증상일 수 있으나, 위장 질환 등 다른 원인도 있으므로 내과 전문의의 정확한 평가가 필요합니다.', 827, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '대사 증후군', '대사증후군', 'SYMPTOM', '대사 증후군은 초기에 뚜렷한 자각 증상이 없는 경우가 많으나, 진행되면 공복 혈당 상승으로 인한 갈증·다뇨·피로감, 고혈압으로 인한 두통·어지러움, 이상지질혈증으로 인한 황색종(눈꺼풀·팔꿈치 지방 침착), 지방간으로 인한 오른쪽 상복부 불편감 등이 나타날 수 있습니다. 장기적으로는 심혈관 질환(심근경색, 뇌졸중), 제2형 당뇨병, 만성 신장 질환의 위험이 크게 높아지므로 정기적인 내과 추적 관찰이 중요합니다.', 828, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '대사 증후군', '대사증후군', 'DIAGNOSIS', '아침에 손발 부종과 소변색이 뿌옇게 되는 증상은 대사 증후군 자체보다는 신장 기능 이상(단백뇨, 신부전)이나 심장 기능 저하(울혈성 심부전)를 시사할 수 있습니다. 대사 증후군으로 인한 고혈압·당뇨는 신장을 손상시켜 단백뇨와 부종을 유발할 수 있으며, 이러한 증상이 있다면 신장 기능 검사(크레아티닌, eGFR)와 소변 검사(단백뇨 확인)를 포함한 내과 또는 신장내과 전문의의 정확한 평가를 받으시기 바랍니다.', 829, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '대사 증후군', '대사증후군', 'TREATMENT', '대사 증후군 치료의 1차적 접근은 생활 습관 개선(체중 감량, 식이 조절, 규칙적 운동)이며, 약물이 반드시 필요한 것은 아닙니다. 그러나 혈당, 혈압, 지질 수치 중 한 가지 이상이 생활 습관 개선만으로 조절되지 않거나, 심혈관 질환 위험도가 높은 경우에는 각각의 이상에 맞는 약물(혈당강하제, 항고혈압제, 지질강하제 등)을 추가로 사용하게 됩니다. 약물 치료 여부는 내과 또는 내분비내과 전문의의 종합적인 평가에 따라 결정됩니다.', 830, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '비만', '비만', 'DIET_LIFE', '식이 개선으로는 정제 탄수화물·가공식품·포화지방·당분을 줄이고, 채소·통곡물·저지방 단백질·불포화지방산 위주의 균형 잡힌 식단을 유지하며 총 칼로리 섭취를 조절하는 것이 중요합니다. 생활 습관으로는 하루 30~60분, 주 5회 이상 중강도 유산소 운동과 근력 운동을 병행하고, 충분한 수면(7~8시간), 스트레스 관리, 금연, 절주를 생활화하면 체중 감량과 대사 개선에 효과적입니다. 구체적인 계획은 내과 또는 비만 전문의와 상담하시기 바랍니다.', 831, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '비만', '비만', 'PREVENTION', '탄수화물 섭취를 줄이면 혈당 스파이크와 인슐린 과다 분비가 억제되어 지방 합성이 감소하고 체지방 분해가 촉진됩니다. 또한 정제 탄수화물 제한은 내장 지방과 복부 비만 감소, 중성지방 저하, HDL 콜레스테롤 증가에 효과적으로 작용하여 비만과 관련된 인슐린 저항성, 이상지질혈증, 당뇨 위험을 낮추는 데 긍정적인 영향을 줍니다. 개인별 적정 탄수화물 섭취량은 내과 또는 영양사와 상담하여 결정하시기 바랍니다.', 832, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '비만', '비만', 'EXERCISE', '비만 해소를 위해 가장 효과적인 운동 방법은 유산소 운동(빠른 걷기, 수영, 자전거, 조깅)과 근력 운동을 병행하는 것으로, 유산소 운동은 주 5회 이상 30~60분, 근력 운동은 주 2~3회 시행이 권장됩니다. 유산소 운동은 칼로리를 직접 소모하고, 근력 운동은 근육량을 늘려 기초 대사율을 높여 장기적인 체중 관리에 도움이 됩니다. 요가와 스트레칭도 유연성 향상과 스트레스 완화에 도움이 되므로 병행하는 것이 좋으며, 내과 또는 비만 전문의와 개인별 운동 계획을 수립하시기 바랍니다.', 833, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '비만', '비만', 'CAUSE', '식욕 증가, 비만 경향, 지능 저하, 근육 약화가 동시에 나타나는 경우 프라더-윌리 증후군(Prader-Willi syndrome)과 같은 유전성 질환, 갑상선 기능 저하증, 쿠싱 증후군(부신피질 호르몬 과다) 등 내분비 질환을 의심할 수 있습니다. 이러한 증상들이 복합적으로 나타나면 단순한 생활 습관 문제가 아닌 기저 질환이 원인일 수 있으므로, 소아과(소아의 경우) 또는 내분비내과 전문의에게 정확한 진단 및 원인 규명을 위한 평가를 받으시기 바랍니다.', 834, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '비만', '비만', 'DEFINITION', '소아 비만 치료의 핵심은 성장을 저해하지 않으면서 체중 증가 속도를 조절하는 것으로, 칼로리 조절보다는 균형 잡힌 영양 공급과 신체 활동 증가에 초점을 맞춥니다. 하루 1시간 이상의 신체 활동, 가공식품·당분 음료 제한, 스크린 타임 조절이 권장되며, 가족 전체의 생활 습관 개선이 중요합니다. 예방을 위해서는 모유 수유, 신선한 채소·과일·통곡물 위주의 식단 습관 형성, 규칙적인 신체 활동을 어릴 때부터 생활화하며, 소아과 또는 소아 내분비 전문의와 정기 상담을 받으시기 바랍니다.', 835, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '비만', '비만', 'SYMPTOM', '비만은 체질량지수(BMI)가 25kg/m² 이상(한국 기준)인 경우로 정의되며, 과체중은 23~24.9, 1단계 비만 25~29.9, 2단계 비만 30~34.9, 3단계 비만(고도비만) 35 이상으로 세분됩니다. BMI 외에도 복부 비만(허리둘레 남성 90cm, 여성 85cm 이상)도 대사 질환 위험을 평가하는 중요한 기준으로 함께 사용되며, 체지방률과 체성분 분석도 비만 평가에 활용됩니다. 정확한 비만도 평가는 내과 또는 비만 전문 클리닉에서 받으시기 바랍니다.', 836, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '비만', '비만', 'DIAGNOSIS', '비만에는 유전적 요인(가족력)과 환경·생활 습관 요인이 모두 중요하게 작용하며, 연구에 따르면 유전적 요인이 비만 위험도의 40~70%를 설명합니다. 그러나 유전자를 바꾸는 것은 불가능한 반면, 식이·운동·생활 습관은 직접 조절 가능하므로 실제 비만 예방과 치료에서 생활 습관 개선이 더 핵심적인 역할을 합니다. 유전적 위험 요인이 있더라도 건강한 생활 습관을 꾸준히 유지하면 비만 발생을 예방하거나 지연시킬 수 있습니다.', 837, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '비만', '비만', 'TREATMENT', '비만인 경우 단백질(생선, 닭가슴살, 두부, 콩류)과 식이섬유(채소, 통곡물, 과일)가 풍부한 식품을 중심으로 섭취하고, 포화지방·트랜스지방·단순당·가공식품·음료를 제한하는 것이 중요합니다. 식사 시 천천히 꼭꼭 씹어 먹기, 규칙적인 식사 시간 유지, 야식 금지, 음식 일기를 통한 섭취량 확인이 도움이 되며, 음식을 먹는 순서도 채소→단백질→탄수화물 순으로 하면 혈당 급상승을 억제할 수 있습니다. 개인화된 식이 치료 계획은 내과 또는 영양사와 상담하시기 바랍니다.', 838, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '새집 증후군', '새집증후군', 'PREVENTION', '입주 전 보일러를 55~60도로 높여 베이크아웃(bake-out)을 2~3일씩 반복하면 마감재와 가구에서 방출되는 포름알데히드, VOCs(휘발성 유기화합물) 등 유해 물질의 방출을 촉진하고, 이후 충분한 환기로 유해 물질을 실외로 배출하여 실내 농도를 낮추는 데 효과적입니다. 입주 후에도 하루 2회 이상 30분씩 자연 환기를 시행하고, 공기청정기를 사용하며, 유해 물질 방출이 많은 신규 가구·페인트의 충분한 건조 후 사용이 새집 증후군 예방에 도움이 됩니다.', 839, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '새집 증후군', '새집증후군', 'CAUSE', '새집에 입주한 후 새집 증후군 예방을 위해서는 입주 전 충분한 베이크아웃(고온 가열 후 환기)을 여러 차례 반복하고, 하루 2~3회 30분 이상 창문을 열어 자연 환기를 생활화하는 것이 가장 중요합니다. 포름알데히드·VOC 흡착 식물(스파티필럼, 고무나무, 아이비 등)을 배치하거나 활성탄 공기청정기를 사용하는 것도 도움이 되며, 새 가구는 유해물질이 적은 친환경 인증 제품을 선택하고 충분히 환기한 후 사용하는 것이 권고됩니다.', 840, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '새집 증후군', '새집증후군', 'DEFINITION', '새집 증후군은 신규 건축물의 건축 자재(합판, 접착제, 페인트, 마감재)에서 방출되는 포름알데히드, 벤젠, 톨루엔, 자일렌 등 휘발성 유기화합물(VOCs)에 노출되어 발생하는 다양한 증상의 복합체입니다. 주요 증상으로는 두통, 눈·코·목의 자극 증상, 피부 가려움, 호흡기 불편감, 피로감, 어지러움 등이 있으며, 예방을 위해서는 입주 전 충분한 베이크아웃, 정기적 환기, 친환경 자재 사용이 중요합니다. 증상이 지속되면 내과 또는 직업환경의학과 전문의에게 상담하시기 바랍니다.', 841, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '새집 증후군', '새집증후군', 'SYMPTOM', '새집 증후군으로 인한 피부 가려움은 포름알데히드 등 화학 물질이 피부 자극, 알레르기 접촉 피부염, 면역 반응을 유발하여 발생합니다. 눈 가려움은 동일한 화학 물질이 눈의 결막을 자극하여 가려움증, 충혈, 눈물을 유발하고, 두 증상은 동일한 화학 물질 노출로 인해 동시에 발현되는 경우가 많습니다. 증상이 집 안에서만 나타나고 외출 시 호전된다면 새집 증후군을 강하게 의심할 수 있으며, 피부과 또는 알레르기내과 전문의의 진료를 권고드립니다.', 842, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '새집 증후군', '새집증후군', 'DIAGNOSIS', '새집 이사 후 피부 반점과 호흡기 불편감이 발생한 경우 피부과(피부 반점·가려움 평가), 알레르기내과(알레르기 반응·호흡기 과민 평가), 또는 내과를 방문하시면 됩니다. 화학 물질 과민증이 의심되면 직업환경의학과에서 전문적인 평가를 받을 수도 있으며, 증상이 집 안에서만 나타나고 외출 시 호전되는 패턴을 의사에게 정확히 설명하는 것이 진단에 도움이 됩니다.', 843, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '새집 증후군', '새집증후군', 'TREATMENT', '새집 증후군의 가정 내 대처로는 하루 2~3회 이상 자연 환기를 충분히 시행하고, 활성탄 필터 공기청정기를 가동하며, 유해 물질 흡착 식물(산세비에리아, 스파티필럼, 보스턴고사리)을 배치하는 것이 도움이 됩니다. 실내 습도를 40~60%로 유지하여 유해 물질 방출을 억제하고, 입주 초기 여름철 고온이나 보일러 가동으로 온도를 높인 후 충분히 환기하는 베이크아웃을 반복하는 것도 효과적입니다. 증상이 지속되면 내과 또는 알레르기내과 전문의의 진료를 받으시기 바랍니다.', 844, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '알코올성 간질환', '알코올성간질환', 'CHECKUP', '알코올성 간질환 진단을 위해서는 간기능 검사(AST, ALT, GGT, ALP, 빌리루빈), 혈청 단백질·알부민·PT(프로트롬빈 시간) 등 간 기능 평가, 복부 초음파 또는 CT로 간 형태 이상 확인, 간 섬유화 평가(피브로스캔, FIB-4 지수), 필요 시 간 조직 검사를 시행합니다. 검사 주기는 질환 진행 정도와 금주 여부에 따라 다르며, 활동성 간염·간경변 단계라면 3~6개월마다 정기 추적이 필요하므로 소화기내과 전문의와 상담하시기 바랍니다.', 845, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '알코올성 간질환', '알코올성간질환', 'DIET_LIFE', '알코올성 간질환 환자는 무엇보다 완전한 금주가 가장 중요하며, 간 회복을 위해 고단백(두부, 생선, 닭가슴살, 달걀)·고비타민(채소, 과일) 식단을 유지하고 지방간 악화를 막기 위해 포화지방과 단순당을 제한해야 합니다. 간 독성을 유발할 수 있는 불필요한 약물·건강 보조제 복용을 피하고, 충분한 수면과 규칙적인 가벼운 운동으로 전신 건강을 유지하는 것이 중요합니다. 정기적인 소화기내과 추적 관찰을 통해 간 상태를 모니터링하시기 바랍니다.', 846, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '알코올성 간질환', '알코올성간질환', 'MEDICATION', '알코올성 간질환의 가장 흔한 증상은 무증상(알코올성 지방간 단계)이거나 피로감, 식욕부진, 오른쪽 상복부 불쾌감·통증, 구역·구토입니다. 진행되면 황달(피부·눈 흰자 노란색), 복수(배가 부름), 하지 부종, 간성 뇌증(혼돈, 의식 저하), 식도 정맥류 출혈(토혈·흑색변), 응고 장애(멍, 출혈 경향) 등 간경변 합병증이 나타날 수 있습니다. 이러한 증상이 있으면 즉시 소화기내과 전문의의 진료를 받으시기 바랍니다.', 847, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '알코올성 간질환', '알코올성간질환', 'CAUSE', '알코올성 간질환의 발생은 단순히 음주량의 절대적 수치보다는 음주 패턴, 개인별 대사 능력 차이, 유전적 소인, 영양 상태, 동반 간 질환(B·C형 간염) 여부 등 복합적 요인에 의해 결정됩니다. 소량이라도 매일 음주하는 경우, 간 알코올 대사 효소(ADH, ALDH)의 유전적 변이로 인해 알코올의 독성 대사물인 아세트알데히드가 축적되어 간 손상이 발생할 수 있습니다. 간 손상을 예방하기 위해서는 음주량과 빈도 모두를 줄이는 것이 중요하며, 소화기내과 전문의와 상담하시기 바랍니다.', 848, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '알코올성 간질환', '알코올성간질환', 'DEFINITION', '알코올성 간질환은 장기간 과도한 음주로 인해 간에 지방 축적, 염증, 섬유화가 진행되는 질환으로, 매일 음주하는 경우 알코올성 지방간→알코올성 간염→간경변으로 진행 위험이 높습니다. 일반적으로 남성은 하루 40g(소주 약 3잔) 이상, 여성은 20g(소주 약 1.5잔) 이상의 음주가 지속될 경우 위험도가 크게 증가하며, 영양 결핍·비만·바이러스성 간염 동반 시 더 빠르게 악화됩니다. 간 건강 보호를 위해 금주가 가장 중요하며, 소화기내과 전문의와 정기적으로 상담하시기 바랍니다.', 849, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '알코올성 간질환', '알코올성간질환', 'SYMPTOM', '알코올성 간질환에서 오른쪽 상복부 통증은 간 염증과 부종으로 간 피막이 늘어나 발생하며, 황달(고빌리루빈혈증)은 손상된 간 세포가 담즙 대사를 정상적으로 처리하지 못해 혈중 빌리루빈이 축적되어 나타납니다. 이러한 증상이 동반되면 알코올성 간염 이상의 진행 단계를 의미하며, 복수, 하지 부종, 간성 뇌증, 식도 정맥류 출혈 등 간경변 합병증으로 이어질 수 있어 즉시 소화기내과 전문의의 진료와 입원 치료가 필요할 수 있습니다.', 850, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '알코올성 간질환', '알코올성간질환', 'DIAGNOSIS', '알코올성 간질환 진단은 소화기내과 또는 간전문의를 찾아가는 것이 적절합니다. 종합병원이나 대학병원의 소화기내과에서 혈액검사(간기능 수치, 빌리루빈, ALT, AST), 복부 초음파, 필요 시 간 조직검사를 통해 정확한 진단을 받을 수 있습니다. 증상이 있다면 가까운 내과를 먼저 방문해 전문의에게 의뢰받는 방법도 있습니다.', 851, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '알코올성 간질환', '알코올성간질환', 'TREATMENT', '알코올성 간질환의 가장 중요한 치료는 완전한 금주이며, 민간요법만으로 치료하는 것은 의학적으로 권장되지 않습니다. 일부 민간요법(밀크씨슬 등)이 간 보호 효과에 대한 연구가 있으나, 그 효과가 충분히 입증되지 않았고 오히려 상태를 악화시킬 수 있습니다. 반드시 소화기내과 전문의 상담을 통해 적절한 치료 계획을 세우시기 바랍니다.', 852, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '음식 알레르기', '음식알레르기', 'DIET_LIFE', '음식 알레르기는 면역 시스템이 특정 식품 단백질을 과도하게 인식해 발생하는 것으로, 단순히 면역력을 높인다고 해서 알레르기가 개선되지는 않습니다. 오히려 잘못된 방법으로 면역력을 자극하면 알레르기 반응이 악화될 수 있습니다. 알레르기 식품 회피와 알레르기 전문의 상담을 통한 면역 치료가 더 효과적인 접근입니다.', 853, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '음식 알레르기', '음식알레르기', 'MEDICATION', '현재 음식 알레르기를 완전히 치료하는 약물은 없으며, 약물 치료는 주로 증상 완화에 사용됩니다. 항히스타민제, 스테로이드, 에피네프린(심한 반응 시)이 사용되며, 최근에는 면역치료(알레르기 면역요법)가 일부 식품 알레르기에 적용되고 있습니다. 근본적 치료를 위해서는 알레르기내과 전문의 상담을 권고합니다.', 854, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '음식 알레르기', '음식알레르기', 'PREVENTION', '복숭아 섭취 후 목이 따끔거리는 증상은 구강 알레르기 증후군일 수 있으며, 이를 예방하려면 해당 식품을 회피하는 것이 가장 중요합니다. 복숭아를 가열 조리하면 알레르기 단백질이 변성되어 증상이 줄어드는 경우도 있습니다. 증상이 반복된다면 알레르기내과 전문의에게 정확한 원인 식품 검사와 회피 방법에 대한 상담을 받으시기 바랍니다.', 855, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '음식 알레르기', '음식알레르기', 'CAUSE', '음식 알레르기는 면역 시스템이 특정 식품 단백질(항원)을 외부 침입자로 잘못 인식해 IgE 항체를 생성함으로써 발생합니다. 면역치료(탈감작 요법)를 통해 특정 항원에 대한 면역 반응을 조절하면 증상 완화 및 일부 경우 치료 효과를 기대할 수 있습니다. 그러나 이는 알레르기 전문의 감독 하에 진행해야 하며, 임의로 시도하면 위험할 수 있습니다.', 856, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '음식 알레르기', '음식알레르기', 'DEFINITION', '식도 및 위의 점막에 두드러기, 구토, 미각이상, 복통 등의 증상이 나타날 경우 음식 알레르기 또는 호산구성 위장관 질환 등을 의심해볼 수 있습니다. 음식 알레르기는 피부, 소화기, 호흡기, 전신 반응 등 다양한 형태로 나타날 수 있습니다. 정확한 진단을 위해 알레르기내과 또는 소화기내과 전문의 진료를 받으시기 바랍니다.', 857, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '음식 알레르기', '음식알레르기', 'SYMPTOM', '음식 섭취나 접촉 후 얼굴과 입술에 붉은 두드러기가 생기고 가려우며 긁을수록 반점이 커지는 증상은 음식 알레르기의 전형적인 피부 반응입니다. 이는 IgE 매개 즉시형 과민 반응으로, 히스타민 등 화학 물질이 분비되어 발생합니다. 증상이 심하거나 반복될 경우 알레르기내과 전문의에게 피부 단자 검사 및 혈액 IgE 검사를 통한 진단을 받으시기 바랍니다.', 858, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '음식 알레르기', '음식알레르기', 'DIAGNOSIS', '음식 알레르기 진단을 위해 병원에서는 피부 단자 검사(skin prick test), 혈액 내 특이 IgE 항체 검사(RAST 또는 ImmunoCAP), 구성 패치 검사 등을 시행합니다. 확진을 위해 의사 감독 하에 음식 유발 검사(oral food challenge)를 시행하기도 합니다. 알레르기내과 또는 소아과(소아의 경우) 전문의 진료를 통해 적절한 검사를 받으시기 바랍니다.', 859, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '음식 알레르기', '음식알레르기', 'TREATMENT', '특정 음식에 대한 면역 과민 반응 증상(두드러기, 호흡 곤란, 아나필락시스 등)은 중증도에 따라 다르게 치료합니다. 경증은 항히스타민제, 중증은 에피네프린 자동주사기(에피펜)와 스테로이드를 사용하며, 장기적으로는 면역치료(특이 면역요법)가 고려됩니다. 알레르기내과 전문의와 상담해 개인에게 맞는 치료 계획을 수립하시기 바랍니다.', 860, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '이상지질혈증', '이상지질혈증', 'CHECKUP', '이상지질혈증 검진 시 현재 복용 중인 지질 강하제(스타틴, 피브레이트 등), 당뇨약, 베타차단제 등의 약물은 혈중 지질 수치에 영향을 줄 수 있으므로 반드시 의료진에게 알려야 합니다. 갑상선 수술, 담낭 수술 등의 과거력도 지질 대사에 영향을 미칠 수 있습니다. 검진 전 약 복용 여부와 공복 여부(보통 9~12시간 공복 필요)를 담당 의사와 확인하시기 바랍니다.', 861, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '이상지질혈증', '이상지질혈증', 'DIET_LIFE', '이상지질혈증 예방을 위해 포화지방(붉은 육류, 버터, 치즈, 튀긴 음식)과 트랜스지방(가공식품, 패스트푸드)을 제한해야 합니다. 콜레스테롤이 높은 내장류, 새우, 달걀 노른자도 과도한 섭취는 피하고, 대신 채소, 통곡물, 등푸른 생선, 견과류를 섭취하는 것이 좋습니다. 규칙적인 유산소 운동, 금연, 절주도 이상지질혈증 예방에 중요합니다.', 862, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '이상지질혈증', '이상지질혈증', 'MEDICATION', '이상지질혈증 약물 치료의 목표 수치는 환자의 심혈관 위험도에 따라 결정됩니다. 당뇨, 고혈압, 흡연, 나이 등 위험 요인이 많을수록, 또는 이미 심혈관 질환이 있는 경우에는 LDL 콜레스테롤 목표치를 더 낮게(70 mg/dL 미만, 또는 55 mg/dL 미만) 설정합니다. 개인별 위험도 평가에 따른 목표 수치는 심장내과 또는 내분비내과 전문의와 상담해 결정하시기 바랍니다.', 863, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '이상지질혈증', '이상지질혈증', 'PREVENTION', 'HDL(고밀도)콜레스테롤 수치를 높이기 위해서는 규칙적인 유산소 운동(주 5회 이상, 30분 이상)이 가장 효과적입니다. 금연, 절주, 불포화지방산이 풍부한 식품(올리브유, 아보카도, 견과류, 등푸른 생선) 섭취, 체중 감량도 HDL 콜레스테롤 상승에 도움이 됩니다. 트랜스지방과 정제 탄수화물 섭취를 줄이는 것도 중요합니다.', 864, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '이상지질혈증', '이상지질혈증', 'EXERCISE', '이상지질혈증 약 복용 중에도 운동은 치료 효과를 높이는 중요한 보조 요법입니다. 주 3~5회, 30분 이상의 유산소 운동(빠르게 걷기, 수영, 자전거)이 LDL 콜레스테롤 감소와 HDL 콜레스테롤 증가에 효과적입니다. 다만 스타틴 복용 중 근육통이 있다면 고강도 운동을 피하고 담당 전문의와 상담 후 운동 강도를 조절하시기 바랍니다.', 865, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '이상지질혈증', '이상지질혈증', 'CAUSE', '이상지질혈증의 원인은 유전적 요인 외에도 고지방·고열량 식사, 운동 부족, 비만, 흡연, 과음, 당뇨병, 갑상선 기능 저하증 등이 있습니다. 일부 약물(베타차단제, 이뇨제, 스테로이드 등)도 지질 수치에 영향을 줄 수 있습니다. 나이가 들수록 지질 대사 능력이 변화하므로 중년 이후 정기적인 혈액 검사를 통한 관리가 필요합니다.', 866, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '이상지질혈증', '이상지질혈증', 'DEFINITION', '이상지질혈증이란 혈중 총콜레스테롤, LDL 콜레스테롤, 중성지방이 정상 범위보다 높거나 HDL 콜레스테롤이 정상보다 낮은 상태를 말합니다. 이 질환은 대부분 증상이 없지만, 장기간 지속되면 동맥경화증, 심근경색, 뇌졸중 등 심각한 심혈관 합병증을 유발할 수 있습니다. 조기 발견과 관리가 중요하므로 정기적인 혈액 검사를 권장합니다.', 867, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '이상지질혈증', '이상지질혈증', 'SYMPTOM', '이상지질혈증 자체는 대부분 증상이 없어 혈액 검사 없이는 발견하기 어렵습니다. 그러나 수치가 매우 높은 경우 피부 황색종, 눈 주위 황색판종이 나타나기도 합니다. 장기간 방치 시 동맥경화, 협심증, 심근경색, 뇌졸중으로 이어질 수 있으므로 정기 혈액 검사를 받고 이상 소견 시 내과 전문의 상담을 받으시기 바랍니다.', 868, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '이상지질혈증', '이상지질혈증', 'DIAGNOSIS', '이상지질혈증의 기본 진단은 9~12시간 공복 후 채혈하여 총콜레스테롤, LDL, HDL, 중성지방 수치를 확인하는 혈액 검사입니다. 추가적으로 동맥경화 합병증 평가를 위해 경동맥 초음파(내중막 두께 측정), 심전도, 심장 초음파 등을 시행하기도 합니다. 이상지질혈증 진단과 합병증 평가를 위해 내과 전문의 진료를 받으시기 바랍니다.', 869, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '이상지질혈증', '이상지질혈증', 'TREATMENT', '이상지질혈증의 약물 치료에서 가장 널리 사용되는 약물은 스타틴(HMG-CoA 환원효소 억제제)으로 LDL 콜레스테롤을 효과적으로 낮춥니다. 중성지방이 높은 경우 피브레이트계 약물이나 오메가-3 제제를, HDL이 낮은 경우 니아신이 사용될 수 있습니다. 약물 선택은 환자의 지질 프로파일, 심혈관 위험도, 동반 질환에 따라 내과 전문의가 결정하므로 반드시 전문의 상담을 받으시기 바랍니다.', 870, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '전신 홍반성 낭창', '전신홍반성낭창', 'CHECKUP', '전신 홍반성 낭창(루푸스) 의심 증상으로는 발진, 광과민성, 구강 궤양 등이 있으며, 정확한 진단을 위해 류마티스내과를 방문하는 것이 가장 적절합니다. 종합병원 또는 대학병원의 류마티스내과에서 혈액 검사(ANA, anti-dsDNA 항체 등)와 임상 기준 평가를 통해 진단합니다. 초진은 일반 내과나 피부과를 통해 류마티스내과로 의뢰받을 수도 있습니다.', 871, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '전신 홍반성 낭창', '전신홍반성낭창', 'DIET_LIFE', '전신 홍반성 낭창(루푸스)은 자가면역 질환으로, 음식물 위생 문제가 직접적인 원인은 아닙니다. 그러나 알팔파 새싹, 마늘 등 일부 식품이 루푸스 증상을 악화시킬 수 있다는 보고가 있습니다. 특정 식품 섭취 후 증상이 악화되는 경우 식이 일지를 작성해 류마티스내과 전문의와 상담하시기 바랍니다.', 872, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '전신 홍반성 낭창', '전신홍반성낭창', 'MEDICATION', '전신 홍반성 낭창 치료에 사용되는 스테로이드(코르티코스테로이드)의 장기 복용 시 주요 부작용으로는 골다공증, 당뇨병, 고혈압, 체중 증가, 쿠싱 증후군, 면역 억제로 인한 감염 취약성, 위장 장애 등이 있습니다. 백내장, 녹내장 등 안과적 부작용도 나타날 수 있습니다. 스테로이드 복용 중에는 정기적인 검진을 통해 부작용을 모니터링하고 담당 전문의와 상담하시기 바랍니다.', 873, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '전신 홍반성 낭창', '전신홍반성낭창', 'PREVENTION', '전신 홍반성 낭창(루푸스)은 유전적 소인을 가진 사람에게 환경적 요인이 더해져 면역 체계 이상이 발생하는 질환입니다. 유전적으로 HLA-DR2, DR3 등의 유전자가 관련되며, 환경적 요인으로는 자외선 노출, 특정 약물, 바이러스 감염, 호르몬(에스트로겐) 등이 있습니다. 이러한 복합적 요인으로 자기 항체가 생성되어 전신 장기를 공격하게 되므로, 예방보다는 조기 진단과 관리가 중요합니다.', 874, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '전신 홍반성 낭창', '전신홍반성낭창', 'EXERCISE', '전신 홍반성 낭창 환자의 피로와 무기력 개선을 위해 저강도 유산소 운동이 도움이 됩니다. 수영, 가벼운 걷기, 자전거 타기, 수중 에어로빅 등 관절에 부담이 적은 운동이 적합합니다. 다만 운동 후 증상 악화 여부를 관찰하고, 자외선 노출 가능성이 있는 야외 운동 시에는 자외선 차단제를 사용하며 류마티스내과 전문의와 운동 계획을 상의하시기 바랍니다.', 875, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '전신 홍반성 낭창', '전신홍반성낭창', 'CAUSE', '임신 중 온몸이 붉고 가려운 증상은 루푸스 악화, 임신 중 발생하는 다형임신 발진, 임신성 소양증 등 다양한 원인일 수 있습니다. 특히 루푸스 환자의 임신은 고위험 임신으로 분류되며, 태아와 산모 모두에 심각한 위험을 줄 수 있습니다. 즉시 산부인과 및 류마티스내과에 방문해 원인을 파악하고 적절한 치료를 받으시기 바랍니다.', 876, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '전신 홍반성 낭창', '전신홍반성낭창', 'DEFINITION', '전신 홍반성 낭창(루푸스)은 자가면역 질환으로 자신의 면역 체계가 정상 조직을 공격하는 질환입니다. 약 90%가 여성(특히 가임기 여성)에서 발생하며, 이는 에스트로겐이 면역 반응을 증폭시키는 역할을 하기 때문으로 알려져 있습니다. 남성에서도 발생할 수 있으나 여성에 비해 빈도가 낮고, 남성 루푸스 환자는 신장 침범 등 더 심각한 임상 양상을 보이는 경우가 있습니다.', 877, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '전신 홍반성 낭창', '전신홍반성낭창', 'SYMPTOM', '전신 홍반성 낭창 환자의 피부 발진은 볼과 코 위에 걸친 나비 모양 홍반(malar rash)이 특징적이며, 자외선 노출 후 악화되는 광과민성 발진도 흔합니다. 피부 위의 반점이나 붉은 변화가 나타나면 질병 활성도가 높아졌을 가능성이 있으며, 이때는 류마티스내과 전문의에게 검진을 받아야 합니다. 피부 증상만으로 루푸스를 진단하기 어려우므로 반드시 혈액 검사와 임상 평가가 필요합니다.', 878, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '전신 홍반성 낭창', '전신홍반성낭창', 'DIAGNOSIS', '전신 홍반성 낭창의 혈액 검사 진단에서는 ANA(항핵항체) 검사가 선별 검사로 사용되며, 양성 시 anti-dsDNA, anti-Sm 항체 등 추가 검사를 합니다. 보체(C3, C4) 수치 감소, 혈구감소증(빈혈, 백혈구 감소, 혈소판 감소) 등도 확인합니다. ACR/EULAR 분류 기준(11가지 임상·면역 기준 중 4가지 이상 충족)을 통해 진단하며, 류마티스내과 전문의가 종합적으로 평가합니다.', 879, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '전신 홍반성 낭창', '전신홍반성낭창', 'TREATMENT', '전신 홍반성 낭창은 단순 피부 질환이 아니라 피부, 신장, 심장, 폐, 관절, 신경계 등 전신을 침범하는 자가면역 질환입니다. 면역 체계가 자신의 세포 핵 성분(DNA 등)에 대한 자가항체를 생성해 전신 염증을 일으키며 발생합니다. 치료는 증상의 중증도에 따라 항말라리아제(하이드록시클로로퀸), 스테로이드, 면역억제제 등을 사용하며 류마티스내과 전문의의 지속적인 관리가 필요합니다.', 880, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '춘곤증', '춘곤증', 'PREVENTION', '춘곤증의 피로감, 졸음, 집중력 저하를 예방하려면 규칙적인 수면 패턴을 유지하고 봄철 늘어난 활동량에 맞게 점진적으로 활동을 늘리는 것이 중요합니다. 단백질, 비타민B군, 철분이 풍부한 균형 잡힌 식사를 하고, 가벼운 스트레칭과 규칙적인 운동으로 신진대사를 활성화하는 것이 도움이 됩니다. 증상이 심하거나 2~3주 이상 지속된다면 다른 질환 가능성도 고려해 내과 진료를 받으시기 바랍니다.', 881, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '춘곤증', '춘곤증', 'CAUSE', '춘곤증이 봄철에만 나타나는 이유는 낮이 길어지고 기온이 올라가면서 신체 생체리듬이 변화하기 때문입니다. 체온 조절을 위해 피부 혈관이 확장되고 말초 혈류가 늘어나 뇌로 가는 혈류가 일시적으로 줄고, 겨울 동안의 활동 감소에서 봄철 활동 증가로의 전환 과정에서 신체가 적응하며 피로감을 느끼게 됩니다. 또한 봄철 알레르기나 일조량 변화로 인한 멜라토닌 분비 변화도 영향을 줍니다.', 882, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '춘곤증', '춘곤증', 'DEFINITION', '춘곤증은 의학적 질병이 아니라 봄철 환경 변화(기온 상승, 일조량 증가)에 신체가 적응하는 과정에서 나타나는 일시적인 생리적 현상입니다. 주요 특징은 낮 시간의 과도한 졸음, 나른함, 피로감, 집중력 저하, 식욕 변화 등이며 보통 수주 내에 자연스럽게 호전됩니다. 증상이 오래 지속되거나 심한 경우에는 다른 질환을 배제하기 위해 의사 진료를 받는 것이 좋습니다.', 883, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '춘곤증', '춘곤증', 'SYMPTOM', '춘곤증의 나른함과 졸음은 봄철 체온 조절을 위한 말초 혈관 확장으로 뇌 혈류가 상대적으로 감소하면서 나타납니다. 집중력 저하와 권태감은 생체 리듬 재조정 과정에서 발생하며, 식욕 부진과 소화 불량은 자율신경계 변화, 현기증은 혈압 조절 적응 과정에서 생길 수 있습니다. 대부분 2~4주 내에 자연 회복되나 증상이 지속되면 내과 전문의 진료를 받으시기 바랍니다.', 884, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '춘곤증', '춘곤증', 'DIAGNOSIS', '춘곤증은 질병이 아닌 생리적 현상이므로 별도의 특별한 검진이 필요하지 않습니다. 그러나 증상이 2주 이상 지속되거나 일상생활에 지장이 크다면 빈혈, 갑상선 기능 저하증, 당뇨, 우울증 등 다른 원인을 배제하기 위해 내과 또는 가정의학과를 방문해 혈액 검사 등을 받아보시는 것이 좋습니다.', 885, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('기타', '춘곤증', '춘곤증', 'TREATMENT', '춘곤증은 선천적 질환이 아니라 봄철 환경 변화에 신체가 적응하는 과정에서 나타나는 일시적인 생리적 현상입니다. 누구에게나 나타날 수 있으며, 특히 겨울 동안 활동이 적었거나 수면 패턴이 불규칙했던 경우 더 심하게 느껴질 수 있습니다. 규칙적인 생활 습관, 균형 잡힌 식사, 적절한 운동으로 대부분 자연 회복되므로 크게 걱정하지 않아도 됩니다.', 886, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '강박 장애', '강박장애', 'MEDICATION', '강박 장애에서 스트레스와 불안을 완화하기 위해 주로 사용되는 약물은 세로토닌 재흡수 억제제(SSRI, 예: 플루옥세틴, 플루복사민, 서트랄린, 파록세틴 등)입니다. 이 약물들은 강박 증상 자체에도 효과적이며, 의사 처방 하에 사용해야 합니다. 약물 치료와 함께 인지행동치료(CBT)를 병행할 때 더 나은 효과를 기대할 수 있으므로, 정신건강의학과 전문의 상담을 권고합니다.', 887, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '강박 장애', '강박장애', 'CAUSE', '강박 장애(OCD)의 원인은 세로토닌, 도파민 등 신경전달물질의 불균형, 전두엽-선조체-시상 신경 회로의 이상, 유전적 소인이 복합적으로 작용하는 것으로 알려져 있습니다. 스트레스, 외상 경험, 환경적 요인도 증상 발현을 촉진할 수 있습니다. 하루 종일 정리와 청소를 반복하며 다른 활동을 못 하는 경우는 강박 장애의 전형적인 양상으로, 정신건강의학과 전문의 상담을 받으시기 바랍니다.', 888, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '강박 장애', '강박장애', 'DEFINITION', '강박 장애는 원치 않는 반복적인 생각(강박 사고)과 그로 인한 불안을 줄이기 위해 반복적인 행동(강박 행동)을 하는 정신 질환입니다. 청소와 정돈을 자주 하는 것 자체가 강박 장애의 원인이 되는 것이 아니라, 이러한 행동이 통제되지 않고 본인의 의지와 무관하게 강박적으로 이루어지면서 일상생활에 지장을 줄 때 강박 장애로 볼 수 있습니다. 정확한 진단은 정신건강의학과 전문의를 통해 받으시기 바랍니다.', 889, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '강박 장애', '강박장애', 'SYMPTOM', '강박 장애의 핵심 증상은 자신도 원치 않는 반복적이고 침습적인 생각(강박 사고)과 이를 완화하기 위한 반복 행동(강박 행동)입니다. 시도 때도 없이 반복적인 행동이 나타나고 이를 멈추기 어려우며, 행동을 못하면 극심한 불안이 생기는 패턴이 강박 장애의 증상에 해당합니다. 이러한 증상이 하루 1시간 이상 지속되거나 일상에 지장을 준다면 정신건강의학과 전문의 진료를 받으시기 바랍니다.', 890, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '강박 장애', '강박장애', 'DIAGNOSIS', '강박 장애 진료는 정신건강의학과(정신과)에서 받을 수 있습니다. 종합병원, 대학병원, 개인 정신건강의학과 의원 모두 가능하며, 정신건강 복지센터에서도 초기 상담을 받을 수 있습니다. 강박 장애는 인지행동치료(CBT)와 약물치료(SSRI)의 병용이 효과적이므로, 전문의 상담을 통해 적절한 치료 계획을 수립하시기 바랍니다.', 891, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '강박 장애', '강박장애', 'TREATMENT', '강박 장애의 심리 치료(인지행동치료, 노출 및 반응 방지 요법 등)는 정신건강의학과 전문의 또는 임상심리사에게 받을 수 있습니다. 종합병원 및 대학병원의 정신건강의학과, 개인 정신과 의원, 심리상담센터 등에서 치료를 받을 수 있습니다. 한국정신건강복지센터(1577-0199)를 통해 가까운 전문 기관을 안내받는 것도 좋은 방법입니다.', 892, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '건강염려증', '건강염려증', 'MEDICATION', '건강염려증 환자의 불안 조절에는 항불안제(벤조디아제핀계)가 단기적으로 사용될 수 있으나 의존성 위험이 있어 장기 사용은 권장되지 않습니다. SSRI(선택적 세로토닌 재흡수 억제제)나 SNRI가 불안 증상 완화에 효과적으로 사용됩니다. 건강염려증은 약물 단독보다 인지행동치료 병행 시 더 효과적이므로, 정신건강의학과 전문의 상담을 통해 적합한 치료를 선택하시기 바랍니다.', 893, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '건강염려증', '건강염려증', 'CAUSE', '대장암 예방을 위한 영양제와 건강염려증은 직접적인 관련이 없습니다. 대장암 예방에는 식이섬유가 풍부한 채소·과일 섭취, 적색육·가공육 제한, 규칙적인 운동, 금연·절주, 정기적인 대장 내시경 검사가 근거 기반의 예방법입니다. 특정 영양제의 대장암 예방 효과는 제한적이므로, 지나친 건강 불안이 있다면 정신건강의학과 전문의 상담도 함께 고려하시기 바랍니다.', 894, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '건강염려증', '건강염려증', 'DEFINITION', '건강염려증(질병불안장애)이란 신체 증상이 없거나 경미함에도 불구하고 자신이 심각한 질병에 걸렸다는 과도한 공포와 불안이 6개월 이상 지속되는 정신 건강 장애입니다. 반복적인 의료 검진을 받아도 안심하지 못하거나, 반대로 의료기관을 회피하는 양상을 보입니다. 인지행동치료와 SSRI 약물 치료가 효과적이며, 정신건강의학과 전문의 진료를 권고합니다.', 895, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '건강염려증', '건강염려증', 'SYMPTOM', '건강염려증 환자는 실제 질병이 없어도 자신이 심각한 병에 걸렸다는 믿음 때문에 심계항진, 복통, 두통, 피로감 등 다양한 신체 증상을 실제로 경험할 수 있습니다. 이는 불안이 신체화되어 나타나는 현상입니다. 검사 결과가 정상임에도 불안이 지속된다면, 신체 증상에만 집착하기보다 정신건강의학과 전문의를 통해 근본적인 불안 치료를 받으시기 바랍니다.', 896, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '건강염려증', '건강염려증', 'DIAGNOSIS', '가족의 갑작스러운 사망 이후 건강에 대한 극도의 불안이 생기는 것은 건강염려증으로 발전할 수 있는 위험 요인입니다. 건강염려증 진단은 정신건강의학과 전문의가 증상 기간(6개월 이상), 일상생활 지장 정도, 다른 정신 질환 배제 등을 종합적으로 평가해 내립니다. 이러한 증상이 지속된다면 정신건강의학과 전문의 진료를 통해 정확한 평가와 적절한 치료를 받으시기 바랍니다.', 897, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '건강염려증', '건강염려증', 'TREATMENT', '건강염려증 환자가 신체적 불편과 함께 과도한 심리적 스트레스를 받을 때 심계항진, 호흡 곤란, 발한, 손떨림, 소화 장애, 두통 등 다양한 신체화 증상이 나타날 수 있습니다. 또한 반복적으로 병원을 찾거나 인터넷으로 증상을 검색하는 행동이 증가하고, 불안과 우울이 악화되는 악순환이 생길 수 있습니다. 인지행동치료와 약물치료를 통해 불안의 근본 원인을 치료하는 것이 중요합니다.', 898, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '경추 추간판 탈출증', '경추추간판탈출증', 'CAUSE', '잘못된 자세(장시간 고개를 숙이거나 앞으로 내미는 자세, 구부정한 자세)는 경추에 과도한 하중을 주어 추간판 탈출증의 발생 위험을 높입니다. 특히 스마트폰, 컴퓨터 장시간 사용 시 목을 앞으로 내미는 자세는 경추 추간판에 가해지는 압력을 크게 증가시킵니다. 또한 노화로 인한 추간판 퇴행, 외상, 과도한 신체 활동도 원인이 될 수 있으므로, 증상이 있으면 정형외과 또는 신경외과 전문의 진료를 받으시기 바랍니다.', 899, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '경추 추간판 탈출증', '경추추간판탈출증', 'DEFINITION', '경추 추간판 탈출증은 목뼈(경추) 사이의 디스크(추간판)가 제자리에서 이탈하거나 파열되어 주변 신경을 압박하는 질환입니다. 목과 어깨의 통증, 팔과 손의 저림·통증·무력감, 심한 경우 척수 압박으로 인한 보행 장애까지 나타날 수 있습니다. 진단은 신경학적 검사와 MRI(자기공명영상) 검사를 통해 이루어지며, 정형외과 또는 신경외과 전문의 진료가 필요합니다.', 900, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '경추 추간판 탈출증', '경추추간판탈출증', 'SYMPTOM', '경추 추간판 탈출증의 주요 증상으로는 목과 어깨 통증, 팔과 손의 저림·방사통·근력 약화 외에도 두통, 뒷목 뻐근함, 손가락 감각 이상이 나타날 수 있습니다. 심한 경우 척수를 압박하여 보행 불안정, 하지 근력 약화, 손발 무기력증, 방광·장 기능 이상(척수증)이 생길 수 있습니다. 이러한 증상이 있으면 정형외과 또는 신경외과 전문의 진료를 받으시기 바랍니다.', 901, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '경추 추간판 탈출증', '경추추간판탈출증', 'DIAGNOSIS', '경추 추간판 탈출증의 자가 진단 방법으로는 스펄링 검사(목을 아픈 쪽으로 기울이고 위에서 압박 시 팔 통증 악화 여부 확인)가 있으나, 정확한 진단은 전문의 진찰과 MRI 검사를 통해서만 가능합니다. 목·어깨 결림이 팔 저림이나 방사통을 동반한다면 경추 추간판 탈출증 가능성이 높으므로 자가 진단에만 의존하지 말고 신경외과 또는 정형외과 전문의 진료를 받으시기 바랍니다.', 902, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '경추 추간판 탈출증', '경추추간판탈출증', 'TREATMENT', '경추 추간판 탈출증의 치료는 증상 경중에 따라 달라집니다. 먼저 보존적 치료(안정, 소염진통제, 근이완제, 물리치료, 경추 견인 치료)를 시행하며, 효과가 없으면 경막외 스테로이드 주사를 고려합니다. 증상이 심하거나 신경학적 결손(근력 저하, 보행 장애 등)이 있는 경우에는 수술적 치료(전방 경추 디스크 절제 및 유합술 등)를 시행하며, 정형외과 또는 신경외과 전문의 상담을 통해 치료 방법을 결정합니다.', 903, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '공황 장애', '공황장애', 'CHECKUP', '엘리베이터 탑승 시 가슴 답답함이 반복적으로 나타난다면 폐소공포증이나 공황 장애의 가능성이 있습니다. 공황 장애 및 불안 장애 진단은 정신건강의학과에서 받을 수 있으며, 먼저 심장 질환 등 신체적 원인을 배제하기 위해 내과나 심장내과를 방문할 수도 있습니다. 증상이 반복된다면 정신건강의학과 전문의 진료를 통해 정확한 진단과 치료를 받으시기 바랍니다.', 904, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '공황 장애', '공황장애', 'DIET_LIFE', '공황 장애의 불안과 공포 완화를 위해 카페인, 알코올, 흡연을 줄이고 규칙적인 수면과 식사를 유지하는 것이 도움이 됩니다. 규칙적인 유산소 운동, 복식 호흡 연습, 마음챙김 명상, 점진적 근육 이완법 등의 이완 기법도 효과적입니다. 이러한 생활 습관 개선과 함께 정신건강의학과 전문의 상담을 통해 인지행동치료 및 필요 시 약물치료를 병행하시기 바랍니다.', 905, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '공황 장애', '공황장애', 'MEDICATION', '공황 장애의 불안 증상 완화에는 SSRI(선택적 세로토닌 재흡수 억제제, 예: 에스시탈로프람, 서트랄린)나 SNRI가 1차 약물로 사용됩니다. 벤조디아제핀계 항불안제는 급성 공황 발작 시 단기간 사용하지만 의존성 위험 때문에 장기 사용은 권장되지 않습니다. 약물 치료는 인지행동치료와 병행 시 효과가 높으므로, 반드시 정신건강의학과 전문의 처방 하에 사용하시기 바랍니다.', 906, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '공황 장애', '공황장애', 'PREVENTION', '공황 장애 예방과 불안 관리에 효과적인 명상으로는 마음챙김 명상(MBSR)이 가장 근거가 많습니다. 호흡에 집중하는 복식 호흡 명상, 바디스캔 명상, 점진적 근육 이완 명상이 불안 감소에 도움이 됩니다. 처음에는 하루 5~10분씩 시작해 점차 늘려가며, 명상 앱이나 전문 프로그램을 활용하면 더 체계적으로 진행할 수 있습니다.', 907, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '공황 장애', '공황장애', 'CAUSE', '공황 장애는 특별한 위험한 상황이 없어도 갑자기 극심한 공포와 신체 증상이 나타나는 것이 특징이나, 시험·면접·수술 같은 스트레스 상황이 공황 발작을 유발하거나 악화시킬 수 있습니다. 관련 요인으로는 세로토닌·노르에피네프린 등 신경전달물질의 불균형, 편도체 과활성화, 과거 외상 경험, 유전적 소인, 만성 스트레스 등이 있습니다. 정확한 원인 파악과 치료를 위해 정신건강의학과 전문의 상담을 권고합니다.', 908, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '공황 장애', '공황장애', 'DEFINITION', '공황 장애는 예고 없이 발생하는 반복적인 공황 발작(심계항진, 흉통, 호흡 곤란, 발한, 현기증, 죽을 것 같은 공포감 등)을 특징으로 하는 불안 장애입니다. 불규칙한 심장 박동(심계항진)은 공황 발작의 대표적인 신체 증상이며, 밀폐된 공간(터널, 엘리베이터)에 대한 공포를 함께 경험할 수 있습니다. 이러한 증상이 반복된다면 정신건강의학과 전문의에게 진단을 받으시기 바랍니다.', 909, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '공황 장애', '공황장애', 'SYMPTOM', '가슴의 열감, 답답함, 날숨 시 뜨거운 느낌, 불규칙한 심박수 증가는 공황 발작의 전형적인 신체 증상에 해당할 수 있습니다. 공황 발작 시 교감신경계가 과활성화되어 심박수 상승, 흉부 불편감, 열감, 호흡 곤란 등이 나타납니다. 그러나 이러한 증상은 심장 질환, 갑상선 항진증 등 신체 질환과 구별이 필요하므로 내과 및 정신건강의학과 전문의 진료를 받으시기 바랍니다.', 910, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '공황 장애', '공황장애', 'DIAGNOSIS', '공황 장애 치료는 크게 인지행동치료(CBT)와 약물 치료(SSRI, SNRI)로 나뉩니다. 인지행동치료는 공황에 대한 잘못된 인지를 교정하고 회피 행동을 줄이는 데 효과적이며, 약물은 발작 빈도와 예기 불안을 감소시킵니다. 치료 방법은 증상의 중증도, 환자의 선호도, 동반 질환 등을 고려해 정신건강의학과 전문의가 결정하며, 두 방법의 병용이 가장 효과적입니다.', 911, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '공황 장애', '공황장애', 'TREATMENT', '공황 장애의 인지행동치료(CBT)만으로 치료하는 경우 치료 기간은 개인차가 있으나 일반적으로 12~20회기(약 3~6개월)의 구조화된 치료 과정이 권장됩니다. 그러나 증상 개선 속도, 동반 질환, 환자의 참여도에 따라 더 길어질 수 있습니다. 정신건강의학과 전문의와 상담해 약물 병용 여부를 포함한 개인별 치료 계획을 세우시기 바랍니다.', 912, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '금단 현상', '금단현상', 'CAUSE', '금연 시 금단 현상은 니코틴에 신체적으로 의존했던 뇌가 니코틴 공급이 끊기면서 발생합니다. 니코틴은 도파민, 노르에피네프린 등 신경전달물질 분비를 촉진하는데, 금연 후 이 작용이 없어지면 강한 흡연 욕구, 불안, 집중력 저하, 과민성, 두통, 불면증, 체중 증가 등의 금단 증상이 나타납니다. 금단 증상은 보통 금연 후 2~3일이 가장 심하고 2~4주 내에 완화됩니다.', 913, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '금단 현상', '금단현상', 'DEFINITION', '금단 현상은 특정 물질에 의존하던 신체가 해당 물질이 갑자기 중단될 때 나타나는 신체적·정신적 증상군입니다. 담배를 끊은 후의 금단 증상으로는 강렬한 흡연 욕구, 불안감, 과민성, 집중력 저하, 두통, 불면증, 식욕 증가, 피로감, 기침 증가 등이 있을 수 있습니다. 이러한 증상은 일시적이며, 니코틴 대체 요법(패치, 껌)이나 금연 보조제를 통해 증상을 완화할 수 있습니다.', 914, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '금단 현상', '금단현상', 'SYMPTOM', '금연 초기에는 일반적으로 심박수가 증가하는 경향이 있으나, 심박수가 느려지는 경우는 드물며 이 경우 다른 원인(미주신경 반응, 전해질 이상 등)을 고려해야 합니다. 금연 후 수일~수주 내에 심박수가 정상화되고 혈압이 낮아지는 등 심혈관계 개선 효과가 나타납니다. 금연 중 심박수 이상이 느껴진다면 내과 전문의에게 진료를 받는 것이 안전합니다.', 915, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '금단 현상', '금단현상', 'DIAGNOSIS', '금단 현상으로 인한 손떨림, 집중력 저하 등의 증상 진단을 위해서는 먼저 어떤 물질(알코올, 담배, 약물 등)의 금단인지 확인이 필요합니다. 알코올 금단의 경우 내과 또는 정신건강의학과를 방문해 금단 증상 평가와 적절한 치료(필요 시 약물 지원)를 받아야 합니다. 금단 증상이 심각하다면 즉시 의료 기관을 방문하시기 바랍니다.', 916, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '금단 현상', '금단현상', 'TREATMENT', '급성 호흡기 증후군(ARDS) 환자의 입원 치료는 중환자실에서 이루어지며, 기계호흡, 지속적인 활력징후 모니터링, 흡인 예방 등 전문 의료진의 24시간 관리가 필요합니다. 보호자나 간병인은 환자의 심리적 안정과 일부 기본 케어를 도울 수 있으나, 의료적 처치는 의료진이 담당합니다. 중환자실 방문 정책은 병원마다 다르므로 담당 의료진에게 구체적인 면회·간병 지침을 확인하시기 바랍니다.', 917, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '기면증', '기면증', 'CHECKUP', '기면증 검진을 위해서는 수면의학 전문의(신경과 또는 정신건강의학과)를 방문하는 것이 적합합니다. 진단 검사로는 수면다원검사(polysomnography)와 다중수면잠복기검사(MSLT)가 표준 검사입니다. 몽유병(수면보행증)은 수면 중 각성 장애로 기면증과는 다른 질환이며, 두 질환 모두 수면전문 클리닉 또는 신경과에서 정확한 감별 진단을 받을 수 있습니다.', 918, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '기면증', '기면증', 'MEDICATION', '기면증 치료에 사용되는 주요 약물과 그 부작용으로는 모다피닐(두통, 구역, 불면증), 메틸페니데이트(식욕 저하, 심박수 증가, 불면증), 암페타민류(의존성, 심혈관 부작용), 옥시베이트나트륨(구역, 두통, 야뇨증, 수면 중 보행)이 있습니다. 항탈력발작 약물(벤라팍신, 클로미프라민)은 구강 건조, 변비 등의 부작용이 있을 수 있습니다. 부작용은 개인차가 있으므로 반드시 신경과 전문의와 상담하며 복용하시기 바랍니다.', 919, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '기면증', '기면증', 'CAUSE', '기면증의 주요 원인은 뇌에서 각성을 유지하는 신경전달물질인 하이포크레틴(오렉신)을 생성하는 신경세포가 파괴되어 발생하는 것으로 알려져 있습니다. 자가면역 반응, 유전적 소인(HLA-DQB1*06:02 양성), 뇌 손상, 수면 패턴 이상 등이 기면증 발생과 관련이 있습니다. 불충분한 수면 위생과 생활 습관도 과도한 주간 졸음을 악화시킬 수 있으나, 기면증은 반드시 신경과 전문의를 통해 진단받아야 합니다.', 920, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '기면증', '기면증', 'DEFINITION', '기면증은 충분히 잤음에도 불구하고 낮 시간에 갑작스럽고 억제할 수 없는 졸음이 반복적으로 나타나는 수면 장애입니다. 감정 자극 시 갑자기 근육 힘이 빠지는 탈력발작(카탈렙시), 수면 마비, 입면 환각 등이 동반될 수 있습니다. 밤 수면은 비교적 잘 이루지만 수면이 여러 번 분절되는 특징이 있으며, 정확한 진단을 위해 신경과 전문의와 수면다원검사가 필요합니다.', 921, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '기면증', '기면증', 'SYMPTOM', '공부 중 졸림과 집중력 저하만으로 기면증을 확정할 수는 없으나, 충분한 수면 후에도 주간 졸음이 심하고 통제가 안 된다면 기면증을 의심할 수 있습니다. 진단을 위해 수면다원검사(polysomnography)와 다중수면잠복기검사(MSLT)가 시행되며, 평균 수면 잠복 시간 8분 미만이고 2회 이상의 REM 수면이 나타나면 기면증으로 진단합니다. 신경과 또는 수면클리닉에서 전문의 진료를 받으시기 바랍니다.', 922, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '기면증', '기면증', 'DIAGNOSIS', '12시간 이상 자도 지속적인 피로감이 있는 경우 기면증뿐 아니라 수면무호흡증, 갑상선 기능 저하증, 우울증, 빈혈 등 다양한 원인을 고려해야 합니다. 기면증 전문 진료는 신경과(수면장애 전문의) 또는 정신건강의학과를 방문하시면 되며, 대학병원의 수면클리닉에서 보다 전문적인 평가를 받을 수 있습니다. 가까운 신경과 또는 내과에서 초기 평가 후 전문 기관으로 의뢰받는 방법도 있습니다.', 923, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '기면증', '기면증', 'TREATMENT', '기면증 약물 치료의 부작용은 약물 종류에 따라 다릅니다. 모다피닐은 두통, 구역이 있으나 비교적 부작용이 적고, 메틸페니데이트는 심박수 증가, 혈압 상승, 불면증이 나타날 수 있습니다. 부작용이 걱정된다면 신경과 전문의와 상담해 모다피닐처럼 상대적으로 부작용이 적은 약물부터 시작하고, 수면 위생 개선(규칙적인 낮잠 등)을 병행하시기 바랍니다.', 924, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '기억상실증', '기억상실증', 'MEDICATION', '뇌 건강 유지와 기억력 보호를 위해서는 규칙적인 유산소 운동, 균형 잡힌 식사(오메가-3 지방산, 항산화 식품 풍부), 충분한 수면, 금연, 절주가 중요합니다. 인지 활동(독서, 퍼즐, 새로운 학습), 사회적 관계 유지, 혈압·혈당·콜레스테롤 관리도 뇌 건강에 도움이 됩니다. 기억상실증 예방을 위한 특정 약물은 없으며, 뇌혈관 위험 인자 관리를 위해 내과 또는 신경과 전문의 상담을 권고합니다.', 925, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '기억상실증', '기억상실증', 'CAUSE', '특별한 뇌 손상 없이 특정 시기의 기억이 잘 나지 않는 경우 해리성 기억상실, 극심한 스트레스나 심리적 외상으로 인한 심인성 기억 장애, 또는 일반적인 노화에 따른 기억력 저하 등을 고려할 수 있습니다. 만성 수면 부족, 우울증, 불안 장애도 기억력에 영향을 줍니다. 증상이 일상생활에 지장을 줄 정도라면 신경과 또는 정신건강의학과 전문의 진료를 받으시기 바랍니다.', 926, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '기억상실증', '기억상실증', 'DEFINITION', '기억상실증은 뇌 손상, 심리적 충격, 알코올 등으로 인해 새로운 기억 형성이나 과거 기억 회상이 불가능해지는 상태입니다. 환자는 일상생활, 직업, 대인관계에서 큰 어려움을 겪으며, 가족 등 주변인도 돌봄 부담과 의사소통 어려움을 경험할 수 있습니다. 두부 외상 후 기억 장애가 있다면 즉시 신경과 또는 응급 신경외과 전문의 진료를 받아야 합니다.', 927, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '기억상실증', '기억상실증', 'SYMPTOM', '기억상실증의 진행은 원인에 따라 다릅니다. 뇌손상으로 인한 기억상실은 시간이 지남에 따라 일부 회복되는 경우가 있으나, 알츠하이머 등 퇴행성 원인이라면 점진적으로 악화됩니다. 새로운 기억 형성 불가(전향성 기억상실)가 심해지거나, 방향감각 상실, 언어 장애, 일상 활동 수행 불능이 동반된다면 신경과 전문의를 방문해 뇌 영상 검사와 신경심리 검사를 받으시기 바랍니다.', 928, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '기억상실증', '기억상실증', 'DIAGNOSIS', '교통사고 후 이전 기억을 못하는 역행성 기억상실 진단을 위해서는 뇌 CT 또는 MRI로 뇌 구조적 손상을 확인하고, 신경심리 검사로 기억력의 종류와 범위를 평가합니다. 신경과 전문의가 임상 평가와 함께 기억 손실의 양상(역행성/전향성), 범위, 지속 기간 등을 종합적으로 분석하여 진단합니다. 사고 후 기억 장애가 있다면 즉시 신경과 또는 응급 신경외과 진료를 받으시기 바랍니다.', 929, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '기억상실증', '기억상실증', 'TREATMENT', '기억상실증 치료는 원인에 따라 다르며, 신체적 원인(뇌 손상, 뇌졸중)인 경우 원인 치료와 함께 인지 재활 치료가 중요합니다. 외상 후 스트레스 장애(PTSD) 등 심리적 요인에 의한 해리성 기억상실에는 인지행동치료, 안구운동 민감소실 및 재처리(EMDR) 요법, 정신치료가 사용됩니다. 치료는 신경과·정신건강의학과 전문의 팀이 협력해 개인별로 계획하며, 가족의 지지와 지속적인 재활이 중요합니다.', 930, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌경색', '뇌경색', 'DIET_LIFE', '흡연은 혈관 내피를 손상시키고 혈전 형성을 촉진해 뇌경색의 위험을 크게 높이므로, 금연이 가장 효과적인 예방 조치입니다. 금연을 위해 니코틴 대체 요법(패치, 껌), 금연 보조 약물(바레니클린, 부프로피온), 금연 클리닉 참여가 도움이 됩니다. 금연 상담은 가까운 보건소 금연 클리닉이나 내과 전문의를 통해 받을 수 있습니다.', 931, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌경색', '뇌경색', 'MEDICATION', '뇌경색으로 인한 언어 장애(실어증)는 손상된 뇌 부위와 범위에 따라 회복 기간이 크게 다릅니다. 약물(아스피린, 항응고제 등)은 재발 예방에 사용되며 언어 능력 직접 회복 목적이 아니므로, 언어 치료사에 의한 언어 재활 치료가 핵심입니다. 언어 장애는 수개월에서 수년에 걸쳐 지속적으로 개선될 수 있으므로, 신경과 전문의 진료와 함께 언어 치료를 꾸준히 받으시기 바랍니다.', 932, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌경색', '뇌경색', 'PREVENTION', '고지혈증(이상지질혈증)은 혈관 내에 지질이 쌓여 동맥경화증을 유발하고, 이로 인해 뇌혈관이 좁아지거나 막혀 뇌경색 위험을 높입니다. LDL 콜레스테롤 수치를 적정 수준으로 관리하면 동맥경화 진행을 늦추고 뇌경색 위험을 유의미하게 줄일 수 있습니다. 스타틴 계열 약물이 뇌경색 1·2차 예방에 효과적이므로, 내과 또는 신경과 전문의와 상담해 지질 관리 계획을 세우시기 바랍니다.', 933, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌경색', '뇌경색', 'CAUSE', '뇌경색은 주로 두 가지 기전으로 발생합니다. 첫째, 뇌혈관 자체에서 동맥경화로 혈관이 좁아지거나 혈전이 형성되어 막히는 혈전성 뇌경색, 둘째, 심장(심방세동 등)이나 대동맥에서 혈전이 떨어져 나와 뇌혈관을 막는 색전성 뇌경색이 있습니다. 고혈압, 당뇨, 고지혈증, 흡연이 혈관 손상과 혈전 형성을 촉진하는 주요 위험 인자입니다.', 934, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌경색', '뇌경색', 'REHAB', '뇌경색 재활은 운동 재활(물리치료, 작업치료), 언어 재활(언어치료), 인지 재활, 심리 지원으로 구성됩니다. 재활 치료는 뇌의 신경 가소성을 이용해 손상된 기능을 최대한 회복하는 것이 목표이며, 발병 후 72시간 내 조기 재활 시작이 효과적입니다. 재활 목표는 환자의 손상 정도에 따라 개별화되며, 신경과·재활의학과 전문의 팀이 환자 상태에 맞는 포괄적 재활 프로그램을 설계합니다.', 935, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌경색', '뇌경색', 'DEFINITION', '뇌졸중은 뇌혈관 이상으로 뇌 기능이 갑자기 손상되는 질환의 총칭으로, 뇌경색(허혈성, 80%)과 뇌출혈(출혈성, 20%)로 나뉩니다. 뇌경색은 혈관이 막혀 뇌 조직이 괴사하는 것이고, 뇌출혈은 혈관이 터져 혈액이 뇌 내로 흘러들어가는 것입니다. 두 질환은 치료 방향이 다르므로(뇌경색은 혈전 용해·항응고, 뇌출혈은 지혈·수술 등), 빠른 영상 진단으로 감별이 매우 중요합니다.', 936, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌경색', '뇌경색', 'SYMPTOM', '오른쪽 한 쪽만 힘이 빠지고 감각이 이상한 증상은 뇌경색의 전조 증상(일과성 허혈 발작) 또는 실제 뇌경색의 증상일 수 있습니다. 뇌경색은 뇌의 반대쪽(좌뇌)에 이상이 생기면 오른쪽 편마비·감각 이상으로 나타납니다. 이러한 증상이 나타나면 즉각적으로 119를 통해 응급실을 방문해야 하며, 4.5시간 이내의 치료가 예후에 결정적입니다.', 937, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌경색', '뇌경색', 'DIAGNOSIS', '뇌경색 진단을 위해 뇌 CT(출혈과 경색 초기 감별), 뇌 MRI(뇌경색 범위와 위치 확인), 자기공명혈관조영술(MRA), 경동맥 초음파, 심장 초음파, 심전도, 혈액 검사(혈구, 응고 검사, 지질, 혈당)가 시행됩니다. 가족 중 뇌경색 환자가 있거나 고혈압·당뇨 등 위험 인자가 있다면 정기적으로 신경과 전문의 검진을 받는 것이 좋습니다.', 938, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌경색', '뇌경색', 'TREATMENT', '뇌경색 증상 발생 후 4.5시간 이내에 종합병원을 방문하면 tPA(조직플라스미노겐 활성제) 정맥 혈전 용해술을 받을 수 있어 혈관을 막은 혈전을 녹여 뇌 손상을 최소화할 수 있습니다. 발병 후 6~24시간 이내에는 뇌혈관 조영술 및 동맥 내 혈전 제거술(기계적 혈전 제거술)이 가능한 경우도 있습니다. 뇌경색은 시간이 생명이므로, 증상 발생 즉시 119를 통해 뇌졸중 센터를 갖춘 병원으로 이송이 필요합니다.', 939, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌동맥류', '뇌동맥류', 'DIET_LIFE', '뇌동맥류 예방을 위해 고혈압 관리(저염식, 고혈압 약 복용), 금연, 절주, 규칙적인 운동이 중요합니다. 과도한 카페인 섭취를 피하고 스트레스를 줄이는 것도 혈압 관리에 도움이 됩니다. 편도결석이나 귀 염증은 뇌동맥류와 직접적인 관련은 없지만, 이명 등의 증상이 있다면 이비인후과 전문의 진료를 받고, 두통이나 뇌혈관 관련 증상은 신경과 전문의에게 상담하시기 바랍니다.', 940, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌동맥류', '뇌동맥류', 'MEDICATION', '뇌동맥류 치료에는 약물 치료(혈압 조절, 두통 완화)와 함께 수술적 치료가 근본 치료입니다. 수술적 방법으로는 개두술을 통한 동맥류 결찰술(클리핑)과 혈관 내 치료(코일색전술, 스텐트 보조 코일색전술)가 있습니다. 혈관 벽 강화 약물이나 혈전 예방 약물만으로는 파열 위험을 충분히 낮추기 어려우므로, 신경외과 또는 중재적 신경방사선과 전문의와 치료 계획을 논의해야 합니다.', 941, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌동맥류', '뇌동맥류', 'PREVENTION', '뇌동맥류 가족력이 있거나 다낭성 신질환, 결합조직 질환(마판 증후군 등), 고혈압, 흡연 등의 위험 인자가 있다면 뇌혈관 MRA(자기공명혈관조영술) 검사를 통한 선별 검사를 받는 것이 권장됩니다. 예방을 위해 혈압을 정상 수준으로 관리하고 금연, 절주를 실천하는 것이 중요합니다. 1촌 이상에서 뇌동맥류 가족력이 있다면 신경과 또는 신경외과 전문의와 검진 시기를 상담하시기 바랍니다.', 942, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌동맥류', '뇌동맥류', 'CAUSE', '명상은 교감신경계 활성을 줄이고 부교감신경계를 활성화해 심박수와 혈압을 낮추는 데 도움이 됩니다. 규칙적인 마음챙김 명상(MBSR)은 스트레스 호르몬(코르티솔)을 감소시키고 혈압 조절에 긍정적 효과가 있습니다. 다만 명상만으로 고혈압을 완전히 치료할 수는 없으므로, 항고혈압 약물 및 생활 습관 개선(저염식, 규칙적 운동)과 병행하고 담당 내과 전문의 지도하에 관리하시기 바랍니다.', 943, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌동맥류', '뇌동맥류', 'DEFINITION', '뇌동맥류는 뇌혈관 벽의 일부가 풍선처럼 부풀어 오른 상태로, 파열 시 지주막하 출혈이 발생해 생명을 위협할 수 있습니다. 뇌동맥류 환자는 격렬한 운동이나 갑작스러운 힘을 쓰는 행위(무거운 물건 들기, 고강도 웨이트 트레이닝 등)를 피하는 것이 좋습니다. 가벼운 유산소 운동(걷기, 수영)은 가능하나, 운동 종류와 강도는 반드시 신경외과 전문의와 상담 후 결정하시기 바랍니다.', 944, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌동맥류', '뇌동맥류', 'SYMPTOM', '편두통과 반복적인 어지러움은 다양한 원인으로 나타날 수 있습니다. 뇌동맥류, 뇌종양, 뇌혈관 기형, 전정기관 이상(전정신경염, 양성돌발성체위성현훈), 편두통성 현훈(전정 편두통) 등을 감별해야 합니다. 특히 갑작스럽고 극심한 두통(벼락두통), 의식 변화, 시야 이상이 동반된다면 뇌동맥류 파열 가능성이 있어 즉시 응급실을 방문해야 합니다.', 945, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌동맥류', '뇌동맥류', 'DIAGNOSIS', '갑자기 심하게 머리가 아픈 증상, 특히 평생 경험하지 못한 가장 심한 두통(벼락두통)은 뇌동맥류 파열(지주막하 출혈)의 경고 신호일 수 있습니다. 뇌동맥류 진단을 위해 뇌 CT 혈관조영술(CTA), 뇌 MRA, 디지털 감산 혈관조영술(DSA)이 시행됩니다. 갑자기 심한 두통이 발생했다면 즉시 응급실을 방문하거나, 증상이 경한 경우에는 신경과 또는 신경외과 전문의 외래 진료를 받으시기 바랍니다.', 946, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌동맥류', '뇌동맥류', 'TREATMENT', '뇌동맥류는 크기, 위치, 모양, 성장 속도, 환자의 연령과 전신 상태에 따라 치료 여부를 결정합니다. 증상이 없는 소형 동맥류(<5~7mm)의 경우 경과 관찰을 선택하기도 하나, 일정 크기 이상이거나 위치가 위험한 경우 예방적 수술(클리핑 또는 코일색전술)이 권장됩니다. 치료 방침은 개인별 파열 위험도를 신경외과 전문의가 종합적으로 판단해 결정합니다.', 947, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌사', '뇌사', 'CAUSE', '뇌사의 가장 흔한 원인은 중증 두부 외상(교통사고, 낙상), 뇌출혈(지주막하 출혈, 뇌내출혈), 저산소성 뇌손상(심정지 후), 뇌경색, 중증 뇌염, 대사성 뇌병증 등입니다. 이러한 원인들이 뇌간을 포함한 전뇌의 기능을 비가역적으로 소실시켜 뇌사 상태에 이르게 합니다. 뇌사는 의학적으로 매우 엄격한 기준으로 판정되며, 반드시 전문 의료진에 의해 진단됩니다.', 948, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌사', '뇌사', 'DEFINITION', '뇌사는 뇌간을 포함한 전뇌의 기능이 비가역적으로 완전 소실된 상태로, 자발 호흡과 뇌간 반사가 없으며 인공호흡기 없이는 생명 유지가 불가능합니다. 교통사고, 뇌출혈, 저산소증, 중증 감염 등 뇌에 심각한 손상을 주는 모든 상황에서 발생할 수 있습니다. 뇌사는 의학적·법적으로 사망으로 간주되며, 우리나라에서는 장기이식법에 따른 엄격한 판정 기준을 따릅니다.', 949, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌사', '뇌사', 'SYMPTOM', '뇌사 자체는 비가역적 상태이므로 뇌사 판정 이후에는 회복을 목적으로 한 치료보다 장기 기증 여부 결정과 가족 지지가 주요 과제가 됩니다. 뇌사 의심 증상(혼수, 자발 호흡 없음, 뇌간 반사 소실)이 나타나면 즉시 119를 통해 응급실로 이송해야 합니다. 뇌사 판정은 반드시 전문 의료진에 의해 엄격한 기준(무호흡 검사, 뇌간 반사 검사 등 2회 이상)으로 이루어지며, 가족은 의료진과 긴밀히 소통하시기 바랍니다.', 950, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌사', '뇌사', 'DIAGNOSIS', '뇌사 진단은 법적으로 규정된 엄격한 절차에 따라 이루어집니다. 먼저 자발 호흡 완전 소실, 뇌간 반사 소실 등 임상적 기준을 충족해야 하며, 전문의 2인 이상이 6시간 간격으로 두 차례 검사를 시행합니다. 뇌파 검사(EEG)에서 평탄 뇌파가 확인되어야 하며, 담당 신경과 또는 신경외과 전문의와 자세히 상담하시기 바랍니다.', 951, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌성 마비', '뇌성마비', 'PREVENTION', '뇌성 마비는 출생 전후의 뇌 손상에 의해 발생하는 것으로, 개인의 운동 습관으로 예방하기는 어렵습니다. 뇌성 마비 환자의 경우 물리치료사의 지도 아래 근력 강화 운동, 수중 치료, 스트레칭 등을 통해 기능을 유지하고 근육 경직을 완화하는 것이 도움이 됩니다. 운동 종류와 강도는 환자 상태에 따라 달라지므로 재활의학과 전문의 상담을 권장합니다.', 952, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌성 마비', '뇌성마비', 'CAUSE', '뇌성 마비에서 운동 능력 저하와 언어 능력 저하는 같은 뇌 손상에서 비롯된 병행 결과입니다. 구어 발화에는 입, 혀, 성대 등 구음 근육의 정교한 협응이 필요한데, 운동 조절 장애가 이 근육들에도 영향을 미쳐 조음 장애, 발성 장애로 나타납니다. 즉 두 기능 저하는 독립된 원인이 아니라 동일한 운동 신경계 손상이 각각 사지와 구음 기관에 나타난 것입니다.', 953, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌성 마비', '뇌성마비', 'REHAB', '언어 및 의사소통 재활 프로그램은 언어치료사가 구음 근육 강화, 호흡 훈련, 대체 의사소통 기기(AAC) 활용 등을 체계적으로 훈련시켜 의사소통 능력을 향상시킵니다. 반복적인 자극과 피드백을 통해 신경 가소성을 활용한 기능 회복을 도모하며, 어휘·문장 이해력 향상에도 기여합니다. 개인별 손상 양상이 다르므로 전문 언어치료사의 평가를 바탕으로 맞춤형 프로그램을 진행하는 것이 중요합니다.', 954, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌성 마비', '뇌성마비', 'DEFINITION', '뇌성 마비는 근육 경직(경직형), 불수의 운동(불수의 운동형), 균형 장애(실조형) 등의 운동 장애가 나타나며, 유형에 따라 증상이 다릅니다. 언어 장애는 구음 근육의 조절 이상으로 발음이 불명확하거나 발성이 어려운 형태로 나타납니다. 이 외에도 지적 장애, 시각·청각 장애, 간질 등이 동반될 수 있으며, 전문의 평가를 통한 조기 재활이 중요합니다.', 955, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌성 마비', '뇌성마비', 'SYMPTOM', '뇌성 마비의 비진행성 뇌 손상은 손상 자체는 악화되지 않지만, 성장하면서 근육 경직·구축, 관절 변형, 이상 자세 등의 이차적 합병증이 나타날 수 있습니다. 운동 발달 지연, 걷기 이상, 손 기능 저하, 언어 및 연하 장애 등이 흔하며, 뇌전증 발작이나 지적 장애가 동반되기도 합니다. 증상 범위와 정도는 손상 부위와 크기에 따라 매우 다양하므로 재활의학과 전문의의 지속적인 추적 관리가 필요합니다.', 956, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌성 마비', '뇌성마비', 'DIAGNOSIS', 'CT에서 오래된 뇌 손상 흔적이 발견되었을 때 이것이 뇌성 마비 후유증인지 여부는 영상 소견만으로는 판단하기 어렵습니다. 경미한 뇌성 마비의 경우 어린 시절 진단이 누락되기도 하며, 현재 나타나는 기능적 제한과 영상 소견을 종합해 판단해야 합니다. 정확한 평가를 위해 신경과 또는 재활의학과 전문의의 진료를 받아보시길 권장합니다.', 957, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌성 마비', '뇌성마비', 'TREATMENT', '뇌성 마비 치료는 재활의학과, 소아신경과, 정형외과, 언어치료, 작업치료 등이 협력하는 다학제 접근이 가장 효과적입니다. 병원 선택 시 전문 재활치료 인력과 시설, 보조기 및 보조공학 서비스 제공 여부를 확인하는 것이 중요합니다. 치료 방법은 물리치료, 보톡스 주사, 경구 근이완제, 선택적 등쪽 신경근 절제술 등 환자 상태에 따라 달라지므로 전문의와 충분히 상담하시기 바랍니다.', 958, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌염', '뇌염', 'CAUSE', '뇌염의 가장 흔한 원인은 바이러스 감염으로, 단순포진 바이러스(HSV)가 대표적입니다. 그 외 장바이러스, 일본뇌염 바이러스, 수두-대상포진 바이러스 등도 원인이 될 수 있습니다. 감염성 외에도 자가면역성 뇌염(항NMDA 수용체 항체 뇌염 등)이 점점 중요한 원인으로 인식되고 있으며, 신경과 전문의의 정밀 진단이 필요합니다.', 959, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌염', '뇌염', 'DEFINITION', '뇌염에서 발열과 통증은 항염증제(해열진통제, 스테로이드)로 조절하며, 바이러스성 뇌염의 경우 항바이러스제(아시클로버 등)를 사용합니다. 자가면역성 뇌염은 면역글로불린 정맥주사, 혈장교환술, 스테로이드 등 면역치료를 시행합니다. 뇌부종이 동반된 경우 삼투압 이뇨제를 투여하고 중환자실 집중 관리가 필요하며, 신경과 전문의의 치료 방향 결정이 중요합니다.', 960, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌염', '뇌염', 'SYMPTOM', '뇌염의 주요 증상으로는 고열, 두통, 오한, 구역·구토가 흔히 나타나며, 의식 저하, 혼란, 기억력 장애 등 인지 변화가 특징적입니다. 경련 발작, 언어 장애, 팔다리 마비, 성격 변화 등이 나타날 수 있으며, 증상이 수 시간에서 수 일에 걸쳐 급격히 진행될 수 있습니다. 이러한 증상이 나타나면 즉시 응급실을 방문하여 신속한 진단과 치료를 받아야 합니다.', 961, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌염', '뇌염', 'DIAGNOSIS', '두통, 의식 변화, 발작이 동반된 경우 신경과 또는 신경외과 전문의에게 진료를 받아야 합니다. 대학병원이나 종합병원 신경과에서 뇌 MRI, 뇌파 검사, 뇌척수액 검사 등 체계적인 진단 검사가 가능합니다. 증상이 급격히 악화되거나 의식 변화가 심한 경우 즉시 119를 이용해 응급실로 내원하시기 바랍니다.', 962, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌염', '뇌염', 'TREATMENT', '뇌염 치료에는 약물 치료 외에도 지지 요법이 중요하며, 발작 조절을 위한 항경련제 투여, 뇌압 상승 시 뇌압 조절 치료를 시행합니다. 자가면역성 뇌염의 경우 면역글로불린 정맥주사, 혈장교환술 등 면역치료를 병행합니다. 급성기 이후에는 인지, 언어, 운동 기능 회복을 위한 재활치료가 필요하며, 신경과 전문의의 장기적인 추적 관리가 중요합니다.', 963, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌전증', '뇌전증', 'CHECKUP', '뇌전증 진단을 위해 뇌파 검사(EEG)가 가장 기본적이며, 여기에 뇌 MRI 검사를 통해 구조적 이상 여부를 확인합니다. 필요에 따라 혈액 검사, 유전자 검사, 신경심리 검사, 비디오-뇌파 동시 모니터링 등을 추가로 시행할 수 있습니다. 발작의 원인과 유형을 정확히 파악해야 적합한 치료가 가능하므로 신경과 전문의의 종합적인 평가를 받으시기 바랍니다.', 964, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌전증', '뇌전증', 'DIET_LIFE', '케톤 식이요법은 약물로 조절되지 않는 뇌전증 환자에서 발작 빈도를 줄이는 데 효과적인 식이 치료법입니다. 규칙적인 수면, 과음 자제, 과도한 스트레스 피하기, 규칙적인 생활 리듬 유지도 발작 예방에 도움이 됩니다. 식이 요법이나 생활 습관 변경은 반드시 담당 신경과 전문의와 상의하여 안전하게 진행하시기 바랍니다.', 965, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌전증', '뇌전증', 'MEDICATION', '뇌전증 약물(항경련제)의 흔한 부작용으로는 졸림, 어지러움, 인지 기능 저하, 체중 변화 등이 있으며, 약물마다 특이적 부작용이 다릅니다. 발프로산은 간 독성·체중 증가, 페니토인은 잇몸 비대·말초신경병증, 카바마제핀은 저나트륨혈증·피부 발진의 위험이 있습니다. 부작용이 발생하면 임의로 복용을 중단하지 말고 반드시 신경과 전문의와 상담하여 약물 조정을 받으시기 바랍니다.', 966, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌전증', '뇌전증', 'PREVENTION', '뇌전증의 원인 중 하나인 뇌손상을 예방하려면 교통사고·낙상 등 두부 외상을 줄이기 위해 안전벨트, 헬멧 착용 등 안전 수칙을 철저히 지키는 것이 중요합니다. 뇌혈관 질환 예방을 위해 고혈압, 당뇨, 고지혈증 등 위험 인자를 관리하고, 산전 관리를 통해 신생아 뇌 손상 위험을 줄이는 것도 필요합니다. 후천적 뇌손상 예방이 뇌전증 발생 위험을 낮추는 데 기여하므로 정기적인 건강 검진과 전문의 상담을 권장합니다.', 967, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌전증', '뇌전증', 'CAUSE', '뇌전증 환자에서 운전 중 발작이 발생하면 극히 위험한 상황이 될 수 있으며, 수면 부족, 음주, 약물 복용 불이행, 강한 빛 자극 등이 발작을 유발할 수 있습니다. 국내 도로교통법상 뇌전증 환자는 일정 기간 발작이 없을 때까지 운전이 제한될 수 있습니다. 운전 여부와 안전 관리에 대해 반드시 신경과 전문의와 상담하고 법적 기준을 준수하시기 바랍니다.', 968, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌전증', '뇌전증', 'REHAB', '뇌전증으로 인한 국소 경련의 재활치료로는 작업치료를 통한 손 기능 훈련, 신경근 전기자극 치료, 협응 운동 훈련 등이 도움이 될 수 있습니다. 발작 조절이 우선이며, 항경련제로 발작을 충분히 억제한 후 재활치료의 효과가 극대화됩니다. 정확한 재활 방향은 재활의학과 전문의 및 신경과 전문의와 함께 상담하여 개인 맞춤형 프로그램을 수립하시기 바랍니다.', 969, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌전증', '뇌전증', 'DEFINITION', '뇌전증은 다른 원인 없이 반복적으로 발작이 발생할 때 진단하며, 신경과 전문의가 뇌파 검사, 뇌 MRI, 상세한 병력 청취를 통해 종합적으로 진단합니다. 발작 시 의식 소실, 근육 경련, 감각 이상 등의 증상이 반복되면 뇌전증을 의심하고 신경과 진료를 받아야 합니다. 단 한 번의 발작만으로는 뇌전증으로 확진하지 않으며, 전문의의 정확한 평가가 중요합니다.', 970, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌전증', '뇌전증', 'SYMPTOM', '갑자기 몸에 힘을 잃고 쓰러지는 증상은 뇌전증의 이완성 발작(atonic seizure) 또는 무긴장 발작의 특징적인 증상일 수 있습니다. 그러나 심장 이상, 저혈당 등 다른 원인에 의한 실신과 감별이 필요합니다. 해당 증상이 반복된다면 즉시 소아신경과 또는 신경과 전문의의 진료를 받아 뇌파 검사 등 정밀 검사를 시행하시기 바랍니다.', 971, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌전증', '뇌전증', 'DIAGNOSIS', '뇌전증은 신경과에서 진료를 받는 것이 적합하며, 신경과에서 뇌파 검사, 뇌 MRI 등 필요한 검사와 약물 치료를 담당합니다. 신경외과는 약물로 조절되지 않는 뇌전증에서 수술적 치료가 필요한 경우에 해당합니다. 따라서 처음 진단과 내과적 치료는 신경과를 먼저 방문하시고, 수술 여부는 신경과 전문의의 의뢰를 통해 결정하시기 바랍니다.', 972, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌전증', '뇌전증', 'TREATMENT', '뇌전증 환자의 운동 시 발작 위험을 최소화하기 위해 발작 유발 요인(과로, 수면 부족, 음주 등)을 피하고 규칙적인 약물 복용을 유지하는 것이 중요합니다. 수영이나 위험한 기구 운동보다는 감시 하에 가능한 안전한 운동을 선택하고, 발작 시 즉시 도움받을 수 있는 환경을 조성해야 합니다. 운동 종류와 강도에 대해 담당 신경과 전문의와 충분히 상의하시기 바랍니다.', 973, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌졸중', '뇌졸중', 'DIET_LIFE', '뇌졸중 예방을 위해 혈압, 혈당, 콜레스테롤을 철저히 관리하고, 금연·절주와 규칙적인 유산소 운동(주 150분 이상)이 중요합니다. 나트륨 섭취를 줄이고 채소·과일·등푸른 생선 중심의 균형 잡힌 식단을 유지하며, 복부 비만을 예방하는 것이 도움이 됩니다. 정기적인 건강검진과 함께 신경과 또는 심장내과 전문의의 지속적인 관리가 필요합니다.', 974, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌졸중', '뇌졸중', 'MEDICATION', '혈전 용해제(tPA)는 뇌경색 시 막힌 혈전을 녹여 혈류를 빠르게 회복시키며, 골든타임(증상 발생 후 4.5시간) 내 투여 시 신경 손상을 최소화합니다. 항혈소판제나 항응고제 등 혈관 보호 약물은 혈전 재형성을 예방하고 뇌졸중 재발 위험을 낮춥니다. 약물의 선택과 용량은 환자 상태와 뇌졸중 유형에 따라 달라지므로 반드시 신경과 전문의의 처방에 따라 복용하셔야 합니다.', 975, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌졸중', '뇌졸중', 'PREVENTION', '갑작스러운 언어 장애(말이 이상하거나 이해 불가)는 뇌졸중의 전형적인 전조 증상으로, 즉시 119에 연락하고 응급실로 이송해야 합니다. 증상이 일시적으로 회복되더라도 일과성 뇌허혈 발작(TIA)일 수 있으므로 반드시 신경과 진료를 받아야 합니다. 평소 고혈압·당뇨·부정맥 등 위험 인자를 적극 관리하고, 금연·금주와 규칙적인 운동으로 뇌졸중 예방에 힘쓰시기 바랍니다.', 976, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌졸중', '뇌졸중', 'EXERCISE', '안면 마비 완화를 위해 거울을 보며 얼굴 근육 운동(눈 감기, 이마 찡그리기, 뺨 부풀리기, 입술 오므리기 등)을 반복하는 안면 근육 재활 운동이 도움이 됩니다. 온찜질을 통해 혈액순환을 증진시키고, 전기 자극 치료나 침치료를 병행하는 것도 효과적일 수 있습니다. 마비 정도와 원인에 따라 치료 방향이 달라지므로 재활의학과 또는 신경과 전문의의 진료 후 맞춤형 치료를 받으시기 바랍니다.', 977, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌졸중', '뇌졸중', 'CAUSE', '고콜레스테롤혈증은 혈관 내벽에 플라크를 형성하여 동맥경화를 유발하고, 이로 인한 뇌혈관 협착 및 혈전 형성이 뇌졸중 위험을 높입니다. LDL 콜레스테롤을 적정 수준으로 관리하면 동맥경화 진행을 억제하고 뇌졸중 발생 위험을 유의미하게 줄일 수 있습니다. 식이 조절과 운동으로 조절되지 않는 경우 스타틴 계열 약물을 사용하며, 심뇌혈관내과 또는 신경과 전문의의 지속적인 관리가 필요합니다.', 978, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌졸중', '뇌졸중', 'REHAB', '뇌졸중 재활치료는 가능한 한 급성기부터 조기에 시작하고 지속적으로 유지하는 것이 기능 회복에 가장 효과적입니다. 일시적으로 치료를 중단하면 회복 속도가 느려질 수 있으나, 피로나 건강 악화 시 의료진과 상의하여 치료 강도를 조절하는 것은 가능합니다. 장기간 휴식은 근력 약화와 기능 퇴화를 초래할 수 있으므로 재활의학과 전문의의 지도 아래 꾸준한 재활치료를 이어가시기 바랍니다.', 979, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌졸중', '뇌졸중', 'DEFINITION', '뇌졸중은 뇌에 혈액을 공급하는 혈관이 막히거나(뇌경색) 터져(뇌출혈) 뇌세포가 손상되는 응급 질환입니다. 갑작스러운 편측 마비, 언어 장애, 안면 비대칭, 심한 두통, 어지럼증, 시야 장애 등이 주요 증상이며, 증상 발생 즉시 119를 통해 응급 처치를 받는 것이 중요합니다. 골든타임 내 치료가 예후에 결정적 영향을 미치므로 증상 발생 시 즉각적인 대처가 필요합니다.', 980, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌졸중', '뇌졸중', 'SYMPTOM', '뇌졸중의 전조 증상(갑작스러운 마비, 언어 장애, 시야 이상, 심한 두통 등)이 나타나면 즉시 119에 신고하고 응급실로 이송해야 합니다. 환자를 눕히고 머리를 약간 높여 편안한 자세를 유지하며, 음식이나 음료를 먹이지 않아야 합니다. 증상이 일시적으로 회복되더라도 반드시 신경과 응급 진료를 받아야 하며, 이동 중 경과를 지속 관찰해야 합니다.', 981, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌졸중', '뇌졸중', 'DIAGNOSIS', '난원공 개존증 진단에는 경식도 심초음파(TEE)가 가장 정확한 표준 검사로, 버블 테스트를 통해 우-좌 단락을 확인합니다. 경흉부 심초음파(TTE)도 사용되며, 경두개 도플러 초음파로 미세색전을 간접 확인할 수 있습니다. CT 혈관조영술(CTA)이나 심장 MRI를 통해 심장 구조를 자세히 평가하기도 하며, 심장내과 또는 순환기내과 전문의의 진단이 필요합니다.', 982, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌졸중', '뇌졸중', 'TREATMENT', '골든타임이 지난 뇌졸중 환자도 조기 재활치료가 기능 회복에 매우 중요합니다. 물리치료(보행·근력 훈련), 작업치료(일상생활 동작 훈련), 언어치료(실어증·연하장애 치료)를 포함한 포괄적 재활을 시행하며, 합병증 예방을 위한 간호도 중요합니다. 재발 예방을 위한 항혈소판제, 항응고제, 위험 인자 관리를 병행하면서 재활의학과 전문의의 장기적인 관리를 받으시기 바랍니다.', 983, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌출혈', '뇌출혈', 'MEDICATION', '뇌부종 치료에 사용되는 만니톨, 스테로이드 등의 약물 부작용을 줄이기 위해 신장 기능과 전해질 수치를 정기적으로 모니터링하는 것이 중요합니다. 스테로이드 사용 시 혈당 조절, 감염 예방, 골다공증 예방 등 부작용 관리가 필요합니다. 약물 용량과 사용 기간은 의료진이 환자 상태에 맞게 조절하므로, 임의로 복용을 변경하지 말고 신경과 또는 신경외과 전문의의 지시에 따라 관리받으시기 바랍니다.', 984, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌출혈', '뇌출혈', 'PREVENTION', '뇌출혈 예방을 위해 가장 중요한 것은 고혈압 관리로, 혈압을 정기적으로 측정하고 약물과 생활 습관 개선을 통해 조절해야 합니다. 금연, 절주, 규칙적인 유산소 운동, 저염식 식단, 체중 관리가 혈압 조절과 혈관 건강에 핵심적입니다. 항응고제·항혈소판제 복용 중이라면 출혈 위험을 의료진과 정기적으로 점검하고, 두부 외상 예방을 위한 안전 수칙도 철저히 지키시기 바랍니다.', 985, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌출혈', '뇌출혈', 'CAUSE', '고혈압은 뇌혈관 벽에 지속적인 압력을 가해 혈관 손상·동맥경화·혈관류를 유발하므로 뇌출혈의 가장 중요한 원인입니다. 그 외 뇌동맥류 파열, 뇌혈관 기형, 과도한 음주, 항응고제 복용, 혈액응고장애, 뇌종양 등도 뇌출혈 원인이 될 수 있습니다. 따라서 고혈압의 철저한 관리가 뇌출혈 예방의 핵심이며, 위험 인자를 가진 경우 신경과 또는 심뇌혈관내과의 정기 관리를 받으시기 바랍니다.', 986, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌출혈', '뇌출혈', 'REHAB', '뇌출혈 수술 후 통원 재활은 재활의학과가 개설된 종합병원 또는 재활 전문 병원에서 가능합니다. 지역 내 국립재활원, 대학병원 재활의학과, 재활 전문 요양병원을 검색하여 거리와 접근성을 고려해 선택하시기 바랍니다. 담당 주치의에게 통원 재활 가능한 기관으로의 의뢰서(진료의뢰서)를 요청하면 더욱 체계적으로 연계받을 수 있습니다.', 987, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌출혈', '뇌출혈', 'DEFINITION', '뇌출혈은 뇌 내 혈관이 파열되어 혈액이 뇌 조직으로 흘러드는 질환이며, 뇌경색은 혈관이 막혀 뇌 조직에 혈액 공급이 차단되는 질환으로, 두 질환 모두 뇌졸중에 해당합니다. 두 질환 모두 갑작스러운 두통, 편측 마비, 언어 장애, 의식 저하 등 유사한 증상을 보이지만, 뇌출혈은 극심한 두통이 더 두드러지는 경향이 있습니다. 손상 부위와 범위에 따라 운동·언어·인지 등 다양한 후유증이 나타날 수 있으며, 신경과 또는 신경외과 전문의의 정확한 진단이 필요합니다.', 988, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌출혈', '뇌출혈', 'SYMPTOM', '뇌출혈 후 발생한 실어증(말 어눌함)은 손상 부위와 정도에 따라 자연 회복되기도 하지만, 회복 없이 지속되거나 일부에서는 다른 유형의 언어 장애(이해 장애, 표현 장애 등)로 변할 수 있습니다. 언어 재활 치료를 꾸준히 받으면 증상 개선에 도움이 되며, 초기 집중 치료일수록 회복 가능성이 높습니다. 증상 변화가 있다면 신경과 전문의 재평가와 언어치료사의 지속적인 재활을 받으시기 바랍니다.', 989, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌출혈', '뇌출혈', 'DIAGNOSIS', '뇌출혈 후 발생하는 섬망은 급성 뇌 손상과 관련된 주요 합병증으로, 섬망 자체가 추가 뇌 손상 위험과 높은 사망률, 장기 예후 악화와 연관됩니다. 반복적인 섬망은 낙상, 자해, 치료 방해 등 위험 상황을 초래할 수 있으므로 신중한 관리가 필요합니다. 섬망이 지속되면 신경과 전문의의 재평가를 통해 원인 파악과 적절한 치료를 받으시기 바랍니다.', 990, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뇌출혈', '뇌출혈', 'TREATMENT', '뇌출혈 치료는 출혈 부위, 크기, 환자 상태에 따라 수술적 치료와 내과적 치료를 결정합니다. 수술이 필요하지 않은 경우 혈압 조절, 뇌압 감소, 지혈제 투여, 전해질·혈당 관리 등 내과적 치료를 시행합니다. 수술은 출혈량이 많거나 뇌압이 위험 수준으로 상승하거나 뇌간을 압박하는 경우에 고려되며, 신경외과 전문의의 종합적인 판단이 필요합니다.', 991, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '다발성 경화증', '다발성경화증', 'CAUSE', '다발성 경화증은 유전적 요인과 환경적 요인이 복합적으로 작용하여 발생합니다. 유전적으로 HLA 유전자 변이가 위험도를 높이는 것으로 알려져 있으며, 비타민 D 결핍, 엡스타인-바 바이러스 감염, 흡연, 위도(일조량) 등의 환경적 요인도 발병에 기여합니다. 따라서 어느 하나의 요인이 단독으로 작용하기보다 두 요인의 상호작용에 의해 발병하는 것으로 현재 이해되고 있습니다.', 992, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '다발성 경화증', '다발성경화증', 'DEFINITION', '다발성 경화증은 중추신경계(뇌와 척수)의 수초(myelin)를 면역계가 공격하여 염증과 탈수초를 일으키는 만성 자가면역 질환입니다. 주로 20~40대 젊은 여성에게 많이 발생하며, 여성이 남성보다 약 2~3배 높은 발병률을 보입니다. 증상이 재발과 완화를 반복하는 경우가 많으며, 시각 장애, 감각 이상, 운동 장애, 피로감 등 다양한 신경학적 증상이 나타납니다.', 993, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '다발성 경화증', '다발성경화증', 'SYMPTOM', '다발성 경화증에서 시신경염은 눈을 움직일 때 통증과 시야 흐림이 나타나는 형태로 발생하며, 시신경 수초 탈락으로 인해 발생합니다. 피부의 찌르는 듯한 감각(이상감각)은 척수 또는 뇌의 감각 전달 경로의 탈수초로 인해 나타나며, 전기가 흐르는 것처럼 느껴지는 레르미트 증상이 특징적입니다. 이러한 증상은 재발·완화를 반복할 수 있으며, 신경과 전문의의 MRI 및 정밀 검사를 통한 진단이 필요합니다.', 994, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '다발성 경화증', '다발성경화증', 'DIAGNOSIS', '다발성 부위의 통증과 저림 증상은 다발성 경화증 외에도 디스크 질환, 말초신경병증, 섬유근통 등 여러 원인으로 나타날 수 있습니다. 다발성 경화증을 의심할 경우 신경과 전문의의 진찰 후 뇌 및 척수 MRI, 뇌척수액 검사, 유발 전위 검사 등을 시행하여 감별 진단을 받아야 합니다. 자의적 판단보다 전문의의 체계적인 평가가 정확한 진단을 위해 반드시 필요합니다.', 995, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '다발성 경화증', '다발성경화증', 'TREATMENT', '다발성 경화증 치료에는 재발을 줄이고 진행을 억제하는 질병조절치료제(인터페론베타, 글라티라머, 나탈리주맙 등)가 핵심입니다. 급성 재발 시에는 고용량 스테로이드 정맥 투여를 통해 염증을 빠르게 억제하며, 증상 완화를 위한 대증 치료(피로, 통증, 경직 관리)도 병행합니다. 물리치료, 작업치료, 심리 지지 등 비약물적 접근도 삶의 질 향상에 중요하며, 신경과 전문의의 장기적 관리가 필요합니다.', 996, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '다발성 신경병증', '다발성신경병증', 'CAUSE', '다발성 신경병증의 주요 원인으로는 당뇨병이 가장 흔하며, 알코올 남용, 비타민 결핍(B1·B12), 신부전, 항암제 등 독성 물질이 있습니다. 자가면역 기전으로는 길랑-바레 증후군, 만성 염증성 탈수초 다발성 신경병증(CIDP), 혈관염 등이 말초신경을 손상시켜 신경병증을 유발합니다. 자가면역성 신경병증은 면역글로불린, 스테로이드, 혈장교환술 등으로 치료하며, 신경과 전문의의 정확한 원인 진단이 치료 방향 설정에 중요합니다.', 997, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '다발성 신경병증', '다발성신경병증', 'DEFINITION', '다발성 신경병증은 말초신경계(팔, 다리 등 신체 말단의 신경)에 발생하는 질환으로, 다수의 말초신경이 동시에 또는 순차적으로 손상되는 상태입니다. 주로 양쪽 사지의 원위부(손발 끝)에서 감각 이상, 근력 저하, 자율신경 기능 이상이 나타납니다. 원인이 매우 다양하므로 정확한 진단을 위해 신경과 전문의의 진찰과 근전도, 신경전도 검사 등이 필요합니다.', 998, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '다발성 신경병증', '다발성신경병증', 'SYMPTOM', '손발의 찌릿하고 저린 느낌, 화끈거림, 전기가 통하는 듯한 이상감각은 다발성 신경병증의 대표적인 주요 증상입니다. 이는 말초신경의 감각 섬유 손상으로 인해 발생하며, 주로 양쪽 발끝에서 시작해 위쪽으로 퍼지는 ''장갑-양말'' 형태의 분포를 보입니다. 증상의 강도와 범위는 원인과 진행 정도에 따라 다르므로, 신경과 전문의의 진료와 신경전도 검사를 통한 정확한 평가가 필요합니다.', 999, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '다발성 신경병증', '다발성신경병증', 'DIAGNOSIS', '알코올성 신경병증, 비타민 결핍성 신경병증 등 다발성 신경병증은 신경과에서 진단받을 수 있습니다. 신경과 외래에서 신경전도 검사, 근전도 검사, 혈액 검사(비타민 수치, 알코올 관련 지표 등)를 통해 원인을 규명합니다. 대학병원이나 종합병원 신경과를 방문하시면 체계적인 검사와 치료 계획을 받으실 수 있습니다.', 1000, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '다발성 신경병증', '다발성신경병증', 'TREATMENT', '다발성 신경병증의 치료는 원인 질환 교정이 우선이며, 당뇨 조절, 음주 중단, 비타민 보충 등이 핵심 치료입니다. 통증과 이상감각 완화를 위해 가바펜틴, 프레가발린, 삼환계 항우울제, 둘록세틴 등의 신경병증성 통증 약물이 주로 사용됩니다. 증상이 지속되거나 악화되는 경우 신경과 전문의의 진료를 통해 원인에 맞는 맞춤형 치료를 받으시기 바랍니다.', 1001, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뚜렛 증후군', '뚜렛증후군', 'MEDICATION', '뚜렛 증후군 치료에 약물은 틱 증상을 완화하는 데 효과적이며, 아리피프라졸, 할로페리돌, 클로니딘 등이 사용됩니다. 약물을 임의로 중단하거나 불규칙하게 복용하면 증상이 재악화되거나 반동 증상이 나타날 수 있으며, 일부 약물은 갑작스러운 중단 시 금단 증상이 발생할 수 있습니다. 약물 복용과 중단은 반드시 소아정신과 또는 신경과 전문의와 상의하여 결정하시기 바랍니다.', 1002, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뚜렛 증후군', '뚜렛증후군', 'CAUSE', '뚜렛 증후군은 유전적 요인이 발병에 중요한 역할을 하며, 일란성 쌍둥이 연구에서 높은 일치율이 확인되었습니다. SLITRK1 등 일부 유전자 변이가 관련된 것으로 알려져 있으며, 가족 내 발병 위험이 일반 인구보다 높습니다. 다만 유전 외에도 환경적 요인(임신 중 합병증, 감염, 스트레스 등)이 복합적으로 작용하므로, 유전만으로 발병이 결정되지는 않습니다.', 1003, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뚜렛 증후군', '뚜렛증후군', 'REHAB', '뚜렛 증후군의 어깨 근육틱 재활에는 습관 역전 훈련(HRT)이 효과적인 행동치료로 알려져 있으며, 틱 충동을 인식하고 대체 행동으로 전환하는 훈련을 합니다. 바이오피드백 치료와 이완 요법도 틱 강도 감소에 도움이 될 수 있으며, 심한 경우 근육 이완을 위한 보톡스 주사를 고려하기도 합니다. 치료 방향은 소아정신과 또는 신경과 전문의와의 상담을 통해 결정하시기 바랍니다.', 1004, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뚜렛 증후군', '뚜렛증후군', 'DEFINITION', '뚜렛 증후군은 프랑스 신경과 의사 조르주 질 드 라 뚜렛이 처음 기술한 신경발달 장애로, 다양한 운동 틱과 음성 틱이 1년 이상 지속되는 것이 특징입니다. 눈 깜빡임, 얼굴 찡그림, 어깨 들썩임 등의 운동 틱과 헛기침, 코 킁킁, 욕설 발화(음성외설증) 등의 음성 틱이 나타납니다. 도파민 신경계 이상과 유전적 요인이 병인에 관여하며, 소아·청소년기에 주로 발병하고 성인이 되면서 증상이 완화되는 경우가 많습니다.', 1005, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뚜렛 증후군', '뚜렛증후군', 'SYMPTOM', '뚜렛 증후군 환자는 스트레스와 피로가 틱 증상을 악화시키므로, 충분한 수면과 규칙적인 생활 리듬을 유지하는 것이 중요합니다. 과도한 긴장이나 흥분을 줄이고, 명상·이완 기법 등 스트레스 관리 방법을 익히면 증상 완화에 도움이 됩니다. 학교·직장 환경에서 증상에 대한 주변의 이해와 지지가 환자의 심리적 안정과 일상생활 적응에 큰 도움이 됩니다.', 1006, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뚜렛 증후군', '뚜렛증후군', 'DIAGNOSIS', '1년 이상 지속되는 눈 깜빡임 증상은 틱 장애 또는 뚜렛 증후군의 가능성이 있으며, 소아청소년 정신건강의학과(소아정신과) 전문의의 진료가 필요합니다. 소아신경과에서도 진단이 가능하며, 진단 후 증상 정도에 따라 행동치료 또는 약물 치료를 결정합니다. 조기 진단과 치료가 아이의 심리적 부담을 줄이고 사회 적응에 도움이 되므로, 지체 없이 전문의를 찾으시길 권장합니다.', 1007, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '뚜렛 증후군', '뚜렛증후군', 'TREATMENT', '뚜렛 증후군 치료에 사용되는 약물로는 도파민 차단제인 아리피프라졸, 할로페리돌, 피모자이드와 알파2 작용제인 클로니딘, 구안파신이 주로 사용됩니다. 동반된 ADHD 증상에는 아토목세틴이나 클로니딘을 사용하며, 강박 증상에는 선택적 세로토닌 재흡수 억제제(SSRI)가 도움이 됩니다. 약물 선택과 용량은 증상 유형과 동반 질환에 따라 달라지므로 소아정신과 또는 신경과 전문의의 처방에 따라 복용하시기 바랍니다.', 1008, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '레이노병', '레이노병', 'MEDICATION', '레이노병 치료에 사용되는 칼슘통로 차단제(암로디핀 등)는 두통, 안면 홍조, 발목 부종, 저혈압 등의 부작용이 나타날 수 있습니다. 포스포다이에스터라제 억제제나 프로스타글란딘 제제도 두통, 소화 장애, 혈압 저하 등의 부작용이 보고됩니다. 부작용이 발생하면 임의로 약을 중단하지 말고 류마티스내과 또는 혈관외과 전문의와 상담하여 약물 조정을 받으시기 바랍니다.', 1009, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '레이노병', '레이노병', 'CAUSE', '레이노병은 추위나 스트레스 자극에 의해 손가락·발가락 등의 말초 혈관이 과도하게 수축하여 혈류가 차단되는 혈관 연축 질환입니다. 발작의 주요 유발 요인으로는 차가운 온도 노출, 정서적 스트레스, 진동 공구 사용, 흡연 등이 있으며, 자가면역 질환이나 약물이 이차적 원인이 되기도 합니다. 교감신경계의 과민 반응과 혈관 수축 기전의 이상이 핵심 병태생리로, 증상 완화를 위해 류마티스내과 전문의의 진료를 받으시기 바랍니다.', 1010, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '레이노병', '레이노병', 'DEFINITION', '레이노병은 추위나 스트레스에 노출될 때 손가락·발가락 등 말초 부위의 혈관이 과도하게 수축하여 창백해지고, 이어서 청색증(청보라색), 충혈(빨간색)의 3색 변화가 특징입니다. 창백해지는 것은 혈관 수축으로 혈류가 줄어들기 때문이며, 이는 레이노병의 전형적인 증상입니다. 일차성(특발성)과 이차성(루푸스, 공피증 등 기저 질환 동반)으로 나뉘며, 류마티스내과 전문의의 진단과 치료가 필요합니다.', 1011, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '레이노병', '레이노병', 'SYMPTOM', '레이노병 환자들은 추위나 스트레스 시 손가락·발가락이 창백해지다가 청색으로 변하고, 이후 혈류 회복 시 빨갛게 충혈되는 3색 변화를 경험합니다. 발작 중 저린감, 통증, 감각 저하가 동반되며, 심한 경우 궤양이나 괴저가 발생할 수 있습니다. 증상이 반복되거나 악화된다면 류마티스내과 또는 혈관외과 전문의를 방문하여 정확한 진단과 치료를 받으시기 바랍니다.', 1012, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '레이노병', '레이노병', 'DIAGNOSIS', '손가락·발가락이 창백해지고 혈액 순환 장애가 반복된다면 류마티스내과 또는 혈관외과(혈관내과) 전문의에게 진료를 받는 것이 적합합니다. 이차성 레이노 현상의 경우 기저 자가면역 질환(루푸스, 공피증 등)이 동반될 수 있으므로 자가면역 항체 검사도 함께 시행하는 것이 중요합니다. 증상이 심하거나 궤양이 동반된 경우 조기에 전문의 진료를 받으시기 바랍니다.', 1013, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '레이노병', '레이노병', 'TREATMENT', '레이노병 치료의 가장 중요한 비의학적 접근은 추위와 스트레스 회피, 보온(장갑·양말 착용), 금연으로 혈관 수축 유발 요인을 줄이는 것입니다. 증상이 경미한 경우 생활 습관 교정만으로 충분한 경우도 있으나, 증상이 잦고 심한 경우 칼슘통로 차단제 등 약물 치료가 필요합니다. 두 가지 접근을 함께 활용하는 것이 가장 효과적이며, 치료 방침은 류마티스내과 전문의와 상담하시기 바랍니다.', 1014, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '망상 장애', '망상장애', 'CAUSE', '망상 장애의 원인으로는 생물학적(도파민 신경계 이상, 유전적 취약성)·심리학적·사회적 요인이 복합적으로 작용합니다. 심리학적으로는 어린 시절 트라우마, 극심한 스트레스, 사회적 고립, 낮은 자존감 등이 망상적 사고 형성에 기여할 수 있습니다. 또한 인지 왜곡, 편집적 귀인 양식 등 심리적 취약 요인이 망상의 내용과 지속에 영향을 미치며, 정신건강의학과 전문의의 종합적 평가가 필요합니다.', 1015, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '망상 장애', '망상장애', 'DEFINITION', '망상 장애는 현실과 동떨어진 고정된 믿음(망상)이 1개월 이상 지속되면서 기능 저하가 나타날 때 진단합니다. 환청이나 환시 같은 환각보다 망상이 주된 증상이며, 피해 망상, 과대 망상, 질투 망상 등 다양한 유형이 있습니다. 비정상적 믿음이 의심된다면 정신건강의학과 전문의의 면담 및 심리 평가를 통해 정확한 진단과 치료 방향을 결정받으시기 바랍니다.', 1016, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '망상 장애', '망상장애', 'SYMPTOM', '낯선 사람들이 자신을 향해 웃는다고 반복적으로 느끼고, 집에 CCTV가 설치되어 있다는 근거 없는 믿음은 피해 망상의 전형적인 증상일 수 있습니다. 이러한 증상은 망상 장애 또는 조현병의 초기 징후일 수 있으며, 조기에 정신건강의학과 전문의의 평가를 받는 것이 중요합니다. 증상이 일상생활과 대인관계에 영향을 미친다면 지체 없이 전문 진료를 권장합니다.', 1017, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '망상 장애', '망상장애', 'DIAGNOSIS', '망상 장애 진단과 치료는 정신건강의학과(정신과) 전문의에게 받는 것이 적합합니다. 대학병원 또는 종합병원 정신건강의학과, 정신건강 전문 병·의원에서 체계적인 면담, 심리 검사, 약물 치료, 심리치료를 받을 수 있습니다. 지역 정신건강복지센터를 통해 가까운 전문 의료기관을 안내받는 것도 좋은 방법입니다.', 1018, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '망상 장애', '망상장애', 'TREATMENT', '망상 장애의 주된 치료는 항정신병 약물(리스페리돈, 아리피프라졸 등)로 망상 증상을 완화하는 것입니다. 약물 치료와 함께 인지행동치료(CBT)를 병행하면 망상적 사고 패턴을 수정하고 현실 검증 능력을 향상시키는 데 효과적입니다. 치료 순응도가 낮은 경우가 많으므로 가족의 지지와 정신건강의학과 전문의의 장기적인 추적 관리가 매우 중요합니다.', 1019, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '모야모야병', '모야모야병', 'DIET_LIFE', '모야모야병 소아 환자는 과호흡을 유발하는 격렬한 운동, 울음, 뜨거운 음식 섭취 등을 피하고 충분한 수분을 섭취하는 것이 중요합니다. 탈수와 저혈압을 예방하기 위해 규칙적인 식사와 수면을 유지하고, 추운 날씨나 고온 환경 노출을 최소화하는 것이 좋습니다. 일상생활 내 주의 사항과 응급 대처 방법에 대해 담당 소아신경과 또는 신경외과 전문의와 충분히 상담하시기 바랍니다.', 1020, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '모야모야병', '모야모야병', 'MEDICATION', '모야모야병 자체를 직접 치료하는 약물은 없으며, 주로 혈소판 응집을 억제하는 아스피린이 혈전 예방 목적으로 사용됩니다. 아스피린의 부작용으로 위장 출혈, 위장 불편감, 출혈 경향 증가 등이 나타날 수 있습니다. 모야모야병의 근본 치료는 혈관 우회 수술(혈관재건술)이므로, 약물 치료만으로는 한계가 있으며 신경외과 전문의의 치료 방향 결정이 중요합니다.', 1021, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '모야모야병', '모야모야병', 'PREVENTION', '모야모야병 예방을 위해 과호흡 유발 행동 외에도 탈수 예방을 위한 충분한 수분 섭취, 저혈압 방지, 격렬한 운동 자제가 중요합니다. 뇌허혈 발작을 줄이기 위해 아스피린 등의 항혈소판제를 의사 처방 하에 복용하며, 정기적인 영상 검사로 혈관 상태를 모니터링해야 합니다. 근본적인 예방을 위해서는 혈관재건술(두개내외 혈관 문합술)을 고려할 수 있으며, 신경외과 전문의와 상담하시기 바랍니다.', 1022, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '모야모야병', '모야모야병', 'CAUSE', '모야모야병은 뇌 내 주요 동맥(내경동맥 말단부)이 점진적으로 협착되고 이를 보상하기 위한 측부 혈관들이 과도하게 발달하는 원인 불명의 혈관 질환입니다. 자가면역 반응이 혈관 내벽을 손상시켜 혈관염을 유발한다는 가설이 있으나, 정확한 발병 기전은 아직 완전히 규명되지 않았습니다. 유전적 요인(RNF213 유전자 등)도 관여하는 것으로 알려져 있으며, 지속적인 연구가 진행 중입니다.', 1023, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '모야모야병', '모야모야병', 'REHAB', '모야모야병으로 인한 운동 기능 제한 시 재활치료는 신경 손상 부위와 증상에 따라 물리치료(근력·보행 훈련), 작업치료(일상생활 동작 훈련), 언어치료 등을 포함하는 다학제 재활이 이루어집니다. 수술 후에는 뇌 혈류가 안정화된 뒤 재활의학과에서 체계적인 재활 프로그램을 시작하게 됩니다. 재활 시작 시기와 강도는 담당 신경외과 및 재활의학과 전문의가 환자 상태에 맞게 결정합니다.', 1024, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '모야모야병', '모야모야병', 'DEFINITION', '모야모야병은 뇌 내 주요 동맥이 진행성으로 좁아지고 비정상적인 측부 혈관망이 형성되는 희귀 뇌혈관 질환입니다. 10세 이하 소아에서는 허혈성 발작(TIA, 뇌경색), 30~40대 성인에서는 출혈성 뇌졸중 형태로 호발하는 이중 발병 연령 분포를 보이며, 이는 연령별 혈류 역학 및 측부 혈관 특성 차이에 기인하는 것으로 추정됩니다. 국내에서 비교적 높은 유병률을 보이며, 신경외과 전문의의 정밀 진단과 치료가 필요합니다.', 1025, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '모야모야병', '모야모야병', 'SYMPTOM', '성인 모야모야병은 소아와 달리 출혈성 뇌졸중(뇌출혈, 뇌실내 출혈)이 주요 증상으로 나타나는 경우가 많습니다. 갑작스러운 심한 두통, 편측 마비, 언어 장애, 의식 저하 등이 발생할 수 있으며, 반복적인 일과성 허혈 발작(TIA)이 나타나기도 합니다. 소아에서는 주로 허혈 증상이 나타나는 것과 구별되며, 성인도 허혈 증상이 동반될 수 있어 신경과·신경외과 전문의의 정확한 감별 진단이 필요합니다.', 1026, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '모야모야병', '모야모야병', 'DIAGNOSIS', '모야모야병 환자는 혈소판 응집을 억제하는 아스피린을 복용하는 경우가 많으므로, 출혈 위험을 높이는 다른 항혈소판제나 항응고제 병용에 주의해야 합니다. 고삼투압 약물, 혈관 수축 약물, 에페드린 계열 약물 등 뇌혈류에 영향을 줄 수 있는 약물도 주의가 필요합니다. 모든 약물 복용과 영양제 섭취 전에 담당 신경외과 또는 신경과 전문의와 반드시 상의하시기 바랍니다.', 1027, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '모야모야병', '모야모야병', 'TREATMENT', '모야모야병 수술 후에도 장기적으로 허혈성 또는 출혈성 뇌졸중이 재발할 수 있으며, 수술 직후 수주~수개월 내 일시적 뇌허혈 증상 악화가 나타날 수 있습니다. 편측 마비, 언어 장애, 인지 기능 저하 등의 후유증이 지속될 수 있으며, 이는 수술 전 뇌 손상 정도와 뇌혈류 회복에 따라 달라집니다. 수술 후 정기적인 뇌혈관 영상 추적과 재활치료, 신경외과 전문의의 지속적인 관리가 필수적입니다.', 1028, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '바이러스성 뇌수막염', '바이러스성뇌수막염', 'CHECKUP', '아이가 두통과 발열이 있을 경우 신속히 소아청소년과 또는 응급실을 방문하여 진료를 받아야 합니다. 바이러스성 뇌수막염이 의심되면 뇌척수액 검사, 혈액 검사, 뇌 영상 검사 등을 통해 진단이 이루어지며, 소아청소년과 또는 신경과가 개설된 병원에서 가능합니다. 증상이 심하거나 급격히 악화될 경우 즉시 119를 통해 응급실로 이송하시기 바랍니다.', 1029, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '바이러스성 뇌수막염', '바이러스성뇌수막염', 'CAUSE', '바이러스성 뇌수막염의 가장 흔한 원인은 장바이러스(에코바이러스, 콕사키바이러스 등)로, 전체 사례의 대부분을 차지합니다. 그 외 단순포진 바이러스(HSV-2), 수두-대상포진 바이러스, 유행성이하선염 바이러스, HIV 등도 원인이 될 수 있습니다. 면역 저하 상태, 영아 및 소아, 밀집 생활 환경이 감염 위험을 높이는 요인이며, 신경과 전문의의 원인 규명이 중요합니다.', 1030, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '바이러스성 뇌수막염', '바이러스성뇌수막염', 'DEFINITION', '바이러스성 뇌수막염은 뇌와 척수를 둘러싸는 수막(지주막, 연막)에 바이러스 감염으로 염증이 생기는 질환입니다. 주요 증상으로는 고열, 심한 두통, 목 경직(항강), 광과민증, 오심·구토 등이 나타나며, 대부분 세균성에 비해 경과가 양호합니다. 그러나 증상이 빠르게 진행될 수 있으므로 의심 시 즉시 신경과 또는 소아청소년과 응급 진료를 받으시기 바랍니다.', 1031, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '바이러스성 뇌수막염', '바이러스성뇌수막염', 'SYMPTOM', '바이러스성 뇌수막염의 발열과 오한은 바이러스 감염에 대한 신체의 면역 반응으로 발생하며, 감염성 원인과 직접적으로 관련됩니다. 이러한 증상이 나타나면 즉시 의료기관을 방문하여 뇌척수액 검사, 혈액 검사 등을 통해 세균성 뇌수막염과 감별해야 합니다. 고열이 심하거나 의식 변화, 경련이 동반되면 응급실로 즉시 이송이 필요하며, 자의적인 해열제 복용만으로 대처하지 마시기 바랍니다.', 1032, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '바이러스성 뇌수막염', '바이러스성뇌수막염', 'DIAGNOSIS', '고열, 심한 두통, 경련 발작이 동반된 경우 뇌수막염의 가능성이 높으므로 즉시 응급실을 방문해야 합니다. 응급실에서 신경과 또는 소아청소년과 전문의가 진단과 초기 치료를 담당하며, 뇌척수액 검사를 통해 뇌수막염 여부와 원인을 확인합니다. 신속한 진단과 치료가 예후에 결정적이므로 증상 발현 즉시 119를 통해 이송하거나 응급실에 내원하시기 바랍니다.', 1033, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '바이러스성 뇌수막염', '바이러스성뇌수막염', 'TREATMENT', '바이러스성 뇌수막염 현장에서는 환자를 안정시키고 기도를 확보하며 119에 즉시 신고하는 것이 최우선입니다. 경련이 발생한 경우 주변 위험물을 치우고 환자를 옆으로 눕혀 기도를 유지하며, 입 안에 이물질을 넣지 않아야 합니다. 병원에서는 항바이러스제(HSV인 경우 아시클로버), 해열진통제, 수액 치료 등 지지 요법이 주된 치료이며, 응급 처치 후 신속한 병원 이송이 중요합니다.', 1034, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '박테리아성 뇌수막염', '박테리아성뇌수막염', 'CHECKUP', '박테리아성 뇌수막염 의심 시 혈액 배양 검사, 전혈구 검사, CRP·PCT 등 염증 지표, 혈액응고 검사 등을 시행합니다. 뇌 영상 검사로는 CT나 MRI를 통해 뇌부종, 농양, 뇌실염 등의 합병증을 확인하며, 확진을 위한 요추 천자(뇌척수액 검사)가 필수적입니다. 세균성 뇌수막염은 신속한 진단과 항생제 치료가 예후를 결정하므로, 의심 즉시 응급실에서 검사와 치료를 병행해야 합니다.', 1035, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '박테리아성 뇌수막염', '박테리아성뇌수막염', 'DIET_LIFE', '박테리아성 뇌수막염 예방을 위해 수막구균, 폐렴구균, Hib 백신 등 관련 예방 접종을 시행하는 것이 중요합니다. 식사 전후 손 씻기, 기침 예절 준수, 개인 식기와 음료 컵 구분 사용 등 개인 위생이 기본입니다. 영양 균형이 잡힌 식단과 충분한 수면으로 면역력을 유지하고, 밀집된 환경에서의 감염 예방에도 주의하시기 바랍니다.', 1036, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '박테리아성 뇌수막염', '박테리아성뇌수막염', 'MEDICATION', '박테리아성 뇌수막염에서 항생제 치료와 함께 덱사메타손 등의 스테로이드 제제를 투여하는 이유는 염증 반응을 억제하여 뇌부종을 줄이고 신경학적 합병증(청력 손실, 인지 장애 등)의 위험을 낮추기 위해서입니다. 뇌압이 상승한 경우 삼투압 이뇨제(만니톨)를 추가하여 뇌압을 조절합니다. 이러한 병행 치료는 생존율 향상과 후유증 최소화에 중요하므로 신경과 전문의의 처방에 따라 진행됩니다.', 1037, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '박테리아성 뇌수막염', '박테리아성뇌수막염', 'PREVENTION', '박테리아성 뇌수막염 위험 지역(아프리카 뇌수막염 벨트, 메카 성지 순례 등) 여행자는 출발 전 수막구균 백신(특히 ACWY 및 B형)을 접종받는 것이 강력히 권장됩니다. 여행 중 밀집된 숙소 환경, 현지인과의 음식·음료 공유를 피하고 손 위생을 철저히 지켜야 합니다. 귀국 후 두통, 발열, 목 경직 등의 증상이 발생하면 즉시 의료기관을 방문하여 여행 이력을 알리시기 바랍니다.', 1038, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '박테리아성 뇌수막염', '박테리아성뇌수막염', 'CAUSE', '박테리아성 뇌수막염의 가장 흔한 원인균은 성인에서 폐렴구균(Streptococcus pneumoniae), 신생아·영아에서 B군 사슬알균과 대장균, 청소년·청년에서 수막구균(Neisseria meningitidis)입니다. 원인균은 호흡기 분비물을 통해 비말로 전파될 수 있으며, 밀접 접촉자(같은 공간 장시간 접촉)에게 전파 위험이 있습니다. 수막구균의 경우 밀접 접촉자에게 예방적 항생제(리팜피신 등) 투여를 권고할 수 있으므로 감염내과 또는 신경과 전문의에게 문의하시기 바랍니다.', 1039, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '박테리아성 뇌수막염', '박테리아성뇌수막염', 'DEFINITION', '박테리아성 뇌수막염 원인균들은 먼저 비인두 점막 상피세포에 부착하여 점막 장벽을 통과한 뒤 혈류로 진입하고, 혈행성으로 뇌혈관 내피세포에 도달합니다. 이후 혈뇌장벽을 통과하여 뇌척수액과 수막으로 침투하며 염증 반응을 유발합니다. 각 균마다 특이적인 표면 단백질과 독소를 이용하여 세포 침투와 면역 회피 기전을 활용하며, 이 과정에서 심각한 신경계 손상이 발생합니다.', 1040, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '박테리아성 뇌수막염', '박테리아성뇌수막염', 'SYMPTOM', '박테리아성 뇌수막염이 의심되는 발열, 두통, 목 경직 증상이 동반된 경우 즉시 응급실을 방문하여 신경과 또는 감염내과 진료를 받아야 합니다. 혈액 배양 검사와 뇌척수액 검사(요추 천자)가 필수적이며, 뇌 CT로 검사 전 뇌압 상승 여부를 먼저 확인하기도 합니다. 확진 전에도 임상적으로 강하게 의심되면 항생제 치료를 즉시 시작하는 것이 예후에 중요합니다.', 1041, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '박테리아성 뇌수막염', '박테리아성뇌수막염', 'DIAGNOSIS', '박테리아성 뇌수막염 진단에서 뇌척수액 검사(요추 천자)가 확진을 위한 가장 중요한 검사입니다. 그러나 혈액 배양 검사를 먼저 시행하여 원인균을 규명하는 데 도움이 되며, 뇌압 상승이 의심될 때는 CT 확인 후 요추 천자를 시행합니다. 임상적으로 강력히 의심되는 경우 검사 결과를 기다리지 않고 항생제 치료를 먼저 시작하는 것이 생존율 향상에 중요하며, 신경과 또는 감염내과 전문의의 판단에 따릅니다.', 1042, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '박테리아성 뇌수막염', '박테리아성뇌수막염', 'TREATMENT', '박테리아성 뇌수막염에서 적절한 항생제를 충분한 기간 투여했음에도 호전이 없거나 악화된다면, 내성균 감염 여부 확인, 항생제 변경 또는 추가를 고려해야 합니다. 뇌농양, 경막하축농, 뇌수두증 등의 합병증이 발생한 경우 신경외과적 배농 수술이 필요할 수 있습니다. 치료 반응이 없을 때는 신경과, 감염내과, 신경외과 전문의가 협력하여 원인을 재평가하고 치료 방향을 재설정해야 합니다.', 1043, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '반사회성 인격장애', '반사회성인격장애', 'CAUSE', '반사회성 인격장애는 선천적(유전, 신경생물학적 이상)요인과 환경적(아동기 학대·방임, 불안정한 가정 환경, 반사회적 또래 집단 노출)요인이 함께 작용합니다. 현재까지의 연구에서는 어느 한 요인이 절대적 우위를 보이기보다는 유전적 취약성을 가진 사람이 불리한 환경에 노출될 때 발병 위험이 높아지는 상호작용 모델이 지지됩니다. 조기 환경적 개입이 예방에 중요하며, 정신건강의학과 전문의의 평가가 필요합니다.', 1044, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '반사회성 인격장애', '반사회성인격장애', 'DEFINITION', '반사회성 인격장애는 타인의 권리를 무시하고 반복적으로 규칙을 어기며 공감 능력이 결여된 패턴이 만 18세 이후에도 지속되는 경우 진단합니다. 아동기의 품행 장애(규칙 위반, 거짓말, 공격성 등)가 선행되는 경우가 많으며, 이러한 행동이 다양한 상황에서 일관되게 나타나는 것이 특징입니다. 아동의 규칙 위반 행동이 반복된다면 소아청소년 정신건강의학과 전문의의 조기 평가와 개입이 중요합니다.', 1045, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '반사회성 인격장애', '반사회성인격장애', 'SYMPTOM', '반사회성 인격장애의 주요 증상으로는 타인 공격성 외에도 반복적인 거짓말과 사기 행동, 충동성과 계획 불능, 무책임한 행동(직업·재정 의무 방기), 죄책감이나 후회의 결여 등이 있습니다. 법적 규범을 반복적으로 어기거나 타인을 착취하는 행동 패턴이 지속되며, 위험 상황을 무모하게 회피하지 않는 경향도 나타납니다. 이러한 증상이 의심된다면 정신건강의학과 전문의의 정확한 진단이 필요합니다.', 1046, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '반사회성 인격장애', '반사회성인격장애', 'DIAGNOSIS', '반사회성 인격장애 진단은 정신건강의학과(정신과) 전문의의 정밀 면담과 심리 평가(MMPI, 인격 검사 등)를 통해 이루어집니다. DSM-5 진단 기준(만 15세 이전 품행 장애 병력, 만 18세 이후 반복적 반사회적 행동 등)을 충족해야 진단할 수 있습니다. 진단을 위해 정신건강의학과를 방문하시고, 필요한 경우 신뢰할 수 있는 가족이나 보호자가 동행하는 것이 도움이 됩니다.', 1047, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '반사회성 인격장애', '반사회성인격장애', 'TREATMENT', '반사회성 인격장애의 폭력적·공격적 행동 치료는 인지행동치료를 통한 충동 조절, 감정 조절 능력 향상이 핵심입니다. 공격성 완화를 위해 기분 안정제, 항충동 약물 등이 보조적으로 사용될 수 있습니다. 치료 동기가 낮은 경우가 많아 치료가 어려울 수 있으며, 본인 의지와 지속적인 전문 치료가 중요하므로 정신건강의학과 전문의의 장기적 관리를 받으시기 바랍니다.', 1048, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '발작', '발작', 'CAUSE', '신생아 경련의 선천적 원인으로는 유전성 대사 질환, 뇌 기형, 염색체 이상 등이 있으며, 후천적 원인으로는 분만 중 저산소성 허혈성 뇌증, 저혈당, 저칼슘혈증, 뇌출혈, 감염(뇌수막염) 등이 있습니다. 가장 흔한 원인은 신생아 가사(저산소성 허혈성 뇌증)이며, 이는 후천적 요인에 해당합니다. 신생아 경련은 즉각적인 원인 규명과 치료가 신경학적 예후에 중요하므로 신속히 신생아과 전문의의 진료를 받아야 합니다.', 1049, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '발작', '발작', 'DEFINITION', '발작은 뇌의 신경세포들이 비정상적이고 과도하게 동시에 방전되어 나타나는 갑작스럽고 일시적인 신경학적 현상입니다. 근육 경련, 강직, 의식 소실, 감각 이상, 자율신경 증상 등 다양한 형태로 나타나며, 원인에 따라 뇌전증성 발작과 비뇌전증성 발작(발열성 경련, 실신, 저혈당 등)으로 구분됩니다. 반복적인 발작이 발생하면 신경과 전문의의 뇌파 검사와 영상 검사를 통한 정확한 진단이 필요합니다.', 1050, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '발작', '발작', 'SYMPTOM', '발작 시 의식 소실과 함께 전신 근육의 경직 및 간대성 경련(몸이 리드미컬하게 떨림)이 나타날 수 있으며, 눈이 돌아가거나 입에서 거품이 나오기도 합니다. 발작 후에는 일시적인 혼미, 두통, 피로감이 동반되는 발작 후 상태(postictal state)가 나타날 수 있습니다. 발작 증상이 의심된다면 신경과 전문의의 진료를 받으시기 바랍니다.', 1051, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '발작', '발작', 'DIAGNOSIS', '식은땀과 극심한 공포를 동반하는 발작 감별을 위해 신경과 또는 정신건강의학과를 방문하여 뇌파 검사(EEG), 뇌 MRI, 혈액 검사 등을 시행합니다. 공황 발작과 뇌전증 발작을 구분하는 것이 중요하며, 상세한 증상 발생 상황과 경과를 의료진에게 설명하는 것이 진단에 도움이 됩니다. 정확한 진단을 위해 반드시 전문의 상담을 받으시기 바랍니다.', 1052, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '발작', '발작', 'TREATMENT', '만성 천식의 급성 발작 시 속효성 기관지 확장제(SABA, 살부타몰 등) 흡입이 1차 대처법이며, 중증 발작에는 전신 스테로이드 투여와 산소 공급이 필요합니다. 평소 흡입 스테로이드 등 장기 조절 약물을 꾸준히 사용해 발작 빈도를 줄이는 것이 중요합니다. 적절한 치료 계획 수립을 위해 호흡기내과 전문의와 상담하시기 바랍니다.', 1053, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불면증', '불면증', 'DIET_LIFE', '불면증 완화에 도움이 되는 음식으로는 트립토판이 풍부한 우유, 바나나, 견과류와 멜라토닌이 들어있는 체리 등이 있습니다. 취침 전 과도한 카페인, 알코올, 자극적인 음식은 수면을 방해하므로 피하는 것이 좋습니다. 규칙적인 식사 시간 유지와 취침 2~3시간 전에는 과식을 삼가는 식습관이 수면의 질 개선에 도움이 됩니다.', 1054, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불면증', '불면증', 'MEDICATION', '불면증에 사용되는 신경안정제(벤조디아제핀계, 비벤조디아제핀계) 약물은 의존성, 내성, 기억력 저하, 낮 시간 졸림, 어지러움, 낙상 위험 증가 등의 부작용이 있을 수 있습니다. 고령자의 경우 특히 부작용 위험이 높으므로 주의가 필요하며, 장기 복용은 삼가는 것이 권장됩니다. 약물 복용 전 반드시 정신건강의학과 또는 신경과 전문의의 처방과 지도하에 사용하시기 바랍니다.', 1055, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불면증', '불면증', 'PREVENTION', '수면 촉진에 도움이 되는 음식으로는 트립토판을 함유한 따뜻한 우유, 바나나, 아몬드, 오트밀 등이 있으며, 이들 성분은 세로토닌과 멜라토닌 합성을 도와 수면을 유도합니다. 취침 전 카페인 음료(커피, 녹차)와 음주는 수면의 질을 저하시키므로 피하는 것이 좋습니다. 수면 장애가 지속된다면 수면의학 전문의 또는 신경과에서 정확한 원인 파악 후 치료받으시기 바랍니다.', 1056, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불면증', '불면증', 'EXERCISE', '불면증 개선에 효과적인 운동으로는 유산소 운동(빠르게 걷기, 수영, 자전거 타기)이 있으며, 규칙적인 운동이 수면의 질을 향상시킵니다. 단, 카페인의 각성 효과는 약 6시간 지속되므로 취침 6시간 전부터는 커피 섭취를 중단하고, 취침 3~4시간 이내의 격렬한 운동도 피하는 것이 좋습니다. 운동은 오전이나 이른 오후에 하는 것이 수면에 가장 유익합니다.', 1057, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불면증', '불면증', 'CAUSE', '불면증의 원인은 심리적 요인(스트레스, 불안, 우울증), 신체 질환(통증, 수면무호흡증, 하지불안증후군), 환경적 요인(소음, 빛, 온도), 약물 및 카페인·알코올 섭취, 생체리듬 이상 등 다양합니다. 교대 근무나 불규칙한 수면 습관도 불면증을 유발할 수 있습니다. 지속적인 불면증은 수면의학 전문의 또는 정신건강의학과의 정확한 원인 평가가 필요합니다.', 1058, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불면증', '불면증', 'DEFINITION', '불면증은 잠들기 어렵거나, 자다가 자주 깨거나, 너무 일찍 깨어 충분한 수면을 취하지 못하는 상태가 주 3회 이상, 3개월 이상 지속되는 수면 장애입니다. 치료는 인지행동치료(CBT-I)가 1차 치료로 권장되며, 수면 위생 교육, 자극 조절법, 수면 제한 요법 등이 포함됩니다. 필요에 따라 단기간 약물 치료를 병행할 수 있으며, 정신건강의학과 또는 수면의학 전문의 상담을 권고합니다.', 1059, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불면증', '불면증', 'SYMPTOM', '30대 후반 여성에서 불면증, 안면 홍조, 불규칙한 월경이 동반된다면 조기 폐경(조기 난소 부전)을 의심할 수 있습니다. 이 경우 에스트로겐 감소로 인해 자율신경 불안정 증상이 나타나며, 갑상선 기능 이상이나 우울증 등도 감별이 필요합니다. 정확한 진단을 위해 산부인과 또는 내분비내과 전문의 진료와 호르몬 검사를 받으시기 바랍니다.', 1060, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불면증', '불면증', 'DIAGNOSIS', '수면 중 자주 깨거나 다시 잠들기 어려운 증상이 지속된다면 정신건강의학과, 신경과, 또는 수면클리닉을 운영하는 종합병원에서 진료받을 수 있습니다. 수면다원검사(PSG)나 수면 일지 작성을 통해 수면 패턴을 평가하며, 수면무호흡증 등 다른 수면 장애와의 감별도 이루어집니다. 증상이 2주 이상 지속된다면 전문의 진료를 받으시기 바랍니다.', 1061, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불면증', '불면증', 'TREATMENT', '주 3회 이상 불면증이 있는 경우 약물 치료 외에 인지행동치료(CBT-I)가 가장 효과적인 비약물 치료로 권장됩니다. 규칙적인 수면 스케줄 유지, 침실을 수면 전용 공간으로 사용하기, 낮잠 제한, 카페인·알코올 섭취 줄이기 등 수면 위생 개선도 중요합니다. 지속적인 불면증은 정신건강의학과 또는 수면의학 전문의와 상담하여 개인화된 치료 계획을 세우시기 바랍니다.', 1062, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불안 장애', '불안장애', 'CHECKUP', '교통사고 후 불안 장애 확인을 위해 정신건강의학과에서 구조화된 임상 면담과 표준화된 심리 검사(PTSD 척도, 불안 척도 등)를 시행합니다. 필요에 따라 뇌 MRI 또는 CT로 신체적 원인을 배제하며, 외상 후 스트레스 장애(PTSD)와의 감별도 이루어집니다. 사고 후 회피 행동과 불안 증상이 지속된다면 정신건강의학과 전문의 진료를 받으시기 바랍니다.', 1063, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불안 장애', '불안장애', 'DIET_LIFE', '불안 장애 관리를 위해 규칙적인 복식 호흡과 점진적 근육 이완법 연습, 규칙적인 신체 활동이 도움이 됩니다. 카페인·알코올 섭취 줄이기, 충분한 수면 취하기, 과부하를 줄이기 위한 일정 관리 등도 중요합니다. 일상적인 자기 관리만으로 호전되지 않는다면 정신건강의학과 전문의 상담과 인지행동치료를 받으시기 바랍니다.', 1064, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불안 장애', '불안장애', 'MEDICATION', '지적 장애(정신 지체)가 있는 아이는 언어 및 인지 발달 지연, 새로운 환경이나 변화에 대한 적응 어려움으로 인해 불안 장애 증상이 동반될 수 있습니다. 불안 장애 치료에는 인지행동치료를 변형한 적응 치료, 행동 중재, 필요 시 항불안제 약물 치료가 사용되며, 지적 장애의 정도를 고려한 맞춤 접근이 필요합니다. 소아정신건강의학과 전문의와 상담하여 아이에게 적합한 치료 계획을 세우시기 바랍니다.', 1065, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불안 장애', '불안장애', 'PREVENTION', '불안정한 생각이 지속적으로 반복되고 일상생활을 방해한다면 범불안장애(GAD) 등 불안 장애의 주요 증상일 수 있습니다. 예방을 위해 규칙적인 운동, 명상 및 마음 챙김 훈련, 규칙적인 수면 습관, 스트레스 관리 기술 습득이 도움이 됩니다. 증상이 지속된다면 정신건강의학과 전문의 상담을 통해 적절한 치료와 예방 전략을 수립하시기 바랍니다.', 1066, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불안 장애', '불안장애', 'CAUSE', '불안 장애의 원인은 유전적 소인, 뇌 신경전달물질(세로토닌, 노르에피네프린) 불균형, 어린 시절의 트라우마나 스트레스 경험, 만성 스트레스, 특정 성격 특성 등이 복합적으로 작용합니다. 어린이의 경우 부모의 갈등, 학업 압박, 따돌림 등 환경적 스트레스가 불안 장애 발생의 주요 촉진 요인이 될 수 있습니다. 조카에게 관련 증상이 있다면 소아정신건강의학과 전문의 진료를 받으시기 바랍니다.', 1067, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불안 장애', '불안장애', 'DEFINITION', '불안 장애, 특히 사회 불안 장애(사회공포증)는 타인의 시선을 받을 때 가슴 두근거림, 식은땀, 얼굴 붉어짐, 손 떨림 등의 신체 증상이 나타나는 것이 특징입니다. 이는 교감신경계 과활성화로 인한 반응이며, 사회적 상황에 대한 과도한 두려움이 핵심 원인입니다. 해당 증상으로 일상생활에 지장이 있다면 정신건강의학과 전문의 상담을 권고합니다.', 1068, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불안 장애', '불안장애', 'SYMPTOM', '불안 장애의 증상으로는 호흡 곤란, 근육 긴장 외에도 지속적인 걱정과 불안, 집중력 저하, 수면 장애, 피로감, 심계항진(가슴 두근거림), 어지러움, 소화 장애, 과민성 등이 나타날 수 있습니다. 공황 발작 시에는 극심한 공포와 함께 흉통, 손발 저림, 질식감 등이 동반될 수 있습니다. 이러한 증상이 지속된다면 정신건강의학과 전문의 진료를 받으시기 바랍니다.', 1069, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불안 장애', '불안장애', 'DIAGNOSIS', '가슴이 묵직하고 숨쉬기 힘든 증상에 대해 먼저 심장 및 호흡기 질환을 배제하기 위해 심전도, 흉부 X선, 혈액 검사 등을 시행합니다. 신체 질환이 배제된 경우 정신건강의학과에서 구조화된 면담과 불안 척도 검사를 통해 불안 장애 또는 공황 장애 여부를 평가합니다. 증상이 반복된다면 내과 또는 정신건강의학과 전문의를 방문하시기 바랍니다.', 1070, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '불안 장애', '불안장애', 'TREATMENT', '대중교통 이용이 어렵고 불안 증상이 동반된다면 광장공포증(agoraphobia)이나 공황 장애, 또는 사회 불안 장애를 의심할 수 있습니다. 진단을 위해 정신건강의학과에서 임상 면담과 표준화된 불안 척도 검사를 시행하며, 증상의 지속 기간과 일상생활 지장 정도를 평가합니다. 치료는 인지행동치료와 필요 시 약물 치료를 병행하므로 전문의 상담을 받으시기 바랍니다.', 1071, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '삼차 신경병증', '삼차신경병증', 'CAUSE', '삼차신경은 얼굴 감각과 저작근 운동을 담당하는데, 임플란트 시술 시 하치조신경 또는 삼차신경 분지에 손상이 가해지면 동측 턱 부위의 감각 이상, 저림, 통증이 나타날 수 있습니다. 기존에 삼차 신경병증이 있는 경우 시술 후 증상이 악화될 위험이 있으므로 시술 전 신경외과 또는 신경과와 사전 협의가 권장됩니다. 임플란트 후 신경 증상이 나타난다면 즉시 구강악안면외과 또는 신경과 전문의 진료를 받으시기 바랍니다.', 1072, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '삼차 신경병증', '삼차신경병증', 'DEFINITION', '삼차신경병증은 삼차신경(제5뇌신경)의 손상 또는 압박으로 인해 발생하며, 안면 감각 이상(저림, 무감각)과 씹기 근육(교근, 측두근 등) 약화를 유발합니다. 원인으로는 혈관에 의한 신경 압박, 다발성 경화증, 뇌종양, 외상, 헤르페스 바이러스 감염 등이 있습니다. 정확한 원인 파악을 위해 신경과 또는 신경외과 전문의의 진료와 MRI 검사가 필요합니다.', 1073, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '삼차 신경병증', '삼차신경병증', 'SYMPTOM', '삼차 신경통(삼차 신경병증의 일종)의 특징적인 통증은 주로 씹기, 말하기, 세수, 양치질, 찬바람 노출 등 얼굴에 가해지는 가벼운 자극에 의해 유발됩니다. 통증은 수 초에서 수 분간 지속되는 전격통(전기 충격이나 칼로 찌르는 듯한 통증) 형태로 나타나며, 주로 뺨, 턱, 치아, 잇몸 부위에 발생합니다. 해당 증상이 있다면 신경과 전문의 진료를 받으시기 바랍니다.', 1074, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '삼차 신경병증', '삼차신경병증', 'DIAGNOSIS', '음식을 씹기 어렵고 근육 약화가 동반된 삼차 신경병증 의심 증상은 신경과 또는 신경외과 전문의에게 진단받는 것이 적합합니다. 필요에 따라 구강악안면외과와의 협진도 이루어질 수 있으며, MRI, 근전도 검사(EMG), 신경전도 검사 등을 통해 원인을 파악합니다. 증상이 지속된다면 신속하게 전문의 진료를 받으시기 바랍니다.', 1075, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '삼차 신경병증', '삼차신경병증', 'TREATMENT', '삼차 신경병증의 치료는 원인에 따라 다르며, 약물 치료로는 카바마제핀, 옥스카바제핀 등의 항경련제가 신경통 완화에 사용됩니다. 약물에 반응하지 않는 경우 미세혈관 감압술, 방사선 수술(감마 나이프), 경피적 신경 차단술 등의 수술적 또는 시술적 치료를 고려할 수 있습니다. 치료 방법 선택을 위해 신경과 또는 신경외과 전문의와 상담하시기 바랍니다.', 1076, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '섬망', '섬망', 'MEDICATION', '섬망 관리를 위한 약물은 할로페리돌, 쿠에티아핀 등의 항정신병 약물이 주로 사용되며, 이는 전문의 처방이 필요한 전문 의약품으로 일반 약국에서 구매할 수 없습니다. 시중에 판매되는 일반 의약품으로는 섬망을 효과적으로 관리하기 어려우며, 오히려 일부 약물(항히스타민제 등)은 섬망을 악화시킬 수 있습니다. 섬망 증상이 있다면 즉시 응급실 또는 정신건강의학과 전문의의 진료를 받으시기 바랍니다.', 1077, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '섬망', '섬망', 'CAUSE', '섬망 발생에는 개인의 취약성(고령, 인지 기능 저하, 기저 뇌 질환)과 촉발 요인(수술, 감염, 약물, 대사 이상)이 상호작용합니다. 심리적 스트레스와 정신적 압박은 직접적인 원인이기보다는 취약한 개인에서 섬망 발생을 촉진하는 보조 요인으로 작용할 수 있습니다. 특히 중환자실 입원, 낯선 환경, 수면 박탈 등도 섬망을 유발하는 상황적 스트레스로 알려져 있습니다.', 1078, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '섬망', '섬망', 'DEFINITION', '섬망은 급성으로 발생하는 뇌 기능 장애로, 주의력 저하와 의식 수준 변화를 특징으로 합니다. 주요 원인으로는 감염(폐렴, 요로감염), 약물 독성 또는 금단, 대사 이상(전해질 불균형, 저혈당), 탈수, 수술 후 상태, 뇌 질환 등이 있습니다. 고령자와 기저 인지 장애가 있는 경우 발생 위험이 높으며, 원인 치료가 무엇보다 중요합니다.', 1079, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '섬망', '섬망', 'SYMPTOM', '섬망과 치매 모두 인지 기능 저하, 혼란, 기억 장애 등 유사한 증상을 보이지만, 섬망은 급성(수 시간~수 일)으로 발생하고 증상 변동이 심하며 주의력 장애가 두드러지는 반면, 치매는 수 개월~수 년에 걸쳐 서서히 진행됩니다. 섬망은 원인 치료 시 호전 가능하지만, 기저 치매가 있는 환자는 섬망 발생 시 인지 기능이 더 빠르게 악화될 수 있습니다. 두 질환의 감별을 위해 전문의 진료가 필요합니다.', 1080, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '섬망', '섬망', 'DIAGNOSIS', '섬망 진단 시 증상의 급격한 변동, 주의력 장애, 의식 수준 변화, 인지 기능 변화를 확인하는 CAM(Confusion Assessment Method) 도구를 사용합니다. 정신과적 질환(정신증, 우울증), 치매 급성 악화, 비경련성 간질 지속 상태 등을 감별하기 위해 혈액 검사, 뇌 영상, 뇌파 검사 등이 필요합니다. 증상의 원인과 경과에 따라 다른 진단이 내려질 수 있으므로 전문의의 종합적 평가가 중요합니다.', 1081, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '섬망', '섬망', 'TREATMENT', '섬망은 주로 급성 신체 질환에 의해 발생하므로 심리치료보다 원인 질환 치료가 우선입니다. 다만 인지행동치료 원리를 적용한 비약물적 중재(현실 감각 교정, 수면-각성 주기 유지, 규칙적인 자극 제공)가 섬망 예방 및 증상 완화에 효과가 있는 것으로 알려져 있습니다. 대인치료는 섬망 자체보다 회복 후 동반되는 불안이나 우울 증상 관리에 도움이 될 수 있습니다.', 1082, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '섭식 장애', '섭식장애', 'CHECKUP', '섭식 장애 진단에는 체중, 신장, BMI 측정 등의 신체 검사와 함께 혈액 검사(전해질, 혈당, 갑상선 기능 등), 심전도 검사가 사용됩니다. 심리적 평가를 위해 EDE-Q(섭식 장애 검사), EDI(섭식 장애 목록) 등의 표준화된 심리 척도와 임상 면담이 활용되며, 이를 통해 신경성 식욕 부진증, 신경성 폭식증, 폭식 장애 등을 감별합니다. 진단을 위해 정신건강의학과 또는 섭식 장애 전문 클리닉에서 진료받으시기 바랍니다.', 1083, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '섭식 장애', '섭식장애', 'MEDICATION', '섭식 장애 치료에는 약물 치료 외에 인지행동치료(CBT)가 가장 근거가 확립된 치료로, 왜곡된 신체상과 식이 행동 패턴을 교정합니다. 영양사를 통한 영양 상담과 식이 재활, 가족 치료(특히 청소년), 변증법적 행동 치료(DBT) 등도 효과적인 대안입니다. 섭식 장애는 신체적·심리적 합병증이 심각할 수 있으므로 정신건강의학과 전문의와 다학제 팀의 치료를 받으시기 바랍니다.', 1084, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '섭식 장애', '섭식장애', 'PREVENTION', '미디어와 사회적 압박으로 인한 섭식 장애 예방을 위해 미디어 리터러시 교육을 통해 비현실적인 신체 이미지에 비판적 시각을 기르는 것이 중요합니다. 긍정적인 신체상(body positivity) 증진, 체중이 아닌 건강 중심의 가치관 형성, 과도한 다이어트 정보 노출 제한이 도움이 됩니다. 학교 및 가정에서 건강한 식습관과 자존감 향상을 위한 교육을 실시하고, 이상 징후 발견 시 조기에 전문가 도움을 받는 것이 권장됩니다.', 1085, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '섭식 장애', '섭식장애', 'CAUSE', '섭식 장애에서 심리적 스트레스는 음식과 체중에 대한 통제감 상실, 자존감 저하, 감정 조절 어려움과 연결되어 증상을 악화시키는 주요 요인입니다. 부정적 사고 완화에 도움이 되는 운동으로는 과도한 칼로리 소모보다 심신 통합을 강조하는 요가, 필라테스, 걷기 등이 권장됩니다. 심리적 스트레스와 섭식 문제가 복합적으로 나타난다면 정신건강의학과 전문의 상담을 받으시기 바랍니다.', 1086, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '섭식 장애', '섭식장애', 'DEFINITION', '섭식 장애는 음식 섭취, 체중, 신체상에 대한 심각한 장애로, 신경성 식욕 부진증(극도의 식이 제한), 신경성 폭식증(폭식 후 제거 행동), 폭식 장애 등을 포함합니다. 음식을 충분히 섭취하지 못하는 것도 섭식 장애의 하나인 신경성 식욕 부진증 또는 회피·제한적 음식 섭취 장애(ARFID)에 해당할 수 있습니다. 정확한 진단을 위해 정신건강의학과 또는 섭식 장애 전문 클리닉의 진료를 받으시기 바랍니다.', 1087, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '섭식 장애', '섭식장애', 'SYMPTOM', '섭식 장애의 주요 증상은 체중 증가보다 음식 및 체중에 대한 왜곡된 인식, 비정상적인 식이 행동(극단적 제한, 폭식, 제거 행동)이 핵심입니다. 폭식 장애나 야간 식이 장애의 경우 체중 증가가 동반될 수 있으며, 이 외에도 영양 불량, 전해질 이상, 위장 장애, 우울증·불안 증상이 나타날 수 있습니다. 이러한 증상이 의심된다면 정신건강의학과 전문의와 상담하시기 바랍니다.', 1088, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '섭식 장애', '섭식장애', 'DIAGNOSIS', '사춘기에 체중 증가로 인한 예민함과 심리적 어려움은 성장기 호르몬 변화, 신체상 왜곡, 또래 압박 등과 관련될 수 있으며, 섭식 장애로 발전할 위험 요인이 됩니다. 진단은 정신건강의학과 또는 소아청소년 정신건강의학과에서 임상 면담과 심리 검사를 통해 이루어집니다. 아이의 체중과 관련한 심리적 어려움이 지속된다면 조기에 전문의 상담을 받으시기 바랍니다.', 1089, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '섭식 장애', '섭식장애', 'TREATMENT', '균형 잡힌 규칙적인 식사와 폭식·제한 없는 정상적인 식이 패턴 회복은 섭식 장애 치료의 핵심입니다. 충분한 수면, 스트레스 관리, 과도한 운동 자제, 사회적 지지망 유지 등 생활습관 개선이 치료 효과를 높입니다. 자기 돌봄과 생활 습관 조절은 전문 치료를 보완하는 역할을 하므로, 정신건강의학과 전문의와 영양사의 지도하에 체계적으로 진행하시기 바랍니다.', 1090, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '성인 주의력 결핍 과잉행동장애', '성인주의력결핍과잉행동장애', 'CAUSE', '성인 ADHD의 원인은 유전적 요인이 가장 크며, 도파민·노르에피네프린 등 신경전달물질의 불균형과 전두엽 기능 이상이 주요 기전으로 알려져 있습니다. 아동기 ADHD가 성인기까지 지속되는 경우가 많으며, 환경적 스트레스, 수면 부족, 물질 남용 등이 증상을 악화시킬 수 있습니다. 정확한 원인 평가와 진단을 위해 정신건강의학과 전문의 진료를 받으시기 바랍니다.', 1091, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '성인 주의력 결핍 과잉행동장애', '성인주의력결핍과잉행동장애', 'DEFINITION', '아동기 ADHD는 약 60~70%에서 성인기까지 증상이 지속되며, 유전적 소인이 강하게 작용합니다. 성인 ADHD는 아동기와 달리 과잉행동보다 주의력 결핍, 충동성, 시간 관리 어려움, 감정 조절 문제가 두드러집니다. 성인기 ADHD는 직업·대인관계·학업에 영향을 미치므로 정신건강의학과 전문의를 통한 정확한 진단과 치료가 권장됩니다.', 1092, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '성인 주의력 결핍 과잉행동장애', '성인주의력결핍과잉행동장애', 'SYMPTOM', '성인 ADHD 환자는 초조함, 집중력 결여 외에도 충동성, 시간 관리 어려움, 잦은 실수, 계획·조직화 능력 저하, 감정 기복, 과민성, 수면 장애, 낮은 자존감 등의 증상이 나타날 수 있습니다. 우울증, 불안 장애 등의 공존 질환이 흔하여 증상을 복잡하게 만들기도 합니다. 이러한 증상이 지속된다면 정신건강의학과 전문의 진료를 받으시기 바랍니다.', 1093, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '성인 주의력 결핍 과잉행동장애', '성인주의력결핍과잉행동장애', 'DIAGNOSIS', '성인 ADHD 자가 보고 척도(ASRS-v1.1 등)는 주의력 결핍과 과잉행동·충동성 증상의 빈도와 심각도를 자가 평가하는 도구로, 진단의 보조 수단으로 활용됩니다. 자가 보고 척도는 선별 검사 역할을 하며, 실제 진단은 임상 면담, 병력 청취, 신경심리 검사, 기능 평가를 종합하여 이루어집니다. 자가 척도 결과만으로 확진은 불가능하므로 전문의 진료가 필요합니다.', 1094, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '성인 주의력 결핍 과잉행동장애', '성인주의력결핍과잉행동장애', 'TREATMENT', '성인 ADHD 환자의 가족이나 배우자가 증상을 이해하고 일상적인 조직화·시간 관리를 함께 지원하면 환자의 기능 향상과 자존감 회복에 도움이 됩니다. 보호자의 정서적 지지는 치료 순응도를 높이고 공존 질환인 우울증·불안 장애 증상도 완화하는 데 긍정적 영향을 미칩니다. 가족 교육 프로그램 참여와 전문 상담을 통해 환자와 가족 모두의 삶의 질을 개선할 수 있습니다.', 1095, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '수면 장애', '수면장애', 'CAUSE', '스트레스는 코르티솔 등 스트레스 호르몬을 증가시켜 뇌의 각성 상태를 높이고 수면을 방해합니다. 직장·학업·대인관계 스트레스, 경제적 걱정 등 만성 심리 사회적 스트레스가 교감신경계를 지속적으로 활성화하여 잠들기 어렵거나 수면 유지가 힘들어집니다. 스트레스 관리를 위한 이완 기법, 규칙적인 운동, 충분한 휴식이 도움이 되며, 증상이 지속된다면 전문의 상담을 권고합니다.', 1096, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '수면 장애', '수면장애', 'DEFINITION', '수면 중 자주 깨는 것은 수면 유지 불면증의 특징적인 증상으로, 수면 장애의 일종입니다. 원인으로는 수면무호흡증, 하지불안증후군, 주기성 사지 운동 장애, 통증, 야간 뇨, 스트레스, 우울증·불안, 카페인·알코올 섭취 등이 있습니다. 수면 중 자주 깨는 증상이 지속된다면 수면의학 전문의 또는 신경과에서 원인을 파악하고 치료받으시기 바랍니다.', 1097, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '수면 장애', '수면장애', 'SYMPTOM', '수면 장애의 주요 증상으로는 잠들기 어려움, 수면 유지 어려움, 이른 각성, 비회복성 수면 외에도 코골이·무호흡(수면무호흡증), 수면 중 비정상적인 행동(수면 보행증), 과도한 주간 졸림증, 수면 중 다리 불편감 등이 있습니다. 이러한 증상이 있다면 수면의학 전문의(신경과, 이비인후과, 정신건강의학과)와 상담하는 것이 적합합니다. 정확한 진단을 위해 전문의 진료를 받으시기 바랍니다.', 1098, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '수면 장애', '수면장애', 'DIAGNOSIS', '수면 장애 진단 시 2주 이상 지속되는 수면 문제, 주간 기능 저하(집중력 저하, 피로, 졸림), 수면 중 특이 행동이나 호흡 이상 등에 주의해야 합니다. 진단을 받으면 원인에 따라 수면 위생 교육, 인지행동치료(CBT-I), 수면다원검사(PSG) 등의 추가 검사, 또는 약물 치료 등의 조치가 취해집니다. 증상이 지속되거나 일상생활에 지장을 준다면 즉시 전문의 진료를 받으시기 바랍니다.', 1099, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '수면 장애', '수면장애', 'TREATMENT', '수면제 대신 사용할 수 있는 치료로는 인지행동치료(CBT-I)가 가장 효과적인 1차 치료로 권장되며, 수면 제한 요법, 자극 조절법, 이완 훈련 등이 포함됩니다. 수면 위생 개선(규칙적인 수면 시간, 침실 환경 최적화, 카페인 제한), 광 치료, 운동 요법도 보조 치료로 활용됩니다. 멜라토닌 제제가 일부 수면 장애에 사용될 수 있으나, 적합한 치료 선택을 위해 수면의학 전문의 상담을 받으시기 바랍니다.', 1100, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '신경성 폭식증', '신경성폭식증', 'MEDICATION', '신경성 폭식증 치료에 사용되는 항우울제(SSRI, 특히 플루옥세틴)는 오심, 두통, 수면 장애, 성기능 이상, 초기 불안 증가 등의 부작용이 있을 수 있습니다. 폭식 행동과 관련된 전해질 불균형(저칼륨혈증 등)이 있는 경우 일부 약물의 심장 부작용 위험이 증가할 수 있으므로 정기적인 혈액 검사가 필요합니다. 약물 복용 전 반드시 정신건강의학과 전문의의 처방과 지도하에 사용하시기 바랍니다.', 1101, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '신경성 폭식증', '신경성폭식증', 'CAUSE', '신경성 폭식증의 원인은 호르몬 이상 외에도 심리적 요인(낮은 자존감, 완벽주의, 충동 조절 어려움), 사회문화적 압박(날씬함에 대한 이상화), 유전적 소인, 어린 시절 트라우마나 학대 경험, 불안·우울 등 공존 정신 질환이 복합적으로 작용합니다. 세로토닌 등 신경전달물질 불균형도 폭식 충동과 관련이 있는 것으로 알려져 있습니다. 정확한 원인 평가를 위해 정신건강의학과 전문의 진료를 권고합니다.', 1102, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '신경성 폭식증', '신경성폭식증', 'DEFINITION', '신경성 폭식증은 짧은 시간 내 대량의 음식을 섭취하는 폭식 삽화와, 이를 보상하기 위한 구토·하제·이뇨제 남용·과도한 운동 등의 제거 행동이 반복되는 섭식 장애입니다. 폭식 시 음식 조절 불가능감을 경험하며, 이후 죄책감·수치심이 동반됩니다. 반복적인 구토는 치아 부식, 전해질 불균형, 식도 손상 등 심각한 신체 합병증을 초래할 수 있으므로 전문 치료가 필요합니다.', 1103, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '신경성 폭식증', '신경성폭식증', 'SYMPTOM', '반복적인 폭식과 구토는 저칼륨혈증(심부정맥 위험), 식도염·식도 파열, 침샘 비대, 치아 부식, 만성 위장 장애 등의 신체 증상을 유발합니다. 심리적으로는 우울증, 불안, 충동 조절 어려움이 악화되고 자존감이 현저히 저하될 수 있습니다. 이러한 증상이 있다면 정신건강의학과 전문의에게 즉시 진료를 받으시기 바랍니다.', 1104, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '신경성 폭식증', '신경성폭식증', 'DIAGNOSIS', '신경성 폭식증은 DSM-5 기준에 따라 주 1회 이상의 폭식과 보상 행동이 3개월 이상 지속되고, 자기 평가가 체형·체중에 과도하게 영향을 받는 경우 진단됩니다. 진단 과정에서는 정신건강의학과 임상 면담, 식이 행동 및 심리 평가, 신체 합병증 확인을 위한 혈액 검사와 신체 검진이 이루어집니다. 정확한 진단을 위해 정신건강의학과 전문의를 방문하시기 바랍니다.', 1105, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '신경성 폭식증', '신경성폭식증', 'TREATMENT', '신경성 폭식증은 심리적 요인이 핵심 원인이므로 인지행동치료(CBT)를 중심으로 한 정신과적 치료가 필수적입니다. CBT를 통해 폭식을 유발하는 왜곡된 인지 패턴과 부적응적 식이 행동을 교정하며, 항우울제(SSRI) 병용 시 폭식 빈도 감소와 심리 증상 호전을 기대할 수 있습니다. 치료를 통해 재발률 감소, 자존감 향상, 정상적인 식이 패턴 회복의 효과를 기대할 수 있습니다.', 1106, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '실어증', '실어증', 'CHECKUP', '충격이나 심리적 외상으로 인한 실어증 의심 증상을 확인하려면 신경과, 재활의학과, 또는 언어치료실이 있는 종합병원을 방문하시기 바랍니다. 언어 기능 평가를 위한 표준화된 실어증 검사(K-WAB 등)와 뇌 MRI·CT 검사를 통해 기질적 원인을 확인합니다. 심인성 언어 장애가 의심되는 경우 정신건강의학과와의 협진도 필요할 수 있습니다.', 1107, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '실어증', '실어증', 'PREVENTION', '치매 환자에서 말수가 줄어드는 것은 언어 능력 저하의 자연스러운 경과일 수 있으나, 적극적인 언어 자극이 진행을 늦추는 데 도움이 됩니다. 예방을 위해 매일 규칙적인 대화 참여, 독서·노래 등 언어 활동, 언어 치료사의 정기적인 언어 재활 치료가 권장됩니다. 치매 치료 중인 경우 신경과 또는 재활의학과 전문의와 협력하여 언어 기능 유지를 위한 계획을 세우시기 바랍니다.', 1108, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '실어증', '실어증', 'CAUSE', '실어증의 주요 원인은 뇌졸중(허혈성·출혈성)이 가장 흔하며, 뇌종양, 두부 외상, 뇌염, 퇴행성 뇌 질환(치매)도 원인이 됩니다. 좌반구 언어 영역(브로카 영역, 베르니케 영역 등)의 손상이 실어증을 일으키며, 손상 부위에 따라 실어증의 유형과 심각도가 다르게 나타납니다. 뇌졸중이 가장 빠른 회복과 예방이 가능한 원인이므로 조기 발견과 치료가 중요합니다.', 1109, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '실어증', '실어증', 'REHAB', '실어증 재활은 언어 치료사에 의한 언어 재활(언어 표현·이해 훈련)이 핵심이며, 이 외에 뇌졸중 등으로 인한 운동 장애가 동반된 경우 물리 치료(운동 기능 회복)와 작업 치료(일상생활 기능 향상)가 함께 시행됩니다. 음악 치료(멜로디 억양 치료)가 비유창성 실어증 환자의 언어 표현 개선에 보조적으로 활용되기도 합니다. 재활 계획은 재활의학과 전문의와 다학제 팀의 평가를 통해 수립됩니다.', 1110, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '실어증', '실어증', 'DEFINITION', '실어증은 주로 뇌 손상으로 인한 후천적 언어 장애로, 5세 아동의 언어 발달 지연은 실어증보다 언어 발달 장애, 자폐 스펙트럼 장애, 청력 문제 등을 먼저 고려해야 합니다. 실어증은 정상 발달 후 뇌 손상 등으로 갑자기 언어 기능을 잃는 것이 특징으로, 발달 과정에서의 언어 지연과는 구별됩니다. 아이의 언어 문제는 소아청소년과 또는 소아 발달 전문가의 평가를 받으시기 바랍니다.', 1111, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '실어증', '실어증', 'SYMPTOM', '말을 제대로 하지 못하고 표현력이 현저히 감소한 경우 실어증 가능성이 있으며, 특히 고령에서 갑자기 발생했다면 뇌졸중에 의한 실어증을 우선 의심해야 합니다. 실어증은 말하기, 이해하기, 읽기, 쓰기 능력의 저하를 포함하며, 손상된 뇌 부위에 따라 유창성 여부가 다르게 나타납니다. 관련 증상이 있다면 즉시 신경과 전문의 진료와 뇌 영상 검사를 받으시기 바랍니다.', 1112, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '실어증', '실어증', 'DIAGNOSIS', '말 더듬기, 단어가 갑자기 생각나지 않는 증상에 대해 신경과에서 뇌 MRI·CT, 언어 기능 평가를 통해 기질적 원인(뇌졸중, 종양 등)을 먼저 확인합니다. 언어 기능 검사로는 표준화된 실어증 검사(K-WAB, 보스턴 실어증 진단 검사 등)가 사용됩니다. 말 더듬기가 어린 시절부터 지속된 경우라면 언어 치료사의 유창성 장애 평가가 필요합니다.', 1113, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '실어증', '실어증', 'TREATMENT', '심리적 충격이나 극심한 스트레스로 인한 실어증(기능성/심인성 실어증)의 치료는 언어 치료와 함께 정신건강의학과의 심리 치료(인지행동치료, 지지 치료)가 병행됩니다. 외상 후 스트레스 장애(PTSD)나 해리 장애가 동반된 경우 이에 대한 치료가 언어 기능 회복에도 중요합니다. 기질적 원인 배제 후 심인성 실어증으로 판단되면 신경과와 정신건강의학과의 협진 치료를 받으시기 바랍니다.', 1114, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '안면 마비', '안면마비', 'MEDICATION', '안면 마비(벨 마비)의 약물 치료로는 부종 완화를 위한 스테로이드(prednisolone)와 단순 헤르페스 바이러스 관련 시 항바이러스제가 초기에 사용됩니다. 약물 치료 후에도 회복이 불완전한 경우 물리 치료, 침 치료, 안면 근육 재훈련 운동 등 추가 치료가 필요할 수 있습니다. 안면 마비 증상 발생 시 가능한 빨리 신경과 또는 이비인후과 전문의 진료를 받으시기 바랍니다.', 1115, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '안면 마비', '안면마비', 'PREVENTION', '안면 마비의 완전한 예방은 어렵지만, 면역력 저하(과로, 스트레스, 수면 부족)가 주요 유발 요인이므로 규칙적인 수면과 과로 피하기가 중요합니다. 얼굴을 찬바람에 장시간 노출하지 않도록 하고, 헤르페스 바이러스 재활성화를 방지하기 위한 면역 관리가 도움이 됩니다. 뇌졸중 예방을 위한 고혈압·당뇨·고지혈증 관리도 중추성 안면 마비 예방에 중요합니다.', 1116, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '안면 마비', '안면마비', 'CAUSE', '과도한 음주는 신경 독성과 영양 결핍(비타민 B1 등)을 유발하여 신경 손상의 위험을 높이고, 흡연은 혈관 수축과 동맥경화를 촉진하여 뇌졸중 관련 안면 마비의 위험 요인이 됩니다. 이러한 환경적 요인이 직접적인 원인인지 확인하기 위해 신경과 전문의 진료와 검사가 필요합니다. 금주·금연과 함께 건강한 생활 습관 유지가 안면 마비 재발 예방에 도움이 됩니다.', 1117, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '안면 마비', '안면마비', 'DEFINITION', '안면 마비는 얼굴 한쪽을 지배하는 안면 신경(7번 뇌신경)의 기능 장애로, 해당 부위 근육의 부분적 또는 완전한 마비가 나타나는 상태입니다. 가장 흔한 원인은 벨 마비(특발성 안면 신경 마비)로, 스트레스·면역력 저하와 관련이 있으며, 뇌졸중에 의한 중추성 안면 마비와의 감별이 중요합니다. 증상이 있다면 즉시 신경과 또는 응급실에서 진료를 받으시기 바랍니다.', 1118, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '안면 마비', '안면마비', 'SYMPTOM', '안면 마비의 전조 증상으로는 귀 뒤 통증, 귀 주변 불편감, 얼굴 한쪽의 가벼운 감각 이상이 나타날 수 있습니다. 본격적인 증상으로는 눈이 완전히 감기지 않음, 입이 한쪽으로 돌아감, 이마 주름 소실, 음식물이 한쪽으로 흘러내림, 미각 변화 등이 나타납니다. 이러한 증상이 갑자기 발생하면 뇌졸중 등 중증 원인을 배제하기 위해 즉시 전문의 진료를 받으시기 바랍니다.', 1119, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '안면 마비', '안면마비', 'DIAGNOSIS', '자고 일어난 후 얼굴 표정이 굳어지는 것은 벨 마비(안면 신경 마비)의 전형적인 발현 양상으로 초기 증상에 해당할 수 있습니다. 벨 마비는 수 시간에서 하루 이틀에 걸쳐 증상이 완성되며, 눈 감기 어려움, 이마 주름 소실, 입 돌아감 등이 동반됩니다. 중추성 마비(뇌졸중)와의 감별을 위해 즉시 신경과 또는 응급실에서 진료를 받으시기 바랍니다.', 1120, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '안면 마비', '안면마비', 'TREATMENT', '안면 마비로 인한 입 한쪽 마비 완화를 위해 스테로이드 약물 치료, 안면 근육 재훈련 운동(표정 근육 반복 훈련), 전기 자극 치료, 침 치료 등이 사용됩니다. 눈이 완전히 감기지 않는 경우 각막 보호를 위해 인공 눈물 점안과 취침 시 안대 착용이 필요합니다. 마비가 6개월 이상 지속된다면 수술적 치료를 고려할 수 있으므로 신경과 또는 성형외과 전문의와 상담하시기 바랍니다.', 1121, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알츠하이머병', '알츠하이머병', 'CAUSE', '나이는 알츠하이머병의 가장 강력한 위험 요인으로, 65세 이후 5년마다 발병률이 약 2배씩 증가합니다. 연령 증가에 따른 아밀로이드 베타 단백질 축적과 신경 세포 손실이 알츠하이머 병태 생리와 밀접하게 연관되어 있습니다. 유전적 요인(APOE-ε4 유전자), 고혈압·당뇨·비만 등 혈관 위험 인자 관리가 예방 전략으로 중요합니다.', 1122, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알츠하이머병', '알츠하이머병', 'DEFINITION', '알츠하이머병은 뇌에 아밀로이드 베타 플라크와 타우 단백질 엉킴이 축적되어 신경 세포가 서서히 손상·소멸되는 퇴행성 뇌 질환으로, 치매의 가장 흔한 원인입니다. 초기에는 단기 기억력 저하로 시작하여 언어, 판단력, 방향 감각 등 다양한 인지 기능이 점진적으로 저하됩니다. 진단은 신경과에서 신경심리 검사, 뇌 MRI·PET, 혈액 검사 등을 통해 이루어집니다.', 1123, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알츠하이머병', '알츠하이머병', 'SYMPTOM', '기억력 감퇴와 단어가 잘 떠오르지 않는 증상은 알츠하이머병을 포함한 치매의 초기 증상으로 나타날 수 있으며, 이 두 증상은 밀접한 관련이 있습니다. 알츠하이머병에서는 해마 부위의 손상으로 새로운 정보를 저장하고 인출하는 능력이 저하되어 이러한 증상이 발생합니다. 다만 노화에 따른 정상적인 기억력 변화와의 감별이 필요하므로 신경과 전문의 진료를 받으시기 바랍니다.', 1124, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알츠하이머병', '알츠하이머병', 'DIAGNOSIS', '알츠하이머병 진단을 위해 신경심리 검사(MMSE, MoCA 등), 뇌 MRI·CT, 뇌 아밀로이드 PET, 뇌척수액 바이오마커 검사, 혈액 검사(갑상선 기능, 비타민 B12 등) 등이 시행됩니다. 중증도는 CDR(임상 치매 척도) 또는 GDS(전반적 퇴화 척도)를 사용하여 경도·중등도·중증으로 분류하며, 인지 기능 저하 정도와 일상생활 능력을 기준으로 판정합니다. 정확한 진단과 중증도 평가를 위해 신경과 전문의 진료를 받으시기 바랍니다.', 1125, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알츠하이머병', '알츠하이머병', 'TREATMENT', '알츠하이머병 치료에는 콜린에스테라제 억제제(도네페질, 리바스티그민, 갈란타민)가 경도~중등도에, NMDA 수용체 길항제(메만틴)가 중등도~중증에 사용되어 인지 기능 저하 속도를 늦춥니다. 2023년 이후 아밀로이드 제거를 목표로 하는 항아밀로이드 항체 치료제(레카네맙 등)가 초기 알츠하이머에 승인되어 사용되고 있습니다. 이들 약물은 병의 진행을 완전히 막지는 못하므로 조기 진단과 조기 치료 시작이 중요합니다.', 1126, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알코올 의존성', '알코올의존성', 'CAUSE', '알코올 의존성의 원인은 유전적 소인(가족력), 심리적 요인(우울증, 불안, 스트레스 대처 방식), 사회적 요인(음주 문화, 또래 압력), 뇌의 보상 회로에서 도파민 시스템의 변화 등이 복합적으로 작용합니다. 반복적인 음주로 내성이 생기고 금단 증상이 나타나면서 더욱 의존하게 되는 악순환이 형성됩니다. 알코올 의존성이 의심된다면 정신건강의학과 또는 알코올 전문 치료 기관에서 진료를 받으시기 바랍니다.', 1127, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알코올 의존성', '알코올의존성', 'DEFINITION', '알코올 의존성(알코올 사용 장애)은 알코올에 대한 강한 갈망과 조절 능력 상실, 신체적 내성 및 금단 증상을 특징으로 하는 만성 뇌 질환으로, 단순한 의지의 문제가 아닙니다. 지속적인 음주로 인한 신체적·정신적 문제가 있음에도 음주를 지속하는 것이 핵심 특징입니다. 알코올 의존성은 치료 가능한 질환이므로 정신건강의학과 또는 알코올 전문 기관에서 전문적 치료를 받으시기 바랍니다.', 1128, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알코올 의존성', '알코올의존성', 'SYMPTOM', '하루 한 병씩 정기적으로 음주하면서 손 떨림과 불안감이 동반된다면 알코올 의존성(알코올 사용 장애)의 가능성이 높습니다. 특히 음주를 중단하거나 줄일 때 손 떨림, 불안, 발한이 나타나는 것은 알코올 금단 증상으로 의존성의 중요한 징표입니다. 이러한 증상이 있다면 정신건강의학과 또는 중독 전문 기관에서 즉시 진료를 받으시기 바랍니다.', 1129, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알코올 의존성', '알코올의존성', 'DIAGNOSIS', '알코올 의존성 평가에는 AUDIT(알코올 사용 장애 선별 검사), CAGE 설문 등 표준화된 선별 도구가 사용되며, 음주 빈도·음주량·조절 능력·금단 증상·사회적 기능 저하 여부를 종합적으로 평가합니다. 임상적으로는 1주일 이상의 음주 일지 작성과 혈액 검사(GGT, AST, ALT 등 간 기능 지표)도 진단에 활용됩니다. 정확한 평가를 위해 정신건강의학과 전문의 진료를 받으시기 바랍니다.', 1130, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알코올 의존성', '알코올의존성', 'TREATMENT', '알코올 의존성 치료에서 항갈망제(날트렉손, 아캄프로세이트)와 혐오 요법제(디설피람)가 사용됩니다. 디설피람은 음주 시 아세트알데히드 분해를 억제하여 심한 불쾌 반응(구역, 홍조, 심계항진)을 유발함으로써 음주 욕구를 줄이는 방식으로 작용합니다. 약물 치료는 금주 의지와 심리 치료·지지 그룹(AA 등)과 병행해야 효과적이며, 반드시 전문의의 감독하에 진행하시기 바랍니다.', 1131, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알코올성 치매', '알코올성치매', 'CHECKUP', '알코올성 치매가 의심된다면 신경과 또는 정신건강의학과에서 개인 신경 검진과 인지 기능 평가를 받을 수 있습니다. 가족 중에 알코올성 치매 환자가 있더라도 본인이나 다른 가족 구성원이 별도로 검진을 받는 것이 가능하며, 위험 요인이 있다면 예방적 검진이 권장됩니다. 알코올성 치매 관련 진료는 종합병원의 신경과, 정신건강의학과 또는 치매 안심 센터를 이용하시기 바랍니다.', 1132, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알코올성 치매', '알코올성치매', 'PREVENTION', '알코올성 치매의 가장 효과적인 예방법은 금주 또는 절주이며, 특정 약물이 알코올성 치매를 직접적으로 예방한다는 근거는 제한적입니다. 알코올성 치매와 관련된 티아민(비타민 B1) 결핍을 보충하기 위해 티아민 제제가 사용될 수 있으나, 이는 예방보다 치료적 목적입니다. 알코올성 치매 예방을 위한 약물 선택은 전문의와 상담 후 결정하시기 바랍니다.', 1133, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알코올성 치매', '알코올성치매', 'CAUSE', '알코올성 치매는 음주량과 음주 기간에 비례하여 위험도가 높아지며, 다량·장기 음주자에서 증상이 더 심각하게 나타날 수 있습니다. 알코올에 의한 신경 독성과 티아민 결핍이 누적될수록 뇌 손상이 심해져 인지 기능 저하가 가속화됩니다. 이미 증상이 있다면 즉각적인 금주와 함께 신경과 전문의의 진료를 받으시기 바랍니다.', 1134, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알코올성 치매', '알코올성치매', 'DEFINITION', '알코올성 치매는 장기적인 과도한 음주로 인한 뇌 손상과 티아민(비타민 B1) 결핍으로 발생하는 인지 기능 저하 질환으로, 알코올 의존성이 선행 원인이 될 수 있으나 두 질환은 구별됩니다. 알코올 의존성은 알코올에 대한 신체적·심리적 의존 상태이며, 이것이 지속될 경우 알코올성 치매로 진행될 수 있습니다. 두 질환 모두 전문적인 치료가 필요하므로 정신건강의학과 또는 신경과 전문의 진료를 받으시기 바랍니다.', 1135, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알코올성 치매', '알코올성치매', 'SYMPTOM', '알코올성 치매 환자에서는 기억력 저하(최근 사건 기억 어려움), 시간·장소·사람 지남력 장애, 판단력 저하, 성격 및 행동 변화(충동성, 공격성, 무기력), 보행 장애, 작화증(없는 일을 실제처럼 말함) 등이 나타날 수 있습니다. 평소와 다른 이상 행동(과도한 의심, 환각, 극단적인 기분 변화)도 나타날 수 있으며, 이는 알코올성 치매의 진행을 시사합니다. 이러한 증상이 나타난다면 신경과 전문의 진료를 받으시기 바랍니다.', 1136, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알코올성 치매', '알코올성치매', 'DIAGNOSIS', '알코올성 치매 진단을 위해 신경과 또는 정신건강의학과에서 신경심리 검사(인지 기능 평가), 뇌 MRI, 혈액 검사(티아민, 간 기능, 영양 상태), 음주력 평가 등이 시행됩니다. 알코올성 치매와 다른 원인의 치매, 베르니케-코르사코프 증후군 등과의 감별 진단도 이루어집니다. 진단을 위해 신경과 또는 정신건강의학과 전문의를 방문하시기 바랍니다.', 1137, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '알코올성 치매', '알코올성치매', 'TREATMENT', '알코올성 치매 치료에서 금주가 가장 중요하며, 갑작스러운 금주는 심각한 금단 증상(경련, 섬망)을 유발할 수 있으므로 반드시 전문의의 감독하에 진행해야 합니다. 금주 지원을 위해 입원 치료, 약물 치료(날트렉손, 아캄프로세이트), 동기 강화 상담, 자조 모임(단주 모임)이 활용됩니다. 술을 끊기 어렵다면 정신건강의학과 또는 알코올 전문 치료 기관에 도움을 요청하시기 바랍니다.', 1138, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '양극성 장애', '양극성장애', 'MEDICATION', '양극성 장애 약물(기분 안정제, 항정신병약, 항우울제 등)은 복잡한 상호작용이 있어 잘못된 약물 조합은 조증 삽화 유발, 혼재성 삽화 악화, 부작용 증가 등의 위험이 있습니다. 예를 들어 항우울제 단독 사용은 조증 전환 위험이 있으며, 약물 간 대사 상호작용으로 혈중 농도가 변할 수 있습니다. 약물 상호작용 이해는 치료 효과를 극대화하고 부작용을 최소화하기 위해 필수적이므로 반드시 전문의와 상담하시기 바랍니다.', 1139, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '양극성 장애', '양극성장애', 'PREVENTION', '스트레스는 양극성 장애에서 삽화 재발과 증상 악화의 주요 촉발 요인으로 알려져 있습니다. 스트레스 관리를 위해 규칙적인 수면 패턴 유지(수면 부족이 조증 유발 가능), 규칙적인 운동, 마음 챙김(mindfulness) 명상, 인지행동치료를 통한 스트레스 대처 기술 향상이 권장됩니다. 스트레스 관리 계획은 정신건강의학과 전문의와 함께 수립하시기 바랍니다.', 1140, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '양극성 장애', '양극성장애', 'CAUSE', '부모의 이혼은 아동에게 심리적 외상과 스트레스를 유발할 수 있는 환경적 요인이지만, 양극성 장애의 주요 원인은 유전적 소인과 신경생물학적 요인입니다. 외상적 경험과 만성 스트레스는 유전적으로 취약한 개인에서 양극성 장애 발현을 촉진하는 촉발 요인으로 작용할 수 있습니다. 정확한 진단과 원인 평가를 위해 소아청소년 정신건강의학과 전문의의 지속적인 진료가 필요합니다.', 1141, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '양극성 장애', '양극성장애', 'DEFINITION', '양극성 장애는 비정상적으로 고양된 조증 삽화와 우울 삽화가 교대로 나타나는 만성 기분 장애로, 스트레스 상황이 삽화를 촉발할 수 있지만 스트레스만으로 발생하는 일시적 기분 변화와는 구별됩니다. 발생 원인으로는 유전적 소인, 도파민·세로토닌 등 신경전달물질 불균형, 뇌 구조적 이상이 복합적으로 작용합니다. 정확한 진단을 위해 정신건강의학과 전문의 상담을 받으시기 바랍니다.', 1142, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '양극성 장애', '양극성장애', 'SYMPTOM', '양극성 장애는 하루 이내에 기분이 오르내리는 것(기분 반응성)보다는 수 일에서 수 주 이상 지속되는 조증 또는 우울 삽화가 특징입니다. 하루에 여러 번 기분이 급격하게 변한다면 양극성 장애보다 경계성 인격 장애, 감정 조절 장애, 혼재성 삽화 등을 고려해야 합니다. 정확한 진단을 위해 정신건강의학과 전문의의 임상 평가를 받으시기 바랍니다.', 1143, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '양극성 장애', '양극성장애', 'DIAGNOSIS', '양극성 장애에서 기분 삽화는 수면 부족, 심한 스트레스, 계절 변화, 음주 및 약물 남용, 항우울제 단독 사용 등에 의해 촉발될 수 있습니다. 또한 생활 리듬의 급격한 변화(시차, 교대 근무, 불규칙한 수면)도 삽화 발생과 관련이 있습니다. 이러한 촉발 요인을 파악하고 관리하는 것이 재발 예방에 중요하며, 정신건강의학과 전문의와 함께 계획을 세우시기 바랍니다.', 1144, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '양극성 장애', '양극성장애', 'TREATMENT', '양극성 장애 치료에서 기분 안정제(리튬, 발프로에이트) 및 항정신병약 등 약물 치료가 삽화 예방과 증상 조절에 필수적이며, 정신치료(인지행동치료, 가족 중심 치료)는 복약 순응도 향상, 촉발 요인 인식, 사회·직업 기능 회복에 도움을 줍니다. 약물 치료는 빠른 증상 조절에 효과적이나 단독으로는 장기적 기능 회복에 한계가 있어 정신치료와의 병행이 권장됩니다. 최적의 치료 계획 수립을 위해 정신건강의학과 전문의와 상담하시기 바랍니다.', 1145, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '외상 후 스트레스 장애', '외상후스트레스장애', 'CHECKUP', 'PTSD 진단은 정신건강의학과 또는 정신건강 전문 의료 기관에서 받을 수 있으며, 종합병원 정신건강의학과, 정신건강 복지 센터, 국가 트라우마 센터 등이 적합합니다. 군 관련 외상이라면 보훈 병원, 성폭력 피해라면 해바라기 센터, 재난 피해라면 국립 정신 건강 센터를 이용할 수 있습니다. PTSD는 전문적인 심리 치료와 약물 치료가 필요하므로 조기에 전문기관을 방문하시기 바랍니다.', 1146, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '외상 후 스트레스 장애', '외상후스트레스장애', 'MEDICATION', 'PTSD 약물 치료로는 SSRI(세르트랄린, 파록세틴)가 FDA 승인을 받은 1차 약물로 가장 근거가 확립되어 있으며, 침입 증상, 회피, 과각성 증상 전반에 효과적입니다. SNRI(벤라팍신)도 효과적인 대안으로 사용되며, 악몽과 수면 장애에는 프라조신이 보조적으로 활용됩니다. 최적의 약물 선택은 개인의 증상 프로파일과 부작용을 고려하여 정신건강의학과 전문의와 함께 결정하시기 바랍니다.', 1147, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '외상 후 스트레스 장애', '외상후스트레스장애', 'PREVENTION', '명상과 마음 챙김 훈련은 외상 관련 과각성 상태를 진정시키고 현재 순간에 집중하도록 도와 PTSD 예방과 증상 완화에 도움이 됩니다. 점진적 근육 이완법과 횡격막 호흡(복식 호흡)은 교감신경계 과활성화를 억제하여 신체적 긴장과 불안을 완화합니다. 이러한 자기 조절 기술은 전문 치료(EMDR, 인지처리치료)의 보완적 수단으로 활용되며, 증상이 있다면 전문의 상담을 병행하시기 바랍니다.', 1148, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '외상 후 스트레스 장애', '외상후스트레스장애', 'EXERCISE', 'PTSD 환자에게 권장되는 운동으로는 규칙적인 유산소 운동(걷기, 달리기, 수영)이 코르티솔 조절과 세로토닌·엔도르핀 분비를 촉진하여 스트레스와 우울·불안 증상 완화에 효과적입니다. 요가는 신체 인식과 이완을 통해 외상과 관련된 신체적 각성 반응을 줄이는 데 도움이 됩니다. 운동 프로그램은 안전하고 통제된 환경에서 시작하며, 외상 기억을 자극하는 환경은 피하는 것이 좋습니다.', 1149, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '외상 후 스트레스 장애', '외상후스트레스장애', 'CAUSE', 'PTSD의 원인이 되는 외상적 사건으로는 전쟁·전투 경험, 성폭력·신체 폭행, 심각한 교통사고, 자연재해, 테러, 아동 학대, 사랑하는 사람의 갑작스러운 죽음 목격 등이 있습니다. 이러한 외부 요인은 공포, 무력감, 극심한 공포 반응을 유발하며 뇌의 편도체·해마·전전두엽의 기능 이상을 초래합니다. 동일한 외상에 노출되어도 개인의 취약성, 사회적 지지 체계에 따라 PTSD 발생 여부가 달라질 수 있습니다.', 1150, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '외상 후 스트레스 장애', '외상후스트레스장애', 'REHAB', 'PTSD는 외상 사건으로 인해 뇌의 스트레스 반응 체계가 과활성화되어 지속적인 고통이 유발되므로 전문적 심리 지원이 필수적입니다. 외상 기억은 자연스럽게 통합되지 않고 반복적으로 침습하기 때문에, 인지행동치료(CBT)나 EMDR 같은 전문 치료를 통해 기억을 재처리하고 신경계를 안정시켜야 합니다. 정신건강의학과 전문의 또는 심리치료사와의 상담을 권고드립니다.', 1151, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '외상 후 스트레스 장애', '외상후스트레스장애', 'DEFINITION', '외상 후 스트레스 장애(PTSD)는 생명을 위협하는 충격적 사건을 경험하거나 목격한 후 발생하는 정신건강 질환으로, 사건 후 1개월 이상 증상이 지속될 때 진단합니다. 주요 증상으로는 외상 기억의 반복적 침습(플래시백), 악몽, 사건 관련 자극 회피, 감각 마비, 과각성(수면 장애·과도한 경계) 등이 있습니다. 정확한 진단과 치료를 위해 정신건강의학과 전문의 상담을 권고드립니다.', 1152, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '외상 후 스트레스 장애', '외상후스트레스장애', 'SYMPTOM', '교통사고 후 운전 공포는 PTSD의 회피 및 과각성 증상으로, 운전 시도 시 심박수 증가·발한·근육 긴장·호흡 곤란 등의 자율신경계 반응이 나타납니다. 사고 장면이 생생하게 떠오르는 플래시백과 함께 공황 발작이 동반되기도 하며, 지속적인 회피로 인해 일상생활 기능이 저하될 수 있습니다. 이러한 증상이 지속된다면 정신건강의학과 전문의 상담을 권고드립니다.', 1153, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '외상 후 스트레스 장애', '외상후스트레스장애', 'DIAGNOSIS', '교통사고 후 지속적인 외상 기억 문제가 있다면 정신건강의학과 전문의를 통한 구조화된 임상 면담이 가장 효과적인 진단 방법입니다. DSM-5 기준에 따라 침습 증상, 회피, 인지·감정 변화, 과각성 증상을 4주 이상 평가하며, PCL-5 등의 표준화된 자가보고 척도도 보조적으로 활용됩니다. 증상이 의심된다면 조기에 정신건강의학과를 방문하시길 권고드립니다.', 1154, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '외상 후 스트레스 장애', '외상후스트레스장애', 'TREATMENT', 'PTSD 치료에서 인지처리치료(CPT), 지속노출치료(PE), EMDR 등의 심리치료가 1차 치료로 권고되며, 외상 기억 재처리에 가장 근본적인 효과를 보입니다. 약물치료(SSRI 계열 항우울제)는 불안·우울·수면 장애 증상 완화에 도움이 되며, 심리치료와 병행 시 치료 효과가 높아집니다. 환자 상태에 따라 최적의 치료 계획은 정신건강의학과 전문의와 상담하여 결정하시길 권고드립니다.', 1155, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '우울증', '우울증', 'MEDICATION', '산후 우울증 치료에는 일반적인 우울증 치료에 사용되는 SSRI(선택적 세로토닌 재흡수 억제제) 계열 약물이 동일하게 사용됩니다. 성분이 동일한 약물로는 세르트랄린(졸로푸트), 에스시탈로프람(렉사프로) 등이 있으며, 수유 중에도 비교적 안전한 것으로 알려져 있습니다. 그러나 모유 수유 여부와 개인 상태에 따라 처방이 달라지므로 반드시 정신건강의학과 전문의와 상담 후 복용하십시오.', 1156, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '우울증', '우울증', 'CAUSE', '우울증은 단일 원인이 아닌 신체적·정신적·사회환경적 요인이 복합적으로 작용하여 발생합니다. 신체적 요인으로는 세로토닌·노르에피네프린 등 신경전달물질 불균형, 유전적 소인, 만성 질환 등이 있으며, 정신적 요인으로는 부정적 사고 패턴, 심리적 외상, 스트레스 등이 있습니다. 두 요인은 상호작용하므로 어느 하나가 더 주된 원인이라기보다 개인마다 다르며, 전문의 평가를 통해 원인을 파악하는 것이 중요합니다.', 1157, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '우울증', '우울증', 'DEFINITION', '산욕기(출산 후 6주)에 나타나는 우울한 기분, 불안감, 불면, 의욕 저하, 죄책감은 산후 우울증의 전형적인 증상에 해당합니다. 산후 우울증은 호르몬 급격한 변화, 수면 부족, 양육 스트레스 등이 복합적으로 작용하여 발생하며, 출산 여성의 10~15%에서 나타납니다. 증상이 2주 이상 지속되거나 일상생활에 지장을 준다면 정신건강의학과 전문의 상담을 권고드립니다.', 1158, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '우울증', '우울증', 'SYMPTOM', '월경 전 긴장, 초조, 우울, 불안 증상은 월경전증후군(PMS) 또는 더 심한 경우 월경전불쾌장애(PMDD)와 관련이 있을 수 있습니다. PMS는 황체기(배란 후~월경 전)에 에스트로겐·프로게스테론 변화로 인해 발생하며, 증상이 월경 시작과 함께 호전되는 패턴이 특징입니다. 증상이 일상생활에 지장을 줄 정도로 심하다면 산부인과 또는 정신건강의학과 전문의 상담을 권고드립니다.', 1159, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '우울증', '우울증', 'DIAGNOSIS', '우울감, 무기력감, 감정 기복 증상이 있다면 정신건강의학과(신경정신과), 신경과, 또는 정신건강증진센터에서 진단받을 수 있습니다. 전국 정신건강복지센터(1577-0199)를 통해 가까운 기관을 안내받을 수 있으며, 보건소에서도 우울증 선별 검사를 무료로 제공합니다. 증상이 2주 이상 지속된다면 빠른 시일 내에 전문의 상담을 받으시길 권고드립니다.', 1160, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '우울증', '우울증', 'TREATMENT', '비만, 고혈압, 우울증, 골다공증이 동반된 쿠싱 증후군이 의심된다면 우선 내분비내과 전문의를 찾아야 합니다. 쿠싱 증후군은 코르티솔 과다 분비로 인한 질환으로, 내분비내과에서 호르몬 검사 및 영상 검사를 통해 원인을 파악하고 치료 방향을 결정합니다. 동반 증상에 따라 정신건강의학과, 심장내과 등 다학제적 접근이 필요할 수 있으므로 전문의와 상담하시길 권고드립니다.', 1161, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '인터넷 중독', '인터넷중독', 'MEDICATION', '인터넷 중독 치료에서 우울감, 불안, 스트레스, 소외감 완화를 위해 SSRI 계열 항우울제(세르트랄린, 에스시탈로프람 등)와 항불안제가 사용될 수 있습니다. 이 약물들은 뇌 내 세로토닌 수치를 조절하여 기분 안정과 충동 조절에 도움을 줍니다. 다만 약물 치료는 반드시 정신건강의학과 전문의의 처방에 따라 이루어져야 하며, 인지행동치료와 병행하는 것이 더 효과적입니다.', 1162, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '인터넷 중독', '인터넷중독', 'PREVENTION', '하루 인터넷 사용 시간을 2시간으로 제한하는 것은 중독 예방에 도움이 되는 좋은 접근입니다. 단순한 시간 제한 외에도 사용 목적 명확화, 오프라인 활동 대체, 취침 1시간 전 기기 사용 중단 등의 습관을 함께 실천하면 더 효과적입니다. 특히 청소년의 경우 가족과 함께 규칙을 정하고 일관되게 적용하는 것이 중요하며, 조절이 어렵다면 전문가 상담을 권고드립니다.', 1163, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '인터넷 중독', '인터넷중독', 'CAUSE', '인터넷 중독의 원인으로는 개인적 요인(충동성, 낮은 자존감, 우울·불안 등 정신건강 문제), 환경적 요인(가정 내 갈등, 또래 관계 어려움, 학업 스트레스), 그리고 인터넷 자체의 특성(즉각적 보상, 익명성, 24시간 접근성)이 복합적으로 작용합니다. 이 중 심리적 취약성과 현실 도피 욕구가 중독 발전에 가장 큰 영향을 미치는 것으로 알려져 있습니다. 원인 파악과 치료를 위해 정신건강의학과 또는 중독전문 상담기관 방문을 권고드립니다.', 1164, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '인터넷 중독', '인터넷중독', 'DEFINITION', '인터넷 중독과 관련된 질환으로는 게임 중독(게임장애, ICD-11 등재), SNS 중독, 온라인 도박 중독, 음란물 중독 등이 있습니다. 이들은 강박적 사용, 조절 실패, 일상생활 기능 저하를 공통으로 보이며, 우울장애·불안장애·ADHD 등 정신건강 문제와 동반되는 경우가 많습니다. 증상이 의심될 경우 정신건강의학과 또는 인터넷 중독 예방상담센터(스마트쉼센터)에서 전문 상담을 받으시길 권고드립니다.', 1165, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '인터넷 중독', '인터넷중독', 'SYMPTOM', '인터넷 중독의 주요 증상으로는 사용 시간이 점점 증가하고 스스로 조절이 어려워지는 내성, 사용하지 못할 때 불안·짜증·우울이 나타나는 금단 증상, 학업·직장·대인관계 문제가 발생함에도 사용을 지속하는 강박적 집착이 있습니다. 수면 장애, 식사 불규칙, 신체 활동 감소 등 신체적 문제도 동반될 수 있습니다. 이러한 증상이 6개월 이상 지속된다면 전문가 상담을 권고드립니다.', 1166, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '인터넷 중독', '인터넷중독', 'DIAGNOSIS', '인터넷 중독 자가진단 10문항을 제시합니다. 1)인터넷을 하다 보면 계획한 시간보다 더 오래 사용하게 된다. 2)인터넷 사용을 줄이려 해도 잘 되지 않는다. 3)인터넷을 못 하면 불안하거나 짜증이 난다. 4)인터넷 때문에 숙제나 공부를 제때 하지 못한다. 5)가족이나 친구보다 인터넷 친구와 더 많은 시간을 보낸다. 6)인터넷을 하는 동안 식사나 수면을 건너뛴 적이 있다. 7)인터넷 사용 때문에 학교 성적이 떨어진 적이 있다. 8)인터넷 사용 문제로 부모님과 다툰 적이 있다. 9)인터넷을 하지 않을 때도 인터넷 생각이 자주 난다. 10)현실보다 인터넷 속 세상이 더 재미있고 편하다고 느낀다. 6개 이상 해당 시 전문가 상담을 권고드립니다.', 1167, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '인터넷 중독', '인터넷중독', 'TREATMENT', '인터넷 중독은 의지만으로 극복하기 어려운 경우가 많으나, 스스로 사용 시간 기록하기, 알람 설정, 특정 앱 삭제, 오프라인 취미 활동 늘리기 등의 자기조절 전략이 도움이 될 수 있습니다. 그러나 금단 증상이나 일상 기능 저하가 동반된다면 인지행동치료나 동기강화상담 등 전문적 치료가 필요합니다. 한국지능정보사회진흥원의 스마트쉼센터(0800-955-0-119)에서 무료 상담을 받으실 수 있습니다.', 1168, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '조현병', '조현병', 'DIET_LIFE', '규칙적인 식사와 균형 잡힌 영양 섭취는 조현병 치료약물의 대사 부작용(체중 증가, 혈당 이상)을 관리하는 데 도움이 됩니다. 규칙적인 수면, 금주·금연, 스트레스 관리, 적절한 신체 활동은 도파민 시스템 안정화에 기여하여 증상 악화와 재발 예방에 중요한 역할을 합니다. 약물 복용을 임의로 중단하지 않는 것이 가장 중요하며, 구체적인 생활 관리 방법은 정신건강의학과 전문의와 상담하시길 권고드립니다.', 1169, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '조현병', '조현병', 'MEDICATION', '조현병 치료 약물(항정신병약)은 주로 도파민 D2 수용체를 차단하여 망상·환청 등 양성 증상을 완화시킵니다. 2세대 약물은 세로토닌 5-HT2A 수용체도 함께 차단하여 음성 증상과 인지 기능 개선에도 도움을 줍니다. 약물을 임의로 중단하면 도파민 수용체가 과민해져 증상이 재발·악화될 수 있으므로, 반드시 정신건강의학과 전문의의 지시에 따라 복용을 유지하시길 권고드립니다.', 1170, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '조현병', '조현병', 'CAUSE', '일란성 쌍둥이 중 한 명이 조현병일 경우 다른 쌍둥이의 발병 일치율은 약 40~50%로, 이란성 쌍둥이(약 10~15%)보다 유의미하게 높습니다. 이는 유전적 요인이 조현병 발병에 중요한 역할을 함을 시사하지만, 일치율이 100%가 아닌 것은 환경적 요인도 발병에 영향을 미친다는 것을 의미합니다. 조현병의 발병은 유전적 취약성과 환경적 스트레스가 복합적으로 작용하는 것으로 이해되고 있습니다.', 1171, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '조현병', '조현병', 'DEFINITION', '조현병은 망상·환청·와해된 사고 등을 특징으로 하는 정신건강 질환이며, 조현병 환자 대부분은 폭력적이지 않습니다. 일부 연구에서 치료받지 않은 조현병 환자에서 충동 조절 어려움이 보고되지만, 범죄와 조현병을 직접 연결하는 것은 과학적 근거가 부족하고 편견을 강화할 수 있습니다. 조현병에 대한 정확한 이해와 편견 해소, 조기 치료 접근이 중요하며, 정신건강의학과 전문의와의 상담을 권고드립니다.', 1172, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '조현병', '조현병', 'SYMPTOM', '조현병의 망상·환청·와해된 행동이 진행되면 만성적 스트레스 반응으로 수면 장애, 식욕 감퇴, 체중 변화가 나타날 수 있습니다. 자기 돌봄 능력 저하로 위생 관리가 어려워지고, 운동 부족으로 심혈관 건강이 악화될 수 있습니다. 또한 항정신병약물의 부작용으로 추체외로 증상(근육 경직, 손 떨림), 체중 증가, 대사 증후군 등의 신체 변화가 동반될 수 있으므로 정기적인 신체 건강 모니터링이 필요합니다.', 1173, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '조현병', '조현병', 'DIAGNOSIS', '타인의 목소리가 자신의 목소리로 들리거나 없는 소리가 들리는 환청 증상은 조현병의 주요 증상 중 하나이므로, 지체 없이 정신건강의학과를 방문하여 전문의 진단을 받는 것이 필요합니다. 조기 발견과 치료가 예후에 결정적인 영향을 미치므로 증상 발현 초기에 전문적 평가를 받는 것이 매우 중요합니다. 증상이 갑자기 악화되거나 자해·타해 위험이 있는 경우에는 즉시 응급실을 방문하시기 바랍니다.', 1174, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '조현병', '조현병', 'TREATMENT', '조현병 치료에서 항정신병약물 복용을 임의로 중단하면 도파민 수용체의 과민성 증가로 인해 환청·망상 등 양성 증상이 재발하거나 이전보다 더 심하게 악화될 수 있습니다. 특히 재발이 반복될수록 약물 반응성이 저하되고 사회 기능 회복이 어려워집니다. 반드시 정신건강의학과 전문의와 상의 없이 약물을 중단하지 마시고, 부작용이 있을 경우 의사와 상담하여 약물 조정을 받으시길 권고드립니다.', 1175, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '자폐증 / 자폐 스펙트럼 장애', '자폐증/자폐스펙트럼장애', 'CHECKUP', '자폐 스펙트럼 장애(ASD) 진단은 소아청소년 정신건강의학과 또는 소아신경과 전문의에게서 받을 수 있습니다. 대형 병원의 발달장애 클리닉, 어린이병원, 발달장애인지원센터에서 표준화된 진단 도구(ADOS-2, ADI-R 등)를 활용한 정밀 평가가 이루어집니다. 발달 이상이 의심될 경우 빠른 시일 내에 소아청소년 정신건강의학과 전문의를 찾아 평가받으시길 권고드립니다.', 1176, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '자폐증 / 자폐 스펙트럼 장애', '자폐증/자폐스펙트럼장애', 'DIET_LIFE', '자폐 스펙트럼 장애 환자에서 글루텐·카제인 제거 식이 등 특별 식이요법이 일부에서 시도되지만, 현재까지 과학적으로 충분히 입증된 효과는 없습니다. 균형 잡힌 영양 섭취가 가장 중요하며, 감각 민감성으로 인한 편식이 심할 경우 특정 영양소 결핍에 주의해야 합니다. 식이 조절을 계획할 경우 소아과 또는 영양사와 상담하여 영양 불균형이 생기지 않도록 전문가의 지도하에 진행하시길 권고드립니다.', 1177, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '자폐증 / 자폐 스펙트럼 장애', '자폐증/자폐스펙트럼장애', 'MEDICATION', '자폐 스펙트럼 장애의 핵심 증상(사회적 의사소통 어려움, 반복 행동)에 효과적인 특이적 약물은 없으나, 동반 증상 조절을 위해 약물이 사용됩니다. 과잉행동·충동성에는 메틸페니데이트, 공격성·자해에는 리스페리돈·아리피프라졸(FDA 승인), 불안·우울에는 SSRI 등이 처방될 수 있습니다. 각 약물은 식욕 감소, 졸음, 체중 증가, 추체외로 증상 등의 부작용이 있을 수 있으므로 소아청소년 정신건강의학과 전문의와 충분히 상담하시길 권고드립니다.', 1178, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '자폐증 / 자폐 스펙트럼 장애', '자폐증/자폐스펙트럼장애', 'PREVENTION', '자폐 스펙트럼 장애는 유전적 요인이 강하게 관여하는 복합적 신경발달 질환으로, 자녀에게 전달될 위험이 일반 집단보다 높습니다. 가족력이 있는 경우 유전 상담을 통해 위험도를 평가받을 수 있으며, 임신 후 태아 정기 발달 검진을 통해 조기 발견 가능성을 높일 수 있습니다. 결혼 전 또는 임신 계획 시 의유전학 전문의나 소아청소년 정신건강의학과 전문의와 상담하여 구체적인 정보를 얻으시길 권고드립니다.', 1179, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '자폐증 / 자폐 스펙트럼 장애', '자폐증/자폐스펙트럼장애', 'EXERCISE', '부모와 자폐 아동이 함께하는 운동은 사회적 상호작용, 정서 조절, 신체 협응 능력 향상에 긍정적인 효과가 있습니다. 수영, 트램폴린, 승마 치료(히포테라피), 함께하는 걷기·자전거 타기 등은 감각 통합과 집중력 개선에 도움이 됩니다. 운동 프로그램은 아동의 감각 민감도와 선호를 고려하여 개별화해야 하며, 작업치료사 또는 체육치료 전문가와 함께 계획을 세우시길 권고드립니다.', 1180, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '자폐증 / 자폐 스펙트럼 장애', '자폐증/자폐스펙트럼장애', 'CAUSE', '자폐 스펙트럼 장애에서 변화에 대한 저항과 제한적 관심사는 뇌의 집행 기능 및 중앙 통합 능력 이상과 관련이 있습니다. 예측 불가능한 변화에 대한 과도한 불안과 반복적 루틴 선호는 감각 처리 이상, 불안 조절 어려움, 전환(shift) 능력 저하에서 기인하는 것으로 알려져 있습니다. 정확한 원인 평가와 맞춤형 행동 중재를 위해 소아청소년 정신건강의학과 전문의 상담을 권고드립니다.', 1181, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '자폐증 / 자폐 스펙트럼 장애', '자폐증/자폐스펙트럼장애', 'REHAB', '자폐 스펙트럼 장애의 재활 치료로는 응용행동분석(ABA), 언어치료(AAC 포함), 작업치료(감각통합치료), 사회기술훈련, 놀이치료 등이 있습니다. 3세 이전 조기 집중 행동 치료를 시작할수록 언어 발달과 사회성 향상에 더 효과적인 것으로 알려져 있습니다. 개인별 강점과 필요에 따른 맞춤형 치료 계획을 위해 소아청소년 정신건강의학과 또는 발달재활 전문가와 상담하시길 권고드립니다.', 1182, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '자폐증 / 자폐 스펙트럼 장애', '자폐증/자폐스펙트럼장애', 'DEFINITION', '자폐 스펙트럼 장애(ASD)는 사회적 의사소통·상호작용의 지속적인 어려움과 제한적·반복적 행동 패턴을 특징으로 하는 신경발달 질환입니다. ''스펙트럼''이라는 표현처럼 경증의 아스퍼거 증후군부터 중증의 자폐증까지 증상의 범위와 심각도가 매우 다양합니다. 지적 능력이 정상이거나 특정 영역에서 높은 재능을 보이는 경우도 있으며, 정확한 진단을 위해 소아청소년 정신건강의학과 전문의 상담을 권고드립니다.', 1183, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '자폐증 / 자폐 스펙트럼 장애', '자폐증/자폐스펙트럼장애', 'SYMPTOM', '자폐증에서 언어 및 표현 이해 어려움, 타인에 대한 관심 저하는 사회적 의사소통 결함의 핵심 증상이며, 이는 지적장애 동반 여부, 언어 수준, 감각 처리 특성에 따라 다양하게 나타납니다. 언어가 전혀 없는 비언어 자폐증부터 언어 발달은 정상이나 사회적 사용이 어려운 고기능 자폐까지 스펙트럼 내 차이가 크며, 각각 다른 중재 접근이 필요합니다. 구체적인 증상 평가와 치료 계획은 소아청소년 정신건강의학과 전문의와 상담하시길 권고드립니다.', 1184, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '자폐증 / 자폐 스펙트럼 장애', '자폐증/자폐스펙트럼장애', 'DIAGNOSIS', '자폐 스펙트럼 장애 진단은 소아청소년 정신건강의학과에서 ADOS-2(자폐 진단 관찰 스케줄), ADI-R(자폐 진단 인터뷰), 발달력 청취, 인지기능 평가 등을 종합하여 이루어집니다. 눈 맞춤 어려움, 의사소통 문제가 있다면 만 18~24개월에 조기 선별 검사(M-CHAT)를 받아볼 수 있으며, 이상이 의심될 경우 즉시 전문 기관을 방문하는 것이 중요합니다. 소아청소년 정신건강의학과 또는 발달장애 클리닉 방문을 권고드립니다.', 1185, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '자폐증 / 자폐 스펙트럼 장애', '자폐증/자폐스펙트럼장애', 'TREATMENT', '자폐 스펙트럼 장애 치료에는 정신건강의학과 전문의(진단, 약물 관리), 임상심리사(행동 평가·ABA), 언어치료사(의사소통 중재), 작업치료사(감각통합·일상생활 기술), 특수교육 교사, 사회복지사 등 다학제팀이 협력합니다. 가족의 역할도 매우 중요하여 부모 훈련 프로그램(PECS, RDI 등)을 통해 가정에서도 일관된 중재를 이어나갈 수 있습니다. 개인 특성에 맞는 통합적 치료 계획은 소아청소년 정신건강의학과 전문의와 상담하시길 권고드립니다.', 1186, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '주의력결핍 과잉행동장애', '주의력결핍과잉행동장애', 'CHECKUP', '산만함, 주의 집중 어려움, 충동성 등의 증상이 여러 상황에서 지속된다면 ADHD(주의력결핍 과잉행동장애) 가능성을 고려하여 전문 검진을 받는 것이 중요합니다. 소아청소년 정신건강의학과에서 임상 면담, 행동 평가 척도(K-ARS 등), 신경심리 검사를 통해 정확한 진단을 받을 수 있습니다. 단순 성격 특성과 ADHD를 구분하려면 반드시 전문의의 평가가 필요하므로 정신건강의학과 방문을 권고드립니다.', 1187, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '주의력결핍 과잉행동장애', '주의력결핍과잉행동장애', 'DIET_LIFE', 'ADHD가 있는 경우 설탕·인공색소·가공식품을 줄이고 오메가-3(등 푸른 생선, 견과류)를 충분히 섭취하면 집중력 유지에 도움이 될 수 있습니다. 규칙적인 수면 일정, 체계화된 일과표 사용, 운동(특히 유산소 운동)은 뇌의 도파민·노르에피네프린 분비를 촉진하여 주의력 향상에 긍정적입니다. 생활 습관 조정만으로 증상 조절이 어렵다면 약물 치료와 행동 치료를 병행하는 것이 효과적이므로 정신건강의학과 전문의 상담을 권고드립니다.', 1188, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '주의력결핍 과잉행동장애', '주의력결핍과잉행동장애', 'MEDICATION', 'ADHD 치료에서 약물 치료 외에 인지행동치료(CBT)는 자기조절 능력과 실행 기능 향상에 효과적인 1차 비약물 치료로 권고됩니다. 행동 수정 치료, 부모 훈련 프로그램, 사회기술훈련, 신경피드백 치료, 특수교육 지원 등도 활용됩니다. 아동의 경우 부모 훈련과 학교 기반 중재가 특히 효과적이며, 약물 치료와 비약물 치료를 병행하는 것이 가장 좋은 결과를 보이므로 정신건강의학과 전문의와 상담하시길 권고드립니다.', 1189, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '주의력결핍 과잉행동장애', '주의력결핍과잉행동장애', 'EXERCISE', '규칙적인 유산소 운동(달리기, 수영, 자전거 등)은 뇌의 도파민·세로토닌·노르에피네프린 분비를 증가시켜 ADHD 아동과 성인의 집중력과 실행 기능 향상에 도움이 됩니다. 연구에 따르면 주 3회 이상, 회당 20~30분의 중등도 유산소 운동이 주의력 개선에 효과적인 것으로 알려져 있습니다. 운동 효과는 꾸준한 실천이 중요하며, 개인별 적합한 운동 프로그램은 전문의와 상담하여 결정하시길 권고드립니다.', 1190, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '주의력결핍 과잉행동장애', '주의력결핍과잉행동장애', 'CAUSE', 'ADHD는 선천적 신경발달 특성이 주원인이지만, 후천적으로도 극심한 스트레스, 납·수은 등 환경독소 노출, 뇌 손상(외상, 감염), 극도의 조기 방치 등이 ADHD 유사 증상을 유발할 수 있습니다. 조산·저체중 출생, 임신 중 흡연·알코올 노출도 위험 요인으로 알려져 있습니다. 원인 파악과 감별 진단을 위해 소아청소년 정신건강의학과 전문의 상담을 받으시길 권고드립니다.', 1191, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '주의력결핍 과잉행동장애', '주의력결핍과잉행동장애', 'DEFINITION', 'ADHD는 주의 집중 어려움이 여러 상황(가정·학교·직장)에서 6개월 이상 지속되고, 연령에 맞지 않는 수준이며, 기능적 손상(학업·직업·대인관계 문제)이 동반될 때 진단합니다. 단순히 주의력이 낮거나 지루할 때만 집중이 어려운 경우와 달리, ADHD는 관심 있는 상황에서도 지속적 주의력 유지가 어렵고 충동성·과잉행동이 함께 나타나는 경향이 있습니다. 정확한 구분을 위해 소아청소년 정신건강의학과 전문의의 종합 평가가 필요합니다.', 1192, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '주의력결핍 과잉행동장애', '주의력결핍과잉행동장애', 'SYMPTOM', '또래와 어울리지 못하고 자주 소리를 지르는 행동은 ADHD의 충동성·사회기술 부족 증상으로 나타날 수 있으며, 주목할 필요가 있는 행동입니다. 그러나 이러한 증상은 ADHD 외에도 자폐 스펙트럼 장애, 반항성 장애, 불안장애 등에서도 나타날 수 있어 정확한 감별 진단이 중요합니다. 증상이 지속되고 일상생활에 지장을 준다면 소아청소년 정신건강의학과 전문의를 방문하여 정확한 평가를 받으시길 권고드립니다.', 1193, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '주의력결핍 과잉행동장애', '주의력결핍과잉행동장애', 'DIAGNOSIS', '주의 집중 어려움과 쉬운 산만함, 지루함이 여러 상황에서 지속된다면 ADHD의 초기 증상일 수 있으나, 이러한 증상만으로 확진할 수는 없습니다. ADHD 진단은 증상이 12세 이전에 시작되고, 두 가지 이상의 상황에서 나타나며, 기능 저하를 유발하고, 다른 정신질환으로 설명되지 않을 때 DSM-5 기준에 따라 내려집니다. 정확한 진단을 위해 소아청소년 정신건강의학과 전문의 상담을 받으시길 권고드립니다.', 1194, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '주의력결핍 과잉행동장애', '주의력결핍과잉행동장애', 'TREATMENT', 'ADHD는 학령기 아동의 약 5~7%에서 진단되며, 소아에서 남아가 여아보다 약 2~3배 더 많이 진단됩니다. 여아는 과잉행동보다 주의력 결핍이 두드러져 진단이 늦어지는 경향이 있습니다. ADHD는 성인까지 지속되는 경우가 많으며, 치료는 약물 치료(메틸페니데이트, 아토목세틴 등)와 행동 치료를 병행하는 것이 효과적이므로 전문의 상담을 권고드립니다.', 1195, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '중증 근무력증', '중증근무력증', 'CAUSE', '중증 근무력증은 신경-근육 접합부에서 아세틸콜린 수용체(AChR)에 대한 자가항체가 생성되어 수용체가 차단·파괴되는 자가면역 질환입니다. 이로 인해 신경 신호가 근육에 제대로 전달되지 않아 근력 약화와 쉬운 피로감이 발생하며, 흉선(흉선종 포함)의 면역 조절 이상이 자가항체 생성에 중요한 역할을 하는 것으로 알려져 있습니다. 자가면역 기전에 대한 자세한 설명과 치료는 신경과 전문의와 상담하시길 권고드립니다.', 1196, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '중증 근무력증', '중증근무력증', 'DEFINITION', '중증 근무력증은 자가면역 기전으로 신경-근육 접합부의 아세틸콜린 수용체가 손상되어 운동 후 근력이 약해지고 휴식 후 회복되는 변동성 근력 약화가 특징인 질환입니다. 눈꺼풀 처짐, 복시, 삼킴 곤란, 사지 근력 약화 등이 운동 후 악화되는 양상을 보입니다. 운동 후 증상이 반복된다면 신경과 전문의를 방문하여 항-AChR 항체 검사와 근전도 검사 등의 정확한 진단을 받으시길 권고드립니다.', 1197, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '중증 근무력증', '중증근무력증', 'SYMPTOM', '집게 사용 등 반복적인 근육 활동 후 몇 분 만에 힘이 빠지고 휴식 후 회복되는 증상은 중증 근무력증의 전형적인 특징인 운동 유발성 근력 약화에 해당할 수 있습니다. 중증 근무력증은 운동이 지속될수록 근력 저하가 심해지고 휴식 후 회복되는 변동성을 보이는 것이 특징입니다. 이러한 증상이 지속된다면 신경과 전문의를 방문하여 정확한 진단을 받으시길 권고드립니다.', 1198, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '중증 근무력증', '중증근무력증', 'DIAGNOSIS', '스트레스와 피로로 인한 근력 저하는 기능적 증상일 수 있지만, 중증 근무력증과의 감별이 필요합니다. 중증 근무력증 자가 진단의 단서로는 운동할수록 심해지고 휴식 후 회복되는 근력 약화, 눈꺼풀 처짐, 복시, 삼킴 어려움이 있습니다. 그러나 자가 진단에는 한계가 있으므로, 증상이 의심된다면 신경과 전문의를 방문하여 근전도 검사, 항-AChR 항체 검사 등의 정확한 진단을 받으시길 권고드립니다.', 1199, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '중증 근무력증', '중증근무력증', 'TREATMENT', '복시(사물이 2개로 보임)와 극심한 피로는 중증 근무력증의 전형적인 증상으로, 신경과 전문의의 치료가 필요합니다. 치료로는 아세틸콜린에스테라제 억제제(피리도스티그민), 면역억제제(스테로이드, 아자티오프린), 혈장교환술, 면역글로불린 정맥주사, 흉선절제술 등이 사용됩니다. 증상이 심하거나 호흡 곤란이 동반된다면 즉시 응급실을 방문하고, 치료 방침은 신경과 전문의와 상담하여 결정하시길 권고드립니다.', 1200, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '지적장애', '지적장애', 'DIET_LIFE', '지적장애 환자의 식이 습관 개선을 위해서는 구조화된 식사 일과(정해진 시간과 장소), 시각적 메뉴판 활용, 소량씩 다양한 식품을 반복 노출하는 방법이 효과적입니다. 영양 불균형 예방을 위해 영양사의 맞춤형 식단 지도를 받는 것이 중요하며, 감각 과민으로 인한 편식이 심할 경우 작업치료사와 협력하여 식이 중재 계획을 세우는 것이 도움이 됩니다. 구체적인 생활 습관 개선 방법은 담당 전문의 및 재활팀과 상담하시길 권고드립니다.', 1201, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '지적장애', '지적장애', 'MEDICATION', '지적장애 자체를 치료하는 특이적 약물은 없으며, 동반 증상(ADHD, 불안, 경련, 공격성 등)에 대해서만 약물 치료가 이루어집니다. 약물의 필요성과 지속 여부는 증상 조절 효과와 부작용을 고려하여 정신건강의학과 또는 소아신경과 전문의가 정기적으로 평가합니다. 임의로 약물을 중단하거나 변경하면 증상이 악화될 수 있으므로, 반드시 전문의의 지시에 따라 복용하시길 권고드립니다.', 1202, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '지적장애', '지적장애', 'CAUSE', '술·담배를 하지 않아도 지적장애는 염색체 이상(다운증후군 등), 유전자 돌연변이, 임신 중 감염(풍진, 거대세포바이러스), 태아 저산소증, 조산·저체중 출생, 신생아 대사 이상, 뇌 기형 등 다양한 원인으로 발생할 수 있습니다. 이 중 원인 불명인 경우도 상당수이며, 환경 및 유전적 요인의 복합적 작용이 관여합니다. 정확한 원인 파악을 위해 소아청소년과 또는 의유전학 전문의 상담을 권고드립니다.', 1203, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '지적장애', '지적장애', 'REHAB', '지적장애인의 의사소통 기능 향상과 행동 발달을 위한 재활 프로그램은 재활의학과, 발달장애인지원센터, 장애인복지관, 특수학교 등에서 제공됩니다. 언어치료, 인지 재활, 작업치료, 사회기술 훈련, 응용행동분석(ABA) 기반 프로그램 등이 운영되며, 보건복지부 발달재활서비스 바우처를 통해 치료비 지원을 받을 수 있습니다. 지역 내 이용 가능한 기관과 프로그램은 담당 전문의 또는 지역 발달장애인지원센터에 문의하시길 권고드립니다.', 1204, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '지적장애', '지적장애', 'DEFINITION', '사회성 저하와 제한적 관심사만으로 지적장애를 진단할 수는 없습니다. 지적장애는 지적 기능(IQ 70 미만)과 적응 행동(사회성·실용적 기술) 모두에서 유의한 제한이 있고 발달기(18세 이전)에 시작될 때 진단됩니다. 사회성 저하와 제한적 관심사는 자폐 스펙트럼 장애, ADHD 등 다른 발달 질환에서도 나타날 수 있으므로, 정확한 감별 진단을 위해 소아청소년 정신건강의학과 전문의 상담을 권고드립니다.', 1205, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '지적장애', '지적장애', 'SYMPTOM', '지적장애는 지적 기능과 적응 행동의 심각한 제한이 발달기에 나타나는 상태로, 경도·중등도·중증·최중증으로 분류됩니다. 주요 증상으로는 언어 발달 지연, 부정확한 발음 및 이해 어려움, 추상적 사고·문제 해결 어려움, 사회적 상황 판단 어려움, 기억력·학습 속도 저하 등이 있습니다. 발음 부정확과 이해 어려움은 언어 지연의 일부로 나타날 수 있으며, 언어치료와 함께 정기적인 전문의 추적 관찰이 필요합니다.', 1206, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '지적장애', '지적장애', 'DIAGNOSIS', '아동의 행동 및 감정 조절 문제를 평가하려면 소아청소년 정신건강의학과를 방문하는 것이 적절합니다. 임상 면담, 행동 평가 척도(CBCL 등), 신경심리 검사(지능 검사, 실행기능 검사), 놀이 관찰 등을 통해 종합적인 평가가 이루어집니다. 소아청소년 정신건강의학과 전문의를 통해 ADHD, 지적장애, 자폐 스펙트럼 장애, 불안장애 등의 감별 진단을 받으시길 권고드립니다.', 1207, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '지적장애', '지적장애', 'TREATMENT', '지적장애 치료에는 언어치료, 작업치료 외에 인지 재활, 응용행동분석(ABA), 사회기술훈련, 특수교육, 음악·미술 치료 등 다양한 방법이 활용됩니다. 동반된 ADHD·불안·경련 등에 대한 약물 치료와 함께 가족 상담 및 부모 교육도 중요한 치료의 일부입니다. 개인의 강점과 필요에 맞는 맞춤형 치료 계획을 위해 재활의학과 또는 소아청소년 정신건강의학과 전문의와 상담하시길 권고드립니다.', 1208, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '진전', '진전', 'MEDICATION', '약물 남용으로 인한 진전(떨림) 관리에는 원인 약물 중단이 가장 중요하며, 알코올 금단성 진전에는 벤조디아제핀(디아제팜, 로라제팜)이 1차 약물로 사용됩니다. 교감신경 흥분제 남용에 의한 진전에는 베타차단제(프로프라놀올)가 효과적입니다. 약물 남용과 관련된 진전은 금단 증상을 동반할 수 있어 전문의의 감독 하에 치료가 이루어져야 하므로, 반드시 신경과 또는 중독의학과 전문의의 상담을 받으시길 권고드립니다.', 1209, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '진전', '진전', 'CAUSE', '손가락 떨림(진전)의 주요 원인으로는 본태성 진전(가족력, 원인 불명), 파킨슨병(안정 시 떨림), 갑상선 기능 항진증, 카페인·약물 과다복용, 생리적 진전(피로·불안), 소뇌 질환 등이 있습니다. 원인에 따라 치료가 달라지며, 본태성 진전에는 프로프라놀롤·프리미돈, 파킨슨병에는 도파민 제제, 갑상선 질환에는 원인 치료가 시행됩니다. 떨림 증상의 정확한 원인 파악을 위해 신경과 전문의 상담을 권고드립니다.', 1210, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '진전', '진전', 'REHAB', '중증 진전 환자의 재활은 물리치료(균형 훈련, 근력 강화), 작업치료(보조 도구 활용, 일상생활 동작 훈련), 언어치료(삼킴 장애 동반 시)를 통해 기능 유지와 삶의 질 향상을 목표로 합니다. 웨이트 커프(무게 보조 장치), 특수 식기 등 보조 기구 사용도 도움이 되며, 반복적 과제 훈련을 통해 신경 가소성을 활용한 기능 개선이 가능합니다. 개인 상태에 맞는 재활 프로그램은 재활의학과 전문의와 상담하여 계획하시길 권고드립니다.', 1211, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '진전', '진전', 'DEFINITION', '손발가락의 떨림(진전)은 본태성 진전, 파킨슨병, 소뇌 질환, 갑상선 기능 이상, 말초신경병증, 약물 부작용 등 다양한 원인에 의해 발생할 수 있습니다. 진전의 발생 시점(안정 시·운동 시·자세 유지 시), 부위, 빈도, 동반 증상에 따라 원인 질환이 다르며, 정확한 원인 감별이 치료에 중요합니다. 손발 떨림이 지속되거나 일상생활에 지장을 준다면 신경과 전문의 상담을 권고드립니다.', 1212, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '진전', '진전', 'SYMPTOM', '손발 저림과 떨림을 평가하기 위해 신경과에서 신경전도 검사, 근전도 검사, 뇌 MRI, 혈액 검사(갑상선 기능, 혈당, 전해질, 비타민 B12 등)가 시행됩니다. 진전의 특성(안정 시·활동 시), 부위, 발생 양상에 대한 임상 평가도 중요합니다. 증상이 지속되거나 악화된다면 신경과 전문의를 방문하여 정확한 원인 진단을 받으시길 권고드립니다.', 1213, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '진전', '진전', 'DIAGNOSIS', '뇌 양성 종양(뇌수막종, 신경초종 등) 진단을 위해서는 MRI(자기공명영상)가 가장 정확하고 표준적인 검사로, 종양의 위치·크기·성상을 상세히 파악할 수 있습니다. CT(컴퓨터단층촬영)도 초기 선별 검사로 활용되나 연조직 구분에는 MRI가 더 우수합니다. 두통, 신경학적 증상이 지속된다면 신경과 또는 신경외과 전문의 진료 후 적절한 영상 검사를 받으시길 권고드립니다.', 1214, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '진전', '진전', 'TREATMENT', '진전의 원인을 중추신경계 이상과 생리적 진전으로 감별하기 위해 신경과에서 상세한 병력 청취와 신경학적 검진이 기본이 됩니다. 중추성 원인이 의심될 경우 뇌 MRI, 생리적·약물성 원인 감별을 위해 혈액 검사(갑상선 기능, 혈당, 약물 농도), 근전도·신경전도 검사 등이 시행됩니다. 떨림 증상의 정확한 원인 파악과 치료를 위해 신경과 전문의 상담을 권고드립니다.', 1215, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '척추 종양', '척추종양', 'PREVENTION', '척추 종양의 예방을 위한 완전한 방법은 없으나, 금연, 발암물질 노출 최소화, 규칙적인 운동, 면역력 강화, 정기 건강 검진이 간접적인 예방에 도움이 됩니다. 기저 악성 종양(폐암, 유방암 등)이 있는 경우 조기 치료와 정기적인 척추 상태 모니터링이 전이성 척추 종양 조기 발견에 중요합니다. 척추 관련 증상이 있거나 위험 요인이 있는 경우 정기적으로 신경외과 또는 정형외과 전문의 검진을 받으시길 권고드립니다.', 1216, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '척추 종양', '척추종양', 'CAUSE', '척추 종양은 원발성(원발성 척추 종양, 드묾)과 전이성(폐·유방·전립선암 전이, 흔함)으로 나뉘며, 명확한 단일 원인은 없으나 유전적 소인, 방사선 노출, 면역 저하, 기저 암 등이 위험 요인입니다. 주요 증상으로는 지속적이고 악화되는 요통, 하지 방사통, 감각 저하, 근력 약화, 심한 경우 배뇨·배변 장애가 나타납니다. 이러한 증상이 있다면 신경외과 또는 정형외과 전문의 진료를 즉시 받으시길 권고드립니다.', 1217, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '척추 종양', '척추종양', 'DEFINITION', '척추 종양은 척추 뼈, 척수, 신경 조직에 발생하는 종양으로 양성과 악성으로 분류됩니다. 전이성 척추 종양은 폐암, 유방암, 전립선암 등에서 자주 발생하며, 척수 압박으로 마비가 올 수 있어 조기 발견이 매우 중요합니다. 예방을 위해서는 기저 악성 종양의 조기 치료, 금연, 정기 검진이 중요하며, 허리 통증이 지속되거나 악화된다면 신경외과 전문의 상담을 권고드립니다.', 1218, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '척추 종양', '척추종양', 'SYMPTOM', '척추 종양의 초기에는 국소 요통이 주로 나타나며, 밤에 누워도 완화되지 않는 특징이 있습니다. 중기에는 종양이 신경을 압박하면서 팔·다리로 퍼지는 방사통, 감각 저하, 근력 약화가 발생합니다. 말기에는 척수 압박으로 인한 하지 마비, 배뇨·배변 장애, 보행 불능 등 심각한 신경학적 손상이 나타날 수 있으며, 조기 발견과 치료가 예후에 결정적이므로 신경외과 전문의 즉시 방문을 권고드립니다.', 1219, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '척추 종양', '척추종양', 'DIAGNOSIS', '허리 통증과 척추 종양의 연관성을 평가하기 위해서는 신경외과 또는 정형외과 전문의를 방문하시면 됩니다. 전문의는 임상 증상, 신경학적 검진, MRI·CT 등 영상 검사를 통해 척추 종양 여부를 확인합니다. 야간에도 지속되는 허리 통증, 체중 감소, 발열이 동반되거나 방사통·근력 약화가 있다면 조속히 신경외과 전문의 진료를 받으시길 권고드립니다.', 1220, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '척추 종양', '척추종양', 'TREATMENT', '척추 종양의 치료는 종양의 종류(양성·악성), 위치, 신경 압박 여부, 환자 전신 상태에 따라 결정되며 수술만이 유일한 방법은 아닙니다. 방사선 치료(정위 방사선 수술 포함), 항암화학요법, 표적 치료, 스테로이드 치료 등 다양한 비수술적 치료가 적용될 수 있으며, 경우에 따라 수술과 병행합니다. 최적의 치료 계획은 신경외과·종양내과·방사선종양학과 등 다학제팀이 협력하여 결정하므로 전문의 상담을 권고드립니다.', 1221, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '치매', '치매', 'CHECKUP', '기억력, 언어력, 판단력 저하 등 인지 기능 이상이 의심될 때는 신경과 또는 정신건강의학과(신경정신과)를 방문하시면 적절한 치매 검사와 진료를 받을 수 있습니다. 가까운 보건소의 치매안심센터(치매국가책임제)에서도 무료로 인지 기능 선별 검사를 받을 수 있습니다. 조기 발견과 치료가 치매 진행 속도를 늦추는 데 중요하므로 빠른 시일 내에 전문의 상담을 받으시길 권고드립니다.', 1222, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '치매', '치매', 'DIET_LIFE', '당뇨병은 혈관 손상과 인슐린 저항성을 통해 뇌 혈류를 감소시키고 신경세포 손상을 유발하여 혈관성 치매 및 알츠하이머 치매의 발생 위험을 증가시키는 것으로 알려져 있습니다. 고혈당으로 인한 산화 스트레스, 아밀로이드 베타 축적 증가, 뇌 인슐린 신호 이상이 치매 발병 기전에 관여하는 것으로 연구되고 있습니다. 따라서 혈당 관리가 치매 예방에 중요한 역할을 하며, 당뇨병 환자는 정기적인 인지 기능 모니터링을 받으시길 권고드립니다.', 1223, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '치매', '치매', 'MEDICATION', '치매 치료 약물은 노인과 젊은 성인 모두에게 동일한 약물이 사용되지만, 노인의 경우 신장·간 기능 저하와 다약제 복용으로 인해 약물 대사가 달라져 용량 조정이 필요한 경우가 많습니다. 콜린에스테라제 억제제(도네페질, 리바스티그민, 갈란타민)와 메만틴은 연령에 상관없이 사용되나, 노인에서 낙상·심박 이상 등 부작용 위험이 더 높습니다. 치료 약물 선택과 용량은 반드시 신경과 또는 정신건강의학과 전문의와 상담하여 개인 상태에 맞게 결정하시길 권고드립니다.', 1224, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '치매', '치매', 'PREVENTION', '규칙적인 유산소 운동은 뇌 혈류를 증가시키고 뇌유래신경영양인자(BDNF) 분비를 촉진하여 해마 용적을 증가시키고 신경 가소성을 향상시켜 치매 예방에 도움이 됩니다. 주 3회 이상, 회당 30~45분의 중등도 유산소 운동(빠른 걷기, 수영, 자전거 등)이 인지 기능 저하 예방에 효과적인 것으로 연구에서 확인되었습니다. 운동과 함께 사회적 활동, 인지 활동, 지중해식 식단을 병행하면 치매 예방 효과가 더 높아집니다.', 1225, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '치매', '치매', 'EXERCISE', '치매로 인한 기억력 감퇴, 지남력 저하, 판단력 감소 완화에 도움이 되는 운동으로는 빠른 걷기, 수영 등 유산소 운동과 함께 균형 운동(태극권, 요가), 인지-운동 복합 프로그램이 효과적입니다. 최근에는 걸으면서 인지 과제를 동시에 수행하는 이중 과제 훈련이 치매 환자의 인지 기능 개선에 도움이 된다는 연구 결과가 있습니다. 환자 상태에 맞는 운동 처방은 재활의학과 전문의 또는 치매 전문 치료팀과 상담하여 계획하시길 권고드립니다.', 1226, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '치매', '치매', 'CAUSE', '과도한 알코올 섭취는 신경독성 작용으로 뇌 신경세포를 직접 손상시키고, 비타민 B1(티아민) 결핍을 유발하여 코르사코프 증후군(기억 장애)을 초래할 수 있습니다. 만성 음주는 뇌 위축, 해마 손상, 알츠하이머 치매 위험 증가와 관련이 있으며, 알코올성 치매는 금주를 통해 진행을 늦출 수 있는 특징이 있습니다. 알코올 섭취를 절제하는 것이 치매 예방에 중요하며, 음주 문제가 있다면 알코올 전문 치료기관 방문을 권고드립니다.', 1227, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '치매', '치매', 'DEFINITION', '알츠하이머병은 치매의 가장 흔한 원인(전체 치매의 60~70%)으로, 뇌에 아밀로이드 베타 단백질과 타우 단백질이 축적되어 신경세포가 서서히 사멸하는 퇴행성 뇌질환입니다. 발병 원인으로는 유전적 요인(APOE ε4 유전자 등), 고령, 심혈관 위험 요인, 교육 수준, 생활 습관 등이 복합적으로 관여합니다. 치매는 조기 발견 시 진행을 늦출 수 있으므로 기억력 저하가 의심될 때 신경과 전문의 상담을 권고드립니다.', 1228, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '치매', '치매', 'SYMPTOM', '알츠하이머 치매는 기억력 저하(특히 최근 기억)가 가장 먼저 나타나고 언어, 판단력, 지남력 저하가 서서히 진행됩니다. 파킨슨병 치매는 운동 증상(손 떨림, 보행 장애, 경직)이 먼저 나타난 후 인지 기능 저하가 뒤따르며, 주의력·시공간 기능 저하가 두드러집니다. 두 질환 모두 정확한 감별을 위해 신경과 전문의 평가가 필요하며, 치료 약물과 접근 방식도 다르므로 반드시 전문의 상담을 권고드립니다.', 1229, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '치매', '치매', 'DIAGNOSIS', '치매 진단에는 인지 기능 선별 검사(MMSE, MoCA), 신경심리 검사(기억·언어·집행기능 평가), 뇌 MRI(위축 부위 파악), 아밀로이드 PET·FDG-PET(뇌 대사 평가), 혈액 검사(갑상선 기능, 비타민 B12 등 가역적 원인 감별), 뇌척수액 검사 등이 활용됩니다. MRI는 혈관성 치매와 알츠하이머 감별에, PET는 알츠하이머 조기 진단에 특히 유용합니다. 진단 방법의 선택은 신경과 전문의가 임상 상황에 따라 결정합니다.', 1230, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '치매', '치매', 'TREATMENT', '치매 치료에서 현재 알츠하이머 치매의 증상 완화를 위해 콜린에스테라제 억제제(도네페질, 리바스티그민, 갈란타민)와 중등도 이상에서 메만틴이 사용됩니다. 약물 치료와 함께 인지 재활(인지 자극 훈련), 운동 치료, 작업 치료, 사회 활동 참여, 가족 지지 및 교육이 삶의 질 향상에 중요합니다. 치매는 완치보다 진행 지연과 삶의 질 유지가 목표이며, 개인 상태에 맞는 통합적 치료 계획은 신경과 전문의와 상담하시길 권고드립니다.', 1231, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '틱 장애', '틱장애', 'CHECKUP', '틱 장애는 자신의 의지와 관계없이 반복적·갑작스럽게 나타나는 운동 또는 음성 증상으로, 소아청소년 정신건강의학과에서 진단과 치료를 받을 수 있습니다. 전국 정신건강복지센터(1577-0199)나 지역 보건소를 통해 가까운 전문 의료기관을 안내받을 수 있으며, 소아신경과에서도 진료가 가능합니다. 증상이 1년 이상 지속되거나 일상생활에 지장을 준다면 빠른 시일 내에 전문의 진료를 받으시길 권고드립니다.', 1232, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '틱 장애', '틱장애', 'DIET_LIFE', '틱 장애 예방과 증상 완화를 위한 스트레스 관리 방법으로는 규칙적인 수면과 생활 습관 유지, 복식 호흡과 이완 훈련, 신체 활동(운동), 취미 활동을 통한 긍정적 기분 전환이 효과적입니다. 학교·가정에서 과도한 압박을 줄이고 아이가 심리적으로 안정감을 느낄 수 있는 환경을 조성하는 것이 중요합니다. 틱 증상이 지속되거나 심화된다면 습관 역전 훈련(HRT) 등의 행동 치료를 위해 소아청소년 정신건강의학과 전문의 상담을 권고드립니다.', 1233, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '틱 장애', '틱장애', 'CAUSE', '소아에서 눈 깜박임, 코 훌쩍거림 등의 반복 행동이 나타나는 틱 장애는 기저핵-피질-시상-피질 신경 회로의 기능 이상과 도파민 시스템 불균형이 주요 원인으로 알려져 있습니다. 유전적 소인, 심리적 스트레스, 피로, 긴장 상태에서 증상이 악화되는 경향이 있으며, ADHD·강박증과 동반되는 경우가 많습니다. 원인과 치료 방법에 대한 자세한 안내는 소아청소년 정신건강의학과 전문의 상담을 통해 받으시길 권고드립니다.', 1234, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '틱 장애', '틱장애', 'DEFINITION', '얼굴 찡그림, 고개 갸우뚱거림 등의 반복적이고 갑작스러운 동작은 운동 틱의 전형적인 증상에 해당할 가능성이 높습니다. 틱 장애는 만 5~10세 소아에서 가장 흔히 발생하며, 증상이 4주 이상 지속되고 스트레스나 피로 시 악화되는 특징이 있습니다. 일시적인 틱은 저절로 호전되기도 하지만, 1년 이상 지속되거나 일상에 지장이 있다면 소아청소년 정신건강의학과 전문의 상담을 권고드립니다.', 1235, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '틱 장애', '틱장애', 'SYMPTOM', '운동 틱 장애에서는 반복적이고 갑작스러운 근육 운동이 얼굴에서 시작하여 목·어깨·몸통·사지 등 다른 신체 부위로 이동하거나 확장되는 양상을 보이는 경우가 있습니다. 이는 뚜렛 증후군으로 발전할 수 있으며, 음성 틱(헛기침, 코 훌쩍거림)이 함께 나타나기도 합니다. 틱의 부위 이동은 운동 틱 장애의 특성 중 하나이며, 정확한 평가와 치료를 위해 소아청소년 정신건강의학과 전문의 상담을 권고드립니다.', 1236, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '틱 장애', '틱장애', 'DIAGNOSIS', '눈을 자주 깜박이거나 반복적인 특정 행동이 4주 이상 지속된다면 틱 장애를 의심할 수 있습니다. 그러나 틱 장애는 자신의 의지와 관계없이 나타나는 갑작스럽고 반복적인 동작·음성이 특징이며, ADHD·강박증 등과 감별이 필요합니다. 틱 장애 여부는 소아청소년 정신건강의학과 전문의의 임상 면담과 평가를 통해 확인해야 하므로, 의심 증상이 있다면 전문의 상담을 받으시길 권고드립니다.', 1237, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '틱 장애', '틱장애', 'TREATMENT', '틱 장애의 1차 치료로 습관 역전 훈련(HRT), 노출 및 반응 방지(ERP) 등의 행동 치료가 효과적이며, 학교·가정의 스트레스 감소와 심리 지지도 중요합니다. 증상이 심하거나 일상생활 기능에 지장이 있는 경우 할로페리돌, 리스페리돈, 클로니딘 등의 약물 치료를 병행합니다. 행동 치료는 부작용 없이 장기적 효과가 있으나 전문가 지도가 필요하고, 약물 치료는 증상 억제 효과가 빠른 반면 부작용 가능성이 있으므로 소아청소년 정신건강의학과 전문의와 상담하여 결정하시길 권고드립니다.', 1238, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '파킨슨병', '파킨슨병', 'CHECKUP', '손 떨림, 보행 이상 등 파킨슨병이 의심될 때는 신경과에서 임상 신경학적 검사(안정 시 떨림, 경직, 운동 완서, 자세 불안정 평가)가 우선 시행됩니다. 뇌 도파민 신경세포 기능을 확인하는 DaT 스캔(도파민 운반체 SPECT), 뇌 MRI, 파킨슨 약물(레보도파) 반응 검사가 진단에 활용됩니다. 증상이 의심된다면 신경과 전문의를 방문하여 정확한 진단을 받으시길 권고드립니다.', 1239, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '파킨슨병', '파킨슨병', 'DIET_LIFE', '파킨슨병 환자는 고단백 식사가 레보도파 흡수를 방해할 수 있으므로 약물 복용 시간과 식사 시간을 조율하고, 섬유질이 풍부한 식사로 변비를 예방하는 것이 중요합니다. 규칙적인 유산소 운동과 균형 훈련은 운동 증상 완화와 낙상 예방에 도움이 되며, 충분한 수분 섭취, 규칙적인 수면, 사회 활동 참여도 권고됩니다. 구체적인 식이 및 생활 습관 지도는 신경과 전문의와 영양사, 물리치료사와 함께 상담하여 개인화된 계획을 세우시길 권고드립니다.', 1240, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '파킨슨병', '파킨슨병', 'MEDICATION', '파킨슨병 치료의 주요 약물로는 도파민 전구체인 레보도파/카르비도파(마도파, 시네메트), 도파민 작용제(프라미펙솔, 로피니롤), MAO-B 억제제(라사길린, 셀레길린)가 있습니다. 부작용으로는 오심·구토, 기립성 저혈압, 이상운동증(장기 레보도파 사용 시), 충동 조절 장애(도파민 작용제), 수면 장애, 환각 등이 나타날 수 있습니다. 약물 선택과 부작용 관리는 신경과 전문의와 충분히 상담하여 결정하시길 권고드립니다.', 1241, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '파킨슨병', '파킨슨병', 'EXERCISE', '파킨슨병 환자에서 언어치료는 발음 명료도 향상, 음성 크기 조절, 삼킴 기능 개선에 효과적이며, LSVT(Lee Silverman Voice Treatment)가 대표적인 방법입니다. 운동치료(물리치료)는 보행 속도·보폭 개선, 균형 향상, 낙상 예방에 중요하며, LSVT BIG 프로그램이 파킨슨 환자에 특화되어 있습니다. 두 치료 모두 조기에 시작할수록 기능 유지에 유리하므로, 진단 후 빠른 시일 내에 재활의학과 또는 신경과 전문의를 통해 재활 치료를 시작하시길 권고드립니다.', 1242, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '파킨슨병', '파킨슨병', 'CAUSE', '파킨슨병의 유전적 원인으로는 SNCA, LRRK2, PRKN, PINK1, DJ-1 등 여러 유전자 돌연변이가 알려져 있으며, 가족성 파킨슨병의 일부를 설명합니다. 그러나 파킨슨병의 대부분(85~90%)은 특정 단일 유전자 이상이 아닌 유전적 취약성과 노화, 환경적 요인(농약·독소 노출 등)의 복합적 상호작용으로 발생합니다. 가족 중 파킨슨병 환자가 있다면 신경과 전문의와 상담하여 유전적 위험도 평가와 정기 검진을 받으시길 권고드립니다.', 1243, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '파킨슨병', '파킨슨병', 'DEFINITION', '파킨슨병은 뇌 속에서 몸을 움직이는 명령을 도와주는 ''도파민''이라는 물질이 점점 줄어들어 생기는 병입니다. 주요 증상으로 손이 떨리고, 몸이 뻣뻣해지고, 행동이 느려지며, 걸을 때 균형 잡기가 어려워집니다. 마치 로봇처럼 천천히 움직이게 되는 병으로, 약을 꾸준히 먹고 운동을 열심히 하면 증상을 조절할 수 있으며, 신경과 선생님께 정기적으로 진료를 받는 것이 중요합니다.', 1244, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '파킨슨병', '파킨슨병', 'SYMPTOM', '파킨슨병에서 보행 속도 저하(소보행, 끌리는 걸음)와 표정 감소(가면 얼굴)는 전형적인 운동 증상으로, 도파민 저하로 인한 운동 완서의 일부입니다. 그 외 안정 시 손 떨림(4~6Hz), 근육 경직(톱니바퀴 강직), 자세 불안정, 목소리 작아짐, 글씨 작아짐(소자증), 변비, 후각 저하 등이 동반될 수 있습니다. 이러한 증상들이 복합적으로 나타난다면 신경과 전문의를 방문하여 정확한 평가를 받으시길 권고드립니다.', 1245, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '파킨슨병', '파킨슨병', 'DIAGNOSIS', '파킨슨병 진단을 위해 의사는 안정 시 떨림, 근육 경직, 운동 완서, 자세 불안정의 4대 증상을 중심으로 신경학적 검진을 시행합니다. 뇌 MRI(다른 원인 배제), DaT 스캔(도파민 신경세포 소실 확인), 레보도파 반응 검사(약물 복용 후 증상 개선 여부)가 진단 보조에 활용됩니다. 파킨슨병은 현재 혈액 검사나 단일 검사로 확진되지 않으며, 임상 증상과 경과 관찰을 통해 전문의가 종합적으로 진단하므로 신경과 전문의 상담을 권고드립니다.', 1246, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '파킨슨병', '파킨슨병', 'TREATMENT', '파킨슨병 환자에서 유산소 운동(걷기, 자전거)은 도파민 신경 보호 효과와 함께 보행 속도·보폭 개선에 도움이 됩니다. 균형 훈련(태극권, 요가)은 낙상 예방에 효과적이며, 저항 운동은 근력 유지와 경직 완화에 도움이 됩니다. 떨림 자체는 운동으로 크게 개선되지 않을 수 있으나, 전반적인 운동 기능과 삶의 질 향상에 중요하므로 신경과 전문의 및 물리치료사와 상담하여 개인화된 운동 처방을 받으시길 권고드립니다.', 1247, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '편두통', '편두통', 'DIET_LIFE', '편두통 완화를 위한 생활 치료로는 규칙적인 수면과 식사 시간 유지, 충분한 수분 섭취, 카페인·알코올·초콜릿 등 유발 음식 제한이 도움이 됩니다. 규칙적인 유산소 운동, 이완 요법(명상, 심호흡), 스트레스 관리가 편두통 빈도 감소에 효과적이며, 통증 발생 시 어두운 조용한 환경에서 휴식을 취하는 것이 권고됩니다. 편두통이 월 2회 이상이거나 일상생활에 지장이 있다면 신경과 전문의 상담을 받으시길 권고드립니다.', 1248, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '편두통', '편두통', 'MEDICATION', '편두통 예방을 위해 매일 복용하는 예방 약물로는 베타차단제(프로프라놀롤), 항경련제(토피라메이트, 발프로산), 항우울제(아미트립틸린), CGRP 길항제(에레누맙) 등이 사용됩니다. 예방 약물은 월 편두통 일수가 4일 이상이거나 급성기 약물로 조절이 어려울 때 고려됩니다. 반면, 급성기 약물(트립탄, 진통제 등)을 매일 복용하면 약물 과용 두통이 발생할 수 있으므로, 복용 계획은 반드시 신경과 전문의와 상담하여 결정하시길 권고드립니다.', 1249, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '편두통', '편두통', 'PREVENTION', '편두통, 긴장성 두통, 어지러움 예방을 위해서는 규칙적인 수면과 식사, 충분한 수분 섭취, 적당한 유산소 운동이 중요합니다. 카페인·알코올·흡연을 절제하고, 화면 사용 시 정기적인 휴식을 취하며, 목·어깨 스트레칭으로 긴장을 완화하는 것이 긴장성 두통 예방에 도움이 됩니다. 어지러움이 동반된다면 뇌혈관 질환 가능성도 있으므로, 반복적인 두통과 어지러움이 있을 경우 신경과 전문의 상담을 권고드립니다.', 1250, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '편두통', '편두통', 'CAUSE', '편두통은 주로 머리 한쪽에서 발생하지만, 양쪽 모두에 통증이 생기기도 합니다. 편두통 원인을 확인하려면 신경과 전문의를 방문하여 신경학적 검사와 MRI 또는 CT 검사를 받는 것이 권장됩니다. 이를 통해 뇌 혈관 이상이나 다른 기질적 원인을 배제할 수 있습니다.', 1251, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '편두통', '편두통', 'DEFINITION', '편두통은 뇌 신경계의 과민 반응과 혈관 변화로 인해 발생하는 반복적인 두통 질환으로, 주로 머리 한쪽에서 중등도 이상의 박동성 통증이 나타납니다. 구역, 구토, 빛·소리 민감성이 동반되는 것이 특징이며, 전조 증상(시각적 섬광, 감각 이상)이 먼저 나타나기도 합니다. 정확한 진단과 치료를 위해 신경과 전문의 상담을 권고드립니다.', 1252, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '편두통', '편두통', 'SYMPTOM', '편두통의 주요 증상으로는 박동성 두통과 함께 빛(광선 공포증) 및 소리(음성 공포증)에 대한 민감성이 흔하게 나타납니다. 구역질과 구토도 편두통 발작 중 자주 동반되는 증상입니다. 이러한 증상이 반복된다면 신경과 전문의를 방문하여 정확한 진단과 적절한 치료를 받으시기 바랍니다.', 1253, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '편두통', '편두통', 'DIAGNOSIS', '편두통은 반드시 머리 한쪽에만 통증이 오는 것은 아니며, 양측성 통증도 가능합니다. 진단 기준으로는 중등도 이상의 박동성 두통이 4~72시간 지속되고, 구역·구토·빛·소리 민감성 중 하나 이상이 동반되어야 합니다. 머리 한쪽 두통만으로 편두통을 자가 진단하기보다 신경과 전문의의 정확한 진단을 받으시기 바랍니다.', 1254, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '편두통', '편두통', 'TREATMENT', '한의학에서는 편두통을 간기울결(肝氣鬱結), 담습(痰濕), 어혈(瘀血) 등의 병리로 보고 침치료, 한약, 부항 등을 활용합니다. 일부 연구에서 침치료가 편두통 발작 빈도 감소에 효과적임이 보고되어 있습니다. 그러나 일상생활에 지장을 주는 편두통은 신경과 또는 한의사 전문의와 상담 후 본인에게 맞는 치료 방법을 선택하는 것이 좋습니다.', 1255, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '편집성 인격장애', '편집성인격장애', 'CAUSE', '편집성 인격장애의 원인은 선천적 유전 요인과 후천적 환경 요인이 복합적으로 작용합니다. 유전적 소인이 있더라도 아동기 학대, 방치, 외상 경험 등 환경적 요인이 발병에 중요한 역할을 하는 것으로 알려져 있습니다. 어느 한 요인만으로 설명하기 어려우며, 정확한 원인 파악과 치료를 위해 정신건강의학과 전문의 상담을 권고드립니다.', 1256, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '편집성 인격장애', '편집성인격장애', 'DEFINITION', '편집성 인격장애는 타인에 대한 지속적이고 근거 없는 불신과 의심을 핵심 특징으로 하는 성격장애로, 조현병이나 망상장애와는 구별되지만 일부 특성을 공유합니다. 이 장애를 가진 사람은 주변 사람들이 자신을 해치거나 착취한다고 의심하며 대인관계에 심각한 어려움을 겪습니다. 가족이나 직장 내 갈등을 유발할 수 있으므로 정신건강의학과 전문의의 평가가 필요합니다.', 1257, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '편집성 인격장애', '편집성인격장애', 'SYMPTOM', '편집성 인격장애는 선천적 기질과 후천적 경험이 함께 영향을 미치며, 순수하게 선천적인 증상으로 보기는 어렵습니다. 가족 중 편집성 인격장애나 조현병 환자가 있을 경우 유전적 취약성이 높아질 수 있다는 연구 결과가 있습니다. 그러나 유전적 요인이 있어도 반드시 발병하는 것은 아니므로, 증상이 의심될 경우 정신건강의학과 전문의 상담을 받으시기 바랍니다.', 1258, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '편집성 인격장애', '편집성인격장애', 'DIAGNOSIS', '편집성 인격장애 진단은 DSM-5 기준에 따라 장기간에 걸친 패턴을 평가하며, 일시적인 의심과 구별하기 위해 여러 차례 면담과 관찰이 필요합니다. 반복적인 확인을 통해 증상이 다른 정신질환(조현병, 양극성 장애 등)으로 설명되지 않는지 배제 진단을 내립니다. 이러한 과정은 오진을 방지하고 정확한 치료 계획 수립을 위해 필수적입니다.', 1259, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '편집성 인격장애', '편집성인격장애', 'TREATMENT', '편집성 인격장애의 불신과 의심 증상 개선에는 인지행동치료(CBT)가 가장 많이 활용되며, 왜곡된 사고 패턴을 인식하고 수정하는 데 도움이 됩니다. 심리치료와 함께 필요한 경우 항불안제나 항정신병 약물을 병용하기도 합니다. 치료 효과를 높이기 위해서는 정신건강의학과 전문의와의 지속적인 치료적 관계 형성이 중요합니다.', 1260, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '폐소공포증', '폐소공포증', 'CAUSE', '폐소공포증은 유전적 요인이 발병에 영향을 줄 수 있어, 부모가 폐소공포증이나 불안장애를 겪은 경우 자녀의 발병 위험이 높아질 수 있습니다. 또한 어린 시절 좁은 공간에서의 부정적 경험이나 트라우마도 중요한 원인으로 작용합니다. 유전적 소인과 환경적 요인이 복합적으로 작용하므로, 증상이 있다면 정신건강의학과 전문의의 평가를 받는 것이 좋습니다.', 1261, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '폐소공포증', '폐소공포증', 'DEFINITION', '터널처럼 좁고 밀폐된 공간에서 호흡 곤란, 식은땀, 불안감이 나타난다면 폐소공포증의 증상일 가능성이 있습니다. 폐소공포증은 밀폐 공간에 대한 지속적이고 과도한 공포 반응이 특징인 특정 공포증의 일종입니다. 증상이 반복되고 일상생활에 지장을 준다면 정신건강의학과 전문의 상담을 통해 정확한 진단을 받으시기 바랍니다.', 1262, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '폐소공포증', '폐소공포증', 'SYMPTOM', '좁고 갇힌 공간에서 소리를 지르거나 안절부절못하는 행동은 폐소공포증의 초기 또는 발병 증상으로 해석될 수 있습니다. 폐소공포증은 밀폐 공간에 대한 극도의 불안과 공황 반응을 포함하며, 이를 피하려는 회피 행동이 동반됩니다. 친구에게 이런 증상이 있다면 정신건강의학과 전문의의 상담과 체계적인 치료를 받도록 권유하는 것이 좋습니다.', 1263, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '폐소공포증', '폐소공포증', 'DIAGNOSIS', '폐소공포증 진단 시 공황장애, 천식 등 실제 호흡기 질환과 구별하기 위해 신체 검사가 선행됩니다. 주요 감별 요인은 증상이 밀폐 공간 노출에만 국한되는지, 다른 상황에서도 동일 증상이 나타나는지 여부입니다. 호흡기 원인이 배제되고 특정 상황(밀폐 공간)에서만 증상이 반복된다면 폐소공포증으로 진단하며, 정신건강의학과 전문의의 평가가 필요합니다.', 1264, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '폐소공포증', '폐소공포증', 'TREATMENT', '폐소공포증은 약물 외에도 인지행동치료(CBT)와 노출치료가 매우 효과적인 것으로 알려져 있습니다. 노출치료는 밀폐 공간에 단계적으로 노출시켜 공포 반응을 감소시키는 방법으로, 장기적인 효과가 우수합니다. 이완 훈련, 호흡 조절법 등 보완적 방법도 도움이 되므로 정신건강의학과 전문의와 상담 후 본인에게 적합한 치료를 선택하시기 바랍니다.', 1265, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '하지불안증후군', '하지불안증후군', 'CHECKUP', '하지불안증후군과 하지정맥류는 다리 불편감이라는 공통점이 있지만, 하지불안증후군은 안정 시 다리를 움직이고 싶은 충동과 이상 감각이 특징이고, 하지정맥류는 혈관 확장으로 인한 통증과 부종이 주증상입니다. 하지불안증후군 진단을 위해서는 신경과 또는 수면의학과 전문의를 방문하여 임상 평가, 혈액검사(철분, 페리틴 수치 등), 필요 시 수면다원검사를 받는 것이 좋습니다.', 1266, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '하지불안증후군', '하지불안증후군', 'DIET_LIFE', '하지불안증후군은 철분 결핍, 카페인 과다 섭취, 음주, 흡연과 관련이 있어 이를 피하는 것이 중요합니다. 규칙적인 수면 습관, 적당한 유산소 운동, 취침 전 다리 마사지나 온욕이 증상 완화에 도움이 됩니다. 균형 잡힌 식사로 철분과 엽산을 충분히 섭취하고, 생활 습관 개선에도 증상이 지속된다면 전문의 상담을 권고드립니다.', 1267, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '하지불안증후군', '하지불안증후군', 'MEDICATION', '하지불안증후군의 일차적 치료는 전문의 처방이 필요한 약물(도파민 작용제, 철분제 등)이며, 처방 없이 살 수 있는 약국 약으로는 근본적인 치료가 어렵습니다. 철분 결핍이 원인인 경우 철분 보충제를 약국에서 구입할 수 있으나, 복용 전 혈액검사로 철분 수치를 확인하는 것이 안전합니다. 증상이 있다면 반드시 신경과 전문의 진료 후 적절한 처방을 받으시기 바랍니다.', 1268, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '하지불안증후군', '하지불안증후군', 'PREVENTION', '하지불안증후군 예방을 위해서는 규칙적인 수면 습관 유지, 카페인·알코올 제한, 철분이 풍부한 식단 섭취가 도움이 됩니다. 물구나무서기 자체가 하지불안증후군의 직접적인 원인이나 예방법으로 알려져 있지는 않습니다. 하지만 규칙적인 스트레칭과 가벼운 유산소 운동은 증상 예방에 긍정적 영향을 줄 수 있으므로, 증상이 있다면 신경과 전문의와 상담하시기 바랍니다.', 1269, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '하지불안증후군', '하지불안증후군', 'CAUSE', '누워 있거나 앉아 있을 때 다리가 근질거리고 불편하며, 다리를 움직이면 증상이 완화되는 특징이 있다면 하지불안증후군을 의심할 수 있습니다. 하지불안증후군은 특히 저녁이나 밤에 증상이 심해지는 경향이 있습니다. 정확한 진단을 위해 신경과 전문의를 방문하여 임상 평가와 필요한 검사를 받으시기 바랍니다.', 1270, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '하지불안증후군', '하지불안증후군', 'DEFINITION', '다리의 불편감과 저림이 안정 시, 특히 저녁이나 야간에 심해지고 다리를 움직이면 일시적으로 나아진다면 하지불안증후군의 가능성이 있습니다. 단순한 저림증은 혈액 순환 문제나 신경 압박으로도 나타날 수 있어, 두 질환의 감별이 필요합니다. 정확한 진단을 위해 신경과 전문의를 방문하시기 바랍니다.', 1271, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '하지불안증후군', '하지불안증후군', 'SYMPTOM', '하지불안증후군의 주요 증상으로는 다리의 불쾌감(근질거림, 기어가는 느낌, 타는 듯한 느낌), 안정 시 증상 악화, 다리를 움직이면 완화, 저녁·야간에 심화 등이 있습니다. 다리 경련은 하지불안증후군의 핵심 증상보다는 주기성 사지운동증(PLMS)과 동반될 때 나타납니다. 이러한 증상이 지속된다면 신경과 전문의 상담을 권고드립니다.', 1272, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '하지불안증후군', '하지불안증후군', 'DIAGNOSIS', '다리의 불안감과 움직임 충동, 안절부절못하는 증상이 있다면 신경과 또는 수면의학과 전문의를 방문하여 하지불안증후군 진단을 받는 것이 적합합니다. 수면 문제가 동반된다면 수면클리닉에서 수면다원검사도 함께 받는 것이 도움이 됩니다. 증상이 심하고 일상생활에 지장을 준다면 빠른 전문의 진료를 권고드립니다.', 1273, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '하지불안증후군', '하지불안증후군', 'TREATMENT', '하지불안증후군의 다리 간질거림과 불쾌감 완화를 위해 도파민 작용제(프라미펙솔, 로티고틴 등)가 일차 치료제로 사용됩니다. 철분 결핍이 원인인 경우 철분 보충 치료가 효과적이며, 비약물 치료로는 규칙적인 운동, 다리 마사지, 온냉요법 등이 도움이 됩니다. 치료 약물은 부작용이 있을 수 있으므로 반드시 신경과 전문의의 지도 아래 복용하시기 바랍니다.', 1274, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '해리 장애', '해리장애', 'MEDICATION', '해리 장애 치료에 사용되는 항우울제, 항불안제 등은 위장관 불편감(메스꺼움, 구역)을 초기 부작용으로 유발할 수 있으며, 이는 약물이 장애를 악화시키는 것이 아닙니다. 이러한 부작용은 보통 복용 초기에 나타나며 시간이 지나면 호전되는 경우가 많습니다. 부작용이 심하거나 지속된다면 처방 의사 또는 정신건강의학과 전문의와 상담하여 약물 조정을 받으시기 바랍니다.', 1275, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '해리 장애', '해리장애', 'CAUSE', '해리 장애의 원인으로 성적 학대, 신체적 폭력, 부모의 사망 등 심각한 외상 경험이 중요한 역할을 하는 것으로 알려져 있습니다. 특히 아동기 반복적 외상은 해리 증상 발생에 가장 큰 위험 요인으로 꼽히지만, 개인의 심리적 취약성과 지지 환경에 따라 영향이 다를 수 있습니다. 정확한 원인 파악과 치료를 위해 정신건강의학과 전문의 상담을 권고드립니다.', 1276, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '해리 장애', '해리장애', 'DEFINITION', '해리성 기억 상실은 외상이나 극심한 스트레스로 인해 중요한 개인 정보나 특정 사건에 대한 기억을 회상하지 못하는 증상입니다. 해리성 기억 상실 장애(해리성 건망증)는 이러한 증상이 진단 기준을 충족할 정도로 심각하고 지속적으로 나타나는 공식적인 정신건강 장애입니다. 두 개념은 증상의 심각도와 지속성에서 차이가 있으며, 전문의의 정확한 진단이 필요합니다.', 1277, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '해리 장애', '해리장애', 'SYMPTOM', '해리 장애에서 나타나는 기억력 저하와 의식 장애는 주로 감당하기 어려운 심리적 외상이나 극심한 스트레스에 대한 방어 기제로 발생합니다. 뇌가 고통스러운 경험을 의식에서 분리시키는 과정에서 해리 증상이 나타나며, 이는 심리적 자기보호 기능의 일환입니다. 증상이 지속된다면 정신건강의학과 전문의의 정확한 평가와 치료를 받으시기 바랍니다.', 1278, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '해리 장애', '해리장애', 'DIAGNOSIS', '해리 장애는 정체성, 기억, 의식, 인식의 정상적 통합이 붕괴되는 증상을 특징으로 하며, 해리성 정체성 장애, 해리성 건망증, 이인증/비현실감 장애 등이 포함됩니다. 진단은 정신건강의학과 전문의가 DSM-5 기준에 따라 구조화된 면담과 심리검사를 통해 이루어지며, 다른 정신질환 및 신체 질환을 배제하는 과정을 포함합니다. 증상이 의심되면 정신건강의학과를 방문하시기 바랍니다.', 1279, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '해리 장애', '해리장애', 'TREATMENT', '외상 경험으로 인한 해리 장애의 치료에는 트라우마 중심 인지행동치료(TF-CBT), 안구운동 민감소실 및 재처리 요법(EMDR) 등이 효과적으로 활용됩니다. 안전한 치료 환경에서 외상 기억을 단계적으로 처리하는 것이 핵심이며, 필요 시 불안이나 우울 증상 조절을 위한 약물 치료도 병행합니다. 해리 장애 치료는 전문적인 정신건강의학과 치료가 필수적이므로 반드시 전문의와 상담하시기 바랍니다.', 1280, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '행동 및 충동 장애', '행동및충동장애', 'PREVENTION', '행동 및 충동 장애 예방을 위해 청소년은 분노와 감정을 건강하게 표현하는 법을 배우고, 충동적 행동 전 결과를 생각하는 습관을 기르는 것이 중요합니다. 규칙적인 수면, 균형 잡힌 식사, 적절한 운동 등 건강한 생활습관 유지도 충동 조절에 도움이 됩니다. 가정과 학교에서의 안정적인 환경과 정서적 지지가 예방에 중요하며, 증상이 우려된다면 소아청소년 정신건강의학과 상담을 권고드립니다.', 1281, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '행동 및 충동 장애', '행동및충동장애', 'CAUSE', '행동 및 충동 장애는 유전적 요인, 뇌의 전두엽 기능 이상(충동 조절 담당), 세로토닌·도파민 등 신경전달물질 불균형이 주요 원인으로 꼽힙니다. 외상 경험, 불안정한 가정환경, 아동기 학대, 또래 관계 문제 등 환경적 요인도 중요한 역할을 합니다. 복합적인 원인이 작용하므로 증상이 나타나면 정신건강의학과 전문의의 정확한 평가와 치료 계획이 필요합니다.', 1282, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '행동 및 충동 장애', '행동및충동장애', 'DEFINITION', '행동 및 충동 장애를 가진 아동·청소년은 감정 조절의 어려움, 공격적 행동, 규칙 위반, 무단 결석, 재산 파괴 등의 행동 변화가 나타날 수 있습니다. 또한 충동적 결정, 또래 관계 어려움, 학업 저하 등이 함께 나타나는 경우가 많습니다. 이러한 변화가 지속된다면 소아청소년 정신건강의학과 전문의의 조기 평가와 개입이 매우 중요합니다.', 1283, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '행동 및 충동 장애', '행동및충동장애', 'SYMPTOM', '행동 및 충동 장애는 충동 조절의 어려움이 핵심이며, 층간소음 보복행위 자체가 장애의 원인으로 지목되지는 않습니다. 그러나 분노 조절 문제나 충동적 공격 성향이 있는 경우 층간소음과 같은 외부 자극에 과잉 반응하여 보복 행동으로 이어질 수 있습니다. 충동적이고 타인에게 해가 되는 행동이 반복된다면 정신건강의학과 전문의 상담을 받으시기 바랍니다.', 1284, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '행동 및 충동 장애', '행동및충동장애', 'TREATMENT', '행동 및 충동 장애 치료에는 기분 안정제(발프로에이트, 리튬), 항충동 효과가 있는 항정신병 약물, ADHD가 동반된 경우 중추신경자극제(메틸페니데이트) 등이 사용될 수 있습니다. 약물 치료는 반드시 전문의의 처방에 따라 이루어져야 하며, 인지행동치료와 병행하는 것이 효과적입니다. 치료 방법과 약물 선택은 정신건강의학과 전문의와의 상담을 통해 결정하시기 바랍니다.', 1285, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '히스테리성 인격장애', '히스테리성인격장애', 'DIET_LIFE', '히스테리성 인격장애(연극성 인격장애)를 가진 가족을 위해서는 일관된 경계 설정과 명확한 의사소통이 중요합니다. 가족 전체가 함께 가족치료에 참여하거나, 가족 구성원 개인이 심리상담을 받으면 감정 소진을 예방하고 안정을 유지하는 데 도움이 됩니다. 환자 본인의 치료와 함께 가족의 심리적 지지를 위해 정신건강의학과 전문의 또는 심리상담사와 상담하시기 바랍니다.', 1286, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '히스테리성 인격장애', '히스테리성인격장애', 'MEDICATION', '히스테리성 인격장애(연극성 인격장애)는 예방을 위해 특정 약물을 복용해야 하는 질환으로 정립되어 있지 않습니다. 만성적인 스트레스가 인격장애 증상에 영향을 줄 수 있으므로 스트레스 관리, 규칙적인 생활습관, 심리상담 등이 도움이 됩니다. 인격장애 예방 및 치료에 관심이 있다면 정신건강의학과 전문의와 상담하시기 바랍니다.', 1287, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '히스테리성 인격장애', '히스테리성인격장애', 'CAUSE', '히스테리성 인격장애(연극성 인격장애)는 어린 시절 정서적 방치, 불안정한 애착 관계, 부모로부터의 불충분한 사랑 경험이 발병에 영향을 미칠 수 있습니다. 이러한 경험이 정서 조절 능력 발달에 영향을 주어 과도한 관심 추구 행동 등으로 이어질 수 있습니다. 과거 경험으로 인한 어려움이 있다면 정신건강의학과 또는 심리상담 전문가의 치료적 도움을 받으시기 바랍니다.', 1288, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '히스테리성 인격장애', '히스테리성인격장애', 'DEFINITION', '히스테리성 인격장애(연극성 인격장애)는 과도한 감정 표현과 지속적인 관심 추구를 핵심 특징으로 하는 성격장애입니다. 주요 증상으로는 타인의 관심을 끌기 위한 극적 행동, 피상적이고 급변하는 감정 표현, 외모 집착, 암시에 쉽게 영향받는 경향 등이 있습니다. 증상이 지속되어 일상생활과 대인관계에 어려움이 생긴다면 정신건강의학과 전문의 진료를 권고드립니다.', 1289, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '히스테리성 인격장애', '히스테리성인격장애', 'SYMPTOM', '히스테리성 인격장애에서 자기 중심성은 자신이 항상 주목받아야 한다는 욕구로 나타나며, 타인을 조종하는 행동은 감정적 호소, 과장된 반응, 외모를 이용한 유혹 등의 방식으로 표현됩니다. 이러한 행동 패턴은 무의식적으로 이루어지는 경우가 많으며, 대인관계에서 반복적인 갈등을 유발합니다. 증상이 심하다면 정신건강의학과 전문의를 통한 심리치료를 받는 것이 도움이 됩니다.', 1290, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '히스테리성 인격장애', '히스테리성인격장애', 'DIAGNOSIS', '과도한 감정 표현과 관심 추구 증상으로 히스테리성 인격장애(연극성 인격장애)가 의심된다면 정신건강의학과 전문의를 방문하여 진단 및 치료를 받는 것이 적절합니다. 성격장애 진단은 전문적인 심리평가와 구조화된 면담을 통해 이루어집니다. 증상이 일상생활이나 대인관계에 지장을 준다면 빠른 시일 내 정신건강의학과 상담을 받으시기 바랍니다.', 1291, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '히스테리성 인격장애', '히스테리성인격장애', 'TREATMENT', '히스테리성 인격장애(연극성 인격장애)로 일상생활이 어려운 경우 정신건강의학과에서의 장기적인 심리치료(특히 정신역동치료, 인지행동치료)가 핵심 치료법입니다. 증상에 따라 기분 안정제나 항불안제 등 약물 치료를 병행하기도 합니다. 배우자가 치료를 거부하는 경우도 많으므로, 필요하다면 가족치료나 부부상담도 함께 고려하고 전문의와 상담하시기 바랍니다.', 1292, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '각막염', '각막염', 'CHECKUP', '각막염 진단을 위해 안과에서는 세극등 현미경 검사를 통해 각막 상태를 직접 관찰합니다. 원인균을 확인하기 위해 각막 찰과 검체를 채취하여 균 배양 및 감수성 검사를 시행하기도 합니다. 정확한 진단과 적절한 치료를 위해 안과 전문의를 방문하시기 바랍니다.', 1293, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '각막염', '각막염', 'DIET_LIFE', '각막염 회복을 위해 비타민 A(당근, 달걀, 유제품)와 비타민 C(과일, 채소) 섭취가 안구 건강에 도움이 됩니다. 콘택트렌즈 착용을 일시 중단하고, 눈을 손으로 비비지 않으며, 자외선 차단 안경을 착용하는 것이 중요합니다. 증상이 지속되거나 악화된다면 반드시 안과 전문의의 치료를 받으시기 바랍니다.', 1294, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '각막염', '각막염', 'MEDICATION', '세균성 각막염에는 항생제 안약(플루오로퀴놀론 계열 등)이 주로 사용되며, 보통 1~2주 간 집중 점안 치료를 합니다. 항생제의 효과는 원인균의 종류와 감수성에 따라 다르며, 증상이 호전되어도 처방된 기간 동안 꾸준히 사용해야 내성을 예방할 수 있습니다. 각막염의 정확한 원인과 적합한 약물 선택은 안과 전문의와 상담 후 결정하시기 바랍니다.', 1295, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '각막염', '각막염', 'PREVENTION', '포도막염과 각막염은 서로 다른 눈의 구조에 발생하는 질환으로 원인과 치료가 다릅니다. 포도막염 예방을 위해서는 면역 강화에 도움이 되는 항산화 식품(블루베리, 시금치, 당근 등) 섭취가 도움이 될 수 있으며, 포도 자체가 특별한 예방 효과가 있다는 의학적 근거는 부족합니다. 눈 이상 증상이 있다면 자의적 판단보다 안과 전문의를 방문하시기 바랍니다.', 1296, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '각막염', '각막염', 'CAUSE', '콘택트렌즈 장시간 착용은 각막의 산소 공급을 차단하고, 렌즈와 각막 사이에 세균이 번식하기 좋은 환경을 만들어 각막염 위험을 크게 높입니다. 렌즈 착용 시 각막 미세 손상이 발생하면 병원체가 침투하기 쉬워지므로, 착용 시간 준수와 철저한 위생 관리가 각막염 예방에 필수적입니다. 각막염 예방을 위해 권장 착용 시간을 지키고 정기적인 안과 검진을 받으시기 바랍니다.', 1297, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '각막염', '각막염', 'DEFINITION', '각막염은 눈의 투명한 앞면인 각막에 염증이 발생하는 질환으로, 세균, 바이러스, 진균, 아칸토아메바 등의 감염이나 비감염성 원인(외상, 건조증 등)에 의해 발생합니다. 주요 증상으로는 눈 통증, 충혈, 시력 저하, 눈물 흘림, 눈부심, 눈꺼풀 경련 등이 있습니다. 방치 시 시력 손상으로 이어질 수 있어 증상이 나타나면 신속히 안과를 방문하시기 바랍니다.', 1298, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '각막염', '각막염', 'SYMPTOM', '각막염으로 인한 눈 통증, 흐릿한 시력, 충혈이 심화되면 각막 궤양, 각막 천공, 시력 영구 손상 등의 심각한 합병증으로 이어질 수 있습니다. 특히 시력이 급격히 저하되거나 통증이 매우 심한 경우 즉시 안과를 방문해야 합니다. 조기에 적절한 치료를 받는 것이 시력 보호에 매우 중요합니다.', 1299, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '각막염', '각막염', 'DIAGNOSIS', '각막염 진단을 위해 세극등 현미경 검사가 가장 기본적으로 사용되며, 각막의 염증 범위와 깊이를 관찰합니다. 원인균 확인을 위해 각막 표면의 검체를 채취하여 균 배양 검사를 시행하고, 필요 시 공초점 현미경 검사나 각막 지형도 검사도 활용됩니다. 정확한 진단을 위해 안과 전문의의 진찰을 받으시기 바랍니다.', 1300, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '각막염', '각막염', 'TREATMENT', '꽃가루 시기에 발생하는 알레르기성 각막염의 가려움증에는 항히스타민제 안약과 비만세포 안정제 안약이 효과적으로 사용됩니다. 필요 시 단기간 스테로이드 안약을 처방받아 사용할 수 있으나, 스테로이드 안약은 반드시 안과 전문의의 처방에 따라야 합니다. 자의적인 약물 사용은 각막 손상을 악화시킬 수 있으므로 반드시 안과 전문의의 진료를 먼저 받으시기 바랍니다.', 1301, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '결막염', '결막염', 'PREVENTION', '렌즈 착용 시 손을 깨끗이 씻지 않으면 손에 있는 세균이나 바이러스(아데노바이러스 등)가 렌즈를 통해 눈으로 전파되어 출혈성 결막염을 일으킬 수 있습니다. 출혈성 결막염은 전염성이 강하므로 손 위생이 가장 효과적인 예방법입니다. 렌즈 착용 및 제거 전 비누로 30초 이상 손 씻기를 반드시 실천하시기 바랍니다.', 1302, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '결막염', '결막염', 'CAUSE', '출혈성 결막염은 엔테로바이러스 또는 아데노바이러스 감염이 주요 원인으로, 눈의 충혈, 출혈, 통증, 분비물, 가려움증이 나타나며 회복이 느릴 수 있습니다. 바이러스성 결막염은 항바이러스 치료제가 제한적이라 자연 회복되기까지 시간이 걸리며 그 사이 증상이 오래 지속되는 것입니다. 감염 예방을 위해 손 위생을 철저히 하고, 증상이 심하면 안과 전문의의 진료를 받으시기 바랍니다.', 1303, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '결막염', '결막염', 'DEFINITION', '알레르기성 결막염은 꽃가루, 집먼지진드기, 동물 털 등의 알레르겐에 노출되었을 때 면역계가 과민 반응하여 발생합니다. 눈의 점막이 알레르겐에 직접 접촉하면 히스타민 등의 화학물질이 분비되어 가려움, 충혈, 눈물 흘림 등의 증상이 나타납니다. 알레르기 원인 물질을 파악하고 회피하는 것이 중요하며, 증상이 심할 경우 안과 전문의의 치료를 받으시기 바랍니다.', 1304, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '결막염', '결막염', 'SYMPTOM', '아침에 눈 뜨기 힘들 정도로 눈곱이 끼고 충혈이 심하다면 세균성 또는 바이러스성 결막염의 전형적인 증상일 수 있습니다. 세균성 결막염은 다량의 화농성 눈곱, 바이러스성 결막염은 수양성 분비물이 특징적으로 나타납니다. 이러한 증상이 있다면 안과 전문의를 방문하여 정확한 원인 파악과 치료를 받으시기 바랍니다.', 1305, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '결막염', '결막염', 'DIAGNOSIS', '알레르기 결막염이 심해진다면 안과를 방문하여 진단 및 치료를 받는 것이 적절합니다. 안과에서는 항히스타민제 또는 비만세포 안정제 안약을 처방하며, 증상에 따라 스테로이드 안약도 단기간 처방할 수 있습니다. 예약 후 방문하는 것이 일반적이며, 지역 안과 병·의원에 전화 또는 온라인으로 예약하여 진료 받으시기 바랍니다.', 1306, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '결막염', '결막염', 'TREATMENT', '결막염의 종류에 따라 경과가 다른데, 경미한 바이러스성 결막염은 1~2주 내 자연 호전되기도 하지만, 세균성이나 알레르기성 결막염은 적절한 치료 없이는 증상이 지속되거나 악화될 수 있습니다. 치료 없이 방치하면 각막염 등 합병증이 생길 수 있으므로 무조건 기다리는 것은 권장되지 않습니다. 증상이 48시간 이상 지속된다면 안과 전문의의 진료를 받는 것이 안전합니다.', 1307, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '근시', '근시', 'MEDICATION', '근시 치료에는 저농도 아트로핀 안약이 근시 진행 억제 효과가 있는 것으로 연구되어 있으며, 특히 소아·청소년에게 사용됩니다. 그러나 이미 진행된 근시를 회복시키는 약물은 현재 없으며, 교정(안경, 렌즈)이나 수술적 방법이 시력 개선에 활용됩니다. 약물 치료에 대해서는 안과 전문의와 상담 후 결정하시기 바랍니다.', 1308, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '근시', '근시', 'PREVENTION', '어린이·청소년의 근시 예방을 위해 하루 1~2시간 이상의 야외 활동이 효과적인 것으로 알려져 있습니다. 독서나 스마트폰 사용 시 30분마다 20분간 먼 곳을 바라보는 20-20-20 규칙을 실천하고, 적절한 조명 아래서 올바른 자세로 책을 읽는 습관이 중요합니다. 어두운 곳에서의 스마트폰 사용과 장시간 근거리 작업을 최소화하는 것도 권장됩니다.', 1309, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '근시', '근시', 'CAUSE', '어두운 환경에서 스마트폰이나 책을 보는 것은 눈의 피로를 증가시키지만, 근시의 직접적인 원인으로 확립된 것은 아닙니다. 근시 발생의 주요 환경적 요인은 장시간 근거리 작업과 야외 활동 부족으로 알려져 있습니다. 밤에 불을 끄고 스마트폰을 사용하는 습관은 눈 건강에 좋지 않으므로 충분한 조명 아래서 사용하는 것이 권장됩니다.', 1310, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '근시', '근시', 'DEFINITION', '가까운 것은 잘 보이고 먼 것은 흐릿하게 보이는 증상은 근시의 대표적인 특징으로, 근시를 의심해볼 수 있는 소견입니다. 근시는 안구의 전후 길이가 길거나 각막·수정체의 굴절력이 강해 망막 앞에 초점이 맺히는 굴절 이상입니다. 이러한 증상이 있다면 안과에서 시력 검사와 굴절 검사를 통해 정확한 진단을 받으시기 바랍니다.', 1311, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '근시', '근시', 'SYMPTOM', '근시의 발생에는 유전적 요인과 환경적 요인이 복합적으로 작용합니다. 부모 모두 근시인 경우 자녀의 근시 발생률이 높아지며, 환경적으로는 장시간 근거리 작업, 야외 활동 부족, 스마트폰·컴퓨터 과다 사용이 근시 진행을 촉진합니다. 유전적 소인이 있더라도 올바른 생활습관으로 근시 진행을 늦출 수 있습니다.', 1312, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '근시', '근시', 'DIAGNOSIS', '근시는 가까운 물체는 선명하게 보이지만 먼 곳의 물체는 흐릿하게 보이는 굴절 이상입니다. 눈을 찡그리거나 TV나 칠판에 가까이 다가가려는 행동이 근시의 징후일 수 있으며, 안과에서 시력 검사와 굴절 검사로 진단합니다. 이러한 증상이 있다면 안과 전문의를 방문하여 정확한 검사를 받으시기 바랍니다.', 1313, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '근시', '근시', 'TREATMENT', '근시 교정을 위해 안경이나 소프트/하드 콘택트렌즈를 착용하는 것이 가장 일반적인 방법입니다. 성인의 경우 라식, 라섹, 렌즈삽입술(ICL) 등 굴절 교정 수술을 고려할 수 있으며, 소아·청소년에서는 드림렌즈(각막굴절교정술)나 저농도 아트로핀으로 근시 진행을 억제합니다. 적합한 치료 방법은 나이, 근시 정도 등을 고려하여 안과 전문의와 상담 후 결정하시기 바랍니다.', 1314, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '난시', '난시', 'CAUSE', '난시는 각막이나 수정체의 형태가 완전한 구형이 아니어서 빛이 한 점에 초점을 맺지 못해 생기며, 근시와 함께 동반되는 경우가 흔합니다. 독서 시 책이나 사물의 초점이 맞지 않고 흐릿하게 보이는 현상은 난시의 대표적인 증상으로, 망막에 여러 초점이 생기는 굴절 이상에서 비롯됩니다. 안과에서 굴절 검사를 통해 정확히 확인할 수 있습니다.', 1315, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '난시', '난시', 'DEFINITION', '복시(사물이 두 개로 보임)는 사시, 눈 근육 이상, 신경 문제 등 다양한 원인으로 발생하며, 난시와 유사하게 물체가 흐릿하거나 겹쳐 보이는 증상이 나타날 수 있습니다. 난시는 주로 물체 경계가 흐릿하거나 왜곡되어 보이는 반면, 복시는 물체가 명확히 두 개로 나뉘어 보이는 점에서 다릅니다. 두 증상을 정확히 구별하기 위해 안과 전문의의 진찰이 필요합니다.', 1316, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '난시', '난시', 'SYMPTOM', '가까운 곳과 먼 곳 모두 흐릿하게 보이는 증상은 난시의 가능성이 있으며, 근시나 원시가 동반된 복합 굴절 이상일 수도 있습니다. 난시는 거리에 관계없이 시야가 흐릿하거나 왜곡되어 보이는 것이 특징입니다. 정확한 진단을 위해 안과에서 시력 및 굴절 검사를 받으시기 바랍니다.', 1317, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '난시', '난시', 'DIAGNOSIS', '난시는 안과에서 굴절 검사(자동 굴절 검사기 및 검영기 검사)를 통해 각막의 굴절력 차이를 측정하여 진단합니다. 뿌옇게 보이거나 물체가 왜곡되어 보이는 증상이 있다면 안과를 방문하여 시력 및 굴절 검사를 받는 것이 필요합니다. 안과 전문의의 처방에 따라 안경이나 토릭 콘택트렌즈로 교정할 수 있습니다.', 1318, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '난시', '난시', 'TREATMENT', '초등학생의 한쪽 눈 시력 저하는 약시 가능성이 있으므로 조기에 안과 전문의 진료를 받는 것이 매우 중요합니다. 약시의 경우 좋은 눈을 가리고 약한 눈을 사용하는 가림 치료(패치 치료)가 효과적이며, 굴절 이상이 있다면 안경 교정을 병행합니다. 적절한 치료 시기를 놓치면 시력 회복이 어려울 수 있으므로 반드시 안과 전문의와 상담하시기 바랍니다.', 1319, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '노안', '노안', 'PREVENTION', '컴퓨터와 스마트폰의 장시간 근거리 사용은 눈의 조절근을 과도하게 사용하여 피로와 일시적인 시력 저하를 일으키지만, 노안 자체를 직접 유발하지는 않습니다. 노안은 수정체 탄력 감소로 인한 자연스러운 노화 현상이나, 디지털 기기 과다 사용으로 증상을 더 빨리 인지하게 될 수 있습니다. 눈의 피로를 줄이기 위해 정기적인 휴식과 적절한 거리 유지가 권장됩니다.', 1320, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '노안', '노안', 'CAUSE', '노안은 나이가 들면서 수정체의 탄력이 감소하고 조절 능력이 떨어져 근거리 초점 조절이 어려워지는 자연적인 노화 과정입니다. 주로 40대 이후에 시작되며, 가까운 글씨를 읽기 어렵거나 눈이 쉽게 피로해지는 증상이 나타납니다. 근시가 있는 경우 노안의 진행 양상이 다르게 느껴질 수 있으므로, 정확한 평가를 위해 안과 전문의 진료를 받으시기 바랍니다.', 1321, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '노안', '노안', 'DEFINITION', '근거리 시력 저하와 시야 흐림이 나타나면 먼저 안과를 방문하여 노안, 백내장, 기타 안질환 여부를 확인하는 것이 중요합니다. 노안으로 진단된 경우 돋보기 안경이나 다초점 안경, 콘택트렌즈로 교정할 수 있으며, 라식·라섹 등 수술적 방법도 고려할 수 있습니다. 증상이 갑자기 심해지거나 눈 통증, 두통이 동반된다면 즉시 안과를 방문하시기 바랍니다.', 1322, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '노안', '노안', 'SYMPTOM', '40대에 눈이 침침해지고 야간 시력이 저하되는 것은 수정체의 노화로 인한 노안의 초기 증상일 수 있습니다. 야간에는 동공이 확대되면서 굴절 이상이 더 두드러져 시력 저하가 심해지는 경향이 있습니다. 이러한 증상이 지속된다면 안과 전문의를 방문하여 노안 외에 녹내장, 백내장 등 다른 안질환이 없는지 확인하시기 바랍니다.', 1323, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '노안', '노안', 'DIAGNOSIS', '근시, 난시, 노안 진단을 위해 안과에서는 시력 검사, 굴절 검사, 조절력 검사, 안압 측정, 안저 검사 등을 시행합니다. 가까운 물체가 흐릿하면 노안 또는 원시, 먼 곳이 흐릿하면 근시, 모든 거리에서 흐릿하면 난시를 의심하지만, 자가 판단보다 안과 전문의의 정확한 검사가 필요합니다. 정기적인 안과 검진을 통해 굴절 이상 여부를 확인하시기 바랍니다.', 1324, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '노안', '노안', 'TREATMENT', '40대 중반 노안 증상 개선을 위해 돋보기 안경이나 다초점 안경 착용이 가장 기본적인 교정 방법입니다. 레이저 수술(모노비전 라식 등)이나 다초점 인공수정체 삽입술을 고려할 수도 있으며, 이는 개인의 생활방식과 눈 상태에 따라 적합성을 판단해야 합니다. 적절한 치료 방법 선택을 위해 안과 전문의와 상담하시기 바랍니다.', 1325, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '녹내장', '녹내장', 'CHECKUP', '녹내장은 초기에는 증상이 거의 없어 자각하기 어렵기 때문에 이미 진단을 받았다면 정기적인 추적 관찰이 매우 중요합니다. 진단의 정확성을 높이기 위해 안압 검사, 시야 검사, 시신경 검사 등을 여러 번에 걸쳐 시행하는 것이 일반적입니다. 다른 의사에게 재검을 원한다면 녹내장 전문 안과 의사를 찾아 2차 소견을 구하는 것이 좋습니다.', 1326, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '녹내장', '녹내장', 'MEDICATION', '녹내장 안약 치료 중 비염 약을 복용할 때, 항콜린제 성분(덱스클로르페니라민, 클로르페니라민 등)이 포함된 항히스타민제는 안압을 상승시킬 수 있어 주의가 필요합니다. 교감신경 자극제(슈도에페드린 등) 성분도 일부 녹내장 환자에게 위험할 수 있습니다. 비염 약 복용 전 반드시 담당 안과 전문의 또는 약사에게 녹내장 병력을 알리고 안전한 약물을 선택하시기 바랍니다.', 1327, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '녹내장', '녹내장', 'PREVENTION', '녹내장 위험이 있는 경우 안압을 높이는 과도한 수분 섭취, 카페인, 흡연을 피하는 것이 좋습니다. 항산화 식품(녹황색 채소, 과일)을 충분히 섭취하고, 정기적인 유산소 운동이 안압 조절에 도움이 될 수 있습니다. 무엇보다 가족력이 있다면 40세 이후 매년 안과 정기 검진을 통해 조기 발견 및 관리가 가장 중요합니다.', 1328, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '녹내장', '녹내장', 'EXERCISE', '녹내장 환자에게는 안압을 과도하게 높이지 않는 유산소 운동(걷기, 수영, 자전거 타기 등)이 안압 조절에 도움이 됩니다. 반면 역도, 물구나무서기, 다이빙 등 안압을 급격히 올리는 운동은 피하는 것이 좋습니다. 운동 종류와 강도에 대해서는 담당 안과 전문의와 상담 후 결정하시기 바랍니다.', 1329, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '녹내장', '녹내장', 'CAUSE', '백내장, 녹내장, 당뇨망막병증은 서로 다른 질환으로, 한 눈에서 다른 눈으로 또는 사람 간에 전파되는 감염성 질환이 아닙니다. 백내장은 수정체 혼탁, 녹내장은 시신경 손상, 당뇨망막병증은 당뇨병으로 인한 망막 혈관 손상이 원인입니다. 이들 질환은 노화, 유전, 전신 질환 등 내인성 원인으로 발생하므로 정기 안과 검진으로 조기 발견이 중요합니다.', 1330, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '녹내장', '녹내장', 'DEFINITION', '녹내장은 안압 상승 등으로 인해 시신경이 손상되어 시야가 점진적으로 좁아지는 질환입니다. 초기에는 증상이 없는 경우가 많고, 진행하면 주변 시야 손실, 시야 흐림이 나타납니다. 눈이 침침하고 두통·구토가 동반되면 급성 폐쇄각 녹내장일 수 있으므로 즉시 안과를 방문해야 하며, 정기적인 안과 검진이 조기 발견에 중요합니다.', 1331, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '녹내장', '녹내장', 'SYMPTOM', '녹내장의 증상은 초기에는 거의 없다가, 진행하면서 주변 시야부터 점차 시야가 좁아지는 형태로 나타납니다. 안개가 낀 듯 흐릿한 시야, 빛 주위의 무지개빛 후광, 눈 통증 등이 급성 녹내장에서 나타날 수 있습니다. 이러한 증상은 녹내장 외에도 백내장, 망막 질환 등에서도 나타날 수 있으므로 안과 전문의의 정확한 진단이 필요합니다.', 1332, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '녹내장', '녹내장', 'DIAGNOSIS', '눈 통증, 흐린 시야, 빛 민감성이 있다면 안과 전문의를 방문하여 정확한 진단을 받는 것이 가장 중요합니다. 안과에서는 안압 측정, 시신경 검사, 시야 검사, 세극등 검사 등을 통해 녹내장, 포도막염, 각막 질환 등 다양한 원인을 감별합니다. 증상이 갑작스럽고 심하다면 급성 녹내장이나 안내염 가능성이 있으므로 즉시 응급 안과 진료를 받으시기 바랍니다.', 1333, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '녹내장', '녹내장', 'TREATMENT', '녹내장은 완치가 어렵지만 조기 발견과 지속적인 치료로 진행을 늦추고 시력을 보존할 수 있습니다. 안압 하강 안약이 가장 기본적인 치료이며, 약물로 조절이 어려운 경우 레이저 치료(선택적 레이저 섬유주 성형술) 또는 수술(섬유주 절제술 등)을 시행합니다. 실명 예방을 위해 정기적인 안과 검진과 꾸준한 치료가 필수적이므로 안과 전문의의 지속적인 관리를 받으시기 바랍니다.', 1334, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '당뇨망막병증', '당뇨망막병증', 'CHECKUP', '비문증으로 인한 유리체 출혈이 있다면 시야가 갑자기 흐릿해지거나 빨간빛이 나타나는 증상이 동반될 수 있습니다. 왼쪽 눈이 뿌옇게 보이는 증상은 유리체 출혈의 심한 정도에 따라 다를 수 있습니다. 이러한 증상이 갑자기 나타난다면 망막 손상이나 박리의 위험이 있으므로 즉시 안과 전문의를 방문하시기 바랍니다.', 1335, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '당뇨망막병증', '당뇨망막병증', 'PREVENTION', '당뇨망막병증 예방을 위해 혈당을 안정적으로 유지하는 것이 가장 중요하며, 저혈당 지수 식품(통곡물, 채소, 콩류) 위주의 식단이 도움이 됩니다. 정기적인 유산소 운동, 금연, 혈압·혈중지질 관리도 망막 혈관 보호에 필수적입니다. 당뇨 진단 후 매년 안과 검진을 통해 조기 발견과 관리를 받으시기 바랍니다.', 1336, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '당뇨망막병증', '당뇨망막병증', 'CAUSE', '당뇨망막병증의 위험 요인으로는 당뇨 유병 기간 증가, 혈당 조절 불량, 고혈압, 이상지질혈증, 신장 합병증, 흡연, 비만 등이 있습니다. 특히 당뇨 유병 기간이 길수록 망막병증 발생 위험이 크게 높아집니다. 이러한 위험 인자들을 종합적으로 관리하는 것이 당뇨망막병증 예방에 중요하며, 정기적인 안과 및 내과 검진을 권고드립니다.', 1337, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '당뇨망막병증', '당뇨망막병증', 'DEFINITION', '당뇨망막병증은 당뇨병 환자에서 지속적인 고혈당으로 인해 망막의 미세 혈관이 손상되는 질환입니다. 초기에는 무증상이지만 진행하면서 시야 흐림, 갑작스러운 시력 저하, 빛 번짐, 비문증 등이 나타날 수 있습니다. 방치 시 실명으로 이어질 수 있으므로 당뇨 환자는 정기적인 안과 검진과 엄격한 혈당 관리가 필수입니다.', 1338, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '당뇨망막병증', '당뇨망막병증', 'SYMPTOM', '당뇨망막병증은 초기(비증식성 단계)에 증상이 거의 없어 환자 본인이 알아채기 어려운 경우가 많습니다. 증상이 전혀 없더라도 당뇨 환자라면 망막 손상이 진행 중일 수 있으므로, 정기적인 안과 검진이 반드시 필요합니다. 무증상 상태에서 조기 발견해야 치료 효과가 높으므로 당뇨 진단 후 매년 안저 검사를 받으시기 바랍니다.', 1339, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '당뇨망막병증', '당뇨망막병증', 'DIAGNOSIS', '당뇨망막병증이 의심될 때 안과에서는 시력 검사, 안압 측정, 세극등 검사, 산동 후 안저 검사, 형광안저조영술, 빛간섭단층촬영(OCT) 등을 시행합니다. 이를 통해 망막 혈관의 변화, 부종, 출혈 및 신생 혈관 생성 여부를 평가합니다. 당뇨 환자는 내과와 안과 전문의 협진을 통해 혈당 관리와 안과 치료를 함께 받는 것이 중요합니다.', 1340, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '당뇨망막병증', '당뇨망막병증', 'TREATMENT', '당뇨망막병증 치료에는 혈당 조절을 위한 내과적 치료 외에, 안과적으로는 유리체강 내 항혈관내피성장인자(anti-VEGF) 주사(베바시주맙, 라니비주맙, 애플리버셉트 등)가 황반부종 및 신생 혈관 치료에 사용됩니다. 레이저 광응고술도 표준 치료로 활용됩니다. 약물 가격은 종류와 급여 여부에 따라 상이하며, 구체적인 치료 방법과 비용은 안과 전문의와 상담하시기 바랍니다.', 1341, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '망막 박리', '망막박리', 'PREVENTION', '망막 박리 예방을 위해 강한 충격이 가해질 수 있는 스포츠(복싱, 격투기 등) 시 안면 보호대나 고글 착용이 도움이 됩니다. 보호 장비는 외부 충격으로 인한 망막 박리를 예방하고 눈 손상 위험을 줄이는 효과가 있습니다. 고도 근시나 이전 망막 이상 병력이 있다면 정기적인 안과 검진을 통해 망막 열공을 조기에 발견하는 것이 중요합니다.', 1342, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '망막 박리', '망막박리', 'CAUSE', '망막 박리는 망막이 망막색소상피로부터 분리되어 발생하며, 주요 원인으로는 열공(망막 찢어짐), 당뇨 합병증, 외상, 염증 등이 있습니다. 사물이 찌그러져 보이거나 시야가 어둡게 보이는 증상은 망막이 박리되면서 시각 정보 처리에 이상이 생겨 나타나는 것입니다. 이러한 증상은 응급 상황이므로 즉시 안과 전문의에게 진찰받아야 합니다.', 1343, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '망막 박리', '망막박리', 'DEFINITION', '망막 박리는 망막이 안구 내벽에서 분리되는 안과적 응급 질환입니다. 초기 증상으로는 갑작스러운 비문증 증가, 빛 번쩍임(광시증), 커튼이 드리워진 것 같은 시야 결손, 시력 저하 등이 나타납니다. 치료하지 않으면 영구적인 시력 손실로 이어질 수 있으므로 이러한 증상이 생기면 즉시 안과 응급 진료를 받아야 합니다.', 1344, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '망막 박리', '망막박리', 'SYMPTOM', '눈을 움직일 때 여러 물체가 흐릿하게 보이거나 광시증이 나타나는 증상은 유리체 변성, 후유리체 박리, 망막 박리 등에서 주로 나타납니다. 특히 고도 근시, 노인, 안구 외상 경험자, 이전 안과 수술을 받은 사람에게서 더 흔히 발생합니다. 이러한 증상이 갑작스럽게 나타난다면 신속히 안과 전문의의 진찰을 받으시기 바랍니다.', 1345, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '망막 박리', '망막박리', 'DIAGNOSIS', '망막 박리 진단에는 세극등 현미경을 이용한 안저 검사가 기본이며, 동공 확대 후 간접검안경 검사를 통해 망막 전체를 확인합니다. 망막이 흐릿하게 보일 때는 초음파 검사(B-scan)로 박리 여부와 범위를 파악하고, 빛간섭단층촬영(OCT)으로 정밀 평가를 합니다. 증상 발생 즉시 안과를 방문하면 빠른 진단이 가능합니다.', 1346, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '망막 박리', '망막박리', 'TREATMENT', '망막 박리 치료에는 레이저 광응고술(열공 봉합), 냉동응고술, 공막돌륭술, 유리체절제술 등이 사용됩니다. 유리체절제술에서는 특수 유리체 절제기, 레이저, 실리콘 오일 또는 가스를 이용하여 박리된 망막을 원상 복구합니다. 치료 방법은 박리의 유형과 범위, 황반 침범 여부에 따라 안과 전문의가 결정하므로 전문의 상담이 반드시 필요합니다.', 1347, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '백내장', '백내장', 'PREVENTION', '백내장 예방을 위해 자외선 차단 선글라스 착용, 금연, 혈당 및 혈압 조절이 중요합니다. 루테인과 제아잔틴(시금치, 케일), 비타민 C(감귤류, 브로콜리), 비타민 E(견과류, 식물성 기름), 오메가-3 지방산이 수정체 건강에 도움이 되는 것으로 알려져 있습니다. 40세 이후 정기적인 안과 검진을 통해 조기 발견하는 것이 중요합니다.', 1348, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '백내장', '백내장', 'CAUSE', '노인성 백내장 외에도 당뇨병, 장기간 스테로이드 약물 복용, 자외선 과다 노출, 안구 외상, 방사선 노출, 선천성 요인(태내 감염, 유전) 등이 백내장을 유발할 수 있습니다. 젊은 나이에도 이러한 위험 요인에 노출될 경우 백내장이 발생할 수 있습니다. 시력 변화가 있다면 나이와 관계없이 안과 전문의를 방문하시기 바랍니다.', 1349, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '백내장', '백내장', 'DEFINITION', '안개가 낀 것처럼 시야가 뿌옇게 보이는 것은 백내장의 대표적인 증상으로, 수정체가 혼탁해지면서 빛이 산란되기 때문입니다. 백내장은 수정체(눈의 렌즈)가 혼탁해져 시야 흐림, 빛 번짐, 눈부심, 색 변화 등이 나타나는 질환으로, 주로 노화로 발생하지만 다른 원인도 있습니다. 증상이 심하여 일상생활에 지장이 있다면 수술적 치료를 고려하며, 안과 전문의와 상담하시기 바랍니다.', 1350, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '백내장', '백내장', 'SYMPTOM', '백내장이 진행되면 수정체가 혼탁해지면서 노안이 일시적으로 호전되는 ''수정체 근시'' 현상이 나타날 수 있습니다. 즉, 돋보기 없이도 가까운 것이 잘 보이다가 다시 시력이 저하되는 것은 백내장의 특징적인 증상 중 하나입니다. 이러한 증상이 지속된다면 안과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 1351, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '백내장', '백내장', 'DIAGNOSIS', '백내장 수술 여부는 시력 저하 정도, 일상생활의 불편함, 백내장의 진행 속도를 종합적으로 고려하여 결정합니다. 일반적으로 교정시력이 0.5 이하로 저하되거나 눈부심·복시 등으로 생활에 지장이 있을 때 수술을 권장합니다. 초기 백내장은 점안액 등으로 진행을 늦출 수 있으나, 수술 시기와 방법은 안과 전문의와 상담하여 결정하는 것이 중요합니다.', 1352, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '백내장', '백내장', 'TREATMENT', '현재까지 백내장을 근본적으로 치료하는 방법은 혼탁한 수정체를 제거하고 인공수정체를 삽입하는 수술이 유일합니다. 초기 단계에서는 카르노신 성분의 점안액이나 항산화제 등이 진행을 일부 늦출 수 있으나, 완치 효과는 없습니다. 정확한 치료 계획은 반드시 안과 전문의와 상담하시기 바랍니다.', 1353, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '복시', '복시', 'MEDICATION', '복시 치료에 사용되는 약물은 원인 질환에 따라 다르며, 중증 근무력증에는 항콜린에스테라제제(피리도스티그민), 신경 관련 원인에는 스테로이드 등이 사용됩니다. 이러한 치료약은 의사의 처방에 따라 적절히 사용하면 약물 남용의 위험이 낮습니다. 복시의 원인과 치료 방침은 전문의의 진단 후 결정되므로 임의로 약물을 사용하지 마십시오.', 1354, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '복시', '복시', 'PREVENTION', '중증 근무력증으로 인한 안검하수와 복시는 면역계 이상이 원인이므로, 충분한 수면과 과로를 피하는 것이 증상 완화에 도움이 됩니다. 식이 면에서는 균형 잡힌 영양 섭취와 함께 비타민 D, 오메가-3 등 면역 조절에 도움이 되는 영양소를 보충하는 것이 권장됩니다. 그러나 근본적인 치료와 생활 지침은 신경과 또는 안과 전문의의 지도하에 따르는 것이 중요합니다.', 1355, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '복시', '복시', 'CAUSE', '눈의 외상은 복시의 주요 원인 중 하나입니다. 안와 골절이나 외안근 손상이 발생하면 두 눈의 정렬이 틀어져 물체가 겹쳐 보이는 복시가 나타날 수 있습니다. 외상 후 복시 증상이 나타나면 안과 전문의를 즉시 방문하여 원인을 확인하고 적절한 치료를 받으시기 바랍니다.', 1356, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '복시', '복시', 'DEFINITION', '복시는 주로 두 눈의 정렬 불일치나 외안근·신경 이상으로 발생하며, 각막 이상도 한 눈에서 단안 복시를 유발할 수 있습니다. 눈의 건조함이나 충혈(실핏줄)은 복시의 직접적인 증상이라기보다는 안구건조증이나 결막염 등 다른 안과 질환의 증상일 가능성이 높습니다. 정확한 원인 감별을 위해 안과 전문의의 진찰을 받으시기 권장합니다.', 1357, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '복시', '복시', 'SYMPTOM', '복시의 주요 증상은 사물이 두 개로 겹쳐 보이는 것이며, 이와 함께 두통, 눈의 피로감, 눈을 찡그리는 행동이 동반될 수 있습니다. 또한 어지러움, 균형 감각 이상, 한쪽 눈을 가리면 증상이 사라지는 특징도 나타납니다. 이러한 증상이 지속된다면 신경과 또는 안과 전문의의 진료를 받으시기 바랍니다.', 1358, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '복시', '복시', 'DIAGNOSIS', '사물이 겹쳐 보이는 복시 증상은 안과적 원인(사시, 백내장) 외에도 뇌신경 마비, 뇌혈관 질환, 당뇨병성 신경병증 등 전신 질환과 관련될 수 있습니다. 증상이 수년간 지속된 경우라도 원인 규명이 중요하므로 안과 및 신경과 전문의의 진료를 통해 정확한 원인을 찾는 것을 권장합니다. 특히 갑작스럽게 악화되는 경우 즉각적인 의료 평가가 필요합니다.', 1359, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '복시', '복시', 'TREATMENT', '눈 밑 지방 수술 후 하사근 손상으로 인한 복시와 어지러움에는 프리즘 안경이 시각적 불편함을 완화하는 데 도움이 될 수 있습니다. 시기능 훈련(시각 치료)을 통해 양안 협조 능력을 강화하는 것도 보조적으로 활용됩니다. 증상이 지속된다면 안과 전문의와 상담하여 수술적 교정 여부를 포함한 치료 계획을 수립하시기 바랍니다.', 1360, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '비문증', '비문증', 'CAUSE', '비문증은 유리체 내 혼탁물이 망막에 그림자를 드리워 점, 실, 거미줄 모양의 부유물이 보이는 증상이 주된 특징입니다. 시야가 전반적으로 흐려지거나 사물이 번져 보이는 현상은 비문증보다는 다른 안과 질환(백내장, 굴절 이상, 망막 질환 등)에서 더 흔하게 나타납니다. 정확한 원인 감별을 위해 안과 전문의의 진찰을 받으시기 권장합니다.', 1361, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '비문증', '비문증', 'DEFINITION', '눈 앞에 먼지나 작은 점이 떠다니는 느낌은 비문증(floaters)의 대표적인 증상으로, 유리체의 노화나 변성으로 인해 발생합니다. 대부분은 생리적 현상으로 치료가 필요하지 않으나, 갑자기 부유물이 증가하거나 섬광이 동반되는 경우 망막 박리의 징후일 수 있어 즉시 안과 전문의의 진찰이 필요합니다.', 1362, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '비문증', '비문증', 'SYMPTOM', '비문증은 눈앞에 점, 실, 지렁이, 거미줄, 고리 모양의 부유물이 보이는 것이 주된 증상입니다. 이 외에도 밝은 곳이나 흰 배경을 볼 때 증상이 더 뚜렷해지고, 눈을 움직이면 부유물도 함께 움직이는 특징이 있습니다. 갑작스러운 섬광(빛 번쩍임)이 동반되거나 증상이 급격히 악화되면 망막 박리 가능성이 있으므로 즉시 안과를 방문하셔야 합니다.', 1363, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '비문증', '비문증', 'DIAGNOSIS', '비문증 진단은 안과에서 산동 검사(동공 확대 후 안저 검사)를 통해 이루어지며, 망막 이상 여부까지 확인할 수 있습니다. 가까운 안과 의원이나 종합병원 안과를 방문하시면 세극등 검사와 안저 검사를 통해 정확한 진단을 받으실 수 있습니다. 증상이 갑자기 심해지거나 섬광이 동반된다면 빠른 시일 내에 진료를 받으시기 바랍니다.', 1364, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '비문증', '비문증', 'TREATMENT', '생리적 비문증은 대부분 특별한 치료 없이 경과를 관찰하며, 시간이 지나면 뇌가 부유물에 적응하여 불편함이 줄어들기도 합니다. 심한 경우 유리체절제술이나 레이저 유리체용해술을 고려할 수 있으나, 합병증 위험이 있어 신중히 결정해야 합니다. 치료 방침은 안과 전문의의 진단과 상담을 통해 결정하시기 바랍니다.', 1365, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '사시', '사시', 'CAUSE', '사시의 원인으로는 외안근의 불균형, 뇌신경(3·4·6번 뇌신경) 마비, 굴절 이상(특히 원시에 의한 조절내사시), 유전적 요인, 뇌종양이나 뇌혈관 질환 등이 있습니다. 소아에서는 약시, 백내장, 망막모세포종 등 시력을 저하시키는 질환이 사시를 유발할 수 있습니다. 눈동자가 한쪽 방향으로 치우치는 증상이 있다면 소아안과 전문의의 조기 진찰을 받는 것이 중요합니다.', 1366, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '사시', '사시', 'DEFINITION', '사시는 두 눈이 동일한 방향을 향하지 못하고 한쪽 눈이 안쪽·바깥쪽·위·아래로 편위되는 상태를 말합니다. 증상으로는 눈의 정렬 불일치, 물체가 겹쳐 보이는 복시, 약시 발생 등이 있습니다. 아기에서 사시가 의심된다면 소아 안과가 있는 종합병원 또는 안과 전문 병원을 방문하시어 전문의의 진찰을 받으시기 바랍니다.', 1367, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '사시', '사시', 'SYMPTOM', '사시의 증상으로는 한쪽 눈이 다른 방향을 향하거나(내사시·외사시·상사시·하사시), 햇빛 아래서 한쪽 눈을 찡그리는 행동, 고개를 기울이거나 돌리는 행동, 물체가 겹쳐 보이는 복시가 나타날 수 있습니다. 소아에서는 약시로 이어질 수 있어 조기 발견이 매우 중요합니다. 아이의 눈 정렬이 의심된다면 지체 없이 소아안과 전문의의 진찰을 받으시기 바랍니다.', 1368, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '사시', '사시', 'DIAGNOSIS', '사시 진단을 위한 주요 검사로는 각막반사 검사(히르쉬베르크 검사), 가림-가림 떼기 검사, 프리즘 검사, 시력 검사, 굴절 검사(사이클로플레지아 굴절 검사) 등이 있습니다. 사시의 원인에 따라 신경과적 검사(MRI, CT)나 전신 질환 관련 검사가 추가로 필요할 수 있습니다. 정확한 검사와 진단을 위해 안과 전문의의 진찰을 받으시기 바랍니다.', 1369, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '사시', '사시', 'TREATMENT', '사시의 치료는 원인과 종류에 따라 다르며, 굴절 이상이 원인인 경우 안경 교정이 우선됩니다. 약시가 동반된 경우 가림 치료를 시행하고, 이후에도 눈의 정렬이 교정되지 않으면 사시 수술을 통해 외안근의 위치를 조정합니다. 치료 효과는 조기에 시작할수록 좋으므로, 안과 전문의와 상담하여 최적의 치료 계획을 수립하시기 바랍니다.', 1370, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '색약', '색약', 'CAUSE', '색약의 대부분은 X 염색체에 연관된 열성 유전 방식으로 유전됩니다. 어머니가 보인자(X^a X)인 경우 아들에게 50% 확률로 색약이 나타나며, 여성은 두 개의 X 염색체가 모두 이상이 있어야 색약이 발현되므로 남성에서 훨씬 빈도가 높습니다. 이 외에도 눈 또는 뇌 질환으로 인한 후천성 색각 이상도 존재하므로, 색각 이상이 의심되면 안과 전문의의 진찰을 받으시기 바랍니다.', 1371, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '색약', '색약', 'DEFINITION', '색약은 특정 색상(주로 적색과 녹색, 또는 청색과 황색)을 정상적으로 구분하지 못하는 색각 이상입니다. 하나의 색만 구분하지 못하는 것이 아니라 관련 색 계열 전반에서 혼동이 발생하며, 가장 흔한 유형은 적녹 색약입니다. 정확한 진단은 안과에서 이시하라 색각 검사 또는 파른스워스 검사를 통해 받으실 수 있습니다.', 1372, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '색약', '색약', 'SYMPTOM', '색약의 종류에 따라 적녹 색약(제1색약·제2색약)은 빨간색과 녹색을 혼동하고, 청황 색약(제3색약)은 파란색과 노란색을 구분하기 어렵습니다. 전색맹은 색을 전혀 구분하지 못하는 극히 드문 상태입니다. 대부분의 색약은 일상생활에 큰 지장이 없으나, 특정 직업에서 제한이 있을 수 있으므로 안과 전문의의 정확한 진단이 필요합니다.', 1373, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '색약', '색약', 'DIAGNOSIS', '색약 진단은 안과에서 이시하라 색각 검사(숫자판 검사) 또는 파른스워스-먼셀 색각 검사를 통해 정확하게 받을 수 있습니다. 운전면허 신체검사 시 색각 이상이 의심된 경우, 가까운 안과 전문의를 방문하시면 정밀 색각 검사를 통해 진단과 종류를 확인할 수 있습니다. 검사 결과에 따라 취업이나 면허 취득 가능 여부도 안내받으실 수 있습니다.', 1374, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '색약', '색약', 'TREATMENT', '선천성 색약은 현재까지 완치하는 치료 방법이 없습니다. 다만, 특수 색각 교정 렌즈(색각 이상 보조 콘택트렌즈)나 색각 보정 안경을 사용하면 일부 색의 구별 능력을 향상시켜 신호등 식별 등 일상 불편함을 줄이는 데 도움이 될 수 있습니다. 구체적인 보조 기구 선택은 안과 전문의와 상담하시기 바랍니다.', 1375, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '시신경염', '시신경염', 'MEDICATION', '시신경염의 1차 치료로 고용량 정맥 내 스테로이드(메틸프레드니솔론) 투여가 표준 치료법입니다. 스테로이드 외에 원인이 시신경척수염 범주 질환(NMOSD)이나 MOG 항체 관련 질환인 경우 면역억제제(아자티오프린, 미코페놀레이트 등) 병용이 필요할 수 있습니다. 다발성 경화증이 동반된 경우 재발 방지를 위한 질병조절치료제도 고려하므로, 신경과·안과 전문의의 진료가 필요합니다.', 1376, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '시신경염', '시신경염', 'CAUSE', '시신경염은 바이러스·세균성 감염 외에도 다발성 경화증, 시신경척수염(NMOSD), 루푸스·쇼그렌증후군 등 자가면역 질환, 결핵, 매독, 라임병 등에서도 발생할 수 있습니다. 또한 특정 약물(에탐부톨 등)이나 방사선 치료 후에도 시신경염이 나타날 수 있습니다. 원인에 따라 치료 방향이 달라지므로 안과 및 신경과 전문의의 정밀 검사가 필요합니다.', 1377, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '시신경염', '시신경염', 'DEFINITION', '시신경염은 시신경에 염증이 발생하는 질환으로, 주요 증상은 수 시간~수일에 걸쳐 진행하는 시력 저하, 색각 이상(특히 적색 인식 저하), 눈을 움직일 때 발생하는 통증입니다. 시야 결손(중심 암점), 밝기 감소, 빛에 대한 과민반응도 나타날 수 있습니다. 증상이 의심되면 즉시 안과 또는 신경과 전문의를 방문하시기 바랍니다.', 1378, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '시신경염', '시신경염', 'SYMPTOM', '시신경염의 주요 증상으로 시력 감소가 대표적이며, 눈 주위 또는 안와 부위의 통증(특히 안구 운동 시 심해짐)이 흔히 동반됩니다. 따끔거림보다는 뻐근하거나 묵직한 통증이 더 전형적이며, 색각 저하와 시야 결손도 나타납니다. 망막 질환과 시신경염은 감별이 필요하므로 안과 전문의의 정밀 검사를 받으시기 바랍니다.', 1379, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '시신경염', '시신경염', 'DIAGNOSIS', '시신경염 진단을 위해 시력 및 색각 검사, 동공 반응 검사(상대성 구심성 동공 결손 확인), 시야 검사, 안저 검사가 기본적으로 시행됩니다. 추가로 시각유발전위 검사(VEP), 뇌 및 안와 MRI 검사가 시신경 염증과 다발성 경화증 등 기저 질환 확인에 중요합니다. 안구 운동 시 통증은 시신경염의 특징적 소견이므로, 안과 또는 신경과 전문의의 진료를 받으시기 바랍니다.', 1380, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '시신경염', '시신경염', 'TREATMENT', '시신경염에서 빛이 번쩍이는 광시증(phosphene)은 안구를 움직일 때 염증이 있는 시신경이 자극되어 나타나는 증상입니다. 어두운 환경에서 눈을 움직이거나 압력이 가해질 때 빛 섬광이 보일 수 있으며, 이는 시신경 자체의 이상 전기 활동으로 발생합니다. 이 증상이 나타난다면 안과 전문의를 방문하여 정확한 진단과 치료를 받으시기 바랍니다.', 1381, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안검하수', '안검하수', 'CHECKUP', '안검하수는 눈꺼풀이 아래로 처져 검은자위(각막)를 일부 가리는 상태로, 외관상 처짐이 뚜렷한 경우는 물론 경미한 경우에도 시야 방해·약시 위험이 있어 검진이 필요합니다. 특히 소아에서는 약시 예방을 위해 조기 검진과 치료가 중요하며, 성인도 시야 장애나 눈의 피로가 동반되면 안과 전문의의 평가가 권장됩니다.', 1382, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안검하수', '안검하수', 'MEDICATION', '안검하수에서 약물 치료는 원인이 중증 근무력증인 경우 항콜린에스테라제제(피리도스티그민)가 효과적이며, 면역 매개 원인에는 스테로이드 등 면역억제제가 사용됩니다. 그러나 선천성 또는 건막성 안검하수의 경우 약물 효과가 제한적이어서 수술이 주된 치료법입니다. 원인에 따른 적절한 치료 방법은 안과 전문의와 상담하여 결정하시기 바랍니다.', 1383, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안검하수', '안검하수', 'CAUSE', '안검하수는 눈꺼풀올림근(상안검거근)이나 뮬러근의 기능 저하, 건막 이상, 신경 손상(안신경 마비, 호너증후군), 중증 근무력증 등 다양한 원인으로 발생합니다. 눈썹 빠짐이나 시력 이상과 직접적인 관련은 없으며, 노화에 따른 건막 약화가 가장 흔한 원인입니다. 정확한 원인 파악을 위해 안과 전문의의 진찰을 받으시기 바랍니다.', 1384, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안검하수', '안검하수', 'DEFINITION', '안검하수 진단은 주로 안과에서 임상적으로 이루어지며, 마진-반사 거리(MRD1) 측정, 상안검거근 기능 검사, 시야 검사, 세극등 현미경 검사 등이 활용됩니다. 필요에 따라 텐실론 검사(중증 근무력증 의심 시)나 신경 영상 검사(MRI/CT)가 추가될 수 있습니다. 눈 피로와 눈꺼풀 무거움이 지속된다면 안과 전문의의 진찰을 받으시기 바랍니다.', 1385, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안검하수', '안검하수', 'SYMPTOM', '한쪽 눈꺼풀이 더 처져 양쪽 눈 크기 차이가 뚜렷한 경우, 선천성 안검하수, 중증 근무력증, 호너증후군, 동안신경 마비 등의 가능성을 고려해야 합니다. 갑자기 발생한 경우 뇌동맥류나 뇌졸중과 같은 응급 질환의 징후일 수 있어 즉각적인 의료 평가가 필요합니다. 정확한 진단과 원인 감별을 위해 안과 또는 신경과 전문의를 방문하시기 바랍니다.', 1386, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안검하수', '안검하수', 'DIAGNOSIS', '안검하수는 위 눈꺼풀이 처져 각막(검은자위)을 정상보다 많이 덮는 상태로, 마진-반사 거리(눈꺼풀 가장자리와 각막 반사점 사이 거리)가 3mm 미만이면 안검하수로 진단합니다. 진단을 위해 안과에서 상안검거근 기능 검사, 시야 검사, 원인 감별을 위한 신경학적 검사 등이 시행됩니다. 눈꺼풀이 검은자위를 많이 가린다면 안과 전문의의 정확한 평가를 받으시기 바랍니다.', 1387, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안검하수', '안검하수', 'TREATMENT', '안검하수로 인한 경미한 증상은 눈꺼풀 운동 강화 운동(눈 크게 뜨기, 눈썹 올리기 등)이 일부 도움이 될 수 있으나, 효과는 제한적입니다. 외부 보조 기구(눈꺼풀 지지 안경)를 사용하면 일시적으로 증상을 완화할 수 있습니다. 근본적인 교정은 수술이 필요한 경우가 많으므로, 안과 전문의와 상담하여 치료 방침을 결정하시기 바랍니다.', 1388, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안구 건조증', '안구건조증', 'DIET_LIFE', '안구 건조증 악화 시에는 스마트폰·컴퓨터 사용 시 20분마다 20초간 6미터 거리를 바라보는 ''20-20-20 법칙''을 실천하는 것이 도움이 됩니다. 스크린 밝기를 줄이고, 기기를 눈 높이보다 약간 아래에 배치하며, 사용 시간을 의식적으로 제한하는 습관이 안구 건조증 관리에 효과적입니다. 증상이 지속된다면 안과 전문의와 상담하시기 바랍니다.', 1389, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안구 건조증', '안구건조증', 'PREVENTION', '안구 건조증 예방을 위해 실내 습도를 40~60%로 유지하고, 에어컨·선풍기 바람이 눈에 직접 닿지 않도록 하는 것이 중요합니다. 충분한 수분 섭취, 오메가-3 지방산이 풍부한 식품(등 푸른 생선, 견과류) 섭취, 의식적으로 자주 눈을 깜빡이는 습관도 도움이 됩니다. 증상이 심한 경우 안과 전문의의 진찰을 통해 원인에 맞는 치료를 받으시기 바랍니다.', 1390, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안구 건조증', '안구건조증', 'CAUSE', '안구 건조증의 주요 원인으로는 노화, 장시간 스크린 사용(눈 깜빡임 감소), 콘택트렌즈 착용, 건조한 환경, 자가면역 질환(쇼그렌증후군), 특정 약물(항히스타민제, 이뇨제) 복용 등이 있습니다. 관리를 위해서는 인공눈물 사용, 습도 조절, 스크린 사용 시간 제한, 오메가-3 섭취, 온찜질 등이 권장됩니다. 증상이 지속되거나 심한 경우 안과 전문의의 진찰을 받으시기 바랍니다.', 1391, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안구 건조증', '안구건조증', 'DEFINITION', '외출 시 눈이 뻑뻑하고 간지러운 증상은 안구 건조증의 대표적인 증상 중 하나입니다. 바람, 자외선, 낮은 습도 등 외부 환경이 눈물 증발을 촉진하여 증상을 악화시킬 수 있습니다. 증상이 자주 반복된다면 안과 전문의의 진찰을 통해 안구 건조증 여부 및 원인을 확인하고 적절한 치료를 받으시기 바랍니다.', 1392, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안구 건조증', '안구건조증', 'SYMPTOM', '안구 건조증의 주요 증상에는 눈의 건조감과 뻑뻑함이 포함되며, 이는 눈물 분비 부족이나 눈물막 불안정으로 인해 발생합니다. 이 외에도 이물감, 따가움, 충혈, 바람이나 연기에 과민 반응, 눈부심, 일시적인 시력 저하 등이 나타날 수 있습니다. 증상이 지속된다면 안과 전문의의 진찰을 통해 적절한 치료를 받으시기 바랍니다.', 1393, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안구 건조증', '안구건조증', 'DIAGNOSIS', '안구 건조증 진단을 위해 안과에서는 쉬르머 검사(눈물 분비량 측정), 눈물막 파괴 시간(TBUT) 검사, 세극등 현미경을 이용한 결막·각막 염색 검사 등이 시행됩니다. 환절기에 눈 깜빡임이 불편한 경우 눈물층 이상이 원인일 수 있으므로 안과 전문의의 정확한 진단이 필요합니다. 진단 결과에 따라 인공눈물, 항염증 치료 등 적절한 치료를 받으실 수 있습니다.', 1394, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안구 건조증', '안구건조증', 'TREATMENT', '찬바람으로 인한 눈물 증발 촉진과 안구 건조증 악화에는 방풍 효과가 있는 보호 안경이나 선글라스 착용이 도움이 됩니다. 인공눈물(히알루론산 성분)을 정기적으로 점안하거나, 필요 시 젤 타입의 인공눈물을 사용하는 것도 효과적입니다. 증상이 심하거나 지속된다면 안과 전문의와 상담하여 더 적극적인 치료(항염증 점안제, 눈물점 마개 삽입 등)를 받으시기 바랍니다.', 1395, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안암', '안암', 'CAUSE', '안암(안구 종양)은 유전적 요인이 일부 영향을 미치는데, 망막모세포종은 RB1 유전자 돌연변이와 강하게 연관되어 유전성이 약 40%를 차지합니다. 포도막 흑색종은 유전적 소인이 있으나 주로 산발적으로 발생하며, 자외선 노출, 밝은 홍채색, 면역 억제 등도 위험 요인입니다. 가족력이 있다면 안과 전문의의 정기 검진을 받으시는 것이 중요합니다.', 1396, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안암', '안암', 'DEFINITION', '안암은 눈에만 국한되지 않으며, 눈에 발생하는 종양(안구 내 흑색종, 망막모세포종, 결막 종양 등) 외에도 눈 주변 조직(안와, 눈꺼풀, 누선)에 발생할 수 있습니다. 또한 다른 장기(폐, 유방, 피부 흑색종 등)의 악성 종양이 눈에 전이되는 경우도 있습니다. 눈에 종양이 의심되는 증상이 있다면 안과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 1397, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안암', '안암', 'SYMPTOM', '안암의 증상으로는 시력 저하, 시야 결손, 눈 안에 부유물 증가, 눈의 통증, 안구 돌출, 눈 내부에 보이는 흰색 반사(백색 동공), 충혈, 사시 등이 나타날 수 있습니다. 망막모세포종은 주로 소아에서 백색 동공으로 발견되며, 포도막 흑색종은 성인에서 시력 변화나 부유물 증가로 나타납니다. 이러한 증상이 있다면 즉시 안과 전문의의 진찰을 받으시기 바랍니다.', 1398, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안암', '안암', 'DIAGNOSIS', '안암 진단을 위해 안과에서는 세극등 검사, 안저 검사, 안구 초음파 검사가 기본적으로 시행됩니다. 조기 발견을 위해서는 형광안저촬영, 안구 MRI/CT 검사, 광간섭단층촬영(OCT)이 활용되며, 필요 시 조직 생검이 이루어집니다. 위험 요인이 있거나 증상이 의심되는 경우 안과 전문의의 정기적인 검진이 조기 발견에 중요합니다.', 1399, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '안암', '안암', 'TREATMENT', '안암의 치료는 종양의 종류, 크기, 위치, 전이 여부에 따라 다르며, 방사선 치료(근접방사선치료, 양성자 치료), 레이저 치료(광역학요법, 광응고술), 냉동 치료, 수술적 절제, 안구 적출술 등이 있습니다. 최근에는 표적 치료제와 면역항암요법이 포도막 흑색종의 전이 치료에 활용되고 있습니다. 치료 계획은 안과 종양 전문의를 포함한 다학제 팀과의 상담을 통해 결정하시기 바랍니다.', 1400, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '알레르기성 결막염', '알레르기성결막염', 'MEDICATION', '알레르기성 결막염 치료에는 히스타민 차단과 비만세포 안정 효과를 동시에 갖는 복합 작용 점안제(올로파타딘, 케토티펜 등)가 1차 치료제로 널리 사용됩니다. 증상이 심한 경우 단기간 스테로이드 점안제를 사용할 수 있으며, 눈 건조함이 동반된 경우 인공눈물을 함께 사용합니다. 약물 선택과 사용 기간은 안과 전문의와 상담하여 결정하시기 바랍니다.', 1401, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '알레르기성 결막염', '알레르기성결막염', 'PREVENTION', '알레르기성 결막염 예방을 위해 꽃가루·집먼지진드기·반려동물 털 등 알레르기 유발 물질(알레르겐) 노출을 최소화하는 것이 가장 중요합니다. 외출 후 손을 깨끗이 씻고, 눈을 손으로 비비지 않으며, 인공눈물로 눈을 세척하는 것이 도움이 됩니다. 알레르기 증상이 반복된다면 안과 전문의의 진찰을 받아 적절한 예방 및 치료 방법을 안내받으시기 바랍니다.', 1402, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '알레르기성 결막염', '알레르기성결막염', 'CAUSE', '알레르기성 결막염의 주요 원인은 꽃가루(수목·잡초·풀), 집먼지진드기, 반려동물의 털과 비듬, 곰팡이 포자, 화장품, 콘택트렌즈 용액 등의 알레르겐에 결막이 과민 반응을 일으키는 것입니다. 이러한 물질에 노출 시 면역글로불린 E(IgE) 매개 반응으로 히스타민이 분비되어 가려움·충혈·분비물 증상이 나타납니다. 알레르겐 확인을 위해 알레르기 검사를 받아보실 것을 권장합니다.', 1403, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '알레르기성 결막염', '알레르기성결막염', 'DEFINITION', '알레르기성 결막염은 꽃가루, 집먼지진드기 등의 알레르겐에 대한 면역 과민 반응으로 결막에 염증이 발생하는 질환입니다. 주요 증상으로는 심한 가려움증, 눈 충혈, 눈물 과다 분비, 눈꺼풀 부종, 점액성 분비물(눈곱) 등이 있으며, 양쪽 눈에 동시에 나타나는 경우가 많습니다. 충혈과 가려움이 반복된다면 안과 전문의의 진찰을 통해 정확한 진단을 받으시기 바랍니다.', 1404, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '알레르기성 결막염', '알레르기성결막염', 'SYMPTOM', '충혈, 심한 가려움증, 눈곱(점액성 분비물) 발생은 알레르기성 결막염의 전형적인 증상에 해당합니다. 이 외에도 눈물 과다, 눈꺼풀 부종, 이물감, 빛 민감성이 동반될 수 있으며, 가려워서 눈을 비비면 증상이 악화됩니다. 이러한 증상이 반복되거나 지속된다면 안과 전문의의 진찰을 받아 적절한 치료를 받으시기 바랍니다.', 1405, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '알레르기성 결막염', '알레르기성결막염', 'DIAGNOSIS', '봄철 알레르기성 결막염 진단 시 의사는 주로 양측 눈의 가려움증 정도, 충혈, 분비물의 양상, 눈꺼풀 결막의 유두 반응(검사 시 확인), 알레르기 병력(비염·천식·아토피 동반 여부), 꽃가루 노출 후 증상 악화 여부 등을 확인합니다. 결막 도말 검사(호산구 확인)나 알레르기 피부 반응 검사가 추가로 시행될 수 있습니다. 정확한 진단을 위해 안과 전문의의 진찰을 받으시기 바랍니다.', 1406, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '알레르기성 결막염', '알레르기성결막염', 'TREATMENT', '알레르기성 결막염의 자가 관리로는 차가운 냉찜질로 가려움증과 부종을 완화하고, 인공눈물로 알레르겐을 눈에서 세척하는 것이 도움이 됩니다. 알레르겐 노출을 줄이기 위해 외출 시 안경·선글라스 착용, 귀가 후 세안, 실내 환기 조절 등이 권장됩니다. 눈을 손으로 비비는 것은 증상 악화와 감염 위험을 높이므로 반드시 피하시고, 증상이 심하면 안과 전문의의 처방을 받으시기 바랍니다.', 1407, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '야맹증', '야맹증', 'DIET_LIFE', '야맹증 완화를 위해 비타민 A가 풍부한 식품(간, 달걀노른자, 유제품)과 베타카로틴이 많은 식품(당근, 시금치, 고구마, 브로콜리)을 충분히 섭취하는 것이 도움이 됩니다. 생활 습관으로는 급격한 명암 변화에 적응할 시간을 충분히 갖고, 야간 운전을 삼가며, 어두운 환경에서는 보조 조명을 활용하는 것이 좋습니다. 증상이 지속된다면 안과 전문의의 진찰을 받으시기 바랍니다.', 1408, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '야맹증', '야맹증', 'PREVENTION', '야맹증 예방을 위해 비타민 A가 풍부한 식품(간, 달걀, 유제품, 주황색·녹황색 채소)을 균형 있게 섭취하는 것이 중요합니다. 규칙적인 유산소 운동은 전신 혈액 순환을 개선하여 망막의 건강 유지에 간접적으로 도움이 될 수 있으나, 운동이 야맹증을 직접적으로 예방하는 근거는 제한적입니다. 야맹증이 의심된다면 안과 전문의의 진찰을 통해 원인을 확인하시기 바랍니다.', 1409, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '야맹증', '야맹증', 'CAUSE', '야맹증의 원인으로는 비타민 A 결핍이 가장 흔하지만, 이 외에도 망막색소변성증(유전 질환), 녹내장, 백내장, 당뇨병성 망막병증, 아연 결핍, 특정 약물(항말라리아제 등) 부작용이 원인이 될 수 있습니다. 선천성 야맹증은 유전적 요인에 의한 망막 기능 이상이 원인입니다. 정확한 원인 파악을 위해 안과 전문의의 검진을 받으시기 바랍니다.', 1410, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '야맹증', '야맹증', 'DEFINITION', '야맹증은 어두운 환경에서 시력이 저하되어 사물 식별이 어려운 질환으로, 밝은 곳에서 어두운 곳으로 이동 시 적응 시간이 매우 길어지는 것이 주요 특징입니다. 야간 운전의 어려움, 어두운 곳에서 걸을 때 장애물에 부딪히는 증상이 나타나며, 망막색소변성증이 원인인 경우 시야 협착(터널 시야)도 동반될 수 있습니다. 이러한 증상이 있다면 안과 전문의의 진찰을 받으시기 바랍니다.', 1411, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '야맹증', '야맹증', 'SYMPTOM', '야맹증으로 인한 어두운 곳에서의 시력 저하 외에, 명암 순응 시간 연장, 시야 협착(특히 망막색소변성증의 경우), 색각 이상, 물체 경계 구분 어려움 등의 증상이 더 뚜렷하게 나타날 수 있습니다. 망막색소변성증이 동반된 경우 주변 시야가 점차 좁아지는 증상이 진행됩니다. 이러한 증상이 있다면 안과 전문의의 정밀 검진을 받으시기 바랍니다.', 1412, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '야맹증', '야맹증', 'DIAGNOSIS', '야맹증 진단은 안과에서 받으실 수 있으며, 야간 시력 검사, 시야 검사, 안저 검사, 망막전위도 검사(ERG) 등을 통해 원인을 확인합니다. 가까운 안과 의원이나 대학병원 안과를 방문하시면 정밀 검사를 받으실 수 있으며, 야간 운전이 위험할 정도로 시력이 저하된 경우 빠른 진료를 권장합니다. 운전 안전을 위해 야맹증 진단 전까지 야간 운전은 삼가시기 바랍니다.', 1413, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '야맹증', '야맹증', 'TREATMENT', '비타민 A 결핍으로 인한 야맹증은 레티놀(동물성 비타민 A) 또는 베타카로틴(식물성 전구체)을 포함한 비타민 A 보충제를 섭취하면 효과적으로 개선될 수 있습니다. 다만, 비타민 A는 과잉 섭취 시 독성이 나타날 수 있으므로 의사의 지도 하에 적정 용량을 복용해야 합니다. 야맹증의 원인이 비타민 A 결핍이 아닌 경우(망막색소변성증 등) 비타민 보충의 효과가 제한적이므로, 먼저 안과 전문의의 진단을 받으시기 바랍니다.', 1414, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '약시', '약시', 'PREVENTION', '소아 약시 예방을 위해 루테인·제아잔틴(시금치, 케일, 달걀 등)과 오메가-3 지방산, 비타민 A가 풍부한 균형 잡힌 식단이 눈 건강에 도움이 됩니다. 생활 습관으로는 과도한 스크린 노출을 줄이고, 하루 2시간 이상 야외 활동을 통해 근시 진행을 억제하는 것이 권장됩니다. 약시는 조기 발견이 중요하므로 만 3세부터 정기적인 안과 검진을 받으시기 바랍니다.', 1415, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '약시', '약시', 'CAUSE', '약시는 유전적 요인이 영향을 미칠 수 있으며, 사시나 굴절 이상(고도 원시·근시·난시)에 대한 유전적 소인이 약시 발생 위험을 높입니다. 그러나 약시 자체보다는 약시의 원인이 되는 사시, 굴절 이상, 백내장 등이 유전되는 경우가 많습니다. 어릴 때부터 증상이 있었다면 안과 전문의의 진찰을 통해 원인을 정확히 파악하는 것이 중요합니다.', 1416, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '약시', '약시', 'DEFINITION', '두 눈의 시력이 모두 좋지 않거나 서로 다른 경우, 원인에 따라 굴절 이상(근시·원시·난시), 양안 약시, 기질적 안구 질환(백내장, 녹내장, 망막 이상 등) 등 다양한 진단이 가능합니다. 정확한 진단을 위해 시력 검사, 굴절 검사, 안저 검사, 시야 검사 등 종합적인 안과 검사가 필요합니다. 두 눈 모두 시력 이상이 있다면 안과 전문의의 정밀 검진을 받으시기 바랍니다.', 1417, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '약시', '약시', 'SYMPTOM', '눈을 자주 찡그리는 것은 약시보다는 근시·원시·난시 등 굴절 이상이 있을 때 더 선명하게 보려는 반응으로 나타나는 경우가 많습니다. 약시의 경우 눈 찡그림보다는 한쪽 눈을 가림, 눈의 정렬 불일치(사시), 시력 저하, 독서나 세밀한 작업의 어려움이 주요 증상입니다. 아이가 눈을 자주 찡그린다면 안과 전문의의 진찰을 통해 굴절 이상이나 약시 여부를 확인하시기 바랍니다.', 1418, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '약시', '약시', 'DIAGNOSIS', '잘못된 도수의 안경을 착용하면 눈의 피로, 두통, 어지러움, 시력 저하, 집중력 저하가 나타날 수 있습니다. 특히 도수가 과하게 교정된 경우 조절 부담이 증가하여 이러한 증상이 심해집니다. 불편함이 지속된다면 안과 전문의의 정확한 굴절 검사를 통해 올바른 안경 도수를 처방받으시기 바랍니다.', 1419, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '약시', '약시', 'TREATMENT', '약시 치료의 핵심은 시력이 좋은 눈을 가려 약시안을 강제로 사용하게 하는 가림 치료(폐쇄 요법)입니다. 가림 치료가 어려운 경우 정상안에 아트로핀 점안액을 점안하여 시력을 흐리게 하는 약물적 페널티 요법도 효과적입니다. 굴절 이상이 원인인 경우 안경 교정을 우선 시행하며, 조기 치료일수록 예후가 좋으므로 안과 전문의의 지도 하에 치료를 진행하시기 바랍니다.', 1420, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '출혈성 결막염', '출혈성결막염', 'CAUSE', '출혈성 결막염은 주로 엔테로바이러스 70형이나 콕사키바이러스 A24형 등 바이러스 감염이 가장 흔한 원인입니다. 드물게 세균 감염, 외상, 혈액 응고 장애나 고혈압 등 혈관 관련 문제가 결막하 출혈을 유발할 수 있으나, 이는 출혈성 결막염과는 구별되는 상태입니다. 증상이 발생하면 안과 전문의의 진찰을 통해 원인을 확인하시기 바랍니다.', 1421, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '출혈성 결막염', '출혈성결막염', 'DEFINITION', '출혈성 결막염은 고도의 전염성 바이러스(엔테로바이러스)에 의해 발생하며, 여름철 수영장·목욕탕 등 사람이 많이 모이는 물 환경에서 손을 통한 접촉 전파가 활발하게 이루어지기 때문에 유행이 잦습니다. 오염된 물이나 손으로 눈을 만질 때 바이러스가 결막에 직접 감염되어 발병합니다. 개인위생 철저와 공동 시설 이용 자제가 예방에 중요합니다.', 1422, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '출혈성 결막염', '출혈성결막염', 'SYMPTOM', '출혈성 결막염의 주요 증상은 결막하 점상 또는 반상 출혈로 인한 눈의 빨간 출혈, 심한 눈의 통증과 이물감, 눈물 과다 분비, 눈꺼풀 부종, 점액성 또는 화농성 눈곱 등이 있습니다. 증상은 대개 24~48시간 내에 급격히 나타나며 1~2주 내에 자연 회복되는 경우가 많습니다. 증상이 심하거나 시력 변화가 동반된다면 안과 전문의의 진찰을 받으시기 바랍니다.', 1423, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '출혈성 결막염', '출혈성결막염', 'DIAGNOSIS', '눈이 빨갛고 통증이 있는 증상은 출혈성 결막염의 전형적인 증상과 일치합니다. 출혈성 결막염에서는 결막하 출혈로 인한 선명한 적색 충혈, 눈 통증, 이물감, 눈물, 눈곱이 동시에 나타납니다. 그러나 급성 녹내장, 포도막염 등 다른 안과 응급 질환도 유사 증상을 보일 수 있으므로, 정확한 진단을 위해 안과 전문의의 진찰을 받으시기 바랍니다.', 1424, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '출혈성 결막염', '출혈성결막염', 'TREATMENT', '출혈성 결막염은 바이러스성 질환으로 특이적인 항바이러스제가 없어 대증 치료가 주된 방법입니다. 증상 완화를 위해 차가운 냉찜질, 인공눈물 점안, 2차 세균 감염 예방을 위한 항생제 점안제, 염증이 심한 경우 단기 스테로이드 점안제가 사용됩니다. 대부분 1~2주 내 자연 호전되지만, 전염성이 강하므로 안과 전문의의 지도하에 치료를 받고 격리 수칙을 지키는 것이 중요합니다.', 1425, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '포도막염', '포도막염', 'DIET_LIFE', '포도막염 환자는 항산화 영양소(비타민 C, E, 베타카로틴)가 풍부한 채소와 과일, 오메가-3 지방산이 포함된 생선을 충분히 섭취하는 것이 도움이 됩니다. 생활 습관으로는 자외선 차단 안경 착용, 금연, 스트레스 관리, 면역 조절에 좋은 규칙적인 수면이 권장됩니다. 포도막염의 원인 질환(강직척추염, 류마티스 질환 등) 관리와 병행하여 전문의의 지도를 받으시기 바랍니다.', 1426, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '포도막염', '포도막염', 'MEDICATION', '포도막염 치료에 가장 많이 사용되는 약물은 스테로이드(코르티코스테로이드)로, 점안제·안구 주사·전신 투여 형태가 있습니다. 동공 확대와 유착 방지를 위한 산동제(아트로핀, 사이클로펜톨레이트)도 함께 사용됩니다. 자가면역 원인이 있는 경우 면역억제제(메토트렉세이트, 아자티오프린)나 생물학적 제제가 추가되며, 복용 방법과 횟수는 안과 전문의의 처방에 따라 결정됩니다.', 1427, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '포도막염', '포도막염', 'PREVENTION', '눈이 피곤하고 빨갛게 보인다면 컴퓨터나 스마트폰 사용을 줄이고, 충분한 휴식을 취하는 것이 도움이 됩니다. 인공눈물을 사용하여 눈의 건조함을 해소하고, 실내 습도를 적절히 유지하는 것도 좋습니다. 증상이 지속되거나 통증, 시력 변화, 분비물이 동반된다면 포도막염 등 안과 질환일 수 있으므로 안과 전문의의 진찰을 받으시기 바랍니다.', 1428, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '포도막염', '포도막염', 'CAUSE', '포도막염은 전신 자가면역 질환(강직척추염, 류마티스 관절염, 베체트병, 사르코이드증 등)과 연관되어 발생하는 경우가 많으며, 감염(결핵, 헤르페스, 매독, 톡소플라스마 등)도 원인이 됩니다. 안과 질환 자체(교감성 안염, 수정체과민 포도막염)나 안구 외상, 수술 후 합병증으로도 발생할 수 있습니다. 원인 파악을 위해 안과 및 내과 전문의의 종합적인 검사가 필요합니다.', 1429, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '포도막염', '포도막염', 'DEFINITION', '포도막염은 눈 앞에 부유물(비문증) 외에도 눈의 통증, 충혈, 빛에 대한 과민 반응(수명), 시력 저하, 눈부심, 눈물 과다 분비 등의 증상이 나타날 수 있습니다. 후부 포도막염의 경우 망막 손상으로 인한 시야 결손이나 황반 부종이 발생할 수 있습니다. 이러한 증상이 의심된다면 즉시 안과 전문의의 진찰을 받으시기 바랍니다.', 1430, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '포도막염', '포도막염', 'SYMPTOM', '포도막염의 증상으로는 시력 저하, 눈부심(수명), 비문증 외에도 눈의 충혈(특히 각막 주변의 섬모체 충혈), 눈의 통증 또는 압박감, 눈물 과다, 빛 번쩍임(광시증), 색각 이상 등이 나타날 수 있습니다. 운전 시에는 이러한 증상들이 복합적으로 안전에 영향을 줄 수 있습니다. 증상이 지속된다면 안과 전문의의 조속한 진찰을 받으시기 바랍니다.', 1431, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '포도막염', '포도막염', 'DIAGNOSIS', '포도막염 진단을 위해 안과에서 세극등 현미경 검사(전방 염증세포·혼탁 확인), 안저 검사, 안압 측정, 형광안저촬영, 광간섭단층촬영(OCT) 등이 시행됩니다. 원인 감별을 위해 혈액 검사(HLA-B27, ACE, 결핵 검사 등)와 흉부 X선 검사도 필요합니다. 안과 전문의에게 1차 진료를 받은 후 원인에 따라 류마티스내과·감염내과 등과 협진이 이루어지기도 합니다.', 1432, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '포도막염', '포도막염', 'TREATMENT', '포도막염 환자는 빛에 대한 과민성(수명)이 증가하므로 자외선 차단과 눈부심 완화를 위한 선글라스(자외선 차단 기능 포함) 착용이 권장됩니다. 특히 스테로이드 치료 중이거나 동공이 확대된 상태에서는 밝은 빛이 더 불편할 수 있어 보호 안경이 도움이 됩니다. 근본적인 치료는 안과 전문의의 지도하에 약물 치료를 지속하는 것이 가장 중요합니다.', 1433, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '황반변성', '황반변성', 'DIET_LIFE', '규칙적인 유산소 운동은 혈액 순환 개선, 혈압·혈당·콜레스테롤 조절을 통해 황반변성의 주요 위험 요인을 감소시키는 데 도움이 됩니다. 특히 비만 예방과 산화 스트레스 감소에 기여하여 황반 건강 유지에 간접적인 효과가 있습니다. 그러나 운동 단독으로 황반변성을 예방하기는 어려우므로, 금연·균형 잡힌 식단·정기 안과 검진과 함께 병행하는 것이 중요합니다.', 1434, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '황반변성', '황반변성', 'CAUSE', '황반변성의 위험 요인으로는 유전적 소인 외에도 고령(55세 이상), 흡연, 자외선 장기 노출, 심혈관 질환, 고혈압, 비만, 산화 스트레스, 루테인·오메가-3 등 영양소 부족이 있습니다. 특히 흡연은 황반변성 발생 위험을 2~3배 높이는 가장 강력한 환경적 위험 요인입니다. 위험 요인을 줄이고 정기적인 안과 검진을 받는 것이 조기 발견에 중요합니다.', 1435, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '황반변성', '황반변성', 'DEFINITION', '황반변성의 주요 위험 요인으로는 고령(55세 이상), 흡연, 가족력(유전적 소인), 자외선 장기 노출, 심혈관 질환, 고혈압, 비만, 밝은 홍채색 등이 있습니다. 이러한 위험 요인이 있는 경우 황반의 망막색소상피세포와 광수용체가 손상되어 중심 시력이 점차 저하될 수 있습니다. 위험 요인이 있다면 안과 전문의의 정기 검진을 통해 조기 발견하는 것이 중요합니다.', 1436, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '황반변성', '황반변성', 'SYMPTOM', '시야 중심부의 특정 부분이 어둡거나 비어 보이고(중심 암점), 글자가 공백처럼 사라지거나 물체가 휘어 보이는 증상은 황반변성의 특징적인 증상입니다. 이 외에도 직선이 물결처럼 보이는 변시증(metamorphopsia), 색감 변화도 나타날 수 있습니다. 이러한 증상이 갑자기 발생했다면 신속히 안과 전문의의 진찰을 받으시기 바랍니다.', 1437, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '황반변성', '황반변성', 'DIAGNOSIS', '황반변성은 눈의 중심 시야를 담당하는 황반 부위의 망막이 손상되어 중심 시력이 저하되는 질환으로, 건성(비삼출성)과 습성(삼출성) 두 가지 유형이 있습니다. 황반이 손상되면 중심부가 흐릿하거나 왜곡되어 보이고, 심한 경우 중심 시야 상실로 독서·운전·얼굴 인식 등 정밀 시력을 요하는 활동이 어려워집니다. 조기 발견과 치료가 시력 보존에 중요하므로 정기적인 안과 검진을 권장합니다.', 1438, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('눈질환', '황반변성', '황반변성', 'TREATMENT', '루테인과 제아잔틴은 황반 색소의 주요 구성 성분으로, 산화 스트레스와 청색광으로부터 망막을 보호하는 항산화 역할을 합니다. 대규모 연구(AREDS2)에 따르면 루테인·제아잔틴·오메가-3·아연·비타민 C·E 복합 보충제가 중기 이상 건성 황반변성의 진행을 늦추는 데 도움이 되는 것으로 확인되었습니다. 루테인 복용 여부와 용량은 안과 전문의와 상담하여 결정하시기 바랍니다.', 1439, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구개열', '구개열', 'CHECKUP', '구개열 치료는 연령과 상태에 따라 단계적으로 진행됩니다. 생후 3~6개월에는 구순열(입술 갈림) 교정 수술, 12~18개월에는 구개 봉합 수술이 이루어집니다. 이후 언어 치료, 치과 교정, 필요 시 중이염 치료(환기관 삽입), 성장 후 코·안면 교정 수술 등이 단계적으로 시행되며, 구강외과·성형외과·이비인후과·소아과 전문의의 협진이 필요합니다.', 1440, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구개열', '구개열', 'DIET_LIFE', '구개열 수술 후 초기에는 액체식 또는 유동식으로 시작하여 부드러운 음식으로 서서히 전환하며, 딱딱하거나 뾰족한 음식은 피하는 것이 중요합니다. 구강 근육 회복을 위해 언어치료사의 지도 하에 입 주위 근육 운동(블로우 운동, 빨대 사용 훈련 등)을 시행하면 발음과 근육 기능 향상에 도움이 됩니다. 수술 후 관리 및 재활 지침은 담당 의료진의 지시에 따르시기 바랍니다.', 1441, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구개열', '구개열', 'MEDICATION', '구개열 환자의 수술 후 약물 치료에서 진통제(이부프로펜, 아세트아미노펜) 사용 시 위장 장애가 나타날 수 있고, 항생제 사용 시 소화 장애, 설사, 알레르기 반응이 발생할 수 있습니다. 전신 마취 관련 약물은 메스꺼움·구토가 흔한 부작용입니다. 약물 복용 중 이상 반응이 나타나면 즉시 담당 의료진에게 알리시고, 임의로 약물을 중단하지 마시기 바랍니다.', 1442, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구개열', '구개열', 'PREVENTION', '구개열 예방을 위해 임신 초기(임신 전~임신 12주)에 엽산(하루 400~800mcg)을 복용하는 것이 신경관 결손 및 일부 구순구개열 예방에 도움이 됩니다. 임신 중 비타민 B6, 아연, 비타민 C의 충분한 섭취도 권장되며, 금연·금주·약물 복용 주의가 중요합니다. 임신 계획 중이거나 임신 초기라면 산부인과 전문의와 영양 보충제 복용에 대해 상담하시기 바랍니다.', 1443, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구개열', '구개열', 'EXERCISE', '구개열 수술 후 잔존 증상 개선을 위해 언어 치료(발음 교정, 구강 근육 훈련)를 꾸준히 받는 것이 가장 효과적입니다. 입술·혀·볼 근육을 강화하는 구강 운동(바람 불기, 빨대로 음료 마시기, 풍선 불기 등)이 도움이 될 수 있습니다. 치과 교정 치료나 추가 수술(인두성형술 등)이 필요한 경우도 있으므로, 구개열 전문 의료팀과 지속적으로 상담하시기 바랍니다.', 1444, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구개열', '구개열', 'CAUSE', '가족력이 없는 경우에도 구개열은 임신 초기 엽산 결핍, 임신 중 흡연·음주·특정 약물(레티노이드, 항경련제 등) 복용, 당뇨병, 바이러스 감염, 방사선 노출, 환경 독소 등 다양한 환경적·유전적 요인의 복합적인 작용으로 발생할 수 있습니다. 약 70%의 구순구개열은 다인자성으로 유전자와 환경 요인이 함께 작용합니다. 정확한 원인 분석을 위해 유전 상담을 받으시는 것도 도움이 됩니다.', 1445, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구개열', '구개열', 'REHAB', '구개열은 뇌 외상이나 뇌격량과 직접적인 관련이 없는 선천성 구조 기형입니다. 구개열 환자의 재활은 수술 후 언어 치료(발음·공명 개선), 구강 운동 치료, 청력 관리(중이염 예방), 치과 교정 등을 중심으로 이루어집니다. 시력과 신체 기능 개선은 구개열 재활의 일반적인 목표가 아니며, 구체적인 재활 계획은 구개열 전문 의료팀(구강외과·언어치료사·치과)과 상담하여 수립하시기 바랍니다.', 1446, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구개열', '구개열', 'DEFINITION', '구개열은 태아 발생 과정에서 입천장(구개)의 좌우 구조물이 완전히 융합되지 않아 입천장에 갈라진 틈이 생기는 선천성 기형입니다. 입술만 갈라지는 구순열, 입천장만 갈라지는 구개열, 또는 두 가지가 함께 나타나는 구순구개열로 분류됩니다. 이로 인해 수유 장애, 언어 발달 문제, 중이염 등의 합병증이 발생할 수 있으며, 조기 수술적 교정이 필요합니다.', 1447, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구개열', '구개열', 'SYMPTOM', '아이의 입천장이 다른 아이들과 다르게 생겼다면 구개열의 가능성을 고려해야 하며, 주요 증상으로는 입천장에 갈라진 틈, 수유 시 코로 액체가 새어 나오는 역류, 수유 장애, 비음(콧소리) 섞인 발음, 잦은 중이염 등이 있습니다. 점막 하 구개열(점막으로 덮인 골 결손)은 외관상 정상으로 보이더라도 발음 이상으로 발견되기도 합니다. 의심된다면 소아과나 구강외과 전문의의 진찰을 받으시기 바랍니다.', 1448, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구개열', '구개열', 'DIAGNOSIS', '구개열 진단 및 치료는 대학병원 또는 상급종합병원의 구강악안면외과, 성형외과, 소아과로 구성된 다학제 팀에서 이루어집니다. 건강보험심사평가원 홈페이지(www.hira.or.kr)나 국민건강보험공단 지정 의료기관 안내를 통해 구개열 치료 전문 기관을 검색하실 수 있습니다. 담당 소아과 의사에게 전문 의료기관 의뢰를 요청하시는 것도 좋은 방법입니다.', 1449, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구개열', '구개열', 'TREATMENT', '구개열 수술 후 완전한 회복이 이루어지지 않은 경우, 언어 치료를 통해 발음과 구강 기능을 지속적으로 개선할 수 있습니다. 구개 인두 기능 부전이 지속되는 경우 인두성형술 등 추가적인 수술적 교정이 고려될 수 있습니다. 치료 방향은 구개열 전문 의료팀(구강외과·언어치료사·이비인후과)과 상담하여 개인 상태에 맞는 최적의 방법을 결정하시기 바랍니다.', 1450, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구순열', '구순열', 'CHECKUP', '구순열은 출생 전 임신 중기에 초음파 검사로 발견될 수 있으며, 출산 후에는 신체검진을 통해 입술과 구개의 형태를 직접 확인합니다. 출산 후에는 소아과 및 성형외과 전문의가 구순열의 범위와 심각도를 평가하며, 필요시 영상 검사를 추가로 시행합니다. 정확한 평가를 위해 소아과 또는 구순열 전문 클리닉 방문을 권고합니다.', 1451, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구순열', '구순열', 'DIET_LIFE', '구순열 수술 후에는 모유나 분유를 특수 수유 도구(클레프트 젖꼭지 등)로 제공하며, 이유식 단계에서는 부드러운 퓨레 형태의 음식부터 시작합니다. 딱딱하거나 질긴 음식, 빨대 사용은 수술 부위에 자극을 줄 수 있으므로 피해야 합니다. 구체적인 식이 지침은 담당 소아과 및 성형외과 전문의와 상담하여 결정하시기 바랍니다.', 1452, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구순열', '구순열', 'MEDICATION', '구순열 수술 후 구강 내 붓기와 통증에는 이부프로펜, 아세트아미노펜 등의 진통소염제가 사용되며, 항생제는 수술 후 감염 예방을 위해 처방될 수 있습니다. 구내염이 동반된 경우에는 국소 마취 성분의 구강 연고나 항진균제, 항바이러스제가 원인에 따라 사용됩니다. 약물 선택 및 용량은 반드시 전문의 처방에 따라 결정해야 합니다.', 1453, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구순열', '구순열', 'PREVENTION', '임신 초기 엽산(folic acid) 보충제 복용은 구순열을 포함한 신경관 결손 위험을 줄이는 데 도움이 됩니다. 임신 중 흡연, 음주, 특정 약물(항경련제, 스테로이드 등) 복용은 구순열 발생 위험을 높일 수 있으므로 피해야 합니다. 임신 계획 시 산부인과 전문의와 상담하여 적절한 예방 조치를 취하는 것이 중요합니다.', 1454, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구순열', '구순열', 'EXERCISE', '구순열 수술 후 입술 기능과 외모를 자연스럽게 회복하기 위해 입술 마사지와 스트레칭 운동이 권장되며, 일반적으로 수술 후 수 주 이상 꾸준히 시행합니다. 흉터 연화와 유연성 향상을 위한 마사지는 다른 재활 운동에 비해 단순하지만 지속적인 시행이 중요합니다. 구체적인 재활 방법과 기간은 담당 성형외과 전문의의 지도에 따르시기 바랍니다.', 1455, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구순열', '구순열', 'CAUSE', '임신 중 특정 감기약 성분(예: 일부 항히스타민제, 의사 처방 없이 복용하는 약물)이 태아의 구순열 발생 위험을 높일 수 있다는 연구가 있습니다. 그러나 구순열의 원인은 유전적 요인, 환경적 요인 등 복합적이며, 단일 원인으로 단정 짓기 어렵습니다. 임신 중 약물 복용은 반드시 산부인과 전문의와 상담 후 결정하시기 바랍니다.', 1456, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구순열', '구순열', 'REHAB', '구순열 환자의 재활에는 수술 후 언어치료(발음 교정), 치과 교정치료, 입술 마사지 및 흉터 관리, 청각 검사 및 치료 등이 포함됩니다. 정신적 측면에서는 심리 상담과 자존감 향상 프로그램이 도움이 되며, 가족 지지도 중요합니다. 다학제적 팀(성형외과, 치과, 언어치료사, 심리전문가)의 협력 치료를 전문 의료기관에서 받으시기 권고합니다.', 1457, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구순열', '구순열', 'DEFINITION', '구순열은 입술이 갈라진 상태(구순열)와 입천장이 갈라진 상태(구개열)를 총칭하며, 두 가지가 함께 나타나는 경우도 흔합니다. 이는 태아 발생 과정에서 얼굴 구조의 융합이 불완전하게 이루어져 발생하는 선천성 기형입니다. 구순열과 구개열은 각각 또는 동시에 나타날 수 있으며, 정확한 진단을 위해 전문의 상담을 권고합니다.', 1458, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구순열', '구순열', 'SYMPTOM', '구순열에서는 입술과 잇몸이 갈라지는 것 외에도 구개열이 동반될 경우 수유 곤란, 발음 문제, 중이염 반복, 치아 발달 이상 등이 나타날 수 있습니다. 또한 코 변형, 청력 저하, 언어 발달 지연 등의 증상도 동반될 수 있습니다. 증상의 범위와 심각도는 개인마다 다르므로 소아과 및 성형외과 전문의의 정확한 평가가 필요합니다.', 1459, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구순열', '구순열', 'DIAGNOSIS', '구순열 진단은 주로 소아과, 성형외과, 또는 구순구개열 전문 클리닉에서 받을 수 있습니다. 대학병원이나 상급 종합병원의 구순구개열 전문팀(성형외과, 소아과, 치과, 언어치료 등)이 가장 포괄적인 진단과 치료를 제공합니다. 가까운 소아과나 성형외과에서 초기 상담 후 전문 기관으로 연계받으시는 것을 권고합니다.', 1460, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '구순열', '구순열', 'TREATMENT', '구순열 성형수술의 대표적인 방법으로는 밀라드법(Millard technique), 테니슨-랜덜법(Tennison-Randall technique) 등이 있으며, 손상 형태와 범위에 따라 적합한 방법을 선택합니다. 수술은 일반적으로 생후 3~6개월에 시행하며, 구개열이 동반된 경우 12~18개월에 추가 수술을 합니다. 정확한 수술 방법 선택은 담당 성형외과 전문의와 충분히 상담하시기 바랍니다.', 1461, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '돌출입', '돌출입', 'CHECKUP', '돌출입 교정은 치아와 턱뼈의 구조적 문제를 다루므로 일반적으로 치과(교정과) 또는 구강악안면외과에서 먼저 평가받는 것이 적합합니다. 단순 치아 돌출은 치과 교정으로, 턱뼈 자체의 문제는 구강악안면외과와 성형외과의 협진이 필요할 수 있습니다. 정확한 진단과 치료 계획을 위해 치과 교정 전문의 상담을 먼저 받으시기를 권고합니다.', 1462, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '돌출입', '돌출입', 'DIET_LIFE', '딱딱하거나 질긴 음식을 지속적으로 씹는 습관은 저작근(씹는 근육)인 교근을 발달시켜 돌출입보다는 사각턱을 유발할 수 있습니다. 돌출입은 주로 치아 또는 턱뼈의 구조적 전방 위치가 원인이며, 음식 종류보다는 혀의 압력, 구호흡 등의 습관과 더 관련이 있습니다. 돌출입의 원인과 치료에 대해서는 치과 교정 전문의와 상담하시기 바랍니다.', 1463, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '돌출입', '돌출입', 'MEDICATION', '돌출입의 주된 치료는 치아 교정(브래킷, 투명 교정)이며, 심한 경우 치아 발치 후 교정이나 악교정 수술(양악 수술)이 필요할 수 있습니다. 돌출입에 대한 별도의 약물 치료는 없으며, 수술이나 교정이 가장 효과적인 방법입니다. 치료 방법은 돌출 정도와 원인에 따라 다르므로 치과 교정 전문의 또는 구강악안면외과 전문의와 상담하시기 바랍니다.', 1464, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '돌출입', '돌출입', 'PREVENTION', '돌출입은 옆모습 사진 촬영, 세팔로메트릭 방사선 검사(측모 두부 규격 X선)를 통해 치아와 턱뼈의 각도 및 위치를 계측하여 진단합니다. 정상 기준치 대비 상하악 전치(앞니)와 턱의 전방 돌출 정도를 수치로 평가합니다. 정확한 진단을 위해 치과 교정 전문의 또는 구강악안면외과 전문의의 검진을 받으시기 권고합니다.', 1465, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '돌출입', '돌출입', 'EXERCISE', '돌출입 자체를 운동으로 교정하는 방법은 없으며, 구조적인 문제이므로 교정 치료나 수술적 접근이 필요합니다. 다만 입술 근육 강화 운동(구륜근 운동)은 교정 치료의 보조적 역할을 할 수 있습니다. 돌출입 치료는 치과 교정 전문의와의 상담을 통해 적절한 치료 계획을 세우시기를 권고합니다.', 1466, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '돌출입', '돌출입', 'CAUSE', '돌출입의 주요 원인으로는 유전적 요인에 의한 턱뼈 및 치아 구조의 전방 위치, 어릴 때의 손가락 빨기·구호흡·혀 내밀기 등의 구강 습관, 치아 배열 공간 부족 등이 있습니다. 이러한 요인들이 복합적으로 작용하여 상하악 전치(앞니)와 입술이 전방으로 돌출되게 됩니다. 원인 파악과 치료 계획 수립을 위해 치과 교정 전문의 상담을 권고합니다.', 1467, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '돌출입', '돌출입', 'REHAB', '돌출입은 구조적 문제로 식이 요법만으로 교정이 어렵지만, 재활 기간 중에는 딱딱하거나 질긴 음식을 피하고 부드러운 음식 위주로 섭취하면 치료 부위에 가해지는 자극을 줄일 수 있습니다. 교정 장치 착용 중에는 끈적이거나 단단한 음식을 삼가고 균형 잡힌 식단을 유지하는 것이 도움이 됩니다. 구체적인 식이 관리는 담당 치과 교정 전문의의 안내에 따르시기 바랍니다.', 1468, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '돌출입', '돌출입', 'DEFINITION', '돌출입은 앞니와 입술이 정상보다 앞으로 돌출되어 옆면에서 보면 입술이 코와 턱 앞에 위치하는 안면 형태를 말합니다. 정면에서도 입술이 두드러져 보이고, 입을 다물기 불편하거나 억지로 다물면 턱 부분에 긴장감이 생기는 특징이 있습니다. 이는 치아나 턱뼈의 구조적 전방 위치로 발생하며, 치과 교정 전문의의 정확한 진단이 필요합니다.', 1469, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '돌출입', '돌출입', 'SYMPTOM', '돌출입의 대표적인 증상으로 입을 자연스럽게 다물기 어렵고, 억지로 입을 다물면 턱 끝 부위(이순구 주변)에 쭈글쭈글한 주름이 생기는 ''멘탈리스 근육 과긴장'' 소견이 나타납니다. 또한 입술이 이완 상태에서도 앞으로 돌출되어 보이며, 옆모습에서 코-입술-턱의 라인이 불균형하게 보입니다. 이러한 증상이 있다면 치과 교정 전문의 또는 구강악안면외과 전문의 상담을 권고합니다.', 1470, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '돌출입', '돌출입', 'DIAGNOSIS', '돌출입 진단은 성형외과보다 치과(교정과) 또는 구강악안면외과에서 받는 것이 더 적합하며, 세팔로메트릭 X선 검사를 통한 정밀 계측이 이루어집니다. 수술적 교정이 필요한 경우에는 구강악안면외과와 성형외과가 협진하는 경우도 있습니다. 정확한 진단을 위해 치과 교정 전문의 또는 구강악안면외과 전문의를 먼저 방문하시기 권고합니다.', 1471, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '돌출입', '돌출입', 'TREATMENT', '돌출입 치료에는 치아교정 외에도 악교정 수술(르포르 절골술, 하악 시상분할 절골술 등)이 있으며, 돌출 정도가 심한 경우 발치 후 교정, 또는 수술과 교정의 병행 치료가 필요합니다. 경미한 경우 투명 교정 장치나 기능성 교정 장치를 사용하기도 합니다. 개인의 상태에 맞는 치료 방법은 치과 교정 전문의 또는 구강악안면외과 전문의와 충분한 상담 후 결정하시기 바랍니다.', 1472, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '두개 유합증', '두개유합증', 'CHECKUP', '두개 유합증은 두개골 봉합선이 조기에 닫혀 머리 형태 이상이 나타나는 질환으로, 두개골 CT 검사, 두개골 X선 검사, 3D CT 촬영을 통해 확인합니다. 측모 이상이나 두개 형태 이상이 의심될 경우 소아과 또는 신경외과에서 초기 평가 후 전문 기관으로 의뢰됩니다. 정확한 진단을 위해 소아신경외과 또는 두개안면외과 전문의 상담을 권고합니다.', 1473, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '두개 유합증', '두개유합증', 'MEDICATION', '두개 유합증의 근본 치료는 수술(두개골 재형성술)이며, 약물만으로 치료하는 것은 현재 불가능합니다. 수술 전후 두개내압 상승 조절을 위해 약물(만니톨 등)이 보조적으로 사용될 수 있으며, 관련 증상 완화를 위한 약물이 필요한 경우도 있습니다. 두개 유합증의 치료 계획은 소아신경외과 또는 두개안면외과 전문의와 상담하시기 바랍니다.', 1474, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '두개 유합증', '두개유합증', 'PREVENTION', '두개 유합증은 주로 유전적 요인과 선천적 발달 이상으로 발생하며, 완전한 예방은 어렵습니다. 임신 중 엽산 보충, 금연·금주, 방사선 노출 최소화 등이 선천성 기형 예방에 일반적으로 도움이 됩니다. 가족력이 있는 경우 산전 유전 상담과 정기적인 산전 초음파 검사를 받으시는 것을 권고합니다.', 1475, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '두개 유합증', '두개유합증', 'CAUSE', '두개 유합증의 원인은 대부분 유전자 돌연변이(FGFR 유전자 등)로 인한 선천적 이상이며, 산발성 돌연변이(가족력 없이 발생)나 아페르 증후군, 크루존 증후군 등 특정 유전 증후군과 관련될 수 있습니다. 특정 봉합선만 조기 유합되면 두개골의 성장 방향이 변형되어 두개 형태 이상이 나타납니다. 정확한 원인 규명을 위해 소아신경외과 및 유전과 전문의 상담을 권고합니다.', 1476, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '두개 유합증', '두개유합증', 'DEFINITION', '두개 유합증은 두개골 봉합선(봉합)이 정상보다 일찍 닫혀(조기 유합) 뇌와 두개골이 정상적으로 성장하지 못하는 선천성 질환입니다. 이로 인해 두개골 모양이 비정상적으로 변형되고, 심한 경우 뇌압이 상승하여 신경학적 문제가 발생할 수 있습니다. 정의에 대한 더 자세한 설명은 소아신경외과 전문의와 상담하시기 바랍니다.', 1477, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '두개 유합증', '두개유합증', 'SYMPTOM', '두개 유합증에서는 어느 봉합선이 조기 유합되느냐에 따라 두개 형태가 달라지며, 시상봉합 유합 시 선두형(머리가 길고 좁음), 관상봉합 유합 시 편평두형(이마가 납작하고 눈 주위 변형), 단독 또는 복합 봉합 유합에 따라 삼각두형, 소두형 등이 나타납니다. 또한 안면부 발달 이상, 안구 돌출, 코 변형 등의 얼굴 형태 이상도 동반될 수 있습니다. 증상에 따른 정확한 진단은 소아신경외과 또는 두개안면외과 전문의를 통해 받으시기 바랍니다.', 1478, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '두개 유합증', '두개유합증', 'DIAGNOSIS', '두개 유합증이 의심되는 경우, 대학병원 소아신경외과, 두개안면외과, 또는 소아과에서 정밀 검사(두개골 CT, 3D CT 등)를 통해 확진할 수 있습니다. 의심 소견이 있다면 빠른 시일 내에 전문의를 찾아야 하며, 생후 초기에 수술적 치료를 받는 것이 예후에 중요합니다. 가능한 빨리 상급 종합병원 소아신경외과 전문의를 방문하시기를 강력히 권고합니다.', 1479, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '두개 유합증', '두개유합증', 'TREATMENT', '두개 유합증의 주된 치료는 두개골 재형성 수술이며, 조기 유합된 봉합선을 개방하고 두개골을 재형성하여 뇌 성장을 위한 공간을 확보합니다. 수술 방법으로는 내시경적 봉합선 절제술(경증, 생후 6개월 이전 권장)과 개두술을 이용한 두개골 재형성술이 있습니다. 수술 시기와 방법은 유합 봉합선의 종류, 두개내압 상승 여부, 아이의 나이에 따라 소아신경외과 전문의가 결정합니다.', 1480, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '사각턱', '사각턱', 'CHECKUP', '사각턱 검진은 성형외과, 구강악안면외과, 치과 등에서 받을 수 있으며, 원인에 따라 적합한 과를 선택하는 것이 중요합니다. 대학병원이나 상급 종합병원의 성형외과 또는 구강악안면외과에서 정밀 평가가 가능합니다. 지역 내 성형외과 또는 구강악안면외과 전문의에게 먼저 상담받으시기를 권고합니다.', 1481, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '사각턱', '사각턱', 'DIET_LIFE', '껌을 많이 씹으면 하악각에 붙은 교근(씹는 근육)이 과발달하여 하악각이 두드러지게 되어 사각턱처럼 보이게 됩니다. 사각턱 예방을 위해 껌 씹는 횟수를 줄이는 것과 함께 질긴 음식 자제, 이갈이(bruxism) 치료, 수면 중 마우스피스 착용 등도 도움이 됩니다. 교근 비대로 인한 사각턱은 성형외과 또는 구강악안면외과 전문의와 상담하시기 바랍니다.', 1482, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '사각턱', '사각턱', 'MEDICATION', '교근 비대로 인한 사각턱에는 보툴리눔 독소(보톡스) 주사 치료가 효과적이며, 교근에 직접 주사하여 근육을 위축시켜 얼굴 라인을 개선합니다. 유전적 요인으로 인한 하악각의 뼈 자체가 각진 경우에는 하악각 절제 수술이 고려됩니다. 약물(보톡스) 치료 여부와 방법은 성형외과 또는 구강악안면외과 전문의와 상담하시기 바랍니다.', 1483, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '사각턱', '사각턱', 'PREVENTION', '사각턱 예방을 위해 껌 씹기와 딱딱하고 질긴 음식 섭취를 줄이는 것이 도움이 됩니다. 추가적으로 이갈이(bruxism)가 있다면 치과에서 마우스피스 처방을 받고, 한쪽으로만 씹는 습관을 교정하는 것도 예방에 효과적입니다. 이미 발생한 교근 비대는 성형외과 전문의 상담을 통해 적절한 치료를 받으시기 권고합니다.', 1484, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '사각턱', '사각턱', 'EXERCISE', '치아 교정 자체가 직접적으로 사각턱을 유발하지는 않으나, 교정 과정에서의 과도한 저작 또는 기저 교근 발달이 함께 있을 수 있습니다. 사각턱 개선을 위한 단순 운동은 효과가 제한적이며, 교근 비대가 원인이라면 보톡스 치료가, 뼈 구조가 문제라면 수술이 권장됩니다. 조카의 상태에 대한 정확한 원인 파악과 치료 방법은 성형외과 또는 구강악안면외과 전문의에게 상담받으시기 바랍니다.', 1485, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '사각턱', '사각턱', 'CAUSE', '사각턱의 주요 원인은 유전적 요인에 의한 하악골(아래턱뼈)의 형태, 교근(저작근) 비대, 또는 두 가지의 복합적 작용입니다. 생활 습관으로는 껌이나 질긴 음식을 자주 씹는 것, 이갈이, 한쪽으로만 씹는 습관 등이 교근 발달을 촉진하여 사각턱을 심화시킬 수 있습니다. 성형외과 또는 구강악안면외과 전문의와 상담하여 원인에 맞는 치료를 받으시기 권고합니다.', 1486, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '사각턱', '사각턱', 'REHAB', '사각턱의 재활 치료는 원인에 따라 달라지며, 교근 비대가 원인인 경우 교근 과활성을 줄이는 스트레칭, 저작 습관 교정, 마우스피스 사용 등이 포함됩니다. 보톡스 시술 후에는 교근 사용을 줄이는 생활 습관 교정과 함께 가벼운 얼굴 근육 스트레칭을 병행합니다. 개인에게 맞는 재활 방법은 성형외과 또는 구강악안면외과 전문의의 지도하에 시행하시기 바랍니다.', 1487, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '사각턱', '사각턱', 'DEFINITION', '사각턱이란 하악골(아래턱뼈) 하악각이 발달하거나 교근(씹는 근육)이 비대해져 얼굴 하부 양측이 각지고 넓어 보이는 형태를 말합니다. 일반적인 갸름한 턱형과 달리 정면에서 턱 라인이 사각형처럼 보이는 것이 특징이며, 측면에서도 하악각이 두드러져 보입니다. 원인이 뼈인지 근육인지에 따라 치료 방법이 달라지므로 전문의 상담이 필요합니다.', 1488, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '사각턱', '사각턱', 'SYMPTOM', '옆모습과 앞모습에서 도드라져 보이는 근육은 주로 교근(masseter muscle)으로, 하악각(턱뼈 모서리) 부위에 위치하며 저작 기능을 담당하는 근육입니다. 이 근육이 과발달하면 하악각이 두드러져 사각턱처럼 보이게 됩니다. 정확한 진단을 위해 성형외과 또는 구강악안면외과 전문의의 진찰을 받으시기 권고합니다.', 1489, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '사각턱', '사각턱', 'DIAGNOSIS', '사각턱으로 인한 외모 콤플렉스는 대인관계 불안, 자존감 저하, 사회활동 위축 등 심리적 불편감을 유발할 수 있으며, 일부에서는 우울증으로 이어지기도 합니다. 물리적으로도 교근 비대가 심한 경우 두통이나 턱관절 불편감을 동반할 수 있습니다. 사각턱으로 인한 불편함이 있다면 성형외과 또는 구강악안면외과 전문의와 상담하여 적절한 치료 방법을 결정하시기 바랍니다.', 1490, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '사각턱', '사각턱', 'TREATMENT', '사각턱 치료 방법으로는 교근 비대가 원인인 경우 보툴리눔 독소(보톡스) 주사, 하악골 구조 문제인 경우 하악각 절제 수술이 있습니다. 치료 여부를 결정하기 위해 성형외과 또는 구강악안면외과에서 CT 촬영 및 전문의 진찰을 통해 원인(뼈/근육)을 정확히 파악하는 것이 중요합니다. 개인의 상태에 맞는 치료 방법은 반드시 전문의와의 충분한 상담을 통해 결정하시기 바랍니다.', 1491, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '안면 골절', '안면골절', 'CAUSE', '안면 골절의 원인에는 교통사고, 낙상, 스포츠 손상, 폭행(구타) 등 다양한 외상이 포함됩니다. 여성을 포함한 누구에게나 강한 외력이 안면부에 가해지면 안면 골절이 발생할 수 있습니다. 안면부에 외상 후 부종, 통증, 변형이 있다면 성형외과 또는 구강악안면외과 응급 진료를 즉시 받으시기 바랍니다.', 1492, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '안면 골절', '안면골절', 'DEFINITION', '안면 골절이란 외부 충격으로 인해 코뼈, 광대뼈, 안와(눈 주변 뼈), 상악골, 하악골 등 얼굴 뼈가 부러진 상태를 말합니다. 턱뼈가 부러진 경우 하악골 골절에 해당하며, CT 검사를 통해 골절 여부 및 범위를 확인할 수 있습니다. 구타 등 외상 후 턱이나 얼굴 통증·붓기·비대칭이 있다면 응급실 또는 성형외과·구강악안면외과를 즉시 방문하시기 바랍니다.', 1493, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '안면 골절', '안면골절', 'SYMPTOM', '안면 골절 시 외상 부위의 부종(붓기), 멍, 통증, 압통은 대표적인 증상이며, 안면 비대칭, 씹기 불편함, 시야 장애 등도 나타날 수 있습니다. 부기만으로 골절을 확정할 수 없으므로 CT 또는 X선 검사를 통한 영상 진단이 필요합니다. 얼굴 외상 후 지속적인 부종과 통증이 있다면 즉시 응급실 또는 성형외과·구강악안면외과를 방문하시기 바랍니다.', 1494, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '안면 골절', '안면골절', 'DIAGNOSIS', '얼굴에 강한 충격 후 눈 주위 부종과 통증이 있다면 안와 골절(blow-out fracture)이 의심될 수 있으며, 성형외과, 안과, 또는 구강악안면외과에서 CT 검사를 통해 진단받을 수 있습니다. 가까운 종합병원 응급실 또는 성형외과·안과 외래를 방문하시면 적절한 진료를 받을 수 있습니다. 시야 이상(복시 등)이 동반된 경우 빠른 시일 내에 전문의 진료를 받으시기 권고합니다.', 1495, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '안면 골절', '안면골절', 'TREATMENT', '안면 골절 치료 후 재활에는 악관절 운동 범위 회복을 위한 턱 개구 운동, 얼굴 근육 기능 회복 운동 등이 포함됩니다. 수술 후 초기에는 부드러운 음식 섭취와 안정이 중요하며, 이후 점진적으로 저작 훈련과 근육 재활을 진행합니다. 물리치료 및 재활 계획은 담당 성형외과 또는 구강악안면외과 전문의와 함께 수립하시기 바랍니다.', 1496, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '안면 비대칭', '안면비대칭', 'CAUSE', '하악 수술 후 안면 비대칭이 발생할 수 있는 원인으로는 수술 중 골절편의 부정확한 위치 고정, 비대칭적 골 유합, 수술 후 부종의 불균형한 소실, 또는 악관절(TMJ)의 비대칭적 반응 등이 있습니다. 또한 수술 후 연조직(근육·지방)의 비대칭적 변화도 원인이 될 수 있습니다. 수술 후 안면 비대칭이 의심되면 담당 구강악안면외과 또는 성형외과 전문의와 상담하시기 바랍니다.', 1497, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '안면 비대칭', '안면비대칭', 'DEFINITION', '안면 비대칭은 얼굴의 좌우가 대칭을 이루지 않는 상태로, 뼈(하악골, 광대뼈 등)의 비대칭, 근육 발달의 차이, 또는 연조직 분포의 불균형이 주된 원인입니다. 양쪽 얼굴 표면의 비대칭은 안면 비대칭의 핵심 증상이며, 교합 비대칭, 턱 중심선 이탈 등도 동반될 수 있습니다. 정확한 원인 파악을 위해 구강악안면외과 또는 성형외과 전문의의 진찰을 받으시기 권고합니다.', 1498, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '안면 비대칭', '안면비대칭', 'SYMPTOM', '안면 비대칭의 주요 증상으로는 좌우 얼굴 크기 또는 형태의 차이, 턱 중심선 편위, 교합 불균형, 얼굴 윤곽의 비대칭 등이 있습니다. 심한 경우에는 저작 불편감, 발음 이상, 턱관절 통증을 유발하기도 합니다. 증상이 심하거나 기능적 문제가 동반된 경우 구강악안면외과 또는 성형외과 전문의의 진료를 받으시기 바랍니다.', 1499, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '안면 비대칭', '안면비대칭', 'DIAGNOSIS', '안면 비대칭 진단을 위해서는 구강악안면외과 또는 성형외과 전문의와 상담하는 것이 적합하며, 치과 교정 전문의도 교합 관련 비대칭 평가에 도움을 줄 수 있습니다. 진단 시 정면·측면 임상 사진, 세팔로메트릭 X선, 파노라마 X선, CT 촬영 등의 영상 자료가 필요하며, 과거 치과·교정 기록도 유용합니다. 전문의 상담 전 현재 증상과 불편함을 구체적으로 정리하여 방문하시기 바랍니다.', 1500, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '안면 비대칭', '안면비대칭', 'TREATMENT', '안면 비대칭의 수술 외 치료로는 치과 교정(경미한 교합 비대칭 개선), 보툴리눔 독소 주사(근육 비대칭 개선), 필러(연조직 비대칭 교정) 등이 있습니다. 치료 방법 선택 시 비대칭의 원인(뼈/근육/연조직), 정도, 기능적 문제 동반 여부, 환자의 선호도 등을 종합적으로 고려해야 합니다. 적절한 치료 계획은 구강악안면외과 또는 성형외과 전문의와 충분히 상담하여 결정하시기 바랍니다.', 1501, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '외꺼풀', '외꺼풀', 'CAUSE', '외꺼풀은 눈꺼풀에 쌍꺼풀 선이 없는 눈 형태로, 동아시아인에게 흔하며 주로 유전적 요인으로 결정됩니다. 부모가 쌍꺼풀이 있어도 열성 유전 또는 유전자 조합에 따라 자녀가 외꺼풀로 태어날 수 있으며, 눈꺼풀 지방 분포와 거근건막(눈꺼풀 올리는 근육 힘줄)의 부착 위치도 영향을 미칩니다. 눈 형태에 관한 궁금증은 안과 또는 성형외과 전문의와 상담하시기 바랍니다.', 1502, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '외꺼풀', '외꺼풀', 'DEFINITION', '외꺼풀이란 눈꺼풀에 주름(쌍꺼풀 선)이 없는 눈꺼풀 형태로, 눈꺼풀 거근건막이 피부에 직접 연결되지 않거나 눈꺼풀 지방이 많아 주름이 형성되지 않는 상태입니다. 동아시아인에게 흔하며, 의학적으로는 단순한 해부학적 변이이나 일부에서는 눈꺼풀 처짐(안검하수)이나 속눈썹 내향(첩모난생)과 동반될 수 있습니다. 안과적 문제가 동반된 경우 안과 전문의 진료가 필요합니다.', 1503, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '외꺼풀', '외꺼풀', 'SYMPTOM', '외꺼풀이 있는 경우, 두꺼운 눈꺼풀로 인해 속눈썹이 각막을 찌르는 첩모난생이 나타날 수 있으며, 이로 인해 이물감, 충혈, 눈물 흘림, 눈부심, 각막 손상 등의 증상이 발생할 수 있습니다. 또한 눈꺼풀 처짐(안검하수)이 동반된 경우 시야 방해와 눈 피로감이 나타날 수 있습니다. 이러한 증상이 있다면 안과 전문의 진료를 받으시기 권고합니다.', 1504, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '외꺼풀', '외꺼풀', 'DIAGNOSIS', '외꺼풀 수술 계획 시 피부 처짐(피부 이완)과 근육(눈꺼풀거근) 기능 저하를 구분하는 것이 중요하며, 피부만 처진 경우 피부 절제술, 근육 기능이 저하된 경우 거근 교정술이 적합합니다. 구분은 세극등 검사, 눈꺼풀 올림 힘(MRD) 측정, 피부 집어보기 검사 등으로 이루어집니다. 정확한 진단과 수술 방법 결정은 안과(성형안과) 또는 성형외과 전문의와 상담하시기 바랍니다.', 1505, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '외꺼풀', '외꺼풀', 'TREATMENT', '외꺼풀 자체가 직접적으로 두통이나 구역질, 정신병적 증상을 유발하지는 않습니다. 다만, 심한 안검하수(눈꺼풀 처짐)로 인해 눈을 뜨기 위해 이마 근육을 과도하게 사용하면 두통이 나타날 수 있습니다. 두통 외 구역질이나 정신병적 증상이 있다면 신경과, 정신건강의학과 등 해당 증상에 맞는 전문의 진료를 받으시기 바랍니다.', 1506, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '주걱턱', '주걱턱', 'CHECKUP', '주걱턱 진단은 주로 치과(교정과) 또는 구강악안면외과에서 이루어지며, 세팔로메트릭 X선 검사를 통해 상하악의 전후 관계를 평가합니다. 성형외과에서도 악교정 수술 상담이 가능하나, 일차적으로는 치과 교정 전문의나 구강악안면외과 전문의를 방문하는 것이 적합합니다. 정확한 진단을 위해 치과 교정 전문의 또는 구강악안면외과 전문의를 먼저 찾으시기 권고합니다.', 1507, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '주걱턱', '주걱턱', 'DIET_LIFE', '주걱턱(하악 전돌증)은 어릴 때부터 아래턱을 내미는 습관이 지속되면 하악골 과성장을 유도하거나 심화시킬 수 있습니다. 음식 섭취 시 아래턱을 내밀어 씹는 습관이나 이갈이, 혀 밀기 습관 등도 주걱턱을 악화시키는 요인이 될 수 있습니다. 주걱턱이 의심되면 치과 교정 전문의와 상담하여 조기에 습관 교정과 치료를 시작하는 것이 도움이 됩니다.', 1508, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '주걱턱', '주걱턱', 'MEDICATION', '주걱턱(하악 전돌증)에 대한 직접적인 약물 치료는 없으며, 교정 치료나 악교정 수술이 주된 치료입니다. 보톡스는 교근 비대로 인한 얼굴 비대칭 개선에 일부 활용되나, 주걱턱 자체의 근본 치료는 되지 않습니다. 필러는 보조적인 윤곽 개선 목적으로 사용될 수 있으나 주걱턱 치료 효과는 제한적이므로, 전문의 상담을 통해 적합한 치료 방법을 선택하시기 바랍니다.', 1509, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '주걱턱', '주걱턱', 'PREVENTION', '주걱턱의 유전적 요인은 하악골의 과성장이나 상악골의 저성장에 관여하는 유전자들이 부모에서 자녀로 전달되어 발현됩니다. 유전적 소인이 있을 경우 성장 과정에서 하악골이 상악골보다 과도하게 성장하여 주걱턱이 나타날 가능성이 높습니다. 주걱턱의 예방은 완전히 어렵지만, 조기 발견 및 성장기 교정 치료를 통해 악화를 늦출 수 있으므로 치과 교정 전문의 상담을 권고합니다.', 1510, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '주걱턱', '주걱턱', 'EXERCISE', '주걱턱 환자에서 혀 위치와 기능 이상이 동반된 경우, 혀를 정상 위치(윗입천장)에 두는 혀 훈련 운동이 악골 성장에 긍정적인 영향을 줄 수 있습니다. 특히 성장기 아동에서 구호흡과 혀 내밀기 습관 교정을 위한 근기능 운동(MFT)은 교정 치료의 효과를 높이는 데 도움이 됩니다. 혀 운동 치료는 언어치료사나 치과 교정 전문의의 지도하에 시행하시기 바랍니다.', 1511, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '주걱턱', '주걱턱', 'CAUSE', '주걱턱은 유전적 요인 외에도 하악골의 성장 과잉, 상악골 저성장, 혀 내밀기·구호흡 등의 구강 습관, 성장호르몬 이상, 턱관절 이상 등 다양한 원인으로 발생할 수 있습니다. 가족력이 없더라도 위 요인들의 단독 또는 복합 작용으로 주걱턱이 나타날 수 있습니다. 정확한 원인 파악을 위해 치과 교정 전문의 또는 구강악안면외과 전문의와 상담하시기 바랍니다.', 1512, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '주걱턱', '주걱턱', 'REHAB', '시상분할 절골술(BSSO) 수술 후 회복을 돕는 재활로는 초기 악관절 유연성 회복 운동(개구 운동), 언어 재활, 저작 근육 스트레칭 등이 있습니다. 수술 후 수주간 유동식과 연식을 섭취하며 점진적으로 악관절 운동 범위를 늘리는 것이 권장됩니다. 구체적인 재활 프로그램은 담당 구강악안면외과 전문의 및 재활의학과 전문의의 지도에 따르시기 바랍니다.', 1513, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '주걱턱', '주걱턱', 'DEFINITION', '주걱턱이란 하악골(아래턱뼈)이 상악골보다 과도하게 전방으로 발달하거나 상악골이 후방에 위치하여 아래턱이 위턱보다 앞으로 돌출된 상태입니다. 정면에서 보면 아래턱이 도드라지고, 옆면에서는 아래입술이 윗입술보다 앞에 위치하며, 씹기(교합) 기능 이상과 반대 교합이 특징입니다. 진단과 치료 방법은 치과 교정 전문의 또는 구강악안면외과 전문의와 상담하시기 바랍니다.', 1514, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '주걱턱', '주걱턱', 'SYMPTOM', '주걱턱 교정을 위한 악교정 수술(양악 수술 등) 후 부작용으로 일시적인 감각 이상(하순·턱 부위 저림), 부종, 출혈, 감염, 개구 제한 등이 나타날 수 있습니다. 드물게 악관절 이상, 재발(턱뼈 위치 변화), 신경 손상, 기도 문제 등 심각한 합병증이 발생할 수 있습니다. 수술 전 담당 구강악안면외과 전문의와 부작용 및 위험성에 대해 충분히 상담하시기 바랍니다.', 1515, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '주걱턱', '주걱턱', 'DIAGNOSIS', '주걱턱 치료 상담 시 ''치료 방법 및 단계(교정과 수술의 순서)'', ''예상 치료 기간'', ''수술 후 부작용 및 회복 기간'', ''재발 가능성'', ''비용'' 등을 의사에게 질문하는 것이 중요합니다. 회복을 위해서는 수술 후 지시에 따른 식이 제한(유동식·연식 유지), 구강 위생 관리, 정기 추적 관찰이 필요합니다. 치과 교정 전문의 및 구강악안면외과 전문의와 충분한 상담을 통해 치료 계획을 수립하시기 바랍니다.', 1516, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('성형미용 및 재건', '주걱턱', '주걱턱', 'TREATMENT', '주걱턱 수술적 치료로는 하악 시상분할 절골술(BSSO), 상악 르포르 절골술(Le Fort I), 또는 양악 수술 등이 있으며, 심각도와 원인에 따라 단독 또는 병행하여 시행합니다. 교정 치료를 선행한 후 수술을 진행하는 것이 일반적이며, 수술 후에도 교정 치료를 통해 교합을 안정시킵니다. 수술 방법 결정은 구강악안면외과 전문의 및 치과 교정 전문의와 면밀히 상담하여 결정하시기 바랍니다.', 1517, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '가와사키병', '가와사키병', 'MEDICATION', '가와사키병 치료에 사용되는 주요 약물인 아스피린과 면역글로불린(IVIG)은 일반적으로 임신 중 또는 수유 중인 여성에게는 적용되지 않으며, 가와사키병은 주로 소아 연령층에서 발생합니다. 아스피린은 임신 중 고용량 사용 시 태아에 영향을 줄 수 있으며, IVIG는 상대적으로 안전하나 수유 중 사용은 전문의 지도하에 이루어져야 합니다. 임신 또는 수유 중 약물 사용에 대해서는 반드시 담당 의사와 상담하시기 바랍니다.', 1518, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '가와사키병', '가와사키병', 'PREVENTION', '가와사키병은 명확한 예방법이 확립되어 있지 않으며, 유전적 감수성과 특정 감염(바이러스, 세균 등)의 상호작용으로 발생하는 것으로 알려져 있습니다. 유전적 소인을 가진 소아에서 면역 반응이 과활성화되면 발병 위험이 높아지나, 유전자 자체를 변경하여 예방하는 방법은 현재 없습니다. 조기 발견과 신속한 치료가 합병증 예방에 가장 중요하므로, 의심 증상 발생 시 소아과 전문의를 즉시 방문하시기 바랍니다.', 1519, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '가와사키병', '가와사키병', 'CAUSE', '가와사키병은 특정 유전적 소인(HLA 등 면역 관련 유전자)이 있는 경우 발병 위험이 높아질 수 있으나, 부모가 앓은 적 없어도 산발적으로 발생할 수 있습니다. 정확한 원인은 아직 완전히 밝혀지지 않았으며, 유전적 요인 외에 특정 감염(바이러스·세균)에 대한 비정상적 면역 반응이 주요 원인으로 추정됩니다. 자녀에게 증상이 의심된다면 소아과 전문의에게 즉시 상담하시기 바랍니다.', 1520, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '가와사키병', '가와사키병', 'DEFINITION', '가와사키병은 주로 5세 미만 영유아에서 발생하는 원인 불명의 급성 열성 전신 혈관염으로, 전신의 중간 크기 혈관에 염증이 생기는 질환입니다. 적절히 치료하지 않으면 관상동맥류(심장 혈관 합병증)가 발생할 수 있어 조기 진단과 치료가 매우 중요합니다. 증상이 의심되면 즉시 소아과 전문의를 방문하시기 바랍니다.', 1521, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '가와사키병', '가와사키병', 'SYMPTOM', '가와사키병의 주요 증상으로는 5일 이상 지속되는 고열(38.5℃ 이상), 양측 비화농성 결막 충혈, 입술과 구강 점막의 발적·딸기 혀, 손발 부종 후 낙설(피부 벗겨짐), 다형성 피부 발진, 경부 림프절 비대가 있습니다. 이 중 5가지 이상이 충족될 때 가와사키병으로 진단합니다. 해당 증상이 나타나면 즉시 소아과 전문의에게 진료를 받으시기 바랍니다.', 1522, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '가와사키병', '가와사키병', 'DIAGNOSIS', '가와사키병은 전신 혈관염으로, 피부 발진과 홍조 외에도 발열, 림프절 비대, 점막 이상 등 다양한 전신 증상이 동반되므로 피부과보다 소아과에서 진단받는 것이 적합합니다. 가와사키병 진단은 소아과 전문의가 임상 기준 평가, 혈액 검사, 심장 초음파 검사 등을 통해 시행합니다. 의심 증상이 있다면 빠른 시일 내에 소아과 전문의를 방문하시기 바랍니다.', 1523, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '가와사키병', '가와사키병', 'TREATMENT', '가와사키병의 주된 치료는 고용량 아스피린 복용과 면역글로불린(IVIG) 정맥 주사이며, 적절한 치료 시 대부분 2~3일 내에 열이 내리고 증상이 호전됩니다. 관상동맥류 합병증 예방을 위해 조기 치료가 매우 중요하며, 심장 초음파 추적 관찰이 필요합니다. 약물 치료 중 증상 변화나 우려사항은 담당 소아과 전문의와 즉시 상담하시기 바랍니다.', 1524, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '과숙아', '과숙아', 'CAUSE', '과숙아(만기 후 분만)는 임신 42주 이상까지 출산이 이루어지지 않는 경우로, 자궁 수축 기전의 이상, 태아 부신-뇌하수체 축의 미성숙, 자궁경부의 불량한 성숙, 또는 원인 불명인 경우가 많습니다. 일부에서는 유전적 소인, 비만, 초산부 등이 위험 요인으로 알려져 있습니다. 분만 시기에 대한 우려가 있다면 담당 산부인과 전문의와 상담하시기 바랍니다.', 1525, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '과숙아', '과숙아', 'DEFINITION', '과숙아는 출산이 임신 42주 이상 지연되는 경우를 말하며, 단순히 ''출산을 하지 않는 것''이 원인이 아니라 자궁 수축 신호의 이상, 태아 성숙 신호의 지연 등 복합적인 생리적 요인이 원인입니다. 가장 흔한 경우는 원인이 명확하지 않은 특발성이며, 유도 분만 등 의학적 개입을 통해 분만을 유도합니다. 정확한 이유와 관리 방법은 담당 산부인과 전문의와 상담하시기 바랍니다.', 1526, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '과숙아', '과숙아', 'SYMPTOM', '과숙아는 태반 기능 저하로 인한 산소·영양 공급 감소로 저산소 손상이 발생할 수 있으며, 이로 인해 신경 발달 이상이 나타날 수 있습니다. 특이 행동이나 발달 지연이 관찰되는 경우, 분만 중 저산소증 병력, 태변 흡입 증후군 등의 영향을 평가해야 합니다. 과숙아 아동의 발달 및 행동 평가는 소아과 또는 소아신경과 전문의와 상담하시기 바랍니다.', 1527, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '과숙아', '과숙아', 'TREATMENT', '과숙아는 태반 기능 저하, 저산소증, 태변 흡입 등의 합병증 예방을 위해 분만 전 면밀한 태아 감시와 적절한 시기의 유도 분만이 가장 중요한 치료입니다. 출생 후 합병증(저혈당, 저산소증 등)이 있을 경우 신생아 집중치료실(NICU)에서 적절한 지지 치료를 제공합니다. 미숙아는 호흡 보조, 영양 지원, 감염 예방 등의 치료가 필요하며, 모두 신생아과 전문의의 관리하에 이루어집니다.', 1528, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '기관지폐 형성이상', '기관지폐형성이상', 'PREVENTION', '기관지폐 형성이상(BPD) 예방을 위해 임신 중에는 조산 예방(자궁경부 무력증 관리, 조기진통 치료 등)이 가장 중요합니다. 조산이 불가피한 경우 출산 전 산모에게 코르티코스테로이드를 투여하여 태아 폐 성숙을 촉진하고, 출생 후 계면활성제 투여 및 최소한의 침습적 인공호흡기 사용이 BPD 발생 위험을 줄입니다. 조산아 관리에 대해서는 신생아과 전문의와 상담하시기 바랍니다.', 1529, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '기관지폐 형성이상', '기관지폐형성이상', 'CAUSE', '기관지폐 형성이상(BPD)의 주요 원인으로는 조산(특히 임신 28주 미만)으로 인한 미성숙한 폐, 산소 독성(장기간 고농도 산소 투여), 기계적 인공호흡기로 인한 압력 손상, 출생 전후 감염 및 염증 등이 있습니다. 이러한 요인들이 복합적으로 작용하여 폐 조직의 발달 이상과 만성 염증을 유발합니다. 자녀의 상태 및 치료에 대해서는 담당 신생아과 전문의와 충분히 상담하시기 바랍니다.', 1530, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '기관지폐 형성이상', '기관지폐형성이상', 'DEFINITION', '기관지폐 형성이상(BPD)은 주로 미숙아에서 인공호흡기 치료 및 산소 치료 후 28일 이상 산소 의존성이 지속되는 만성 폐질환입니다. 최근 출산 평균 연령(산모 고령화)보다는 임신 주수가 낮은 조산아의 생존율 향상과 의료 기술 발전으로 인해 극소 미숙아가 증가하면서 BPD 발생이 늘고 있습니다. 정확한 정보는 담당 신생아과 전문의와 상담하시기 바랍니다.', 1531, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '기관지폐 형성이상', '기관지폐형성이상', 'SYMPTOM', '기관지폐 형성이상(BPD)에서 호흡 시 이상한 소리(천명음, 그렁거리는 소리 등)는 기도 좁아짐이나 분비물 저류로 인해 발생하며, 호기 시 또는 흡기 시 들릴 수 있습니다. 이는 기도 반응성 증가, 만성 염증, 기도 연화증 등이 원인으로, 운동이나 감염 시 악화될 수 있습니다. 호흡 이상음이 지속되면 신생아과 또는 소아 호흡기내과 전문의에게 진료를 받으시기 바랍니다.', 1532, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '기관지폐 형성이상', '기관지폐형성이상', 'DIAGNOSIS', '기관지폐 형성이상(BPD) 진단은 신생아과에서 이루어지며, 조산아 또는 미숙아에서 28일 이상 지속되는 산소 의존성 여부를 평가합니다. 흉부 X선, 혈액 가스 검사, 폐 기능 검사, 필요시 CT 촬영 등이 진단에 활용됩니다. 호흡 기능 이상이 의심된다면 신생아 집중치료실(NICU) 또는 신생아과 전문의에게 즉시 의뢰하시기 바랍니다.', 1533, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '기관지폐 형성이상', '기관지폐형성이상', 'TREATMENT', '기관지폐 형성이상(BPD)은 치료 후에도 호흡곤란이 지속될 수 있으며, 폐 발달이 이루어지는 생후 수년에 걸쳐 점진적으로 호전되는 경우가 많습니다. 일부에서는 학령기까지 기도 반응성 증가나 운동 시 호흡 제한이 남을 수 있습니다. 호흡곤란이 지속된다면 소아 호흡기내과 전문의와 장기 추적 관찰 및 치료 계획을 수립하시기 바랍니다.', 1534, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '라이 증후군', '라이증후군', 'CHECKUP', '라이 증후군 확인을 위해 혈액 검사(간 효소, 암모니아, 혈당 등), 척수액 검사 외에도 간 생검(간 조직 검사)이 확진에 중요한 검사입니다. 뇌 부종 평가를 위한 뇌 CT 또는 MRI, 뇌파 검사(EEG)도 신경학적 상태 평가에 필요합니다. 정확한 검사 계획은 소아과 또는 소아신경과 전문의와 상담하시기 바랍니다.', 1535, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '라이 증후군', '라이증후군', 'DIET_LIFE', '라이 증후군은 바이러스 감염(특히 인플루엔자, 수두) 후 아스피린 복용과 관련하여 발생하는 것으로 알려져 있으므로, 소아에서 바이러스 감염 시 아스피린 사용을 피하는 것이 가장 중요한 예방 습관입니다. 발열 시에는 아세트아미노펜(타이레놀)을 사용하고, 충분한 수분 섭취와 휴식, 규칙적인 예방접종(인플루엔자, 수두 백신)이 권장됩니다. 소아 발열 시 약물 선택에 대해서는 소아과 전문의와 상담하시기 바랍니다.', 1536, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '라이 증후군', '라이증후군', 'MEDICATION', '라이 증후군 치료 중 뇌부종 및 두개내압 상승 조절을 위해 고삼투압 약물 투여 시 전해질 불균형 및 신기능 이상 모니터링이 필요합니다. 혈당 조절, 암모니아 수치 감소를 위한 치료 중 저혈당, 전해질 이상 등의 부작용이 발생할 수 있어 집중적인 임상 모니터링이 중요합니다. 모든 치료 및 부작용 관리는 소아과 전문의 및 중환자 전문의의 감독하에 이루어져야 합니다.', 1537, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '라이 증후군', '라이증후군', 'PREVENTION', '라이 증후군 예방을 위해 소아의 바이러스 감염(인플루엔자, 수두 등) 시 해열제로 아스피린 대신 아세트아미노펜(타이레놀)이나 이부프로펜을 사용하는 것이 권장됩니다. 타이레놀은 소아에서 안전하게 사용할 수 있으며, 적절한 용량을 지켜 복용하면 라이 증후군 위험 없이 발열과 통증을 조절할 수 있습니다. 소아 약물 복용에 대해서는 반드시 소아과 전문의 또는 약사와 상담하시기 바랍니다.', 1538, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '라이 증후군', '라이증후군', 'CAUSE', '라이 증후군은 바이러스 감염(인플루엔자, 수두 등) 후 아스피린 복용이 주요 유발 요인으로, 미토콘드리아 기능 이상을 초래하여 지방산 산화 장애와 암모니아 대사 이상이 발생합니다. 이로 인해 간세포 손상, 고암모니아혈증, 저혈당, 뇌부종이 나타나며, 이것이 급성 뇌증과 간 기능 부전의 원인이 됩니다. 정확한 정보는 소아과 또는 소아신경과 전문의와 상담하시기 바랍니다.', 1539, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '라이 증후군', '라이증후군', 'DEFINITION', '상기도 감염이나 수두 치료 말기에 생명이 위험해지는 것은 라이 증후군의 발현 때문으로, 바이러스 감염과 아스피린 복용이 결합되면 미토콘드리아 손상이 일어나 간 기능 부전과 급성 뇌부종이 급격히 진행하기 때문입니다. 초기 증상(구역, 구토, 의식 변화 등)이 갑자기 악화되어 혼수상태에 이를 수 있어 빠른 대응이 중요합니다. 감염 중 갑작스러운 의식 변화나 구토가 나타나면 즉시 응급 진료를 받으시기 바랍니다.', 1540, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '라이 증후군', '라이증후군', 'SYMPTOM', '라이 증후군에서 바이러스 감염 회복 중(2~5일 후) 갑자기 심한 구역·구토가 나타나는 것이 초기 대표 증상이며, 이는 반복적이고 지속적인 특성을 보입니다. 이후 의식 변화(혼란, 무기력), 행동 이상, 경련 등 신경학적 증상이 빠르게 진행합니다. 바이러스 감염 후 갑작스러운 구토와 의식 변화가 나타나면 즉시 응급실을 방문하시기 바랍니다.', 1541, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '라이 증후군', '라이증후군', 'DIAGNOSIS', '혼수상태와 같은 의식 저하가 바이러스 감염 후 나타났다면 라이 증후군을 포함한 다양한 원인을 감별해야 하며, 소아과 또는 소아신경과 전문의를 즉시 찾아야 합니다. 대학병원 응급실 소아과에서 혈액 검사(암모니아, 간 효소, 혈당), 신경학적 평가, 뇌 영상 검사 등을 통해 빠른 진단이 이루어집니다. 즉각적인 의료 처치가 생명과 직결되므로 지체 없이 응급 진료를 받으시기 바랍니다.', 1542, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '라이 증후군', '라이증후군', 'TREATMENT', '라이 증후군 치료는 특정 원인 약물이 없으며, 뇌부종 감소(만니톨 등), 두개내압 모니터링, 혈당 및 전해질 교정을 위한 포도당 정맥 주사, 암모니아 감소 치료 등 집중지지 치료가 중심입니다. 가와사키병은 면역글로불린(IVIG)과 아스피린으로 치료하며, 라이 증후군과는 별개의 질환입니다. 각 질환의 정확한 치료 방법은 담당 소아과 전문의와 상담하시기 바랍니다.', 1543, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '미숙아 망막병증', '미숙아망막병증', 'CAUSE', '미숙아 망막병증(ROP)의 원인으로는 산소 과다 투여 외에도 미숙아 자체의 혈관 미성숙, 저산소증 및 재산소화 반복, 패혈증(감염), 빈혈, 수혈, 저체중 출생, 인슐린 유사 성장인자-1(IGF-1) 결핍 등이 있습니다. 이러한 요인들이 복합적으로 작용하여 미성숙한 망막 혈관의 비정상적 증식을 유발합니다. 자녀의 ROP 관련 우려는 신생아과 및 소아 안과 전문의와 상담하시기 바랍니다.', 1544, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '미숙아 망막병증', '미숙아망막병증', 'DEFINITION', '미숙아 망막병증(ROP)은 임신 28주 미만의 극소 미숙아나 출생 체중 1500g 미만의 저체중출생아에서 발생 위험이 높으며, 미숙 정도가 심할수록 발병률과 중증도가 높아집니다. 적절히 치료하지 않으면 망막 박리와 실명으로 이어질 수 있어 조기 발견과 치료가 매우 중요합니다. 고위험 미숙아는 정기적인 안과 검진(망막 검사)을 받아야 하므로 담당 소아과 및 안과 전문의의 안내를 따르시기 바랍니다.', 1545, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '미숙아 망막병증', '미숙아망막병증', 'SYMPTOM', '미숙아 망막병증(ROP)에서 혈관 이상 외에도 중증으로 진행 시 망막 견인(tractional retinal detachment), 망막 박리, 사시(내사시 등), 약시, 근시, 심한 경우 실명 등이 나타날 수 있습니다. 초기에는 증상이 없거나 미미하여 정기 안과 검진으로 조기 발견이 중요합니다. 자녀의 망막 상태는 소아 안과 또는 망막 전문의에게 정기적으로 평가받으시기 바랍니다.', 1546, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '미숙아 망막병증', '미숙아망막병증', 'DIAGNOSIS', '미숙아 망막병증(ROP) 진단 및 치료는 소아 안과, 망막 전문 안과 또는 신생아과와 안과가 협진하는 대학병원·상급 종합병원에서 받을 수 있습니다. 고위험 미숙아는 생후 4~6주 이내 안과 검진을 시작하며, 이후 망막 발달 상태에 따라 추적 관찰합니다. 저체중출생아를 돌보는 신생아과 전문의와 안과 전문의에게 정기 검진 일정을 상담하시기 바랍니다.', 1547, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '미숙아 망막병증', '미숙아망막병증', 'TREATMENT', '레이저 치료(레이저 광응고술)는 미숙아 망막병증의 비정상적 혈관 증식을 억제하여 망막 박리를 예방하는 효과가 있으며, 자연 경과보다 실명 위험을 크게 줄입니다. 최근에는 항혈관내피성장인자(anti-VEGF) 주사 치료가 도입되어 레이저보다 시야 보존 효과가 좋을 수 있으나, 장기 안전성은 추가 연구가 필요합니다. 치료 방법 선택은 담당 소아 안과 또는 망막 전문의와 충분히 상담하여 결정하시기 바랍니다.', 1548, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '발달 장애', '발달장애', 'PREVENTION', '임신 전 예방 조치로는 엽산 보충제 복용(선천성 기형 예방), 풍진·수두 등 예방접종 확인, 당뇨·갑상선 질환 등 만성질환 관리, 음주·흡연·유해물질 노출 차단 등이 있으며, 이를 통해 일부 발달 장애 위험을 줄일 수 있습니다. 또한 유전 상담을 통해 유전적 위험도를 미리 파악할 수 있습니다. 임신 전 건강 상태와 예방 조치에 대해서는 산부인과 또는 유전 상담 전문가와 상담하시기 바랍니다.', 1549, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '발달 장애', '발달장애', 'CAUSE', '발달 장애에서 운동·언어·사회적 능력의 발달 지연이 나타나는 이유는 뇌 발달 과정에서 특정 신경회로의 형성이 비정상적으로 이루어지기 때문입니다. 유전적 이상, 뇌 구조 이상, 조산, 분만 중 저산소증, 감염 등 다양한 원인이 복합적으로 작용하여 여러 발달 영역에 동시에 영향을 줄 수 있습니다. 발달 지연이 의심되면 소아청소년과 또는 소아신경과 전문의에게 조기 평가와 치료를 받으시기 권고합니다.', 1550, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '발달 장애', '발달장애', 'DEFINITION', '아기의 발달 지연이 의심될 경우 소아청소년과 전문의를 먼저 방문하여 발달 선별 검사(Denver II 등)를 받는 것이 권장됩니다. 이후 필요에 따라 소아신경과, 소아재활의학과, 발달소아과 등에서 표준화된 발달 평가 도구와 신경학적 검사, 뇌 MRI, 염색체 검사 등을 시행합니다. 뒤집기는 생후 4~6개월경 가능한 것이 정상이므로, 이 시기를 지나도 못 한다면 지체 없이 전문의 상담을 받으시기 바랍니다.', 1551, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '발달 장애', '발달장애', 'SYMPTOM', '발달 장애에서 사회적 관계 문제는 눈 맞춤 회피, 또래와의 상호작용 어려움, 공감 능력 저하로 나타나며, 의사소통 지연은 언어 발달 지체, 비언어적 의사소통 제한 등으로 진행됩니다. 인지 발달 지연은 학습 능력 저하, 추상적 사고 어려움, 일상생활 기술 습득 지연을 초래하며, 이로 인해 학교 적응 곤란, 사회적 고립, 직업 활동 제한 등의 결과가 나타날 수 있습니다. 조기 발견과 개입이 예후에 큰 영향을 미치므로 전문의 상담을 통한 조기 평가가 중요합니다.', 1552, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '발달 장애', '발달장애', 'DIAGNOSIS', '발달 장애 진단은 소아청소년과, 소아신경과, 소아정신건강의학과, 발달소아과 전문의가 담당합니다. 진단 과정에는 발달력 청취, 표준화된 발달 검사(Denver II, Bayley 발달 검사 등), 행동 관찰, 심리 검사, 필요 시 뇌 MRI·EEG·염색체 검사 등이 포함됩니다. 여러 전문가가 팀을 이루어 다각도로 평가하므로, 발달 지연이 의심되면 소아청소년과를 통해 전문 기관에 의뢰받는 것이 좋습니다.', 1553, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '발달 장애', '발달장애', 'TREATMENT', '발달 장애 치료 및 지원에는 언어치료, 작업치료, 물리치료, 행동 분석 치료(ABA), 특수교육 등이 포함됩니다. 사회적 기술 훈련, 감각 통합 치료, 인지 재활 프로그램도 활용되며, 필요 시 정신건강의학과적 약물 치료가 병행됩니다. 조기 집중 개입일수록 효과가 크므로, 발달 장애가 의심되거나 진단된 경우 소아청소년과 및 관련 전문의와 상담하여 개인에게 맞는 통합적 치료 계획을 수립하는 것이 중요합니다.', 1554, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '방실 중격 결손', '방실중격결손', 'CAUSE', '방실 중격 결손은 대부분 선천성 원인으로 발생하며, 태아 심장 발생 과정 중 심방 중격과 심실 중격, 방실 판막이 정상적으로 형성되지 않아 나타납니다. 다운증후군(21번 삼염색체증) 등 염색체 이상과의 연관성이 높으며, 특히 완전형 방실 중격 결손의 경우 다운증후군 환자에서 흔하게 발견됩니다. 유전자 변이, 임신 초기 풍진 감염, 특정 약물 노출 등도 선천성 원인으로 알려져 있습니다.', 1555, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '방실 중격 결손', '방실중격결손', 'DEFINITION', '방실 중격 결손(AVSD)은 심장의 심방 중격, 심실 중격, 승모판 및 삼첨판이 정상적으로 분리 형성되지 않아 심방과 심실 사이에 구멍이 생기는 선천성 심장 기형입니다. 이로 인해 좌우 심장 사이에 비정상적인 혈액 단락이 발생하여 폐혈류가 증가하고, 심부전, 폐동맥 고혈압 등으로 진행할 수 있습니다. 다운증후군과 동반되는 경우가 많으며, 정확한 진단과 치료를 위해 소아심장과 전문의 상담이 필요합니다.', 1556, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '방실 중격 결손', '방실중격결손', 'SYMPTOM', '방실 중격 결손의 특징적인 증상으로는 수유 곤란, 빠른 호흡, 체중 증가 불량, 발한, 청색증 등이 있습니다. 심부전이 진행되면 빈호흡, 함몰호흡, 늑골하 함몰, 간 비대 등이 나타날 수 있으며, 반복적인 호흡기 감염도 흔합니다. 증상의 정도는 결손 크기와 유형에 따라 다양하므로, 위와 같은 증상이 관찰될 경우 소아심장과 전문의의 진료를 받으시기 바랍니다.', 1557, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '방실 중격 결손', '방실중격결손', 'DIAGNOSIS', '방실 중격 결손 진단은 소아심장과(소아순환기과) 전문의를 찾아야 하며, 진단 과정에는 청진, 심전도(ECG), 흉부 X선, 심장 초음파(심초음파)가 기본적으로 포함됩니다. 심초음파는 결손의 크기, 위치, 혈류 방향, 판막 기능을 평가하는 핵심 검사이며, 필요 시 심장 MRI나 심도자술이 추가될 수 있습니다. 다운증후군이 동반된 경우에는 염색체 검사도 함께 시행될 수 있습니다.', 1558, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '방실 중격 결손', '방실중격결손', 'TREATMENT', '방실 중격 결손의 근본적인 치료는 외과적 수술이며, 심방 및 심실 중격의 구멍을 패치로 막고 방실 판막을 교정하는 수술을 시행합니다. 수술 시기는 보통 생후 3~6개월 이내로 심부전 증상, 결손 크기, 동반 기형 등을 고려하여 소아심장과 전문의가 결정합니다. 수술 전까지는 이뇨제, 디곡신 등의 약물로 심부전 증상을 조절할 수 있으며, 가족력 여부와 무관하게 조기 수술적 교정이 중요합니다.', 1559, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '선천성 담관 폐쇄증', '선천성담관폐쇄증', 'DIET_LIFE', '선천성 담관 폐쇄증으로 수술(카사이 수술 또는 간이식) 후에도 간 기능 보호를 위해 고지방·고열량 식이와 지용성 비타민(A, D, E, K) 보충이 필요합니다. 담즙 정체로 인한 감염 예방을 위해 위생 관리를 철저히 하고, 주기적인 간 기능 검사와 전문의 추적 관찰이 필수적입니다. 간경변이나 문맥 고혈압 등의 합병증 발생 여부를 정기적으로 확인하고, 소아소화기과 및 간이식 전문의의 지속적인 관리를 받으시기 바랍니다.', 1560, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '선천성 담관 폐쇄증', '선천성담관폐쇄증', 'CAUSE', '선천성 담관 폐쇄증의 원인에서 유전자의 역할은 아직 완전히 밝혀지지 않았으나, CFC1, CFCR 등 좌우 비대칭 결정 유전자의 변이가 일부 환자에서 보고되어 있습니다. 그러나 대부분의 경우는 단일 유전자 이상보다는 면역학적 이상, 바이러스 감염(CMV, 로타바이러스 등), 담관 발생 이상 등 복합적인 원인으로 발생합니다. 가족성 발생은 드물어 유전성 질환으로 분류되지 않으나, 유전적 소인이 일부 기여할 수 있으므로 소아소화기과 전문의 상담을 권장합니다.', 1561, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '선천성 담관 폐쇄증', '선천성담관폐쇄증', 'DEFINITION', '선천성 담관 폐쇄증은 유전적·발생적 요인 외에도 면역학적 이상(담관에 대한 자가면역 반응), 바이러스 감염(CMV, 로타바이러스, 레오바이러스 등), 담관 혈행 이상 및 허혈성 손상, 독소 노출 등이 발병에 관여하는 것으로 알려져 있습니다. 태내 또는 신생아기 염증 반응이 담관 파괴를 유발하는 기전이 주목받고 있으며, 이러한 복합적 요인들이 상호작용하여 발생하는 것으로 이해됩니다. 정확한 병인 규명을 위해 전문의 상담이 필요합니다.', 1562, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '선천성 담관 폐쇄증', '선천성담관폐쇄증', 'SYMPTOM', '선천성 담관 폐쇄증에서는 담즙 배출 장애로 인해 빌리루빈이 혈액에 축적되어 소변이 진한 갈색 또는 콜라색으로 변하는 증상이 나타납니다. 반면 대변은 담즙이 포함되지 않아 흰색 또는 회백색(무담즙변)으로 변하는 것이 특징적 증상입니다. 소변이 검게 변하는 것은 담즙색소 배출 증가를 반영하므로, 이러한 증상이 신생아에게 나타나면 즉시 소아청소년과 또는 소아소화기과 전문의를 방문하시기 바랍니다.', 1563, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '선천성 담관 폐쇄증', '선천성담관폐쇄증', 'DIAGNOSIS', '아기의 소변이 갈색으로 변하고 황달이 지속되면 선천성 담관 폐쇄증을 의심할 수 있으며, 소아청소년과 또는 소아소화기과가 있는 종합병원을 방문해야 합니다. 진단을 위해 혈액 검사(간 기능, 빌리루빈), 복부 초음파, 간 생검, 동위원소 간담도 스캔 등이 시행됩니다. 이 질환은 조기 진단과 치료(카사이 수술)가 예후에 결정적이므로, 생후 60일 이전에 전문의 진료를 받는 것이 매우 중요합니다.', 1564, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '선천성 담관 폐쇄증', '선천성담관폐쇄증', 'TREATMENT', '신생아 황달과 흰색(회백색) 변이 동반되는 경우 선천성 담관 폐쇄증을 강력히 의심해야 하며, 담관 폐쇄로 담즙이 장으로 배출되지 않아 대변이 흰색 또는 회색을 띠는 것이 특징입니다. 치료는 카사이 수술(간문맥장문합술)이 표준 치료이며, 생후 60일 이내에 시행할수록 성공률이 높습니다. 카사이 수술 후에도 간경변이 진행되는 경우 간이식이 필요할 수 있으므로, 증상이 의심되면 즉시 소아소화기과 전문의를 방문하시기 바랍니다.', 1565, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '성조숙증', '성조숙증', 'CAUSE', '초등학교 입학 전(남아 기준 만 9세 이전) 고환 용적 증가(4mL 이상)와 음모 발현은 성조숙증의 대표적인 신체 징후입니다. 이는 시상하부-뇌하수체-생식선 축의 조기 활성화로 인한 성선자극호르몬 의존성 성조숙증이거나, 부신 이상, 뇌종양, 고환 종양 등 다양한 원인에 의한 것일 수 있습니다. 정확한 원인 감별과 적절한 치료를 위해 소아내분비과 전문의의 진료를 받으시기 바랍니다.', 1566, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '성조숙증', '성조숙증', 'DEFINITION', '성조숙증은 여아 만 8세, 남아 만 9세 이전에 2차 성징이 나타나는 상태로, 뇌하수체 성선자극호르몬의 조기 분비로 인해 성호르몬이 과다 분비되어 발생합니다. 성욕 증가 등 심리·행동적 문제가 나타나면 소아정신건강의학과 상담과 함께 소아내분비과 치료를 병행해야 합니다. 치료는 GnRH 작용제 투여로 사춘기 진행을 억제하며, 최종 키 감소와 심리사회적 문제를 예방하기 위해 전문의 지도하에 관리하는 것이 중요합니다.', 1567, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '성조숙증', '성조숙증', 'SYMPTOM', '성조숙증의 특징적 증상은 또래보다 빠른 신체 성장, 2차 성징의 조기 발현이며, 초기에는 성장 속도가 빠르지만 성장판이 조기 폐쇄되어 최종 키가 오히려 작아지는 결과를 초래합니다. 반면 발달이 또래보다 느린 경우는 성조숙증과 반대 개념으로, 성장 지연이나 성선기능저하증 등 다른 내분비 이상을 의심해야 합니다. 성장 속도나 사춘기 발현 시기에 이상이 있다면 소아내분비과 전문의 진료를 받으시기 바랍니다.', 1568, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '성조숙증', '성조숙증', 'DIAGNOSIS', '남아의 고환 용적이 4mL 이상으로 커지거나 만 9세 이전에 증가한다면 성조숙증을 의심할 수 있으며, 소아내분비과 전문의를 방문해야 합니다. 진단을 위해 혈중 황체형성호르몬(LH), 난포자극호르몬(FSH), 테스토스테론 측정, GnRH 자극 검사, 골연령(손목 X선) 검사가 시행됩니다. 뇌하수체 MRI 등 영상 검사로 기질적 원인을 감별하는 것도 중요하므로, 지체 없이 전문의 진료를 받으시기 바랍니다.', 1569, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '성조숙증', '성조숙증', 'TREATMENT', '여아에서 만 8세 이전의 유방 발달과 음모 발현은 성조숙증의 진단 기준에 해당하며, 소아내분비과 전문의의 진료가 필요합니다. 치료는 원인에 따라 달라지며, 특발성 중추성 성조숙증의 경우 GnRH 작용제(류프로라이드 등) 주사 치료로 사춘기 진행을 억제합니다. 치료를 통해 성장판 조기 폐쇄를 막아 최종 키를 보호하고 심리사회적 문제를 예방할 수 있으므로, 조기 진단과 치료 시작이 중요합니다.', 1570, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '성홍열', '성홍열', 'DIET_LIFE', '성홍열 예방에 특별히 효과가 입증된 특정 식품은 없으나, 균형 잡힌 영양 섭취로 면역력을 유지하는 것이 중요합니다. 비타민 C가 풍부한 채소·과일, 단백질(육류, 생선, 두류), 아연이 풍부한 식품(견과류, 해산물) 섭취가 일반적인 면역 증진에 도움이 됩니다. 가장 효과적인 예방법은 손 씻기, 기침 예절 준수, 환자와의 접촉 최소화이며, 증상이 나타나면 즉시 소아청소년과 전문의 진료를 받으시기 바랍니다.', 1571, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '성홍열', '성홍열', 'MEDICATION', '성홍열의 원인균인 A군 베타용혈성 연쇄구균 치료에는 페니실린 V를 10일간 경구 투여하는 것이 표준 요법입니다. 페니실린 치료 시작 후 24~48시간 이내에 전염력이 소실되고 발열 등 증상이 호전되기 시작하지만, 합병증(류마티스열, 사구체신염) 예방을 위해 반드시 10일 전 과정을 완료해야 합니다. 페니실린 알레르기가 있는 경우 아목시실린, 세팔로스포린, 아지스로마이신 등 대체 항생제를 사용하며, 처방은 전문의에게 받으시기 바랍니다.', 1572, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '성홍열', '성홍열', 'PREVENTION', '현재 성홍열에 대한 공인된 예방 백신은 존재하지 않습니다. 예방을 위해서는 철저한 손 씻기, 기침·재채기 시 입과 코 가리기, 감염자와의 접촉 및 식기 공유 금지, 환기가 잘 되는 환경 유지 등 개인위생 수칙 준수가 중요합니다. 성홍열 환자와 밀접 접촉 후 인후통, 발열, 발진 등 증상이 나타나면 즉시 소아청소년과 또는 내과 전문의를 방문하여 진단과 항생제 치료를 받으시기 바랍니다.', 1573, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '성홍열', '성홍열', 'CAUSE', '성홍열은 A군 베타용혈성 연쇄구균(Streptococcus pyogenes)이 생성하는 발열독소(pyrogenic exotoxin)에 의해 발생합니다. 이 독소가 혀의 유두(papillae)를 자극하여 염증을 일으키고 혀가 오돌토돌하고 붉게 변하는 ''딸기혀(strawberry tongue)'' 소견이 나타나며, 인두·편도에 심한 염증을 유발하여 심한 목 통증이 동반됩니다. 비말 또는 직접 접촉으로 전파되므로, 의심 증상 시 즉시 소아청소년과 전문의의 진료와 항생제 치료를 받으시기 바랍니다.', 1574, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '성홍열', '성홍열', 'DEFINITION', '성홍열은 A군 베타용혈성 연쇄구균 감염에 의해 발생하는 급성 감염성 질환으로, 발열, 인후통, 전신 발진(사포 같은 촉감의 붉은 발진), 딸기혀가 특징적입니다. 주로 5~15세 학령기 아동에게 흔하며, 겨울과 봄에 유행하는 경향이 있습니다. 적절한 항생제 치료로 대부분 완치되나, 치료하지 않으면 류마티스열, 사구체신염 등 심각한 합병증이 생길 수 있으므로 전문의 진료가 중요합니다.', 1575, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '성홍열', '성홍열', 'SYMPTOM', '성홍열에서 목 통증은 A군 연쇄구균이 인두 및 편도 점막을 직접 침범하여 화농성 염증을 일으키기 때문에 발생합니다. 동시에 세균이 분비하는 발열독소가 전신에 작용하여 발진, 발열, 딸기혀 등의 전신 증상을 유발하므로, 인후통과 발진이 함께 나타나는 것이 성홍열의 특징적인 임상 양상입니다. 이러한 증상이 동시에 발생하면 성홍열을 강력히 의심하고 소아청소년과 전문의의 진료를 받으시기 바랍니다.', 1576, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '성홍열', '성홍열', 'DIAGNOSIS', '성홍열 진단의 핵심 검사는 인두 도말 신속 항원 검사(Rapid Strep Test)로, 결과를 수분 내에 확인할 수 있습니다. 신속 검사 음성이지만 임상적으로 의심되는 경우 인두 배양 검사(48~72시간 소요)를 추가로 시행합니다. 혈액 검사(CBC, CRP, ASO 항체가)는 감염 정도 및 합병증 감별에 활용되며, 모든 검사와 치료는 소아청소년과 또는 내과 전문의의 판단하에 이루어집니다.', 1577, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '성홍열', '성홍열', 'TREATMENT', '성홍열의 표준 치료는 경구 항생제(페니실린, 아목시실린 등) 10일 투여이며, 페니실린 알레르기 시 세팔로스포린이나 마크로라이드 계열로 대체합니다. 보조적 치료로는 충분한 수분 섭취, 해열진통제(아세트아미노펜, 이부프로펜)를 통한 발열 및 통증 조절, 인후 불편감 완화를 위한 소금물 가글 등을 시행할 수 있습니다. 그러나 항생제 치료 없이는 합병증 예방이 어려우므로 반드시 전문의 처방에 따른 항생제 치료를 완료해야 합니다.', 1578, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신경모세포종', '신경모세포종', 'CAUSE', '신경모세포종은 교감신경계의 미분화 신경능선세포(neural crest cell)에서 발생하는 악성 종양으로, 정확한 원인은 아직 완전히 밝혀지지 않았습니다. MYCN 유전자 증폭, ALK 유전자 변이, PHOX2B 유전자 변이 등 유전적 이상이 일부 환자에서 확인되며, 특히 가족성 신경모세포종과 관련이 깊습니다. 대부분은 산발적으로 발생하며, 특정 환경적 요인이 기여할 수 있으나 소아종양전문의의 정확한 평가가 필요합니다.', 1579, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신경모세포종', '신경모세포종', 'DEFINITION', '신경모세포종은 대부분 5세 미만의 영유아 및 소아에서 발생하며, 전체 환자의 약 90%가 5세 이전에 진단됩니다. 성인에서도 드물게 발생할 수 있으나 매우 희귀하며, 성인 발생 시 임상 양상이 소아와 다소 다를 수 있습니다. 신생아기에 발견되는 경우도 있으며 자연 퇴행이 일어나기도 하므로, 연령과 임상 상황에 따른 소아혈액종양과 전문의의 개별적 평가와 치료 계획이 필요합니다.', 1580, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신경모세포종', '신경모세포종', 'SYMPTOM', '신경모세포종의 주요 증상인 복부 종괴, 발열, 체중 감소 외에도 종양 위치에 따라 다양한 증상이 나타날 수 있습니다. 척추 주변 침범 시 하지 마비, 배뇨·배변 장애가 생길 수 있고, 안와 전이 시 눈 주위 멍(너구리 눈)과 안구 돌출이 나타납니다. 또한 고혈압, 설사, 발한 등 카테콜아민 과분비 증상, 뼈 전이로 인한 통증, 신경학적 이상도 동반될 수 있으므로 소아혈액종양과 전문의의 진료가 중요합니다.', 1581, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신경모세포종', '신경모세포종', 'DIAGNOSIS', '신경모세포종처럼 희귀하고 치료가 복잡한 소아 악성 종양의 경우, 소아종양 전문 센터에서 이중 확인(second opinion)을 받는 것이 권장됩니다. 진단 정확도 재확인, 병기 및 위험군 분류 재평가, 최신 치료 프로토콜 적용 여부 확인, 임상 시험 참여 가능성 검토 등의 이유로 다른 기관의 의견이 도움이 됩니다. 정확한 진단과 최적의 치료 계획 수립을 위해 소아혈액종양과 전문의와 충분히 상담하시기 바랍니다.', 1582, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신경모세포종', '신경모세포종', 'TREATMENT', '신경모세포종은 위험군 분류에 따라 치료 방법이 달라지며, 수술 외에도 항암화학요법(화학치료), 방사선 치료, 고용량 항암치료 후 자가조혈모세포이식, 면역치료(디누툭시맙 등), 레티노이드 분화 치료 등이 시행됩니다. 저위험군은 수술만으로 완치될 수 있으나, 고위험군은 다양한 치료를 병합합니다. 최적의 치료 계획은 소아혈액종양과 전문의가 종양의 위치, 병기, 생물학적 특성을 종합 평가하여 결정하므로 전문의 상담이 필수적입니다.', 1583, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 경련', '신생아경련', 'CAUSE', '아래쪽으로 눈이 고정(편위)되는 것은 신생아 경련의 한 증상일 수 있으며, 경련의 원인이 되기보다는 경련 발생 시 나타나는 신경학적 징후입니다. 신생아 경련의 실제 원인으로는 저산소성 허혈성 뇌병증, 저혈당, 저칼슘혈증, 뇌막염, 뇌 기형, 대사 이상 등이 있습니다. 신생아에게 눈 고정 등 이상한 움직임이 관찰되면 즉시 소아청소년과 또는 소아신경과 전문의의 응급 평가를 받으시기 바랍니다.', 1584, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 경련', '신생아경련', 'DEFINITION', '신생아 경련은 대뇌 피질의 신경세포들이 비정상적으로 동기화되어 과도하게 방전될 때 발생하는 신경학적 응급 상태입니다. 팔다리가 떨리거나(간대성 경련), 몸이 뻣뻣해지거나(강직성 경련), 눈이 한쪽으로 쏠리거나, 무호흡, 빠는 행동 등 다양한 형태로 나타납니다. 신생아 경련은 뇌손상의 결과이거나 원인이 될 수 있으므로, 이러한 증상이 나타나면 즉시 신생아 중환자실이 있는 병원 응급실을 방문해야 합니다.', 1585, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 경련', '신생아경련', 'SYMPTOM', '신생아 경련의 증상에는 눈이 위로 돌아가거나 한쪽으로 편위되는 현상, 무호흡 또는 불규칙한 호흡이 포함될 수 있습니다. 몸 움직임이 일시적으로 둔해지는 긴장 저하(hypotonia)도 경련의 한 형태(무긴장성 경련)로 나타날 수 있습니다. 신생아 경련은 증상이 성인과 달리 매우 미묘하고 다양하므로, 의심스러운 행동이 관찰되면 즉시 소아신경과 전문의의 평가를 받는 것이 중요합니다.', 1586, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 경련', '신생아경련', 'DIAGNOSIS', '열이 없는 신생아 경련은 저산소성 허혈성 뇌병증, 저혈당증, 저칼슘혈증, 저마그네슘혈증, 저나트륨혈증 등 전해질·대사 이상, 뇌 기형, 선천성 대사 이상, 뇌출혈, 비타민 B6 결핍증 등 다양한 원인으로 발생할 수 있습니다. 열이 없어도 경련이 발생하면 즉각적인 원인 규명과 치료가 필요하며, 이는 뇌손상과 연관될 수 있는 응급 상황입니다. 즉시 신생아 집중치료가 가능한 병원의 소아신경과 전문의를 방문하시기 바랍니다.', 1587, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 경련', '신생아경련', 'TREATMENT', '신생아 경련의 치료는 원인 질환 교정(저혈당, 전해질 이상 교정 등)이 가장 중요하며, 항경련제로는 페노바르비탈이 1차 약제로 사용되고 레비티라세탐, 포스페니토인 등이 추가될 수 있습니다. 경련의 원인과 신경학적 손상 정도에 따라 예후가 크게 다르며, 저혈당이나 전해질 이상 등 교정 가능한 원인에 의한 경련은 치료 후 호전될 수 있습니다. 장기적 예후와 발달 경과에 대해서는 소아신경과 전문의와 지속적인 추적 관찰이 필요합니다.', 1588, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 괴사성 장염', '신생아괴사성장염', 'CAUSE', '신생아 괴사성 장염(NEC)의 발생에는 환경적 요인이 더 크게 작용하는 것으로 알려져 있습니다. 주요 위험 요인으로는 미숙아(특히 32주 미만), 저출생체중, 장관 허혈, 세균 또는 바이러스 감염, 분유 수유(모유 대비 위험 증가), 장내 세균 불균형 등이 있습니다. 유전적 소인도 일부 기여할 수 있으나 현재까지는 환경·임상적 요인이 주된 원인으로 받아들여지고 있으므로, 미숙아의 경우 신생아 중환자 전문의와 긴밀히 협력하는 것이 중요합니다.', 1589, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 괴사성 장염', '신생아괴사성장염', 'DEFINITION', '제시된 증상(밤에 울음, 40도 고열, 물설사)은 신생아 괴사성 장염보다는 급성 장염이나 다른 감염성 질환에 더 가까운 양상입니다. 신생아 괴사성 장염은 주로 미숙아에서 발생하며, 복부 팽만, 혈변, 수유 불내성, 복부 압통 등이 특징적입니다. 고열과 설사가 지속되는 경우 즉시 소아청소년과 전문의의 진료를 받아 정확한 원인 감별 및 치료를 받으시기 바랍니다.', 1590, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 괴사성 장염', '신생아괴사성장염', 'SYMPTOM', '신생아 괴사성 장염의 복부 팽만과 가스 외에 혈변 또는 혈액 혼합변, 수유 불내성(먹지 않으려 함, 위 잔유량 증가), 구토, 무기력, 체온 불안정(저체온 또는 발열), 복벽 발적·부종, 쇼크 징후 등이 동반될 수 있습니다. 복부 X선에서 장 괴사의 특징적 소견인 장관 내 공기증(pneumatosis intestinalis)이 나타나기도 합니다. 이러한 증상이 미숙아에서 나타나면 신속하게 신생아 중환자실에서 전문 치료를 받아야 합니다.', 1591, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 괴사성 장염', '신생아괴사성장염', 'DIAGNOSIS', '수유 거부, 복통, 복부 팽만감이 있는 신생아, 특히 미숙아에서는 신생아 괴사성 장염을 의심할 수 있으며, 신생아 전문의의 진료가 필요합니다. 진단을 위해 복부 X선(장관 내 공기증, 문맥 내 가스 확인), 복부 초음파, 혈액 검사(CBC, CRP, 혈액 배양) 등이 시행됩니다. 조기 발견과 신속한 치료가 예후에 중요하므로, 해당 증상이 나타나면 신생아 중환자실이 있는 병원의 신생아과 전문의를 즉시 방문하시기 바랍니다.', 1592, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 괴사성 장염', '신생아괴사성장염', 'TREATMENT', '신생아 괴사성 장염의 치료는 정맥영양법(경장 수유 중단 후 완전 정맥 영양 공급)이 중요한 축이지만 유일한 치료법은 아닙니다. 광범위 항생제 투여, 비위관 감압, 활력징후 모니터링, 수혈 등의 내과적 치료가 동반되며, 장 천공이나 복막염이 발생한 경우 외과적 수술(장 절제, 장루 형성술 등)이 필요합니다. 치료 방법은 중증도에 따라 결정되므로 신생아 집중치료 전문의와 소아외과 전문의의 협진이 필수적입니다.', 1593, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 호흡곤란증후군', '신생아호흡곤란증후군', 'PREVENTION', '신생아 호흡곤란증후군 예방을 위한 청색증 예방에는 분만 전 산모에게 코르티코스테로이드(베타메타손, 덱사메타손) 투여로 태아 폐 성숙을 촉진하는 것이 가장 효과적입니다. 출생 후에는 즉각적인 호흡 보조(지속 기도양압, CPAP 또는 기계 환기), 폐 표면활성제(서팩턴트) 투여로 저산소증과 청색증을 예방합니다. 조산이 예상되는 경우 주산기 전문 의료진이 있는 신생아 집중치료실 보유 병원에서 분만하는 것이 중요합니다.', 1594, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 호흡곤란증후군', '신생아호흡곤란증후군', 'CAUSE', '신생아 호흡곤란증후군(RDS)은 폐 표면활성제(surfactant) 부족으로 발생하며, 조산아에서 가장 흔한 원인입니다. 34주 미만의 미숙아에서 폐포를 열린 상태로 유지하는 표면활성제가 충분히 생성되지 않아 폐포 허탈, 저산소증, 호흡 부전이 발생합니다. 조기 진통으로 태어난 조산아일수록 RDS 발생 위험이 높으며, 임신 주수가 낮을수록 위험도가 증가하므로 산전 관리와 전문 의료진의 즉각적인 개입이 중요합니다.', 1595, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 호흡곤란증후군', '신생아호흡곤란증후군', 'DEFINITION', '신생아 호흡곤란증후군(RDS)은 주로 미숙아에서 폐 표면활성제(surfactant) 결핍으로 인해 폐포가 허탈되어 호흡 부전이 발생하는 질환입니다. 빠른 호흡(빈호흡), 흡기 시 가슴 함몰, 코 벌렁거림, 신음 호흡, 청색증이 주요 증상이며, 출생 직후 또는 수 시간 내에 나타납니다. 치료는 폐 표면활성제 투여, 산소 공급, 기계 환기(CPAP 또는 인공호흡기)이며, 신생아 집중치료실에서 전문 의료진의 치료가 필수적입니다.', 1596, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 호흡곤란증후군', '신생아호흡곤란증후군', 'SYMPTOM', '신생아 호흡곤란증후군에서 무호흡(호흡 정지)이 발생할 수 있으며, 이는 특히 미숙아에서 중추성 무호흡증과 함께 나타날 수 있습니다. RDS 자체보다는 미숙아의 호흡 조절 미숙으로 인한 무호흡이 동반되는 경우가 많으며, 지속적인 저산소증으로 인해 호흡 부전이 악화될 수 있습니다. 이러한 응급 상황에 대비하여 신생아 중환자실에서 지속적인 모니터링과 즉각적인 호흡 보조 치료가 이루어져야 합니다.', 1597, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 호흡곤란증후군', '신생아호흡곤란증후군', 'DIAGNOSIS', '신생아 호흡곤란증후군 청진 시 호흡음이 감소하거나 들어가는 공기 소리가 줄어드는 폐포 허탈 소견이 확인됩니다. 신음 호흡(grunting)은 성문을 부분적으로 닫아 기도 내압을 유지하려는 보상 반응으로 나타나는 특징적 소견이며, 수포음(crackles)이 들릴 수 있습니다. 흉부 X선에서 미만성 간유리음영(ground-glass opacity), 공기 기관지조영상(air bronchogram)이 특징적이며, 혈액 가스 분석에서 저산소증과 이산화탄소 증가가 확인됩니다.', 1598, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 호흡곤란증후군', '신생아호흡곤란증후군', 'TREATMENT', '신생아 호흡곤란증후군의 치료에서 방사선 치료는 사용되지 않습니다. 핵심 치료는 기관 내 투여를 통한 폐 표면활성제(서팩턴트) 보충 요법이며, 이와 함께 CPAP(지속적 기도 양압) 또는 기계 환기를 통한 호흡 보조, 충분한 산소 공급, 체온 유지, 수액·영양 관리가 이루어집니다. 산전 코르티코스테로이드 투여로 폐 성숙을 촉진하는 예방적 치료도 중요하며, 모든 치료는 신생아 집중치료 전문의의 판단하에 시행됩니다.', 1599, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 황달', '신생아황달', 'CAUSE', '모유 수유와 신생아 황달의 관계에서, 모유를 중단하면 황달이 호전되는 것은 모유 황달(breast milk jaundice) 때문입니다. 모유 내 특정 물질이 장에서 빌리루빈 재흡수를 촉진하여 혈중 빌리루빈이 증가하는 것이 원인으로, 이는 모유 수유 자체가 황달을 악화시키는 기전입니다. 모유 황달은 일반적으로 무해하며 대부분 자연 회복되므로, 모유 중단 여부는 소아청소년과 전문의와 상담하여 결정하시기 바랍니다.', 1600, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 황달', '신생아황달', 'DEFINITION', '신생아 황달은 혈중 빌리루빈 수치가 상승하여 피부와 공막(눈 흰자)이 노랗게 변하는 질환으로, 얼굴과 눈 흰자부터 시작하여 빌리루빈 수치가 높아질수록 몸통, 팔다리 순으로 황달이 진행됩니다. 생리적 황달은 생후 2~4일에 시작하여 1~2주 내 자연 소실되지만, 황달이 24시간 이내 발생하거나 2주 이상 지속되면 병적 황달을 의심해야 합니다. 얼굴이 노랗게 변하는 증상이 관찰되면 소아청소년과 전문의의 진료를 받으시기 바랍니다.', 1601, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 황달', '신생아황달', 'SYMPTOM', '신생아 황달에서 얼굴이 노랗게 변하는 것은 빌리루빈이 피부에 침착되어 나타나는 가장 초기의 특징적인 증상입니다. 황달이 심해지면 무기력, 수유 부진, 고음의 울음 등이 동반될 수 있으며, 빌리루빈이 과도하게 상승하면 핵황달(kernicterus)로 진행되어 뇌 손상을 일으킬 수 있습니다. 신생아의 얼굴이 노랗고 울음이 변하는 등의 증상이 나타나면 즉시 소아청소년과 전문의를 방문하여 빌리루빈 수치를 확인하시기 바랍니다.', 1602, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 황달', '신생아황달', 'DIAGNOSIS', '신생아 황달이 의심될 때는 소아청소년과(소아과) 전문의를 방문하는 것이 적절합니다. 산부인과는 분만 직후 입원 기간 중 황달 여부를 모니터링하지만, 퇴원 후 황달 증상이 나타나거나 심해지면 소아청소년과 전문의에게 진료받아야 합니다. 빌리루빈 수치 측정과 필요 시 광선치료 또는 교환수혈 등의 치료를 받게 되므로, 신생아 황달 증상이 있으면 지체 없이 소아청소년과를 방문하시기 바랍니다.', 1603, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '신생아 황달', '신생아황달', 'TREATMENT', '신생아 황달은 진단 후 빌리루빈 수치와 임상 증상에 따라 치료 여부와 시기를 결정하며, 치료가 필요한 경우 즉시 시작하는 것이 중요합니다. 빌리루빈이 치료 기준 이상이면 광선치료(빛 치료)를 즉시 시작하고, 매우 높은 경우 교환수혈을 시행합니다. 황달이 심하지 않고 생리적 황달로 판단되면 경과 관찰이 가능하지만, 이는 반드시 소아청소년과 전문의가 결정해야 하며 임의로 지켜보는 것은 위험할 수 있습니다.', 1604, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '심방 중격 결손', '심방중격결손', 'MEDICATION', '심방 중격 결손 치료에 사용되는 약물에는 이뇨제(푸로세마이드 등), 디곡신, ACE 억제제 등이 있으며, 이는 심부전 증상 조절에 주로 사용됩니다. 이뇨제는 전해질 불균형(저칼륨혈증 등)을, 디곡신은 부정맥과 구역을, ACE 억제제는 저혈압을 부작용으로 일으킬 수 있습니다. 이러한 약물들은 근본적 치료가 아닌 보조적 역할이며, 약물 선택과 용량은 소아심장과 전문의가 개별 환자의 상태에 따라 결정합니다.', 1605, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '심방 중격 결손', '심방중격결손', 'CAUSE', '심방 중격 결손(ASD)은 선천성 심장 질환으로, 태아 심장 발생 과정 중 심방 중격이 완전히 형성되지 않아 발생합니다. 다른 선천성 심장 질환으로는 심실 중격 결손(VSD), 방실 중격 결손(AVSD), 동맥관 개존증(PDA), 팔로 4징증(TOF), 대동맥 축착, 폐동맥 협착 등이 있습니다. 선천성 심장 질환은 산전 초음파나 출생 후 청진 이상으로 발견되는 경우가 많으며, 소아심장과 전문의의 정확한 진단과 추적 관찰이 필요합니다.', 1606, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '심방 중격 결손', '심방중격결손', 'DEFINITION', '심방 중격 결손이 치료되지 않고 장기간 방치되면 폐혈류 증가로 폐동맥 고혈압이 발생하고, 이것이 심해지면 혈액의 방향이 역전되어 우→좌 단락이 생기는 아이젠멩거 증후군으로 진행할 수 있습니다. 아이젠멩거 증후군이 발생하면 청색증, 운동 불내성, 적혈구 증가증 등이 나타나며, 이 단계에서는 수술적 교정이 불가능해집니다. 따라서 심방 중격 결손은 폐동맥 고혈압이 비가역적으로 진행하기 전에 소아심장과 전문의의 판단에 따라 적시에 치료받는 것이 매우 중요합니다.', 1607, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '심방 중격 결손', '심방중격결손', 'SYMPTOM', '심방 중격 결손은 소아기에 증상이 없다가 10대 이후나 성인기에 증상이 나타나는 경우가 많습니다. 운동 시 호흡 곤란, 피로감, 두근거림(부정맥), 반복적인 호흡기 감염 등이 나타날 수 있으며, 성인기에는 심방세동·심방조동 등 부정맥 발생 위험이 높아집니다. 치료하지 않으면 30~40대 이후 폐동맥 고혈압, 심부전, 역설적 색전증(뇌졸중) 등 심각한 합병증이 생길 수 있으므로 소아심장과 또는 성인 선천성 심장병 전문의의 진료가 필요합니다.', 1608, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '심방 중격 결손', '심방중격결손', 'DIAGNOSIS', '심방 중격 결손 진단에 가장 흔히 사용되는 검사는 심장 초음파(심초음파)입니다. 경흉부 심초음파로 결손의 크기, 위치, 혈류 방향, 우심 비대, 폐동맥 압력 등을 평가하며, 필요 시 경식도 심초음파로 더 정확히 확인합니다. 심도자술은 폐혈관 저항 측정이나 카테터 시술(폐쇄 장치 삽입)이 필요한 경우에 시행되며, 일차적인 진단 도구는 심초음파입니다.', 1609, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '심방 중격 결손', '심방중격결손', 'TREATMENT', '심방 중격 결손의 수술적 치료는 결손의 크기가 크거나(직경 >8~10mm), 우심 비대, 폐혈류 증가 소견이 있을 때 적응증이 됩니다. 치료 방법에는 개흉 수술을 통한 직접 봉합 또는 패치 교정과 심도자술을 이용한 카테터 폐쇄술(폐쇄 장치 삽입)이 있으며, 결손의 유형과 크기에 따라 선택됩니다. 이차공형(ostium secundum type) ASD는 카테터 폐쇄술이 가능한 경우가 많으며, 정확한 치료 방법과 시기는 소아심장과 전문의가 결정합니다.', 1610, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '아스퍼거 증후군', '아스퍼거증후군', 'DIET_LIFE', '아스퍼거 증후군 환자에서 영양 부족으로 증상이 악화되는 경우, 균형 잡힌 식사를 통한 오메가-3 지방산(등 푸른 생선, 견과류), 마그네슘(채소, 견과류), 비타민 B6, 아연(해산물, 육류) 등의 충분한 섭취가 권장됩니다. 편식이 심한 아스퍼거 증후군 환자는 영양사와 상담하여 개인에 맞는 식단을 구성하는 것이 도움이 됩니다. 그러나 특정 식품이 증상을 직접 치료한다는 근거는 제한적이므로, 소아정신건강의학과 전문의의 종합적인 치료 계획 안에서 식이를 관리하시기 바랍니다.', 1611, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '아스퍼거 증후군', '아스퍼거증후군', 'MEDICATION', '아스퍼거 증후군 자체에 대한 특이적 약물 치료는 없으나, 동반 증상(ADHD, 불안장애, 우울증, 공격성, 강박증)이 심하여 일상생활에 지장을 줄 때 약물 치료를 고려합니다. ADHD 동반 시 메틸페니데이트 등 자극제, 불안·우울 시 SSRI(선택적 세로토닌 재흡수 억제제), 공격성·자해 행동 시 리스페리돈 등 비정형 항정신병약물이 사용될 수 있습니다. 약물 치료는 행동치료, 사회기술훈련 등과 병행하며, 소아정신건강의학과 전문의의 처방과 모니터링이 필수적입니다.', 1612, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '아스퍼거 증후군', '아스퍼거증후군', 'CAUSE', '아스퍼거 증후군은 후천적 원인보다 유전적·신경생물학적 원인이 주된 발병 기전으로 알려져 있습니다. 일란성 쌍둥이 연구에서 높은 일치율이 보고되며, 여러 유전자의 복합적 영향과 신경 발달 과정의 이상이 관여합니다. 환경적 요인(태내 감염, 조산, 고령 부모 등)도 일부 기여할 수 있으나, 양육 방식이나 사회적 환경은 직접적인 원인이 아니므로 부모의 양육 책임이 아님을 이해하는 것이 중요합니다.', 1613, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '아스퍼거 증후군', '아스퍼거증후군', 'DEFINITION', '아스퍼거 증후군은 사회적 상호작용과 비언어적 의사소통에 어려움이 있으나 언어 발달과 지능은 정상 수준인 자폐 스펙트럼 장애의 한 유형으로, 소아정신건강의학과에서 표준화된 발달 평가(ADOS, ADI-R 등)로 진단됩니다. 치료는 사회기술훈련, 인지행동치료, 언어치료, 작업치료, 교육적 지원이 핵심이며, 약물은 동반 증상에 따라 사용됩니다. 언어 능력 회복 기간은 개인차가 크므로 소아정신건강의학과 전문의의 개별 평가와 지속적 치료 계획이 필요합니다.', 1614, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '아스퍼거 증후군', '아스퍼거증후군', 'SYMPTOM', '아스퍼거 증후군에서 언어 발달 지연 외에 사회적 상호작용 어려움(눈 맞춤 부족, 또래 관계 형성 곤란), 특정 주제에 대한 강한 집착과 반복적 행동, 일상 루틴 변화에 대한 강한 저항이 주요 증상입니다. 감각 과민 또는 감각 저민(소리, 빛, 촉감에 예민하거나 무감각), 운동 협응 어려움, 공감 능력 제한도 나타날 수 있습니다. 이러한 증상이 의심될 경우 소아정신건강의학과 전문의의 종합적인 평가를 받으시기 바랍니다.', 1615, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '아스퍼거 증후군', '아스퍼거증후군', 'DIAGNOSIS', '아스퍼거 증후군은 아동기에 주로 진단되지만, 증상이 경미하거나 높은 지능으로 보상된 경우 성인기에 처음 진단되는 사례도 적지 않습니다. 성인 진단은 소아청소년정신건강의학과 또는 정신건강의학과에서 가능하며, 성인용 자폐 스펙트럼 평가 도구(AQ, RAADS 등)를 활용합니다. 조기 진단일수록 조기 개입이 가능하여 예후가 좋지만, 성인 진단도 자기 이해와 적절한 지원 연결에 도움이 되므로 의심되는 경우 전문의 상담을 권장합니다.', 1616, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '아스퍼거 증후군', '아스퍼거증후군', 'TREATMENT', '아스퍼거 증후군 치료에는 소아정신건강의학과 의사(약물 및 전반적 치료 조율), 심리치료사(인지행동치료, 사회기술훈련), 언어치료사(의사소통 훈련), 작업치료사(감각 통합, 일상생활 기술)가 팀을 이루어 협력합니다. 약물 치료 외에 사회기술훈련 그룹, 인지행동치료, 부모 훈련 프로그램, 특수교육 지원 등이 핵심적인 대안 치료 방법입니다. 개인에게 맞는 통합적 치료 계획은 소아정신건강의학과 전문의와 상담하여 수립하시기 바랍니다.', 1617, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '영아 돌연사 증후군', '영아돌연사증후군', 'PREVENTION', '완전 모유 수유가 영아 돌연사 증후군(SIDS) 예방에 효과적인 이유는 모유 내 면역 물질(IgA, 사이토카인 등)이 호흡기·소화기 감염을 예방하고, 수유 중 각성 반응을 높이며, 모유 수유 자세가 산소 포화도 유지에 유리하기 때문입니다. 연구에 따르면 완전 모유 수유는 혼합 수유보다 SIDS 위험을 더 크게 감소시키는 것으로 보고되어 있는데, 이는 모유 수유 지속 기간과 빈도가 보호 효과에 영향을 주기 때문입니다. 대한소아과학회도 최소 6개월 완전 모유 수유를 권장합니다.', 1618, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '영아 돌연사 증후군', '영아돌연사증후군', 'CAUSE', '영아 돌연사 증후군(SIDS)은 생후 1개월 미만의 신생아보다 생후 1~6개월 영아에서 위험도가 가장 높으며, 특히 생후 2~4개월이 최고 위험 시기입니다. 생후 12개월 이후에는 SIDS 위험이 급격히 감소합니다. 이 외에도 엎드려 재우기, 흡연 노출, 과도한 침구 사용, 미숙아·저출생체중, 남아, 사회경제적 취약 계층 등이 위험 요인이므로 안전한 수면 환경 조성이 중요합니다.', 1619, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '영아 돌연사 증후군', '영아돌연사증후군', 'DEFINITION', '영아 돌연사 증후군(SIDS)은 생후 1년 이내의 영아가 수면 중 명확한 원인 없이 갑자기 사망하는 질환으로, 부검, 사망 현장 조사, 병력 검토 후에도 원인을 설명할 수 없는 경우에 진단됩니다. 주요 위험 요인으로는 엎드려 재우기(복와위 수면), 부모 흡연, 지나치게 푹신한 침구, 과열, 미숙아, 생후 2~4개월 연령 등이 있습니다. 예방을 위해 반드시 등을 대고(앙와위) 재우고 딱딱한 침구를 사용하는 안전 수면 수칙을 준수해야 합니다.', 1620, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '영아 돌연사 증후군', '영아돌연사증후군', 'TREATMENT', '영아 돌연사 증후군 예방을 위해 항상 아기를 등을 대고(앙와위) 재워야 하며, 푹신한 이불·베개·범퍼가드는 질식 위험이 있으므로 제거해야 합니다. 수면 환경은 과열되지 않게 유지하고(실내 온도 18~20도), 부모와 같은 침대는 피하되 같은 방에서 재우는 것이 안전합니다. 부모나 보호자의 흡연은 영아와 완전히 분리해야 하며, 안전 수면 수칙에 대한 자세한 안내는 소아청소년과 전문의와 상담하시기 바랍니다.', 1621, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '영아 비대성 유문협착증', '영아비대성유문협착증', 'MEDICATION', '영아 비대성 유문협착증의 치료는 수술(라모스테dt-Weber 유문근절개술)이 표준이며, 약물 치료는 수술 전 일시적 보조 요법으로만 사용됩니다. 아트로핀(항콜린제)을 정맥 또는 경구 투여하여 유문 경련을 완화하는 시도가 있으나 재발률이 높고 효과가 제한적이어서 수술의 대안으로는 적절하지 않습니다. 진단이 확인되면 수액으로 전해질 불균형을 교정한 후 가능한 한 빨리 수술을 시행하는 것이 원칙이므로, 소아외과 전문의와 상담하시기 바랍니다.', 1622, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '영아 비대성 유문협착증', '영아비대성유문협착증', 'CAUSE', '영아 비대성 유문협착증의 정확한 원인은 아직 완전히 밝혀지지 않았으나, 유문 근육의 비대와 과형성으로 유문관이 좁아져 위 내용물이 통과하지 못하는 것이 병태생리입니다. 분유 섭취 자체가 원인은 아니며, 유전적 소인, 출생 후 에리스로마이신 또는 아지스로마이신 복용력, 남아, 첫째 아이, 출생 시 체중 등이 위험 요인으로 알려져 있습니다. 유문 근육의 신경 이상, 국소 성장인자 불균형 등도 원인으로 연구되고 있으며, 소아외과 전문의의 정확한 진단이 필요합니다.', 1623, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '영아 비대성 유문협착증', '영아비대성유문협착증', 'DEFINITION', '영아 비대성 유문협착증은 생후 2~8주의 영아에서 유문 근육의 비대로 위 출구가 막혀 수유 후 분사성(projectile) 구토가 반복적으로 발생하는 질환입니다. 구토는 담즙이 섞이지 않은 소화되지 않은 우유 형태이며, 구토 후에도 배고파하여 수유를 원하는 것이 특징적입니다. 체중 증가 불량, 탈수, 전해질 불균형(저클로르혈증성 대사성 알칼리증)이 초래될 수 있으므로 소아청소년과 또는 소아외과 전문의의 진료를 받으시기 바랍니다.', 1624, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '영아 비대성 유문협착증', '영아비대성유문협착증', 'SYMPTOM', '영아 비대성 유문협착증의 특징적인 증상은 수유를 잘 하고 먹고 싶어 하면서도 수유 직후 분사성 구토를 반복하는 것입니다. 구토와 함께 복부 우상복부에 올리브 모양의 종괴가 만져지거나, 수유 후 위가 연동 운동하는 파형이 관찰되기도 합니다. 반복적인 구토로 탈수, 체중 감소, 황달(간접 빌리루빈 상승)이 동반될 수 있으므로, 이러한 증상이 나타나면 소아청소년과 또는 소아외과 전문의의 진료를 받으시기 바랍니다.', 1625, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '영아 비대성 유문협착증', '영아비대성유문협착증', 'DIAGNOSIS', '눈 흰자가 노랗고(황달) 우유 수유 후 반복 구토가 있는 영아에서 영아 비대성 유문협착증 진단을 위해 복부 초음파 검사가 우선적으로 시행됩니다. 초음파에서 유문 근육 두께 4mm 이상, 유문관 길이 16mm 이상이면 진단적 소견입니다. 황달 여부 확인을 위해 혈청 빌리루빈 검사, 전해질·혈당 등 혈액 검사도 함께 시행되며, 소아청소년과 또는 소아외과 전문의를 방문하시기 바랍니다.', 1626, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '영아 비대성 유문협착증', '영아비대성유문협착증', 'TREATMENT', '영아 비대성 유문협착증의 표준 치료는 라모스테dt-Weber 유문근절개술(laparoscopic 또는 개복)로, 비대해진 유문 근육을 절개하여 유문관을 넓혀주는 수술입니다. 수술 외 약물 치료(아트로핀)가 시도될 수 있으나 재발률이 높고 효과가 제한적이어서 수술적 치료가 압도적으로 선호됩니다. 수술 전 수액 치료로 탈수와 전해질 불균형을 먼저 교정해야 하며, 수술 후 예후는 매우 좋으므로 소아외과 전문의와 상담하시기 바랍니다.', 1627, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '유당분해효소결핍증', '유당분해효소결핍증', 'DIET_LIFE', '유당분해효소결핍증 환자는 우유와 유제품 섭취 자체가 문제이므로, 칼슘이 풍부한 유제품을 우유와 함께 섭취해도 특별한 추가 부작용은 없습니다. 단, 유당(락토스)이 포함된 모든 유제품(우유, 치즈, 아이스크림 등) 섭취 시 복부 팽만, 복통, 설사, 가스 등의 불내성 증상이 나타날 수 있습니다. 칼슘 보충을 위해서는 락토프리 우유, 두유, 칼슘 강화 식품, 뼈째 먹는 생선, 두부, 녹색 채소 등을 대안으로 섭취하는 것이 권장됩니다.', 1628, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '유당분해효소결핍증', '유당분해효소결핍증', 'CAUSE', '유당분해효소결핍증의 원인에서 어느 것이 더 중요한지는 개인과 유형에 따라 다릅니다. 가장 흔한 원인 유형인 성인형(원발성) 유당분해효소결핍증은 유전적으로 유당분해효소 유전자(LCT)의 활성이 성장 후 감소하도록 결정되며, 아시아인과 아프리카인에서 높은 유병률을 보입니다. 후천성(속발성)은 장 점막 손상(장염, 크론병 등) 후 일시적으로 발생하므로, 원인 감별을 위해 소화기내과 전문의의 진단을 받는 것이 중요합니다.', 1629, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '유당분해효소결핍증', '유당분해효소결핍증', 'REHAB', '유당분해효소결핍증으로 인한 유제품 섭취 후 설사에 대한 재활적 접근으로는 유당이 제거된 락토프리 제품 사용, 소량의 유제품을 식사와 함께 점진적으로 도입하는 방법이 있습니다. 경구용 락타아제 효소제(유당분해효소 보충제)를 유제품 섭취 전에 복용하면 증상을 완화하는 데 도움이 됩니다. 칼슘 부족 방지를 위해 두유, 두부, 뼈째 먹는 생선 등을 충분히 섭취하고, 영양사 및 소화기내과 전문의와 상담하여 개인화된 식이 관리를 받으시기 바랍니다.', 1630, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '유당분해효소결핍증', '유당분해효소결핍증', 'DEFINITION', '유당분해효소결핍증에서 우유 섭취 후 소화가 안 되면 복부 팽만, 복통(산통성), 설사, 가스 과다, 구역감 등이 발생합니다. 이러한 증상이 나타나면 유당 함유 식품 섭취를 줄이거나 락토프리 제품으로 대체하고, 증상이 지속되거나 심하면 다른 위장관 질환과의 감별을 위해 소화기내과 전문의의 진료를 받는 것이 권장됩니다. 유당분해효소 보충제 복용이나 발효 유제품(요거트, 치즈) 섭취가 증상 경감에 도움이 될 수 있습니다.', 1631, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '유당분해효소결핍증', '유당분해효소결핍증', 'SYMPTOM', '유당분해효소결핍증의 전형적인 증상은 유당 함유 식품(우유, 유제품) 섭취 후 복부 팽만, 복통, 설사이며, 두유는 유당을 포함하지 않아 일반적으로 유당분해효소결핍증 증상을 유발하지 않습니다. 두유 섭취 후 속 불편감이나 두통이 생긴다면 두유에 대한 콩 알레르기, 콩 단백질 불내성, 또는 다른 원인을 의심해야 합니다. 정확한 원인 감별을 위해 소화기내과 또는 알레르기내과 전문의의 진료를 받으시기 바랍니다.', 1632, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '유당분해효소결핍증', '유당분해효소결핍증', 'DIAGNOSIS', '유당분해효소결핍증의 진단에서 우유 섭취량 자체가 기준이 되지는 않습니다. 주요 진단 방법으로는 유당 부하 호기 검사(수소 호기 검사), 유당 부하 혈당 검사, 소장 생검을 통한 효소 활성도 측정, 유전자 검사 등이 있습니다. 그 중 수소 호기 검사가 비침습적이고 비교적 간편하여 가장 널리 사용되며, 진단은 소화기내과 전문의에 의해 이루어집니다.', 1633, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '유당분해효소결핍증', '유당분해효소결핍증', 'TREATMENT', '유당분해효소결핍증에서는 유당이 함유된 일반 우유와 유제품을 피하고, 락토프리 우유나 식물성 음료(두유, 귀리유 등)로 대체하는 것이 기본입니다. 소량의 발효 유제품(요거트, 숙성 치즈)은 유당이 부분 분해되어 비교적 잘 耐용되므로 칼슘 보충원으로 활용할 수 있으며, 분유나 유제품 섭취 전 락타아제 효소제 복용도 도움이 됩니다. 칼슘과 비타민 D 결핍을 예방하기 위해 두부, 뼈째 먹는 생선, 녹색 채소 섭취를 늘리고, 영양사 상담을 통한 개인화된 식이 관리를 권장합니다.', 1634, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '유행성 이하선염', '유행성이하선염', 'MEDICATION', '유행성 이하선염(볼거리)에서 귀 아래 이하선의 통증과 부종이 주된 증상이며, 증상 완화를 위해 이부프로펜(소염진통제) 또는 아세트아미노펜(해열진통제)이 사용됩니다. 유행성 이하선염은 바이러스 감염이므로 항생제는 효과가 없으며, 치료는 증상 완화 중심의 대증 요법이 원칙입니다. 통증이 심하거나 다른 증상이 동반된 경우에는 임의로 약을 복용하지 말고 소아청소년과 또는 내과 전문의의 처방을 받으시기 바랍니다.', 1635, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '유행성 이하선염', '유행성이하선염', 'PREVENTION', '유행성 이하선염(볼거리) 예방접종(MMR 백신)을 받지 않으면 볼거리 바이러스에 감염될 경우 이하선염, 발열, 두통 등의 증상이 발생하고, 특히 사춘기 이후 남성에서 고환염(합병증)이 생겨 드물게 불임으로 이어질 수 있습니다. 그 외 합병증으로 뇌수막염, 난청, 췌장염, 여성의 난소염 등이 나타날 수 있습니다. 예방접종이 가장 효과적인 예방법이므로, 접종력이 없거나 불확실하다면 소아청소년과 또는 내과 전문의와 상담하여 접종을 받으시기 바랍니다.', 1636, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '유행성 이하선염', '유행성이하선염', 'CAUSE', '유행성 이하선염은 파라믹소바이러스과의 볼거리 바이러스(Mumps virus) 감염에 의해 발생하며, 감염자의 비말 또는 직접 접촉을 통해 전파됩니다. 예방을 위해 MMR(홍역-볼거리-풍진) 백신 2회 접종이 가장 효과적이며, 손 씻기, 기침 예절, 환자와의 접촉 최소화 등 개인위생 수칙도 중요합니다. 발병 시 치료는 항바이러스제가 없어 해열진통제, 충분한 수분 섭취 등 대증 치료가 이루어지며, 증상이 있으면 소아청소년과 전문의를 방문하시기 바랍니다.', 1637, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '유행성 이하선염', '유행성이하선염', 'DEFINITION', '유행성 이하선염은 볼거리 바이러스에 의한 급성 감염으로, 귀 앞쪽과 아래쪽의 이하선(침샘)이 붓고 아프며 발열, 두통, 식욕 부진이 동반됩니다. 보통 한쪽 또는 양쪽 뺨이 부어오르는 것이 특징적이며, 잠복기는 16~18일로 감염자와 접촉 후 2~3주 후에 증상이 나타납니다. 대부분 자연 회복되나, 고환염, 뇌수막염, 난청 등 합병증이 생길 수 있으므로 증상이 있을 경우 소아청소년과 전문의의 진료를 받으시기 바랍니다.', 1638, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '유행성 이하선염', '유행성이하선염', 'SYMPTOM', '볼이 붓고 턱(귀 밑) 부위가 부어오르는 증상이 나타나면 유행성 이하선염(볼거리)을 가장 먼저 의심해야 합니다. 이하선은 귀 앞아래에 위치한 침샘으로, 볼거리 바이러스 감염 시 이하선이 편측 또는 양측으로 부어 볼이 커지는 특징적 양상이 나타납니다. 발열, 두통, 음식 씹을 때 통증이 동반되면 유행성 이하선염 가능성이 높으므로, 소아청소년과 또는 내과 전문의의 진료를 받으시기 바랍니다.', 1639, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '유행성 이하선염', '유행성이하선염', 'DIAGNOSIS', '유행성 이하선염 진단은 주로 임상 증상(이하선 부종, 발열, 접촉력, 예방접종력)으로 이루어지며, 혈액 검사(혈청 볼거리 IgM 항체 검사, 아밀라아제 증가), 타액이나 소변에서 바이러스 배양 또는 PCR 검사가 확진에 사용됩니다. 소아청소년과를 방문하면 임상 증상 평가와 필요에 따라 혈액 검사를 시행하여 진단할 수 있습니다. 학교 등 집단 시설에서 유행하고 있다면 가능한 한 빨리 전문의의 진료를 받으시기 바랍니다.', 1640, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '유행성 이하선염', '유행성이하선염', 'TREATMENT', '유행성 이하선염은 바이러스 감염이므로 특이적 항바이러스 치료는 없으며, 대증 치료(해열진통제, 충분한 수분 섭취, 부드러운 음식 섭취, 충분한 휴식)가 기본입니다. 자가 관리로 이하선 부위에 냉찜질 또는 온찜질을 하면 통증 완화에 도움이 될 수 있으며, 산성 음식은 침샘을 자극하므로 피하는 것이 좋습니다. 증상이 심하거나 고환염, 두통, 청력 이상 등 합병증이 의심되면 즉시 소아청소년과 또는 내과 전문의의 진료를 받으시기 바랍니다.', 1641, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '저신장증', '저신장증', 'CAUSE', '키가 작은 부모 사이에서 아이도 키가 작은 경우는 대부분 가족성 저신장(유전성 저신장)으로, 부모의 유전적 영향을 받아 성장 잠재력 자체가 낮게 결정되기 때문입니다. 이 경우 성장 속도와 골 연령은 정상이나 예측 최종 키(mid-parental height)가 낮습니다. 그러나 성장호르몬 결핍, 갑상선 기능 저하증, 염색체 이상(터너증후군 등) 등 치료 가능한 원인을 감별하기 위해 소아내분비과 전문의 진료를 받는 것이 중요합니다.', 1642, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '저신장증', '저신장증', 'DEFINITION', '저신장증은 같은 연령과 성별의 소아 중 신장이 3백분위수(또는 -2 표준편차) 미만인 경우로 정의됩니다. 유전적 영향은 매우 크며, 부모의 키를 평균한 중간부모키(mid-parental height)가 아이의 성장 잠재력을 예측하는 중요한 지표입니다. 가족성 저신장이 가장 흔하나, 성장호르몬 결핍, 만성 질환, 영양 불량 등 치료 가능한 원인도 있으므로 소아내분비과 전문의의 정확한 평가가 필요합니다.', 1643, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '저신장증', '저신장증', 'SYMPTOM', '저신장증 자체는 특별한 초기 증상이 없으나, 또래에 비해 키가 지속적으로 작고 연간 성장 속도가 4cm 미만으로 느려지는 것이 주요 징후입니다. 시간이 지남에 따라 또래와의 키 차이가 점점 벌어지고, 성장판이 닫히는 사춘기 이후에는 키가 거의 성장하지 않게 됩니다. 원인 질환에 따라 다른 증상(갑상선 기능 저하 시 피로·부종, 성장호르몬 결핍 시 작은 음경·저혈당 등)이 동반될 수 있으므로 소아내분비과 전문의의 평가가 중요합니다.', 1644, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '저신장증', '저신장증', 'DIAGNOSIS', '성장호르몬 분비 부족으로 저신장증이 의심될 경우 소아내분비과 전문의를 찾아야 하며, 이곳에서 성장 곡선 분석, 골 연령 검사(손목 X선), 성장호르몬 자극 검사, 인슐린양성장인자(IGF-1) 측정, 갑상선 기능 검사, 두뇌 MRI 등 정밀 검사를 통해 정확한 원인 감별과 진단이 이루어집니다. 조기 진단과 치료일수록 성장 효과가 크므로, 성장 지연이 의심되면 지체 없이 소아내분비과를 방문하시기 바랍니다.', 1645, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '저신장증', '저신장증', 'TREATMENT', '성장호르몬 치료는 성장호르몬 결핍증, 터너증후군, 만성 신부전 등 공인된 적응증에서 시행하며, 적절히 관리되면 비교적 안전한 치료입니다. 잠재적 부작용으로는 주사 부위 반응, 두통, 부종, 관절통, 혈당 상승, 드물게 뼈 통증(미끄럼 대퇴골단 등)이 있을 수 있습니다. 장기 치료의 안전성과 효과, 부작용 모니터링을 위해 소아내분비과 전문의의 정기적인 추적 관찰과 검사가 반드시 필요합니다.', 1646, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '제대 탈장', '제대탈장', 'CAUSE', '제대 탈장은 배꼽 주변 복벽의 근육과 근막이 완전히 닫히지 않아 배꼽 부위를 통해 복강 내 장기(주로 소장)가 돌출되는 질환입니다. 배꼽 탈장과 제대 탈장은 같은 의미로 혼용되며, 발생 위치와 기전이 같습니다. 일반적인 서혜부 탈장이나 항문 탈장과는 해부학적 위치와 기전이 전혀 다르므로, 배꼽이 불룩하게 튀어나오는 증상이 있다면 소아외과 전문의의 진료를 받으시기 바랍니다.', 1647, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '제대 탈장', '제대탈장', 'DEFINITION', '제대 탈장은 배꼽 부위 복벽 근막의 결손으로 인해 장이나 복막이 배꼽을 통해 외부로 돌출되는 질환으로, 항문과는 전혀 관련이 없습니다. 주로 신생아 및 영아에서 발생하며, 특히 미숙아, 저출생체중아, 아프리카계 아이들에서 빈도가 높습니다. 대부분 2~4세까지 자연 폐쇄되지만, 결손이 크거나 만 4~5세 이후에도 지속되면 수술이 필요할 수 있으므로 소아외과 전문의의 진료를 받으시기 바랍니다.', 1648, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '제대 탈장', '제대탈장', 'SYMPTOM', '제대 탈장의 증상은 배꼽이 볼록하게 돌출되는 것이 가장 특징적이며, 아기가 울거나 힘을 줄 때 더 크게 튀어나오고 누우면 줄어드는 양상을 보입니다. 대부분 통증은 없으나, 드물게 감돈(탈장 내용물이 끼어 혈류 차단)이 발생하면 갑자기 심하게 울고 탈장 부위가 딱딱해지며 복통이 생길 수 있습니다. 감돈이 의심되면 응급 상황이므로 즉시 소아외과 전문의를 방문해야 하며, 일반적인 제대 탈장도 정기적인 추적 관찰이 권장됩니다.', 1649, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '제대 탈장', '제대탈장', 'DIAGNOSIS', '제대 탈장의 진단은 주로 시진과 촉진 등 신체 검사만으로도 가능한 경우가 많습니다. 결손의 크기 측정, 탈장 내용물 확인, 감돈 여부 평가에 복부 초음파 검사가 추가로 시행될 수 있습니다. 증상이 전형적인 경우 별도의 복잡한 검사 없이 소아외과 전문의가 진단하며, 결손 크기와 나이에 따라 경과 관찰 또는 수술 여부를 결정하게 됩니다.', 1650, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '제대 탈장', '제대탈장', 'TREATMENT', '제대 탈장은 주로 수술적 치료가 핵심이며, 특정 약물로 치료하는 방법은 없습니다. 수술 후 통증 관리를 위해 진통제가 사용될 수 있으며, 감염 예방을 위해 항생제가 처방되기도 합니다. 소아의 경우 만 4~5세까지 자연 치유를 기다리기도 하므로, 정확한 치료 방침은 소아외과 또는 외과 전문의와 상담하시기 바랍니다.', 1651, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '팔로 사 징후', '팔로사징후', 'CAUSE', '팔로 사 징후(Tetralogy of Fallot)는 태아 발생 과정에서 심장 구조 형성에 이상이 생겨 발생하는 선천성 심장 기형입니다. 폐동맥 협착, 심실 중격 결손, 대동맥 우방 전위, 우심실 비대의 네 가지 구조적 이상이 동시에 나타나며, 후천적 원인이 아닌 태생기 발달 이상이 주요 원인입니다. 일부 유전적 요인(예: 22번 염색체 미세 결실)과 관련될 수 있으나, 대부분은 원인 불명의 선천적 기형으로 발생합니다.', 1652, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '팔로 사 징후', '팔로사징후', 'DEFINITION', '팔로 사 징후는 폐동맥 협착, 심실 중격 결손, 대동맥 기승, 우심실 비대의 네 가지 심장 구조 이상이 복합적으로 나타나는 선천성 청색증형 심장병입니다. 산소가 부족한 정맥혈이 체순환으로 섞여 들어가 전신 청색증이 나타나는 것이 특징입니다. 신생아 및 영아기에 발견되며, 수술적 교정이 필요한 중증 선천성 심질환입니다.', 1653, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '팔로 사 징후', '팔로사징후', 'SYMPTOM', '팔로 사 징후에서는 청색증 외에도 호흡 곤란, 운동 시 쪼그려 앉는 자세(squatting), 성장 발육 지연, 곤봉지(손가락 끝이 둥글게 비대해지는 현상)가 나타날 수 있습니다. 또한 저산소혈증 발작(tet spell)이 발생하면 갑자기 심한 청색증과 의식 저하가 나타날 수 있어 즉각적인 처치가 필요합니다. 정확한 증상 평가와 치료를 위해 소아심장과 전문의 상담이 필요합니다.', 1654, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '팔로 사 징후', '팔로사징후', 'DIAGNOSIS', '팔로 사 징후는 소아심장 전문의가 있는 대학병원이나 어린이병원에서 진단받을 수 있습니다. 심초음파, 심전도, 흉부 X선, 심장 CT 또는 MRI를 통해 심장 구조 이상을 확인하며, 산전 초음파로도 발견되는 경우가 있습니다. 청색증, 호흡 곤란 등의 증상이 있을 경우 즉시 소아과 또는 소아심장과를 방문하시기 바랍니다.', 1655, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소아청소년질환', '팔로 사 징후', '팔로사징후', 'TREATMENT', '팔로 사 징후의 근본적인 치료는 개심술(심장 개방 수술)을 통한 완전 교정술로, 심실 중격 결손 봉합과 폐동맥 협착 해소를 동시에 시행합니다. 완전 교정 전까지 증상 완화를 위해 팔로-블랙록 단락술(Blalock-Taussig shunt) 같은 고식적 수술을 먼저 시행하기도 합니다. 치료 방침은 환자 상태와 해부학적 구조에 따라 다르므로 소아심장 전문의와 상담하시기 바랍니다.', 1656, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', 'B형간염', 'b형간염', 'DEFINITION', 'B형간염은 B형간염 바이러스(HBV)에 감염되어 발생하는 간 질환으로, 급성과 만성으로 구분됩니다. 혈액, 성 접촉, 수직감염(모자간 전파) 등을 통해 전파되며, 만성화 시 간경화 및 간세포암으로 진행될 수 있습니다. 예방백신이 있어 접종으로 예방이 가능하며, 감염 시 소화기내과 또는 간전문의 진료가 필요합니다.', 1657, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간 전이', '간전이', 'DIET_LIFE', '간 전이 환자는 충분한 단백질과 열량을 섭취하고, 신선한 채소와 과일을 포함한 균형 잡힌 식사를 유지하는 것이 중요합니다. 알코올은 완전히 피하고, 과도한 지방 섭취와 가공식품을 제한하며, 충분한 수분 섭취를 권장합니다. 항암 치료 중에는 영양 상태가 치료 결과에 영향을 미치므로 의료팀 및 영양사와 상담하여 개인화된 식이 계획을 수립하시기 바랍니다.', 1658, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간 전이', '간전이', 'CAUSE', '간 전이 환자에서 나타나는 발열, 발한, 무기력, 식욕 부진, 체중 감소는 종양 자체에서 분비되는 사이토카인과 같은 염증 매개물질, 그리고 간 기능 저하로 인한 대사 이상이 주요 원인입니다. 또한 항암 치료의 부작용으로 이러한 전신 증상이 악화될 수 있습니다. 증상이 지속되거나 악화되면 담당 종양내과 전문의와 즉시 상담하시기 바랍니다.', 1659, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간 전이', '간전이', 'DEFINITION', '위암이나 폐암 환자에서 간 전이가 발생하면 우상복부 통증 또는 불편감, 복부 팽만, 황달(피부와 눈의 노란 변색), 원인 불명의 체중 감소, 피로감, 식욕 부진 등의 증상이 나타날 수 있습니다. 간이 커지면서 우측 늑골 아래 종괴가 만져지기도 합니다. 이러한 증상이 나타나면 즉시 담당 의사와 상담하여 복부 초음파나 CT 검사를 받으시기 바랍니다.', 1660, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간 전이', '간전이', 'SYMPTOM', '황달은 간 전이의 주요 증상 중 하나로, 전이된 암세포가 담도를 압박하거나 간 기능을 심각하게 저하시킬 때 발생합니다. 눈의 흰자위가 노랗게 변하고 피부 황변, 짙은 갈색 소변, 옅은 대변이 동반되면 간 전이를 의심할 수 있습니다. 황달 증상이 나타나면 빠른 시일 내에 소화기내과 또는 종양내과 전문의의 진료를 받으시기 바랍니다.', 1661, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간 전이', '간전이', 'DIAGNOSIS', '간 전이의 예후는 원발암의 종류, 전이 병소의 수와 크기, 간 기능 상태, 전신 상태에 따라 크게 다르며, 일반적으로 예후가 좋다고 단정할 수 없습니다. 다만 대장암의 간 단독 전이처럼 수술적 절제가 가능한 경우에는 완치를 기대할 수 있어 상대적으로 양호한 예후를 보이기도 합니다. 정확한 예후 판단은 담당 종양내과 또는 간담췌외과 전문의와 상담하시기 바랍니다.', 1662, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간 전이', '간전이', 'TREATMENT', '간 전이 치료에서 국소 치료인 고주파 열치료(RFA), 경동맥 화학색전술(TACE), 방사선 치료는 전신 항암화학요법과 병용하여 적용되는 경우가 많습니다. 특히 수술이 어려운 다발성 전이의 경우 항암치료와 국소 치료를 병합하여 생존율을 높이려 합니다. 구체적인 치료 계획은 원발암의 종류와 환자 상태에 따라 다르므로 종양내과 및 간담췌외과 전문의와 상담하시기 바랍니다.', 1663, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', 'C형간염', 'c형간염', 'DEFINITION', 'C형간염은 C형간염 바이러스(HCV)에 감염되어 발생하는 간 질환으로, 주로 혈액을 통해 전파됩니다. 급성 감염 후 약 70~80%에서 만성으로 진행되며, 치료하지 않으면 간경화 및 간세포암으로 발전할 수 있습니다. B형간염과 달리 예방 백신이 없으나, 현재는 직접작용 항바이러스제(DAA)로 95% 이상의 완치율을 보이므로 소화기내과 전문의와 상담하시기 바랍니다.', 1664, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간경화', '간경화', 'DIET_LIFE', '간경화 환자에게는 하루 나트륨 섭취량을 2,000mg(소금 5g) 이하로 제한하도록 권장합니다. 나트륨 과다 섭취는 복수와 부종을 악화시키고, 이미 저하된 신장 기능에 추가적인 부담을 주어 간신증후군으로 진행될 위험을 높입니다. 식이 조절의 세부 사항은 환자의 복수 및 신기능 상태에 따라 달라지므로 소화기내과 전문의 및 영양사와 상담하시기 바랍니다.', 1665, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간경화', '간경화', 'CAUSE', '한국을 포함한 동아시아 국가에서는 만성 B형간염이 간경화의 가장 흔한 원인이며, 서구권에서는 과도한 음주(알코올성 간질환)가 주요 원인입니다. 전 세계적으로 공통된 원인으로는 만성 C형간염, 비알코올성 지방간질환(NAFLD), 자가면역성 간염 등이 있습니다. 따라서 지역에 따라 원인의 빈도는 다르나 주요 원인 질환 자체는 유사하며, 정확한 원인 파악을 위해 소화기내과 전문의 진료가 필요합니다.', 1666, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간경화', '간경화', 'DEFINITION', '간경화는 다양한 원인에 의해 간세포가 반복적으로 손상되고 괴사된 자리가 섬유 조직으로 대체되면서 간 전체 구조가 변형되는 만성 진행성 간질환입니다. 간이 딱딱해지고 표면이 울퉁불퉁해지며, 간 기능이 점진적으로 저하되어 합성 기능, 해독 기능, 대사 기능이 모두 떨어집니다. 단순히 간이 붓는 것과는 다른 비가역적 구조 변화이므로, 소화기내과 전문의의 정확한 진단과 관리가 필요합니다.', 1667, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간경화', '간경화', 'SYMPTOM', '간경화 환자에서 식욕 부진, 소화불량, 복부 불쾌감이 지속되는 것은 간 기능 저하로 인한 담즙 분비 이상, 문맥압 항진으로 인한 위장관 울혈, 복수로 인한 복압 증가가 복합적으로 작용하기 때문입니다. 또한 장내 세균 과증식과 독소 축적도 이러한 소화기 증상을 악화시킵니다. 증상이 지속되면 소화기내과 전문의의 진료를 받아 원인에 맞는 치료를 받으시기 바랍니다.', 1668, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간경화', '간경화', 'DIAGNOSIS', '간경화 진단을 위해 혈액검사(간기능 검사, 혈소판 수치, 응고 검사), 복부 초음파, CT 또는 MRI 검사를 시행합니다. 확진이 필요한 경우 간 조직 생검을 시행하기도 하며, 식도정맥류 확인을 위한 위내시경도 중요한 검사입니다. 증상이 심각하거나 복수, 황달, 토혈 등이 동반될 경우 즉시 소화기내과를 방문하시기 바랍니다.', 1669, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간경화', '간경화', 'TREATMENT', '간경화의 치료는 원인 제거(항바이러스 치료, 금주 등)와 합병증 관리가 핵심으로, 가장 널리 사용되는 방법은 원인 질환에 따른 약물치료와 식이·생활 습관 개선입니다. 복수에는 이뇨제, 식도정맥류 예방에는 베타차단제, B형간염 연관 간경화에는 항바이러스제가 대표적으로 사용됩니다. 말기 간경화에서는 간 이식이 유일한 근본적 치료이므로 소화기내과 전문의의 지속적인 관리가 필요합니다.', 1670, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간농양', '간농양', 'CAUSE', '간농양은 세균성과 아메바성으로 나뉘며, 세균성 간농양은 담도염, 담석증, 충수염 등 복강 내 감염이 혈행성 또는 담도를 통해 간으로 파급되어 발생합니다. 당뇨병, 면역저하 상태, 간경화 등이 있는 환자에서 발생 위험이 높습니다. 크론병, 게실염 등 장 질환의 합병증으로도 발생할 수 있으므로, 원인 파악을 위해 소화기내과 또는 감염내과 전문의 진료가 필요합니다.', 1671, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간농양', '간농양', 'DEFINITION', '간농양은 간 내에 세균이나 기생충 감염으로 인해 고름(농)이 고여 형성된 공동성 병변입니다. 주요 증상으로 발열(38~40도의 고열), 오한, 우상복부 통증, 피로감, 식욕 감소, 체중 감소가 나타납니다. 치료하지 않으면 농양이 파열되어 복막염 등 심각한 합병증으로 이어질 수 있으므로, 해당 증상이 의심될 경우 즉시 소화기내과 또는 외과 전문의의 진료를 받으시기 바랍니다.', 1672, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간농양', '간농양', 'SYMPTOM', '당뇨병은 면역 기능을 저하시켜 세균 감염에 대한 저항력이 떨어지게 하므로, 간농양 발생 위험을 유의미하게 증가시킵니다. 특히 혈당 조절이 불량한 당뇨 환자에서는 Klebsiella pneumoniae에 의한 원발성 간농양이 호발하며, 이는 안구, 폐, 뇌 등 다른 장기로 전이성 감염을 일으키는 침습성 간농양 증후군으로 진행될 수 있습니다. 당뇨 환자에서 발열과 복통이 동반되면 즉시 전문의 진료를 받으시기 바랍니다.', 1673, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간농양', '간농양', 'DIAGNOSIS', '간농양은 복부 초음파와 복부 CT가 가장 중요한 진단 도구로, 간 내부의 농양 위치, 크기, 수, 격막 유무를 확인할 수 있습니다. 혈액검사에서 백혈구 증가, CRP 상승, 간효소 수치 이상 등의 염증 소견이 동반됩니다. 원인균 확인을 위해 혈액 배양 검사 및 초음파 또는 CT 유도 하 경피적 흡인 또는 배농술이 진단과 치료를 겸하여 시행됩니다.', 1674, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간농양', '간농양', 'TREATMENT', '간농양의 주요 치료는 경피적 배농술로, 초음파 또는 CT 유도 하에 피부를 통해 바늘이나 카테터를 삽입하여 농양을 흡인하거나 지속적으로 배농하는 방법입니다. 이 과정에서 초음파 기기, CT 장치, 배농용 카테터 등의 의료 기기가 사용됩니다. 수술적 치료는 경피적 배농이 불가능하거나 실패한 경우에 시행되며, 항생제 치료를 병용하는 것이 원칙입니다.', 1675, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간성 뇌증', '간성뇌증', 'DIET_LIFE', '간성 뇌증 예방을 위해 고암모니아혈증을 유발하는 단백질 과다 섭취를 피하되, 영양 불량이 오지 않도록 식물성 단백질 위주의 균형 잡힌 식사를 유지합니다. 변비는 암모니아 생성을 증가시키므로 식이섬유를 충분히 섭취하고 규칙적인 배변을 유도하며, 알코올과 수면제, 진통제 등 간 대사에 부담을 주는 약물은 피해야 합니다. 정확한 식이 계획은 소화기내과 전문의 및 영양사와 상담하시기 바랍니다.', 1676, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간성 뇌증', '간성뇌증', 'MEDICATION', '간성 뇌증 치료에 사용되는 락툴로오스는 설사, 복부 경련, 가스 팽만이 주요 부작용입니다. 항생제인 리팍시민(rifaximin)은 전신 흡수가 거의 없어 비교적 안전하나, 장기 사용 시 장내 균총 변화가 발생할 수 있습니다. 이러한 약물은 전문의의 처방과 모니터링 하에 사용해야 하며, 부작용이 나타나면 즉시 담당 의사와 상담하시기 바랍니다.', 1677, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간성 뇌증', '간성뇌증', 'PREVENTION', '간성 뇌증 예방을 위해 변비를 방지하고 규칙적인 배변을 유지하며, 담당 의사가 처방한 락툴로오스나 리팍시민을 꾸준히 복용하는 것이 중요합니다. 감염, 탈수, 소화기 출혈, 전해질 이상 등 간성 뇌증을 유발할 수 있는 상황을 조기에 발견하고 치료해야 합니다. 불필요한 진정제, 수면제, 과도한 단백질 섭취를 피하고, 정기적으로 소화기내과 전문의의 추적 관찰을 받으시기 바랍니다.', 1678, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간성 뇌증', '간성뇌증', 'CAUSE', '간성 뇌증은 심한 간 기능 장애로 간이 암모니아를 비롯한 신경독성 물질을 충분히 해독하지 못해 혈중 암모니아 농도가 상승하고, 이것이 혈뇌장벽을 통과하여 뇌에 직접 독성을 미쳐 발생합니다. 암모니아는 뇌의 신경 전달을 방해하고 뇌 세포의 삼투 조절을 교란하여 뇌부종과 신경 기능 저하를 일으킵니다. 정확한 평가와 치료를 위해 소화기내과 전문의의 진료가 필요합니다.', 1679, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간성 뇌증', '간성뇌증', 'DEFINITION', '간성 뇌증은 심한 간 기능 부전 또는 문맥-체순환 단락으로 인해 신경독성 물질(주로 암모니아)이 뇌에 축적되어 발생하는 신경정신과적 합병증입니다. 인지 기능 저하, 의식 혼탁, 행동 변화, 심한 경우 혼수에 이르는 다양한 뇌 기능 이상이 나타납니다. 주로 간경화, 급성 간부전, 간이식 후 등의 심각한 간 질환 환자에서 발생하며 전문적인 치료가 필요합니다.', 1680, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간성 뇌증', '간성뇌증', 'SYMPTOM', '간성 뇌증의 정신적 증상으로는 수면 장애(낮밤이 바뀌는 수면 패턴), 집중력 저하, 기억력 감퇴, 혼돈, 방향감각 상실, 성격 및 행동 변화, 심한 경우 섬망과 혼수가 나타납니다. 이러한 증상은 혈중 암모니아 수치를 낮추는 치료(락툴로오스, 리팍시민 등)와 원인 교정을 통해 호전될 수 있으나, 반복적으로 재발하는 경향이 있어 소화기내과 전문의의 지속적인 관리가 필요합니다.', 1681, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간성 뇌증', '간성뇌증', 'DIAGNOSIS', '간성 뇌증 진단을 위해 특별히 필요한 서류는 없으나, 기존 간 질환(간경화, 간부전 등)의 진료 기록이 있으면 진단에 도움이 됩니다. 혈액검사(암모니아, 간기능 검사), 신경학적 검사, 뇌파 검사 등이 시행되며, 증상이 심한 경우 응급실 방문이 필요합니다. 의식 저하나 혼돈이 동반될 경우 예약 없이 즉시 응급실을 방문하시기 바랍니다.', 1682, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간성 뇌증', '간성뇌증', 'TREATMENT', '간성 뇌증 치료에는 락툴로오스(설사약) 외에 장내 암모니아 생성을 줄이는 항생제 리팍시민(rifaximin)이 효과적으로 사용됩니다. 또한 유발 인자(감염, 소화기 출혈, 전해질 이상, 탈수)를 교정하고, 식이 단백질을 적절히 조절하며, 아연 보충이 도움될 수 있습니다. 말기 간경화에서 반복적인 간성 뇌증이 발생하는 경우 간 이식이 근본적 치료가 될 수 있으므로 전문의와 상담하시기 바랍니다.', 1683, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간염', '간염', 'CHECKUP', '만성 B형간염과 관련된 증상 확인을 위해 B형간염 표면항원(HBsAg), B형간염 e항원(HBeAg), HBV DNA 정량 검사, 그리고 간기능 검사(AST, ALT, 빌리루빈 등)를 받으시기 바랍니다. 복부 초음파 검사도 간 상태 평가에 중요하며, 필요 시 간 섬유화 검사도 시행됩니다. 이러한 검사는 소화기내과 또는 내과에서 받을 수 있습니다.', 1684, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간염', '간염', 'DIET_LIFE', '급성 A형간염으로 식욕이 저하된 경우 소량씩 자주 먹는 방식으로 충분한 열량을 섭취하고, 수분 보충을 충분히 하는 것이 중요합니다. 기름진 음식, 알코올, 가공식품은 간에 부담을 주므로 피하고, 부드러운 죽, 두부, 신선한 채소 등 소화가 쉬운 음식을 선택하세요. 충분한 휴식을 취하는 것이 회복에 가장 중요하며, 증상이 심하면 입원 치료가 필요할 수 있으므로 소화기내과 전문의의 지시에 따르시기 바랍니다.', 1685, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간염', '간염', 'MEDICATION', '급성 바이러스성 간염의 경우 특이적 항바이러스 치료가 없는 경우가 많으며, 피로감과 식욕부진 완화를 위해 대증적 지지 요법이 주로 사용됩니다. 간 보호를 위해 우루소데옥시콜산(UDCA) 같은 간 보호제가 사용될 수 있으며, 구역질이 심할 경우 항구역 약물을 처방받을 수 있습니다. 어떤 약물이든 간에 부담을 줄 수 있으므로 반드시 소화기내과 전문의의 처방 하에 복용하시기 바랍니다.', 1686, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간염', '간염', 'PREVENTION', 'B형간염 예방접종 3회 완료 후 항체(anti-HBs) 검사에서 항체가 생기지 않은 경우 추가 접종을 고려합니다. 1차 접종 3회 완료 후 항체 미형성 시 3회 재접종하며, 재접종 후에도 항체가 생기지 않는 경우(무반응자)는 B형간염 바이러스 노출 시 면역글로불린 주사를 맞는 방법으로 대처합니다. 항체 형성 여부와 추가 접종 필요성은 내과 또는 소화기내과 전문의와 상담하시기 바랍니다.', 1687, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간염', '간염', 'CAUSE', '만성 C형간염은 음식이나 식습관을 통해 전파되지 않으며, 주요 감염 경로는 오염된 혈액과의 접촉입니다. 비위생적인 주사기 공유, 수혈(1990년대 이전), 문신이나 피어싱 시 비위생적 기구 사용, 성 접촉(상대적으로 낮은 확률)이 주요 원인입니다. 식습관 자체는 C형간염의 직접적 원인이 아니므로, 혈액 매개 감염 경로에 대한 주의가 중요합니다.', 1688, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간염', '간염', 'DEFINITION', '급성 B형간염은 B형간염 바이러스(HBV)에 처음 감염되어 6개월 이내에 발생하는 급성 간 염증 질환입니다. HBV는 DNA 바이러스로, Hepadnaviridae과에 속하며, 혈액과 체액을 통해 전파됩니다. 성인에서 급성 감염의 약 95%는 자연 치유되지만, 면역력이 약한 경우 만성 B형간염으로 이행될 수 있으므로 소화기내과 전문의의 경과 관찰이 필요합니다.', 1689, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간염', '간염', 'SYMPTOM', '급성 B형간염의 초기 증상으로는 잠복기(6주~6개월) 이후 피로감, 식욕 부진, 오심, 구토, 우상복부 불쾌감, 발열, 근육통이 나타납니다. 이후 황달기에 접어들면 황달(피부·눈 노란 변색), 짙은 소변, 옅은 대변이 나타나고, 간 비대와 압통이 동반될 수 있습니다. 대부분 성인에서는 수주~수개월 내 자연 회복되지만 증상이 심하면 입원 치료가 필요하므로 소화기내과 전문의의 진료를 받으시기 바랍니다.', 1690, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간염', '간염', 'DIAGNOSIS', '간 효소(ALT, AST) 수치가 높을 경우 소화기내과 또는 내과를 방문하시기 바랍니다. 이 수치 이상은 간염, 지방간, 간경화, 약물성 간손상 등 다양한 간 질환을 시사할 수 있으므로, 추가적인 혈액검사 및 복부 초음파를 통한 원인 감별이 필요합니다. 증상(황달, 복통, 심한 피로 등)이 동반될 경우 즉시 병원을 방문하시기 바랍니다.', 1691, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '간염', '간염', 'TREATMENT', '간염 치료를 위해서는 소화기내과 또는 간전문 클리닉이 있는 내과를 방문하시기 바랍니다. 급성 간염은 주로 외래 치료로 관리하나 증상이 심한 경우 입원이 필요하며, 만성 B형 또는 C형간염은 전문적인 항바이러스 치료가 필요합니다. 대학병원의 소화기내과나 간전문센터에서 체계적인 진단과 치료를 받으시기 바랍니다.', 1692, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '궤양성 대장염', '궤양성대장염', 'CHECKUP', '3개월 이상 지속되는 소화불량, 변비와 설사의 반복, 혈변 또는 점액변이 동반된다면 궤양성 대장염을 포함한 염증성 장 질환의 가능성이 있으므로 검진을 받아보는 것이 좋습니다. 대장내시경 검사가 확진에 가장 중요한 검사이며, 소화기내과 전문의의 진료를 먼저 받으시기 바랍니다. 증상이 지속되거나 혈변, 발열, 체중 감소가 동반되면 빠른 시일 내에 병원을 방문하세요.', 1693, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '궤양성 대장염', '궤양성대장염', 'DIET_LIFE', '궤양성 대장염 환자는 증상 악화기에는 저잔사 식이(식이섬유 제한)를 하고, 완화기에는 균형 잡힌 영양 섭취를 유지합니다. 매운 음식, 알코올, 카페인, 유제품(유당 불내증이 있는 경우)은 증상을 악화시킬 수 있으므로 개인별로 제한하는 것이 좋습니다. 충분한 수분 섭취, 규칙적인 식사, 과도한 스트레스 관리가 중요하며, 구체적인 식이 계획은 소화기내과 전문의 및 영양사와 상담하시기 바랍니다.', 1694, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '궤양성 대장염', '궤양성대장염', 'CAUSE', '현재까지 궤양성 대장염의 정확한 원인은 밝혀지지 않았으나, 카페인이나 매운 음식이 직접적인 원인이 되지는 않습니다. 다만 이러한 음식들은 이미 염증이 있는 장점막을 자극하여 증상을 악화시킬 수 있습니다. 궤양성 대장염은 유전적 소인, 면역 이상, 장내 세균총 불균형, 환경적 요인 등이 복합적으로 작용하는 것으로 알려져 있으며, 정확한 진단을 위해 소화기내과 전문의 상담이 필요합니다.', 1695, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '궤양성 대장염', '궤양성대장염', 'DEFINITION', '궤양성 대장염의 확진을 위해서는 대장내시경 검사와 조직 생검이 가장 중요한 진단 방법입니다. 대장내시경으로 직장에서 시작하여 연속적으로 나타나는 염증, 궤양, 점막 변화를 직접 관찰하고 조직을 채취하여 병리 검사를 시행합니다. 혈액검사(빈혈, 염증 지표), 대변검사, 필요시 CT 또는 MRI 검사도 병행하며, 소화기내과 전문의의 정확한 진단이 필요합니다.', 1696, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '궤양성 대장염', '궤양성대장염', 'SYMPTOM', '궤양성 대장염의 주요 증상은 혈액과 점액이 섞인 설사, 복통, 점액성 변이며, 심한 경우 발열, 체중 감소, 빈혈, 피로감이 동반됩니다. 알코올 자체는 궤양성 대장염의 원인이 아니나 증상을 악화시킬 수 있으며, 장 외 증상으로 관절염, 피부 병변(결절성 홍반), 안구 염증(포도막염)이 나타날 수도 있습니다. 증상이 지속되거나 악화되면 소화기내과 전문의의 진료를 받으시기 바랍니다.', 1697, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '궤양성 대장염', '궤양성대장염', 'DIAGNOSIS', '혈액과 점액이 섞인 설사, 심한 복통, 탈수 등의 증상이 의심될 경우 소화기내과 전문의의 진료를 받아야 합니다. 외래 진료 시 담당 의사의 처방으로 대장내시경, 혈액검사, 대변 배양 검사 등이 시행되며, 증상이 심각하거나 고열, 심한 탈수가 동반되면 응급실을 통한 입원 진료가 필요합니다. 처방 없이 진단 검사가 진행되지 않으므로 먼저 소화기내과 외래를 방문하시기 바랍니다.', 1698, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '궤양성 대장염', '궤양성대장염', 'TREATMENT', '입원 중인 궤양성 대장염 환자의 치료에는 5-아미노살리실산(5-ASA) 계열 약물, 코르티코스테로이드 정맥 투여, 중증 스테로이드 불응성인 경우 사이클로스포린 또는 인플릭시맙 등 생물학적 제제가 사용됩니다. 충분한 수액 공급, 영양 지원(필요시 장관 영양 또는 정맥 영양), 합병증 모니터링이 병행됩니다. 내과적 치료에 반응하지 않는 중증의 경우 결장 절제술이 필요할 수 있으므로 전문의의 지속적 관리가 중요합니다.', 1699, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 A형 간염', '급성a형간염', 'DIET_LIFE', '급성 A형간염 회복을 위해 충분한 휴식이 가장 중요하며, 간에 부담을 주는 알코올, 불필요한 약물, 기름진 음식을 피해야 합니다. 소화가 잘 되는 고탄수화물, 저지방 식사로 충분한 열량을 섭취하고, 수분을 충분히 보충하세요. 회복 기간(보통 수주~수개월)에는 과로를 피하고 충분한 휴식을 취하는 것이 직장 복귀를 앞당기는 데 도움이 되며, 담당 소화기내과 전문의의 지시에 따르시기 바랍니다.', 1700, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 A형 간염', '급성a형간염', 'PREVENTION', '급성 A형간염 초기에는 식욕 부진과 구역이 심할 수 있어 적절한 영양 공급이 회복에 매우 중요합니다. 충분한 열량과 단백질 섭취는 간세포 재생을 촉진하고 면역 기능 유지를 도와 회복 기간을 단축시키는 데 기여합니다. 다만 A형간염 자체의 예방은 백신 접종과 철저한 손 위생, 안전한 음식·물 섭취가 핵심이므로, 예방 접종에 대해 소화기내과 또는 감염내과 전문의와 상담하시기 바랍니다.', 1701, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 A형 간염', '급성a형간염', 'CAUSE', '급성 A형간염의 주된 원인은 A형간염 바이러스(HAV)에 오염된 음식이나 물을 섭취하거나 감염자와의 직접 접촉에 의한 것으로, 피로감 자체가 직접적인 원인은 아닙니다. 다만 과도한 피로와 면역력 저하가 바이러스 감염 후 증상을 악화시킬 수 있습니다. HAV는 대변-구강 경로로 전파되므로 손 위생, 안전한 식수 및 음식 섭취가 중요하며, 감염이 의심되면 소화기내과 전문의를 방문하시기 바랍니다.', 1702, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 A형 간염', '급성a형간염', 'DEFINITION', '급성 A형간염은 A형간염 바이러스(HAV)에 감염되어 발생하는 급성 간 염증 질환으로, 주로 오염된 음식이나 물을 통한 대변-구강 경로로 전파됩니다. 잠복기는 15~50일이며, 발열, 피로, 식욕 부진, 황달 등이 주요 증상이고 대부분 자연 치유됩니다. 만성 간 질환으로 이행되지 않는 것이 B형·C형간염과의 주요 차이점이며, 예방 백신이 효과적으로 사용되고 있습니다.', 1703, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 A형 간염', '급성a형간염', 'SYMPTOM', '오한, 식욕 부진, 권태감, 구역, 두통 등의 증상이 지속되면 A형간염 항체 검사(anti-HAV IgM)와 간기능 검사(AST, ALT, 빌리루빈)를 통해 급성 A형간염을 진단할 수 있습니다. anti-HAV IgM 양성 소견이 급성 감염의 확진 기준이 됩니다. 해당 증상이 있으면 소화기내과 또는 내과를 방문하여 혈액검사를 받으시기 바랍니다.', 1704, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 A형 간염', '급성a형간염', 'DIAGNOSIS', '급성 A형간염 환자와 함께 생활하는 가족, 특히 감염 2주 이내에 노출된 경우 면역글로불린 주사나 A형간염 백신 접종을 고려해야 합니다. 아직 A형간염 항체가 없는 가족 구성원은 예방 접종을 받는 것이 권장되며, 감염 예방을 위해 손 위생 철저, 화장실 사용 후 공용 물품 소독이 중요합니다. 가족 구성원 모두 소화기내과 또는 감염내과 전문의와 상담하여 검사 및 예방 조치를 받으시기 바랍니다.', 1705, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 A형 간염', '급성a형간염', 'TREATMENT', '급성 A형간염의 구역질, 구토, 설사, 발열 등의 증상은 대부분 대증 치료로 관리하며, 충분한 수분 보충과 휴식이 핵심입니다. 구역·구토에는 항구역제, 발열에는 해열제(아세트아미노펜을 간 손상 정도에 맞춰 신중히 사용)가 처방될 수 있습니다. 증상이 심하거나 황달, 탈수가 심한 경우 입원하여 정맥 수액 치료를 받을 수 있으므로 소화기내과 전문의의 진료를 받으시기 바랍니다.', 1706, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 B형 간염', '급성b형간염', 'DIET_LIFE', '급성 B형 간염으로 운동이 어려울 때는 고단백·고탄수화물 식단을 유지하고 충분한 수분을 섭취하는 것이 중요합니다. 기름진 음식과 음주는 반드시 피하고, 소량씩 자주 먹는 방식이 도움이 됩니다. 반드시 소화기내과 전문의와 상담하여 개인 상태에 맞는 식이 지침을 받으세요.', 1707, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 B형 간염', '급성b형간염', 'MEDICATION', '급성 B형 간염 치료 중 일부 약물(아세트아미노펜 과량, 비스테로이드성 소염제 등)은 간에 추가적인 부담을 주어 합병증을 악화시킬 수 있습니다. 반드시 담당 소화기내과 전문의에게 현재 복용 중인 모든 약물을 알리고, 처방 없이 임의로 약을 추가하지 않아야 합니다.', 1708, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 B형 간염', '급성b형간염', 'PREVENTION', 'B형 간염 백신은 3회 접종을 완료하면 약 95% 이상에서 항체가 형성되어 급성 B형 간염과 만성화, 간경변, 간암으로의 진행을 예방할 수 있습니다. 신생아 때부터 접종이 권고되며, 항체가 없는 성인도 접종이 가능합니다. 항체 형성 여부는 접종 후 혈액검사로 확인할 수 있습니다.', 1709, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 B형 간염', '급성b형간염', 'CAUSE', '독감 예방접종 후 급성 B형 간염이 발생하는 경우는 매우 드물며, 접종 자체보다는 주사 과정에서 오염된 기구를 사용했거나 B형 간염 바이러스에 이미 노출된 상태일 가능성이 더 큽니다. 급성 B형 간염의 주된 원인은 감염된 혈액이나 체액 접촉입니다. 정확한 원인 파악을 위해 소화기내과 전문의 진료를 받으세요.', 1710, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 B형 간염', '급성b형간염', 'DEFINITION', '급성 B형 간염은 B형 간염 바이러스(HBV)에 처음 감염되어 6개월 이내에 발병하는 질환입니다. 성인의 경우 약 90~95%는 자연 회복되지만, 5~10%는 만성으로 진행될 수 있습니다. 회복 여부는 혈액검사로 확인하며, 정기적인 소화기내과 추적 관찰이 필요합니다.', 1711, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 B형 간염', '급성b형간염', 'SYMPTOM', '짙은 색 소변과 황달은 급성 B형 간염의 대표적인 증상으로, 간세포 손상으로 인해 빌리루빈이 혈중에 축적되면서 나타납니다. 이러한 증상이 있다면 급성 간염 가능성을 배제할 수 없으므로 즉시 소화기내과를 방문하여 혈액검사와 간기능 검사를 받으시기 바랍니다.', 1712, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 B형 간염', '급성b형간염', 'DIAGNOSIS', '급성 B형 간염을 의심할 때는 황달, 짙은 소변, 피로감, 식욕부진, 오심·구토, 발열, 우상복부 불쾌감 등의 증상을 의사에게 알리세요. 다른 간질환(A형·C형 간염, 지방간 등)과의 감별은 혈액검사로 HBsAg, Anti-HAV, Anti-HCV 등을 함께 확인하여 이루어집니다.', 1713, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 B형 간염', '급성b형간염', 'TREATMENT', '급성 B형 간염의 치료 기간은 대부분 4~8주이며, 성인의 경우 충분한 안정과 영양 섭취만으로도 자연 회복되는 경우가 많습니다. 다만 황달이나 피로가 심한 경우 수 개월이 걸릴 수도 있으므로, 복직 시기는 담당 소화기내과 전문의와 상의하여 결정하는 것이 안전합니다.', 1714, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 C형 간염', '급성c형간염', 'PREVENTION', '현재 C형 간염에 대한 공인된 예방 백신은 없기 때문에, 예방접종 대상자 지정보다는 고위험군 관리가 핵심입니다. 혈액투석 환자, 의료종사자, 주사 마약 사용자, 수혈 경험자 등은 정기적인 Anti-HCV 검사를 받아야 합니다. 감염 예방을 위해 혈액·체액 노출을 철저히 차단하는 것이 중요합니다.', 1715, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 C형 간염', '급성c형간염', 'CAUSE', '급성 C형 간염은 C형 간염 바이러스(HCV)에 감염된 혈액이나 체액과의 접촉을 통해 전파되며, 간세포를 손상시켜 간염, 간경변, 간암으로 진행할 수 있습니다. 약 75~85%가 만성으로 진행되는 특성이 있어 조기 발견과 치료가 매우 중요합니다. 의심 증상이 있으면 소화기내과 전문의 진료를 받으세요.', 1716, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 C형 간염', '급성c형간염', 'DEFINITION', '급성 C형 간염은 HCV 감염 후 6개월 이내의 급성기 상태로, 무증상이거나 피로감·황달·소화불량 등의 가벼운 증상이 나타납니다. 치료는 직접 작용 항바이러스제(DAA)를 사용하며, 8~12주 치료로 95% 이상의 완치율을 보입니다. 만성 C형 간염은 장기간 무증상으로 진행되다 간경변이나 간암으로 발전할 수 있습니다.', 1717, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 C형 간염', '급성c형간염', 'SYMPTOM', '피로감과 소화불량만으로는 급성 C형 간염을 단정하기 어려우며, 기능성 위장장애, 만성피로증후군 등과 증상이 유사합니다. C형 간염 여부는 Anti-HCV 혈액검사로만 확인 가능하므로, 증상이 지속된다면 소화기내과를 방문하여 정확한 검사와 진단을 받으시기 바랍니다.', 1718, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 C형 간염', '급성c형간염', 'DIAGNOSIS', '급성 C형 간염의 주요 진단 검사는 Anti-HCV 항체 검사와 HCV RNA 정량 검사(PCR)입니다. 항체 검사가 양성이면 HCV RNA 검사로 현재 감염 여부를 확인하고, 바이러스 유전자형 검사도 시행합니다. 간기능 검사(AST, ALT)를 통해 간 손상 정도를 평가합니다.', 1719, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 C형 간염', '급성c형간염', 'TREATMENT', '급성 C형 간염의 치료는 주로 직접 작용 항바이러스제(DAA) 경구 복용이 표준 치료로, 8~12주 투약으로 95% 이상 완치가 가능합니다. 충분한 수분 섭취와 안정이 도움이 되며, 음주와 간독성 약물은 피해야 합니다. 치료 방법과 기간은 소화기내과 전문의와 상담하여 결정하세요.', 1720, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 담낭염', '급성담낭염', 'CHECKUP', '급성 담낭염 치료(수술 또는 항생제 치료) 후에는 통증 완화, 염증 감소, 발열 해소 등의 효과를 기대할 수 있습니다. 부작용으로는 항생제 사용 시 구역감·설사, 수술 시 출혈·감염·담즙 누출 등이 드물게 발생할 수 있습니다. 치료 후에도 이상 증상이 있으면 담당 외과 전문의에게 즉시 알리세요.', 1721, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 담낭염', '급성담낭염', 'MEDICATION', '윗배 압통과 부분적인 통증이 있다면 임의로 약을 복용하기보다 먼저 소화기내과나 외과 전문의의 진찰을 받는 것이 중요합니다. 급성 담낭염이 확인되면 항생제와 진통제가 처방될 수 있으며, 경우에 따라 담낭 절제술이 필요합니다. 자가 판단으로 진통제를 복용하면 증상 악화를 놓칠 수 있으므로 전문의 상담이 우선입니다.', 1722, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 담낭염', '급성담낭염', 'CAUSE', '속이 더부룩하고 배가 아픈 증상이 급성 담낭염에 의한 것이라면, 주된 원인은 담석이나 세균 감염으로 인한 담낭 염증입니다. 치료는 금식, 수액 공급, 항생제 투여가 기본이며, 담석이 동반된 경우 복강경 담낭 절제술이 가장 효과적입니다. 정확한 진단을 위해 소화기내과 또는 외과 전문의 진료를 받으세요.', 1723, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 담낭염', '급성담낭염', 'DEFINITION', '급성 담낭염의 주요 치료법은 항생제 투여와 복강경 담낭 절제술이며, 수술 전후 금식이 필요합니다. 치료 중 고지방 음식 섭취를 피하고, 수술 후에는 저지방 식단을 유지해야 합니다. 담당 외과 전문의의 지시를 철저히 따르고, 발열·복통이 악화되면 즉시 응급실을 방문하세요.', 1724, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 담낭염', '급성담낭염', 'SYMPTOM', '지속적인 오심과 구토는 급성 담낭염 외에도 급성 위장염, 위궤양, 췌장염, 장폐색 등 다양한 질환에서 나타날 수 있습니다. 특히 우상복부 통증이 동반된다면 급성 담낭염 가능성이 높으므로, 소화기내과나 응급실을 방문하여 복부 초음파 검사를 받는 것이 중요합니다.', 1725, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 담낭염', '급성담낭염', 'DIAGNOSIS', '호흡 시 통증이 있고 급성 담낭염이 의심된다면 소화기내과 또는 외과가 있는 병원을 방문하세요. 복부 초음파와 혈액검사를 통해 진단이 이루어지며, 증상이 심한 경우 응급실 방문이 필요할 수 있습니다. 통증이 갑자기 심해지거나 고열이 동반되면 즉시 응급처치를 받으세요.', 1726, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 담낭염', '급성담낭염', 'TREATMENT', '담석에 의한 담낭 통증(담도산통) 완화를 위해 진경제(항경련제)와 진통제가 사용되며, 금식과 수액 요법도 시행됩니다. 근본적인 치료는 복강경 담낭 절제술로 담낭을 제거하는 것이며, 이를 통해 재발을 예방할 수 있습니다. 증상이 반복된다면 소화기내과 또는 외과 전문의 상담을 받으세요.', 1727, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 바이러스성 간염', '급성바이러스성간염', 'DIET_LIFE', '급성 바이러스성 간염 예방을 위해 어린 아이들은 손씻기를 철저히 하고, 안전하게 조리된 음식만 먹어야 합니다. B형 간염 예방접종은 출생 직후부터 시작하며, A형 간염 예방접종도 12~23개월에 시행합니다. 청결한 식습관과 규칙적인 생활, 충분한 수면으로 면역력을 유지하는 것이 중요합니다.', 1728, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 바이러스성 간염', '급성바이러스성간염', 'PREVENTION', '균형 잡힌 식단과 충분한 수면, 규칙적인 운동은 면역력을 강화하여 급성 바이러스성 간염 감염 위험을 낮추는 데 도움이 됩니다. 특히 A형 간염은 오염된 식수·음식을 통해 전파되므로 위생 관리가 중요하며, B형·C형 간염 예방접종도 효과적인 예방법입니다. 전문의 상담을 통해 예방접종 일정을 확인하세요.', 1729, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 바이러스성 간염', '급성바이러스성간염', 'CAUSE', '급성 바이러스성 간염의 가장 흔한 원인은 A형·B형·C형 간염 바이러스입니다. A형은 오염된 음식이나 물을 통한 경구 감염, B형과 C형은 감염된 혈액·체액 접촉이나 성 접촉을 통해 전파됩니다. 각 바이러스의 전파 경로가 다르므로 예방 방법도 달리 접근해야 합니다.', 1730, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 바이러스성 간염', '급성바이러스성간염', 'DEFINITION', '급성 바이러스성 간염은 전염성이 있으며, A형은 분변-경구 경로, B형·C형은 혈액·체액을 통해 전파됩니다. 입대 후 집단생활에서 A형 간염이 발생한 경우 신속한 격리와 예방접종이 필요합니다. 회복 후에도 만성화 여부, 간 손상 후유증 여부를 소화기내과에서 정기적으로 확인하는 것이 중요합니다.', 1731, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 바이러스성 간염', '급성바이러스성간염', 'SYMPTOM', '발열, 황달, 식욕부진, 권태감은 급성 바이러스성 간염의 전형적인 증상으로, 바이러스 감염 후 2~6주의 잠복기를 거쳐 나타납니다. 이러한 증상은 황달기에 가장 뚜렷하게 나타나며, 소변이 짙어지고 대변이 연한 색으로 변하기도 합니다. 증상이 나타나면 즉시 소화기내과 전문의를 방문하세요.', 1732, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 바이러스성 간염', '급성바이러스성간염', 'DIAGNOSIS', '급성 바이러스성 간염의 진단에는 혈액검사(ALT, AST, 빌리루빈)와 바이러스 항원·항체 검사(HBsAg, Anti-HAV IgM 등)가 가장 일반적으로 사용됩니다. 필요에 따라 복부 초음파 검사로 간의 형태와 크기를 확인하기도 합니다. 정확한 진단을 위해 소화기내과를 방문하여 적절한 검사를 받으세요.', 1733, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 바이러스성 간염', '급성바이러스성간염', 'TREATMENT', '급성 바이러스성 간염의 대부분은 충분한 안정, 수분 섭취, 균형 잡힌 영양 공급으로 자연 회복됩니다. 음주와 간독성 약물은 반드시 피해야 하며, 심한 경우 입원하여 수액 치료를 받습니다. 특정 바이러스 유형(B형·C형)에는 항바이러스제 치료가 필요할 수 있으므로 소화기내과 전문의 지침을 따르세요.', 1734, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 위장염', '급성위장염', 'DIET_LIFE', '급성 위장염 치료에 사용되는 수액, 지사제, 제토제 등은 의사의 지시에 따라 사용하면 대부분 안전합니다. 다만 지사제는 일부 세균성 감염에서 사용을 제한할 수 있으므로 임의 복용은 피하세요. 약물 복용 시 어지러움이나 알레르기 반응이 나타나면 즉시 의사에게 알려야 합니다.', 1735, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 위장염', '급성위장염', 'CAUSE', '밀가루 음식, 과식, 튀긴 음식은 위장의 운동을 더디게 하고 소화 효소 분비에 부담을 주어 급성 위장염 증상을 악화시킬 수 있습니다. 특히 기름진 음식은 위 점막을 자극하고 소화 시간을 늘려 오심·구토·복통을 유발합니다. 회복 중에는 죽, 미음 등 소화하기 쉬운 음식 위주로 섭취하는 것이 좋습니다.', 1736, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 위장염', '급성위장염', 'DEFINITION', '매운 음식을 먹은 후 위 통증과 팽만감이 나타나는 것은 급성 위장염의 증상일 수 있지만, 위염이나 과민성 장증후군의 증상과도 유사합니다. 증상이 반복되거나 지속된다면 소화기내과 전문의 진료를 받아 정확한 진단을 받는 것이 중요합니다. 자극적인 음식을 피하고 식사 습관을 개선하는 것이 도움이 됩니다.', 1737, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 위장염', '급성위장염', 'SYMPTOM', '복통, 구토, 설사, 복부 팽만감은 급성 위장염의 일반적인 증상입니다. 세균이나 바이러스에 의한 감염, 음식 독소 등이 원인이 되며, 대부분 수일 내 회복됩니다. 증상이 3일 이상 지속되거나 혈변, 고열이 동반된다면 반드시 소화기내과를 방문하여 진료를 받으세요.', 1738, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 위장염', '급성위장염', 'DIAGNOSIS', '복통을 동반한 급성 위장염 진단은 소화기내과 또는 내과에서 받을 수 있습니다. 증상이 심하거나 탈수 증상(어지러움, 극심한 갈증, 소변 감소 등)이 있으면 응급실을 방문하는 것이 좋습니다. 가까운 내과 또는 소화기내과 의원을 방문하여 정확한 진단과 치료를 받으세요.', 1739, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 위장염', '급성위장염', 'TREATMENT', '급성 위장염에 대한 한방 치료(침, 뜸, 부황 등)는 보조적으로 활용될 수 있으나, 효과에 대한 과학적 근거는 제한적입니다. 급성 위장염의 우선 치료는 수액 보충, 전해질 균형 유지, 원인 제거입니다. 한방 치료를 원한다면 반드시 의사나 한의사와 상담하고, 탈수가 심한 경우에는 즉시 내과적 치료를 받으세요.', 1740, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 충수염', '급성충수염', 'CHECKUP', '급성 충수염 수술을 받은 가족이 있더라도, 충수염은 유전 질환이 아니므로 다른 가족 구성원이 특별히 위험하지는 않습니다. 다만 복통, 발열, 구역감 등의 증상이 나타나면 즉시 외과나 응급실을 방문하여 진찰을 받는 것이 중요합니다. 정기적인 건강검진을 통해 전반적인 건강 상태를 확인하세요.', 1741, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 충수염', '급성충수염', 'MEDICATION', '급성 충수염 환자가 열이 날 때 타이레놀(아세트아미노펜)을 단기간 복용하는 것은 일반적으로 가능하지만, 복용 전에 반드시 담당 외과 전문의의 지시를 따라야 합니다. 진통제 복용이 복통 증상을 일시적으로 가릴 수 있어 진단을 어렵게 만들 수 있으므로, 자가 판단보다는 전문의 지침을 받으세요.', 1742, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 충수염', '급성충수염', 'CAUSE', '급성 충수염은 충수 내강이 막힘으로써 발생하며, 분석(딱딱해진 대변 덩어리), 이물질, 종양, 기생충 등이 막힘의 원인이 될 수 있습니다. 내강이 막히면 충수 내 압력이 높아지고 혈류가 감소하면서 세균 번식과 염증이 발생합니다. 이러한 경우 즉각적인 외과적 치료가 필요하므로 전문의 진료를 받으세요.', 1743, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 충수염', '급성충수염', 'DEFINITION', '급성 충수염은 충수에 염증이 생기는 질환으로, 초기에는 배꼽 주변 통증으로 시작해 점차 우하복부(맥버니 포인트)로 이동합니다. 열, 복부 통증, 오심·구토, 식욕부진이 주요 증상이며, 24~72시간 내에 천공될 수 있는 응급 질환입니다. 해당 증상이 있으면 즉시 응급실이나 외과를 방문하세요.', 1744, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 충수염', '급성충수염', 'SYMPTOM', '오른쪽 아랫배 압통과 복부 팽만감, 설사, 기침 시 통증 악화는 급성 충수염에서 흔히 나타나는 증상입니다. 특히 기침이나 움직임에 의해 통증이 심해지는 것은 복막 자극 징후로, 즉각적인 진료가 필요합니다. 이러한 증상이 있다면 지체하지 말고 응급실이나 외과를 방문하세요.', 1745, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 충수염', '급성충수염', 'DIAGNOSIS', '배꼽 주위 복통으로 급성 충수염이 의심된다면 외과 전문의에게 진단을 받아야 합니다. 초기에는 소화기내과를 방문하더라도 충수염이 의심되면 외과로 의뢰됩니다. 증상이 심하거나 야간에 발생한 경우 즉시 응급실을 방문하여 복부 초음파 또는 CT 검사를 받으세요.', 1746, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 충수염', '급성충수염', 'TREATMENT', '급성 충수염의 약물 치료로는 항생제(세팔로스포린계, 메트로니다졸 등)와 진통제가 사용됩니다. 항생제 단독 치료가 경증에서 시도되기도 하지만, 재발률이 있어 복강경 충수 절제술이 표준 치료입니다. 약물 선택과 수술 결정은 반드시 외과 전문의와 상담하여 이루어져야 합니다.', 1747, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 췌장염', '급성췌장염', 'PREVENTION', '갈비뼈에서 날개뼈까지 이어지는 찌르는 듯한 통증은 급성 췌장염의 특징적인 증상일 수 있습니다. 예방을 위해 음주를 중단하고 담석이 있는 경우 조기 치료를 받는 것이 중요합니다. 이러한 통증이 있다면 즉시 소화기내과나 응급실을 방문하여 정확한 진단을 받으세요.', 1748, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 췌장염', '급성췌장염', 'CAUSE', '급성 췌장염의 주요 원인은 담석(40~70%)과 알코올 남용(25~35%)이며, 두 요인은 서로 독립적으로 작용합니다. 담석이 총담관을 막으면 췌장액 흐름이 방해되고, 알코올은 췌장 효소를 직접 활성화시켜 염증을 유발합니다. 두 원인이 동시에 있을 경우 췌장염 위험이 더욱 높아집니다.', 1749, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 췌장염', '급성췌장염', 'DEFINITION', '급성 췌장염은 췌장에 급성 염증이 발생하여 복부 통증, 오심·구토, 발열이 나타나는 질환입니다. 소화가 잘 안 되고 더부룩한 증상만으로는 췌장염을 단정할 수 없으며, 혈액검사(아밀라아제, 리파아제 수치 상승)와 복부 CT로 확인합니다. 증상이 의심된다면 소화기내과 전문의 진료를 받으세요.', 1750, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 췌장염', '급성췌장염', 'SYMPTOM', '급성 췌장염 환자가 반듯이 누우면 통증이 심해지고 앞으로 구부리면 완화되는 특징적인 자세 통증과 함께 구토가 나타나는 것은 전형적인 급성 췌장염 징후입니다. 심한 상복부 통증과 오심·구토가 동반된다면 즉시 응급실을 방문하여 혈액검사와 CT 촬영을 받으세요.', 1751, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 췌장염', '급성췌장염', 'DIAGNOSIS', '급성 췌장염의 원인 파악에는 복부 초음파가 담석 확인에 우선 사용되며, 혈액검사(아밀라아제, 리파아제, 간기능 검사)로 중증도를 평가합니다. CT 촬영은 췌장 괴사나 합병증 확인에 효과적이며, MRCP는 담관 상태 파악에 유용합니다. MRI 단독보다 CT와 혈액검사 조합이 더 효과적으로 사용됩니다.', 1752, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '급성 췌장염', '급성췌장염', 'TREATMENT', '과도한 음주는 췌장 효소를 조기 활성화시켜 급성 췌장염을 일으킵니다. 염증 억제를 위해 즉각적인 금식과 수액 치료가 가장 중요하며, 진통제와 항생제(감염 동반 시)가 사용됩니다. 음주를 반드시 중단해야 하며, 소화기내과 전문의의 지속적인 관리와 치료를 받으세요.', 1753, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '기능성 위장 장애', '기능성위장장애', 'DIET_LIFE', '기능성 위장 장애로 인한 가스 팽만에는 소화가 잘 되는 음식(쌀밥, 두부, 흰살 생선)을 선택하고, 가스를 유발하는 콩류·양배추·탄산음료를 제한하는 것이 좋습니다. 소량씩 천천히 먹고 규칙적인 식사를 유지하면 증상 완화에 도움이 됩니다. 증상이 지속되면 소화기내과 전문의 상담을 받으세요.', 1754, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '기능성 위장 장애', '기능성위장장애', 'PREVENTION', '자녀의 야간 수면 장애가 기능성 위장 장애와 관련된 경우, 취침 2시간 전 과식이나 자극적인 음식을 피하게 하고, 규칙적인 식사와 취침 시간을 유지하는 것이 도움이 됩니다. 스트레스와 불안이 증상을 악화시킬 수 있으므로 심리적 안정도 중요합니다. 증상이 지속되면 소아청소년과 전문의 진료를 받으세요.', 1755, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '기능성 위장 장애', '기능성위장장애', 'CAUSE', '기능성 위장 장애는 기질적 원인 없이 복통, 변비, 팽만감 등의 증상이 발생하는 질환으로, 내장 과민성과 장-뇌 축 기능 이상이 주요 기전으로 알려져 있습니다. 스트레스, 불규칙한 식사, 장내 미생물 불균형 등이 증상을 유발하거나 악화시킵니다. 정확한 진단을 위해 소화기내과 전문의 진료가 필요합니다.', 1756, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '기능성 위장 장애', '기능성위장장애', 'DEFINITION', '속쓰림, 더부룩함, 구토, 소화불량이 반복적으로 나타나고 내시경 등 검사에서 기질적 원인이 없는 경우 기능성 위장 장애(기능성 소화불량)를 의심할 수 있습니다. 다만 위염, 위궤양, 역류성 식도염 등과 증상이 유사하므로, 소화기내과에서 정확한 검사와 감별 진단을 받는 것이 중요합니다.', 1757, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '기능성 위장 장애', '기능성위장장애', 'SYMPTOM', '기능성 위장 장애의 주요 증상으로는 식후 포만감, 조기 포만, 명치 통증, 소화불량, 복부 팽만감, 변비 또는 설사가 있습니다. 관리를 위해서는 규칙적인 식사, 스트레스 관리, 자극적인 음식 제한, 적절한 운동이 도움이 됩니다. 증상이 심하거나 지속될 경우 소화기내과 전문의 진료를 받으세요.', 1758, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '기능성 위장 장애', '기능성위장장애', 'DIAGNOSIS', '기능성 위장 장애로 진단받으려면 소화기내과에서 위내시경, 복부 초음파, 혈액검사 등을 통해 기질적 질환(위궤양, 위암, 담석 등)을 먼저 배제해야 합니다. 로마 기준(Rome criteria)에 따라 6개월 이상 증상이 있고, 최근 3개월간 기준을 충족할 때 진단됩니다. 소화기내과 전문의 진료를 받으세요.', 1759, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '기능성 위장 장애', '기능성위장장애', 'TREATMENT', '스트레스 관련 기능성 위장 장애 치료로는 소화관 운동 촉진제, 위산 억제제, 항불안제 또는 항우울제(저용량)가 사용될 수 있습니다. 인지행동치료와 스트레스 관리도 효과적인 치료법입니다. 담당 소화기내과 전문의의 처방과 지도에 따라 치료 방법을 결정하는 것이 중요합니다.', 1760, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '노로바이러스 장염', '노로바이러스장염', 'DIET_LIFE', '노로바이러스 장염으로 설사가 악화될 때는 유제품, 기름진 음식, 설탕이 많은 음료, 고섬유질 식품, 카페인을 피해야 합니다. 맑은 국물, 전해질 음료, 죽, 바나나 등 소화하기 쉬운 음식이 도움이 되며, 충분한 수분 섭취로 탈수를 예방하는 것이 핵심입니다. 증상이 심하면 내과 전문의 진료를 받으세요.', 1761, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '노로바이러스 장염', '노로바이러스장염', 'PREVENTION', '노로바이러스 장염에는 현재 승인된 특효약이 없으며, 충분한 수분 보충이 가장 중요한 치료입니다. 끓인 물이나 정수된 물 모두 사용 가능하지만, 구토·설사로 인한 전해질 손실 보충을 위해 경구용 전해질 용액이 더 효과적입니다. 증상이 심하거나 탈수가 의심되면 의료기관을 방문하세요.', 1762, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '노로바이러스 장염', '노로바이러스장염', 'CAUSE', '노로바이러스 장염은 오염된 음식(특히 굴 등 패류), 물, 감염자와의 접촉, 오염된 표면을 만진 손으로 입을 통해 전파됩니다. 노로바이러스가 소장 점막을 감염시키면 장 흡수 기능이 저하되어 설사, 메스꺼움, 복부 경련이 발생합니다. 예방을 위해 손씻기와 음식 위생 관리가 가장 중요합니다.', 1763, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '노로바이러스 장염', '노로바이러스장염', 'DEFINITION', '노로바이러스 장염은 노로바이러스 감염에 의해 발생하는 급성 위장관 질환으로, 오심·구토·설사·복통이 주요 증상이며 보통 1~3일 내에 자연 회복됩니다. 아기에게 설사가 나타나면 탈수 예방이 중요하므로 모유나 분유를 지속하고, 전해질 용액을 보충하며, 증상이 지속되면 소아청소년과 전문의를 방문하세요.', 1764, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '노로바이러스 장염', '노로바이러스장염', 'SYMPTOM', '노로바이러스 장염에 걸린 아이는 구토와 설사가 급격히 시작되며, 1~3일 내 회복되는 경우가 많습니다. 어린이에서 특히 탈수 위험이 높으므로 수분 보충이 중요하며, 발열, 혈변, 지속적인 구토가 있다면 즉시 소아청소년과를 방문해야 합니다. 증상이 심한 경우 입원 치료가 필요할 수 있습니다.', 1765, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '노로바이러스 장염', '노로바이러스장염', 'DIAGNOSIS', '굴 보쌈 섭취 후 설사·복통·구토가 나타난 경우 노로바이러스 감염 또는 식중독이 의심됩니다. 증상만으로는 정확한 원인을 구별하기 어려우므로 정확한 진단과 적절한 치료를 위해 내과를 방문하는 것이 중요합니다. 탈수 방지를 위해 수분을 충분히 섭취하고 증상이 지속되면 즉시 진료를 받으세요.', 1766, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '노로바이러스 장염', '노로바이러스장염', 'TREATMENT', '노로바이러스 장염에는 항생제가 효과가 없으며, 충분한 수분 및 전해질 보충이 핵심 치료입니다. 보조적으로 지사제(로페라미드)와 제토제가 사용될 수 있으나, 어린이에게는 신중하게 사용해야 합니다. 탈수가 심하면 정맥 수액 치료가 필요하며, 내과 전문의의 처방에 따르는 것이 중요합니다.', 1767, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담낭 용종', '담낭용종', 'CHECKUP', '담낭 용종 진단에는 복부 초음파가 가장 기본적이고 효과적인 검사입니다. 위내시경이나 대장내시경은 담낭 용종 진단에 직접적으로 사용되지 않으며, 내시경 초음파(EUS)가 담낭 용종 정밀 평가에 도움이 됩니다. 담당 소화기내과 전문의와 상담하여 적절한 검사를 받으세요.', 1768, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담낭 용종', '담낭용종', 'DIET_LIFE', '담낭 용종이 있는 경우 저지방·저콜레스테롤 식단을 유지하고 포화지방과 가공식품 섭취를 줄이는 것이 좋습니다. 규칙적인 운동으로 적정 체중을 유지하고, 음주를 제한하며, 정기적인 복부 초음파 추적 검사를 받는 것이 중요합니다. 담낭 용종 관리를 위해 소화기내과 전문의와 상담하세요.', 1769, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담낭 용종', '담낭용종', 'PREVENTION', '비만은 콜레스테롤 대사 이상을 유발하여 담낭 용종 발생 위험을 높일 수 있습니다. 포화지방과 콜레스테롤이 많은 음식을 줄이고, 채소와 과일 위주의 식단을 유지하며, 규칙적인 운동으로 정상 체중을 유지하는 것이 담낭 용종 예방에 도움이 됩니다. 정기 건강검진으로 조기 발견하는 것도 중요합니다.', 1770, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담낭 용종', '담낭용종', 'CAUSE', '담낭 용종의 원인은 콜레스테롤 침착(콜레스테롤 용종이 가장 흔함), 만성 염증, 담석 동반, 드물게 선종성 변화 등입니다. 비만, 고지혈증, 당뇨 등 대사 질환이 위험 인자로 작용하며, 용종의 크기와 특성에 따라 악성 변환 위험도가 달라집니다. 정기적인 초음파 추적과 전문의 상담이 중요합니다.', 1771, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담낭 용종', '담낭용종', 'DEFINITION', '체중 감소 단독으로는 담낭 용종의 증상이라고 보기 어렵습니다. 담낭 용종은 대부분 무증상이며, 우상복부 불쾌감이나 소화불량이 나타날 수 있습니다. 체중 감소가 걱정된다면 소화기내과나 내과에서 담낭 용종 여부와 함께 다른 원인에 대한 종합 검진을 받으시기 바랍니다.', 1772, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담낭 용종', '담낭용종', 'SYMPTOM', '담낭 용종은 대부분 무증상이지만, 크기가 크거나 담석이 동반된 경우 명치 불편함이나 우상복부 통증이 나타날 수 있습니다. 이 불편함은 담즙 흐름이 방해되거나 담낭 수축 시 용종이 자극을 주기 때문입니다. 증상이 지속된다면 소화기내과를 방문하여 초음파 검사를 받으세요.', 1773, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담낭 용종', '담낭용종', 'DIAGNOSIS', '담낭 용종 진단에는 복부 초음파가 가장 효과적이고 비침습적인 1차 검사입니다. 10mm 이상의 용종이나 악성 의심 소견이 있을 때는 내시경 초음파(EUS)나 복부 CT·MRI를 추가로 시행합니다. 정기적인 초음파 추적이 중요하므로 소화기내과 전문의와 상담하여 검사 일정을 정하세요.', 1774, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담낭 용종', '담낭용종', 'TREATMENT', '담낭 용종 치료에는 경과 관찰(정기 초음파), 복강경 담낭 절제술이 주로 사용됩니다. 수술이 필요한 경우 복강경을 이용한 최소침습 수술이 시행되며, 일반적인 수술실 및 복강경 장비가 사용됩니다. 용종의 크기(10mm 이상)와 악성 위험도에 따라 치료 방법이 결정되므로 외과 전문의와 상담하세요.', 1775, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담석', '담석', 'DIET_LIFE', '담석 예방을 위해 물을 충분히 마시고, 소량씩 자주 식사하며, 단백질을 균형 있게 섭취하는 것이 좋습니다. 추가로 과체중이라면 점진적으로 체중을 줄이고(급격한 감량은 오히려 위험), 포화지방과 콜레스테롤이 많은 음식을 제한하며 규칙적인 운동을 병행하는 것이 도움이 됩니다.', 1776, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담석', '담석', 'MEDICATION', '담석증 치료에는 우르소데옥시콜산(UDCA) 같은 담즙산 제제가 콜레스테롤 담석 용해에 사용될 수 있습니다. 그러나 약물 효과가 제한적이고 재발률이 높아, 증상이 있는 담석의 표준 치료는 복강경 담낭 절제술입니다. 약물 치료 여부는 담당 소화기내과 전문의와 상담하여 결정하세요.', 1777, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담석', '담석', 'PREVENTION', '담석 재발 예방을 위해 과식을 피하고 규칙적인 식사를 유지하며, 고지방·고콜레스테롤 음식(삼겹살, 튀김 등)을 제한하는 것이 좋습니다. 충분한 수분 섭취와 적정 체중 유지, 규칙적인 운동도 중요합니다. 담석 재발이 잦다면 소화기내과에서 담낭 절제술 필요성에 대해 상담하세요.', 1778, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담석', '담석', 'CAUSE', '담석은 담낭 내 담즙 성분(콜레스테롤, 빌리루빈, 칼슘염)이 과포화되어 결정화·응집된 것입니다. 위경련과 심한 복통(담도산통)은 담석이 담낭관을 막을 때 발생합니다. 초음파로 담석이 발견되면 소화기내과 또는 외과 전문의와 상담하여 치료 계획을 세워야 합니다.', 1779, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담석', '담석', 'DEFINITION', '담석은 담낭이나 담관 내에 생기는 돌로, 콜레스테롤이나 빌리루빈이 과포화되어 결정을 형성한 것입니다. 비만, 급격한 체중 감소, 고지방 식단, 임신, 당뇨병 등이 위험 인자이며, 담석이 담관을 막으면 담도산통, 황달, 담낭염, 췌장염 등을 유발할 수 있습니다.', 1780, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담석', '담석', 'SYMPTOM', '소화불량, 상복부 통증, 메스꺼움이 지속되고 소화제로도 호전되지 않는다면 담석 가능성을 배제할 수 없습니다. 담석 진단을 위해 복부 초음파 검사가 기본이며, 소화기내과를 방문하여 정확한 진단을 받는 것을 권장합니다. 고지방 식사 후 증상이 악화된다면 담석 가능성이 더 높습니다.', 1781, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담석', '담석', 'DIAGNOSIS', '왼쪽 상복부 통증의 경우 담석보다는 위, 비장, 췌장 등과 관련된 질환이 더 의심됩니다. 소화기내과 전문의를 방문하여 복부 초음파, 위내시경 등 적절한 검사를 통해 정확한 원인을 파악하는 것이 중요합니다. 통증이 갑자기 심해지거나 발열이 동반되면 즉시 응급실을 방문하세요.', 1782, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '담석', '담석', 'TREATMENT', '담석 치료에서 내시경적 역행성 담췌관 조영술(ERCP)은 담관 내 담석을 제거하는 데 사용됩니다. 이 시술로 담관 담석을 제거하면 담즙 흐름이 회복되고 황달, 담관염, 췌장염 등의 합병증을 예방할 수 있습니다. 담낭 담석의 경우에는 복강경 담낭 절제술이 표준 치료입니다.', 1783, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '대장 용종', '대장용종', 'CHECKUP', '대장 용종 진단에는 대장내시경이 가장 정확하고 직접적인 방법으로, 용종 발견 즉시 제거도 가능합니다. 대장내시경이 어려운 경우 CT 대장조영술(가상 대장내시경)을 시행할 수 있습니다. 50세 이상 또는 가족력이 있는 경우 정기적인 대장내시경 검진을 받는 것이 중요합니다.', 1784, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '대장 용종', '대장용종', 'DIET_LIFE', '변비 완화를 위해 하루 25~30g의 식이섬유(채소, 과일, 통곡물)를 충분히 섭취하고, 하루 1.5~2리터의 물을 마시는 것이 중요합니다. 규칙적인 식사와 아침 식사 후 화장실 가는 습관을 들이고, 매일 30분 이상 걷기 등 신체 활동을 늘리면 도움이 됩니다.', 1785, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '대장 용종', '대장용종', 'PREVENTION', '대장 용종 제거 후 재발 예방을 위해 붉은 고기와 가공육 섭취를 줄이고, 채소·과일·통곡물 위주의 식단을 유지하세요. 음주와 흡연을 삼가고 규칙적인 운동으로 적정 체중을 유지하는 것이 중요합니다. 담당 소화기내과 전문의의 지시에 따라 정기적인 대장내시경 추적 검사를 반드시 받아야 합니다.', 1786, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '대장 용종', '대장용종', 'CAUSE', '대장 용종은 대장 내벽에 비정상적으로 자라는 조직으로, 주로 유전적 요인, 고지방·저섬유질 식단, 비만, 흡연, 음주, 고령이 원인으로 작용합니다. 일부 용종은 시간이 지나면서 대장암으로 발전할 수 있어 대장내시경 시 발견되면 즉시 제거하는 것이 권장됩니다.', 1787, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '대장 용종', '대장용종', 'DEFINITION', '식이섬유 섭취 부족은 대장 내 통과 시간을 늘리고 발암물질과 점막의 접촉 시간을 증가시켜 대장 용종 및 대장암 발병 위험을 높일 수 있습니다. 하루 25~30g의 식이섬유 섭취, 과일·채소·통곡물 위주의 식단이 대장 건강에 도움이 됩니다. 정기적인 대장내시경으로 조기 발견하는 것이 중요합니다.', 1788, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '대장 용종', '대장용종', 'SYMPTOM', '변비, 복통, 가스는 대장 용종의 증상일 수 있으나, 두통과 피로감은 대장 용종과 직접적인 연관성이 낮습니다. 대장 용종은 대부분 무증상이지만, 증상이 지속된다면 소화기내과에서 대장내시경 검사를 통해 확인하는 것이 좋습니다. 정기 건강검진 시 대장내시경을 포함하여 검사를 받으세요.', 1789, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '대장 용종', '대장용종', 'DIAGNOSIS', '대장 용종 확인을 위한 가장 효과적인 검사는 대장내시경으로, 직접 관찰하고 조직 검사 및 제거까지 동시에 가능합니다. 대장내시경 외에 CT 대장조영술(가상 내시경), 대변 잠혈 검사 등도 보조 검사로 활용됩니다. 50세 이상은 5~10년마다 대장내시경을 받는 것이 권장됩니다.', 1790, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '대장 용종', '대장용종', 'TREATMENT', '대장 용종 치료의 가장 효과적이고 안전한 방법은 대장내시경을 이용한 내시경적 용종 절제술입니다. 크기가 크거나 악성이 의심되는 경우 수술이 필요할 수 있습니다. 제거 후에는 반드시 정기적인 추적 대장내시경을 받아야 하며, 담당 소화기내과 전문의의 지시를 따르세요.', 1791, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '덤핑 증후군', '덤핑증후군', 'DIET_LIFE', '덤핑 증후군에서 식사 중 또는 식후 2시간까지 수분 섭취를 제한하는 이유는 수분이 위에서 소장으로의 음식 이동 속도를 빠르게 하여 증상을 악화시킬 수 있기 때문입니다. 이 제한은 초기 덤핑 증상(오심, 설사, 복통)을 줄이는 데 도움이 됩니다. 식이 요법 세부 사항은 담당 전문의와 상담하여 개인 상태에 맞게 조절하세요.', 1792, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '덤핑 증후군', '덤핑증후군', 'MEDICATION', '덤핑 증후군 치료에 사용되는 약물로는 옥트레오타이드(소마토스타틴 유사체)가 위장관 운동을 억제하고 인슐린 분비를 조절하여 효과적입니다. 아카보스는 후기 덤핑(저혈당)에 사용될 수 있으며, 지사제나 소화 효소 보충제도 보조적으로 사용됩니다. 약물 선택은 담당 외과 또는 내과 전문의와 상담하세요.', 1793, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '덤핑 증후군', '덤핑증후군', 'PREVENTION', '식사 속도가 빠를수록 음식이 소장으로 빠르게 이동하여 덤핑 증후군 증상(오심, 복통, 설사, 어지러움)이 심해집니다. 천천히 씹어 먹고 소량씩 나누어 먹으면 소장으로의 급격한 음식 유입을 줄여 회복을 촉진합니다. 식사 속도 조절은 덤핑 증후군 관리의 핵심 요소입니다.', 1794, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '덤핑 증후군', '덤핑증후군', 'CAUSE', '덤핑 증후군은 위 절제술 후 위 내용물이 소장으로 너무 빠르게 이동하면서 발생합니다. 초기 덤핑은 수술 후 30분 이내에 오심, 구토, 복통, 설사, 빈맥이 나타나며, 소장 내 삼투압 변화와 호르몬 분비 이상이 원인입니다. 이는 위 절제술의 흔한 합병증이므로 전문의와의 지속적인 상담이 필요합니다.', 1795, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '덤핑 증후군', '덤핑증후군', 'DEFINITION', '어지러움, 눈 흐림, 속 답답함, 구토, 복통이 식후에 반복적으로 나타난다면 덤핑 증후군 증상과 유사합니다. 그러나 이러한 증상은 저혈당, 전정 기능 이상, 기능성 위장 장애 등 다른 질환과도 겹칠 수 있습니다. 정확한 진단을 위해 소화기내과 전문의 진료를 받으시기 바랍니다.', 1796, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '덤핑 증후군', '덤핑증후군', 'SYMPTOM', '복부 팽창감과 구토가 식후에 반복적으로 나타난다면 덤핑 증후군의 진단 기준에 해당할 수 있습니다. 특히 위 수술 이력이 있는 경우 가능성이 높습니다. 그러나 단순히 증상만으로 진단하기 어려우므로, 소화기내과 또는 외과 전문의 진료와 검사를 통해 확인하는 것이 필요합니다.', 1797, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '덤핑 증후군', '덤핑증후군', 'DIAGNOSIS', '식후 메스꺼움, 어지러움, 복통이 반복된다면 덤핑 증후군 가능성이 있으며, 소화기내과(위 수술 이력이 있는 경우 외과)를 방문하세요. 대형 병원의 소화기내과나 상급 종합병원 외과에서 전문적인 진료와 덤핑 검사를 받을 수 있습니다. 위 절제술 이력을 의사에게 반드시 알리세요.', 1798, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '덤핑 증후군', '덤핑증후군', 'TREATMENT', '덤핑 증후군 환자는 소량씩 6회 이상 나누어 먹고, 단순당(설탕, 사탕, 과일주스)과 고삼투압 음식을 피해야 합니다. 단백질과 복합 탄수화물 위주의 식단을 유지하고, 식사 중 수분 섭취는 제한합니다. 지방은 적당히 섭취하며, 고섬유질 식품이 증상 완화에 도움이 될 수 있습니다.', 1799, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 B형 간염', '만성b형간염', 'CHECKUP', '만성 B형 간염 검진은 내과 또는 소화기내과에서 받을 수 있으며, 혈액검사(HBsAg, HBeAg, HBV DNA 등)와 간기능 검사, 복부 초음파가 기본입니다. 국가 건강검진에서도 B형 간염 표면항원 검사를 포함하고 있으며, 보건소나 가까운 내과 의원에서도 가능합니다. 6개월~1년마다 정기 추적 검진을 받으세요.', 1800, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 B형 간염', '만성b형간염', 'DIET_LIFE', '만성 B형 간염 환자는 충분한 단백질(두부, 흰살 생선, 콩류)과 비타민이 풍부한 채소·과일을 섭취하고, 음주와 가공식품을 피해야 합니다. 황달 예방을 위해 간에 부담을 주는 고지방 음식과 한약·건강보조식품의 무분별한 복용을 삼가세요. 담당 소화기내과 전문의와 식이 지침을 상담하는 것이 중요합니다.', 1801, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 B형 간염', '만성b형간염', 'MEDICATION', '만성 B형 간염의 약물치료 시작 시기는 HBV DNA 수치, ALT 수치, 간 섬유화 정도, 환자 나이 등을 종합적으로 판단하여 결정됩니다. 치료 기준은 개인 건강 상태나 생활습관보다는 바이러스 활성도와 간 손상 정도가 더 중요한 기준이 됩니다. 담당 소화기내과 전문의와 상담하여 치료 시작 여부를 결정하세요.', 1802, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 B형 간염', '만성b형간염', 'PREVENTION', '만성 B형 간염 예방을 위해 예방접종을 완료하지 않은 경우 B형 간염 백신을 접종하고, 감염자의 혈액·체액·성 접촉을 피해야 합니다. 감염된 경우에는 정기적인 추적 검사(6개월마다 혈액검사, 복부 초음파)와 건강한 생활습관을 유지하여 간경변·간암으로의 진행을 예방하는 것이 중요합니다.', 1803, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 B형 간염', '만성b형간염', 'CAUSE', '만성 B형 간염은 B형 간염 바이러스(HBV)가 주요 원인으로, 주로 감염된 어머니에서 신생아로의 수직 감염, 감염된 혈액 접촉, 성적 접촉을 통해 전파됩니다. 특히 수직 감염의 경우 90% 이상이 만성으로 진행되므로, 출생 직후 예방접종과 면역글로불린 투여가 매우 중요합니다.', 1804, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 B형 간염', '만성b형간염', 'DEFINITION', '만성 B형 간염은 B형 간염 바이러스(HBV)에 감염된 후 6개월 이상 HBsAg 양성이 지속되는 상태로, 간에 지속적인 염증이 발생하는 질환입니다. 방치 시 간경변(간경화)이나 간세포암으로 진행할 수 있어 조기 발견과 지속적인 치료·관리가 중요합니다. 소화기내과 전문의와 정기적으로 상담하세요.', 1805, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 B형 간염', '만성b형간염', 'SYMPTOM', '만성 B형 간염에서 피로감과 쇠약감은 간 기능 저하로 인해 나타나는 증상입니다. 충분한 수면, 균형 잡힌 영양 섭취, 무리한 운동 자제, 음주 금지가 도움이 되며, 규칙적인 추적 검사로 간 기능 변화를 모니터링해야 합니다. 증상이 심해지면 담당 소화기내과 전문의에게 즉시 알리세요.', 1806, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 B형 간염', '만성b형간염', 'DIAGNOSIS', '만성 B형 간염의 간 조직 검사(간 생검)는 간 섬유화 및 염증의 정도를 가장 직접적으로 확인할 수 있는 방법입니다. 그러나 침습적이므로 최근에는 비침습적 방법(간 탄성도 검사, FibroScan)이 대안으로 많이 활용됩니다. 검사 방법 선택은 담당 소화기내과 전문의와 상담하여 결정하세요.', 1807, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 B형 간염', '만성b형간염', 'TREATMENT', '만성 B형 간염 치료의 주요 약물로는 경구 항바이러스제(엔테카비르, 테노포비르)와 페그인터페론 주사제가 있습니다. 추가적으로 테노포비르 알라페나미드(TAF) 등 신규 약물도 사용되며, 간기능 상태에 따라 간 보호제가 병용되기도 합니다. 약물 선택은 반드시 소화기내과 전문의와 상담하여 결정하세요.', 1808, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 C형 간염', '만성c형간염', 'MEDICATION', '만성 C형 간염 치료제(직접 작용 항바이러스제, DAA)와 일부 영양제(철분제, 고용량 비타민 A 등)는 상호작용이 있을 수 있습니다. 또한 성 요한 풀(세인트존스워트) 성분 건강보조식품은 DAA 약물 효과를 크게 감소시킬 수 있습니다. 모든 영양제와 건강보조식품은 반드시 담당 소화기내과 전문의에게 알리고 복용 여부를 상담하세요.', 1809, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 C형 간염', '만성c형간염', 'PREVENTION', 'C형 간염 감염자와의 성적 접촉을 피하는 것은 C형 간염 전파 위험을 줄이는 데 도움이 되지만, C형 간염은 혈액을 통한 전파가 주된 경로입니다. 주사 기구 공유, 문신·피어싱 시 비위생적인 도구 사용, 수혈 등이 주요 전파 경로이므로 이를 철저히 차단하는 것이 가장 효과적인 예방법입니다.', 1810, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 C형 간염', '만성c형간염', 'CAUSE', '수혈 후 C형 간염이 발생할 수 있는데, 이는 수혈된 혈액에 HCV가 포함되어 있을 경우 바이러스가 혈액을 통해 직접 전파되기 때문입니다. 1992년 이전 수혈을 받은 경우 C형 간염 검사를 받아보는 것이 권고됩니다. 외상 후 수혈 이력이 있다면 소화기내과에서 Anti-HCV 검사를 받으세요.', 1811, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 C형 간염', '만성c형간염', 'DEFINITION', '만성 C형 간염은 HCV에 6개월 이상 감염된 상태이며, 주로 혈액을 통해 전파됩니다. 급성 A형 간염은 HAV 바이러스에 의한 경구 감염으로, 대부분 자연 회복되고 만성화되지 않습니다. 두 질환은 원인 바이러스, 전파 경로, 예후 모두 다르므로 혼동하지 않는 것이 중요합니다.', 1812, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 C형 간염', '만성c형간염', 'SYMPTOM', 'C형 간염 감염 후 6개월 이상 HCV RNA가 양성으로 지속될 경우 만성 C형 간염으로 정의됩니다. 급성 감염 시 약 75~85%가 만성으로 진행되며, 만성 감염자의 대부분은 수년~수십 년간 무증상으로 지냅니다. 정기적인 Anti-HCV 검사로 감염 여부를 확인하는 것이 중요합니다.', 1813, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 C형 간염', '만성c형간염', 'DIAGNOSIS', 'Anti-HCV 양성은 현재 또는 과거 HCV 감염을 의미합니다. 현재 감염 여부는 HCV RNA(PCR) 검사로 확인하며, RNA가 음성이면 자연 회복된 것으로 볼 수 있습니다. 과거 감염 이력이 있더라도 재감염 가능성이 있으므로 소화기내과 전문의와 상담하여 추가 검사와 경과 관찰을 받는 것이 중요합니다.', 1814, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 C형 간염', '만성c형간염', 'TREATMENT', '만성 C형 간염 치료에 사용되는 직접 작용 항바이러스제(DAA)는 HCV의 복제에 필요한 효소(NS3/4A 단백분해효소, NS5A, NS5B 중합효소 등)를 직접 차단하여 바이러스 증식을 억제합니다. 이를 통해 바이러스가 혈액 내에서 검출되지 않는 수준으로 낮아지고, 8~12주 치료로 95% 이상 완치가 가능합니다.', 1815, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 담낭염', '만성담낭염', 'DIET_LIFE', '만성 담낭염 환자는 고지방·고콜레스테롤 음식(삼겹살, 튀김, 버터 등)을 제한하고, 소량씩 규칙적으로 식사하는 것이 중요합니다. 식이섬유가 풍부한 채소와 과일을 충분히 섭취하고, 음주와 과식을 피하세요. 이상 증상이 나타나면 담당 소화기내과 또는 외과 전문의에게 알리세요.', 1816, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 담낭염', '만성담낭염', 'CAUSE', '만성 담낭염의 주요 원인은 담석이 담낭 내에 지속적으로 자극을 주어 반복적인 염증을 일으키는 것입니다. 그 외에 세균 감염, 담즙의 구성 이상, 담낭 운동 기능 저하 등도 원인이 될 수 있습니다. 만성 담낭염은 급성 담낭염이 반복되거나 담석이 장기간 존재할 때 발생하는 경우가 많습니다.', 1817, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 담낭염', '만성담낭염', 'DEFINITION', '소화불량, 메스꺼움, 상복부 통증이 있다면 만성 담낭염 외에도 위염, 위궤양, 소화성궤양 등 다른 소화기 질환과 감별이 필요합니다. 소화기내과를 방문하여 복부 초음파와 혈액검사, 필요시 위내시경을 받아 정확한 원인을 파악하는 것이 중요합니다. 증상이 심할 경우 즉시 의료기관을 방문하세요.', 1818, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 담낭염', '만성담낭염', 'SYMPTOM', '만성 담낭염 환자는 오른쪽 윗배에서 등까지 퍼지는 통증 외에도 소화불량, 식후 복부 팽만감, 메스꺼움, 기름진 음식 후 증상 악화, 미열 등이 나타날 수 있습니다. 담석이 담낭관을 막을 경우 황달이 동반될 수도 있습니다. 이러한 증상이 반복된다면 소화기내과 전문의에게 진료를 받으세요.', 1819, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 담낭염', '만성담낭염', 'DIAGNOSIS', '상복부 통증과 식욕 부진이 지속된다면 소화기내과 또는 내과에서 진단을 받는 것이 적절합니다. 복부 초음파로 담낭 상태를 확인하고, 혈액검사로 염증 지표를 평가합니다. 증상이 심하거나 발열이 동반된다면 지체하지 말고 가까운 내과나 소화기내과를 방문하세요.', 1820, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 담낭염', '만성담낭염', 'TREATMENT', '만성 담낭염의 치료는 담석 동반 여부에 따라 달라집니다. 담석이 있는 경우 복강경 담낭 절제술이 근본적인 치료법이며, 수술 전 항생제와 진통제가 사용됩니다. 수술이 어려운 경우 담석 용해제(UDCA)나 체외충격파 쇄석술을 시도할 수 있으며, 담당 외과 전문의와 상담하세요.', 1821, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 위염', '만성위염', 'DIET_LIFE', '만성 위염 환자는 자극적인 음식(맵고 짠 음식, 술, 커피)을 피하고, 소량씩 규칙적으로 식사하는 것이 중요합니다. 금연, 스트레스 관리, 규칙적인 수면도 위염 회복에 도움이 됩니다. 헬리코박터 파일로리 감염이 원인인 경우 제균 치료를 통해 증상이 호전되며, 담당 소화기내과 전문의와 상담하세요.', 1822, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 위염', '만성위염', 'CAUSE', '만성 위염의 주요 원인으로는 헬리코박터 파일로리(H. pylori) 감염, 장기적인 NSAID(아스피린, 이부프로펜 등) 복용, 과도한 음주, 흡연, 스트레스, 담즙 역류, 자가면역 질환 등이 있습니다. 이 중 헬리코박터 감염이 가장 흔한 원인으로, 검사 후 양성이면 제균 치료를 받는 것이 중요합니다.', 1823, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 위염', '만성위염', 'DEFINITION', '만성 위염은 위 점막에 지속적인 염증이 6개월 이상 반복되는 상태로, 헬리코박터 감염, 음주, NSAID 복용, 스트레스 등 다양한 원인에 의해 발생합니다. 지속되면 위 점막이 위축되고 장상피화생이 생겨 위암 위험이 증가할 수 있어 정기적인 위내시경 추적 관찰이 중요합니다.', 1824, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 위염', '만성위염', 'SYMPTOM', '만성 위염의 주요 증상으로는 명치 통증, 속쓰림, 소화불량, 식후 포만감, 오심, 구역감 등이 있으며, 일부에서는 무증상으로 나타나기도 합니다. 추가로 식욕 감소, 체중 감소, 피로감이 동반될 수 있으며, 심한 경우 위출혈로 혈변이 나타날 수 있습니다. 증상이 지속되면 소화기내과 진료를 받으세요.', 1825, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 위염', '만성위염', 'DIAGNOSIS', '식사 후 윗배 통증이 반복된다면 만성 위염 가능성이 있으며, 소화기내과에서 위내시경 검사를 받는 것이 가장 정확한 진단 방법입니다. 위내시경으로 위 점막 상태를 직접 확인하고 헬리코박터 검사 및 조직 검사를 동시에 시행할 수 있습니다. 지체하지 말고 소화기내과 전문의 진료를 받으세요.', 1826, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 위염', '만성위염', 'TREATMENT', '만성 위염은 위산 분비 이상, 위 점막 손상, 소화 효소 기능 저하를 유발하여 소화가 잘 안 되고 위가 더부룩한 증상을 일으킬 수 있습니다. 헬리코박터 감염이 있는 경우 제균 치료로 소화 기능이 개선되는 경우가 많습니다. 소화기내과에서 위내시경과 헬리코박터 검사를 받아 원인을 확인하세요.', 1827, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 췌장염', '만성췌장염', 'DIET_LIFE', '만성 췌장염 환자에게 흡연은 췌장 섬유화를 가속시키고 통증을 악화시키는 중요한 위험 인자입니다. 담배를 끊는 것이 강력히 권고되며, 금연 자체가 만성 췌장염 진행을 늦추는 데 도움이 됩니다. 흡연 외에 만성 음주, 담석, 자가면역 등도 원인이 되므로 소화기내과 전문의와 상담하세요.', 1828, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 췌장염', '만성췌장염', 'CAUSE', '만성 췌장염은 반복적인 췌장 염증으로 인해 췌장 실질이 섬유화되어 외분비(소화효소)·내분비(인슐린) 기능이 저하되는 질환입니다. 주요 원인은 장기적인 과도한 음주(가장 흔함), 흡연, 담석, 유전적 요인, 자가면역, 고칼슘혈증 등이 있습니다. 원인 제거와 함께 전문의의 지속적인 관리가 필요합니다.', 1829, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 췌장염', '만성췌장염', 'DEFINITION', '만성 췌장염은 반복적인 췌장 염증으로 인해 상복부 또는 등으로 방사되는 만성 통증이 특징이며, 식욕부진, 체중 감소, 소화불량, 지방변(기름진 대변), 당뇨가 동반될 수 있습니다. 이러한 증상이 있다면 소화기내과 전문의 진료를 통해 정확한 진단과 치료를 받으세요.', 1830, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 췌장염', '만성췌장염', 'SYMPTOM', '음주 후 소화불량과 지속적인 체중 감소가 있다면 만성 췌장염 가능성을 배제할 수 없습니다. 진단을 위해 혈액검사(아밀라아제, 리파아제), 복부 CT 또는 MRCP 검사가 필요합니다. 즉시 음주를 중단하고 소화기내과 전문의를 방문하여 정확한 검사와 치료를 받으시기 바랍니다.', 1831, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 췌장염', '만성췌장염', 'DIAGNOSIS', '만성 췌장염 진단을 위해 의사에게 복통의 위치·강도·지속 시간, 음주량과 기간, 체중 변화, 대변 상태(지방변 여부), 당뇨 증상 유무, 가족력 등의 정보를 제공하면 도움이 됩니다. 혈액검사, 복부 CT, MRCP 등의 검사 결과도 함께 준비하면 보다 정확한 진단에 도움이 됩니다.', 1832, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '만성 췌장염', '만성췌장염', 'TREATMENT', '만성 췌장염의 수술 외 치료로는 통증 완화를 위한 진통제 투여, 췌장 효소 보충제(소화 효소제), 금주·금연, 영양 지원(지방 제한 식이), 당뇨 관리가 포함됩니다. 내시경을 통한 췌관 결석 제거나 스텐트 삽입도 효과적입니다. 담당 소화기내과 전문의와 치료 계획을 상의하세요.', 1833, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '맹장염', '맹장염', 'CAUSE', '맹장염(충수염)의 정확한 원인은 아직 완전히 밝혀지지 않아 인터넷에서도 다양한 의견이 있습니다. 가장 일반적으로 알려진 원인은 분석(굳은 대변), 이물질, 감염 등에 의한 충수 내강 폐쇄입니다. 단일한 원인보다는 여러 요인이 복합적으로 작용하는 것으로 이해되고 있습니다.', 1834, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '맹장염', '맹장염', 'DEFINITION', '맹장염(급성 충수염)은 충수에 염증이 생기는 질환으로, 초기에 배꼽 주변 통증으로 시작해 오른쪽 아랫배로 이동하는 통증이 특징입니다. 발열, 오심·구토, 식욕 감소가 동반될 수 있으며, 복통·설사·변비 등이 지속된다면 응급실 또는 외과를 방문하여 신속한 진단을 받아야 합니다.', 1835, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '맹장염', '맹장염', 'SYMPTOM', '맹장염(충수염)에서 복통과 설사가 심하다면, 즉시 응급실이나 외과를 방문하여 진찰을 받아야 합니다. 충수염은 응급 수술이 필요한 질환이므로 자가 처방이나 지사제 복용으로 증상을 가리는 것은 위험합니다. 의사의 진단 전에 임의로 진통제를 복용하는 것도 피해야 합니다.', 1836, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '맹장염', '맹장염', 'DIAGNOSIS', '맹장염(충수염) 진단을 위해 복부 초음파, 복부 CT 촬영, 혈액검사(백혈구 수치 확인) 등이 시행됩니다. 복부 CT는 충수염 진단의 정확도가 가장 높으며, 초음파는 방사선 노출 없이 사용 가능합니다. 증상이 의심되면 즉시 외과나 응급실을 방문하여 검사를 받으세요.', 1837, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '맹장염', '맹장염', 'TREATMENT', '종양 괴사인자(TNF) 억제제는 TNF-α 단백질을 차단하여 염증 반응을 줄이는 생물학적 제제로, 류마티스 관절염·크론병 등 염증성 질환에 사용됩니다. 맹장염(급성 충수염)은 세균 감염에 의한 급성 염증이므로 항생제 치료와 수술이 표준 치료이며, TNF 억제제는 사용되지 않습니다. 치료에 대해서는 전문의와 상담하세요.', 1838, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '바이러스성 장염', '바이러스성장염', 'CHECKUP', '바이러스성 장염이 의심될 때는 대변 바이러스 검사와 함께 혈액검사(염증 수치, 전해질 확인), 필요시 대변 세균 배양 검사를 추가로 받는 것이 좋습니다. 탈수가 심한 경우 신장 기능 검사도 필요합니다. 정확한 진단을 위해 소화기내과나 내과 전문의를 방문하세요.', 1839, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '바이러스성 장염', '바이러스성장염', 'MEDICATION', '바이러스성 장염은 바이러스가 원인이므로 항생제는 효과가 없으며, 치료의 핵심은 수분과 전해질 보충입니다. 보조적으로 지사제(로페라미드), 제토제(메토클로프라미드), 정장제(프로바이오틱스)가 처방될 수 있습니다. 세균성 장염과의 감별이 필요한 경우 내과 전문의의 처방에 따르는 것이 중요합니다.', 1840, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '바이러스성 장염', '바이러스성장염', 'PREVENTION', '노로바이러스는 굴 등 패류와 오염된 채소·물에서 주로 검출되므로 생식을 피하고 충분히 가열 조리해야 합니다. 로타바이러스는 분변-경구 경로로 전파되어 영유아에게 흔하므로 손 위생이 중요합니다. 아데노바이러스는 비말과 접촉으로 전파되므로 집단생활 시 위생 관리를 철저히 해야 합니다.', 1841, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '바이러스성 장염', '바이러스성장염', 'CAUSE', '바이러스성 장염의 전염성이 높은 이유는 노로바이러스·로타바이러스가 소량으로도 감염을 일으키고, 바이러스가 환경에서 장시간 생존하기 때문입니다. 오염된 음식·물, 감염자 접촉, 오염된 표면을 통해 쉽게 전파되며, 특히 집단 생활 환경(병원, 학교, 요양원)에서 집단 발병이 빈번합니다.', 1842, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '바이러스성 장염', '바이러스성장염', 'DEFINITION', '바이러스성 장염에 걸린 아이가 유치원에 등원하면 감염력이 매우 강한 바이러스를 다른 아이들에게 전파할 위험이 높습니다. 증상이 완전히 회복된 후 최소 48~72시간이 지날 때까지 등원을 자제하는 것이 권고됩니다. 탈수 예방과 충분한 회복을 위해 소아청소년과 전문의 진료를 받으세요.', 1843, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '바이러스성 장염', '바이러스성장염', 'SYMPTOM', '바이러스성 장염의 주요 증상은 갑작스러운 오심·구토, 설사(하루 5~10회), 복통, 발열(38도 이하), 두통, 근육통이며, 성인보다 영유아에서 탈수 위험이 더 높습니다. 보통 1~3일 내에 호전되지만, 면역저하자나 영유아는 증상이 더 심할 수 있으므로 전문의 진료가 필요합니다.', 1844, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '바이러스성 장염', '바이러스성장염', 'DIAGNOSIS', '회나 고기 섭취 후 냄새가 심한 설사가 나타난 경우 식중독(살모넬라, 비브리오 등 세균성)이나 바이러스성 장염 모두 가능성이 있습니다. 진단을 위해 내과를 방문하여 대변 검사(세균 배양, 바이러스 검사)와 혈액검사를 받는 것이 필요합니다. 탈수 방지를 위해 수분을 충분히 섭취하세요.', 1845, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '바이러스성 장염', '바이러스성장염', 'TREATMENT', '바이러스성 장염 치료에서 약물은 증상 완화를 위한 보조 역할이며, 치료의 핵심은 충분한 수분과 전해질 보충입니다. 대부분 1~3일 내에 자연 회복되므로 과도한 약물 사용보다는 안정과 수분 섭취가 중요합니다. 탈수가 심하거나 증상이 지속되면 내과 전문의를 방문하여 수액 치료를 받으세요.', 1846, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변비', '변비', 'CHECKUP', '변비 검진은 소화기내과나 내과에서 받을 수 있으며, 복부 X선, 대장내시경, 대장통과시간 검사 등이 시행됩니다. 만성 변비가 지속되거나 혈변·체중 감소 등 이상 증상이 동반된다면 반드시 전문의 진료를 받아야 합니다. 가까운 내과나 소화기내과 의원에서 먼저 상담을 시작하세요.', 1847, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변비', '변비', 'DIET_LIFE', '변비 치료에 도움이 되는 운동으로는 하루 30분 이상의 걷기, 자전거 타기, 수영 등 유산소 운동이 효과적입니다. 복부 마사지와 요가도 장 운동을 촉진하는 데 도움이 됩니다. 규칙적인 운동과 함께 충분한 수분 섭취와 식이섬유 섭취를 병행하면 더욱 효과적이며, 심한 경우 소화기내과 전문의와 상담하세요.', 1848, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변비', '변비', 'MEDICATION', '변비 완화를 위해 완하제(부피형성 하제, 삼투압성 하제, 자극성 하제 등)가 사용됩니다. 부피형성 하제(차전자피)는 장기 사용에도 비교적 안전하며, 삼투압성 하제(락툴로스, 폴리에틸렌글리콜)도 효과적입니다. 자극성 하제는 단기간만 사용해야 하며, 약물 선택은 소화기내과 전문의와 상담하여 결정하세요.', 1849, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변비', '변비', 'CAUSE', '변비로 인한 복부 팽만감, 복통, 가스, 식욕 감소, 두통 등은 모두 변비와 연관될 수 있는 증상입니다. 변이 장에 오래 머물면서 가스 생성이 증가하고 독소 흡수가 늘어나 이러한 증상이 나타납니다. 증상이 지속된다면 소화기내과 전문의 진료를 받아 정확한 원인을 파악하세요.', 1850, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변비', '변비', 'DEFINITION', '변비는 배변 횟수가 주 3회 미만이거나, 배변 시 과도한 힘이 필요하고, 변이 딱딱하며, 배변 후에도 잔변감이 있는 상태를 말합니다. 수분과 식이섬유 부족, 신체 활동 부족, 특정 약물, 스트레스, 기질적 질환 등 다양한 원인이 있습니다. 만성 변비는 소화기내과 전문의 상담이 필요합니다.', 1851, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변비', '변비', 'SYMPTOM', '대장암에서 변비, 변 모양 변화(가늘어짐), 체중 감소 등이 나타나는 이유는 종양이 대장 내강을 좁히고 장 운동을 방해하기 때문입니다. 혈변이나 점액변도 동반될 수 있으며, 이러한 증상이 갑자기 나타나거나 지속된다면 즉시 소화기내과를 방문하여 대장내시경 검사를 받는 것이 중요합니다.', 1852, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변비', '변비', 'DIAGNOSIS', '변비와 함께 몸이 붓고 소변량이 줄어드는 증상은 신장 기능 이상(신부전 또는 요독증)과 관련될 수 있습니다. 요독증은 혈액검사(혈청 크레아티닌, BUN)와 소변검사로 확인합니다. 이러한 증상이 있다면 즉시 내과(신장내과)를 방문하여 정확한 원인을 파악해야 합니다.', 1853, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변비', '변비', 'TREATMENT', '최근 설사·변비 반복, 소화 장애가 있다면 직장암 가능성 배제를 위해 대장내시경 검사를 받는 것이 권고됩니다. 혈변, 빈혈, 체중 감소, 배변 습관 변화가 동반된다면 더욱 시급한 진료가 필요합니다. 소화기내과를 방문하여 상담하고 적절한 검사를 받으세요.', 1854, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변실금', '변실금', 'CHECKUP', '변실금이 의심될 때는 소화기내과나 외과(대장항문외과) 전문의에게 진료를 받는 것이 좋습니다. 항문 내압 검사, 항문 초음파, 배변 조영술 등의 검사를 통해 항문 괄약근 기능과 직장 감각을 평가합니다. 가까운 내과 또는 대학병원 대장항문외과를 방문하여 상담하세요.', 1855, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변실금', '변실금', 'DIET_LIFE', '변실금 완화를 위해 수분과 식이섬유 섭취를 조절하여 변의 형태를 정상화하는 것이 중요합니다. 설사가 주된 경우 자극적인 음식과 카페인을 피하고, 변비가 있는 경우 수분과 섬유질을 충분히 섭취하세요. 규칙적인 배변 훈련과 케겔 운동(골반저 근육 강화)도 증상 개선에 도움이 됩니다.', 1856, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변실금', '변실금', 'MEDICATION', '변실금 약물 치료로는 설사가 주된 원인인 경우 지사제(로페라미드)가 효과적이며, 항문 괄약근 기능 저하에는 외용 국소 페닐레프린 크림이 보조적으로 사용됩니다. 약물 치료는 원인과 증상에 따라 다르므로 대장항문외과 전문의와 상담하여 처방을 받으세요. 임의로 약을 복용하지 마세요.', 1857, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변실금', '변실금', 'PREVENTION', '변실금에 대한 특별한 예방접종은 없습니다. 전문가 상담 시 증상의 빈도와 정도, 유발 요인, 출산력이나 항문·직장 수술 이력, 배변 습관, 식이 내용 등을 구체적으로 이야기하면 도움이 됩니다. 예방을 위해 항문 괄약근 강화 운동과 규칙적인 배변 훈련을 시작하는 것이 좋습니다.', 1858, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변실금', '변실금', 'EXERCISE', '변실금에 도움이 되는 운동은 항문 주위 근육을 강화하는 케겔 운동(골반저 근육 수축·이완 반복)이 가장 효과적입니다. 항문을 10초간 조이고 10초간 이완하는 동작을 하루 3세트씩 반복하면 괄약근 기능 향상에 도움이 됩니다. 구체적인 운동 방법은 대장항문외과 전문의나 물리치료사와 상담하세요.', 1859, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변실금', '변실금', 'CAUSE', '변실금의 주요 원인은 항문 괄약근 손상(출산, 수술, 외상), 직장 감각 저하, 설사, 변비로 인한 직장 팽창, 신경 손상(당뇨, 척수 질환), 치매 등 신경계 질환입니다. 원인에 따라 치료 방법이 달라지므로 대장항문외과 전문의에게 진료를 받아 정확한 원인을 파악하는 것이 중요합니다.', 1860, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변실금', '변실금', 'DEFINITION', '변실금은 자신의 의지와 관계없이 대변이나 가스가 새어 나오는 상태로, 항문 괄약근 기능 저하나 신경 이상이 주된 원인입니다. 관련 질환으로는 직장탈출증, 직장류, 과민성대장증후군, 염증성 장질환, 당뇨성 신경병증 등이 있습니다. 대장항문외과 전문의 진료를 받으세요.', 1861, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변실금', '변실금', 'SYMPTOM', '변실금과 치매는 다른 질환입니다. 변실금은 항문 괄약근 기능 저하나 직장 감각 이상으로 대변을 참지 못하는 것이고, 치매는 인지기능 저하로 인해 배변 조절 능력 자체를 상실하는 것입니다. 치매 환자의 변실금은 신경인성 원인에 의한 것으로, 둘은 원인과 치료 접근이 다릅니다.', 1862, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변실금', '변실금', 'DIAGNOSIS', '변실금의 진단 기준은 반복적(최근 3개월 이상)으로 본인의 의지와 무관하게 대변이나 가스가 배출되는 것입니다. 항문 내압 검사로 괄약근 수축력을 측정하고, 항문 초음파로 괄약근 손상 여부를 확인합니다. 대장항문외과 전문의에게 진료를 받아 정확한 평가를 받으세요.', 1863, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '변실금', '변실금', 'TREATMENT', '변실금 치료에 도움이 되는 보조적 치료법으로는 바이오피드백 훈련(항문 괄약근 조절 능력 향상), 케겔 운동, 전기자극 치료가 효과적입니다. 식이 조절(식이섬유 섭취 조절, 자극 음식 제한)과 규칙적인 배변 훈련도 중요합니다. 담당 대장항문외과 전문의와 치료 계획을 수립하세요.', 1864, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복막염', '복막염', 'DIET_LIFE', '복막염이 의심될 경우 즉시 응급실을 방문해야 하며, 금식하고 자가 처방을 피해야 합니다. 복막염은 응급 수술이 필요한 상태이므로 진통제로 증상을 가리는 것은 위험합니다. 평소 복막염 예방을 위해 충수염, 위궤양 등 원인 질환을 조기에 치료하는 것이 중요합니다.', 1865, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복막염', '복막염', 'CAUSE', '복막염은 위궤양이나 충수염 천공, 담낭 파열, 장 천공 등 다양한 복강 내 원인으로 발생할 수 있습니다. 식도염이나 단순 위궤양 자체가 복막염을 직접 유발하지는 않으나, 위궤양이 천공되면 복막염이 발생할 수 있습니다. 복통, 발열, 복부 경직이 있으면 즉시 응급실을 방문하세요.', 1866, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복막염', '복막염', 'DEFINITION', '복막염은 복강 내 장기를 감싸고 있는 복막에 염증이 발생한 상태로, 세균 감염(천공성 복막염)이 가장 흔한 원인입니다. 급성 복통, 복부 경직, 발열, 구역·구토가 특징이며, 즉각적인 외과적 처치가 필요한 응급 상황입니다. 의심 증상이 있으면 즉시 응급실을 방문하세요.', 1867, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복막염', '복막염', 'SYMPTOM', '기침 시 복통 악화와 허리를 구부릴 때 심한 통증은 복막 자극 징후로, 복막염에서 흔히 나타나는 특징적인 증상입니다. 이는 기침이나 움직임이 염증이 있는 복막에 진동을 전달하여 통증을 유발하기 때문입니다. 이러한 증상이 있다면 즉시 응급실을 방문하여 빠른 진단과 치료를 받으세요.', 1868, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복막염', '복막염', 'DIAGNOSIS', '복막염이 의심될 때는 복부 초음파, 복부 X선, CT 촬영 등의 영상 검사와 혈액검사(백혈구, CRP)가 시행됩니다. 진단 확인 후에는 즉각적인 수술과 항생제 투여가 이루어집니다. 응급 상황이므로 증상이 나타나면 지체하지 말고 응급실을 방문하세요.', 1869, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복막염', '복막염', 'TREATMENT', '복막염에 의한 심한 복통과 고열은 즉각적인 외과적 치료(탐색 개복술 또는 복강경 수술)와 강력한 항생제 정맥 투여가 필요합니다. 수술로 감염 원인을 제거하고 복강을 세척·배액하는 것이 핵심 치료입니다. 즉시 응급실을 방문하여 외과 전문의의 치료를 받으세요.', 1870, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복부 통증', '복부통증', 'CHECKUP', '복부 통증, 복강 내 출혈, 맥박 감소 증상이 있다면 대동맥 박리나 복부 대동맥류 파열 등 혈관외과 응급 상황일 수 있습니다. 즉시 응급실을 방문하여 응급 CT 혈관 조영술 검사를 받아야 하며, 혈관외과 또는 흉부외과 전문의의 즉각적인 치료가 필요합니다.', 1871, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복부 통증', '복부통증', 'DIET_LIFE', '복부 통증 완화를 위해 하루 식사를 거르는 것은 일반적으로 권장되지 않습니다. 다만 급성 복통이 심하거나 수술이 예정된 경우 의사의 지시에 따라 금식이 필요할 수 있습니다. 복부 통증이 지속된다면 임의로 금식하기보다 소화기내과 전문의 진료를 먼저 받는 것이 중요합니다.', 1872, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복부 통증', '복부통증', 'MEDICATION', '난소암으로 인한 복부 팽만감과 복통에는 의사의 처방에 따라 진통제(오피오이드 계열 또는 비스테로이드성 소염제), 복수 완화를 위한 이뇨제, 항암화학요법 약물 등이 사용될 수 있습니다. 생리 이상은 호르몬 치료가 필요할 수 있습니다. 반드시 담당 산부인과 또는 종양내과 전문의의 처방을 따르세요.', 1873, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복부 통증', '복부통증', 'CAUSE', '복부 통증의 원인이 되는 질환은 매우 다양하며, 복수(간경변, 악성 종양), 흉통(심장·폐 질환), 자궁 탈출증, 골반 염증성 질환 등이 각각 복부 통증과 관련될 수 있습니다. 증상 위치, 성질, 동반 증상에 따라 관련 질환이 달라지므로 내과 전문의에게 정확한 진료를 받아야 합니다.', 1874, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복부 통증', '복부통증', 'DEFINITION', '복부 통증이 지속되는 원인은 소화기 질환(위염, 궤양, 장염, 담석), 비뇨기 질환(요로결석), 부인과 질환(자궁근종, 난소 낭종), 근골격계 이상 등 다양합니다. 통증의 위치, 양상, 지속 시간, 동반 증상을 정확히 파악하여 소화기내과 또는 관련 전문의를 방문하는 것이 중요합니다.', 1875, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복부 통증', '복부통증', 'SYMPTOM', '복부 통증에 구토, 설사, 변비, 발열, 흉통, 복부 팽만감이 동시에 나타난다면 급성 복막염, 장폐색, 장천공 등 심각한 상태일 수 있습니다. 이러한 증상 조합은 즉각적인 응급 치료가 필요할 수 있으므로, 지체하지 말고 즉시 응급실을 방문하시기 바랍니다.', 1876, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복부 통증', '복부통증', 'DIAGNOSIS', '출산 예정일이 가까운 상황에서 하복부 통증과 질 출혈이 나타나면 조기 진통이나 태반 조기 박리가 의심됩니다. 즉시 산부인과 전문의를 방문하거나 응급실을 통해 산부인과 진료를 받아야 합니다. 응급 상황일 수 있으므로 지체하지 말고 빠르게 의료기관을 방문하세요.', 1877, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복부 통증', '복부통증', 'TREATMENT', '복부 통증의 진단을 위해 통증의 위치·성질·지속 시간·악화·완화 요인을 파악하고, 혈액검사, 복부 초음파, CT 촬영 등이 시행됩니다. 원인에 따라 소화기내과, 외과, 부인과, 비뇨의학과 등 해당 전문과의 치료가 필요합니다. 갑작스러운 심한 복통은 응급 상황일 수 있으므로 즉시 응급실을 방문하세요.', 1878, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복수', '복수', 'MEDICATION', '복수 치료 약물(이뇨제)과 두통약을 함께 복용하는 경우, 이뇨제로 인한 전해질 이상이 두통을 유발할 수 있습니다. 두통약 복용 시간은 이뇨제 복용과 간격을 두거나 담당 의사의 지시에 따르는 것이 안전합니다. 두통이 심하거나 지속된다면 임의로 약을 조절하지 말고 담당 내과 전문의와 상담하세요.', 1879, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복수', '복수', 'CAUSE', '복수가 간 기능 저하 시에만 나타나는 것은 아니지만, 간경변은 복수의 가장 흔한 원인(약 75%)입니다. 간이 안 좋을 때 복수가 차는 이유는 문맥압 항진증으로 인해 복강 내 혈관에서 액체가 복강으로 새어 나오기 때문입니다. 반복적인 복수는 소화기내과 전문의의 정기적인 관리가 필요합니다.', 1880, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복수', '복수', 'DEFINITION', '복수는 복강 내에 비정상적으로 액체가 고이는 상태로, 간경변, 악성 종양, 심부전, 신증후군 등이 원인입니다. 치료 약물로는 스피로노락톤, 푸로세미드 등 이뇨제가 사용되며, 필요 시 복수천자(복강 내 직접 배액)도 시행됩니다. 담당 소화기내과 전문의의 처방과 지도에 따르는 것이 중요합니다.', 1881, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복수', '복수', 'SYMPTOM', '복수가 있을 때 나타나는 옆구리 팽창감과 복부 팽만은 흉막 삼출(흉수), 복부 비만, 난소 낭종 등 다른 상태와 유사하게 보일 수 있습니다. 이를 구별하기 위해 이동탁음(타진) 검사나 복부 초음파로 복수 여부를 확인합니다. 담당 소화기내과 전문의에게 정확한 진단을 받으세요.', 1882, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복수', '복수', 'DIAGNOSIS', '복수가 육안으로 확인될 정도로 복부가 팽만된 경우, 의사는 복부 타진(이동탁음, 수파음 검사)과 복부 초음파를 통해 복수를 확인합니다. 복수의 원인 파악을 위해 혈액검사, 복수천자 후 복수 분석(세포 수, 단백질, 알부민, 세균 배양)이 시행됩니다. 소화기내과 전문의 진료를 받으세요.', 1883, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '복수', '복수', 'TREATMENT', '복수 치료의 기본은 저염식이와 이뇨제(스피로노락톤, 푸로세미드) 사용입니다. 약물에 반응하지 않는 난치성 복수에는 반복적인 복수천자(배액)나 경정맥 간내 문맥정맥 단락술(TIPS)이 시행됩니다. 원인에 따라 간이식이 필요한 경우도 있으므로 소화기내과 전문의와 치료 방향을 상담하세요.', 1884, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '비알코올성 지방간', '비알코올성지방간', 'MEDICATION', '비알코올성 지방간의 약물 치료는 아직 FDA 승인 약물이 제한적이며, 주로 원인 질환(당뇨, 비만, 고지혈증) 치료제가 사용됩니다. 비타민 E(항산화 효과), 피오글리타존(인슐린 저항성 개선), GLP-1 작용제 등이 연구되고 있습니다. 약물 치료보다 생활습관 개선이 우선이며, 전문의 상담을 받으세요.', 1885, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '비알코올성 지방간', '비알코올성지방간', 'DEFINITION', '비알코올성 지방간은 음주를 거의 하지 않는데도 간세포 내에 지방이 비정상적으로 축적되는 질환으로, 비만·당뇨·고지혈증·대사증후군 등과 밀접한 관련이 있습니다. 단순 지방간에서 비알코올성 지방간염(NASH), 간경변, 간암으로 진행할 수 있어 조기 발견과 관리가 중요합니다.', 1886, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '비알코올성 지방간', '비알코올성지방간', 'DIET_LIFE', '비알코올성 지방간 관리의 핵심은 체중 감량(체중의 7~10% 감량 시 간 지방 감소)으로, 칼로리 제한 식단과 규칙적인 운동이 가장 효과적입니다. 포화지방, 단순당, 가공식품을 줄이고 채소·통곡물·오메가3 지방산이 풍부한 식품을 섭취하세요. 음주와 흡연도 간 손상을 악화시키므로 삼가야 합니다.', 1887, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '비알코올성 지방간', '비알코올성지방간', 'CAUSE', '비알코올성 지방간의 주요 원인은 인슐린 저항성(비만, 제2형 당뇨)으로 인해 간으로 유리 지방산 유입이 증가하고 간 내 지방 합성이 늘어나기 때문입니다. 그 외에 고지방 식이, 유전적 소인, 장내 미생물 불균형, 특정 약물(스테로이드, 타목시펜 등)도 원인이 될 수 있습니다.', 1888, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '비알코올성 지방간', '비알코올성지방간', 'EXERCISE', '비알코올성 지방간에 가장 효과적인 운동은 주 150분 이상의 중강도 유산소 운동(빠르게 걷기, 자전거, 수영)과 주 2회 이상의 근력 운동입니다. 규칙적인 운동은 인슐린 저항성을 개선하고 간 내 지방을 감소시킵니다. 운동 시작 전 담당 내과 전문의와 상담하여 개인 상태에 맞는 운동 계획을 세우세요.', 1889, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '비알코올성 지방간', '비알코올성지방간', 'DIAGNOSIS', '비알코올성 지방간 진단은 혈액검사(간기능 검사, AST/ALT 상승)와 복부 초음파로 1차 평가하며, 음주력 확인이 필수입니다. 간 섬유화 정도는 FibroScan(간 탄성도 검사)이나 혈청 표지자 검사로 평가합니다. 정확한 섬유화 단계 확인이 필요한 경우 간 생검을 시행하기도 합니다.', 1890, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '비알코올성 지방간', '비알코올성지방간', 'SYMPTOM', '비알코올성 지방간은 대부분 무증상이지만, 일부에서 피로감, 우상복부 불쾌감이 나타날 수 있습니다. 진행하면 간경변 증상(복수, 황달, 식도 정맥류 출혈)이 나타납니다. 간수치 이상이나 복부 초음파에서 이상 소견이 발견되면 소화기내과 전문의 진료를 통해 정확한 평가를 받으세요.', 1891, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '비알코올성 지방간', '비알코올성지방간', 'TREATMENT', '비알코올성 지방간의 치료에는 생활습관 개선이 가장 중요하며, 체중의 7~10% 감량, 규칙적인 운동, 건강한 식단(지중해식 식이)이 핵심입니다. 원인 질환(당뇨, 고지혈증, 비만) 치료도 병행해야 하며, 간 섬유화가 진행된 경우 전문의와 약물 치료를 상담합니다. 음주를 완전히 금하는 것이 중요합니다.', 1892, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '석회화 담낭', '석회화담낭', 'CAUSE', '석회화 담낭은 담낭 벽에 칼슘이 침착되어 도자기처럼 경화되는 상태로, 만성 담낭염이나 담석의 반복적인 자극이 주요 원인입니다. 고지방·고콜레스테롤 식습관, 만성 감염도 석회화를 촉진할 수 있습니다. 담낭암 발생 위험이 있어 전문의의 지속적인 추적 관찰이 필요합니다.', 1893, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '석회화 담낭', '석회화담낭', 'DEFINITION', '석회화 담낭(도자기 담낭)은 담낭 벽에 칼슘이 침착되어 굳은 상태로, 만성 담낭염이나 담석의 반복적인 자극으로 발생합니다. 담낭암 발생 위험과의 연관성이 일부 보고되어 예방적 담낭 절제술이 권고되기도 합니다. 소화기내과 또는 외과 전문의와 치료 방향을 상담하세요.', 1894, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '석회화 담낭', '석회화담낭', 'SYMPTOM', '갑작스러운 우상복부 통증, 소화불량은 석회화 담낭보다는 급성 담낭염이나 담석의 전형적인 증상입니다. 석회화 담낭 자체는 대부분 무증상이며, 복부 X선이나 CT에서 우연히 발견되는 경우가 많습니다. 이러한 증상이 있다면 소화기내과 전문의를 방문하여 정확한 진단을 받으세요.', 1895, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '석회화 담낭', '석회화담낭', 'DIAGNOSIS', '석회화 담낭이 의심된다면 소화기내과 또는 외과(간담췌외과) 전문의가 있는 종합병원이나 대학병원을 방문하세요. 복부 초음파, CT, 복부 X선으로 진단할 수 있으며, 담낭암 위험 평가를 위한 정밀 검사도 시행됩니다. 전문의 진찰을 통해 치료 방향을 결정하는 것이 중요합니다.', 1896, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '석회화 담낭', '석회화담낭', 'TREATMENT', '석회화 담낭은 체외충격파 쇄석술로 치료하기 어려우며, 담낭 벽 자체가 석회화되어 있어 이 방법은 효과가 제한적입니다. 표준 치료는 복강경 담낭 절제술로, 담낭암 위험을 예방하고 통증을 근본적으로 해결할 수 있습니다. 치료 방법은 외과 전문의와 상담하여 결정하세요.', 1897, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '선천성 거대결장증', '선천성거대결장증', 'CHECKUP', '선천성 거대결장증 진단을 위해 바륨 관장 검사(대장 X선), 직장 내압 검사(항문 내압 검사), 직장 점막 흡입 생검(신경절 세포 유무 확인)이 시행됩니다. 이 중 직장 생검으로 신경절 세포 부재를 확인하는 것이 가장 확진적인 방법입니다. 소아 외과나 소아청소년과 전문의에게 진료를 받으세요.', 1898, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '선천성 거대결장증', '선천성거대결장증', 'CAUSE', '선천성 거대결장증은 주로 RET 유전자를 포함한 여러 유전자 변이와 관련이 있으며, 상염색체 우성 또는 다인자 유전 양상을 보입니다. 유전적 원인 외에도 배아 발생 과정에서 장 신경절 세포의 이동 장애가 핵심 기전입니다. 가족력이 있는 경우 전문의 상담을 통해 유전 검사를 고려할 수 있습니다.', 1899, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '선천성 거대결장증', '선천성거대결장증', 'DEFINITION', '선천성 거대결장증(히르슈스프룽병)은 대장에 신경절 세포가 없어 장 운동이 마비되고 심한 변비, 복부 팽만이 생기는 선천성 질환입니다. 심한 경우 장염이나 장 천공이 발생할 수 있으며, 수술로 신경절 세포가 없는 장 부위를 제거하는 것이 표준 치료입니다. 소아 외과 전문의의 조기 진단과 치료가 중요합니다.', 1900, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '선천성 거대결장증', '선천성거대결장증', 'SYMPTOM', '선천성 거대결장증에서 구토·고열·설사는 히르슈스프룽 관련 장염의 증상일 수 있어 매우 위험합니다. 이러한 증상이 나타나면 즉시 소아 응급실을 방문해야 하며, 바륨 관장, 직장 생검 등의 검사가 필요합니다. 조기에 소아 외과 전문의에게 진료를 받아 수술 치료 계획을 세우는 것이 중요합니다.', 1901, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '선천성 거대결장증', '선천성거대결장증', 'DIAGNOSIS', '아기의 반복적인 구토나 복부가 딱딱하게 만져지는 증상이 있다면 소아 외과 또는 소아청소년과 전문의를 찾아야 합니다. 종합병원이나 대학병원의 소아 외과 전문의가 선천성 거대결장증 진단과 수술 치료를 담당합니다. 빠른 진단을 위해 지체하지 말고 소아 전문 의료기관을 방문하세요.', 1902, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '선천성 거대결장증', '선천성거대결장증', 'TREATMENT', '선천성 거대결장증으로 인공항문(결장루)을 조성한 신생아는 배변을 위해 복부의 장루 주머니를 관리해야 하며, 피부 관리와 주머니 교체가 일상적으로 필요합니다. 이후 근본 수술(풀스루 수술)을 통해 장루를 닫고 정상적인 배변을 회복할 수 있습니다. 소아 외과 전문의의 지속적인 관리와 부모의 적극적인 참여가 중요합니다.', 1903, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '세균성 이질', '세균성이질', 'DIET_LIFE', '세균성 이질 예방을 위해 오염된 물과 음식 섭취를 피하고, 식사 전·화장실 후 반드시 손을 씻어야 합니다. 여행 중에는 생수나 끓인 물을 마시고 길거리 음식 섭취를 삼가세요. 채소와 과일은 철저히 세척 후 먹고, 조리 기구를 위생적으로 관리하는 것이 중요합니다.', 1904, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '세균성 이질', '세균성이질', 'CAUSE', '해외 여행 후 복통과 설사 증상이 있다면 대변 세균 배양 검사와 적리균(Shigella) 검사를 받아야 합니다. 내과나 감염내과를 방문하여 혈액검사와 대변 검사를 통해 세균성 이질 여부를 확인하세요. 심한 탈수 증상이 있다면 즉시 응급실을 방문하여 수액 치료를 받는 것이 중요합니다.', 1905, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '세균성 이질', '세균성이질', 'DEFINITION', '세균성 이질은 Shigella 균 감염으로 발생하는 급성 장관 감염증으로, 발열, 복통, 설사(혈변, 점액변)가 주요 증상입니다. 대변에 혈액이 섞이는 이유는 균이 대장 점막을 직접 침범하여 염증과 궤양을 일으키기 때문입니다. 의심 증상이 있으면 내과 또는 감염내과 전문의 진료를 받으세요.', 1906, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '세균성 이질', '세균성이질', 'SYMPTOM', '세균성 이질과 식중독은 증상이 유사하지만, 세균성 이질은 Shigella균에 의한 대장 점막 침범으로 혈변·점액변이 특징적입니다. 한 달 이상 지속된다면 감염이 장기화되거나 만성 대장 염증으로 발전한 것일 수 있으므로, 즉시 내과 또는 감염내과를 방문하여 대변 배양 검사를 받아야 합니다.', 1907, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '세균성 이질', '세균성이질', 'DIAGNOSIS', '베트남 여행 후 발열·복통·설사가 있다면 세균성 이질 외에도 장티푸스, 콜레라, 아메바성 이질 등을 감별해야 합니다. 진단을 위해 내과(감염내과)를 방문하여 대변 세균 배양 검사, 혈액검사, 필요시 대장내시경을 받는 것이 필요합니다. 탈수 방지를 위해 수분을 충분히 섭취하세요.', 1908, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '세균성 이질', '세균성이질', 'TREATMENT', '세균성 이질 치료의 기본은 수액 공급으로 탈수를 교정하고, 항생제(시프로플록사신, 아지스로마이신 등)로 균을 제거하는 것입니다. 추가로 발열 조절을 위한 해열제, 전해질 음료를 통한 전해질 보충이 필요합니다. 어린이나 면역저하자의 경우 증상이 심하면 입원 치료가 필요할 수 있습니다.', 1909, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '소장암', '소장암', 'CHECKUP', '소장암 증상(복통, 혈변, 체중 감소, 장폐색 등)이 의심될 때는 소화기내과 또는 소화기외과 전문의를 찾아야 합니다. 소장내시경(캡슐 내시경, 더블 풍선 소장내시경)과 CT 소장조영술로 진단이 이루어지며, 조직 검사로 확진합니다. 즉시 소화기내과 전문의를 방문하여 정확한 진단을 받으세요.', 1910, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '소장암', '소장암', 'DIET_LIFE', '가공육과 식이섬유가 적은 식단은 대장암(직장·결장암) 위험을 높이는 것으로 잘 알려져 있지만, 소장암과의 직접적인 연관성에 대한 근거는 제한적입니다. 전문가들은 균형 잡힌 식단과 건강한 생활습관이 소화기암 전반의 예방에 도움이 된다고 권고합니다. 소화기내과 전문의와 상담하세요.', 1911, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '소장암', '소장암', 'CAUSE', '붉은 육류와 염장·훈제 음식에 포함된 헤테로사이클릭아민, 니트로사민 등의 발암 물질이 소장 점막 세포의 DNA를 손상시켜 암 발생 위험을 높이는 것으로 알려져 있습니다. 포화지방 과잉 섭취는 담즙산 분비를 증가시켜 소장 점막에 자극을 줄 수 있습니다. 균형 잡힌 식단을 유지하고 전문의 상담을 받으세요.', 1912, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '소장암', '소장암', 'DEFINITION', '소장암은 소장(십이지장, 공장, 회장)에서 발생하는 악성 종양으로, 복통, 체중 감소, 빈혈, 혈변, 장폐색 등이 주요 증상입니다. 다른 부위(폐암, 유방암 등)에서 소장으로 전이되는 전이암도 발생할 수 있으나, 원발성 소장암 자체는 드문 편입니다. 증상이 의심되면 소화기내과 전문의 진료를 받으세요.', 1913, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '소장암', '소장암', 'SYMPTOM', '검은 핏덩어리(흑변) 및 매스꺼움, 복통, 복부 팽만은 소장암보다는 상부 소화관(위, 십이지장) 출혈 또는 장폐색과 더 연관될 수 있습니다. 그러나 이러한 증상이 지속된다면 소장암을 포함한 소화기 악성 종양 가능성을 배제할 수 없으므로, 즉시 소화기내과 전문의를 방문하여 정확한 검사를 받으세요.', 1914, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '소장암', '소장암', 'DIAGNOSIS', '소장암(이 문맥에서는 대장·직장암도 포함)은 가족력이 중요한 위험 인자 중 하나로, 직계 가족 중 대장암 환자가 있으면 발생 위험이 2~3배 높아집니다. 유전성 대장암 증후군(린치증후군, 가족성 선종성 용종증)이 있는 경우 더 젊은 나이에 정기 검진이 권고됩니다. 소화기내과 전문의와 상담하세요.', 1915, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '소장암', '소장암', 'TREATMENT', '소장암 치료의 기본은 수술(절제술)이며, 종양 위치와 진행 정도에 따라 범위가 결정됩니다. 수술 후 재발 위험이 높은 경우 항암화학요법이나 방사선 치료를 병행합니다. 식습관 개선만으로 암을 치료할 수 없으며, 즉시 소화기외과 전문의를 방문하여 정확한 병기 평가와 치료 계획을 세워야 합니다.', 1916, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '소화불량', '소화불량', 'DIET_LIFE', '소화불량 완화를 위해 식사는 소량씩 천천히 먹고, 식사 직후 눕지 않으며, 고지방·고자극성 음식을 피하는 것이 중요합니다. 규칙적인 식사 시간을 유지하고 과식을 피하며, 스트레스 관리와 적당한 운동도 소화 기능 개선에 도움이 됩니다. 증상이 지속되면 소화기내과 전문의 상담을 받으세요.', 1917, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '소화불량', '소화불량', 'PREVENTION', '과다한 육류 섭취는 고지방 성분으로 인해 위 운동을 저하시키고 소화 효소 분비를 초과하여 소화불량을 일으킬 수 있습니다. 식이섬유 부족 및 포화지방 과잉 섭취는 장 운동을 저하시켜 증상을 악화시킵니다. 육류는 소량씩 조리하여 섭취하고, 채소와 과일을 충분히 곁들이는 것이 권장됩니다.', 1918, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '소화불량', '소화불량', 'CAUSE', '탄산음료의 탄산가스는 위장 내 가스를 증가시켜 팽만감, 트림, 소화불량을 유발합니다. 특히 식사와 함께 탄산음료를 마시거나 공복에 마시는 경우, 또는 과민성 장증후군이나 기능성 소화불량이 있는 사람에게서 증상이 더 심하게 나타납니다. 소화불량이 있다면 탄산음료 섭취를 제한하세요.', 1919, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '소화불량', '소화불량', 'DEFINITION', '소화불량이 지속된다면 소화기내과(성인) 또는 소아청소년과(아이)를 방문하면 됩니다. 의사에게 증상의 시작 시기, 빈도, 통증 위치, 식습관, 복용 약물, 관련 증상(구역·구토·혈변 등)을 구체적으로 알려주면 정확한 진단에 도움이 됩니다. 필요시 위내시경 검사를 받을 수 있습니다.', 1920, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '소화불량', '소화불량', 'SYMPTOM', '소화불량으로 인한 식후 복통 외에도 속쓰림, 오심, 트림, 복부 팽만감, 조기 포만감, 식욕 감소 등이 함께 나타날 수 있습니다. 심한 경우 체중 감소, 빈혈, 혈변이 동반될 수 있으며, 이러한 경보 증상이 있다면 즉시 소화기내과 전문의를 방문하여 위내시경 검사를 받아야 합니다.', 1921, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '소화불량', '소화불량', 'DIAGNOSIS', '소화불량, 골반통, 빈뇨가 동시에 나타난다면 난소 질환(난소 낭종, 난소암)을 포함한 부인과적 원인을 감별해야 합니다. 산부인과(부인과)를 방문하여 골반 초음파 및 CA-125 혈액 종양표지자 검사를 받는 것이 권고됩니다. 증상이 지속되거나 악화된다면 지체하지 말고 전문의를 방문하세요.', 1922, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '소화불량', '소화불량', 'TREATMENT', '식후 소화불량으로 속이 더부룩하고 답답한 증상이 지속된다면 소화기내과를 방문하여 위내시경 검사를 받는 것이 진단의 첫 단계입니다. 검사에서 기질적 원인이 없으면 기능성 소화불량으로 진단되며, 이에 맞는 약물 치료(위장 운동 촉진제, 위산 억제제)와 식습관 교정이 이루어집니다.', 1923, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도 정맥류', '식도정맥류', 'MEDICATION', '식도 정맥류 치료 후에도 원인 질환(간경변 등) 관리를 위해 약물 치료가 지속적으로 필요합니다. 주로 비선택적 베타차단제(프로프라놀롤, 카르베딜롤)가 재출혈 예방을 위해 사용되며, 간경변 치료제도 병행됩니다. 담당 소화기내과 전문의의 처방과 정기 추적 내시경 검사가 중요합니다.', 1924, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도 정맥류', '식도정맥류', 'PREVENTION', '식도 정맥류 예방을 위해 부드럽고 자극이 적은 음식을 소량씩 천천히 먹고, 딱딱하거나 날카로운 음식을 피하는 것이 중요합니다. 음주는 간 손상을 악화시키므로 반드시 금해야 하며, 복압을 높이는 무거운 물건 들기도 피해야 합니다. 담당 소화기내과 전문의와 식이 지침을 상담하세요.', 1925, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도 정맥류', '식도정맥류', 'CAUSE', '식도 정맥류는 간경변 외에도 문맥압 항진증을 유발하는 다른 원인들, 즉 문맥 혈전증, 버드-키아리 증후군(간정맥 폐쇄), 혈흡충증, 간외 문맥 폐쇄 등에 의해서도 발생할 수 있습니다. 정확한 원인 파악을 위해 소화기내과 전문의의 진료와 검사가 필요합니다.', 1926, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도 정맥류', '식도정맥류', 'DEFINITION', '식도 정맥류는 간경변으로 인한 문맥압 항진증이 생겨 식도 하부 정맥이 비정상적으로 확장된 상태입니다. 이 정맥이 파열되면 대량 출혈이 발생하여 생명을 위협할 수 있습니다. 간경변증 환자는 정기적인 내시경 검사와 예방 치료를 통해 식도 정맥류 파열 위험을 줄여야 합니다.', 1927, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도 정맥류', '식도정맥류', 'SYMPTOM', '식도 정맥류는 혈변(토혈 또는 흑변) 외에도 어지러움, 빈맥, 저혈압(출혈 시), 복수, 황달, 간성 뇌증 증상이 동반될 수 있습니다. 출혈이 없는 경우에도 복부 불쾌감이나 연하 곤란이 드물게 나타날 수 있습니다. 이상 증상이 있으면 즉시 소화기내과 전문의를 방문하세요.', 1928, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도 정맥류', '식도정맥류', 'DIAGNOSIS', '식도 정맥류 진단은 소화기내과에서 상부 위장관 내시경(위내시경) 검사로 이루어집니다. 정맥류의 크기와 출혈 위험을 평가하며, 필요시 내시경 결찰술(EVL)이나 경화 요법을 동시에 시행합니다. 간경변이나 복수가 있는 환자는 소화기내과에서 정기적인 내시경 검진을 받는 것이 중요합니다.', 1929, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도 정맥류', '식도정맥류', 'TREATMENT', '내시경 결찰술(EVL)은 식도 정맥류 주위를 고무 밴드로 묶어 혈류를 차단하고 정맥류를 소멸시키는 방법으로, 출혈 예방과 치료에 매우 효과적입니다. 내시경 경화요법(혈관에 경화제 주사)도 사용될 수 있습니다. 이러한 시술은 정맥류 파열 예방 및 출혈 후 지혈 치료에 중요한 역할을 합니다.', 1930, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '소화성궤양', '소화성궤양', 'DEFINITION', '소화성궤양은 위산과 소화효소에 의해 위 또는 십이지장 점막이 손상되어 결손(궤양)이 생기는 질환입니다. 주요 원인은 헬리코박터 파일로리 감염과 비스테로이드성 소염제(NSAIDs) 복용이며, 명치 통증, 속쓰림, 소화불량이 주요 증상입니다. 소화기내과 전문의의 진단과 치료가 필요합니다.', 1931, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도염', '식도염', 'DIET_LIFE', '역류성 식도염에 영향을 주는 식이로는 고지방 음식, 초콜릿, 커피, 탄산음료, 알코올, 민트, 신 음식이 하부 식도 괄약근을 이완시켜 역류를 악화시킵니다. 식사 후 바로 눕지 않고, 취침 2~3시간 전 음식 섭취를 피하며, 적정 체중을 유지하는 것이 중요합니다. 소화기내과 전문의와 구체적인 지침을 상담하세요.', 1932, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도염', '식도염', 'MEDICATION', '식도염 치료에는 프로톤 펌프 억제제(PPI, 오메프라졸 등)가 가장 효과적인 약물로 처방됩니다. 처방전 없이 약국에서 구할 수 있는 제산제(겔포스, 탄산칼슘)나 H2 수용체 차단제(라니티딘 대체제)가 단기 증상 완화에 도움이 될 수 있으나, 장기 복용이나 심한 증상에는 반드시 전문의 처방을 받으세요.', 1933, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도염', '식도염', 'PREVENTION', '식도염 예방을 위해 자극적인 음식(맵고 신 음식, 탄산음료, 커피, 알코올)을 피하고, 소량씩 천천히 먹는 것이 중요합니다. 식후 바로 눕지 않고, 취침 시 머리를 약간 높이고 자며, 복압을 높이는 행동(꽉 끼는 옷, 과식)을 피하는 것도 도움이 됩니다. 소화기내과 전문의와 예방법을 상담하세요.', 1934, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도염', '식도염', 'CAUSE', '밥을 먹은 후 눕는 습관은 위 내용물이 식도로 역류하기 쉽게 만들어 역류성 식도염을 유발하거나 악화시킵니다. 식사 후에는 최소 2~3시간 동안 눕지 않고 가볍게 걷거나 앉아 있는 것이 좋습니다. 이 습관을 교정하면 역류성 식도염 증상 개선에 큰 도움이 됩니다.', 1935, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도염', '식도염', 'DEFINITION', '식도염은 식도 점막에 염증이 발생한 상태로, 역류성 식도염(위산 역류), 감염성 식도염(캔디다, 바이러스), 호산구성 식도염, 약물성 식도염 등 여러 유형이 있습니다. 주요 증상은 가슴 쓰림(흉부 작열감), 연하 곤란, 역류감 등이며, 소화기내과 전문의의 내시경 검사로 진단됩니다.', 1936, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도염', '식도염', 'SYMPTOM', '식도염, 특히 중증 역류성 식도염이나 호산구성 식도염에서는 음식물을 삼키기 어려운 연하 곤란이 발생할 수 있습니다. 이는 식도 점막 염증이 심해지면서 식도가 좁아지거나 경련이 생기기 때문입니다. 연하 곤란이 있다면 즉시 소화기내과 전문의를 방문하여 내시경 검사를 받아야 합니다.', 1937, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도염', '식도염', 'DIAGNOSIS', '식도암 검진은 소화기내과에서 위내시경(상부 위장관 내시경)을 통해 받을 수 있습니다. 고위험군(60세 이상, 만성 흡연자, 역류성 식도염 환자, 바렛 식도 진단자)은 정기적인 내시경 검진이 권고됩니다. 연하 곤란, 체중 감소, 만성 역류 증상이 있다면 즉시 소화기내과를 방문하세요.', 1938, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도염', '식도염', 'TREATMENT', '식도염 치료 후 재발 시에는 장기간의 프로톤 펌프 억제제(PPI) 유지 요법, 생활습관 교정 강화, 항역류 수술(위저부 주름술)이 고려될 수 있습니다. 재발이 반복된다면 식도 협착, 바렛 식도, 식도암으로의 진행 여부 확인을 위해 내시경 검사를 받아야 합니다. 소화기내과 전문의와 상담하세요.', 1939, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '지방간', '지방간', 'DIET_LIFE', '지방간 환자의 칼로리 섭취는 개인의 체중, 활동 수준, 동반 질환에 따라 다르지만, 일반적으로 현재 체중 유지나 서서히 감량하는 수준의 칼로리(약 1,400~1,600 kcal/일)가 권장됩니다. 급격한 칼로리 제한은 오히려 간 손상을 악화시킬 수 있으므로, 담당 소화기내과 또는 영양사와 상담하여 개인 맞춤 식단을 계획하세요.', 1940, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '지방간', '지방간', 'PREVENTION', '지방간 예방을 위해 포화지방과 단순당 섭취를 줄이고, 채소·과일·통곡물·생선 위주의 식단으로 개선하세요. 규칙적인 운동(주 150분 이상 유산소 운동)으로 체중을 점진적으로 감량하고, 음주는 간 지방 축적을 악화시키므로 줄이거나 끊어야 합니다. 정기 건강검진으로 간 상태를 모니터링하세요.', 1941, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '지방간', '지방간', 'CAUSE', '지방간은 음주를 하지 않는 경우에도 비알코올성 지방간(NAFLD)으로 발생할 수 있으며, 비만·당뇨·고지혈증·대사증후군이 주된 원인입니다. 알코올성 간염과 유사하게 AST, ALT 수치가 높아지고 피로감 등이 나타날 수 있습니다. 음주 여부와 관계없이 소화기내과 전문의를 방문하여 정확한 진단을 받으세요.', 1942, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '지방간', '지방간', 'DEFINITION', '알코올성 간질환은 지속적인 과음에 의해 발생하며, 남성 기준 하루 40g(맥주 약 4캔), 여성 기준 하루 20g 이상을 수년간 마신 경우 발생 위험이 높습니다. 음주자의 약 90%에서 지방간이 생기지만, 알코올성 간염은 10~35%, 간경변은 10~20%에서 발생합니다. 음주량을 줄이고 전문의 상담을 받으세요.', 1943, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '지방간', '지방간', 'SYMPTOM', '지방간에서 간수치(AST, ALT) 상승과 피로감 외에도 우상복부 불쾌감, 소화불량, 식욕 감소가 나타날 수 있습니다. 진행하면 복수, 황달, 하지 부종 등 간경변 증상이 나타납니다. 지방간이 의심되는 증상이 있으면 소화기내과에서 혈액검사와 복부 초음파로 정기적인 추적 관찰을 받으세요.', 1944, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '지방간', '지방간', 'DIAGNOSIS', '지방간 진단의 기본 검사는 혈액검사(ALT, AST)와 복부 초음파이며, 간초음파가 간 내 지방 침착 확인에 유용합니다. 간세포암(간암) 의심 시에는 AFP(알파태아단백) 혈액검사와 복부 CT 또는 MRI 조영 검사가 표준 진단법입니다. 정기적인 추적 검사를 위해 소화기내과 전문의와 상담하세요.', 1945, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '지방간', '지방간', 'TREATMENT', '지방간 치료에 사용되는 약물로는 인슐린 저항성 개선제(메트포르민, 피오글리타존), 항산화제(비타민 E), 지질 저하제(스타틴), GLP-1 수용체 작용제 등이 연구 및 사용되고 있습니다. 그러나 현재까지 지방간 치료를 위해 FDA에서 승인된 특이적 약물은 없으며, 생활습관 개선이 최우선입니다. 전문의와 상담하세요.', 1946, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '염증성 장질환', '염증성장질환', 'DEFINITION', '염증성 장질환(IBD)은 소화관에 만성적인 면역 매개 염증이 발생하는 질환으로, 크론병과 궤양성 대장염이 대표적입니다. 복통, 설사(혈변), 체중 감소, 피로감이 주요 증상이며, 정확한 진단은 대장내시경과 조직 검사로 이루어집니다. 소화기내과 전문의의 장기적인 치료와 관리가 필요합니다.', 1947, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '위장관출혈', '위장관출혈', 'DEFINITION', '위장관출혈은 식도, 위, 소장, 대장 등 소화관에서 출혈이 발생하는 상태로, 토혈(위·식도 출혈), 흑변(상부 소화관 출혈), 혈변(하부 소화관 출혈)으로 나타납니다. 주요 원인으로는 소화성 궤양, 식도 정맥류, 대장암, 게실, 혈관 이형성 등이 있으며, 출혈이 있으면 즉시 응급실을 방문해야 합니다.', 1948, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '위선종', '위선종', 'DEFINITION', '위선종은 위 점막에서 발생하는 양성 종양으로, 선상피에서 기원하며 위암으로 발전할 수 있는 전암 병변입니다. 대부분 무증상이며 위내시경 검사 중 우연히 발견됩니다. 발견 시 내시경적 절제(EMR, ESD)를 시행하고, 이후 정기적인 위내시경 추적 검사를 받는 것이 중요합니다.', 1949, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '췌장염', '췌장염', 'CAUSE', '췌장염의 주요 원인은 담석(담석성 췌장염, 가장 흔함)과 과도한 음주(알코올성 췌장염)이며, 이 두 가지가 전체의 약 80%를 차지합니다. 그 외에 고중성지방혈증, 약물 부작용, 복부 외상, 역행성 담췌관 조영술(ERCP) 후 합병증, 자가면역 등도 원인이 될 수 있습니다.', 1950, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '췌장염', '췌장염', 'DEFINITION', '췌장염은 췌장에 염증이 발생하는 질환으로, 췌장 소화 효소가 활성화되어 췌장 자체를 손상시키는 것이 핵심 기전입니다. 급성 췌장염은 갑작스러운 상복부 통증과 오심·구토가 특징이며, 만성 췌장염은 반복적인 염증으로 췌장 기능이 점진적으로 저하됩니다. 전문의 진료가 필요합니다.', 1951, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '충수염', '충수염', 'DEFINITION', '충수염(맹장염)은 대장의 시작 부분에 위치한 충수에 염증이 생기는 질환입니다. 초기에는 배꼽 주변 통증이 나타났다가 점차 오른쪽 아랫배 통증으로 이동하며, 발열·오심·구토·식욕 부진이 동반됩니다. 즉각적인 수술(충수 절제술)이 필요한 응급 질환이므로 의심 증상이 있으면 바로 응급실을 방문하세요.', 1952, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '고혈압', '고혈압', 'CHECKUP', '혈압 측정은 고혈압 진단과 치료 모니터링의 핵심으로, 실제 혈압 수치를 직접 확인할 수 있는 유일한 방법입니다. 증상이 없어도 고혈압은 진행될 수 있어 정기적 측정이 중요하며, 여러 번 측정한 평균값(수축기 140mmHg 이상 또는 이완기 90mmHg 이상)으로 진단합니다. 심혈관내과 전문의와 상담하세요.', 1953, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '고혈압', '고혈압', 'DIET_LIFE', '고혈압 환자는 저염식(하루 나트륨 2g 이하), 칼륨이 풍부한 채소·과일, 통곡물, 저지방 유제품, 등푸른 생선을 섭취하는 DASH 식단이 권장됩니다. 포화지방과 트랜스지방, 가공식품, 음주를 줄이는 것도 중요합니다. 개인 맞춤 식단은 담당 심혈관내과 또는 내과 전문의와 상담하여 계획하세요.', 1954, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '고혈압', '고혈압', 'MEDICATION', '임신 중 고혈압 치료에 사용되는 약물(라베탈롤, 니페디핀, 메틸도파 등)은 일부 약물(NSAIDs, ACE억제제, ARB)과 상호작용이 있을 수 있습니다. 임의로 다른 약물을 추가하지 말고, 복용 중인 모든 약물을 담당 산부인과 및 내과 전문의에게 알려야 합니다. 전문의의 지시에 따른 복용이 중요합니다.', 1955, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '고혈압', '고혈압', 'PREVENTION', '임신 중 단백뇨와 고혈압이 동반된다면 자간전증이 의심되며, 담당 산부인과 전문의에게 즉시 알려야 합니다. 예방을 위해 저용량 아스피린 투여(위험군에서), 칼슘 보충, 정기 산전 검진이 권고됩니다. 갑작스러운 두통, 시야 변화, 상복부 통증이 있으면 즉시 응급실을 방문하세요.', 1956, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '고혈압', '고혈압', 'EXERCISE', '고혈압 환자가 운동 시 혈압이 상승하는 것은 자연스러운 반응이지만, 운동 전 혈압이 매우 높은 경우(수축기 180mmHg 이상) 격렬한 운동은 삼가야 합니다. 운동 전 준비운동을 충분히 하고, 중강도 유산소 운동(빠르게 걷기 등)부터 시작하며, 운동 중 두통·흉통·어지러움이 생기면 즉시 중단하고 전문의와 상담하세요.', 1957, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '고혈압', '고혈압', 'CAUSE', '복부 대동맥류 발생의 위험 인자로는 고혈압, 고지혈증, 흡연, 고령(60세 이상), 남성, 가족력이 있습니다. 고혈압은 혈관벽에 지속적인 압력을 가하여 혈관을 약화시키고, 고지혈증은 죽상경화증을 유발하여 혈관 구조를 손상시킵니다. 위험 인자 관리를 위해 혈관외과 전문의와 상담하세요.', 1958, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '고혈압', '고혈압', 'DEFINITION', '부신 종양(갈색세포종, 알도스테론 생성 선종 등)은 과도한 카테콜라민이나 알도스테론을 분비하여 혈압을 비정상적으로 높이는 이차성 고혈압의 원인이 됩니다. 부신 종양에 의한 고혈압은 약물에 잘 반응하지 않고, 발작성 혈압 상승·두통·발한·빈맥이 특징입니다. 내분비내과 전문의 진료가 필요합니다.', 1959, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '고혈압', '고혈압', 'SYMPTOM', '고혈압은 대부분 무증상이지만, 혈압이 매우 높거나 갑자기 오를 경우 두통(특히 뒷머리), 뒷목이 뻣뻣한 느낌, 어지러움, 코피, 시야 흐림, 흉통이 나타날 수 있습니다. 이러한 증상이 있으면 즉시 혈압을 측정하고 내과 또는 심혈관내과 전문의를 방문하여 진료를 받으세요.', 1960, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '고혈압', '고혈압', 'DIAGNOSIS', '당뇨병과 고혈압을 동시에 앓는 환자에서 파종혈관내응고(DIC) 진단 시에는 두 질환 모두 합병증 위험 인자가 되므로 혈당과 혈압을 모두 엄격히 관리해야 합니다. DIC는 혈액응고 이상이 주된 문제이므로 혈액내과 또는 집중치료의학과 전문의가 치료를 담당하며, 기저 질환 관리도 병행되어야 합니다.', 1961, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '고혈압', '고혈압', 'TREATMENT', '임신성 고혈압 합병증 예방을 위해 혈압 조절 약물 복용, 저염식이, 충분한 휴식, 정기적인 산전 검진이 필요합니다. 치료 가능 여부는 혈압 수치, 단백뇨 정도, 태아 상태, 임신 주수 등을 종합적으로 평가하여 담당 산부인과 전문의가 결정합니다. 자간전증으로 진행되면 조기 분만이 필요할 수 있습니다.', 1962, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '급성 심근경색증', '급성심근경색증', 'DIET_LIFE', '급성 심근경색증 수술 후에는 저염·저지방·저콜레스테롤 식단을 유지하고, 금연·금주가 필수입니다. 오메가3 지방산(등푸른 생선)과 채소·과일 섭취를 늘리고, 정기적인 중강도 유산소 운동(의사 허가 후)을 권장합니다. 약물 복용을 규칙적으로 유지하고 심혈관내과 전문의의 정기 추적 진료를 받으세요.', 1963, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '급성 심근경색증', '급성심근경색증', 'MEDICATION', '급성 심근경색증 후 복용하는 항혈소판제(아스피린, 클로피도그렐)나 항응고제는 양배추(비타민 K 함유)와 일부 상호작용 가능성이 있습니다. 특히 와파린을 복용 중이라면 양배추 섭취량을 갑자기 크게 늘리거나 줄이지 않도록 주의해야 합니다. 현재 복용 약물과 식이에 대해 담당 심혈관내과 전문의에게 반드시 상담하세요.', 1964, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '급성 심근경색증', '급성심근경색증', 'PREVENTION', '급성 심근경색증 예방을 위해 금연, 규칙적인 운동, 건강한 식단(저염·저지방), 정상 체중 유지, 혈압·혈당·콜레스테롤 관리가 중요합니다. 스트레스 관리와 정기적인 심혈관계 건강검진도 예방에 도움이 됩니다. 가족력이 있거나 고위험군이라면 심혈관내과 전문의와 상담하여 적극적인 예방 관리를 받으세요.', 1965, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '급성 심근경색증', '급성심근경색증', 'EXERCISE', '급성 심근경색증으로 스텐트 시술을 받은 후 계단 오르기 같은 중강도 이상의 운동은 담당 심혈관내과 전문의의 허가 이후에 시작해야 합니다. 무리한 운동은 심근에 과부하를 주어 부정맥, 재경색 위험을 높일 수 있습니다. 운동 중 흉통·호흡 곤란·어지러움이 생기면 즉시 중단하고 전문의에게 연락하세요.', 1966, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '급성 심근경색증', '급성심근경색증', 'CAUSE', '급성 심근경색증은 유전적 요인(가족성 고콜레스테롤혈증, LDL 수용체 유전자 변이 등)이 작용하여 조기에 죽상경화증이 발생하고 관상동맥이 막히는 기전으로 발생합니다. 가족력이 강한 경우 혈중 LDL 콜레스테롤이 높거나 관상동맥 석회화가 조기에 진행됩니다. 심혈관내과 전문의와 유전적 위험 인자를 상담하세요.', 1967, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '급성 심근경색증', '급성심근경색증', 'DEFINITION', '급성 심근경색증은 관상동맥이 갑자기 완전히 막혀 심장근육이 괴사하는 상태이며, 심장마비(심정지)는 심장이 갑자기 기능을 멈추는 것입니다. 급성 심근경색증이 심장마비로 이어질 수 있지만, 두 개념은 다릅니다. 급성 심근경색증의 주요 증상은 흉통, 식은땀, 호흡 곤란이며 즉각적인 응급 치료가 필요합니다.', 1968, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '급성 심근경색증', '급성심근경색증', 'SYMPTOM', '급성 심근경색증의 주요 증상은 갑작스러운 흉통(쥐어짜거나 압박하는 듯한 통증), 좌측 팔·턱·등으로 방사되는 통증, 호흡 곤란, 식은땀, 오심·구토, 실신 등입니다. 이러한 증상이 나타나면 즉시 119에 연락하거나 응급실을 방문하여 빠른 처치를 받아야 합니다. 골든 타임 내 치료가 생명을 구합니다.', 1969, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '급성 심근경색증', '급성심근경색증', 'DIAGNOSIS', '가슴 통증, 창백함, 식은땀이 동반된 경우 급성 심근경색증이 강하게 의심됩니다. 진단을 위해 즉시 심전도(ECG), 심근 효소 혈액검사(트로포닌, CK-MB), 관상동맥 조영술이 시행됩니다. 이러한 증상이 나타나면 즉시 119에 신고하거나 응급실로 이동하여 빠른 치료를 받아야 합니다.', 1970, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '급성 심근경색증', '급성심근경색증', 'TREATMENT', '급성 심근경색증 치료는 순환기내과(심장내과) 또는 흉부외과 전문의가 있는 응급 심장 치료 가능 병원에서 받아야 합니다. 치료로는 경피적 관상동맥 중재시술(PCI, 스텐트 삽입)이 표준이며, 혈전용해제 투여도 사용됩니다. 증상 발생 즉시 119를 통해 관상동맥 시술이 가능한 병원 응급실로 이송하세요.', 1971, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '난원공 개존증', '난원공개존증', 'CHECKUP', '난원공 개존증 진단을 위해 심장 초음파(경흉부·경식도 심초음파)와 버블 테스트(발포 생리식염수 주입 후 심방 간 이동 확인)가 시행됩니다. 뇌졸중 경력이 있는 경우 경두개 도플러(TCD) 검사도 시행합니다. 심장내과 전문의를 방문하여 검사 필요성과 절차를 상담하세요.', 1972, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '난원공 개존증', '난원공개존증', 'CAUSE', '난원공 개존증은 주로 태아기에 좌우 심방을 연결하는 구멍이 출생 후에도 완전히 닫히지 않아 발생합니다. 유전적 요인과 환경적 요인이 복합적으로 작용하며, 특정 유전자(GATA4 등)와의 연관성이 연구되고 있습니다. 가족력이 있는 경우 심장내과 전문의와 상담하여 검사를 받는 것이 좋습니다.', 1973, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '난원공 개존증', '난원공개존증', 'DEFINITION', '난원공 개존증은 좌우 심방 사이 난원공이 출생 후 닫히지 않고 남아있는 상태로, 대부분 증상이 없지만 역설적 색전증을 통해 뇌경색(뇌졸중)으로 이어질 수 있습니다. 성인의 약 25%에서 발견되며, 뇌경색 위험은 다른 위험 인자와 복합될 때 증가합니다. 심장내과 전문의와 상담하세요.', 1974, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '난원공 개존증', '난원공개존증', 'SYMPTOM', '난원공 개존증 자체는 증상이 거의 없지만, 역설적 색전증으로 인해 뇌경색, 일과성허혈발작(TIA), 편두통, 잠수병 감수성 증가 등이 나타날 수 있습니다. 다른 선천성 심장 기형(심방 중격 결손 등)이 동반된 경우 증상이 더 다양하게 나타날 수 있습니다. 심장내과 전문의의 평가가 필요합니다.', 1975, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '난원공 개존증', '난원공개존증', 'DIAGNOSIS', '심초음파로 난원공 개존증이 진단된 경우, 심실 중격 결손(심방 중격이 아닌 심실 사이 구멍)과 감별이 필요하며, 이는 심초음파로 확인합니다. 심내막염은 세균이 심장 내막에 감염되는 것으로 발열, 심잡음, 색전 증상이 특징입니다. 정확한 진단은 심장내과 전문의에게 받으세요.', 1976, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '난원공 개존증', '난원공개존증', 'TREATMENT', '난원공 개존증의 치료로는 경과 관찰, 항혈소판제 또는 항응고제 약물 치료, 경피적 카테터를 이용한 난원공 폐쇄술이 있습니다. 뇌경색이 재발하거나 크기가 큰 경우 시술이 고려됩니다. 치료 방법은 뇌경색 과거력, 결손 크기, 나이, 위험 요인을 종합하여 심장내과 전문의가 결정합니다.', 1977, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '대혈관 전위', '대혈관전위', 'CAUSE', '대혈관 전위는 선천성 심장 기형으로, 폐동맥과 대동맥이 뒤바뀌어 산소가 없는 혈액이 전신으로 순환하는 심각한 상태입니다. 발생 원인은 아직 명확하지 않으나, 임신 초기 태아 발생 과정에서의 이상이 주된 기전으로 알려져 있습니다. 신생아 집중치료실과 소아 심장외과 전문의의 즉각적인 처치가 필요합니다.', 1978, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '대혈관 전위', '대혈관전위', 'DEFINITION', '대혈관 전위는 심장의 두 주요 혈관인 대동맥과 폐동맥의 위치가 정상과 반대로 연결된 선천성 심장 기형입니다. 이로 인해 산소가 없는 혈액이 전신으로 순환하고 산소가 풍부한 혈액은 폐에만 공급되어 생존이 어렵습니다. 출생 직후 응급 수술(대동맥 치환술)이 필요한 응급 질환입니다.', 1979, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '대혈관 전위', '대혈관전위', 'SYMPTOM', '대혈관 전위의 주요 증상으로는 출생 직후 심한 청색증(입술·손발이 파랗게 변함), 호흡 곤란, 수유 불량, 빠른 맥박이 나타납니다. 다른 심장 기형이 동반되지 않으면 청색증이 매우 심하며, 즉각적인 처치 없이는 생존이 어렵습니다. 출생 즉시 소아 심장과 전문의의 응급 평가와 치료가 필요합니다.', 1980, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '대혈관 전위', '대혈관전위', 'DIAGNOSIS', '대혈관 전위 진단이 필요한 경우 소아 심장내과 전문의가 있는 상급 종합병원이나 대학병원 소아심장과를 방문해야 합니다. 특정 의사의 연락처를 제공하기는 어려우나, 각 지역 대학병원 소아심장과로 직접 문의하거나 응급 상황이라면 119를 통해 이송하세요. 빠른 진단과 치료가 생명을 좌우합니다.', 1981, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '대혈관 전위', '대혈관전위', 'TREATMENT', '신생아에서 대혈관 전위가 진단되면 즉시 프로스타글란딘 E1을 정맥으로 투여하여 동맥관을 유지하고, 수일 내에 대동맥 치환술(아트리얼 스위치 수술, ASO)을 시행합니다. 이 수술은 뒤바뀐 대동맥과 폐동맥을 원래 위치로 전환하는 것으로, 조기에 시행할수록 예후가 좋습니다. 소아 심장외과 전문의의 신속한 처치가 중요합니다.', 1982, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '동맥관 개존증', '동맥관개존증', 'MEDICATION', '동맥관 개존증 치료약(인도메타신, 이부프로펜 등 COX 억제제)을 지속적으로 복용하는 것은 신생아에서 동맥관 폐쇄를 유도하기 위함이며, 심장에 가해지는 혈류 부담과 폐 고혈압 합병증을 예방합니다. 처방된 기간과 용량을 정확히 지키고, 약물에 반응하지 않으면 카테터 시술이나 수술이 필요합니다. 소아 심장내과 전문의의 지도를 따르세요.', 1983, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '동맥관 개존증', '동맥관개존증', 'PREVENTION', '임신 중 동맥관 개존증 예방을 위해 산모는 임신 초기(특히 1삼분기) 풍진 예방접종(임신 전), 약물 남용 금지, 과도한 알코올 섭취 금지, 흡연 금지가 중요합니다. 임신 중 NSAIDs(이부프로펜 등) 복용을 피하고, 정기적인 산전 검사를 통해 태아 심장 이상을 조기에 발견하는 것이 권고됩니다.', 1984, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '동맥관 개존증', '동맥관개존증', 'CAUSE', '신생아에서 청취된 심잡음과 동맥관 개존증은 동맥관이 출생 후 정상적으로 닫히지 않아 발생합니다. 동맥관 개존증이 있으면 좌우 단락(혈액이 대동맥에서 폐동맥으로 흐름)으로 인해 폐에 과부하가 걸려 심잡음이 들립니다. 정확한 진단은 심초음파로 확인하며, 소아 심장내과 전문의 진료가 필요합니다.', 1985, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '동맥관 개존증', '동맥관개존증', 'DEFINITION', '동맥관 개존증은 태아기에 열려 있던 동맥관이 출생 후 닫히지 않아 대동맥 혈액이 폐동맥으로 역류하는 상태입니다. 이로 인해 폐에 혈류가 과잉 공급되면 호흡 곤란, 폐 고혈압, 수유 곤란, 심부전 증상이 나타날 수 있습니다. 크기가 크거나 증상이 심한 경우 치료가 필요합니다.', 1986, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '동맥관 개존증', '동맥관개존증', 'SYMPTOM', '동맥관 개존증의 크기가 작고 증상이 없는 경우 자연적으로 닫히거나 합병증 없이 생활이 가능합니다. 그러나 크기가 크거나 치료받지 않으면 성인에서 폐 고혈압, 심부전 등의 합병증이 발생할 수 있습니다. 규칙적인 소아 심장내과 추적 검사를 통해 상태를 모니터링하는 것이 중요합니다.', 1987, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '동맥관 개존증', '동맥관개존증', 'DIAGNOSIS', '동맥관 개존증을 심초음파로 진단할 때 동맥관 크기, 혈류 방향, 폐동맥압을 평가합니다. 심초음파는 심장 종양(점액종 등)의 위치와 크기 파악에도 유용하지만, 이는 동맥관 개존증과는 별개의 평가입니다. 정확한 심초음파 결과 해석을 위해 소아 심장내과 전문의에게 진료를 받으세요.', 1988, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '동맥관 개존증', '동맥관개존증', 'TREATMENT', '동맥관 개존증의 치료로는 신생아에서 인도메타신·이부프로펜 약물 투여, 크기가 크거나 약물에 반응하지 않는 경우 경피적 카테터 폐쇄술 또는 수술적 결찰이 사용됩니다. 치료 성공 여부는 동맥관 폐쇄 여부와 폐 고혈압 회복으로 확인합니다. 소아 심장내과 및 심장외과 전문의와 치료 방향을 상담하세요.', 1989, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '림프부종', '림프부종', 'DIET_LIFE', '림프마사지(도수 림프 배액술, MLD)는 림프 흐름을 촉진하여 부종을 줄이고 림프부종의 증상을 완화하는 치료법입니다. 통증 감소, 피부 경직 완화, 감염 예방에 도움이 되며, 압박 스타킹·붕대와 함께 복합 부종 치료(CDT)의 핵심 구성 요소입니다. 전문 치료사에게 올바른 방법으로 받는 것이 중요합니다.', 1990, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '림프부종', '림프부종', 'MEDICATION', '림프부종 치료에 사용되는 약물로는 벤조피론 계열의 혈관 보호제가 사용되기도 하지만 효과가 제한적입니다. 이뇨제는 혈관성 부종에 효과적이지만 림프부종에는 일반적으로 권장되지 않습니다. 약물보다는 압박 요법, 림프마사지, 운동 등 비약물 치료가 림프부종의 표준 치료이며, 전문의와 상담하세요.', 1991, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '림프부종', '림프부종', 'PREVENTION', '유방암 수술 후 림프부종 예방을 위해 수술 측 팔에 혈압 측정, 주사, 채혈을 피하고, 꽉 끼는 옷이나 시계 착용을 삼가야 합니다. 균형 잡힌 저염식을 유지하고 적정 체중을 관리하며, 감염 예방을 위해 피부 상처와 벌레 물림에 주의하세요. 규칙적인 압박 스타킹 착용과 전문의 추적 관찰이 중요합니다.', 1992, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '림프부종', '림프부종', 'EXERCISE', '림프부종에 효과적인 운동은 압박 스타킹을 착용한 상태에서의 중강도 유산소 운동(걷기, 수영)과 림프 흐름을 돕는 부드러운 스트레칭입니다. 과도한 고강도 운동은 림프 부담을 증가시킬 수 있으므로 주의가 필요합니다. 운동 전 물리치료사나 림프부종 전문 치료사에게 적합한 운동 프로그램을 상담하세요.', 1993, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '림프부종', '림프부종', 'CAUSE', '림프부종은 림프관 손상이나 폐쇄로 인해 림프액이 정상적으로 순환하지 못하고 조직에 축적되는 상태입니다. 주요 원인으로는 암 수술(림프절 절제), 방사선 치료, 감염(사상충증), 외상, 선천성 림프관 이상이 있습니다. 이 질환의 관리를 위해 전문의(림프부종 클리닉, 혈관외과)와 상담하세요.', 1994, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '림프부종', '림프부종', 'DEFINITION', '림프부종은 림프액이 조직에 고여 팔다리 등이 부어오르는 상태로, 주요 증상은 팔다리의 점진적인 부종, 무거운 느낌, 피부 경직, 통증, 감염 취약성 증가입니다. 진행하면 피부가 두꺼워지고 섬유화(상피비대증)가 나타납니다. 증상이 의심되면 혈관외과 또는 림프부종 전문 클리닉에서 진료를 받으세요.', 1995, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '림프부종', '림프부종', 'SYMPTOM', '림프부종은 초기에는 가볍게 붓다가 시간이 지남에 따라 부종이 심해지고 피부가 딱딱해지는 양상으로 진행합니다. 초기에 치료를 시작할수록 효과적이므로, 수술이나 방사선 치료 후 팔다리가 붓기 시작하면 즉시 담당 의료진에게 알리고 전문 클리닉에서 평가를 받는 것이 중요합니다.', 1996, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '림프부종', '림프부종', 'DIAGNOSIS', '겨드랑이의 묵직한 덩어리가 느껴진다면 림프절 종대나 림프부종 외에도 지방종, 유방 질환, 림프종 등 다양한 원인이 있을 수 있습니다. 이를 정확히 평가하기 위해 외과 또는 혈관외과, 종양혈액내과 전문의를 방문하여 초음파나 조직 검사를 받는 것이 중요합니다. 지체하지 말고 전문의 진료를 받으세요.', 1997, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '림프부종', '림프부종', 'TREATMENT', '터너 증후군에서의 림프부종은 선천성 림프관 이상으로 발생하며, 압박 스타킹 착용, 림프마사지, 적절한 운동이 증상 완화에 도움이 됩니다. 두통은 혈압 이상(터너 증후군에서 흔함)과 관련될 수 있으므로 혈압 조절 치료가 필요합니다. 소아청소년과·내분비내과·혈관외과 전문의의 통합적 관리가 중요합니다.', 1998, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '발육부전성 좌심 증후군', '발육부전성좌심증후군', 'CHECKUP', '발육부전성 좌심 증후군이 의심된다면 즉시 소아 심장내과 또는 소아 심장외과가 있는 3차 의료기관(대학병원)을 방문해야 합니다. 심초음파, 심전도, 흉부 X선 등의 검사가 시행되며, 필요 시 심장 카테터 검사도 이루어집니다. 신생아에게 청색증이나 호흡 곤란이 있다면 즉시 응급실을 방문하세요.', 1999, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '발육부전성 좌심 증후군', '발육부전성좌심증후군', 'CAUSE', '발육부전성 좌심 증후군의 원인은 명확히 밝혀지지 않았으나, 유전적 요인이 일부 작용하는 것으로 알려져 있습니다. 특정 유전자(NOTCH1 등) 변이와 관련성이 보고되었으며, 가족 중 선천성 심장 기형 환자가 있는 경우 위험이 높아질 수 있습니다. 소아 심장내과 전문의에게 유전 상담을 받는 것이 도움이 됩니다.', 2000, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '발육부전성 좌심 증후군', '발육부전성좌심증후군', 'DEFINITION', '발육부전성 좌심 증후군(HLHS)은 좌심실, 승모판, 대동맥판, 상행 대동맥이 충분히 발달하지 못한 선천성 심장 기형으로, 좌심실이 체순환을 유지할 수 없는 상태입니다. 출생 후 동맥관이 닫히면 급격히 쇼크 상태가 되는 중증 청색증형 선천성 심장병입니다. 단계적 수술(Norwood, Glenn, Fontan 수술)이 필요하며, 소아심장과 전문의의 즉각적인 개입이 필수적입니다.', 2001, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '발육부전성 좌심 증후군', '발육부전성좌심증후군', 'SYMPTOM', '발육부전성 좌심 증후군에서 호흡 곤란, 수유 곤란, 구토는 좌심실 부전으로 인한 폐울혈과 저심박출량의 결과로 나타나는 특징적인 증상입니다. 피부 청색증, 창백함, 사지 냉감, 빠른 호흡도 동반되며, 이러한 증상은 출생 후 수일 내에 급격히 악화될 수 있습니다. 이러한 증상이 신생아에서 나타나면 즉시 소아심장과 전문의의 응급 평가가 필요합니다.', 2002, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '발육부전성 좌심 증후군', '발육부전성좌심증후군', 'DIAGNOSIS', '발육부전성 좌심 증후군은 산전 태아 심초음파 검사를 통해 임신 18~22주경 진단될 수 있으며, 이것이 가장 중요한 산전 영상 검사입니다. 출생 후에는 심초음파(에코)가 심장 구조 이상을 확인하는 표준 검사이며, 심장 MRI나 CT가 추가적인 해부학적 정보 제공에 사용될 수 있습니다. 정확한 진단과 치료 계획 수립을 위해 소아심장 전문 센터에서의 평가가 필요합니다.', 2003, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '발육부전성 좌심 증후군', '발육부전성좌심증후군', 'TREATMENT', '발육부전성 좌심 증후군에서 수술 전 혈액 순환 유지를 위해 프로스타글란딘 E1(PGE1)을 정맥 투여하여 동맥관을 개방 상태로 유지하는 것이 필수적인 내과적 치료입니다. 그러나 이는 수술 전 임시 조치이며, 근본적 치료는 단계적 고식적 수술(Norwood, Glenn, Fontan)이 유일한 방법입니다. 심장 이식도 치료 옵션 중 하나이며, 치료 방침은 소아심장외과 전문의와 상담하시기 바랍니다.', 2004, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '불안정형 협심증', '불안정형협심증', 'MEDICATION', '불안정형 협심증 치료에는 니트로글리세린(혀 밑 투여)으로 급성 흉통을 완화하고, 베타차단제로 심근 산소 소비를 줄이며, 아스피린과 클로피도그렐 같은 항혈소판제로 혈전 형성을 억제합니다. 헤파린 등 항응고제와 칼슘채널차단제도 사용되며, 필요에 따라 스타틴 계열 약물로 동맥경화 진행을 억제합니다. 약물 선택과 용량은 환자 상태에 따라 다르므로 심장내과 전문의의 처방에 따르시기 바랍니다.', 2005, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '불안정형 협심증', '불안정형협심증', 'CAUSE', '불안정형 협심증의 주요 원인은 관상동맥 죽상경화증(동맥경화)에 의한 혈관 협착이며, 설탕과 밀가루 등 정제 탄수화물의 과다 섭취는 비만, 고혈당, 이상지질혈증을 유발하여 동맥경화를 촉진시킬 수 있습니다. 고지방식, 운동 부족, 흡연, 고혈압, 당뇨병, 비만 등도 중요한 위험 인자입니다. 심장 질환 예방을 위해 균형 잡힌 식단과 규칙적 운동, 금연 등 생활 습관 개선이 중요하며, 심장내과 전문의와 상담하시기 바랍니다.', 2006, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '불안정형 협심증', '불안정형협심증', 'DEFINITION', '운동 시 가슴 통증이 나타나는 경우 안정형 협심증이 더 전형적이며, 불안정형 협심증은 안정 시에도 흉통이 발생하거나 기존 협심증 증상이 더 자주, 더 심하게, 더 오래 지속되는 것이 특징입니다. 두 경우 모두 관상동맥 질환과 관련될 수 있으나, 불안정형 협심증은 급성 심근경색으로 진행할 위험이 높은 응급 상황입니다. 운동 시 흉통이 반복된다면 즉시 심장내과 전문의의 진료를 받으시기 바랍니다.', 2007, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '불안정형 협심증', '불안정형협심증', 'SYMPTOM', '불안정형 협심증의 작열감과 흉부 압박감은 전형적 협심증 증상으로, 안정형 협심증과 달리 안정 시에도 발생하고 20분 이상 지속되거나 점점 악화되는 특성이 있습니다. 또한 기존에 안정 시 없던 흉통이 새로 발생하거나, 경미한 활동에도 발생한다는 점에서 안정형 협심증과 구분됩니다. 이는 관상동맥이 일시적으로 완전히 막히기 전 단계일 수 있어 즉각적인 심장내과 전문의 진료가 필요합니다.', 2008, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '불안정형 협심증', '불안정형협심증', 'DIAGNOSIS', '흉통이 10분 간격으로 반복되거나 점점 심해지는 경우 불안정형 협심증 또는 급성 관상동맥증후군의 가능성이 있으므로 즉시 응급실을 방문하시기 바랍니다. 진단을 위해 심전도(ECG), 심장 효소(트로포닌) 검사, 흉부 X선이 우선 시행되며, 관상동맥 조영술이 필요할 수 있습니다. 흉통은 생명을 위협하는 상황일 수 있으므로 자가 판단보다는 즉각적인 응급 의료 서비스 이용을 권장합니다.', 2009, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 기능부전', '승모판기능부전', 'DIET_LIFE', '승모판 기능부전 환자에게는 심장 건강을 위해 오메가-3 지방산이 풍부한 등 푸른 생선, 항산화 성분이 풍부한 과일과 채소, 전곡류, 콩류를 포함한 심장에 유익한 식품을 권장합니다. 나트륨 섭취를 제한하여 심장에 가해지는 부하를 줄이고, 포화지방과 트랜스지방이 많은 음식은 피하는 것이 좋습니다. 구체적인 식이 계획은 심장내과 전문의 및 영양사와 상담하시기 바랍니다.', 2010, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 기능부전', '승모판기능부전', 'EXERCISE', '승모판 기능부전 환자는 걷기, 수영, 자전거 타기 등 중등도 강도의 유산소 운동을 꾸준히 하는 것이 권장됩니다. 그러나 고강도 운동이나 무산소성 운동(무거운 역기 들기 등)은 심장에 과부하를 줄 수 있어 피해야 합니다. 운동 시작 전 심장내과 전문의의 평가를 받아 개인 상태에 맞는 운동 강도와 종류를 결정하시기 바랍니다.', 2011, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 기능부전', '승모판기능부전', 'CAUSE', '승모판 기능부전의 원인은 후천적 요인이 더 흔하며, 류마티스 열, 감염성 심내막염, 심근경색 후 유두근 기능 이상, 퇴행성 변화(승모판 탈출증) 등이 대표적입니다. 유전적 요인은 마르판 증후군 등 결합 조직 질환과 연관된 경우에 해당하며, 선천성 기형으로도 발생할 수 있습니다. 정확한 원인 파악은 치료 방향 결정에 중요하므로 심장내과 전문의의 진료가 필요합니다.', 2012, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 기능부전', '승모판기능부전', 'DEFINITION', '류마티스 판막 질환으로 인한 승모판 기능부전은 연쇄구균 인두염 후 발생하는 류마티스 열이 승모판 첨판과 건삭에 반복적인 염증과 섬유화를 일으켜 판막이 제대로 닫히지 않게 됨으로써 발생합니다. 개발도상국에서 류마티스 판막 질환이 승모판 기능부전의 흔한 원인이며, 선진국에서는 퇴행성 승모판 탈출증이 더 흔합니다. 정확한 원인 평가를 위해 심장내과 전문의의 심초음파 검사가 필요합니다.', 2013, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 기능부전', '승모판기능부전', 'SYMPTOM', '승모판 기능부전의 증상으로는 흉통 외에도 호흡 곤란(특히 누운 자세에서 악화), 피로감, 운동 능력 저하, 심계항진(두근거림), 발목 및 하지 부종이 나타날 수 있습니다. 심한 경우 폐부종으로 인한 급성 호흡 부전이 발생할 수 있으며, 심방세동과 같은 부정맥이 동반되기도 합니다. 증상이 있으면 심장내과 전문의의 진료를 받아 심초음파로 중증도를 평가하시기 바랍니다.', 2014, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 기능부전', '승모판기능부전', 'DIAGNOSIS', '수술 권유 여부의 차이는 승모판 역류의 중증도, 좌심실 기능(박출률), 좌심실 크기, 증상 유무에 따라 달라지기 때문입니다. 중증 역류라도 좌심실 기능이 유지되고 증상이 없는 경우 경과 관찰을 권고하기도 하고, 좌심실 기능이 저하되거나 증상이 있으면 수술을 권고합니다. 기관마다 수술 기준이 다를 수 있으므로, 2개 이상의 전문 의료기관에서 심장내과 전문의의 의견을 들어보시기 바랍니다.', 2015, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 기능부전', '승모판기능부전', 'TREATMENT', '승모판 기능부전의 수술 외 치료로는 이뇨제로 폐울혈과 부종을 완화하고, ACE 억제제나 ARB로 심장 부하를 줄이며, 심방세동이 동반된 경우 항부정맥제나 항응고제를 사용합니다. 카테터를 이용한 경피적 승모판 복원술(MitraClip)도 수술 고위험군 환자에서 대안적 치료로 시행됩니다. 그러나 중증 기능부전에서는 결국 외과적 수술이 가장 효과적이므로 심장내과 및 심장외과 전문의와 충분히 상담하시기 바랍니다.', 2016, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 협착', '승모판협착', 'CHECKUP', '승모판 협착 검진을 위해 호흡 곤란, 운동 시 피로감, 두근거림, 기침, 반복적인 호흡기 감염 등의 증상이 있는지 확인해야 합니다. 청진에서 확장기 잡음이 들리면 승모판 협착을 의심하며, 확진을 위해 심초음파 검사가 가장 중요합니다. 심전도, 흉부 X선도 보조 검사로 사용되며, 의심 증상이 있으면 심장내과 전문의를 방문하시기 바랍니다.', 2017, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 협착', '승모판협착', 'DIET_LIFE', '승모판 협착 환자에게는 나트륨과 수분 섭취를 제한하여 심장 부하를 줄이고, 과도한 신체 활동을 피하면서 적정 체중을 유지하는 것이 권장됩니다. 류마티스 열 재발 예방을 위한 항생제 예방 요법이 필요한 경우도 있으며, 금연과 절주가 중요합니다. 심방세동이 동반된 경우 항응고제 복용이 필요하므로, 구체적인 생활 수칙은 심장내과 전문의와 상담하시기 바랍니다.', 2018, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 협착', '승모판협착', 'MEDICATION', '승모판 협착의 약물 치료는 근본적인 판막 협착을 개선하지는 못하며, 증상 완화와 합병증 예방에 초점을 맞춥니다. 심방세동에는 베타차단제, 디곡신, 항응고제가 사용되며, 폐부종에는 이뇨제가 사용됩니다. 부작용으로는 베타차단제의 서맥·저혈압, 이뇨제의 전해질 이상, 항응고제의 출혈 위험이 있으므로, 약물 선택과 관리는 심장내과 전문의의 처방과 정기적 모니터링이 반드시 필요합니다.', 2019, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 협착', '승모판협착', 'PREVENTION', '목감기(A군 연쇄구균 인두염)를 적절히 치료하지 않으면 면역 반응이 심장 판막을 공격하는 류마티스 열로 이어질 수 있으며, 이것이 반복되면 승모판 협착으로 진행됩니다. 류마티스 열 예방을 위해 연쇄구균 인두염은 페니실린 등 항생제로 완전히 치료해야 하며, 류마티스 열을 한 번 앓은 경우 재발 예방을 위한 장기 항생제 예방 요법이 필요합니다. 목감기가 반복되거나 오래 지속되면 내과 또는 이비인후과 전문의의 진료를 받으시기 바랍니다.', 2020, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 협착', '승모판협착', 'CAUSE', '승모판 협착의 주요 원인은 류마티스 열 후 발생하는 판막 염증과 섬유화이며, 드물게 선천성 기형, 방사선 치료 후유증, 칼슘 침착이 원인이 됩니다. 두통, 어지러움, 시야 변화 등의 증상이 있는 경우 승모판 협착으로 인한 심박출량 감소나 심방세동에 의한 뇌색전증 가능성도 고려해야 합니다. 이러한 증상이 있으면 즉시 심장내과 전문의의 진료를 받으시기 바랍니다.', 2021, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 협착', '승모판협착', 'DEFINITION', '승모판 협착은 심장내과가 있는 내과 의원, 종합병원 또는 대학병원의 심장내과에서 진단받을 수 있습니다. 청진으로 이상 심음을 확인한 후 심초음파(에코) 검사로 판막 면적, 압력 차이, 판막 형태를 평가하여 확진합니다. 심전도와 흉부 X선을 보조 검사로 활용하며, 필요시 부하 심초음파나 심장 카테터 검사도 시행됩니다.', 2022, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 협착', '승모판협착', 'SYMPTOM', '승모판 협착에서 호흡 곤란은 좁아진 판막으로 인해 좌심방 압력이 상승하고 폐정맥 압력이 높아져 폐에 수분이 축적되기 때문에 발생합니다. 기침과 가래는 폐울혈로 인한 폐 모세혈관 압력 상승 및 기관지 점막 부종으로 나타나며, 분홍빛 거품 가래가 나타나면 폐부종의 징후일 수 있습니다. 이러한 증상이 악화되면 즉시 심장내과 전문의의 진료를 받으시기 바랍니다.', 2023, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 협착', '승모판협착', 'DIAGNOSIS', '맥박 불규칙(심방세동 가능성)과 혈전 색전증 증상이 있을 경우 즉시 응급실 또는 심장내과를 방문해야 합니다. 승모판 협착 진단은 심장내과가 있는 종합병원이나 대학병원에서 심초음파, 심전도, 혈액 응고 검사 등을 통해 이루어집니다. 혈전 색전증 의심 증상(갑작스러운 편마비, 언어 장애, 시야 이상 등)은 뇌졸중 응급 상황일 수 있으므로 즉시 응급 처치가 필요합니다.', 2024, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '승모판 협착', '승모판협착', 'TREATMENT', '승모판 협착과 승모판 염증(승모판 판막염) 감별을 위해서는 심장내과 전문의의 진료가 필요합니다. 심초음파로 판막 형태, 두께, 운동성, 역류 유무를 평가하여 두 질환을 구분하며, 감염성 심내막염이 의심되는 경우 혈액 배양 검사도 시행합니다. 정확한 진단에 따라 치료 방향이 달라지므로 심장내과 또는 심장외과 전문의를 방문하시기 바랍니다.', 2025, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심계항진', '심계항진', 'CHECKUP', '심계항진 검사로 심전도(ECG) 외에 24~48시간 홀터 모니터링(장시간 심전도 기록), 심초음파(구조 이상 확인), 갑상선 기능 검사, 전해질 및 빈혈 검사(혈액검사), 운동 부하 검사 등이 시행될 수 있습니다. 증상이 특정 상황에서만 나타나는 경우 이벤트 레코더나 루프 레코더 삽입도 고려됩니다. 정확한 원인 파악을 위해 심장내과 전문의의 진료를 받으시기 바랍니다.', 2026, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심계항진', '심계항진', 'DIET_LIFE', '심계항진 증상 완화를 위해 카페인, 알코올, 에너지 드링크 섭취를 줄이고, 마그네슘과 칼륨이 풍부한 채소, 견과류, 통곡물을 포함한 균형 잡힌 식사가 도움될 수 있습니다. 충분한 수분 섭취, 규칙적인 수면, 스트레스 관리(명상, 심호흡)도 증상 완화에 기여합니다. 증상이 반복되거나 어지러움, 실신이 동반되면 심장내과 전문의의 정확한 진단과 치료를 받으시기 바랍니다.', 2027, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심계항진', '심계항진', 'MEDICATION', '심계항진 치료에 사용되는 베타차단제는 피로감, 서맥, 저혈압, 사지 냉감, 수면 장애 등의 부작용이 있을 수 있습니다. 항부정맥제는 종류에 따라 새로운 부정맥(역설적 부정맥)을 유발하거나, 소화기 증상, 광과민성, 갑상선 기능 이상(아미오다론) 등의 부작용이 나타날 수 있습니다. 약물 복용 중 새로운 증상이 나타나면 임의로 중단하지 말고 즉시 심장내과 전문의와 상담하시기 바랍니다.', 2028, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심계항진', '심계항진', 'PREVENTION', '심계항진 예방을 위해 카페인, 알코올, 흡연을 피하고, 충분한 수면과 스트레스 관리(명상, 요가, 규칙적인 운동)를 실천하는 것이 효과적입니다. 탈수와 전해질 불균형을 방지하기 위해 충분한 수분 섭취와 균형 잡힌 식사를 유지하는 것도 중요합니다. 갑상선 기능 항진증, 빈혈 등 기저 질환이 원인인 경우 해당 질환 치료가 가장 중요한 예방책이므로 심장내과 전문의의 진료를 받으시기 바랍니다.', 2029, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심계항진', '심계항진', 'CAUSE', '알코올은 심방에서 이소성 전기 신호를 유발하고 자율신경계를 자극하여 심방세동 등의 부정맥을 일으킬 수 있으며, 이것이 심계항진으로 느껴집니다. 카페인은 교감신경을 활성화하여 심박수를 증가시키고 심근의 자율성을 높여 심계항진을 유발할 수 있습니다. 두 물질 모두 민감한 사람에서는 소량에도 심계항진을 일으킬 수 있으므로, 증상이 반복된다면 심장내과 전문의와 상담하시기 바랍니다.', 2030, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심계항진', '심계항진', 'DEFINITION', '심계항진은 심장 박동이 빠르게, 불규칙하게, 또는 강하게 느껴지는 주관적 증상으로, 정상적인 심박동도 심하게 인식되거나 비정상적인 리듬이 느껴지는 상태를 말합니다. 운동이나 힘든 활동 후 일시적으로 심박수가 증가하는 것은 생리적 정상 반응이나, 안정 시에도 지속되거나 불규칙하게 느껴지면 부정맥 등 병적 원인을 감별해야 합니다. 증상이 반복되거나 어지러움·호흡 곤란이 동반되면 심장내과 전문의 진료를 받으시기 바랍니다.', 2031, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심계항진', '심계항진', 'SYMPTOM', '심계항진의 주요 증상으로는 빠르거나 불규칙한 심장 박동 외에도 흉부 불쾌감이나 통증, 어지러움, 실신 전 느낌(기절할 것 같은 느낌), 호흡 곤란, 불안감이 동반될 수 있습니다. 심한 경우 실제로 실신(기절)하거나 극심한 피로감이 나타날 수 있으며, 이는 중증 부정맥의 신호일 수 있습니다. 어지러움이나 실신이 동반되는 심계항진은 즉시 심장내과 전문의의 평가가 필요합니다.', 2032, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심계항진', '심계항진', 'DIAGNOSIS', '어지러움과 두근거림이 지속된다면 심장내과(부정맥 전문의)를 방문하시기 바랍니다. 심전도, 홀터 모니터링, 심초음파 등으로 부정맥 여부를 평가하고, 필요에 따라 전기생리학 검사도 시행됩니다. 증상이 갑작스럽거나 심한 경우, 또는 실신이 동반되면 즉시 응급실을 방문하시기 바랍니다.', 2033, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심계항진', '심계항진', 'TREATMENT', '약물 치료에 반응하지 않는 심계항진의 경우 전극도자절제술(카테터 어블레이션)을 고려할 수 있으며, 이는 부정맥의 원인이 되는 비정상적인 전기 경로를 고주파 에너지로 차단하는 방법입니다. 심방세동에는 전기적 심율동전환술(DC cardioversion)도 사용되며, 이식형 제세동기(ICD)나 심박조율기 삽입이 필요한 경우도 있습니다. 구체적인 치료 방향은 심장내과(부정맥 전문의) 전문의와 상담하시기 바랍니다.', 2034, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심근염', '심근염', 'MEDICATION', '영아의 심근염 치료는 원인과 중증도에 따라 다르며, 바이러스성 심근염의 경우 항바이러스제 사용보다는 심부전 증상 관리를 위한 이뇨제, 강심제(도부타민, 밀리논), ACE 억제제 등이 사용됩니다. 중증 심근염에서는 면역글로불린(IVIG) 정맥 투여가 시행되기도 합니다. 영아의 약물 치료는 반드시 소아심장과 전문의의 처방과 긴밀한 모니터링 하에 이루어져야 하므로 전문의의 지시에 따르시기 바랍니다.', 2035, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심근염', '심근염', 'CAUSE', '심근염의 주요 원인은 바이러스 감염(특히 콕사키바이러스, 코로나19 포함)이며, 세균 감염, 자가면역 질환, 특정 약물이나 독소도 원인이 됩니다. 생활습관 중에서는 과도한 음주, 극심한 체력 소모가 동반된 운동(특히 감염 중 무리한 운동)이 심근염 발생과 악화 위험을 높일 수 있습니다. 감염 후 흉통, 호흡 곤란, 심계항진이 나타나면 즉시 심장내과 전문의의 진료를 받으시기 바랍니다.', 2036, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심근염', '심근염', 'DEFINITION', '심근염은 다양한 원인(주로 바이러스)에 의해 심근에 염증이 발생하는 질환으로, 심장 기능 저하와 다양한 심혈관계 합병증이 나타날 수 있는 것이 맞습니다. 경증에서는 자연 회복되기도 하지만, 중증의 경우 확장성 심근병증으로 진행하거나 급성 심부전, 부정맥, 심인성 쇼크 등 심각한 합병증이 발생할 수 있습니다. 정확한 진단과 적절한 치료를 위해 심장내과 전문의의 진료가 필요합니다.', 2037, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심근염', '심근염', 'SYMPTOM', '심근염의 증상으로는 빠른 심장 박동(빈맥) 외에도 흉통이나 흉부 압박감, 호흡 곤란, 심한 피로감, 발열, 근육통이 나타날 수 있습니다. 중증의 경우 다리 부종, 어지러움, 실신, 심한 경우 심인성 쇼크 증상이 발생할 수 있습니다. 바이러스 감염 후 이러한 증상이 나타나면 즉시 심장내과 전문의의 진료를 받으시기 바랍니다.', 2038, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심근염', '심근염', 'DIAGNOSIS', '심근염이 의심될 경우 심장내과 전문의를 방문하시기 바랍니다. 초기 평가는 병력 청취와 신체 검진 후 심전도, 혈액검사(심장 효소: 트로포닌, CK-MB, BNP), 흉부 X선, 심초음파 순서로 진행됩니다. 심근 침범의 범위와 정도를 정확히 평가하기 위해 심장 MRI가 가장 유용한 검사이며, 필요 시 심근 생검도 시행됩니다.', 2039, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심근염', '심근염', 'TREATMENT', '심근염으로 인한 폐에 물이 차는 심인성 폐부종의 치료는 이뇨제(주로 푸로세미드) 정맥 투여로 과잉 체액을 제거하는 것이 가장 기본적인 방법입니다. 산소 공급이나 비침습적 양압 호흡(CPAP/BiPAP)으로 호흡을 보조하며, 심한 경우 기계 환기(인공호흡기) 치료가 필요합니다. 심인성 쇼크가 동반된 경우 강심제나 기계적 순환 보조 장치(IABP, ECMO)가 사용될 수 있으므로 즉각적인 전문 의료기관 치료가 필요합니다.', 2040, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심낭염', '심낭염', 'CHECKUP', '흉통이 심하고 자세 변화(앞으로 구부릴 때 완화, 누울 때 악화)에 따라 통증이 달라지는 것은 심낭염의 전형적인 증상입니다. 확인을 위해 심전도(광범위한 ST분절 상승), 혈액검사(CRP, 백혈구, 트로포닌), 흉부 X선, 심초음파를 포함한 검진이 필요합니다. 이러한 증상이 있으면 즉시 응급실 또는 심장내과를 방문하시기 바랍니다.', 2041, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심낭염', '심낭염', 'MEDICATION', '심낭염의 약물 치료는 주로 비스테로이드 항염증제(NSAIDs, 이부프로펜 또는 아스피린)가 사용되며, 이들은 염증 매개물질인 프로스타글란딘 합성을 억제하여 심낭의 염증과 통증을 줄입니다. 콜히친을 NSAIDs와 함께 사용하면 재발 예방에 효과적이며, 중증이거나 다른 원인이 있는 경우 코르티코스테로이드가 사용됩니다. 정확한 약물 선택과 용량은 심장내과 전문의의 처방에 따르시기 바랍니다.', 2042, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심낭염', '심낭염', 'PREVENTION', '심낭염 예방을 위해 세균성 심낭염은 원인 감염(결핵 포함)의 적절한 치료가 중요하며, 감기나 독감 후 흉통이 발생하면 빠른 시일 내에 전문의의 진료를 받아야 합니다. 심낭염 후 재발 예방을 위해 콜히친 복용, 급성기 이후 수주간 격렬한 운동 자제, 심낭염 치료 중 NSAIDs의 적절한 복용 기간 준수가 중요합니다. 자가면역 질환이 원인인 경우 기저 질환 관리가 핵심이므로 심장내과 전문의의 지속적인 관리를 받으시기 바랍니다.', 2043, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심낭염', '심낭염', 'CAUSE', '심낭염의 가장 흔한 원인은 바이러스 감염(콕사키바이러스, 에코바이러스 등)이며, 세균 감염, 결핵, 자가면역 질환(루푸스, 류마티스 관절염), 심근경색 후(드레슬러 증후군), 요독증, 종양, 방사선 치료 후유증 등이 원인이 됩니다. 이러한 요인들은 심낭에 직접 감염되거나 면역 반응을 통해 간접적으로 심낭에 염증을 일으킵니다. 정확한 원인 파악을 위해 심장내과 전문의의 진료와 검사가 필요합니다.', 2044, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심낭염', '심낭염', 'DEFINITION', '심낭염은 심장을 둘러싸고 있는 두 겹의 막인 심낭에 염증이 생기는 질환입니다. 바이러스 감염이 가장 흔한 원인이며, 호흡 곤란·전신 쇠약감·발열·한기 등의 증상이 동반될 수 있습니다. 증상이 의심될 경우 반드시 심장내과 전문의 상담을 받으시기 바랍니다.', 2045, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심낭염', '심낭염', 'SYMPTOM', '심낭염의 흉통은 주로 날카롭고 찌르는 듯한 양상으로 앞가슴 또는 왼쪽 가슴에 나타나며, 숨을 들이쉬거나 누울 때 악화되고 앞으로 몸을 구부리면 완화되는 특징이 있습니다. 발열·마른기침·호흡 곤란이 함께 동반될 수 있으며, 심낭삼출이 발생하면 심장압전으로 이어질 수 있어 전문의 진료가 필요합니다.', 2046, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심낭염', '심낭염', 'DIAGNOSIS', '심낭염 진단에는 심전도·혈액검사(CRP, ESR, 심근 효소)·흉부 X선이 우선 시행되며, 심낭삼출 유무를 확인하기 위해 심장 초음파가 핵심 검사로 활용됩니다. CT는 심낭 두께 측정이나 재발성·수축성 심낭염 감별에 유용하며, 정확한 진단 방법 선택은 심장내과 전문의와 상의하시기 바랍니다.', 2047, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심낭염', '심낭염', 'TREATMENT', '심낭염의 주된 비수술적 치료는 아스피린 또는 NSAIDs(비스테로이드 소염진통제)이며, 재발 예방을 위해 콜히친을 병용하는 것이 표준 치료입니다. 스테로이드는 특정 원인(자가면역, 결핵 등)에 한해 제한적으로 사용되며, 충분한 안정이 중요합니다. 치료 방법은 원인과 중증도에 따라 다르므로 반드시 전문의 지도 하에 진행하세요.', 2048, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심방 세동', '심방세동', 'DIET_LIFE', '심방 세동 환자에게 가장 안전한 유산소 운동은 걷기, 자전거 타기, 수영 등 중강도의 저충격 운동입니다. 운동 강도는 최대 심박수의 50~70% 수준을 유지하는 것이 권장되며, 갑작스러운 고강도 운동은 피해야 합니다. 항응고 치료 중이거나 심부전이 동반된 경우 운동 방법이 달라질 수 있으므로 반드시 주치의와 상담 후 운동 계획을 세우시기 바랍니다.', 2049, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심방 세동', '심방세동', 'PREVENTION', '심방 세동 예방을 위해 고혈압·당뇨·비만 등 기저 질환을 철저히 관리하고, 과도한 음주와 카페인 섭취를 줄이는 것이 중요합니다. 규칙적인 유산소 운동, 금연, 스트레스 관리도 도움이 되며, 수면 무호흡증이 있는 경우 치료를 받는 것이 권장됩니다. 정기적인 심전도 검사 등 건강 검진을 통해 조기 발견하고, 이상 증상이 있으면 즉시 전문의 상담을 받으세요.', 2050, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심방 세동', '심방세동', 'EXERCISE', '심방세동 환자는 불규칙한 심장 박동으로 인해 농구·축구와 같은 고강도 접촉 스포츠는 피하는 것이 권장됩니다. 대신 걷기·수영·사이클링 등 중저강도 유산소 운동이 비교적 안전하며, 갑작스런 심박수 상승을 최소화할 수 있습니다. 어떤 운동이 본인에게 적합한지는 심박수 조절 상태, 항응고 치료 여부 등을 고려해 심장내과 전문의와 상의하여 결정하세요.', 2051, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심방 세동', '심방세동', 'CAUSE', '심방 세동 자체는 흉통보다는 두근거림·호흡 곤란·어지럼증이 주요 증상이나, 동반된 관상동맥질환이나 심근허혈로 인해 흉통이 나타날 수 있습니다. 특히 쥐어짜는 듯한 흉통은 협심증이나 심근경색의 가능성을 시사하며, 심방 세동과 동시에 발생하면 심각한 합병증 위험이 높습니다. 이러한 흉통이 나타나면 즉시 응급 진료를 받으시기 바랍니다.', 2052, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심방 세동', '심방세동', 'DEFINITION', '심방 세동의 치료법은 심박수 조절, 리듬 조절, 혈전 예방(항응고 치료)의 세 가지 원칙에 따라 결정됩니다. 약물 치료로 조절되지 않거나 재발이 잦은 경우 전기적 심율동전환 또는 카테터 절제술(전극도자 절제술)이 시행될 수 있습니다. 수술 방법의 선택은 발작 빈도, 증상 중증도, 기저 심장 질환 등을 종합 평가하여 심장내과 전문의가 결정합니다.', 2053, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심방 세동', '심방세동', 'SYMPTOM', '심방 세동에서 나타나는 가슴 불쾌감이나 흉통은 심방 세동 자체에 의한 증상일 수 있지만, 동반된 협심증·심근경색·심부전 등의 가능성도 배제할 수 없습니다. 특히 지속되거나 심한 흉통은 관상동맥 질환의 증상일 수 있어 즉각적인 평가가 필요합니다. 가슴 불쾌감이 지속될 경우 심장내과 전문의에게 정확한 감별 진단을 받으시기 바랍니다.', 2054, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심방 세동', '심방세동', 'DIAGNOSIS', '심방 세동은 발작성(간헐적)으로 나타나는 경우 검사 당시 정상 심전도를 보여 진단이 누락될 수 있습니다. 이 경우 24~72시간 홀터 모니터링이나 장기간 심전도 모니터링 장치가 필요하며, 증상이 있을 때만 짧게 발생하는 경우 일반 검사로는 발견이 어렵습니다. 반복적인 두근거림·어지럼증이 있다면 전문의에게 장기 심전도 모니터링을 요청하시기 바랍니다.', 2055, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심방 세동', '심방세동', 'TREATMENT', '심방 세동 환자의 초기 평가는 혈역학적 안정성(혈압, 맥박, 의식 상태) 확인이 우선이며, 불안정한 경우 즉각적인 전기적 심율동전환이 필요합니다. 안정적인 경우 심박수 조절(베타차단제, 칼슘채널차단제)과 항응고 치료(혈전색전증 예방)를 병행하며, 이송 중에는 지속적인 심전도 모니터링과 산소 공급이 중요합니다. 구체적인 치료 방침은 반드시 전문의 지도 하에 결정하세요.', 2056, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심방 조동', '심방조동', 'CHECKUP', '심방 조동 검진은 순환기내과(심장내과)에서 받을 수 있으며, 대학병원 및 종합병원의 심장내과 외래를 방문하시면 됩니다. 기본적으로 심전도 검사로 진단이 가능하며, 필요 시 24시간 홀터 검사, 심장 초음파 등이 추가됩니다. 가까운 내과나 심장내과 전문의를 먼저 방문하여 검사 의뢰를 받으시면 됩니다.', 2057, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심방 조동', '심방조동', 'CAUSE', '심방 조동은 심방 내에서 빠르고 규칙적인 전기 신호가 반복 순환(재진입 회로)하면서 발생하며, 분당 250~350회의 심방 수축이 나타납니다. 주요 원인으로는 고혈압, 관상동맥질환, 심부전, 판막 질환, 갑상선 기능 항진증, 만성 폐질환 등이 있습니다. 음주, 과로, 전해질 불균형도 유발 요인이 될 수 있으며, 원인 규명을 위해 심장내과 전문의 진료가 필요합니다.', 2058, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심방 조동', '심방조동', 'DEFINITION', '심방 조동은 심방 내의 비정상적인 전기 신호 순환으로 인해 심방이 분당 250~350회 규칙적으로 빠르게 뛰는 부정맥입니다. 심계항진·두근거림·호흡 곤란 증상이 의심될 때는 심전도 검사를 통해 확인할 수 있으며, 심방 조동 특유의 ''톱니 모양(flutter wave)'' 파형이 관찰됩니다. 이러한 증상이 있다면 즉시 심장내과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 2059, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심방 조동', '심방조동', 'SYMPTOM', '심방 조동의 주요 증상으로는 두근거림(심계항진)·호흡 곤란 외에도 어지럼증, 흉부 불쾌감 또는 흉통, 피로감, 실신 전 느낌(실신 직전 어지럼증) 등이 동반될 수 있습니다. 심박수가 매우 빠를 경우 운동 불내성이나 일상적인 활동 시에도 숨이 차는 증상이 나타납니다. 증상이 지속되거나 심한 경우 즉시 심장내과 전문의 진료를 받으시기 바랍니다.', 2060, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심방 조동', '심방조동', 'DIAGNOSIS', '심방 조동의 가장 핵심적인 진단 방법은 12유도 심전도로, 톱니 모양의 flutter wave를 통해 확인합니다. 증상이 간헐적일 경우 24~72시간 홀터 모니터링이나 이벤트 레코더가 유용하며, 심장 초음파로 구조적 이상이나 혈전 유무를 평가합니다. 전기생리학적 검사는 카테터 절제술 시행 전 정확한 회로 위치 파악을 위해 사용됩니다.', 2061, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심방 조동', '심방조동', 'TREATMENT', '심방 조동 치료는 심박수 조절(베타차단제, 칼슘채널차단제), 리듬 조절(항부정맥제 또는 전기적 심율동전환), 항응고 치료로 구성됩니다. 카테터 절제술(전극도자 절제술)은 재발을 막는 근치적 치료법으로 성공률이 높아 권장됩니다. 치료 방법은 증상 중증도와 기저 질환에 따라 달라지므로 반드시 심장내과 전문의와 상의하여 결정하세요.', 2062, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심실 빈맥', '심실빈맥', 'CHECKUP', '심실 빈맥 검진을 위해서는 우선 심장내과(순환기내과) 전문의 진료를 받아야 하며, 12유도 심전도·24시간 홀터 모니터링·심장 초음파가 기본 검사로 시행됩니다. 구조적 심장 질환이 의심될 경우 심장 MRI나 관상동맥조영술이 추가되며, 전기생리학적 검사로 부정맥 회로를 정밀 평가합니다. 증상이 있다면 지체 없이 심장내과 전문의를 방문하시기 바랍니다.', 2063, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심실 빈맥', '심실빈맥', 'DIET_LIFE', '심실 빈맥 환자는 저지방·저염 식단과 충분한 수분 섭취로 심장 부담을 줄이는 것이 도움이 되며, 과도한 카페인·알코올·흡연은 부정맥을 유발할 수 있어 피해야 합니다. 전해질(칼륨, 마그네슘) 균형 유지가 중요하며, 스트레스 관리와 규칙적인 수면 습관도 도움이 됩니다. 식이와 생활 습관 변화가 증상 개선에 도움이 될 수 있으나, 구체적인 관리 방법은 담당 전문의와 상의하세요.', 2064, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심실 빈맥', '심실빈맥', 'MEDICATION', '심실 빈맥 치료에 사용되는 항부정맥제(아미오다론, 소타롤 등)는 갑상선 기능 이상, 폐독성, 간독성, 광과민성, QT 연장 등의 부작용이 나타날 수 있습니다. 베타차단제는 서맥, 저혈압, 피로감, 기관지 수축을 유발할 수 있으며, 약물마다 부작용 프로필이 다릅니다. 부작용 발생 시 즉시 담당 심장내과 전문의에게 알리고 약물 조정 여부를 상담하시기 바랍니다.', 2065, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심실 빈맥', '심실빈맥', 'EXERCISE', '심실 빈맥 환자에게는 중강도 유산소 운동(걷기, 수영, 자전거)이 심폐 기능 개선에 도움이 될 수 있으나, 고강도 운동이나 갑작스러운 격렬한 운동은 부정맥을 유발할 수 있어 주의가 필요합니다. 운동은 심장 전문의의 평가와 허가 후 시작하는 것이 안전하며, 운동 중 두근거림·어지럼증·흉통이 발생하면 즉시 중단해야 합니다. 운동 방법과 강도는 반드시 담당 전문의와 상의하여 결정하세요.', 2066, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심실 빈맥', '심실빈맥', 'CAUSE', '심실 빈맥의 주요 원인은 심근경색 후 흉터 조직, 심근증(확장성·비후성), 심부전 등 구조적 심장 질환이며, 전해질 이상(저칼륨·저마그네슘)과 약물 독성도 원인이 됩니다. 유전적 요인으로는 롱QT증후군, 브루가다증후군, 카테콜아민성 다형 심실빈맥(CPVT) 등이 있으며, 가족 중 급사 병력이 있다면 유전성 부정맥 가능성을 고려해야 합니다. 유전성이 의심될 경우 전문의에게 유전 검사를 포함한 평가를 받으시기 바랍니다.', 2067, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심실 빈맥', '심실빈맥', 'DEFINITION', '심실 빈맥은 심실에서 분당 100회 이상의 빠른 전기 신호가 발생하는 부정맥으로, 일을 하거나 운동 중에 심장이 빠르게 뛰는 증상이 나타날 수 있습니다. 이는 심실 빈맥의 특징적인 증상일 수 있으며, 어지럼증·흉통·실신이 동반될 경우 위험한 상황일 수 있습니다. 가족 중 이러한 증상이 있다면 반드시 심장내과 전문의 진료를 받도록 권고해 주시기 바랍니다.', 2068, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심실 빈맥', '심실빈맥', 'SYMPTOM', '심실 빈맥의 주요 증상인 흉부 답답함·빠른 심박동 외에도 어지럼증, 실신(기절), 호흡 곤란, 쇠약감, 식은땀이 동반될 수 있습니다. 중증의 경우 의식 소실이나 심정지로 이어질 수 있어 신속한 치료가 필요합니다. 위의 증상들이 나타나면 즉시 응급 진료를 받으시기 바랍니다.', 2069, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심실 빈맥', '심실빈맥', 'DIAGNOSIS', '두근거림·숨 참 증상으로 심실 빈맥이 의심될 경우 대학병원 또는 종합병원의 심장내과(순환기내과)에서 진단받을 수 있습니다. 기본 검사는 12유도 심전도와 홀터 모니터링이며, 증상이 심하거나 갑작스럽게 악화된 경우에는 응급실을 방문해야 합니다. 가까운 내과 또는 심장내과 전문의를 먼저 방문하여 의뢰서를 받는 것이 효율적입니다.', 2070, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심실 빈맥', '심실빈맥', 'TREATMENT', '심실 빈맥 치료는 특정 병원보다 심장 전기생리학 전문의(부정맥 전문의)가 있는 심장내과에서 받는 것이 중요합니다. 전극도자 절제술(카테터 절제술), 이식형 제세동기(ICD) 시술 등이 가능한 심장 부정맥 센터를 갖춘 대학병원이 권장됩니다. 주치의 또는 지역 심장내과 전문의를 통해 적절한 기관으로 의뢰받으시기 바랍니다.', 2071, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심실 중격 결손', '심실중격결손', 'CAUSE', '심실 중격 결손은 주로 태아 발생 과정에서 심실 중격이 완전히 형성되지 않아 발생하는 선천성 심장 기형으로, 정확한 원인은 아직 완전히 밝혀지지 않았습니다. 유전적 요인, 임신 중 풍진·당뇨·약물 복용 등 환경적 요인, 염색체 이상(다운증후군 등)이 복합적으로 관여합니다. 원인 파악 및 관리를 위해 소아심장과 또는 심장내과 전문의의 진료를 받으시기 바랍니다.', 2072, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심실 중격 결손', '심실중격결손', 'DEFINITION', '심실 중격 결손은 좌심실과 우심실 사이의 벽(심실 중격)에 구멍이 있는 선천성 심장 기형으로, 압력이 높은 좌심실의 혈액이 우심실로 유입되는 좌-우 단락이 발생합니다. 이로 인해 폐혈관에 과부하가 걸리고, 장기간 방치 시 폐고혈압 및 아이젠멩거 증후군으로 진행할 수 있습니다. 정확한 진단과 치료 계획은 소아심장과 또는 심장내과 전문의와 상의하세요.', 2073, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심실 중격 결손', '심실중격결손', 'SYMPTOM', '소형 심실 중격 결손은 무증상인 경우가 많지만, 결손이 큰 경우 수유 곤란, 빠른 호흡, 체중 증가 부진, 잦은 폐렴, 발한, 쉽게 피로해지는 증상이 나타납니다. 성인에서는 운동 시 호흡 곤란, 두근거림, 피로감, 장기적으로 폐고혈압 증상이 발생할 수 있습니다. 증상이 있는 경우 반드시 소아심장과 또는 심장내과 전문의 진료를 받으시기 바랍니다.', 2074, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심실 중격 결손', '심실중격결손', 'DIAGNOSIS', '빠른 호흡(빈호흡)과 수유 곤란 증상이 있는 영아는 선천성 심장 기형의 가능성이 있어 소아심장과 전문의 진료를 받아야 합니다. 심실 중격 결손 진단을 위해서는 심장 청진, 심전도, 흉부 X선, 심장 초음파가 시행됩니다. 증상이 있다면 소아과 또는 소아심장과를 방문하여 정확한 평가를 받으시기 바랍니다.', 2075, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '심실 중격 결손', '심실중격결손', 'TREATMENT', '선천성 심실 중격 결손의 치료는 결손 크기와 증상에 따라 다르며, 소형 결손은 자연 폐쇄를 기대하며 경과 관찰할 수 있습니다. 심부전 증상이 있는 경우 이뇨제, 디곡신 등 약물 치료로 증상을 완화하며, 수술적 결손 봉합 또는 경피적 카테터 시술로 근치적 치료가 가능합니다. 치료 방법 결정은 소아심장과 또는 심장내과 전문의의 정밀 평가 후 이루어져야 합니다.', 2076, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '울혈성 심부전', '울혈성심부전', 'DIET_LIFE', '울혈성 심부전 환자는 저염식(나트륨 하루 2g 이하)이 필수이며, 수분 섭취도 담당 의사의 지시에 따라 제한할 수 있습니다. 알코올은 심근 기능을 직접 저하시키므로 가능한 금주하거나 극소량으로 제한해야 합니다. 포화지방과 트랜스지방을 줄이고 과일·채소·통곡물 위주의 식단이 권장되며, 구체적인 식이 지침은 담당 전문의와 상의하세요.', 2077, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '울혈성 심부전', '울혈성심부전', 'MEDICATION', '울혈성 심부전 치료에 사용되는 이뇨제는 전해질 이상(저칼륨혈증)·탈수·저혈압을 유발할 수 있으며, ACE 억제제는 마른기침·고칼륨혈증·저혈압이 부작용으로 나타날 수 있습니다. 베타차단제는 서맥·피로감·현기증을, 디곡신은 과량 복용 시 부정맥·오심·시각 이상을 일으킬 수 있습니다. 부작용이 의심되면 즉시 담당 심장내과 전문의에게 알려 약물 조정 여부를 상담하세요.', 2078, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '울혈성 심부전', '울혈성심부전', 'PREVENTION', '울혈성 심부전 예방을 위해서는 고혈압·당뇨·고지혈증·관상동맥질환 등 심장 질환의 위험 인자를 정기적으로 관리하는 것이 중요합니다. 심전도, 심장 초음파, 혈액 검사(BNP, NT-proBNP), 흉부 X선 등의 정기 검진이 심부전의 조기 발견에 도움이 됩니다. 위험 인자가 있는 경우 매년 심장내과 전문의 추적 검진을 받으시기 바랍니다.', 2079, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '울혈성 심부전', '울혈성심부전', 'EXERCISE', '울혈성 심부전 환자에게 적절한 운동은 심폐 기능 개선, 삶의 질 향상, 입원율 감소에 도움이 됩니다. 의사의 평가 후 걷기나 자전거 등 중저강도 유산소 운동이 권장되며, 심부전 악화 증상(호흡 곤란 심화, 부종 증가, 체중 급증)이 있을 때는 운동을 중단해야 합니다. 운동 종류·강도·빈도는 반드시 담당 심장내과 전문의와 상의하여 결정하세요.', 2080, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '울혈성 심부전', '울혈성심부전', 'CAUSE', '울혈성 심부전의 주요 원인은 관상동맥질환(심근경색), 고혈압성 심장 질환, 심근증(확장성·비후성), 판막 질환입니다. 당뇨병, 비만, 만성 심방 세동, 심근염, 알코올성 심근증, 항암제 독성도 원인이 될 수 있습니다. 원인에 따라 치료 방향이 달라지므로 정확한 원인 규명을 위해 심장내과 전문의의 정밀 검사가 필요합니다.', 2081, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '울혈성 심부전', '울혈성심부전', 'DEFINITION', '울혈성 심부전은 심장이 신체 조직에 필요한 혈액을 충분히 공급하지 못하는 상태로, 주로 심장과 폐에 영향을 주지만 신장·간·뇌 등 다른 장기에도 영향을 미칩니다. 신장으로의 혈류 감소로 인해 신부전이 동반될 수 있으며, 이를 심신증후군(cardiorenal syndrome)이라 합니다. 심부전과 신부전이 함께 있는 경우 치료가 복잡해지므로 심장내과·신장내과 전문의의 협진이 필요합니다.', 2082, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '울혈성 심부전', '울혈성심부전', 'SYMPTOM', '울혈성 심부전 환자는 운동 시 호흡 곤란 외에도 야간 발작성 호흡 곤란(누우면 숨이 차서 깨는 증상), 하지 부종, 체중 급증, 만성 피로감, 복부 팽만감이 동반될 수 있습니다. 심한 경우 거품 섞인 분홍색 가래나 안정 시 호흡 곤란도 나타납니다. 이러한 증상이 나타나면 즉시 심장내과 전문의 진료를 받으시기 바랍니다.', 2083, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '울혈성 심부전', '울혈성심부전', 'DIAGNOSIS', '쉽게 피로하고 운동 시 힘이 드는 증상이 울혈성 심부전 의심 증상이라면, 내과 또는 심장내과가 있는 의원·종합병원·대학병원을 방문하시면 됩니다. 심장 초음파, 심전도, 혈액 검사(BNP), 흉부 X선 등을 통해 정확한 진단이 가능합니다. 증상이 급격히 악화되거나 호흡 곤란이 심한 경우에는 응급실을 방문하시기 바랍니다.', 2084, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '울혈성 심부전', '울혈성심부전', 'TREATMENT', '울혈성 심부전이 유전적 원인(가족성 심근증 등)에 의한 경우에도 대부분 약물 치료가 우선이며, 수술이 반드시 필요한 것은 아닙니다. 그러나 약물 치료에 반응하지 않는 중증 심부전에서는 심장 재동기화 치료(CRT), 이식형 제세동기(ICD), 좌심실 보조 장치(LVAD), 최종적으로 심장 이식이 고려될 수 있습니다. 수술 필요 여부는 담당 심장내과 전문의가 종합적으로 판단합니다.', 2085, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '저혈압', '저혈압', 'CHECKUP', '저혈압 확인을 위해 안정 시 및 기립 시 혈압 측정이 기본이며, 원인에 따라 혈액 검사, 심전도, 심장 초음파, 기립경사 검사 등이 시행될 수 있습니다. 양수색전증이 의심되는 경우에는 혈액 응고 검사, 흉부 CT, 심초음파 등 응급 검사가 필요하며, 산부인과와 중환자 전문의의 즉각적인 개입이 필요합니다. 두 질환이 동시에 의심된다면 즉시 응급 진료를 받으시기 바랍니다.', 2086, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '저혈압', '저혈압', 'DIET_LIFE', '저혈압 완화를 위해 충분한 수분과 염분 섭취가 권장되며, 소량씩 자주 먹는 식습관이 식후 저혈압 예방에 도움이 됩니다. 갑작스러운 기립 시 어지럼증 방지를 위해 천천히 일어나는 습관, 압박 스타킹 착용, 규칙적인 가벼운 운동(걷기 등)이 효과적입니다. 알코올·과도한 탄수화물 섭취는 혈압을 더 낮출 수 있어 주의가 필요하며, 심한 경우 전문의 상담이 필요합니다.', 2087, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '저혈압', '저혈압', 'MEDICATION', '저혈압 치료에 사용되는 약물로는 플루드로코르티손(혈장량 증가), 미도드린(혈관 수축), 드록시도파 등이 있으며, 투여 전 원인 평가와 의사 처방이 필수입니다. 플루드로코르티손은 부종·고혈압·저칼륨혈증을, 미도드린은 누운 자세 고혈압·두피 가려움을 유발할 수 있습니다. 저혈압 약물 치료는 반드시 내과 또는 순환기내과 전문의의 지도 하에 진행하세요.', 2088, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '저혈압', '저혈압', 'PREVENTION', '저혈압 예방을 위해 충분한 수분(하루 2L 이상)과 소금 섭취를 유지하고, 식사는 소량씩 자주 하는 것이 도움이 됩니다. 장시간 서 있거나 갑작스럽게 일어나는 것을 피하고, 기립 시에는 천천히 단계적으로 자세를 변경해야 합니다. 더운 환경, 과도한 음주, 장시간 입욕은 혈압을 떨어뜨릴 수 있어 주의하시기 바랍니다.', 2089, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '저혈압', '저혈압', 'CAUSE', '불면증·변비·구역질·시력 장애 자체가 저혈압의 직접적인 원인은 아니지만, 자율신경계 이상(파킨슨병, 당뇨성 자율신경병증 등)이나 전신 질환이 이 증상들과 저혈압을 동시에 유발할 수 있습니다. 탈수, 영양 결핍, 특정 약물 복용도 간접적으로 혈압을 낮출 수 있습니다. 이러한 증상이 함께 나타난다면 원인 질환 감별을 위해 내과 또는 신경과 전문의 진료를 받으시기 바랍니다.', 2090, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '저혈압', '저혈압', 'DEFINITION', '대사성 산증은 혈액 내 산성 물질이 과도하게 축적되거나 중탄산염이 감소하여 혈액 pH가 7.35 미만으로 떨어지는 상태입니다. 원인으로는 당뇨성 케톤산증, 젖산산증, 신부전, 설사로 인한 중탄산염 손실 등이 있으며, 저혈압·두통·복통·빠른 호흡(쿠스마울 호흡)·구역질 등이 동반됩니다. 대사성 산증이 의심되면 즉시 응급 진료를 받아 혈액 가스 분석 검사를 시행해야 합니다.', 2091, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '저혈압', '저혈압', 'SYMPTOM', '양수색전증은 양수가 모체 혈액 내로 유입되어 발생하는 응급 상태로, 갑작스러운 저혈압·호흡 부전·심정지·경련·파종성 혈관내 응고(DIC)가 나타납니다. 심폐 기능 상실은 조직 저산소증과 다발성 장기 부전으로 이어질 수 있어 매우 치명적입니다. 이 상황은 즉각적인 심폐소생술과 집중치료가 필요한 산과적 응급으로, 즉시 응급 처치가 이루어져야 합니다.', 2092, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '저혈압', '저혈압', 'DIAGNOSIS', '머리가 핑 도는 증상(어지럼증)은 저혈압의 대표적인 증상으로, 특히 갑자기 일어설 때 나타나는 기립성 저혈압이 흔합니다. 저혈압 진단은 안정 시 혈압이 수축기 90mmHg 미만인 경우이며, 기립성 저혈압은 기립 3분 내 수축기 혈압이 20mmHg 이상 떨어질 때 진단됩니다. 진단을 위해 내과 또는 순환기내과를 방문하여 혈압 측정, 기립경사 검사, 원인 감별 검사를 받으시기 바랍니다.', 2093, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '저혈압', '저혈압', 'TREATMENT', '저혈압 치료는 원인에 따라 다르며, 혈압을 낮추는 약물은 저혈압 환자에게는 중단하거나 감량해야 합니다. 비약물 치료로 수분·염분 섭취 증가, 압박 스타킹, 천천히 일어나기가 권장되며, 중증의 경우 미도드린이나 플루드로코르티손이 처방될 수 있습니다. 저혈압의 정확한 원인 파악과 치료 방법은 내과 또는 순환기내과 전문의와 상의하여 결정하세요.', 2094, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '전도 장애', '전도장애', 'CAUSE', '전도 장애의 원인이 허혈성 심장 질환인 경우 금연·저지방식·규칙적 운동이 핵심이며, 심근증에 의한 경우 음주를 제한하고 심장 기능 보존을 위한 약물 복용이 중요합니다. 고혈압·당뇨가 원인인 경우 혈압과 혈당 관리가 우선이며, 전해질 이상이 원인이라면 전해질 균형 유지가 필요합니다. 원인별 맞춤 관리를 위해 심장내과 전문의의 정기적인 추적 진료가 권장됩니다.', 2095, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '전도 장애', '전도장애', 'DEFINITION', '전도 장애는 심장의 전기 신호 전달 경로에 이상이 생겨 심박수나 리듬이 비정상적으로 되는 질환으로, 방실 차단·각차단·동기능 부전 등이 포함됩니다. 주요 증상으로 가슴 두근거림, 호흡 곤란 외에도 어지럼증, 실신, 흉통, 과도한 피로감, 운동 불내성이 나타날 수 있습니다. 증상이 있는 경우 심장내과 전문의 진료를 통해 정확한 평가를 받으시기 바랍니다.', 2096, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '전도 장애', '전도장애', 'SYMPTOM', '전도 장애로 인해 심박출량이 감소하면 뇌혈류가 줄어 어지럼증과 두통이 발생할 수 있으며, 심장의 비효율적인 수축으로 흉부 통증이 나타날 수 있습니다. 특히 고도 방실 차단이나 동기능 부전 시 심박수가 너무 느려지면 뇌와 심근에 혈류 공급이 저하됩니다. 이러한 증상이 동반될 경우 심장내과 전문의에게 즉시 진료를 받으시기 바랍니다.', 2097, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '전도 장애', '전도장애', 'DIAGNOSIS', '가슴 두근거림·호흡 곤란·실신 증상이 있는 전도 장애 환자의 진단을 위해 심전도, 홀터 모니터링, 이벤트 레코더, 기립경사 검사가 시행됩니다. 심장 초음파와 전기생리학적 검사를 통해 구조적 이상과 부정맥 회로를 정밀 평가하며, 진단 결과에 따라 약물, 인공 심박동기 삽입, 카테터 절제술 등이 고려됩니다. 진단 및 치료 방법은 심장내과 전문의와 상의하세요.', 2098, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '전도 장애', '전도장애', 'TREATMENT', '전도 장애가 심혈관계 질환과 직접 관련이 없더라도, 증상(어지럼증·실신·호흡 곤란)이 있거나 심박수가 지나치게 느린 경우에는 치료가 필요할 수 있습니다. 증상 없는 경미한 차단(1도 방실 차단, 우각차단 등)은 경과 관찰만으로 충분한 경우도 있으나, 치료 여부는 반드시 심장내과 전문의의 평가를 통해 결정해야 합니다. 방치할 경우 실신이나 급사로 이어질 수 있어 정기적인 추적 관찰이 중요합니다.', 2099, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '죽상경화증', '죽상경화증', 'DIET_LIFE', '식이 섬유가 풍부한 채소·과일·통곡물·콩류는 LDL 콜레스테롤 수치를 낮추고 동맥 내 플라크 형성을 억제하여 죽상경화증 예방에 도움이 됩니다. 오메가-3 지방산이 풍부한 등 푸른 생선, 올리브 오일 등 불포화지방산을 섭취하고 포화지방·트랜스지방·정제 탄수화물을 줄이는 것이 중요합니다. 금연과 규칙적인 운동을 병행하며, 구체적인 식이 계획은 담당 의사 또는 영양사와 상의하세요.', 2100, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '죽상경화증', '죽상경화증', 'MEDICATION', '스타틴 계열 약물은 LDL 콜레스테롤을 효과적으로 낮추어 죽상경화증 진행을 억제하는 데 도움이 되며, 식이와 생활 습관 개선을 병행할 때 더욱 효과적입니다. 약물 치료와 함께 저지방·고섬유 식단, 금연, 규칙적인 유산소 운동, 체중 관리를 시행하는 것이 권장됩니다. 약물 복용 여부와 종류는 반드시 내과 또는 심장내과 전문의의 처방에 따라 결정해야 합니다.', 2101, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '죽상경화증', '죽상경화증', 'PREVENTION', '죽상경화증 예방을 위해 포화지방과 트랜스지방을 줄이고 식이 섬유·불포화지방산이 풍부한 지중해식 식단이 권장됩니다. 금연, 규칙적인 유산소 운동(주 150분 이상), 정상 체중 유지, 고혈압·당뇨·고지혈증 관리가 핵심적인 예방 전략입니다. 40세 이상이거나 위험 인자가 있는 경우 정기적인 콜레스테롤·혈압·혈당 검사를 통해 조기 발견하고, 이상이 있으면 전문의 상담을 받으세요.', 2102, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '죽상경화증', '죽상경화증', 'EXERCISE', '죽상경화증으로 혈관이 좁아진 경우 고강도 운동은 심근경색 등 위험을 높일 수 있으므로, 중강도 유산소 운동(걷기·수영·자전거)을 규칙적으로 시행하는 것이 혈관 건강에 도움이 됩니다. 운동은 HDL(좋은 콜레스테롤)을 높이고 LDL과 혈압을 낮추는 효과가 있으며, 주 5회 30분 이상의 유산소 운동이 권장됩니다. 운동 시작 전 담당 심장내과 전문의의 평가를 받아 안전한 운동 강도를 확인하세요.', 2103, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '죽상경화증', '죽상경화증', 'CAUSE', '죽상경화증의 주요 원인은 높은 LDL 콜레스테롤로 인한 동맥 내벽 플라크 형성이며, 고혈압·당뇨·흡연·비만·가족력이 발생 위험을 크게 높입니다. 만성 염증, 산화 스트레스, 내피세포 손상이 플라크 형성을 촉진하며, 여러 위험 인자가 복합적으로 작용합니다. 위험 인자를 조기에 파악하고 관리하기 위해 정기적인 혈액 검사와 내과 또는 심장내과 전문의 진료를 받으시기 바랍니다.', 2104, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '죽상경화증', '죽상경화증', 'DEFINITION', '경동맥 초음파에서 죽상경화증이 발견된 경우 뇌졸중 위험이 증가할 수 있으므로, 내과 또는 심장내과·신경과 전문의 진료를 통해 치료 계획을 세워야 합니다. 치료는 생활 습관 개선, 스타틴 등 지질강하제, 항혈소판제(아스피린 등)가 포함될 수 있으며, 협착이 심한 경우 경동맥 내막 절제술이나 스텐트 시술이 필요할 수 있습니다. 뒷머리 당김 증상도 지속되면 신경과 진료를 함께 받으시기 바랍니다.', 2105, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '죽상경화증', '죽상경화증', 'SYMPTOM', '죽상경화증과 고혈압이 동반된 경우 흉통(협심증), 간헐적 파행(다리 통증), 어지럼증, 시야 이상, 두통 등의 증상이 나타날 수 있습니다. 이러한 증상 발생 시 심전도, 운동부하 검사, 경동맥·하지동맥 초음파, 관상동맥 CT 또는 조영술 검사가 필요합니다. 증상이 있다면 지체 없이 심장내과 또는 내과 전문의의 진료를 받으시기 바랍니다.', 2106, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '죽상경화증', '죽상경화증', 'DIAGNOSIS', '죽상경화증 진단을 위해 공복 혈액 검사(총 콜레스테롤·LDL·HDL·중성지방·혈당), 혈압 측정이 기본적으로 시행됩니다. 이후 경동맥 초음파(IMT 측정), 발목-상완 혈압지수(ABI), 관상동맥 CT 등의 영상 검사로 실제 혈관 상태를 평가하며, 증상이 있으면 관상동맥조영술이 진행될 수 있습니다. 이러한 검사를 통해 죽상경화증의 정도와 위험도를 종합적으로 평가할 수 있습니다.', 2107, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '죽상경화증', '죽상경화증', 'TREATMENT', '죽상경화증에서 약물 치료(스타틴·에제티미브·PCSK9 억제제) 외에 생활 습관 개선(저지방식·운동·금연), 혈압 및 혈당 조절이 병행되어야 합니다. 심한 협착의 경우 경피적 관상동맥 중재술(스텐트 삽입) 또는 관상동맥우회술이 시행될 수 있으며, 항혈소판 치료도 병용됩니다. 치료 계획은 죽상경화증의 위치와 중증도에 따라 심장내과 전문의가 개별적으로 결정합니다.', 2108, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '폐 혈전색전증', '폐혈전색전증', 'CAUSE', '폐 혈전색전증은 주로 하지 심부정맥에서 형성된 혈전이 떨어져 폐동맥을 막으면서 발생합니다. 주요 위험 인자로는 장기 부동 상태(장거리 비행·수술 후), 악성 종양, 임신 및 산욕기, 경구 피임약 복용, 혈전성 소인(혈전증 유발 유전자), 비만, 심부전 등이 있습니다. 이러한 위험 인자가 있는 경우 예방적 조치와 정기 검진을 위해 전문의 상담을 받으시기 바랍니다.', 2109, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '폐 혈전색전증', '폐혈전색전증', 'DEFINITION', '폐 혈전색전증은 폐동맥 또는 그 분지가 혈전으로 막혀 폐의 혈액 순환이 차단되는 질환입니다. 혈전은 폐 외에도 하지 심부정맥(DVT), 뇌(뇌졸중), 상지 정맥, 문맥 등 다른 부위에도 발생할 수 있으며, 이를 정맥 혈전색전증(VTE)이라 총칭합니다. 혈전이 의심되는 증상이 있으면 즉시 응급 진료를 받으시기 바랍니다.', 2110, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '폐 혈전색전증', '폐혈전색전증', 'SYMPTOM', '반복적인 호흡 곤란과 기절할 것 같은 증상은 폐 혈전색전증의 의심 증상입니다. 폐 혈전색전증의 주요 증상으로는 갑작스러운 호흡 곤란, 흉통(특히 숨 쉴 때 악화), 빈맥, 기침, 객혈, 실신 전 느낌 또는 실신 등이 있습니다. 이러한 증상이 반복된다면 즉시 응급실 또는 내과·호흡기내과 전문의 진료를 받으시기 바랍니다.', 2111, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '폐 혈전색전증', '폐혈전색전증', 'DIAGNOSIS', '폐 혈전색전증이 의심되는 경우 응급 혈액 검사(D-dimer), 심전도, 흉부 X선이 우선 시행되며, D-dimer 상승 시 CT 폐혈관조영술(CTPA)로 확진합니다. 심장 초음파로 우심실 부하 여부를 평가하고, 중증도 분류 후 항응고 치료 또는 혈전용해술이 결정됩니다. 호흡 곤란과 흉통이 동반되면 즉시 응급실을 방문하여 빠른 검사와 치료를 받으시기 바랍니다.', 2112, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '폐 혈전색전증', '폐혈전색전증', 'TREATMENT', '폐 혈전색전증의 치료는 항응고 요법(헤파린, 저분자량 헤파린, 경구 항응고제)이 기본이며, 중증의 경우 혈전용해제(알테플라제 등) 투여가 시행됩니다. 혈전용해제가 금기이거나 효과가 없는 경우 카테터를 이용한 혈전 제거술이나 외과적 색전 제거술이 고려됩니다. 재발 방지를 위해 장기간 항응고 치료와 원인 인자 교정이 필요하므로 호흡기내과 또는 내과 전문의의 지속적인 관리가 필요합니다.', 2113, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '폐색성 혈전 혈관염', '폐색성혈전혈관염', 'CHECKUP', '폐색성 혈전 혈관염(버거병) 검진은 혈관외과 또는 내과(순환기내과)를 방문하면 됩니다. 팔과 다리 혈압 비교(ABI 검사), 혈관 초음파, 혈관조영술 등이 가능한 병원을 찾으시면 되며, 주요 대학병원 혈관외과에서 전문적인 검진이 가능합니다. 증상이 있다면 가까운 내과나 외과 전문의를 먼저 방문하여 의뢰를 받는 것이 효율적입니다.', 2114, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '폐색성 혈전 혈관염', '폐색성혈전혈관염', 'DIET_LIFE', '폐색성 혈전 혈관염 환자는 말단 부위 혈액 순환 개선을 위해 항산화 성분이 풍부한 채소·과일·오메가-3 지방산(등 푸른 생선) 섭취가 권장됩니다. 포화지방·가공식품·과도한 당류는 혈관 염증을 악화시킬 수 있어 제한해야 하며, 충분한 수분 섭취도 중요합니다. 이 질환에서 가장 중요한 치료 원칙은 완전한 금연이므로, 금연이 이루어지지 않으면 다른 치료 효과가 제한됩니다.', 2115, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '폐색성 혈전 혈관염', '폐색성혈전혈관염', 'MEDICATION', '폐색성 혈전 혈관염 치료에는 혈관 확장제(프로스타글란딘 계열: 일로프로스트, 알프로스타딜)가 가장 많이 사용되며, 혈소판 응집 억제를 위한 아스피린이나 실로스타졸도 처방됩니다. 통증 조절을 위한 진통제도 사용되며, 이로피로스트 정맥 주사는 심한 허혈에 효과적입니다. 약물 처방은 증상의 중증도와 개인 상황에 따라 다르므로 혈관외과 전문의와 상의하세요.', 2116, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '폐색성 혈전 혈관염', '폐색성혈전혈관염', 'PREVENTION', '폐색성 혈전 혈관염의 손발끝 저림 증상 완화를 위해 가장 중요한 것은 완전한 금연으로, 흡연을 계속하면 어떤 치료도 효과가 없습니다. 추위 노출을 피하고 보온에 신경 쓰며, 꽉 끼는 신발이나 양말을 피해야 합니다. 혈관 순환 개선을 위한 규칙적인 걷기 운동과 함께, 증상이 지속될 경우 혈관외과 전문의 진료를 받아 적절한 약물 치료를 받으시기 바랍니다.', 2117, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '폐색성 혈전 혈관염', '폐색성혈전혈관염', 'CAUSE', '폐색성 혈전 혈관염은 주로 흡연과 강한 연관성이 있으며, 40세 이하의 남성 흡연자에게 주로 발생합니다. 흡연 성분이 혈관 내피를 손상시키고 염증성 혈전을 유발하여 중소 동맥과 정맥을 폐색시킵니다. 손발가락 통증과 창백함이 있다면 혈관외과를 방문하여 ABI 검사, 혈관 초음파, 혈관조영술을 통한 정확한 진단이 필요합니다.', 2118, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '폐색성 혈전 혈관염', '폐색성혈전혈관염', 'DEFINITION', '폐색성 혈전 혈관염 관리에는 ABI(발목-상완 혈압지수) 측정기, 혈관 초음파, 혈관조영술 장비가 사용되며, 통증 평가와 허혈 정도 분류를 위해 모세혈관 충전 시간 등을 평가합니다. 정기적인 혈관 초음파와 ABI 측정을 통해 질환 진행 여부를 추적 관찰하며, 검진 결과는 혈관외과 또는 순환기내과 외래에서 전문의에게 설명을 받을 수 있습니다.', 2119, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '폐색성 혈전 혈관염', '폐색성혈전혈관염', 'SYMPTOM', '폐색성 혈전 혈관염은 다리와 발가락에 혈관 폐색으로 인한 허혈성 통증, 간헐적 파행(걸을 때 통증), 안정 시 통증, 피부 창백·청색증, 궤양·괴저 등이 나타날 수 있습니다. 발가락 통증이 이 질환과 관련이 있는지는 흡연력, 통증 양상, 색조 변화 등을 평가하여 혈관외과 전문의가 확인할 수 있습니다. 해당 증상이 있다면 반드시 혈관외과 또는 순환기내과 전문의 진료를 받으시기 바랍니다.', 2120, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '폐색성 혈전 혈관염', '폐색성혈전혈관염', 'DIAGNOSIS', '폐색성 혈전 혈관염 재진단이 필요한 경우 혈관외과(혈관 전문) 또는 순환기내과 전문의를 찾으시면 됩니다. 대학병원 혈관외과에서 혈관조영술·ABI·혈관 초음파 등 정밀 검사를 통해 정확한 진단과 치료 방향을 재평가받을 수 있습니다. 이전 진단 기록과 검사 결과를 지참하여 방문하시면 보다 효율적인 진료가 가능합니다.', 2121, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '폐색성 혈전 혈관염', '폐색성혈전혈관염', 'TREATMENT', '폐색성 혈전 혈관염의 가장 중요한 치료는 완전한 금연이며, 금연 없이는 다른 치료의 효과가 매우 제한적입니다. 약물 치료로는 혈관 확장제(프로스타글란딘), 항혈소판제가 사용되며, 심한 허혈에는 교감신경 차단술이 고려됩니다. 괴저가 진행된 경우 절단이 불가피할 수 있으며, 치료 계획은 혈관외과 전문의와 상의하여 결정하세요.', 2122, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '하지 정맥류', '하지정맥류', 'DIET_LIFE', '하지 정맥류 예방과 증상 완화를 위해 장시간 서거나 앉아 있는 경우 주기적으로 발목 운동을 하고 압박 스타킹을 착용하는 것이 권장됩니다. 식이 측면에서는 식이 섬유가 풍부한 음식으로 변비를 예방하고, 충분한 수분 섭취와 체중 관리가 도움이 됩니다. 다리를 심장보다 높게 올리는 습관(취침 시 다리 거상)도 부종과 통증 완화에 효과적입니다.', 2123, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '하지 정맥류', '하지정맥류', 'PREVENTION', '하지 정맥류 예방을 위한 규칙적인 운동은 종아리 근육을 강화하여 정맥 혈액의 심장 복귀를 도와줍니다. 걷기, 수영, 자전거 타기 등 종아리 근육을 사용하는 유산소 운동이 특히 효과적이며, 하루 30분 이상 규칙적으로 시행하는 것이 권장됩니다. 반면 장시간 서 있거나 앉아 있는 것은 정맥압을 높이므로 피하고, 증상이 있다면 혈관외과 전문의 진료를 받으시기 바랍니다.', 2124, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '하지 정맥류', '하지정맥류', 'CAUSE', '하지 정맥류는 오래 서 있거나 앉아 있는 직업(미용사·요리사·교사 등)에서 정맥 내 압력이 지속적으로 높아져 발생 위험이 증가합니다. 정맥 판막이 약해지면 혈액이 역류하여 정맥이 늘어나게 되며, 발 부종도 정맥 혈류 장애로 인한 증상입니다. 이 외에도 임신, 비만, 가족력도 주요 위험 인자이며, 증상이 지속되면 혈관외과 전문의 진료를 권장합니다.', 2125, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '하지 정맥류', '하지정맥류', 'DEFINITION', '다리가 쉽게 피로하고 무거운 느낌이 든다면 하지 정맥류가 의심되며, 진단을 위해 혈관외과 또는 흉부외과(혈관 전문)를 방문하시면 됩니다. 정맥 도플러 초음파 검사가 하지 정맥류의 핵심 진단 방법으로, 정맥 판막 역류 여부를 확인합니다. 증상이 있다면 초음파 검사를 통해 정확한 진단과 치료 계획을 세우시기 바랍니다.', 2126, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '하지 정맥류', '하지정맥류', 'SYMPTOM', '하지 정맥류에서 야간 다리 저림, 쥐남(근경련), 피부 아래 거미줄 모양의 실핏줄(거미상 정맥류·그물형 정맥류)은 흔한 증상이며, 특히 오래 서 있거나 취침 전에 악화되는 경향이 있습니다. 이 외에도 다리 부종, 가려움증, 피부 변색이 동반될 수 있습니다. 이러한 증상이 지속된다면 혈관외과 전문의를 방문하여 정맥 초음파 검사를 받으시기 바랍니다.', 2127, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '하지 정맥류', '하지정맥류', 'DIAGNOSIS', '다리에 이전에 보이지 않던 혈관이 돌출되거나 구불구불해 보인다면 하지 정맥류를 의심할 수 있는 증상입니다. 진단은 혈관외과, 흉부외과(혈관 전문), 또는 피부과에서 받을 수 있으며, 정맥 도플러 초음파로 확진합니다. 증상이 있다면 가까운 외과 또는 혈관외과를 방문하여 정확한 평가를 받으시기 바랍니다.', 2128, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '하지 정맥류', '하지정맥류', 'TREATMENT', '하루 종일 서서 일하는 경우 압박 스타킹 착용, 1시간마다 짧은 휴식 중 발목 운동 및 걷기, 근무 후 다리 거상이 효과적입니다. 체중 관리와 규칙적인 운동(수영·걷기)으로 종아리 근육을 강화하면 정맥 혈류 개선에 도움이 됩니다. 증상이 심하거나 이미 정맥류가 진행된 경우 혈관경화요법, 레이저 치료, 수술 등의 치료를 혈관외과 전문의와 상담하시기 바랍니다.', 2129, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '허혈성 심질환', '허혈성심질환', 'DIET_LIFE', '허혈성 심질환 관리를 위해 포화지방·트랜스지방·콜레스테롤이 많은 음식(붉은 고기·가공식품·튀긴 음식)을 줄이고, 오메가-3 지방산이 풍부한 생선·견과류·올리브 오일을 섭취하는 것이 권장됩니다. 채소·과일·통곡물·콩류 등 식이 섬유가 풍부한 식품이 심장 건강에 도움이 되며, 염분 제한과 금연, 절주도 중요합니다. 구체적인 식이 계획은 담당 심장내과 전문의 또는 영양사와 상의하세요.', 2130, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '허혈성 심질환', '허혈성심질환', 'MEDICATION', '허혈성 심질환 치료에 사용되는 아스피린은 위장 출혈·위궤양의 위험이 있으며, 베타차단제는 서맥·피로감·저혈압·기관지 수축을 유발할 수 있습니다. 스타틴은 근육통(근병증)·간수치 상승을, 질산염(니트로글리세린)은 두통·저혈압을 일으킬 수 있습니다. 부작용이 의심될 경우 임의로 약을 중단하지 말고 반드시 담당 심장내과 전문의와 상의하세요.', 2131, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '허혈성 심질환', '허혈성심질환', 'PREVENTION', '허혈성 심질환 예방 관점에서 운동부하검사는 심근 허혈 유발 여부를 평가하며, 핵의학 검사(심근관류 스캔)는 실제 혈류 감소 부위를 시각화하여 더욱 정밀한 정보를 제공합니다. 운동부하검사에서 음성이더라도 핵의학 검사에서 허혈이 발견될 수 있으며, 이는 심근관류 스캔의 높은 민감도 때문입니다. 검사 결과 해석과 예방 전략 수립은 심장내과 전문의와 상의하세요.', 2132, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '허혈성 심질환', '허혈성심질환', 'EXERCISE', '허혈성 심질환 환자의 운동 시 호흡 곤란 완화를 위해 준비 운동과 마무리 운동을 충분히 하고, 걷기나 자전거 등 저강도에서 시작하여 점진적으로 강도를 높이는 것이 권장됩니다. 호흡 곤란이 심할 때는 즉시 운동을 중단하고 휴식을 취해야 하며, 빨리 걷기보다는 천천히 꾸준히 하는 것이 안전합니다. 운동 처방은 반드시 심장내과 전문의의 평가 후 개인에 맞게 결정해야 합니다.', 2133, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '허혈성 심질환', '허혈성심질환', 'CAUSE', '허혈성 심질환은 주로 관상동맥 협착으로 심근에 혈액이 부족해지지만, 심각한 경우 신장·뇌·하지 말초 혈관에도 죽상경화증이 동시에 진행되어 신부전·뇌졸중·말초동맥질환이 함께 나타날 수 있습니다. 이를 전신 죽상경화증이라 하며, 한 부위에 발생한 경우 다른 부위도 점검이 필요합니다. 전신적인 혈관 상태 평가를 위해 심장내과 전문의의 종합적인 진료를 받으시기 바랍니다.', 2134, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '허혈성 심질환', '허혈성심질환', 'DEFINITION', '허혈성 심질환은 관상동맥 협착으로 심근에 혈류가 감소하는 질환으로, 협심증(가슴 통증·압박감·조이는 느낌)이 주요 증상이며 급성 심근경색으로 진행될 수 있습니다. 심근 손상이 지속되면 심부전·부정맥·심인성 쇼크 등 심각한 합병증이 발생할 수 있으며, 안정 시에도 증상이 나타나는 경우 응급 상황일 수 있습니다. 흉통이나 흉부 압박감이 있으면 즉시 심장내과 전문의 진료 또는 응급실을 방문하세요.', 2135, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '허혈성 심질환', '허혈성심질환', 'SYMPTOM', '허혈성 심질환의 전형적인 증상인 협심증은 운동이나 신체 활동 시 심근 산소 수요가 증가할 때 발생하는 경우가 많아, 운동 후 흉통·흉부 압박감·호흡 곤란이 나타날 가능성이 높습니다. 안정 시에는 증상이 없다가 운동 후 수분 이내 완화되는 경우 안정형 협심증의 특징입니다. 운동 중 또는 후에 이러한 증상이 반복된다면 즉시 심장내과 전문의 진료를 받으시기 바랍니다.', 2136, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '허혈성 심질환', '허혈성심질환', 'DIAGNOSIS', '허혈성 심질환 의심 증상(가슴 통증·불편감)으로 전문의 상담을 원한다면 내과 또는 심장내과(순환기내과)를 방문하면 됩니다. 초진 시 증상 병력 청취, 신체 검진, 심전도, 혈액 검사(심근 효소)가 시행되며, 이후 운동부하검사, 심장 초음파, 관상동맥 CT 등이 추가될 수 있습니다. 증상이 갑자기 심해지거나 안정 시에도 통증이 있다면 즉시 응급실을 방문하세요.', 2137, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '허혈성 심질환', '허혈성심질환', 'TREATMENT', '허혈성 심질환에서 관상동맥 협착이 확인되면 약물 치료와 함께 경피적 관상동맥 중재술(PCI, 스텐트 삽입술)이 시행될 수 있으며, 다혈관 병변이나 좌주간지 병변의 경우 관상동맥 우회술(CABG)이 권장됩니다. 시술 전 관상동맥조영술로 병변 위치와 중증도를 확인하며, 시술 후에는 항혈소판제 복용과 위험 인자 관리가 필수입니다. 구체적인 시술 방법은 심장내과 전문의와 상의하여 결정하세요.', 2138, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '혈관염', '혈관염', 'CAUSE', '혈관염은 혈관 벽에 염증이 발생하는 질환으로, 원인은 자가면역 반응, 감염(B형·C형 간염 바이러스 등), 약물, 악성 종양과의 연관성이 있습니다. 면역 복합체가 혈관 벽에 침착되거나 자가항체(ANCA 등)가 혈관을 공격하여 염증을 유발하며, 침범하는 혈관 크기에 따라 대혈관·중혈관·소혈관 혈관염으로 분류됩니다. 정확한 원인 파악을 위해 류마티스내과 또는 내과 전문의의 진료가 필요합니다.', 2139, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '혈관염', '혈관염', 'DEFINITION', '혈관염은 혈관 벽에 염증이 생기는 질환으로, 침범 혈관의 크기와 위치에 따라 다양한 증상을 나타냅니다. 다리에 붉은 반점(자반증)이 나타나고 가려움을 동반하는 경우 소혈관 혈관염(피부 백혈구파괴성 혈관염 등)을 의심할 수 있으며, 이는 피부 소혈관에 염증이 생겨 발생합니다. 이러한 증상이 있다면 피부과 또는 류마티스내과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 2140, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '혈관염', '혈관염', 'SYMPTOM', '혈관염에서 창백함·붉음·부종이 동반되는 경우 혈관 염증으로 인한 허혈이나 울혈을 의심할 수 있으며, 피부 생검, 혈액 검사(ANCA, ANA, 보체, 적혈구침강속도, CRP), 소변 검사(단백뇨·혈뇨)가 진단에 중요합니다. 내장 혈관이 침범된 경우 CT 혈관조영술이나 혈관조영술도 시행됩니다. 이러한 증상이 있다면 류마티스내과 또는 내과 전문의에게 진료를 받으시기 바랍니다.', 2141, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '혈관염', '혈관염', 'DIAGNOSIS', '혈관염의 특징적인 증상인 붉은 반점이 다리와 팔에 나타날 경우, 류마티스내과 또는 피부과 전문의를 찾아 정확한 진단을 받는 것이 권장됩니다. 류마티스내과에서는 ANCA 관련 혈관염, IgA 혈관염 등 전신 혈관염을, 피부과에서는 피부 국소 혈관염을 전문적으로 평가합니다. 증상이 전신적이거나 신장·폐 등 내장 침범이 의심될 경우 류마티스내과를 먼저 방문하시기 바랍니다.', 2142, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '혈관염', '혈관염', 'TREATMENT', '혈관염 치료에서 스테로이드(코르티코스테로이드) 외에 면역억제제(메토트렉세이트, 아자티오프린, 사이클로포스파미드, 리툭시맙)가 중증도와 종류에 따라 사용됩니다. 경미한 경우 콜히친이나 다푸손이 사용될 수 있으며, 원인이 감염이나 약물인 경우 원인 제거만으로 호전될 수 있습니다. 치료 방법은 혈관염의 유형과 침범 부위에 따라 다르므로 류마티스내과 전문의와 상의하여 결정하세요.', 2143, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '협심증', '협심증', 'MEDICATION', '협심증에서 동맥 내 지방과 칼슘 축적을 줄이기 위해 스타틴 계열 약물(아토르바스타틴, 로수바스타틴 등)이 LDL 콜레스테롤을 낮추고 플라크를 안정화하는 데 효과적입니다. 에제티미브·PCSK9 억제제도 콜레스테롤 저하에 사용되며, 항혈소판제(아스피린, 클로피도그렐)는 혈전 형성을 예방합니다. 약물 선택과 용량은 반드시 심장내과 전문의의 처방에 따라 결정해야 합니다.', 2144, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '협심증', '협심증', 'PREVENTION', '협심증 예방을 위한 운동은 규칙적인 유산소 운동이 핵심으로, 주 3~5회 30분 이상 빠르게 걷기, 자전거 타기, 수영 등이 권장됩니다. 운동 강도는 최대 심박수의 50~70% 수준을 유지하고, 운동 전후 준비운동과 마무리 운동을 반드시 시행해야 합니다. 유전력이 있는 경우 심장전문의 상담 후 안전한 운동 계획을 수립하시기 바랍니다.', 2145, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '협심증', '협심증', 'CAUSE', '협심증의 주요 원인은 관상동맥의 죽상경화증으로, 콜레스테롤 플라크가 혈관 내벽에 쌓여 혈관이 좁아지면서 심근에 산소 공급이 부족해집니다. 고혈압, 당뇨, 고지혈증, 흡연, 비만, 운동 부족, 가족력 등이 위험인자로 작용합니다. 운동이나 활동 시 심근의 산소 요구량이 증가해 좁아진 혈관으로는 충분한 혈액을 공급하지 못해 흉통이 발생합니다.', 2146, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '협심증', '협심증', 'DEFINITION', '협심증은 관상동맥이 죽상경화증 등으로 좁아져 심근에 충분한 혈액과 산소가 공급되지 못해 발생하는 허혈성 심질환입니다. 주로 운동이나 스트레스 등 심장의 산소 수요가 증가할 때 가슴 압박감, 쥐어짜는 듯한 통증이 나타나며 안정 시 호전되는 것이 특징입니다. 안정형, 불안정형, 변이형 협심증으로 분류되며, 방치 시 심근경색으로 진행될 수 있어 전문의 진료가 필요합니다.', 2147, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '협심증', '협심증', 'SYMPTOM', '협심증 환자에서 가슴 압박감과 불편함은 매우 흔한 증상으로, 흉골 뒤쪽 또는 좌측 가슴에서 시작해 턱, 어깨, 팔로 방사될 수 있습니다. 증상 완화를 위한 운동은 의사의 지도하에 저강도 유산소 운동(걷기, 수영)을 점진적으로 시행하는 것이 도움이 됩니다. 그러나 운동 중 흉통이 나타나면 즉시 중단하고, 운동 프로그램 시작 전 반드시 심장전문의 상담을 받으시기 바랍니다.', 2148, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '협심증', '협심증', 'DIAGNOSIS', '가슴이 쥐어짜는 듯한 증상은 협심증이나 심근경색 등 허혈성 심질환의 주요 증상이므로, 순환기내과(심장내과) 전문의를 방문하는 것이 최우선입니다. 심전도, 심장초음파, 운동부하검사, 관상동맥 CT 등을 통해 정확한 진단이 이루어집니다. 증상이 갑자기 심해지거나 안정 시에도 발생한다면 즉시 응급실을 방문하시기 바랍니다.', 2149, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '협심증', '협심증', 'TREATMENT', '협심증의 수술 외 치료 방법으로는 약물치료와 경피적 관상동맥 중재술(PCI, 스텐트 삽입술)이 있습니다. 약물치료는 니트레이트, 베타차단제, 칼슘채널차단제, 항혈소판제 등을 사용하여 증상을 조절하고 혈전 형성을 예방합니다. 치료 방법 선택은 협심증의 중증도와 병변 위치에 따라 다르므로 반드시 심장전문의와 상담하여 최적의 치료 계획을 수립하시기 바랍니다.', 2150, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고나트륨혈증', '고나트륨혈증', 'MEDICATION', '고나트륨혈증에 두통, 불안감, 경련, 의식 혼미 등 신경학적 증상이 동반될 경우 즉각적인 입원 치료와 약물치료가 필요합니다. 치료의 핵심은 저장성 수액(5% 포도당, 0.45% 생리식염수)으로 혈청 나트륨 농도를 서서히 교정하는 것이며, 경련이 있으면 항경련제도 병용합니다. 혈청 나트륨을 너무 빠르게 교정하면 뇌부종이 발생할 수 있어 반드시 전문의 감독하에 치료받으셔야 합니다.', 2151, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고나트륨혈증', '고나트륨혈증', 'CAUSE', '고나트륨혈증은 나트륨 과다 섭취보다 수분 부족이 더 흔한 원인으로, 주요 원인으로는 수분 섭취 부족, 과도한 발한·구토·설사로 인한 수분 손실, 요붕증(ADH 결핍 또는 저항), 신장 기능 저하 등이 있습니다. 고령자나 영아에서는 갈증 기전 이상으로 수분 섭취가 줄어 발생하기도 합니다. 정확한 원인 파악을 위해 전문의 진료 및 혈액·소변 검사가 필요합니다.', 2152, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고나트륨혈증', '고나트륨혈증', 'DEFINITION', '고나트륨혈증은 혈청 나트륨 농도가 145mEq/L를 초과한 상태로, 주로 수분 부족, 과도한 수분 손실(구토·설사·발한), 요붕증, 과도한 나트륨 섭취 등으로 발생합니다. 증상으로는 갈증, 구강 건조, 피로감, 두통, 의식 혼탁, 경련, 심한 경우 혼수까지 나타날 수 있으며 주로 신경계 증상이 두드러집니다. 증상이 나타나면 즉시 내과 또는 신장내과 전문의 진료를 받으시기 바랍니다.', 2153, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고나트륨혈증', '고나트륨혈증', 'SYMPTOM', '구토와 혈압 저하는 고나트륨혈증의 원인 요소(수분 손실)로도 작용하지만, 증상이 동반될 경우 내과 방문 후 혈청 전해질 검사, 소변 전해질 및 삼투압 검사, 신기능 검사(BUN, 크레아티닌)를 받아야 합니다. 이를 통해 고나트륨혈증의 원인과 중증도를 파악할 수 있습니다. 심한 구토나 혈압 저하가 있다면 즉시 응급실을 방문하시기 바랍니다.', 2154, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고나트륨혈증', '고나트륨혈증', 'DIAGNOSIS', '고나트륨혈증은 혈청 나트륨 농도가 145mEq/L 초과 시 진단되며, 혈액 검사로 확인합니다. 소변 삼투압과 소변 나트륨 농도를 함께 분석하면 원인을 감별할 수 있는데, 소변 삼투압이 낮으면 요붕증, 높으면 신장 외 수분 손실을 시사합니다. 검사 결과 해석과 치료 방향 결정은 내과 또는 신장내과 전문의에게 의뢰하시기 바랍니다.', 2155, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고나트륨혈증', '고나트륨혈증', 'TREATMENT', '중증 고나트륨혈증은 신경계 합병증 위험으로 입원 치료가 원칙이나, 경증이고 증상이 없는 경우 외래에서 경구 수분 보충으로 관리할 수 있습니다. 외래 치료 시 충분한 수분 섭취, 원인 질환(요붕증 등) 약물 치료, 나트륨 섭취 제한이 병행됩니다. 그러나 치료 방법과 범위는 반드시 내과 또는 신장내과 전문의 판단에 따라 결정해야 합니다.', 2156, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고마그네슘혈증', '고마그네슘혈증', 'CHECKUP', '고마그네슘혈증 검진은 내과 또는 신장내과에서 받으실 수 있으며, 혈청 마그네슘 수치 측정을 포함한 전해질 검사를 시행합니다. 전국 대학병원 및 종합병원의 내과, 신장내과를 방문하시거나 가까운 내과 의원에서 기초 검사 후 전원받으실 수 있습니다. 증상이 심하다면 즉시 응급실을 방문하시기 바랍니다.', 2157, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고마그네슘혈증', '고마그네슘혈증', 'DIET_LIFE', '마그네슘 보충제를 과다 복용하면 신장의 배설 능력을 초과하여 혈중 마그네슘 농도가 상승해 고마그네슘혈증이 발생할 수 있습니다. 마그네슘이 적절히 도움이 되는 식단으로는 견과류, 통곡물, 녹색 채소, 두류를 균형 있게 섭취하되, 신장 기능에 이상이 없는 경우에 한합니다. 보충제 복용량은 반드시 전문의와 상담하여 적정 용량을 확인하시기 바랍니다.', 2158, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고마그네슘혈증', '고마그네슘혈증', 'MEDICATION', '고마그네슘혈증 치료 약물로는 칼슘글루코네이트(심장 독성 차단), 푸로세미드(이뇨제를 통한 마그네슘 배설 촉진), 중증 시 혈액투석이 사용됩니다. 칼슘글루코네이트는 마그네슘의 심장 및 신경근 독성을 즉각적으로 길항하는 응급 처치제입니다. 약물 선택과 용량은 혈청 마그네슘 수치와 증상의 중증도에 따라 전문의가 결정해야 합니다.', 2159, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고마그네슘혈증', '고마그네슘혈증', 'PREVENTION', '고마그네슘혈증에서 마그네슘 함유 음식을 제한하는 것은 마그네슘 과부하를 줄여 혈중 농도를 낮추는 데 도움이 되기 때문입니다. 섬유질이 풍부한 음식은 장내 마그네슘 흡수를 일부 억제하고, 식사의 균형을 유지하며 전반적인 신장 건강에 도움을 줍니다. 식이 조절만으로는 한계가 있으므로 반드시 신장내과 전문의와 함께 치료 계획을 수립하시기 바랍니다.', 2160, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고마그네슘혈증', '고마그네슘혈증', 'CAUSE', '고마그네슘혈증의 외부 요인으로는 마그네슘 함유 제산제·하제·보충제의 과다 복용이 가장 흔하며, 신기능 저하(만성 신부전) 환자에서는 마그네슘 배설이 감소해 위험이 높아집니다. 또한 과도한 마그네슘 함유 식품 섭취나 마그네슘 황산염 치료(자간증)도 원인이 될 수 있습니다. 특히 신장 질환, 당뇨, 고령 등의 기저 질환이 있는 경우 더욱 주의가 필요합니다.', 2161, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고마그네슘혈증', '고마그네슘혈증', 'DEFINITION', '고마그네슘혈증 치료는 원인 제거(마그네슘 보충제·제산제 중단)가 우선이며, 증상이 있으면 칼슘글루코네이트 정맥 투여로 심장 독성을 즉각 차단합니다. 이뇨제(푸로세미드) 투여로 마그네슘 배설을 촉진하고, 신기능 저하가 있거나 중증인 경우 혈액투석으로 마그네슘을 제거합니다. 치료 경과는 혈청 마그네슘 수치와 임상 증상을 모니터링하며 전문의 지도하에 진행됩니다.', 2162, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고마그네슘혈증', '고마그네슘혈증', 'SYMPTOM', '고마그네슘혈증에서 눈 떨림(안진)은 마그네슘 과잉으로 인한 신경근 기능 억제의 초기 징후 중 하나로, 어지러움·구역·구토와 함께 나타날 수 있습니다. 마그네슘 농도가 높아질수록 근력 저하, 반사 저하, 호흡 억제, 심장 전도 장애로 진행되므로 이러한 증상들은 서로 연관되어 있습니다. 위와 같은 증상이 나타나면 즉시 내과 또는 응급실을 방문하시기 바랍니다.', 2163, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고마그네슘혈증', '고마그네슘혈증', 'DIAGNOSIS', '비타민 D 복용 후 컨디션 저하와 고마그네슘혈증이 의심된다면, 가까운 내과 의원 또는 종합병원 내과에서 혈청 전해질(마그네슘, 칼슘 포함) 검사를 받으시기 바랍니다. 비타민 D 자체가 고마그네슘혈증을 직접 유발하지는 않으나, 전해질 불균형 여부는 혈액 검사로 확인해야 합니다. 증상이 심하거나 의식 변화가 있다면 즉시 응급실을 방문하시기 바랍니다.', 2164, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고마그네슘혈증', '고마그네슘혈증', 'TREATMENT', '고마그네슘혈증으로 인한 근육 마비나 호흡 곤란 등 중증 증상에는 칼슘글루코네이트 정맥 주사가 즉각적인 길항 효과를 발휘하는 가장 효과적인 응급 처치입니다. 호흡 부전 시에는 기도 확보 및 인공호흡 지원이 필요하며, 신기능 저하 환자는 혈액투석이 필수적입니다. 이러한 중증 상태는 즉시 응급실을 방문하여 집중치료를 받아야 합니다.', 2165, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고칼륨혈증', '고칼륨혈증', 'CAUSE', '고칼륨혈증의 원인으로 칼륨이 많은 식품(바나나, 오렌지, 감자, 토마토 등)의 과다 섭취가 포함되지만, 신기능이 정상인 경우 식이만으로 고칼륨혈증이 발생하기는 드뭅니다. 주로 신부전, 당뇨 관련 저알도스테론증, ACE억제제·칼륨보존 이뇨제 복용 등이 병합될 때 위험이 높아집니다. 신기능 저하가 있는 환자는 칼륨 함량이 높은 식품 섭취에 특히 주의하시기 바랍니다.', 2166, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고칼륨혈증', '고칼륨혈증', 'DEFINITION', '고칼륨혈증은 혈청 칼륨 농도가 5.5mEq/L를 초과한 상태로, 신기능 저하, 부신기능 부전, 세포 파괴(용혈, 횡문근융해), 특정 약물(ACE억제제, 칼륨보존 이뇨제) 등이 원인입니다. 칼륨 농도가 과도하게 높아지면 심장 전도 장애(부정맥), 근육 마비, 심정지 등 생명을 위협하는 합병증이 발생할 수 있습니다. 고칼륨혈증이 의심되면 즉시 내과 또는 신장내과 전문의 진료를 받으시기 바랍니다.', 2167, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고칼륨혈증', '고칼륨혈증', 'SYMPTOM', '고칼륨혈증의 증상으로는 근육 무력감, 피로감, 사지 저림·마비, 심계항진, 부정맥, 심한 경우 심정지가 나타날 수 있습니다. 소화기 증상으로 오심, 구토, 복통도 동반될 수 있으며, 심전도에서 텐트형 T파, PR 간격 연장, 넓은 QRS 등 특징적인 변화가 확인됩니다. 이러한 증상이 나타나면 즉시 응급실 또는 내과 전문의를 방문하시기 바랍니다.', 2168, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고칼륨혈증', '고칼륨혈증', 'DIAGNOSIS', '근육 무력감과 반사 신경 저하를 동반하는 고칼륨혈증은 내과 또는 신장내과 전문의가 진단합니다. 혈청 전해질 검사로 칼륨 수치를 확인하고, 심전도 검사로 심장 이상 여부를 평가합니다. 증상이 심하거나 심전도 이상이 있는 경우 즉각적인 응급 치료가 필요하므로 지체 없이 의료기관을 방문하시기 바랍니다.', 2169, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고칼륨혈증', '고칼륨혈증', 'TREATMENT', '고칼륨혈증 치료에 사용되는 약물로는 심장 보호를 위한 칼슘글루코네이트, 칼륨을 세포 내로 이동시키는 인슐린+포도당 및 알부테롤, 칼륨 배설을 촉진하는 푸로세미드(이뇨제), 위장관을 통한 칼륨 제거를 위한 칼리메이트(폴리스티렌술폰산나트륨)가 사용됩니다. 중증이거나 약물치료에 반응하지 않으면 혈액투석이 필요합니다. 약물 선택과 투여는 반드시 전문의 지도하에 이루어져야 합니다.', 2170, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고환염', '고환염', 'CAUSE', '고환염의 원인은 바이러스(유행성 이하선염 바이러스가 가장 흔함), 세균(대장균, 클라미디아, 임질균 등 성매개감염 포함) 외에도 자가면역 반응, 외상, 요로 시술 후 합병증 등이 있습니다. 또한 부고환염이 고환으로 파급되어 발생하는 경우가 많으며, 결핵균이 원인이 되는 경우도 있습니다. 정확한 원인 파악을 위해 비뇨의학과 전문의 진료가 필요합니다.', 2171, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고환염', '고환염', 'DEFINITION', '고환염은 고환에 염증이 발생하는 질환으로, 바이러스나 세균 감염이 주요 원인이며 고환의 부종, 발적, 통증이 특징적 증상입니다. 유행성 이하선염(볼거리) 합병증으로 발생하거나 성매개감염(클라미디아, 임질)에 의해 유발될 수 있습니다. 고환 부종과 통증이 있다면 고환 염전 등 응급 질환과 감별이 필요하므로 즉시 비뇨의학과 전문의를 방문하시기 바랍니다.', 2172, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고환염', '고환염', 'SYMPTOM', '고환염의 주요 증상은 고환의 부종, 발적, 심한 통증이며, 발열과 오한이 동반되는 경우도 많습니다. 경미한 따끔거림이나 둔통도 초기 증상으로 나타날 수 있으나, 증상의 강도는 개인과 원인에 따라 다양합니다. 오른쪽 고환에 지속적인 불편감이 있다면 고환 염전, 부고환염 등과의 감별을 위해 비뇨의학과 전문의 진료를 받으시기 바랍니다.', 2173, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고환염', '고환염', 'DIAGNOSIS', '고환염 예방을 위해 MMR(홍역·볼거리·풍진) 예방접종이 가장 중요하며, 성매개감염 예방을 위한 안전한 성관계(콘돔 사용)가 필요합니다. 연령에 관계없이 요로감염이나 성매개감염의 조기 치료가 고환염으로의 진행을 막을 수 있습니다. 고환 불편감이나 통증이 있으면 조기에 비뇨의학과 전문의를 방문하여 진단받는 것이 중요합니다.', 2174, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '고환염', '고환염', 'TREATMENT', '고환염은 대부분 항생제(세균성) 또는 소염진통제, 안정, 음낭 거상 등 보존적 치료로 호전되며, 수술이 반드시 필요한 것은 아닙니다. 다만 농양이 형성되었거나 고환 염전이 동반된 경우, 괴사성 감염 등의 합병증 발생 시 외과적 절개 배농 또는 응급 수술이 필요합니다. 치료 방법은 원인과 중증도에 따라 비뇨의학과 전문의가 결정합니다.', 2175, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '과민성 방광', '과민성방광', 'DIET_LIFE', '카페인과 알코올은 방광을 자극하여 배뇨 충동을 증가시키고 방광 용량을 감소시키므로, 이를 제한하면 과민성 방광 증상 완화에 효과적입니다. 카페인은 이뇨 작용과 방광 자극 효과가 있으며, 알코올도 이뇨 효과와 함께 방광 과민성을 악화시킵니다. 음료 제한과 함께 방광 훈련, 골반저 근육 운동 등을 병행하면 증상 개선에 더욱 도움이 됩니다.', 2176, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '과민성 방광', '과민성방광', 'MEDICATION', '과민성 방광 치료제(항무스카린제, 베타3 작용제)는 직접적으로 단백뇨를 유발하지는 않으나, 당뇨 환자에서 단백뇨가 발견되면 신기능 평가가 우선입니다. 과민성 방광은 당뇨 합병증으로 인한 방광 신경병증과 연관될 수 있으므로, 두 질환의 관리가 함께 필요합니다. 복용 중인 약물과 단백뇨의 연관성은 내과 또는 신장내과 전문의와 상담하시기 바랍니다.', 2177, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '과민성 방광', '과민성방광', 'CAUSE', '과민성 방광은 나이가 들면서 방광 근육(배뇨근)의 불수의적 수축이 증가하고 방광 용량이 감소하여 유병률이 높아집니다. 이 외에도 여성의 경우 폐경 후 에스트로겐 감소, 골반저 근육 약화, 남성의 경우 전립선 비대증도 원인이 됩니다. 나이 외에 비만, 당뇨, 뇌졸중 등 신경계 질환도 발병 위험을 높입니다.', 2178, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '과민성 방광', '과민성방광', 'REHAB', '과민성 방광 치료 후 누울 때 소변이 마려운 증상은 방광 훈련이 완전히 정착되지 않았거나 야간 다뇨가 동반된 경우일 수 있습니다. 방광 훈련을 통해 배뇨 간격을 점진적으로 늘리고, 저녁 시간대 수분 섭취를 조절하는 것이 도움이 됩니다. 지속적인 증상이 있다면 비뇨의학과 전문의와 상담하여 치료 계획을 재평가하시기 바랍니다.', 2179, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '과민성 방광', '과민성방광', 'DEFINITION', '과민성 방광은 요절박(갑작스럽고 강한 요의), 빈뇨(하루 8회 이상), 야간뇨, 절박성 요실금 등을 특징으로 하는 방광 기능 장애입니다. 하루 소변 횟수가 8회 이상이면서 참기 어려운 요절박이 동반된다면 과민성 방광을 의심할 수 있습니다. 정확한 진단을 위해서는 비뇨의학과 전문의 진료와 배뇨 일지 작성이 필요합니다.', 2180, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '과민성 방광', '과민성방광', 'SYMPTOM', '과민성 방광의 주요 증상으로 소변을 자주 참지 못하고 실수(절박성 요실금)가 생기는 것 외에, 하루 8회 이상의 빈뇨, 야간뇨(밤에 1회 이상 소변을 위해 깨는 것), 갑자기 강하게 소변이 마려운 요절박 증상이 동반됩니다. 이러한 증상들이 일상생활에 지장을 준다면 비뇨의학과 전문의를 방문하여 정확한 진단과 적절한 치료를 받으시기 바랍니다.', 2181, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '과민성 방광', '과민성방광', 'DIAGNOSIS', '소변을 참기 힘들고 자주 화장실을 가는 과민성 방광 증상이 있다면 비뇨의학과 또는 산부인과(여성의 경우)를 방문하시기 바랍니다. 요역동학 검사, 소변 검사, 방광 초음파 등으로 다른 질환과 감별 진단이 이루어집니다. 가까운 비뇨의학과 의원에서 초기 평가 후 필요시 대학병원으로 의뢰받을 수 있습니다.', 2182, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '과민성 방광', '과민성방광', 'TREATMENT', '과민성 방광의 약물치료(항무스카린제, 베타3 작용제) 외에 행동 치료로 방광 훈련, 배뇨 일지 작성, 골반저 근육 운동(케겔 운동)이 효과적입니다. 생활습관 개선으로 카페인·알코올·자극성 음식 제한, 적절한 수분 섭취 조절도 중요합니다. 약물과 행동 치료에 반응하지 않는 경우 방광 내 보톡스 주입술이나 신경 조절술을 고려할 수 있으며 전문의 상담을 권장합니다.', 2183, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 방광염', '급성방광염', 'DIET_LIFE', '급성 방광염 예방과 증상 완화를 위해 하루 1.5~2L 이상의 충분한 수분 섭취가 권장되며, 소변을 오래 참지 않도록 합니다. 카페인, 알코올, 자극적인 음식은 방광 자극을 악화시키므로 제한하고, 배변 후 항문에서 요도 쪽으로 닦는 방향 위생 관리가 중요합니다(특히 여성). 면역력 유지를 위한 균형 잡힌 식사와 충분한 수면, 크랜베리 제품 섭취가 재발 예방에 도움이 될 수 있습니다.', 2184, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 방광염', '급성방광염', 'MEDICATION', '급성 방광염의 주요 치료제는 항생제로, 트리메토프림-설파메톡사졸, 퀴놀론계, 세팔로스포린계 등이 사용되며 소변 배양 결과에 따라 선택합니다. 급성 방광염 자체가 손발 부종을 직접 유발하지는 않으나, 신우신염으로 진행되거나 신기능에 영향을 미치는 경우 부종이 생길 수 있습니다. 손발 부종이 동반된다면 신기능 평가를 위해 내과 또는 비뇨의학과 전문의를 방문하시기 바랍니다.', 2185, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 방광염', '급성방광염', 'PREVENTION', '야간뇨(자다가 화장실에 1~2회 가는 것)는 급성 방광염의 증상 중 하나이지만, 단독으로는 방광염의 특이적 지표가 아닙니다. 급성 방광염 예방을 위해 충분한 수분 섭취, 소변을 자주 비우기, 성관계 후 소변 보기, 개인 위생 관리(항문에서 요도 방향으로 닦기), 꽉 끼는 속옷 피하기 등이 권장됩니다. 야간뇨가 지속된다면 비뇨의학과 전문의 상담을 받으시기 바랍니다.', 2186, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 방광염', '급성방광염', 'CAUSE', '급성 방광염의 배뇨 시 통증과 빈뇨를 확인하는 검사로 소변 검사(요침사 검사)를 통해 백혈구, 적혈구, 세균 유무를 확인하고, 소변 배양 검사로 원인균과 항생제 감수성을 파악합니다. 이 검사들은 비뇨의학과, 내과, 가정의학과 등에서 시행할 수 있습니다. 증상이 있다면 즉시 의원 방문 후 소변 검사를 받으시기 바랍니다.', 2187, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 방광염', '급성방광염', 'DEFINITION', '급성 방광염의 전형적 증상으로 빈뇨(소변이 자주 마려움), 배뇨통(소변 볼 때 찌릿한 통증), 혈뇨(육안적 또는 현미경적), 절박뇨, 하복부 불쾌감 등이 포함됩니다. 언급하신 증상들은 급성 방광염의 전형적인 증상에 해당합니다. 혈뇨가 동반된 경우 방광암, 신장 결석 등 다른 질환과 감별이 필요하므로 비뇨의학과 전문의 진료를 받으시기 바랍니다.', 2188, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 방광염', '급성방광염', 'SYMPTOM', '급성 방광염에서 소변 보기 힘든 증상(배뇨 곤란)이 동반되는 경우, 배뇨 시 심한 작열감·통증, 소변줄기 약화, 배뇨 후 잔뇨감, 하복부 압박감 등이 나타날 수 있습니다. 심한 경우 요폐(소변이 전혀 나오지 않음)로 진행될 수 있으며, 이는 남성에서는 전립선 비대증이 동반된 경우 더 빈번합니다. 배뇨 곤란이 지속되면 즉시 비뇨의학과 전문의를 방문하시기 바랍니다.', 2189, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 방광염', '급성방광염', 'DIAGNOSIS', '급성 방광염 진단 절차는 먼저 증상 청취와 신체 검사 후 소변 검사(요침사)로 백혈구·적혈구·세균 유무를 확인합니다. 소변 배양 검사를 통해 원인균을 동정하고 항생제 감수성을 파악하며, 필요시 방광 초음파나 복부 CT로 구조적 이상 여부를 평가합니다. 단순 방광염은 비뇨의학과 또는 내과에서 진단 및 치료받을 수 있습니다.', 2190, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 방광염', '급성방광염', 'TREATMENT', '급성 방광염의 요도 통증과 빈뇨는 세균이 방광 점막을 자극·감염시켜 염증 반응이 일어나면서 방광 근육의 과도한 수축과 통증 신호가 발생하는 것입니다. 이는 세균(주로 대장균)이 요도를 통해 방광으로 침입하여 발생하며, 조기에 적절한 항생제 치료를 받으면 대부분 완치됩니다. 증상 완화와 완치를 위해 비뇨의학과 전문의 진료와 항생제 처방을 받으시기 바랍니다.', 2191, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신부전', '급성신부전', 'CHECKUP', '급성 신부전 환자에서 소변량 모니터링은 신기능 회복 여부와 치료 반응을 평가하는 필수적 지표입니다. 소변을 임의로 참는 것은 방광 과충전, 역류성 신손상, 감염 위험을 높일 수 있으므로 절대 권장되지 않습니다. 소변량 측정은 의료진의 지도하에 이루어져야 하며, 핍뇨나 무뇨가 발생하면 즉시 의료팀에 알려야 합니다.', 2192, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신부전', '급성신부전', 'DIET_LIFE', '급성 신부전 환자의 식이 조절로는 저단백 식단(신장 부담 감소), 칼륨·인·나트륨 제한이 권장됩니다. 과일(바나나, 오렌지), 견과류, 유제품 등 칼륨·인이 많은 식품은 피하고, 충분한 열량은 탄수화물과 지방으로 공급합니다. 개인별 신기능 상태에 따라 식이 제한이 다를 수 있으므로 반드시 신장내과 전문의 및 영양사와 상담하시기 바랍니다.', 2193, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신부전', '급성신부전', 'MEDICATION', '급성 신부전 환자에서 다른 약물을 중복 복용할 경우, 신독성 약물(NSAIDs, 아미노글리코사이드 항생제, 조영제 등)이 신손상을 악화시킬 수 있습니다. 또한 신기능 저하로 약물 배설이 감소하여 약물 혈중 농도가 높아지고 부작용 위험이 증가합니다. 복용 중인 모든 약물을 담당 신장내과 전문의에게 반드시 알리고 처방 조정을 받으시기 바랍니다.', 2194, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신부전', '급성신부전', 'PREVENTION', '급성 신부전 예방을 위해 충분한 수분 섭취로 탈수를 방지하고, 저염식·저단백 식사로 신장 부담을 줄이는 것이 중요합니다. 규칙적인 중등도 운동은 혈압 조절과 심혈관 기능 개선을 통해 신장으로의 혈류를 유지하는 데 도움이 됩니다. 당뇨, 고혈압 등 기저 질환이 있는 경우 철저한 관리가 신기능 보호에 핵심이므로 내과 또는 신장내과 정기 진료를 받으시기 바랍니다.', 2195, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신부전', '급성신부전', 'EXERCISE', '혈액 투석 중인 급성 신부전 환자에게는 저강도 유산소 운동인 걷기, 고정식 자전거 타기, 가벼운 스트레칭이 혈액 순환 개선에 도움이 됩니다. 투석 중 운동(intradialytic exercise)도 안전하게 시행 가능하며 심폐 기능 향상에 효과적입니다. 운동 강도와 종류는 심혈관 상태와 투석 일정을 고려하여 담당 의료진과 상담 후 결정하시기 바랍니다.', 2196, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신부전', '급성신부전', 'CAUSE', '급성 신부전의 원인 중 신장 자체 이상(신성 급성 신부전)은 전체의 약 35~40%를 차지하며, 급성 세뇨관 괴사(허혈성, 신독성), 급성 사구체신염, 급성 간질성 신염 등이 해당됩니다. 조영제, NSAIDs, 아미노글리코사이드 항생제 등 신독성 물질 노출이나 심한 저혈압에 의한 허혈이 주요 원인입니다. 신장 자체 질환이 의심되면 신장내과 전문의 진료 및 신장 조직 검사가 필요할 수 있습니다.', 2197, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신부전', '급성신부전', 'DEFINITION', '의식불명으로 응급실 내원 시 급성 신부전 진단을 위해 혈청 크레아티닌, 혈청 요소질소(BUN), 전해질(칼륨, 나트륨, 중탄산염), 혈액 가스 분석, 전혈구 검사 등 혈액 검사를 시행합니다. 소변 검사(요침사, 소변 전해질, 소변 삼투압)와 신장 초음파로 원인 감별을 합니다. 급성 신부전은 혈청 크레아티닌의 급격한 상승 또는 소변량 감소 기준으로 진단됩니다.', 2198, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신부전', '급성신부전', 'SYMPTOM', '급성 신부전 시 신기능 저하로 나타나는 증상으로는 핍뇨 또는 무뇨, 전신 부종(눈 주위, 하지), 고혈압, 오심·구토, 식욕 부진, 피로감 등이 있습니다. 전해질 불균형(고칼륨혈증, 저나트륨혈증)으로 근육 경련, 심계항진, 의식 변화가 올 수 있으며, 요독증이 심하면 흉막염, 심낭염도 발생할 수 있습니다. 이러한 증상이 나타나면 즉시 응급실 또는 신장내과 전문의를 방문하시기 바랍니다.', 2199, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신부전', '급성신부전', 'DIAGNOSIS', '급성 신부전 진단에 가장 핵심적인 혈액 검사는 혈청 크레아티닌 검사로, 48시간 이내 0.3mg/dL 이상 상승 또는 7일 이내 기저치의 1.5배 이상 상승 시 진단됩니다. 혈청 시스타틴 C는 크레아티닌보다 신기능 저하를 조기에 반영하는 더 민감한 표지자로 유용합니다. 단일 검사보다 BUN/크레아티닌 비율, 전해질, 소변 검사를 종합적으로 분석하는 것이 정확도를 높입니다.', 2200, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신부전', '급성신부전', 'TREATMENT', '탈수에 의한 급성 신부전(전신성 급성 신부전)에서 수액 치료는 탈수 교정 후 신기능이 빠르게 회복되는 경우 수 일에서 1~2주 이내에 정상화될 수 있습니다. 수액의 종류와 속도, 입원 기간은 탈수 정도, 기저 질환, 신기능 회복 속도에 따라 다르므로 일률적으로 정할 수 없습니다. 수액 치료와 회복 기간은 담당 내과 또는 신장내과 전문의가 임상 경과를 보며 결정합니다.', 2201, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신우신염', '급성신우신염', 'DIET_LIFE', '급성 신우신염 환자는 하루 2~3L 이상의 충분한 수분 섭취로 소변을 통한 세균 배출을 촉진하고, 소변을 오래 참지 않도록 합니다. 단백질과 염분 섭취를 적절히 조절하여 신장 부담을 줄이고, 면역력 강화를 위한 균형 잡힌 영양 섭취와 충분한 휴식이 중요합니다. 알코올, 카페인, 자극적인 음식은 방광을 자극할 수 있으므로 피하시기 바랍니다.', 2202, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신우신염', '급성신우신염', 'MEDICATION', '급성 신우신염에서 항생제 복용 후 구토가 발생하면 식후 복용을 시도하거나 공복에 복용하는 방법을 바꿔보고, 증상이 지속되면 처방 의사에게 알려 약 변경 또는 구토 억제제 병용을 고려해야 합니다. 항생제는 임의로 중단하지 않는 것이 중요하며, 경구 복용이 불가능할 정도의 심한 구토라면 입원하여 정맥 항생제 투여가 필요합니다. 구토 증상이 지속되면 즉시 담당 의사에게 알리시기 바랍니다.', 2203, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신우신염', '급성신우신염', 'PREVENTION', '급성 신우신염 합병증(신농양, 패혈증, 만성 신우신염으로의 진행 등) 예방을 위해 처방된 항생제를 완전히 복용하고 임의 중단하지 않아야 합니다. 재발 예방을 위해 충분한 수분 섭취, 배변·배뇨 위생 관리, 요로 기형이나 결석이 있는 경우 원인 치료가 필요합니다. 치료 종료 후 소변 배양 검사로 완치를 확인하고, 재발 시 비뇨의학과 또는 신장내과 전문의 진료를 받으시기 바랍니다.', 2204, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신우신염', '급성신우신염', 'CAUSE', '급성 신우신염의 주요 원인균은 대장균(Escherichia coli, 약 80%)으로, 회음부나 항문 주변의 세균이 요도를 통해 방광, 요관, 신장으로 상행 감염되어 발생합니다. 청결하지 못한 위생 관리, 특히 배변 후 잘못된 닦는 방향(항문에서 요도쪽)은 세균 유입을 촉진합니다. 성 활동, 요로 기형·결석, 면역 저하, 도뇨관 사용 등도 위험 요인으로 작용합니다.', 2205, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신우신염', '급성신우신염', 'DEFINITION', '급성 신우신염은 신장의 신우(콩팥깔때기)와 신실질에 세균 감염으로 인한 급성 염증이 발생하는 질환입니다. 주로 대장균이 하부 요로에서 신장으로 상행하여 발생하며, 발열(38.5°C 이상), 오한, 옆구리 통증, 배뇨통, 빈뇨, 오심·구토 등이 특징적 증상입니다. 적절히 치료하지 않으면 신농양, 패혈증으로 진행될 수 있어 즉각적인 항생제 치료가 필요합니다.', 2206, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신우신염', '급성신우신염', 'SYMPTOM', '급성 신우신염은 발열(38.5°C 이상), 오한, 옆구리(늑척추각) 압통, 배뇨통, 빈뇨가 특징적 증상입니다. 진단을 위해 소변 검사(요침사에서 백혈구, 세균 확인), 소변 배양 검사, 혈액 검사(백혈구 증가, CRP 상승, 혈액 배양), 신장 초음파 또는 CT(농양, 결석 감별)가 시행됩니다. 이러한 증상이 있다면 즉시 내과 또는 비뇨의학과에서 검사를 받으시기 바랍니다.', 2207, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신우신염', '급성신우신염', 'DIAGNOSIS', '옆구리 통증과 배뇨 증상이 있어 급성 신우신염이 의심된다면 내과, 비뇨의학과, 또는 가정의학과를 방문하시기 바랍니다. 소변 검사, 소변 배양, 혈액 검사를 통해 진단하며, 필요시 신장 초음파나 CT로 합병증을 평가합니다. 고열이나 심한 통증이 동반되면 즉시 응급실을 방문하시기 바랍니다.', 2208, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '급성 신우신염', '급성신우신염', 'TREATMENT', '급성 신우신염 치료 후 식욕 부진은 항생제 복용 중 흔히 발생할 수 있는 부작용이지만, 기억력 감퇴는 신우신염의 일반적인 후유증이 아닙니다. 고열과 전신 감염에 의한 피로감으로 일시적인 집중력 저하가 올 수 있으나, 기억력 감퇴가 지속된다면 다른 원인(빈혈, 전해질 이상, 약물 부작용 등)을 확인해야 합니다. 치료 후 지속되는 증상이 있다면 담당 전문의와 상담하시기 바랍니다.', 2209, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '남성 불임', '남성불임', 'CHECKUP', '남성 불임 확인을 위한 기본 검사는 정액 검사(정자 수, 운동성, 형태 분석)이며, 가장 중요한 검사입니다. 추가로 호르몬 검사(FSH, LH, 테스토스테론, 프로락틴), 고환 초음파, 유전자 검사(Y 염색체 미세결실, 핵형 분석)가 필요할 수 있습니다. 정자의 운동성, 형태, 농도를 종합적으로 평가하므로 비뇨의학과 전문의를 방문하여 정밀 검사를 받으시기 바랍니다.', 2210, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '남성 불임', '남성불임', 'DIET_LIFE', '남성 불임 관리에 중요한 영양소로는 아연(정자 생성·성호르몬 합성 필수, 굴·견과류·육류에 풍부), 비타민 C(정자 DNA 산화 손상 방지, 감귤류·딸기에 풍부), 비타민 E(항산화 작용으로 정자막 보호, 견과류·식물성 기름에 풍부)가 있습니다. 엽산과 셀레늄도 정자 형성과 기능에 도움을 주는 것으로 알려져 있습니다. 보충제 복용 전 비뇨의학과 전문의와 상담하시기 바랍니다.', 2211, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '남성 불임', '남성불임', 'MEDICATION', '남성 불임 치료에 사용되는 약물로는 호르몬 이상이 원인인 경우 성선자극호르몬(hCG, FSH), 클로미펜 등이 정자 생성을 유도하는 데 효과적입니다. 그러나 무정자증이나 심한 정자 감소증은 약물만으로 해결이 어려울 수 있으며, 원인에 따라 수술(정계정맥류 교정 등)이나 보조 생식술(ICSI)이 필요합니다. 불임 원인에 맞는 치료 방법은 비뇨의학과 전문의와 상담하여 결정하시기 바랍니다.', 2212, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '남성 불임', '남성불임', 'PREVENTION', '남성 불임 예방을 위해 고환 과열을 피해야 하므로 꽉 끼는 속옷 착용, 장시간 사우나·온탕 사용을 자제합니다. 흡연, 과음, 스테로이드 등 정자 생성을 저해하는 요인을 피하고, 균형 잡힌 식사와 규칙적 운동으로 정상 체중을 유지합니다. 성매개감염병 예방을 위한 안전한 성관계와 함께, 이상 증상 발생 시 조기에 비뇨의학과 전문의를 방문하시기 바랍니다.', 2213, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '남성 불임', '남성불임', 'EXERCISE', '규칙적인 중등도 유산소 운동은 테스토스테론 수치를 정상화하고 산화 스트레스를 감소시켜 정자 품질 개선에 도움이 될 수 있습니다. 그러나 무정자증이나 심한 정자 감소증은 운동만으로 교정되기 어려우며, 원인에 따른 의학적 치료가 병행되어야 합니다. 과도한 고강도 운동(특히 스테로이드 사용)은 오히려 정자 생성을 억제할 수 있으므로, 비뇨의학과 전문의와 함께 치료 계획을 수립하시기 바랍니다.', 2214, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '남성 불임', '남성불임', 'CAUSE', '남성 불임의 과거 원인 요인으로는 소아기 유행성 이하선염(볼거리)에 의한 고환염, 미하강 고환(잠복고환) 방치, 항암 치료나 방사선 치료, 정계정맥류, 과거 성매개감염으로 인한 생식기 손상 등이 생식 세포 발달을 저해할 수 있습니다. 유전적 원인(클라인펠터 증후군, Y 염색체 미세결실)도 선천적으로 정자 생성을 제한합니다. 과거력을 포함한 정확한 원인 규명을 위해 비뇨의학과 전문의 진료를 받으시기 바랍니다.', 2215, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '남성 불임', '남성불임', 'DEFINITION', '남성 불임의 정의는 정상적인 성관계에도 1년 이상 임신이 이루어지지 않는 경우이며, 원인의 약 40~50%가 남성에게 있습니다. 확인 방법으로는 비뇨의학과에서 시행하는 정액 검사가 기본이며, 정자 수, 운동성, 형태를 종합 평가합니다. 결과에 따라 호르몬 검사, 유전자 검사, 고환 초음파 등 추가 검사를 진행하게 됩니다.', 2216, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '남성 불임', '남성불임', 'SYMPTOM', '남성 불임에서 발기 지속 시간이 충분하지 않은 것(발기부전, 조루)은 직접적인 불임의 원인은 아니지만, 성관계를 통한 임신을 어렵게 하는 요인이 될 수 있습니다. 불임의 주요 원인은 정자의 수, 운동성, 형태 이상이므로 발기 문제와 별개로 정액 검사가 필요합니다. 발기부전과 불임 모두 비뇨의학과 전문의에게 종합적인 평가와 치료를 받으시기 바랍니다.', 2217, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '남성 불임', '남성불임', 'DIAGNOSIS', '정액 검사는 남성 불임 진단의 첫 번째 표준 검사로, 정자 수·운동성·형태를 직접 평가하므로 불임 원인 파악에 가장 유용합니다. 혈액 검사(호르몬 검사)는 내분비 이상이나 염색체 이상 감별에 유용하지만 정자 기능을 직접 반영하지는 않습니다. 두 검사를 상호 보완적으로 시행하는 것이 가장 정확하므로 비뇨의학과 전문의와 상담하여 적절한 검사 계획을 세우시기 바랍니다.', 2218, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '남성 불임', '남성불임', 'TREATMENT', '남성 불임의 치료는 원인에 따라 다르며, 호르몬 이상은 약물치료(성선자극호르몬), 정계정맥류는 수술적 교정(현미경 수술)이 효과적입니다. 무정자증은 고환 내 정자 채취술(TESE)과 체외수정(ICSI)을 통한 보조 생식술을 시행합니다. 원인 불명의 남성 불임에는 경험적 항산화 치료, 보조 생식술이 적용되며, 최적의 치료 방법은 비뇨의학과 전문의와 충분히 상담하여 결정하시기 바랍니다.', 2219, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신부전', '만성신부전', 'CHECKUP', '만성 신부전 검진을 위해 신장내과(신장내과)를 방문하여 혈청 크레아티닌, 사구체여과율(eGFR), 소변 단백질(알부민/크레아티닌 비율), BUN, 전해질, 혈압 측정 등을 시행합니다. 소변 검사로 단백뇨·혈뇨 여부를 확인하고, 신장 초음파로 신장 크기와 구조를 평가합니다. 신기능 저하가 의심되면 빠른 시일 내에 신장내과 전문의의 정기적인 관리를 받으시기 바랍니다.', 2220, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신부전', '만성신부전', 'DIET_LIFE', '신장 기능이 30% 남은 만성 신부전 환자에게는 저단백 식단(체중 kg당 0.6~0.8g), 저염식(나트륨 2g 이하/일), 칼륨·인 제한 식단이 권장됩니다. 칼륨이 많은 바나나, 오렌지, 감자, 토마토와 인이 많은 유제품, 가공식품은 제한하고 충분한 열량은 탄수화물로 섭취합니다. 개인별 상태에 따라 식이 제한이 다르므로 반드시 신장내과 전문의 및 영양사와 상담하시기 바랍니다.', 2221, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신부전', '만성신부전', 'MEDICATION', '만성 신부전 환자의 고혈압과 단백뇨(거품뇨) 조절에는 ACE억제제(에날라프릴 등)나 ARB(로사르탄 등)가 1차 약물로 사용되며, 신장 보호 효과가 있습니다. 두통 완화를 위해 혈압 조절이 핵심이며, 이뇨제로 부종을 조절합니다. 약물 선택과 용량은 신장 기능 상태에 따라 조정이 필요하므로 반드시 신장내과 전문의 처방하에 복용하시기 바랍니다.', 2222, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신부전', '만성신부전', 'PREVENTION', '만성 신부전 예방에 건강한 식습관(저염식, 저단백, 저칼륨·인 식단)이 중요한 이유는 과도한 나트륨과 단백질이 신장 여과 부담을 증가시키고 혈압을 상승시켜 신기능 저하를 가속화하기 때문입니다. 규칙적인 운동은 혈압·혈당·체중 조절에 효과적이어서 만성 신부전의 주요 원인인 당뇨와 고혈압 예방 및 관리에 핵심적입니다. 기저 질환이 있다면 내과 또는 신장내과에서 정기적으로 신기능을 모니터링하시기 바랍니다.', 2223, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신부전', '만성신부전', 'EXERCISE', '소변 거품(단백뇨)이 지속된다면 만성 신부전 가능성이 있으며, 이때 규칙적인 유산소 운동(걷기, 수영, 자전거)은 혈압·혈당·체중 조절을 통해 신기능 저하 진행을 늦추는 데 도움이 됩니다. 운동은 심혈관 기능을 개선하고 신장으로의 혈류를 안정화하는 효과도 있습니다. 단, 운동 강도와 종류는 신기능 단계에 따라 조정이 필요하므로 신장내과 전문의와 상담 후 시작하시기 바랍니다.', 2224, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신부전', '만성신부전', 'CAUSE', '만성 신부전에서 소변 거품(단백뇨)은 손상된 사구체에서 단백질이 여과되어 소변으로 누출되기 때문이며, 혈압을 동반한 두통은 신장의 레닌-안지오텐신 시스템 과활성화로 혈압이 상승하여 발생합니다. 만성 신부전의 근본 원인으로는 당뇨병성 신증, 고혈압성 신증, 사구체신염 등이 있으며, 이들이 지속적인 신기능 손상을 일으킵니다. 정확한 원인 규명과 치료를 위해 신장내과 전문의 진료를 받으시기 바랍니다.', 2225, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신부전', '만성신부전', 'DEFINITION', '만성 신부전은 3개월 이상 사구체여과율(eGFR)이 60mL/min/1.73m² 미만이거나 신장 손상의 증거(단백뇨 등)가 지속되는 진행성 신기능 저하 상태입니다. 당뇨는 당뇨병성 신증, 고혈압은 신혈관 손상을 통해 가장 흔한 원인으로 작용하며, 두 질환이 동반되면 신기능 저하 속도가 더욱 빠릅니다. 조기 발견과 철저한 혈당·혈압 관리가 진행을 늦추는 핵심이므로 정기적인 신장내과 진료를 받으시기 바랍니다.', 2226, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신부전', '만성신부전', 'SYMPTOM', '만성 신부전의 주요 증상으로 초기에는 거의 증상이 없다가 진행되면서 부종(얼굴·다리), 거품뇨(단백뇨), 혈뇨, 고혈압, 피로감, 식욕 부진, 오심·구토가 나타납니다. 더 진행되면 빈혈(적혈구생성인자 감소), 가려움증(요독 물질 축적), 뼈 통증(신성 골이양증), 의식 변화까지 나타날 수 있습니다. 이러한 증상이 있다면 즉시 신장내과 전문의를 방문하여 신기능 평가를 받으시기 바랍니다.', 2227, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신부전', '만성신부전', 'DIAGNOSIS', '당뇨, 고혈압, 비만 환자의 만성 신부전 위험도 평가를 위해 혈청 크레아티닌·BUN·eGFR 검사, 소변 알부민/크레아티닌 비율, 소변 침사 검사가 필요합니다. 혈당(HbA1c), 지질 검사, 신장 초음파도 위험 인자 평가에 유용합니다. 고위험군은 최소 1년에 1회 이상 정기적으로 신기능 검사를 받고, 내과 또는 신장내과에서 통합 관리받으시기 바랍니다.', 2228, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신부전', '만성신부전', 'TREATMENT', '만성 신부전 말기에서 신장 기능을 대체하는 치료로는 혈액투석, 복막투석, 신장 이식의 세 가지 방법이 있습니다. 혈액투석은 주 3회 병원 방문이 필요하며, 복막투석은 가정에서 자가 시행이 가능합니다. 신장 이식은 이식 성공 시 가장 좋은 삶의 질을 제공하는 방법으로, 각 방법의 적합성은 신장내과 전문의와 충분히 상담하여 결정하시기 바랍니다.', 2229, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신우신염', '만성신우신염', 'DIET_LIFE', '만성 신우신염 환자는 충분한 수분 섭취(하루 2~3L)로 소변을 통한 세균 배출을 촉진하고, 항염·항균 효과가 있는 크랜베리 음료나 주스가 도움이 될 수 있습니다. 면역력 강화를 위해 채소, 과일, 단백질이 균형 잡힌 식사를 권장하며, 신기능이 저하된 경우 저단백·저염 식단이 필요합니다. 허리 통증과 배뇨 통증이 지속된다면 신장내과 또는 비뇨의학과 전문의 진료를 받으시기 바랍니다.', 2230, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신우신염', '만성신우신염', 'PREVENTION', '만성 신우신염 예방을 위해 가장 효과적인 생활 습관은 충분한 수분 섭취(하루 2L 이상)로 소변 희석 및 세균 배출 촉진, 소변을 자주 비우기(오래 참지 않기), 올바른 배변 위생(항문에서 요도 방향으로 닦기)입니다. 면역력 유지를 위한 규칙적인 운동, 충분한 수면, 균형 잡힌 식사도 중요하며, 기저 요로 질환(결석, 기형)의 치료도 필수적입니다. 재발하는 요로 감염이 있다면 비뇨의학과 또는 신장내과에서 정밀 검사를 받으시기 바랍니다.', 2231, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신우신염', '만성신우신염', 'CAUSE', '만성 신우신염의 원인으로는 반복적인 세균 감염(주로 대장균), 요로 기형이나 결석에 의한 요로 폐색, 방광 요관 역류, 면역 저하 상태 등이 있습니다. 만성 피로는 신기능 저하로 인한 빈혈·요독증 때문에, 요통은 신장 염증과 부종으로 발생합니다. 만성 신우신염이 의심된다면 신장내과 또는 비뇨의학과에서 소변 배양, 신장 초음파, 신기능 검사를 받으시기 바랍니다.', 2232, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신우신염', '만성신우신염', 'DEFINITION', '만성 신우신염은 세균 감염으로 인한 신장 염증이 반복되거나 지속적으로 발생하여 3개월 이상 지속되는 상태로, 신장 조직의 반복 손상과 반흔화가 특징입니다. 반복 감염으로 신장 기능이 점진적으로 저하되며, 신장이 작아지고 표면이 불규칙해지는 구조적 변화가 나타납니다. 장기간 방치하면 만성 신부전으로 진행될 수 있어 신장내과 전문의의 지속적 관리가 필요합니다.', 2233, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신우신염', '만성신우신염', 'SYMPTOM', '만성 신우신염에서 혈뇨는 반복 감염으로 인한 신장 사구체 손상과 세뇨관 염증으로 적혈구가 소변으로 누출되어 발생합니다. 잔뇨감은 세균 감염이 방광까지 영향을 미치거나 방광 기능이 저하되어 배뇨 후에도 방광이 완전히 비워지지 않는 느낌이 들기 때문입니다. 지속적인 혈뇨와 잔뇨감은 정확한 평가가 필요하므로 비뇨의학과 또는 신장내과 전문의 진료를 받으시기 바랍니다.', 2234, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신우신염', '만성신우신염', 'DIAGNOSIS', '잔뇨감과 옆구리 통증으로 만성 신우신염이 의심된다면 소변 검사(요침사, 소변 배양), 혈액 검사(신기능, 염증 수치), 신장 초음파 또는 CT 검사를 받으셔야 합니다. 신장내과 또는 비뇨의학과에서 이러한 검사들을 시행하며, 요로 기형이나 결석 유무도 함께 평가합니다. 증상이 지속되거나 고열이 동반된다면 즉시 의료기관을 방문하시기 바랍니다.', 2235, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 신우신염', '만성신우신염', 'TREATMENT', '만성 신우신염에서 항생제 외 치료로는 원인 요로 기형이나 결석의 외과적 교정, 방광 요관 역류 치료가 재발 방지에 중요합니다. 충분한 수분 섭취, 면역 강화, 요로 위생 관리 등 생활 습관 개선도 병행합니다. 신기능이 저하된 경우 만성 신부전 관리(혈압 조절, 단백뇨 치료)가 추가되며, 신장내과 전문의의 장기적 모니터링이 필요합니다.', 2236, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 전립선염', '만성전립선염', 'CAUSE', '만성 전립선염(만성 골반통 증후군)의 원인은 아직 완전히 밝혀지지 않았으나, 세균 감염, 자가면역 반응, 전립선 내 소변 역류, 신경 이상, 심리적 스트레스, 골반저 근육 기능 이상 등이 복합적으로 작용하는 것으로 알려져 있습니다. 장시간 앉아있는 생활 습관, 성생활 패턴, 비뇨기과적 기왕력도 위험 요인입니다. 정확한 원인 평가와 치료를 위해 비뇨의학과 전문의 진료가 필요합니다.', 2237, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 전립선염', '만성전립선염', 'DEFINITION', '만성 전립선염은 전립선에 3개월 이상 지속되는 염증 또는 통증 증후군으로, 세균성(만성 세균성 전립선염)과 비세균성(만성 골반통 증후군)으로 분류됩니다. 주요 증상으로 회음부·하복부·고환 통증, 배뇨통, 빈뇨, 잔뇨감, 성기능 장애 등이 나타납니다. 증상이 3개월 이상 지속되면 비뇨의학과 전문의를 방문하여 정확한 진단과 치료를 받으시기 바랍니다.', 2238, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 전립선염', '만성전립선염', 'SYMPTOM', '만성 전립선염에서 소변을 봐도 개운하지 않은 잔뇨감은 전립선 염증으로 인해 요도 주변 조직이 부어 소변 흐름이 방해받고, 방광 경부 기능이 저하되어 방광이 완전히 비워지지 않기 때문에 발생합니다. 이와 함께 빈뇨, 배뇨통, 야간뇨도 흔히 동반됩니다. 이러한 증상이 3개월 이상 지속된다면 비뇨의학과 전문의에게 진료를 받으시기 바랍니다.', 2239, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 전립선염', '만성전립선염', 'DIAGNOSIS', '만성 전립선염 진단을 위해 소변 검사(요침사, 세균 배양)와 전립선 마사지 전후 소변 및 전립선 분비물 배양 검사(Meares-Stamey 4컵법)가 시행됩니다. 혈액 검사에서 전립선특이항원(PSA) 수치를 확인하고, 전립선 초음파로 구조적 이상을 평가합니다. 정확한 진단을 위해 비뇨의학과 전문의를 방문하여 체계적인 검사를 받으시기 바랍니다.', 2240, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '만성 전립선염', '만성전립선염', 'TREATMENT', '만성 전립선염에서 항생제(세균성인 경우)와 함께 알파차단제(탐술로신 등)가 배뇨 증상 개선에 효과적이며, 비스테로이드 항염증제(NSAIDs)로 통증을 조절합니다. 비세균성 만성 골반통 증후군에는 골반저 물리치료, 심리 치료, 침 치료 등의 다학제 접근이 도움이 됩니다. 치료는 원인과 증상에 따라 개별화되므로 비뇨의학과 전문의와 상담하여 적합한 치료 계획을 수립하시기 바랍니다.', 2241, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '말기 신질환', '말기신질환', 'DIET_LIFE', '말기 신질환 환자는 저단백(0.6~0.8g/kg/일), 저염(2g/일 이하), 저칼륨·저인 식단을 유지하고, 수분 섭취는 소변량에 맞춰 조절해야 합니다. 금주·금연, 규칙적인 가벼운 운동(걷기), 철저한 혈압·혈당 관리, 규칙적인 투약이 중요합니다. 식이 계획은 신기능 단계와 투석 여부에 따라 달라지므로 신장내과 전문의 및 영양사와 긴밀하게 협력하시기 바랍니다.', 2242, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '말기 신질환', '말기신질환', 'MEDICATION', '말기 신질환 치료 약물에는 혈압 조절을 위한 ACE억제제·ARB, 빈혈 치료를 위한 적혈구생성인자(EPO), 고칼륨혈증 치료제, 신성 골이양증 예방을 위한 인 흡착제와 활성 비타민 D, 대사성 산증 교정을 위한 중탄산나트륨 등이 포함됩니다. 이러한 약물들은 말기 신질환의 합병증을 조절하고 투석 전까지 신기능 저하 속도를 늦추는 역할을 합니다. 모든 약물은 신장내과 전문의 처방하에 복용하시기 바랍니다.', 2243, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '말기 신질환', '말기신질환', 'PREVENTION', '말기 신질환 예방을 위해 당뇨와 고혈압의 철저한 조기 관리가 가장 효과적이며, 정기적인 신기능 검사(혈청 크레아티닌, 소변 단백질)를 통한 조기 발견이 중요합니다. 신독성 약물(NSAIDs, 조영제 등) 사용을 최소화하고, 건강한 식습관과 규칙적인 운동으로 비만·고혈압·당뇨를 예방합니다. 고위험군에게는 신장 보호 교육과 정기 검진 프로그램 참여를 권장하며, 내과 또는 신장내과에서 지속적인 관리를 받으시기 바랍니다.', 2244, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '말기 신질환', '말기신질환', 'CAUSE', '말기 신질환은 당뇨병성 신병증, 고혈압성 신경화증, 사구체신염 등 다양한 원인으로 발생하며, 이로 인해 빈혈, 고혈압, 전해질 불균형, 뼈 질환(신성 골이영양증), 심혈관 합병증 등이 나타날 수 있습니다. 또한 부종, 호흡곤란, 요독증에 의한 구역·구토, 의식 변화 등의 증상도 동반될 수 있습니다. 정확한 원인 파악과 합병증 관리를 위해 신장내과 전문의의 진료를 받으시길 권고합니다.', 2245, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '말기 신질환', '말기신질환', 'DEFINITION', '말기 신질환은 신장 기능이 정상의 15% 미만으로 저하된 상태로, 초기에는 피로감, 식욕 저하, 소변량 변화, 발목 부종 등 비특이적 증상이 나타납니다. 진행될수록 심한 부종, 호흡곤란, 구역·구토, 의식 혼탁 등 요독 증상이 심해지며, 치료로는 혈액투석, 복막투석, 신장 이식이 있습니다. 증상이 의심될 경우 신장내과 전문의에게 조기에 상담하시길 권고합니다.', 2246, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '말기 신질환', '말기신질환', 'SYMPTOM', '말기 신질환에서는 신장의 노폐물 배출 기능이 저하되어 요독 물질이 혈중에 축적되고, 이로 인해 피부 가려움증(요독성 소양증)이 나타날 수 있습니다. 특히 투석 환자에서 흔히 발생하며, 인·칼슘 대사 이상, 신경 손상도 가려움증에 기여합니다. 지속적인 피부 가려움증이 있다면 신장내과 전문의의 진료를 받아보시길 권고합니다.', 2247, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '말기 신질환', '말기신질환', 'DIAGNOSIS', '소변 감소, 발목 부종, 식욕 부진, 구토 증상은 신장 기능 저하를 시사하는 증상으로, 신장내과 또는 내과 전문의가 있는 종합병원이나 상급종합병원을 방문하시는 것이 좋습니다. 혈액검사(BUN, 크레아티닌), 소변검사, 신장 초음파 등을 통해 신장 기능을 평가할 수 있습니다. 증상이 갑작스럽거나 심한 경우 응급실을 이용하시길 권고합니다.', 2248, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '말기 신질환', '말기신질환', 'TREATMENT', '말기 신질환에서 신장 기능이 10% 이하로 저하된 경우 신장 이식이 가장 높은 생존율과 삶의 질을 보이는 치료법으로 알려져 있습니다. 이식이 불가능한 경우에는 혈액투석 또는 복막투석을 통해 생명을 유지할 수 있습니다. 최적의 치료 방법 선택은 환자의 전신 상태, 공여자 여부, 동반 질환을 고려하여 신장내과 전문의와 상담하시길 권고합니다.', 2249, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '무정자증', '무정자증', 'DIET_LIFE', '무정자증 치료 후에는 항산화 영양소(아연, 셀레늄, 비타민 C·E)가 풍부한 식품을 섭취하고, 과도한 음주와 흡연을 삼가는 것이 도움이 됩니다. 규칙적인 유산소 운동, 정상 체중 유지, 충분한 수면, 스트레스 관리도 정자 건강에 유익합니다. 생활 습관 개선과 함께 비뇨의학과 전문의의 지속적인 추적 관찰을 권고합니다.', 2250, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '무정자증', '무정자증', 'CAUSE', '환경 호르몬(내분비계 교란물질)은 남성 호르몬인 테스토스테론 분비와 정자 형성을 방해하여 무정자증에 기여할 수 있습니다. 이는 유전적 소인, 고환 온도 상승, 호르몬 불균형, 감염, 생식기 구조 이상 등 다른 원인들과 복합적으로 작용하여 정자 생성을 억제합니다. 정확한 원인 감별을 위해 비뇨의학과 전문의의 진찰과 검사를 받으시길 권고합니다.', 2251, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '무정자증', '무정자증', 'DEFINITION', '무정자증은 정액 검사에서 원심분리 후에도 정자가 전혀 발견되지 않는 상태로 진단하며, 최소 2회 이상 반복 검사를 통해 확인합니다. 정액 검사는 정액량, pH, 정자 농도, 운동성, 형태 등을 평가하며, 무정자증 진단 시 호르몬 검사와 유전자 검사를 추가로 시행하여 폐쇄성과 비폐쇄성을 감별합니다. 정확한 진단과 원인 파악을 위해 비뇨의학과 전문의를 방문하시길 권고합니다.', 2252, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '무정자증', '무정자증', 'SYMPTOM', '무정자증 자체는 특별한 신체 증상을 유발하지 않으며, 대부분 임신 시도 중 불임으로 처음 발견됩니다. 다만 원인 질환에 따라 고환 크기 감소, 성욕 저하, 발기부전, 여성형 유방 등이 동반될 수 있으며, 정계정맥류가 원인인 경우 고환 통증이나 불쾌감이 나타날 수 있습니다. 관련 증상이 있으면 비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2253, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '무정자증', '무정자증', 'DIAGNOSIS', '가정용 정액 자가 검사 키트는 정자 유무나 정자 농도를 간이적으로 확인할 수 있지만, 정확도가 낮아 임상 진단에는 부적합합니다. 무정자증 진단은 반드시 의료기관에서 표준화된 정액 분석을 통해 이루어져야 하며, 자가 검사 결과만으로는 확진할 수 없습니다. 임신이 잘 되지 않거나 불임이 의심될 경우 비뇨의학과 전문의를 방문하여 정밀 검사를 받으시길 권고합니다.', 2254, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '무정자증', '무정자증', 'TREATMENT', '무정자증 치료는 원인에 따라 달라지며, 폐쇄성 무정자증은 수술적 교정(정관 복원술, 부고환 수술) 또는 고환 내 정자 직접 추출(TESE, MESA)을 통해 정자를 채취하여 체외수정에 활용합니다. 비폐쇄성 무정자증에서 호르몬 이상이 원인인 경우 호르몬 치료로 정자 생성을 유도할 수 있습니다. 치료 방법 선택은 원인과 환자 상태에 따라 비뇨의학과 전문의와 충분한 상담 후 결정하시길 권고합니다.', 2255, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '방광요관 역류', '방광요관역류', 'CAUSE', '방광요관 역류의 주요 원인은 방광과 요관 연결 부위(방광요관 접합부)의 선천적 구조 이상으로, 요관이 방광벽을 통과하는 길이가 짧거나 각도가 비정상적이어서 소변이 거꾸로 흐르게 됩니다. 소아에서는 대부분 선천성이며, 성인에서는 방광 기능 이상, 수술 후 흉터 등이 원인이 될 수 있습니다. 정확한 진단과 치료를 위해 소아비뇨의학과 또는 비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2256, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '방광요관 역류', '방광요관역류', 'DEFINITION', '방광요관 역류는 소변이 방광에서 요관과 신장 쪽으로 거꾸로 흐르는 상태로, 방광요관 접합부의 기능 이상이 주원인입니다. 증상으로는 반복적인 요로감염(발열, 보챔, 배뇨통), 옆구리 통증, 소변 시 불편감 등이 나타나며, 반복 감염 시 신장 손상(신반흔)으로 이어질 수 있습니다. 의심 증상이 있으면 비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2257, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '방광요관 역류', '방광요관역류', 'SYMPTOM', '방광요관 역류의 증상으로는 빈뇨, 배뇨통 외에도 발열을 동반한 반복적인 요로감염, 옆구리 또는 등 통증, 배뇨 시 불편감, 소변에서 악취 등이 나타날 수 있습니다. 영아의 경우 발열, 보챔, 수유 거부, 성장 장애로 나타나기도 합니다. 반복적인 요로감염이 있다면 방광요관 역류를 감별하기 위해 비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2258, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '방광요관 역류', '방광요관역류', 'DIAGNOSIS', '방광요관 역류는 배뇨 중 방광요관조영술(VCUG)이 표준 진단 검사로, 방사선 조영제를 방광에 주입하고 배뇨 시 역류 여부와 정도(1~5등급)를 확인합니다. 추가로 신장 초음파, 신장 핵의학 스캔(DMSA)을 통해 신장 손상 여부를 평가합니다. 정확한 진단을 위해 비뇨의학과 전문의에게 진료를 받으시길 권고합니다.', 2259, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '방광요관 역류', '방광요관역류', 'TREATMENT', '방광요관 역류의 수술적 치료(요관 재이식술 또는 내시경적 주입 치료)는 역류 자체를 해부학적으로 교정하기 때문에, 항생제 예방요법에 반응하지 않는 고등급 역류나 반복 감염에서 근본적인 해결책이 됩니다. 수술을 통해 요관이 방광벽을 충분한 길이로 통과하도록 재건하면 역류 방지 기전이 회복됩니다. 치료 방법 선택은 역류 등급, 나이, 신장 손상 여부에 따라 비뇨의학과 전문의와 상담하여 결정하시길 권고합니다.', 2260, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '방광염', '방광염', 'DEFINITION', '여성은 요도 길이가 약 4cm로 남성(약 20cm)보다 매우 짧고, 항문·질과 요도 입구가 근접해 있어 세균이 방광으로 침입하기 쉽습니다. 이로 인해 여성은 남성보다 방광염 발생 빈도가 훨씬 높으며, 성관계, 임신, 폐경 후 에스트로겐 감소도 위험 인자가 됩니다. 반복적인 방광염이 있다면 비뇨의학과 또는 산부인과 전문의의 진료를 받으시길 권고합니다.', 2261, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '배뇨장애', '배뇨장애', 'CAUSE', '과도한 음주는 이뇨 효과로 방광을 과자극하고, 전립선 부종, 신경계 억제 등을 유발하여 배뇨장애를 악화시킬 수 있습니다. 음주 제한, 카페인 줄이기, 규칙적인 배뇨 습관, 충분한 수분 섭취, 과체중 개선 등 생활 습관 조절이 증상 완화에 도움이 됩니다. 배뇨 문제가 지속된다면 비뇨의학과 전문의의 진료를 받아 원인을 파악하시길 권고합니다.', 2262, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '배뇨장애', '배뇨장애', 'DEFINITION', '배뇨장애는 소변을 저장하거나 배출하는 과정에 이상이 생긴 상태로, 빈뇨, 절박뇨, 요실금, 배뇨 곤란, 잔뇨 등의 증상을 포함합니다. 생리 중에는 자궁과 방광의 해부학적 근접성으로 인해 방광 자극 증상이 나타날 수 있으나, 이는 일시적인 경우가 많습니다. 지속적인 배뇨 증상이 있다면 비뇨의학과 전문의의 정확한 진단을 받으시길 권고합니다.', 2263, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '배뇨장애', '배뇨장애', 'SYMPTOM', '배뇨장애의 주요 증상은 빈뇨, 절박뇨, 야간뇨, 배뇨 곤란, 요실금, 잔뇨감 등이며, 배뇨 시 또는 배뇨 후 불쾌감이나 통증이 동반될 수 있습니다. 발끝까지 퍼지는 통증은 배뇨장애의 전형적인 증상은 아니며, 척추·신경 질환이나 말초 혈관 질환을 고려해야 합니다. 다양한 증상이 복합적으로 나타날 경우 비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2264, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '배뇨장애', '배뇨장애', 'DIAGNOSIS', '소변 볼 때 불편함, 배뇨 시 통증, 잔뇨감 등은 배뇨장애의 주요 증상에 해당하며, 방광염, 전립선 질환, 요도 협착 등 다양한 원인에 의해 나타날 수 있습니다. 이러한 증상이 자주 반복된다면 단순한 불편이 아닌 의학적 평가가 필요한 상태일 수 있습니다. 비뇨의학과 전문의를 방문하여 소변 검사, 요류 검사 등을 통해 정확한 진단을 받으시길 권고합니다.', 2265, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '배뇨장애', '배뇨장애', 'TREATMENT', '배뇨 후 잔뇨감, 개운하지 않은 느낌이 지속될 경우 과활동성 방광, 전립선 비대증, 방광 기능 이상 등 다양한 원인을 감별해야 합니다. 정확한 진단을 위해 비뇨의학과에서 요류 검사, 잔뇨 초음파, 소변 검사 등을 시행할 수 있습니다. 증상이 지속되거나 악화된다면 비뇨의학과 전문의의 진료를 받아 적절한 치료를 시작하시길 권고합니다.', 2266, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '복압성 요실금', '복압성요실금', 'CAUSE', '기침, 재채기, 운동 등 복압이 상승하는 상황에서 방광 내 압력이 요도 저항력을 초과하면 소변이 비자의적으로 누출됩니다. 복압성 요실금에서는 요도 괄약근 및 골반저 근육의 약화로 인해 요도가 충분히 닫히지 못하는 것이 핵심 기전입니다. 출산, 노화, 비만, 폐경 등이 골반저 근육 약화에 기여하며, 치료를 위해 비뇨의학과 또는 산부인과 전문의의 진료를 권고합니다.', 2267, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '복압성 요실금', '복압성요실금', 'DEFINITION', '복압성 요실금은 기침, 재채기, 웃음, 운동 등 복압이 증가하는 상황에서 자신의 의지와 무관하게 소변이 누출되는 질환입니다. 주원인은 골반저 근육과 요도 괄약근의 약화로, 출산, 노화, 폐경, 비만, 만성 기침 등이 위험 인자입니다. 증상이 있다면 비뇨의학과 또는 산부인과 전문의에게 진료를 받아 적절한 치료 방법을 선택하시길 권고합니다.', 2268, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '복압성 요실금', '복압성요실금', 'SYMPTOM', '기침 시 의지와 무관하게 소변이 새는 것은 복압성 요실금의 가장 전형적인 증상입니다. 이는 복압 상승 시 방광 내 압력이 요도 폐쇄압을 초과하여 발생하며, 골반저 근육 약화나 요도 괄약근 기능 저하가 원인입니다. 정확한 진단과 치료를 위해 비뇨의학과 또는 산부인과 전문의의 진료를 받으시길 권고합니다.', 2269, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '복압성 요실금', '복압성요실금', 'DIAGNOSIS', '소변이 잦고 배뇨 시 통증이 있는 경우 복압성 요실금 외에 방광염, 과활동성 방광 등도 감별해야 합니다. 진단을 위해 비뇨의학과에서 요류 검사, 방광 초음파, 요역동학 검사, 소변 검사를 시행할 수 있습니다. 할머니의 증상이 지속된다면 비뇨의학과 또는 산부인과 전문의를 방문하여 정확한 진단을 받으시길 권고합니다.', 2270, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '복압성 요실금', '복압성요실금', 'TREATMENT', '복압성 요실금의 치료는 중등도 이상인 경우 수술적 치료(중부요도슬링 수술, TVT, TOT 등)가 80~90%의 높은 성공률로 주로 사용됩니다. 경증의 경우 골반저 근육 운동(케겔 운동), 행동 치료, 약물 치료(둘록세틴 등)를 먼저 시도합니다. 치료 방법은 증상 중증도와 환자 상태에 따라 다르므로 비뇨의학과 또는 산부인과 전문의와 상담하시길 권고합니다.', 2271, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '사구체신염', '사구체신염', 'CAUSE', '사구체신염은 신장 내 사구체에 염증이 생기는 질환으로, 주요 원인으로는 연쇄상구균 등 세균·바이러스 감염 후 면역복합체 침착, 자가면역 질환(루푸스, IgA 신병증), 유전적 요인 등이 있습니다. 면역체계의 이상 반응으로 항원-항체 복합체가 사구체에 쌓이거나 사구체를 직접 공격하여 염증이 유발됩니다. 정확한 원인 파악을 위해 신장내과 전문의의 진료와 신장 생검이 필요할 수 있습니다.', 2272, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '사구체신염', '사구체신염', 'DEFINITION', '사구체신염이 발생하면 혈뇨(붉거나 콜라색 소변), 단백뇨(거품 소변), 부종(눈꺼풀, 발목), 고혈압, 소변량 감소 등이 나타납니다. 혈뇨나 단백뇨가 의심된다면 즉시 수분 섭취를 유지하면서 신장내과 전문의의 진료를 받아야 하며, 임의로 약을 복용하지 않도록 합니다. 조기에 적절한 치료를 받는 것이 신장 기능 보존에 중요하므로 빠른 진료를 권고합니다.', 2273, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '사구체신염', '사구체신염', 'SYMPTOM', '혈뇨와 단백뇨는 사구체신염의 주요 증상으로, 사구체의 여과 기능 손상으로 적혈구와 단백질이 소변으로 새어나와 발생합니다. 치료 시기는 원인과 중증도에 따라 다르며, 급성기에는 조기 치료가 신기능 보전에 중요하고, IgA 신병증 등 만성형은 진행 속도에 따라 치료 시점을 결정합니다. 증상이 있다면 지체 없이 신장내과 전문의의 진료를 받으시길 권고합니다.', 2274, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '사구체신염', '사구체신염', 'DIAGNOSIS', '사구체신염의 진단을 위해 소변 검사, 혈액 검사(BUN, 크레아티닌, 보체 수치, 자가항체 등) 후에도 원인이 불명확하거나 정확한 조직학적 분류가 필요할 경우 신장 생검(조직검사)을 시행합니다. 영상 검사(신장 초음파)는 신장 크기와 구조 평가에 활용됩니다. 추가 진단 절차는 신장내과 전문의의 판단에 따라 결정되므로 전문의 진료를 받으시길 권고합니다.', 2275, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '사구체신염', '사구체신염', 'TREATMENT', '사구체신염의 치료 방법은 원인, 중증도, 신기능 저하 정도에 따라 달라집니다. 경증은 외래 통원 치료로 혈압 조절, 저염식, 안정을 취하며, 중증이거나 급속 진행성인 경우 입원하여 스테로이드, 면역억제제를 투여합니다. 최적의 치료 방침을 결정하기 위해 반드시 신장내과 전문의와 상담하시길 권고합니다.', 2276, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '서혜부 탈장', '서혜부탈장', 'CAUSE', '서혜부 탈장은 복벽 근육의 약한 부위를 통해 장기가 돌출될 때 발생하며, 대변 시 힘을 주면 복압이 급격히 상승하여 기존에 약해진 복벽 부위로 장기가 밀려나올 수 있습니다. 만성 변비, 복수, 비만, 무거운 물건을 자주 드는 행동도 복압을 높여 탈장을 유발하거나 악화시킵니다. 사타구니 부위 돌출이나 통증이 있다면 외과 전문의의 진료를 받으시길 권고합니다.', 2277, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '서혜부 탈장', '서혜부탈장', 'DEFINITION', '서혜부 탈장은 복강 내 장기(주로 소장, 대망)가 서혜부(사타구니) 부위의 약한 복벽을 통해 돌출되는 질환입니다. 주요 증상으로는 사타구니의 볼록한 종물, 서거나 힘을 줄 때 돌출이 심해지고 누우면 줄어드는 양상, 불쾌감 또는 통증이 있으며, 음낭이나 음순까지 내려올 수 있습니다. 증상이 있다면 외과 전문의의 진료를 받으시길 권고합니다.', 2278, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '서혜부 탈장', '서혜부탈장', 'SYMPTOM', '서혜부 탈장의 주요 증상은 사타구니에 볼록하게 튀어나오는 종물로, 서 있거나 힘을 줄 때 커지고 누우면 사라지는 양상을 보입니다. 탈출된 장기에 의해 사타구니 및 하복부 불쾌감, 둔통, 묵직한 느낌이 나타날 수 있으며, 감돈(장이 끼어 혈액 공급이 차단됨) 시 갑작스러운 심한 통증, 구역, 구토가 발생하는 응급 상황이 될 수 있습니다. 관련 증상이 있으면 외과 전문의의 진료를 받으시길 권고합니다.', 2279, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '서혜부 탈장', '서혜부탈장', 'DIAGNOSIS', '통증이 없는 사타구니 돌출이나 종물이 있는 경우에도 서혜부 탈장을 의심할 수 있으며, 복압 상승 시(울기, 힘주기) 돌출이 심해지거나 음낭 부위로 내려오는 양상이 특징적입니다. 영아의 경우 우는 시간에만 간헐적으로 종물이 관찰되기도 합니다. 소아비뇨의학과 또는 소아외과를 방문하여 신체 검진을 통해 진단받으시길 권고합니다.', 2280, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '서혜부 탈장', '서혜부탈장', 'TREATMENT', '서혜부 탈장은 자연 회복되지 않으며 수술적 치료가 표준 치료법입니다. 탈장 교정술(개복 또는 복강경)을 통해 돌출된 장기를 환납하고 약해진 복벽을 메시(mesh)로 보강하는 수술이 가장 효과적이고 재발률이 낮습니다. 감돈 위험성 때문에 진단 후에는 비교적 빠른 수술을 권장하며, 외과 전문의와 상담하시길 권고합니다.', 2281, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '성기능장애', '성기능장애', 'MEDICATION', '피임약(경구 피임약)은 여성 호르몬(에스트로겐·프로게스틴)을 함유하고 있어 여성에서의 성기능에 영향을 줄 수 있으나, 남성 성기능장애의 원인으로는 작용하지 않습니다. 남성 성기능장애에는 당뇨병, 고혈압, 심혈관 질환, 저테스토스테론혈증, 항우울제·항고혈압제 등 일부 약물, 심리적 스트레스 등이 중요한 원인입니다. 성기능 문제가 지속된다면 비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2282, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '성기능장애', '성기능장애', 'CAUSE', '인스턴트 식품의 과다 섭취는 비만, 대사증후군, 혈관 건강 저하를 유발하여 발기 기능에 필요한 혈류에 악영향을 줄 수 있습니다. 과도한 컴퓨터 사용은 신체 활동 감소, 만성 스트레스, 수면 장애, 좌식 자세로 인한 골반 혈류 저하 등을 통해 성기능장애에 간접적으로 기여할 수 있습니다. 성기능 문제가 있다면 생활 습관 개선과 함께 비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2283, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '성기능장애', '성기능장애', 'DEFINITION', '성기능장애는 남성과 여성 모두에게 나타납니다. 여성의 성기능장애는 성욕 저하, 성적 흥분 장애, 오르가즘 장애, 성교통(질경련, 외음부통증) 등을 포함합니다. 폐경, 호르몬 변화, 심리적 요인, 약물, 만성 질환 등이 원인이 될 수 있으며, 산부인과 또는 비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2284, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '성기능장애', '성기능장애', 'SYMPTOM', '성기능장애로 인한 증상으로는 성욕 감소, 발기 부전(남성), 질 건조증·성교통(여성), 오르가즘 도달 어려움, 조루 또는 지루, 성적 흥분 감소 등이 나타날 수 있습니다. 심리적으로 불안, 우울, 관계에 대한 스트레스가 동반되는 경우도 많습니다. 지속적인 증상이 있다면 비뇨의학과 또는 산부인과 전문의의 진료를 받으시길 권고합니다.', 2285, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '성기능장애', '성기능장애', 'DIAGNOSIS', '소변을 보는 데 힘이 들고 시원하게 나오지 않는 증상(배뇨 곤란, 약뇨)은 성기능장애보다는 전립선 비대증, 요도 협착, 방광 기능 이상 등 배뇨 관련 질환을 먼저 의심해야 합니다. 성기능장애는 발기·사정·성욕에 관한 문제를 주로 의미하며, 배뇨 증상과는 구별됩니다. 배뇨 문제가 있다면 비뇨의학과 전문의를 방문하여 정확한 진단을 받으시길 권고합니다.', 2286, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '성기능장애', '성기능장애', 'TREATMENT', '성기능장애 치료에 사용되는 PDE5 억제제(실데나필, 타다라필 등)는 두통, 안면홍조, 소화불량, 코막힘, 시각 변화 등의 부작용이 있으며, 질산염 계열 약물과 병용 시 심각한 저혈압이 유발될 수 있습니다. 호르몬 치료(테스토스테론)는 혈전증, 적혈구 증가, 간 기능 이상의 위험이 있습니다. 성기능장애 치료 약물은 반드시 비뇨의학과 전문의의 처방과 지도하에 사용하시길 권고합니다.', 2287, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신부전', '신부전', 'CAUSE', '신부전은 신장의 여과, 수액·전해질 조절, 산-염기 균형 유지, 노폐물 배설 기능이 저하된 상태입니다. 급성 신부전의 원인으로는 신전성(탈수, 출혈, 심부전에 의한 혈류 감소), 신성(사구체신염, 간질성 신염, 약물 독성), 신후성(요관·방광 폐색) 등이 있습니다. 만성 신부전은 당뇨병, 고혈압, 사구체신염의 지속적인 손상이 주원인이며, 신장내과 전문의의 진료가 필요합니다.', 2288, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신부전', '신부전', 'DEFINITION', '신부전은 신장의 여과 기능을 담당하는 사구체, 세뇨관, 간질 등 신실질 전체가 영향을 받습니다. 사구체는 혈액 여과를, 세뇨관은 전해질·수분 재흡수 및 분비를 담당하며, 이 기능들이 손상되면 노폐물 축적, 전해질 불균형, 산혈증, 빈혈 등이 발생합니다. 신장 기능 이상이 의심되면 신장내과 전문의를 방문하여 혈액 및 소변 검사를 받으시길 권고합니다.', 2289, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신부전', '신부전', 'TREATMENT', '소변량 감소, 부종, 체중 변화 등 신장 기능 저하 증상이 있을 경우 종합병원이나 상급종합병원의 신장내과 또는 내과를 방문하시는 것이 좋습니다. 혈액 검사(크레아티닌, BUN, 전해질), 소변 검사, 신장 초음파 등으로 신기능을 평가합니다. 증상이 급격히 악화되거나 소변이 거의 나오지 않는다면 응급실을 이용하시길 권고합니다.', 2290, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신장 결석', '신장결석', 'DIET_LIFE', '신장 결석 예방을 위해 하루 2~2.5리터 이상의 충분한 수분 섭취가 가장 중요하며, 소변이 연한 노란색을 유지할 정도로 마시는 것이 좋습니다. 나트륨과 동물성 단백질 섭취를 줄이고, 수산염이 많은 음식(시금치, 견과류, 초콜릿)을 적당히 제한하며, 구연산이 풍부한 레몬수도 도움이 됩니다. 재발 방지와 치료 방법 선택을 위해 비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2291, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신장 결석', '신장결석', 'MEDICATION', '신장 결석 치료 시 칼슘 보충제는 결석 형성을 촉진할 수 있어 주의가 필요하며, 비타민 D 과다 보충도 고칼슘뇨를 유발할 수 있습니다. 요산 결석이 있는 경우 요산을 높이는 약물도 피해야 하고, 이뇨제 중 특정 종류는 결석 위험을 높일 수 있습니다. 복용 중인 모든 약물과 건강기능식품을 비뇨의학과 전문의에게 알리고 상담하시길 권고합니다.', 2292, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신장 결석', '신장결석', 'PREVENTION', '수분 섭취가 적으면 소변이 농축되어 칼슘, 수산염, 요산 등 결석 형성 물질의 농도가 높아지고, 소변 내 결석 억제 인자의 농도도 낮아져 결석이 생기기 쉬운 환경이 만들어집니다. 예방을 위해 하루 2리터 이상의 충분한 수분 섭취, 나트륨과 동물성 단백질 과다 섭취 제한, 수산염이 풍부한 음식 조절이 도움이 됩니다. 결석 재발 위험이 높다면 비뇨의학과 전문의와 상담하시길 권고합니다.', 2293, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신장 결석', '신장결석', 'CAUSE', '비타민 D를 과다 복용하면 장에서 칼슘 흡수가 증가하고 신장에서 칼슘 재흡수도 촉진되어 혈중 및 소변 내 칼슘 농도가 높아지는 고칼슘뇨증이 발생합니다. 소변 내 높은 칼슘 농도는 칼슘 수산염, 칼슘 인산염 결석 형성 위험을 높입니다. 비타민 D 보충은 권장 용량을 준수하고, 결석 병력이 있다면 복용 전 비뇨의학과 전문의와 상담하시길 권고합니다.', 2294, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신장 결석', '신장결석', 'REHAB', '신장 결석 자체는 일반적으로 재활 치료의 대상이 아니며, 결석 제거 후 식이 조절, 수분 섭취 증가, 약물 치료 등이 재발 예방의 핵심입니다. 다만 결석으로 인한 신장 기능 저하나 수술 후 회복 과정에서 신체 기능 회복을 위한 관리가 도움이 될 수는 있습니다. 결석 치료 후 관리 방향은 비뇨의학과 전문의와 상의하여 결정하시길 권고합니다.', 2295, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신장 결석', '신장결석', 'DEFINITION', '신장 결석은 소변 내 칼슘, 수산염, 요산, 인산염 등이 과포화 상태가 되어 결정을 형성하고 점차 뭉쳐서 생성됩니다. 결석 형성에 영향을 주는 원인으로는 수분 섭취 부족, 고나트륨·고단백 식이, 비만, 부갑상선 기능항진증, 요로 감염, 유전적 소인, 특정 약물(비타민 D, 칼슘 제제 과다) 등이 있습니다. 결석이 의심되면 비뇨의학과 전문의를 방문하여 정확한 원인 파악과 치료를 받으시길 권고합니다.', 2296, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신장 결석', '신장결석', 'SYMPTOM', '신장 결석은 요관을 따라 이동하면서 심한 옆구리 통증(산통), 혈뇨, 잔뇨감, 배뇨 시 통증, 빈뇨, 구역·구토 등을 유발할 수 있습니다. 소변에서 모래나 작은 돌 같은 것이 나오기도 하며, 요로 폐색이 심하면 소변량이 감소할 수 있습니다. 관련 증상이 있으면 비뇨의학과 전문의를 방문하거나 통증이 극심하면 응급실을 이용하시길 권고합니다.', 2297, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신장 결석', '신장결석', 'DIAGNOSIS', '신장 결석에 의한 심한 통증이나 발열이 있는 경우 비뇨의학과 전문의가 있는 종합병원이나 상급종합병원을 방문하거나 응급실을 이용하시길 권고합니다. 복부·골반 CT(비조영), 신장 초음파, 소변 검사 등으로 진단하며, 예후가 좋지 않거나 결석이 크거나 감염이 동반된 경우 비뇨의학과 전문의에게 즉시 진료를 받아야 합니다. 발열과 옆구리 통증이 함께 나타나면 응급 상황일 수 있습니다.', 2298, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신장 결석', '신장결석', 'TREATMENT', '방광염 치료 후에도 신장 결석이 남아 있는 경우, 결석의 크기와 위치에 따라 자연 배출을 기대하거나 체외충격파쇄석술(ESWL), 요관경 수술, 경피적 신장결석제거술 등 추가 치료가 필요할 수 있습니다. 제거하지 않은 결석은 지속적인 요로 폐색, 반복 감염, 신기능 저하 위험이 있습니다. 결석의 추가 치료 필요 여부는 비뇨의학과 전문의와 상담하여 결정하시길 권고합니다.', 2299, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신증후군', '신증후군', 'CHECKUP', '소변 거품과 부종은 신증후군의 의심 증상으로, 신장내과 또는 내과 전문의가 있는 종합병원이나 상급종합병원을 방문하시길 권고합니다. 소변 검사(단백뇨 정도), 혈액 검사(알부민, 콜레스테롤, 신기능), 신장 초음파, 경우에 따라 신장 생검을 통해 진단합니다. 증상이 있다면 지체 없이 전문의 진료를 받으시길 권고합니다.', 2300, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신증후군', '신증후군', 'CAUSE', '비스테로이드성 진통소염제(NSAIDs)는 신장 혈류를 감소시키고 신독성을 유발하여 신증후군의 원인이 될 수 있으므로, 신증후군 환자는 이 약물을 피해야 합니다. 신증후군 예방을 위해 근본 원인 질환(당뇨병, 루푸스 등) 관리, NSAIDs 장기 복용 자제, 정기적인 소변 검사가 도움이 됩니다. 치료와 예방 전략은 신장내과 전문의와 상담하여 결정하시길 권고합니다.', 2301, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신증후군', '신증후군', 'DEFINITION', '소변의 심한 거품은 단백뇨를 시사하며, 신증후군의 주요 진단 기준 중 하나입니다. 신증후군은 대량 단백뇨(하루 3.5g 이상), 저알부민혈증, 부종, 고지혈증으로 정의되므로 고지혈약을 복용 중인 상황에서 거품뇨가 있다면 신증후군의 가능성을 배제할 수 없습니다. 정확한 진단을 위해 신장내과 전문의를 방문하여 소변 및 혈액 검사를 받으시길 권고합니다.', 2302, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신증후군', '신증후군', 'SYMPTOM', '신증후군에서는 단백뇨로 인해 소변이 거품처럼 보이는 것이 특징적이며, 이는 소변 내 단백질이 표면장력을 낮추기 때문입니다. 소변량 감소는 신증후군에서 부종과 함께 나타날 수 있으나, 주된 증상은 단백뇨와 부종입니다. 이러한 증상이 있다면 신장내과 전문의를 방문하여 정확한 검사와 진단을 받으시길 권고합니다.', 2303, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신증후군', '신증후군', 'DIAGNOSIS', '신증후군 진단에는 주로 소변 검사(24시간 단백뇨), 혈액 검사(알부민, 콜레스테롤, 신기능) 등이 사용됩니다. 복부 초음파는 신장의 크기, 구조, 에코 변화를 평가하고 다른 원인(종양, 폐색)을 배제하는 데 도움이 되며, 신장 생검이 확진과 원인 감별에 가장 중요한 검사입니다. 정확한 진단을 위해 신장내과 전문의의 진료를 받으시길 권고합니다.', 2304, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신증후군', '신증후군', 'TREATMENT', '신증후군 치료는 스테로이드(프레드니솔론)가 1차 치료제이며, 반응이 없으면 면역억제제(사이클로스포린, MMF 등)를 추가합니다. 부종 조절을 위한 이뇨제, 단백뇨 감소를 위한 ACE 억제제/ARB, 고지혈증 치료제도 병용합니다. 소아 신증후군은 소아청소년과나 소아신장내과가 있는 대학병원 또는 어린이병원에서 치료를 받으시길 권고합니다.', 2305, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '야뇨증', '야뇨증', 'CAUSE', '야뇨증의 심리적 원인으로는 스트레스, 불안, 학교나 가정에서의 심리적 압박, 동생 출생 등 환경 변화가 있습니다. 심리적 측면의 도움을 위해 아이에게 야뇨증으로 인한 수치심을 주지 않고, 긍정적 강화(성공 시 칭찬), 정서적 지지, 가정 환경 안정화가 중요합니다. 심리적 원인이 의심된다면 소아청소년과 또는 소아정신건강의학과 전문의의 상담을 받으시길 권고합니다.', 2306, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '야뇨증', '야뇨증', 'DEFINITION', '야뇨증은 만 5세 이후에도 수면 중 반복적으로 소변을 지리는 상태를 말하며, 항이뇨호르몬 분비 미성숙, 방광 용적 부족, 깊은 수면, 심리적 요인 등이 복합적으로 관여합니다. 예방 및 관리를 위해 자기 전 2~3시간 전 수분 섭취를 줄이고, 자기 전 반드시 소변을 보게 하며, 야간 알람 요법도 효과적입니다. 만 5세 이후 증상이 지속된다면 소아청소년과 전문의의 진료를 받으시길 권고합니다.', 2307, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '야뇨증', '야뇨증', 'DIAGNOSIS', '5세 아이의 야뇨증은 생리적으로 흔하며, 이 나이에는 적극적인 치료보다 생활 습관 교정(취침 전 수분 제한, 배뇨 습관 정착)을 우선합니다. 재진단이 필요한 경우는 7세 이후에도 증상이 지속되거나, 낮에도 요실금이 있거나, 다뇨·다음증 등 다른 증상이 동반될 때입니다. 소아청소년과 전문의와 상담하여 아이의 발달 상태와 증상에 맞는 관리 방향을 결정하시길 권고합니다.', 2308, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '야뇨증', '야뇨증', 'TREATMENT', '야뇨증 치료는 행동 치료(야간 알람, 방광 훈련), 약물 치료(데스모프레신)를 통해 60~80%에서 호전을 보이나 치료 중단 후 재발률이 있습니다. 재발 예방을 위해 충분한 치료 기간 유지, 취침 전 수분 섭취 제한, 규칙적인 배뇨 습관, 스트레스 관리, 긍정적인 가족 지지가 중요합니다. 치료 방법 선택과 재발 관리는 소아청소년과 전문의와 상담하시길 권고합니다.', 2309, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요관 협착', '요관협착', 'CHECKUP', '복통, 옆구리 통증, 발열, 배뇨 시 통증이 동반되는 경우 요관 협착 외에 요로결석, 요로감염, 신우신염 등을 감별해야 하며, 비뇨의학과 또는 내과가 있는 종합병원을 방문하시길 권고합니다. 발열과 함께 옆구리 통증이 심하다면 신우신염이나 요관 폐색에 의한 감염이 의심되므로 응급실을 이용하시길 권고합니다. 비뇨의학과 전문의에게 CT 촬영 등의 정밀 검사를 받으시길 권고합니다.', 2310, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요관 협착', '요관협착', 'CAUSE', '요관 협착의 원인으로는 선천성 기형, 요관 수술이나 내시경 시술 후 흉터, 방사선 치료에 의한 섬유화, 요관 결석에 의한 반복적 손상, 결핵·염증성 질환, 외부 종양의 압박 등이 있습니다. CT에서 요관 협착 소견이 나왔다면 협착의 위치, 원인, 신장 수신증(hydronephrosis) 정도를 평가하여 치료 방향을 결정해야 합니다. 비뇨의학과 전문의의 전문적인 진료를 받으시길 권고합니다.', 2311, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요관 협착', '요관협착', 'DEFINITION', '요관 협착은 요관의 일부 또는 전체가 좁아져 소변 흐름이 방해받는 상태로, 신장에서 방광으로 소변 배출이 원활하지 않아 신장 내 소변이 고이는 수신증이 발생합니다. 허리 통증, 옆구리 통증, 소변 시원하지 않음, 잔뇨감, 반복적 요로감염 등의 증상이 나타날 수 있으며, CT 요관조영술, 신장 초음파, 역행성 요관조영술 등으로 진단합니다. 비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2312, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요관 협착', '요관협착', 'SYMPTOM', '요관 협착이 진행되면 옆구리·허리 통증 악화, 소변량 감소, 잦은 요로감염(발열, 오한), 혈뇨, 신장 수신증에 의한 신기능 저하가 나타날 수 있습니다. 심한 경우 신장이 기능을 상실하거나 요독증으로 이어질 수 있으며, 양측 요관 협착 시 급성 신부전이 발생할 수도 있습니다. 증상이 악화된다면 즉시 비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2313, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요관 협착', '요관협착', 'DIAGNOSIS', '요관 협착 진단을 위해 신장 초음파(수신증 확인), 복부·골반 CT 요관조영술(협착 위치와 정도 확인), 역행성 요관조영술(내시경으로 조영제 주입 후 협착 직접 관찰), 신장 핵의학 스캔(분리 신기능 평가) 등이 사용됩니다. 선천성 요관 형성 이상의 경우 태아 초음파나 신생아 초음파로 조기 발견할 수 있습니다. 비뇨의학과 전문의의 진료를 통해 적절한 진단 검사를 받으시길 권고합니다.', 2314, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요관 협착', '요관협착', 'TREATMENT', '요관 협착 치료로는 내시경적 풍선 확장술, 요관 스텐트 삽입, 레이저 협착 절개술 등의 최소 침습적 방법과 개복 또는 복강경 요관 재건 수술이 있습니다. 협착이 짧고 경미한 경우 내시경 치료를, 광범위하거나 재발한 경우 수술적 요관 재건이 효과적입니다. 최적의 치료 방법은 협착의 원인·위치·정도에 따라 비뇨의학과 전문의와 상담하여 결정하시길 권고합니다.', 2315, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요도하열', '요도하열', 'CHECKUP', '요도하열 검진은 소아비뇨의학과 또는 비뇨의학과가 있는 종합병원이나 대학병원에서 받으실 수 있습니다. 소변 방향 이상, 귀두 모양 이상, 포피가 불완전한 경우 요도하열을 의심하여 전문의 진찰을 받는 것이 중요합니다. 조기 발견과 적절한 시기의 치료가 예후에 중요하므로 이상이 의심되면 빠른 시일 내에 전문의를 방문하시길 권고합니다.', 2316, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요도하열', '요도하열', 'PREVENTION', '요도하열의 완전한 예방은 어렵지만, 임신 중 산모는 불필요한 호르몬제 복용을 피하고, 내분비계 교란 물질(환경 호르몬)에 대한 노출을 최소화하는 것이 도움이 될 수 있습니다. 엽산을 포함한 적절한 영양 섭취, 금연, 금주, 정기적인 산전 검진이 태아 발달에 중요합니다. 가족력이 있다면 임신 전부터 산부인과 전문의와 상담하시길 권고합니다.', 2317, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요도하열', '요도하열', 'CAUSE', '요도하열은 태아 발생 과정에서 요도판이 융합되는 과정에 이상이 생겨 요도 개구부가 귀두 끝이 아닌 음경 아래쪽, 음낭, 또는 회음부에 위치하게 됩니다. 주요 원인으로는 안드로겐(남성 호르몬) 분비 부족, 안드로겐 수용체 이상, 유전적 요인, 환경 호르몬 노출 등이 있으며, 이로 인해 요도 형성이 불완전하게 됩니다. 정확한 원인 평가와 치료 계획을 위해 소아비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2318, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요도하열', '요도하열', 'DEFINITION', '요도하열은 요도 개구부가 귀두 끝 정상 위치보다 아래쪽에 위치하여 소변이 흩어지거나 아래 방향으로 나오고, 심한 경우 소변 보기가 불편하며 앉아서 소변을 봐야 할 수 있습니다. 또한 음경이 아래쪽으로 굽어지는 만곡(코르디 변형)이 동반되는 경우가 있습니다. 증상이 의심된다면 소아비뇨의학과 전문의의 진찰을 받아 적절한 시기에 수술적 교정을 고려하시길 권고합니다.', 2319, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요도하열', '요도하열', 'SYMPTOM', '요도하열에서 소변 개구부 위치 이상으로 인해 귀두 앞면 포피가 두건 모양으로 불완전하게 덮이는 두건형 포피, 음경이 아래로 굽는 만곡, 소변이 아래·옆으로 퍼지거나 요도 입구가 보이지 않는 등의 소견이 동반됩니다. 요도 개구부 위치에 따라 귀두형, 음경체형, 음낭형, 회음부형으로 분류됩니다. 정확한 분류와 치료를 위해 소아비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2320, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요도하열', '요도하열', 'DIAGNOSIS', '요도하열 진단은 주로 신체 검진만으로 가능하며, 요도 개구부 위치, 음경 만곡 여부, 포피 상태를 확인합니다. 동반 기형(잠복고환, 성 발달 이상)이 의심될 경우 초음파, 호르몬 검사, 염색체 검사 등을 추가로 시행할 수 있습니다. 필요 시 전신마취 하에 음경 발기 검사로 만곡 정도를 평가하며, 소아비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2321, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요도하열', '요도하열', 'TREATMENT', '요도하열로 인한 배뇨 문제 및 음경 만곡은 주로 수술적 교정(요도성형술)으로 치료하며, 생후 6~18개월 사이에 시행하는 것이 권장됩니다. 수술을 통해 요도 개구부를 귀두 끝으로 이동시키고, 만곡을 교정하여 정상적인 배뇨와 성 기능을 회복시킵니다. 치료 방법과 수술 시기는 요도하열의 유형과 중증도에 따라 소아비뇨의학과 전문의와 상담하여 결정하시길 권고합니다.', 2322, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요독증', '요독증', 'CHECKUP', '사지 저림, 수면 장애, 집중력 저하 등 요독증이 의심되는 증상이 있다면 신장내과 또는 내과 전문의가 있는 종합병원이나 상급종합병원을 방문하시길 권고합니다. 혈액 검사(BUN, 크레아티닌, 전해질), 소변 검사 등을 통해 신장 기능을 평가할 수 있습니다. 증상이 갑자기 악화되거나 의식 변화가 있다면 응급실을 이용하시길 권고합니다.', 2323, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요독증', '요독증', 'CAUSE', '요독증은 신장 기능이 심각하게 저하되어 발생하며, 당뇨병 환자에서 당뇨성 신병증, 고혈압 환자에서 고혈압성 신경화증의 발생 빈도가 높아 이 집단에서 요독증 위험이 증가합니다. 고령, 만성 신장 질환 기왕력, 사구체신염, 전신 홍반 루푸스 환자군에서도 요독증 발생 위험이 높습니다. 당뇨병·고혈압 환자는 정기적인 신장 기능 검사를 통해 조기 발견하시길 권고합니다.', 2324, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요독증', '요독증', 'DEFINITION', '요독증은 신장 기능이 심각하게 저하되어 요독 물질이 체내에 축적된 상태로, 소변을 자주 보거나 배뇨 시 통증을 주된 증상으로 하지는 않습니다. 요독증의 특징적 증상은 오심·구토, 식욕 부진, 피로, 의식 혼탁, 호흡곤란, 부종, 피부 가려움증, 사지 저림 등입니다. 배뇨 증상이 있다면 비뇨의학과 전문의를, 전신 쇠약·부종 등이 있다면 신장내과 전문의의 진료를 받으시길 권고합니다.', 2325, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요독증', '요독증', 'SYMPTOM', '요독증에서 사지 저림은 요독성 말초 신경병증으로 인해, 기억력·집중력 저하는 요독성 뇌병증으로 인해 발생하며, 이는 실제로 요독증과 밀접한 관련이 있습니다. 요독 물질(요소, 크레아티닌, 기타 중분자 독소)의 축적이 신경계에 직접적인 독성을 유발합니다. 이러한 증상이 있다면 신장내과 전문의의 진료를 받아 신장 기능 평가를 시행하시길 권고합니다.', 2326, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요독증', '요독증', 'DIAGNOSIS', '소변 기관(신장, 요관, 방광, 요도)에 문제가 생기면 혈뇨, 단백뇨, 소변 감소 또는 증가, 배뇨 시 통증, 빈뇨, 잔뇨감, 소변 거품, 부종, 허리·옆구리 통증 등이 발생할 수 있습니다. 원인으로는 감염(방광염, 신우신염), 결석, 종양, 사구체 질환, 당뇨병성 신병증, 선천성 기형, 외상 등이 있습니다. 소변 관련 증상이 있으면 비뇨의학과 또는 신장내과 전문의의 진료를 받으시길 권고합니다.', 2327, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요독증', '요독증', 'TREATMENT', '요독증의 치료로는 혈액투석, 복막투석, 신장 이식이 있으며, 이식이 불가능한 경우 투석이 생명을 유지하는 주된 방법입니다. 신장 이식은 장기적인 생존율과 삶의 질이 가장 우수하나 공여자 필요, 면역억제제 복용 등의 조건이 있습니다. 최적의 치료 방법은 환자의 전신 상태, 나이, 공여자 여부 등을 고려하여 신장내과 전문의와 충분히 상담하여 결정하시길 권고합니다.', 2328, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요로결석', '요로결석', 'DIET_LIFE', '요로결석 환자는 하루 2~2.5리터 이상의 충분한 수분 섭취가 가장 중요하며, 소변 색이 연한 노란색을 유지하도록 합니다. 나트륨(소금)과 동물성 단백질 과다 섭취를 줄이고, 수산염이 많은 음식(시금치, 견과류, 초콜릿)은 적당히 제한하며, 구연산이 풍부한 레몬수, 오렌지주스도 도움이 됩니다. 재발 예방을 위해 비뇨의학과 전문의의 지속적인 추적 관찰을 받으시길 권고합니다.', 2329, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요로결석', '요로결석', 'MEDICATION', '요로결석 치료에는 결석 배출을 돕는 알파차단제(탐술로신 등)와 통증 조절을 위한 NSAIDs, 진경제 등의 약물이 사용됩니다. 결석이 작고(5mm 이하) 요관 폐색이 심하지 않으면 약물 복용과 충분한 수분 섭취로 자연 배출을 기대할 수 있습니다. 결석이 크거나 자연 배출이 어려운 경우 체외충격파쇄석술이나 내시경 수술을 고려하며, 비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2330, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요로결석', '요로결석', 'PREVENTION', '나트륨 섭취를 줄이면 소변 내 칼슘 배설이 감소하여 칼슘 수산염, 칼슘 인산염 결석의 형성 위험을 낮출 수 있습니다. 고나트륨 식이는 신장에서 나트륨과 함께 칼슘 재흡수를 방해하여 소변 내 칼슘 농도를 높이기 때문입니다. 나트륨 제한과 함께 충분한 수분 섭취, 동물성 단백질 제한, 구연산 섭취 증가 등을 병행하면 요로결석 예방에 효과적입니다.', 2331, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요로결석', '요로결석', 'CAUSE', '물을 적게 마시는 것 외에도 요로결석의 원인으로는 고나트륨·고단백 식이, 수산염이 풍부한 음식 과다 섭취, 비만, 당뇨병, 부갑상선 기능항진증, 통풍, 반복적인 요로 감염, 비타민 C·D 과다 복용, 칼슘 제제 과다 복용, 특정 이뇨제 사용, 유전적 소인(특발성 고칼슘뇨증 등) 등이 있습니다. 결석 재발이 잦다면 원인 파악을 위해 비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2332, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요로결석', '요로결석', 'DEFINITION', '요로결석은 신장에서만 생기는 것이 아니라 요로계 전체(신장, 요관, 방광, 요도)에 결석이 생길 수 있으며, 위치에 따라 신장 결석, 요관 결석, 방광 결석으로 분류됩니다. 가장 흔한 것은 신장에서 형성된 결석이 요관으로 내려오는 요관 결석입니다. 생식기 관련 구조물에는 발생하지 않으며, 비뇨의학과 전문의의 진료로 정확한 위치와 종류를 진단할 수 있습니다.', 2333, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요로결석', '요로결석', 'SYMPTOM', '혈뇨(붉은 소변)와 옆구리·복부 통증이 동반되는 경우 요로결석에 의한 요관 손상이나 폐색을 강하게 의심해야 합니다. 결석이 요관을 따라 이동하면서 점막을 자극하거나 폐색하면 심한 산통성 통증과 혈뇨, 구역·구토가 나타납니다. 이러한 증상이 있다면 비뇨의학과 전문의를 방문하거나 통증이 심한 경우 응급실을 이용하시길 권고합니다.', 2334, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요로결석', '요로결석', 'DIAGNOSIS', '요로결석 진단은 임상 증상 확인 후 소변 검사(혈뇨, 세균뇨), 혈액 검사(신기능, 감염 여부), 복부·골반 CT(비조영 CT가 표준, 결석 크기·위치 확인), 신장 초음파(방사선 피폭 없이 수신증 확인) 순으로 이루어집니다. CT는 결석의 위치, 크기, 주변 구조 상태를 가장 정확하게 평가합니다. 통증이 심한 경우 비뇨의학과 전문의나 응급실을 방문하시길 권고합니다.', 2335, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요로결석', '요로결석', 'TREATMENT', '요로결석에 의한 혈뇨와 배뇨 통증 치료로는 통증 조절(NSAIDs, 진경제), 알파차단제를 이용한 결석 배출 촉진, 충분한 수분 섭취가 기본입니다. 결석이 작으면(5mm 이하) 자연 배출을 기대할 수 있고, 크거나 폐색이 심한 경우 체외충격파쇄석술(ESWL), 요관경 수술(레이저 쇄석술), 경피적 신장결석제거술 등을 시행합니다. 치료 방법은 결석 크기·위치·신기능에 따라 비뇨의학과 전문의와 상담하여 결정하시길 권고합니다.', 2336, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요실금', '요실금', 'CHECKUP', '요실금 검진 방법으로는 방광 초음파, 요역동학 검사 외에도 요류 검사(소변 속도·양 측정), 소변 검사(감염 여부), 배뇨 일지 작성, 패드 검사(요실금 양 측정), 방광경 검사(방광 내부 관찰) 등이 활용됩니다. 요역동학 검사는 방광 저장과 배출 기능을 종합적으로 평가하는 데 가장 유용합니다. 정확한 요실금 유형 진단을 위해 비뇨의학과 또는 산부인과 전문의의 진료를 받으시길 권고합니다.', 2337, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요실금', '요실금', 'MEDICATION', '복압성 요실금의 약물 치료로는 요도 괄약근 수축을 강화하는 둘록세틴(세로토닌-노르에피네프린 재흡수 억제제)이 사용될 수 있으며, 폐경 여성에서는 국소 에스트로겐 크림이 요도 점막 강화에 도움이 될 수 있습니다. 단, 국내에서 복압성 요실금에 대한 약물 치료 효과는 제한적이므로 케겔 운동 등 행동 치료와 병행하거나 수술적 치료를 고려합니다. 치료 방법은 비뇨의학과 전문의와 상담하여 결정하시길 권고합니다.', 2338, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요실금', '요실금', 'PREVENTION', '나이가 들면 골반저 근육과 요도 괄약근이 약해지고, 여성의 경우 폐경 후 에스트로겐 감소로 요도 점막과 주변 조직이 위축되어 요실금 위험이 높아집니다. 또한 출산 경험, 만성 기침, 비만, 신경계 변화도 연령 증가와 함께 누적되어 요실금 발생에 기여합니다. 예방을 위해 젊을 때부터 규칙적인 케겔 운동, 정상 체중 유지, 금연, 충분한 수분 섭취(과도하지 않게)를 권고합니다.', 2339, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요실금', '요실금', 'EXERCISE', '폐경 후 복압성 또는 절박성 요실금으로 소변이 찔끔 나오는 증상에는 케겔 운동(골반저 근육 강화 운동)이 가장 효과적이고 안전한 운동법입니다. 케겔 운동은 질·항문 주변 근육을 수축하고 5~10초 유지 후 이완하는 동작을 하루 3세트, 각 10~15회 반복하며 꾸준히 시행합니다. 증상이 지속된다면 비뇨의학과 또는 산부인과 전문의의 진료를 받아 적절한 치료를 병행하시길 권고합니다.', 2340, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요실금', '요실금', 'CAUSE', '요실금의 원인에는 선천적 요인(골반 구조 이상, 요도 기형)과 후천적 요인이 있습니다. 후천적 원인으로는 출산(특히 질식 분만), 폐경 후 에스트로겐 감소, 노화에 따른 골반저 근육 약화, 비만, 만성 기침, 신경 질환(뇌졸중, 다발성경화증), 전립선 수술 후(남성) 등이 있습니다. 원인을 구별하고 적합한 치료를 받기 위해 비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2341, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요실금', '요실금', 'DEFINITION', '요실금은 본인의 의지와 무관하게 소변이 새는 상태를 말하며, 소변이 마렵지 않은데도 습관적으로 소변을 자주 보는 것(예방적 빈뇨)은 방광 용량을 줄여 오히려 요실금을 악화시킬 수 있습니다. 옷이 젖는 현상이 지속된다면 복압성 요실금이나 절박성 요실금을 감별해야 합니다. 정확한 진단을 위해 비뇨의학과 전문의의 진료를 받으시길 권고합니다.', 2342, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요실금', '요실금', 'SYMPTOM', '아침에 일어날 때 소변을 참기 어려운 증상은 절박성 요실금 또는 과활동성 방광의 특징적인 증상으로, 요실금과 밀접한 관련이 있습니다. 수면 중 방광에 소변이 채워지고 기상 시 체위 변화, 움직임, 물 소리 등의 자극이 방광 수축을 유발하는 것이 원인입니다. 이러한 증상이 지속된다면 비뇨의학과 전문의를 방문하여 정확한 진단과 치료를 받으시길 권고합니다.', 2343, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요실금', '요실금', 'DIAGNOSIS', '소변이 약간 묻어나는 요실금이 있다면 복압성, 절박성, 혼합성 요실금으로 나눌 수 있으며, 유형에 따라 치료가 달라집니다. 복압성 요실금은 케겔 운동, 중부요도슬링 수술이 효과적이고, 절박성 요실금은 방광 훈련, 항콜린제, 베타3 작용제 등의 약물 치료가 사용됩니다. 정확한 유형 진단과 치료 방법 선택을 위해 비뇨의학과 또는 산부인과 전문의의 진료를 받으시길 권고합니다.', 2344, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '요실금', '요실금', 'TREATMENT', '복압성 요실금의 비수술적 치료로는 골반저근 강화 운동(케겔 운동)이 가장 효과적이며, 규칙적으로 시행 시 증상 개선에 도움이 됩니다. 방광 훈련, 생활 습관 교정(체중 감량, 카페인 제한), 바이오피드백 치료도 병행할 수 있습니다. 증상이 지속되면 비뇨기과 전문의의 진료를 받으시기 바랍니다.', 2345, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '음낭수종', '음낭수종', 'CAUSE', '음낭수종의 주요 치료 방법으로는 수술적 치료(수낭절제술)가 표준 치료입니다. 소아의 경우 생후 1~2년 내 자연 소실되기도 하여 경과 관찰이 우선이며, 성인의 경우 증상이 있거나 크기가 큰 경우 수술을 시행합니다. 치료 방법 결정은 비뇨기과 전문의와 상담 후 결정하시기 바랍니다.', 2346, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '음낭수종', '음낭수종', 'DEFINITION', '음낭 내에서 만져지는 다른 질환으로는 고환암, 고환 부고환염, 정계정맥류, 부고환 낭종, 정액류 등이 있습니다. 고환암은 단단하고 통증 없이 만져지는 덩어리가 특징이며, 복부 림프절 전이 시 복통이 동반될 수 있습니다. 음낭에서 이상이 만져지면 반드시 비뇨기과 전문의의 진찰을 받으시기 바랍니다.', 2347, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '음낭수종', '음낭수종', 'SYMPTOM', '한쪽 고환이 반대쪽에 비해 커진 경우 음낭수종의 증상일 수 있습니다. 음낭수종은 고환 주위에 액체가 고여 음낭이 부풀어 오르는 상태로, 통증 없이 한쪽만 커지는 것이 특징입니다. 소아에서 흔히 발생하나 고환염전이나 종양과 감별이 필요하므로 소아과 또는 비뇨기과 전문의 진찰이 필요합니다.', 2348, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '음낭수종', '음낭수종', 'DIAGNOSIS', '음낭수종 진단에는 음낭 초음파 검사가 가장 일반적으로 사용됩니다. 초음파는 액체의 위치와 양, 고환 및 부고환의 상태를 확인하고 종양 등 다른 질환과 감별하는 데 유용합니다. 확진과 적절한 치료 계획을 위해 비뇨기과 전문의의 진료를 받으시기 바랍니다.', 2349, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '음낭수종', '음낭수종', 'TREATMENT', '음낭수종 자체는 배뇨 장애나 빈뇨를 직접 유발하지 않으므로, 해당 증상은 전립선 비대증이나 방광 문제 등 다른 원인을 고려해야 합니다. 음낭수종이 확인된 경우 수술적 치료(수낭절제술)가 주된 방법이며, 배뇨 증상에 대해서는 별도 평가가 필요합니다. 정확한 진단을 위해 비뇨기과 전문의의 진료를 받으시기 바랍니다.', 2350, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '임질', '임질', 'CHECKUP', '임질은 증상이 없는 경우도 많아 모르고 지내다 합병증이 생길 수 있으므로 정기 검진이 중요합니다. 성 활동이 활발한 경우 연 1회 이상, 여러 파트너가 있거나 콘돔을 사용하지 않는 경우 3~6개월마다 검진을 권장합니다. 치료받지 않으면 골반염, 불임, 패혈증 등 심각한 합병증으로 이어질 수 있어 정기 검진이 필수적입니다.', 2351, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '임질', '임질', 'DIET_LIFE', '임질 치료 중 발열이나 피부 발진이 동반되는 경우 파종성 임균 감염을 의심해야 하며, 충분한 수분 섭취와 균형 잡힌 영양 섭취가 회복에 도움이 됩니다. 항생제 치료 기간 동안 음주를 삼가고 성관계를 피해야 하며, 파트너도 함께 치료를 받아야 합니다. 임질 치료 및 생활 지침은 반드시 비뇨기과 또는 감염내과 전문의의 지도 하에 시행하시기 바랍니다.', 2352, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '임질', '임질', 'MEDICATION', '임질 치료에 사용되는 항생제(세프트리악손, 아지트로마이신 등)는 주로 세균 감염을 표적으로 하여 성기능에 직접적인 영향을 미치지 않습니다. 항생제는 신경계나 성호르몬 체계에 작용하지 않기 때문에 성기능 장애를 일으킬 가능성이 낮습니다. 다만 임질 자체나 심리적 요인이 성기능에 영향을 줄 수 있으므로, 관련 증상이 있으면 전문의와 상담하시기 바랍니다.', 2353, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '임질', '임질', 'PREVENTION', '임질 예방을 위해서는 성관계 시 콘돔을 일관되게 올바르게 사용하는 것이 가장 효과적입니다. 성 파트너 수를 제한하고, 정기적인 성병 검진을 받으며, 파트너가 임질 진단을 받은 경우 즉시 함께 치료를 받아야 합니다. 생식기 가려움증이나 분비물 등 증상이 있을 경우 즉시 비뇨기과 또는 산부인과 전문의의 진료를 받으시기 바랍니다.', 2354, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '임질', '임질', 'CAUSE', '임질은 임균(Neisseria gonorrhoeae)에 의한 세균성 성병으로, 무거운 물건을 들거나 장시간 앉아 있는 행동과는 직접적인 관련이 없습니다. 임질은 오직 성적 접촉(질, 항문, 구강 성교)을 통해 전파되며, 생활 습관이나 신체 활동은 감염 원인이 아닙니다. 임질 감염이 의심되면 비뇨기과 또는 감염내과 전문의의 진료를 받으시기 바랍니다.', 2355, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '임질', '임질', 'DEFINITION', '임질은 임균(Neisseria gonorrhoeae)이라는 세균에 의해 발생하는 성병으로, 주로 성적 접촉을 통해 전파됩니다. 드물게 분만 시 감염된 산모로부터 신생아에게 수직 감염이 될 수 있으나, 성관계 없이 일상 접촉으로는 전파되지 않습니다. 요도, 자궁경부, 인두, 직장 등을 침범하며 치료받지 않으면 심각한 합병증을 유발합니다.', 2356, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '임질', '임질', 'SYMPTOM', '임질의 특징적 증상으로 남성은 요도에서 고름 분비 외에 배뇨 시 작열감, 빈뇨, 요도구 발적 및 부종이 나타납니다. 여성은 무증상인 경우가 많으나 질 분비물 증가, 배뇨 통증, 골반 통증이 나타날 수 있습니다. 치료하지 않으면 남성은 부고환염, 여성은 골반염으로 진행할 수 있으므로 비뇨기과 전문의의 진료를 받으시기 바랍니다.', 2357, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '임질', '임질', 'DIAGNOSIS', '임질이 의심될 경우 비뇨기과 또는 산부인과를 방문하여 요도 분비물이나 자궁경부 분비물 도말 검사 및 균 배양 검사, 핵산 증폭 검사(NAAT)를 시행합니다. 검사 전 항생제 복용이나 배뇨를 삼가면 정확도가 높아집니다. 성 파트너도 함께 검사 및 치료를 받는 것이 중요하며, 반드시 전문의의 진료를 받으시기 바랍니다.', 2358, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '임질', '임질', 'TREATMENT', '임질은 항생제로 치료하며, 현재 표준 치료는 세프트리악손 근육주사와 아지트로마이신 경구 병합 요법입니다. 치료 후 성 파트너도 반드시 함께 검사 및 치료를 받아야 하며, 치료 완료 전까지 성관계를 피해야 합니다. 임질이 의심되면 즉시 비뇨기과 또는 감염내과 전문의의 진료를 받으시기 바랍니다.', 2359, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '잠복고환증', '잠복고환증', 'CAUSE', '잠복고환증은 고환이 태생기에 복강에서 음낭으로 내려오지 못한 상태로, 정확한 원인은 아직 완전히 밝혀지지 않았습니다. 관련 원인으로는 호르몬 이상(안드로겐 부족), 해부학적 이상, 유전적 요인 등이 거론되며, 미숙아에서 발생률이 높습니다. 잠복고환증은 불임과 고환암 위험 증가와 관련이 있어 소아비뇨기과 전문의의 진료가 필요합니다.', 2360, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '잠복고환증', '잠복고환증', 'DEFINITION', '잠복고환증은 고환이 정상적으로 음낭 내로 하강하지 못하고 복강, 서혜부, 음낭 입구 등에 위치한 상태를 말합니다. 만삭아의 약 3%, 미숙아의 약 30%에서 발생하며, 생후 3~6개월 내 자연 하강하는 경우도 있습니다. 치료받지 않으면 불임 및 고환암 위험이 증가하므로 소아비뇨기과 전문의의 조기 진료가 중요합니다.', 2361, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '잠복고환증', '잠복고환증', 'SYMPTOM', '잠복고환증에서는 한쪽 또는 양쪽 음낭이 비어 있거나 작아 보이는 것이 주요 소견입니다. 그 외에 서혜부에서 덩어리가 만져지거나, 음낭 불균형이 관찰될 수 있으며, 대부분 통증은 없습니다. 드물게 고환 비틀림(고환염전)이 발생하면 급성 통증이 나타날 수 있으므로 소아비뇨기과 전문의의 진료를 받으시기 바랍니다.', 2362, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '잠복고환증', '잠복고환증', 'DIAGNOSIS', '잠복고환증의 정확한 진단을 위해서는 소아비뇨기과 전문의를 방문하는 것이 적절합니다. 신체 검진으로 고환 위치를 확인하고, 필요 시 초음파나 MRI 등 영상 검사를 시행합니다. 조기 진단과 치료가 불임 및 고환암 예방에 중요하므로, 음낭이 비어 있다고 의심되면 즉시 전문의의 진료를 받으시기 바랍니다.', 2363, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '잠복고환증', '잠복고환증', 'TREATMENT', '잠복고환증의 표준 치료는 수술적 고환고정술(orchidopexy)로, 생후 6~18개월 사이에 시행하는 것이 권장됩니다. 조기 수술을 통해 생식 기능 보존과 고환암 위험 감소 효과를 기대할 수 있습니다. 호르몬 치료(hCG, GnRH)는 일부 경우에 시도할 수 있으나 효과가 제한적이므로, 소아비뇨기과 전문의와 상담하시기 바랍니다.', 2364, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '조루증', '조루증', 'CHECKUP', '조루증은 사정 조절 능력 부족으로 성관계 시 원하는 것보다 빠르게 사정하는 상태로, 상황에 따라 증상이 달라질 수 있습니다. 스트레스, 불안, 새로운 파트너, 오랜 금욕 후 등의 상황에서 더 심하게 나타나는 경우가 많습니다. 조루증이 지속되어 성생활에 지장을 준다면 비뇨기과 전문의의 검진을 받아 원인을 파악하고 적절한 치료를 받는 것이 중요합니다.', 2365, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '조루증', '조루증', 'MEDICATION', '조루증 약물 치료에는 주로 선택적 세로토닌 재흡수 억제제(SSRI) 계열 약물이 사용되며, 세로토닌 농도를 높여 사정 반사를 억제하는 원리입니다. 단기 작용 약물(다폭세틴)은 성관계 1~3시간 전 복용하고, 장기 작용 약물은 매일 복용합니다. 약물 선택과 복용 방법은 비뇨기과 전문의의 처방에 따라야 하며, 임의로 복용하지 않도록 주의하시기 바랍니다.', 2366, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '조루증', '조루증', 'CAUSE', '조루증의 원인은 심리적 요인(불안, 스트레스, 우울증)과 신체적 요인(신경 과민, 전립선염, 갑상선 기능 항진증)으로 나눌 수 있습니다. 특별히 ''문지''라는 명확한 의학적 원인 개념은 없으며, 조루증은 다양한 심리·신체적 복합 요인에 의해 발생합니다. 정확한 원인 파악과 치료를 위해 비뇨기과 전문의의 진료를 받으시기 바랍니다.', 2367, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '조루증', '조루증', 'DEFINITION', '조루증은 삽입 전이나 삽입 직후 또는 원하기 전에 사정이 반복적으로 발생하여 성생활에 불만족을 초래하는 상태입니다. 신체적으로는 사정 조절 근육과 신경계의 과민 반응이 관련되며, 음경 자체의 구조적 문제보다는 신경·근육 조절 기능의 문제가 주요 원인입니다. 지속적인 증상이 있으면 비뇨기과 전문의의 진료를 받으시기 바랍니다.', 2368, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '조루증', '조루증', 'SYMPTOM', '조루증은 음경의 구조적 손상이나 직접적인 통증을 유발하지는 않으나, 성관계 시 조기 사정으로 인해 성적 불만족과 심리적 스트레스를 초래합니다. 이로 인해 이차적으로 발기부전이나 성욕 저하가 동반될 수 있습니다. 성기 통증이 함께 있다면 전립선염 등 다른 질환을 배제하기 위해 비뇨기과 전문의의 진료를 받으시기 바랍니다.', 2369, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '조루증', '조루증', 'DIAGNOSIS', '질문에서 설명된 증상(삽입 전후 사정의 반복적 재발)은 조루증의 진단 기준에 해당하며, 치료로는 행동 치료(스톱-스타트 기법, 스퀴즈 기법), 약물 치료(SSRI, 국소 마취 크림), 심리 상담 등이 있습니다. 행동 치료와 약물 치료를 병합할 때 더 효과적인 경우가 많습니다. 적절한 치료 방법 선택을 위해 비뇨기과 전문의의 진료를 받으시기 바랍니다.', 2370, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '조루증', '조루증', 'TREATMENT', '조루증의 비약물 치료로는 행동 치료(스톱-스타트 기법, 스퀴즈 기법), 심리 상담 및 성 치료, 골반저근 운동이 있습니다. 국소 마취 크림이나 두꺼운 콘돔 사용으로 귀두 감각을 줄이는 방법도 도움이 됩니다. 수술 치료(배부 신경 차단술)도 있으나 효과와 부작용에 대한 논란이 있으므로 비뇨기과 전문의와 충분한 상담 후 결정하시기 바랍니다.', 2371, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '포경', '포경', 'CAUSE', '포경(phimosis)은 포피가 좁아 귀두를 완전히 노출하기 어려운 상태로, 이로 인해 귀두포피염, 요로감염, 성관계 통증 등이 반복될 수 있습니다. 포경 수술은 이러한 감염과 염증을 예방하고, 음경 위생 관리를 용이하게 하며, 음경암 발생 위험을 낮추는 효과가 있습니다. 수술 필요성 여부는 비뇨기과 전문의와 상담 후 결정하시기 바랍니다.', 2372, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '포경', '포경', 'DEFINITION', '포경은 포피(음경 피부)가 좁아서 귀두 뒤쪽으로 완전히 젖혀지지 않는 상태를 말합니다. 선천성 포경은 소아에서 흔하며 성장하면서 자연 해결되는 경우도 있으나, 반복적인 염증이 있거나 불편감이 심하면 치료가 필요합니다. 아들의 반복적인 귀두포피염이 있다면 비뇨기과 전문의와 상담하여 치료 방향을 결정하시기 바랍니다.', 2373, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '포경', '포경', 'SYMPTOM', '포피가 귀두 뒤로 젖혀진 후 다시 돌아오지 않는 상태를 감돈포경(paraphimosis)이라 하며, 이는 의료적 응급 상황입니다. 감돈포경이 지속되면 귀두와 포피에 혈액 순환이 차단되어 조직 괴사가 발생할 수 있습니다. 이 증상이 나타나면 즉시 응급실 또는 비뇨기과 전문의를 방문하여 신속한 치료를 받으시기 바랍니다.', 2374, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '포경', '포경', 'DIAGNOSIS', '포경 수술은 비뇨기과 전문의가 담당하는 수술로, 아이의 포경 수술 상담 및 시행은 비뇨기과를 방문하시는 것이 적절합니다. 피부과는 피부 질환을 전문으로 하므로 포경 수술에는 적합하지 않습니다. 소아의 경우 소아비뇨기과 전문의가 있는 기관을 선택하면 더욱 전문적인 진료를 받을 수 있습니다.', 2375, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '포경', '포경', 'TREATMENT', '포경은 음경의 포피 부위에 발생하며, 반복적인 귀두포피염과 요로감염을 유발할 수 있습니다. 예방을 위해서는 음경 청결을 유지하고, 포피를 무리하게 강제로 당기지 않아야 합니다. 반복적인 염증이나 배뇨 장애가 있을 경우 비뇨기과 전문의를 방문하여 포경 수술 여부를 포함한 치료 계획을 상담하시기 바랍니다.', 2376, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '혈뇨', '혈뇨', 'CAUSE', '혈뇨의 원인은 요로계 전반(신장, 요관, 방광, 요도)에서 발생할 수 있으며, 주요 원인으로는 요로 결석, 요로감염, 방광암, 신장암, 신장염, 전립선 비대증 등이 있습니다. 혈뇨 평가 시 연령, 흡연력, 통증 유무, 혈뇨 양상(육안적/현미경적)에 주목해야 합니다. 혈뇨가 발견되면 즉시 비뇨기과 전문의의 진료를 받아 원인을 확인하시기 바랍니다.', 2377, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '혈뇨', '혈뇨', 'DEFINITION', '혈뇨란 소변에 적혈구가 섞여 나오는 상태로, 육안으로 붉거나 갈색으로 보이는 ''육안적 혈뇨''와 현미경으로만 확인되는 ''현미경적 혈뇨''로 구분됩니다. 소변을 볼 때 피가 함께 나오는 것은 혈뇨에 해당하며, 단 한 번이라도 발생한 경우 원인 검사가 필요합니다. 비뇨기과 전문의를 방문하여 정확한 원인 진단을 받으시기 바랍니다.', 2378, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '혈뇨', '혈뇨', 'SYMPTOM', '혈뇨가 나타나면 즉시 비뇨기과 전문의의 진료를 받는 것이 가장 중요합니다. 혈뇨는 요로 결석의 경우 옆구리 통증, 감염의 경우 발열·배뇨 통증, 방광암의 경우 통증 없이 혈뇨만 나타나는 등 원인에 따라 동반 증상이 다릅니다. 충분한 수분 섭취는 도움이 될 수 있으나, 자가 판단보다 전문의 진료를 통한 정확한 원인 파악이 필수적입니다.', 2379, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '혈뇨', '혈뇨', 'DIAGNOSIS', '혈뇨가 의심되면 비뇨기과를 1차적으로 방문하는 것이 적합합니다. 비뇨기과 전문의는 소변 검사, 요세포 검사, 초음파, CT 등의 검사를 통해 신장, 요관, 방광 등 요로계의 이상 여부를 체계적으로 평가합니다. 단 1회의 혈뇨라도 방광암 등 심각한 질환의 신호일 수 있으므로 반드시 전문의의 진료를 받으시기 바랍니다.', 2380, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '혈뇨', '혈뇨', 'TREATMENT', '지속적인 혈뇨의 치료는 원인에 따라 달라집니다. 요로감염이 원인이면 항생제 치료를, 요로 결석이면 체외충격파나 수술적 제거를, 방광암이나 신장암이 원인이면 수술·방사선·항암 치료를 시행합니다. 혈뇨가 반복된다면 즉시 비뇨기과 전문의를 방문하여 원인 검사와 적절한 치료를 받으시기 바랍니다.', 2381, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '골반 염증성 질환', '골반염증성질환', 'CAUSE', '골반 염증성 질환(PID)의 주요 원인은 임균, 클라미디아 등 성병균 또는 정상 질 상재균의 상행 감염입니다. 아랫배 통증과 치골 부위 통증은 골반 염증성 질환의 대표적인 증상으로, 원인이 아닌 염증 반응으로 인한 증상에 해당합니다. 이러한 증상이 있으면 산부인과 전문의의 진료를 받아 정확한 원인을 확인하고 치료받으시기 바랍니다.', 2382, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '골반 염증성 질환', '골반염증성질환', 'DEFINITION', '골반 염증성 질환(PID)의 특징적 증상은 하복부 또는 골반 통증, 발열, 자궁경부 접촉 시 통증, 비정상적 질 분비물 등입니다. 복부 통증이나 불편감이 있는 경우 PID를 의심할 수 있으나, 다른 복부 질환과 감별이 필요합니다. 정확한 진단을 위해 반드시 산부인과 전문의의 진료와 검사를 받으시기 바랍니다.', 2383, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '골반 염증성 질환', '골반염증성질환', 'SYMPTOM', '월경 후 지속되는 골반 하부 통증과 악취가 나는 분비물은 골반 염증성 질환의 주요 의심 증상입니다. 이 두 증상의 확인이 중요한 이유는 임균이나 클라미디아 감염이 자궁, 난관, 난소로 상행하여 심각한 염증과 불임을 유발할 수 있기 때문입니다. 이러한 증상이 있으면 즉시 산부인과 전문의의 진료를 받아 적절한 치료를 받으시기 바랍니다.', 2384, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '골반 염증성 질환', '골반염증성질환', 'DIAGNOSIS', '골반 염증성 질환이 의심될 경우 산부인과를 방문하면 골반 내진, 자궁경부 분비물 배양 검사, 혈액 검사(염증 수치), 경질 초음파 검사 등을 받을 수 있습니다. 이를 통해 자궁, 난관, 난소의 염증 상태와 농양 여부를 평가합니다. 조기에 발견하고 치료할수록 불임 등 합병증 예방에 효과적이므로, 증상이 있으면 지체 없이 산부인과 전문의를 방문하시기 바랍니다.', 2385, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '골반 염증성 질환', '골반염증성질환', 'TREATMENT', '골반 염증성 질환의 치료는 주로 항생제 치료를 시행하며, 경증은 경구 항생제로 외래 치료, 중증이나 농양이 있는 경우 입원하여 정맥 항생제를 투여합니다. 항생제 치료 기간은 보통 14일이며, 농양이 동반된 경우 수술적 배농이 필요할 수 있습니다. 치료 방법과 기간은 중증도에 따라 달라지므로 산부인과 전문의의 진료를 받으시기 바랍니다.', 2386, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '과다월경', '과다월경', 'CHECKUP', '과다월경은 1회 월경량이 80mL 이상이거나 월경 기간이 7일을 초과하는 상태로, 빈혈(피로, 어지럼증, 창백), 저혈압, 무기력감 등을 동반할 수 있습니다. 철 결핍성 빈혈이 가장 흔한 합병증으로, 혈색소 감소와 혈청 페리틴 저하가 나타납니다. 과다월경과 빈혈 증상이 함께 있다면 산부인과 전문의의 진료와 혈액 검사를 받으시기 바랍니다.', 2387, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '과다월경', '과다월경', 'MEDICATION', '과다월경의 약물 치료로는 호르몬 치료(경구 피임약, 프로게스틴), 비호르몬 치료(트라넥삼산, 이부프로펜 등 NSAIDs), 자궁내 장치(미레나)가 있으며, 월경량 감소에 효과적입니다. 각 약물은 혈전, 오심, 두통 등의 부작용이 있을 수 있으므로 개인 상태에 따라 신중히 선택해야 합니다. 약물 치료는 반드시 산부인과 전문의의 처방에 따라 시행하시기 바랍니다.', 2388, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '과다월경', '과다월경', 'PREVENTION', '과다월경 예방을 위해 규칙적인 운동과 정상 체중 유지, 철분이 풍부한 식품(붉은 고기, 녹색 채소, 콩류) 섭취가 도움이 됩니다. 스트레스 관리, 충분한 수면, 과도한 카페인과 알코올 섭취 제한도 권장됩니다. 근본적인 원인(자궁근종, 다낭성 난소 증후군 등)이 있는 경우 원인 치료가 우선이므로 산부인과 전문의의 진료를 받으시기 바랍니다.', 2389, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '과다월경', '과다월경', 'CAUSE', '과다월경이 자궁 폴립의 원인이 되는 것은 아니며, 반대로 자궁 폴립이나 자궁근종 등이 과다월경을 유발하는 원인이 됩니다. 자궁 폴립은 자궁내막 조직의 과증식으로 발생하며, 이로 인해 월경량이 증가하고 월경 기간이 길어질 수 있습니다. 과다월경이 지속된다면 산부인과 전문의를 방문하여 자궁 초음파 등 원인 검사를 받으시기 바랍니다.', 2390, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '과다월경', '과다월경', 'DEFINITION', '과다월경은 한 월경 주기 동안 출혈량이 80mL를 초과하거나 월경 기간이 7일 이상 지속되는 상태를 말합니다. 패드나 탐폰을 1~2시간마다 교체해야 할 정도로 출혈이 많거나, 큰 혈전이 자주 배출되는 경우 과다월경으로 의심할 수 있습니다. 이러한 증상이 있으면 산부인과 전문의의 진료를 받아 원인을 확인하시기 바랍니다.', 2391, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '과다월경', '과다월경', 'SYMPTOM', '과다월경의 경우 생리대나 탐폰이 1~2시간 내에 흠뻑 젖거나 옷에 피가 비치는 경우가 흔히 발생합니다. 패드 교체 빈도가 매우 잦거나(하루 6개 이상), 혈전이 동전 크기 이상으로 자주 배출되는 경우 과다월경을 의심할 수 있습니다. 이러한 증상이 지속되면 빈혈을 동반할 수 있으므로 산부인과 전문의의 진료를 받으시기 바랍니다.', 2392, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '과다월경', '과다월경', 'DIAGNOSIS', '과다월경 진단을 위해서는 산부인과 전문의를 방문하시기 바랍니다. 산부인과에서는 문진, 골반 검진, 혈액 검사(빈혈 여부), 자궁 초음파, 필요 시 자궁내막 조직 검사 등을 통해 원인을 평가합니다. 정확한 진단과 원인에 맞는 치료를 위해 증상이 있으면 조기에 전문의를 방문하시기 바랍니다.', 2393, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '과다월경', '과다월경', 'TREATMENT', '경구 피임약(복합 호르몬 피임약)은 자궁내막을 얇게 하고 프로스타글란딘 생성을 억제하여 월경량을 30~50% 감소시키는 효과가 있습니다. 호르몬 자궁내 장치(미레나)는 월경량을 최대 90%까지 줄일 수 있어 가장 효과적인 방법 중 하나입니다. 개인에게 적합한 치료 방법은 원인, 나이, 임신 계획 등을 고려하여 산부인과 전문의와 상담 후 결정하시기 바랍니다.', 2394, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '급성 질염', '급성질염', 'MEDICATION', '급성 질염 치료에 사용되는 항생제나 항진균제가 특정 환자에게 맞지 않거나 알레르기 반응을 일으키는 경우가 있을 수 있습니다. 이런 경우 원인균에 따라 다른 계열의 약물로 변경하거나 대체 치료를 선택할 수 있습니다. 약물에 부작용이 생기거나 증상이 호전되지 않으면 반드시 산부인과 전문의에게 알리고 처방을 변경받으시기 바랍니다.', 2395, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '급성 질염', '급성질염', 'PREVENTION', '당뇨병이 있으면 면역력 저하와 고혈당 환경으로 인해 칸디다성 질염 발생 위험이 높아집니다. 호르몬 피임제(특히 에스트로겐 함량이 높은 경우)는 질내 환경을 변화시켜 감염에 취약하게 만들 수 있으며, 꽉 조이는 옷은 통기성을 저하시켜 질 내 습도와 온도를 높여 균 증식을 유발합니다. 이러한 위험 요인이 있는 경우 산부인과 전문의와 상담하여 예방 및 관리 방법을 지도받으시기 바랍니다.', 2396, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '급성 질염', '급성질염', 'CAUSE', '경구 피임약은 질내 pH와 호르몬 환경을 변화시켜 세균성 질염이나 칸디다성 질염 발생 위험을 높일 수 있습니다. 꽉 끼는 옷이나 합성 섬유 속옷은 통기성을 저하시켜 질 주변의 온도와 습도를 높여 세균 및 진균의 증식에 유리한 환경을 만듭니다. 이러한 외부 요인을 피하는 것이 급성 질염 예방에 도움이 되며, 반복되는 경우 산부인과 전문의의 진료를 받으시기 바랍니다.', 2397, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '급성 질염', '급성질염', 'DEFINITION', '급성 질염은 세균, 진균(칸디다), 트리코모나스 등에 의해 질에 급성 염증이 발생하는 상태로, 갑작스러운 분비물 증가, 분비물 색 및 냄새 변화(비린내 또는 치즈 모양), 가려움증, 작열감, 배뇨 통증 등이 주요 증상입니다. 원인 균종에 따라 증상이 다를 수 있으며, 자가 치료보다 산부인과 전문의의 진료를 통한 정확한 원인 진단과 치료가 필요합니다.', 2398, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '급성 질염', '급성질염', 'SYMPTOM', '급성 질염으로 인한 분비물 증가와 냄새 변화는 세균성 질염이나 트리코모나스 감염에서 흔히 나타납니다. 정확한 진단을 위해서는 산부인과를 방문하여 질 분비물 현미경 검사, pH 측정, 균 배양 검사 등을 시행해야 합니다. 자가 진단이나 시중 약국 약으로만 치료하면 원인을 놓칠 수 있으므로 반드시 전문의의 진료를 받으시기 바랍니다.', 2399, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '급성 질염', '급성질염', 'DIAGNOSIS', '급성 질염 진단 시 분비물의 성상(색, 냄새, 양), 가려움증, 작열감 외에도 질 pH 측정, 현미경 도말 검사(클루세포, 균사 확인), 균 배양 검사가 중요한 역할을 합니다. 필요 시 성병 검사(임균, 클라미디아, 트리코모나스)도 함께 시행합니다. 증상만으로는 원인균을 구별하기 어려우므로 산부인과 전문의의 검사를 통한 정확한 진단이 필요합니다.', 2400, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '급성 질염', '급성질염', 'TREATMENT', '급성 질염의 재발을 줄이기 위해서는 원인균에 맞는 항생제 또는 항진균제 치료를 완료하고, 성 파트너 동반 치료(트리코모나스의 경우), 질 세척 자제, 통기성 속옷 착용 등 생활 습관 개선이 중요합니다. 자궁경부암 검진과 질염은 별개이지만, 정기 산부인과 검진을 통해 조기 발견과 치료를 받는 것이 재발 예방에 도움이 됩니다. 치료 후에도 재발이 잦으면 산부인과 전문의와 상담하시기 바랍니다.', 2401, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '난산', '난산', 'DIET_LIFE', '난산 예방을 위해 임신 중 적절한 체중 증가(평균 11~16kg)를 유지하고, 균형 잡힌 식단으로 태아의 과도한 성장을 방지하는 것이 중요합니다. 규칙적인 유산소 운동(걷기, 수영 등)은 산모의 체력을 높이고 분만 진행에 도움이 됩니다. 당 섭취 과잉은 임신성 당뇨 및 거대아를 유발할 수 있으므로, 산부인과 전문의의 지도 하에 체계적인 산전 관리를 받으시기 바랍니다.', 2402, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '난산', '난산', 'PREVENTION', '태아 자세 이상(둔위, 횡위 등)으로 인한 난산을 예방하기 위해, 임신 말기(36주 이후)에 외회전술(ECV)을 시도하거나 슬흉위 자세(무릎과 가슴을 바닥에 대는 자세)를 시행해 볼 수 있습니다. 그러나 모든 경우에 효과적이지 않으며, 태아 상태에 따라 제왕절개가 필요할 수 있습니다. 태아 자세 이상이 확인된 경우 반드시 산부인과 전문의의 지도 하에 관리를 받으시기 바랍니다.', 2403, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '난산', '난산', 'CAUSE', '난산 발생에 영향을 미치는 생활 및 식생활 요인으로는 비만(과도한 체중 증가)으로 인한 거대아, 임신성 당뇨(과도한 당 섭취)로 인한 태아 과성장, 운동 부족으로 인한 골반저근 약화 등이 있습니다. 흡연이나 음주도 태아 발달에 영향을 미칩니다. 건강한 임신 유지를 위해 산부인과 전문의의 정기적인 산전 진찰과 생활 습관 지도를 받으시기 바랍니다.', 2404, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '난산', '난산', 'DEFINITION', '난산이란 분만 진행이 비정상적으로 지연되거나 어려운 상태로, 태아 크기·자세 이상, 산도 협착, 자궁 수축 이상 등이 원인입니다. 분만 시간이 오래 걸리거나 진행이 정체되면 산부인과 전문의(주산기 전문의)의 진료를 받아야 합니다. 진단을 위해 골반 측정, 태아 초음파, 분만 모니터링(NST, CTG) 등이 시행됩니다.', 2405, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '난산', '난산', 'TREATMENT', '태아의 크기 이상(거대아)이나 자세 이상(둔위, 횡위)으로 인한 난산의 치료로는 외회전술, 흡입 분만, 겸자 분만 또는 제왕절개 수술이 있습니다. 자궁 수축 이상이 동반된 경우 자궁 수축 촉진제(옥시토신)를 사용하기도 합니다. 분만 방법 선택은 산모와 태아의 상태에 따라 달라지므로 반드시 산부인과 전문의의 판단에 따라 시행하시기 바랍니다.', 2406, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '난소, 난관 이상', '난소,난관이상', 'CAUSE', '난소 및 난관 이상은 유전적 원인에 의해 발생할 수 있으며, 터너 증후군(45,X)과 같은 염색체 이상은 난소 발육 부전을 일으킵니다. BRCA1/2 유전자 변이 보유자는 난소암 발생 위험이 높아집니다. 가족력이 있거나 유전적 원인이 의심되는 경우, 산부인과 전문의 및 유전 상담 전문가와 상담하여 적절한 검사와 관리를 받으시기 바랍니다.', 2407, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '난소, 난관 이상', '난소,난관이상', 'DEFINITION', '난소와 난관의 이상은 배란 장애, 난관 폐쇄 또는 유착 등을 통해 난자의 이동과 수정을 방해하여 불임을 유발합니다. 난소 기능 저하는 호르몬 불균형, 무월경, 조기 폐경을 일으킬 수 있으며, 난관 폐쇄는 자연임신을 어렵게 합니다. 생식력 문제가 걱정된다면 산부인과 전문의(생식내분비 전문의)의 진료를 받아 정확한 평가와 치료 계획을 수립하시기 바랍니다.', 2408, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '난소, 난관 이상', '난소,난관이상', 'SYMPTOM', '난소 및 난관 이상에서는 불규칙한 월경, 부정 출혈 외에도 골반 통증, 성교 통증, 분비물 변화, 임신이 잘 되지 않는 불임 증상이 나타날 수 있습니다. 난소 낭종이 있는 경우 복부 팽만감이나 압박감이 동반될 수 있습니다. 이러한 증상이 있을 경우 산부인과 전문의를 방문하여 초음파 및 호르몬 검사 등 정밀 검사를 받으시기 바랍니다.', 2409, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '난소, 난관 이상', '난소,난관이상', 'DIAGNOSIS', '난소 및 난관 이상 진단을 위해 산부인과에서 골반 초음파(난소 크기, 낭종, 난관 확장 여부 확인), 혈액 검사(호르몬 수치, CA-125 등 종양 표지자), 자궁난관조영술(HSG)로 난관 개통성을 평가합니다. 필요 시 복강경 검사로 직접 확인할 수도 있습니다. 질 출혈과 관련 증상이 있으면 즉시 산부인과 전문의의 진료를 받으시기 바랍니다.', 2410, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '난소, 난관 이상', '난소,난관이상', 'TREATMENT', '난소 및 난관 이상으로 인한 생리 불규칙 치료로는 원인에 따라 호르몬 치료(경구 피임약, 프로게스틴)가 가장 널리 사용됩니다. 다낭성 난소 증후군이 원인인 경우 생활 습관 개선과 호르몬 치료를, 난관 폐쇄의 경우 수술적 치료나 체외 수정을 고려합니다. 치료 방법은 원인, 증상, 임신 계획에 따라 달라지므로 산부인과 전문의와 상담하시기 바랍니다.', 2411, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '난소난관염', '난소난관염', 'CAUSE', '난소난관염의 주요 원인은 임균, 클라미디아 등 성병균의 상행 감염이며, 산부인과 시술 후 발생하기도 합니다. 예방을 위해 성관계 시 콘돔 사용, 정기적인 성병 검진, 여러 파트너와의 성관계 자제가 중요합니다. 반복 감염 예방을 위해 성 파트너와 함께 치료를 받고, 산부인과 전문의의 지도 하에 생활 습관을 개선하시기 바랍니다.', 2412, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '난소난관염', '난소난관염', 'DEFINITION', '난소난관염은 난소와 난관에 세균 감염으로 인한 염증이 발생하는 질환으로, 골반 통증, 발열, 비정상적 분비물 등을 유발합니다. 치료받지 않으면 난관 유착이나 폐쇄로 이어져 불임, 자궁외임신, 만성 골반 통증 등 심각한 합병증이 발생할 수 있습니다. 관련 증상이 있으면 즉시 산부인과 전문의의 진료를 받아 조기 치료를 시작하시기 바랍니다.', 2413, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '난소난관염', '난소난관염', 'SYMPTOM', '난소난관염의 주요 증상은 지속적인 골반·하복부 통증, 발열(38도 이상), 오한, 비정상적인 질 분비물(악취), 성교 통증, 자궁경부 접촉 시 통증입니다. 골반 통증이 지속된다면 난소난관염 가능성이 있으므로 즉시 산부인과를 방문하여 정확한 진단과 항생제 치료를 받으시기 바랍니다.', 2414, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '난소난관염', '난소난관염', 'DIAGNOSIS', '난소난관염 진단은 골반 통증, 발열, 자궁경부 움직임 시 통증(chandelier sign) 등의 임상 증상을 바탕으로 하며, 자궁경부 분비물 검사(임균·클라미디아), 혈액 검사(CRP, WBC), 골반 초음파가 주로 사용됩니다. 필요 시 복강경 검사로 확진할 수 있습니다. 증상이 있으면 산부인과 전문의의 진료를 통해 정확한 진단을 받으시기 바랍니다.', 2415, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '난소난관염', '난소난관염', 'TREATMENT', '난소난관염의 1차 치료는 항생제 치료로, 경증은 경구 항생제 외래 치료, 중증이나 농양이 동반된 경우 입원하여 정맥 항생제를 투여합니다. 항생제에 반응하지 않거나 난관난소 농양이 있는 경우 수술적 배농이나 복강경 수술이 필요할 수 있습니다. 조기에 항생제 치료를 시작하는 것이 불임 예방에 중요하므로 산부인과 전문의의 진료를 받으시기 바랍니다.', 2416, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '다낭성 난소 증후군', '다낭성난소증후군', 'CAUSE', '다낭성 난소 증후군(PCOS)의 정확한 원인은 아직 완전히 밝혀지지 않았으나, 선천적으로는 유전적 소인(가족력)이, 후천적으로는 인슐린 저항성, 비만, 환경 호르몬 노출 등이 관련됩니다. 인슐린 저항성은 안드로겐 과다 분비를 유발하여 배란 장애로 이어집니다. 정확한 원인 평가와 치료를 위해 산부인과 전문의(생식내분비)의 진료를 받으시기 바랍니다.', 2417, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '다낭성 난소 증후군', '다낭성난소증후군', 'DEFINITION', '다낭성 난소 증후군(PCOS)은 생리 불규칙, 무월경, 부정 출혈, 여드름, 다모증, 비만 등 다양한 증상을 나타낼 수 있습니다. 생리 주기가 불규칙하고 부정 출혈이 있다면 산부인과를 방문하여 혈액 검사(LH, FSH, 안드로겐, 인슐린 수치), 골반 초음파 등을 받는 것이 적절합니다. 정확한 진단을 위해 산부인과 전문의의 진료를 받으시기 바랍니다.', 2418, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '다낭성 난소 증후군', '다낭성난소증후군', 'SYMPTOM', '다낭성 난소 증후군에서는 LH 과다로 인해 난포가 완전히 성숙하지 못하고 여러 개의 작은 미성숙 난포(직경 2~9mm)가 난소 주변에 구슬처럼 배열됩니다. 이러한 미성숙 난포들이 배란에 이르지 못하고 다낭성 변화를 형성합니다. PCOS의 증상과 치료에 대해 자세한 정보를 원하시면 산부인과 전문의의 진료를 받으시기 바랍니다.', 2419, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '다낭성 난소 증후군', '다낭성난소증후군', 'DIAGNOSIS', '다낭성 난소 증후군 진단을 위한 검사로는 골반 초음파(다낭성 난소 형태 확인), 혈액 호르몬 검사(LH, FSH, 테스토스테론, DHEA-S, 인슐린, 공복 혈당), 생리 주기 기록이 필요합니다. 진단 기준(로테르담 기준)에 따라 희소 배란, 고안드로겐혈증, 다낭성 난소 중 2가지 이상이 해당하면 진단됩니다. 골반 통증이 지속된다면 산부인과 전문의의 진료를 받으시기 바랍니다.', 2420, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '다낭성 난소 증후군', '다낭성난소증후군', 'TREATMENT', '다낭성 난소 증후군은 임신을 원하지 않더라도 자궁내막암, 제2형 당뇨병, 심혈관 질환 등의 장기 합병증 예방을 위해 치료가 필요합니다. 치료를 통해 생리 주기를 정상화하고 자궁내막 과증식을 예방할 수 있습니다. 개인 상태에 맞는 치료 계획을 위해 산부인과 전문의(생식내분비)와 상담하시기 바랍니다.', 2421, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '다태아', '다태아', 'CAUSE', '다태아(쌍둥이 이상) 발생은 자연적으로도 가족력 없이 나타날 수 있으며, 특히 이란성 쌍둥이는 가족력과 관련이 있으나 일란성 쌍둥이는 가족력과 상관없이 발생합니다. 최근에는 배란 유도제 사용이나 체외 수정 등 보조 생식술이 다태아 발생률을 높이는 주요 요인으로 알려져 있습니다. 다태아 임신이 확인되면 주산기 전문의(산부인과)의 집중적인 산전 관리가 필요합니다.', 2422, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '다태아', '다태아', 'DEFINITION', '다태아는 자궁 내에 둘 이상의 태아가 있는 상태로, 자연 발생 외에 배란 유도제, 체외 수정 등으로 발생 빈도가 증가했습니다. 다태아 임신은 조산, 저체중 출생, 임신성 고혈압, 임신성 당뇨 위험이 높아 집중 산전 관리가 필요합니다. 규칙적인 산부인과 검진과 고위험 산모 전문 의료기관 등록을 통해 산모와 태아의 건강을 모니터링하시기 바랍니다.', 2423, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '다태아', '다태아', 'SYMPTOM', '초음파에서 두 개 이상의 태아가 확인되고 각 태아의 심장 박동이 별도로 관찰되는 것은 다태아 임신의 확실한 진단 소견입니다. 심장 박동 수 변화는 태아 건강 상태를 평가하는 중요한 지표로, 비정상적인 심박동은 태아 곤란증의 신호일 수 있습니다. 다태아 임신이 확인되면 주산기 전문 산부인과에서 정기적으로 모니터링을 받으시기 바랍니다.', 2424, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '다태아', '다태아', 'DIAGNOSIS', '임신성 고혈압은 임신 20주 이후 수축기 혈압 140mmHg 이상 또는 이완기 혈압 90mmHg 이상이 나타날 때 의심하며, 두통, 시야 장애, 상복부 통증, 부종이 동반될 수 있습니다. 초음파 외에 혈압 측정, 소변 단백 검사, 혈액 검사(혈소판, 간기능 등)를 통해 평가합니다. 관련 증상이 있으면 즉시 산부인과 전문의의 진료를 받으시기 바랍니다.', 2425, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '다태아', '다태아', 'TREATMENT', '다태아 임신에서는 조산 방지를 위한 자궁경부 길이 모니터링, 조산 징후 시 입원 안정, 자궁 수축 억제제 투여가 필요할 수 있습니다. 태아 발육 상태를 정기 초음파로 확인하고, 합병증 발생 시 조기 분만을 결정하기도 합니다. 다태아 임신 관리는 주산기 전문 산부인과에서 받는 것이 중요하며, 고위험 산모로 등록하여 집중 관리를 받으시기 바랍니다.', 2426, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '무월경', '무월경', 'CAUSE', '무월경의 원인으로 선천적 원인(자궁 발육 부전, 터너 증후군 등 염색체 이상)과 후천적 원인(과도한 체중 감소, 운동 과다, 스트레스, 갑상선 질환, 다낭성 난소 증후군 등) 모두 중요하게 작용합니다. 자궁 발육 부전은 주로 선천적 원인에 해당하며, 후천적 요인에 비해 발생 빈도는 낮으나 근본적 치료가 어렵습니다. 정확한 원인 진단을 위해 산부인과 전문의의 진료를 받으시기 바랍니다.', 2427, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '무월경', '무월경', 'DEFINITION', '무월경은 만 14세까지 초경이 없거나(원발성), 정상 월경을 하던 여성이 3개월 이상 월경이 없는 상태(속발성)를 말합니다. 딸이 만 14~15세까지 초경이 없다면 원발성 무월경으로 평가가 필요합니다. 사춘기 발달(가슴, 음모 등)과 함께 초경이 늦어진 경우가 많으나, 이상이 의심되면 산부인과 또는 소아내분비과 전문의의 진료를 받으시기 바랍니다.', 2428, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '무월경', '무월경', 'SYMPTOM', '코로나19 감염 후 2개월간 월경이 없는 경우, 감염으로 인한 신체적 스트레스나 염증 반응이 시상하부-뇌하수체-난소 축에 영향을 주어 일시적인 월경 중단이 발생할 수 있습니다. 이는 감염 후 일시적 현상으로 회복 후 정상화되는 경우가 많으나, 3개월 이상 지속되면 속발성 무월경으로 평가가 필요합니다. 증상이 지속되면 산부인과 전문의의 진료를 받으시기 바랍니다.', 2429, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '무월경', '무월경', 'DIAGNOSIS', '자녀의 무월경이 걱정될 경우 산부인과 또는 소아·청소년 내분비내과 전문의를 방문하시기 바랍니다. 정확한 진단을 위해 성장 발달 평가, 혈액 호르몬 검사(FSH, LH, 에스트라디올, 갑상선 호르몬 등), 골반 초음파 또는 MRI 검사를 시행합니다. 만 15세가 되도록 초경이 없으면 검사를 권장하며, 이상 징후가 있다면 더 일찍 방문하시기 바랍니다.', 2430, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '무월경', '무월경', 'TREATMENT', '무월경의 원인은 호르몬 이상, 구조적 이상, 만성 질환, 심리적 요인 등 매우 다양하여 원인에 맞는 치료가 필요합니다. 의사와의 상담을 통해 정확한 원인을 파악해야 불필요한 치료를 피하고 적절한 방법(호르몬 치료, 생활 습관 개선, 수술 등)을 선택할 수 있습니다. 무증상이더라도 치료받지 않으면 골다공증, 불임 등 합병증이 발생할 수 있으므로 전문의 상담이 필수적입니다.', 2431, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '배란통', '배란통', 'CAUSE', '배란통의 원인으로 배란 시 난포 파열과 함께 소량의 혈액 및 액체가 복강 내로 방출되어 복막을 자극하는 것이 주된 기전입니다. 호르몬 불균형(에스트로겐 과다)은 난포 성장을 과도하게 자극하여 배란 시 더 강한 통증을 유발할 수 있으며, 난소 낭종이 있으면 배란통이 심해질 수 있습니다. 통증이 심하거나 반복된다면 산부인과 전문의의 진료를 받으시기 바랍니다.', 2432, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '배란통', '배란통', 'DEFINITION', '배란통은 월경 주기 중간(배란기, 약 14일경)에 난포 파열로 인해 발생하는 하복부 또는 골반 통증으로, 수 분에서 수 시간, 드물게 1~2일까지 지속됩니다. 주로 한쪽 하복부에서 발생하며, 월경 주기마다 번갈아 가며 위치가 바뀌기도 합니다. 관련 증상이 심하거나 비정상적인 출혈이 동반된다면 산부인과 전문의의 진료를 받으시기 바랍니다.', 2433, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '배란통', '배란통', 'SYMPTOM', '배란통은 한쪽 하복부 통증 외에 소량의 갈색 분비물(착상혈과 구별 필요), 가벼운 복부 팽만감, 유방 압통이 동반될 수 있습니다. 생리 후 약 2주 뒤 복통이 나타나는 것은 배란통의 전형적인 시기와 일치합니다. 복통이 심하거나 지속된다면 다른 원인(난소 낭종, 자궁외임신 등)과 감별을 위해 산부인과 전문의의 진료를 받으시기 바랍니다.', 2434, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '배란통', '배란통', 'DIAGNOSIS', '배란통(중간통)은 생리통과 달리 월경 주기 중간(배란기)에 발생하며, 생리통은 월경 직전이나 월경 중에 나타나는 것이 특징으로 발생 시기가 다릅니다. 배란통의 진단은 주로 증상 발생 시기와 월경 주기 기록을 통해 임상적으로 이루어지며, 배란 확인이 필요한 경우 초음파 검사를 시행합니다. 증상이 심하면 산부인과 전문의의 진료를 받으시기 바랍니다.', 2435, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '배란통', '배란통', 'TREATMENT', '배란통 완화를 위해 이부프로펜, 나프록센 등 비스테로이드성 소염 진통제(NSAIDs)를 배란 시기에 맞춰 복용하면 효과적입니다. 온열 찜질, 충분한 휴식도 도움이 되며, 경구 피임약은 배란을 억제하여 배란통을 근본적으로 예방합니다. 통증이 매우 심하거나 일상생활에 지장을 준다면 산부인과 전문의와 상담하여 적절한 치료 방법을 찾으시기 바랍니다.', 2436, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '분만 후 출혈', '분만후출혈', 'MEDICATION', '분만 후 출혈 치료에 사용되는 약물로는 자궁 수축 촉진제인 옥시토신(정맥 투여)이 1차 약물이며, 메틸에르고메트린, 카보프로스트(프로스타글란딘 F2α), 미소프로스톨 등이 사용됩니다. 수혈, 응고 인자 투여도 심한 출혈 시 필요합니다. 약물 선택과 용량은 출혈 원인과 중증도에 따라 달라지므로 반드시 산부인과 전문의의 판단 하에 치료가 이루어져야 합니다.', 2437, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '분만 후 출혈', '분만후출혈', 'PREVENTION', '자궁이완증으로 인한 분만 후 출혈 예방을 위해 분만 직후 옥시토신(자궁 수축 촉진제)을 예방적으로 투여하는 것이 표준 처치입니다. 메틸에르고메트린, 미소프로스톨도 자궁 수축 촉진에 사용됩니다. 자궁 마사지와 함께 약물 투여를 병행하면 예방 효과가 더 높아지므로, 분만 후 출혈 위험이 있는 경우 산부인과 전문의의 지도 하에 관리를 받으시기 바랍니다.', 2438, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '분만 후 출혈', '분만후출혈', 'CAUSE', '분만 후 출혈은 산후 24시간 내 500mL(제왕절개 시 1000mL) 이상의 출혈로, 자궁이완증, 태반 잔류, 자궁 열상, 응고 장애 등이 원인입니다. 빠른 출혈로 혈압 저하, 쇼크, 심한 경우 사망까지 이를 수 있어 위험합니다. 고위험 요인(다태아, 거대아, 장시간 분만, 전치태반 등)이 있는 경우 특히 위험하므로 산부인과 전문의의 면밀한 분만 관리가 필요합니다.', 2439, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '분만 후 출혈', '분만후출혈', 'DEFINITION', '임신 중 출혈은 착상 출혈, 유산, 자궁외임신, 전치태반, 태반 조기 박리 등 다양한 원인에 의해 발생할 수 있습니다. 초기 임신(~12주)에는 주로 유산이나 자궁외임신, 후기 임신(28주 이후)에는 전치태반이나 태반 조기 박리가 흔한 원인입니다. 임신 중 출혈이 발생하면 즉시 산부인과 전문의의 진료를 받아야 합니다.', 2440, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '분만 후 출혈', '분만후출혈', 'SYMPTOM', '분만 후 비정상적으로 출혈량이 많거나 지속되는 경우 분만 후 출혈(산후 출혈)의 가능성이 높습니다. 분만 후 정상 출혈(오로)은 점차 감소하는데, 출혈량이 증가하거나 밝은 빨간 혈액이 다량 지속되면 이상 신호입니다. 이러한 증상이 나타나면 즉시 산부인과 전문의의 진료를 받아야 하며, 지체 시 생명을 위협할 수 있습니다.', 2441, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '분만 후 출혈', '분만후출혈', 'DIAGNOSIS', '출산 예정인 산모의 산전 관리와 분만은 산부인과 전문의(주산기 전문의)가 담당합니다. 고위험 임신(다태아, 임신성 당뇨, 임신성 고혈압 등)의 경우 모체태아의학(주산기) 전문의가 있는 기관에서 관리를 받는 것이 중요합니다. 분만 예정일이 가까워지면 분만 계획에 대해 담당 산부인과 전문의와 충분한 상담을 받으시기 바랍니다.', 2442, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '분만 후 출혈', '분만후출혈', 'TREATMENT', '자궁 마사지는 자궁 수축을 촉진하여 자궁이완증으로 인한 분만 후 출혈을 줄이는 데 도움이 됩니다. 자궁이 단단하게 수축하도록 유도하여 출혈 부위의 혈관을 압박하는 효과가 있습니다. 다만 자궁 마사지만으로 출혈이 완전히 멈추지 않을 수 있으며, 약물 투여나 수술적 처치와 병행하는 것이 일반적이므로 산부인과 전문의의 판단에 따라 시행해야 합니다.', 2443, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '비정상적 자궁, 질 출혈', '비정상적자궁,질출혈', 'CAUSE', '비정상적 자궁·질 출혈의 원인은 자궁 내부(자궁내막 폴립, 자궁근종, 자궁내막 과증식, 자궁내막암), 자궁경부(자궁경부암, 용종), 난소(호르몬 분비 종양), 임신 관련 합병증, 혈액 응고 장애 등 다양합니다. 진단을 위해 산부인과에서 골반 검진, 자궁 초음파, 자궁경부 세포 검사, 자궁내막 생검, 혈액 검사 등을 시행합니다. 비정상 출혈이 있으면 즉시 산부인과 전문의의 진료를 받으시기 바랍니다.', 2444, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '비정상적 자궁, 질 출혈', '비정상적자궁,질출혈', 'DEFINITION', '비정상적 자궁·질 출혈이 의심될 경우 산부인과 전문의의 진료를 받아야 합니다. 산부인과에서는 골반 초음파, 자궁내막 조직검사, 호르몬 검사 등을 통해 출혈 원인을 정확히 파악합니다. 2주 이상 지속되는 출혈은 자궁근종, 자궁내막증, 호르몬 불균형 등 다양한 원인이 있을 수 있으므로 반드시 전문의 상담을 받으시기 바랍니다.', 2445, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '비정상적 자궁, 질 출혈', '비정상적자궁,질출혈', 'SYMPTOM', '생리 주기보다 과도한 양의 출혈(과다월경)은 비정상적 자궁출혈의 대표적인 유형 중 하나입니다. 이는 자궁근종, 자궁선근증, 자궁내막 폴립, 혈액응고 장애 등과 관련될 수 있습니다. 정확한 원인 파악을 위해 산부인과 전문의의 진찰과 검사를 받으시기 바랍니다.', 2446, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '비정상적 자궁, 질 출혈', '비정상적자궁,질출혈', 'DIAGNOSIS', '비정상적 자궁·질 출혈 진단에는 골반 초음파(경질 초음파 포함), 자궁경부 세포검사(팝스미어), 자궁내막 조직검사, 혈액검사(호르몬 수치·빈혈·혈액응고 검사), 자궁경 검사, 자기공명영상(MRI) 등이 활용됩니다. 출혈 원인과 양상에 따라 필요한 검사가 달라지므로 산부인과 전문의의 판단 하에 적절한 검사를 진행하는 것이 중요합니다.', 2447, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '비정상적 자궁, 질 출혈', '비정상적자궁,질출혈', 'TREATMENT', '비정상적 자궁·질 출혈과 관련된 증상은 산부인과 전문 클리닉이나 종합병원 산부인과에서 진료를 받아야 합니다. 증상의 중증도와 원인에 따라 1차 의원 산부인과에서도 초기 평가가 가능하며, 필요 시 상급 종합병원으로 의뢰될 수 있습니다. 복통이 심하거나 출혈량이 매우 많은 경우 응급실을 이용하시기 바랍니다.', 2448, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산욕열', '산욕열', 'DIET_LIFE', '산욕열 환자는 충분한 수분 섭취가 가장 중요하며, 체온 관리를 위해 시원하고 담백한 음식을 권장합니다. 단백질이 풍부한 음식(닭고기, 생선, 두부 등)은 면역력 회복에 도움이 되고, 비타민과 미네랄이 풍부한 채소와 과일도 권장됩니다. 그러나 산욕열은 세균 감염으로 인한 질환이므로 식이요법만으로는 치료가 불가능하며, 반드시 전문의 진료와 항생제 치료를 받아야 합니다.', 2449, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산욕열', '산욕열', 'MEDICATION', '분만 후 24시간 이후부터 10일 이내에 38도 이상의 발열이 이틀 이상 지속되면 산욕열을 의심해볼 수 있습니다. 산욕열은 주로 세균 감염이 원인이므로 자의적으로 해열제를 복용하기보다는 즉시 산부인과 전문의를 방문해야 합니다. 치료는 원인균에 따른 항생제를 전문의 처방으로 투여하는 것이 기본이며, 임의로 약물을 복용하는 것은 위험할 수 있습니다.', 2450, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산욕열', '산욕열', 'PREVENTION', '산욕열과 함께 나타날 수 있는 증상으로는 오한, 두통, 근육통, 하복부 통증, 자궁 압통, 악취를 동반한 오로(산후 분비물) 등이 있습니다. 또한 빈맥(빠른 맥박), 전신 쇠약감, 식욕 저하, 상처 부위의 발적·부종 등도 나타날 수 있습니다. 이러한 증상이 나타나면 즉시 산부인과 전문의의 진찰을 받아야 합니다.', 2451, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산욕열', '산욕열', 'CAUSE', '산욕열의 주요 원인은 분만 과정에서 발생한 자궁내막염, 회음부·질·자궁경부 열상의 감염, 요로감염 등 세균 감염입니다. 수유 문제 중 유방염이 발열을 일으킬 수 있으나, 이는 산욕열의 직접적 원인보다는 별도의 감염으로 분류됩니다. 유방이 울혈되거나 유두에 상처가 생기면 세균 침입으로 유방염이 발생할 수 있으므로 올바른 수유 자세와 유방 관리가 중요합니다.', 2452, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산욕열', '산욕열', 'DEFINITION', '산욕열은 분만 후 24시간 이후부터 산욕기(분만 후 약 6주) 중에 발생하는 38도 이상의 발열 상태로, 주로 세균 감염에 의한 산후 감염증을 의미합니다. 자궁내막염, 회음부 감염, 요로감염, 유방염 등이 대표적인 원인이며, 분만 후 첫 24시간 내 발열은 분만 피로나 탈수로 인한 경우가 많아 산욕열과 구분합니다. 발열이 지속되면 반드시 산부인과 전문의의 진료를 받아야 합니다.', 2453, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산욕열', '산욕열', 'SYMPTOM', '산욕열의 주요 증상은 38도 이상의 발열과 오한이며, 이와 함께 자궁 부위의 압통, 악취가 나는 오로, 하복부 통증이 나타납니다. 감염 부위에 따라 회음부 발적·부종, 배뇨 시 통증(요로감염 시), 유방 통증·발적(유방염 시) 등이 동반될 수 있습니다. 전신 증상으로 두통, 근육통, 피로감, 빠른 맥박도 흔히 나타나므로 이러한 증상이 있으면 즉시 전문의의 진찰을 받으시기 바랍니다.', 2454, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산욕열', '산욕열', 'DIAGNOSIS', '산욕열은 분만 후 24시간 이후 발생하고 자궁 압통, 악취 오로, 하복부 통증이 동반되는 것이 특징인 반면, 열감기는 인후통, 콧물, 기침 등 상기도 감염 증상이 주로 나타납니다. 혈액검사에서 산욕열은 백혈구 수치와 CRP가 크게 상승하며, 자궁 관련 증상이 두드러집니다. 분만 후 발열이 있을 때는 자의적으로 판단하지 말고 산부인과 전문의의 진찰을 통해 정확한 원인을 감별하는 것이 중요합니다.', 2455, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산욕열', '산욕열', 'TREATMENT', '산욕열의 가장 중요한 치료는 원인균에 맞는 항생제 투여이며, 초기에는 광범위 항생제를 정맥 투여하는 경우가 많습니다. 해열제 투여와 충분한 수분 보충으로 증상을 완화하고, 감염 부위에 따라 배농 처치나 자궁내 잔류물 제거 등의 추가 시술이 필요할 수 있습니다. 치료 반응이 없거나 패혈증으로 진행될 경우 집중치료가 필요하므로 반드시 전문의의 지시에 따라 치료받아야 합니다.', 2456, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산후 우울증', '산후우울증', 'CHECKUP', '산후 우울증 검진을 위해 산부인과 또는 정신건강의학과에서 에딘버러 산후 우울증 척도(EPDS) 등 표준화된 설문 검사를 실시합니다. 필요에 따라 갑상선 기능 검사 등 혈액검사로 신체적 원인을 배제하기도 합니다. 감정 기복이 심하고 2주 이상 지속된다면 산부인과 또는 정신건강의학과 전문의의 진료를 받으시기 바랍니다.', 2457, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산후 우울증', '산후우울증', 'DIET_LIFE', '산후 우울증으로 인한 체중 문제는 규칙적인 식사와 균형 잡힌 영양 섭취가 중요하며, 수면을 충분히 취하고 가벼운 산책 등 일상적인 신체 활동을 늘리는 것이 도움이 됩니다. 혼자 모든 것을 해결하려 하지 말고 가족이나 지인의 지원을 받고, 필요 시 전문 상담을 활용하는 것이 좋습니다. 산후 우울증 자체에 대한 치료가 선행되어야 하므로 정신건강의학과 또는 산부인과 전문의의 상담을 권고합니다.', 2458, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산후 우울증', '산후우울증', 'MEDICATION', '모유 수유 중인 산후 우울증 환자에게도 필요에 따라 약물 치료가 고려될 수 있으며, 일부 항우울제는 모유 수유 중에도 비교적 안전하게 사용될 수 있습니다. 그러나 약물의 선택과 용량은 반드시 정신건강의학과 또는 산부인과 전문의와 상담 후 결정해야 합니다. 약물 치료 외에도 심리 상담, 인지행동치료 등 비약물 치료를 병행하는 것도 효과적입니다.', 2459, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산후 우울증', '산후우울증', 'PREVENTION', '출산 전부터 산후 우울증에 대한 정보를 부부가 함께 공유하고, 출산 후 육아와 가사를 분담할 계획을 미리 세우는 것이 중요합니다. 산모가 충분한 휴식을 취할 수 있도록 주변의 지지 체계를 구축하고, 산모의 감정 변화에 공감하며 경청하는 것이 예방에 큰 도움이 됩니다. 위험 요인(이전 우울증 병력, 사회적 고립 등)이 있는 경우 산부인과 전문의와 미리 상담하는 것을 권장합니다.', 2460, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산후 우울증', '산후우울증', 'EXERCISE', '출산 후 운동은 자연분만의 경우 통증이 없고 의사가 허가한 시점인 산후 4~6주 이후부터 가벼운 걷기로 시작하는 것이 일반적이며, 제왕절개의 경우 8주 이후부터 단계적으로 시작합니다. 케겔 운동은 분만 직후부터 가능하며, 골반저근 회복에 도움이 됩니다. 운동 강도와 시작 시기는 개인의 회복 상태에 따라 다르므로 산부인과 전문의와 상담 후 결정하시기 바랍니다.', 2461, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산후 우울증', '산후우울증', 'CAUSE', '산후 우울증의 원인은 출산 후 에스트로겐과 프로게스테론의 급격한 감소 등 호르몬 변화가 주요 생물학적 원인이며, 수면 부족, 육아 스트레스, 신체 변화에 대한 적응 어려움도 중요한 요인입니다. 사회적 지지 부족, 부부 갈등, 경제적 어려움 등 심리사회적 요인도 발병에 영향을 미칩니다. 이전에 우울증 병력이 있거나 가족력이 있는 경우 위험도가 더 높습니다.', 2462, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산후 우울증', '산후우울증', 'DEFINITION', '산후 우울증은 출산 후 2주 이상 지속되는 우울한 기분, 무기력감, 아기에 대한 감정 변화 등을 특징으로 하는 정신건강 질환입니다. 24시간 아기와 함께하는 상황에서 수면 부족, 육아 부담, 사회적 고립 등이 복합적으로 작용하여 발생할 수 있습니다. 단순한 ''산후 우울감(baby blues)''과 달리 산후 우울증은 수주 이상 지속되며 일상 기능을 저해하므로 정신건강의학과 또는 산부인과 전문의의 진료가 필요합니다.', 2463, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산후 우울증', '산후우울증', 'SYMPTOM', '산후 우울증의 증상으로 아기에게 감정적 유대감이 느껴지지 않거나 아기가 예쁘다는 느낌이 들지 않는 경우가 실제로 나타날 수 있습니다. 이는 산모에게 죄책감을 유발할 수 있지만, 이는 의지의 문제가 아닌 질병으로 인한 증상입니다. 이러한 증상이 지속된다면 정신건강의학과 전문의의 진료와 적절한 치료를 통해 개선될 수 있으므로 조기에 상담받으시길 권고합니다.', 2464, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산후 우울증', '산후우울증', 'DIAGNOSIS', '산후 우울증 진단을 위해 에딘버러 산후 우울증 척도(EPDS)와 같은 표준화된 심리 검사와 임상 면담이 주로 사용됩니다. 갑상선 기능 저하증 등 신체 질환으로 인한 우울 증상을 배제하기 위해 혈액검사를 시행하기도 합니다. 출산 후 2주 이상 우울감과 무기력감이 지속된다면 정신건강의학과 또는 산부인과 전문의의 진료를 받으시기 바랍니다.', 2465, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '산후 우울증', '산후우울증', 'TREATMENT', '산후 우울증의 치료는 경증의 경우 심리 상담과 인지행동치료가 1차적으로 권장되며, 중등도 이상의 경우 항우울제 약물 치료를 병행합니다. 사회적 지지 강화, 수면 개선, 규칙적인 신체 활동도 중요한 치료 요소입니다. 치료 방법은 증상의 중증도와 수유 여부 등을 고려하여 정신건강의학과 전문의와 상담 후 결정하는 것이 가장 적절합니다.', 2466, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '생식선 및 생식 세포의 신생물', '생식선및생식세포의신생물', 'CAUSE', '생식선 및 생식세포의 신생물(종양)의 정확한 원인은 아직 완전히 규명되지 않았으나, 유전적 이상(특히 염색체 이상), 발달 과정의 이상, 특정 유전자 돌연변이 등이 관여하는 것으로 알려져 있습니다. 일부 경우에는 성선 분화 이상과 관련된 유전질환(예: 클라인펠터 증후군, 터너 증후군)이 위험 요인이 될 수 있습니다. 정확한 원인과 치료 방향은 종양전문의 및 산부인과·비뇨기과 전문의와 상담하시기 바랍니다.', 2467, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '생식선 및 생식 세포의 신생물', '생식선및생식세포의신생물', 'DEFINITION', '생식선 및 생식세포의 신생물은 난소, 고환 등 생식선이나 생식세포에서 발생하는 종양으로, 양성과 악성으로 분류됩니다. 악성 종양의 경우 림프관이나 혈관을 통해 복막, 림프절, 폐, 간 등 인근 및 원격 장기로 전이될 수 있습니다. 조기 발견과 치료가 예후에 중요하므로 이상 증상이 있으면 산부인과 또는 비뇨기과 전문의의 진료를 받으시기 바랍니다.', 2468, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '생식선 및 생식 세포의 신생물', '생식선및생식세포의신생물', 'SYMPTOM', '생식선 및 생식세포 신생물의 주요 증상은 복부 또는 골반 통증, 복부 종괴 촉지, 복부 팽만, 비정상적 출혈 등입니다. 심한 두통이나 구역감은 이 질환의 일반적인 직접 증상으로 포함되지 않으나, 종양이 복강 내에 크게 자라거나 전이된 경우 간접적으로 다양한 증상이 나타날 수 있습니다. 두통과 구토가 지속된다면 신경과적 원인도 함께 감별하기 위해 전문의의 진료를 받으시기 바랍니다.', 2469, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '생식선 및 생식 세포의 신생물', '생식선및생식세포의신생물', 'DIAGNOSIS', '생식선 및 생식세포 신생물의 진단에 있어 폐렴이나 감기와 같은 호흡기 질환은 직접적인 관련이 없습니다. 다만 악성 종양이 폐로 전이된 경우 기침, 흉통, 호흡 곤란 등의 호흡기 증상이 나타날 수 있으며, 이는 감기와 감별이 필요합니다. 생식선 종양이 의심될 경우 영상 검사, 종양표지자 검사 등을 통해 전이 여부를 포함한 정확한 진단을 위해 전문의의 진료를 받으시기 바랍니다.', 2470, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '생식선 및 생식 세포의 신생물', '생식선및생식세포의신생물', 'TREATMENT', '생식선 및 생식세포 신생물의 치료 전 종양의 위치, 크기, 전이 여부를 파악하기 위해 초음파, CT, MRI 등 영상 검사와 혈액 종양표지자 검사(AFP, β-hCG 등)를 시행합니다. 이후 조직검사(생검)를 통해 종양의 종류와 악성도를 확인하고, 이를 바탕으로 수술, 항암화학요법, 방사선 치료 등의 치료 계획을 수립합니다. 치료 방향은 산부인과 또는 비뇨기과, 종양내과 전문의의 다학제 협진을 통해 결정됩니다.', 2471, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '습관성 유산', '습관성유산', 'DIET_LIFE', '습관성 유산 예방을 위해 엽산(하루 400~800mcg)을 충분히 섭취하고, 균형 잡힌 식단으로 적정 체중을 유지하는 것이 중요합니다. 알코올, 카페인 과다 섭취, 흡연은 유산 위험을 높이므로 반드시 피해야 하며, 생선 중 수은 함량이 높은 종류(참치, 황새치 등)도 제한하는 것이 권장됩니다. 식습관 외에도 정확한 원인 파악을 위해 산부인과 전문의의 진료와 검사를 받으시기 바랍니다.', 2472, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '습관성 유산', '습관성유산', 'CAUSE', '부모의 염색체 이상은 습관성 유산의 중요한 유전적 원인 중 하나로, 부부 중 한 명이 균형전좌 등의 염색체 구조 이상을 가질 경우 태아에게 불균형한 염색체가 전달되어 유산이 반복될 수 있습니다. 이 경우 태아 자체의 염색체 이상이 발생하여 정상적인 발달이 이루어지지 않아 자연유산으로 이어집니다. 유전적 원인이 의심될 경우 부부 염색체 검사와 유전상담을 통해 차후 임신 계획을 세우는 것이 중요합니다.', 2473, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '습관성 유산', '습관성유산', 'DEFINITION', '임신 20주 이전에 연속 3회 이상 자연유산이 발생한 경우 습관성 유산으로 진단합니다. 최근에는 2회 이상의 반복 유산도 정밀 검사의 적응증으로 보는 경향이 있습니다. 습관성 유산으로 의심되면 원인 규명을 위해 부부 염색체 검사, 자궁 구조 검사, 혈액응고 이상 검사, 내분비 검사 등을 포함한 산부인과 전문의의 종합적인 평가가 필요합니다.', 2474, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '습관성 유산', '습관성유산', 'SYMPTOM', '습관성 유산의 주요 증상은 반복적인 자연유산 자체이며, 개별 유산 시에는 질 출혈, 하복부 경련 통증, 조직 배출 등이 나타납니다. 임신 테스트와 초음파 결과가 상이한 경우는 생화학적 임신(착상 후 초기 소실)이나 계류유산 가능성이 있으며, 이 역시 습관성 유산의 진단 범주에 포함될 수 있습니다. 정확한 진단 기준 적용과 원인 파악을 위해 반드시 산부인과 전문의의 진료를 받으시기 바랍니다.', 2475, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '습관성 유산', '습관성유산', 'DIAGNOSIS', '습관성 유산 진단을 위해 부부 염색체 검사 외에도 자궁 구조 이상을 확인하는 자궁난관조영술·자궁경 검사·초음파, 항인지질항체 증후군 등 혈액응고 이상을 파악하는 혈액검사, 갑상선 기능·당뇨·프로락틴 등 내분비 검사가 시행됩니다. 각 검사는 유산의 원인(해부학적, 면역학적, 유전적, 내분비적 요인)을 감별하여 원인에 맞는 치료 방향을 결정하기 위해 사용됩니다. 전반적인 검사 계획은 산부인과 전문의와 상담 후 수립하시기 바랍니다.', 2476, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '습관성 유산', '습관성유산', 'TREATMENT', '습관성 유산의 치료는 원인에 따라 다르며, 자궁 구조 이상은 수술적 교정, 항인지질항체 증후군은 저용량 아스피린과 헤파린 병용, 갑상선 기능 이상은 호르몬 조절, 황체기 결함은 프로게스테론 보충 등이 사용됩니다. 원인 불명의 경우에도 적절한 산전 관리와 정서적 지지가 다음 임신 성공률을 높이는 데 도움이 됩니다. 치료 방법은 개별 원인에 따라 달라지므로 산부인과 전문의의 정확한 진단과 처방이 필요합니다.', 2477, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '양수색전증', '양수색전증', 'MEDICATION', '양수색전증은 생명을 위협하는 응급 상황으로, 치료는 증상이 안정될 때까지 집중치료실(ICU)에서 지속적으로 이루어집니다. 혈압 유지를 위한 승압제, 호흡 보조를 위한 기계 환기, 혈액응고 이상 교정을 위한 혈액제제 투여 등이 병행되며, 치료 기간은 환자의 상태에 따라 수일에서 수주까지 다양합니다. 양수색전증 치료는 산부인과·중환자의학과·마취과 등 다학제 전문 팀이 협력하여 진행합니다.', 2478, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '양수색전증', '양수색전증', 'CAUSE', '양수색전증은 분만 중 또는 분만 직후 양수 내 태아 물질이 산모의 혈액 순환으로 유입되어 발생하는 응급 질환입니다. 스트레스나 과도한 운동이 양수색전증의 직접적인 원인이라는 의학적 근거는 없으며, 정확한 발생 기전은 아직 완전히 밝혀지지 않았습니다. 현재는 면역·염증 반응이 복합적으로 관여하는 것으로 추정되며, 예측과 예방이 어려운 질환입니다.', 2479, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '양수색전증', '양수색전증', 'DEFINITION', '양수색전증은 분만 중 또는 분만 직후 양수와 태아 물질이 산모의 혈액으로 유입되어 심폐 허탈, 저혈압, 호흡 곤란, 혈액응고 장애 등을 일으키는 생명을 위협하는 응급 질환입니다. 호흡 곤란은 폐혈관의 수축과 폐부종으로 인해 발생하며, 갑작스러운 심정지로 이어질 수 있습니다. 의심 증상 발생 시 즉각적인 응급 처치와 중환자 치료가 필요합니다.', 2480, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '양수색전증', '양수색전증', 'SYMPTOM', '양수색전증으로 인한 저혈압, 호흡 곤란, 경련 등의 증상이 나타나면 즉시 응급 의료진을 호출하고 산모를 좌측 측위로 눕혀야 합니다. 의료진은 즉각적인 기도 확보, 산소 공급, 정맥로 확보, 수액 및 승압제 투여 등의 응급 소생술을 시행합니다. 이는 생명을 위협하는 응급 상황이므로 분만 중 이상 증상 발생 시 지체 없이 응급 처치를 받아야 합니다.', 2481, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '양수색전증', '양수색전증', 'DIAGNOSIS', '양수색전증의 진단은 주로 임상 증상과 징후를 바탕으로 이루어지며, 다른 원인을 배제하는 방식으로 진행됩니다. 심전도, 흉부 X선, 혈액 가스 분석, 혈액응고 검사(DIC 패널), 심장초음파 등이 보조적으로 활용됩니다. 확진을 위한 단일 검사는 없으나, 분만 중 갑작스러운 심폐 허탈과 출혈 증상이 있으면 임상적으로 진단하고 즉각 치료를 시작합니다.', 2482, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '양수색전증', '양수색전증', 'TREATMENT', '양수색전증은 생명을 위협하는 응급 상황으로 반드시 의사의 처방과 처치가 필요합니다. 치료로는 기도 확보 및 기계 환기, 승압제(예: 에피네프린, 노르에피네프린)를 이용한 혈압 유지, 혈액제제 투여를 통한 응고 장애 교정, 심폐소생술 등이 포함됩니다. 모든 처치는 산부인과·마취과·중환자의학과 전문의의 판단하에 즉각적으로 이루어져야 합니다.', 2483, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '여성 불임', '여성불임', 'CHECKUP', '여성 불임 검사와 함께 남성 불임 여부를 확인하기 위해서는 비뇨기과 또는 남성 불임 클리닉에서 정액 검사(정자 수, 운동성, 형태 검사)를 시행하는 것이 기본입니다. 정액 검사에서 이상이 발견되면 호르몬 검사, 유전자 검사, 정소 초음파 등 추가 검사가 진행될 수 있습니다. 불임의 원인은 부부 양측에 있을 수 있으므로 산부인과와 비뇨기과에서 동시에 평가받는 것을 권장합니다.', 2484, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '여성 불임', '여성불임', 'DIET_LIFE', '한의학적 관점에서 여성 불임 치료에는 침 치료, 한약 처방, 뜸 등이 활용될 수 있으며, 신체의 기혈 순환 개선과 자궁 환경 조성에 도움이 될 수 있다고 알려져 있습니다. 식이 측면에서는 균형 잡힌 영양 섭취, 적정 체중 유지, 카페인·알코올 제한이 권장되며, 규칙적인 생활 습관과 스트레스 관리도 생식 건강에 도움이 됩니다. 한의학적 치료는 현대 의학적 검사로 원인을 파악한 후 보완적으로 활용하는 것이 바람직하며, 전문의와 상담하시기 바랍니다.', 2485, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '여성 불임', '여성불임', 'MEDICATION', '여성 불임의 치료는 원인에 따라 달라지며, 약물 치료만으로 해결되는 경우(배란 유도 등)도 있지만 수술적 치료(난관 복원, 자궁근종 제거 등)나 보조생식술(체외수정, 인공수정 등)이 필요한 경우도 많습니다. 원인에 따라 약물, 수술, 보조생식술을 단계적으로 또는 병행하여 사용하는 것이 일반적입니다. 치료 방법은 원인, 나이, 불임 기간 등을 고려하여 산부인과 전문의와 충분히 상담 후 결정하시기 바랍니다.', 2486, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '여성 불임', '여성불임', 'PREVENTION', '여성 불임 예방을 위해 흡연과 과도한 알코올 섭취를 피하고, 균형 잡힌 식단과 규칙적인 운동으로 적정 체중을 유지하는 것이 중요합니다. 성 매개 감염병(클라미디아, 임질 등)은 난관 손상의 원인이 되므로 안전한 성생활을 실천하고 정기적인 산부인과 검진을 받는 것이 권장됩니다. 환경 호르몬(내분비 교란 물질)에 노출을 줄이고, 극심한 스트레스와 과도한 다이어트도 생식 건강에 부정적 영향을 줄 수 있어 주의가 필요합니다.', 2487, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '여성 불임', '여성불임', 'CAUSE', '5년간 피임 없이 정상적인 부부 생활을 했음에도 임신이 되지 않고 남성 요인이 배제된 경우, 여성 불임 가능성이 높습니다. 여성 불임의 원인으로는 배란 장애(다낭성난소증후군 등), 난관 폐색, 자궁 이상, 자궁내막증, 나이로 인한 난소 기능 저하 등이 있습니다. 원인 불명 불임도 존재하므로 산부인과에서 체계적인 불임 검사를 통해 정확한 원인을 규명하는 것이 중요합니다.', 2488, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '여성 불임', '여성불임', 'DEFINITION', '여성 불임은 1년 이상(35세 이상은 6개월 이상) 정상적인 부부 생활에도 임신이 되지 않는 상태를 말하며, 배란 장애, 난관 이상, 자궁 이상, 자궁경부 요인 등 다양한 원인이 있습니다. 환경 오염 물질과 내분비 교란 물질은 호르몬 균형을 방해하여 배란 이상이나 착상 장애를 일으킬 수 있으며, 가공식품 속 첨가물도 생식 기능에 영향을 미칠 수 있다는 연구가 있습니다. 정확한 진단과 원인 파악을 위해 산부인과 전문의의 진료를 받으시기 바랍니다.', 2489, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '여성 불임', '여성불임', 'DIAGNOSIS', '난소 및 난관 이상으로 인한 여성 불임이 의심되면 산부인과에서 경질 초음파, 자궁난관조영술(HSG), 복강경 검사 등을 통해 정확한 진단을 받을 수 있습니다. 혈액검사를 통한 호르몬 수치(FSH, LH, AMH, 에스트로겐 등) 확인도 난소 기능 평가에 중요합니다. 검사 결과에 따라 원인에 맞는 치료 계획을 세울 수 있으므로 산부인과 전문의와 충분히 상담하시기 바랍니다.', 2490, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '여성 불임', '여성불임', 'TREATMENT', '염색체 이상이 원인인 경우 근본적인 교정은 어려우나, 착상 전 유전자 검사(PGT)를 통해 건강한 배아를 선별하는 체외수정 시술이 시도될 수 있습니다. 다낭성난소증후군(PCOS)으로 인한 불임은 배란 유도 약물(클로미펜, 레트로졸 등), 생활습관 개선, 필요 시 복강경 수술 등으로 치료합니다. 원인별 치료 방법이 다르므로 산부인과 전문의의 정확한 진단과 개인 맞춤형 치료 계획 수립이 필요합니다.', 2491, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '외음부암', '외음부암', 'DIET_LIFE', '외음부암 수술 후 체력 회복을 위해 단백질(닭고기, 생선, 콩류, 달걀)과 비타민·미네랄이 풍부한 채소·과일을 충분히 섭취하는 것이 중요합니다. 상처 회복과 면역력 강화를 위해 비타민 C와 아연이 풍부한 음식을 권장하며, 충분한 수분 섭취와 가벼운 산책 등의 활동이 체력 회복에 도움이 됩니다. 자극적인 음식, 알코올, 흡연은 회복을 방해할 수 있으므로 피해야 하며, 구체적인 식이 계획은 담당 전문의 또는 영양사와 상담하시기 바랍니다.', 2492, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '외음부암', '외음부암', 'PREVENTION', '외음부암 예방을 위해 특별히 금해야 할 특정 음식이 명확히 입증된 것은 없으나, 일반적인 암 예방을 위해 가공육, 과도한 붉은 고기, 고지방·고칼로리 식품, 알코올 섭취를 줄이는 것이 권장됩니다. 항산화 성분이 풍부한 채소·과일의 충분한 섭취와 건강한 체중 유지가 도움이 됩니다. 외음부암은 HPV 감염과 관련이 있으므로 HPV 백신 접종과 정기적인 산부인과 검진이 예방에 중요합니다.', 2493, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '외음부암', '외음부암', 'CAUSE', '외음부암의 원인 연구는 인유두종바이러스(HPV) 감염, 외음부 상피내 이형성증(VIN), 만성 외음부 질환(편평태선, 경화태선)과의 관련성에 초점이 맞춰져 있습니다. 면역 기능, 유전적 요인, 흡연과 외음부암의 연관성을 규명하는 연구도 진행 중이며, HPV 백신의 외음부암 예방 효과에 대한 연구도 활발합니다. 치료 측면에서는 최소 침습 수술, 방사선·항암 병용 치료의 최적화에 대한 연구도 지속되고 있습니다.', 2494, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '외음부암', '외음부암', 'DEFINITION', '외음부암은 외음부(대음순, 소음순, 음핵, 회음부 등)의 피부와 점막에서 발생하며, 편평상피세포암이 가장 흔한 형태입니다. 암세포는 초기에는 국소적으로 진행하다가 이후 림프관을 통해 서혜부 림프절로, 더 진행되면 골반 내 림프절과 원격 장기(폐, 간, 뼈 등)로 전이될 수 있습니다. 조기 발견 시 예후가 좋으므로 외음부에 지속적인 가려움, 덩어리, 궤양이 있으면 즉시 산부인과 전문의의 진료를 받으시기 바랍니다.', 2495, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '외음부암', '외음부암', 'SYMPTOM', '대음순이나 소음순, 음핵 등 외음부에 딱딱한 결절이 만져지는 경우 외음부암뿐만 아니라 외음부 낭종(바르톨린샘 낭종 등), 섬유종, 지방종, 피부섬유종 등 양성 종양도 가능성이 있습니다. 지속적인 가려움증, 피부 색 변화, 궤양이 동반된다면 외음부 상피내 이형성증이나 암을 감별해야 합니다. 정확한 진단을 위해 산부인과 전문의의 진찰과 필요 시 조직검사를 받으시기 바랍니다.', 2496, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '외음부암', '외음부암', 'DIAGNOSIS', '외음부암에서 혹(종괴)은 정상 세포가 비정상적으로 증식하면서 발생하며, 종양이 궤양화되면 출혈이 나타날 수 있습니다. 암조직의 괴사와 이차 감염이 동반되면 분비물이 증가하고 악취가 날 수 있습니다. 이러한 증상은 외음부암의 진행을 의미할 수 있으므로 조기에 산부인과 전문의의 진찰과 조직검사를 통한 확진이 필요합니다.', 2497, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '외음부암', '외음부암', 'TREATMENT', '외음부암의 항암 치료(화학요법)는 주로 방사선 치료와 병행하여 수술 전 종양 크기를 줄이거나 수술 후 재발 방지를 위해 사용됩니다. 주요 부작용으로는 골수 억제(빈혈, 백혈구·혈소판 감소), 오심·구토, 탈모, 구내염, 피로감 등이 있으며, 개인에 따라 정도가 다릅니다. 항암 치료의 적응증, 효과, 부작용 관리에 대해서는 부인종양과 또는 종양내과 전문의와 충분히 상담하시기 바랍니다.', 2498, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '월경전 증후군', '월경전증후군', 'CHECKUP', '월경전 증후군(PMS) 여부를 확인하기 위해서는 산부인과 또는 정신건강의학과에서 증상 일지를 바탕으로 한 임상 평가가 이루어집니다. 기본 혈액 검사(갑상선 기능, 호르몬 수치 등)를 통해 유사 증상을 보이는 다른 질환을 배제합니다. 2~3회의 생리 주기 동안 증상 발생 시기와 양상을 기록한 증상 일지가 진단에 매우 중요하므로 미리 작성하여 진료 시 지참하시기 바랍니다.', 2499, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '월경전 증후군', '월경전증후군', 'DIET_LIFE', '월경전 증후군 완화를 위해 카페인 외에도 소금(나트륨) 섭취를 줄여 부종을 예방하고, 단순당과 정제 탄수화물보다 복합 탄수화물(통곡물, 채소)을 섭취하는 것이 권장됩니다. 칼슘(유제품, 녹색 채소)과 마그네슘(견과류, 콩류)이 풍부한 음식은 월경전 증후군 증상 완화에 도움이 된다는 연구가 있습니다. 규칙적인 식사와 함께 충분한 수면, 규칙적인 유산소 운동도 증상 개선에 효과적입니다.', 2500, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '월경전 증후군', '월경전증후군', 'MEDICATION', '단 음식에 대한 갈망은 월경전 증후군의 흔한 증상 중 하나로, 생리 주기와 관련된 세로토닌 변화와 관련이 있습니다. 약물 치료(SSRI 계열 항우울제, 피임약 등)는 월경전 증후군 증상을 상당히 개선할 수 있으나, 개인에 따라 효과의 정도가 다르며 완전한 소실이 아닌 완화 수준인 경우도 있습니다. 적합한 약물과 치료 계획은 산부인과 또는 정신건강의학과 전문의와 상담 후 결정하시기 바랍니다.', 2501, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '월경전 증후군', '월경전증후군', 'CAUSE', '월경전 증후군에 유전적 요인이 관여한다는 연구 결과가 있으며, 일란성 쌍둥이 연구에서 이란성 쌍둥이보다 증상 일치율이 높아 유전적 소인이 있음이 시사됩니다. 유전적 요인은 세로토닌 수용체나 신경전달물질 관련 유전자 변이와 관련될 수 있으나, 아직 특정 유전자가 명확히 규명된 것은 아닙니다. 유전적 요인 외에도 호르몬 변화에 대한 신체 민감도, 생활 습관, 스트레스 등이 복합적으로 작용합니다.', 2502, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '월경전 증후군', '월경전증후군', 'DEFINITION', '월경전 증후군(PMS)은 생리 시작 1~2주 전(황체기)에 규칙적으로 나타나는 신체적·정서적·행동적 증상의 복합체로, 생리가 시작되면 증상이 사라지는 것이 특징입니다. 정서적 증상으로는 불안, 예민함, 기분 변화, 우울감이 있고, 신체적 증상으로는 유방 통증, 복부 팽만, 두통, 부종 등이 나타납니다. 증상이 일상생활을 방해할 정도로 심하면 산부인과 또는 정신건강의학과 전문의의 진료를 받으시기 바랍니다.', 2503, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '월경전 증후군', '월경전증후군', 'SYMPTOM', '생리 전에 몸이 붓고 정서적으로 불안정한 증상은 월경전 증후군의 대표적인 증상으로, 황체기 호르몬 변화에 의해 나타납니다. 부종은 프로게스테론 영향으로 수분이 체내에 저류되어 발생하고, 정서적 불안정은 세로토닌 및 GABA 신경전달물질의 변화와 관련됩니다. 이러한 증상이 생리 주기와 규칙적으로 연관되어 나타난다면 월경전 증후군의 가능성이 높으며, 전문의 상담을 통해 확인하시기 바랍니다.', 2504, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '월경전 증후군', '월경전증후군', 'DIAGNOSIS', '월경전 증후군의 진단과 치료를 위해서는 산부인과를 1차로 방문하는 것이 가장 적절합니다. 정서적 증상이 심한 경우 정신건강의학과와의 협진이 이루어질 수 있으며, 종합병원이나 여성전문 클리닉에서 통합적인 치료를 받을 수도 있습니다. 증상 발생 시기와 양상을 미리 기록한 일지를 지참하면 진단에 도움이 됩니다.', 2505, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '월경전 증후군', '월경전증후군', 'TREATMENT', '월경전 증후군의 정서적 불안감과 우울 증상 치료를 위해 생활습관 개선(규칙적인 유산소 운동, 충분한 수면, 식이 조절)이 1차적으로 권장됩니다. 증상이 심한 경우 SSRI 계열 항우울제나 경구 피임약이 효과적으로 사용될 수 있으며, 인지행동치료 등 심리 치료도 도움이 됩니다. 적절한 치료 방법은 증상의 정도와 개인적 상황에 따라 달라지므로 산부인과 또는 정신건강의학과 전문의와 상담하시기 바랍니다.', 2506, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '유산', '유산', 'DIET_LIFE', '질문에서 언급된 무산소·유산소운동은 산과적 유산(流産)과는 다른 주제입니다. 유산소운동은 심폐 기능 향상, 체지방 감소, 지구력 증가에 효과적이며, 무산소운동(근력운동)과 병행할 때 근육 피로 회복과 전반적인 체력 향상에 도움이 됩니다. 두 운동을 균형 있게 병행하면 더 효과적인 건강 관리가 가능하며, 개인의 건강 상태에 맞는 운동 계획을 수립하는 것이 중요합니다.', 2507, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '유산', '유산', 'CAUSE', '임신 5개월(20주) 이후의 유산(태아 사망)은 전기 유산과 달리 태반 이상(전치태반, 태반 조기 박리), 자궁경관무력증, 감염(양막염 등), 임신성 고혈압, 태아 기형, 다태 임신, 외상 등이 주요 원인입니다. 이 시기에는 자궁경관이 약해지거나 자궁 수축이 조기에 발생하여 유산 또는 조산으로 이어질 수 있습니다. 임신 중 이상 증상(출혈, 복통, 양수 누출 등)이 있으면 즉시 산부인과 전문의의 진료를 받아야 합니다.', 2508, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '유산', '유산', 'DEFINITION', '유산을 예방하기 위해 임신 전부터 엽산을 충분히 섭취하고, 음주·흡연·카페인 과다 섭취를 피하는 것이 중요합니다. 임신 중에는 과격한 신체 활동, 복부에 충격을 주는 행동, 고온 환경(사우나 등)을 피해야 하며, 규칙적인 산전 진찰을 통해 태아 상태를 확인해야 합니다. 만성 질환(당뇨, 갑상선 질환, 루푸스 등)이 있는 경우 임신 전 충분한 치료와 조절이 필요하며, 산부인과 전문의와 상담 후 임신을 계획하는 것이 바람직합니다.', 2509, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '유산', '유산', 'SYMPTOM', '임신 중 질 출혈은 절박유산의 주요 증상으로, 소량의 점상 출혈에서 생리량 이상의 출혈까지 다양하게 나타날 수 있습니다. 출혈이 수일간 지속되거나 하복부 경련 통증이 동반되면 유산이 진행 중일 가능성이 있습니다. 임신 중 어떠한 출혈도 즉시 산부인과 전문의의 진료를 받아야 하며, 안정 및 적절한 처치가 중요합니다.', 2510, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '유산', '유산', 'DIAGNOSIS', '유산이 발생하면 산부인과에서 초음파 검사로 태아 상태와 자궁 내 잔류물 여부를 확인합니다. 불완전 유산의 경우 자궁 내 잔류물 제거를 위한 소파술(흡입 소파)이 필요할 수 있으며, Rh 음성 혈액형인 경우 Rh 면역글로불린 투여가 필요합니다. 반복 유산이나 원인 불명의 경우 염색체 검사, 자궁 구조 검사 등 추가 검사를 통해 원인을 파악하고 이후 임신을 계획하는 것이 중요합니다.', 2511, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '유산', '유산', 'TREATMENT', '자궁경관무력증으로 인한 반복 유산이나 조산을 예방하기 위해 자궁경부 원형결찰술(맥도날드 봉합술 또는 쉬로드카 수술)이 시행됩니다. 이 수술은 주로 임신 12~14주에 자궁경부를 실로 봉합하여 자궁 입구를 강화하는 방법으로, 임신 37주경 결찰을 제거합니다. 자궁경관무력증이 의심되거나 과거력이 있는 경우 산부인과 전문의와 미리 상담하여 임신 계획 단계부터 관리를 시작하는 것이 중요합니다.', 2512, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '이상 태위', '이상태위', 'CAUSE', '이상 태위(태아의 비정상적 위치)는 임신 후기까지 자연적으로 교정되는 경우가 많아 34~36주 이전에는 경과 관찰을 하는 것이 일반적입니다. 자궁 내 성장 지연과 이상 태위가 동반된 경우 태아의 상태를 면밀히 모니터링하면서 분만 시기와 방법을 결정해야 합니다. 수술 없이 관찰하는 이유는 자연 교정 가능성이 있고 조기 개입의 위험성이 이익보다 클 수 있기 때문이나, 최종 결정은 산부인과 전문의와 상담하여 내려야 합니다.', 2513, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '이상 태위', '이상태위', 'DEFINITION', '이상 태위는 태아의 머리가 아래를 향하지 않고 둔부, 횡위, 사위 등 비정상적인 자세를 취하는 상태입니다. 분만 시 이상 태위가 교정되지 않으면 난산, 탯줄 탈출, 태아 가사, 태반 조기 박리 등의 합병증이 발생할 수 있어 제왕절개가 필요한 경우가 많습니다. 임신 후기에 이상 태위가 확인되면 산부인과 전문의와 분만 계획을 충분히 상담하시기 바랍니다.', 2514, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '이상 태위', '이상태위', 'SYMPTOM', '이상 태위에서 태아의 머리가 복부 상부(배꼽 위쪽)에서 만져지는 것은 둔위(역아)를 시사합니다. 이 경우 태아의 엉덩이나 발이 자궁 하부에 위치하게 되어 자연분만 시 탯줄 압박, 태아 가사, 두부 후출 난산 등의 위험이 증가할 수 있습니다. 태아 건강에 직접적 영향을 주는 것은 아니나 분만 방법 결정에 중요한 요소가 되므로 산부인과 전문의와 상담하여 분만 계획을 세워야 합니다.', 2515, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '이상 태위', '이상태위', 'DIAGNOSIS', '이상 태위의 진단은 주로 산전 초음파 검사를 통해 태아의 위치와 자세를 확인하는 방법으로 이루어집니다. 혈액 검사는 이상 태위 자체를 진단하는 데 사용되지 않으며, 태아 DNA 검사는 유전 질환 선별에 활용됩니다. 복부 촉진(레오폴드 수기)과 경질 초음파를 통한 태아 위치 확인이 가장 정확하며, 임신 후기에 정기적인 산전 초음파를 통해 태아 위치를 확인하는 것이 중요합니다.', 2516, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '이상 태위', '이상태위', 'TREATMENT', '이상 태위 교정을 위한 가장 권장되는 방법은 임신 36~37주에 시행하는 외부 두위 회전술(ECV)로, 의사가 복벽 외부에서 손으로 태아를 두위로 유도하는 방법입니다. 성공률은 약 50~60%이며, 시술 전 태아 모니터링이 필수적입니다. 이상 태위가 교정되지 않거나 ECV가 금기인 경우 제왕절개가 권장되며, 모든 결정은 산부인과 전문의와 충분히 상담 후 내려야 합니다.', 2517, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '임신성 고혈압', '임신성고혈압', 'CHECKUP', '임신 20주 이후 임신성 고혈압이 의심되면 산부인과에서 혈압 측정(2회 이상), 소변 단백뇨 검사, 혈액검사(전혈구 검사, 간 기능, 신장 기능, 혈액응고 검사)를 시행합니다. 태아 상태 평가를 위해 태아 초음파와 비수축 검사(NST)도 함께 시행됩니다. 임신 중 갑작스러운 혈압 상승, 두통, 시야 장애, 상복부 통증, 부종이 있으면 즉시 산부인과 전문의의 진료를 받으시기 바랍니다.', 2518, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '임신성 고혈압', '임신성고혈압', 'MEDICATION', '임신 중 사용 가능한 혈압 강하제로는 라베타롤, 하이드랄라진, 니페디핀, 메틸도파 등이 있으며, 이 약물들은 태아 안전성이 비교적 확인된 것들입니다. ACE 억제제, ARB 계열 약물은 태아에게 해로울 수 있어 임신 중에는 금기입니다. 임신 중 고혈압 약물 치료는 반드시 산부인과 전문의의 처방에 따라 이루어져야 하며, 임의로 약물을 복용하거나 중단해서는 안 됩니다.', 2519, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '임신성 고혈압', '임신성고혈압', 'CAUSE', '임신성 고혈압은 임신 자체가 산모의 혈관과 신장에 부담을 주어 발생하며, 태반에서 분비되는 물질이 혈관 내피세포 기능을 변화시켜 혈압을 높이는 것으로 알려져 있습니다. 태반 기능 이상으로 혈관 수축을 촉진하는 물질이 과다 분비되거나, 산모의 면역 반응이 태반 혈관 발달을 방해할 경우 혈압이 상승합니다. 초산부, 다태 임신, 비만, 당뇨, 가족력 등이 위험 요인이 될 수 있습니다.', 2520, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '임신성 고혈압', '임신성고혈압', 'DEFINITION', '임신성 고혈압은 임신 20주 이후 수축기 혈압 140mmHg 이상 또는 이완기 혈압 90mmHg 이상이 지속되는 상태를 말합니다. 치료 약물로는 라베타롤(경구·정맥), 니페디핀, 하이드랄라진, 메틸도파 등이 주로 사용되며, 중증 고혈압(160/110 이상)의 경우 즉각적인 약물 치료가 필요합니다. 약물 선택과 치료 계획은 산부인과 전문의의 판단에 따라 결정되어야 합니다.', 2521, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '임신성 고혈압', '임신성고혈압', 'SYMPTOM', '임신성 고혈압으로 인한 부종 치료는 이뇨제 사용보다 안정(휴식), 염분 섭취 제한, 적절한 수분 섭취 유지가 우선적으로 권장됩니다. 부종이 자간전증(단백뇨 동반)으로 진행된 경우 입원 치료와 황산마그네슘 투여가 필요할 수 있습니다. 임신 중 부종과 혈압 이상이 동반될 때는 즉시 산부인과 전문의의 진료를 받아야 합니다.', 2522, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '임신성 고혈압', '임신성고혈압', 'DIAGNOSIS', '임신 중 복부 통증이 있으면 산부인과 전문의의 진료를 먼저 받는 것이 가장 적절합니다. 임신성 고혈압이나 자간전증이 의심되는 상복부 통증(상복부 압통, 명치 통증)의 경우 응급 상황일 수 있으므로 즉시 산부인과 응급실을 방문해야 합니다. 증상의 위치, 정도, 동반 증상(두통, 시야 이상, 부종, 혈압 이상 등)을 함께 파악하여 진료 시 의사에게 알려주시기 바랍니다.', 2523, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '임신성 고혈압', '임신성고혈압', 'TREATMENT', '임신성 고혈압 치료는 약물 치료(혈압 강하제)와 함께 충분한 안정 및 침상 안정, 저염식 식이 조절, 정기적인 혈압 및 태아 모니터링이 병행됩니다. 자간전증으로 진행된 경우 황산마그네슘을 이용한 경련 예방과 조기 분만 유도가 고려될 수 있습니다. 임신성 고혈압 치료는 산부인과 전문의의 지속적인 관리와 감독 하에 이루어져야 하며, 증상이 악화될 경우 입원 치료가 필요합니다.', 2524, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '임신성 당뇨병', '임신성당뇨병', 'CAUSE', '임신성 당뇨병은 태반에서 분비되는 호르몬(인간태반유산소마토트로핀, 프로게스테론, 코르티솔 등)이 인슐린 저항성을 증가시켜 발생합니다. 호르몬 변화 외에도 임신 전 과체중·비만, 가족력(당뇨병), 이전 임신성 당뇨병 병력, 고령 임신, 다낭성난소증후군 등이 중요한 위험 요인입니다. 이러한 위험 요인이 있는 경우 산전 검사 시 혈당 검사를 조기에 시행하는 것이 권장됩니다.', 2525, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '임신성 당뇨병', '임신성당뇨병', 'DEFINITION', '임신성 당뇨병 치료를 위해 산부인과 전문의, 내분비내과 전문의, 영양사, 당뇨 교육 간호사 등 다학제 팀이 협력합니다. 식이 조절(탄수화물 분배, 균형 잡힌 영양 섭취)과 규칙적인 운동이 혈당 관리의 기본이며, 식이와 운동으로 조절이 안 될 경우 인슐린 치료가 추가됩니다. 태아의 성장과 상태를 지속적으로 모니터링하며 적절한 분만 시기를 결정하는 것이 중요합니다.', 2526, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '임신성 당뇨병', '임신성당뇨병', 'SYMPTOM', '임신성 당뇨병은 임신 전에는 혈당이 정상이었다가 임신 중 처음 발견되는 당뇨 상태로, 일반 당뇨와 달리 대부분 분만 후 정상화됩니다. 증상이 없는 경우가 많아 선별 검사(50g 경구 당부하 검사, 100g 경구 당부하 검사)로 진단하며, 일반 2형 당뇨처럼 다뇨·다음·다식 등의 증상이 뚜렷하지 않습니다. 그러나 임신성 당뇨병 산모는 향후 2형 당뇨병 발생 위험이 높아 출산 후에도 지속적인 혈당 관리와 검진이 필요합니다.', 2527, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '임신성 당뇨병', '임신성당뇨병', 'DIAGNOSIS', '임신성 당뇨병 진단을 위해 임신 24~28주에 50g 경구 당부하 검사(1시간 혈당 140mg/dL 이상 시 양성)를 선별 검사로 시행하며, 양성인 경우 100g 3시간 경구 당부하 검사로 확진합니다. 위험 요인(비만, 가족력 등)이 있는 경우 임신 초기부터 공복 혈당 검사를 시행할 수 있습니다. 진단 기준과 검사 방법은 기관마다 다소 차이가 있으므로 담당 산부인과 전문의의 안내에 따라 검사를 진행하시기 바랍니다.', 2528, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '임신성 당뇨병', '임신성당뇨병', 'TREATMENT', '임신성 당뇨병 치료의 기본은 식이 조절(탄수화물 제한, 균형 잡힌 영양 섭취)과 규칙적인 중등도 유산소 운동(걷기 등)으로, 이를 통해 혈당을 목표 범위 내로 유지하는 것이 우선입니다. 생활습관 조절로 혈당 조절이 불충분한 경우 인슐린 주사가 처방되며, 일부 경우 메트포르민 등 경구 혈당강하제가 사용될 수 있습니다. 치료 방법은 혈당 수준과 개인 상황에 따라 달라지므로 산부인과 또는 내분비내과 전문의와 상담하시기 바랍니다.', 2529, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자간전증', '자간전증', 'CAUSE', '자간전증의 정확한 원인은 아직 완전히 밝혀지지 않았으나, 태반 혈관 발달 이상으로 인해 산화 스트레스와 전신 염증 반응이 유발되는 것이 핵심 기전으로 알려져 있습니다. 면역계 이상으로 모체가 태반 조직을 이물질로 인식하여 면역 반응이 과도하게 활성화되고, 혈관 수축 물질 증가와 혈관 내피세포 손상이 고혈압·단백뇨·간 기능 이상으로 이어질 수 있습니다. 이는 산부인과 영역의 질환으로 자가면역 간염과는 구별됩니다.', 2530, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자간전증', '자간전증', 'DEFINITION', '자간전증의 주요 특징은 임신 20주 이후 발생하는 고혈압(140/90mmHg 이상)과 단백뇨(24시간 소변 단백질 300mg 이상)입니다. 이로 인해 두통, 시야 이상(흐림, 점멸), 상복부·명치 통증, 심한 부종, 급격한 체중 증가가 나타날 수 있으며, 중증의 경우 간 기능 이상, 혈소판 감소, 신장 기능 저하가 동반됩니다. 이러한 증상은 산모와 태아 모두에게 위험하므로 즉시 산부인과 전문의의 진료를 받아야 합니다.', 2531, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자간전증', '자간전증', 'SYMPTOM', '자간전증에서 두통은 중요한 증상 중 하나로, 이마와 뒷머리에 주로 나타나는 심한 두통이 특징적입니다. 임신 중 고혈압으로 인한 두통은 일반 임산부에 비해 자간전증 산모에서 더 흔하고 심하게 나타날 수 있습니다. 임신 중 심한 두통이 새로 발생하거나, 부종·시야 이상·상복부 통증이 동반될 경우 즉시 산부인과 전문의를 방문해야 합니다.', 2532, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자간전증', '자간전증', 'DIAGNOSIS', '자간전증 진단을 위한 혈압 측정이나 혈액·소변 검사 전 특별히 공복을 유지하거나 수면을 조절할 필요는 없습니다. 다만 혈압을 정확하게 측정하기 위해 검사 전 30분간 안정을 취하고, 카페인 섭취와 과격한 활동을 피하는 것이 좋습니다. 증상이 의심되면 공복 여부와 관계없이 즉시 산부인과 전문의의 진찰을 받는 것이 가장 중요합니다.', 2533, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자간전증', '자간전증', 'TREATMENT', '자간전증은 임신 중에 발생하는 질환으로 어린이나 청소년에게는 발생하지 않습니다. 자간전증의 근본적 치료는 분만이며, 산모의 혈압 조절, 황산마그네슘을 통한 경련 예방, 태아 상태 모니터링이 핵심 치료입니다. 자간전증 산모에게서 태어난 자녀는 장기적으로 심혈관 위험이 다소 높을 수 있어 정기적인 건강 관리가 권장됩니다.', 2534, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자간증', '자간증', 'MEDICATION', '자간증 치료에 사용되는 황산마그네슘은 비교적 안전한 것으로 알려져 있으나, 태반을 통과하여 태아에게 전달될 수 있습니다. 고농도의 마그네슘이 태아에게 전달되면 신생아 호흡 저하, 근육 긴장도 감소, 저마그네슘혈증 등의 부작용이 드물게 나타날 수 있습니다. 그러나 자간증 치료의 이득이 위험보다 크므로, 약물 투여 여부와 용량은 반드시 산부인과 전문의의 판단에 따라 결정되어야 합니다.', 2535, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자간증', '자간증', 'PREVENTION', '자간증에서 나타나는 경련(발작)을 예방하기 위해 황산마그네슘 투여가 표준 치료로 사용됩니다. 분만 전후 혈압을 엄격히 조절하고 자극(밝은 빛, 소음 등)을 최소화하는 조용한 환경을 유지하는 것도 중요합니다. 자간증은 생명을 위협하는 응급 상황이므로 관련 증상(심한 두통, 시야 장애, 상복부 통증)이 나타나면 즉시 산부인과 응급 진료를 받아야 합니다.', 2536, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자간증', '자간증', 'CAUSE', '자간증은 자간전증(임신성 고혈압+단백뇨)이 진행되어 경련이 발생하는 상태로, 정확한 원인은 아직 완전히 규명되지 않았습니다. 가장 유력한 원인으로는 뇌혈관 과반응 및 허혈, 혈압의 급격한 상승으로 인한 뇌부종, 전신 혈관 내피 기능 장애 등이 알려져 있습니다. 현재 경험하고 있는 증상이 자간증과 관련이 있는지 정확히 파악하려면 반드시 산부인과 전문의의 진찰과 검사를 받으시기 바랍니다.', 2537, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자간증', '자간증', 'DEFINITION', '자간증은 임신과 직접적으로 관련된 질환으로 임신 중이거나 분만 직후(산후 48시간 이내)에 발생하며, 일반적으로 임신하지 않은 사람에게는 발생하지 않습니다. 자간전증(고혈압+단백뇨)에서 진행하여 전신 경련이 발생한 상태로 정의되며, 드물게 분만 후 48시간~4주 이내에도 발생할 수 있습니다. 임신과 무관한 경련은 간질 등 다른 신경계 질환을 감별해야 하므로 전문의의 진료를 받아야 합니다.', 2538, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자간증', '자간증', 'SYMPTOM', '자간증의 주요 증상은 전신 강직-간대성 경련(발작)이며, 경련 전 전구 증상으로 심한 두통, 시야 이상, 상복부 통증, 불안감이 나타날 수 있습니다. 불규칙한 심장 박동이나 팽팽한 느낌의 심계항진이 자간증의 전형적인 증상으로 포함되지는 않으나, 자간증에 의한 전신 상태 악화로 심박 이상이 동반될 수 있습니다. 심계항진이 지속된다면 심장 질환 감별을 위해 심장내과 진료도 고려해야 합니다.', 2539, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자간증', '자간증', 'DIAGNOSIS', '임신성 고혈압이 자간전증으로 진행되고 이후 경련이 발생하면 자간증으로 진단될 수 있습니다. 임신성 고혈압 산모의 일부에서 단백뇨, 혈소판 감소, 간 기능 이상 등이 동반되면 자간전증으로, 여기서 더 진행하여 경련이 발생하면 자간증으로 이어집니다. 임신 중 혈압이 높거나 단백뇨가 있다면 자간증으로의 진행을 예방하기 위해 산부인과 전문의의 면밀한 추적 관리가 필요합니다.', 2540, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자간증', '자간증', 'TREATMENT', '임신 중 심한 부종과 두통이 동반된다면 자간전증 또는 자간증의 가능성을 배제하기 위해 즉시 산부인과 전문의의 진료를 받아야 합니다. 혈압 측정과 소변 단백뇨 검사가 기본이며, 이상 소견이 있으면 혈액검사 및 태아 모니터링이 추가됩니다. 치료는 혈압 조절 약물, 황산마그네슘 투여, 필요 시 조기 분만이 고려되며, 증상이 심하면 입원 집중 치료가 필요합니다.', 2541, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 경부의 이형성증', '자궁경부의이형성증', 'DIET_LIFE', '자궁경부 이형성증 예방을 위해 HPV 백신 접종, 콘돔 사용을 포함한 안전한 성생활, 금연이 가장 중요한 생활 습관입니다. 면역력 유지를 위해 균형 잡힌 식사, 충분한 수면, 스트레스 관리, 규칙적인 운동이 도움이 됩니다. 정기적인 자궁경부 세포검사(팝스미어)와 HPV 검사를 통해 이형성증을 조기에 발견하고 관리하는 것이 중요합니다.', 2542, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 경부의 이형성증', '자궁경부의이형성증', 'PREVENTION', '건강한 식사와 생활습관은 면역 체계를 강화하여 HPV 감염에 대한 저항력을 높이고 이형성증으로의 진행을 억제하는 데 도움이 됩니다. 특히 흡연은 자궁경부 이형성증과 자궁경부암의 위험을 크게 높이므로 금연이 필수적이며, 항산화 비타민(엽산, 비타민 A·C·E)의 충분한 섭취도 권장됩니다. 생활습관 개선과 함께 HPV 백신 접종 및 정기 검진을 병행하는 것이 가장 효과적인 예방 전략입니다.', 2543, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 경부의 이형성증', '자궁경부의이형성증', 'CAUSE', '자궁경부 이형성증의 주요 원인은 인유두종바이러스(HPV) 감염이며, 특히 고위험군 HPV(16, 18형 등)가 자궁경부 세포의 이상 변화를 유발합니다. HPV 감염 자체는 증상이 없는 경우가 많으나, 이형성증이 진행되면 성관계 후 출혈, 비정상적 질 분비물 증가, 질 출혈 등이 나타날 수 있습니다. 이러한 증상이 있거나 HPV 감염이 의심되면 산부인과 전문의의 진찰과 자궁경부 세포검사를 받으시기 바랍니다.', 2544, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 경부의 이형성증', '자궁경부의이형성증', 'DEFINITION', '자궁 경부의 이형성증은 자궁경부 세포가 정상에서 벗어나 비정상적인 형태로 변화된 상태를 말하며, 자궁경부 이형 조직의 존재를 나타내는 질환입니다. 이형 세포는 DNA 손상이 누적되면서 점차 악성으로 전환될 수 있으며, 특히 고위험 인유두종바이러스(HPV) 감염이 이 과정을 촉진합니다. 정기적인 자궁경부암 검사와 전문의 상담을 통해 조기 발견과 관리가 중요합니다.', 2545, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 경부의 이형성증', '자궁경부의이형성증', 'SYMPTOM', '자궁 경부의 이형성증은 대부분 무증상이지만, 성관계 후 출혈이나 비정기적인 질 출혈이 나타날 수 있습니다. 그러나 이러한 출혈은 이형성증의 전형적인 증상이라기보다 진행된 병변이나 동반 질환에서 나타나는 경우가 많습니다. 출혈 증상이 있다면 반드시 산부인과 전문의를 방문하여 정확한 원인을 확인하시기 바랍니다.', 2546, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 경부의 이형성증', '자궁경부의이형성증', 'DIAGNOSIS', '자궁경부 이형성증의 진단 결과는 검사 시기, 검체 채취 방법, 판독 의사의 경험 등에 따라 다소 차이가 날 수 있습니다. 세포 검사(Pap smear)는 위음성률이 존재하므로 다른 병원에서 재검사 시 결과가 다를 가능성이 있습니다. 결과에 대한 의문이 있다면 조직 검사(생검) 등 추가 확진 검사를 통해 정확한 진단을 받는 것이 중요합니다.', 2547, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 경부의 이형성증', '자궁경부의이형성증', 'TREATMENT', '자궁 경부의 이형성증 치료는 병변의 등급에 따라 달라지며, 중등도 이상(CIN 2~3)의 경우 수술적 치료가 필요합니다. 주요 수술 방법으로는 루프 전기절제술(LEEP), 냉동요법, 레이저 치료, 원추 절제술 등이 있습니다. 적절한 치료 방법은 병변의 범위와 환자 상태에 따라 결정되므로 반드시 산부인과 전문의와 상담하시기 바랍니다.', 2548, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 내 성장 지연', '자궁내성장지연', 'CHECKUP', '자궁 내 성장 지연이 의심되는 경우 산부인과 또는 모체태아의학(주산기의학) 전문의를 방문하는 것이 가장 적절합니다. 태아 성장 이상은 임신 중 관리와 밀접하게 관련되어 있어 산부인과에서 초음파 및 태아 상태 평가가 이루어집니다. 이상 증상이 있다면 즉시 산부인과 전문의와 상담하여 조기 진단과 관리를 받으시기 바랍니다.', 2549, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 내 성장 지연', '자궁내성장지연', 'CAUSE', '자궁 내 성장 지연을 일으키는 외부 요인으로는 흡연, 음주, 약물 남용, 영양 결핍 등이 대표적입니다. 또한 고도 거주(산소 부족), 방사선 노출, 특정 감염(거대세포바이러스, 풍진 등), 과도한 스트레스도 태아 성장에 영향을 미칩니다. 임신 중에는 이러한 위험 요인을 피하고 정기적인 산전 검진을 통해 태아 성장을 모니터링하는 것이 중요합니다.', 2550, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 내 성장 지연', '자궁내성장지연', 'DEFINITION', '자궁 내 성장 지연(IUGR)은 태아가 임신 주수에 비해 예상 체중의 10 백분위수 미만으로 성장하는 상태를 말합니다. 이는 태반 기능 저하, 모체 질환, 태아 이상 등 다양한 원인으로 발생하며, 생리주기 불규칙이나 생리통과는 직접적인 관련이 없는 임신 중 발생하는 문제입니다. 해당 증상은 산부인과 전문의 상담을 통해 정확한 원인을 파악하는 것이 필요합니다.', 2551, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 내 성장 지연', '자궁내성장지연', 'SYMPTOM', '자궁 내 성장 지연이 의심될 때 나타날 수 있는 증상으로는 태동 감소, 자궁 크기가 임신 주수에 비해 작은 것, 산모 체중 증가 불량 등이 있습니다. 초음파 검사에서 태아 복부 둘레 및 예상 체중이 기준치 이하로 측정될 수 있으며, 태반 기능 저하로 양수량이 감소할 수 있습니다. 태동이 감소하거나 산전 검진에서 이상이 발견되면 즉시 산부인과 전문의와 상담하시기 바랍니다.', 2552, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 내 성장 지연', '자궁내성장지연', 'DIAGNOSIS', '자궁 내 성장 지연 진단을 위해서는 산부인과에서 초음파 검사를 통해 태아 성장 지표(두위, 복위, 대퇴골 길이, 예상 체중)를 측정하고 성장 곡선과 비교합니다. 또한 도플러 초음파로 태반 및 태아 혈류를 평가하고, 비수축검사(NST) 등 태아 안녕 평가도 시행합니다. 진단이 내려지면 원인 규명을 위한 추가 검사와 함께 전문의의 지속적인 모니터링이 필요합니다.', 2553, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 내 성장 지연', '자궁내성장지연', 'TREATMENT', '자궁 내 성장 지연의 치료는 원인과 중증도에 따라 달라지며, 산모의 충분한 영양 섭취, 안정, 금연·금주가 기본입니다. 태아 상태가 악화되면 조기 분만을 고려할 수 있으며, 필요 시 입원하여 집중 태아 감시를 시행합니다. 구체적인 치료 계획은 모체태아의학 전문의와 상의하여 결정하는 것이 중요합니다.', 2554, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 발육부전', '자궁발육부전', 'CAUSE', '자궁 발육부전은 유전적 요인과 호르몬 이상 외에도 터너증후군 등 염색체 이상, 선천성 기형, 자궁 내 감염, 방사선 치료의 영향 등이 원인이 될 수 있습니다. 또한 뇌하수체나 시상하부 기능 이상으로 인한 성선자극호르몬 결핍도 자궁 발달에 영향을 미칩니다. 정확한 원인 파악을 위해 산부인과 및 내분비내과 전문의와 상담하시기 바랍니다.', 2555, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 발육부전', '자궁발육부전', 'DEFINITION', '자궁 발육부전은 자궁이 사춘기 이후에도 충분히 성숙하지 못하여 정상 성인 여성의 크기와 기능에 미치지 못하는 상태를 말합니다. 이로 인해 월경 이상, 불임, 임신 합병증 등이 나타날 수 있으며, 선천성 또는 후천성 원인에 의해 발생합니다. 증상이 의심된다면 산부인과 전문의를 통해 초음파 및 호르몬 검사 등으로 정확히 평가받으시기 바랍니다.', 2556, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 발육부전', '자궁발육부전', 'SYMPTOM', '자궁 발육부전에서는 희발월경(생리 주기가 길어짐), 무월경, 생리량 감소 등의 월경 이상이 주요 증상으로 나타납니다. 또한 이차성징 발달 지연, 불임, 반복 유산 등이 동반될 수 있으며, 골반 통증이나 성교통이 나타나기도 합니다. 이러한 증상이 있다면 산부인과 전문의 상담을 통해 정확한 진단과 치료 방향을 결정하시기 바랍니다.', 2557, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 발육부전', '자궁발육부전', 'DIAGNOSIS', '자궁 발육부전 진단 후에도 증상이 지속된다면 다른 동반 질환의 가능성을 배제하기 위한 추가 검사를 고려하는 것이 타당합니다. 호르몬 검사, 염색체 분석, MRI 등 정밀 영상 검사를 통해 더 세밀한 평가가 가능합니다. 지속적인 불편감이 있다면 산부인과 전문의와 재상담하여 추가적인 진단 및 치료 계획을 세우시기 바랍니다.', 2558, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 발육부전', '자궁발육부전', 'TREATMENT', '자궁 발육부전 환자에서 호르몬 치료 외에도 보조생식술(IVF 등), 자궁 성형술, 심리 상담 및 지지 치료 등이 고려될 수 있습니다. 유산 경험이 있는 경우 자궁경부 봉합술이나 황체호르몬 보충 요법도 병행될 수 있습니다. 개인별 상태에 맞는 맞춤 치료 계획은 산부인과 전문의와 충분히 상의하여 결정하시기 바랍니다.', 2559, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 외 임신', '자궁외임신', 'CAUSE', '자궁 외 임신의 원인은 난관 손상이나 기능 이상으로 인해 수정란이 자궁 내막에 착상하지 못하고 난관에 착상하는 것입니다. 아랫배 통증과 소량의 질 출혈은 자궁 외 임신의 증상으로 나타날 수 있지만, 그 자체가 자궁 외 임신을 유발하는 원인은 아닙니다. 이러한 증상이 있을 경우 즉시 산부인과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 2560, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 외 임신', '자궁외임신', 'DEFINITION', '자궁 외 임신은 수정란이 자궁 내막 외부, 주로 난관에 착상하는 상태로, 혈중 hCG 수치가 상승하지만 초음파에서 자궁 내 임신낭이 보이지 않을 때 의심합니다. 진단을 위해서는 혈중 β-hCG 수치 측정과 질식 초음파 검사를 시행하며, hCG 수치가 일정 수준 이상인데도 자궁 내 임신낭이 없으면 자궁 외 임신을 강하게 의심합니다. 관련 증상이 있다면 즉시 산부인과를 방문하시기 바랍니다.', 2561, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 외 임신', '자궁외임신', 'SYMPTOM', '자궁 외 임신의 주요 증상으로는 무월경 후 불규칙한 질 출혈, 한쪽 하복부 통증, 어깨 통증(횡격막 자극 시), 어지러움 등이 있습니다. 진단을 위해서는 혈중 β-hCG 검사와 질식 초음파 검사가 필수적이며, 파열 시에는 급성 복통과 쇼크 증상이 나타날 수 있습니다. 위와 같은 증상이 있다면 즉시 산부인과 응급 진료를 받으시기 바랍니다.', 2562, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 외 임신', '자궁외임신', 'DIAGNOSIS', '자궁 외 임신 진단을 위해서는 혈중 β-hCG 수치 측정, 질식 초음파 검사, 복부 초음파 검사가 기본적으로 시행됩니다. 복부 통증이 동반될 경우 자궁 외 임신 파열 가능성을 고려하여 응급 평가가 필요할 수 있으며, 필요 시 복강경 검사도 시행됩니다. 이러한 증상이 있다면 즉시 산부인과 응급 진료를 받으시기 바랍니다.', 2563, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 외 임신', '자궁외임신', 'TREATMENT', '자궁 외 임신이 파열되어 산모의 생명이 위협받는 응급 상황에서는 즉각적인 수술적 치료(복강경 또는 개복 수술)가 가장 효과적입니다. 파열 전 조기 발견된 경우에는 약물치료(메토트렉세이트)나 복강경 수술이 가능하나, 활발한 출혈이 있는 응급 상황에서는 즉시 수술이 필요합니다. 자궁 외 임신이 의심될 경우 즉시 응급실을 방문하시기 바랍니다.', 2564, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 탈출증', '자궁탈출증', 'EXERCISE', '골반저 근육 강화 운동(케겔 운동)은 가벼운 자궁 탈출증의 증상 완화와 진행 예방에 도움이 될 수 있습니다. 그러나 중등도 이상의 탈출증에서는 운동만으로 근본적인 치료가 어려울 수 있으며, 페서리(pessary) 삽입 또는 수술적 치료가 필요할 수 있습니다. 운동 방법과 치료 계획에 대해서는 산부인과 전문의와 상담하여 개인 상태에 맞는 접근을 권장합니다.', 2565, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 탈출증', '자궁탈출증', 'CAUSE', '자궁 탈출증은 자궁을 지지하는 골반저 근육과 인대가 약해져 자궁이 정상 위치에서 아래로 내려와 질 내부 또는 질 밖으로 돌출되는 상태입니다. 주요 원인으로는 분만 시 외상, 노화, 폐경 후 에스트로겐 감소, 비만, 만성 복압 증가(변비, 만성 기침) 등이 있습니다. 증상이 있다면 산부인과 전문의를 방문하여 정확한 평가와 치료 방향을 결정하시기 바랍니다.', 2566, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 탈출증', '자궁탈출증', 'DEFINITION', '질 외부로 무언가 돌출되는 느낌과 골반 압박감은 자궁 탈출증의 전형적인 증상입니다. 자궁 탈출증은 골반저 지지 구조물이 약화되어 자궁이 질 방향으로 하강하는 상태로, 오래 서 있거나 복압이 증가할 때 증상이 악화됩니다. 이러한 증상이 있다면 산부인과 전문의를 방문하여 진단과 적절한 치료를 받으시기 바랍니다.', 2567, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 탈출증', '자궁탈출증', 'SYMPTOM', '자궁 탈출증의 주요 증상으로는 질 입구에서 무언가 빠져나오는 느낌, 골반 압박감 및 묵직함, 요통, 배뇨 장애(소변 자주 마려움, 요실금), 변비 등이 있습니다. 중증의 경우 실제로 자궁이 질 밖으로 돌출될 수 있으며, 이를 완전 탈출증(4도)이라 합니다. 이러한 증상이 있다면 산부인과 전문의를 방문하여 정확한 진단과 치료를 받으시기 바랍니다.', 2568, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 탈출증', '자궁탈출증', 'DIAGNOSIS', '자궁 탈출증이 의심될 경우 산부인과(또는 여성비뇨부인과) 전문의를 방문하면 정확한 진단을 받을 수 있습니다. 골반 진찰과 함께 탈출 정도를 평가하는 POP-Q 분류법을 이용하며, 필요 시 요역동학 검사나 영상 검사가 추가될 수 있습니다. 증상이 일상생활에 불편을 준다면 빠른 시일 내에 전문의 상담을 받으시기 바랍니다.', 2569, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁 탈출증', '자궁탈출증', 'TREATMENT', '자궁 탈출증의 비수술적 치료로는 골반저 근육 강화 운동(케겔 운동), 페서리(pessary) 삽입, 에스트로겐 국소 도포 등이 있습니다. 페서리는 증상 완화에 효과적이지만 근본적인 치료는 아니며, 지속적인 관리가 필요합니다. 완치를 위해서는 수술적 치료가 더 효과적이므로, 증상의 정도와 개인 상황에 따라 산부인과 전문의와 최적의 치료 방법을 상의하시기 바랍니다.', 2570, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경관무력증', '자궁경관무력증', 'CAUSE', '자궁경관무력증의 원인으로는 선천성 자궁경부 구조 이상, 이전 자궁경부 수술(원추 절제술, LEEP 등)로 인한 손상, 반복적인 자궁경부 확장 시술, 자궁경부 외상 등이 있습니다. 가족력이나 특정 유전적 요인이 결합 조직의 약화와 관련될 수 있으나, 직접적인 유전성 질환으로 분류되지는 않습니다. 정확한 원인 파악과 임신 관리를 위해 산부인과 전문의와 상담하시기 바랍니다.', 2571, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경관무력증', '자궁경관무력증', 'DEFINITION', '자궁경관무력증은 자궁경부가 임신 중 태아의 무게를 견디지 못하고 통증 없이 조기에 열리거나 짧아지는 상태로, 주로 임신 2삼분기 유산이나 조산의 원인이 됩니다. 주요 증상으로는 통증 없는 자궁경부 개대, 하복부 압박감, 소량의 질 분비물 또는 출혈 등이 있습니다. 반복 유산이나 조산 경험이 있다면 임신 전부터 산부인과 전문의와 상담하여 관리 계획을 세우시기 바랍니다.', 2572, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경관무력증', '자궁경관무력증', 'SYMPTOM', '자궁경관무력증으로 인해 임신이 종결될 경우 주로 통증 없이 자궁경부가 열리면서 양막이 팽출되거나 파막이 일어나 유산 또는 조산이 발생합니다. 증상으로는 하복부 압박감, 질 분비물 증가, 소량의 출혈이 나타날 수 있으며, 초기에는 뚜렷한 통증이 없어 인지하기 어렵습니다. 임신 중 이러한 증상이 나타나면 즉시 산부인과를 방문하시기 바랍니다.', 2573, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경관무력증', '자궁경관무력증', 'DIAGNOSIS', '자궁경관무력증은 증상이 거의 없어 조기 발견이 어렵고, 진단 없이 방치하면 반복 유산이나 조산으로 이어질 수 있습니다. 초음파를 통한 자궁경부 길이 측정과 과거 임신력 평가로 진단하며, 조기에 발견할수록 자궁경부 봉합술(맥도날드 술식) 등의 예방적 치료가 가능합니다. 반복 유산 경험이 있다면 임신 초기부터 전문의의 체계적인 검사를 받는 것이 중요합니다.', 2574, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경관무력증', '자궁경관무력증', 'TREATMENT', '자궁경관무력증 수술(자궁경부 봉합술)은 보통 임신 12~14주경에 시행하며, 수술 전 감염 여부와 태아 상태를 확인해야 합니다. 수술 후에는 안정을 취하고 성관계를 자제하며, 조기 진통이나 파막 증상 발생 시 즉시 병원을 방문해야 합니다. 봉합사는 일반적으로 임신 36~37주에 제거하며, 모든 과정은 산부인과 전문의의 지속적인 관리 하에 이루어져야 합니다.', 2575, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경부염', '자궁경부염', 'CHECKUP', '자궁경부염이 의심될 때는 산부인과 전문의를 방문하는 것이 가장 정확한 진단을 받을 수 있는 방법입니다. 산부인과에서는 자궁경부 시진, 분비물 배양 검사, 성병 검사(임균, 클라미디아 등), 자궁경부 세포 검사 등을 통해 원인을 파악합니다. 증상이 의심된다면 지체 없이 산부인과를 방문하시기 바랍니다.', 2576, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경부염', '자궁경부염', 'DIET_LIFE', '자궁경부염 예방을 위해서는 면역력을 높이는 균형 잡힌 식단이 도움이 되며, 항산화 식품(채소, 과일)과 유산균이 풍부한 음식을 권장합니다. 당분이 많은 음식, 과도한 음주, 자극적인 음식은 질 내 환경을 변화시켜 감염에 취약하게 만들 수 있으므로 피하는 것이 좋습니다. 식이 조절과 함께 개인 위생 관리 및 정기 산부인과 검진을 병행하시기 바랍니다.', 2577, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경부염', '자궁경부염', 'MEDICATION', '자궁경부염의 치료 약물은 원인균에 따라 달라지며, 세균성(임균, 클라미디아)의 경우 항생제(아지트로마이신, 독시사이클린, 세프트리악손 등)가 사용됩니다. 바이러스성(HPV) 원인에는 항바이러스제보다 병변 제거 치료가 우선되며, 트리코모나스 감염에는 메트로니다졸이 사용됩니다. 약물 처방은 반드시 산부인과 전문의의 진단 후 이루어져야 합니다.', 2578, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경부염', '자궁경부염', 'PREVENTION', 'HPV 예방 백신은 특정 고위험 HPV 유형(주로 16, 18형)에 대한 예방 효과가 있지만, 모든 HPV 유형을 차단하지는 않습니다. 따라서 백신 접종 후에도 정기적인 자궁경부암 검사, 안전한 성관계(콘돔 사용), 금연 등 추가적인 예방 수단을 병행하는 것이 중요합니다. 백신은 예방의 한 축일 뿐이므로 다각적인 예방 전략이 필요합니다.', 2579, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경부염', '자궁경부염', 'CAUSE', '자궁경부염은 세균 감염 외에도 자궁경부 외번(ectropion), 화학적 자극(질 세정제, 피임 기구), 호르몬 변화에 의한 질 내 환경 불균형 등 내부적 요인에 의해서도 발생할 수 있습니다. 에스트로겐 수치 변화는 자궁경부 상피 세포를 취약하게 만들어 감염 위험을 높일 수 있습니다. 원인에 따라 치료 방법이 다르므로 산부인과 전문의의 정확한 진단이 필요합니다.', 2580, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경부염', '자궁경부염', 'DEFINITION', '질 입구 가려움, 화끈거림, 배뇨 시 쓰라림은 자궁경부염보다는 질염(세균성 질증, 칸디다 질염 등)의 주요 증상에 더 가깝습니다. 자궁경부염은 주로 농성 자궁경부 분비물, 성관계 후 출혈, 골반 불쾌감 등이 특징적입니다. 두 질환이 동시에 나타날 수 있으므로 정확한 감별을 위해 산부인과 전문의의 진료를 받으시기 바랍니다.', 2581, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경부염', '자궁경부염', 'SYMPTOM', '자궁경부염은 생리통과 유사한 골반 통증 외에도 비정상적인 질 분비물(노란색 또는 녹색, 악취), 성관계 후 출혈, 배뇨 장애, 성교통 등의 증상이 나타날 수 있습니다. 상행 감염이 일어나면 골반염으로 진행되어 고열, 심한 하복부 통증이 동반될 수 있습니다. 이러한 증상이 있다면 빠른 시일 내에 산부인과 전문의 진료를 받으시기 바랍니다.', 2582, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경부염', '자궁경부염', 'DIAGNOSIS', '자궁경부염 진단을 위해 의사는 자궁경부 시진, 질 분비물 검사(현미경 검사, 배양 검사), 클라미디아 및 임균 핵산증폭검사(NAAT), 자궁경부 세포 검사(Pap smear) 등을 시행합니다. 자궁경부 직접 관찰을 통해 발적, 분비물, 접촉 출혈 등의 염증 소견을 확인하는 것이 중요합니다. 정확한 진단을 위해 산부인과 전문의에게 내원하여 체계적인 검사를 받으시기 바랍니다.', 2583, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경부염', '자궁경부염', 'TREATMENT', '자궁경부염 치료를 위해서는 규칙적인 운동, 균형 잡힌 영양 섭취, 충분한 수면을 통한 면역력 강화가 도움이 됩니다. HPV 백신 미접종 상태에서 발생한 경우에도 항생제, 항바이러스제, 또는 국소 치료 등 원인에 맞는 약물치료가 가능합니다. 자극적인 질 세정제 사용을 피하고, 치료 기간 중 성관계를 자제하며, 반드시 산부인과 전문의의 지도 하에 치료를 받으시기 바랍니다.', 2584, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁근종', '자궁근종', 'MEDICATION', '자궁근종 치료에 사용되는 약물 중 GnRH 작용제(류프로라이드 등)는 에스트로겐 분비를 억제하여 근종의 크기를 일시적으로 줄이는 효과가 있습니다. 울리프리스탈 아세테이트와 같은 선택적 프로게스테론 수용체 조절제도 근종 성장을 억제하는 데 사용됩니다. 약물치료는 근종을 완전히 제거하지 못하며 약 중단 후 재성장 가능성이 있어, 치료 방법 선택은 산부인과 전문의와 상의하시기 바랍니다.', 2585, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁근종', '자궁근종', 'CAUSE', '자궁근종 제거 수술 후 임신 시 수술 부위 흉터(자궁 절개 부위)는 임신이 진행되면서 태아의 성장으로 인한 압력을 받을 수 있습니다. 특히 자궁벽을 관통하는 수술을 받은 경우 자궁 파열의 위험이 증가할 수 있으며, 이는 산모와 태아 모두에게 생명을 위협하는 합병증입니다. 근종 제거 수술 후 임신을 계획하거나 임신 중인 경우 반드시 산부인과 전문의의 긴밀한 관리를 받으시기 바랍니다.', 2586, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁근종', '자궁근종', 'DEFINITION', '자궁근종은 자궁의 평활근 조직에서 발생하는 양성 종양으로, 가임기 여성에서 가장 흔한 골반 내 종양입니다. 갱년기 이후에는 에스트로겐 감소로 근종이 자연적으로 축소되는 경우가 많으나, 이 시기에 새로운 출혈이나 급격한 종양 성장이 있을 경우 자궁내막암 등 악성 질환과의 감별이 필요합니다. 이상 증상이 있다면 산부인과 전문의를 방문하여 정확한 평가를 받으시기 바랍니다.', 2587, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁근종', '자궁근종', 'SYMPTOM', '자궁근종의 주요 증상으로는 과다 월경(생리량 증가, 생리 기간 연장), 불규칙한 질 출혈, 빈혈, 하복부 또는 골반 압박감과 통증, 빈뇨, 변비 등이 있습니다. 성교통 외에도 근종 위치와 크기에 따라 요통이나 하지 방사통이 나타날 수 있으며, 가임력 저하 및 불임의 원인이 되기도 합니다. 이러한 증상이 있다면 산부인과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 2588, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁근종', '자궁근종', 'DIAGNOSIS', '자궁근종 진단에는 골반 초음파(경복부 및 질식)가 가장 먼저 활용되며, 근종의 위치, 크기, 개수를 평가하는 데 효과적입니다. MRI는 근종과 다른 골반 병변을 보다 정밀하게 감별하고 수술 계획 수립에 유용합니다. CT는 자궁근종 진단에 일차적으로 권장되지 않으며 방사선 노출이 있으므로, 검사 방법은 산부인과 전문의와 상의하여 결정하시기 바랍니다.', 2589, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁근종', '자궁근종', 'TREATMENT', '자궁근종의 수술적 치료로는 근종만 제거하는 자궁근종 절제술(개복, 복강경, 로봇 수술)과 자궁 전체를 제거하는 자궁 절제술이 있습니다. 자궁 보존을 원하는 경우 근종 절제술이 선택되며, 더 이상 임신을 원하지 않는 경우 자궁 절제술이 근본적인 치료가 될 수 있습니다. 최적의 수술 방법은 근종의 개수, 위치, 크기 및 환자의 상태에 따라 다르므로 산부인과 전문의와 충분히 상담하시기 바랍니다.', 2590, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁내막 이상증식증', '자궁내막이상증식증', 'CAUSE', '자궁내막 이상증식증은 주로 에스트로겐 과잉 노출(비만, 다낭성 난소증후군, 에스트로겐 단독 호르몬 치료 등)로 인해 자궁내막 세포가 과도하게 증식하여 발생합니다. 자궁 외 조직이 직접적으로 자궁내막 이상증식증을 일으키는 것은 아니며, 에스트로겐 과잉이 핵심 기전입니다. 정확한 원인 파악을 위해 산부인과 전문의의 진단과 상담이 필요합니다.', 2591, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁내막 이상증식증', '자궁내막이상증식증', 'DEFINITION', '자궁내막 이상증식증은 자궁내막 세포가 비정상적으로 과다 증식하여 발생하는 질환으로, 일부는 자궁내막암으로 진행할 수 있습니다. 주요 증상으로는 불규칙한 질 출혈, 폐경 후 출혈, 생리량 과다 등이 있으며, 무증상인 경우도 있습니다. 이러한 증상이 있거나 위험 요인이 있다면 산부인과 전문의를 방문하여 조기 진단과 치료를 받으시기 바랍니다.', 2592, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁내막 이상증식증', '자궁내막이상증식증', 'SYMPTOM', '자궁내막 이상증식증에서 생리량이 매우 과다하여 빈혈이나 일상생활 장애가 심한 경우, 약물치료에 반응이 없거나 비정형 이형성증이 동반된 경우에는 수술적 치료(자궁내막 소작술 또는 자궁 절제술)가 필요할 수 있습니다. 수술 여부는 환자의 나이, 임신 계획, 이형성 정도에 따라 결정되므로 산부인과 전문의와 충분히 상의하여 결정하시기 바랍니다.', 2593, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁내막 이상증식증', '자궁내막이상증식증', 'DIAGNOSIS', '자궁내막 이상증식증 진단을 위해 의사는 자궁내막 조직 검사(소파술 또는 자궁경 하 생검)를 시행하여 병리학적으로 확인합니다. 질식 초음파로 자궁내막 두께를 측정하고 이상 소견을 평가하며, 자궁경 검사로 내막 상태를 직접 관찰할 수 있습니다. 최종 진단은 조직 병리 결과로 이루어지며, 산부인과 전문의의 판단에 따라 적절한 검사가 선택됩니다.', 2594, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁내막 이상증식증', '자궁내막이상증식증', 'TREATMENT', '자궁내막 이상증식증의 관리를 위해서는 산부인과 전문의가 주축이 되며, 비만이 원인인 경우 내분비내과 또는 비만 전문의와 협력합니다. 다낭성 난소증후군이 동반된 경우 생식내분비 전문의, 악성 전환이 의심될 경우 부인종양 전문의와의 협진이 필요합니다. 통합적인 다학제 접근을 통해 원인 치료와 재발 예방을 함께 도모하는 것이 중요합니다.', 2595, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁내막증', '자궁내막증', 'CHECKUP', '자궁내막증 진단을 위해서는 질식 초음파가 기본 검사로 사용되며, 난소 자궁내막종(초콜릿 낭종) 등을 확인할 수 있습니다. 혈액 검사(CA-125)는 보조적으로 활용되나 특이도가 낮으며, 확진을 위해서는 복강경 수술을 통한 조직 검사가 표준 진단법입니다. 증상이 있거나 불임이 의심된다면 산부인과 전문의를 방문하여 적절한 검사를 받으시기 바랍니다.', 2596, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁내막증', '자궁내막증', 'MEDICATION', '자궁내막증 치료에 사용되는 호르몬제(GnRH 작용제, 프로게스틴, 경구 피임약 등)의 부작용을 최소화하려면 가능한 최소 유효 용량을 사용하고 정기적으로 부작용을 모니터링하는 것이 중요합니다. GnRH 작용제 사용 시 골밀도 감소를 예방하기 위해 역 첨가 요법(add-back therapy)을 병행하는 경우도 있습니다. 약물 선택과 부작용 관리는 반드시 산부인과 전문의와 상의하여 진행하시기 바랍니다.', 2597, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁내막증', '자궁내막증', 'PREVENTION', '자궁내막증은 유전적 소인이 있어 어머니가 자궁내막증인 경우 딸의 발생 위험이 6배가량 증가합니다. 예방을 위해서는 정기적인 산부인과 검진으로 조기 발견에 힘쓰고, 심한 월경통이나 골반통이 있다면 지체 없이 검사를 받는 것이 중요합니다. 현재 자궁내막증을 완전히 예방하는 방법은 없으나, 조기 발견과 치료로 진행을 늦출 수 있습니다.', 2598, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁내막증', '자궁내막증', 'CAUSE', '자궁내막증의 발생 원인 중 하나로 역행성 월경설이 있으며, 이는 월경혈이 난관을 통해 복강으로 역류하여 자궁내막 세포가 복강 내에 착상·증식한다는 이론입니다. 대부분의 여성에서 역행성 월경이 발생하지만, 모두 자궁내막증으로 진행되지는 않으며 면역학적 요인도 중요하게 작용합니다. 월경 시에만 이 현상이 일어나는 것은 맞으나 자궁내막증 발생에는 복합적인 기전이 관여합니다.', 2599, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁내막증', '자궁내막증', 'DEFINITION', '자궁내막증은 자궁내막 조직이 자궁 밖(난소, 복막, 장, 방광 등)에 존재하며 월경 주기에 반응하는 질환으로, 정확한 원인은 아직 완전히 밝혀지지 않았습니다. 주요 증상으로는 심한 월경통, 만성 골반통, 성교통, 배변 통증, 불임 등이 있으며, 증상의 정도는 병변 위치와 범위에 따라 다양합니다. 이러한 증상이 있다면 산부인과 전문의를 방문하여 조기 진단과 치료를 받으시기 바랍니다.', 2600, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁내막증', '자궁내막증', 'SYMPTOM', '자궁내막증에서 월경 시 극심한 통증(월경곤란증)은 만성 골반통, 성교통, 배변 또는 배뇨 시 통증과 밀접하게 연관됩니다. 또한 월경량 과다, 불규칙한 출혈, 피로감, 불임 등과도 관련될 수 있습니다. 증상의 심각도와 치료 방향은 개인마다 다르므로 산부인과 전문의와의 상담을 통해 적절한 관리를 받으시기 바랍니다.', 2601, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁내막증', '자궁내막증', 'DIAGNOSIS', '자궁내막증이 의심되는 증상(심한 생리통, 골반통, 성교통 등)이 있을 때 산부인과를 방문하는 것이 가장 적절한 선택입니다. 산부인과에서 초음파 검사와 병력 청취를 통해 초기 평가가 이루어지며, 필요 시 복강경 등 추가 검사를 진행합니다. 조기에 진단받아 치료를 시작할수록 증상 조절과 가임력 보존에 유리하므로 빠른 방문을 권장합니다.', 2602, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁내막증', '자궁내막증', 'TREATMENT', '자궁내막증 통증 완화를 위해 비스테로이드성 항염증제(NSAIDs, 이부프로펜 등)가 일차적으로 사용되며, 경구 피임약이나 프로게스틴도 통증 조절에 효과적입니다. 심한 통증에는 GnRH 작용제가 사용될 수 있으며, 냉온찜질, 경피신경전기자극(TENS) 등 비약물적 방법도 보조적으로 활용됩니다. 약물 처방 및 의료 기기 사용은 반드시 산부인과 전문의의 지도 하에 이루어져야 합니다.', 2603, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁선근증', '자궁선근증', 'MEDICATION', '자궁선근증 환자에서 호르몬제(프로게스틴, 경구 피임약, 레보노르게스트렐 자궁내장치 등)는 자궁내막의 증식을 억제하고 생리량을 줄여 월경통과 생리 과다를 완화하는 데 효과적입니다. GnRH 작용제는 에스트로겐 분비를 억제하여 자궁선근증의 크기 감소와 증상 완화에 도움을 줄 수 있습니다. 적절한 약물 선택과 복용 기간은 산부인과 전문의와 상담하여 결정하시기 바랍니다.', 2604, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁선근증', '자궁선근증', 'CAUSE', '자궁선근증의 정확한 원인은 아직 명확히 밝혀지지 않았으며, 유전적 요인이 일부 관여하는 것으로 알려져 있습니다. 그 외에도 이전 자궁 수술(제왕절개, 소파술), 자궁내막 손상, 에스트로겐 과잉 노출, 출산 경험 등이 위험 요인으로 거론됩니다. 발생 기전과 치료에 대해서는 산부인과 전문의와 상담하여 개인에 맞는 관리를 받으시기 바랍니다.', 2605, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁선근증', '자궁선근증', 'DEFINITION', '자궁선근증은 자궁내막 조직이 자궁 근육층(자궁근층) 내로 침투하여 성장하는 질환으로, 자궁이 전체적으로 커지고 월경 시 자궁근층 내 출혈과 염증이 반복됩니다. 주요 증상으로는 심한 월경통, 생리량 과다, 생리 기간 연장, 만성 골반통 등이 있으며, 불임의 원인이 되기도 합니다. 증상이 있다면 산부인과 전문의를 방문하여 초음파 또는 MRI 검사를 통해 정확한 진단을 받으시기 바랍니다.', 2606, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁선근증', '자궁선근증', 'SYMPTOM', '자궁선근증으로 인한 생리 과다, 생리통, 빈혈 증상이 있을 때 다른 질환(자궁근종, 자궁내막증, 혈액 응고 장애 등)을 감별하기 위해 혈액 검사(CBC, 혈액응고 검사), 골반 초음파, 자궁경 검사, 필요 시 MRI 등을 받는 것이 권장됩니다. 빈혈이 심한 경우 내과적 치료도 병행될 수 있으므로 산부인과 전문의와 상담하시기 바랍니다.', 2607, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁선근증', '자궁선근증', 'DIAGNOSIS', '자궁선근증으로 인한 생리 과다나 불임이 의심될 경우 산부인과(또는 불임·생식내분비 전문 클리닉)를 방문하는 것이 적절합니다. 불임 진단을 위해서는 기본 가임력 검사(호르몬 검사, 난관 조영술, 자궁 초음파 등)를 시행하며, 자궁선근증의 범위와 영향을 평가합니다. 증상이 있다면 지체 없이 산부인과 전문의를 찾아 체계적인 진단과 치료 계획을 세우시기 바랍니다.', 2608, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁선근증', '자궁선근증', 'TREATMENT', '자궁선근증 치료는 임신 계획 여부와 증상의 정도에 따라 달라집니다. 임신을 원하는 경우 호르몬 치료(프로게스틴, GnRH 작용제, 레보노르게스트렐 자궁내장치)나 자궁선근증 병소 부분 절제술이 우선 고려되며, 임신을 원하지 않거나 증상이 심한 경우 자궁 절제술이 근본적 치료가 됩니다. 치료 방향은 개인 상황에 따라 달라지므로 반드시 산부인과 전문의와 충분히 상담하시기 바랍니다.', 2609, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '전치 태반', '전치태반', 'CAUSE', '전치 태반은 태반이 자궁 하부에 착상하여 자궁경부 내구를 부분 또는 완전히 덮는 상태로, 아이의 귀 모양 등 신체적 특징과는 전혀 관련이 없습니다. 주요 위험 요인으로는 이전 제왕절개술, 자궁 수술력, 고령 임산부, 다태 임신, 흡연, 전치 태반 과거력 등이 있습니다. 정확한 정보와 임신 관리는 산부인과 전문의와 상담하시기 바랍니다.', 2610, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '전치 태반', '전치태반', 'DEFINITION', '전치 태반은 태반이 자궁 하부에 위치하여 자궁경부 내구를 가리는 상태로, 정확한 원인은 명확하지 않으나 이전 자궁 수술, 자궁내막 손상, 고령 임산부 등이 위험 요인입니다. 흡연은 태반 발달에 영향을 미쳐 전치 태반의 위험을 증가시키는 것으로 알려져 있습니다. 임신 중 금연은 전치 태반을 포함한 다양한 임신 합병증 예방을 위해 매우 중요합니다.', 2611, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '전치 태반', '전치태반', 'SYMPTOM', '전치 태반에서 자궁경관이 부분 또는 완전히 덮인 상태에서는 임신 후반기에 통증 없는 선홍색 질 출혈이 갑자기 나타나는 것이 가장 특징적인 증상입니다. 출혈은 반복적으로 발생할 수 있으며, 태반 조기 박리가 동반되면 통증이 나타날 수 있습니다. 임신 중 이러한 출혈이 있다면 즉시 산부인과 응급 진료를 받으시기 바랍니다.', 2612, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '전치 태반', '전치태반', 'DIAGNOSIS', '전치 태반 확인을 위해서는 질식 초음파 검사가 가장 정확하며, 태반의 위치와 자궁경부와의 관계를 평가합니다. 출혈, 복통, 자궁 수축 등의 증상이 있을 때 초음파로 전치 태반 여부를 확인할 수 있으며, 임신 중기 이후 시행한 초음파에서 더 정확한 진단이 가능합니다. 해당 증상이 있다면 즉시 산부인과 응급 진료를 받으시기 바랍니다.', 2613, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '전치 태반', '전치태반', 'TREATMENT', '전치 태반으로 인한 출혈을 예방하기 위해서는 성관계와 심한 신체 활동을 피하고 안정을 취하는 것이 중요합니다. 전치 태반이 진단된 경우 정기적인 초음파 추적 관찰이 필요하며, 출혈이 발생하면 즉시 입원하여 산모와 태아 상태를 면밀히 모니터링합니다. 분만은 일반적으로 제왕절개술로 계획하며, 구체적인 관리 방법은 산부인과 전문의와 상담하여 결정하시기 바랍니다.', 2614, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 양막 파열', '조기양막파열', 'CHECKUP', '임신 말기에 질에서 액체가 나오는 경우 조기 양막 파열(PROM)을 의심할 수 있으며, 확인을 위해 산부인과에서 질 검진과 양수 여부 확인 검사(니트라진 검사, 양치 모양 결정 검사, 양수 내 단백질 검사)를 시행합니다. 최근에는 양수 특이 단백질(PAMG-1, IGFBP-1)을 이용한 신속 진단 키트도 활용됩니다. 이러한 증상이 있다면 즉시 산부인과 응급 진료를 받으시기 바랍니다.', 2615, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 양막 파열', '조기양막파열', 'MEDICATION', '조기 양막 파열 치료에는 감염 예방을 위한 항생제(암피실린, 아지트로마이신 등)가 사용되며, 조산 예방을 위한 자궁수축억제제(리토드린, 아토시반 등)와 태아 폐 성숙 촉진을 위한 코르티코스테로이드(베타메타손)도 투여됩니다. 항생제는 융모양막염 예방에 효과적이나, 자궁수축억제제는 일시적 효과만 기대하며 부작용(빈맥, 저혈당 등)이 있을 수 있습니다. 모든 약물 치료는 산부인과 전문의의 지도 하에 이루어져야 합니다.', 2616, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 양막 파열', '조기양막파열', 'PREVENTION', '임신 초기 요가 운동은 스트레스 감소와 골반저 근육 강화에 도움이 될 수 있으나, 조기 양막 파열을 직접적으로 예방하는 효과는 제한적입니다. 조기 양막 파열 예방을 위해서는 금연, 감염 예방(질염 조기 치료), 균형 잡힌 영양 섭취, 무리한 신체 활동 자제가 더 중요합니다. 임신 중 운동 방법과 강도는 산부인과 전문의와 상의하여 안전하게 진행하시기 바랍니다.', 2617, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 양막 파열', '조기양막파열', 'CAUSE', '조기 양막 파열(PROM)은 진통 시작 전에 양막이 파열되는 상태로, 주요 원인으로는 생식기 감염(세균성 질증, 성병 등), 자궁경부 무력증, 다태 임신, 양수 과다증, 흡연, 이전 조기 양막 파열 병력 등이 있습니다. 파열은 자연적으로 또는 약한 자궁 수축, 물리적 충격 등으로 발생할 수 있으며, 임신 주수에 관계없이 발생 가능합니다. 이러한 증상이 있다면 즉시 산부인과 응급 진료를 받으시기 바랍니다.', 2618, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 양막 파열', '조기양막파열', 'DEFINITION', '맑은 액체가 지속적으로 질에서 흘러나오면 조기 양막 파열을 의심해야 하며, 이는 응급 상황이므로 즉시 산부인과 응급실을 방문해야 합니다. 자의로 판단하거나 지체하지 말고 빠르게 의료 기관으로 이동하며, 이동 시 누운 자세를 유지하는 것이 좋습니다. 조기 양막 파열 후 치료 지연 시 감염, 탯줄 탈출, 태아 압박 등 심각한 합병증이 발생할 수 있습니다.', 2619, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 양막 파열', '조기양막파열', 'SYMPTOM', '조기 양막 파열의 주요 증상으로는 갑자기 또는 지속적으로 맑은(혹은 약간 혼탁한) 액체가 질에서 흘러나오는 것이 가장 특징적입니다. 그 외에 골반 압박감, 경미한 자궁 수축, 또는 질 내 습한 느낌이 동반될 수 있습니다. 임신 중 위와 같은 증상이 나타나면 즉시 산부인과 응급 진료를 받으시기 바랍니다.', 2620, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 양막 파열', '조기양막파열', 'DIAGNOSIS', '조기 양막 파열(PROM)은 규칙적인 자궁 수축(진통) 시작 전에 양막이 파열되어 양수가 흘러나오는 상태입니다. 만삭(37주 이후)에 발생하면 만삭 조기 양막 파열, 37주 이전이면 미숙아 조기 양막 파열(pPROM)로 분류됩니다. 질에서 액체가 지속적으로 흐른다면 양수, 소변, 질 분비물 등을 감별해야 하므로 즉시 산부인과를 방문하여 정확한 진단을 받으시기 바랍니다.', 2621, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 양막 파열', '조기양막파열', 'TREATMENT', '조기 양막 파열의 치료는 임신 주수와 태아 상태에 따라 달라집니다. 만삭에 가까운 경우 분만을 유도하거나 제왕절개를 시행하며, 미숙아 조기 양막 파열의 경우 입원 후 안정, 항생제 투여, 코르티코스테로이드 투여, 태아 상태 모니터링을 통해 분만 시기를 결정합니다. 양수가 지속적으로 흐르는 경우 자가 처치 없이 즉시 산부인과 응급 진료를 받으시기 바랍니다.', 2622, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 진통', '조기진통', 'CAUSE', '조기 진통의 원인은 복합적이며, 심한 정신적 스트레스는 코르티솔과 카테콜아민 분비를 증가시켜 자궁 수축을 촉진하고 조기 진통의 위험을 높일 수 있습니다. 그 외 원인으로는 생식기 감염, 자궁경부 무력증, 다태 임신, 양수 과다증, 이전 조산 병력 등이 있습니다. 임신 중 스트레스 관리와 정기적인 산전 진찰이 조기 진통 예방에 중요합니다.', 2623, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 진통', '조기진통', 'DEFINITION', '조기 진통 예방을 위해서는 금연, 과도한 신체 활동 자제, 충분한 수분 섭취, 스트레스 관리, 균형 잡힌 영양 섭취가 중요합니다. 생식기 감염이 있다면 조기에 치료받고, 자궁경부 길이 감소나 무력증이 있는 경우 전문의와 상의하여 예방적 처치를 받는 것이 필요합니다. 조기 진통 위험이 있는 경우 정기적인 산전 진찰을 통해 면밀한 모니터링을 받으시기 바랍니다.', 2624, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 진통', '조기진통', 'SYMPTOM', '조기 진통의 증상으로는 규칙적인 자궁 수축(10분 간격 이내), 요통, 골반 압박감, 생리통 같은 복통 외에도 질 분비물 증가 또는 성상 변화, 소량의 질 출혈(이슬), 양막 파열감 등이 나타날 수 있습니다. 임신 30주에 지속적인 요통과 함께 이러한 증상이 동반된다면 즉시 산부인과 응급 진료를 받으시기 바랍니다.', 2625, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 진통', '조기진통', 'DIAGNOSIS', '조기 진통이 의심될 때는 즉시 산부인과를 방문하거나 응급실로 이동하는 것이 가장 중요합니다. 산부인과 전문의는 자궁 수축 모니터링, 자궁경부 내진, 초음파 검사(자궁경부 길이 측정) 등을 통해 조기 진통 여부를 진단할 수 있습니다. 예정일이 남아 있더라도 조기 진통은 언제든 발생할 수 있으므로 지체 없이 전문의 진료를 받으시기 바랍니다.', 2626, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 진통', '조기진통', 'TREATMENT', '조기 진통에서 약물치료를 피하고 싶다면 입원하여 안정을 취하고 수액을 공급하는 방법이 보조적으로 시도될 수 있습니다. 그러나 자궁 수축이 지속된다면 태아와 산모의 안전을 위해 약물치료(자궁수축억제제)가 불가피한 경우가 많습니다. 조기 진통의 치료 방향은 임신 주수와 상태에 따라 다르므로 반드시 산부인과 전문의의 판단에 따르시기 바랍니다.', 2627, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 폐경', '조기폐경', 'MEDICATION', '조기 폐경 치료에 사용되는 호르몬 대체 요법(에스트로겐 단독 또는 프로게스틴 병합)은 증상 완화에 효과적이며, 일반적으로 자연 폐경 연령(약 50세)까지 지속하는 것을 권장합니다. 그러나 호르몬 요법이 증상을 ''완전히 사라지게'' 하지는 않으며, 복용을 중단하면 증상이 재발할 수 있습니다. 약물의 종류, 용량, 복용 기간은 산부인과 또는 내분비내과 전문의와 상담하여 개인에 맞게 결정하시기 바랍니다.', 2628, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 폐경', '조기폐경', 'CAUSE', '조기 폐경의 선천적 원인으로는 터너증후군 등 염색체 이상, FMR1 유전자 변이(취약 X 증후군 보인자), 갈락토스혈증 등 유전 질환이 있습니다. 후천적 원인으로는 자가면역질환, 항암화학요법, 방사선 치료, 난소 수술, 감염 등이 있습니다. 두 원인을 감별하려면 염색체 검사, 자가면역 항체 검사, 유전자 검사 등을 시행하며, 산부인과 또는 내분비내과 전문의와 상담하시기 바랍니다.', 2629, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 폐경', '조기폐경', 'DEFINITION', '조기 폐경은 40세 이전에 난소 기능이 저하되어 에스트로겐 분비가 감소하고 생리가 불규칙해지거나 중단되는 상태입니다. 주요 증상으로는 생리 불규칙 또는 무월경, 안면 홍조, 야간 발한, 질 건조증, 성욕 감퇴, 피로감, 감정 기복 등이 있습니다. 혈액 검사에서 FSH 상승과 에스트라디올 감소가 확인되면 조기 폐경을 진단할 수 있으며, 전문의 상담을 권장합니다.', 2630, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 폐경', '조기폐경', 'SYMPTOM', '월경 불규칙, 성욕 감퇴, 감정 기복은 조기 폐경의 증상과 일치할 수 있습니다. 그러나 이러한 증상은 갑상선 기능 이상, 다낭성 난소증후군, 우울증 등 다른 질환에서도 나타날 수 있으므로 혈액 검사(FSH, 에스트라디올, AMH 등)를 통해 정확한 감별이 필요합니다. 증상이 지속된다면 산부인과 또는 내분비내과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 2631, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 폐경', '조기폐경', 'DIAGNOSIS', '성관계와 무관하게 수개월간 생리가 없고 성욕 감퇴가 동반된다면 조기 폐경, 다낭성 난소증후군, 갑상선 기능 이상, 뇌하수체 이상 등 다양한 원인을 고려해야 합니다. 폐경 진단을 위해서는 FSH, 에스트라디올, AMH 혈액 검사와 함께 임신 여부 확인이 선행되어야 합니다. 정확한 진단을 위해 산부인과 또는 내분비내과 전문의를 방문하시기 바랍니다.', 2632, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조기 폐경', '조기폐경', 'TREATMENT', '조기 폐경 시 호르몬 치료 외에도 규칙적인 유산소 운동과 근력 운동으로 골밀도 유지와 심혈관 건강 증진에 도움이 됩니다. 칼슘과 비타민 D가 풍부한 식단, 금연, 절주, 스트레스 관리도 중요하며, 사회적 지지와 심리 상담도 정서적 건강 유지에 도움이 됩니다. 생활 습관 개선과 함께 정기적인 전문의 추적 관리를 받으시기 바랍니다.', 2633, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조산', '조산', 'CHECKUP', '양수가 터진 것으로 의심된다면 즉시 119에 연락하거나 가까운 산부인과 응급실을 방문하는 것이 가장 중요합니다. 병원 도착 후 질 분비물 검사, 초음파 검사, 태아 심박 모니터링 등을 통해 조산 여부와 태아 상태를 평가합니다. 자의로 판단하거나 지체하지 말고 즉시 의료 기관을 방문하시기 바랍니다.', 2634, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조산', '조산', 'DIET_LIFE', '조산 예방을 위해서는 금연, 금주, 규칙적인 산전 검진, 충분한 수분 섭취, 균형 잡힌 영양 섭취(엽산, 철분, 칼슘 등)가 중요합니다. 생식기 감염이 있다면 조기 치료를 받고, 과도한 신체 활동과 스트레스를 줄이는 것도 도움이 됩니다. 이전에 조산 경험이 있다면 임신 초기부터 산부인과 전문의와 긴밀히 상담하여 관리 계획을 세우시기 바랍니다.', 2635, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조산', '조산', 'MEDICATION', '조산 방지를 위해 자궁수축억제제로 리토드린(베타 작용제), 아토시반(옥시토신 수용체 차단제), 마그네슘황산염, 니페디핀(칼슘 채널 차단제) 등이 사용됩니다. 또한 태아 폐 성숙을 위해 코르티코스테로이드(베타메타손)를 투여하며, 감염 예방을 위한 항생제도 사용됩니다. 약물 선택과 투여 방법은 임신 주수와 산모 상태에 따라 산부인과 전문의가 결정합니다.', 2636, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조산', '조산', 'PREVENTION', '임신 20주에 조산 위험이 있다는 의사의 말은 현재 태아가 충분히 성숙하지 않은 상태에서 조기 분만이 발생할 위험성이 있다는 의미입니다. 임신 20~22주 이전의 조산은 태아 생존 가능성이 매우 낮으며, 이후 주수가 증가할수록 태아 예후가 좋아집니다. 조산 위험 요인을 최소화하기 위해 산부인과 전문의의 지시에 따라 안정과 치료를 받으시기 바랍니다.', 2637, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조산', '조산', 'CAUSE', '이전 조산 경험은 다음 임신에서 조산이 반복될 위험을 높이는 가장 강력한 위험 요인 중 하나입니다. 이는 자궁경부 무력증, 자궁 구조 이상, 만성 감염, 또는 면역학적 요인 등 근본적인 원인이 해결되지 않았을 가능성이 있기 때문입니다. 이전 조산 경험이 있다면 임신 전부터 산부인과 전문의와 상담하여 원인 분석과 예방 계획을 세우는 것이 중요합니다.', 2638, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조산', '조산', 'DEFINITION', '조산은 임신 37주 미만에 분만하는 경우를 말하며, 임신 주수에 따라 극조산(28주 미만), 조산(28~32주), 후기 조산(32~36주+6일)으로 분류됩니다. 임신성 고혈압 등 합병증으로 인한 조산도 동일한 기준이 적용됩니다. 조산의 주수와 원인에 따라 신생아 예후가 다르므로, 산부인과 전문의의 지속적인 관리가 중요합니다.', 2639, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조산', '조산', 'SYMPTOM', '임신 10개월(40주) 이전에 생리통과 유사한 복통이 규칙적으로 반복된다면 조산의 증상일 가능성이 있습니다. 특히 임신 37주 이전에 10분 이내 간격의 자궁 수축, 하복부 통증, 요통, 질 출혈이나 분비물 증가가 동반된다면 조산 진통을 의심해야 합니다. 이러한 증상이 있다면 즉시 산부인과 응급 진료를 받으시기 바랍니다.', 2640, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조산', '조산', 'DIAGNOSIS', '조산 진단은 임신 37주 미만에 규칙적인 자궁 수축과 함께 자궁경부 개대(1cm 이상) 또는 소실이 확인될 때 내려집니다. 출생 체중이 낮은 것은 조산의 결과이지 진단 기준이 아니며, 재태 주수가 조산의 핵심 기준입니다. 조산이 의심될 경우 산부인과에서 태아 심박 모니터링, 초음파, 자궁경부 검사 등을 통해 정확한 평가를 받아야 합니다.', 2641, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '조산', '조산', 'TREATMENT', '자궁경부 길이가 짧은 경우 프로게스테론 질정 투여나 자궁경부 봉합술(맥도날드 술식)이 조산 예방에 효과적입니다. 양수 상태가 좋지 않다면 원인에 따라 항생제 투여, 안정 및 수분 공급, 자궁수축억제제 등의 치료를 병행합니다. 구체적인 치료 계획은 산부인과 전문의와의 긴밀한 상담을 통해 개인 상태에 맞게 결정하시기 바랍니다.', 2642, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태반 조기 박리', '태반조기박리', 'CHECKUP', '태반 조기 박리가 의심될 경우 즉각적인 산부인과 진료가 필요하며, 복부 초음파 검사로 태반 뒤 혈종(혈액 고임) 유무를 확인합니다. 태아 심박 모니터링(NST)을 통해 태아 상태를 평가하고, 혈액 검사(CBC, 응고 검사)로 출혈 정도와 DIC(파종성 혈관 내 응고증) 여부를 확인합니다. 증상이 있다면 즉시 산부인과 응급 진료를 받으시기 바랍니다.', 2643, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태반 조기 박리', '태반조기박리', 'MEDICATION', '태반 조기 박리의 치료는 응급 상황이 많아 즉각적인 처치가 우선이며, 약물 치료보다는 분만(유도 분만 또는 제왕절개)이 주된 치료입니다. 태반 조기 박리 관련 약물(자궁수축제, 혈액 응고 제제 등)의 부작용과 안전성 정보는 담당 산부인과 전문의에게 직접 문의하거나, 처방된 약물의 의약품 설명서 및 의약품안전나라(식품의약품안전처 운영) 등을 통해 확인할 수 있습니다.', 2644, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태반 조기 박리', '태반조기박리', 'PREVENTION', '금연, 금주, 혈압 조절, 적절한 체중 유지가 태반 조기 박리 예방에 중요합니다. 임신 중 복부 외상을 피하고 과도한 신체 활동을 자제하며, 코카인 등 불법 약물 사용을 금해야 합니다. 정기적인 산전 검진을 통해 고혈압과 자궁 이상을 조기에 발견하는 것이 중요합니다.', 2645, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태반 조기 박리', '태반조기박리', 'EXERCISE', '태반 조기 박리가 있는 경우 임신 초기에 요가 등의 운동은 출혈이나 태반 추가 박리를 유발할 위험이 있어 원칙적으로 권장되지 않습니다. 복압을 높이는 동작이나 자궁에 압력을 가하는 자세는 태반 박리를 악화시킬 수 있습니다. 반드시 산부인과 전문의와 상담 후 안전한 활동 범위를 결정하시기 바랍니다.', 2646, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태반 조기 박리', '태반조기박리', 'CAUSE', '고령 임산부는 만성 고혈압, 자궁혈관 동맥경화, 당뇨병 등 혈관질환 위험이 높아 태반 조기 박리 위험이 증가합니다. 노화에 따른 혈관 탄력 저하와 자궁-태반 혈류 감소가 태반과 자궁벽 사이의 결합을 약화시킬 수 있습니다. 고령 임산부는 정기적인 산전 검진과 혈압 관리를 철저히 해야 합니다.', 2647, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태반 조기 박리', '태반조기박리', 'DEFINITION', '임신 중 갑작스러운 질출혈과 복통이 동반되면 태반 조기 박리를 의심하고 즉시 응급실을 방문해야 합니다. 자가 처치나 이동을 최소화하고, 누운 자세를 유지하며 빠르게 전문 의료기관으로 이송하는 것이 중요합니다. 태반 조기 박리는 산모와 태아 모두에게 생명을 위협할 수 있는 응급 상황으로, 지체 없는 산부인과 전문의 진료가 필요합니다.', 2648, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태반 조기 박리', '태반조기박리', 'SYMPTOM', '태반 조기 박리의 주요 증상으로는 갑작스러운 질출혈(무통 또는 동반 통증), 복부 또는 등의 심한 통증, 자궁 수축, 자궁 압통 등이 나타납니다. 태아의 심박수 이상, 태아 가사 징후가 나타날 수 있으며 심한 경우 응고장애로 인한 쇼크가 발생할 수 있습니다. 출혈이 자궁 내부에 갇혀 외부로 나오지 않는 은폐 출혈도 가능하므로, 복통이 심하면 즉시 병원을 찾아야 합니다.', 2649, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태반 조기 박리', '태반조기박리', 'DIAGNOSIS', '초음파 검사는 태반 조기 박리 진단에 보조적으로 사용되지만 민감도가 약 25~50% 정도로 낮아 초음파 정상 소견이 박리를 완전히 배제하지는 못합니다. 임상 증상(출혈, 복통, 자궁 긴장)과 함께 혈액 응고 검사, CTG(태아 심박 모니터링) 등을 병행하여 종합적으로 진단합니다. 태반 조기 박리가 의심되면 산부인과 전문의의 즉각적인 진료가 필요합니다.', 2650, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태반 조기 박리', '태반조기박리', 'TREATMENT', '만삭 임산부의 태반 조기 박리는 즉각적인 분만이 가장 중요한 치료로, 태아와 산모 상태에 따라 제왕절개 또는 질식 분만을 결정합니다. 분만 전까지 정맥 수액 공급, 수혈, 산소 투여 등 산모 상태를 안정시키는 처치를 병행합니다. 이는 응급 상황이므로 지체 없이 분만 가능한 산부인과 전문의료기관으로 이송해야 합니다.', 2651, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태아 알코올 증후군', '태아알코올증후군', 'CHECKUP', '태아 알코올 증후군 진단을 위해 신생아의 안면 기형(얇은 윗입술, 인중 평탄화, 짧은 눈꺼풀 간격) 확인, 성장 지표, 중추신경계 이상 평가를 포함한 신체 검진이 우선 이루어집니다. 산모의 임신 중 음주력 확인이 필수적이며, 신경발달 평가, 뇌 영상검사(MRI), 청각 및 시력 검사 등도 시행합니다. 소아청소년과 전문의, 신경과, 유전상담 등 다학제적 접근이 필요합니다.', 2652, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태아 알코올 증후군', '태아알코올증후군', 'MEDICATION', '임신 중 알코올과 함께 특정 약물을 병용하면 태아 독성이 증가할 수 있으며, 특히 항경련제(발프로산, 페니토인), 항불안제(벤조디아제핀류), 일부 항생제, 레티노이드(비타민A 유도체)가 태아 기형 위험을 높입니다. 알코올 자체가 중추신경계 독성 물질로 약물과의 상호작용 없이도 태아 알코올 스펙트럼 장애를 유발할 수 있습니다. 임신 중 약물 복용은 반드시 산부인과 전문의와 상담 후 결정해야 합니다.', 2653, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태아 알코올 증후군', '태아알코올증후군', 'PREVENTION', '임신 중 알코올 섭취는 양과 시기에 무관하게 태아 알코올 증후군의 직접적 원인이 되며, 알코올을 분해하는 효소 활성이 낮은 태아는 더 큰 손상을 받습니다. 임신 초기 기관 형성기와 뇌 발달이 활발한 시기에 특히 위험하며, 유전적 요인, 영양 상태, 산모의 건강 상태가 위험도에 영향을 줍니다. 가장 확실한 예방법은 임신 중 완전한 금주이며, 음주 중단 시점에 대해 산부인과 전문의와 상담하시기 바랍니다.', 2654, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태아 알코올 증후군', '태아알코올증후군', 'CAUSE', '태아 알코올 증후군의 직접적 원인은 임신 중 산모의 알코올 섭취로, 알코올과 그 대사물질(아세트알데히드)이 태반을 통해 태아에게 전달됩니다. 산모에게 알코올 의존증이나 간질환이 있으면 알코올 대사가 더 비효율적으로 이루어져 태아 노출량이 증가할 수 있습니다. 올케의 간 기능 상태, 영양 결핍, 기저 질환 등이 알코올의 태아 독성 정도에 영향을 줄 수 있으므로, 산부인과 전문의 상담을 권합니다.', 2655, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태아 알코올 증후군', '태아알코올증후군', 'REHAB', '태아 알코올 증후군 환자의 재활을 위해 언어치료, 작업치료, 물리치료, 인지행동치료 등 다각적 접근이 권장됩니다. 학습장애와 행동문제에 대해 특수교육 프로그램과 사회기술 훈련이 도움이 되며, 부모 및 양육자 교육도 중요한 재활 요소입니다. 개인별 결핍 영역에 맞춘 맞춤형 재활 계획 수립을 위해 소아청소년 정신건강의학과 및 재활의학과 전문의 상담을 권장합니다.', 2656, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태아 알코올 증후군', '태아알코올증후군', 'DEFINITION', '태아 알코올 증후군은 임신 중 어머니의 알코올 섭취로 인해 태아가 알코올에 노출되어 발생하는 선천성 장애입니다. 특징적인 안면 기형(얇은 윗입술, 짧은 눈꺼풀 간격, 편평한 인중), 성장 장애, 중추신경계 이상(지적장애, 학습장애, 행동문제)이 주요 증상입니다. 완치가 어려운 영구적 장애로, 임신 중 완전한 금주가 유일한 예방법입니다.', 2657, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태아 알코올 증후군', '태아알코올증후군', 'SYMPTOM', '임신 중 알코올 섭취 자체가 태아 알코올 증후군의 원인이지 산모에게 나타나는 증상은 아닙니다. 산모에게는 알코올 의존에 따른 금단 증상, 간 기능 이상, 영양 결핍 등이 나타날 수 있으며, 이는 태아에게도 간접적으로 영향을 줍니다. 임신 중 음주를 하고 있다면 즉시 중단하고 산부인과 전문의와 태아 건강 상태에 대해 상담하시기 바랍니다.', 2658, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태아 알코올 증후군', '태아알코올증후군', 'DIAGNOSIS', '태아 알코올 증후군은 출생 후 임상 진단이 원칙으로, 산전 양수검사로는 직접 진단할 수 없습니다. 태아 초음파로 성장 지연이나 구조적 이상을 확인할 수 있으나 확진은 어렵습니다. 출생 후 안면 특징, 성장 지표, 신경발달 평가, 산모의 음주력을 종합하여 소아청소년과 및 유전의학과 전문의가 진단을 내립니다.', 2659, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '태아 알코올 증후군', '태아알코올증후군', 'TREATMENT', '태아 알코올 증후군 치료는 산부인과보다는 소아청소년과를 중심으로 이루어지며, 신경과, 정신건강의학과, 재활의학과, 특수교육 전문가의 다학제적 협력이 필요합니다. 동반된 심장 기형, 청력 및 시력 문제는 해당 전문과에서 별도로 치료받아야 합니다. 증상이 다양하고 복합적이므로 환자의 필요에 따라 여러 전문과가 협력하는 통합 치료 접근이 가장 효과적입니다.', 2660, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '폐경', '폐경', 'MEDICATION', '폐경기 호르몬 대체요법(HRT)은 난소 기능 저하로 감소한 에스트로겐과 프로게스테론을 외부에서 보충하여 폐경 증상(안면홍조, 질건조증, 골다공증 예방 등)을 완화하는 치료입니다. 이는 폐경된 난소가 다시 호르몬을 생성하도록 하는 것이 아니라, 외부 호르몬을 공급하여 부족분을 보상하는 원리입니다. 호르몬 대체요법은 유방암, 혈전 위험 등 부작용이 있을 수 있으므로 반드시 산부인과 전문의와 상담 후 시행해야 합니다.', 2661, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '폐경', '폐경', 'CAUSE', '과도한 운동 자체는 폐경을 직접 유발하지 않으나, 극단적인 저체중이나 에너지 부족을 동반한 과도한 운동(운동성 시상하부성 무월경)은 성선자극호르몬 분비를 억제하여 난소 기능을 저하시킬 수 있습니다. 이는 조기 난소 기능 부전이나 기능성 무월경의 원인이 될 수 있으며, 운동으로 인한 급격한 체지방 감소가 에스트로겐 생성에 영향을 줍니다. 운동량과 월경 변화의 관계에 대해 산부인과 전문의 진료를 받아 보시기 바랍니다.', 2662, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '폐경', '폐경', 'DEFINITION', '폐경 여부를 확인하기 위해 혈중 FSH(난포자극호르몬), LH(황체형성호르몬), 에스트라디올 수치를 측정하는 혈액 검사가 기본적으로 시행됩니다. FSH가 40 mIU/mL 이상이고 에스트라디올이 낮으면 폐경으로 진단하며, AMH(항뮐러관호르몬) 검사도 난소 예비능 평가에 도움이 됩니다. 산부인과에서 생리력 청취와 함께 이러한 검사들을 받아 정확한 진단을 받으시기 바랍니다.', 2663, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '폐경', '폐경', 'SYMPTOM', '불규칙한 생리 주기는 폐경 전환기(폐경이행기)의 대표적인 징후로, 혈중 FSH, 에스트라디올, AMH 검사를 통해 호르몬 변화를 확인할 수 있습니다. 갑상선 기능 이상, 다낭성 난소증후군 등도 생리 불규칙의 원인이 될 수 있으므로 갑상선 기능 검사도 함께 고려합니다. 산부인과 전문의 진료를 통해 정확한 원인을 감별하고 필요한 검사를 받으시기 바랍니다.', 2664, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '폐경', '폐경', 'DIAGNOSIS', '폐경 진단은 주로 임상적으로 이루어지며, 12개월 이상 생리가 없는 경우 폐경으로 진단합니다. 필요시 혈중 FSH, 에스트라디올 수치 측정으로 확인하며, 산부인과 또는 내분비내과에서 진단 가능합니다. 조기 폐경이나 다른 질환이 의심되는 경우 추가 검사가 필요하므로 전문의 상담을 권합니다.', 2665, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '폐경', '폐경', 'TREATMENT', '폐경 전후 안면홍조 치료로 호르몬 대체요법이 가장 효과적이며, 금기증이 없는 경우 에스트로겐 단독 또는 프로게스틴 병합 요법을 사용합니다. 호르몬 치료가 어려운 경우 SSRI/SNRI 계열 약물, 가바펜틴, 클로니딘 등 비호르몬 치료제를 고려할 수 있습니다. 치료 방법의 선택은 개인의 건강 상태와 금기증에 따라 달라지므로 산부인과 전문의와 상담하시기 바랍니다.', 2666, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '회음 열상', '회음열상', 'CAUSE', '회음 열상은 분만 시 태아가 통과하면서 회음부 조직이 찢어지는 것으로, 주요 원인은 급속 분만, 큰 태아, 후두 후방 위치, 회음부 신축성 감소 등입니다. 통증 완화를 위해 냉찜질(초기 24~48시간), 진통제 복용, 좌욕, 청결 유지가 도움이 됩니다. 열상 정도에 따라 봉합이 필요할 수 있으므로 산부인과 전문의의 평가가 중요합니다.', 2667, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '회음 열상', '회음열상', 'DEFINITION', '회음 열상은 자연 분만 중 태아의 머리가 회음부를 통과할 때 주로 발생하며, 제왕절개 분만에서는 발생하지 않습니다. 자연 분만 시 회음부 조직의 신장 한계를 초과할 때 피부, 근육, 항문 괄약근, 직장 점막 등이 단계적으로 찢어질 수 있습니다. 회음부 마사지, 분만 속도 조절 등으로 예방을 시도할 수 있으며 심한 열상은 수술적 봉합이 필요합니다.', 2668, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '회음 열상', '회음열상', 'SYMPTOM', '분만 중 회음 열상이 발생하면 분만 팀이 즉시 출혈량을 평가하고 열상 정도(1~4도)를 확인합니다. 1~2도 열상은 자연 치유되기도 하나 대부분 봉합술이 필요하며, 3~4도 열상(항문 괄약근, 직장 점막 포함)은 즉각적인 수술적 봉합이 필요합니다. 주요 증상으로는 회음부 통증, 출혈, 배변 또는 배뇨 시 불편감, 심한 경우 변실금이 나타날 수 있습니다.', 2669, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '회음 열상', '회음열상', 'DIAGNOSIS', '아이의 머리가 크다는 것 자체가 회음 열상의 원인이 될 수 있으나, 출산 후 아이 머리 크기는 열상과 직접적 인과관계보다는 분만 당시 상황이 중요합니다. 회음 열상 진단은 분만 직후 산부인과 전문의가 시각적 확인과 신체 검진으로 이루어지며, 별도의 영상 검사 없이도 진단 가능합니다. 항문 괄약근 손상이 의심되는 경우 항문 초음파나 항문 내압 검사가 추가로 필요할 수 있습니다.', 2670, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '회음 열상', '회음열상', 'TREATMENT', '분만 후 회음 열상으로 인한 통증과 부기 완화를 위해 초기 24~48시간은 아이스팩 냉찜질이 효과적이며, 이후에는 따뜻한 좌욕이 혈액 순환을 촉진합니다. 진통제(아세트아미노펜, 이부프로펜)를 정기적으로 복용하고, 회음 청결 유지와 항문 압력을 줄이는 변비 예방도 중요합니다. 증상이 심하거나 지속되면 산부인과 전문의를 방문하여 적절한 치료를 받으시기 바랍니다.', 2671, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갈색세포종', '갈색세포종', 'CAUSE', '갈색세포종 발생에는 유전적 요인과 산발적 요인이 모두 관여하며, 약 30~40%는 유전성으로 RET, VHL, NF1, SDHB/C/D 등의 유전자 변이와 관련됩니다. 나머지 60~70%는 특별한 유전적 원인 없이 산발적으로 발생하며, 명확한 환경적 원인은 아직 밝혀지지 않았습니다. 유전성이 의심되는 경우 유전상담 및 유전자 검사를 내분비내과 전문의와 상담하는 것을 권장합니다.', 2672, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갈색세포종', '갈색세포종', 'DEFINITION', '갈색세포종은 부신 수질이나 부교감신경절에서 발생하는 종양으로, 카테콜아민(에피네프린, 노르에피네프린)을 과다 분비하는 것이 특징입니다. 주요 증상으로는 발작적 고혈압, 심한 두통, 발한, 심계항진, 창백함의 3대 증상과 함께 불안, 체중 감소 등이 나타납니다. 드물지만 악성 변환이 가능하며, 고혈압 합병증으로 심혈관계 위험이 높으므로 내분비내과 전문의의 진료가 필요합니다.', 2673, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갈색세포종', '갈색세포종', 'SYMPTOM', '갈색세포종의 전형적인 증상은 발작적 고혈압, 심한 두통, 발한, 심계항진이며, 식욕 감소와 체중 감소도 나타날 수 있습니다. 어지럼증과 기립성 저혈압도 발생할 수 있으나 시력 저하가 직접적인 갈색세포종 증상은 아닙니다. 이러한 증상들이 복합적으로 나타난다면 내분비내과 전문의를 방문하여 혈중/소변 카테콜아민 검사를 받아보시기 바랍니다.', 2674, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갈색세포종', '갈색세포종', 'DIAGNOSIS', '방광 갈색세포종 진단을 받은 경우, 다른 병원 방문 시 이전 검사 결과(혈중·소변 카테콜아민 수치, CT/MRI 영상, 조직검사 결과)와 의무기록을 지참하는 것이 중요합니다. 현재 복용 중인 약물 목록(특히 알파 차단제 등 혈압약)을 명시하고, 가족력과 관련 유전자 검사 결과도 함께 제공하면 도움이 됩니다. 전이 여부 확인을 위한 MIBG 스캔이나 PET 결과도 있다면 함께 가져가시기 바랍니다.', 2675, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갈색세포종', '갈색세포종', 'TREATMENT', '갈색세포종의 표준 치료는 종양의 외과적 절제(복강경 또는 개복 부신절제술)이며, 수술 전 2~4주간 알파 차단제(페녹시벤자민, 독사조신)로 혈압을 안정시키는 것이 필수적입니다. 수술 전 충분한 혈압 조절 없이 수술 시 고혈압 위기가 발생할 수 있습니다. 전이성 갈색세포종의 경우 MIBG 치료, 화학요법, 방사선 치료 등을 고려하며, 내분비내과 및 외과 전문의와 협력 치료가 필요합니다.', 2676, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선 결절', '갑상선결절', 'CAUSE', '갑상선 결절 진단 후 결절의 악성 여부를 정기적으로 추적 관찰하고, 크기 변화나 새로운 증상(연하 곤란, 목 통증, 목쉼) 발생 시 즉시 병원을 방문해야 합니다. 방사성 요오드 노출을 피하고, 과도한 요오드 섭취나 결핍 모두 갑상선 기능에 영향을 줄 수 있으므로 균형 잡힌 식단을 유지하는 것이 중요합니다. 정기적인 갑상선 초음파와 갑상선 기능 검사를 통해 내분비내과 또는 이비인후과 전문의의 지속적인 관리를 받으시기 바랍니다.', 2677, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선 결절', '갑상선결절', 'DEFINITION', '갑상선 결절은 갑상선 조직 내에 생기는 종괴로, 대부분 양성이지만 일부는 악성(갑상선암)일 수 있습니다. 목소리가 갈라지는 것은 갑상선 결절이 커져 인근의 반회후두신경을 압박할 때 발생할 수 있으며, 이는 악성 결절의 신호일 수 있어 빠른 전문의 평가가 필요합니다. 초음파 유도 세침흡인세포검사(FNA)를 통해 양악성 감별이 가능하며, 이비인후과 또는 내분비내과 전문의 진료를 권장합니다.', 2678, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선 결절', '갑상선결절', 'SYMPTOM', '갑상선 결절은 갑상선 내에 생기는 덩어리로, 대부분 무증상이나 크기가 커지면 목의 전면부 돌출, 연하 곤란, 목쉼, 호흡 곤란 등이 나타날 수 있습니다. 작은 결절은 대개 증상이 없으나 갑상선 기능 항진을 유발하는 독성 결절의 경우 체중 감소, 심계항진 등이 동반될 수 있습니다. 목에 혹이 만져지면 갑상선 초음파 검사와 기능 검사를 위해 내분비내과 또는 이비인후과를 방문하시기 바랍니다.', 2679, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선 결절', '갑상선결절', 'DIAGNOSIS', '목 전면부 부종과 작은 덩어리가 만져지는 경우 갑상선 결절 평가를 위해 내분비내과, 이비인후과, 외과에서 진료를 받을 수 있습니다. 갑상선 초음파 검사는 대부분의 종합병원 및 대형 의원에서 시행 가능하며, 필요시 세침흡인세포검사(FNA)도 같은 기관에서 가능합니다. 증상이 있는 경우 지역 내과나 가정의학과를 통한 1차 진료 후 전문과 의뢰도 가능합니다.', 2680, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선 결절', '갑상선결절', 'TREATMENT', '갑상선 결절로 인한 목쉼과 호흡 곤란이 있다면 이는 결절이 기도나 신경을 압박하는 것으로 단순 약물로 해결하기 어려우며, 전문의 평가가 우선입니다. 양성 결절로 인한 압박 증상 시 알코올 절제술, 고주파 절제술, 또는 수술적 제거를 고려할 수 있습니다. 악성 가능성 배제와 적절한 치료 계획 수립을 위해 반드시 내분비내과 또는 이비인후과 전문의 진료를 받으시기 바랍니다.', 2681, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선기능저하증', '갑상선기능저하증', 'CHECKUP', '갑상선기능저하증 확인을 위해 혈중 TSH(갑상선자극호르몬), free T4(유리 사이록신) 검사가 기본이며, TSH 상승과 T4 감소 시 확진됩니다. 하시모토 갑상선염이 의심되면 갑상선 항체(TPO 항체, Tg 항체) 검사도 시행합니다. 갑상선 기능 검사는 정확한 진단과 약물 용량 조절에 사용되며, 증상 소실은 적절한 갑상선 호르몬 보충 치료 후 서서히 이루어지므로 내분비내과 전문의의 지속적인 관리가 필요합니다.', 2682, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선기능저하증', '갑상선기능저하증', 'DIET_LIFE', '갑상선기능저하증 환자는 셀레늄이 풍부한 식품(참치, 달걀, 브라질너트)이 갑상선 기능에 도움을 줄 수 있으며, 균형 잡힌 식단으로 단백질, 철분, 아연, 비타민D를 충분히 섭취하는 것이 중요합니다. 과도한 요오드 섭취는 오히려 기능 저하를 악화시킬 수 있으므로 주의가 필요하며, 갑상선 호르몬제 복용 시 커피, 고섬유 식품, 칼슘·철분 보충제는 복용 4시간 이후에 섭취해야 합니다. 영양 보충 전략은 내분비내과 전문의 또는 영양사와 상담 후 결정하시기 바랍니다.', 2683, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선기능저하증', '갑상선기능저하증', 'MEDICATION', '갑상선호르몬 제제(레보티록신)는 철분이나 칼슘 보충제와 동시에 복용하면 흡수가 크게 감소합니다. 갑상선호르몬 제제는 아침 공복에 단독 복용하고, 철분이나 칼슘 보충제는 최소 4시간 이상 간격을 두고 복용해야 합니다. 이 원칙을 지키지 않으면 갑상선 기능 조절이 어려워질 수 있으므로 내분비내과 전문의와 복용 일정에 대해 상담하시기 바랍니다.', 2684, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선기능저하증', '갑상선기능저하증', 'CAUSE', '부갑상선기능저하증 진단을 위해 혈중 칼슘(저칼슘혈증), 인(고인산혈증), PTH(부갑상선호르몬 감소) 검사가 기본입니다. 또한 마그네슘, 비타민D 수치 검사와 소변 칼슘 배설량 측정이 도움이 됩니다. 저칼슘혈증 증상(손발 저림, 경련, 테타니)이 있다면 내분비내과 전문의를 방문하여 혈액 검사로 확인하시기 바랍니다.', 2685, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선기능저하증', '갑상선기능저하증', 'DEFINITION', '부갑상선기능저하증은 부갑상선호르몬(PTH) 분비 부족으로 혈중 칼슘이 감소하는 질환으로, 갑상선 수술 후 부갑상선 손상, 자가면역, 유전적 원인 등으로 발생합니다. 손발 저림, 근육 경련(테타니), 얼굴 근육 떨림, 경련 발작 등이 저칼슘혈증으로 인한 특징적 증상입니다. 칼슘과 비타민D 보충 치료로 증상 조절이 가능하므로 내분비내과 전문의의 정확한 진단과 치료가 필요합니다.', 2686, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선기능저하증', '갑상선기능저하증', 'SYMPTOM', '갑상선기능저하증의 추가 중요 증상으로는 피로감, 추위에 민감함, 변비, 피부 건조, 탈모, 기억력 저하, 우울감, 서맥(느린 맥박) 등이 있습니다. 이 중 피로감과 추위 민감, 변비는 많은 환자에서 목쉼·부기·체중 증가보다 먼저 나타나거나 더 두드러지는 경우가 많아 임상적으로 중요합니다. 여러 증상이 복합적으로 나타난다면 내분비내과 전문의를 방문하여 갑상선 기능 검사를 받아보시기 바랍니다.', 2687, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선기능저하증', '갑상선기능저하증', 'DIAGNOSIS', '갑상선기능저하증 진단을 위해 혈중 TSH 상승과 free T4 감소를 확인하는 혈액 검사가 기본입니다. 갑상선 초음파는 갑상선 결절, 하시모토 갑상선염의 특징적 소견(불균질 에코, 섬유화), 갑상선 크기 이상을 확인하는 데 사용됩니다. 혈액 검사와 초음파를 병행하면 기능 저하의 원인을 파악하는 데 도움이 되므로 내분비내과 전문의의 종합적인 평가를 받으시기 바랍니다.', 2688, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선기능저하증', '갑상선기능저하증', 'TREATMENT', '갑상선기능저하증의 표준 치료는 연령과 무관하게 레보티록신(합성 T4) 경구 보충 요법입니다. 소아의 경우 정상 성장과 뇌 발달을 위해 적극적인 치료가 더욱 중요하며, 성인보다 체중 대비 용량이 높을 수 있습니다. 성인과 소아 모두 TSH 목표치에 따라 용량을 조절하므로 내분비내과 또는 소아내분비과 전문의의 정기적인 추적 관리가 필수적입니다.', 2689, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선기능항진증', '갑상선기능항진증', 'DIET_LIFE', '갑상선기능항진증 환자는 충분한 열량과 단백질을 섭취하여 체중 감소를 예방하고, 카페인과 알코올은 심계항진을 악화시킬 수 있으므로 피해야 합니다. 과도한 요오드 섭취(다시마, 요오드 보충제)는 갑상선 기능을 더욱 항진시킬 수 있어 주의가 필요합니다. 충분한 수면, 스트레스 관리, 금연이 도움이 되며 구체적인 식이 계획은 내분비내과 전문의와 상담하시기 바랍니다.', 2690, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선기능항진증', '갑상선기능항진증', 'MEDICATION', '메티마졸(항갑상선제) 복용 후 어지럼증과 가려움증은 약물 부작용일 가능성이 있습니다. 피부 발진과 가려움증은 비교적 흔한 부작용이며, 심한 경우 프로필티오우라실(PTU) 등 다른 약제로 교체를 고려합니다. 드물지만 무과립구증(발열, 인후통 동반) 등 심각한 부작용도 가능하므로, 증상이 지속되거나 발열이 동반되면 즉시 내분비내과 전문의를 방문하시기 바랍니다.', 2691, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선기능항진증', '갑상선기능항진증', 'CAUSE', '갑상선기능항진증 약물 복용 중 여드름 악화와 체중 증가는 갑상선 기능이 정상화 또는 저하되면서 나타나는 현상으로, 이전 항진 상태에서 억제되었던 증상들이 회복되는 과정입니다. 과교정으로 인한 갑상선기능저하증으로 체중이 증가할 수 있으며, 여드름은 호르몬 균형 변화와 관련될 수 있습니다. 증상 변화가 지속된다면 내분비내과 전문의를 방문하여 갑상선 기능 수치와 약물 용량을 재평가받으시기 바랍니다.', 2692, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선기능항진증', '갑상선기능항진증', 'DEFINITION', '식욕 증가와 체중 감소, 심계항진, 더위에 민감, 발한 증가, 손 떨림 등이 동반된다면 갑상선기능항진증을 의심할 수 있습니다. 진단을 위해 내분비내과를 방문하여 혈중 TSH, free T4, T3 검사를 받는 것이 우선입니다. 그레이브스병이 원인인 경우 안구 돌출 등의 증상도 확인해야 하므로 전문의 진료가 필요합니다.', 2693, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선기능항진증', '갑상선기능항진증', 'SYMPTOM', '갑상선기능항진증에서 체중 감소 외에도 심계항진, 빈맥, 손떨림, 과도한 발한, 더위 민감, 피로감, 근력 약화, 불안, 수면 장애, 설사, 생리 불순, 안구 돌출(그레이브스병) 등 다양한 증상이 나타납니다. 골밀도 감소로 인한 골다공증 위험도 증가하며, 고령자에서는 심방세동 등 부정맥이 주요 합병증이 될 수 있습니다. 이러한 증상이 있으면 내분비내과 전문의의 진료를 받으시기 바랍니다.', 2694, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선기능항진증', '갑상선기능항진증', 'DIAGNOSIS', '갑상선기능항진증 진단을 위한 혈액 검사에서 TSH 감소, free T4 및 T3 상승 소견을 확인합니다. 그레이브스병이 의심되는 경우 TSH 수용체 항체(TRAb), 갑상선 과산화효소 항체(TPO Ab) 검사를 추가로 시행합니다. 필요시 갑상선 초음파 및 방사성요오드 섭취율 검사를 통해 원인을 감별하며, 내분비내과 전문의가 결과를 종합하여 진단합니다.', 2695, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선기능항진증', '갑상선기능항진증', 'TREATMENT', '갑상선기능항진증 약물 중단 후 완치 확인을 위해 혈중 TSH, free T4, T3 수치를 정기적으로 측정하고, 그레이브스병의 경우 TRAb(TSH 수용체 항체)가 음전화되는지 확인합니다. 약물 중단 후 1~2개월, 이후 3~6개월 간격으로 추적 검사를 받는 것이 권장됩니다. 재발률이 약 50% 정도로 높으므로 장기간 추적 관찰이 필요하며, 내분비내과 전문의의 지속적인 관리가 중요합니다.', 2696, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선염', '갑상선염', 'MEDICATION', '갑상선염의 치료 약물은 원인과 유형에 따라 다르며, 갑상선기능항진기에는 베타 차단제로 증상을 조절하고, 기능저하기에는 레보티록신을 보충합니다. 하시모토 갑상선염의 경우 갑상선호르몬 저하 시 레보티록신 복용이 기본 치료입니다. 약물 변경은 임의로 결정하기 어려우므로 현재 복용 약물의 부작용과 대체 약물에 대해 내분비내과 전문의와 상담하시기 바랍니다.', 2697, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선염', '갑상선염', 'CAUSE', '갑상선염의 주요 원인으로는 자가면역 반응(하시모토 갑상선염, 그레이브스병 관련), 바이러스 감염 후 염증반응(아급성 갑상선염), 세균 감염, 방사선 치료, 약물(아미오다론, 리튬, 인터페론) 등이 있습니다. 면역력 저하 시 바이러스 감염 후 아급성 갑상선염이 발생할 수 있으며, 이때 갑상선 부위의 통증과 부종이 특징입니다. 정확한 원인 파악을 위해 내분비내과 전문의의 진료와 갑상선 기능 검사가 필요합니다.', 2698, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선염', '갑상선염', 'DEFINITION', '갑상선염은 다양한 원인으로 갑상선에 염증이 생기는 질환으로, 하시모토 갑상선염(자가면역), 아급성 갑상선염(바이러스 후), 무통성 갑상선염 등으로 분류됩니다. 증상은 유형에 따라 다르며, 갑상선 부위 통증과 부종(아급성), 무증상이나 서서히 진행하는 기능 저하(하시모토), 일시적인 기능 항진 후 저하(무통성) 등이 나타납니다. 지속적인 피로감, 체중 변화, 목 부위 이상이 있다면 내분비내과 전문의 진료를 받으시기 바랍니다.', 2699, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선염', '갑상선염', 'SYMPTOM', '갑상선염의 무기력감과 안면 열감은 갑상선 기능 변화에 따른 증상으로, 기능 저하 시에는 갑상선호르몬 보충, 기능 항진 시에는 베타 차단제나 항갑상선제가 사용됩니다. 아급성 갑상선염으로 인한 통증에는 비스테로이드성 소염제(NSAIDs)나 스테로이드가 효과적입니다. 증상과 원인에 맞는 정확한 치료 결정을 위해 내분비내과 전문의의 진료와 갑상선 기능 검사를 받으시기 바랍니다.', 2700, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선염', '갑상선염', 'DIAGNOSIS', '갑상선 기능 저하증과 함께 갑상선암이나 갑상선염이 의심되는 경우, 내분비내과, 이비인후과, 또는 외과(갑상선 전문)에서 진단을 받을 수 있습니다. 갑상선 초음파와 갑상선 기능 혈액 검사(TSH, free T4, 항체 검사)가 기본 검사이며, 결절이 있는 경우 세침흡인세포검사(FNA)로 악성 여부를 감별합니다. 가까운 내과나 가정의학과에서 1차 진료 후 전문과로 의뢰받는 방법도 가능합니다.', 2701, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '갑상선염', '갑상선염', 'TREATMENT', '갑상선기능항진증과 갑상선염은 서로 연관될 수 있으며, 그레이브스병 등 자가면역성 갑상선 항진증 환자는 동일한 자가면역 기전으로 하시모토 갑상선염으로 진행할 위험이 있습니다. 또한 항갑상선제 치료로 기능이 저하되면서 갑상선염의 기능저하기와 유사한 양상이 나타날 수 있습니다. 치료 방향 결정은 복합 병태를 고려해야 하므로 내분비내과 전문의의 면밀한 추적 관리가 필요합니다.', 2702, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '고칼슘혈증', '고칼슘혈증', 'CAUSE', '고칼슘혈증의 원인으로는 부갑상선호르몬(PTH) 이상 외에도 악성 종양(부갑상선호르몬 유사 펩타이드 분비), 비타민D 과잉 섭취 또는 과활성화, 육아종성 질환(사르코이도시스), 갑상선기능항진증, 부동화(장기 침상 안정), 특정 약물(칼슘 보충제, 티아지드 이뇨제, 리튬) 등이 있습니다. 악성 종양에 의한 고칼슘혈증은 빠르게 진행하고 중증일 수 있어 감별 진단이 중요합니다. 정확한 원인 파악을 위해 내분비내과 전문의의 진료가 필요합니다.', 2703, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '고칼슘혈증', '고칼슘혈증', 'DEFINITION', '고칼슘혈증은 혈중 칼슘 농도가 정상 범위(8.5~10.5 mg/dL)를 초과하는 상태로, 부갑상선 과활성이나 악성 종양 등 다양한 원인으로 발생합니다. 경증의 경우 무증상이지만, 칼슘 농도가 높아지면 구역, 구토, 변비, 다뇨, 다음, 피로감, 근육 약화, 신장 결석, 의식 변화 등이 나타날 수 있습니다. 증상이 있거나 혈액 검사에서 고칼슘혈증이 발견되면 내분비내과 전문의의 진료가 필요합니다.', 2704, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '고칼슘혈증', '고칼슘혈증', 'SYMPTOM', '고칼슘혈증의 주요 증상으로 ''뼈, 돌, 신음, 정신적 증상(Bones, Stones, Groans, Psychic moans)''으로 요약되는 뼈 통증, 신장 결석, 소화기 증상(구역·구토·변비), 신경정신 증상(무기력·혼란·우울)이 나타납니다. 심한 고칼슘혈증에서는 심부정맥, 신부전, 혼수 등 심각한 합병증이 발생할 수 있습니다. 이러한 증상들이 나타나면 즉시 병원을 방문하여 혈중 칼슘 수치 확인과 원인 규명을 위한 전문의 진료를 받으시기 바랍니다.', 2705, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '고칼슘혈증', '고칼슘혈증', 'DIAGNOSIS', '혈중 칼슘 농도 이상이 확인된 경우 내분비내과 또는 신장내과 전문의에게 진료를 받는 것이 적합합니다. 대부분의 종합병원과 대학병원 내분비내과에서 부갑상선 기능 검사, PTH 수치, 비타민D 수치 측정 및 원인 감별 진단을 시행합니다. 악성 종양 관련 고칼슘혈증이 의심되는 경우 혈액종양내과와 협진이 필요할 수 있습니다.', 2706, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '고칼슘혈증', '고칼슘혈증', 'TREATMENT', '고칼슘혈증 치료 시 충분한 수분 섭취(하루 2L 이상)로 신장을 통한 칼슘 배설을 촉진하고, 비타민D와 칼슘 보충제의 과도한 복용을 삼가야 합니다. 식이로는 과도한 칼슘 섭취를 피하면서도 완전한 제한은 하지 않으며, 인 함량이 높은 식품도 제한하는 것이 도움이 됩니다. 원인 질환의 치료가 근본적으로 중요하며, 이중인산염 약물, 수액 치료 등은 전문의의 처방이 필요합니다.', 2707, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '골다공증', '골다공증', 'CHECKUP', '골다공증 진단의 표준 검사는 이중에너지 X선 흡수계측법(DEXA 스캔)으로 요추와 대퇴골 골밀도를 측정합니다. 혈액 검사(칼슘, 인, 비타민D, PTH, 간·신기능)와 소변 검사를 통해 2차성 골다공증 원인을 감별합니다. 손톱이 쉽게 부러지는 것만으로 골다공증을 진단할 수는 없으며, 내분비내과 또는 정형외과 전문의를 방문하여 골밀도 검사를 받아보시기 바랍니다.', 2708, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '골다공증', '골다공증', 'DIET_LIFE', '우유를 포함한 유제품의 칼슘 섭취는 골다공증 예방에 도움이 되며, 하루 권장 칼슘 섭취량은 성인 기준 약 1000~1200mg입니다. 그러나 과도한 칼슘 섭취는 신장 결석, 혈관 석회화 등의 부작용이 있을 수 있으므로 적정량 섭취가 중요합니다. 칼슘 흡수를 위한 비타민D 섭취, 체중 부하 운동, 금주·금연이 함께 이루어져야 효과적으로 골다공증을 예방할 수 있습니다.', 2709, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '골다공증', '골다공증', 'MEDICATION', '갑상선호르몬 약물(레보티록신)을 과도하게 복용하거나 TSH가 지나치게 억제되면 골밀도 감소로 인한 척추 압박 골절과 요통이 발생할 수 있습니다. 이는 갑상선호르몬이 과잉 시 골 흡수를 촉진하여 골다공증을 유발하기 때문입니다. 갑상선 약물 복용 중 척추 통증이나 자세 변화가 생기면 내분비내과 전문의와 상담하여 약물 용량과 골밀도를 함께 점검하시기 바랍니다.', 2710, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '골다공증', '골다공증', 'PREVENTION', '멸치, 우유, 두부 등 칼슘이 풍부한 식품 섭취는 골다공증 예방에 도움이 되지만, 보충제로 과다 복용하는 것보다 식이를 통한 적정 섭취가 권장됩니다. 칼슘 흡수를 위해 비타민D가 필수적이며, 햇빛 노출과 비타민D 보충이 함께 이루어져야 효과적입니다. 추가적으로 규칙적인 체중 부하 운동, 금연, 절주, 낙상 예방도 골다공증 예방의 중요한 요소입니다.', 2711, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '골다공증', '골다공증', 'EXERCISE', '골다공증 환자에게는 낙상 위험을 줄이면서 골밀도를 높이는 체중 부하 운동이 권장되며, 걷기, 계단 오르기, 저강도 에어로빅이 적합합니다. 근력 강화 운동(가벼운 저항 운동, 탄성 밴드)으로 근육량을 유지하면 낙상 예방에도 효과적입니다. 과도한 굴곡 동작(허리를 앞으로 심하게 구부리는 것)은 척추 압박 골절 위험이 있으므로 피하고, 운동 프로그램은 재활의학과 또는 정형외과 전문의와 상담 후 시작하시기 바랍니다.', 2712, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '골다공증', '골다공증', 'CAUSE', '노화 외에도 에스트로겐 감소(폐경), 낮은 체중과 체질량지수, 칼슘·비타민D 결핍, 흡연, 과음, 스테로이드 장기 복용, 갑상선·부갑상선 질환, 류마티스 관절염, 신장 질환 등이 골다공증을 유발할 수 있습니다. 이러한 요인들은 파골세포에 의한 골 흡수를 증가시키거나 조골세포에 의한 골 형성을 감소시켜 골 소실을 일으킵니다. 위험 인자가 있는 경우 조기 골밀도 검사와 예방적 관리를 내분비내과 또는 정형외과 전문의와 상담하시기 바랍니다.', 2713, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '골다공증', '골다공증', 'DEFINITION', '골다공증은 뼈의 강도와 골밀도가 감소하여 골절 위험이 증가하는 대사성 뼈 질환으로, 초기에는 증상이 없어 ''침묵의 질병''이라고도 불립니다. 치료 없이 약만 먹는 것은 골밀도 유지에 도움이 되나, 생활습관 개선(운동, 칼슘·비타민D 섭취, 낙상 예방)과 병행해야 효과적입니다. 골다공증 치료제(비스포스포네이트, 데노수맙 등)의 지속적인 복용과 정기적인 골밀도 추적 검사가 중요합니다.', 2714, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '골다공증', '골다공증', 'SYMPTOM', '골다공증은 초기에 통증이 없으나 골밀도가 충분히 감소하면 작은 충격에도 골절이 발생할 수 있으며, 척추 압박 골절로 인한 허리 통증과 키 감소, 척추 후만(등 굽음)이 나타납니다. 골절은 특히 척추, 고관절, 손목에 흔히 발생하며, 고관절 골절의 경우 심각한 기능 저하와 사망률 증가로 이어질 수 있습니다. 골절 위험이 높다면 낙상 예방 조치와 골다공증 치료를 즉시 시작하도록 전문의 진료를 받으시기 바랍니다.', 2715, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '골다공증', '골다공증', 'DIAGNOSIS', '중격 결손(예: 심방·심실 중격 결손)이 뼈가 부러지는 것과 직접적인 관련은 없습니다. 사소한 충격에 골절이 발생한다면 골다공증, 골연화증, 악성 종양 등 뼈의 취약성을 높이는 질환을 의심해야 합니다. DEXA 스캔을 통한 골밀도 검사와 혈액 검사로 원인을 감별하기 위해 내분비내과 또는 정형외과 전문의 진료를 권장합니다.', 2716, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '골다공증', '골다공증', 'TREATMENT', '골다공증으로 인한 골절 위험이 높다면 비스포스포네이트(알렌드로네이트, 리세드로네이트), 데노수맙, 또는 부갑상선호르몬 유사체(테리파라타이드) 등의 약물 치료를 시작해야 합니다. 칼슘(하루 1000~1200mg)과 비타민D(하루 800~1000IU) 보충을 병행하고, 낙상 예방을 위한 환경 개선(미끄럼 방지, 조명 확보)도 중요합니다. 치료 방법은 골밀도 수치, 골절 위험 점수(FRAX), 기저 질환에 따라 달라지므로 내분비내과 또는 정형외과 전문의와 상담하시기 바랍니다.', 2717, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 기능 항진', '뇌하수체기능항진', 'CAUSE', '뇌하수체 기능 항진과 갑상선 기능 항진은 별개의 질환이지만 연관될 수 있으며, 뇌하수체에서 TSH를 과다 분비하는 TSH 분비 선종이 있으면 갑상선 기능 항진을 유발할 수 있습니다. 갑상선 호르몬 과잉(갑상선기능항진증)의 경우 T3, T4가 증가하고 TSH는 감소하는 것이 일반적이나, TSH 분비 선종의 경우 TSH도 높게 나타나는 것이 특징입니다. 정확한 감별 진단을 위해 내분비내과 전문의 진료가 필요합니다.', 2718, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 기능 항진', '뇌하수체기능항진', 'DEFINITION', '뇌하수체 기능 항진(뇌하수체 선종 등)은 뇌하수체에서 특정 호르몬이 과다 분비되는 상태로, 성장호르몬 과다 시 거인증·말단비대증, 프로락틴 과다 시 무월경·유루증, 부신피질자극호르몬(ACTH) 과다 시 쿠싱병이 발생합니다. 두통과 시야 장애(종양에 의한 시신경 교차 압박)가 흔히 동반됩니다. 정확한 원인 진단을 위해 내분비내과에서 호르몬 검사와 뇌 MRI 검사를 받으시기 바랍니다.', 2719, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 기능 항진', '뇌하수체기능항진', 'SYMPTOM', '뇌하수체 기능 항진 환자에서 두통과 시야 장애는 뇌하수체 종양에 의한 압박으로 나타나는 흔한 증상입니다. 빈뇨는 뇌하수체 후엽의 항이뇨호르몬(ADH) 분비 이상이 동반될 때 나타날 수 있으며, 눈의 통증은 시신경 압박과 관련될 수 있습니다. 이러한 증상들이 복합적으로 나타난다면 뇌하수체 종양의 크기와 호르몬 분비 패턴을 평가하기 위해 내분비내과 전문의 진료가 시급합니다.', 2720, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 기능 항진', '뇌하수체기능항진', 'DIAGNOSIS', '뇌하수체 기능 항진으로 인한 거인증(소아기 성장호르몬 과다) 또는 말단비대증(성인 성장호르몬 과다) 진단을 위해 혈중 성장호르몬(GH)과 IGF-1(인슐린양 성장인자-1) 측정이 기본 검사입니다. 경구 당부하 검사(75g 포도당 투여 후 GH 억제 확인) 및 뇌하수체 MRI가 표준 진단 절차입니다. 진단 확정 후 치료(수술, 방사선, 소마토스타틴 유사체 약물) 계획을 세우기 위해 내분비내과 및 신경외과 협진이 필요합니다.', 2721, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 기능 항진', '뇌하수체기능항진', 'TREATMENT', '뇌하수체 기능 항진증의 원인 규명을 위해 혈중 호르몬 수치(GH, IGF-1, 프로락틴, ACTH, 코르티솔, TSH, 갑상선호르몬, FSH, LH, 성호르몬) 등 뇌하수체 기능 전반을 평가하는 혈액 검사를 시행합니다. 뇌하수체 MRI(조영증강)로 종양의 위치, 크기, 주변 구조 침범 여부를 확인합니다. 호르몬 과다 분비의 원인이 확인되면 수술적 제거(경접형골 수술)가 1차 치료로 고려되며, 내분비내과·신경외과 협진이 필요합니다.', 2722, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 기능부전', '뇌하수체기능부전', 'CHECKUP', '뇌하수체 기능부전이 의심되는 복부 통증, 근력 약화, 갑작스러운 증상(부신 위기 가능성)이 있다면 내분비내과에서 우선 검진을 받는 것이 적합합니다. 부신 위기가 의심되는 경우 응급 상황으로 즉시 응급실을 방문해야 합니다. 증상이 만성적이라면 내분비내과에서 뇌하수체 기능 전반 평가를 받고, 필요시 신경외과, 신경과 등과 협진합니다.', 2723, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 기능부전', '뇌하수체기능부전', 'MEDICATION', '뇌하수체 기능부전으로 인한 무기력증과 중심 잡기 어려움은 부신피질호르몬 결핍(수소코르티존), 갑상선호르몬 결핍, 또는 성장호르몬 결핍과 관련될 수 있습니다. 치료는 결핍된 호르몬에 따라 하이드로코르티손, 레보티록신, 성장호르몬 등의 호르몬 보충 요법이 사용됩니다. 임의로 약물을 선택하지 말고 반드시 내분비내과 전문의의 정확한 진단과 처방 후 치료를 시작해야 합니다.', 2724, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 기능부전', '뇌하수체기능부전', 'CAUSE', '뇌하수체 기능부전의 원인으로는 뇌하수체 종양(가장 흔함), 두부 외상, 뇌수술 또는 방사선 치료, 자가면역 뇌하수체염, 샤이한 증후군(분만 후 출혈로 인한 뇌하수체 경색), 침윤성 질환(사르코이도시스) 등이 있습니다. 만성 피로와 쇠약감은 부신피질호르몬이나 갑상선호르몬 결핍의 흔한 증상으로, 단순 과로와 구별이 필요합니다. 지속적인 피로가 있다면 내분비내과 전문의를 방문하여 뇌하수체 호르몬 기능 평가를 받으시기 바랍니다.', 2725, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 기능부전', '뇌하수체기능부전', 'DEFINITION', '뇌하수체 기능부전은 뇌하수체 호르몬 분비 저하로 갑상선자극호르몬(TSH) 결핍을 초래하여 이차성 갑상선기능저하증을 유발할 수 있습니다. 갑상선기능항진증은 뇌하수체 기능부전에서는 드물며, 주로 뇌하수체 기능 항진이나 갑상선 자체 이상에서 발생합니다. 뇌하수체 기능부전에서는 성장호르몬, 성선자극호르몬, ACTH, TSH, 프로락틴 등 여러 호르몬이 복합적으로 결핍될 수 있습니다.', 2726, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 기능부전', '뇌하수체기능부전', 'SYMPTOM', '뇌하수체 기능부전으로 결핍될 수 있는 호르몬과 증상으로는 성장호르몬 결핍(피로, 체지방 증가, 근력 저하), 성선자극호르몬 결핍(성기능 저하, 무월경, 불임), 갑상선자극호르몬 결핍(피로, 추위 민감, 체중 증가), 부신피질자극호르몬 결핍(무기력, 저혈압, 저혈당, 저나트륨혈증), 프로락틴 결핍(수유 불가)이 있습니다. 부신 호르몬 결핍은 생명을 위협하는 부신 위기를 유발할 수 있어 가장 시급한 치료가 필요합니다. 내분비내과 전문의의 체계적인 평가와 호르몬 보충 치료가 중요합니다.', 2727, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 기능부전', '뇌하수체기능부전', 'DIAGNOSIS', '뇌하수체 기능부전이 의심되는 경우 뇌하수체 MRI(조영증강)로 구조적 이상을 확인하고, 뇌하수체 자극 검사(인슐린 저혈당 검사, 메티라폰 검사, CRH/GHRH 자극 검사 등)를 통해 각 호르몬 축의 기능을 평가합니다. 기저 호르몬 수치(cortisol 아침값, TSH, free T4, GH, IGF-1, LH, FSH, 성호르몬, 프로락틴) 측정이 병행됩니다. 이러한 검사들은 내분비내과에서 종합적으로 시행하며 전문의의 지도 하에 이루어져야 합니다.', 2728, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 기능부전', '뇌하수체기능부전', 'TREATMENT', '뇌하수체 기능부전 치료는 결핍된 호르몬에 따른 호르몬 보충 요법이 기본으로, 부신피질호르몬(하이드로코르티손), 갑상선호르몬(레보티록신), 성호르몬(에스트로겐/테스토스테론), 성장호르몬 주사, 항이뇨호르몬(데스모프레신, 요붕증 동반 시)이 사용됩니다. 원인이 종양인 경우 수술적 제거나 방사선 치료가 선행될 수 있으며, 호르몬 보충 후 정기적인 혈액 검사로 용량을 조절합니다. 모든 치료는 내분비내과 전문의의 처방과 관리 하에 이루어져야 합니다.', 2729, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 양성 및 악성 신생물', '뇌하수체양성및악성신생물', 'CAUSE', '뇌하수체 양성 및 악성 신생물의 주요 증상으로는 종양 크기에 따른 두통, 시야 장애(양측 측두부 시야 결손), 호르몬 과다 분비로 인한 증상(유루증, 불임, 생리불순, 성기능 저하, 말단비대증, 쿠싱 증상)이 있습니다. 질의 건조함, 안면홍조 등은 성선자극호르몬 결핍으로 인한 에스트로겐 저하 증상입니다. 이러한 증상들이 복합적으로 나타난다면 내분비내과 및 신경외과 전문의의 종합적인 평가가 필요합니다.', 2730, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 양성 및 악성 신생물', '뇌하수체양성및악성신생물', 'DEFINITION', '뇌하수체 신생물은 크기에 따라 미세선종(10mm 미만)과 거대선종(10mm 이상)으로, 호르몬 분비 여부에 따라 기능성(호르몬 분비)과 비기능성 선종으로 분류됩니다. 기능성 선종으로는 프로락틴 분비종, 성장호르몬 분비종, ACTH 분비종 등이 있으며, 악성 뇌하수체 종양(뇌하수체암)은 매우 드뭅니다. 대부분은 양성이나 주변 구조 압박과 호르몬 이상을 유발하므로 내분비내과와 신경외과 협진을 통한 정확한 분류와 치료 계획이 필요합니다.', 2731, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 양성 및 악성 신생물', '뇌하수체양성및악성신생물', 'SYMPTOM', '두통과 시력 저하가 점점 심해지거나 시야의 특정 부분이 보이지 않는다면, 이는 뇌하수체 종양에 의한 시신경 교차 압박을 시사하는 응급 신호일 수 있습니다. 즉시 내분비내과 또는 신경외과를 방문하여 뇌 MRI와 시야 검사(안과)를 받아야 하며, 종양에 의한 압박이 확인되면 신속한 수술적 감압이 필요할 수 있습니다. 증상이 갑자기 악화되는 뇌하수체 졸중의 경우 응급 처치가 필요합니다.', 2732, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 양성 및 악성 신생물', '뇌하수체양성및악성신생물', 'DIAGNOSIS', '두통, 시력 저하, 체중 감소가 복합적으로 나타나는 경우 뇌하수체 종양을 포함한 두개내 병변 가능성을 배제하기 위해 뇌 MRI 검사가 필요합니다. 뇌하수체 종양 진단을 위해 호르몬 검사(프로락틴, GH, IGF-1, cortisol, TSH, LH, FSH)를 함께 시행합니다. 이러한 증상들이 동시에 나타난다면 내분비내과 또는 신경과 전문의를 방문하여 정확한 원인 평가를 받으시기 바랍니다.', 2733, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '뇌하수체 양성 및 악성 신생물', '뇌하수체양성및악성신생물', 'TREATMENT', '뇌하수체 종양의 원인은 대부분 산발적 유전자 돌연변이에 의한 뇌하수체 세포의 단클론 증식이며, 일부는 MEN1, AIP 등 유전 증후군과 관련됩니다. 기능성 뇌하수체 종양의 치료로는 경접형골 미세수술이 1차 치료이며, 프로락틴 분비종은 도파민 작용제(카버골린)가 효과적입니다. 수술 후에도 잔존 종양이나 재발에 대해 방사선 수술(감마나이프), 약물 치료를 병행하며 내분비내과·신경외과 협진으로 장기 관리합니다.', 2734, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병', '당뇨병', 'CHECKUP', '당뇨 가족력이 있는 40대 여성은 공복혈당 또는 당화혈색소(HbA1c) 검사를 포함한 당뇨 선별 검사를 매년 1회 받는 것을 권장합니다. 국가 건강검진의 일환으로 2년마다 기본 혈당 검사가 시행되지만, 가족력 등 고위험군에서는 더 자주 검진이 필요합니다. 검진은 내과, 가정의학과, 또는 내분비내과에서 받을 수 있으며 정상 범위라도 매년 추적 관찰이 중요합니다.', 2735, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병', '당뇨병', 'DIET_LIFE', '당뇨병 예방을 위해 백미·흰 빵 등 정제 탄수화물 대신 통곡물, 채소, 식이섬유 위주의 식단을 유지하고, 당분이 많은 음료와 가공식품을 줄여야 합니다. 규칙적인 식사와 적절한 열량 섭취로 정상 체중을 유지하는 것이 중요하며, 포화지방과 트랜스 지방 섭취를 제한합니다. 과일은 적당량 섭취하고 전반적인 식이 패턴을 지중해식 식단에 가깝게 구성하는 것이 근거에 기반한 당뇨 예방 전략입니다.', 2736, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병', '당뇨병', 'MEDICATION', '이상지질혈증의 약물 치료로는 LDL 콜레스테롤 저하를 위한 스타틴(아토르바스타틴, 로수바스타틴)이 1차 약제로 가장 널리 사용됩니다. 중성지방이 높은 경우 피브레이트나 오메가-3 지방산이 사용되며, HDL 저하 및 복합 지질 이상에는 나이아신도 고려될 수 있습니다. 당뇨병, 비만, 알코올 섭취가 원인인 경우 근본 원인 조절이 선행되어야 하며, 약물 선택은 개인의 심혈관 위험도를 고려하여 내과 전문의와 상담 후 결정해야 합니다.', 2737, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병', '당뇨병', 'PREVENTION', '당뇨병 예방을 위해 매일 150분 이상의 중등도 유산소 운동(빠르게 걷기, 자전거, 수영)과 주 2회 근력 운동이 인슐린 감수성을 향상시키고 혈당 조절에 효과적입니다. 체중의 5~7% 감량만으로도 당뇨병 발생 위험을 크게 줄일 수 있으며, 저칼로리·저탄수화물 식단과 운동의 병행이 가장 효과적입니다. 당뇨병 전단계(공복혈당 장애, 내당능 장애)에서 이러한 생활습관 개선은 당뇨병 진행을 40~60% 감소시킬 수 있습니다.', 2738, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병', '당뇨병', 'EXERCISE', '당뇨병 전단계(공복혈당 장애)에 적합한 운동으로는 빠르게 걷기, 자전거 타기, 수영 등 주 150분 이상의 중등도 유산소 운동이 권장됩니다. 인슐린 감수성 향상을 위해 주 2~3회 근력 운동을 병행하고, 운동 후 혈당 변화를 모니터링하는 것이 중요합니다. 운동 전 저혈당 예방을 위해 혈당 확인 습관을 갖고, 개인 건강 상태에 맞는 운동 프로그램은 내과 또는 운동 전문가와 상담하여 결정하시기 바랍니다.', 2739, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병', '당뇨병', 'CAUSE', '단 음식(설탕, 과당 등) 자체가 당뇨병의 직접 원인은 아니나, 과도한 섭취가 비만과 인슐린 저항성을 유발하여 제2형 당뇨병 위험을 높일 수 있습니다. 특히 당분이 많은 음료(탄산음료, 과일 주스)의 과다 섭취는 혈당을 급격히 올리고 체중 증가를 촉진하여 당뇨 위험을 증가시킵니다. 단 음식 자체보다는 전반적인 식이 패턴, 신체 활동량, 유전적 소인이 당뇨 발생에 더 큰 영향을 미칩니다.', 2740, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병', '당뇨병', 'DEFINITION', '제1형 당뇨병은 자가면역 반응으로 췌장 베타세포가 파괴되어 인슐린이 거의 분비되지 않는 질환으로, 주로 소아·청소년에서 발생하며 인슐린 주사 치료가 필수입니다. 제2형 당뇨병은 인슐린 저항성과 상대적 인슐린 분비 부족으로 발생하며, 중장년층에 흔하고 초기에는 식이·운동·경구 혈당강하제로 치료가 가능합니다. 두 유형 모두 고혈당으로 인한 합병증 예방이 중요하며, 정확한 유형 분류와 치료 계획은 내분비내과 전문의와 상담하시기 바랍니다.', 2741, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병', '당뇨병', 'SYMPTOM', '당뇨병의 주요 증상으로는 다음(多飮, 과도한 갈증), 다뇨(잦은 소변), 다식(과도한 식욕)과 체중 감소가 있으며, 피로감, 시야 흐림, 상처 회복 지연도 나타납니다. 단 음식을 많이 먹는다고 바로 당뇨병이 생기는 것은 아니며, 과도한 당분 섭취로 인한 비만과 인슐린 저항성이 제2형 당뇨의 위험 인자가 됩니다. 이러한 증상이 나타난다면 공복혈당 검사를 통해 내과 전문의 진료를 받아보시기 바랍니다.', 2742, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병', '당뇨병', 'DIAGNOSIS', '당뇨병은 공복혈당 126 mg/dL 이상(2회 이상 확인), 식후 2시간 혈당 200 mg/dL 이상, 당화혈색소(HbA1c) 6.5% 이상, 또는 고혈당 증상과 함께 임의 혈당 200 mg/dL 이상 중 하나를 만족하면 진단합니다. 공복혈당 100~125 mg/dL는 공복혈당 장애(당뇨 전단계), HbA1c 5.7~6.4%도 전당뇨에 해당합니다. 정확한 진단과 추적 관찰을 위해 내과 전문의의 진료를 받으시기 바랍니다.', 2743, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병', '당뇨병', 'TREATMENT', '당뇨병 치료는 약물 치료 외에도 식사 요법(탄수화물·칼로리 조절, 균형 잡힌 식단), 규칙적인 운동(유산소+근력 운동), 자가 혈당 모니터링, 당화혈색소 정기 추적이 포함됩니다. 체중 감량(비만인 경우)과 금연도 중요한 비약물적 치료의 일부입니다. 음식 계획과 혈당 모니터링은 치료의 핵심 요소로, 내분비내과 전문의와 당뇨 전문 교육을 통해 개인화된 치료 계획을 수립하는 것을 권장합니다.', 2744, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 말초신경병증', '당뇨병성말초신경병증', 'PREVENTION', '당뇨병성 말초신경병증을 예방하려면 혈당을 철저히 조절하는 것이 가장 중요하며, 금연과 금주, 규칙적인 유산소 운동이 도움이 됩니다. 발과 다리를 매일 점검하고 상처나 변색이 없는지 확인하며, 꽉 조이는 신발 착용을 피해야 합니다. 저린 통증이 심해진다면 신경과 또는 내분비내과 전문의 상담을 받으시길 권고드립니다.', 2745, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 말초신경병증', '당뇨병성말초신경병증', 'CAUSE', '고혈당이 지속되면 신경에 산소와 영양을 공급하는 미세혈관이 손상되고, 포도당 대사 과정에서 생성된 독성 물질이 신경세포를 직접 손상시킵니다. 고혈당 외에도 고혈압, 고지혈증, 흡연, 음주, 비만 등이 복합적으로 작용하여 신경병증 위험을 높입니다. 정확한 원인 평가와 관리를 위해 내분비내과 전문의 상담을 권고드립니다.', 2746, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 말초신경병증', '당뇨병성말초신경병증', 'DEFINITION', '당뇨병성 말초신경병증은 만성 고혈당으로 인해 말초신경이 손상되어 양쪽 손발에 저림, 따가움, 화끈거림, 감각저하 등이 나타나는 합병증입니다. 진단은 신경전도 검사, 근전도 검사, 발의 감각 검사(모노필라멘트 검사 등)를 통해 이루어지며, 혈당 조절 상태도 함께 평가합니다. 증상이 있다면 내분비내과 또는 신경과 전문의를 방문하여 정확한 진단과 치료를 받으시길 권고드립니다.', 2747, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 말초신경병증', '당뇨병성말초신경병증', 'SYMPTOM', '양 발 양말 부위에서 밤마다 따갑고 화끈거리는 증상은 당뇨병성 말초신경병증의 전형적인 증상으로, 특히 야간에 악화되는 통증이 특징입니다. 이러한 ''장갑-양말 분포(glove-stocking distribution)'' 형태의 대칭적 감각 이상은 말초신경 손상을 강하게 시사합니다. 정확한 진단과 적절한 통증 관리를 위해 내분비내과 또는 신경과 전문의 상담을 받으시길 권고드립니다.', 2748, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 말초신경병증', '당뇨병성말초신경병증', 'DIAGNOSIS', '당뇨병성 말초신경병증 진단 후에도 인슐린이나 경구혈당강하제로 혈당을 목표 범위 내로 유지하는 것이 합병증 진행을 늦추는 데 핵심적입니다. 합병증 진행 여부는 정기적인 신경전도 검사, HbA1c 측정, 발 감각 검사 등을 통해 확인하며, 통상 3~6개월 간격으로 추적 관찰합니다. 인슐린 치료 지속 여부와 모니터링 계획은 담당 내분비내과 전문의와 상의하여 결정하시길 권고드립니다.', 2749, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 말초신경병증', '당뇨병성말초신경병증', 'TREATMENT', '당뇨병성 말초신경병증 통증 치료에는 프레가발린, 둘록세틴이 1차 약물로 널리 사용되며, 삼환계 항우울제(아미트립틸린)나 가바펜틴도 효과적입니다. 혈당 조절 자체가 신경 손상 진행을 늦추는 근본 치료이므로 혈당 관리와 병행해야 합니다. 적합한 약물 선택과 용량 조절은 개인 상태에 따라 다르므로 반드시 신경과 또는 내분비내과 전문의와 상담하시길 권고드립니다.', 2750, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 족부 질환', '당뇨병성족부질환', 'DIET_LIFE', '당뇨병성 족부 질환 환자는 혈당을 급격히 올리는 정제 탄수화물(흰 쌀밥, 흰 빵, 설탕), 포화지방이 많은 음식, 염분이 높은 가공식품, 알코올을 피해야 합니다. 혈액순환 장애와 상처 회복 지연을 악화시킬 수 있는 흡연도 반드시 중단해야 합니다. 구체적인 식단 계획은 당뇨 전문 영양사 또는 내분비내과 전문의와 상담하여 개인에 맞게 설계하시길 권고드립니다.', 2751, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 족부 질환', '당뇨병성족부질환', 'PREVENTION', '상처 재발 방지를 위해 매일 발을 꼼꼼히 점검하고, 발에 잘 맞는 당뇨 전용 신발과 양말을 착용하는 것이 중요합니다. 발바닥 압력을 분산시키는 특수 깔창(insole) 사용, 발톱을 일자로 짧게 유지하기, 맨발 보행 금지 등이 효과적인 예방법입니다. 정기적으로 내분비내과 또는 혈관외과 전문의를 방문하여 발 상태를 평가받으시길 권고드립니다.', 2752, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 족부 질환', '당뇨병성족부질환', 'CAUSE', '지속적인 고혈당은 발의 말초신경을 손상시켜 감각을 무디게 하고(신경병증), 동시에 미세혈관과 대혈관을 손상시켜 혈액 공급을 저하시킵니다(혈관병증). 감각이 저하되면 상처를 인지하지 못하고, 혈액 공급 부족으로 상처 치유가 지연되어 궤양과 괴저로 이어질 수 있습니다. 이러한 위험 요인 관리를 위해 철저한 혈당 조절과 내분비내과 전문의 정기 추적 관찰이 필수적입니다.', 2753, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 족부 질환', '당뇨병성족부질환', 'DEFINITION', '당뇨 진단 후 발끝 가려움과 감각 둔화는 당뇨병성 말초신경병증의 초기 증상일 수 있으며, 이는 당뇨병성 족부 질환으로 진행될 수 있는 전조 증상입니다. 당뇨병성 족부 질환은 신경병증과 혈관병증이 복합적으로 작용하여 발에 궤양, 감염, 괴저 등이 발생하는 상태를 의미합니다. 해당 증상이 있다면 즉시 내분비내과 또는 신경과 전문의를 방문하여 정밀 평가를 받으시길 권고드립니다.', 2754, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 족부 질환', '당뇨병성족부질환', 'SYMPTOM', '당뇨병성 족부 질환에서 외상 후에는 감각 저하로 인해 통증을 느끼지 못하는 가운데 상처가 커지고, 고혈당 환경에서 세균 감염이 빠르게 진행될 수 있습니다. 상처 부위가 붓고, 발적, 열감, 분비물이 발생하며 심하면 골수염(뼈 감염)이나 봉와직염으로 악화될 수 있습니다. 당뇨 환자의 발 상처는 매우 심각해질 수 있으므로 즉시 내분비내과 또는 외과 전문의의 진료를 받으시길 강력히 권고드립니다.', 2755, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 족부 질환', '당뇨병성족부질환', 'DIAGNOSIS', '발바닥 감각 둔화와 발가락의 흑색 변색은 당뇨병성 족부 질환 중 허혈성 괴저 가능성을 시사하는 심각한 증상입니다. 진단을 위해 내분비내과 또는 혈관외과를 방문하여 발 감각 검사, 발목-상완 혈압비(ABI) 측정, 하지 동맥 초음파 또는 혈관 조영술 등을 시행합니다. 발가락 변색은 응급 상황일 수 있으므로 즉시 전문 의료기관에 방문하시길 강력히 권고드립니다.', 2756, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 족부 질환', '당뇨병성족부질환', 'TREATMENT', '당뇨병성 족부 질환은 단일 과목으로 해결하기 어려운 복합 질환으로, 혈당 조절을 위한 내분비내과, 상처 관리와 수술을 위한 외과(혈관외과, 정형외과), 감염 관리를 위한 감염내과가 협력하는 다학제 치료가 가장 효과적입니다. 초기 방문은 내분비내과 또는 족부 전문 외과를 권장하며, 피부과는 일반적인 족부 질환의 주 치료과가 아닙니다. 정확한 치료 방향을 위해 내분비내과 전문의와 먼저 상담하시길 권고드립니다.', 2757, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 케톤산증', '당뇨병성케톤산증', 'PREVENTION', '당뇨병 환자는 알코올이 인슐린 분비와 혈당 조절을 방해하므로 반드시 음주를 중단해야 하며, 특히 맥주 1리터는 과도한 탄수화물과 알코올을 함유하여 케톤산증 위험을 높입니다. 혈당을 규칙적으로 자가 측정하고, 인슐린 주사를 절대 임의로 중단하지 않으며, 감염이나 발열 시 즉시 의료진에게 연락해야 합니다. 식단과 음주에 관한 구체적인 지침은 내분비내과 전문의 또는 당뇨 전담 교육자와 상담하시길 권고드립니다.', 2758, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 케톤산증', '당뇨병성케톤산증', 'CAUSE', '당뇨병성 케톤산증에서 인슐린 결핍으로 세포가 포도당을 이용하지 못하면 지방이 분해되어 케톤체가 과잉 생성되고 혈액이 산성화(산증)됩니다. 이로 인한 전해질 불균형(특히 칼륨, 나트륨)과 신경 독성이 근육 통증, 근력 저하, 감각 이상 등을 유발합니다. 이러한 증상은 의학적 응급 상황이므로 즉시 응급실 또는 내분비내과를 방문하시길 강력히 권고드립니다.', 2759, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 케톤산증', '당뇨병성케톤산증', 'DEFINITION', '당뇨병성 케톤산증(DKA)은 주로 제1형 당뇨병 환자에서 인슐린이 절대적으로 부족할 때 케톤체가 과잉 축적되어 혈액이 심하게 산성화되는 생명을 위협하는 급성 합병증입니다. 인슐린 중단, 감염, 수술, 스트레스 등이 유발 요인이 될 수 있으며, 혈당 관리가 불량한 경우 반복적으로 재발할 수 있습니다. 재발 방지를 위해 인슐린 치료 준수와 정기적인 내분비내과 전문의 상담이 필수적입니다.', 2760, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 케톤산증', '당뇨병성케톤산증', 'SYMPTOM', '당뇨병성 케톤산증의 주요 증상인 체중 감소와 쇠약감은 인슐린 부족으로 세포가 포도당을 이용하지 못하고 지방·근육이 분해되어 발생하며, 구토는 케톤체에 의한 위장관 자극과 산증으로 인해 나타납니다. 이러한 증상들은 수액 보충, 인슐린 정맥 투여, 전해질 교정 등의 입원 집중 치료로 대부분 호전됩니다. 해당 증상이 의심된다면 즉시 응급실을 방문하시길 강력히 권고드립니다.', 2761, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 케톤산증', '당뇨병성케톤산증', 'DIAGNOSIS', '당뇨병성 케톤산증 진단 시 유발 원인을 파악하기 위해 감염 여부(혈액배양, 소변 검사, 흉부 X선), 심근경색(심전도, 심근효소) 등 추가 검사가 필요할 수 있습니다. 또한 갑상선 기능 이상, 췌장염, 쿠싱 증후군 등 동반 내분비 질환을 감별하기 위한 검사가 시행될 수 있습니다. 필요한 추가 검사의 종류와 범위는 담당 내분비내과 전문의가 임상 상황에 맞게 결정합니다.', 2762, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '당뇨병성 케톤산증', '당뇨병성케톤산증', 'TREATMENT', '당뇨병성 케톤산증 입원 치료에서 수액(생리식염수) 정맥 투여는 탈수 교정, 혈당 희석, 신장을 통한 케톤 배설 촉진에 핵심적 역할을 하며, 동시에 인슐린 투여와 전해질 보충이 병행됩니다. 적절한 수액 치료로 산증이 교정되고 활력 징후가 안정되면 경구 섭취와 피하 인슐린으로 전환하며, 입원 기간은 중증도에 따라 보통 1~3일 정도 소요됩니다. 치료 과정 전반은 내분비내과 전문의의 지도 하에 진행됩니다.', 2763, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '말단비대증', '말단비대증', 'CAUSE', '말단비대증에서 손발에 액체가 축적되는 것은 성장호르몬(GH) 과잉 분비가 인슐린 유사 성장인자-1(IGF-1)을 증가시켜 나트륨과 수분 저류를 촉진하기 때문입니다. 과잉 성장호르몬은 연골, 뼈, 연조직의 비정상적 성장을 유도하여 손발 크기 증가, 두꺼운 피부, 부종 등을 유발합니다. 말단비대증은 대부분 뇌하수체 선종이 원인이므로 내분비내과 전문의를 통해 정밀 검사와 치료를 받으시길 권고드립니다.', 2764, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '말단비대증', '말단비대증', 'DEFINITION', '뇌하수체 기능 항진증은 뇌하수체에서 여러 호르몬이 과도하게 분비되는 광범위한 상태를 의미하는 반면, 말단비대증은 뇌하수체 선종에서 성장호르몬(GH)이 특이적으로 과잉 분비되어 IGF-1이 증가하고 뼈와 연조직이 비정상적으로 성장하는 특정 질환입니다. 즉 말단비대증은 뇌하수체 기능 항진증의 한 유형으로, 성장판이 닫힌 성인에서 손발·얼굴이 커지는 특징적 외형 변화가 나타납니다. 정확한 진단을 위해 내분비내과 전문의 상담을 권고드립니다.', 2765, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '말단비대증', '말단비대증', 'SYMPTOM', '말단비대증에서 두통은 뇌하수체 선종이 주변 구조물을 압박하여 발생하고, 쉰 목소리와 목소리 변화는 성장호르몬 과잉으로 인한 성대 주변 연조직 비대와 후두 연골 성장으로 나타납니다. 이러한 증상들이 지속되면 상기도 협착으로 인한 수면무호흡증, 심혈관 합병증, 시신경 압박으로 인한 시야 장애 등이 동반될 수 있습니다. 말단비대증이 의심된다면 내분비내과 전문의를 방문하여 혈중 IGF-1 검사 및 뇌 MRI 검사를 받으시길 권고드립니다.', 2766, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '말단비대증', '말단비대증', 'DIAGNOSIS', '말단비대증은 내분비내과 전문의가 주된 진단 및 치료를 담당하며, 뇌하수체 종양이 원인인 경우 뇌신경외과와의 협진이 필요합니다. 대형 병원 또는 대학병원의 내분비내과를 방문하여 혈중 성장호르몬(GH), IGF-1 검사와 뇌하수체 MRI 촬영을 받으시길 권고드립니다. 의심 증상이 있다면 지체 없이 전문의를 찾아 조기에 진단받는 것이 중요합니다.', 2767, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '말단비대증', '말단비대증', 'TREATMENT', '말단비대증의 1차 치료는 뇌하수체 선종 제거를 위한 경접형골 수술이며, 수술이 불완전하거나 불가능한 경우 소마토스타틴 유사체(옥트레오타이드, 란레오타이드)를 주사하여 성장호르몬 분비를 억제합니다. 도파민 효능제(카베르골린)나 성장호르몬 수용체 길항제(페그비소만트)도 사용될 수 있으며, 방사선 치료는 다른 치료가 효과 없을 때 고려합니다. 개인 상황에 맞는 최적 치료 방법은 내분비내과 및 뇌신경외과 전문의와 상담하여 결정하시길 권고드립니다.', 2768, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선기능저하증', '부갑상선기능저하증', 'MEDICATION', '부갑상선기능저하증에서는 부갑상선호르몬(PTH) 분비 감소로 혈중 칼슘 농도가 낮아져(저칼슘혈증) 근육 경련, 손발 저림, 경련 발작 등이 나타납니다. 칼슘 보충제와 활성형 비타민 D(칼시트리올) 투여는 혈중 칼슘 농도를 정상화하고 이러한 증상을 예방하는 핵심 치료입니다. 칼슘 보충량과 모니터링 방법은 내분비내과 전문의의 지도 하에 조정해야 합니다.', 2769, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선기능저하증', '부갑상선기능저하증', 'CAUSE', '부갑상선기능저하증의 가장 흔한 원인은 갑상선 수술 등 경부 수술 중 부갑상선 손상 또는 제거입니다. 그 외 자가면역질환, 방사선 치료, 마그네슘 결핍, 드물게 유전적 원인(DiGeorge 증후군 등)도 발병 원인이 될 수 있습니다. 정확한 원인 감별을 위해 수술력 외 다른 가능성도 내분비내과 전문의와 함께 평가하시길 권고드립니다.', 2770, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선기능저하증', '부갑상선기능저하증', 'DEFINITION', '부갑상선기능저하증은 부갑상선호르몬(PTH) 분비 부족으로 혈중 칼슘이 낮아지고 인산이 높아지는 질환입니다. 저칼슘혈증으로 인해 신경과 근육의 흥분성이 증가하여 손발·얼굴 저림, 근육 경련, 심하면 후두 경련이나 경련 발작이 나타날 수 있습니다. 치료하지 않으면 백내장, 기저핵 석회화, 치아 이상 등 장기적 합병증이 발생할 수 있으므로 내분비내과 전문의의 지속적 관리가 필요합니다.', 2771, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선기능저하증', '부갑상선기능저하증', 'SYMPTOM', '부갑상선기능저하증으로 인한 저칼슘혈증은 근육 경련과 통증을 유발하므로, 처방된 칼슘 보충제와 활성형 비타민 D를 규칙적으로 복용하고 혈중 칼슘 수치를 정기적으로 모니터링해야 합니다. 예방을 위해 커피, 알코올, 고인산 식품(가공식품, 탄산음료)을 제한하고 충분한 수분 섭취와 균형 잡힌 식이를 유지하는 것이 중요합니다. 증상 악화 시 즉시 내분비내과 전문의를 방문하시길 권고드립니다.', 2772, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선기능저하증', '부갑상선기능저하증', 'DIAGNOSIS', '부갑상선기능저하증 진단은 혈중 칼슘, 인, PTH, 마그네슘 수치 측정을 통해 이루어지며, 내분비내과에서 주로 진단과 치료를 담당합니다. 수술 후 발생한 경우 수술 집도의(외과)와 협진이 필요할 수 있지만, 일반적으로 외과 의사 상담이 필수적인 것은 아닙니다. 증상이 의심된다면 내분비내과 전문의를 먼저 방문하여 혈액 검사를 받으시길 권고드립니다.', 2773, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선기능저하증', '부갑상선기능저하증', 'TREATMENT', '갑상선 수술 후 부갑상선기능저하증으로 인한 손발·입술 저림 치료의 핵심은 활성형 비타민 D(칼시트리올)와 칼슘 보충제를 병용 투여하여 혈중 칼슘을 정상화하는 것입니다. 증상이 심한 급성기에는 정맥 내 칼슘 글루코네이트 투여가 필요할 수 있으며, 장기적으로는 마그네슘 보충도 고려합니다. 치료 용량과 모니터링 주기는 내분비내과 전문의의 지도 하에 개인 상태에 맞게 조정하시길 권고드립니다.', 2774, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선기능항진증', '부갑상선기능항진증', 'MEDICATION', '부갑상선기능항진증 치료 약물로는 고칼슘혈증을 낮추는 시나칼세트(calcimimetic), 뼈 보호를 위한 비스포스포네이트, 수분 보충을 위한 수액 요법 등이 사용됩니다. 무증상 경증의 경우 경과 관찰을 할 수 있으나, 근본적 치료는 과잉 분비하는 부갑상선 조직을 제거하는 수술(부갑상선 절제술)입니다. 적합한 치료 방법 선택은 내분비내과 및 외과 전문의와 상담하시길 권고드립니다.', 2775, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선기능항진증', '부갑상선기능항진증', 'CAUSE', '부갑상선기능저하증의 원인은 경부 수술(갑상선·부갑상선 수술) 후 부갑상선 손상이 가장 흔하며, 자가면역에 의한 부갑상선 파괴, 방사성 요오드 치료, 마그네슘 결핍, 유전적 결함(예: DiGeorge 증후군) 등이 원인이 됩니다. 이로 인해 PTH 분비가 감소하면 혈중 칼슘이 낮아지고 인산이 높아져 신경·근육 증상이 나타납니다. 정확한 원인 확인을 위해 내분비내과 전문의의 진료를 받으시길 권고드립니다.', 2776, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선기능항진증', '부갑상선기능항진증', 'DEFINITION', '부갑상선기능항진증은 부갑상선에서 PTH가 과잉 분비되어 혈중 칼슘이 높아지는(고칼슘혈증) 질환이고, 갑상선기능항진증은 갑상선에서 갑상선 호르몬(T3, T4)이 과잉 분비되는 전혀 다른 질환입니다. 부갑상선기능항진증의 원인은 부갑상선 선종(약 85%), 부갑상선 과형성, 드물게 부갑상선암이며, 신장 결석, 골다공증, 위장 증상, 피로감 등이 나타납니다. 정확한 진단을 위해 내분비내과 전문의를 방문하시길 권고드립니다.', 2777, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선기능항진증', '부갑상선기능항진증', 'SYMPTOM', '부갑상선기능항진증의 주요 증상으로 피로감, 무력감, 우울감, 집중력 저하 등 신경정신과적 증상과 오심, 변비, 식욕 부진 등 소화기 증상이 흔합니다. 신장 결석, 다뇨, 다음, 골다공증, 골절 위험 증가도 중요한 합병증이며, 심한 고칼슘혈증에서는 의식 변화까지 나타날 수 있습니다. 두통이나 근육 통증도 동반될 수 있으므로 증상이 있다면 내분비내과 전문의 상담을 권고드립니다.', 2778, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선기능항진증', '부갑상선기능항진증', 'DIAGNOSIS', '부갑상선기능항진증 진단을 위한 혈액 검사로 혈중 칼슘(총칼슘, 이온화 칼슘), 부갑상선호르몬(intact PTH), 혈청 인, 알부민, 크레아티닌(신기능) 측정이 기본적으로 시행됩니다. 혈중 칼슘과 PTH가 동시에 상승해 있다면 원발성 부갑상선기능항진증을 강하게 시사합니다. 정확한 진단과 원인 감별은 내분비내과 전문의와 상담하시길 권고드립니다.', 2779, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선기능항진증', '부갑상선기능항진증', 'TREATMENT', '부갑상선기능항진증의 근본적 치료는 과잉 기능하는 부갑상선 조직을 제거하는 수술(부갑상선 절제술)로, 선종이 원인인 경우 완치율이 매우 높습니다. 수술이 불가능하거나 무증상 경증의 경우 시나칼세트(칼시미메틱) 약물로 PTH와 칼슘을 조절하거나 경과 관찰을 선택합니다. 가장 효과적인 치료 방법은 환자의 연령, 칼슘 수치, 증상, 골밀도 등을 고려하여 내분비내과 및 외과 전문의와 함께 결정해야 합니다.', 2780, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선암', '부갑상선암', 'CHECKUP', '부갑상선암은 매우 드문 악성 종양으로 특정 연령대에서 현저히 높은 빈도를 보이지는 않으며, 오히려 40~60대에 주로 발생합니다. 젊은 연령에서 발생하는 경우 MEN1, MEN2A 같은 유전성 내분비 종양 증후군과 관련이 있을 수 있어, 가족력이 있는 경우 유전자 검사와 조기 검진이 권장됩니다. 부갑상선암은 조기 발견 시 수술로 치료 효과가 높으므로 고칼슘혈증이나 관련 증상이 있으면 내분비내과 전문의를 방문하시길 권고드립니다.', 2781, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선암', '부갑상선암', 'DIET_LIFE', '부갑상선암 치료 후 면역력 강화를 위해 단백질(닭고기, 생선, 두부), 항산화 영양소(채소, 과일), 아연과 비타민 C가 풍부한 식품을 충분히 섭취하는 것이 좋습니다. 규칙적인 가벼운 유산소 운동, 충분한 수면, 금연·금주가 면역 기능 유지에 도움이 됩니다. 치료 중 식이와 생활 습관에 대한 구체적인 지침은 담당 내분비내과 또는 종양내과 전문의와 상담하시길 권고드립니다.', 2782, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선암', '부갑상선암', 'MEDICATION', '부갑상선암은 약물만으로 완전한 치료가 어려우며, 수술적 절제(부갑상선암 및 주변 조직 제거)가 주된 치료입니다. 약물 치료는 수술 후 재발이나 전이 시 고칼슘혈증을 조절하는 목적으로 시나칼세트, 비스포스포네이트, 데노수맙 등을 사용합니다. 치료 전략은 내분비내과 및 외과 전문의의 다학제 협진을 통해 결정되어야 하므로 전문의 상담을 권고드립니다.', 2783, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선암', '부갑상선암', 'PREVENTION', '부갑상선암으로 인한 고칼슘혈증 예방을 위해 충분한 수분 섭취(하루 2L 이상)로 신장 결석 위험을 낮추고, 칼슘 과잉 보충제는 삼가며 저칼슘 식이를 유지하는 것이 도움이 됩니다. 정기적인 혈중 칼슘 및 PTH 모니터링을 통해 이상 수치를 조기에 발견하는 것이 중요합니다. 신경학적 증상이나 신장 결석 증상이 나타나면 즉시 내분비내과 전문의를 방문하시길 권고드립니다.', 2784, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선암', '부갑상선암', 'CAUSE', '부갑상선암의 정확한 발병 원인은 아직 완전히 밝혀지지 않았으나, HRPT2(CDC73) 유전자 돌연변이가 가장 중요한 위험 인자로 알려져 있습니다. 그 외 방사선 노출, MEN1(다발성 내분비 종양 1형) 등 유전성 내분비 질환, 이전의 부갑상선기능항진증도 관련이 있을 수 있습니다. 가족력이 있거나 유전성 질환이 의심된다면 내분비내과 전문의와 유전자 검사에 대해 상담하시길 권고드립니다.', 2785, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선암', '부갑상선암', 'REHAB', '부갑상선암 치료 중에는 담당 의료진이 지시한 정기 추적 검사(혈중 칼슘, PTH, 영상 검사)를 빠짐없이 받는 것이 가장 중요합니다. 피로를 최소화하는 범위에서의 가벼운 걷기 운동, 균형 잡힌 영양 섭취, 충분한 수면이 전반적인 건강 상태 유지에 도움이 됩니다. 항암 치료 중 운동 및 활동 계획은 담당 종양내과 또는 내분비내과 전문의와 상의하여 개인 상태에 맞게 조정하시길 권고드립니다.', 2786, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선암', '부갑상선암', 'DEFINITION', '부갑상선암은 목 앞쪽에 위치한 부갑상선에서 발생하는 악성 종양으로, PTH를 과잉 분비하여 심한 고칼슘혈증을 유발합니다. 원인은 HRPT2 유전자 돌연변이, 방사선 노출, 유전성 내분비 질환 등이 관련되나 대부분 원인 불명입니다. 방사선 치료는 부갑상선암에서 수술 후 재발 고위험 환자나 완전 절제가 어려운 경우 보조 요법으로 사용되며, 치료 계획은 내분비내과 및 외과 전문의와 상담하시길 권고드립니다.', 2787, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선암', '부갑상선암', 'SYMPTOM', '부갑상선암의 근본 치료는 수술적 절제이며, 재발이나 전이 시 시나칼세트, 비스포스포네이트 등의 약물로 고칼슘혈증을 조절합니다. 손발 저림은 수술 후 저칼슘혈증으로 인해 나타날 수 있으며, 이 경우 칼슘 보충제와 활성형 비타민 D 투여로 완화합니다. 치료 방법과 증상 관리는 내분비내과 전문의의 진료를 통해 개인 상태에 맞게 결정하시길 권고드립니다.', 2788, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선암', '부갑상선암', 'DIAGNOSIS', '부갑상선암 진단에서 가장 신뢰할 수 있는 방법은 조직 검사(병리 조직학적 검사)이며, 수술 중 또는 수술 후 적출된 조직으로 악성 여부를 최종 확인합니다. 혈액 검사(고칼슘혈증, 매우 높은 PTH)는 의심 단계에서 중요한 단서를 제공하고, 영상 검사(초음파, CT, 세스타미비 스캔)는 병변의 위치와 전이 여부를 평가합니다. 따라서 세 가지 검사가 상호 보완적으로 활용되며, 내분비내과 및 외과 전문의와 상담하시길 권고드립니다.', 2789, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부갑상선암', '부갑상선암', 'TREATMENT', '부갑상선암 수술 후 보조 요법으로 방사선 치료나 항암화학요법이 일부 환자에게 고려될 수 있으나, 효과가 제한적이어서 주로 재발 고위험 또는 전이 환자에게 적용됩니다. 수술 후 생활 습관으로는 충분한 수분 섭취, 균형 잡힌 식이, 금연·금주, 규칙적인 가벼운 운동, 정기적인 혈중 칼슘·PTH 추적 검사가 중요합니다. 수술 후 관리와 보조 치료 계획은 내분비내과 및 종양내과 전문의와 상담하여 결정하시길 권고드립니다.', 2790, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부신 기능부전', '부신기능부전', 'MEDICATION', '부신 기능부전은 코르티솔 등 부신 호르몬 분비가 부족한 상태로, 치료에 사용되는 글루코코르티코이드(하이드로코르티손, 프레드니솔론 등)는 용량이 너무 많거나 적어도 문제가 생길 수 있어 의사 처방 없이 임의로 조절해서는 안 됩니다. 또한 다른 약물이 스테로이드 대사에 영향을 미칠 수 있고, 약물 상호작용이나 부작용 위험이 있어 새로운 약물 추가 시 반드시 의사와 사전 상담이 필요합니다. 안전하고 효과적인 치료를 위해 내분비내과 전문의의 지속적인 관리를 받으시길 권고드립니다.', 2791, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부신 기능부전', '부신기능부전', 'CAUSE', '스테로이드를 장기간 사용하면 외부에서 공급된 코르티코스테로이드가 뇌하수체-부신 축을 억제하여 부신이 스스로 코르티솔을 만드는 능력이 저하됩니다. 스테로이드를 갑자기 중단하면 부신이 즉각적으로 충분한 코르티솔을 생산하지 못해 부신 기능부전(스테로이드 유발 2차 부신 기능부전)이 발생합니다. 스테로이드 감량과 중단은 반드시 내분비내과 전문의의 지도 하에 서서히 진행해야 합니다.', 2792, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부신 기능부전', '부신기능부전', 'DEFINITION', '스테로이드를 장기 복용하면 뇌하수체-부신 축이 억제되어 부신이 자체적으로 코르티솔을 생산하는 기능이 저하되는 2차성 부신 기능부전이 발생합니다. 이로 인해 코르티솔 분비가 부족해지면 저혈압, 저혈당, 피로, 구역, 전해질 불균형(저나트륨혈증) 등이 나타날 수 있으며, 감염이나 수술 같은 스트레스 상황에서는 부신 위기로 이어질 수 있습니다. 스테로이드 사용 중이라면 반드시 내분비내과 전문의의 지도 하에 용량 조절과 모니터링을 받으시길 권고드립니다.', 2793, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부신 기능부전', '부신기능부전', 'SYMPTOM', '부신 기능부전으로 코르티솔 분비가 저하되면 극심한 피로와 무력감, 식욕 부진과 체중 감소, 오심·구토 등이 나타납니다. 코르티솔과 알도스테론 부족으로 저혈압, 저혈당, 저나트륨혈증, 고칼륨혈증이 발생하고, 1차성(원발성) 부신 기능부전에서는 피부와 점막의 과색소 침착(피부 검게 변색)이 특징적으로 나타납니다. 이러한 증상이 의심된다면 내분비내과 전문의를 방문하여 혈액 검사와 부신 기능 검사를 받으시길 권고드립니다.', 2794, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부신 기능부전', '부신기능부전', 'DIAGNOSIS', '부신 기능부전은 내분비내과에서 주로 진단하며, 1차 의원급에서도 혈액 검사(혈중 코르티솔, ACTH)를 의뢰할 수 있으나 확진을 위한 부신 자극 검사(ACTH 자극 시험)와 영상 검사는 주로 종합병원 또는 대학병원 내분비내과에서 시행합니다. 경증 의심 환자도 1차 의료기관에서 혈액 검사를 통해 초기 평가 후 전문 의료기관으로 의뢰되는 경우가 많습니다. 증상이 있다면 우선 가까운 내과를 방문하여 상담하시길 권고드립니다.', 2795, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '부신 기능부전', '부신기능부전', 'TREATMENT', '식욕 부진, 체중 감소, 저혈압, 저혈당이 동반된 경우 부신 기능부전이 의심되며, 이는 내분비내과 전문의의 진료와 혈중 코르티솔·ACTH 검사가 필요한 상태입니다. 부신 기능부전으로 확진되면 하이드로코르티손 경구 보충 요법이 표준 치료이며, 저혈당·저혈압이 심한 경우 스트레스 용량(stress dose) 스테로이드 투여나 입원 치료가 필요할 수 있습니다. 자가 판단으로 스테로이드를 복용해서는 안 되며, 반드시 내분비내과 전문의의 진료를 받으시길 강력히 권고드립니다.', 2796, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '성장호르몬 결핍증', '성장호르몬결핍증', 'MEDICATION', '성장호르몬 결핍증 치료에 사용되는 재조합 인간 성장호르몬(rhGH) 주사의 부작용으로 관절통, 근육통, 부종, 두통, 손목 터널 증후군 등이 나타날 수 있습니다. 드물게 혈당 상승(인슐린 저항성 증가), 두개 내압 상승, 성인에서 이차성 종양 위험 증가도 보고됩니다. 부작용이 나타나면 용량 조절이 필요하므로 임의로 중단하지 말고 내분비내과 전문의와 상담하시길 권고드립니다.', 2797, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '성장호르몬 결핍증', '성장호르몬결핍증', 'CAUSE', '선천성 성장호르몬 결핍증은 출생 시부터 뇌하수체 발달 이상이나 유전자 돌연변이로 인해 성장호르몬 분비가 부족하며, 영아기부터 성장 지연이 나타납니다. 후천성 원인으로는 뇌하수체 종양, 뇌 방사선 치료, 두부 외상, 뇌수막염 등이 있으며, 이 경우 이전에는 정상 성장을 보이다가 특정 시점 이후 성장 속도가 감소합니다. 정확한 원인 감별을 위해 소아 내분비내과 또는 내분비내과 전문의의 진료를 받으시길 권고드립니다.', 2798, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '성장호르몬 결핍증', '성장호르몬결핍증', 'DEFINITION', '성장호르몬 결핍증은 뇌하수체에서 성장호르몬(GH) 분비가 불충분하여 소아에서 성장 지연, 성인에서 체성분 변화(체지방 증가, 근육량 감소) 등이 나타나는 질환입니다. 영양소 결핍과의 관련성은 직접적이지 않으나, 단백질·아연·비타민 D 결핍은 성장호르몬의 작용을 방해하고 성장에 부정적 영향을 줄 수 있습니다. 정확한 원인 평가와 치료는 소아 내분비내과 또는 내분비내과 전문의와 상담하시길 권고드립니다.', 2799, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '성장호르몬 결핍증', '성장호르몬결핍증', 'SYMPTOM', '소아에서 또래보다 현저히 키가 작고, 성장 속도가 느리며, 체지방이 많고 근육량이 적은 경우 성장호르몬 결핍증을 의심할 수 있습니다. 허약하고 활발하지 못한 행동도 성장호르몬 결핍으로 인한 근육량 감소 및 에너지 대사 저하의 증상일 수 있습니다. 성장 문제가 우려된다면 소아 내분비내과 전문의를 방문하여 성장 곡선 평가와 성장호르몬 자극 검사를 받으시길 권고드립니다.', 2800, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '성장호르몬 결핍증', '성장호르몬결핍증', 'DIAGNOSIS', '성장호르몬 결핍증 진단을 위해 성장호르몬 자극 검사(인슐린 저혈당 유발 검사, 아르기닌 자극 검사 등)가 필요하며, 이 검사는 수 시간이 소요됩니다. 비용은 병원과 검사 종류에 따라 다르나 수십만 원대이며, 건강보험 적용 여부는 담당 병원에서 확인해야 합니다. 골 연령 평가를 위한 손목 X선 검사와 뇌하수체 MRI를 병행할 수 있으며, 구체적인 검사 계획은 소아 내분비내과 전문의와 상담하시길 권고드립니다.', 2801, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '성장호르몬 결핍증', '성장호르몬결핍증', 'TREATMENT', '성장호르몬 결핍증의 가장 효과적인 치료는 재조합 인간 성장호르몬(rhGH) 피하 주사 요법으로, 소아에서 조기 시작할수록 성인 최종 키에 더 긍정적인 영향을 미칩니다. 성인 성장호르몬 결핍증에서도 rhGH 치료는 체성분 개선, 골밀도 증가, 삶의 질 향상에 효과적입니다. 치료 시작 시기와 용량은 나이, 원인 질환, 성장 상태 등을 고려하여 내분비내과 전문의와 상담하여 결정하시길 권고드립니다.', 2802, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '여성형 유방', '여성형유방', 'MEDICATION', '여성형 유방 치료에 사용되는 타목시펜, 랄록시펜 등의 약물은 전문의약품으로 의사 처방 없이 약국에서 구매할 수 없습니다. 약국에서 처방 없이 구매 가능한 여성형 유방 치료 약물은 현재 국내에 없으므로, 임의로 보조제를 복용하는 것은 권장되지 않습니다. 여성형 유방 증상이 있다면 비뇨의학과 또는 내분비내과 전문의를 방문하여 원인 평가와 처방을 받으시길 권고드립니다.', 2803, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '여성형 유방', '여성형유방', 'CAUSE', '여성형 유방은 남성에서 여성 호르몬(에스트로겐)에 대한 남성 호르몬(테스토스테론)의 상대적 비율 저하로 유방 조직이 증식하여 발생합니다. 비뇨생식계 이상으로 고환 기능 저하(클라인펠터 증후군, 고환 종양 등)가 생기면 테스토스테론 분비가 감소하고 상대적 에스트로겐 과다 상태가 되어 여성형 유방을 유발할 수 있습니다. 원인 평가를 위해 비뇨의학과 또는 내분비내과 전문의의 진료를 받으시길 권고드립니다.', 2804, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '여성형 유방', '여성형유방', 'DEFINITION', '여성형 유방(여유증)은 남성에서 유방 조직(유선 조직)이 비정상적으로 증식하여 유방이 여성처럼 커지는 상태입니다. 청소년기(사춘기) 남자아이의 약 50~70%에서 호르몬 변화로 인해 일시적으로 발생하며, 대부분 2년 이내에 자연 소실됩니다. 지속되거나 성인에서 발생한 경우 호르몬 이상이나 약물 부작용 등 원인을 찾아야 하므로 내분비내과 또는 비뇨의학과 전문의 상담을 권고드립니다.', 2805, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '여성형 유방', '여성형유방', 'SYMPTOM', '여성형 유방에서 남성의 흉부 유방 조직이 증식하면 유두 아래 단단하고 압통이 있는 원형 결절이 먼저 촉지되고, 이후 유방 전체 크기가 증가하여 여성의 유방과 유사한 형태로 발달합니다. 한쪽 또는 양쪽에 발생할 수 있으며, 유두 분비물, 유방 통증이나 압통이 동반될 수 있습니다. 유방에 덩어리가 만져지면 유방암과 감별이 필요하므로 내분비내과 또는 외과 전문의의 진료를 받으시길 권고드립니다.', 2806, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '여성형 유방', '여성형유방', 'DIAGNOSIS', '남성도 유방 초음파 또는 유방 X선 촬영(맘모그래피), 신체 검진을 통해 여성형 유방 여부를 확인할 수 있으며, 비뇨의학과, 내분비내과, 외과에서 진단이 가능합니다. 원인 감별을 위해 혈중 테스토스테론, 에스트라디올, LH, FSH, 갑상선 호르몬 등의 혈액 검사도 시행됩니다. 유방 조직이 만져지거나 비대해진다면 유방암과의 감별을 위해 반드시 전문의의 진료를 받으시길 권고드립니다.', 2807, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '여성형 유방', '여성형유방', 'TREATMENT', '여성형 유방의 약물 치료로 타목시펜(항에스트로겐제) 또는 아나스트로졸(아로마타제 억제제)이 초기 단계에서 효과적이며, 원인 약물이 있다면 해당 약물 중단이 우선됩니다. 수술 치료(유방 조직 절제술, 지방 흡입술)는 약물 치료에 반응이 없거나 조직이 이미 섬유화된 경우, 심미적 문제가 큰 경우에 선택합니다. 가장 적합한 치료 방법은 원인과 중증도에 따라 달라지므로 비뇨의학과 또는 내분비내과 전문의와 상담하시길 권고드립니다.', 2808, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '요붕증', '요붕증', 'DIET_LIFE', '소변이 희뿌옇고 배뇨 시 통증이 있는 증상은 요로 감염이나 전립선 질환일 가능성이 높으며, 이는 요붕증의 전형적 증상이 아닙니다. 요붕증 환자는 묽고 무색의 소변을 하루 3~20L 이상 다량 배출하는 것이 특징이며, 생활 관리로는 충분한 수분 섭취로 탈수를 예방하고 카페인·알코올을 제한하는 것이 도움이 됩니다. 정확한 원인 감별을 위해 비뇨의학과 또는 내분비내과 전문의의 진료를 먼저 받으시길 권고드립니다.', 2809, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '요붕증', '요붕증', 'MEDICATION', '요붕증은 항이뇨호르몬(ADH, 바소프레신) 결핍이나 신장의 ADH 반응 저하로 발생하며, 현재 표준 치료는 합성 ADH 유사체인 데스모프레신(DDAVP) 투여입니다. 한약이 요붕증에 과학적으로 검증된 효과가 있다는 근거는 불충분하며, 데스모프레신과 비교할 만한 치료 효과를 기대하기 어렵습니다. 치료 방법은 내분비내과 전문의와 상담하여 근거 기반의 치료를 받으시길 권고드립니다.', 2810, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '요붕증', '요붕증', 'CAUSE', '임신 중 수분 섭취 증가와 빈뇨는 주로 태아 성장에 따른 방광 압박, 혈액량 증가, 신장 여과율 상승 등 생리적 변화로 인해 나타나는 정상적인 현상입니다. 그러나 하루 소변량이 비정상적으로 많고(다뇨) 농도가 매우 낮은 경우, 임신성 요붕증(임신 중 바소프레신 분해 효소 증가로 인한 일시적 요붕증)을 드물게 의심할 수 있습니다. 임신 중 비정상적인 다음·다뇨 증상이 있다면 산부인과 또는 내분비내과 전문의와 상담하시길 권고드립니다.', 2811, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '요붕증', '요붕증', 'DEFINITION', '요붕증은 항이뇨호르몬(ADH) 결핍(중추성) 또는 신장의 ADH 반응 저하(신성)로 인해 수분 재흡수가 안 되어 하루 3L 이상의 묽은 소변이 과다 배출되고 극심한 갈증이 동반되는 질환입니다. 이로 인해 탈수, 고나트륨혈증, 전해질 불균형이 발생하여 피로, 두통, 심하면 의식 변화까지 나타날 수 있습니다. 다음·다뇨 증상이 있다면 내분비내과 전문의를 방문하여 수분 박탈 검사 등 정밀 진단을 받으시길 권고드립니다.', 2812, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '요붕증', '요붕증', 'SYMPTOM', '요붕증의 주요 증상은 하루 3~20L에 달하는 대량의 묽은 소변 배출(다뇨)과 이에 따른 극심한 갈증(다음), 탈수입니다. 탈수로 인해 두통, 집중력 저하, 피로, 심하면 발열과 의식 변화가 동반될 수 있으며, 수분을 충분히 보충하지 못하면 고나트륨혈증과 혈액 농축이 발생합니다. 야간뇨와 수면 장애도 흔하게 나타나며, 정확한 진단을 위해 내분비내과 전문의 상담을 권고드립니다.', 2813, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '요붕증', '요붕증', 'DIAGNOSIS', '요붕증 진단 시 주요 주의 증상은 하루 3L 이상의 지속적인 다뇨와 극심한 갈증(다음)이며, 소변 색깔이 거의 무색에 가깝고 비중이 매우 낮은 것이 특징입니다. 소변에 피가 섞이는 혈뇨는 요붕증의 증상이 아니며, 혈뇨가 있다면 신장 결석, 방광염, 신장 질환 등을 별도로 감별해야 합니다. 다뇨와 다음이 함께 나타난다면 내분비내과 전문의를 방문하여 수분 박탈 검사를 받으시길 권고드립니다.', 2814, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '요붕증', '요붕증', 'TREATMENT', '중추성 요붕증의 1차 약물 치료는 합성 항이뇨호르몬 유사체인 데스모프레신(DDAVP)으로, 비강 내 분무, 경구 복용, 피하 주사 등 다양한 형태로 투여됩니다. 신성 요붕증에는 염분 제한, 수분 충분 섭취와 함께 티아지드계 이뇨제, 인도메타신 등이 사용될 수 있습니다. 적합한 약물과 용량은 요붕증의 종류와 중증도에 따라 다르므로 내분비내과 전문의와 상담하시길 권고드립니다.', 2815, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '유방 종양', '유방종양', 'CHECKUP', '유방 종양 진단 후 재발 예방을 위해 정기적인 유방 자가 검진과 병원 추적 검사(유방 초음파, 맘모그래피)가 중요합니다. 건강한 체중을 유지하고, 규칙적인 신체 활동, 금주, 균형 잡힌 식이, 스트레스 관리가 도움이 됩니다. 유방 조직이 밖으로 돌출되는 증상은 즉시 외과 또는 유방 전문 클리닉에서 평가받으시길 권고드립니다.', 2816, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '유방 종양', '유방종양', 'CAUSE', '유방 종양의 발생은 임신 중 단유보다는 호르몬 불균형, 유전적 요인, 방사선 노출 등과 더 관련이 있습니다. 임신 중 단유(젖을 억제하는 것)와 출산 후 단유 중 어느 것이 더 부작용이 많다는 과학적 근거는 명확하지 않으며, 모유 수유 지속이 유방 종양 위험을 오히려 낮출 수 있다는 연구가 있습니다. 유방 종양 진단을 받으셨다면 산부인과 또는 외과 전문의와 수유 관련 결정에 대해 상담하시길 권고드립니다.', 2817, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '유방 종양', '유방종양', 'DEFINITION', '유방 종양은 유방 조직에 발생하는 종괴(덩어리)로, 양성(섬유선종, 낭종 등)과 악성(유방암)으로 나뉩니다. 주요 증상으로 유방 내 만져지는 덩어리, 유방 통증, 유두 분비물, 피부 변화(함몰, 주름) 등이 있으며, 원인으로는 호르몬 요인, 유전적 요인(BRCA1/2 돌연변이), 방사선 노출, 생활 습관 등이 관련됩니다. 유방에 덩어리가 만져지면 즉시 외과 또는 유방외과 전문의를 방문하여 초음파 및 조직 검사를 받으시길 권고드립니다.', 2818, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '유방 종양', '유방종양', 'SYMPTOM', '오른쪽 유방에서 동그랗고 경계가 명확한 덩어리가 촉지되는 것은 유방 종양의 흔한 증상이며, 유방 종양은 림프종과는 별개의 질환입니다. 양성 유방 종양(섬유선종, 낭종)은 경계가 명확하고 부드러우며 잘 움직이는 경향이 있고, 악성인 경우 딱딱하고 불규칙한 경계와 고정된 양상을 보일 수 있습니다. 유방 덩어리는 원인 불문하고 외과 또는 유방외과 전문의를 방문하여 정확한 진단을 받으시길 권고드립니다.', 2819, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '유방 종양', '유방종양', 'DIAGNOSIS', '유방 종양 검진은 유방외과(외과), 영상의학과에서 주로 담당하며, 산부인과도 유방 초음파 검사를 시행하는 곳이 있어 접근성이 높습니다. 산부인과는 특히 임신·수유 관련 유방 문제나 여성 건강 검진 시 유방 초음파를 함께 시행하여 조기 발견에 기여합니다. 단, 유방암이 의심되거나 조직 검사가 필요한 경우에는 유방외과 전문의에게 의뢰하는 것이 정확한 진단과 치료에 가장 적합합니다.', 2820, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '유방 종양', '유방종양', 'TREATMENT', '유방암의 수술 방법으로는 종양만 제거하는 유방 보존술(부분 절제술)과 유방 전체를 제거하는 전절제술(유방 절제술)이 있으며, 림프절 전이 여부에 따라 감시 림프절 생검 또는 액와 림프절 절제술이 병행됩니다. 수술의 목적은 종양 완전 제거와 재발 방지이며, 예상 회복 기간은 수술 방법에 따라 다르지만 일반적으로 퇴원까지 1~7일, 일상 복귀까지 2~6주 정도 소요됩니다. 수술 방법과 예후는 담당 유방외과 전문의와 자세히 상담하시길 권고드립니다.', 2821, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '유선염', '유선염', 'MEDICATION', '모유 수유 중 유선염으로 통증이 있을 때, 이부프로펜이나 아세트아미노펜은 모유로 소량만 이행되어 수유 중에도 비교적 안전하게 사용할 수 있는 진통제로 권장됩니다. 단, 아스피린은 신생아 라이 증후군 위험으로 수유 중 피해야 합니다. 모유 수유 중 약물 복용은 산부인과 또는 내과 전문의와 반드시 상담하여 용량과 복용 시기를 조정하시길 권고드립니다.', 2822, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '유선염', '유선염', 'PREVENTION', '수유 중 유즙이 유방에 오래 고이면 세균이 번식하기 좋은 환경이 조성되고, 정체된 유즙이 유관을 막아 염증을 일으키는 유선염이 발생하기 쉽습니다. 규칙적이고 완전한 수유 또는 유축을 통해 유방을 자주 비워주면 유즙 정체와 세균 감염을 예방할 수 있습니다. 유선염 증상(발열, 유방 발적, 통증)이 나타나면 즉시 산부인과 전문의의 진료를 받으시길 권고드립니다.', 2823, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '유선염', '유선염', 'CAUSE', '유선염의 가장 흔한 원인은 수유 중 유즙 정체로 인한 세균(주로 포도상구균) 감염이며, 유두 균열을 통해 세균이 유관으로 침입하는 경우가 많습니다. 예방을 위해 올바른 수유 자세로 유방을 완전히 비우고, 유두 균열 시 즉시 치료하며 유방을 청결히 유지하는 것이 중요합니다. 증상이 나타나면 조기에 산부인과 전문의를 방문하여 항생제 치료를 받으시길 권고드립니다.', 2824, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '유선염', '유선염', 'DEFINITION', '유선염은 주로 수유 중 여성에서 유즙 정체와 세균 감염으로 발생하는 흔한 질환이지만, 비수유 여성이나 남성에서도 유관 확장증, 자가면역질환, 유두 피어싱 등으로 인해 비감염성 또는 감염성 유선 염증이 발생할 수 있습니다. 비수유성 유선염도 동일한 유선 조직의 염증이므로 같은 범주의 질환으로 분류됩니다. 수유 여부와 무관하게 유방 통증과 발열이 동반된다면 외과 또는 산부인과 전문의의 진료를 받으시길 권고드립니다.', 2825, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '유선염', '유선염', 'SYMPTOM', '수유 중 발열, 유방 국소 열감, 발적, 통증, 부종은 유선염의 전형적인 증상입니다. 수유 여성은 유즙 정체와 세균 감염으로 유선염이 발생하기 쉬우며, 체온이 38도 이상 상승하고 독감 유사 증상이 동반되면 유선염을 적극적으로 의심해야 합니다. 이러한 증상이 나타나면 즉시 산부인과 또는 외과 전문의를 방문하여 항생제 치료 등 적절한 치료를 받으시길 권고드립니다.', 2826, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '유선염', '유선염', 'DIAGNOSIS', '유선염 치료에 사용되는 항생제(주로 디클록사실린, 세팔렉신 등)는 모유로 매우 소량 이행되므로 대부분의 경우 수유를 지속해도 안전합니다. 진통제(이부프로펜, 아세트아미노펜)도 수유 중 비교적 안전하지만, 아스피린은 피해야 합니다. 약물의 안전성은 약물 종류와 용량에 따라 달라지므로 처방 전 산부인과 또는 소아과 전문의에게 수유 중 안전성을 반드시 확인하시길 권고드립니다.', 2827, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '유선염', '유선염', 'TREATMENT', '유선염의 기본 치료는 원인균(주로 황색포도상구균)에 대한 항생제(디클록사실린, 세팔렉신 등) 10~14일 복용과 함께 수유 또는 유축을 지속하여 유방을 비우는 것입니다. 농양이 형성된 경우 절개 배농 또는 초음파 유도 흡인이 필요하며, 진통제와 온찜질로 통증을 완화합니다. 치료 지연 시 재발성 유선염이나 농양으로 발전할 수 있으므로 증상 초기에 산부인과 또는 외과 전문의의 진료를 받으시길 권고드립니다.', 2828, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '제1형 당뇨병', '제1형당뇨병', 'MEDICATION', '제1형 당뇨병의 근본 치료는 인슐린 보충이며, 인슐린 펌프나 다회 주사 요법이 사용됩니다. 메트포르민이 일부 제1형 당뇨병 환자에서 인슐린 요구량 감소에 도움이 될 수 있다는 연구가 있으나, 인슐린이 절대적으로 부족한 제1형 당뇨병에서 인슐린 내성을 개선하는 경구 약물의 역할은 제2형과 달리 제한적입니다. 약물 치료 계획은 내분비내과 전문의와 상담하여 개인 상태에 맞게 결정하시길 권고드립니다.', 2829, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '제1형 당뇨병', '제1형당뇨병', 'PREVENTION', '제1형 당뇨병은 자가면역에 의한 췌장 베타세포 파괴가 원인으로, 현재까지 확립된 1차 예방법은 없습니다. 다만 고위험군(가족력, 자가항체 양성자)에서 면역 조절 치료 연구가 진행 중이며, 체중 관리는 인슐린 저항성을 낮추는 데 도움이 되나 근본 예방과는 다릅니다. 지속적인 혈당 모니터링, 인슐린 치료 준수, 정기 합병증 검진이 중요하므로 내분비내과 전문의와 꾸준히 상담하시길 권고드립니다.', 2830, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '제1형 당뇨병', '제1형당뇨병', 'CAUSE', '제1형 당뇨병은 자가면역 반응에 의해 췌장의 인슐린 생산 베타세포가 파괴되어 인슐린이 절대적으로 부족해지는 질환입니다. 인슐린이 없으면 세포가 포도당을 이용하지 못해 지방과 근육이 분해되면서 체중 감소가 발생하고, 혈당 상승으로 신장에서 포도당이 소변으로 배출되면서 삼투성 이뇨로 야뇨증과 다뇨가 나타납니다. 즉 체중 감소와 야뇨증은 원인이 아닌 인슐린 결핍의 결과로 나타나는 증상이므로 내분비내과 전문의의 진료를 받으시길 권고드립니다.', 2831, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '제1형 당뇨병', '제1형당뇨병', 'DEFINITION', '제1형 당뇨병은 자가면역에 의한 췌장 베타세포 파괴로 인슐린 분비가 거의 없는 상태로, 인슐린 저항성이 주된 특징인 제2형 당뇨병과 구별됩니다. 인슐린 절대 부족으로 다음(갈증), 다뇨, 체중 감소, 피로, 시력 변화가 나타나며, 치료하지 않으면 당뇨병성 케톤산증으로 이어질 수 있습니다. 정확한 감별 진단을 위해 내분비내과 전문의의 진료와 C-펩타이드, 자가항체 검사가 필요합니다.', 2832, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '제1형 당뇨병', '제1형당뇨병', 'SYMPTOM', '제1형 당뇨병 환자에서 과도한 다뇨는 소변량을 증가시키는 것이며, 이로 인해 탈수가 심해지면 오히려 소변 생성량이 감소할 수 있습니다. 심한 탈수는 혈압 저하, 전해질 불균형, 신기능 저하, 당뇨병성 케톤산증 악화로 이어질 수 있는 의학적 응급 상황입니다. 다뇨 증상이 심하다면 즉시 내분비내과 전문의를 방문하거나 응급실을 이용하시길 강력히 권고드립니다.', 2833, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '제1형 당뇨병', '제1형당뇨병', 'DIAGNOSIS', '제1형과 제2형 당뇨병 모두 공복혈당 126mg/dL 이상, 당화혈색소(HbA1c) 6.5% 이상, 또는 포도당 부하 검사 2시간 혈당 200mg/dL 이상이면 당뇨병으로 진단됩니다. 그러나 두 유형의 감별을 위해 C-펩타이드(인슐린 분비 능력), 항GAD 항체·항IA-2 항체 등 자가항체 검사를 추가로 시행합니다. 이러한 감별 검사 결과에 따라 치료 방향이 달라지므로 내분비내과 전문의와 상담하시길 권고드립니다.', 2834, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '제1형 당뇨병', '제1형당뇨병', 'TREATMENT', '제1형 당뇨병의 표준 치료는 인슐린 집중 요법(다회 주사 또는 지속 피하 인슐린 주입 펌프)이며, 연속 혈당 모니터링 시스템(CGM)과 인슐린 펌프를 결합한 인공 췌장 시스템이 최신 치료로 주목받고 있습니다. 면역 조절 치료(테플리주맙 등)가 발병 초기 단계에서 베타세포 기능 보존에 일부 효과가 있음이 연구되고 있으며, 췌장 또는 췌도 이식도 선별된 환자에서 고려됩니다. 치료 방법에 대한 자세한 상담은 내분비내과 전문의와 함께 진행하시길 권고드립니다.', 2835, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '쿠싱 증후군', '쿠싱증후군', 'CAUSE', '쿠싱 증후군에서 얼굴이 둥글게 되는 것(moon face)과 팔다리가 가늘어지는 것은 코르티솔 과잉으로 인한 지방 재분포와 근육 소모(근위부 근육 위축)의 증상입니다. 즉 이는 쿠싱 증후군의 원인이 아니라 코르티솔 과잉 상태에서 나타나는 특징적인 임상 증상으로 분류됩니다. 이러한 체형 변화와 함께 고혈압, 고혈당, 피부 선조 등이 동반된다면 내분비내과 전문의를 방문하여 정밀 검사를 받으시길 권고드립니다.', 2836, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '쿠싱 증후군', '쿠싱증후군', 'DEFINITION', '쿠싱 증후군은 코르티솔(부신 피질 호르몬)이 장기간 과도하게 분비되거나 외부에서 공급되어 나타나는 임상 증후군으로, 복부 비만, 달 모양 얼굴, 물소 등(buffalo hump), 피부 선조, 고혈압, 당뇨 등 다양한 특징적 증상이 나타납니다. 원인으로는 뇌하수체 선종(ACTH 과잉 분비, 쿠싱병), 부신 선종, 이소성 ACTH 분비 종양, 장기간 스테로이드 복용 등이 있습니다. 의심 증상이 있다면 내분비내과 전문의를 방문하여 정밀 검사를 받으시길 권고드립니다.', 2837, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '쿠싱 증후군', '쿠싱증후군', 'SYMPTOM', '쿠싱 증후군에서 피부 변화(복부 선조, 피부 얇아짐), 여드름, 조모증, 홍조, 혈당·혈압 상승이 복합적으로 나타나는 경우 코르티솔 과잉이 강하게 시사됩니다. 치료는 원인에 따라 다르며, 뇌하수체 선종이 원인이면 수술(경접형골 수술)이 우선이고, 약물(케토코나졸, 메티라폰, 파시레오타이드 등)이나 방사선 치료가 보조적으로 사용됩니다. 치료 방법 선택은 내분비내과 전문의와의 상담을 통해 결정하시길 권고드립니다.', 2838, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '쿠싱 증후군', '쿠싱증후군', 'DIAGNOSIS', '전신에 털이 증가하는 조모증과 함께 복부 비만, 보라색 선조, 고혈압, 고혈당, 달 모양 얼굴이 동반된다면 코르티솔 과잉을 유발하는 쿠싱 증후군을 의심해야 합니다. 진단을 위해 24시간 소변 유리 코르티솔 측정, 야간 덱사메타손 억제 검사, 혈중 ACTH 검사, 뇌하수체 MRI 등이 시행됩니다. 조모증이나 쿠싱 증후군이 의심된다면 내분비내과 전문의를 방문하여 정밀 검사를 받으시길 권고드립니다.', 2839, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '쿠싱 증후군', '쿠싱증후군', 'TREATMENT', '쿠싱 증후군 원인 종양 제거 후에도 코르티솔 수치가 정상화되었는지 확인하기 위해 수술 후 혈중 코르티솔, 24시간 소변 코르티솔, ACTH 검사를 시행합니다. 완전 절제되지 않았거나 재발한 경우에는 덱사메타손 억제 검사와 뇌하수체 또는 복부 MRI·CT 추적 검사가 필요합니다. 수술 후 잔존 증상이나 재발 여부 평가는 내분비내과 전문의의 지속적인 추적 관찰을 통해 확인하시길 권고드립니다.', 2840, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '흉선암', '흉선암', 'CHECKUP', '흉선암 조기 발견을 위해 가장 유용한 검사는 흉부 CT(컴퓨터 단층촬영)로, 전종격동의 종양을 세밀하게 평가할 수 있습니다. 흉부 X선 검사는 기본 선별로 활용되며, PET-CT는 전이 여부 평가에 사용됩니다. 흉선암은 증상이 없는 경우 건강검진에서 우연히 발견되는 경우가 많으므로, 정기적인 흉부 검진을 통한 조기 발견이 중요하며 흉부외과 또는 종양내과 전문의와 상담하시길 권고드립니다.', 2841, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '흉선암', '흉선암', 'CAUSE', '흉선암의 원인은 대부분 명확히 밝혀지지 않았으나, 방사선 노출, 유전적 소인, 면역 이상 등이 관련 요인으로 거론됩니다. 또한 일부 흉선암에서 EGFR, KIT, CDKN2A 유전자 변이가 발견되어 분자 수준의 유전적 이상도 관련이 있는 것으로 알려져 있습니다. 흉선암은 드문 악성 종양이므로 발생 원인과 치료에 대해 흉부외과 또는 종양내과 전문의와 상담하시길 권고드립니다.', 2842, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '흉선암', '흉선암', 'DEFINITION', '흉선암은 흉부 전종격동에 위치한 흉선에서 발생하는 악성 종양으로, 흉선종보다 악성도가 높습니다. 주요 증상으로 흉통, 기침, 호흡 곤란, 상대정맥 증후군(얼굴·목 부종), 중증 근무력증 동반 등이 있으나, 초기에는 무증상으로 흉부 X선이나 CT에서 우연히 발견되는 경우가 많습니다. 흉부 촬영에서 종격동 종양이 발견되었다면 즉시 흉부외과 또는 종양내과 전문의를 방문하여 정밀 검사와 치료 계획을 수립하시길 권고드립니다.', 2843, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '흉선암', '흉선암', 'SYMPTOM', '팔과 어깨 통증은 흉선암이 인접 신경이나 혈관을 침범하거나 상대정맥 증후군이 발생할 때 나타날 수 있습니다. 흉선 부위의 단단한 덩어리가 촉지되거나 영상 검사에서 전종격동 종괴가 확인되면 흉선암을 포함한 종격동 종양에 대한 정밀 검사가 필요합니다. 이러한 증상들이 있다면 즉시 흉부외과 또는 종양내과 전문의를 방문하여 흉부 CT 및 조직 검사를 받으시길 강력히 권고드립니다.', 2844, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '흉선암', '흉선암', 'DIAGNOSIS', '흉선암이 의심된다는 소견을 받으셨다면 흉부외과 또는 종양내과 전문의를 통해 CT, PET 검사 및 조직 생검 등 정밀 검사를 받는 것이 필요합니다. 타 병원 방문이 불안하다면 상급종합병원의 흉부외과나 종양내과로 진료를 의뢰받아 확진 검사를 진행하시기 바랍니다. 빠른 정확한 진단과 병기 결정이 치료 방향 설정에 중요하므로 전문의 상담을 권고합니다.', 2845, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유방내분비질환', '흉선암', '흉선암', 'TREATMENT', '흉선암의 치료는 병기, 절제 가능 여부, 환자 전신 상태에 따라 수술, 방사선치료, 항암화학요법을 단독 또는 병합하여 결정합니다. 완전 절제가 가능한 경우 수술이 가장 우선되며, 절제 불가능한 경우에는 항암방사선 병합치료를 시행합니다. 최적의 치료 방침은 다학제 팀의 논의를 통해 결정되므로 반드시 전문의 상담을 받으시기 바랍니다.', 2846, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '갈락토오스혈증', '갈락토오스혈증', 'DIET_LIFE', '갈락토오스혈증은 갈락토오스-1-인산 우리딜트랜스퍼라제 효소 결핍으로 갈락토오스가 체내에 축적되는 선천성 대사질환으로, 우유의 유당(락토오스)이 소화되면 갈락토오스와 포도당으로 분해됩니다. 이때 갈락토오스를 대사하지 못해 축적되면서 독성 물질이 생성되어 간, 뇌, 눈에 손상을 일으킵니다. 유당 소화불량은 락타아제 부족으로 유당 분해가 안 되는 것이고, 갈락토오스혈증은 분해 이후 갈락토오스 대사 자체가 불가능한 별개의 심각한 대사 장애입니다.', 2847, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '갈락토오스혈증', '갈락토오스혈증', 'CAUSE', '갈락토오스혈증 환아는 모유와 일반 분유에 포함된 유당이 분해되어 생성되는 갈락토오스를 대사하지 못하므로 모유 수유 시 갈락토오스가 혈액에 축적됩니다. 이로 인해 신생아기에 황달, 구토, 저혈당, 간부전 등 심각한 증상이 나타나며 생명을 위협할 수 있습니다. 따라서 진단 즉시 갈락토오스가 없는 특수분유로 교체해야 하며, 반드시 신생아과 전문의 지도하에 식이를 관리해야 합니다.', 2848, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '갈락토오스혈증', '갈락토오스혈증', 'DEFINITION', '갈락토오스혈증은 갈락토오스 대사에 필요한 효소(주로 GALT)의 선천적 결핍으로 갈락토오스 및 독성 대사산물이 체내에 축적되는 상염색체 열성 유전질환입니다. 효소 결핍 시 갈락토오스-1-인산과 갈락티톨이 간, 뇌, 신장, 눈에 축적되어 간경화, 지적장애, 백내장, 패혈증 등 심각한 합병증을 유발합니다. 신생아 선별검사를 통해 조기 발견하고 갈락토오스 제한 식이를 시작하는 것이 예후 개선에 필수적입니다.', 2849, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '갈락토오스혈증', '갈락토오스혈증', 'SYMPTOM', '갈락토오스혈증의 주요 증상은 신생아기에 수유 후 구토, 설사, 황달, 저혈당, 기면, 체중 증가 불량으로 시작됩니다. 치료받지 않을 경우 간비대, 간경화, 백내장, 지적장애, 패혈증(특히 대장균 패혈증) 등으로 진행될 수 있습니다. 증상이 의심될 경우 즉시 수유를 중단하고 소아과 전문의 진료를 받아야 합니다.', 2850, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '갈락토오스혈증', '갈락토오스혈증', 'DIAGNOSIS', '갈락토오스혈증으로 성인이 되어도 갈락토오스 제한 식이를 유지하더라도 인지 기능 저하, 언어 장애, 운동 실조, 난소 기능 부전(여성의 경우) 등 장기 합병증이 나타날 수 있습니다. 성인기에 재진단되는 경우 이미 어느 정도의 합병증이 진행된 상태일 수 있어 불임, 골다공증, 신경학적 문제가 일상생활에 영향을 줄 수 있습니다. 정기적인 전문의 추적 관찰과 대사 관리가 삶의 질 유지에 중요합니다.', 2851, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '갈락토오스혈증', '갈락토오스혈증', 'TREATMENT', '갈락토오스혈증은 상염색체 열성 유전이므로 부모 모두 보인자인 경우 자녀에게 25%의 확률로 발병합니다. 가족 중 환자가 있다면 유전 상담을 통해 보인자 검사를 시행하고, 임신 시 산전 유전자 검사(양수 검사 또는 융모막 검사)로 태아의 이환 여부를 확인할 수 있습니다. 근본적인 유전자 치료는 아직 임상 적용 단계가 아니므로 유전 전문의 상담을 통해 가족계획을 세우시기 바랍니다.', 2852, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '골형성부전증', '골형성부전증', 'CAUSE', '골형성부전증은 주로 COL1A1 또는 COL1A2 유전자 돌연변이로 인한 제1형 콜라겐 결함이 원인이며, 90% 이상은 상염색체 우성 유전이지만 드물게 열성 유전도 나타납니다. 유전 외에도 자연 발생적 신규 돌연변이(de novo mutation)가 전체 환자의 약 25~30%에서 발생하며, 콜라겐 단백질의 양적 부족 또는 질적 이상 모두 원인이 될 수 있습니다. 골밀도 저하와 뼈의 구조적 결함이 복합적으로 작용하여 골절 취약성을 높입니다.', 2853, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '골형성부전증', '골형성부전증', 'DEFINITION', '골형성부전증은 콜라겐 결함으로 인해 뼈가 쉽게 부러지는 선천성 유전질환으로, 심장 기능 저하 자체를 정의로 하지는 않습니다. 다만 중증 골형성부전증(3형, 4형)에서는 흉곽 변형으로 인한 호흡 제한과 이로 인한 심폐 기능 저하가 합병증으로 나타날 수 있습니다. 심장 관련 증상이 동반된 경우 소아청소년과 및 심장내과 전문의의 협진 평가가 필요합니다.', 2854, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '골형성부전증', '골형성부전증', 'SYMPTOM', '골형성부전증 환자는 피로감 외에 반복적인 골절과 골절 후 통증, 척추 측만증, 키가 작은 성장 지연, 파란 공막, 치아 발육 이상(치아형성부전증), 청력 소실 등이 동반될 수 있습니다. 중증의 경우 흉곽 변형으로 인한 호흡 곤란과 심폐 기능 저하도 나타납니다. 증상의 종류와 중증도는 골형성부전증 유형(1~4형 등)에 따라 다르므로 전문의의 평가가 필요합니다.', 2855, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '골형성부전증', '골형성부전증', 'DIAGNOSIS', '소아청소년과 또는 정형외과 전문의와 상담 시 골절 빈도, 골절 유발 원인의 경미함 여부, 가족력, 파란 공막, 치아 이상, 성장 지연 등을 상세히 설명해야 합니다. 진단에는 방사선 검사, 골밀도 측정(DEXA), 필요 시 피부 콜라겐 분석이나 유전자 검사가 활용됩니다. 아동 학대와의 감별이 중요하므로 다학제 전문팀의 평가를 받는 것이 권장됩니다.', 2856, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '골형성부전증', '골형성부전증', 'TREATMENT', '현재 골형성부전증의 가장 효과적인 치료로는 비스포스포네이트 제제(파미드로네이트, 졸레드론산) 투여가 표준 치료로 사용되며 골밀도 증가와 골절 감소 효과가 있습니다. 최근에는 로모소주맙, 데노수맙 등 새로운 약물과 유전자 치료 연구도 진행 중이지만 일부는 아직 연구 단계입니다. 수술적 교정(골내 금속봉 삽입)과 물리치료를 병행하는 다학제적 접근이 필요하므로 전문의 상담을 권고합니다.', 2857, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '근긴장성 이영양증', '근긴장성이영양증', 'CAUSE', '근긴장성 이영양증(myotonic dystrophy)은 유전적 요인이 핵심 원인으로, 1형은 19번 염색체 DMPK 유전자의 CTG 삼핵산 반복 확장, 2형은 3번 염색체 CNBP 유전자의 CCTG 반복 확장이 원인입니다. 이 반복 서열이 비정상적으로 늘어날수록 증상이 더 심해지는 경향이 있으며(표현촉진현상), 부모에서 자녀로 전달될 때 반복 수가 더 늘어날 수 있습니다. 환경적 요인이나 후천적 원인보다는 상염색체 우성 유전이 발병의 주된 기전입니다.', 2858, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '근긴장성 이영양증', '근긴장성이영양증', 'DEFINITION', '근긴장성 이영양증은 상염색체 우성 유전질환으로, 1형은 19번 염색체 DMPK 유전자의 CTG 반복 확장, 2형은 3번 염색체 CNBP 유전자의 CCTG 반복 확장으로 발생합니다. 근긴장성 이영양증은 근육이 수축 후 이완이 느려지는 근긴장증과 진행성 근력 약화를 특징으로 하는 신경근육계 유전질환입니다. 유전자 변이 확인을 위한 분자유전학적 검사를 통해 진단할 수 있으며, 신경과 전문의 상담을 권고합니다.', 2859, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '근긴장성 이영양증', '근긴장성이영양증', 'SYMPTOM', '영아기 근긴장성 이영양증에서는 근긴장 저하로 인해 물건 잡기, 빨기, 삼키기 등 운동 기능이 전반적으로 저하될 수 있어 의심 근거가 될 수 있습니다. 다만 이는 다른 신경근육질환에서도 나타날 수 있으므로, 가족력(특히 어머니의 근긴장 증상), 안면 근력 약화, 호흡 문제 등과 함께 종합적으로 판단해야 합니다. 정확한 감별 진단을 위해 소아신경과 전문의 진료와 유전자 검사를 받으시기 바랍니다.', 2860, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '근긴장성 이영양증', '근긴장성이영양증', 'DIAGNOSIS', '근긴장성 이영양증 진단 및 치료를 위해서는 신경과(신경근육질환 전문) 또는 소아신경과를 방문하시는 것이 적합합니다. 상급종합병원의 신경과나 희귀질환 센터를 이용하면 근전도 검사, 유전자 검사 등 전문 진단 서비스를 받을 수 있습니다. 한국희귀·필수의약품센터(1588-7775) 또는 한국희귀질환연합회에 문의하면 전문 의료기관 안내를 받을 수 있습니다.', 2861, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '근긴장성 이영양증', '근긴장성이영양증', 'TREATMENT', '근긴장성 이영양증은 희귀 신경근육질환으로 전문적인 진단과 다학제적 관리가 필요하므로 상급종합병원이나 대학병원의 신경과를 방문하는 것이 적절합니다. 동네 병원은 초기 증상 평가나 의뢰서 발급에는 도움이 될 수 있지만, 근전도 검사, 유전자 검사, 심장·호흡 합병증 관리 등 전문적인 처치는 대형 병원에서 이루어져야 합니다. 진단 후에도 주기적인 심장, 호흡, 눈 등 합병증 모니터링을 위한 전문의 추적 관찰이 필요합니다.', 2862, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '다운 증후군', '다운증후군', 'CAUSE', '다운 증후군은 21번 염색체가 3개로 복제되는 삼염색체증(trisomy 21)이 주된 원인이며, 모체 나이가 증가할수록 발생 위험이 높아집니다. 산전 초음파 검사에서 목덜미 투명대(NT) 증가, 코뼈 결여, 심장 이상 등 이상 소견이 관찰될 수 있으며, 이는 진단 확정이 아닌 선별검사입니다. 확진을 위해서는 융모막 검사나 양수 검사를 통한 염색체 핵형 분석이 필요합니다.', 2863, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '다운 증후군', '다운증후군', 'DEFINITION', '다운 증후군은 21번 염색체가 정상적인 2개 대신 3개 존재하는 삼염색체증 21(trisomy 21)이 원인으로, 전체의 약 95%를 차지합니다. 나머지는 로버트슨 전좌(다른 염색체에 21번 염색체 일부가 부착)나 모자이크형으로 발생하며, 특정 단일 유전자가 아닌 21번 염색체 전체의 과잉 발현이 원인입니다. 발생 위험은 모체 나이와 관련이 깊으며 35세 이상에서 빈도가 유의하게 증가합니다.', 2864, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '다운 증후군', '다운증후군', 'SYMPTOM', '다운 증후군의 신체적 특징으로는 납작한 얼굴, 위로 치켜 올라간 눈꼬리, 작은 귀, 짧은 목, 단장지(짧은 손가락), 손바닥의 단일 굴곡선(원숭이선) 등이 있습니다. 의학적 문제로는 선천성 심장질환(약 40~50%), 갑상선 기능 저하증, 소화기 이상, 반복적인 호흡기 감염, 청력 및 시력 문제가 동반될 수 있습니다. 지적 발달 지연의 정도는 개인차가 크며, 조기 교육과 치료적 개입으로 삶의 질을 향상시킬 수 있습니다.', 2865, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '다운 증후군', '다운증후군', 'DIAGNOSIS', '질문에서 언급된 ''69명 중 1명''은 다운 증후군의 출생 위험률을 나타내는 수치로, 이는 감염 확률이 아니라 해당 연령이나 검사 결과에서의 다운 증후군 발생 가능성을 의미합니다. 이 수치는 선별검사 결과이며 확진이 아니므로, 실제 이환 여부는 양수 검사나 융모막 검사로 확인해야 합니다. 정확한 수치 해석은 산부인과 전문의 또는 유전 상담 전문가와 상담하시기 바랍니다.', 2866, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '다운 증후군', '다운증후군', 'TREATMENT', '다운 증후군 자체는 치료제가 없으며, 동반된 합병증(선천성 심장질환, 소화기 이상 등)에 따라 해당 전문과에서 치료를 받습니다. 신생아 집중 치료가 필요한 경우 신생아 집중치료실(NICU)을 갖춘 상급종합병원의 신생아과에서 관리가 이루어집니다. 장기적으로는 소아청소년과, 심장내과, 재활의학과, 언어치료 등 다학제 팀의 포괄적인 지원이 필요하며 전문의 상담을 권고합니다.', 2867, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '당원 축적병', '당원축적병', 'DIET_LIFE', '당원 축적병 환자는 유형에 따라 다르지만 일반적으로 저혈당 예방을 위해 자주 소량씩 먹는 식사 패턴과 밤사이 지속적인 포도당 공급(야간 위관 영양 또는 생옥수수 전분 섭취)이 중요합니다. 격렬한 운동은 저혈당을 유발할 수 있으므로 피하고, 고단백·저지방 식이와 규칙적인 혈당 모니터링이 권장됩니다. 구체적인 식이 요법은 유형별로 다르므로 반드시 대사질환 전문의 및 영양사와 상담하여 개인별 계획을 세우시기 바랍니다.', 2868, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '당원 축적병', '당원축적병', 'CAUSE', '당원 축적병(글리코겐 축적병)은 글리코겐 합성이나 분해에 관여하는 효소의 선천적 결핍으로 발생하는 상염색체 열성 유전질환입니다. 각 유형(1형: 포도당-6-인산분해효소 결핍, 2형: 산성 알파-글루코시다제 결핍 등)에 따라 결핍되는 효소의 유전자 돌연변이가 다르며, 부모 양쪽이 보인자일 때 자녀에게 25% 확률로 발병합니다. 유전자 돌연변이로 효소 기능이 소실되면 글리코겐이 간, 근육, 심장 등에 비정상적으로 축적됩니다.', 2869, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '당원 축적병', '당원축적병', 'DEFINITION', '당원 축적병은 글리코겐 대사 효소의 유전적 결핍으로 글리코겐이 특정 장기에 비정상적으로 축적되는 선천성 대사질환입니다. 유형에 따라 간비대, 저혈당, 근육 약화, 심근병증 등 다양한 증상이 나타납니다. 치료는 유형별로 다르며, 1형은 엄격한 식이 관리와 옥수수 전분 요법, 2형(폼페병)은 효소 대체 요법이 사용되므로 대사질환 전문의 상담이 필요합니다.', 2870, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '당원 축적병', '당원축적병', 'SYMPTOM', '당원 축적병(특히 1형)에서 간비대와 신장 비대는 글리코겐과 지방이 간세포와 신장세포에 과도하게 축적되어 발생합니다. 저혈당 시 지방산 분해가 증가하여 중성지방과 요산이 상승하고, 이것이 간과 신장에 추가 부담을 줍니다. 과민성 장증후군은 당원 축적병의 직접적인 증상은 아니므로, 복부 증상이 지속된다면 소화기내과 및 대사질환 전문의의 감별 진단이 필요합니다.', 2871, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '당원 축적병', '당원축적병', 'DIAGNOSIS', '볼의 갈색 지방 축적만으로 당원 축적병을 진단하기는 어려우며, 이는 비특이적 소견입니다. 당원 축적병 의심 시에는 대학병원 또는 상급종합병원의 소아청소년과(대사내분비분과) 또는 내과(내분비대사분과)를 방문하여 혈액 검사(혈당, 간효소, 요산, 젖산, 지질), 효소 활성도 검사, 유전자 검사 등을 받으시기 바랍니다. 정확한 진단을 위해서는 전문의의 진찰과 검사가 필요합니다.', 2872, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '당원 축적병', '당원축적병', 'TREATMENT', '당원 축적병은 효소 결핍이라는 근본 원인이 있으므로 자연 치료(식이 보조 등)만으로는 치료가 불가능합니다. 유형에 따라 효소 대체 요법(2형/폼페병), 식이 관리(1형), 기질 감소 요법 등의 의학적 치료가 필요하며, 치료를 하지 않으면 심각한 합병증이 발생합니다. 보완적 식이 요법은 증상 관리에 도움이 될 수 있지만 반드시 전문의의 지도하에 시행해야 합니다.', 2873, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '묘성 증후군', '묘성증후군', 'CAUSE', '묘성 증후군(5p 결실 증후군)은 5번 염색체 단완(5p)의 부분 결실로 발생하며, 대부분은 자연 발생적 돌연변이로 특별한 외부 원인이 없습니다. 약 10~15%에서는 부모 중 한 명이 5번 염색체 구조 이상(전좌 등) 보인자인 경우 발생할 수 있으며, 방사선 노출이나 환경 독소 등의 외부 요인은 일반적으로 원인으로 인정되지 않습니다. 가족 중 환자 발생 시 부모의 염색체 검사가 권장됩니다.', 2874, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '묘성 증후군', '묘성증후군', 'REHAB', '묘성 증후군 환자에게는 언어치료, 작업치료, 물리치료를 포함한 조기 집중 재활이 신체 기능 향상과 발달 촉진에 효과적입니다. 언어치료는 의사소통 능력 향상에, 작업치료는 소근육 운동과 일상생활 기능 향상에, 물리치료는 대근육 운동 발달과 자세 교정에 도움이 됩니다. 재활치료는 가능한 한 조기에 시작할수록 예후가 좋으며, 재활의학과 전문의의 개별화된 치료 계획이 필요합니다.', 2875, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '묘성 증후군', '묘성증후군', 'DEFINITION', '묘성 증후군의 진단은 주로 특징적인 임상 소견(고양이 울음소리 같은 영아기 울음, 소두증, 작은 얼굴, 넓은 눈 간격 등)을 바탕으로 의심하고, 염색체 핵형 분석(5p 결실 확인)으로 확진합니다. 표준 핵형 검사로 발견되지 않는 작은 결실의 경우 FISH(형광제자리부합법)나 염색체 마이크로어레이 검사를 시행합니다. 진단은 소아청소년과 또는 유전 전문의를 통해 받을 수 있습니다.', 2876, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '묘성 증후군', '묘성증후군', 'SYMPTOM', '묘성 증후군의 주요 증상으로는 고양이 울음소리 같은 특유의 영아기 울음 외에 소두증, 저출생 체중, 발달 지연 및 지적장애, 근긴장 저하, 넓은 눈 간격, 낮게 위치한 귀, 소악증(작은 턱) 등의 특징적인 얼굴 모양이 있습니다. 선천성 심장질환이 약 30%에서 동반되며, 성장 지연, 언어 발달 지연, 행동 문제도 나타납니다. 증상의 심각도는 5p 결실 크기와 위치에 따라 다양합니다.', 2877, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '묘성 증후군', '묘성증후군', 'DIAGNOSIS', '묘성 증후군에서 고양이 울음소리와 유사한 울음이 나타나는 이유는 5번 염색체 단완 결실로 인해 후두 발달 이상이 생기기 때문입니다. 후두 연골과 신경근육 조절 이상으로 성대의 구조와 기능에 문제가 생겨 높고 날카로운 특유의 울음소리가 발생하며, 이는 영아기 초기에 가장 뚜렷하게 나타나다가 성장하면서 점차 소실되는 경향이 있습니다. 유사한 목소리 변화가 성인에서 나타난다면 다른 원인을 감별하기 위해 이비인후과 전문의 진료를 받으시기 바랍니다.', 2878, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '묘성 증후군', '묘성증후군', 'TREATMENT', '묘성 증후군의 치료에서 물리치료, 작업치료, 언어치료 등을 병합하는 이유는 이 질환이 근긴장 저하, 대근육·소근육 운동 발달 지연, 언어 발달 지연 등 다양한 영역에 영향을 미치기 때문입니다. 각 치료법은 서로 다른 기능 영역을 담당하여 상호 보완적으로 작용하며, 조기 통합 재활치료가 장기적인 발달 결과를 최대화하는 데 효과적입니다. 선천성 심장질환이 동반된 경우 심장 치료도 함께 진행되므로 다학제 접근이 필수적입니다.', 2879, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '선천성 갑상선기능저하증', '선천성갑상선기능저하증', 'MEDICATION', '선천성 갑상선기능저하증의 표준 치료는 레보티록신(levothyroxine) 경구 복용으로, 갑상선 호르몬을 대체하는 약물입니다. 조기(신생아기)에 적절한 용량의 레보티록신을 투여하면 뇌 발달 손상을 예방하고 정상 성장을 도울 수 있으며, 평생 복용이 필요한 경우가 많습니다. 약물 용량과 복용 방법은 반드시 소아내분비과 전문의의 지시에 따라야 하며 정기적인 갑상선 기능 검사를 통해 조절해야 합니다.', 2880, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '선천성 갑상선기능저하증', '선천성갑상선기능저하증', 'CAUSE', '선천성 갑상선기능저하증의 원인으로는 갑상선 발달 이상(갑상선 무형성, 갑상선 이소성)이 가장 흔하며(전체의 약 85%), 갑상선 호르몬 합성 효소 결핍(갑상선 형성이상), 모체 항갑상선 항체의 태반 통과, 요오드 결핍 등도 원인이 됩니다. 일부는 TSH 수용체 유전자 돌연변이나 갑상선 호르몬 합성 관련 유전자 이상으로 발생합니다. 원인에 따라 치료 기간과 예후가 다를 수 있으므로 소아내분비과 전문의 평가가 필요합니다.', 2881, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '선천성 갑상선기능저하증', '선천성갑상선기능저하증', 'DEFINITION', '선천성 갑상선기능저하증은 출생 시부터 갑상선 호르몬이 부족하거나 전혀 분비되지 않는 상태로, 갑상선 발달 이상이나 호르몬 합성 효소 결핍이 주된 원인입니다. 치료받지 않으면 성장 지연, 지적장애, 황달 지속, 변비, 근육 저긴장, 수유 불량 등이 나타납니다. 한국에서는 신생아 선별검사를 통해 조기 발견하고, 레보티록신으로 치료하면 대부분 정상 발달이 가능합니다.', 2882, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '선천성 갑상선기능저하증', '선천성갑상선기능저하증', 'SYMPTOM', '선천성 갑상선기능저하증 환자에서 호흡곤란 외에도 황달의 지속(생리적 황달보다 오래 지속), 수유 불량, 변비, 쉰 목소리로 우는 울음, 피부 건조 및 황색조, 복부 팽만, 근긴장 저하(축늘어진 아기), 체온 저하, 서맥 등이 나타날 수 있습니다. 치료받지 않고 지속되면 성장 지연과 지적장애로 이어질 수 있습니다. 이러한 증상이 있으면 즉시 소아청소년과 전문의를 방문하시기 바랍니다.', 2883, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '선천성 갑상선기능저하증', '선천성갑상선기능저하증', 'DIAGNOSIS', '태아 갑상선기능저하증이 의심될 경우 출생 후 신생아 선별검사(생후 48~72시간 발꿈치 채혈)를 통해 TSH와 T4를 측정하는 것이 기본입니다. 산전에는 양수 검사나 태아 혈액 채취를 통한 갑상선 기능 검사, 태아 초음파를 통한 갑상선 크기 평가 등이 가능하지만, 일상적으로 시행되지는 않습니다. 이상 소견 발견 시 소아내분비과 및 모체태아의학 전문의와 상담하시기 바랍니다.', 2884, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '선천성 갑상선기능저하증', '선천성갑상선기능저하증', 'TREATMENT', '선천성 갑상선기능저하증의 주 치료는 레보티록신 호르몬 대체 요법이며, 치료 효과를 높이기 위한 보조 요법으로는 적절한 영양 공급(요오드 충분한 모유 또는 분유)과 정기적인 발달 평가가 포함됩니다. 필요 시 성장 지연, 발달 지연에 대한 조기 개입(물리치료, 작업치료, 언어치료)이 병행될 수 있습니다. 레보티록신 복용 시 철분제나 칼슘은 흡수를 방해할 수 있으므로 복용 시간 조절에 대해 전문의와 상담이 필요합니다.', 2885, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '선천성 기형', '선천성기형', 'CAUSE', '임신 중 음주와 흡연은 태아에게 직접적인 영향을 미쳐 선천성 기형 발생 위험을 실질적으로 높입니다. 알코올은 태반을 통해 태아에 전달되어 태아알코올증후군(안면 기형, 지적장애, 심장 기형 등)을 유발할 수 있고, 흡연은 산소와 영양 공급을 감소시켜 심혈관 기형, 구순구개열 등의 위험을 증가시킵니다. 임신 중에는 음주와 흡연을 반드시 금하고, 기형아 예방을 위해 산부인과 전문의의 산전 관리를 철저히 받으시기 바랍니다.', 2886, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '선천성 기형', '선천성기형', 'DEFINITION', '발가락 선천성 기형(합지증, 다지증, 단지증 등)의 진단은 주로 임상 시진과 방사선 검사(X선)를 통해 이루어집니다. 기형의 종류와 정도에 따라 정형외과 또는 성형외과 전문의의 진료가 필요하며, 염색체 이상이나 유전질환과 관련된 경우 유전과 상담도 고려할 수 있습니다. 기능적 문제나 미용적 문제가 있다면 전문의 상담을 통해 치료 여부와 방법을 결정하시기 바랍니다.', 2887, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '신경섬유종', '신경섬유종', 'CHECKUP', '신경섬유종증 검진을 위해서는 신경과, 피부과, 또는 유전의학과를 방문하시는 것이 적합합니다. 유전자 검사(NF1 또는 NF2 유전자 돌연변이 확인)는 상급종합병원의 유전의학과 또는 진단검사의학과에서 받을 수 있습니다. 확진 기준에는 카페오레 반점 6개 이상, 신경섬유종 2개 이상 등 임상 기준이 포함되므로 먼저 피부과나 신경과 전문의의 임상 평가를 받으시기 바랍니다.', 2888, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '신경섬유종', '신경섬유종', 'MEDICATION', '신경섬유종증의 카페오레 반점은 멜라닌 색소의 이상 침착으로 생기는 것으로, 현재 약국에서 구입할 수 있는 약물로 이를 완화하는 효과적인 방법은 없습니다. 피부과적으로는 레이저 치료(Q-스위치 레이저 등)를 시도할 수 있으나 신경섬유종증 자체의 치료가 우선이며, 미용 목적의 치료는 전문의 상담 후 결정해야 합니다. 임의로 일반 미백 제품을 사용하기보다는 피부과 전문의 진료를 먼저 받으시기 바랍니다.', 2889, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '신경섬유종', '신경섬유종', 'CAUSE', '신경섬유종증 1형(NF1)의 경우 약 50%는 부모로부터 상염색체 우성으로 유전되고, 나머지 50%는 자연 발생적 신규 돌연변이로 발생합니다. NF1은 17번 염색체의 NF1 유전자(뉴로피브로민 단백질 코딩) 돌연변이가 원인이며, 한 명의 부모가 NF1인 경우 자녀에게 50% 확률로 유전됩니다. 따라서 가족 내 환자가 있는 경우 유전 상담을 받으시는 것이 중요합니다.', 2890, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '신경섬유종', '신경섬유종', 'REHAB', '신경섬유종 환자에서는 신경섬유종이 신경이나 근골격계에 영향을 미치는 경우 물리치료와 작업치료가 기능 회복에 도움이 됩니다. 척추 측만증이 동반된 경우 코어 근육 강화 운동, 자세 교정 운동이 권장되며, 신경 압박으로 인한 근력 약화가 있는 경우 저항 운동과 유연성 운동이 도움될 수 있습니다. 구체적인 재활 운동 계획은 재활의학과 전문의의 평가 후 개인별로 맞춤 설계해야 합니다.', 2891, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '신경섬유종', '신경섬유종', 'DEFINITION', '신경섬유종증(NF1)은 진행성 질환으로 치료받지 않을 경우 카페오레 반점과 피부 신경섬유종이 시간이 지남에 따라 수와 크기가 증가하며, 증상은 대개 평생 지속됩니다. 합병증으로 시신경 교종, 악성 말초신경초 종양, 척추 측만증, 학습장애, 고혈압 등이 발생할 수 있으며 이는 삶의 질과 예후에 영향을 미칩니다. 조기 진단과 정기적인 추적 관찰이 합병증 예방 및 조기 발견에 중요하므로 전문의 상담을 권고합니다.', 2892, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '신경섬유종', '신경섬유종', 'SYMPTOM', '쥐젖(연성 섬유종)은 신경섬유종과는 다른 양성 피부 병변으로, 신경섬유종의 발생 원인이 아닙니다. 신경섬유종은 NF1 유전자 돌연변이로 인해 말초신경의 슈반세포 등이 비정상적으로 증식하여 생기는 것이고, 쥐젖은 피부의 섬유모세포와 혈관이 증식한 별개의 병변입니다. 두 병변은 외관상 유사할 수 있으나 원인과 성격이 다르므로 피부과 전문의의 감별 진단이 필요합니다.', 2893, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '신경섬유종', '신경섬유종', 'DIAGNOSIS', '신생아에서 6개 이상의 카페오레 반점(직경 0.5cm 이상)이 발견되는 경우 신경섬유종증 1형(NF1)을 의심할 수 있는 중요한 임상 소견입니다. NF1 진단 기준 중 하나가 6개 이상의 카페오레 반점이므로, 이러한 반점이 관찰되면 소아청소년과 또는 유전의학과 전문의에게 조기 의뢰하여 추가 평가를 받는 것이 권장됩니다. 반점 수가 적더라도 가족력이 있거나 다른 의심 소견이 있으면 전문의 진료를 받으시기 바랍니다.', 2894, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '신경섬유종', '신경섬유종', 'TREATMENT', '피부 신경섬유종은 수술적 절제와 레이저 치료(CO2 레이저) 외에도, 다발성 병변에는 전기소작술, 냉동치료 등이 사용될 수 있습니다. 최근에는 MEK 억제제(셀루메티닙)가 총상 신경섬유종에 FDA 승인을 받아 약물 치료 옵션이 생겼으며, 증상에 따라 적합한 치료를 선택합니다. 치료 방법의 선택은 신경섬유종의 위치, 크기, 증상, 환자 상태에 따라 다르므로 전문의 상담을 통해 결정하시기 바랍니다.', 2895, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '연골무형성증', '연골무형성증', 'CHECKUP', '콧물 증상만으로는 연골무형성증과 직접적인 연관성이 없으며, 연골무형성증은 주로 사지 단축, 두개안면 기형, 척추 문제 등을 통해 의심됩니다. 다만 연골무형성증 아이는 중이염 및 상기도 감염이 잦을 수 있어 이비인후과 추적이 필요할 수 있습니다. 연골무형성증 가능성이 의심된다면 소아청소년과 전문의에게 아이의 성장 발달 전반에 대한 평가를 받으시기 바랍니다.', 2896, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '연골무형성증', '연골무형성증', 'CAUSE', '연골무형성증은 주로 4번 염색체 FGFR3 유전자의 특정 점돌연변이(G380R)로 발생하며, 약 80%는 자연 발생적 신규 돌연변이로 부모로부터 유전되지 않습니다. 임신 6개월 시기의 특정 식품 섭취나 자궁·질 발달과는 관련이 없으며, 주요 발생 요인은 FGFR3 유전자 돌연변이로 연골 세포의 증식과 분화가 억제되는 것입니다. 고령 부친(특히 35세 이상)의 경우 신규 돌연변이 발생 위험이 약간 증가하는 것으로 알려져 있습니다.', 2897, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '연골무형성증', '연골무형성증', 'REHAB', '연골무형성증 재활 치료의 주요 목표는 신체 기능 최대화, 통증 관리, 합병증 예방 및 삶의 질 향상입니다. 물리치료를 통한 근력 강화와 관절 유연성 유지, 작업치료를 통한 일상생활 기능 향상, 척추 측만증 및 척추관 협착 예방을 위한 자세 교정 훈련이 주로 사용됩니다. 성장 과정에서 중이염 예방을 위한 청력 관리, 언어치료도 필요할 수 있으며 재활의학과 전문의의 개별 평가가 필요합니다.', 2898, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '연골무형성증', '연골무형성증', 'DEFINITION', '연골무형성증은 FGFR3 유전자 돌연변이로 연골 내 골화 과정이 억제되어 사지 단축 및 특징적인 왜소증이 나타나는 가장 흔한 선천성 골격계 이형성증입니다. 팔다리뼈가 짧고(근위부 더욱 단축), 머리가 크며, 중안면부 함몰, 손가락이 삼지창 모양인 특징적인 외모를 보입니다. 현재 예방법은 없으며, 최근 보수메티닙(C-type natriuretic peptide 유사체) 등의 약물 치료가 승인되어 성장 효과를 보이고 있으므로 전문의 상담을 권고합니다.', 2899, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '연골무형성증', '연골무형성증', 'SYMPTOM', '연골무형성증에서 최종 키가 낮은 이유는 FGFR3 유전자 돌연변이로 성장판의 연골 세포 증식이 억제되어 팔다리 장골의 성장이 현저히 제한되기 때문입니다. 성인 평균 신장은 남성 약 131cm, 여성 약 124cm이며, 사지 단축이 몸통에 비해 더 심하게 나타납니다. 최근 보수메티닙(vosoritide) 등의 치료제가 최종 신장 향상에 효과를 보이고 있으므로 소아내분비과 또는 유전의학과 전문의와 상담하시기 바랍니다.', 2900, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '연골무형성증', '연골무형성증', 'DIAGNOSIS', '두상이 크고 팔다리가 짧은 아이에서 연골무형성증이 의심될 경우 소아청소년과, 의료유전학과(유전의학과), 정형외과 전문의에게 진료를 받으시기 바랍니다. 소아청소년과에서 성장 발달 전반을 평가하고, 유전의학과에서 FGFR3 유전자 검사 및 확진을 진행하며, 정형외과에서 골격계 이상을 평가합니다. 방사선 검사(골격 X선)와 유전자 검사가 주요 진단 방법이며 조기 진단이 중요합니다.', 2901, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '연골무형성증', '연골무형성증', 'TREATMENT', '연골무형성증의 치료는 정형외과(척추 및 사지 수술), 신경외과(척추관 협착 수술), 소아청소년과, 의료유전학과, 재활의학과, 이비인후과, 치과 등 다학제 팀의 협진이 필요합니다. 치료 기간은 평생에 걸쳐 이루어지며, 성장기에는 합병증 모니터링과 필요 시 수술적 교정, 성인기에는 척추관 협착 등 합병증 관리가 중심이 됩니다. 최근 약물 치료제(보수메티닙)가 소아에서 사용 가능해졌으므로 전문의와 치료 옵션을 상담하시기 바랍니다.', 2902, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '윌리암스 증후군', '윌리암스증후군', 'CAUSE', '윌리암스 증후군은 7번 염색체 장완(7q11.23)의 미세 결실로 발생하며, 이 결실은 거의 대부분 자연 발생적으로 생기고 특별한 외부 요인이 원인으로 확인되지 않습니다. 방사선 노출, 식습관, 생활 환경 등 외부 요인이 발생에 기여한다는 증거는 없으며, 고령 부모도 위험인자로 강하게 작용하지 않습니다. 드물게 부모가 보인자인 경우(약 5~10%)에는 상염색체 우성으로 유전될 수 있습니다.', 2903, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '윌리암스 증후군', '윌리암스증후군', 'DEFINITION', '윌리암스 증후군의 특징적인 얼굴 모양으로는 넓은 이마, 별모양 홍채, 들창코, 두드러진 인중, 넓고 두꺼운 입술, 작고 크게 벌어진 입, 통통한 볼 등이 있습니다. 이러한 외모는 7번 염색체 결실로 인한 발달 이상의 결과로 나타납니다. 조카의 얼굴 특이함이 걱정된다면 소아청소년과나 의료유전학과 전문의에게 진료를 받으시어 정확한 평가를 받으시기 바랍니다.', 2904, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '윌리암스 증후군', '윌리암스증후군', 'SYMPTOM', '윌리암스 증후군의 특징적인 얼굴 모양(요정 같은 얼굴)은 7번 염색체 7q11.23 부위의 미세 결실로 인한 발달 이상 때문에 나타납니다. 들창코, 두터운 입술, 넓은 입, 별 모양 홍채, 넓은 이마 등이 특징적이며, 이는 해당 부위에 위치한 유전자(ELN 등)의 결실이 안면 발달에 영향을 주기 때문입니다. 이외에도 사교적 성격, 음악적 재능, 지적 발달 지연, 심혈관 이상(대동맥판 상부 협착 등)이 동반됩니다.', 2905, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '윌리암스 증후군', '윌리암스증후군', 'DIAGNOSIS', '윌리암스 증후군이 의심되는 경우 소아청소년과 또는 의료유전학과(유전의학과) 전문의에게 먼저 진료를 받으시는 것이 적합합니다. 진단 확인 후에는 심장 이상 평가를 위해 소아심장과, 발달 평가를 위해 발달소아과, 내분비 이상(고칼슘혈증 등)을 위해 소아내분비과 등 다학제 협진이 필요합니다. FISH 또는 염색체 마이크로어레이를 통한 유전자 검사로 확진할 수 있습니다.', 2906, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '윌리암스 증후군', '윌리암스증후군', 'TREATMENT', '윌리암스 증후군은 근본적인 치료법은 없으며, 각 증상과 합병증에 따른 대증적 치료가 이루어집니다. 심혈관 이상(대동맥판 상부 협착)에는 수술적 치료, 고칼슘혈증에는 식이 조절과 약물 치료, 발달 지연에는 조기 재활(언어치료, 작업치료, 물리치료) 및 특수교육이 가장 효과적입니다. 포괄적인 다학제 접근을 통한 조기 중재가 장기적인 예후와 삶의 질 향상에 가장 중요하므로 전문의 상담을 권고합니다.', 2907, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '척수구근 근위축증', '척수구근근위축증', 'EXERCISE', '척수구근 근위축증(Kennedy병) 환자에서 과도하거나 강도 높은 운동은 오히려 근육 손상을 악화시킬 수 있어 주의가 필요합니다. 가벼운 유산소 운동(걷기, 수중 운동)과 저강도 저항 운동은 근육 기능 유지와 심폐 기능 향상에 도움이 될 수 있으나, 근육 피로를 유발하는 고강도 운동은 피해야 합니다. 개인별 상태에 맞는 운동 계획은 재활의학과 또는 신경과 전문의와 상담하여 수립하시기 바랍니다.', 2908, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '척수구근 근위축증', '척수구근근위축증', 'CAUSE', '보행 이상과 자주 넘어지는 증상은 척수구근 근위축증에서 골반대 및 하지 근력 약화로 인해 나타날 수 있습니다. 그러나 이러한 증상은 다른 신경근육질환(척수성 근위축증, 다발성 근육염, 파킨슨병 등)에서도 나타나므로, 단독으로 척수구근 근위축증의 원인이라고 단정 짓기 어렵습니다. 정확한 원인 감별을 위해 신경과 전문의를 방문하여 근전도 검사, 유전자 검사 등을 받으시기 바랍니다.', 2909, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '척수구근 근위축증', '척수구근근위축증', 'DEFINITION', '지속적인 근육 약화가 있다면 척수구근 근위축증(Kennedy병)을 포함한 다양한 신경근육질환을 의심해볼 수 있습니다. 척수구근 근위축증은 안드로겐 수용체 유전자(AR)의 CAG 반복 확장에 의해 발생하는 X 염색체 연관 열성 유전질환으로, 주로 성인 남성에서 서서히 진행하는 사지 근력 약화와 구근 증상(삼키기 어려움, 발음 이상)이 특징입니다. 근육 약화 증상이 지속된다면 신경과 전문의를 방문하여 정밀 검사를 받으시기 바랍니다.', 2910, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '척수구근 근위축증', '척수구근근위축증', 'SYMPTOM', '척수구근 근위축증(Kennedy병)에서는 주로 어깨와 골반대 근육의 대칭적인 근력 약화가 먼저 나타나며, 점차 사지 원위부로 진행합니다. 구근 증상으로 혀와 인두 근육 약화에 의한 연하 곤란, 구음 장애, 혀 근육 속상수축이 나타나고, 안면 근육 약화로 표정 변화도 생깁니다. 여성화 유방, 성기능 저하 등 안드로겐 불감증 증상과 손 떨림도 동반될 수 있으며 전문의 진료가 필요합니다.', 2911, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '척수구근 근위축증', '척수구근근위축증', 'DIAGNOSIS', '혀 근육 속상수축(혀가 파르르 떨리는 현상)은 척수구근 근위축증의 특징적인 소견 중 하나로, 이를 포함한 구근 증상과 사지 근력 약화가 동반된다면 신경과 전문의 진료를 받으시기 바랍니다. 진단을 위해 근전도 검사(만성 탈신경 소견 확인), 혈중 크레아틴인산키나아제(CK) 측정, AR 유전자의 CAG 반복 수 확인을 위한 유전자 검사가 시행됩니다. 상급종합병원의 신경과에서 정밀 검사를 받으실 것을 권고합니다.', 2912, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '척수구근 근위축증', '척수구근근위축증', 'TREATMENT', '척수구근 근위축증의 물리치료는 잔존 근력 유지, 관절 구축 예방, 호흡 기능 보존을 목표로 합니다. 저강도 유산소 운동, 관절 가동 범위 운동, 수중 물리치료(근육에 부하가 적어 선호됨), 호흡 근육 강화 운동이 주로 활용됩니다. 연하 곤란이 있는 경우 언어치료사에 의한 삼킴 재활도 중요하며, 구체적인 치료 방법은 재활의학과 전문의와 상담하여 결정하시기 바랍니다.', 2913, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '척수근육위축', '척수근육위축', 'CHECKUP', '척수근육위축증(SMA) 환자가 정기 검진을 받으면 현재 진행 상태를 파악하고, 호흡 기능 저하, 척추 측만증, 영양 상태 등 합병증을 조기에 발견하여 대처할 수 있습니다. 또한 최근 SMA 치료제(누시네르센, 졸겐스마, 리스디플람)의 등장으로 조기 치료 시작이 기능 보존에 매우 중요해졌으므로, 정기 검진을 통한 치료 시기 결정과 경과 모니터링이 일상생활 유지에 큰 영향을 줍니다. 신경과 또는 소아신경과 전문의의 정기 추적 관찰을 받으시기 바랍니다.', 2914, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '척수근육위축', '척수근육위축', 'MEDICATION', '척수근육위축증(SMA)은 운동신경 기능 저하를 일으키는 질환이지만, 태아의 태동은 태아 자신의 근육 운동에 의한 것이므로 산모의 SMA가 직접적으로 태동에 영향을 주지는 않습니다. 다만 SMA를 가진 산모는 임신 중 호흡 기능, 체위, 근력 약화 등으로 인해 임신과 분만에 특수한 위험이 따를 수 있으며, 고위험 임신으로 관리가 필요합니다. SMA 산모의 임신 관리에 대해서는 신경과 및 모체태아의학 전문의와 반드시 상담하시기 바랍니다.', 2915, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '척수근육위축', '척수근육위축', 'CAUSE', '척수근육위축증(SMA)의 주된 원인은 5번 염색체 SMN1 유전자 결실 또는 돌연변이로 인한 운동신경세포 퇴화이며, 허리 통증은 SMA의 직접적인 발병 원인이 아닙니다. SMA 환자에서 허리 통증이 생기는 것은 척추 측만증, 자세 이상, 약화된 척추 지지 근육으로 인한 이차적 합병증으로 나타날 수 있습니다. 허리 통증이 있다면 SMA 전문의와 함께 정형외과 또는 재활의학과 전문의의 평가를 받으시기 바랍니다.', 2916, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '척수근육위축', '척수근육위축', 'DEFINITION', '척수근육위축증(SMA)은 SMN1 유전자 결핍으로 척수 전각세포(운동신경원)가 퇴화하여 팔다리 및 몸통 근육에 신경 신호가 전달되지 않아 근육 위축과 근력 약화가 진행하는 상염색체 열성 유전질환입니다. 운동신경원이 사멸하면 해당 신경이 지배하는 근육이 자극을 받지 못해 점차 위축되고, 특히 근위부(어깨, 허리 주변) 근육이 더 심하게 영향을 받습니다. 감각신경과 지적 기능은 일반적으로 보존됩니다.', 2917, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '척수근육위축', '척수근육위축', 'SYMPTOM', '척수근육위축증의 증상 발현 시기와 중증도는 유형에 따라 다릅니다. 1형(영아형)은 생후 6개월 이내에 심한 근력 약화가 나타나 스스로 앉지 못하고, 치료 없이는 2세 이전에 호흡 부전으로 생명을 위협받습니다. 2형은 생후 6~18개월에 발현하여 앉기는 가능하나 보행은 불가하고, 3형은 18개월 이후 발현하여 보행이 가능하지만 서서히 악화되며, 4형은 성인기에 발현합니다.', 2918, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '척수근육위축', '척수근육위축', 'DIAGNOSIS', '걸음걸이 이상과 자세 유지 어려움이 있을 경우 척수근육위축증을 포함한 다양한 신경근육질환의 가능성이 있으므로, 상급종합병원 또는 대학병원의 신경과(성인) 또는 소아신경과(소아)를 방문하시기 바랍니다. 희귀질환 전문 클리닉이 있는 기관을 선택하면 SMN1/SMN2 유전자 검사, 근전도 검사 등 전문 진단 서비스를 받을 수 있습니다. 한국희귀·필수의약품센터나 희귀질환 헬프라인(1588-7775)에서 전문 의료기관 안내를 받으실 수도 있습니다.', 2919, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '척수근육위축', '척수근육위축', 'TREATMENT', '현재 SMA 치료에는 SMN 단백질을 증가시키는 승인된 치료제로 누시네르센(뇌척수액 주사), 리스디플람(경구약), 졸겐스마(1회 유전자 치료, 소아 대상)가 사용 가능합니다. 이 약물들은 질병 진행을 늦추고 운동 기능을 개선하는 효과가 있으며, 조기 투여일수록 효과가 좋습니다. 이외에도 호흡 지원, 영양 관리, 물리치료, 척추 측만증 수술 등 대증적 치료를 병행하며, 치료 방법은 신경과 전문의와 상담하여 결정하시기 바랍니다.', 2920, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '클라인펠터 증후군', '클라인펠터증후군', 'CHECKUP', '클라인펠터 증후군(47,XXY)이 의심될 경우 혈액 채취를 통한 염색체 핵형 분석이 확진에 필수적입니다. 이 외에도 혈중 테스토스테론, FSH, LH, 에스트라디올 등 호르몬 검사와 정액 검사(무정자증 확인), 골밀도 검사 등이 동반되며, 의료유전학과 또는 내분비내과(성인), 소아내분비과(소아)에서 검진을 받으실 수 있습니다. 산전에는 양수 검사나 융모막 검사로도 진단 가능합니다.', 2921, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '클라인펠터 증후군', '클라인펠터증후군', 'CAUSE', '클라인펠터 증후군은 정자 또는 난자 형성 과정에서 성염색체의 비분리(non-disjunction) 현상으로 발생합니다. 정상적으로 정자는 X 또는 Y 염색체를 하나씩 가져야 하지만, 감수분열 오류로 X와 Y 두 개를 가진 정자가 X 난자와 결합하면 47,XXY가 됩니다. 마찬가지로 XX 난자가 Y 정자와 결합해도 발생할 수 있으며, 이 비분리 현상은 주로 산모 나이가 증가할수록 빈도가 높아집니다.', 2922, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '클라인펠터 증후군', '클라인펠터증후군', 'DEFINITION', '클라인펠터 증후군은 남성에서 X 염색체가 1개 더 존재하는 47,XXY 핵형을 가지는 성염색체 이상 질환입니다. 남성에서 발생하며 여성화 유방, 작은 고환, 무정자증 또는 감소된 정자 수로 인한 불임, 낮은 테스토스테론 수치, 키가 크고 팔다리가 긴 체형 등이 나타날 수 있습니다. 여성성과 남성성을 ''동시에 가진다''는 표현보다는 남성 표현형이지만 여성화 특징(여성화 유방 등)이 일부 나타나는 것으로, 호르몬 치료로 증상을 관리할 수 있습니다.', 2923, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '클라인펠터 증후군', '클라인펠터증후군', 'SYMPTOM', '클라인펠터 증후군(47,XXY)의 주요 증상으로는 작은 고환과 음경, 여성화 유방(여유증), 낮은 테스토스테론으로 인한 성욕 감소, 무정자증에 의한 불임, 키가 크고 팔다리가 긴 체형이 있습니다. 사춘기 발달 지연, 체모와 수염이 적음, 골다공증, 학습 장애 및 언어 발달 지연도 나타날 수 있습니다. 증상의 정도는 개인마다 다르며 조기에 테스토스테론 호르몬 치료를 시작하면 많은 증상을 개선할 수 있습니다.', 2924, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '클라인펠터 증후군', '클라인펠터증후군', 'DIAGNOSIS', '클라인펠터 증후군에서 작은 고환과 낮은 테스토스테론은 47,XXY 핵형으로 인해 고환의 정상 발달이 방해받기 때문에 나타납니다. 이로 인해 사춘기 이후 FSH와 LH는 높게, 테스토스테론은 낮게 측정되며, 이는 일차성 성선기능저하증에 해당합니다. 진단은 혈중 테스토스테론, FSH, LH 검사와 함께 염색체 핵형 분석으로 확인하며, 내분비내과 또는 비뇨의학과 전문의와 상담하시기 바랍니다.', 2925, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '클라인펠터 증후군', '클라인펠터증후군', 'TREATMENT', '클라인펠터 증후군에서 테스토스테론 호르몬 치료는 성기능, 골밀도, 근육량, 체력, 기분, 인지 기능 향상에 효과적이며 조기 시작할수록 유리합니다. 수술(여유증 교정)은 심리적 문제와 미용적 문제를 해결하는 데 도움이 되며, 생식 보조술(고환 내 정자 추출, TESE)은 불임 치료에 활용됩니다. 호르몬 치료는 근본적인 염색체 이상을 교정하지는 못하지만 증상 개선 효과가 크므로, 내분비내과 또는 비뇨의학과 전문의의 지도하에 시행하시기 바랍니다.', 2926, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '터너 증후군', '터너증후군', 'DIET_LIFE', '터너 증후군(45,X) 환자는 골다공증 예방을 위해 칼슘과 비타민 D를 충분히 섭취하고, 규칙적인 체중 부하 운동(걷기, 달리기)을 권장합니다. 에스트로겐 결핍으로 인한 심혈관 위험 관리를 위해 저지방, 고섬유질 식이와 금연, 표준 체중 유지가 중요합니다. 갑상선 질환, 당뇨, 청력 손실 등 합병증에 대한 정기적인 검진과 전문의 추적 관찰이 생애 전반에 걸쳐 필요합니다.', 2927, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '터너 증후군', '터너증후군', 'MEDICATION', '터너 증후군에서 에스트로겐 결핍으로 인한 사춘기 발달 지연과 무월경, 골다공증 예방을 위해 에스트로겐-프로게스테론 호르몬 대체 요법이 사용됩니다. 에스트라디올(경구, 패치, 젤 형태)이 주로 사용되며, 자궁이 있는 경우 자궁내막 보호를 위해 프로게스테론을 함께 투여합니다. 호르몬 치료의 시작 시기, 용량, 방법은 소아내분비과 또는 부인과 전문의의 지도하에 개인별로 결정해야 합니다.', 2928, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '터너 증후군', '터너증후군', 'PREVENTION', '터너 증후군은 X 염색체 비분리에 의한 선천성(태생적) 염색체 이상으로 발생하며, 후천적으로 생기지 않습니다. 따라서 후천적인 예방 방법은 존재하지 않으며, 산전 유전 상담과 검사(양수 검사, 융모막 검사 또는 비침습적 산전 검사)를 통해 태아 이환 여부를 확인하는 것이 현재 가능한 접근입니다. 진단 후에는 합병증 예방과 조기 치료를 통해 삶의 질을 향상시키는 것이 중요합니다.', 2929, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '터너 증후군', '터너증후군', 'CAUSE', '터너 증후군은 임신 중 식품 섭취와 관계없이 발생하는 성염색체 비분리에 의한 선천성 유전 질환으로, 특정 식품이 원인으로 작용하지 않습니다. 발생 원인은 주로 감수분열 과정에서의 X 염색체 비분리 현상이며, 모체 나이와의 강한 연관성도 확인되지 않아 다운 증후군과는 다릅니다. 따라서 임신 중 어떤 음식을 먹었는지는 터너 증후군 발생과 무관합니다.', 2930, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '터너 증후군', '터너증후군', 'DEFINITION', '터너 증후군은 손목을 많이 사용하는 사람들에게 발생하는 질환이 아니며, 이는 잘못된 정보입니다. 터너 증후군은 여성에서 X 염색체 중 하나가 부분 또는 전체 결실(45,X 등)된 선천성 성염색체 이상으로, 저신장, 난소 기능 부전, 불임, 심장 및 신장 기형 등을 특징으로 하는 유전 질환입니다. 손목 과사용으로 생기는 질환은 손목 건초염이나 수근관 증후군 등이며 이는 전혀 다른 질환입니다.', 2931, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '터너 증후군', '터너증후군', 'SYMPTOM', '터너 증후군은 선천성 유전 질환으로 증상 자체를 예방할 수는 없으나, 각 증상에 대한 조기 발견과 적극적인 치료로 합병증을 최소화할 수 있습니다. 성장호르몬 치료를 통한 신장 증가, 호르몬 대체 요법을 통한 사춘기 유도와 골다공증 예방, 심장 및 신장 합병증의 정기 모니터링이 중요합니다. 소아내분비과 전문의를 통한 지속적인 추적 관찰이 건강 유지에 필수적입니다.', 2932, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '터너 증후군', '터너증후군', 'DIAGNOSIS', '터너 증후군 진단의 핵심은 염색체 핵형 분석으로, 여성에서 45,X(또는 다양한 모자이크형) 소견이 확인되면 확진됩니다. 터너 증후군은 남성에서는 발생하지 않으며 표현형은 여성이므로 남성성·여성성 구분이 진단 기준은 아닙니다. 저신장, 사춘기 발달 지연, 무월경, 특징적인 신체 소견(물갈퀴목, 팔꿈치 외번 등)이 의심 기준이 되며, 최종 확진은 염색체 검사로 합니다.', 2933, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '터너 증후군', '터너증후군', 'TREATMENT', '터너 증후군 치료에 사용되는 성장호르몬 치료는 저신장 소아에서 신장 증가를 목적으로 사용되며, 터너 증후군이 없는 아이에서도 성장호르몬 결핍증 등 다른 적응증이 있을 경우 사용될 수 있습니다. 에스트로겐 호르몬 대체 요법은 터너 증후군 특유의 치료이며, 골다공증 예방과 사춘기 유도를 목적으로 합니다. 모든 치료는 적응증과 안전성 평가 후 소아내분비과 또는 내분비내과 전문의의 처방에 따라 시행되어야 합니다.', 2934, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '페닐케톤뇨증', '페닐케톤뇨증', 'CAUSE', '페닐케톤뇨증(PKU)의 주된 원인은 페닐알라닌 수산화효소(PAH) 유전자의 상염색체 열성 돌연변이로 인해 페닐알라닌이 티로신으로 전환되지 못하는 것입니다. 유전적 요인이 유일한 발병 원인이며 환경이나 식습관이 직접 원인이 되지는 않으나, 페닐알라닌이 많은 음식(고단백 식품)을 섭취하면 증상이 심해집니다. 따라서 유전적 소인이 있는 사람에서 식이 관리가 증상 조절에 매우 중요합니다.', 2935, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '페닐케톤뇨증', '페닐케톤뇨증', 'DEFINITION', '페닐케톤뇨증(PKU)은 페닐알라닌 수산화효소(PAH) 유전자 이상으로 페닐알라닌이 체내에 축적되는 선천성 대사질환입니다. 치료받지 않으면 페닐알라닌과 그 대사산물이 뇌에 독성을 일으켜 지적장애, 발달 지연, 경련, 행동 이상이 나타나고, 피부와 머리카락이 색소 감소(금발, 피부 밝음), 특유의 쥐오줌 냄새가 발생합니다. 신생아 선별검사로 조기 발견하여 식이 치료와 약물 치료를 시작하면 정상 발달이 가능합니다.', 2936, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '페닐케톤뇨증', '페닐케톤뇨증', 'SYMPTOM', '페닐케톤뇨증에서 소변의 특이한 냄새(쥐오줌 냄새 같은 퀴퀴한 냄새)는 축적된 페닐알라닌 대사산물인 페닐피루브산이 소변으로 배출되기 때문이며, 피부 발진은 페닐알라닌 과잉으로 인한 멜라닌 합성 저하와 관련됩니다. 이러한 증상과 함께 발달 지연이 있다면 혈중 페닐알라닌 농도 측정, 소변 아미노산 분석, PAH 유전자 검사를 통해 진단하며, 소아청소년과(대사내분비) 또는 유전의학과 전문의 진료가 필요합니다.', 2937, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '페닐케톤뇨증', '페닐케톤뇨증', 'DIAGNOSIS', '신생아 선천성 대사 이상 선별검사는 생후 48~72시간에 발꿈치 채혈(heel prick)로 시행하는 것이 가장 적절합니다. 이 시기는 단백질이 포함된 모유나 분유를 충분히 수유한 후여야 페닐알라닌 등 대사산물이 충분히 상승하여 위음성을 최소화할 수 있습니다. 출생 후 24시간 이내에 검사하면 위음성 가능성이 높아지므로, 결과가 양성이면 즉시 확진 검사와 함께 소아청소년과 전문의 진료를 받아야 합니다.', 2938, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '페닐케톤뇨증', '페닐케톤뇨증', 'TREATMENT', '페닐케톤뇨증으로 인한 신경 발달 지연과 특이한 체취는 저페닐알라닌 식이(페닐알라닌 제한 특수분유 및 식이 조절)를 통해 혈중 페닐알라닌 농도를 목표 범위 내로 유지하는 것이 가장 중요한 치료입니다. 일부 환자는 테트라히드로비옵테린(BH4, 사프로프테린) 약물 치료가 효과적이며, 신경 발달 지연이 이미 발생한 경우 조기 재활치료(언어치료, 인지 재활)가 도움이 됩니다. 치료 방법은 대사내분비 전문의와 상담하여 개인별로 결정하시기 바랍니다.', 2939, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '프라더 윌리 증후군', '프라더윌리증후군', 'CHECKUP', '프라더 윌리 증후군의 확진을 위해서는 메틸화 특이 PCR(methylation-specific PCR) 또는 메틸화 특이 다중결합의존성탐색증폭법(MS-MLPA)이 표준 검사로 사용됩니다. 이 검사는 15번 염색체 부위의 부성 유전자 발현 결여를 확인하며, 결실, 모체 일부다염색체성, 각인 결함 등 다양한 유전 기전을 구별할 수 있습니다. 확진 검사는 의료유전학과 또는 진단검사의학과에서 시행받으실 수 있습니다.', 2940, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '프라더 윌리 증후군', '프라더윌리증후군', 'CAUSE', '프라더 윌리 증후군은 15번 염색체 장완(15q11-q13)의 부성 유전 부위가 발현되지 않을 때 발생합니다. 가장 흔한 원인(약 70%)은 아버지로부터 받은 15번 염색체 결실이며, 두 번째 원인(약 25%)은 15번 염색체를 어머니로부터만 2개 받는 ''모체 일부다염색체성(maternal uniparental disomy)''입니다. 각인 결함(imprinting defect)도 소수에서 발생하며, 어떤 경우든 부성 유전자의 발현 결여가 공통 기전입니다.', 2941, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '프라더 윌리 증후군', '프라더윌리증후군', 'DEFINITION', '프라더 윌리 증후군은 15번 염색체 부성 유전 영역의 발현 결여로 발생하는 복합 유전질환으로, 신생아기에는 심한 근긴장 저하와 수유 곤란이 주 증상이며, 영아기 이후에는 과도한 식욕(과식증)과 비만, 성장 지연, 지적장애, 성선기능저하증, 행동 문제(고집, 강박)가 특징적으로 나타납니다. 성장호르몬 분비 감소로 인해 성장 지연도 동반되며, 조기 진단과 성장호르몬 치료, 식이 조절이 예후에 중요합니다.', 2942, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '프라더 윌리 증후군', '프라더윌리증후군', 'SYMPTOM', '프라더 윌리 증후군에서 과식증 외에 초기 증상으로 심한 근긴장 저하(근육 힘이 매우 없음), 수유 곤란, 체중 증가 불량, 영아기 성장 지연이 나타납니다. 이후 성장하면서 성선기능저하증(음경/고환 작음, 사춘기 지연), 키가 작은 성장 지연, 아몬드 모양의 눈, 작은 손발, 피부 흰색, 지적장애, 강박적 행동과 고집스러운 기질이 나타납니다. 성장호르몬 치료와 다학제적 관리가 필요하므로 전문의 상담을 권고합니다.', 2943, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '프라더 윌리 증후군', '프라더윌리증후군', 'DIAGNOSIS', '프라더 윌리 증후군의 세포유전학적 검사로는 표준 G-밴딩 핵형 분석과 FISH(형광제자리부합법)를 통해 15번 염색체 결실을 확인합니다. 분자 유전 검사로는 메틸화 특이 PCR이나 MS-MLPA가 사용되며, 이는 15q11-q13 부위의 CpG 부위 메틸화 패턴을 분석하여 부성 유전자 발현 결여를 확인하는 원리입니다. 모체 일부다염색체성과 각인 결함 구별을 위해서는 마이크로새틀라이트 마커 분석이나 SNP 배열 비교 유전체 혼성화 검사가 추가로 시행될 수 있습니다.', 2944, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '프라더 윌리 증후군', '프라더윌리증후군', 'TREATMENT', '프라더 윌리 증후군 치료에는 소아과·유전학과 전문의를 중심으로 내분비과(성장호르몬 치료), 영양사(비만 관리), 언어치료사, 물리치료사, 심리치료사, 특수교육 전문가 등 다학제 팀의 협력이 필요합니다. 행동·정서 문제에는 소아정신건강의학과 상담도 필수적이므로 전문의와 함께 개인별 치료 계획을 수립하시기 바랍니다.', 2945, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '헌팅톤 병', '헌팅톤병', 'CHECKUP', '근육 긴장도 증가와 경직은 헌팅톤병의 운동 증상 중 하나로 나타날 수 있으며, 특히 가족력이 있는 경우 신경과 전문의 진료를 받아보실 것을 권고합니다. 헌팅톤병 검진은 신경과(신경내과)에서 유전자 검사 및 신경학적 평가를 통해 이루어지며, 상급종합병원 신경과를 방문하시면 됩니다.', 2946, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '헌팅톤 병', '헌팅톤병', 'DIET_LIFE', '헌팅톤병은 진행성 신경퇴행성 질환으로, 운동·인지·정신 기능이 서서히 악화되기 때문에 정기적인 건강 점검이 필수적입니다. 규칙적인 추적 관찰을 통해 증상 변화를 조기에 발견하고, 약물 조정·재활·영양 관리 등 적절한 중재를 적시에 시행하여 삶의 질을 유지할 수 있습니다. 신경과 전문의와 함께 정기 방문 일정을 계획하시기 바랍니다.', 2947, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '헌팅톤 병', '헌팅톤병', 'MEDICATION', '헌팅톤병의 무도증에는 테트라베나진(tetrabenazine) 또는 도이테트라베나진이 사용되며, 우울·불안 등 정신 증상에는 항우울제(SSRI)와 항정신병약물이, 인지 증상 완화에는 보조적으로 콜린에스테라제 억제제가 고려될 수 있습니다. 이들 약물은 증상 완화에 도움이 되나 질병 자체를 늦추지는 못하므로, 반드시 신경과 및 정신건강의학과 전문의의 처방 하에 사용하여야 합니다.', 2948, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '헌팅톤 병', '헌팅톤병', 'PREVENTION', '헌팅톤병은 유전질환이므로 가족력이 있는 경우 신경과에서 유전자 검사를 통해 조기에 확인할 수 있습니다. 증상 발현 전부터 정기적인 신경학적 평가, 인지기능 검사, 정신건강 모니터링을 받고, 규칙적인 유산소 운동과 균형 잡힌 식단으로 전반적인 뇌 건강을 유지하는 것이 관리에 도움이 됩니다. 유전 상담도 함께 권고드립니다.', 2949, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '헌팅톤 병', '헌팅톤병', 'CAUSE', '헌팅톤병은 4번 염색체의 HTT 유전자 내 CAG 삼핵산 반복 서열이 비정상적으로 늘어나는 상염색체 우성 유전에 의해 발생합니다. 변이된 헌팅틴 단백질이 선조체와 대뇌 피질 신경세포를 손상시키며, 이 과정에서 도파민 및 세로토닌 계통의 이상으로 우울증이 주요 초기 증상으로 나타납니다. 부모 중 한 명이 환자이면 자녀에게 50% 확률로 유전됩니다.', 2950, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '헌팅톤 병', '헌팅톤병', 'REHAB', '헌팅톤병으로 인한 불수의 운동(무도증) 및 얼굴·손발 근육 이상에는 물리치료와 작업치료를 통한 재활이 도움이 됩니다. 물리치료로 균형·보행·근력을 유지하고, 작업치료로 일상생활 기능을 보존하며, 말하기·삼키기 장애에는 언어치료를 병행합니다. 재활 계획은 신경과 및 재활의학과 전문의와 함께 개인 상태에 맞게 수립하시기 바랍니다.', 2951, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '헌팅톤 병', '헌팅톤병', 'DEFINITION', '헌팅톤병은 HTT 유전자의 CAG 반복 증가로 인한 유전성 신경퇴행 질환으로, 불수의적 운동(무도증), 인지 저하, 정신 증상이 특징입니다. 진단은 특징적인 임상 증상과 가족력 확인, 유전자 검사(CAG 반복 수 40회 이상)로 확진하며, 뇌 MRI에서 선조체 위축 소견이 관찰될 수 있습니다. 확진 및 유전 상담을 위해 신경과 전문의를 방문하시기 바랍니다.', 2952, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '헌팅톤 병', '헌팅톤병', 'SYMPTOM', '헌팅톤병에서는 무도증(불수의 운동)으로 인해 걸음걸이가 불규칙하고 비틀거리는 양상이 나타나며, 구음 장애로 말투가 어눌해지고 늘어지는 증상도 대표적입니다. 또한 삼킴 곤란, 근육 경직, 균형 이상이 동반될 수 있어 이러한 증상이 있으면 신경과 전문의 진료를 받아보시기 바랍니다.', 2953, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '헌팅톤 병', '헌팅톤병', 'DIAGNOSIS', '헌팅톤병 진단은 임상 증상(무도증, 인지 변화, 정신 증상)과 가족력을 바탕으로 하며, 혈액 유전자 검사에서 HTT 유전자 CAG 반복이 40회 이상이면 확진됩니다. 뇌 MRI로 선조체(미상핵) 위축을 확인하고, 신경심리 검사로 인지 기능을 평가하기도 합니다. 신경과 전문의에게 상담 후 적절한 검사를 받으시기 바랍니다.', 2954, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '헌팅톤 병', '헌팅톤병', 'TREATMENT', '헌팅톤병의 피로와 운동 어려움 개선에는 개인 맞춤형 물리치료와 작업치료가 가장 효과적인 비약물적 방법입니다. 규칙적인 유산소 운동(수영, 걷기 등)이 근력과 지구력 유지에 도움이 되며, 피로 관리를 위해 에너지 절약 기법과 충분한 수면도 중요합니다. 운동 계획 수립은 재활의학과 및 신경과 전문의와 상담하시기 바랍니다.', 2955, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '혈우병', '혈우병', 'CHECKUP', '상처 후 지혈이 되지 않거나 오래 걸리는 경우 혈우병을 의심할 수 있으며, 특히 남아에서 이런 증상이 반복된다면 혈액내과(소아혈액종양과) 진료를 권고합니다. 검진은 전혈구검사, PT/aPTT 등 혈액응고 검사, 응고인자 VIII·IX 활성도 측정을 통해 이루어지므로 소아과 또는 혈액내과를 방문하시기 바랍니다.', 2956, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '혈우병', '혈우병', 'MEDICATION', '아스피린은 혈소판 기능을 억제하여 출혈 시간을 연장시키므로 혈우병 환자에게 매우 위험합니다. 혈우병 환자는 아스피린 및 NSAIDs(비스테로이드 항염증제) 복용을 원칙적으로 피해야 하며, 진통이 필요할 경우 아세트아미노펜(타이레놀)을 사용하는 것이 안전합니다. 복용 중인 약물에 대해서는 반드시 혈액내과 전문의와 상담하시기 바랍니다.', 2957, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '혈우병', '혈우병', 'PREVENTION', '혈우병은 X 염색체 연관 열성 유전질환이므로, 가족력이 있는 경우 임신 전 유전 상담과 산전 유전자 검사(융모막 생검 또는 양수 검사)를 통해 태아의 유전 여부를 확인할 수 있습니다. 보인자 여성은 혈액내과 및 산부인과 전문의와 협력하여 출산 계획을 세우는 것이 중요하며, 신생아 출생 시 즉시 응고인자 검사를 받도록 해야 합니다.', 2958, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '혈우병', '혈우병', 'EXERCISE', '혈우병 환자에게는 관절과 근육에 충격을 최소화하는 수영, 수중 운동, 걷기, 자전거 타기 등 저충격 유산소 운동이 적합합니다. 근력 강화 운동도 관절 보호에 도움이 되나, 과격한 접촉 운동이나 낙상 위험이 높은 운동은 피해야 합니다. 운동 프로그램은 혈액내과 전문의 및 물리치료사와 상담 후 개인 상태에 맞게 시작하시기 바랍니다.', 2959, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '혈우병', '혈우병', 'CAUSE', '혈우병은 X 염색체에 위치한 F8(8번 응고인자) 또는 F9(9번 응고인자) 유전자의 돌연변이로 인해 발생하는 유전질환입니다. F8 유전자 이상은 혈우병 A, F9 유전자 이상은 혈우병 B를 유발하며, 해당 응고인자의 결핍으로 혈액이 정상적으로 응고되지 않아 과도한 출혈이 나타납니다. 30% 정도는 가족력 없이 새로운 돌연변이로 발생할 수 있습니다.', 2960, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '혈우병', '혈우병', 'DEFINITION', '혈우병은 응고인자(주로 VIII 또는 IX 인자) 결핍으로 인해 출혈이 잘 멈추지 않는 유전성 출혈 질환입니다. 주요 특징으로는 경미한 외상에도 과도한 출혈, 관절 내 출혈(혈관절증), 근육 출혈, 수술·치과 처치 후 과다 출혈 등이 있으며, 대부분 남성에서 발생합니다. 결핍된 응고인자 종류와 활성도에 따라 혈우병 A, B로 구분되고 중증도가 나뉩니다.', 2961, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '혈우병', '혈우병', 'SYMPTOM', '혈우병의 주요 증상은 경미한 외상이나 자연적으로 발생하는 과도한 출혈로, 피부 멍(자반), 근육 내 혈종, 관절 내 출혈(부종·통증·운동 제한), 비출혈, 혈뇨, 소화관 출혈 등이 나타날 수 있습니다. 중증의 경우 명백한 원인 없이도 자발성 출혈이 발생하며, 두개 내 출혈 등 생명을 위협하는 출혈도 가능하므로 혈액내과 전문의 진료를 받으시기 바랍니다.', 2962, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '혈우병', '혈우병', 'DIAGNOSIS', '과도한 출혈이 반복적으로 발생한다면 혈우병을 포함한 출혈성 질환을 감별하기 위해 전문적인 진단이 필요합니다. 응고 기능 검사는 일반 병원에서도 시행 가능하나, 정확한 응고인자 검사와 치료를 위해서는 혈액내과가 있는 대학병원 방문을 권고합니다. 조기 진단이 관절 손상 등 합병증 예방에 매우 중요합니다.', 2963, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('유전질환', '혈우병', '혈우병', 'TREATMENT', '혈우병 소아에서 수혈(혈액제제)은 응고인자 보충을 위해 필요하나, 혈액 매개 감염(B형·C형 간염, HIV 등) 위험이 있었으나 현재는 바이러스 불활화 처리된 농축 응고인자 제제를 주로 사용합니다. 수혈 후에는 응고인자 억제항체(inhibitor) 형성이 발생할 수 있어 치료를 복잡하게 만들 수 있습니다. 치료 방법과 위험성에 대해 혈액내과 전문의와 충분히 상담하시기 바랍니다.', 2964, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '고산병', '고산병', 'MEDICATION', '고산병 예방에 효과가 입증된 약물로는 아세타졸아마이드(다이아목스)가 가장 대표적이며, 고도 상승 1~2일 전부터 복용을 시작합니다. 덱사메타손(스테로이드)은 급성 고산병 및 뇌부종 예방·치료에 사용되며, 실데나필은 고산성 폐부종 예방에 일부 사용됩니다. 이들 약물은 부작용이 있으므로 반드시 의사의 처방에 따라 복용하여야 합니다.', 2965, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '고산병', '고산병', 'PREVENTION', '고산병 예방을 위해 고도에 천천히 적응(하루 300~500m 이상 상승 자제)하고, 충분한 수분 섭취가 중요합니다. 음주는 탈수와 호흡 억제를 유발하여 고산병을 악화시킬 수 있으므로 자제해야 하며, 흡연도 산소 운반 능력을 저하시키므로 피하는 것이 좋습니다. 고위험자는 아세타졸아마이드 예방 복용을 의사와 상담하시기 바랍니다.', 2966, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '고산병', '고산병', 'CAUSE', '고산병에 걸릴 가능성이 높은 사람은 빠른 속도로 고도를 높인 경우, 이전에 고산병을 경험한 사람, 심폐 질환자, 빈혈 환자 등입니다. 반면 고도에 강한 사람은 일반적으로 이전 고지대 생활 경험이 있거나 느린 적응 과정을 거친 경우이나, 특별한 신체적 특징보다는 점진적 순응이 더 중요한 요소입니다. 과거 고산병 경험이 있다면 의사와 상담 후 예방 조치를 취하시기 바랍니다.', 2967, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '고산병', '고산병', 'DEFINITION', '산에 오를 때 두통, 메스꺼움, 어지럼증, 식욕 저하 등의 증상이 나타나는 것은 전형적인 급성 고산병(AMS) 증상에 해당합니다. 고산병은 해발 2,500m 이상의 고도에서 산소 분압 감소로 인해 발생하며, 정상 등반 시 이러한 증상이 나타난다면 더 이상 상승하지 않고 휴식을 취하거나 하강하는 것이 필요합니다.', 2968, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '고산병', '고산병', 'SYMPTOM', '어지럼증과 구토는 고산병의 주요 증상에 포함됩니다. 고산병은 두통을 포함하여 피로, 식욕 부진, 메스꺼움·구토, 어지럼증, 수면 장애 등이 복합적으로 나타나며, 증상이 악화되면 고산성 뇌부종이나 폐부종으로 진행될 수 있어 즉시 하강이 필요합니다. 이러한 증상이 고지대에서 나타나면 즉시 전문의 또는 구조대에 도움을 요청하시기 바랍니다.', 2969, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '고산병', '고산병', 'DIAGNOSIS', '고산병은 빠른 고도 상승으로 인해 산소 분압이 낮아지면서 발생하며, 일반적으로 해발 2,500m 이상에서 두통, 피로, 구역, 수면 장애 등의 증상으로 진단합니다. 임상 증상 기반으로 진단하며(Lake Louise 점수 등), 심한 경우 흉부 X선, 산소포화도 측정, 뇌 CT/MRI로 합병증을 평가합니다. 증상 발현 시 고도 하강이 가장 중요한 치료이므로 즉각적인 조치가 필요합니다.', 2970, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '고산병', '고산병', 'TREATMENT', '고산병으로 인한 소화기 증상(복부 팽만, 메스꺼움, 속쓰림, 역류)은 주로 산소 부족에 의한 것이므로, 우선 하강 또는 산소 공급이 가장 중요한 처치입니다. 증상이 지속된다면 내과 또는 소화기내과 전문의 진료를 통해 위장 증상에 대한 추가 평가와 치료를 받으시기 바랍니다. 고산병 전반적인 관리는 응급의학과 또는 내과 전문의와 상담하시기 바랍니다.', 2971, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '과호흡 증후군', '과호흡증후군', 'DIET_LIFE', '과호흡 증후군에 의한 어지럼증과 호흡 촉박 증상 개선을 위해서는 스트레스와 불안을 줄이는 것이 핵심입니다. 복식호흡 연습, 명상, 규칙적인 유산소 운동이 증상 완화에 효과적이며, 카페인과 알코올 섭취를 줄이고 충분한 수면을 취하는 것이 중요합니다. 증상이 지속된다면 호흡기내과 또는 정신건강의학과 전문의와 상담하시기 바랍니다.', 2972, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '과호흡 증후군', '과호흡증후군', 'PREVENTION', '과호흡 증후군 예방을 위해 불안·스트레스 관리가 가장 중요하며, 규칙적인 호흡 훈련(복식호흡, 횡격막 호흡)이 도움이 됩니다. 카페인 섭취 제한, 금연, 적절한 운동, 충분한 수면이 폐 건강과 자율신경 안정에 기여합니다. 과호흡 발작이 반복된다면 호흡기내과 또는 정신건강의학과 전문의의 진료를 받아 원인을 파악하시기 바랍니다.', 2973, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '과호흡 증후군', '과호흡증후군', 'CAUSE', '과호흡 증후군의 주요 원인은 불안, 공황장애, 극도의 스트레스 등 심리적 요인이며, 이로 인해 호흡수가 증가하면 혈중 이산화탄소 농도가 감소(저탄산혈증)하여 호흡성 알칼리증이 발생합니다. 이 상태가 말초 혈관 수축, 뇌혈류 감소, 칼슘 이온 변화를 유발해 어지럼증·손발 저림·흉통 등 신체 증상으로 이어지는 악순환이 형성됩니다. 심리적 원인이 의심된다면 정신건강의학과 상담을 권고합니다.', 2974, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '과호흡 증후군', '과호흡증후군', 'DEFINITION', '과호흡 증후군은 분당 호흡수가 정상(12~20회)을 초과하여 혈중 이산화탄소가 과도하게 배출됨으로써 발생하는 상태로, 폐렴에 의한 호흡 곤란과는 구별됩니다. 주요 증상으로 어지럼증, 손발 저림, 흉통, 구강 주위 저림, 두근거림 등이 나타나며, 폐렴은 감염에 의한 염증으로 호흡 곤란이 발생하는 별개의 질환입니다. 호흡 곤란이 지속된다면 호흡기내과 전문의 진료를 받으시기 바랍니다.', 2975, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '과호흡 증후군', '과호흡증후군', 'SYMPTOM', '과호흡 증후군에서는 빠른 호흡으로 인해 혈중 이산화탄소(CO2)가 과도하게 배출되어 혈중 CO2 농도가 오히려 감소(저탄산혈증)하고, 이로 인해 혈액 pH가 상승하는 호흡성 알칼리증이 나타납니다. 혈중 CO2 감소는 뇌혈관 수축, 산소-헤모글로빈 해리 곡선 이동 등을 유발하여 두통, 어지럼증, 손발 저림 등의 증상을 일으킵니다. 이 악순환 차단을 위해 호흡 조절 훈련이 핵심 치료입니다.', 2976, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '과호흡 증후군', '과호흡증후군', 'DIAGNOSIS', '과호흡 증후군의 심리적 원인 평가를 위해 정신건강의학과에서 불안장애·공황장애에 대한 구조화된 면담 및 심리검사(불안척도, 공황척도 등)를 시행합니다. 신체 원인 배제를 위해 폐기능 검사, 혈액 가스 분석 등을 먼저 시행하는 경우도 많으므로, 호흡기내과와 정신건강의학과를 함께 방문하는 것이 권고됩니다.', 2977, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '과호흡 증후군', '과호흡증후군', 'TREATMENT', '과호흡 증후군 응급 시 가장 먼저 환자를 안정시키고, 천천히 코로 들이쉬고 입으로 내쉬는 복식호흡을 유도하는 것이 중요합니다. 과거에는 종이봉투 호흡법이 사용되었으나 현재는 권장되지 않으며, 대신 양손을 모아 코와 입을 살짝 가리고 호흡을 조절하거나 안정된 환경을 제공하는 방법을 사용합니다. 증상이 지속되거나 반복된다면 호흡기내과 또는 응급의학과 진료를 받으시기 바랍니다.', 2978, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '광견병', '광견병', 'MEDICATION', '광견병 예방을 위한 약물로는 광견병 예방 백신(광견병 불활화 바이러스 백신)이 있으며, 반려견은 동물병원에서 정기 예방접종을 받아야 합니다. 사람의 경우 고위험군(수의사, 야생동물 접촉자 등)은 사전 예방접종을 받을 수 있으며, 동물에게 물린 후에는 즉시 상처를 씻고 응급의료기관에서 노출 후 예방(PEP) 처치를 받아야 합니다.', 2979, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '광견병', '광견병', 'PREVENTION', '광견병 예방접종은 사람의 경우 노출 전 예방(0, 7, 21~28일 3회 접종)과 노출 후 예방(0, 3, 7, 14일 접종)으로 나뉩니다. 동물에게 물린 후에는 상처를 비누와 물로 즉시 충분히 세척한 후, 가능한 빨리 의료기관을 방문하여 광견병 면역글로불린(HRIG)과 백신을 투여받아야 합니다. 반려동물은 수의사를 통해 정기적으로 예방접종을 유지해야 합니다.', 2980, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '광견병', '광견병', 'CAUSE', '광견병은 광견병 바이러스(Lyssavirus)에 감염된 동물(개, 박쥐, 너구리 등)에게 물리거나 긁혀 타액이 상처에 접촉될 때 감염됩니다. 예방을 위해서는 반려동물의 정기 예방접종, 야생동물 접촉 자제, 물림 사고 발생 시 즉각적인 상처 세척 및 의료기관 방문이 가장 중요합니다. 광견병은 발병 후 치료가 어려우므로 노출 즉시 예방 처치를 받는 것이 핵심입니다.', 2981, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '광견병', '광견병', 'DEFINITION', '광견병은 광견병 바이러스에 감염된 포유동물(개, 고양이, 박쥐, 너구리, 여우 등)에게 물리거나 타액이 점막·상처에 접촉될 때 감염되는 인수공통감염병입니다. 위험 요소로는 광견병 유행 지역 여행, 야생동물 접촉, 예방접종을 받지 않은 동물과의 접촉 등이 있으며, 일단 증상이 발현되면 거의 100% 치명적이므로 노출 즉시 예방 처치가 필수입니다.', 2982, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '광견병', '광견병', 'SYMPTOM', '개에게 물린 후 광견병을 의심할 수 있는 증상으로는 잠복기(수일~수개월) 후 물린 부위의 통증·저림, 발열, 두통, 불안이 나타난 후 신경 증상(공수증, 공풍증, 흥분, 마비)이 진행됩니다. 그러나 증상 발현 전에 예방이 핵심이므로, 개에게 물린 즉시 상처를 세척하고 응급실 또는 내과를 방문하여 노출 후 예방접종(PEP)을 받아야 합니다.', 2983, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '광견병', '광견병', 'DIAGNOSIS', '개에게 물린 후 광견병 의심 시 확진은 주로 사후 뇌 조직 검사로 이루어지며, 생존 중에는 피부 생검, 타액, 뇌척수액 RT-PCR 검사로 진단합니다. 그러나 물린 후에는 진단을 기다리지 않고 즉시 응급실에서 상처 세척, 파상풍 예방, 광견병 노출 후 예방(HRIG + 백신) 처치를 시작해야 하며, 보건소에도 신고하여 해당 동물의 관찰이 이루어져야 합니다.', 2984, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '광견병', '광견병', 'TREATMENT', '광견병 바이러스에 감염된 동물에게 물린 후 치료를 받지 않으면 광견병이 발병할 가능성이 있으며, 일단 증상이 나타나면 치사율이 거의 100%에 달합니다. 물린 즉시 상처를 충분히 세척하고 24시간 내에 의료기관에서 광견병 면역글로불린과 예방 백신을 투여받는 노출 후 예방(PEP)이 발병을 효과적으로 막을 수 있으므로, 지체 없이 응급실을 방문하시기 바랍니다.', 2985, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '구획 증후군', '구획증후군', 'CAUSE', '구획 증후군은 교통사고나 골절 외에도 심한 타박상, 압좌 손상, 화상, 장시간 지혈대 사용, 과격한 운동(특히 경골 근육), 혈관 손상 후 재관류, 석고 붕대나 압박 드레싱에 의한 외부 압박, 출혈성 질환, 약물 주사 합병증 등 다양한 원인으로 발생할 수 있습니다. 원인에 관계없이 구획 내 압력이 상승하면 응급 근막절개술이 필요하므로 즉시 정형외과 또는 응급의학과 진료를 받으시기 바랍니다.', 2986, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '구획 증후군', '구획증후군', 'DEFINITION', '구획 증후군과 함께 나타날 수 있는 증상으로는 심한 통증, 부종, 피부 긴장감, 감각 이상(저림·무감각), 근력 저하, 창백·차가운 피부 등이 있습니다. 치료가 지연될 경우 근육 괴사로 인해 영구적 근육 손상, 신경 손상, 사지 기능 상실, 신부전(횡문근융해증), 패혈증 등 심각한 합병증이 발생할 수 있습니다. 증상이 의심되면 즉시 응급의학과 또는 정형외과를 방문하시기 바랍니다.', 2987, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '구획 증후군', '구획증후군', 'SYMPTOM', '구획 증후군에서 종아리의 단단함(경결감)과 감각 이상은 구획 내 압력이 상승하여 근육과 신경, 혈관이 압박받고 있음을 의미하는 중요한 경고 신호입니다. 이는 조직으로의 혈류 공급이 저하되어 근육 괴사가 진행 중일 수 있으므로, 즉각적인 응급 처치(근막절개술)가 필요한 응급 상황임을 나타냅니다. 이러한 증상 발생 시 지체 없이 응급실을 방문하시기 바랍니다.', 2988, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '구획 증후군', '구획증후군', 'DIAGNOSIS', '갑작스러운 부종과 심한 통증이 발생한 경우 구획 증후군을 포함한 여러 응급 상태를 배제하기 위해 즉시 의료기관을 방문해야 합니다. 구획 증후군은 응급 질환으로 동네 병원에서 초기 평가 후 즉각적인 수술적 처치가 가능한 정형외과 또는 응급의학과가 있는 2차·3차 의료기관으로 이송이 필요할 수 있습니다. 증상 발생 시 지체 없이 대형 병원 응급실을 방문하시기 바랍니다.', 2989, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '구획 증후군', '구획증후군', 'TREATMENT', '구획 증후군의 근본적 치료는 근막절개술(fasciotomy)로, 증가된 구획 내 압력을 즉각 해소하는 응급 수술입니다. 보존적으로는 압박 드레싱·석고 제거, 심장보다 낮게 사지 위치(과도한 거상은 금지), 통증 조절, 산소 공급 등이 시행되나 이는 수술 전 일시적 조치입니다. 치료 지연 시 영구적 근육·신경 손상이 발생할 수 있어 정형외과 전문의의 신속한 처치가 필수입니다.', 2990, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '급성 류마티스성 열', '급성류마티스성열', 'MEDICATION', '급성 류마티스성 열 치료에는 A군 연쇄상구균 박멸을 위한 페니실린(또는 아목시실린) 항생제, 관절염과 발열 조절을 위한 아스피린 또는 NSAIDs, 심한 심장염에는 코르티코스테로이드가 사용됩니다. 재발 예방을 위해 장기간 페니실린 예방 투여가 필요하며, 이 약물들은 원인균 제거, 염증 억제, 심장 합병증 예방에 효과적입니다. 약물 선택과 기간은 소아과 또는 내과 전문의와 상담하시기 바랍니다.', 2991, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '급성 류마티스성 열', '급성류마티스성열', 'PREVENTION', '급성 류마티스성 열의 가장 중요한 예방책은 A군 연쇄상구균(GAS)에 의한 인두염을 신속히 진단하고 페니실린 등 항생제로 완전히 치료하는 것입니다. 1차 예방은 인두염 발생 시 9일 이내 항생제 치료를 시작하는 것이며, 류마티스 열을 경험한 환자는 재발 방지를 위해 수년간 장기 항생제 예방 투여가 필요합니다. 인두염 증상 발생 시 소아과 또는 내과 전문의를 방문하시기 바랍니다.', 2992, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '급성 류마티스성 열', '급성류마티스성열', 'CAUSE', '급성 류마티스성 열은 A군 베타 용혈성 연쇄상구균(화농성 연쇄상구균) 인두 감염 후 2~4주 뒤에 발생하는 자가면역 반응입니다. 세균 항원과 심장, 관절, 피부, 뇌 조직 간의 분자 모방(molecular mimicry)으로 인해 면역계가 자기 조직을 공격하여 염증이 발생하며, 심장 판막을 침범하면 류마티스 심장병으로 영구적 손상을 초래할 수 있습니다.', 2993, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '급성 류마티스성 열', '급성류마티스성열', 'DEFINITION', '급성 류마티스성 열은 A군 베타 용혈성 연쇄상구균 인두 감염 후 발생하는 자가면역성 염증 질환으로, 주로 5~15세 소아·청소년에서 발생합니다. 관절염(이동성 다발성), 심장염(심내막·심근·심막), 무도증(시드넘 무도병), 피하 결절, 윤상 홍반을 주요 특징으로 하며, 심장 합병증이 가장 중요한 후유증입니다. 소아과 또는 내과 전문의와 상담하여 조기 치료를 받으시기 바랍니다.', 2994, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '급성 류마티스성 열', '급성류마티스성열', 'SYMPTOM', '급성 류마티스성 열에서 인두 통증과 편도 부종은 선행하는 A군 연쇄상구균 인두염의 증상으로, 페니실린 또는 아목시실린 등 항생제를 10일간 투여하면 세균 제거와 함께 증상 완화에 효과적입니다. 통증 완화를 위해 아세트아미노펜이나 이부프로펜을 사용할 수 있으며, 충분한 수분 섭취와 휴식도 중요합니다. 항생제 치료는 반드시 소아과 또는 내과 전문의 처방에 따라 시행하시기 바랍니다.', 2995, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '급성 류마티스성 열', '급성류마티스성열', 'DIAGNOSIS', '관절통, 이동성 다발성 관절염과 함께 발열, 인두염 병력이 있다면 급성 류마티스성 열을 의심할 수 있으며, 소아과(소아의 경우) 또는 내과·류마티스내과 전문의를 방문하시기 바랍니다. 의사는 임상 증상, 항연쇄상구균 항체(ASO), 인후 배양 검사, 염증 수치, 심장 초음파 등을 통해 진단합니다. 조기 진단과 치료가 심장 합병증 예방에 매우 중요합니다.', 2996, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '급성 류마티스성 열', '급성류마티스성열', 'TREATMENT', '급성 류마티스성 열의 기본 치료는 항생제(페니실린)와 항염증제(아스피린/스테로이드)이지만, 심장염이 심한 경우 침상 안정이 필요하며 심부전 합병증에는 이뇨제·디곡신 등이 추가됩니다. 관절 증상에는 물리치료, 무도증에는 항경련제(할로페리돌, 발프로산)가 사용될 수 있으며, 장기 페니실린 예방 투여와 정기적인 심장 초음파 추적 관찰도 필수적입니다. 전문의와 함께 개인 상태에 맞는 치료 계획을 수립하시기 바랍니다.', 2997, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '기도 폐쇄', '기도폐쇄', 'PREVENTION', '기도 폐쇄 예방을 위해 음식을 천천히 먹고 충분히 씹으며, 식사 중 과도한 대화나 웃음을 피하고, 소아에게는 작은 물건을 가까이 두지 않는 것이 중요합니다. 의식 저하 환자나 연하 장애 환자에게는 음식 질감을 조절(죽·연식)하고 식사 자세를 관리하며, 의료진은 기도 흡인 예방 조치를 취해야 합니다. 천식·알레르기 등 만성 기도 질환자는 정기적인 호흡기내과 추적 관찰이 필요합니다.', 2998, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '기도 폐쇄', '기도폐쇄', 'CAUSE', '기도(식도) 폐쇄의 주요 원인으로는 음식물 급격한 섭취 외에도, 의치나 이물질 삼킴, 목 또는 식도 종양, 외부 종괴에 의한 압박, 알레르기 반응(아나필락시스)에 의한 인후 부종, 후두개염, 신경근육 질환에 의한 연하 장애, 소아에서의 이물질 흡인 등이 있습니다. 원인에 따라 치료가 달라지므로 기도 폐쇄 증상 발생 시 즉시 응급실을 방문하시기 바랍니다.', 2999, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '기도 폐쇄', '기도폐쇄', 'DEFINITION', '기도 폐쇄는 이물질, 부종, 종양 등으로 인해 공기가 폐로 이동하는 기도가 부분 또는 완전히 막힌 상태를 말합니다. 치킨을 먹다 사레가 들려 호흡 곤란이 발생한 경우 이물질에 의한 기도 폐쇄일 수 있으며, 기침으로 해결되지 않고 증상이 지속된다면 즉시 응급 처치(하임리히법)가 필요하고 응급실로 이송해야 합니다.', 3000, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '기도 폐쇄', '기도폐쇄', 'SYMPTOM', '기도 폐쇄의 주요 증상에는 호흡 없음(무호흡), 입술·손발톱 청색증(청색증), 의식 소실이 포함되며, 이는 완전 기도 폐쇄의 심각한 징후입니다. 이 외에도 고음의 천명음(stridor), 쉰 목소리, 극심한 호흡 노력, 목을 잡는 행동 등이 나타날 수 있습니다. 이러한 증상 발생 시 즉각적인 하임리히법 시행과 응급 구조 요청(119)이 필요합니다.', 3001, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '기도 폐쇄', '기도폐쇄', 'DIAGNOSIS', '혈액 산소포화도 측정(맥박산소측정기)은 비침습적이고 즉각적으로 산소화 상태를 평가할 수 있어 기도 폐쇄 의심 시 신속한 중증도 판단에 유용합니다. 반면 생리학적 폐기능 검사는 시간이 소요되어 응급 상황에는 적합하지 않습니다. 다만 산소포화도 측정만으로는 기도 폐쇄의 원인을 파악할 수 없으므로 기도내시경, 영상 검사 등 추가 진단이 필요하며 응급의학과 전문의의 판단이 중요합니다.', 3002, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '기도 폐쇄', '기도폐쇄', 'TREATMENT', '기도 폐쇄 응급 상황에서는 의식 있는 환자에게 하임리히법(복부 밀쳐올리기)을 시행하고, 의식 없는 경우 즉시 심폐소생술(CPR)을 시작합니다. 의료 현장에서는 후두경과 마기엘 포셉을 이용한 이물질 제거, 응급 기관 삽관, 윤상갑상막 절개술 등이 사용되며, 산소 공급 장비와 백밸브마스크가 필수적입니다. 119를 즉시 호출하고 전문 의료진의 처치를 받아야 합니다.', 3003, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대동맥 박리', '대동맥박리', 'PREVENTION', '대동맥 박리의 주요 위험 인자인 고혈압 예방 및 관리를 위해 정기적인 혈압 측정, 저염식·저지방 식단, 규칙적인 유산소 운동, 금연, 절주가 중요합니다. 혈압이 조절되지 않는다면 항고혈압제를 꾸준히 복용해야 하며, 마르판 증후군 등 결체조직 질환이 있는 경우 정기적인 심장혈관 검진이 필수적입니다. 고혈압 관리를 위해 순환기내과 전문의와 지속적으로 협력하시기 바랍니다.', 3004, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대동맥 박리', '대동맥박리', 'CAUSE', '대동맥 박리의 주요 원인은 고혈압(가장 흔함)으로, 지속적인 혈압 상승이 대동맥 내막을 약화시킵니다. 이 외에 마르판 증후군·엘러스-단로스 증후군 등 결체조직 질환, 대동맥 죽상경화증, 이첨판 대동맥판막, 임신, 외상, 코카인 사용 등이 원인이 될 수 있습니다. 이러한 위험 인자를 가진 경우 순환기내과 전문의의 정기 검진을 받으시기 바랍니다.', 3005, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대동맥 박리', '대동맥박리', 'DEFINITION', '대동맥 박리는 대동맥 내막에 찢어짐이 발생하여 혈액이 내막과 중막 사이로 파고들어 박리강을 형성하는 생명을 위협하는 응급 질환입니다. 주로 고혈압 환자에서 발생하며, 갑작스러운 찢어지는 듯한 흉통이나 등 통증으로 시작됩니다. 즉각적인 수술 또는 혈압 조절 치료가 필요하며, 치료 지연 시 사망률이 매우 높으므로 의심 증상 발현 시 즉시 응급실을 방문해야 합니다.', 3006, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대동맥 박리', '대동맥박리', 'SYMPTOM', '대동맥 박리의 주요 증상은 갑작스럽고 극심한 찢어지거나 쥐어짜는 듯한 흉통 또는 등 통증이 가장 전형적입니다. 추가 증상으로 혈압 좌우 차이, 맥박 소실, 실신, 뇌졸중 증상(편마비·언어 장애), 신부전, 장 허혈에 의한 복통, 하지 허혈, 대동맥 판막 역류에 의한 호흡 곤란 등이 나타날 수 있으며, 즉각적인 응급 처치가 필요한 질환입니다.', 3007, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대동맥 박리', '대동맥박리', 'DIAGNOSIS', '고혈압 환자에서 갑작스럽게 발생하는 찢어지는 듯한 심한 흉통 또는 등 통증은 대동맥 박리를 강하게 의심해야 하는 증상으로, 즉시 응급실을 방문해야 합니다. 대동맥 박리 진단을 위해 흉부 CT 혈관조영술, 경식도 심초음파, MRI 등을 시행하며, 진단이 확인되면 즉각적인 혈압 조절 및 수술적 치료가 필요합니다. 절대 지체하지 말고 119를 호출하시기 바랍니다.', 3008, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대동맥 박리', '대동맥박리', 'TREATMENT', '대동맥 박리는 즉각적인 생명 위협 상황으로, 극심한 흉통·등 통증, 혈압 이상, 의식 저하, 뇌졸중 증상, 사지 맥박 소실 등이 나타나면 응급 상황으로 판단합니다. 치료는 먼저 혈압과 심박수를 낮추는 약물 치료(베타차단제, 니트로프루시드)로 진행 억제를 시도하며, 상행 대동맥 침범(Type A)은 응급 수술, 하행 대동맥(Type B)은 약물 치료 또는 혈관 내 스텐트 시술을 시행합니다.', 3009, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대사성 산증', '대사성산증', 'MEDICATION', '대사성 산증 치료에 사용되는 중탄산나트륨(sodium bicarbonate)은 산증 교정에 효과적이나 과다 투여 시 대사성 알칼리증, 저칼슘혈증, 저칼륨혈증 등의 부작용이 나타날 수 있습니다. 부작용 최소화를 위해 혈액 가스 및 전해질 검사로 면밀히 모니터링하면서 적정 용량을 투여하며, 원인 질환(당뇨 케톤산증에는 인슐린, 신부전에는 투석 등) 치료를 병행하는 것이 중요합니다. 약물 치료는 내과 전문의의 처방에 따라 시행되어야 합니다.', 3010, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대사성 산증', '대사성산증', 'CAUSE', '대사성 산증의 주요 원인은 당뇨병성 케톤산증(DKA), 젖산 산증(쇼크·패혈증·저산소증), 신부전에 의한 산 배출 장애, 심한 설사에 의한 중탄산염 소실, 독성 물질 섭취(메탄올, 에틸렌글리콜, 살리실산) 등입니다. 원인에 따라 치료 방향이 달라지므로 혈액 가스 분석, 전해질 검사, 음이온 갭(anion gap) 계산을 통해 원인을 파악하는 것이 중요하며, 내과 전문의 진료를 받으시기 바랍니다.', 3011, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대사성 산증', '대사성산증', 'DEFINITION', '대사성 산증은 혈액의 pH가 7.35 미만으로 낮아지는 상태로, 체내 산의 과잉 축적 또는 중탄산염(HCO3-)의 과도한 소실로 발생합니다. 원인으로는 당뇨 케톤산증, 젖산 산증, 신부전, 설사, 독성물질 섭취 등이 있으며, 치료는 원인 제거(인슐린 투여, 수액 공급, 투석 등)와 함께 중증인 경우 중탄산나트륨 투여로 pH를 교정합니다. 증상 발생 시 내과 전문의 진료를 받으시기 바랍니다.', 3012, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대사성 산증', '대사성산증', 'SYMPTOM', '대사성 산증의 주요 증상으로는 기면·졸음, 두통 외에도 빠르고 깊은 호흡(쿠스마울 호흡), 오심·구토, 복통, 피로, 혼돈·의식 저하, 부정맥, 혈압 저하, 피부 창백 등이 나타날 수 있습니다. 당뇨 케톤산증의 경우 과일향(아세톤) 입냄새가 동반되며, 중증인 경우 쇼크와 혼수로 진행할 수 있습니다. 이러한 증상 발생 시 즉시 내과 또는 응급실을 방문하시기 바랍니다.', 3013, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대사성 산증', '대사성산증', 'DIAGNOSIS', '저혈압, 폐부종, 부정맥을 동반한 대사성 산증은 응급 상황으로, 즉시 응급실이 있는 종합병원 또는 대학병원을 방문해야 합니다. 중환자실에서의 집중 모니터링과 원인 치료가 필요하며, 내과(신장내과, 내분비내과 등) 전문의의 처치가 이루어집니다. 응급 처치가 지연될수록 위험하므로 119를 통한 빠른 이송이 중요합니다.', 3014, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대사성 산증', '대사성산증', 'TREATMENT', '대사성 산증 치료에서 중탄산나트륨은 pH 7.1 미만의 심한 산증에서 단독 또는 다른 치료와 병행하여 사용됩니다. 당뇨 케톤산증에는 인슐린·수액 치료가 우선이며, 신부전에 의한 산증은 투석이 필요합니다. 젖산 산증에서는 원인 교정(쇼크 치료)이 핵심이며, 부작용 감소를 위해 혈액 가스·전해질 모니터링하에 세심하게 투여량을 조절해야 합니다.', 3015, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대사성 알칼리증', '대사성알칼리증', 'CAUSE', '대사성 알칼리증의 원인으로는 구토·위 흡인 외에도 이뇨제(특히 루프 이뇨제·티아지드) 과다 사용, 코르티코스테로이드·무기질코르티코이드 과잉, 원발성 알도스테론증, 심한 저칼륨혈증, 우유-알칼리 증후군, 중탄산나트륨 과다 투여 등이 있습니다. 원인 파악을 위해 소변 염소 농도, 전해질 검사가 도움이 되며, 내과 전문의 진료를 받으시기 바랍니다.', 3016, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대사성 알칼리증', '대사성알칼리증', 'DEFINITION', '대사성 알칼리증은 혈액 pH가 7.45를 초과하여 상승하는 상태로, 체내 산의 소실(구토, 이뇨제) 또는 중탄산염의 과잉 축적으로 발생합니다. 신장에서의 중탄산염 재흡수 증가가 알칼리증을 지속시키며, 주요 증상으로는 근육 경련, 손발 저림, 혼돈, 부정맥, 저환기 등이 나타날 수 있습니다. 내과 전문의 진료를 통해 원인을 파악하고 치료를 받으시기 바랍니다.', 3017, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대사성 알칼리증', '대사성알칼리증', 'SYMPTOM', '대사성 알칼리증의 증상으로는 근육 경련·경직, 손발 저림(감각 이상), 두통, 어지럼증, 혼돈, 과민성, 오심, 저환기(호흡 보상), 부정맥이 나타날 수 있습니다. 저칼슘혈증·저칼륨혈증을 동반하는 경우가 많아 심각한 부정맥이나 근육 마비로 이어질 수 있으며, 기저 질환(고혈압, 신장 질환)과 관련된 증상이 함께 나타날 수 있습니다. 내과 전문의의 진단과 치료를 받으시기 바랍니다.', 3018, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대사성 알칼리증', '대사성알칼리증', 'DIAGNOSIS', '인지력 저하와 저린 증상이 동반된 대사성 알칼리증이 의심된다면 내과(신장내과) 전문의를 우선 방문하여 혈액 가스 분석 및 전해질 검사를 받는 것이 권고됩니다. 신경학적 증상이 두드러지는 경우 신경과 전문의와의 협진이 필요할 수 있으며, 이뇨제 복용 중이거나 구토가 반복되는 경우 원인 약물 조정과 전해질 교정이 우선적으로 이루어져야 합니다.', 3019, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '대사성 알칼리증', '대사성알칼리증', 'TREATMENT', '식염수(생리식염수) 정맥 투여는 저염소혈증과 수분 부족을 교정하여 신장의 중탄산염 재흡수를 줄이고 알칼리증을 개선합니다. 염화칼륨 투여는 저칼륨혈증을 교정하고 신장에서의 중탄산염 배출을 촉진하여 알칼리증 회복에 기여합니다. 이 두 가지 치료를 병행하면 대사성 알칼리증의 가장 흔한 원인을 효과적으로 교정할 수 있으며, 투여 용량과 속도는 내과 전문의의 처방에 따라 조절해야 합니다.', 3020, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '독성 쇼크 증후군', '독성쇼크증후군', 'PREVENTION', '독성 쇼크 증후군 예방을 위해 탐폰은 가능한 낮은 흡수력 제품을 선택하고, 4~8시간마다 교체하며, 취침 시에는 사용하지 않는 것이 좋습니다. 상처나 수술 부위가 있는 경우 황색포도상구균 감염 예방을 위해 상처를 청결히 유지하고, 감염 증상(발열, 발진, 저혈압) 발생 시 즉시 의료기관을 방문해야 합니다.', 3021, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '독성 쇼크 증후군', '독성쇼크증후군', 'CAUSE', '독성 쇼크 증후군(TSS)은 황색포도상구균(MRSA 포함) 또는 A군 연쇄상구균이 생산하는 외독소(superantigen)가 면역계를 과활성화하여 발생하는 전신 염증 반응입니다. 두통과 보행 곤란을 유발할 정도의 증상은 TSS의 진행된 상태를 시사할 수 있으며, 발열(38.9℃ 이상), 저혈압, 전신 홍반성 발진이 동반된다면 즉시 응급실을 방문해야 합니다.', 3022, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '독성 쇼크 증후군', '독성쇼크증후군', 'DEFINITION', '독성 쇼크 증후군(TSS)은 황색포도상구균이 생산하는 독소(TSST-1)에 의해 발생하는 전신 면역 과반응으로, 탐폰(특히 고흡수성 제품)이 세균 증식의 환경을 제공하여 독소 생성을 촉진할 수 있습니다. 탐폰 관련 TSS는 생리 중 발생하며 갑작스러운 고열, 저혈압, 전신 홍반 발진, 다발성 장기 부전을 특징으로 하는 응급 질환입니다.', 3023, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '독성 쇼크 증후군', '독성쇼크증후군', 'SYMPTOM', '탐폰 사용 관련 독성 쇼크 증후군의 주요 증상은 갑작스러운 고열(38.9℃ 이상), 수축기 혈압 90mmHg 이하의 저혈압, 일광 화상처럼 보이는 전신 홍반성 발진(손발바닥 포함 후 낙설), 구토·설사, 근육통, 어지럼증, 혼돈 등입니다. 증상 발생 즉시 탐폰을 제거하고 응급실을 방문해야 하며, 치료가 지연되면 다발성 장기 부전으로 진행할 수 있습니다.', 3024, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '독성 쇼크 증후군', '독성쇼크증후군', 'DIAGNOSIS', '탐폰 사용 후 발열과 손 떨림이 나타난다면 독성 쇼크 증후군의 초기 증상일 수 있으므로 즉시 탐폰을 제거하고 의료기관을 방문해야 합니다. TSS 진단은 임상 기준(발열, 저혈압, 발진, 다기관 침범)을 바탕으로 하며, 혈액 배양 검사와 전혈구·전해질 검사를 시행합니다. 증상이 의심된다면 지체 없이 응급실을 방문하시기 바랍니다.', 3025, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '독성 쇼크 증후군', '독성쇼크증후군', 'TREATMENT', '독성 쇼크 증후군 응급 치료는 즉각적인 감염원 제거(탐폰, 이물질, 상처 배농), 적극적인 수액 소생술로 저혈압 교정, 항생제(항포도상구균 항생제+클린다마이신) 투여가 핵심입니다. 중증 쇼크 시 승압제(노르에피네프린), 면역글로불린(IVIG) 투여, 집중치료실 모니터링이 필요하며, 다발성 장기 부전에 따른 투석·기계 환기 등 장기 지원 치료도 시행됩니다.', 3026, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '두통', '두통', 'PREVENTION', '스트레스는 긴장성 두통과 편두통의 주요 유발 요인으로, 두통이 자주 발생하거나 2시간 이상 지속된다면 스트레스 관리가 필요합니다. 규칙적인 수면, 식사, 운동과 함께 이완 요법, 명상, 스트레스 해소 활동이 도움이 됩니다. 두통이 반복적으로 발생하거나 점점 심해진다면 신경과 전문의를 방문하여 정확한 원인 진단을 받으시기 바랍니다.', 3027, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '두통', '두통', 'CAUSE', '수면 후에도 지속되는 두통은 단순 긴장성 두통 외에 뇌압 상승(뇌종양, 경막하혈종), 수면 무호흡증, 고혈압, 뇌수막염 등의 기저 질환을 시사할 수 있습니다. 특히 이른 아침에 심하고 구역·구토를 동반하는 두통은 뇌압 상승의 경고 신호일 수 있습니다. 이러한 두통이 반복된다면 신경과 전문의를 방문하여 뇌 영상 검사를 포함한 정밀 진단을 받으시기 바랍니다.', 3028, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '두통', '두통', 'DEFINITION', '코로나19(COVID-19)는 SARS-CoV-2 바이러스 감염에 의한 급성 호흡기 질환으로, 발열과 두통은 흔한 증상이지만 중증 급성 호흡기 증후군(SARS)과는 다른 질환입니다. 코로나19가 의심된다면 가까운 선별진료소 또는 호흡기 내과를 방문하여 PCR 또는 신속항원 검사를 받으시기 바랍니다. 발열·두통 외에 호흡 곤란이 동반된다면 즉시 의료기관을 방문해야 합니다.', 3029, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '두통', '두통', 'SYMPTOM', '두통이 심해질 때 나타나는 증상으로는 박동성(지끈지끈) 통증 증가, 광과민증(빛에 민감), 소음 과민증, 구역·구토, 시각 장애(전조 증상), 어지럼증, 집중력 저하 등이 있습니다. 편두통에서는 이러한 증상이 뚜렷하게 나타나며, 벼락두통(갑작스럽고 극심한 두통), 의식 저하, 발열, 경직이 동반되면 즉시 응급실을 방문해야 하는 응급 상황입니다.', 3030, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '두통', '두통', 'DIAGNOSIS', '안면홍조, 두통, 어지럼증이 동반되고 골수증식종양이 의심된다면 혈액내과(내과) 전문의를 방문하여 전혈구 검사(CBC), JAK2 V617F 유전자 돌연변이 검사, 골수 검사 등을 받는 것이 정확한 진단 방법입니다. 빠른 진단을 위해서는 혈액내과 외래가 있는 대학병원이나 종합병원을 방문하시는 것이 좋으며, 이상 소견이 있다면 즉시 전문의를 방문하시기 바랍니다.', 3031, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '두통', '두통', 'TREATMENT', '두통의 비약물 치료로는 냉찜질 또는 온찜질, 어두운 조용한 환경에서 휴식, 규칙적인 수면 습관, 스트레스 관리(명상, 이완 요법), 규칙적인 유산소 운동, 침술, 바이오피드백 요법 등이 효과적입니다. 편두통에는 규칙적인 식사와 수분 섭취, 카페인·알코올·특정 식품 회피가 도움이 됩니다. 두통이 반복되거나 지속된다면 신경과 전문의 진료를 권고합니다.', 3032, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '복강 내 출혈', '복강내출혈', 'CAUSE', '복강 내 출혈의 원인으로는 외상(교통사고, 둔기·관통 손상)이 가장 흔하며, 비외상성으로는 복부 대동맥류 파열, 자궁외 임신 파열, 비장·간 종양 자연 파열, 장기 생검 후 합병증, 혈관 기형, 항응고제 사용 중 자연 출혈 등이 있습니다. 원인에 관계없이 급격한 복통과 활력징후 불안정이 나타나면 즉시 응급실을 방문해야 합니다.', 3033, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '복강 내 출혈', '복강내출혈', 'DEFINITION', '외상 없이 발생한 복강 내 출혈은 혈관 기형, 종양 파열, 자궁외 임신 파열, 응고 장애 등의 비외상성 원인을 감별해야 합니다. 치료는 출혈 양상과 혈역학적 안정성에 따라 혈관조영술을 이용한 경피적 색전술(중재적 치료) 또는 응급 수술(개복 또는 복강경)로 출혈 부위를 지혈하며, 동시에 수혈과 수액 소생술로 쇼크를 교정합니다. 즉각적인 외과 및 영상의학과 전문의의 개입이 필요합니다.', 3034, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '복강 내 출혈', '복강내출혈', 'SYMPTOM', '복강 내 출혈 의심 증상인 복부 통증, 체온 하강(저체온), 얕은 호흡, 빈맥(심장이 빠르게 뜀), 저혈압, 식은땀은 출혈성 쇼크의 전형적인 징후로, 복강 내 다량의 혈액이 축적되어 순환 혈액량이 감소한 상태를 나타냅니다. 이러한 증상은 즉각적인 의료 개입이 필요한 응급 상황이므로 지체 없이 119를 호출하고 응급실로 이송해야 합니다.', 3035, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '복강 내 출혈', '복강내출혈', 'DIAGNOSIS', '교통사고 후 복통과 식은땀이 나타난다면 복강 내 출혈이 강하게 의심되므로 즉시 119를 통해 응급실로 이송해야 합니다. 응급실에서는 복부 초음파(FAST 검사)를 신속히 시행하고 활력징후를 모니터링하며, 필요 시 복부 CT로 출혈 부위와 양을 확인합니다. 진단 즉시 외과 전문의에 의한 응급 수술 또는 중재 시술이 시행될 수 있습니다.', 3036, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '복강 내 출혈', '복강내출혈', 'TREATMENT', '복강 내 출혈의 병원 전·이송 중 처치로는 정맥로 확보 후 수액·혈액 투여로 혈압 유지, 산소 공급, 활력징후 지속 모니터링, 쇼크 체위 유지가 이루어집니다. 병원 도착 후에는 혈관조영 색전술(중재적 지혈)이나 응급 개복·복강경 수술로 출혈을 지혈하며, 대량 수혈 프로토콜(적혈구·혈장·혈소판 1:1:1 투여)이 적용됩니다. 신속한 외과적 처치가 생존을 결정하는 핵심입니다.', 3037, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '복부 대동맥류', '복부대동맥류', 'DIET_LIFE', '복부 대동맥류는 대부분 증상이 없으나, 크기가 커지면 복부나 허리에 둔한 통증, 배꼽 주변 박동 느낌이 나타날 수 있습니다. 식습관 측면에서 저지방·저콜레스테롤·저염 식단으로 동맥경화 진행을 늦추고, 금연과 규칙적인 저강도 운동(격렬한 운동은 금지)이 중요합니다. 복부 대동맥류 진단 시 혈관외과 전문의와 상담하여 정기 추적 관찰 계획을 세우시기 바랍니다.', 3038, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '복부 대동맥류', '복부대동맥류', 'PREVENTION', '복부 대동맥류를 방치하면 류가 점차 커져 파열 위험이 높아지며, 파열 시 극심한 복통과 허리 통증, 급격한 혈압 저하, 쇼크가 발생하여 즉각적인 응급 수술 없이는 매우 높은 사망률을 보입니다. 또한 류 내 혈전이 말초 혈관을 막아 하지 허혈 증상이 나타날 수 있습니다. 복부 대동맥류 의심 또는 위험 인자가 있다면 혈관외과 또는 심장혈관외과 전문의의 정기 검진을 받으시기 바랍니다.', 3039, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '복부 대동맥류', '복부대동맥류', 'CAUSE', '복부 대동맥류 발생에는 노화 외에도 흡연(가장 강력한 위험 인자), 고혈압, 동맥경화증, 남성, 가족력, 고지혈증, 만성 폐쇄성 폐질환(COPD) 등이 관련됩니다. 특히 흡연은 대동맥류 발생 위험을 약 8배 높이므로 금연이 매우 중요하며, 고혈압·고지혈증 조절과 정기 복부 초음파 검진이 조기 발견에 필수적입니다.', 3040, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '복부 대동맥류', '복부대동맥류', 'DEFINITION', '복부 대동맥류는 복부 대동맥(신동맥 하방 부위가 가장 흔함)의 벽이 약해져 정상 직경의 1.5배(약 3cm 이상)로 비정상적으로 확장·팽대된 상태입니다. 대동맥 내막과 중막의 구조적 약화로 인해 혈압과 혈류 부하를 견디지 못하고 점진적으로 커지며, 파열 시 복강 내 대량 출혈로 생명을 위협합니다. 혈관외과 전문의에게 진료를 받으시기 바랍니다.', 3041, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '복부 대동맥류', '복부대동맥류', 'SYMPTOM', '혈압 조절이 어려운 복부 대동맥류 환자에게는 복부나 허리의 둔하고 박동성 통증, 배꼽 주위에서 느껴지는 박동, 하지 부종, 다리 통증 또는 허혈 증상(하지 혈전 색전증), 신장 허혈로 인한 신기능 저하 등의 증상이 나타날 수 있습니다. 고혈압이 지속되면 류의 성장 속도가 빨라지고 파열 위험이 높아지므로 혈압 조절이 매우 중요합니다.', 3042, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '복부 대동맥류', '복부대동맥류', 'DIAGNOSIS', '복부 대동맥류 재발 또는 재평가가 필요한 경우 복부 초음파가 1차 선별 검사로 사용되며, 크기와 형태를 정확히 확인하기 위해 복부 CT 혈관조영술(CTA)이 표준 진단 검사입니다. 이전 수술(인조혈관 치환술) 또는 스텐트 삽입 후에도 정기적인 CT 추적 검사가 필요하며, 혈관외과 또는 심장혈관외과 전문의와 함께 검진 일정을 계획하시기 바랍니다.', 3043, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '복부 대동맥류', '복부대동맥류', 'TREATMENT', '복부 대동맥류의 수술 외 치료로는 혈관 내 스텐트 그래프트 삽입술(EVAR, 혈관 내 수술)이 있으며, 개복 수술에 비해 회복이 빠르고 합병증이 적습니다. 크기가 작고(5.5cm 미만) 파열 위험이 낮은 경우에는 금연, 고혈압·고지혈증 약물 치료, 정기 초음파·CT 추적 관찰로 보존적 관리를 합니다. 치료 방법은 크기, 해부학적 특성, 환자 상태에 따라 혈관외과 전문의와 결정하시기 바랍니다.', 3044, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '부정맥', '부정맥', 'MEDICATION', '부정맥 치료 약물의 주요 부작용으로는 항부정맥제(아미오다론 등) 복용 시 갑상선 기능 이상, 폐 독성, 광과민성이 나타날 수 있으며, 베타차단제는 서맥, 저혈압, 피로감을 유발할 수 있습니다. 칼슘 채널 차단제는 부종, 변비, 어지러움이 생길 수 있고, 디곡신은 독성이 나타나면 구역, 시야 이상, 심각한 서맥을 일으킬 수 있습니다. 약물 부작용이 의심되면 즉시 담당 전문의와 상담하여 용량 조절 또는 약제 변경 여부를 결정해야 합니다.', 3045, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '부정맥', '부정맥', 'PREVENTION', '수면 중 심장 두근거림을 예방하기 위해서는 카페인(커피, 에너지 음료, 녹차), 알코올, 고당분 음식, 과도한 자극성 향신료 섭취를 피하는 것이 중요합니다. 취침 전 과식이나 야식도 자율신경계를 자극해 부정맥을 악화시킬 수 있으므로 삼가야 합니다. 증상이 지속된다면 심장내과 전문의의 진료를 받아 원인을 정확히 파악하는 것이 필요합니다.', 3046, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '부정맥', '부정맥', 'CAUSE', '카페인은 심장의 전기 전도계를 자극하여 심박수를 증가시키고 심근의 흥분성을 높여 부정맥을 유발할 수 있습니다. 카페인은 아데노신 수용체를 차단하고 교감신경계를 활성화시켜 심장의 자동능을 증가시키는 작용을 합니다. 일반적으로 부정맥 환자는 하루 카페인 섭취량을 200mg(커피 약 1~2잔) 이하로 제한할 것이 권고되나, 개인차가 크므로 심장내과 전문의와 상담하여 적절한 섭취량을 결정하십시오.', 3047, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '부정맥', '부정맥', 'DEFINITION', '부정맥이란 심장의 정상적인 전기 신호 생성 또는 전도에 이상이 생겨 심박수나 리듬이 불규칙해지는 질환으로, 빈맥(빠른 맥), 서맥(느린 맥), 심방세동 등 다양한 유형이 있습니다. 주요 증상으로는 두근거림, 가슴 불편감, 어지러움, 실신, 호흡 곤란 등이 나타날 수 있습니다. 혈액순환 장애가 의심되면 즉시 심장내과 전문의를 찾아 심전도 검사 등 정밀 검사를 받는 것이 중요합니다.', 3048, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '부정맥', '부정맥', 'SYMPTOM', '부정맥의 증상은 심장 두근거림과 가슴 통증 외에도 어지러움, 실신 또는 전실신(기절할 것 같은 느낌), 호흡 곤란, 피로감, 식은땀, 불안감 등이 나타날 수 있습니다. 심방세동의 경우 불규칙한 맥박이 특징적으로 나타나며, 심실성 부정맥은 혈압 저하로 인한 의식 소실을 일으킬 수 있습니다. 이러한 증상이 반복적으로 나타나면 심장내과 전문의의 진료를 받으시기 바랍니다.', 3049, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '부정맥', '부정맥', 'DIAGNOSIS', '심장 두근거림, 불규칙한 맥박, 가슴 통증, 어지러움, 실신이나 失神 전 느낌, 호흡 곤란 등의 증상이 나타날 때 부정맥 검사를 받아야 합니다. 증상이 발생하는 즉시 또는 반복적으로 나타날 경우 가능한 빨리 심장내과를 방문하여 심전도, 24시간 홀터 모니터링, 운동 부하 검사 등을 받는 것이 권장됩니다. 증상이 갑작스럽고 심한 경우에는 응급실을 바로 방문하십시오.', 3050, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '부정맥', '부정맥', 'TREATMENT', '삽입형 제세동기 외에도 부정맥 치료에는 항부정맥 약물 치료, 전극도자 절제술(카테터 절제술), 심박조율기 삽입술, 전기적 심율동 전환술(cardioversion) 등이 있습니다. 전극도자 절제술은 비정상적인 전기 신호를 발생시키는 심장 조직을 카테터로 선택적으로 소작하는 방법으로 완치 효과를 기대할 수 있습니다. 적절한 치료 방법은 부정맥의 유형과 환자 상태에 따라 다르므로 심장내과 전문의와 충분히 상담하여 결정하십시오.', 3051, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '비브리오 패혈증', '비브리오패혈증', 'DIET_LIFE', '비브리오 패혈증은 세균 감염에 의한 중증 질환으로, 식이요법만으로 치료할 수 없으며 즉각적인 응급 치료가 최우선입니다. 상처 부위가 바닷물에 노출되고 발열, 피부 괴사성 병변 등이 나타나면 즉시 응급실을 방문해야 합니다. 회복 중에는 고단백, 고칼로리 식단으로 면역력을 높이고 충분한 수분 보충이 필요하며, 음식은 완전히 익혀서 섭취해야 합니다.', 3052, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '비브리오 패혈증', '비브리오패혈증', 'MEDICATION', '비브리오 패혈증 치료의 표준은 항생제 병합요법으로, 3세대 세팔로스포린(세프트리악손 등)과 독시사이클린 또는 플루오로퀴놀론계 항생제를 함께 사용합니다. 조기에 적절한 항생제를 투여할수록 예후가 좋으며, 괴사성 근막염으로 진행된 경우 외과적 괴사 조직 제거술이 필요할 수 있습니다. 항생제 종류와 용량은 반드시 감염내과 전문의의 처방에 따라야 하며 자의적으로 복용하거나 중단해서는 안 됩니다.', 3053, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '비브리오 패혈증', '비브리오패혈증', 'PREVENTION', '비브리오 패혈증 예방을 위해 여름철(5~10월)에는 어패류를 반드시 완전히 익혀 섭취하고, 생굴 등 날 해산물 섭취를 자제해야 합니다. 해산물을 다룰 때는 반드시 장갑을 착용하고, 피부에 상처가 있는 경우 바닷물 접촉을 피해야 하며, 간 질환이나 면역 저하 환자는 특히 주의가 필요합니다. 어패류는 85℃ 이상에서 1분 이상 가열하여 조리하고, 교차 오염을 방지하기 위해 조리 도구를 분리 사용하십시오.', 3054, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '비브리오 패혈증', '비브리오패혈증', 'CAUSE', '비브리오 패혈증은 Vibrio vulnificus 세균이 원인으로, 이 균은 15~37℃ 바닷물에서 활발히 증식하며 수온이 높은 여름철에 어패류에 오염됩니다. 오염된 생 어패류(특히 굴, 조개 등)를 섭취하거나 상처 난 피부가 오염된 해수에 노출될 때 감염되며, 사람 간 직접 전파는 거의 없습니다. 간 질환, 당뇨, 면역 저하 환자에서 균이 빠르게 혈류로 침투하여 패혈증을 일으키므로 고위험군은 각별히 주의해야 합니다.', 3055, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '비브리오 패혈증', '비브리오패혈증', 'DEFINITION', '비브리오 패혈증은 Vibrio vulnificus에 의해 발생하는 특수한 패혈증으로, 일반 패혈증과 달리 주로 간 질환자 등 면역 저하 환자에서 치명적으로 나타나며 피부 괴사성 병변이 특징적입니다. 이 질환은 주로 수온이 높은 5~10월에 집중 발생하지만, 겨울에도 면역이 극도로 저하된 환자나 수입 어패류 섭취를 통해 드물게 발생할 수 있습니다. 사망률이 50% 이상으로 매우 높아 증상 발생 즉시 응급 치료가 필요합니다.', 3056, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '비브리오 패혈증', '비브리오패혈증', 'SYMPTOM', '비브리오 패혈증의 초기 급성 증상(발열, 전신 쇠약, 복통, 설사) 외에 피부에 특징적인 출혈성 수포와 괴사성 병변이 동반되는 것이 중요한 특징입니다. 혈압 저하, 쇼크, 다발성 장기 부전으로 빠르게 진행될 수 있으며, 오한, 구역, 구토도 흔히 나타납니다. 특히 면역 저하 환자에서 24~48시간 내에 급격히 악화될 수 있으므로 위 증상이 나타나면 즉시 응급실을 방문해야 합니다.', 3057, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '비브리오 패혈증', '비브리오패혈증', 'DIAGNOSIS', '비브리오 패혈증의 확진에는 혈액, 상처 분비물, 대변 등의 검체에서 Vibrio vulnificus를 배양 및 동정하는 세균 배양 검사가 가장 정확합니다. 혈액 배양 검사는 패혈증 진단에 필수적이며, PCR 검사로 신속하게 균을 확인할 수도 있습니다. 배양 결과를 기다리는 동안에도 임상 증상과 역학적 특성을 근거로 즉시 치료를 시작하는 것이 중요하므로, 의심 증상 발생 시 즉시 병원을 방문하십시오.', 3058, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '비브리오 패혈증', '비브리오패혈증', 'TREATMENT', '비브리오 패혈증은 응급 항생제 치료와 적극적인 의료 처치가 핵심이며, 음식이나 영양제로 치료할 수 있는 질환이 아닙니다. 발열과 오한 중에는 충분한 수분을 보충하고, 소화기 증상이 있을 때는 소화가 잘 되는 부드러운 음식을 소량씩 섭취하는 것이 도움됩니다. 증상 호전 후 회복기에는 면역력 강화를 위해 균형 잡힌 식사와 충분한 휴식이 필요하며, 치료는 반드시 전문의의 지도하에 이루어져야 합니다.', 3059, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '소화관 내 이물', '소화관내이물', 'CAUSE', '음식물 섭취 후 소화관 내 이물이 발생하면 이물의 위치와 크기에 따라 증상이 다르게 나타납니다. 식도에 걸린 경우 삼킴 곤란, 가슴 통증, 침 흘림이 나타나고, 위장관 내에서는 복통, 구역, 구토, 출혈이 생길 수 있습니다. 뾰족하거나 큰 이물은 천공을 유발할 수 있으며, 이 경우 심한 복통과 발열이 동반될 수 있으므로 즉시 응급실을 방문해야 합니다.', 3060, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '소화관 내 이물', '소화관내이물', 'DEFINITION', '소화관 내 이물이란 구강에서 항문까지의 소화관 내에 음식물 외의 물질이 위치하게 된 상태를 말합니다. 이물로 간주되는 것으로는 동전, 단추, 장난감 부품, 바늘, 생선 가시, 닭뼈, 틀니, 전지, 자석, 의약품 포장재 등이 있으며, 특히 소아와 정신과 환자에서 빈번하게 발생합니다. 의도적 또는 비의도적으로 삼킨 모든 비식품 물질이 대상이 되며, 크기와 형태에 따라 위험도가 다릅니다.', 3061, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '소화관 내 이물', '소화관내이물', 'SYMPTOM', '소화관 내 이물이 식도에 걸린 경우 호흡 곤란, 침 삼키기 어려움(연하 곤란), 기침, 구역감이 나타날 수 있습니다. 특히 뾰족한 이물이나 기도를 압박하는 큰 이물은 실제로 호흡 곤란을 유발할 수 있으며, 소아에서는 음식 거부, 과다 침 분비, 천명음이 나타날 수 있습니다. 이러한 증상이 나타나면 즉시 응급실을 방문하여 이물 위치를 확인하고 적절한 처치를 받아야 합니다.', 3062, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '소화관 내 이물', '소화관내이물', 'DIAGNOSIS', '소화관 내 이물 진단에는 흉부 및 복부 X-선 촬영이 1차 검사로 시행되며, 금속이나 방사선 불투과성 이물의 위치와 형태를 확인할 수 있습니다. X-선으로 보이지 않는 이물(생선 가시, 플라스틱 등)은 CT 촬영이나 내시경 검사로 확인합니다. 삼킴 곤란, 이물감, 흉통, 복통 등의 증상이 있으면 소화기내과 또는 응급의학과를 방문하여 정확한 진단과 적절한 처치를 받으십시오.', 3063, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '소화관 내 이물', '소화관내이물', 'TREATMENT', '소화관 내 이물의 주요 치료 방법은 내시경적 제거술로, 식도나 위에 있는 이물의 약 80~90%가 이 방법으로 제거됩니다. 이물이 내시경으로 제거되지 않거나 천공 등 합병증이 발생한 경우 외과적 수술이 필요합니다. 단추전지, 뾰족한 이물, 두 개 이상의 자석은 즉각적인 내시경 제거가 필요한 응급 상황이며, 증상이 없어도 이물을 삼킨 것이 확인되면 반드시 전문의의 진료를 받아야 합니다.', 3064, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '수부 외상', '수부외상', 'CAUSE', '손으로 하는 반복적인 작업이 많은 사람들은 기계나 공구에 의한 절단, 압착, 관통 등의 직접 외상에 노출될 위험이 높습니다. 또한 반복적인 과부하로 인한 건 손상, 스트레스 골절, 관절 손상도 발생할 수 있으며, 고온·화학물질·전기 등에 의한 화상이나 감전도 수부 외상의 원인이 됩니다. 작업 환경에서는 적절한 보호 장갑 착용과 안전 수칙 준수가 수부 외상 예방에 중요합니다.', 3065, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '수부 외상', '수부외상', 'DEFINITION', '수부 외상이란 손(수부)에 발생하는 모든 형태의 외상을 총칭하는 용어로, 골절, 탈구, 건 손상, 신경 손상, 혈관 손상, 연부 조직 손상 등을 포함합니다. 피부 손상 없이 내부 구조만 손상된 폐쇄성 골절과 피부가 열린 개방성 골절 모두 수부 외상에 해당하며, 외력에 의한 모든 손 손상이 포함됩니다. 정확한 진단과 치료를 위해 정형외과 또는 수부외과 전문의의 진료가 필요합니다.', 3066, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '수부 외상', '수부외상', 'SYMPTOM', '수부 외상으로 손 사용이 어려울 때는 주로 사용하는 손의 기능 저하 외에도 손가락 변형, 부종, 멍, 압통, 손가락 움직임 제한이 나타납니다. 신경 손상이 동반된 경우 손이나 손가락의 감각 저하 또는 마비가 나타날 수 있으며, 혈관 손상 시 손이 차가워지거나 창백해질 수 있습니다. 이러한 증상이 동반된다면 즉시 응급 처치 후 정형외과 또는 수부외과 전문의의 진료를 받아야 합니다.', 3067, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '수부 외상', '수부외상', 'DIAGNOSIS', '손에 박힌 작은 이물(금속 파편, 나무 가시 등)은 감염, 신경 손상, 혈관 손상의 위험을 높이므로 수부 외상의 중증도를 높이는 요인이 됩니다. 이물이 깊이 박혀 있거나 신경·혈관 근처에 위치한 경우, 감염 징후(발적, 부종, 고름)가 있는 경우, 감각 이상이나 운동 장애가 동반된 경우에는 응급 처치와 전문의 진료가 반드시 필요합니다. 수부는 기능적으로 매우 중요한 구조이므로 작은 손상이라도 정형외과나 수부외과 전문의의 평가를 받는 것이 권장됩니다.', 3068, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '수부 외상', '수부외상', 'TREATMENT', '수부 외상에서는 정형외과(수부외과) 외에도 손상 유형에 따라 다양한 전문의의 협진이 필요할 수 있습니다. 신경 손상 시 신경외과, 피부 및 연부 조직 결손 시 성형외과, 혈관 손상 시 혈관외과의 도움이 필요하며, 재활 치료를 위해 재활의학과 전문의와 작업치료사의 협력도 중요합니다. 수부 외상의 정확한 진단과 최적의 치료를 위해 수부외과 또는 정형외과를 1차 방문하여 필요시 협진을 의뢰받으십시오.', 3069, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '식중독', '식중독', 'PREVENTION', '여름철 식중독 예방을 위해 손 씻기, 음식 익혀먹기, 음식 끓여먹기 등 식품 위생 3원칙을 철저히 지켜야 합니다. 음식은 2시간 이상 상온에 방치하지 말고, 냉장고 온도는 5℃ 이하, 냉동고는 -18℃ 이하로 유지하며, 날 음식과 조리된 음식을 분리 보관해야 합니다. 조리 기구는 용도별로 구분하여 사용하고, 도마와 칼은 사용 후 즉시 세척·소독하는 습관을 들이는 것이 중요합니다.', 3070, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '식중독', '식중독', 'CAUSE', '음식 섭취 후 수 시간~수일 내에 발생하는 설사와 복통의 가장 흔한 원인은 식중독입니다. 살모넬라, 포도상구균, 장염비브리오, 캄필로박터, 노로바이러스 등 다양한 병원체에 오염된 음식 섭취, 불충분한 가열, 부적절한 보관이 주요 원인입니다. 증상이 심하거나 지속된다면 감염내과 또는 소화기내과 전문의를 방문하여 정확한 원인 파악과 치료를 받으십시오.', 3071, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '식중독', '식중독', 'DEFINITION', '식재료에서 나온 독성 물질에 의한 식중독으로는 복어 독(테트로도톡신), 버섯 독, 감자 싹의 솔라닌, 날 콩의 렉틴 등이 있으며 이들은 신경 마비, 구역, 구토, 설사, 환각, 심한 경우 사망을 유발할 수 있습니다. 세균성 식중독은 오염된 음식 섭취 후 수 시간 내 오심, 구토, 설사, 복통, 발열이 나타납니다. 독소형 식중독은 항생제가 효과 없는 경우가 많으므로 심한 증상 시 즉시 응급실을 방문하여 전문의 진료를 받아야 합니다.', 3072, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '식중독', '식중독', 'SYMPTOM', '음식 섭취 후 나타나는 부기(두드러기, 혈관부종)와 가려움증은 식중독보다는 음식 알레르기 반응에 가깝습니다. 식중독은 주로 오심, 구토, 설사, 복통, 발열이 특징이며, 피부 두드러기와 가려움증이 주증상인 경우 알레르기 반응 가능성이 더 높습니다. 두 가지를 구별하기 위해 증상 발생 시기, 이전 동일 음식 반응 여부, 동반 증상 등을 확인하고 알레르기내과 또는 내과 전문의의 진료를 받으십시오.', 3073, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '식중독', '식중독', 'DIAGNOSIS', '날 생선(회) 섭취 후 복통과 설사가 나타나면 장염비브리오, 노로바이러스, 살모넬라 감염 등의 식중독이 의심됩니다. 진단을 위해 대변 배양 검사, 식중독균 PCR 검사, 혈액 검사(염증 수치 확인)가 시행되며, 중증도에 따라 혈액 배양 검사도 필요할 수 있습니다. 증상이 심하거나 혈변, 고열, 탈수 증상이 동반되면 즉시 감염내과 또는 응급실을 방문하십시오.', 3074, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '식중독', '식중독', 'TREATMENT', '경미한 식중독(가벼운 설사, 구역)의 경우 충분한 수분과 전해질 보충(이온음료, 구강 수액)이 가장 중요한 자가 처치입니다. 설사 중 지사제 사용은 독소 배출을 방해할 수 있으므로 신중해야 하며, 죽이나 토스트 등 소화가 잘 되는 음식으로 위장을 쉬게 해야 합니다. 그러나 고열(38.5℃ 이상), 혈변, 심한 복통, 12시간 이상 지속되는 구토, 의식 변화가 있으면 즉시 병원을 방문해야 합니다.', 3075, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '아나필락시스', '아나필락시스', 'CHECKUP', '벌 쏘임 후 호흡 곤란과 두드러기 등 아나필락시스 증상이 나타나면 응급 검진을 통해 활력 징후(혈압, 맥박, 산소포화도), 혈액 검사(혈청 트립타제, IgE 등), 알레르기 피부 반응 검사 결과를 확인할 수 있습니다. 급성기 검진에서 저혈압, 산소 저하 등이 확인되면 즉각적인 에피네프린 투여 등 응급 처치가 시작됩니다. 회복 후에는 알레르기내과에서 특이 IgE 혈액 검사와 피부 단자 검사를 통해 원인 항원을 확인하고 이후 면역요법 여부를 결정할 수 있습니다.', 3076, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '아나필락시스', '아나필락시스', 'DIET_LIFE', '아나필락시스 위험이 있는 사람은 알레르기 원인 음식(견과류, 갑각류, 계란, 우유 등)과 유발 인자를 철저히 파악하고 이를 완전히 피해야 합니다. 외식 시 재료를 반드시 확인하고, 항상 에피네프린 자가 주사기(에피펜)를 휴대하며 사용법을 숙지해야 합니다. 라벨 없는 식품, 가공식품, 교차 오염 가능 음식에도 주의가 필요하며, 응급 상황 시 대처 방법을 주변 사람들에게도 알려두는 것이 중요합니다.', 3077, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '아나필락시스', '아나필락시스', 'MEDICATION', '특정 약물 자체가 아나필락시스의 직접적인 원인이 될 수 있으며, 페니실린계 항생제, 아스피린, 비스테로이드 항염증제(NSAIDs), 조영제, 마취제 등이 대표적인 원인 약물입니다. 이미 아나필락시스 과거력이 있는 환자에게 원인 약물을 투여하면 치명적인 중증 반응이 재발할 수 있습니다. 약물 복용 전 반드시 과거 약물 알레르기 및 아나필락시스 병력을 의료진에게 알리고, 전문의의 지시에 따라 안전한 대체 약물을 선택해야 합니다.', 3078, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '아나필락시스', '아나필락시스', 'PREVENTION', '아나필락시스 자체에 대한 예방 백신은 존재하지 않으며, 알레르기 면역요법(탈감작 요법)이 일부 원인(벌 독, 꽃가루 등)에 대해 시행됩니다. 면역요법은 알레르기내과 전문의의 처방으로 수개월~수년에 걸쳐 진행되며, 접종 시간대보다는 접종 후 30분 이상 병원 내 대기하여 즉각적인 반응을 확인하는 것이 더 중요합니다. 치료 계획 및 접종 시기는 반드시 알레르기내과 전문의와 상담하여 결정하십시오.', 3079, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '아나필락시스', '아나필락시스', 'CAUSE', '오징어에 의한 아나필락시스는 오징어 단백질(주로 파라발부민 등)에 대한 IgE 매개 과민 반응으로 발생합니다. 오징어 외에도 아나필락시스 원인으로는 땅콩, 견과류, 우유, 계란, 밀, 갑각류(새우, 게), 어류, 벌·말벌 독, 페니실린 등 항생제, 아스피린, 조영제, 라텍스, 운동 등 다양한 항원이 있습니다. 정확한 원인 항원 파악을 위해 알레르기내과에서 특이 IgE 혈액 검사 및 피부 단자 검사를 받아보시기 바랍니다.', 3080, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '아나필락시스', '아나필락시스', 'DEFINITION', '아나필락시스란 특정 항원에 노출된 후 수분~수 시간 내에 발생하는 중증 전신 알레르기 반응으로, 면역계의 과도한 반응에 의해 히스타민 등 화학 매개체가 대량 분비되어 나타납니다. 피부 증상(두드러기, 발진)과 함께 호흡 곤란, 혈압 저하, 의식 소실 등 생명을 위협하는 전신 반응이 특징이며, 운동 유발성 아나필락시스는 운동 중 또는 직후에 발생합니다. 재발 방지를 위해 원인 항원을 파악하고 에피네프린 자가 주사기를 항상 휴대하는 것이 필수적입니다.', 3081, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '아나필락시스', '아나필락시스', 'SYMPTOM', '아나필락시스의 경증 증상으로는 피부 두드러기, 발진, 가려움, 홍조, 혈관부종이 있으며, 중등도에서는 복통, 구역, 구토, 콧물, 재채기, 가슴 답답함이 나타납니다. 중증 반응에서는 기도 부종으로 인한 호흡 곤란과 천명음, 심한 저혈압에 의한 쇼크, 의식 소실, 심정지까지 진행될 수 있습니다. 경증 증상이라도 빠르게 중증으로 악화될 수 있으므로 즉시 에피네프린을 투여하고 119를 호출하여 응급 치료를 받아야 합니다.', 3082, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '아나필락시스', '아나필락시스', 'DIAGNOSIS', '아나필락시스의 초기 증상은 항원 노출 수분~30분 후 피부 가려움, 두드러기, 얼굴 부종, 코막힘, 복통, 구역으로 시작하여 급격히 호흡 곤란, 혈압 저하로 진행됩니다. 응급 상황 관리로는 즉각적인 에피네프린 근육 주사(대퇴부 외측)가 1차 치료이며, 119 호출 후 환자를 눕히고(쇼크 시 다리를 올림) 기도를 유지해야 합니다. 병원 도착 후에는 산소 투여, 항히스타민제, 스테로이드, 수액 치료가 추가로 시행되며, 전문의의 모니터링이 필요합니다.', 3083, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '아나필락시스', '아나필락시스', 'TREATMENT', '벌 쏘임으로 인한 아나필락시스 증상에는 즉각적인 에피네프린 근육 주사(허벅지 외측)가 1차 치료이며, 에피펜이 있다면 즉시 자가 투여 후 119를 호출해야 합니다. 병원에서는 에피네프린 추가 투여, 항히스타민제(디펜히드라민), 스테로이드(히드로코르티손), 기관지 확장제 흡입, 정맥 수액 치료 등이 이루어집니다. 증상이 완화된 후에도 수 시간 내 이상성 반응이 재발할 수 있으므로 최소 4~8시간 병원에서 관찰해야 합니다.', 3084, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '악성 고열증', '악성고열증', 'MEDICATION', '악성 고열증 치료의 핵심 약물은 단트롤렌(dantrolene)으로, 근육 세포의 칼슘 방출을 억제하여 과도한 근육 수축과 열 생성을 차단합니다. 단트롤렌 투여와 함께 냉각 요법(얼음 팩, 냉각 포 적용), 중탄산나트륨(산증 교정), 포도당과 인슐린(고칼륨혈증 치료), 이뇨제(신장 보호), 항부정맥제 등이 동반 증상에 따라 사용됩니다. 이 약물들의 구체적인 사용은 집중 치료실에서 전문 마취통증의학과 및 중환자의학과 전문의에 의해 이루어집니다.', 3085, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '악성 고열증', '악성고열증', 'PREVENTION', '악성 고열증 예방에 있어 본인 또는 가족이 이전 마취 중 이상 반응(고열, 근육 강직)을 경험한 사실을 미리 아는 것은 매우 중요한 예방 조치입니다. 악성 고열증은 유전성 소인(RYR1, CACNA1S 유전자 변이)이 있는 환자에서 트리거 마취제(할로탄, 석시닐콜린 등) 노출 시 발생하므로, 사전에 의료진에게 고지하면 유발 마취제를 피하고 비유발 마취법을 선택할 수 있습니다. 의심되는 경우 유전자 검사 또는 카페인-할로탄 수축 검사를 통해 감수성을 확인하고 마취통증의학과 전문의와 충분히 상의해야 합니다.', 3086, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '악성 고열증', '악성고열증', 'CAUSE', '악성 고열증의 주요 원인은 RYR1(라이아노딘 수용체 1형) 유전자 변이에 의한 유전적 감수성이지만, 유전자 변이 외에도 근육 질환(중심 핵 병, 선천성 근육병증)이 위험 인자가 됩니다. 환경적 요인으로는 트리거 마취제(흡입 마취제, 석시닐콜린)가 직접적인 유발 인자이며, 극도의 더위나 격렬한 운동도 드물게 비마취성 악성 고열 유사 증후군을 유발할 수 있습니다. 스트레스, 감염, 특정 약물도 일부 취약 환자에서 증상을 악화시킬 수 있어 수술 전 전문의 평가가 중요합니다.', 3087, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '악성 고열증', '악성고열증', 'DEFINITION', '악성 고열증이란 특정 흡입 마취제(할로탄, 이소플루란 등)나 탈분극성 근이완제(석시닐콜린)에 유전적 감수성이 있는 환자에서 골격근 세포 내 칼슘 조절 이상으로 발생하는 드물지만 치명적인 과대사성 증후군입니다. 체온 상승(41℃ 이상), 근육 강직, 빈맥, 과호흡, 대사성 산증이 특징이며, 진단은 임상 증상, 동맥혈 가스 분석, 근효소 수치, 체온 측정을 종합하여 이루어집니다. 의심 시 즉시 트리거 마취제를 중단하고 단트롤렌을 투여해야 하므로 수술 중 마취통증의학과 전문의의 신속한 대응이 중요합니다.', 3088, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '악성 고열증', '악성고열증', 'SYMPTOM', '마취 및 근이완제 사용 중 발생하는 악성 고열증의 대표적 증상은 급격한 체온 상승(41℃ 이상), 전신 근육 강직(특히 턱 근육 강직이 초기 징후), 빈맥, 혈압 불안정, 빠른 호흡(과호흡)입니다. 피부 청색증, 과도한 발한, 소변색 어두워짐(근육 손상으로 인한 미오글로빈뇨)도 나타날 수 있으며, 혈액 검사에서 이산화탄소 급증, 산증, 전해질 이상(고칼륨혈증), 근효소(CK) 상승이 확인됩니다. 이 증상들이 수술 중 나타나면 즉각적인 응급 처치가 필요합니다.', 3089, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '악성 고열증', '악성고열증', 'DIAGNOSIS', '악성 고열증 진단 시 동맥혈 가스 분석에서 대사성·호흡성 산증과 고이산화탄소혈증이 확인되고, 혈청 CK(크레아틴 키나제)가 수만 단위 이상으로 급격히 상승합니다. 고칼륨혈증, 고칼슘혈증, 젖산 상승, 미오글로빈뇨도 동반되며, 이 결과들을 토대로 즉시 트리거 마취제 중단, 순수 산소 투여, 단트롤렌 정맥 투여, 냉각 요법, 전해질 교정이 시작됩니다. 이후 중환자실 입원하여 장기 기능 모니터링과 합병증(신부전, 파종성혈관내응고) 예방 치료가 이루어집니다.', 3090, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '악성 고열증', '악성고열증', 'TREATMENT', '악성 고열증 치료에 사용되는 단트롤렌의 부작용으로는 근력 저하, 오심, 구토, 졸음, 간독성(장기 복용 시) 등이 있습니다. 치료 과정에서의 냉각 요법 과정 중 저체온증이 발생할 수 있으며, 중탄산나트륨 투여 시 전해질 불균형, 인슐린 투여 시 저혈당도 주의해야 합니다. 악성 고열증 자체의 합병증으로 급성 신부전, 파종성혈관내응고(DIC), 뇌손상, 심부전이 발생할 수 있으므로 치료 중 집중 모니터링이 필수적입니다.', 3091, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '압궤 손상', '압궤손상', 'CAUSE', '팔을 베개처럼 사용해 아이가 장시간 같은 자세로 팔 위에 누워있으면 신경과 혈관이 지속적으로 압박되어 압궤 손상의 경미한 형태가 발생할 수 있습니다. 특히 장시간 수면 중 지속적인 압박은 신경 압박(Saturday night palsy 등), 혈류 차단을 유발할 수 있습니다. 아이에게 팔을 베게 하는 습관보다는 적절한 베개를 사용하게 하는 것이 바람직하며, 저림이나 감각 이상 증상이 지속된다면 소아과 또는 신경과 전문의의 진료를 받으십시오.', 3092, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '압궤 손상', '압궤손상', 'DEFINITION', '압궤 손상이란 신체의 일부가 두 물체 사이에 강한 압력으로 눌리거나 짓눌려 발생하는 외상으로, 피부, 근육, 신경, 혈관, 뼈, 내부 장기 등 다양한 구조에 손상이 초래됩니다. 주요 발생 원인으로는 교통사고, 건설 현장 사고, 중장비에 끼임, 건물 붕괴, 광산 사고, 지진 등 대형 재난이 있으며, 산업 현장에서 가장 빈번하게 발생합니다. 손상 정도는 압력의 크기, 지속 시간, 압박 부위에 따라 크게 달라집니다.', 3093, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '압궤 손상', '압궤손상', 'SYMPTOM', '압궤 손상은 압박 부위에 따라 다른 증상이 나타납니다. 사지 압궤 시 부종, 멍, 통증, 피부 괴사, 근육 손상으로 인한 운동 및 감각 장애가 나타나고, 흉부 압궤 시 늑골 골절, 기흉, 폐 타박, 호흡 곤란이 발생합니다. 복부 압궤 시 내부 장기 파열과 복강 내 출혈이 생길 수 있으며, 광범위한 근육 손상은 횡문근 융해증을 유발하여 급성 신부전으로 이어질 수 있어 즉각적인 의료 처치가 필요합니다.', 3094, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '압궤 손상', '압궤손상', 'DIAGNOSIS', '압궤 손상 진단에는 X-선 촬영(골절, 이물 확인), CT 촬영(내부 장기, 혈관, 신경 손상 범위 파악), MRI(연부 조직 및 신경 손상 정밀 평가), 초음파(혈관 상태, 혈종 확인) 등이 사용됩니다. 혈액 검사로 CK 수치 상승(근육 손상 지표), 신장 기능 수치(BUN, creatinine), 전해질 이상, 혈색소 등을 확인하여 전신 상태를 평가합니다. 혈관 손상이 의심될 경우 혈관 조영술도 시행될 수 있으며, 다학제 협진을 통한 종합적 평가가 중요합니다.', 3095, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '압궤 손상', '압궤손상', 'TREATMENT', '압궤 손상 치료 후 발생 가능한 부작용으로는 치료 중 대량 수액 투여로 인한 부종 악화, 감압술 후 감염, 괴사 조직 제거 후 피부 결손, 수혈 관련 합병증이 있습니다. 장기적으로는 근육 손상 후 구획 증후군, 신경 손상에 따른 감각·운동 장애, 혈관 손상 후 사지 허혈 및 절단, 횡문근 융해증으로 인한 급성 신부전이 발생할 수 있습니다. 심한 손상의 경우 만성 통증, 관절 경직, 기능 장애가 후유증으로 남을 수 있어 재활치료가 필요합니다.', 3096, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '약물 알레르기', '약물알레르기', 'CAUSE', '약물 알레르기의 발생 위험도는 유전적 소인(HLA 유전자형 등), 이전 알레르기 반응 병력, 아토피 체질, 면역 상태에 따라 개인차가 큽니다. 특히 HLA-B*57:01 유전자형을 가진 사람은 아바카비르에, HLA-B*15:02 유전자형은 카르바마제핀에 심각한 과민반응을 일으킬 위험이 높습니다. 이처럼 유전적 감수성이 높은 사람은 특정 약물에 더 심한 알레르기 반응을 일으킬 가능성이 높으므로 약물 투여 전 알레르기 과거력을 반드시 의료진에게 알려야 합니다.', 3097, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '약물 알레르기', '약물알레르기', 'DEFINITION', '약물 알레르기란 약물에 대한 면역계의 과민 반응으로, IgE 매개 반응부터 T세포 매개 반응까지 다양한 면역 기전에 의해 발생합니다. 가장 흔한 원인 약물은 페니실린계 항생제, 세팔로스포린, 아스피린, NSAIDs, 설파제, 조영제 등이며, 증상으로는 두드러기, 발진, 가려움, 혈관부종, 호흡 곤란, 저혈압, 아나필락시스까지 경증부터 생명 위협적 반응까지 다양합니다. 약물 알레르기가 의심되면 해당 약물 투여를 즉시 중단하고 알레르기내과 전문의의 진료를 받아야 합니다.', 3098, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '약물 알레르기', '약물알레르기', 'SYMPTOM', '약물 알레르기 증상은 환자의 면역 상태, 약물 종류와 용량, 투여 경로, 기저 질환에 따라 크게 달라집니다. 아토피 환자나 이전 알레르기 반응이 있는 환자에서 더 심한 반응이 나타날 수 있고, 면역 억제 상태에서는 증상이 비전형적으로 나타날 수 있습니다. 신부전이나 간부전이 있는 환자는 약물 대사가 저하되어 독성 반응이 증가할 수 있으며, 증상이 의심되면 즉시 약물 투여를 중단하고 알레르기내과 전문의와 상담하십시오.', 3099, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '약물 알레르기', '약물알레르기', 'DIAGNOSIS', '약물 알레르기 진단은 먼저 상세한 병력 청취(약물명, 증상 발생 시기, 이전 반응 여부)로 시작하며, 피부 단자 검사와 피내 검사로 IgE 매개 반응 여부를 확인합니다. 혈청 특이 IgE 검사, 약물 유발 림프구 전환 검사(LTT), 혈청 트립타제 측정도 진단에 활용됩니다. 확진을 위해 안전이 보장된 환경에서 단계적 약물 유발 검사를 시행하기도 하며, 모든 검사와 해석은 반드시 알레르기내과 전문의의 지도하에 이루어져야 합니다.', 3100, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '약물 알레르기', '약물알레르기', 'TREATMENT', '약물 알레르기 치료에서 경증 반응(두드러기, 가려움)에는 항히스타민제(세티리진, 펙소페나딘 등)와 스테로이드가 사용되어 히스타민 수용체를 차단하고 염증 반응을 억제합니다. 중증 반응 또는 아나필락시스에서는 에피네프린이 1차 치료제로, 기관지 확장과 혈압 상승 효과로 급성 반응을 역전시킵니다. 이후 스테로이드(프레드니솔론)와 항히스타민제가 이중 반응 예방을 위해 추가되며, 치료 방법과 약물 선택은 반드시 전문의의 처방에 따라야 합니다.', 3101, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '열 피로', '열피로', 'CAUSE', '열 피로에서 염분(나트륨) 부족은 과도한 발한으로 전해질이 소실될 때 발생하며, 이로 인해 근육 경련, 오심, 두통, 어지러움, 쇠약감이 나타납니다. 수분만 과도하게 섭취하고 전해질을 보충하지 않으면 저나트륨혈증으로 악화될 수 있습니다. 이 외에도 열 피로 시에는 과도한 발한, 차갑고 창백한 피부, 빠른 맥박, 혈압 저하, 심한 피로감도 동반될 수 있으므로 시원한 장소로 이동하고 전해질 음료를 섭취하는 것이 중요합니다.', 3102, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '열 피로', '열피로', 'DEFINITION', '열 피로는 더운 환경에서 체액과 전해질이 과도하게 소실되어 발생하는 열 관련 질환으로, 체온 조절 기능은 아직 유지되어 있어 일반적으로 시원한 곳에서 충분히 쉬고 수분을 보충하면 증상이 호전됩니다. 그러나 완전한 회복에는 수 시간~1일이 소요될 수 있고, 적절한 처치 없이 방치하면 더 심각한 열사병으로 진행될 위험이 있습니다. 증상이 1시간 이상 개선되지 않거나 체온 상승, 의식 변화가 동반되면 즉시 의료기관을 방문하십시오.', 3103, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '열 피로', '열피로', 'SYMPTOM', '열 피로로 인한 탈수 증상 외에도 창백하고 차갑고 축축한 피부, 빠르고 약한 맥박, 저혈압, 심한 피로와 쇠약감이 나타납니다. 오심, 구토, 두통, 근육 경련(특히 다리), 어지러움, 실신감도 흔히 동반되며, 소변량이 감소하고 소변색이 진해질 수 있습니다. 일반 열사병과 달리 피부는 차갑고 체온은 40℃ 이하인 경우가 많으나 증상이 심하거나 지속되면 즉시 의료 기관을 방문해야 합니다.', 3104, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '열 피로', '열피로', 'TREATMENT', '열 피로로 인한 의식 저하 시 병원 도착 전 응급 처치로 우선 환자를 시원한 그늘진 곳으로 이동하고 옷을 느슨하게 풀어줍니다. 차가운 물수건으로 목, 겨드랑이, 사타구니를 식히고, 의식이 있으면 이온음료나 소금물을 천천히 마시게 합니다. 의식이 저하된 경우 음식이나 음료를 억지로 먹이지 말고 즉시 119에 연락하여 응급 이송을 요청해야 하며, 병원에서는 정맥 수액 보충과 전해질 교정이 이루어집니다.', 3105, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '열사병', '열사병', 'MEDICATION', '열사병으로 인한 어지러움과 메스꺼움, 구토는 열사병 자체를 응급 처치하는 것이 최우선이며, 약물 단독으로 치료할 수 없습니다. 병원 응급 치료 중에는 신속한 체온 냉각과 함께 오심·구토에 대해 항구토제(온단세트론 등)가 보조적으로 사용될 수 있고, 어지러움은 수액 보충과 체온 정상화로 대부분 호전됩니다. 열사병은 즉각적인 응급 처치가 필요한 응급 상황이므로 증상 발생 즉시 119에 연락하여 응급실로 이송해야 합니다.', 3106, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '열사병', '열사병', 'PREVENTION', '열사병 예방을 위해 기온이 높은 낮 시간대(오전 10시~오후 4시) 야외 활동을 삼가고, 야외 작업 시 자주 휴식을 취하며 서늘한 환경에서 쉬어야 합니다. 헐렁하고 밝은 색상의 옷을 착용하고, 시원한 물이나 전해질 음료를 규칙적으로 섭취하며(갈증을 느끼기 전에 마실 것), 자동차 내 어린이나 노인을 방치하지 않아야 합니다. 노인, 영유아, 만성 질환자, 이뇨제 복용자는 열사병 고위험군으로 더욱 철저한 예방이 필요합니다.', 3107, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '열사병', '열사병', 'CAUSE', '더운 환경에서 오래 있으면 체온 조절 기능이 한계에 달해 체온이 급격히 상승하여 열사병이 발생할 수 있습니다. 40℃ 이상의 고체온, 중추신경계 기능 장애(의식 혼탁, 섬망, 경련, 혼수), 무한증(피부가 뜨겁고 건조)이 특징이며, 다발성 장기 부전으로 진행될 수 있는 생명을 위협하는 응급 상황입니다. 즉각적인 냉각 처치와 응급실 이송 없이는 사망에 이를 수 있으므로 증상 발생 즉시 119에 연락해야 합니다.', 3108, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '열사병', '열사병', 'DEFINITION', '열사병은 체온 조절 기능이 완전히 실패하여 중추신경계 손상을 동반하는 중증 고체온증으로, 40℃ 이상의 고열, 의식 장애(혼수, 섬망), 뜨겁고 건조한 피부가 특징입니다. 일사병(열 탈진)은 과도한 발한으로 체액과 전해질이 소실되어 발생하지만 체온 조절 기능과 의식은 유지되며, 차갑고 축축한 피부, 어지러움, 오심이 특징입니다. 핵심 차이는 의식 상태와 피부 상태로, 열사병은 즉각적인 응급 처치가 필요한 생명 위협적 상황입니다.', 3109, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '열사병', '열사병', 'SYMPTOM', '더운 환경에 오래 있을 때 어지러움과 오심이 나타나면 열 피로(일사병)의 가능성이 높지만, 의식 변화나 40℃ 이상의 고열이 동반된다면 열사병을 의심해야 합니다. 갑자기 추워지는 경우의 어지러움과 오심은 저체온증이나 혈압 변화와 관련이 있을 수 있어 열사병과는 구분이 필요합니다. 어느 경우든 증상이 지속되거나 악화되면 즉시 시원한 곳으로 이동하고 의료 기관의 진료를 받아야 합니다.', 3110, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '열사병', '열사병', 'DIAGNOSIS', '열사병 진단에서 직장·식도 체온 측정 외에도 고막 체온계, 방광 내 체온 측정도 사용될 수 있으나 정확도는 직장 체온이 가장 높습니다. 임상 진단과 함께 혈액 검사(혈구 검사, 전해질, 신장 기능, 간 기능, 응고 검사), 동맥혈 가스 분석, 심전도 검사, 소변 검사가 시행되어 장기 손상 여부를 평가합니다. 의식 저하가 동반된 경우 뇌 CT나 MRI를 통해 다른 원인(뇌졸중 등)을 배제하는 것도 중요합니다.', 3111, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '열사병', '열사병', 'TREATMENT', '열사병으로 병원 이송 중 가장 중요한 응급 조치는 즉각적인 체온 냉각으로, 시원하거나 에어컨이 있는 장소로 이동하고 차가운 물수건으로 전신, 특히 목·겨드랑이·사타구니를 냉각시켜야 합니다. 의식이 없는 경우 안전한 회복 자세를 취하게 하고, 음식이나 음료를 억지로 먹이지 말며, 기도를 유지하고 호흡과 맥박을 지속적으로 확인합니다. 열사병은 분 단위로 악화될 수 있는 응급 상황이므로 119 호출 후 최대한 빠른 이송이 생명 구조에 핵심입니다.', 3112, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '외상성 뇌 손상', '외상성뇌손상', 'CAUSE', '외상성 뇌 손상을 일으키는 강한 충격의 원인으로는 교통사고, 낙상, 스포츠 부상, 폭행, 폭발 사고 등이 있습니다. 이로 인해 두통, 의식 소실, 기억 상실, 혼란, 구역·구토, 어지러움, 감각 이상, 경련이 나타날 수 있으며, 중증 손상에서는 장기 혼수나 식물인간 상태로 이어질 수 있습니다. 충격 후 이러한 증상이 나타나면 즉시 응급실을 방문하여 신경외과 전문의의 평가를 받아야 합니다.', 3113, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '외상성 뇌 손상', '외상성뇌손상', 'REHAB', '외상성 뇌 손상 재활 프로그램은 인지 재활(기억력, 집중력, 문제 해결 능력 향상), 언어 치료, 운동 재활(근력, 균형, 협응 능력 회복), 작업 치료(일상생활 기능 회복)를 종합적으로 포함합니다. 이러한 재활 프로그램은 뇌 가소성을 활용하여 손상된 기능의 회복과 잔존 기능의 최대화를 도모하며, 조기 시작 시 더 좋은 결과를 얻을 수 있습니다. 환자 개인의 손상 부위, 중증도, 연령에 맞는 맞춤형 재활 계획이 필요하므로 재활의학과 전문의와 다학제 팀의 협력이 중요합니다.', 3114, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '외상성 뇌 손상', '외상성뇌손상', 'DEFINITION', '외부 물리적 힘에 의해 뇌 조직에 손상이 발생하는 질환은 외상성 뇌 손상(Traumatic Brain Injury, TBI)입니다. 충격, 관통, 가속-감속 등의 외력이 두개골과 뇌에 직접 또는 간접적으로 작용하여 뇌 조직의 타박, 열상, 혈종, 미만성 축삭 손상 등을 초래합니다. 경증(뇌진탕)부터 중증(뇌좌상, 뇌출혈)까지 다양하며, 두부 외상 후 증상이 나타나면 즉시 신경외과 전문의의 진료를 받아야 합니다.', 3115, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '외상성 뇌 손상', '외상성뇌손상', 'SYMPTOM', '차 사고 후 구토가 나타나는 것은 외상성 뇌 손상(특히 뇌진탕 또는 뇌좌상)의 초기 증상일 수 있습니다. 사고 후 두통, 구역·구토, 어지러움, 일시적 의식 소실, 기억 혼란 등이 나타나면 뇌 손상을 강력히 의심해야 합니다. 증상의 경중에 관계없이 사고 후에는 반드시 응급실을 방문하여 CT 촬영 등 정밀 검사를 받아야 하며, 증상이 수 시간 내 악화되면 즉시 신경외과 전문의의 진료가 필요합니다.', 3116, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '외상성 뇌 손상', '외상성뇌손상', 'DIAGNOSIS', '뇌 구조적 이상 없이 기능적 부전이 의심되는 외상성 뇌 손상(뇌진탕 등) 진단에는 신경외과 또는 신경과 전문의의 평가가 우선적으로 필요합니다. 증상에 따라 스포츠의학과, 재활의학과 전문의도 진단과 관리에 참여할 수 있으며, 신경심리검사를 통한 인지 기능 평가도 중요합니다. 두부 외상 후 증상이 지속되면 증상을 자세히 기록하여 전문의 진료 시 전달하고, 임의로 활동을 재개하지 않도록 해야 합니다.', 3117, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '외상성 뇌 손상', '외상성뇌손상', 'TREATMENT', '외상성 뇌 손상 치료는 손상 정도에 따라 결정됩니다. 경증(뇌진탕)은 안정과 증상 완화 치료가 주를 이루며, 뇌부종이나 두개내압 상승이 있을 때는 삼투압 이뇨제(만니톨)와 두개내압 감시를 시행합니다. 경막외·경막하 혈종, 함몰 두개골 골절, 뇌좌상으로 인한 출혈이 있는 경우 즉각적인 개두술 또는 혈종 제거 수술이 필요하며, 뇌 손상 속도가 빠른 경우(acute) 더욱 응급 수술이 필요합니다. 치료 방침은 신경외과 전문의가 결정합니다.', 3118, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '외상성 척수 손상', '외상성척수손상', 'CAUSE', '외상성 척수 손상의 원인으로 교통사고 외에도 낙상(특히 노인), 스포츠 사고(다이빙, 격투기, 스키 등), 산업 재해, 폭행, 총상·자상 등 관통 외상, 건물 붕괴나 낙석 등 압착 손상이 있습니다. 스포츠 중 과도한 굴곡·신전·회전에 의한 척추 손상도 중요한 원인이며, 이미 척추 협착이나 척추증이 있는 환자는 경미한 외상에도 척수 손상이 발생할 수 있습니다. 척수 손상 의심 시 즉각적인 고정과 응급 이송이 추가 손상을 예방하는 데 중요합니다.', 3119, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '외상성 척수 손상', '외상성척수손상', 'DEFINITION', '외상성 척수 손상이란 외부로부터의 물리적 충격으로 척수가 손상되어 손상 부위 이하의 운동, 감각, 자율신경 기능에 장애가 발생하는 상태를 말합니다. 손상 부위(경추, 흉추, 요추)와 손상 정도(완전 손상: 모든 기능 소실, 불완전 손상: 일부 기능 보존)에 따라 증상의 범위와 중증도가 결정됩니다. 조기 진단과 적절한 치료, 재활이 기능 회복 가능성을 높이므로 가능한 한 빨리 신경외과 또는 척추외과 전문의의 진료를 받는 것이 중요합니다.', 3120, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '외상성 척수 손상', '외상성척수손상', 'SYMPTOM', '외상성 척수 손상의 증상은 손상 부위와 정도에 따라 달라집니다. 경추 손상 시 사지 마비(사지마비), 호흡 근육 마비로 인공호흡기가 필요할 수 있으며, 흉추 손상은 하지 마비(하반신 마비)와 흉부 이하 감각 소실을 유발합니다. 불완전 손상은 근력 저하, 감각 저하, 방광·장 기능 이상이 부분적으로 나타나며, 완전 손상은 손상 부위 이하의 모든 운동·감각 기능이 완전 소실됩니다. 초기에는 척수 쇼크로 모든 반사가 소실될 수 있습니다.', 3121, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '외상성 척수 손상', '외상성척수손상', 'DIAGNOSIS', '외상성 척수 손상 응급 상황에서는 손상 부위 이하의 갑작스러운 운동 마비, 감각 소실, 심한 경부 또는 등 통증이 나타납니다. 경추 손상 시 호흡 마비로 인한 호흡 부전, 서맥과 저혈압(신경원성 쇼크), 체온 조절 이상이 동반될 수 있습니다. 이러한 응급 증상이 나타나면 즉시 119를 호출하고 목과 척추를 움직이지 않도록 고정한 상태에서 이송해야 하며, 즉각적인 신경외과 전문의의 처치가 필요합니다.', 3122, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '외상성 척수 손상', '외상성척수손상', 'TREATMENT', '외상성 척수 손상의 치료는 급성기에 척추 안정화와 추가 손상 예방이 최우선으로, 경추 보조기나 경추 고정대를 이용한 고정이 시행됩니다. 수술적 치료로 뼈 파편이나 혈종에 의한 압박을 제거하는 감압술과 척추 불안정성 교정을 위한 내고정술이 필요할 수 있으며, 고용량 스테로이드(메틸프레드니솔론) 투여가 일부 환자에서 고려됩니다. 급성기 치료 후에는 재활의학과 주도의 물리치료, 작업치료, 방광·장 관리 등 포괄적 재활이 장기 기능 회복에 필수적입니다.', 3123, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '일산화탄소 중독', '일산화탄소중독', 'PREVENTION', '연탄이나 숯 등 불완전 연소가 일어나는 난방 방식은 밀폐된 공간에서 일산화탄소를 다량 발생시켜 중독의 위험이 매우 높습니다. 예방을 위해 환기가 충분히 되는 환경에서만 사용하고, 취침 시에는 사용을 중단해야 하며, 일산화탄소 감지기를 설치하는 것이 중요합니다. 증상 발생 시 즉시 창문을 열고 신선한 공기를 마시며 119에 신고하고 응급실을 방문해야 합니다.', 3124, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '일산화탄소 중독', '일산화탄소중독', 'CAUSE', '일산화탄소 중독의 주요 위험 요소로는 밀폐 공간에서의 가스레인지, 연탄·숯 난방기, 보일러, 차량 엔진, 발전기, 휴대용 가스버너, 캠핑용 화로 사용이 있습니다. 노후된 가스 배관, 불량한 환기 시스템, 터널이나 지하 공간, 화재 현장도 위험 환경입니다. 특히 가스 보일러 사용 중 배기구 막힘, 차량 내 히터 장시간 가동(창문 닫힌 상태), 텐트 내 숯 사용은 치명적인 중독을 유발할 수 있으므로 반드시 주의해야 합니다.', 3125, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '일산화탄소 중독', '일산화탄소중독', 'DEFINITION', '일산화탄소 중독은 일산화탄소(CO)가 헤모글로빈과 결합하여 산소 운반을 방해함으로써 조직 저산소증을 일으키는 질환입니다. 가벼운 중독에서는 두통, 어지러움, 오심, 피로감이 나타나고, 중증에서는 의식 저하, 경련, 심근 손상, 심부전, 뇌 손상으로 진행되며 사망할 수 있습니다. 산소 친화도가 헤모글로빈보다 200배 이상 높아 소량 노출에도 신체에 심각한 영향을 미치므로 즉각적인 신선 공기 노출과 응급 의료 처치가 필수입니다.', 3126, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '일산화탄소 중독', '일산화탄소중독', 'SYMPTOM', '일산화탄소 중독은 연소 과정에서 발생하는 무색무취의 일산화탄소를 흡입하여 산소 결핍이 초래되는 상태로, 증상이 없거나 경미해도 중독이 이미 진행 중일 수 있습니다. 연기를 마신 후 두통, 구토, 어지러움, 의식 저하가 나타나면 일산화탄소 중독을 의심해야 하며, 여러 사람이 동시에 비슷한 증상을 보일 때 특히 의심됩니다. 의심 상황 발생 시 즉시 외부로 대피하고 119에 신고한 후 응급실에서 혈중 카복시헤모글로빈 수치 검사와 산소 치료를 받아야 합니다.', 3127, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '일산화탄소 중독', '일산화탄소중독', 'DIAGNOSIS', '일산화탄소는 저농도 노출 시 증상이 없거나 가벼운 두통만 있어 자각하기 어려우므로, 노출이 확인된 경우 증상이 없어도 병원 진단이 필요합니다. 혈중 카복시헤모글로빈(COHb) 수치 측정으로 실제 노출 정도를 확인할 수 있으며, 심전도, 심장 효소 검사, 뇌 CT 등으로 장기 손상을 평가해야 합니다. 지연성 신경학적 후유증(기억력 저하, 집중력 장애)은 초기 증상이 경미했어도 발생할 수 있으므로 조기 진단과 적극적 치료가 중요합니다.', 3128, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '일산화탄소 중독', '일산화탄소중독', 'TREATMENT', '일산화탄소 중독으로 의식이 없는 환자를 이송하는 동안 즉시 환자를 신선한 공기가 있는 장소로 이동시키고 기도를 확보해야 합니다. 호흡이 있으면 회복 자세를 취하게 하고, 호흡·맥박이 없으면 즉시 심폐소생술(CPR)을 시행합니다. 가능하다면 고농도 산소 마스크로 100% 산소를 공급하고, 응급실 도착 후에는 고압 산소 치료(HBO)가 중증 일산화탄소 중독의 표준 치료로 시행됩니다.', 3129, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저나트륨혈증', '저나트륨혈증', 'CAUSE', '과도한 수분 섭취는 혈중 나트륨이 희석되어 저나트륨혈증을 유발하거나 악화시킬 수 있습니다. 특히 단시간 내 대량의 물을 마시는 경우, 신장의 수분 배출 능력을 초과하면 혈중 나트륨 농도가 급격히 저하되는 희석성 저나트륨혈증이 발생할 수 있습니다. 컨디션이 저조하면 수분과 전해질 균형이 이미 불안정할 수 있으므로, 물 대신 전해질이 포함된 음료를 적절히 섭취하고 지속적인 증상이 있으면 내과 전문의의 진료를 받으십시오.', 3130, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저나트륨혈증', '저나트륨혈증', 'DEFINITION', '저나트륨혈증이란 혈중 나트륨 농도가 정상(135~145 mEq/L) 이하인 135 mEq/L 미만으로 저하된 상태를 말합니다. 주요 증상으로는 오심, 두통, 피로감, 집중력 저하, 근육 경련이 나타나고, 심한 경우(120 mEq/L 이하) 혼란, 경련, 혼수, 뇌부종으로 인한 사망에 이를 수 있습니다. 증상이 의심되면 내과 또는 응급의학과 전문의를 방문하여 혈액 검사로 나트륨 수치를 확인하고 적절한 치료를 받아야 합니다.', 3131, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저나트륨혈증', '저나트륨혈증', 'SYMPTOM', '저나트륨혈증의 대표적 증상은 두통, 오심, 피로감, 의식 혼탁, 경련 등 주로 중추신경계 증상입니다. 손발 감각 둔화나 손끝 발끝 어지러움(말초 감각 이상)은 저나트륨혈증보다는 말초신경 문제나 다른 전해질 이상(저칼슘혈증, 저마그네슘혈증)과 더 관련이 있을 수 있어, 저나트륨혈증의 전형적 증상이라 단정하기는 어렵습니다. 정확한 진단을 위해 내과 전문의를 방문하여 혈액 검사를 받아보시기를 권장합니다.', 3132, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저나트륨혈증', '저나트륨혈증', 'DIAGNOSIS', '과도한 수분 섭취로 인한 어지러움과 두통이 있을 때 저나트륨혈증 진단을 위해 혈청 나트륨 농도 측정이 포함된 기본 혈액 전해질 검사(Na, K, Cl, CO2)가 1차 검사입니다. 원인 파악을 위해 혈청 삼투압, 소변 나트륨 농도, 소변 삼투압도 함께 측정하며, 갑상선·부신 기능 검사도 필요할 수 있습니다. 증상이 경미해도 나트륨 수치가 낮으면 내과 전문의의 지도하에 적절한 치료가 필요합니다.', 3133, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저나트륨혈증', '저나트륨혈증', 'TREATMENT', '저나트륨혈증의 치료 약물은 원인과 중증도에 따라 다릅니다. 경증에서는 원인 교정(수분 제한, 이뇨제 조절 등)이 주를 이루며, 중등도~중증에서는 0.9% 또는 3% 고장성 식염수 정맥 주사를 통해 나트륨을 천천히 교정합니다. 부적절 항이뇨호르몬 분비 증후군(SIADH)이 원인인 경우 바소프레신 수용체 길항제(콘밥탄, 톨밥탄)가 사용될 수 있으나, 나트륨 교정 속도가 너무 빠르면 삼투성 탈수초 증후군이 발생할 수 있으므로 반드시 내과 전문의의 처방에 따라야 합니다.', 3134, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저마그네슘혈증', '저마그네슘혈증', 'DIET_LIFE', '알코올 중독 환자의 저마그네슘혈증에서는 마그네슘이 풍부한 식품 섭취가 중요하며, 녹색 채소(시금치, 브로콜리), 견과류(아몬드, 호두), 씨앗류(호박씨, 해바라기씨), 콩류, 전곡류, 생선이 좋은 공급원입니다. 알코올은 신장에서 마그네슘 배설을 증가시키므로 금주가 가장 중요한 식이 지침이며, 술 대신 충분한 수분과 균형 잡힌 영양 섭취가 필요합니다. 중증 결핍은 정맥 마그네슘 보충이 필요할 수 있으므로 내과 전문의와 상담하여 식이 및 보충 치료 계획을 수립하십시오.', 3135, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저마그네슘혈증', '저마그네슘혈증', 'MEDICATION', '저마그네슘혈증 치료의 기본은 마그네슘 보충으로, 경증에서는 경구 마그네슘(산화마그네슘, 구연산마그네슘 등)을 사용하고 중증 또는 흡수 장애 시에는 정맥 황산마그네슘을 투여합니다. 동반된 저칼슘혈증이나 저칼륨혈증이 있으면 함께 교정해야 하며, 원인 약물(이뇨제, 프로톤 펌프 억제제 등)의 조정도 필요할 수 있습니다. 마그네슘 보충제의 용량과 종류, 기간은 내과 전문의의 처방에 따라 결정되어야 하며 임의로 복용량을 바꾸지 말아야 합니다.', 3136, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저마그네슘혈증', '저마그네슘혈증', 'CAUSE', '저마그네슘혈증은 혈중 마그네슘 농도가 0.7 mmol/L(1.7 mg/dL) 미만으로 저하된 상태로, 주요 원인으로는 알코올 과다 섭취, 이뇨제(특히 루프이뇨제) 장기 복용, 설사·구토·흡수 불량, 신장 질환, 당뇨병, 프로톤 펌프 억제제 장기 복용 등이 있습니다. 마그네슘 결핍은 신경근 흥분성 증가(근육 경련, 진전), 저칼슘혈증 유발, 부정맥, 인슐린 저항성 등 다양한 문제를 일으킵니다. 증상이 의심되면 내과 전문의의 진료를 받아 혈중 마그네슘 수치를 확인하는 것이 중요합니다.', 3137, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저마그네슘혈증', '저마그네슘혈증', 'DEFINITION', '저마그네슘혈증이란 혈청 마그네슘 농도가 정상 범위(0.7~1.0 mmol/L) 이하로 저하된 상태를 의미합니다. 마그네슘은 체내 300여 개 이상의 효소 반응에 관여하며, 신경근 신호 전달, 에너지 대사, 단백질 합성, 심근 기능 유지에 필수적인 전해질입니다. 결핍 시 마그네슘의 신장 재흡수 감소, 장관 흡수 불량, 과도한 손실로 인해 발생하며, 증상 확인과 원인 파악을 위해 내과 전문의의 진료가 필요합니다.', 3138, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저마그네슘혈증', '저마그네슘혈증', 'SYMPTOM', '마그네슘 영양제 변경 후 소화불량과 설사가 나타나는 것은 새로운 마그네슘 제제의 종류(산화마그네슘은 설사 유발 가능성 높음)나 용량과 관련이 있을 수 있습니다. 마그네슘 과잉 섭취(고마그네슘혈증)도 설사를 유발할 수 있어 저마그네슘혈증 자체의 증상이라기보다 보충제 부작용일 가능성이 있습니다. 약 변경 후 소화 증상이 지속된다면 내과 전문의와 상담하여 혈중 마그네슘 수치를 확인하고 적절한 제제와 용량을 조정하는 것이 권장됩니다.', 3139, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저마그네슘혈증', '저마그네슘혈증', 'DIAGNOSIS', '저마그네슘혈증의 의심 증상으로는 근육 경련(특히 야간 다리 경련), 안면 근육 떨림, 손발 저림과 경련, 피로감, 과민성, 부정맥이 있으며, 말씀하신 얼굴 근육 떨림과 다리 쥐가 나는 증상은 저마그네슘혈증 가능성을 의심하는 데 도움이 됩니다. 진단은 혈청 마그네슘 농도 측정으로 이루어지며, 임상 증상만으로는 확진이 어려우므로 반드시 혈액 검사가 필요합니다. 이러한 증상이 반복된다면 내과 전문의의 진료를 받아 정확한 원인 파악과 치료를 받으시기 바랍니다.', 3140, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저마그네슘혈증', '저마그네슘혈증', 'TREATMENT', '저마그네슘혈증의 치료는 결핍 정도에 따라 다르며, 경증의 경우 마그네슘이 풍부한 식품(견과류, 녹색채소, 곡물 등) 섭취 증가와 경구 마그네슘 영양제 복용으로 치료가 가능한 경우도 있습니다. 그러나 중증 결핍, 흡수 장애 질환, 신장 기능 이상이 있는 경우에는 경구 보충만으로 부족하며 정맥 마그네슘 주사 치료가 필요합니다. 영양제 복용 전 반드시 내과 전문의와 상담하여 현재 수치와 원인에 맞는 적절한 치료 방법을 선택하십시오.', 3141, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저체온증', '저체온증', 'DIET_LIFE', '저체온증은 심부 체온이 35℃ 이하로 떨어지는 상태로 몸이 뜨겁게 느껴지는 증상과는 상관이 없으며, 오히려 전신이 차고 떨리는 것이 특징입니다. 저체온증 회복기 또는 동반 질환에 의한 피로와 불쾌감을 완화하기 위해서는 고열량 균형 식단, 충분한 수면과 휴식, 적절한 보온이 중요합니다. 증상이 지속되거나 심하다면 저체온증과 관련 없는 다른 원인이 있을 수 있으므로 내과 전문의의 진료를 받아보시기 바랍니다.', 3142, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저체온증', '저체온증', 'PREVENTION', '알코올은 말초혈관을 확장시켜 일시적으로 따뜻한 느낌을 주지만, 실제로는 체열 손실을 증가시켜 심부 체온을 낮추고 저체온증 위험을 높입니다. 또한 알코올은 체온 조절 중추인 시상하부 기능을 억제하고, 판단력을 저하시켜 추위에 대한 대처 행동(따뜻한 곳으로 이동, 옷 입기)을 방해합니다. 야외 캠핑 시 음주는 특히 기온이 낮은 밤에 저체온증 위험을 크게 높이므로 반드시 자제하고, 따뜻한 옷과 보온 장비를 충분히 갖추어야 합니다.', 3143, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저체온증', '저체온증', 'CAUSE', '저체온증은 외부 기온이 낮거나 차가운 물에 노출되어 신체가 충분한 열을 생산하지 못할 때 심부 체온이 35℃ 이하로 저하되면서 발생합니다. 주요 발생 원인으로는 저온 환경 장기 노출, 차가운 물 침수, 젖은 옷 착용, 강풍, 영양 부족, 고령, 알코올 섭취, 의식 저하, 갑상선 기능 저하증 등이 있습니다. 피부가 청색으로 변하고 몸이 심하게 떨리는 것은 저체온증의 전형적 증상으로, 즉시 따뜻하고 건조한 곳으로 이동하여 체온을 올리고 중증의 경우 즉시 응급 처치를 받아야 합니다.', 3144, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저체온증', '저체온증', 'DEFINITION', '저체온증은 핵심 체온이 35°C 이하로 떨어진 상태를 말합니다. 계곡에서 장시간 차가운 물에 노출된 후 오한과 두통이 나타나는 것은 저체온증의 초기 증상일 수 있으며, 추가로 피로감, 혼돈, 근육 경직 등이 동반될 수 있습니다. 증상이 지속된다면 신속히 따뜻한 곳으로 이동하고 전문의 진료를 받으시기 바랍니다.', 3145, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저체온증', '저체온증', 'SYMPTOM', '저체온증의 주요 증상으로는 체온 저하, 손발 냉감 외에도 지속적인 오한, 피부 창백 또는 청색증, 피로감, 언어 장애, 혼돈, 근육 경직 등이 포함됩니다. 중증으로 진행될 경우 심장 부정맥, 의식 저하, 혼수 상태까지 이어질 수 있으므로 증상이 나타나면 즉시 전문의 상담이 필요합니다.', 3146, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저체온증', '저체온증', 'DIAGNOSIS', '저체온증은 일반적으로 핵심 체온이 정상(36.5~37.5°C)보다 낮은 35°C 미만일 때 진단됩니다. 체온에 따라 경증(32~35°C), 중등도(28~32°C), 중증(28°C 미만)으로 분류하며, 직장 체온이나 식도 체온 측정이 정확도가 높습니다. 정확한 진단은 의료기관에서 전문의를 통해 받으시기 바랍니다.', 3147, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저체온증', '저체온증', 'TREATMENT', '저체온증 중등도(28~32°C)의 경우 적극적인 외부 가온(따뜻한 담요, 가온된 IV 수액, 가온된 산소 흡입)이 주된 치료법이며, 심부정맥이 동반된 경우 항부정맥제를 사용할 수 있습니다. 저체온증의 중증도에 따라 치료 방법과 약물 처방이 달라지므로 반드시 응급의학과 전문의의 지시에 따른 치료가 필요합니다.', 3148, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저칼륨혈증', '저칼륨혈증', 'DIET_LIFE', '우유는 칼륨을 100ml당 약 150mg 함유하고 있어 저칼륨혈증 환자에게 도움이 될 수 있으나, 단독으로 치료 수단이 되기는 어렵습니다. 칼륨 보충의 기간과 방법은 혈중 칼륨 수치, 원인 질환, 증상에 따라 개별화되므로 정확한 식이 권고는 내과 또는 신장내과 전문의와 상담하여 결정하시기 바랍니다.', 3149, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저칼륨혈증', '저칼륨혈증', 'CAUSE', '저칼륨혈증의 주요 원인으로는 구토·설사 등의 위장관 손실, 이뇨제·스테로이드 등의 약물 복용, 신장질환, 불충분한 칼륨 섭취 등이 있습니다. 칼륨이 부족하면 근육세포와 신경세포의 전기 전위가 불안정해져 근육 약화, 경련, 심장 부정맥, 피로감 등의 증상이 발생합니다. 정확한 원인 파악과 치료를 위해 내과 전문의 진료를 받으시기 바랍니다.', 3150, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저칼륨혈증', '저칼륨혈증', 'DEFINITION', '저칼륨혈증은 혈청 칼륨 농도가 정상 범위(3.5~5.0mmol/L) 미만인 3.5mmol/L 이하로 낮아진 상태를 말합니다. 칼륨은 신경·근육 기능, 심장 리듬 조절, 세포 내 삼투압 유지에 필수적인 전해질로, 부족 시 다양한 신체 기능 이상이 발생할 수 있습니다. 증상이 있다면 내과 전문의의 진단과 치료를 받으시기 바랍니다.', 3151, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저칼륨혈증', '저칼륨혈증', 'SYMPTOM', '혈청 칼륨 농도가 3.5mmol/L 미만으로 낮아지면 근육 약화, 피로감, 변비, 근육 경련이 나타날 수 있으며, 2.5mmol/L 미만의 심한 경우에는 마비, 심장 부정맥, 심한 경우 심정지까지 발생할 수 있습니다. 또한 소변량 증가, 다음(多飮), 구역감 등도 동반될 수 있습니다. 이러한 증상이 있으면 즉시 내과 전문의의 진료를 받으시기 바랍니다.', 3152, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저칼륨혈증', '저칼륨혈증', 'DIAGNOSIS', '저칼륨혈증이 의심되면 내과 또는 신장내과 전문의와 상담하는 것이 적절합니다. 혈액검사로 혈청 칼륨 수치를 확인하고, 원인에 따라 추가 검사(소변 전해질, 심전도 등)가 필요할 수 있습니다. 근육 약화, 피로감, 심계항진 등의 증상이 있다면 지체 없이 의료기관을 방문하시기 바랍니다.', 3153, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저칼륨혈증', '저칼륨혈증', 'TREATMENT', '혈청 칼륨이 3.5mmol/L 미만이더라도 증상이 있거나 수치가 낮으면 치료가 필요하며, 경증의 경우 칼륨이 풍부한 식품(바나나, 감자, 녹색 채소) 섭취와 경구 칼륨 보충제를 사용합니다. 중증이거나 심장 부정맥이 동반된 경우 정맥 내 칼륨 보충이 필요하며, 이뇨제 조절 등 원인 치료도 병행합니다. 반드시 내과 전문의의 지도 하에 치료받으시기 바랍니다.', 3154, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저칼슘혈증', '저칼슘혈증', 'DIET_LIFE', '저칼슘혈증에서 손발 저림과 심장박동 이상은 칼슘이 신경·근육 세포의 흥분성 조절에 핵심적 역할을 하기 때문에 나타납니다. 혈중 칼슘이 낮아지면 신경이 과흥분되어 감각 이상, 근육 경련(테타니), 심장 부정맥이 발생합니다. 이러한 증상이 지속된다면 내분비내과 또는 내과 전문의의 진료를 받으시기 바랍니다.', 3155, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저칼슘혈증', '저칼슘혈증', 'MEDICATION', '저칼슘혈증 치료에 사용되는 칼슘제와 비타민 D 제제는 일반적으로 식사와 함께 또는 식후에 복용하는 것이 흡수율을 높이는 데 도움이 됩니다. 다만, 약물 종류(탄산칼슘 vs 구연산칼슘)에 따라 복용 시점이 다를 수 있으므로 처방 약사나 담당 전문의의 안내에 따라 복용 방법을 확인하시기 바랍니다.', 3156, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저칼슘혈증', '저칼슘혈증', 'CAUSE', '저칼슘혈증(칼슘)의 원인으로는 부갑상선기능저하증, 비타민 D 결핍, 신장질환, 흡수 불량 증후군, 췌장염, 특정 약물(이중인산염, 항경련제) 등이 있습니다. 질문에 언급된 이뇨제, 스테로이드, 고알도스테론증, 쿠싱증후군, 간 질환은 주로 저칼륨혈증의 원인이며, 저칼슘혈증의 원인과 구분이 필요합니다. 정확한 원인 감별을 위해 내분비내과 전문의 진료를 권고드립니다.', 3157, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저칼슘혈증', '저칼슘혈증', 'DEFINITION', '저칼슘혈증은 혈장 내 총 칼슘 농도가 정상 범위(8.5~10.5mg/dL) 미만으로 감소한 상태를 말합니다. 원인으로는 부갑상선기능저하증, 비타민 D 결핍, 신부전, 흡수 불량 등이 있으며, 칼슘 조절 호르몬(부갑상선호르몬, 비타민 D)의 이상이 주된 기전입니다. 정확한 진단과 원인 규명을 위해 내분비내과 전문의의 진료가 필요합니다.', 3158, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저칼슘혈증', '저칼슘혈증', 'SYMPTOM', '칼슘 섭취 부족은 저칼슘혈증의 직접적 원인이 되기보다는 위험 요인 중 하나이며, 인체는 뼈에서 칼슘을 동원해 혈중 농도를 유지하려 합니다. 장기적인 칼슘 결핍은 골다공증, 근육 경련, 감각 이상을 유발할 수 있으며, 성인은 하루 1,000mg 이상의 칼슘 섭취가 권장됩니다. 저칼슘혈증이 의심되면 혈액 검사와 함께 내과 전문의의 평가를 받으시기 바랍니다.', 3159, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저칼슘혈증', '저칼슘혈증', 'DIAGNOSIS', '손발 감각 이상과 경련이 지속될 때 저칼슘혈증 진단을 위해 혈액검사(혈청 칼슘, 알부민, 인, 마그네슘, 부갑상선호르몬), 심전도 검사(QT 연장 확인), 그리고 신경 기능 평가가 활용됩니다. 또한 Chvostek 징후(얼굴 신경 두드림 시 근육 수축)와 Trousseau 징후(혈압 측정 시 손 경련)와 같은 임상 검사도 진단에 도움이 됩니다. 증상이 있다면 내과 또는 내분비내과 전문의의 진료를 받으시기 바랍니다.', 3160, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저칼슘혈증', '저칼슘혈증', 'TREATMENT', '저칼슘혈증의 치료는 칼슘 보충이 기본이며, 경증은 경구 칼슘제와 비타민 D 보충제를 사용하고, 중증이나 급성인 경우 정맥 내 칼슘 글루코네이트를 투여합니다. 원인 질환 치료(부갑상선기능저하증, 비타민 D 결핍 교정, 신장질환 관리)도 병행되며, 마그네슘 결핍이 동반된 경우 마그네슘 보충도 필요합니다. 치료 계획은 내분비내과 전문의와 상담하여 개별화하시기 바랍니다.', 3161, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저혈당증', '저혈당증', 'CAUSE', '식사 간격이 길어지면 간에서의 포도당 생성이 혈당 소모를 따라가지 못할 때 저혈당이 발생할 수 있습니다. 특히 당뇨병 치료 중 인슐린이나 설폰요소제 복용 환자, 영양 상태가 불량한 경우, 또는 과도한 운동 후에 공복 상태가 지속되면 저혈당 위험이 높아집니다. 저혈당 증상이 자주 나타난다면 내과 전문의의 상담을 받으시기 바랍니다.', 3162, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저혈당증', '저혈당증', 'DEFINITION', '저혈당증은 혈중 포도당 농도가 70mg/dL 미만으로 떨어진 상태를 말하며, 즉각적인 혈당 상승이 필요합니다. 의식이 있는 저혈당 환자에게 설탕물, 사탕, 주스 등 빠르게 흡수되는 당분 15~20g을 섭취하면 혈당 회복에 효과적입니다. 저혈당이 반복된다면 원인 파악을 위해 내과 또는 내분비내과 전문의의 진료를 받으시기 바랍니다.', 3163, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저혈당증', '저혈당증', 'SYMPTOM', '가슴 두근거림(심계항진), 식은땀, 떨림은 저혈당 시 교감신경이 활성화되어 나타나는 자율신경계 증상으로, 신체가 저혈당 상태를 극복하려는 반응입니다. 이 증상들은 혈당이 70mg/dL 아래로 내려가면 흔히 발생하며, 즉시 당분을 섭취하면 호전될 수 있습니다. 이런 증상이 반복된다면 내과 전문의의 진료를 통해 원인을 파악하는 것이 중요합니다.', 3164, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저혈당증', '저혈당증', 'DIAGNOSIS', '저혈당증이 의심될 때는 혈당 측정기를 이용한 손가락 채혈 혈당 검사가 가장 기본적이며, 병원에서는 정맥혈당 검사, 인슐린·C-펩타이드 수치, 48~72시간 금식 검사, 혼합식이 유발 검사 등을 통해 원인을 감별합니다. 당뇨약 복용 중이라면 약물 조절이 필요할 수 있으므로 내과 또는 내분비내과 전문의의 진료를 받으시기 바랍니다.', 3165, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '저혈당증', '저혈당증', 'TREATMENT', '당뇨약 복용 중 저혈당이 발생하면 즉각적으로 빠르게 흡수되는 당분(포도당 정제, 주스, 사탕)을 섭취하고 15분 후 혈당을 재측정합니다. 장기적으로는 약물 종류·용량 조절, 식사 시간 규칙화, 운동 전 혈당 확인 등이 중요하며, 글루카곤 응급 주사제를 처방받아 보관하는 것도 도움이 됩니다. 저혈당이 반복된다면 내과 또는 내분비내과 전문의와 상담하여 치료 계획을 재조정하시기 바랍니다.', 3166, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '호흡성 산증', '호흡성산증', 'CAUSE', '천식 발작 시 기관지 경련과 염증으로 환기량이 감소하면 이산화탄소(CO2)가 체내에 축적되어 혈액이 산성화되는 호흡성 산증이 발생할 수 있습니다. 특히 중증 천식에서는 호흡근 피로로 인해 환기 능력이 더욱 저하되어 심각한 호흡성 산증으로 진행될 수 있습니다. 천식 조절이 불량하거나 호흡 곤란이 심하면 즉시 응급의학과 또는 호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3167, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '호흡성 산증', '호흡성산증', 'DEFINITION', '호흡성 산증은 폐의 환기량 감소로 이산화탄소(CO2) 배출이 불충분해져 혈중 CO2 농도(PaCO2)가 45mmHg 이상으로 증가하고 혈액 pH가 7.35 미만으로 낮아진 상태입니다. 영향 요인으로는 폐질환(COPD, 천식, 폐렴), 신경근육질환, 중추신경계 억제, 호흡근 약화 등이 있으며, 적절한 산소 투여와 원인 치료가 필요합니다. 호흡 이상이 있다면 호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3168, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '호흡성 산증', '호흡성산증', 'SYMPTOM', '호흡성 산증의 주요 증상으로는 호흡 곤란, 빠른 호흡 외에도 두통, 혼돈, 집중력 저하, 기면 상태, 심한 경우 의식 저하가 나타납니다. 또한 피부 및 점막의 청색증(산소 부족 시), 심계항진, 부정맥이 동반될 수 있으며, 만성 호흡성 산증에서는 적혈구 증가증도 나타날 수 있습니다. 이러한 증상이 있다면 호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3169, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '호흡성 산증', '호흡성산증', 'DIAGNOSIS', '호흡성 산증 진단의 기준 검사는 동맥혈 가스 분석(ABGA)이며, 여기에 더해 흉부 X선 및 CT(폐 병변 확인), 폐기능 검사(FEV1/FVC 측정), 심전도, 혈액 전해질 검사가 보완적으로 활용됩니다. 동맥혈 가스 분석은 pH, PaCO2, HCO3- 등을 직접 측정할 수 있는 가장 정확한 방법이나, 동맥 천자가 필요해 침습적인 단점이 있습니다. 정확한 진단을 위해 호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3170, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '호흡성 알칼리증', '호흡성알칼리증', 'CAUSE', '호흡성 알칼리증은 과호흡으로 인한 CO2 과다 배출로 발생하며, 폐렴이나 폐 손상은 저산소증을 유발해 호흡 중추를 자극하고 과호흡을 일으켜 CO2가 과도하게 배출됩니다. 이 외에도 불안·공황장애, 패혈증, 간 부전, 고열, 고지대 등도 원인이 됩니다. 정확한 원인 파악과 치료를 위해 호흡기내과 또는 내과 전문의의 진료를 받으시기 바랍니다.', 3171, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '호흡성 알칼리증', '호흡성알칼리증', 'DEFINITION', '호흡성 알칼리증은 과호흡으로 이산화탄소(CO2)가 과도하게 배출되어 혈중 PaCO2가 35mmHg 미만으로 감소하고 혈액 pH가 7.45 이상으로 상승한 상태입니다. 불안, 통증, 발열, 폐질환, 임신, 특정 약물(살리실산염) 등이 원인이 될 수 있으며, 원인 치료와 함께 심한 경우 호흡 조절이 필요합니다. 증상이 있다면 내과 전문의의 진료를 받으시기 바랍니다.', 3172, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '호흡성 알칼리증', '호흡성알칼리증', 'SYMPTOM', '호흡성 알칼리증은 과호흡으로 혈중 CO2가 과도하게 배출되어 혈액이 알칼리화되는 상태이며, 팔다리 감각 이상(저림, 따끔거림)은 대표적 증상 중 하나입니다. 이는 혈중 칼슘 이온화가 감소하고 신경의 흥분성이 증가하여 발생하며, 입 주위 감각 이상, 근육 경련, 어지러움도 함께 나타날 수 있습니다. 이러한 증상이 있다면 내과 또는 호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3173, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '호흡성 알칼리증', '호흡성알칼리증', 'DIAGNOSIS', '입 주위와 손발의 감각 이상, 호흡 관련 증상이 있을 때는 내과 또는 호흡기내과를 방문하는 것이 적절합니다. 동맥혈 가스 분석, 혈중 전해질 검사, 심전도 등을 통해 호흡성 알칼리증 여부를 확인할 수 있습니다. 증상이 갑자기 심해지거나 지속된다면 응급실을 방문하거나 빠른 시일 내에 전문의 진료를 받으시기 바랍니다.', 3174, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '호흡성 알칼리증', '호흡성알칼리증', 'TREATMENT', '호흡성 알칼리증 치료의 핵심은 원인 제거이며, 불안·공황으로 인한 경우 종이봉투 호흡법이나 안정 요법이 도움이 될 수 있습니다. 저산소증이 원인인 경우 산소 투여, 폐질환이 원인인 경우 해당 질환 치료가 필요하며, 필요 시 진정제 투여나 기계 환기 조절도 고려됩니다. 치료 방법과 계획은 원인에 따라 달라지므로 내과 또는 호흡기내과 전문의와 상담하시기 바랍니다.', 3175, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '혼수', '혼수', 'CAUSE', '혼수상태는 외상성 뇌손상(교통사고, 낙상), 뇌출혈, 뇌졸중 외에도 뇌종양, 뇌수막염, 심한 저혈당·고혈당, 약물 과다 복용, 저산소증, 심각한 전해질 이상 등 다양한 원인에 의해 발생합니다. 뇌간 또는 양측 대뇌 반구가 광범위하게 손상될 때 각성 상태를 유지하는 망상활성계(RAS)가 기능을 잃어 의식이 소실됩니다. 혼수 상태는 즉각적인 응급 치료가 필요한 응급상황입니다.', 3176, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '혼수', '혼수', 'DEFINITION', '혼수는 외부 자극에 반응하지 않고 의식을 회복할 수 없는 깊은 무의식 상태로, 약물 중독은 중추신경계를 억제하여, 뇌염·뇌수막염과 같은 중추신경계 질환은 뇌 기능을 직접 손상시켜 혼수를 유발합니다. 치료는 원인 제거(해독, 감염 치료)와 기도 확보, 영양 지지, 합병증 예방이 기본이며, 신경과 또는 신경외과 전문의의 집중 관리가 필요합니다.', 3177, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '혼수', '혼수', 'SYMPTOM', '뇌출혈로 인한 혼수 상태에서는 통증·음성 자극에 반응 없음, 비정상적인 근육 긴장(제뇌 또는 제피질 자세), 동공 이상(산동, 대광반사 소실), 비정상적 호흡 패턴(체인-스토크스 호흡 등), 안구 운동 이상이 나타납니다. 뇌간 손상이 심할수록 반사 기능이 소실되며, 자율신경 이상으로 혈압·맥박·체온 조절도 불안정해집니다. 뇌출혈 혼수는 신경외과적 응급 처치가 필요합니다.', 3178, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '혼수', '혼수', 'DIAGNOSIS', '후향성(파열된) 뇌동맥류로 인한 혼수 상태에서 진단은 뇌 CT, 뇌 MRI/MRA, 뇌척수액 검사, 뇌혈관 조영술을 통해 이루어집니다. 혼수 상태 자체를 깨우기 위해 특정 약물을 단독으로 사용하는 방법은 없으며, 근본적인 뇌동맥류 치료(수술적 클리핑 또는 혈관 내 코일링)와 뇌압 관리, 뇌혈관 연축 예방(니모디핀 투여)이 우선됩니다. 즉각적인 신경외과 전문의 치료가 필요합니다.', 3179, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '혼수', '혼수', 'TREATMENT', '혼수의 치료는 원인에 따라 다르며, 공통적으로 기도 확보 및 기계 환기, 뇌압 감시 및 조절(만니톨, 과호흡), 혈압·혈당·체온·전해질 안정화가 기본입니다. 뇌졸중은 혈전용해 또는 수술, 저혈당은 포도당 투여, 약물 중독은 해독제 투여, 감염은 항생제 치료 등 원인별 치료가 병행됩니다. 혼수 환자는 신경과 또는 신경외과 전문의의 집중 치료실 관리가 필요합니다.', 3180, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '화상', '화상', 'DIET_LIFE', '화상 재활 환자에게는 고단백, 고칼로리 식이(하루 2,000~3,000kcal 이상)가 조직 회복과 면역 강화에 필수적입니다. 생활 측면에서는 화상 부위 감염 예방을 위한 청결 유지, 자외선 차단, 압박 의류 착용(흉터 방지), 금연, 규칙적인 재활 운동이 권장됩니다. 구체적인 식이 및 재활 계획은 화상외과 또는 재활의학과 전문의와 상담하여 결정하시기 바랍니다.', 3181, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '화상', '화상', 'MEDICATION', '화상 치료에는 상처 청결과 세균 감염 예방을 위한 국소 항균제(실버설파다이아진, 무피로신)가 사용되며, 통증 조절을 위해 진통제(아세트아미노펜, NSAIDs, 마약성 진통제)가 처방됩니다. 심한 화상에서는 이식 수술과 함께 전신 항생제, 수액 치료, 영양 지원도 병행됩니다. 약물 선택과 용량은 화상의 정도와 범위에 따라 달라지므로 반드시 전문의의 처방을 따르시기 바랍니다.', 3182, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '화상', '화상', 'PREVENTION', '화상 예방을 위해 주방에서는 뜨거운 액체·기름 취급 시 주의하고, 어린이를 주방 화기 근처에 두지 않는 것이 중요합니다. 화학물질 취급 시 보호 장갑·안전 복장 착용, 전기 장치의 정기 점검도 필요합니다. 화상 발생 시 즉시 흐르는 찬물로 20분 이상 냉각하고, 2도 이상 화상이나 얼굴·손·생식기 부위 화상은 즉시 응급실을 방문하시기 바랍니다.', 3183, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '화상', '화상', 'CAUSE', '화상의 원인으로는 열(화염, 뜨거운 물, 증기), 화학물질, 전기 외에도 방사선(방사선 치료, 과도한 자외선), 마찰, 극저온(동상도 넓은 의미의 냉화상)도 포함됩니다. 특히 전기 화상은 외부보다 내부 조직 손상이 심할 수 있으며, 방사선 화상은 지연 발현되는 특성이 있습니다. 원인에 따라 치료 접근법이 달라지므로 정확한 평가를 위해 화상외과 전문의의 진료를 받으시기 바랍니다.', 3184, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '화상', '화상', 'DEFINITION', '화상은 손상 깊이에 따라 1도(표피만 손상, 발적·통증), 2도 표재성(진피 상층, 수포·심한 통증), 2도 심층(진피 하층, 수포·감각 저하), 3도(전층 손상, 흰색·갈색 괴사, 무통)로 분류합니다. 진단은 임상적 시진과 촉진으로 이루어지며, 치료는 냉각 처치, 드레싱, 감염 예방, 심한 경우 피부 이식 수술이 적용됩니다. 정확한 화상 분류와 치료를 위해 응급의학과 또는 화상외과 전문의의 진료를 받으시기 바랍니다.', 3185, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '화상', '화상', 'SYMPTOM', '스케이트 등으로 인한 마찰이나 압력에 의해 발바닥에 수포와 발적, 통증이 나타나는 것은 마찰 화상(friction burn) 또는 압력에 의한 피부 손상으로 볼 수 있으며, 표재성 2도 화상에 해당할 수 있습니다. 반면 동상의 경우에도 수포와 통증이 나타나지만 극저온 노출 후 발생한다는 점에서 구분됩니다. 정확한 진단과 적절한 처치를 위해 응급의학과 또는 피부과 전문의의 진료를 받으시기 바랍니다.', 3186, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '화상', '화상', 'DIAGNOSIS', '화상이 발생하면 응급처치(흐르는 찬물 20분 냉각) 후 경증은 피부과, 중등도 이상은 응급실이나 화상외과를 방문합니다. 진료 시 화상 발생 시각, 원인(열, 화학물질, 전기 등), 이미 시행한 응급처치 내용을 의료진에게 제공해야 합니다. 화상 면적이 넓거나(성인 체표면적 10% 이상), 얼굴·손·발·생식기·관절 부위이거나 3도 화상으로 의심되면 즉시 전문 화상센터를 방문하시기 바랍니다.', 3187, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '화상', '화상', 'TREATMENT', '2도 화상의 흉터 예방을 위해서는 초기에 적절한 드레싱(비접착성 습윤 드레싱), 감염 예방, 충분한 보습이 중요합니다. 치유 후에는 실리콘 젤 시트 또는 실리콘 젤 도포, 압박 의류 착용(최소 6개월~1년), 자외선 차단이 흉터 형성을 줄이는 데 효과적입니다. 흉터가 이미 형성된 경우 레이저 치료, 스테로이드 주사, 수술적 교정 등을 피부과 또는 성형외과 전문의와 상담하시기 바랍니다.', 3188, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '횡격막 탈장', '횡격막탈장', 'DEFINITION', '횡격막 탈장은 횡격막의 결손 부위를 통해 복강 내 장기(위, 소장, 대장 등)가 흉강으로 이탈한 상태를 말합니다. 선천성(보호렉-달라포이 탈장 등)과 후천성(외상, 식도열공 탈장 등) 모두 존재하며, 선천성은 신생아기에 발견되는 경우가 많고, 후천성은 외상이나 복압 증가에 의해 성인에서도 발생합니다. 정확한 진단을 위해 흉부외과 또는 외과 전문의의 진료를 받으시기 바랍니다.', 3189, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '횡격막 탈장', '횡격막탈장', 'SYMPTOM', '성인에서 횡격막 탈장은 외상(교통사고, 낙상), 식도열공 탈장의 악화, 복압 증가(만성 기침, 비만, 임신) 등으로 발생할 수 있습니다. 증상으로는 식후 흉통, 역류, 호흡 곤란, 소화 불량이 나타날 수 있으며, 장 감돈(탈장된 장기의 혈류 차단) 시 응급상황이 됩니다. 이러한 증상이 있다면 흉부외과 또는 소화기내과 전문의의 진료를 받으시기 바랍니다.', 3190, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '횡격막 탈장', '횡격막탈장', 'DIAGNOSIS', '횡격막 탈장의 진단에는 흉부 X선(흉강 내 공기·액체 음영), 흉부 CT(가장 정확한 해부학적 확인), 상부 위장관 조영술, 초음파 등이 활용됩니다. 복부 이상과의 감별을 위해 CT에서 횡격막 연속성의 단절 여부, 흉강 내 복강 장기 존재 여부, 위장관의 위치를 확인하는 것이 핵심입니다. 정확한 진단과 치료를 위해 흉부외과 전문의의 진료를 받으시기 바랍니다.', 3191, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '횡격막 탈장', '횡격막탈장', 'TREATMENT', '횡격막 탈장의 치료는 원칙적으로 수술이 기본이며, 장기 감돈이나 호흡 부전이 동반된 경우 응급 수술이 필요합니다. 식도열공 탈장에서 증상이 경미한 경우 위산 억제제(PPI) 등 약물로 증상을 완화할 수 있으나, 근본적 치료는 수술(복강경 또는 개복 횡격막 복원)입니다. 치료 시기와 방법은 탈장의 유형, 크기, 증상에 따라 달라지므로 흉부외과 전문의와 상담하시기 바랍니다.', 3192, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '횡문근융해증', '횡문근융해증', 'CAUSE', '횡문근융해증은 과도한 운동이나 근육 손상으로 근육 세포가 파괴되어 발생하는 것으로, 근육 약화와 부종이 나타났다면 즉각적인 운동 중단과 충분한 수분 보충이 필요합니다. 운동을 재개하는 시기는 증상 완화, CK 수치 정상화, 의사 확인 후 결정해야 하며, 근육이 회복되기 전 운동을 지속하면 신부전 등 심각한 합병증이 발생할 수 있습니다. 반드시 내과 또는 응급의학과 전문의의 지시에 따르시기 바랍니다.', 3193, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '횡문근융해증', '횡문근융해증', 'DEFINITION', '허벅지와 종아리의 근육 약화, 통증, 경련은 과도한 운동, 탈수, 외상, 약물(스타틴) 등 다양한 원인으로 발생하며, 횡문근융해증의 증상일 수 있습니다. 횡문근융해증은 근육 세포가 파괴되어 마이오글로빈이 혈류로 유출되어 발생하며, 특징적으로 갈색·적갈색 소변이 동반됩니다. 이러한 증상이 있다면 즉시 내과 또는 응급의학과에서 혈액검사(CK 수치)와 소변 검사를 받으시기 바랍니다.', 3194, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '횡문근융해증', '횡문근융해증', 'SYMPTOM', '횡문근융해증의 특징적 증상으로는 운동 후 심한 근육통(주로 사용한 근육 부위), 근육 부종과 압통, 근육 경련, 그리고 마이오글로빈뇨로 인한 진한 갈색·콜라색 소변이 있습니다. 전신 증상으로는 발열, 구역·구토, 심한 피로감이 동반되며, 신부전이 합병될 경우 소변량 감소, 부종도 나타납니다. 이러한 증상이 나타나면 즉시 응급의학과 또는 내과 전문의의 진료를 받으시기 바랍니다.', 3195, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '횡문근융해증', '횡문근융해증', 'DIAGNOSIS', '횡문근융해증 진단 후 근육 통증, 허벅지 안쪽 통증은 근육 세포 파괴와 염증 반응으로 인해 발생하며 흔히 나타납니다. 통증은 손상된 근육 부위에 국한되어 나타나고, 근육이 회복됨에 따라 점차 완화됩니다. 통증이 지속되거나 악화된다면 추가 손상 또는 합병증(구획증후군)을 시사할 수 있으므로 담당 전문의에게 즉시 알리시기 바랍니다.', 3196, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '횡문근융해증', '횡문근융해증', 'TREATMENT', '횡문근융해증의 기본 치료인 수액 요법과 소변 알칼리화 외에도, 고칼륨혈증·고인산혈증 등 전해질 이상에 대한 교정, 신부전 발생 시 혈액투석이 필요할 수 있습니다. 원인 약물(스타틴 등) 복용 중이라면 중단이 필요하며, 구획증후군이 발생한 경우 근막 절개술이 시행됩니다. 치료는 반드시 내과 또는 응급의학과 전문의의 지도 하에 이루어져야 합니다.', 3197, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '흉통', '흉통', 'CAUSE', '흉통의 주요 원인으로는 심장성(협심증, 심근경색, 심낭염), 폐 관련(폐렴, 폐색전증, 기흉), 소화기(위식도역류, 식도 경련), 근골격계(늑골 골절, 늑연골염), 그리고 불안·공황장애 등이 있습니다. 심근경색에 의한 흉통은 주로 안정 시에도 발생하며 좌측 팔이나 턱으로 방사되고, 폐색전증은 갑작스러운 호흡곤란과 함께 나타납니다. 흉통이 갑자기 심하게 나타나면 즉시 응급실을 방문하시기 바랍니다.', 3198, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '흉통', '흉통', 'DEFINITION', '식도·위에서 발생하는 흉통은 주로 흉골 하부 또는 명치(상복부) 부위에서 타는 듯하거나 쥐어짜는 느낌으로 나타납니다. 폐 관련 흉통은 측흉부나 흉벽에서 날카롭게 느껴지는 경우가 많으며, 호흡에 따라 악화되는 특징이 있습니다. 정확한 원인 감별을 위해서는 내과 또는 소화기내과, 호흡기내과 전문의의 진료와 적절한 검사가 필요합니다.', 3199, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '흉통', '흉통', 'SYMPTOM', '지역사회 획득 폐렴의 주요 증상으로는 발열(38°C 이상), 기침(가래 동반), 흉통(흉막 자극으로 인한 흉막성 흉통, 호흡 시 악화), 호흡 곤란이 대표적입니다. 흉통은 염증이 흉막에 파급될 때 발생하며 심호흡이나 기침 시 악화되는 양상이 특징적이고, 발열에 따른 빈맥, 피로감, 식욕 부진도 동반됩니다. 이러한 증상이 있다면 호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3200, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '흉통', '흉통', 'TREATMENT', '중등도 이상의 흉통에서 약물 치료만으로 재발을 완전히 예방하기는 어려우며, 원인 질환에 따라 비약물적 치료가 필요합니다. 관상동맥 질환의 경우 관상동맥 스텐트 삽입술(PCI) 또는 관상동맥 우회술(CABG), 역류성 식도 질환은 생활 습관 교정과 식이 조절, 기흉은 흉관 삽입술이나 수술 치료가 있습니다. 흉통의 원인에 맞는 최적 치료 계획은 해당 전문과(심장내과, 소화기내과 등) 전문의와 상담하시기 바랍니다.', 3201, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '간세포성 암종', '간세포성암종', 'PREVENTION', '간세포성 암종 예방을 위해 B형·C형 간염 예방(예방접종, 항바이러스 치료), 과도한 음주 제한, 비알코올성 지방간 예방을 위한 체중 관리가 중요합니다. 또한 아플라톡신이 오염된 음식 섭취를 피하고, 간경변증 환자는 6개월마다 복부 초음파와 AFP 검사를 통한 정기 검진이 권장됩니다. 고위험군(만성 간염, 간경변증 환자)은 소화기내과 또는 간내과 전문의의 정기적인 추적 관찰이 필수적입니다.', 3202, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '간세포성 암종', '간세포성암종', 'CAUSE', '우리나라에서 아플라톡신 오염 식품(땅콩, 옥수수 등)에 의한 간암 위험이 상대적으로 낮은 이유는 식품 안전 관리 체계와 수입 기준이 엄격하고, 기후적으로 아플라톡신을 생산하는 아스퍼길루스 곰팡이가 번식하기 어려운 환경이기 때문입니다. 그러나 국내에서도 보관 상태가 불량한 견과류나 곡류에 곰팡이가 생길 수 있으므로 식품 보관에 주의가 필요합니다.', 3203, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '간세포성 암종', '간세포성암종', 'DEFINITION', '간세포성 암종은 주로 만성 B형·C형 간염, 간경변증, 알코올성 간 질환을 배경으로 발생합니다. 종양이 커지거나 간 기능이 저하되면 우상복부 통증, 체중 감소, 복부에서 만져지는 종괴, 황달, 복수가 나타나며, 초기에는 무증상인 경우가 많습니다. 만성 간 질환이 있는 경우 정기적인 검진을 통해 조기 발견하는 것이 치료 예후에 매우 중요합니다.', 3204, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '간세포성 암종', '간세포성암종', 'SYMPTOM', '간세포성 암종에서 황달은 종양이 커져 담도를 압박하거나 간 기능이 심각하게 저하될 때 발생하며, 우상복부 통증은 간 피막의 신전이나 종양 내 출혈로 인해 나타납니다. 이 두 증상은 실제로 진행된 간세포암에서 나타나는 증상이나, 초기에는 증상이 없는 경우가 많아 정기 검진의 중요성이 강조됩니다. 이러한 증상이 있다면 즉시 소화기내과 또는 간내과 전문의의 진료를 받으시기 바랍니다.', 3205, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '간세포성 암종', '간세포성암종', 'DIAGNOSIS', '간세포성 암종 진단과 치료는 소화기내과(간내과) 또는 외과(간담췌외과)에서 이루어집니다. 복부 초음파, 역동적 조영 증강 CT 또는 MRI, AFP 혈액 검사가 주요 검사이며, 필요 시 조직 생검이 시행됩니다. 상급 종합병원의 간 전문 클리닉이나 암센터를 방문하시면 다학제적 진료(소화기내과, 외과, 방사선종양학과 등)를 받으실 수 있습니다.', 3206, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '간세포성 암종', '간세포성암종', 'TREATMENT', '간세포성 암종의 수술 외 치료로는 경동맥 화학색전술(TACE), 고주파 열치료(RFA), 마이크로파 소작술, 방사선색전술(TARE), 입체정위 방사선치료(SBRT), 소라페닙·렌바티닙 등의 표적치료제, 면역항암요법(아테졸리주맙+베바시주맙)이 있습니다. 치료 방법은 종양의 크기·개수·위치, 간 기능, 전신 상태에 따라 선택되므로 간내과 및 간담췌외과 전문의와 다학제적 상담이 필요합니다.', 3207, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '간의 양성 신생물', '간의양성신생물', 'DEFINITION', '간의 양성 신생물(혈관종, 선종, 국소 결절성 과형성 등)이 있어도 간의 다른 부위에 악성 종양이나 별개의 양성 병변이 발생할 수 있으며, 간 전이암이나 간세포암과의 감별이 중요합니다. 특히 간선종은 악성 전환 위험이 있으며, 만성 간염·간경변증이 동반된 경우 간세포암 발생 위험도 함께 존재합니다. 정기적인 영상 검사와 소화기내과 전문의의 추적 관찰이 필요합니다.', 3208, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '간의 양성 신생물', '간의양성신생물', 'DIAGNOSIS', '급성 B형간염 후 간의 양성 신생물(예: 혈관종, 국소 결절성 과형성)이 있다면 일반적으로 정기 검진이 권장됩니다. 양성 병변이라도 크기 변화나 악성 전환 여부를 감시하고, B형간염 후 만성화 또는 간경변증 진행 시 간암 위험을 모니터링하기 위해 정기 검진이 필요합니다. 검진 주기와 방법은 병변의 종류와 간 기능 상태에 따라 소화기내과 전문의와 상담하여 결정하시기 바랍니다.', 3209, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '간의 양성 신생물', '간의양성신생물', 'TREATMENT', '간의 양성 신생물 중 간혈관종은 크기가 작고(5cm 미만) 무증상인 경우 악성 전환 위험이 없어 수술 없이 정기 영상 추적 관찰만으로 관리합니다. 국소 결절성 과형성(FNH)도 대부분 증상이 없고 악성화 위험이 낮아 추적 관찰이 원칙입니다. 반면 간선종은 출혈·파열·악성 전환 위험이 있어 크기와 증상에 따라 수술적 치료를 고려하므로, 정확한 진단 후 소화기내과 또는 간담췌외과 전문의와 상담이 필요합니다.', 3210, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '간암', '간암', 'DEFINITION', '간암은 간에서 발생하는 악성 종양으로, 간세포에서 기원하는 간세포암이 가장 흔하며 전체 간암의 85% 이상을 차지합니다. 국내에서는 B형·C형 간염 바이러스 감염과 간경변증이 주요 원인이며, 초기에는 증상이 없다가 진행되면 우상복부 통증, 황달, 복수, 체중 감소가 나타납니다. 조기 발견을 위해 고위험군은 6개월마다 복부 초음파와 AFP 검사를 받는 것이 권장됩니다.', 3211, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '갑상선암', '갑상선암', 'CHECKUP', '목에 결절이 만져지거나 갑상선암이 의심될 경우 내분비내과 또는 이비인후과(두경부외과) 전문의와 상담하는 것이 적절합니다. 갑상선 초음파 검사와 필요 시 초음파 유도 하 세침 흡인 세포 검사(FNAC)를 통해 정확한 진단을 받을 수 있습니다. 빠른 시일 내에 전문의를 방문하여 검진을 받으시기 바랍니다.', 3212, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '갑상선암', '갑상선암', 'DIET_LIFE', '갑상선암 수술 후 체중 관리를 위해 고칼로리·고지방 식품과 단순 당류의 과잉 섭취를 줄이고, 균형 잡힌 식단(충분한 채소, 저지방 단백질, 복합 탄수화물)을 유지하는 것이 권장됩니다. 특히 방사성 요오드 치료 예정인 경우 저요오드 식이가 필요하며, 수술 후 갑상선 호르몬제 복용 중에는 과도한 식이 제한보다 적절한 영양 균형이 중요합니다. 구체적인 식단 계획은 담당 내분비내과 전문의 또는 영양사와 상담하시기 바랍니다.', 3213, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '갑상선암', '갑상선암', 'MEDICATION', '갑상선암 치료 후 갑상선 전절제술을 시행한 경우 갑상선 호르몬 대체 요법(레보티록신)을 복용해야 하며, 재발 고위험군은 TSH 억제 용량을 유지합니다. 방사성 요오드(I-131) 치료도 보조적으로 사용됩니다. 약물 복용 효과를 높이기 위해 규칙적인 식사, 적절한 운동, 금연, 적정 체중 유지가 도움이 되며, 약물 조절은 반드시 내분비내과 전문의와 상담하여 결정하시기 바랍니다.', 3214, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '갑상선암', '갑상선암', 'PREVENTION', '갑상선암의 가족력이 있는 경우 정기적인 갑상선 초음파 검진을 받는 것이 가장 중요합니다. 식습관 측면에서는 균형 잡힌 식단을 유지하고, 과도한 방사선 노출을 피하며, 충분한 요오드를 섭취하는 것이 권장됩니다. 단, 특정 식품이 갑상선암을 직접 예방한다는 근거는 제한적이므로, 가족력이 있다면 내분비내과 전문의와 정기적인 상담을 통한 감시가 가장 효과적입니다.', 3215, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '갑상선암', '갑상선암', 'CAUSE', '갑상선암의 원인으로 방사선 노출은 가장 확립된 위험 인자로, 특히 어린 시절 두경부 방사선 조사 경험이 갑상선암 위험을 크게 높입니다. 이 외에도 가족력(유전적 요인, RET 유전자 변이 등), 여성 호르몬(여성에서 3~4배 높은 발생률), 비만, 만성 갑상선 질환(하시모토 갑상선염) 등이 위험 인자로 알려져 있습니다. 위험 인자가 있다면 내분비내과 전문의를 통한 정기 검진을 받으시기 바랍니다.', 3216, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '갑상선암', '갑상선암', 'DEFINITION', '갑상선암은 갑상선 세포의 종류에 따라 여포 세포 기원(유두암·여포암·역형성암)과 C세포 기원(수질암)으로 분류됩니다. 유두암이 전체의 80~90%로 가장 흔하며 예후가 좋고, 여포암은 10~15%, 수질암은 3~5%, 역형성암은 1% 미만이지만 가장 악성도가 높습니다. 각 종류에 따라 치료 방법과 예후가 다르므로 정확한 조직 진단이 중요합니다.', 3217, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '갑상선암', '갑상선암', 'SYMPTOM', '갑상선암의 주요 증상인 갑상선 결절은 갑상선 세포의 비정상적 증식으로 발생하며, 목 앞 중앙 하부에서 단단하고 경계가 불명확한 종괴로 만져질 수 있습니다. 대부분 무증상이나, 크기가 커지면 목 이물감, 연하 곤란, 쉰 목소리(되돌이후두신경 침범), 호흡 곤란, 경부 림프절 종대가 동반될 수 있습니다. 이러한 증상이 있다면 내분비내과 또는 이비인후과 전문의의 진료를 받으시기 바랍니다.', 3218, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '갑상선암', '갑상선암', 'DIAGNOSIS', '갑상선 결절의 정확한 진단을 위해서는 내분비내과 또는 이비인후과(두경부외과) 전문의를 방문하는 것이 적절합니다. 갑상선 초음파로 결절의 성질을 평가하고, 악성이 의심되면 초음파 유도 하 세침흡인세포검사(FNAC)를 통해 조직학적 진단을 받을 수 있습니다. 결절이 2주 이상 지속되거나 빠르게 커진다면 빠른 시일 내에 전문의를 방문하시기 바랍니다.', 3219, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '갑상선암', '갑상선암', 'TREATMENT', '갑상선암의 표준 치료는 수술(갑상선 절제술)이며, 수술 범위는 암의 종류, 크기, 림프절 전이 여부에 따라 결정됩니다. 수술 후 고위험군에서는 방사성 요오드(I-131) 치료와 갑상선 호르몬 억제 요법이 병행되며, 재발 또는 전이성 병변에는 표적치료제(소라페닙, 렌바티닙)나 방사선 치료가 활용됩니다. 치료 계획은 내분비내과, 외과, 핵의학과, 방사선종양학과의 다학제적 협진을 통해 결정됩니다.', 3220, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '고환 종양', '고환종양', 'CAUSE', '고환 종양의 정확한 원인은 아직 완전히 밝혀지지 않았으나, 잠복고환이 가장 확립된 위험 인자입니다. 고환 외상, 염증, 호르몬 투여(에스트로겐), 정계정맥류 병력 등도 위험도를 다소 높일 수 있다는 보고가 있으나, 잠복고환에 비해 상대적으로 근거가 약합니다. 정기적인 고환 자가 검진과 이상이 발견되면 비뇨의학과 전문의의 진료를 받는 것이 중요합니다.', 3221, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '고환 종양', '고환종양', 'DEFINITION', '고환 종양은 고환을 구성하는 세포에서 발생하는 악성 신생물로, 생식세포 기원(세미노마, 비세미노마)이 95%를 차지합니다. 양쪽 고환 크기가 동일하더라도 고환 내 작은 종양이 있을 수 있으며, 잠복고환 병력, 가족력, 클라인펠터 증후군 등이 위험 인자입니다. 15~35세 남성에서 가장 흔하게 발생하며, 의심 증상이 있다면 비뇨의학과 전문의의 진료를 받으시기 바랍니다.', 3222, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '고환 종양', '고환종양', 'SYMPTOM', '고환이 점점 커지는 경우 고환 종양의 대표적인 증상으로, 통증이 없는 고환 종대(딱딱하고 무거운 느낌), 음낭 내 이물감이나 불쾌감이 특징입니다. 진행될 경우 복부나 허리 통증(후복막 림프절 전이), 호흡 곤란이나 기침(폐 전이), 여성형 유방(호르몬 분비 종양)도 나타날 수 있습니다. 고환의 크기 변화나 종대가 발견되면 즉시 비뇨의학과 전문의의 진료를 받으시기 바랍니다.', 3223, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '고환 종양', '고환종양', 'DIAGNOSIS', '고환 종양이 의심되면 비뇨의학과 전문의를 방문하여 음낭 초음파 검사, 혈청 종양 표지자(AFP, β-hCG, LDH) 검사, 흉부·복부·골반 CT를 통해 진단 및 병기를 결정합니다. 확정 진단을 위해 근치적 고환 적출술(서혜부 접근)을 시행하며, 진단과 치료를 동시에 진행하는 경우가 많습니다. 고환 이상이 발견되면 빠른 시일 내에 비뇨의학과를 방문하시기 바랍니다.', 3224, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '고환 종양', '고환종양', 'TREATMENT', '고환 종양의 기본 치료는 근치적 고환 적출술(서혜부 접근)로 확정 진단과 동시에 치료 효과를 기대합니다. 이후 병기에 따라 세미노마는 방사선 치료 또는 예방적 항암화학요법(카보플라틴), 비세미노마는 후복막 림프절 절제술 또는 항암화학요법(BEP 요법: 블레오마이신, 에토포사이드, 시스플라틴)이 시행됩니다. 통증 조절을 위한 진통제 투여도 병행되며, 치료 계획은 비뇨의학과 전문의와 상담하시기 바랍니다.', 3225, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '골수증식종양', '골수증식종양', 'CAUSE', '골수증식종양(MPN)의 발생 원인으로 가장 중요한 유전자 변이는 JAK2 V617F 변이로, 진성 적혈구증가증의 약 95%, 본태성 혈소판증가증과 골수섬유증의 약 50~60%에서 발견됩니다. 이 외에도 CALR(칼레티쿨린) 유전자 변이, MPL(트롬보포이에틴 수용체) 변이가 각각 본태성 혈소판증가증과 골수섬유증에서 발견됩니다. 정확한 유전자 검사는 혈액종양내과 전문의를 통해 받으시기 바랍니다.', 3226, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '골수증식종양', '골수증식종양', 'DEFINITION', '말초 통증이 지속될 때 골수증식종양 여부를 확인하기 위해서는 전혈구검사(CBC), 말초혈액 도말 검사, JAK2/CALR/MPL 유전자 변이 검사가 기본입니다. 골수 생검 및 흡인 검사로 최종 진단이 이루어지며, 이를 위해 혈액종양내과 전문의의 진료를 받는 것이 필요합니다. 원인 불명의 지속적인 말초 통증이나 혈구 수치 이상이 있다면 빠른 시일 내에 내과 또는 혈액종양내과를 방문하시기 바랍니다.', 3227, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '골수증식종양', '골수증식종양', 'SYMPTOM', '골수증식종양에서 체중 감소와 뼈 통증 외에도 비장·간 비대로 인한 좌상복부 포만감 또는 통증, 야간 발한, 피로감, 소양증(목욕 후 악화), 혈전증(뇌졸중, 심근경색, 심부정맥혈전증), 출혈 경향이 나타날 수 있습니다. 진성 적혈구증가증에서는 얼굴 홍조와 두통이, 본태성 혈소판증가증에서는 사지 말단 작열감이 특징적입니다. 증상이 있다면 혈액종양내과 전문의의 진료를 받으시기 바랍니다.', 3228, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '골수증식종양', '골수증식종양', 'DIAGNOSIS', '골수 생검과 혈액 검사를 위해 특별한 사전 준비는 필수적이지 않으나, 담당 의사의 지시에 따라 아스피린·항응고제 등 출혈 위험 약물을 일시 중단할 수 있습니다. 검사 전 금식은 일반적으로 필요하지 않으나, 진정제 사용 시 검사 전 수 시간 금식이 요구될 수 있습니다. 정확한 준비 사항은 담당 혈액종양내과 전문의 또는 간호팀에게 확인하시기 바랍니다.', 3229, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '골수증식종양', '골수증식종양', 'TREATMENT', '골수증식종양은 혈액종양내과 전문의가 있는 상급 종합병원에서 치료받는 것이 권장되며, 특히 골수 이식이 필요한 경우 이식 전문 센터에서 치료가 이루어집니다. 다른 의료기관에서 추가 의견(second opinion)을 구하는 것은 환자의 권리이며, 치료 계획의 최적화를 위해 도움이 될 수 있습니다. 현재 치료에 대한 궁금증이나 다른 치료 옵션에 대해서는 담당 혈액종양내과 전문의와 충분히 상담하시기 바랍니다.', 3230, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '골수형성이상증후군', '골수형성이상증후군', 'CAUSE', '골수형성이상증후군(MDS)의 주된 원인으로는 노화에 따른 조혈모세포의 유전자 변이 축적(특발성, 원발성)이 가장 흔합니다. 이차성 MDS는 이전의 항암화학요법(알킬화제, 토포이소머라제 억제제), 방사선 치료, 벤젠 등의 독성 물질 노출에 의해 발생합니다. 선천성 원인(판코니 빈혈, 다운증후군)도 있으며, 정확한 원인 파악을 위해 혈액종양내과 전문의의 진료가 필요합니다.', 3231, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '골수형성이상증후군', '골수형성이상증후군', 'DEFINITION', '골수형성이상증후군은 조혈모세포의 이형성(dysplasia)으로 인해 혈구 생성이 비효율적으로 이루어져 하나 이상의 혈구 수치(적혈구·백혈구·혈소판)가 감소하는 만성 혈액 질환입니다. 골수에서는 세포 수가 정상이거나 증가해 있음에도 불구하고 성숙한 혈구가 충분히 생성되지 않는 ''무효 조혈''이 특징이며, 일부에서는 급성 골수성 백혈병으로 진행할 수 있습니다.', 3232, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '골수형성이상증후군', '골수형성이상증후군', 'SYMPTOM', '골수형성이상증후군에서 빈혈은 가장 흔한 증상으로 피로감·호흡 곤란으로 나타나며, 백혈구 감소로 인한 반복적인 감염(열감 포함)도 흔히 관찰됩니다. 혈소판 감소로 인한 출혈 경향(멍, 잇몸 출혈)도 나타납니다. 이러한 증상들은 MDS에서 일반적으로 나타나는 증상이므로, 지속되거나 악화된다면 혈액종양내과 전문의의 진료를 받으시기 바랍니다.', 3233, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '골수형성이상증후군', '골수형성이상증후군', 'DIAGNOSIS', '골수형성이상증후군 진단을 위해서는 전혈구검사(CBC)에서 혈구 감소 소견, 말초혈액 도말 검사에서 이형성 혈구 확인, 골수 흡인 및 생검으로 이형성 소견 확인, 세포유전학 검사(염색체 이상), 분자유전학 검사(SF3B1 등 변이)가 필요합니다. 지속적인 빈혈, 반복 감염, 원인 불명의 출혈이 있다면 혈액종양내과 전문의를 방문하여 적절한 검사를 받으시기 바랍니다.', 3234, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '골수형성이상증후군', '골수형성이상증후군', 'TREATMENT', '골수형성이상증후군의 주요 치료법으로는 조혈모세포 이식(근치적 치료, 고위험군), 저메틸화제(아자시티딘, 데시타빈, 고위험군 증상 완화 및 생존 연장 효과), 면역억제요법(일부 저위험군), 적혈구 생성 자극제(ESA, 저위험 빈혈), 수혈(지지 요법)이 있습니다. 이식은 완치 가능성이 높으나 고령·동반 질환 시 적용이 제한적이고, 저메틸화제는 외래에서 투여 가능하다는 장점이 있습니다. 치료 선택은 위험도 분류와 환자 상태에 따라 혈액종양내과 전문의와 결정하시기 바랍니다.', 3235, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '교모세포종', '교모세포종', 'PREVENTION', '교모세포종의 명확한 예방 방법은 아직 확립되지 않았으나, 건강한 생활 습관이 전반적인 암 위험을 낮추는 데 도움이 될 수 있습니다. 과도한 전리방사선 노출 회피, 금연, 균형 잡힌 식단, 적절한 운동을 통한 면역 기능 유지가 권장되며, 유전성 증후군(NF1, TP53 변이 등)이 있는 경우 정기적인 신경과 검진이 중요합니다. 두통, 경련, 신경학적 이상이 지속된다면 신경과 전문의의 진료를 받으시기 바랍니다.', 3236, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '교모세포종', '교모세포종', 'CAUSE', '교모세포종은 대뇌의 신경교세포(성상세포)에서 발생하는 원발성 뇌종양으로, 대부분 특발성으로 발생하며 명확한 원인이 밝혀지지 않았습니다. 유전적 요인으로는 NF1, TP53, PTEN 유전자 이상이 관련될 수 있으나, 대부분의 경우는 유전성이 아닌 후천적 유전자 변이에 의해 발생합니다. 증상이 있다면 신경과 또는 신경외과 전문의의 진료를 받으시기 바랍니다.', 3237, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '교모세포종', '교모세포종', 'DEFINITION', '교모세포종(WHO 4등급 신경교종)은 악성도가 가장 높은 원발성 뇌종양으로, 진단은 뇌 MRI와 조직 생검(분자유전학적 검사 포함)으로 이루어집니다. 치료는 최대한 안전한 수술적 제거 후 방사선 치료와 테모졸로마이드 항암 요법을 병행하는 것이 표준입니다. 발병률은 인구 10만 명당 약 3~4명으로 비교적 드물지만 예후가 불량하며, 치료와 예후에 대해 신경외과 또는 신경종양내과 전문의와 상담하시기 바랍니다.', 3238, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '교모세포종', '교모세포종', 'SYMPTOM', '교모세포종에서 두통, 구토, 기억력 상실 외에도 경련·발작(새로 발생한 간질), 언어 장애(실어증), 한쪽 팔다리 약화(편마비), 시야 결손, 인격 변화나 행동 이상, 인지 기능 저하가 나타날 수 있습니다. 증상은 종양의 위치와 크기에 따라 다양하게 나타납니다. 이러한 신경학적 증상이 갑자기 발생하면 신경과 또는 신경외과 전문의의 즉각적인 진료가 필요합니다.', 3239, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '교모세포종', '교모세포종', 'DIAGNOSIS', '교모세포종 진단 후 다른 병원에서 추가 의견(second opinion)을 구하는 것은 환자의 권리이며, 특히 대학병원이나 암센터의 신경외과 또는 신경종양내과 전문의를 통해 치료 계획을 재검토받을 수 있습니다. 이를 위해 기존 영상 자료(MRI)와 병리 검사 결과를 지참하면 도움이 됩니다. 다학제 협진(신경외과, 방사선종양학과, 신경종양내과)을 제공하는 상급 종합병원의 뇌종양 전문 클리닉을 방문하시기 바랍니다.', 3240, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '교모세포종', '교모세포종', 'TREATMENT', '교모세포종은 뇌에서 발생하는 종양으로 월경 이상이나 과다출혈과는 직접적인 관련이 없으며, 이러한 증상은 부인과적 원인(자궁근종, 자궁내막 이상, 호르몬 불균형 등)을 먼저 고려해야 합니다. 교모세포종 치료는 신경외과, 방사선종양학과, 신경종양내과에서 이루어지며, 부인과적 증상은 산부인과 전문의의 진료를 받으시기 바랍니다. 두 증상이 동시에 있다면 각각 해당 전문과에서 평가받는 것이 필요합니다.', 3241, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '급성골수성백혈병', '급성골수성백혈병', 'MEDICATION', '급성 골수성 백혈병의 항암화학요법은 관해 유도(인다루비신 또는 다우노루비신 + 시타라빈)와 공고화 요법으로 진행되며, 완전 관해(혈구 수치 정상화, 골수 모세포 5% 미만)를 목표로 합니다. FLT3 변이가 있는 경우 미도스타우린 등 표적치료제가 추가되며, 관해 달성 후 재발 방지를 위해 조혈모세포 이식을 고려합니다. 치료 효과와 부작용은 환자 상태에 따라 다르므로 혈액종양내과 전문의와 상담하시기 바랍니다.', 3242, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '급성골수성백혈병', '급성골수성백혈병', 'CAUSE', '가죽 공장 등에서 벤젠, 포름알데히드 같은 유기용제와 화학약품에 장기간 노출되면 조혈모세포의 DNA 손상을 일으켜 급성 골수성 백혈병(AML) 발생 위험이 유의하게 증가합니다. 벤젠은 AML의 잘 알려진 직업성 위험 인자로, 세계보건기구(WHO)에서도 1군 발암 물질로 분류합니다. 유해 화학물질 취급 시 적절한 보호 장비 착용과 환기가 필수적이며, 관련 증상이 있으면 직업환경의학과 또는 혈액종양내과 전문의의 진료를 받으시기 바랍니다.', 3243, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '급성골수성백혈병', '급성골수성백혈병', 'DEFINITION', '급성 골수성 백혈병은 골수에서 비정상적인 미성숙 골수구(모세포)가 과증식하여 정상 혈구 생성을 억제하는 질환으로, 주요 증상으로는 빈혈(피로감, 창백함), 호중구 감소에 따른 반복 감염과 발열, 혈소판 감소로 인한 멍과 출혈이 있습니다. 이 외에도 뼈 통증, 림프절 종대, 간·비장 비대, 잇몸 침범(치은 비대)이 나타날 수 있으며, 급격히 진행하는 경우가 많아 즉각적인 혈액종양내과 전문의의 진료와 치료가 필요합니다.', 3244, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '급성골수성백혈병', '급성골수성백혈병', 'SYMPTOM', '급성골수성백혈병에서는 일반적으로 백혈구 수가 증가하고 혈소판 수가 감소하는 소견이 나타납니다. 미성숙 백혈구(모세포)가 골수를 채워 정상 혈소판 생성을 억제하기 때문에 혈소판 감소증이 동반됩니다. 다만 일부 환자에서는 백혈구 수가 정상이거나 오히려 감소할 수도 있으므로, 정확한 진단을 위해 혈액종양 전문의의 진료와 골수 검사를 받으시길 권고합니다.', 3245, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '급성골수성백혈병', '급성골수성백혈병', 'DIAGNOSIS', '급성골수성백혈병은 진행 속도가 빠른 혈액암으로, 진단 후 치료 시작이 늦어질수록 예후가 불량해질 수 있습니다. 두 달이 경과한 경우에도 치료는 가능하지만, 병기 진행 여부와 환자 상태를 재평가하는 것이 중요합니다. 지체 없이 혈액종양 전문의를 찾아 현재 질병 상태를 확인하고 적절한 치료 계획을 수립하시길 강력히 권고합니다.', 3246, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '급성골수성백혈병', '급성골수성백혈병', 'TREATMENT', '급성골수성백혈병의 치료는 관해 유도 항암화학요법과 공고 항암화학요법이 표준 치료법입니다. 사이타라빈과 안트라사이클린 계열 약물의 병합요법이 대표적이며, 특정 유전자 변이(FLT3, IDH1/2 등)가 있는 경우 표적치료제를 병용하기도 합니다. 고위험군 환자에서는 동종 조혈모세포 이식이 권장되므로, 담당 혈액종양 전문의와 상세한 치료 계획을 상담하시기 바랍니다.', 3247, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '급성림프모구백혈병', '급성림프모구백혈병', 'CHECKUP', '급성림프모구백혈병 검진 결과를 관리하려면 말초혈액 검사(CBC), 골수 검사 결과, 면역표현형 및 염색체·분자유전학 검사 결과를 체계적으로 수집해야 합니다. 치료 반응을 평가하는 미세잔존질환(MRD) 수치도 중요한 관리 지표입니다. 검진 결과의 해석과 치료 계획은 반드시 혈액종양 전문의와 상담하여 진행하시기 바랍니다.', 3248, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '급성림프모구백혈병', '급성림프모구백혈병', 'CAUSE', '멍이 자주 들고 코피가 나오는 증상은 급성림프모구백혈병의 원인이 아니라 결과(증상)에 해당합니다. 이는 비정상 림프모구가 골수를 침범하여 정상 혈소판 생성을 억제함으로써 발생하는 출혈 경향입니다. 해당 증상이 지속된다면 지체 없이 혈액종양 전문의를 방문하여 정밀 혈액 검사를 받으시길 권고합니다.', 3249, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '급성림프모구백혈병', '급성림프모구백혈병', 'DEFINITION', '급성림프모구백혈병은 림프구 전구세포(림프모구)가 골수에서 악성으로 증식하여 정상 조혈을 방해하는 혈액암입니다. 빠르게 진행되며 빈혈·출혈 경향·발열·감염, 림프절 및 간비장 종대 등의 증상이 나타납니다. 소아에서 가장 흔한 백혈병으로 성인에도 발생하며, 진단 즉시 전문의 치료가 필요합니다.', 3250, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '급성림프모구백혈병', '급성림프모구백혈병', 'SYMPTOM', '급성림프모구백혈병의 주요 증상으로 빈혈로 인한 피로감·무기력감, 체중 감소가 포함됩니다. 그러나 온몸이 붓는 부종은 전형적인 증상보다는 일부 환자에서 간·비장 종대나 림프절 비대로 복부 팽만감이 나타나는 경우가 있습니다. 이러한 증상들이 나타날 경우 혈액종양 전문의의 진료를 받으시기 바랍니다.', 3251, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '급성림프모구백혈병', '급성림프모구백혈병', 'DIAGNOSIS', '중추신경계 증상, 구토, 정신 증상이 있는 경우 급성림프모구백혈병의 중추신경계 침범을 의심하여 말초혈액 검사, 골수 검사, 요추천자(뇌척수액 검사)가 필요합니다. 뇌 MRI 및 CT도 병변 확인에 도움이 됩니다. 정확한 진단을 위해 혈액종양 전문의와 신경과 전문의의 협진이 필요하므로 전문 의료기관을 방문하시길 권고합니다.', 3252, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '급성림프모구백혈병', '급성림프모구백혈병', 'TREATMENT', '급성림프모구백혈병 항암치료 중 골수 기능 회복 여부는 정기적인 말초혈액 검사(CBC)와 골수 검사를 통해 확인합니다. 관해 유도 치료 후 골수에서 모세포가 5% 미만으로 감소하고 정상 혈구 수치가 회복되면 완전관해로 판정합니다. 치료 중 골수 기능 회복 단계 평가는 담당 혈액종양 전문의가 정기적으로 시행합니다.', 3253, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소 낭종', '난소낭종', 'PREVENTION', '난소 낭종 예방을 위해 적정 체중 유지, 규칙적인 운동, 호르몬 균형에 영향을 미치는 환경호르몬(내분비 교란물질) 노출 최소화가 도움이 됩니다. 정기적인 산부인과 검진을 통해 조기 발견하는 것도 중요합니다. 경구 피임약이 일부 낭종 예방에 효과적일 수 있으나 복용 여부는 산부인과 전문의와 상담 후 결정하시기 바랍니다.', 3254, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소 낭종', '난소낭종', 'CAUSE', '난소 낭종은 남성에게는 발생하지 않으므로 외할아버지의 아버지(남성)에서 난소 낭종 발생은 의학적으로 불가능합니다. 질문에 혼동이 있는 것으로 보이며, 실제로 여성 가족 중 난소 낭종이나 난소암 병력이 있다면 유전적 요인이 관련될 수 있습니다. 가족력에 대한 정확한 파악과 유전적 위험도 평가를 위해 산부인과 전문의와 상담하시기 바랍니다.', 3255, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소 낭종', '난소낭종', 'DEFINITION', '난소 낭종은 난소 내부 또는 표면에 액체나 반고체 물질이 차 있는 주머니 모양의 종괴를 말합니다. 배란 과정에서 생기는 기능성 낭종이 가장 흔하며, 자궁내막증·다낭성 난소 증후군·양성 종양 등 다양한 원인에 의해서도 발생합니다. 대부분 양성이지만 크기가 크거나 증상이 있는 경우 산부인과 전문의의 진료가 필요합니다.', 3256, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소 낭종', '난소낭종', 'SYMPTOM', '난소 낭종의 증상으로는 복부 팽만감, 골반통이나 복통 외에도 성교통, 월경 불규칙, 배뇨 빈도 증가, 배변 시 불편감이 나타날 수 있습니다. 낭종이 파열되거나 꼬임(염전)이 발생하면 갑작스럽고 극심한 복통, 오심·구토, 발열 등 응급 증상이 생길 수 있습니다. 이러한 증상 발생 시 즉시 산부인과 전문의의 진료를 받으시기 바랍니다.', 3257, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소 낭종', '난소낭종', 'DIAGNOSIS', '난소 낭종 진단은 골반 초음파 검사를 통해 위치, 크기, 내부 성상을 확인하는 것이 일차적입니다. 필요에 따라 혈액 종양표지자 검사(CA-125 등)와 MRI·CT를 추가로 시행할 수 있습니다. 초음파에서 악성 의심 소견이 있거나 폐경 후 낭종이 발견된 경우 산부인과 전문의의 정밀 평가가 반드시 필요합니다.', 3258, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소 낭종', '난소낭종', 'TREATMENT', '난소 낭종의 재발을 줄이기 위해 정기적인 산부인과 초음파 검진이 중요하며, 산부인과 전문의의 판단에 따라 경구 피임약이 재발 예방에 도움이 될 수 있습니다. 건강한 체중 유지, 규칙적인 운동, 스트레스 관리도 호르몬 균형 유지에 도움이 됩니다. 낭종의 종류와 재발 위험도에 따라 치료 방침이 달라지므로 담당 전문의와 지속적으로 상담하시기 바랍니다.', 3259, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소암', '난소암', 'CHECKUP', '난소암은 초기 증상이 없어 상당수가 3기 이후에 발견되므로 정기 검진이 매우 중요합니다. 고위험군(BRCA 유전자 변이, 가족력 등)은 산부인과 전문의와 상담하여 정기적인 골반 초음파와 CA-125 혈액 검사를 받는 것이 권장됩니다. 조기 발견을 위해 이상 증상(복부 팽만, 골반통 등)이 지속될 경우 즉시 전문의의 진료를 받으시기 바랍니다.', 3260, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소암', '난소암', 'MEDICATION', '난소암에서 약물 저항성은 화학요법 후 암세포가 약물을 배출하거나 세포사멸 경로를 회피하는 기전으로 발생합니다. 저항성 발생 시에는 다른 계열의 항암제로 전환하거나, PARP 억제제(BRCA 변이 시), 베바시주맙 등의 표적치료제, 면역항암제 병용이 고려됩니다. 약물 저항성 관리는 반드시 부인종양 전문의와 함께 개별화된 치료 계획을 수립해야 합니다.', 3261, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소암', '난소암', 'PREVENTION', '난소암 예방을 위해 정기적인 산부인과 검진이 권장되며, 골반 초음파 검사와 혈액 종양표지자 CA-125 검사가 도움이 됩니다. 가족력이 있거나 BRCA1/2 유전자 변이가 의심되는 경우 유전자 검사도 고려할 수 있습니다. 정기 검진 주기와 검사 방법은 개인의 위험도에 따라 달라지므로 부인과 전문의와 상담하시기 바랍니다.', 3262, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소암', '난소암', 'CAUSE', '유방암과 난소암은 BRCA1·BRCA2 유전자 변이를 공통으로 공유하기 때문에 유방암 병력이 있는 경우 난소암 위험이 유의미하게 높습니다. BRCA1 변이 보유자의 난소암 평생 위험도는 39~46%, BRCA2는 12~20%로 일반 인구 대비 현저히 높습니다. 유방암 병력이 있다면 부인종양 전문의와 상담하여 유전자 검사 및 난소암 조기 발견을 위한 정기 검진 계획을 수립하시기 바랍니다.', 3263, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소암', '난소암', 'DEFINITION', '자궁경부암은 주로 인유두종바이러스(HPV) 감염에 의해 자궁 경부(목)에서 발생하며, HPV 백신으로 예방이 가능합니다. 난소암은 난소에서 발생하며 뚜렷한 조기 증상이 없어 진단 시 진행된 경우가 많고, 유전적 요인(BRCA 변이)이 중요한 위험인자입니다. 두 암 모두 부인과 암이지만 발생 위치, 원인, 증상, 치료법이 다르므로 각각 전문의 진료가 필요합니다.', 3264, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소암', '난소암', 'SYMPTOM', '소화 불량과 복부 팽만, 복부 딱딱한 느낌이 지속된다면 난소암을 포함한 복강 내 이상을 감별해야 합니다. 정확한 진단을 위해 골반 초음파, 복부 CT, CA-125 등 종양표지자 혈액 검사가 필요합니다. 증상이 지속될 경우 지체하지 말고 부인과 또는 소화기내과 전문의를 방문하여 정밀 검사를 받으시길 권고합니다.', 3265, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소암', '난소암', 'DIAGNOSIS', '유전성 난소암 관련 유전자 검사로 가장 중요한 것은 BRCA1과 BRCA2 유전자 변이 검사입니다. 가족 중 난소암이나 유방암 환자가 있다면 유전 상담을 통해 BRCA 검사 대상 여부를 평가받고, 필요 시 확장 패널 유전자 검사도 고려할 수 있습니다. 유전자 검사와 결과 해석은 임상유전학 전문의 또는 부인종양 전문의와 반드시 상담하여 진행하시기 바랍니다.', 3266, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소암', '난소암', 'TREATMENT', '난소암 치료를 위해서는 부인종양 전문의가 주치의 역할을 하며, 수술·항암화학요법·방사선종양 전문의가 협력하여 치료합니다. 출혈과 복통 완화를 위해 수술적 치료(종양 제거)와 함께 통증 조절을 위한 완화의학팀의 지원도 중요합니다. 증상 관리와 치료 계획 수립을 위해 종합병원의 부인종양과를 방문하시기 바랍니다.', 3267, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소의 양성 종양', '난소의양성종양', 'CAUSE', '난소의 양성 종양은 생식 연령대 여성에서 더 빈번히 발생하는데, 이는 배란 주기가 활발하여 기능성 낭종이 생기기 쉽고 에스트로겐 등 여성호르몬이 종양 성장에 영향을 미치기 때문입니다. 임신·출산 경험, 배란 유도제 사용 등 생식 활동과 관련된 요인들이 발생 위험을 높일 수 있습니다. 정기적인 산부인과 검진을 통해 조기에 발견하고 전문의의 관리를 받으시기 바랍니다.', 3268, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소의 양성 종양', '난소의양성종양', 'DEFINITION', '난소의 양성 종양은 아랫배 통증, 하복부 압박감, 배변 시 불편감 등의 증상을 유발할 수 있으며, 크기가 작은 경우 무증상이기도 합니다. 종양이 커지면 빈뇨, 변비, 성교통, 월경 불규칙 등이 동반될 수 있습니다. 증상이 지속된다면 산부인과 전문의를 방문하여 골반 초음파 검사를 받아보시길 권고합니다.', 3269, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소의 양성 종양', '난소의양성종양', 'SYMPTOM', '난소의 양성 종양에 의한 하복부 통증, 요통, 빈뇨 외에도 복부 팽만감, 성교통, 월경 불규칙(월경 과다 또는 결핍), 변비, 오심·구토가 나타날 수 있습니다. 종양이 염전(꼬임)되거나 파열되는 응급 상황에서는 갑작스러운 심한 복통과 발열이 발생합니다. 증상의 원인을 정확히 파악하기 위해 산부인과 전문의의 진료를 받으시기 바랍니다.', 3270, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소의 양성 종양', '난소의양성종양', 'DIAGNOSIS', '복부 통증과 팽만감이 있을 때 난소의 양성 종양 확인을 위해 골반 초음파 검사가 가장 우선적으로 시행됩니다. 추가로 혈액 종양표지자 검사(CA-125, CA19-9)와 복부·골반 MRI 또는 CT가 필요할 수 있습니다. 정확한 진단과 치료 방침 결정을 위해 산부인과 전문의의 진료를 받으시기 바랍니다.', 3271, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '난소의 양성 종양', '난소의양성종양', 'TREATMENT', '난소의 양성 종양은 배란 관련 기능성 낭종, 자궁내막증, 성숙 기형종(피부양 낭종), 장액성·점액성 낭선종 등이 주요 원인입니다. 치료는 크기, 종류, 증상 유무에 따라 결정되며, 경과 관찰, 약물치료, 복강경 수술 또는 개복 수술이 시행됩니다. 극심한 복통이 있는 경우 응급 상황일 수 있으므로 즉시 산부인과 전문의의 진료를 받으시기 바랍니다.', 3272, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '뇌종양', '뇌종양', 'CAUSE', '두통, 발작, 보행장애, 발음 부정확 등은 뇌종양의 원인이 아닌 증상(결과)에 해당합니다. 뇌종양의 발생 원인으로는 이온화 방사선 노출, 일부 유전적 소인(신경섬유종증 등)이 알려져 있으나 대부분은 원인이 불명확합니다. 위의 신경학적 증상들이 지속된다면 신경외과 또는 신경과 전문의를 방문하여 뇌 MRI 등 정밀 검사를 받으시길 권고합니다.', 3273, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '뇌종양', '뇌종양', 'DEFINITION', '뇌종양은 뇌와 척수에서 발생하는 세포의 비정상적 증식으로, 원발성(뇌 자체 발생)과 전이성(다른 암에서 전이)으로 나뉩니다. 두통과 어지러움은 뇌종양의 흔한 증상이 될 수 있으나, 뇌압 상승이나 종양 위치에 따라 나타나는 것이므로 단독으로는 진단 근거가 되기 어렵습니다. 두통과 어지러움이 지속되거나 점차 악화된다면 신경외과 또는 신경과 전문의를 방문하여 뇌 MRI 검사를 받으시길 권고합니다.', 3274, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '뇌종양', '뇌종양', 'SYMPTOM', '뇌종양의 증상은 종양의 위치에 따라 다르게 나타납니다. 전두엽 종양은 성격 변화·인지 저하, 두정엽은 감각 이상·공간 지각 장애, 측두엽은 언어 장애·기억 이상, 소뇌는 균형 이상·보행 장애, 뇌간은 연하 장애·안면 마비·호흡 장애를 유발합니다. 증상에 따라 종양 위치를 유추할 수 있으므로, 신경학적 증상이 있다면 신경외과 전문의와 MRI 검사를 받으시기 바랍니다.', 3275, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '뇌종양', '뇌종양', 'DIAGNOSIS', '뇌종양이 운동 피질 또는 척수로 향하는 신경 전도로를 침범하면 반신 운동 마비나 보행 장애가 발생하며, 감각 피질 침범 시 저림·감각 둔화 등 감각 이상이 나타납니다. 진단을 위해 뇌 MRI(조영증강 포함), 신경학적 검진, 필요 시 뇌전도(EEG) 및 신경전도 검사가 시행됩니다. 운동·감각 이상 증상이 있다면 신경외과 또는 신경과 전문의의 진료를 받으시기 바랍니다.', 3276, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '뇌종양', '뇌종양', 'TREATMENT', '뇌종양 수술 후 합병증으로 뇌부종, 수술 부위 출혈, 감염(뇌막염, 뇌농양), 뇌척수액 누출 등이 발생할 수 있습니다. 또한 종양 위치에 따라 운동·언어·인지 기능 저하, 시야 장애, 뇌전증(간질) 발작이 나타날 수 있습니다. 수술 후 합병증 예방과 관리를 위해 담당 신경외과 전문의의 지속적인 추적 관찰이 반드시 필요합니다.', 3277, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '다발골수종', '다발골수종', 'CHECKUP', '다발골수종 확인을 위해 혈청 단백 전기영동 및 면역고정 전기영동 검사, 혈청 유리경쇄 검사가 기본적으로 시행됩니다. 골수 검사(골수 천자 및 생검)를 통해 골수 내 형질세포 비율을 확인하며, 형광동소교잡법(FISH)으로 염색체 이상도 평가합니다. 정확한 진단과 병기 결정을 위해 혈액종양 전문의를 방문하시기 바랍니다.', 3278, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '다발골수종', '다발골수종', 'MEDICATION', '다발골수종의 주요 치료 약물로는 보르테조밉(프로테아솜 억제제), 레날리도마이드·탈리도마이드(면역조절제), 덱사메타손이 병용 사용됩니다. 최근에는 다라투무맙(항CD38 단클론항체) 등 새로운 표적치료제도 사용됩니다. 약물 선택과 복용 방법은 환자의 나이, 신장 기능, 이식 가능 여부 등에 따라 달라지므로 혈액종양 전문의와 충분히 상담하시기 바랍니다.', 3279, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '다발골수종', '다발골수종', 'CAUSE', '다발골수종의 합병증은 주로 암세포(형질세포)의 골수 침범과 M단백질 과생산으로 발생합니다. 뼈 파괴로 인한 고칼슘혈증과 병적 골절, 신장 기능 저하(골수종 신증), 빈혈, 면역 기능 저하로 인한 감염 취약성, 과점도 증후군 등이 주요 합병증입니다. 합병증 예방과 관리를 위해 정기적인 혈액종양 전문의의 추적 관찰이 필요합니다.', 3280, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '다발골수종', '다발골수종', 'DEFINITION', '다발골수종은 골수 내 형질세포(B림프구에서 분화)가 악성 증식하여 비정상 단백(M단백)을 과도하게 생산하는 혈액암입니다. 이로 인해 단백뇨(빈스존스 단백), 적혈구 감소로 인한 빈혈, 신장 손상이 나타날 수 있어 신장 조직 검사에서 이상이 발견되기도 합니다. 다발골수종 의심 시 혈액종양 전문의를 방문하여 골수 검사와 특수 혈액 검사를 받으시기 바랍니다.', 3281, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '다발골수종', '다발골수종', 'SYMPTOM', '다발골수종에서 형질세포가 골수 내에서 과증식하면 정상 적혈구 생성(조혈)이 억제되어 빈혈이 발생합니다. 또한 암세포가 분비하는 M단백이 적혈구에 달라붙어 가성 적혈구 연전 형성을 유발하고 적혈구 수명을 단축시켜 빈혈을 악화시킵니다. 형질세포 증식 정도와 빈혈의 심각도는 비례하는 경향이 있으며, 치료로 형질세포가 감소하면 빈혈도 호전됩니다.', 3282, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '다발골수종', '다발골수종', 'DIAGNOSIS', '골다공증과 함께 다발골수종이 의심되는 경우 혈액종양 내과(또는 내과 혈액종양 분과)가 있는 대학병원이나 종합병원을 방문하는 것이 적합합니다. 혈청 단백 전기영동, 골수 검사 등 전문적인 검사가 필요하므로 혈액종양 전문의의 진료를 받으시길 강력히 권고합니다.', 3283, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '다발골수종', '다발골수종', 'TREATMENT', '다발골수종에서 방사선 치료는 뼈 통증 완화와 국소 종양 억제에 사용되며, 항암치료와 병용 시 전신 골수종 세포 감소와 국소 증상 조절을 함께 달성할 수 있습니다. 보르테조밉, 레날리도마이드 등의 항암제로 골수종 세포를 전신적으로 억제하면서 방사선으로 통증이 심한 뼈 병변 부위를 추가 치료하는 방식으로 시너지 효과를 기대합니다. 최적 치료 조합은 병기와 환자 상태에 따라 결정되므로 담당 혈액종양 전문의와 상담하시기 바랍니다.', 3284, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '담관암', '담관암', 'CHECKUP', '담관암 진단을 위해 혈액 검사(CA19-9, CEA, 간기능 검사) 외에 복부 초음파, CT, MRI(MRCP), 내시경 역행성 담췌관 조영술(ERCP), 내시경 초음파(EUS) 등이 시행됩니다. ERCP나 EUS를 통해 담즙 또는 조직 세포진 검사로 확진이 가능합니다. 황달 등 증상이 있다면 소화기내과 또는 외과 전문의를 방문하여 정밀 검사를 받으시기 바랍니다.', 3285, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '담관암', '담관암', 'MEDICATION', '담관암에서 황달이 있는 경우 담관 폐색을 해소하기 위해 내시경 스텐트 삽입술(ERCP) 또는 경피경간 담관 배액술(PTBD)이 효과적인 치료법입니다. 수술 가능한 경우 근치적 절제술이 최선이며, 수술 불가 시 항암화학요법(젬시타빈+시스플라틴)과 방사선 치료도 사용됩니다. 치료 방법은 담관암의 위치와 병기에 따라 달라지므로 소화기내과·외과 전문의와 상담하시기 바랍니다.', 3286, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '담관암', '담관암', 'PREVENTION', '담관암 예방을 위해 원발성 경화성 담관염, 담관 결석, 간흡충 감염 등 위험 요인을 조기에 치료하고 관리하는 것이 중요합니다. 간흡충(간디스토마) 감염 예방을 위해 민물고기 생식을 피하고, 정기적인 복부 초음파 검진을 받는 것이 권장됩니다. 음주를 줄이고 건강한 생활습관을 유지하며, 관련 증상(황달, 우상복부 통증)이 있으면 즉시 소화기내과 전문의의 진료를 받으시기 바랍니다.', 3287, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '담관암', '담관암', 'CAUSE', '담관암에서 유전적 요인의 역할은 제한적이나, BRCA1/2 변이, Lynch 증후군(MLH1, MSH2 등), 선천성 담관 기형(담관낭종) 등 유전적 소인이 위험도를 높일 수 있습니다. 유전성 담관 기형이 있는 경우 악성화 위험이 있어 정기 검진이 필요합니다. 가족력이 있거나 유전적 위험이 의심된다면 유전 상담과 함께 소화기내과 전문의의 정기 검진을 받으시길 권고합니다.', 3288, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '담관암', '담관암', 'DEFINITION', '담관암 4기는 원격 전이가 있는 진행된 병기로 완치적 수술이 어렵고 5년 생존율이 낮습니다. 항암화학요법(젬시타빈+시스플라틴)과 담관 폐색 완화 시술로 생존 기간 연장을 목표로 합니다. 생활에서는 고단백·고영양 식이를 유지하고 체력을 보존하며, 완화의학팀의 지원을 받아 삶의 질을 높이는 것이 중요하므로 담당 전문의와 적극적으로 상담하시기 바랍니다.', 3289, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '담관암', '담관암', 'SYMPTOM', '담관암의 주요 증상인 황달은 암으로 인한 담관 폐색 때문에 담즙이 혈중으로 역류하여 발생하며, 피부와 공막(눈 흰자위)이 노랗게 변하고 소변이 진한 갈색, 대변이 회백색으로 변합니다. 피로감은 간 기능 저하와 전신 소모 상태로 인해 나타납니다. 이러한 증상이 있다면 소화기내과 전문의를 즉시 방문하여 검사를 받으시기 바랍니다.', 3290, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '담관암', '담관암', 'DIAGNOSIS', '황달(피부와 공막의 황색 변화) 증상이 있을 때 담관암 진단을 위해 소화기내과 또는 간담췌외과가 있는 종합병원이나 대학병원을 방문하시기 바랍니다. 복부 초음파, CT, MRI를 통한 영상 검사와 담관 내시경(ERCP)을 시행하며, 담관 조직 검사로 확진합니다. 황달은 담관암 외에도 다양한 원인이 있으므로 조속히 전문의 진료를 받으시길 권고합니다.', 3291, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '담관암', '담관암', 'TREATMENT', '담관암 치료는 종양 위치와 진행 상태에 따라 크게 달라집니다. 수술 가능한 조기 담관암에서는 근치적 절제술이 표준 치료이며, 절제 불가 또는 전이 담관암에는 젬시타빈+시스플라틴 항암화학요법이 1차 치료로 사용됩니다. 황달이 있는 경우 ERCP 또는 경피경간 담관 배액술로 담관 폐색을 해소하는 시술이 선행되며, 방사선 치료도 보조적으로 활용됩니다.', 3292, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '담낭암', '담낭암', 'PREVENTION', '고지방·고칼로리 식이, 비만, 담석을 유발하는 식습관은 담낭암 위험을 높이는 것으로 알려져 있습니다. 특히 동물성 지방과 가공식품 과다 섭취는 담석 형성을 촉진하며, 담석은 담낭 점막에 만성 자극을 주어 발암 위험을 높입니다. 담낭암 예방을 위해 채소·과일이 풍부한 균형 식단, 체중 조절, 정기적인 복부 초음파 검진이 권장됩니다.', 3293, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '담낭암', '담낭암', 'CAUSE', '담낭암은 담석·담낭 용종·만성 담낭염 등에 의한 담낭 점막의 만성 자극이 주요 원인이며, 담석이 있는 환자에서 발생 위험이 높습니다. 증상으로는 우상복부 통증, 황달, 오심·구토, 체중 감소, 식욕 부진, 발열이 나타날 수 있습니다. 초기에는 무증상이 많아 조기 발견이 어려우므로, 담석이나 담낭 용종이 있다면 소화기내과 전문의의 정기 추적 관찰이 필요합니다.', 3294, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '담낭암', '담낭암', 'DEFINITION', '담낭암 진단 후 나타날 수 있는 증상으로는 우상복부 통증 및 압통, 황달(피부·눈의 황색 변화), 체중 감소, 식욕 부진, 오심·구토, 피로감이 있습니다. 진행된 경우 복부 종괴가 만져지거나 복수가 차기도 합니다. 증상과 진행 속도는 개인마다 다르므로 담당 소화기외과 또는 간담췌외과 전문의와 지속적으로 상담하시기 바랍니다.', 3295, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '담낭암', '담낭암', 'SYMPTOM', '담낭암에서 가장 흔히 나타나는 증상은 우상복부 통증과 불편감이며, 담관 침범 시 황달이 동반됩니다. 설사보다는 오심·구토, 식욕 부진, 소화 불량이 더 흔한 소화기 증상입니다. 이러한 증상들은 담석증이나 담낭염과 유사하여 감별이 필요하므로, 지속적인 증상이 있다면 소화기내과 전문의의 진료를 받으시기 바랍니다.', 3296, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '담낭암', '담낭암', 'DIAGNOSIS', '체중 감소, 피로감, 황달이 동반된 경우 담낭암 외에도 담관암, 췌장암, 간암, 담석증 등 다양한 소화기 질환의 가능성이 있습니다. 정확한 진단을 위해 복부 초음파, CT 또는 MRI, 혈액 검사(간기능, CA19-9 등)가 필요합니다. 지체하지 말고 소화기내과 또는 외과 전문의를 방문하여 정밀 검사를 받으시길 강력히 권고합니다.', 3297, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '담낭암', '담낭암', 'TREATMENT', '담낭암의 항암화학요법으로는 젬시타빈+시스플라틴 병용요법이 표준 치료이며, 수술 후 보조항암요법으로도 사용됩니다. 수술(담낭절제술+주변 조직 절제)이 완치를 목표로 하는 유일한 치료법이나, 수술 불가 시 항암화학요법과 방사선 치료를 병용합니다. 최근 면역항암제(PDL1 발현 시) 및 표적치료도 도입되어 효과가 향상되고 있으며, 담당 전문의와 최적 치료 계획을 상담하시기 바랍니다.', 3298, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장암', '대장암', 'CHECKUP', '대장암 검진(대장 내시경) 전 식이 제한은 장 정결 효과를 높이기 위한 것으로, 붉은 육류(적색 음식)는 장 점막에 잔류물을 남겨 검사 시야를 방해할 수 있습니다. 육식(특히 붉은 고기) 과다 섭취는 대장암 발생 위험 요인이기도 하므로, 평소 섭취를 줄이는 것이 대장암 예방에 도움이 됩니다. 50세 이상 또는 가족력이 있는 경우 5~10년마다 대장 내시경 검진이 권장됩니다.', 3299, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장암', '대장암', 'DIET_LIFE', '대장 양성 종양(선종성 용종) 예방을 위해 채소·과일·통곡물 등 식이섬유가 풍부한 식단을 섭취하고, 붉은 육류와 가공육 섭취를 줄이는 것이 중요합니다. 규칙적인 운동, 적정 체중 유지, 금연, 절주도 위험을 낮춥니다. 대장 내시경 검진을 정기적으로 받아 선종을 조기에 발견하고 제거하는 것이 대장암으로의 진행을 막는 가장 효과적인 방법입니다.', 3300, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장암', '대장암', 'MEDICATION', '대장암 항암제로는 플루오로우라실(5-FU)·카페시타빈(DNA 합성 억제), 옥살리플라틴(DNA 가교 형성), 이리노테칸(토포이소머라제 억제) 등이 있습니다. 표적치료제로는 베바시주맙(항VEGF 혈관신생 억제), 세툭시맙·파니투무맙(항EGFR, KRAS 야생형 한정)이 사용되며, 면역항암제는 MSI-H/dMMR인 경우 효과적입니다. 부작용으로 오심·구토, 말초신경병증, 골수 억제, 설사 등이 발생할 수 있으므로 담당 전문의의 지도 하에 치료받으시기 바랍니다.', 3301, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장암', '대장암', 'PREVENTION', '포화지방 및 총 지방 섭취를 줄이면 비만을 예방하고 인슐린 저항성을 낮춰 대장암을 포함한 대사성 질환 위험을 감소시킵니다. 뇌졸중과 심장병 예방을 위해서는 트랜스지방과 포화지방을 줄이고 오메가-3 등 불포화지방산을 늘리는 식습관이 중요합니다. 균형 잡힌 식단, 규칙적인 운동, 금연, 절주가 이들 질병 예방의 핵심 생활습관입니다.', 3302, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장암', '대장암', 'EXERCISE', '대장암 치료 중이더라도 피로감과 체력을 고려하여 가벼운 걷기, 스트레칭, 수중 운동(수영, 아쿠아로빅) 등 저강도 유산소 운동이 안전하게 권장됩니다. 규칙적인 운동은 장 운동 촉진, 피로감 개선, 심리적 안정에 도움이 됩니다. 운동 종류와 강도는 수술 부위, 항암치료 상태, 체력에 따라 달라지므로 담당 전문의와 상담 후 개인에게 맞는 운동 계획을 세우시기 바랍니다.', 3303, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장암', '대장암', 'CAUSE', '대장암 발생과 관련된 식습관으로는 붉은 육류 및 가공육(햄, 소시지 등) 과다 섭취, 식이섬유 부족, 고지방·저섬유 식단이 주요 위험 요인입니다. 이외에도 음주, 흡연, 비만, 좌식 생활습관이 대장암 발생 위험을 높입니다. 대장암 예방을 위해 채소·과일·통곡물 위주의 식단으로 전환하고 규칙적인 운동을 실천하시기 바랍니다.', 3304, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장암', '대장암', 'DEFINITION', '식이섬유는 장내 발암물질과 결합하여 대장 통과 시간을 단축하고 발암물질의 장 점막 접촉을 줄여 대장암 발생 위험을 낮추는 데 도움이 됩니다. 채소, 과일, 통곡물, 콩류를 충분히 섭취하는 것이 대장암 예방에 권장되는 식이 습관입니다. 식이섬유 섭취와 함께 규칙적인 운동, 정기적인 대장 내시경 검진을 병행하는 것이 효과적입니다.', 3305, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장암', '대장암', 'SYMPTOM', '대장암 초기 증상으로 혈변, 배변 습관 변화(변비·설사), 잔변감, 복통 등이 있을 경우 즉시 대장 내시경 검사를 받는 것이 중요합니다. 50세 이상은 증상이 없더라도 정기적인 분변 잠혈 검사 또는 대장 내시경 검진이 권장됩니다. 증상이 있다면 소화기내과 전문의를 방문하여 조기 검진과 정확한 진단을 받으시기 바랍니다.', 3306, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장암', '대장암', 'DIAGNOSIS', '대장암 진단 후 치료 방침에 의문이 있거나 불안한 경우 다른 의료기관에서 이차 소견(second opinion)을 구하는 것은 환자의 권리이자 권장되는 사항입니다. 특히 수술 범위, 항암 치료 여부 등 중요한 결정 사항이 있을 때 전문 대학병원의 소화기외과 또는 소화기내과 전문의에게 추가 의견을 구하는 것이 도움이 될 수 있습니다.', 3307, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장암', '대장암', 'TREATMENT', '대장암 수술 후 항암치료는 수술 단독 치료보다 재발률을 낮추고 생존율을 높이기 위한 보조 치료입니다. 2~3기 대장암에서 옥살리플라틴 기반 FOLFOX 또는 CAPOX 요법이 표준 보조항암화학요법으로 사용됩니다. 방사선 치료는 주로 직장암에서 수술 전·후에 병용되며, 대장암의 위치와 병기에 따라 치료 방식이 달라지므로 담당 소화기외과·종양내과 전문의와 상담하시기 바랍니다.', 3308, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장의 양성 종양', '대장의양성종양', 'PREVENTION', '대장 양성 종양(선종성 용종) 예방을 위해 규칙적인 대장 내시경 검진을 통해 용종을 조기에 발견하고 제거하는 것이 가장 중요합니다. 식이섬유가 풍부한 채소·과일·통곡물 섭취, 붉은 육류와 가공육 제한, 규칙적인 운동, 금연, 절주가 용종 발생 위험을 낮춥니다. 가족력이 있는 경우 더 이른 나이(45세 이전)부터 정기 검진을 시작하는 것이 권장됩니다.', 3309, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장의 양성 종양', '대장의양성종양', 'CAUSE', '대장의 양성 종양(선종 등) 발생과 식이의 관계에서 고지방·저섬유 식단, 붉은 육류 과다 섭취가 위험 요인으로 알려져 있습니다. 그러나 내시경에서 ''지름진 음식''이 많다는 표현은 임상적으로 일반적인 표현이 아니므로, 정확한 소견 해석은 담당 소화기내과 전문의와 상담하시기 바랍니다. 용종이 발견된 경우 정기적인 추적 내시경 검사가 필요합니다.', 3310, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장의 양성 종양', '대장의양성종양', 'DEFINITION', '대장의 양성 종양(선종성 용종 등) 진단 시 대장 점막에서 돌출된 혹(폴립) 형태의 변화가 확인됩니다. 조직학적으로는 선종(관상, 융모상, 혼합형)이 가장 흔하며, 일부는 대장암으로 진행될 가능성이 있는 전암 병변입니다. 발견된 용종의 크기·종류·이형성 정도에 따라 추적 내시경 검사 간격이 결정되므로 담당 전문의의 지시에 따르시기 바랍니다.', 3311, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장의 양성 종양', '대장의양성종양', 'SYMPTOM', '대장의 양성 종양(선종성 용종)은 대부분 무증상이나, 크기가 크거나 수가 많은 경우 혈변, 점액변, 간헐적 복통, 배변 습관 변화(설사 또는 변비), 잔변감 등이 나타날 수 있습니다. 대장 내시경은 용종을 발견하는 동시에 제거할 수 있어 예방적 효과가 있습니다. 증상이 있거나 50세 이상이라면 소화기내과 전문의와 상담하여 내시경 검사를 받으시기 바랍니다.', 3312, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장의 양성 종양', '대장의양성종양', 'DIAGNOSIS', '대장 양성 종양 확인을 위해 대장 내시경과 CT 외에도 대변 잠혈 반응 검사, CT 가상 대장경(CT 콜로노그래피), 에스결장경 검사 등이 사용될 수 있습니다. 그러나 정확한 진단과 동시 제거를 위해 대장 내시경이 가장 우선적으로 권장됩니다. 검사 방법 선택은 증상, 나이, 이전 검진 결과에 따라 달라지므로 소화기내과 전문의와 상담하시기 바랍니다.', 3313, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '대장의 양성 종양', '대장의양성종양', 'TREATMENT', '대장의 양성 종양 치료(내시경 용종 절제술) 기간 중 항문 이상(치질, 항문 열상 등)이 있는 경우 시술 후 출혈 위험이 높아질 수 있으므로 시술 전 담당 의사에게 반드시 알려야 합니다. 시술 후에는 출혈 예방을 위해 아스피린 등 항혈전제 복용 제한, 심한 운동 자제, 고섬유 식이 등 주의사항을 따라야 합니다. 항문 이상 증상이 지속된다면 대장항문외과 전문의의 진료를 함께 받으시기 바랍니다.', 3314, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '두경부암', '두경부암', 'PREVENTION', '흡연은 두경부암의 가장 중요한 위험 요인으로, 담배 연기의 발암물질이 구강·인두·후두 점막에 직접 자극을 주어 유전자 변이를 유발합니다. 흡연량과 기간에 비례하여 두경부암 발생 위험이 증가하며, 금연 후에도 위험이 점진적으로 감소하므로 조기 금연이 매우 중요합니다. 금연을 위해 금연 클리닉이나 전문의의 도움을 받는 것을 권장합니다.', 3315, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '두경부암', '두경부암', 'CAUSE', '두경부암의 주요 위험 요인으로 흡연(가장 강력), 과음, 인유두종바이러스(HPV) 감염이 있으며, 흡연과 음주의 복합 노출은 위험을 상승적으로 높입니다. 흡연을 중단하면 구강·인두 점막의 발암물질 노출이 즉시 줄어들고, 수년에 걸쳐 암 발생 위험이 점차 감소합니다. 금연 외에도 절주와 HPV 백신 접종이 두경부암 예방에 효과적입니다.', 3316, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '두경부암', '두경부암', 'DEFINITION', '두경부암은 두경부(머리·목) 영역에서 발생하는 악성 종양의 총칭으로, 구강암, 인두암(구인두·하인두·비인두), 후두암, 비강·부비동암, 침샘암 등이 포함됩니다. 주요 원인으로 흡연, 음주, HPV 감염이 있으며, 위치에 따라 증상(목 이물감, 연하곤란, 쉰 목소리 등)과 치료법이 다릅니다. 두경부암이 의심되는 증상이 있다면 이비인후과 또는 두경부외과 전문의의 진료를 받으시기 바랍니다.', 3317, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '두경부암', '두경부암', 'SYMPTOM', '목의 이물감은 두경부암, 특히 인두암이나 후두암에서 종양이 점막을 자극하거나 종괴 효과로 발생할 수 있습니다. 이로 인한 통증은 암세포 침윤, 염증 반응, 신경 압박 등으로 인해 발생하며 연하통(삼킬 때 통증)이나 방사통(귀 통증)으로 나타나기도 합니다. 이물감과 통증이 2주 이상 지속된다면 이비인후과 전문의를 방문하여 후두경 검사 등 정밀 진단을 받으시기 바랍니다.', 3318, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '두경부암', '두경부암', 'DIAGNOSIS', '부비동에 원인 불명의 세포 증식(덩어리)이 발견된 경우 이비인후과(두경부외과) 전문의가 있는 종합병원이나 대학병원을 방문하시기 바랍니다. 부비동 내시경 검사, 부비동 CT, MRI, 조직 생검을 통해 양성 종양과 악성 종양을 감별합니다. 정확한 진단을 위해 전문 의료기관의 이비인후과·두경부외과에서 정밀 검진을 받으시길 권고합니다.', 3319, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '두경부암', '두경부암', 'TREATMENT', '두경부암의 치료에 대한 질문이지만 내용은 증상에 관한 것입니다. 지속적 통증과 귀 밑·목에 혹이 만져지는 것 외에 두경부암의 주요 증상으로 쉰 목소리, 연하곤란(삼키기 어려움), 입이나 목의 궤양, 코막힘·비출혈, 체중 감소, 구강 내 하얀 반점(백반증) 등이 있습니다. 이러한 증상이 2~3주 이상 지속된다면 이비인후과 전문의의 진료를 받으시기 바랍니다.', 3320, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '림프종', '림프종', 'MEDICATION', '오비누투주맙(obinutuzumab)은 CD20 항원에 결합하는 2세대 항CD20 단클론항체로, B세포 림프종과 만성림프구성백혈병 치료에 사용됩니다. 1세대 리툭시맙보다 직접 세포독성과 항체 의존성 세포독성(ADCC) 효과가 향상되어 치료 반응률이 개선되었습니다. 특히 CLL과 여포성 림프종에서 화학요법과 병용 시 무진행 생존기간 연장 효과가 입증되어 있습니다.', 3321, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '림프종', '림프종', 'CAUSE', '림프종은 림프구의 악성 증식으로 발생하며, 주요 원인으로 EBV·HTLV-1 등 바이러스 감염, 면역결핍 상태, 자가면역질환, 헬리코박터 감염(위 MALT 림프종) 등이 있습니다. 림프종이 발생하면 림프절 종대(목, 겨드랑이, 사타구니)가 가장 흔하며, 림프관 폐색으로 부종이 생길 수 있습니다. 림프절 종대 등 증상이 있다면 혈액종양 전문의의 진료를 받으시기 바랍니다.', 3322, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '림프종', '림프종', 'DEFINITION', '림프종은 단일 질환이 아닌 림프구에서 기원하는 다양한 악성 종양의 집합체입니다. 크게 호지킨 림프종과 비호지킨 림프종으로 나뉘며, 비호지킨 림프종만 해도 미만성 거대B세포 림프종, 여포성 림프종, T세포 림프종, 버킷 림프종 등 30가지 이상의 아형이 포함됩니다. 각 아형에 따라 임상 경과, 예후, 치료법이 크게 다르므로 정확한 조직학적 진단이 필수적입니다.', 3323, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '림프종', '림프종', 'SYMPTOM', '림프종의 증상으로 겨드랑이 림프절 종대가 발생하면 해당 부위가 붓고 불편감이 생길 수 있으며, 림프절이 커질수록 압박감이나 통증이 동반될 수 있습니다. 이는 림프종의 전형적인 증상 중 하나로, 목·사타구니 림프절 종대와 함께 나타나는 경우가 많습니다. 2~4주 이상 지속되거나 크기가 커지는 림프절 종대는 혈액종양 전문의의 진료가 필요합니다.', 3324, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '림프종', '림프종', 'DIAGNOSIS', '림프종 진단에서 흉부 X선 촬영은 종격동(가슴 중앙부) 림프절 비대 여부를 확인하는 초기 검사로 활용됩니다. 종격동에 림프종이 있으면 X선에서 종격동이 넓어진 소견이 관찰되며, 이는 림프종 세포가 림프절 내에서 증식하여 림프절을 비정상적으로 비대시키기 때문입니다. 확진을 위해서는 CT, PET-CT, 림프절 생검이 추가로 필요합니다.', 3325, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '림프종', '림프종', 'TREATMENT', '림프종 치료 중 및 치료 후 추적 검사로 CT, PET-CT, 혈액 검사(LDH, CBC 등)가 정기적으로 시행됩니다. 재발 여부 확인을 위해 치료 종료 후 처음 2년은 3~6개월마다, 이후에는 매년 영상 검사와 혈액 검사를 받는 것이 일반적입니다. 재발 가능성과 추적 관찰 일정은 림프종의 종류와 치료 반응에 따라 달라지므로 담당 혈액종양 전문의의 지시를 따르시기 바랍니다.', 3326, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '만성골수백혈병', '만성골수백혈병', 'MEDICATION', '만성골수백혈병의 표준 표적치료제는 이매티닙(gleevec)이며, 2세대 제제로 닐로티닙, 다사티닙, 보수티닙이 있습니다. 이 중 닐로티닙과 다사티닙은 이매티닙보다 분자반응률이 높고 부작용 프로파일이 약간 다르나, 부작용이 가장 적다는 표현은 약제마다 다르므로 개별 특성을 고려해야 합니다. 약물 선택은 환자의 나이, 동반 질환, 부작용 위험을 고려하여 혈액종양 전문의와 상담 후 결정하시기 바랍니다.', 3327, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '만성골수백혈병', '만성골수백혈병', 'PREVENTION', '갑상선암 예방을 위한 방사선 촬영은 일반적으로 권장되지 않으며, 오히려 불필요한 방사선 노출은 암 발생 위험을 높일 수 있습니다. 갑상선암 조기 발견을 위해서는 경부 초음파 검사가 더 적합한 방법입니다. 불필요한 방사선 검사보다 정기적인 건강검진과 목에 혹이 만져지거나 이상 증상이 있을 때 내분비내과 또는 이비인후과 전문의의 진료를 받는 것이 중요합니다.', 3328, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '만성골수백혈병', '만성골수백혈병', 'CAUSE', '만성골수백혈병의 핵심 발병 기전은 9번과 22번 염색체 간의 상호 전좌로 생성되는 BCR-ABL 융합 유전자입니다. 이 융합 유전자는 BCR-ABL 티로신 키나제를 지속 활성화하여 골수 세포의 과증식·분화 이상을 유발합니다. 가족력은 만성골수백혈병의 주요 위험 요인이 아니며, 대부분 후천적으로 발생하는 체세포 돌연변이입니다.', 3329, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '만성골수백혈병', '만성골수백혈병', 'DEFINITION', '만성골수백혈병은 BCR-ABL 융합 유전자에 의한 비정상적 티로신 키나제 활성화로 골수에서 성숙 과립구가 과증식하는 혈액암입니다. 비장종대로 인한 좌상복부 불편감·조기 포만감, 백혈구 및 혈소판 증가가 특징적이며 소화 불량이 동반될 수 있습니다. 이매티닙 등 BCR-ABL 표적치료제로 높은 치료 효과를 기대할 수 있으며, 혈액종양 전문의와 지속적인 치료 관리가 필요합니다.', 3330, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '만성골수백혈병', '만성골수백혈병', 'SYMPTOM', '만성골수백혈병은 초기(만성기)에는 무증상이거나 경미한 피로감·비장종대만 있어 일반 건강검진에서 혈액 검사 이상(백혈구 수치 증가)으로 우연히 발견되는 경우가 많습니다. 따라서 증상 없이 건강검진에서 진단받는 경우는 드물지 않습니다. 무증상이라도 진단 후 즉시 혈액종양 전문의와 상담하여 치료를 시작하는 것이 중요합니다.', 3331, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '만성골수백혈병', '만성골수백혈병', 'DIAGNOSIS', '만성골수백혈병 진단 후 치료 기관 선택에 있어 혈액종양과가 있는 종합병원이나 대학병원에서 표적치료제(이매티닙 등)를 처방받고 정기적으로 추적 관찰하는 것이 원칙입니다. 진단 재확인이 필요하다면 다른 혈액종양과 전문의에게 이차 소견을 구할 수 있습니다. 치료 경과 확인을 위해 BCR-ABL 정량 검사 등을 시행하는 혈액종양 전문 의료기관이 적합합니다.', 3332, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '만성골수백혈병', '만성골수백혈병', 'TREATMENT', '만성골수백혈병은 BCR-ABL 표적치료제(이매티닙, 닐로티닙, 다사티닙 등)가 매우 효과적이어서 대부분의 환자에서 골수이식 없이 치료가 가능합니다. 표적치료제로 심부분자반응(DMR)을 달성하면 치료 중단(치료 없는 완화, TFR)을 시도할 수도 있습니다. 골수이식은 표적치료제 내성이나 급성 전환 등 고위험 상황에서 고려되며, 담당 혈액종양 전문의와 치료 계획을 상담하시기 바랍니다.', 3333, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '만성림프구백혈병', '만성림프구백혈병', 'CAUSE', '만성림프구백혈병은 혈액암 중 가족력이 비교적 잘 알려진 편으로, 1촌 가족(부모, 형제)에 환자가 있으면 발생 위험이 2~7배 높아집니다. 그러나 가족력이 있다고 해서 반드시 발병하는 것은 아니며, 대부분은 60대 이상에서 발생합니다. 아버지가 만성림프구백혈병이라면 혈액종양 전문의와 상담하여 정기적인 혈액 검사를 받는 것이 권장됩니다.', 3334, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '만성림프구백혈병', '만성림프구백혈병', 'DEFINITION', '만성림프구백혈병은 성숙 B림프구가 골수·혈액·림프절에 비정상 축적되는 혈액암으로, 서구에서는 가장 흔한 성인 백혈병입니다. 특징으로 천천히 진행하는 임상 경과, 면역 기능 저하로 인한 감염 취약성, 자가면역 용혈성 빈혈, 일부에서 리히터 증후군(공격적 림프종으로 전환)이 있습니다. 진행 속도와 치료 시작 시점은 개인마다 달라 혈액종양 전문의의 정기적인 추적 관찰이 필요합니다.', 3335, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '만성림프구백혈병', '만성림프구백혈병', 'SYMPTOM', '만성림프구백혈병에서 피로감과 무기력감은 빈혈, 암세포에서 분비되는 사이토카인, 면역 기능 저하로 인해 발생합니다. 일상에서 쉽게 지치고 활동 능력이 줄어들며, 집중력 저하와 수면 장애를 동반하기도 합니다. 이러한 증상이 업무·일상생활에 지장을 준다면 담당 혈액종양 전문의와 증상 관리 방법을 상담하시기 바랍니다.', 3336, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '만성림프구백혈병', '만성림프구백혈병', 'DIAGNOSIS', '만성림프구백혈병 진단을 위해 혈액 검사에서 성숙 소형 림프구가 5×10⁹/L 이상으로 증가한 소견이 기본 기준입니다. 유세포 분석(flow cytometry)으로 CD5, CD19, CD23 등 특이 면역표현형을 확인하여 확진합니다. 미열과 림프절 부종이 있다면 혈액종양 전문의를 방문하여 말초혈액 검사와 유세포 분석 검사를 받으시기 바랍니다.', 3337, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '만성림프구백혈병', '만성림프구백혈병', 'TREATMENT', '만성림프구백혈병의 치료는 병기와 증상에 따라 경과 관찰부터 적극적 치료까지 다양합니다. 골수이식 외 치료로 FCR(플루다라빈+사이클로포스파미드+리툭시맙), 이브루티닙·아칼라브루티닙(BTK 억제제), 베네토클락스(BCL-2 억제제), 오비누투주맙 등 표적치료제가 효과적으로 사용됩니다. 치료 방법은 환자의 나이, 체력, 유전자 이상(17p 결실 등)에 따라 결정되므로 혈액종양 전문의와 충분히 상담하시기 바랍니다.', 3338, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '면역결핍증', '면역결핍증', 'CAUSE', '면역결핍증의 원인은 유전성이 유일한 것이 아니며, 선천성(유전성)과 후천성으로 나뉩니다. 후천성 면역결핍증은 HIV 감염(AIDS), 영양 결핍, 면역억제제 사용, 항암화학요법, 당뇨병, 악성 종양 등 다양한 원인으로 발생합니다. 다만 선천성 면역결핍증은 유전자 변이에 의한 것이 대부분이므로 ''선천성''에 한해서는 유전성이 주된 원인으로 알려져 있습니다.', 3339, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '면역결핍증', '면역결핍증', 'DEFINITION', '면역결핍증은 면역계의 구성 요소(림프구, 항체, 보체, 식세포 등)가 선천적 또는 후천적으로 부족하거나 기능이 저하되어 감염과 특정 질병에 취약해지는 상태입니다. 선천성은 유전자 변이로, 후천성은 HIV 감염, 영양 결핍, 면역억제 치료 등에 의해 발생합니다. 반복적인 심한 감염이 있다면 면역학 또는 감염내과 전문의의 정밀 평가가 필요합니다.', 3340, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '면역결핍증', '면역결핍증', 'SYMPTOM', '면역결핍증에서 면역 기능이 저하되면 바이러스·세균에 대한 방어 능력이 감소하여 일반인에게는 경미하게 지나가는 감기(상기도 감염)가 심해지거나 오래 지속됩니다. 또한 폐렴, 부비동염, 중이염 등 2차 합병증으로 진행하기 쉽고 회복 기간도 깁니다. 면역결핍증이 있다면 독감 예방접종 등 감염 예방 조치를 강화하고 감염내과 전문의의 지속적인 관리를 받으시기 바랍니다.', 3341, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '면역결핍증', '면역결핍증', 'DIAGNOSIS', '가족력(선천성 면역결핍증)이 있는 신생아에서는 신생아 스크리닝으로 T세포·B세포 수 측정(TREC/KREC 검사), 림프구 아형 분류 검사(유세포 분석), 면역글로불린(IgG, IgA, IgM) 측정, 유전자 검사 등이 시행됩니다. 이 검사들은 생후 가능한 한 빠른 시기에 이루어져야 적절한 치료(조혈모세포 이식, 면역글로불린 치료 등)를 시작할 수 있습니다. 선천성 면역결핍증이 의심된다면 소아면역학 또는 소아혈액종양 전문의에게 진료를 받으시기 바랍니다.', 3342, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '면역결핍증', '면역결핍증', 'TREATMENT', '면역결핍증의 치료 목표는 감염 예방과 면역 기능 보완이며, 선천성 면역결핍증의 경우 조혈모세포 이식이 일부 유형(SCID 등)에서 완치를 기대할 수 있는 치료법입니다. 후천성 면역결핍증은 원인 질환(HIV 등) 치료, 면역글로불린 보충, 예방적 항생제·항진균제 사용, 생백신 접종 제한 등으로 관리합니다. 면역결핍증의 유형과 중증도에 따라 치료 방침이 달라지므로 면역학 또는 감염내과 전문의와 상담하시기 바랍니다.', 3343, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '면역혈소판감소증', '면역혈소판감소증', 'CAUSE', '면역혈소판감소증(ITP)에서 혈소판 수치 감소와 멍·출혈 경향은 자가항체(주로 IgG)가 혈소판 표면 항원에 결합하여 비장에서 혈소판이 파괴되기 때문에 발생합니다. 이와 함께 자가항체가 거핵구(혈소판 전구세포)의 혈소판 생성을 직접 억제하는 기전도 함께 작용합니다. 쉽게 멍이 들거나 자연 출혈이 있다면 혈액내과 전문의를 방문하여 혈소판 수치 및 관련 검사를 받으시기 바랍니다.', 3344, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '면역혈소판감소증', '면역혈소판감소증', 'DEFINITION', '면역혈소판감소증은 혈소판 수가 감소하여 피부에 점상출혈(작은 빨간 점), 자반(멍), 상처 부위 출혈 지연, 코피, 잇몸 출혈 등이 나타날 수 있습니다. 심한 경우 내부 장기 출혈이나 뇌출혈 같은 심각한 합병증이 발생할 수 있으므로, 이러한 증상이 관찰될 경우 즉시 소아과 또는 혈액내과 전문의의 진료를 받으시기 바랍니다.', 3345, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '면역혈소판감소증', '면역혈소판감소증', 'SYMPTOM', '면역혈소판감소증의 증상으로는 코피, 하지 자반(멍) 외에도 점상출혈, 잇몸 출혈, 혈뇨, 혈변, 월경 과다, 상처 후 지혈 지연 등이 나타날 수 있습니다. 드물게 뇌출혈이나 소화관 출혈 같은 중증 출혈이 발생할 수 있으며, 이 경우 응급 치료가 필요하므로 혈액내과 전문의와 반드시 상담하시기 바랍니다.', 3346, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '면역혈소판감소증', '면역혈소판감소증', 'DIAGNOSIS', '면역혈소판감소증의 진단은 주로 혈액 검사(전혈구검사)로 혈소판 감소를 확인하고 다른 원인을 배제하는 방식으로 이루어집니다. 골수 검사는 모든 환자에게 필수적이지 않으며, 비정형적인 소견이 있거나 다른 혈액 질환이 의심될 때 선택적으로 시행됩니다. 정확한 진단과 검사 필요 여부는 혈액내과 전문의와 상담하시기 바랍니다.', 3347, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '면역혈소판감소증', '면역혈소판감소증', 'TREATMENT', '면역혈소판감소증의 치료로는 부신피질스테로이드(프레드니손)가 1차 치료로 가장 많이 사용되며, 정맥내 면역글로불린(IVIG) 주사, 항-D 면역글로불린 투여도 사용됩니다. 스테로이드에 반응하지 않는 만성 경우에는 리툭시맙, 트롬보포이에틴 수용체 작용제(엘트롬보팍, 로미플로스팀) 등의 약물 치료를 고려할 수 있으며, 구체적인 치료 계획은 혈액내과 전문의와 상담하시기 바랍니다.', 3348, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '방광암', '방광암', 'MEDICATION', '방광암 치료에 사용되는 약물로는 방광 내 BCG(결핵균 면역요법)와 미토마이신C 등이 있으며, BCG는 면역계를 자극하여 암세포를 제거하고 재발을 억제합니다. 전신 항암화학요법으로는 시스플라틴 기반 병합 요법이 주로 사용되며, 최근에는 면역관문억제제(아테졸리주맙, 펨브롤리주맙)도 진행성 방광암에 활용됩니다. 적합한 약물 치료 선택은 종양내과 전문의와 상담하시기 바랍니다.', 3349, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '방광암', '방광암', 'PREVENTION', '방광암 치료 후 재발 예방을 위해 금연이 가장 중요하며, 하루 1.5~2리터 이상의 충분한 수분 섭취로 방광 내 발암물질 농도를 낮추는 것이 도움이 됩니다. 방사선이나 발암성 화학물질 노출을 피하고, 의사가 권고하는 정기적인 방광경 검사와 소변 세포검사를 빠짐없이 받는 것이 재발의 조기 발견에 중요합니다. 생활 습관 개선과 함께 비뇨의학과 전문의의 지속적인 추적 관리를 받으시기 바랍니다.', 3350, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '방광암', '방광암', 'CAUSE', '방광염은 세균 감염에 의한 방광의 염증으로, 그 자체가 방광암의 직접적인 원인은 아닙니다. 다만 만성 방광염이 반복되면 방광 점막에 지속적인 자극과 염증이 생겨 세포 변이 위험이 높아질 수 있으며, 일부 기생충 감염(주혈흡충증)에 의한 만성 방광염은 편평세포암과 관련성이 있습니다. 반복적인 방광염 증상이 있으면 비뇨의학과 전문의를 방문하여 정확한 원인을 감별받으시기 바랍니다.', 3351, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '방광암', '방광암', 'DEFINITION', '방광암은 방광의 내벽 세포에서 발생하는 악성 종양으로, 이행상피세포암이 가장 흔한 형태입니다. 주요 증상으로는 무통성 혈뇨, 빈뇨, 배뇨 통증, 배뇨 급박감 등이 있으며, 진행될 경우 골반 통증이나 하지 부종이 나타날 수 있습니다. 방광염이 심해져도 방광암으로 직접 진행되는 것은 아니지만, 유사한 증상이 나타나면 비뇨의학과 전문의를 통해 정확한 감별 진단을 받으시기 바랍니다.', 3352, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '방광암', '방광암', 'SYMPTOM', '빈뇨와 혈뇨가 동시에 나타나는 경우 방광암 외에도 방광염, 요로결석, 신우신염, 전립선 질환(남성) 등 다양한 원인을 고려해야 합니다. 방광암은 특히 통증 없는 혈뇨가 특징적이며, 빈뇨가 동반되기도 합니다. 이러한 증상이 나타날 경우 자의적으로 판단하지 말고 비뇨의학과 전문의를 방문하여 소변 검사 및 영상 검사를 통한 정확한 진단을 받으시기 바랍니다.', 3353, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '방광암', '방광암', 'DIAGNOSIS', '방광암의 가장 흔한 초기 증상은 통증을 동반하지 않는 육안적 혈뇨(소변에 피가 보임)로, 간헐적으로 나타날 수 있어 주의가 필요합니다. 이 증상이 나타날 경우 비뇨의학과 전문의를 방문하여 소변 세포검사, 방광경 검사, 초음파 또는 CT 검사 등을 통해 정확한 진단을 받아야 합니다. 혈뇨는 방광암 외에도 다른 질환에서도 나타날 수 있으므로 전문의의 감별 진단이 중요합니다.', 3354, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '방광암', '방광암', 'TREATMENT', '경요도 방광종양 절제술(TURBT)은 비근침윤성 방광암(표재성 방광암)의 표준 치료로, 요도를 통해 내시경을 삽입하여 종양을 절제하는 최소 침습적 방법입니다. 그러나 근침윤성 방광암이나 광범위한 종양의 경우에는 근치적 방광절제술이 더 적합할 수 있어 TURBT가 모든 방광암에 가장 효과적인 방법이라고 단정할 수는 없습니다. 치료 방법 선택은 암의 병기와 환자 상태에 따라 비뇨의학과 전문의와 상담하여 결정하시기 바랍니다.', 3355, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '백혈병', '백혈병', 'CHECKUP', '만성골수세포백혈병(CML) 진단에는 혈액 검사에서 미성숙 골수세포 증가, 백혈구 수 상승, 혈소판 변화 확인이 필요합니다. 결정적 진단은 골수 검사 및 염색체 검사를 통한 필라델피아 염색체(BCR-ABL 융합 유전자) 확인으로 이루어집니다. 정확한 진단과 치료 계획 수립을 위해 혈액내과 전문의의 상담을 받으시기 바랍니다.', 3356, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '백혈병', '백혈병', 'MEDICATION', '탈모는 일부 백혈병 항암화학요법 약물(사이클로포스파마이드, 빈크리스틴, 안트라사이클린 계열 등)의 대표적인 부작용으로 나타날 수 있습니다. 표적항암제인 이마티닙(글리벡)의 경우 탈모 부작용이 상대적으로 적지만 완전히 배제되지는 않습니다. 복용 중인 약물과 탈모의 관련성은 담당 혈액내과 전문의와 상담하여 정확히 평가받으시기 바랍니다.', 3357, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '백혈병', '백혈병', 'PREVENTION', '백혈병 중 일부는 유전적 소인이 관련될 수 있으나, 대부분은 직접 유전되는 질환이 아닙니다. 가족력이 있는 경우 정기적인 혈액 검사를 통한 조기 검진이 권장되며, 방사선 과다 노출, 벤젠 등 발암물질 노출을 최소화하고 흡연을 피하는 것이 도움이 됩니다. 구체적인 검진 주기와 예방 조치는 혈액내과 전문의와 상담하시기 바랍니다.', 3358, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '백혈병', '백혈병', 'CAUSE', '백혈병은 컴퓨터 모니터나 일반 사무 환경의 전자기파와 직접적인 인과관계가 과학적으로 입증되지 않았습니다. 다만 반도체, 디스플레이 제조 등 일부 컴퓨터 관련 제조업 종사자들은 벤젠, 포름알데히드 같은 발암 화학물질에 노출될 수 있어 백혈병 위험이 높아질 수 있습니다. 직업적 노출이 우려되는 경우 산업의학과 또는 혈액내과 전문의와 상담하시기 바랍니다.', 3359, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '백혈병', '백혈병', 'DEFINITION', '백혈병은 골수에서 혈액 세포를 만드는 과정에 이상이 생겨 비정상적인 백혈구가 과도하게 증식하는 혈액 악성 종양입니다. 이러한 비정상 세포들이 골수와 혈액을 가득 채워 정상적인 적혈구, 백혈구, 혈소판의 생성을 방해하며, 급성과 만성, 림프구성과 골수성 등으로 분류됩니다. 정확한 진단과 치료를 위해 혈액내과 전문의와 상담하시기 바랍니다.', 3360, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '백혈병', '백혈병', 'SYMPTOM', '백혈병에서 나타나는 창백함, 지속적 피로, 관절 통증은 정상 적혈구 감소(빈혈)와 백혈병 세포의 뼈 침범으로 인한 증상이며, 특정 생활 습관이 이 증상들의 직접적 원인은 아닙니다. 다만 과도한 음주, 흡연, 방사선 및 벤젠 노출 등은 백혈병 발병 위험을 높이는 요인으로 알려져 있습니다. 이러한 증상들이 지속될 경우 자의적으로 원인을 판단하지 말고 혈액내과 전문의를 방문하여 혈액 검사를 받으시기 바랍니다.', 3361, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '백혈병', '백혈병', 'DIAGNOSIS', '백혈병은 혈액내과에서 혈액 검사, 골수 검사, 염색체 및 유전자 검사를 통해 진단받을 수 있으며, 감기·빈혈 등과 증상이 유사하여 초기에 다른 질환으로 오인될 수 있습니다. 빈혈, 혈소판 감소증, 발열, 체중 감소 등의 증상이 지속되면 혈액내과를 방문하여 전혈구검사를 받는 것이 조기 진단에 중요합니다. 의심 증상이 있다면 즉시 혈액내과 전문의의 진료를 받으시기 바랍니다.', 3362, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '백혈병', '백혈병', 'TREATMENT', '호중구감소증 치료에서 면역 시스템 연구는 활발히 진행 중이며, 과립구 집락 자극인자(G-CSF) 투여를 통해 골수에서 호중구 생산을 촉진하는 방법이 대표적입니다. 자가면역성 호중구감소증의 경우 면역 시스템이 자체 호중구를 공격하는 기전이 확인되어, 면역억제제나 리툭시맙 같은 생물학적 제제가 치료에 활용됩니다. 정확한 원인 규명과 치료 방향 결정을 위해 혈액내과 전문의 상담이 반드시 필요합니다.', 3363, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '범혈구감소증', '범혈구감소증', 'CAUSE', '범혈구감소증의 원인 중 영양 결핍으로는 비타민 B12·엽산·철분 결핍이 대표적이며, 감염 원인으로는 HIV, 패혈증, 결핵, 말라리아 등이 해당됩니다. 독소로는 항암제, 방사선, 벤젠 등 화학물질이 골수 기능을 억제할 수 있고, 자가면역 질환이나 골수 침범 질환도 주요 원인입니다. 정확한 원인 파악을 위해 혈액내과 전문의의 진료와 검사가 필요합니다.', 3364, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '범혈구감소증', '범혈구감소증', 'DEFINITION', '범혈구감소증은 혈액 내 적혈구, 백혈구, 혈소판 세 가지 혈액 세포 모두가 동시에 감소된 상태를 말합니다. 적혈구 감소로 인한 빈혈, 백혈구 감소로 인한 감염 위험 증가, 혈소판 감소로 인한 출혈 경향 등 복합 증상이 나타납니다. 원인이 다양하므로 골수 검사를 포함한 정밀 검사를 통해 혈액내과 전문의에게 진단과 치료를 받으시기 바랍니다.', 3365, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '범혈구감소증', '범혈구감소증', 'SYMPTOM', '범혈구감소증에서 빈혈 외에도 백혈구 감소로 인해 반복적인 감염, 발열, 구내염 등이 나타날 수 있습니다. 혈소판 감소로 인해 피부에 점출혈이나 자반증, 잇몸 출혈, 코피, 생리 과다 등 출혈 증상이 동반될 수 있습니다. 이러한 증상이 복합적으로 나타날 경우 즉시 혈액내과 전문의의 진료를 받으시기 바랍니다.', 3366, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '범혈구감소증', '범혈구감소증', 'DIAGNOSIS', '헌혈 부적격 판정 후 범혈구감소증이 의심된다면 상급종합병원 혈액내과를 방문하는 것이 가장 적합합니다. 전국 주요 대학병원의 혈액내과에서 전혈구검사, 말초혈액 도말검사, 골수검사 등 정밀 진단이 가능합니다. 헌혈 시 받은 검사 결과지를 지참하면 진료에 도움이 됩니다.', 3367, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '범혈구감소증', '범혈구감소증', 'TREATMENT', '범혈구감소증 치료에는 원인에 따라 수혈, 조혈 촉진제 투여, 면역억제 치료 등이 활용됩니다. 중증 재생불량빈혈의 경우 무균 격리, 조혈모세포이식, 혈액성분 분리가 필요하며, 항감염 치료를 위한 혈액 배양 및 항생제 투여도 필수적입니다. 치료 계획은 혈액내과 전문의와 상담하여 환자 상태에 맞게 결정해야 합니다.', 3368, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신 종양', '부신종양', 'CHECKUP', '손발 저림과 불규칙한 생리가 동반될 경우 부신 종양 감별을 위해 혈액 및 24시간 소변 호르몬 검사, 복부 CT 또는 MRI 검사가 필요합니다. 내분비내과 전문의를 방문하여 증상에 대한 종합적인 평가를 받으시기 바랍니다.', 3369, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신 종양', '부신종양', 'DIET_LIFE', '부신 종양 환자에서 생활습관 개선은 동반 증상 관리에 도움이 됩니다. 저염식, 규칙적인 운동, 금주, 금연을 통해 고혈압, 혈당 이상 등 호르몬 과잉 분비로 인한 합병증을 일부 완화할 수 있습니다. 그러나 부신 종양 자체는 생활습관만으로 치료되지 않으므로 내분비내과 전문의의 치료 계획을 따르시기 바랍니다.', 3370, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신 종양', '부신종양', 'MEDICATION', '부신 종양 치료에 사용되는 미토탄은 장기 복용 시 식욕 부진, 구역, 피로감, 부신기능부전 등의 부작용이 나타날 수 있습니다. 갈색세포종 치료에 쓰이는 알파·베타 차단제는 저혈압, 어지럼증을 유발할 수 있으며, 케토코나졸 등은 간 독성에 주의가 필요합니다. 약물 복용 중 이상 반응 발생 시 즉시 내분비내과 전문의와 상담하시기 바랍니다.', 3371, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신 종양', '부신종양', 'PREVENTION', '부신 종양 재발 예방을 위해 수술 후 정기적인 영상 검사와 호르몬 수치 추적 검사가 중요합니다. 금연, 금주, 균형 잡힌 식단, 규칙적인 유산소 운동으로 면역 기능을 강화하고 스트레스를 관리하는 것이 도움이 됩니다. 재발 여부는 내분비내과 전문의와의 정기 추적 관찰을 통해 조기에 발견할 수 있습니다.', 3372, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신 종양', '부신종양', 'EXERCISE', '부신 종양 수술 후 가벼운 운동은 심폐 기능 회복, 근력 유지, 피로 감소, 기분 개선에 도움이 됩니다. 수술 부위가 안정되면 걷기 등 저강도 유산소 운동부터 시작하여 통증이 없는 범위에서 점차 강도를 높일 수 있습니다. 운동 시작 시기와 강도는 담당 내분비내과 전문의의 지도하에 결정하시기 바랍니다.', 3373, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신 종양', '부신종양', 'CAUSE', '부신 종양의 유병률 증가는 주로 복부 CT·MRI 등 영상 검사의 보편화로 인해 이전에는 발견되지 않던 무증상 종양이 많이 발견되는 것과 관련이 있습니다. 실제 발생률 자체의 증가보다는 진단 기술 향상이 주요 원인으로 평가되며, 비만·고혈압 증가 등 대사 질환과의 연관성도 일부 연구에서 제시됩니다. 정확한 평가를 위해 내분비내과 전문의의 진료를 받으시기 바랍니다.', 3374, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신 종양', '부신종양', 'REHAB', '부신 종양 수술 후 근육 강화 재활로는 복부 및 코어 근육을 안정시키는 단계적 운동이 효과적이며, 초기에는 누운 자세에서의 하지 운동과 호흡 운동부터 시작합니다. 이후 수술 부위 회복에 따라 저항 밴드 운동, 수중 운동, 가벼운 근력 운동 순으로 진행합니다. 재활의학과 전문의 또는 물리치료사의 지도하에 맞춤형 재활 프로그램을 진행하시기 바랍니다.', 3375, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신 종양', '부신종양', 'DEFINITION', '부신 종양은 신장 위에 위치한 부신에서 발생하는 종양으로, 양성과 악성, 기능성과 비기능성으로 구분됩니다. 기능성 종양은 호르몬을 과잉 분비하여 고혈압, 저칼륨혈증, 쿠싱 증상 등을 유발하며, 비기능성 종양은 영상 검사에서 우연히 발견되는 경우가 많습니다. 종양의 특성에 따라 치료 방법이 달라지므로 내분비내과 및 비뇨기과 전문의의 정밀 평가가 필요합니다.', 3376, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신 종양', '부신종양', 'SYMPTOM', '부신 종양, 특히 알도스테론을 과잉 분비하는 원발성 알도스테론증이나 코티솔을 과잉 분비하는 쿠싱증후군에서 치료에 잘 반응하지 않는 고혈압이 나타날 수 있습니다. 손발 저림은 저칼륨혈증이 동반된 알도스테론 과잉 분비 시 흔히 나타나는 증상입니다. 혈압약에도 혈압이 조절되지 않는다면 내분비내과 전문의를 방문하여 호르몬 검사를 받으시기 바랍니다.', 3377, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신 종양', '부신종양', 'DIAGNOSIS', '장기간 스테로이드 사용 후 부신 종양이 의심된다면 내분비내과 전문의를 방문하는 것이 적절합니다. 스테로이드 장기 복용은 부신 기능 저하 또는 쿠싱증후군 유사 증상을 유발할 수 있으므로, 복부 CT와 혈청 코티솔·ACTH 검사를 통해 정확한 진단이 이루어집니다. 전국 주요 대학병원 내분비내과에서 정밀 진단을 받으실 수 있습니다.', 3378, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신 종양', '부신종양', 'TREATMENT', '부신 종양의 완전 절제 수술이 가장 근본적인 치료로 재발 억제 효과도 가장 높습니다. 수술 후 호르몬 결핍이 발생하는 경우 호르몬 대체 치료가 반드시 필요합니다. 악성 부신 종양의 경우 수술 후 미토탄 등 보조 약물 치료를 병행하여 재발을 억제하는 전략을 담당 내분비내과 전문의와 상의하시기 바랍니다.', 3379, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신암', '부신암', 'CAUSE', '부신암 발생에는 유전자 돌연변이 외에도 TP53 유전자 이상, MEN1·Lynch 증후군 같은 유전성 증후군이 위험 인자가 됩니다. 고용량 스테로이드 장기 사용, 특정 호르몬 환경, 이전 방사선 노출도 부신암 발생에 영향을 줄 수 있습니다. 부신암은 드문 질환이므로 정확한 원인 규명과 위험도 평가를 위해 내분비내과 또는 종양내과 전문의와 상담하시기 바랍니다.', 3380, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신암', '부신암', 'DEFINITION', '부신암은 코티솔을 과잉 분비하여 쿠싱증후군을 일으킬 수 있으며, 쿠싱증후군의 원인이 부신 자체의 종양인 경우와 뇌하수체 종양인 경우를 감별하는 것이 중요합니다. 쿠싱 증상이 있다면 내분비내과 전문의를 통해 부신암 여부를 포함한 정밀 검사를 받으시기 바랍니다.', 3381, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신암', '부신암', 'SYMPTOM', '식욕 부진과 체중 감소는 부신암의 가능성 있는 증상이나, 다른 여러 질환에서도 나타날 수 있습니다. 부신암 확인을 위해 복부 CT 또는 MRI, 혈청 및 소변 호르몬 검사를 시행합니다. 증상이 지속된다면 내분비내과 전문의를 방문하여 정밀 검사를 받으시기 바랍니다.', 3382, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신암', '부신암', 'DIAGNOSIS', '부신암 진단은 복부 CT·MRI로 종양을 확인하고, PET-CT로 전이 여부를 평가하는 것이 일반적입니다. 호르몬 기능 검사, 조직 검사, 혈액검사를 종합하여 종양의 양성·악성 여부와 병기를 결정합니다. 내분비내과 및 외과 전문의와 상담하시기 바랍니다.', 3383, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '부신암', '부신암', 'TREATMENT', '부신암의 약물 치료에서 미토탄이 1차 표준 치료제로 사용됩니다. 진행된 부신암에는 미토탄과 함께 에토포사이드, 독소루비신, 시스플라틴을 병용하는 EDP-M 요법이 사용되며, 최근에는 면역항암제 임상 연구도 진행 중입니다. 종양내과 또는 내분비내과 전문의의 지도하에 치료받으시기 바랍니다.', 3384, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '비소세포성 폐암', '비소세포성폐암', 'PREVENTION', '비소세포성 폐암 예방의 가장 중요한 방법은 금연과 간접흡연 회피이며, 석면·라돈·미세먼지 등 발암물질 노출을 최소화하는 것도 중요합니다. 항산화 식단을 유지하며 규칙적인 운동을 하는 것이 전반적인 암 예방에 도움이 됩니다. 두 가지 이상의 암을 관리하는 경우 종양내과 전문의와 통합적인 관리 계획을 수립하시기 바랍니다.', 3385, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '비소세포성 폐암', '비소세포성폐암', 'CAUSE', '흡연이 비소세포성 폐암의 가장 큰 원인이지만, 붉은 육류·가공육 과다 섭취, 고지방 식단, 과음은 폐암 위험을 높일 수 있습니다. 신선한 과일·채소를 충분히 섭취하는 식단은 항산화 효과로 위험을 낮출 수 있습니다. 규칙적인 운동과 균형 잡힌 생활습관 유지, 정기 검진이 중요합니다.', 3386, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '비소세포성 폐암', '비소세포성폐암', 'DEFINITION', '비소세포성 폐암은 폐에서 발생하는 악성 종양 중 소세포암을 제외한 모든 폐암을 통칭하며, 전체 폐암의 약 85%를 차지합니다. 크게 선암, 편평세포암, 대세포암으로 분류되며, 조직형에 따라 EGFR, ALK 등 유전자 변이 검사를 통해 표적 치료 가능 여부가 결정됩니다. 흉부내과 전문의와 상담이 중요합니다.', 3387, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '비소세포성 폐암', '비소세포성폐암', 'SYMPTOM', '기침과 가래가 지속된다면 흉부 X선 및 흉부 CT 검사가 우선 권고됩니다. CT에서 이상 소견이 발견되면 기관지내시경 또는 경피적 폐 생검을 통해 암 여부를 확인합니다. 2주 이상 지속되는 기침과 가래는 흉부내과 전문의를 방문하시기 바랍니다.', 3388, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '비소세포성 폐암', '비소세포성폐암', 'DIAGNOSIS', '비소세포성 폐암 진단에는 흉부 CT가 1차적으로 활용되며, 전이 여부 확인에는 PET-CT, 뇌 전이 확인에는 뇌 MRI가 필수적입니다. 최종 확진은 반드시 조직 생검을 통한 병리 검사로 이루어지므로, 흉부내과 전문의에게 종합적인 진단을 받으시기 바랍니다.', 3389, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '비소세포성 폐암', '비소세포성폐암', 'TREATMENT', '비소세포성 폐암으로 인한 기침과 호흡 증상 치료는 근본적인 암 치료와 병행하여 증상 완화를 목표로 합니다. 기도 폐쇄로 인한 증상에는 기관지 스텐트 삽입이나 레이저 시술이 고려됩니다. 담당 종양내과 및 흉부외과 전문의와 증상 전반에 대해 상담하시기 바랍니다.', 3390, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '비인두 종양', '비인두종양', 'CAUSE', '비인두 종양은 비인두 부위에서 발생하여 인접 구조물을 압박하거나 침범함으로써 음식물 삼킴에 영향을 줄 수 있습니다. 종양이 인두 및 식도 입구를 좁히거나, 연하 기능에 관여하는 신경을 침범할 경우 연하 곤란, 음식 역류 등의 증상이 나타납니다. 연하 곤란 증상은 이비인후과 전문의에게 조속히 평가받으시기 바랍니다.', 3391, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '비인두 종양', '비인두종양', 'DEFINITION', '이비인후과 코 내시경 검사에서 비인두 종양이 발견되었다면 조직 생검이 필요하며, CT 또는 MRI로 크기와 주변 침범 여부를 평가합니다. 내시경 소견만으로 양성·악성 여부를 판단하기 어려우므로 담당 이비인후과 또는 두경부외과 전문의의 추가 검사를 받으시기 바랍니다.', 3392, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '비인두 종양', '비인두종양', 'SYMPTOM', '귀가 막힌 느낌과 난청, 귀 통증은 비인두 종양의 대표적인 증상입니다. 비인두 종양이 유스타키오관 입구를 막으면 중이에 삼출액이 고여 삼출성 중이염을 유발하고 전음성 난청이 발생합니다. 이러한 증상이 지속된다면 이비인후과 전문의를 방문하여 비인두 내시경 및 청력 검사를 받으시기 바랍니다.', 3393, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '비인두 종양', '비인두종양', 'DIAGNOSIS', '비인두 종양 진단 후 2개월 뒤 재진을 권고하는 것은 종양의 크기 변화, 치료 반응 또는 자연 경과를 추적하기 위한 목적입니다. 증상이 악화된다면 재진 시까지 기다리지 말고 즉시 담당 이비인후과 전문의에게 연락하시기 바랍니다.', 3394, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '비인두 종양', '비인두종양', 'TREATMENT', '수도권 외 지역에서 비인두 종양 치료 병원을 찾으려면 보건복지부 지정 권역별 암센터를 먼저 확인하시기 바랍니다. 국립암센터 홈페이지나 건강보험심사평가원 병원 평가 정보 사이트에서 지역 내 두경부암 전문 병원을 검색할 수 있습니다. 이비인후과 또는 두경부외과가 있는 지역 상급종합병원에서 통합 치료를 받으실 수 있습니다.', 3395, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '소세포성 폐암', '소세포성폐암', 'CHECKUP', '소세포성 폐암 진단을 위한 흉부 CT 검사는 특별한 금식이 필요하지 않으나, 조영제 CT의 경우 4~6시간 전 금식이 필요합니다. 기관지내시경 생검 전에는 혈액 응고 검사와 금식이 필요하며, PET-CT는 6시간 전 금식이 필요합니다. 복용 중인 항응고제나 당뇨약은 담당 의료진에게 반드시 알리시기 바랍니다.', 3396, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '소세포성 폐암', '소세포성폐암', 'DIET_LIFE', '소세포성 폐암 위험을 낮추기 위해 금연이 가장 중요하며, 라돈·석면 등 발암물질 노출을 피하는 것도 필수적입니다. 항산화 성분이 풍부한 신선한 과일과 채소를 충분히 섭취하고, 규칙적인 유산소 운동, 충분한 수면, 스트레스 관리도 면역 기능 유지에 도움이 됩니다. 흡연력이 있다면 정기적인 폐암 검진을 받으시기 바랍니다.', 3397, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '소세포성 폐암', '소세포성폐암', 'MEDICATION', '소세포성 폐암의 약물 치료는 주로 에토포사이드+시스플라틴(EP 요법) 또는 에토포사이드+카보플라틴 조합이 1차 표준 요법으로 사용됩니다. 제한기 소세포폐암의 경우 통상 4~6사이클의 항암화학요법이 방사선 치료와 병행되며, 최근에는 면역항암제 병합 요법도 사용됩니다. 치료 기간과 방법은 담당 종양내과 전문의와 상담하시기 바랍니다.', 3398, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '소세포성 폐암', '소세포성폐암', 'PREVENTION', '소세포성 폐암 예방에서 금연이 가장 효과적입니다. 비타민 C·E, 베타카로틴이 풍부한 채소·과일 섭취가 폐 건강에 유익할 수 있으나, 고용량 베타카로틴 보충제는 흡연자에게 오히려 폐암 위험을 높인다는 연구가 있어 주의가 필요합니다. 흡연력이 있는 경우 저선량 흉부 CT 검진을 정기적으로 받으시기 바랍니다.', 3399, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '소세포성 폐암', '소세포성폐암', 'CAUSE', '소세포성 폐암의 가장 큰 원인은 흡연으로, 전체 소세포폐암의 95% 이상이 흡연과 관련 있습니다. 라돈 가스 노출, 석면·중금속 등 직업성 발암물질, 만성 폐 질환, 가족력도 위험 인자로 알려져 있습니다. 흡연 중이라면 즉각적인 금연이 가장 효과적인 예방 방법입니다.', 3400, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '소세포성 폐암', '소세포성폐암', 'DEFINITION', '색색거리는 숨소리(천명음)와 기침 시 각혈은 폐 및 기도에 심각한 병변이 있음을 시사하는 증상으로, 소세포성 폐암을 포함한 다양한 폐 질환을 의심해볼 수 있습니다. 결핵, 기관지확장증, 폐렴 등에서도 나타날 수 있어 반드시 감별이 필요합니다. 즉시 흉부내과 전문의를 방문하여 흉부 CT 및 기관지내시경 검사를 받으시기 바랍니다.', 3401, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '소세포성 폐암', '소세포성폐암', 'SYMPTOM', '소세포성 폐암에서 호흡 곤란은 종양이 주요 기관지를 막거나 폐 실질을 침범하여 산소 교환 능력이 저하될 때 발생합니다. 현기증은 저산소증, 빈혈, 또는 뇌 전이로 인해 나타날 수 있으며, 소세포폐암은 부종양 증후군을 일으켜 전해질 이상으로도 어지럼증을 유발할 수 있습니다. 담당 종양내과 전문의와 상담하시기 바랍니다.', 3402, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '소세포성 폐암', '소세포성폐암', 'DIAGNOSIS', '기침과 각혈 증상이 있다면 호흡기내과 전문의를 먼저 방문하는 것이 적절합니다. 흉부 CT, 기관지내시경, 객담 세포 검사 등을 통해 정확한 진단을 받을 수 있습니다. 소아에서는 소아 호흡기내과 전문의에게, 성인에서는 호흡기내과 전문의에게 진료를 받으시기 바랍니다.', 3403, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '소세포성 폐암', '소세포성폐암', 'TREATMENT', '소세포성 폐암 치료의 주축은 항암화학요법이며, 제한기에서는 흉부 방사선 치료를 병행합니다. 완전 반응을 보인 환자에게는 예방적 두부 방사선 조사가 뇌 전이 예방에 효과적입니다. 치료 전략은 병기와 전신 상태에 따라 달라지므로 종양내과 전문의와 심층 상담하시기 바랍니다.', 3404, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '식도암', '식도암', 'CHECKUP', '목의 따가움, 통증, 삼킴 불편감이 지속된다면 식도암 감별을 위해 소화기내과를 방문하시기 바랍니다. 상부위장관 내시경 검사가 1차 검사로, 식도 점막 이상 여부를 직접 관찰하고 필요 시 조직 생검이 가능합니다. 증상이 2주 이상 지속된다면 지체 없이 진료를 받으시기 바랍니다.', 3405, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '식도암', '식도암', 'PREVENTION', '목이 따갑고 음식을 삼킬 때 불편감이 오래 지속되는 것은 식도 점막에 자극이나 손상이 있음을 나타내며, 식도암의 조기 증상일 수 있습니다. 특히 역류성 식도염이 장기간 방치되어 바렛식도로 진행한 경우 식도암 위험이 높아집니다. 소화기내과 전문의를 방문하여 내시경 검사를 받으시기 바랍니다.', 3406, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '식도암', '식도암', 'CAUSE', '식도암과 위암 발생에 자극적인 음식은 위험 인자 중 하나이지만 단독으로 가장 큰 원인이라고 볼 수는 없습니다. 식도암의 주요 원인은 흡연, 음주, 역류성 식도염이며, 위암의 경우 헬리코박터 파일로리 감염, 짠 음식·훈제 식품 과다 섭취, 흡연이 주요 원인입니다. 자극적인 음식 섭취가 잦다면 식습관 개선과 함께 소화기내과 정기 검진을 받으시기 바랍니다.', 3407, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '식도암', '식도암', 'DEFINITION', '식도암은 식도에서 발생하는 악성 종양으로, 편평세포암과 선암으로 나뉩니다. 초기에는 증상이 없거나 경미하다가 진행하면 연하 곤란, 체중 감소, 흉통 등이 나타납니다. 예후는 조기 발견 시 크게 향상되므로, 위험 인자가 있거나 증상이 있다면 소화기내과 전문의에게 정기 검진을 받으시기 바랍니다.', 3408, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '식도암', '식도암', 'SYMPTOM', '식도암의 주요 증상은 연하 곤란이 가장 특징적이며, 진행하면서 체중 감소, 흉통, 만성 기침, 쉰 목소리, 역류 증상 등이 나타날 수 있습니다. 종양이 주변 구조물을 침범하면 호흡 곤란, 기침 악화, 목소리 변화 등이 동반될 수 있습니다. 소화기내과 전문의를 방문하여 내시경 및 정밀 검사를 받으시기 바랍니다.', 3409, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '식도암', '식도암', 'DIAGNOSIS', '식도암의 1차 진단 검사는 상부위장관 내시경으로, 식도 점막을 직접 관찰하고 조직 생검이 가능합니다. 조기 식도암은 증상이 거의 없어 내시경 검진으로 발견되는 경우가 많습니다. 위험 인자가 있거나 증상이 있다면 소화기내과 전문의에게 내시경 검사를 받으시기 바랍니다.', 3410, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '식도암', '식도암', 'TREATMENT', '식도암 치료는 병기와 환자 상태에 따라 수술, 방사선 치료, 항암화학요법, 또는 이들의 병합 치료가 사용됩니다. 수술 전 항암화학방사선 치료를 시행하여 종양을 축소한 후 수술하는 방법이 일반적입니다. 치료 방향은 소화기외과·종양내과·방사선종양학과가 포함된 다학제 팀과 상담하시기 바랍니다.', 3411, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '위암', '위암', 'CHECKUP', '체중 감소와 빈혈이 동반된 경우 위내시경 검사를 통해 위 점막을 직접 관찰하고 조직 생검을 시행하여 조기 위암 여부를 진단할 수 있습니다. 조기 위암은 증상이 경미하거나 없는 경우도 많아 내시경 검진이 가장 효과적입니다. 증상이 있다면 소화기내과 전문의를 방문하여 내시경 검사를 받으시기 바랍니다.', 3412, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '위암', '위암', 'DIET_LIFE', '위암 수술 후에는 소량씩 자주(하루 5~6회) 먹는 것이 기본이며, 처음에는 미음이나 죽으로 시작하여 점차 부드러운 음식으로 진행합니다. 덤핑 증후군 예방을 위해 식사 중 수분 섭취를 줄이고, 당분이 많은 음식은 피하는 것이 좋습니다. 퇴원 후 소화기외과 또는 영양사의 식이 교육을 받으시기 바랍니다.', 3413, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '위암', '위암', 'PREVENTION', '위암 예방을 위한 위내시경 검진은 헬리코박터 파일로리 감염, 만성 위축성 위염 등 전단계 병변을 발견하고 치료하는 데 효과적입니다. 국가암검진 프로그램에 따라 만 40세 이상은 2년마다 위내시경 검사를 받도록 권고되고 있습니다. 위암 가족력이 있거나 헬리코박터 감염이 확인된 경우 소화기내과 전문의와 상담하여 더 자주 검진을 받으시기 바랍니다.', 3414, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '위암', '위암', 'CAUSE', '헬리코박터 파일로리는 위 점막에 만성 감염을 일으켜 위축성 위염과 장상피화생으로 진행하면서 위암 발생 위험을 높입니다. 이 균이 분비하는 독소는 위 상피세포의 DNA 손상과 증식 이상을 초래하여 암으로의 전환을 촉진합니다. 헬리코박터 감염이 확인되면 제균 치료를 통해 위암 발생 위험을 유의미하게 낮출 수 있으므로 소화기내과 전문의와 상담하시기 바랍니다.', 3415, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '위암', '위암', 'DEFINITION', '위암은 위 점막에서 발생하는 악성 종양으로, 우리나라에서 발생률이 높은 암 중 하나입니다. 조기 위암은 점막 또는 점막하층에 국한된 경우로 예후가 매우 좋으며, 주요 위험 인자로는 헬리코박터 파일로리 감염, 짠 음식·훈제 식품 과다 섭취, 흡연, 가족력 등이 있습니다. 만 40세 이상은 정기적인 위내시경 검진을 통해 조기 발견이 권고됩니다.', 3416, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '위암', '위암', 'SYMPTOM', '위암이 위 입구에 발생하면 연하 곤란이, 위 출구에 발생하면 식후 구역·구토와 함께 위 팽만감이 주로 나타납니다. 진행된 경우 체중 감소, 흑색변, 빈혈 증상도 동반됩니다. 이러한 증상이 있다면 소화기내과 전문의를 방문하여 위내시경 검사를 받으시기 바랍니다.', 3417, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '위암', '위암', 'DIAGNOSIS', '구토와 체중 감소가 지속된다면 소화기내과 전문의를 먼저 방문하는 것이 적절합니다. 위내시경 검사를 통해 위암을 포함한 상부위장관 질환을 감별할 수 있으며, 필요 시 복부 CT, 혈액 검사를 추가로 시행합니다. 증상이 2주 이상 지속되거나 빠르게 악화된다면 즉시 진료를 받으시기 바랍니다.', 3418, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '위암', '위암', 'TREATMENT', '항암 치료 중 쇼크 증상은 응급 상황으로, 아나필락시스 반응, 패혈증, 심한 탈수, 심장 독성 등 다양한 원인이 있을 수 있습니다. 항암제 투여 후 1주일 내 발생하는 경우 골수 억제로 인한 호중구감소성 패혈증이 흔한 원인 중 하나입니다. 즉각적인 응급 처치가 필요하므로 증상 발생 즉시 치료 중인 병원 응급실이나 담당 종양내과 전문의에게 연락하시기 바랍니다.', 3419, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '유방암', '유방암', 'CHECKUP', '고밀도 유방은 유방 촬영술에서 종양과 유사하게 보여 작은 병변이 가려질 수 있습니다. 이 경우 유방 초음파 추가 검사가 권고되며, 경우에 따라 MRI 검사도 고려됩니다. 고밀도 유방 자체가 유방암 위험 인자이기도 하므로 담당 전문의와 추적 검진 일정을 상담하시기 바랍니다.', 3420, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '유방암', '유방암', 'DIET_LIFE', '유방암 수술 기법은 과거의 전절제술 중심에서 유방 보존술로 크게 발전하였습니다. 최근에는 로봇 수술, 종양성형술, 유방 재건술이 보편화되었으며, 표적 치료제, 면역항암제, CDK4/6 억제제 등 신약의 도입으로 치료 성적도 향상되고 있습니다. 유방외과 전문의와 최신 치료 옵션을 상담하시기 바랍니다.', 3421, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '유방암', '유방암', 'MEDICATION', '유방의 양성 종양은 대부분 경과 관찰하거나 필요 시 수술적 제거가 이루어집니다. 유방 낭종은 주사 흡인으로 치료하며, 섬유선종이 크거나 증가하면 수술적 절제를 시행합니다. 유방외과 전문의의 진단 후 적절한 치료 방향을 결정하시기 바랍니다.', 3422, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '유방암', '유방암', 'PREVENTION', '유방암 예방을 위해 규칙적인 유산소 운동, 건강한 체중 유지, 음주 제한, 모유 수유가 도움이 됩니다. 만 40세 이상은 2년마다 유방 촬영술 검진을 받는 것이 권고됩니다. 가족력이 있거나 BRCA 유전자 이상이 있는 경우 유방외과 전문의와 상담하시기 바랍니다.', 3423, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '유방암', '유방암', 'EXERCISE', '유방암 수술 후 어깨 관절 회복을 위한 스트레칭으로는 벽을 짚고 손가락으로 올라가는 손가락 걷기, 수건을 이용한 어깨 회전 운동, 팔 전방 거상 운동이 효과적입니다. 처음에는 통증 없는 범위에서 시작하여 점차 운동 범위를 늘리는 것이 중요합니다. 재활의학과 또는 물리치료사의 지도를 받아 진행하시기 바랍니다.', 3424, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '유방암', '유방암', 'CAUSE', '가슴 통증과 멍울은 유방암뿐 아니라 섬유선종, 유방낭종, 유선염 등 양성 유방 질환에서도 나타날 수 있는 증상입니다. 멍울이 만져진다면 자가 판단하지 말고 유방외과 전문의를 방문하여 유방 촬영술 및 초음파 검사를 받으시기 바랍니다.', 3425, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '유방암', '유방암', 'DEFINITION', '유방암은 BRCA1, BRCA2 등 유전자 돌연변이와 관련된 유전성 유방암이 전체의 약 5~10%를 차지합니다. 가족 중 유방암 또는 난소암 환자가 여러 명 있거나 젊은 나이에 발병한 경우 유전 상담과 BRCA 유전자 검사를 고려할 수 있습니다. 유방외과 전문의와 위험도 평가를 받으시기 바랍니다.', 3426, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '유방암', '유방암', 'SYMPTOM', '유방암의 초기 증상으로 유방에서 멍울이 만져지는 것이 가장 흔한 증상이며, 대부분 통증이 없는 경우가 많습니다. 통증 없는 단단한 멍울이 오히려 악성 가능성이 높다고 알려져 있습니다. 멍울이 만져진다면 즉시 유방외과 전문의를 방문하여 유방 촬영술 및 초음파 검사를 받으시기 바랍니다.', 3427, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '유방암', '유방암', 'DIAGNOSIS', '유선염의 자가 확인 증상으로는 유방의 국소적 발적, 열감, 부종, 압통이 있으며, 발열과 전신 몸살이 동반되는 경우가 많습니다. 항생제 치료에 반응하지 않는 경우 농양 형성 또는 염증성 유방암과의 감별이 필요합니다. 유방외과 또는 외과 전문의를 방문하여 초음파 검사를 포함한 정확한 진단을 받으시기 바랍니다.', 3428, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '유방암', '유방암', 'TREATMENT', '유방암 진단 후 치료 방법은 병기, 종양 크기, 호르몬 수용체 및 HER2 발현 여부에 따라 결정됩니다. 수술 외에도 방사선 치료, 항암화학요법, 호르몬 치료, HER2 양성인 경우 표적 치료가 있으며, 병기에 따라 병합하여 사용합니다. 유방외과 전문의와 최적의 치료 방향을 상담하시기 바랍니다.', 3429, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '육종', '육종', 'CAUSE', '육종의 발생 원인은 아직 완전히 밝혀지지 않았으나, 유전적 요인, 이전 방사선 치료 노출, 만성 림프 부종, 특정 화학물질 노출이 위험 인자로 알려져 있습니다. 육종이 의심된다면 정형외과 또는 종양외과 전문의의 진료를 받으시기 바랍니다.', 3430, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '육종', '육종', 'DEFINITION', '육종은 뼈, 근육, 지방, 혈관, 신경 등 결합 조직에서 발생하는 악성 종양으로, 전체 암의 약 1%를 차지하는 드문 암입니다. 초기에 통증 없이 서서히 커지는 종괴로 나타나 오랫동안 양성 종양으로 오인될 수 있습니다. 통증 없이 커지는 종괴가 4~5cm 이상이거나 점차 커지는 경향이 있다면 정형외과 또는 종양외과 전문의를 방문하시기 바랍니다.', 3431, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '육종', '육종', 'SYMPTOM', '육종의 증상은 발생 부위와 크기에 따라 다양합니다. 사지에서 발생하는 경우 점차 커지는 무통성 종괴가 흔하며, 신경이나 혈관을 압박하면 통증, 저림, 부종이 발생할 수 있습니다. 이러한 증상이 있다면 종양외과 전문의를 방문하여 정밀 검사를 받으시기 바랍니다.', 3432, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '육종', '육종', 'DIAGNOSIS', '육종 진단에서 MRI가 가장 우선적으로 권고되며, 종양의 연부조직 침범 범위와 신경·혈관과의 관계를 파악할 수 있습니다. CT는 폐 전이 확인에 활용되며, 최종 진단을 위해서는 반드시 조직 생검을 통한 병리 검사가 필요합니다. 정형외과 또는 종양외과 전문의와 상담하시기 바랍니다.', 3433, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '육종', '육종', 'TREATMENT', '육종의 예후는 종양 종류에 따라 크게 다릅니다. 공통적으로 조기 발견, 완전 절제 여부, 종양 등급, 크기, 전이 여부가 예후에 가장 큰 영향을 미칩니다. 정확한 예후 예측을 위해 종양외과 전문의와 상담하시기 바랍니다.', 3434, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자가면역 질환', '자가면역질환', 'CHECKUP', '탈모, 기억력 저하, 소화 장애가 복합적으로 나타나는 경우 자가면역 질환 감별을 위해 자가항체 검사, 갑상선 기능 검사, 전혈구검사 등이 필요합니다. 증상이 여러 계통에 걸쳐 나타난다면 류마티스내과 또는 내과 전문의를 방문하여 종합적인 평가를 받으시기 바랍니다.', 3435, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자가면역 질환', '자가면역질환', 'CAUSE', '자가면역 질환의 발병에는 유전적 소인이 중요한 역할을 하며, 특정 HLA 유전자형이 루푸스, 류마티스관절염 등의 위험을 높입니다. 유전만으로 발병이 결정되지는 않으며 감염, 호르몬, 환경적 요인이 복합적으로 작용합니다. 가족 중 자가면역 질환이 있고 관련 증상이 있다면 류마티스내과 전문의에게 상담을 받으시기 바랍니다.', 3436, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자가면역 질환', '자가면역질환', 'DEFINITION', '자가면역 질환은 면역 시스템이 자신의 신체 조직을 외부 물질로 잘못 인식하여 공격함으로써 발생하는 질환군입니다. 루푸스, 류마티스관절염, 하시모토 갑상선염 등 80종 이상의 질환이 포함되며, 피로감, 발열, 관절 통증 등 다양한 증상이 나타납니다. 증상이 만성적으로 지속된다면 류마티스내과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 3437, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자가면역 질환', '자가면역질환', 'SYMPTOM', '자가면역 질환의 증상은 약물 치료를 통해 완화 또는 관해 상태로 유지될 수 있으나, 대부분 완전한 완치보다는 증상 조절이 치료 목표입니다. 스테로이드는 강력한 항염 효과가 있지만 장기 사용 시 부작용이 있으며, 면역억제제는 감염 취약성을 높일 수 있습니다. 담당 류마티스내과 전문의의 정기적인 모니터링 하에 치료를 진행하시기 바랍니다.', 3438, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자가면역 질환', '자가면역질환', 'DIAGNOSIS', '만성 피로, 체중 변화, 탈모가 복합적으로 나타날 경우 갑상선 질환, 루푸스, 쇼그렌 증후군 등 자가면역 질환을 의심할 수 있습니다. 류마티스내과 또는 내분비내과를 방문하여 자가항체 검사, 갑상선 기능 검사 등을 시행하는 것이 권고됩니다. 자가 판단 없이 전문의를 방문하여 정확한 감별 진단을 받으시기 바랍니다.', 3439, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자가면역 질환', '자가면역질환', 'TREATMENT', '자가면역 질환은 대부분 완치보다 관해 유지와 재발 방지가 목표인 만성 질환으로, 장기적인 치료 전략이 필요합니다. 면역억제 치료를 갑자기 중단하면 반동성 악화가 일어날 수 있어 지속적인 의료진 감독이 필수입니다. 환자 스스로도 정기 검진, 복약 순응, 감염 예방, 스트레스 관리를 통해 질환 관리에 참여하는 것이 중요합니다.', 3440, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자가면역용혈질환', '자가면역용혈질환', 'CAUSE', '자가면역용혈질환의 원인으로는 자가항체 생성 외에도 림프종, 루푸스, 감염, 약물 등이 연관될 수 있습니다. 면역 조절 이상, HLA 유전자형 등 유전적 소인도 발병에 기여합니다. 혈액내과 전문의를 통해 기저 원인에 대한 정밀 평가를 받으시기 바랍니다.', 3441, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자가면역용혈질환', '자가면역용혈질환', 'DEFINITION', '자가면역용혈질환은 면역 시스템이 자신의 적혈구에 대한 자가항체를 생성하여 적혈구를 조기에 파괴함으로써 발생하는 빈혈 질환입니다. 온항체형과 냉항체형으로 나뉘며, 직접 항글로불린 검사(쿰스 검사)가 진단에 중요합니다. 혈액내과 전문의의 정확한 진단과 치료가 필요합니다.', 3442, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자가면역용혈질환', '자가면역용혈질환', 'SYMPTOM', '자가면역용혈질환의 주요 증상으로는 빈혈 증상(피로, 어지럼증, 창백함, 호흡 곤란)이 나타납니다. 용혈 시 방출된 빌리루빈에 의해 황달이 발생할 수 있으며, 중증 용혈 시에는 짙은 갈색 또는 붉은색 소변이 나타나기도 합니다. 이러한 증상이 있다면 혈액내과 전문의를 즉시 방문하시기 바랍니다.', 3443, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자가면역용혈질환', '자가면역용혈질환', 'DIAGNOSIS', '자가면역용혈질환 진단 및 관절 통증 평가를 위해서는 혈액내과 및 류마티스내과 전문의가 있는 상급종합병원을 방문하시기 바랍니다. 쿰스 검사, 전혈구검사, 자가항체 검사 등 정밀 진단이 가능합니다. 관절 통증이 동반된 경우 루푸스 등 전신 자가면역 질환의 이차적 발현일 수 있으므로 통합적 평가가 중요합니다.', 3444, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자가면역용혈질환', '자가면역용혈질환', 'TREATMENT', '자가면역용혈질환의 1차 치료는 스테로이드이며, 반응하지 않거나 재발하는 경우 비장절제술, 리툭시맙 등 면역억제제가 사용됩니다. 중증 용혈 시에는 수혈이 필요할 수 있습니다. 치료 방향은 유형과 중증도에 따라 달라지므로 혈액내과 전문의와 상담하시기 바랍니다.', 3445, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁 상피 내 암종', '자궁상피내암종', 'CHECKUP', '자궁 상피 내 암종 검진에서는 자궁경부 세포 검사가 1차 선별 검사로 가장 널리 사용됩니다. 이상 소견이 발견되면 질확대경 검사 및 조직 생검을 시행합니다. 정기적인 자궁경부 세포 검사가 조기 발견에 가장 효과적이므로 산부인과 전문의를 통해 정기 검진을 받으시기 바랍니다.', 3446, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁 상피 내 암종', '자궁상피내암종', 'DIET_LIFE', '자궁 상피 내 암종 관리에서 생활습관으로는 금연이 가장 중요하며, 균형 잡힌 식단이 면역 기능 강화에 도움이 됩니다. 그러나 생활습관 개선은 보조적인 역할을 하므로, 산부인과 전문의의 치료 및 추적 관찰을 병행하시기 바랍니다.', 3447, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁 상피 내 암종', '자궁상피내암종', 'PREVENTION', '자궁 상피 내 암종의 주요 원인은 HPV 감염으로, 성 접촉을 통해 전파됩니다. 가장 효과적인 예방법은 HPV 백신 접종과 정기적인 자궁경부 세포 검사이므로, 산부인과 전문의와 백신 접종 및 검진 계획을 상담하시기 바랍니다.', 3448, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁 상피 내 암종', '자궁상피내암종', 'CAUSE', '자궁 상피 내 암종의 가장 주요한 원인은 고위험 HPV 16형, 18형 감염으로, 흡연, 면역 기능 저하, 다수의 성 파트너가 위험 인자로 알려져 있습니다. HPV 백신 접종과 정기적인 자궁경부 세포 검사 및 HPV 검사가 예방과 조기 발견에 효과적이므로 산부인과 전문의와 상담하시기 바랍니다.', 3449, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁 상피 내 암종', '자궁상피내암종', 'DEFINITION', '자궁 상피 내 암종은 자궁경부 또는 자궁 내막 상피 세포가 암세포로 변하였으나 아직 기저막을 침범하지 않은 전암 단계입니다. 치료는 병변 범위에 따라 냉동 치료, LEEP, 원추 절제술 등을 시행하며 산부인과 전문의의 치료 후 정기 추적 검사가 필수적입니다.', 3450, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁 상피 내 암종', '자궁상피내암종', 'SYMPTOM', '자궁 상피 내 암종(CIS)은 증상이 없는 경우가 많아 정기 검진이 가장 중요합니다. 비정상적인 질 출혈(성교 후 출혈, 월경 외 출혈), 이상한 질 분비물, 성교 시 통증 등의 증상이 나타날 경우 즉시 세포 검사를 받아야 합니다. 증상 유무에 관계없이 만 20세 이상 여성은 정기적인 자궁경부 세포 검사를 받도록 산부인과 전문의와 상담하시기 바랍니다.', 3451, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁 상피 내 암종', '자궁상피내암종', 'DIAGNOSIS', '자궁 상피 내 암종(CIS)은 암세포가 상피층 내에만 국한되어 기저막을 침범하지 않은 0기 암으로, 의학적으로 암의 한 형태로 공식 인정됩니다. 침윤성 암과 달리 전이 가능성이 매우 낮고 치료 예후가 좋으나, 치료 없이 방치하면 침윤성 암으로 진행될 수 있습니다. 정확한 진단과 치료 방향은 산부인과 또는 부인종양과 전문의와 상담하시기 바랍니다.', 3452, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁 상피 내 암종', '자궁상피내암종', 'TREATMENT', '자궁 상피 내 암종의 치료 방법으로는 루프 전기 절제술(LEEP), 냉동 요법, 레이저 소작술, 원추 절제술 등이 있으며, 각각 비정상 세포가 있는 조직을 제거하거나 파괴하여 암의 진행을 막습니다. 고령이거나 임신을 원하지 않는 경우에는 자궁 적출술이 고려될 수 있습니다. 환자의 나이, 병변 범위, 임신 계획 등에 따라 적합한 치료 방법이 달라지므로 산부인과 전문의와 상담하시기 바랍니다.', 3453, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁경부암', '자궁경부암', 'CHECKUP', '국가암검진 사업에서는 만 12~17세 여성 청소년에게 HPV 백신을 무료 접종하며, 해당 연령을 지난 경우 무료 접종 혜택은 일반적으로 적용되지 않습니다. 단, 지자체별 지원 정책이 다를 수 있으므로 거주지 보건소에 문의하면 추가 지원 여부를 확인할 수 있습니다. 무료 접종 대상이 아니더라도 자비로 접종이 가능하며, 자세한 사항은 산부인과 전문의 또는 보건소와 상담하시기 바랍니다.', 3454, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁경부암', '자궁경부암', 'PREVENTION', '자궁경부암 수술 후에는 균형 잡힌 영양 섭취로 면역력을 높이고 회복을 돕는 것이 중요하며, 과도한 지방과 가공식품 섭취를 줄이고 채소, 과일, 단백질을 충분히 섭취하는 것이 권장됩니다. 전이 예방을 위해 금연, 절주, 규칙적인 운동, 충분한 수면을 유지하고 정기적인 추적 검사를 빠짐없이 받는 것이 중요합니다. 수술 후 생활 습관 관리에 대한 구체적인 지침은 담당 부인종양과 전문의와 상담하시기 바랍니다.', 3455, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁경부암', '자궁경부암', 'CAUSE', '자궁경부암의 주요 원인은 인유두종 바이러스(HPV) 감염으로, 특히 HPV 16형과 18형이 자궁경부암의 약 70%를 차지하는 고위험 바이러스입니다. HPV는 성 접촉을 통해 전파되며, 대부분은 면역계에 의해 자연 소멸되지만 일부에서 지속 감염되어 자궁경부 세포 변이를 유발합니다. 정기적인 자궁경부 세포 검사와 HPV 예방 백신 접종에 대해 산부인과 전문의와 상담하시기 바랍니다.', 3456, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁경부암', '자궁경부암', 'DEFINITION', 'HPV 예방 접종을 받지 않으면 자궁경부암의 주요 원인인 고위험 HPV(16형, 18형 등)에 감염될 경우 이를 예방할 수 없어 자궁경부암 발생 위험이 높아집니다. HPV 백신은 자궁경부암의 약 70%를 예방할 수 있으므로 접종이 강력히 권장되며, 백신 접종을 하더라도 정기적인 자궁경부 세포 검사를 통한 조기 발견이 여전히 중요합니다. HPV 백신 접종과 검진에 대해 산부인과 전문의와 상담하시기 바랍니다.', 3457, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁경부암', '자궁경부암', 'SYMPTOM', '자궁경부암의 원인으로는 HPV(인유두종 바이러스) 지속 감염이 가장 중요하며, 이 외에도 흡연, 면역 저하, 다수의 성 파트너, 이른 성 경험 시작, 경구 피임약 장기 복용, 다산 등이 위험 요인으로 알려져 있습니다. 출혈과 하복부·다리 통증은 자궁경부암이 어느 정도 진행된 경우 나타나는 증상일 수 있으므로 즉시 산부인과 전문의를 방문하시기 바랍니다.', 3458, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁경부암', '자궁경부암', 'DIAGNOSIS', '성교 후 출혈과 악취를 동반한 질 분비물이 있는 경우 자궁경부암이 의심될 수 있으며, 정확한 진단을 위해 자궁경부 세포 검사(Pap smear), HPV 검사, 질확대경(콜포스코피) 검사, 필요시 조직 생검이 필요합니다. 이러한 증상은 자궁경부염, 성병 등 다른 원인일 수도 있으므로 자의적인 판단보다 산부인과 전문의를 즉시 방문하여 정확한 진단을 받으시기 바랍니다.', 3459, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁경부암', '자궁경부암', 'TREATMENT', '자궁경부암 치료에서 자궁 보존 여부는 암의 병기, 연령, 임신 계획에 따라 결정됩니다. 초기(IA1~IB1)이고 임신을 원하는 경우 원추 절제술이나 자궁경부 절제술로 자궁을 보존할 수 있으나, 암이 진행되었거나 임신 계획이 없는 경우에는 광범위 자궁 절제술이 필요합니다. 자궁 보존 가능 여부는 병기, 림프절 전이, 절제연 상태 등에 따라 다르므로 부인종양과 전문의와 충분히 상담하시기 바랍니다.', 3460, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁내막암', '자궁내막암', 'CHECKUP', '자궁내막암 예방을 위한 검진으로는 정기적인 골반 초음파 검사와 자궁내막 세포 흡인 검사 또는 자궁내막 조직 검사가 활용됩니다. 특히 비만, 당뇨, 고혈압, 무배란 이상, 타목시펜 복용자, 가족력이 있는 고위험군은 증상이 없더라도 정기 검진을 받는 것이 권장됩니다. 검진 주기와 방법에 대해서는 산부인과 전문의와 상담하시기 바랍니다.', 3461, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁내막암', '자궁내막암', 'PREVENTION', '현재 자궁내막암에 대한 승인된 예방 백신은 없습니다. 예방을 위해서는 정상 체중 유지, 규칙적인 운동, 당뇨 및 고혈압 관리, 경구 피임약 복용(의사 지도 하), 장기 에스트로겐 단독 호르몬 치료 피하기 등의 생활 습관 관리가 중요합니다. 고위험군에 해당하는 경우 정기적인 산부인과 검진을 통해 조기 발견하는 것이 현재로서 가장 효과적인 예방 방법입니다.', 3462, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁내막암', '자궁내막암', 'CAUSE', '자궁내막암의 발생 위험 요인으로 폐경 지연과 비만이 포함됩니다. 폐경이 늦을수록 에스트로겐에 노출되는 기간이 길어지며, 비만의 경우 지방 조직에서 에스트로겐이 과다 생성되어 자궁내막을 지속적으로 자극하므로 암 발생 위험이 높아집니다. 폐경 지연과 비만 모두 자궁내막암의 위험 요인에 해당하므로 산부인과 전문의와 정기적인 검진 상담을 받으시기 바랍니다.', 3463, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁내막암', '자궁내막암', 'DEFINITION', '자궁내막암은 자궁 내벽(자궁내막)에서 발생하는 악성 종양으로, 주로 50~60대 폐경 전후 여성에게 흔하게 발생합니다. 주요 증상으로는 폐경 후 비정상적인 자궁 출혈, 폐경 전에는 불규칙한 월경이나 월경 과다, 하복부 통증, 골반 통증, 체중 감소 등이 나타날 수 있습니다. 폐경 후 출혈이 발생하면 즉시 산부인과 전문의를 방문하여 검사를 받으시기 바랍니다.', 3464, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁내막암', '자궁내막암', 'SYMPTOM', '자궁내막암의 가장 특징적인 증상은 비정상적인 자궁 출혈로, 폐경 후 출혈이나 폐경 전 불규칙한 월경·월경 과다가 나타납니다. 이 외에도 하복부 또는 골반 통증, 성교 시 통증, 이상한 질 분비물, 체중 감소, 진행된 경우 배뇨 이상이나 변비 등의 증상이 동반될 수 있습니다. 이러한 증상이 나타나면 지체 없이 산부인과 전문의를 방문하여 정확한 검사를 받으시기 바랍니다.', 3465, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁내막암', '자궁내막암', 'DIAGNOSIS', '자궁내막암의 진단을 위해서는 골반 초음파 검사로 자궁내막 두께를 확인하고, 자궁내막 조직 검사(흡인 생검 또는 자궁내막 소파술)를 통해 확진합니다. 폐경 후 비정상 출혈, 불규칙한 월경, 하복부 통증, 이상 분비물 등의 증상이 있을 때 산부인과를 방문하여 진단을 받는 것이 중요합니다. 증상이 있으면 즉시 산부인과 전문의를 방문하시기 바랍니다.', 3466, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁내막암', '자궁내막암', 'TREATMENT', '자궁내막암의 주요 치료 방법은 수술로, 복강경 또는 개복 자궁 절제술(양측 난소·난관 포함)이 기본 치료입니다. 수술 후 병기와 조직학적 소견에 따라 방사선 치료, 항암화학요법, 호르몬 요법(프로게스틴)을 추가적으로 시행할 수 있습니다. 치료 방법은 암의 병기, 환자의 나이, 전신 상태에 따라 달라지므로 부인종양과 전문의와 상담하시기 바랍니다.', 3467, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '전립선암', '전립선암', 'CHECKUP', '전립선암 진단에서 초음파 검사는 전립선의 구조적 이상이나 결절을 확인하고 조직 생검 시 정확한 위치 안내에 활용됩니다. 특히 PSA(전립선특이항원) 수치가 높거나 직장 수지 검사에서 이상 소견이 발견될 때 경직장 초음파 유도 하 생검을 통해 확진합니다. 전립선암 의심 증상이 있거나 PSA 수치 이상이 있는 경우 비뇨의학과 전문의와 상담하시기 바랍니다.', 3468, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '전립선암', '전립선암', 'DIET_LIFE', '전립선암 수술 후 회복을 위해 고단백, 저지방 균형 식단을 유지하고 토마토(라이코펜), 녹차, 십자화과 채소 등 항산화 식품 섭취를 늘리는 것이 도움이 됩니다. 규칙적인 가벼운 걷기 운동, 충분한 수면, 금연, 절주를 실천하고 케겔 운동을 통해 요실금 회복을 도울 수 있습니다. 수술 후 회복 과정에서의 구체적인 식이와 생활 지침은 담당 비뇨의학과 전문의와 상담하시기 바랍니다.', 3469, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '전립선암', '전립선암', 'MEDICATION', '전립선암 치료 약물(항남성호르몬제, 비칼루타마이드, 엔잘루타마이드 등)은 다른 약물과 상호작용할 수 있어 주의가 필요합니다. 혈액 희석제(와파린), 일부 항경련제, 심장 약물 등과의 병용은 약물 효과에 영향을 줄 수 있으므로 모든 복용 중인 약물과 건강기능식품을 담당 의사에게 반드시 알려야 합니다. 약물 병용에 관한 구체적인 주의사항은 담당 비뇨의학과 또는 종양내과 전문의와 상담하시기 바랍니다.', 3470, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '전립선암', '전립선암', 'PREVENTION', '소변이 잘 나오지 않는 증상은 전립선 비대증, 전립선암 등의 전립선 질환을 의심할 수 있으며, 정기적인 PSA 검사와 비뇨의학과 검진을 통한 조기 발견이 중요합니다. 예방을 위해 금연, 절주, 규칙적인 운동, 건강한 체중 유지, 토마토·녹차 등 항산화 식품 섭취가 도움이 될 수 있습니다. 배뇨 장애 증상이 지속되면 즉시 비뇨의학과 전문의를 방문하여 정확한 원인 진단을 받으시기 바랍니다.', 3471, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '전립선암', '전립선암', 'CAUSE', '전립선암의 주요 원인으로는 고령(50세 이상), 가족력, 고지방 식이, 흑인 인종, 남성 호르몬(테스토스테론) 등이 알려져 있습니다. 성관계 빈도 자체가 전립선암의 직접적인 원인이라는 근거는 없으며, 오히려 규칙적인 사정이 전립선암 위험을 낮춘다는 일부 연구 결과도 있습니다. 전립선암 위험 요인 평가와 검진에 대해서는 비뇨의학과 전문의와 상담하시기 바랍니다.', 3472, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '전립선암', '전립선암', 'DEFINITION', '전립선암은 전립선에서 발생하는 악성 종양으로, 초기에는 무증상인 경우가 많아 PSA 검사를 통한 조기 발견이 중요합니다. 다른 암과 비교하여 일반적으로 진행이 느리고 예후가 상대적으로 좋은 편이나, 진행되면 뼈 전이가 흔하며 골반 통증이나 병적 골절이 나타날 수 있습니다. 정확한 진단과 치료 방향은 비뇨의학과 전문의와 상담하시기 바랍니다.', 3473, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '전립선암', '전립선암', 'SYMPTOM', '배뇨 후 잔뇨감이나 찝찝한 느낌은 전립선암의 초기 증상 중 하나일 수 있으나, 전립선 비대증이나 전립선염에서도 흔히 나타나는 증상입니다. 전립선암은 초기에는 증상이 없는 경우가 많고 증상만으로 전립선암과 다른 전립선 질환을 구별하기 어려우므로, PSA 혈액 검사와 직장 수지 검사를 통한 정확한 감별이 필요합니다. 해당 증상이 지속될 경우 비뇨의학과 전문의를 방문하시기 바랍니다.', 3474, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '전립선암', '전립선암', 'DIAGNOSIS', '전립선 통증만으로 전립선암을 자가 진단하는 것은 어려우며, 전립선암 초기에는 통증이 없는 경우가 많습니다. 전립선암 선별 검사로는 PSA(전립선특이항원) 혈액 검사가 가장 기본적이며, 이상 소견이 있을 경우 직장 수지 검사와 경직장 초음파 유도 하 조직 생검을 통해 확진합니다. 자가 진단보다는 50세 이상 남성(가족력 있는 경우 45세부터)은 정기적으로 비뇨의학과 전문의를 방문하시기 바랍니다.', 3475, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '전립선암', '전립선암', 'TREATMENT', '전립선암의 치료 방법으로는 근치적 전립선 절제술, 방사선 치료(외부 방사선, 브라키테라피), 호르몬 요법, 항암화학요법, 면역 치료 등이 있습니다. 국소 전립선암은 수술이나 방사선 치료로 완치를 기대할 수 있으며, 고령이거나 저위험군은 적극적 감시(active surveillance)도 선택될 수 있습니다. 최적의 치료 방법은 암의 병기, 글리슨 점수, PSA 수치, 환자 상태에 따라 다르므로 비뇨의학과 전문의와 충분히 상담하시기 바랍니다.', 3476, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '전이 암', '전이암', 'CAUSE', '전이 암은 원발 부위의 암세포가 혈액이나 림프계를 통해 다른 장기로 이동하여 새로운 종양을 형성한 것으로, 원발 암의 종류에 따라 전이 부위가 다릅니다. 치료는 원발 암의 종류와 전이 부위, 환자 상태에 따라 항암화학요법, 표적 치료, 면역 치료, 방사선 치료, 완화 치료 등을 복합적으로 사용합니다. 전이 암의 치료 계획은 종양내과 전문의와 다학제팀 상담을 통해 결정하시기 바랍니다.', 3477, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '전이 암', '전이암', 'DEFINITION', '전이 암은 원발 종양의 암세포가 혈관이나 림프관으로 침투하여 혈류 또는 림프류를 타고 이동한 뒤, 다른 장기에 정착하여 증식하는 경로로 발생합니다. 주요 전이 경로로는 혈행성 전이(혈관을 통한 폐, 간, 뼈, 뇌 전이)와 림프성 전이(림프절 전이), 복막 전이 등이 있습니다. 원발 암의 종류에 따라 전이 패턴이 다르므로 담당 종양내과 전문의와 상담하시기 바랍니다.', 3478, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '전이 암', '전이암', 'SYMPTOM', '림프절의 멍울이 수 시간 만에 만져지는 경우는 전이 암보다는 급성 감염이나 염증 반응일 가능성이 높습니다. 전이 암으로 인한 림프절 비대는 서서히 진행되며 통증이 없는 경우가 많고, 단단하고 고정된 느낌이 특징입니다. 갑자기 생긴 림프절 멍울은 감염, 염증 등 다양한 원인이 있을 수 있으므로 즉시 내과 또는 전문의를 방문하여 정확한 원인 평가를 받으시기 바랍니다.', 3479, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '전이 암', '전이암', 'DIAGNOSIS', '전이 암 환자는 추적 검사 시 CT, PET-CT, MRI, 뼈 스캔 등 영상 검사와 종양표지자 혈액 검사를 병행하여 원발 부위와 기존 전이 부위의 반응, 새로운 전이 여부를 평가합니다. 검사의 종류와 주기는 원발 암의 종류, 전이 부위, 치료 경과에 따라 달라지며 담당 의사가 개별적으로 결정합니다. 정확한 추적 검사 계획은 담당 종양내과 전문의와 상담하시기 바랍니다.', 3480, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '전이 암', '전이암', 'TREATMENT', '전이 암의 치료는 완치보다는 암의 진행 억제와 증상 완화, 삶의 질 향상을 목표로 하는 경우가 많습니다. 치료 방법으로는 항암화학요법, 표적 치료제, 면역관문억제제, 호르몬 요법, 방사선 치료, 수술(일부 경우), 완화 치료 등이 원발 암의 종류와 전이 부위에 따라 선택됩니다. 전이 암의 치료 가능 여부와 구체적인 치료 계획은 종양내과 전문의와 다학제 팀을 통해 상담하시기 바랍니다.', 3481, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '조기 위암', '조기위암', 'PREVENTION', '잘못된 식습관(고염식이, 훈제·가공식품 과다 섭취, 신선 채소·과일 부족), 흡연, 헬리코박터균 감염 등의 위험요인을 관리하면 조기 위암 예방에 긍정적인 영향을 미칩니다. 저염식, 금연, 신선한 채소와 과일 섭취 증가, 헬리코박터균 치료를 통해 위암 발생 위험을 줄일 수 있습니다. 위험 요인 관리와 함께 정기적인 위내시경 검사를 통한 조기 발견도 중요하므로 소화기내과 전문의와 상담하시기 바랍니다.', 3482, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '조기 위암', '조기위암', 'CAUSE', '헬리코박터 파일로리(H. pylori)균은 위 점막에 만성 염증을 일으키고, 위축성 위염과 장상피화생을 거쳐 위암으로 진행될 수 있는 중요한 위암 위험 인자입니다. 건강 검진에서 조기 위암이 발견된 경우 헬리코박터균 감염 여부를 확인하고, 감염이 있다면 제균 치료를 받는 것이 권장됩니다. 조기 위암의 정확한 원인과 치료 계획은 소화기내과 또는 외과 전문의와 상담하시기 바랍니다.', 3483, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '조기 위암', '조기위암', 'DEFINITION', '조기 위암은 암세포가 위의 점막층 또는 점막하층에만 국한된 암으로, 림프절 전이 유무에 관계없이 이 정의에 해당합니다. 즉, 조기 위암이라도 림프절 전이가 있을 수 있으며, 반드시 전이가 없는 상태만을 의미하지 않습니다. 정확한 병기와 림프절 전이 여부는 내시경 초음파, CT 검사 등을 통해 평가하며, 치료 방향은 소화기내과 또는 외과 전문의와 상담하시기 바랍니다.', 3484, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '조기 위암', '조기위암', 'SYMPTOM', '소화 불량과 상복부 불편감은 조기 위암뿐 아니라 위염, 위궤양 등에서도 나타나는 비특이적 증상이나, 증상이 지속되거나 반복된다면 방치하지 않는 것이 중요합니다. 이러한 증상이 있을 경우 소화기내과를 방문하여 위내시경 검사를 받아 조기에 이상 여부를 확인하는 것이 권장됩니다. 자의적으로 소화제를 장기 복용하기보다 전문의의 진단을 통해 원인을 확인하시기 바랍니다.', 3485, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '조기 위암', '조기위암', 'DIAGNOSIS', '조기 위암을 내시경으로 진단하고 치료하는 병원은 고해상도 내시경 장비와 내시경 점막하 박리술(ESD) 또는 내시경 점막 절제술(EMR)을 시행할 수 있는 숙련된 내시경 전문의가 있어야 합니다. 대형 병원이나 암 전문 센터에서는 이러한 장비와 전문 인력을 갖추고 있는 경우가 많습니다. 내시경 치료 가능 여부와 적합한 의료 기관 선택에 대해서는 소화기내과 전문의와 상담하시기 바랍니다.', 3486, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '조기 위암', '조기위암', 'TREATMENT', '조기 위암 치료로는 내시경 점막하 박리술(ESD), 내시경 점막 절제술(EMR), 복강경 또는 개복 위 절제술 등이 고려되며, 종양의 크기·위치·분화도·림프절 전이 위험에 따라 선택됩니다. 고령이거나 수술 위험이 높은 환자의 경우 내시경 치료나 보존적 치료가 우선 고려될 수 있으며, 환자의 생활 습관과 전신 상태도 치료 계획에 반영됩니다. 구체적인 치료 방법은 소화기내과 및 외과 전문의와 충분히 상담하시기 바랍니다.', 3487, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '직장암', '직장암', 'CHECKUP', '배변 시 통증과 잔변감이 있을 경우 직장암을 포함하여 치질, 과민성 대장 증후군, 직장염 등 다양한 원인을 감별해야 합니다. 직장암 진단을 위해서는 직장 수지 검사, 대장 내시경 검사, 조직 생검, CT 또는 MRI 검사 등이 시행됩니다. 이러한 증상이 지속되면 대장항문외과 또는 소화기내과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 3488, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '직장암', '직장암', 'DIET_LIFE', '직장암 항암 치료 중에는 충분한 수분 섭취, 고단백 식이(닭가슴살, 생선, 두부 등), 소화하기 쉬운 음식 섭취로 영양 상태를 유지하는 것이 부작용 완화에 도움이 됩니다. 규칙적인 가벼운 운동(산책), 충분한 수면, 스트레스 관리를 통해 면역력을 유지하고, 설사가 심할 경우 저섬유질 식이로 조절하는 것이 권장됩니다. 생활 습관 개선의 구체적인 방법은 담당 종양내과 전문의 또는 영양사와 상담하시기 바랍니다.', 3489, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '직장암', '직장암', 'MEDICATION', '직장암에서 수술 전 방사선·항암 병합 치료(선행 치료)를 시행하면 종양의 크기를 줄여 수술 절제 가능성을 높이고 항문 보존율을 향상시킬 수 있으며, 수술 후 항암치료의 효과와 예후에도 긍정적인 영향을 미칩니다. 또한 항암제를 종양 부위에 직접 적용하거나 전신 투여하는 방식은 미세 전이 세포를 제거하여 재발 위험을 낮출 수 있습니다. 구체적인 치료 순서와 약물 선택은 대장항문외과 및 종양내과 전문의와 상담하시기 바랍니다.', 3490, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '직장암', '직장암', 'PREVENTION', '직장암 예방을 위해 포화 지방과 붉은 육류·가공육 섭취를 줄이고 식이 섬유가 풍부한 채소, 과일, 통곡물 섭취를 늘리는 것은 과학적으로 권장되는 효과적인 예방 방법입니다. 그러나 식이 요법 외에도 금연, 절주, 규칙적인 운동, 정상 체중 유지, 정기적인 대장 내시경 검사가 함께 이루어질 때 예방 효과가 더욱 높아집니다. 종합적인 예방 전략에 대해 소화기내과 또는 대장항문외과 전문의와 상담하시기 바랍니다.', 3491, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '직장암', '직장암', 'EXERCISE', '직장암 치료 중 환자에게 권장되는 운동으로는 가벼운 걷기, 수영, 스트레칭 등 저강도 유산소 운동이 적합합니다. 규칙적인 운동은 항암 치료 부작용(피로감, 근력 저하) 완화, 장운동 개선, 정신건강 향상에 도움이 됩니다. 운동의 강도와 종류는 치료 단계와 환자 상태에 따라 달라질 수 있으므로 담당 종양내과 전문의 또는 재활의학과 전문의와 상담 후 시행하시기 바랍니다.', 3492, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '직장암', '직장암', 'CAUSE', '혈변과 가는 변은 직장암의 원인이 아니라 직장암으로 인해 나타나는 증상입니다. 직장에 종양이 생기면 장 내강이 좁아져 변이 가늘어지고, 종양 표면이 상처를 받거나 혈관이 풍부한 종양 조직에서 출혈이 발생하여 혈변이 나타납니다. 이러한 증상은 치질 등 다른 질환과 유사할 수 있으므로, 지속적인 혈변과 배변 습관 변화가 있으면 대장항문외과 전문의를 방문하여 정확한 검사를 받으시기 바랍니다.', 3493, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '직장암', '직장암', 'DEFINITION', '직장암은 대장의 말단 부분인 직장(항문에서 약 15cm 이내)에서 발생하는 악성 종양으로, 직장 점막의 선세포에서 시작됩니다. 암은 점막층에서 시작하여 점막하층, 근육층, 장막층으로 점차 침범하고 림프절, 혈관을 통해 간, 폐 등으로 전이될 수 있습니다. 정확한 진단과 치료를 위해 대장항문외과 또는 소화기내과 전문의와 상담하시기 바랍니다.', 3494, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '직장암', '직장암', 'SYMPTOM', '잔변감(변을 보고 나서도 변이 남은 느낌)은 직장암의 대표적인 증상 중 하나인 이급후중(tenesmus)으로, 직장 내 종양이 직장 점막을 자극하여 발생합니다. 설사와 잔변감이 함께 나타나는 경우 직장암 외에도 직장염, 과민성 장 증후군 등의 가능성도 있습니다. 이러한 증상이 지속될 경우 대장항문외과 또는 소화기내과 전문의를 방문하여 대장 내시경 검사를 받으시기 바랍니다.', 3495, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '직장암', '직장암', 'DIAGNOSIS', '식욕부진, 체중 감소, 혈변, 가는 변 등의 증상이 있을 경우 대장 내시경 검사를 통해 직장 내 종양 유무를 확인하고, 이상 소견이 있으면 조직 생검으로 확진합니다. 추가로 CT, MRI 검사를 통해 암의 병기와 전이 여부를 평가합니다. 이러한 증상들이 나타나면 지체하지 말고 대장항문외과 또는 소화기내과 전문의를 방문하여 정확한 진단을 받으시기 바랍니다.', 3496, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '직장암', '직장암', 'TREATMENT', '직장암 치료에서 혈변, 복부 불편감, 배변 장애 증상이 있을 때 항암화학요법으로는 5-FU(플루오로우라실), 카페시타빈, 옥살리플라틴, 이리노테칸 등이 단독 또는 병합으로 사용됩니다. 수술 전 방사선과 항암제 병합 치료(FOLFOX, FOLFIRI 등)는 종양 축소에 효과적입니다. 구체적인 약물 치료 선택과 계획은 종양내과 전문의와 충분히 상담하시기 바랍니다.', 3497, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '질암', '질암', 'PREVENTION', 'HPV 예방 백신(가다실, 서바릭스)은 질암의 주요 원인인 고위험 HPV 감염을 예방함으로써 HPV 관련 질암 발생 위험을 의미 있게 줄일 수 있습니다. 백신 접종을 완료한 경우 HPV 16형·18형 등 고위험 바이러스에 의한 질암 예방 효과를 기대할 수 있으나, 모든 유형의 질암을 완전히 예방하지는 못합니다. 백신 접종 후에도 정기적인 부인과 검진을 통해 조기 발견에 노력하시기 바랍니다.', 3498, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '질암', '질암', 'CAUSE', '성 파트너 수가 많을수록 HPV(인유두종 바이러스), HSV(단순 헤르페스 바이러스), 클라미디아 등 성병에 노출될 기회가 증가하여 감염 위험이 높아집니다. HPV는 질암의 주요 원인이며, 반복적인 성병 감염은 생식기 점막의 손상과 면역 저하를 일으켜 암 발생 위험을 증가시킬 수 있습니다. 성병 예방을 위해 콘돔 사용, HPV 예방 접종, 정기적인 부인과 검진을 산부인과 전문의와 상담하시기 바랍니다.', 3499, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '질암', '질암', 'DEFINITION', '질암은 유전적 요인이 발병에 일부 기여할 수 있으나, 직접적인 유전성 암으로 분류되지는 않습니다. 가족 중 자궁경부암, 질암, 외음부암 등의 HPV 관련 암 병력이 있는 경우 HPV 감염 위험과 관련된 환경적 요인이 공유될 수 있어 주의가 필요합니다. 가족력이 있는 경우 정기적인 부인과 검진과 HPV 예방 접종에 대해 산부인과 전문의와 상담하시기 바랍니다.', 3500, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '질암', '질암', 'SYMPTOM', '질암의 주요 증상인 비정상적인 질 출혈 외에도 악취를 동반한 이상 질 분비물, 성교 시 통증 또는 출혈, 배뇨 장애(빈뇨, 배뇨 시 통증), 골반 통증, 진행된 경우 변비나 직장 통증 등이 나타날 수 있습니다. 질 부위에 만져지는 덩어리나 궤양이 관찰될 수도 있습니다. 이러한 증상이 나타나면 즉시 산부인과 전문의를 방문하여 정확한 검사를 받으시기 바랍니다.', 3501, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '질암', '질암', 'DIAGNOSIS', '자궁경부 세포 검사(Pap smear)는 자궁경부에서 세포를 채취하여 비정상 세포 여부를 확인하는 검사로, 이상 소견 시 HPV 검사와 질확대경(콜포스코피) 검사를 추가로 시행합니다. 질확대경 검사에서 이상 소견이 보이면 조직 생검을 통해 확진하며, 이를 통해 정상, 이형성증, 상피 내 암종, 침윤성 암 등을 정확히 구별할 수 있습니다. 검사 방법과 주기에 대해서는 산부인과 전문의와 상담하시기 바랍니다.', 3502, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '질암', '질암', 'TREATMENT', '질암의 치료 방법은 수술, 방사선 치료, 항암화학요법을 단독 또는 병합으로 사용하며, 어느 방법이 가장 효과적인지는 암의 병기, 위치, 크기, 환자 상태에 따라 다릅니다. 초기 질암에는 수술이나 방사선 치료가 효과적이며, 진행된 경우에는 방사선과 항암제 병합 요법이 주로 사용됩니다. 각 치료법의 부작용과 효과는 개인차가 있으므로 부인종양과 전문의와 충분히 상담하여 최적의 치료 방법을 선택하시기 바랍니다.', 3503, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '척수 종양', '척수종양', 'PREVENTION', '감각 이상, 저린 느낌, 근력 약화, 보행 장애 증상이 있을 때 척수 종양을 정확히 평가하기 위해서는 척추 MRI(자기공명영상) 검사가 가장 중요한 검사입니다. 필요에 따라 CT 척수조영술을 추가로 시행하며, 종양이 발견된 경우 조직 생검을 통해 종양의 종류와 악성 여부를 확인합니다. 이러한 증상이 있으면 신경외과 또는 신경과 전문의를 방문하여 정확한 검사를 받으시기 바랍니다.', 3504, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '척수 종양', '척수종양', 'CAUSE', '척수 종양의 발생과 특정 음식, 비타민제, 스트레스 사이의 직접적인 인과관계는 현재까지 과학적으로 명확히 입증되지 않았습니다. 일부 척수 종양은 유전적 요인(신경섬유종증 등), 방사선 치료 과거력, 면역 저하 등과 관련될 수 있습니다. 척수 종양이 의심되는 증상이 있을 경우 신경외과 전문의를 방문하여 정확한 원인 평가를 받으시기 바랍니다.', 3505, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '척수 종양', '척수종양', 'DEFINITION', '강아지의 다리 저는 증상은 척수 종양 외에도 추간판 탈출증, 관절 질환, 근육 손상 등 다양한 원인이 있을 수 있으며, 이는 인체 의학이 아닌 수의학의 영역입니다. 반려동물의 정확한 진단을 위해서는 동물병원에서 신경학적 검사, X선, MRI 등의 영상 검사를 받는 것이 필요합니다. 반려동물의 증상에 대해서는 수의사를 방문하여 적절한 진단과 치료를 받으시기 바랍니다.', 3506, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '척수 종양', '척수종양', 'SYMPTOM', '척수 종양 말기에 나타날 수 있는 신체적 변화로는 완전한 하반신 또는 사지 마비, 대소변 실금이나 완전한 배뇨·배변 기능 상실, 극심한 신경 통증, 호흡근 마비(경추 종양의 경우), 욕창 발생 등이 있습니다. 종양의 위치와 크기에 따라 증상 진행 속도와 양상이 다를 수 있습니다. 정확한 진단과 치료 계획은 신경외과 전문의와 상담하시기 바랍니다.', 3507, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '척수 종양', '척수종양', 'DIAGNOSIS', '척수 종양 진단에는 가돌리늄 조영제를 사용한 척추 MRI가 가장 정확한 검사로, 종양의 위치, 크기, 척수와의 관계를 명확히 확인할 수 있습니다. MRI 촬영이 어려운 경우(체내 금속 삽입물 등) CT 척수조영술이 대안이 될 수 있습니다. 두 검사의 선택과 추가 검사 필요 여부는 신경외과 전문의와 상담하여 결정하시기 바랍니다.', 3508, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '척수 종양', '척수종양', 'TREATMENT', '척수 종양의 치료는 수술적 절제가 기본이나, 종양의 종류, 위치, 신경 조직과의 관계에 따라 완전 절제가 어려울 수 있습니다. 수술 외에도 방사선 치료(일반 방사선 또는 정위적 방사선수술), 항암화학요법, 표적 치료 등이 종양의 종류에 따라 추가로 고려됩니다. 척수 기능 보존과 치료 효과를 모두 고려한 최적의 치료 계획은 신경외과 전문의와 다학제 팀의 상담을 통해 결정하시기 바랍니다.', 3509, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '철결핍빈혈', '철결핍빈혈', 'CHECKUP', '철결핍빈혈과 창백함에 대한 진단은 내과, 가정의학과, 혈액내과에서 받을 수 있으며, 혈액 검사(전혈구검사, 혈청 페리틴, 혈청 철, TIBC 등)를 통해 진단합니다. 소아의 경우 소아과, 여성의 경우 산부인과에서도 초기 평가를 받을 수 있습니다. 빈혈 증상이 있다면 가까운 내과 또는 가정의학과를 방문하여 혈액 검사를 받아보시기 바랍니다.', 3510, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '철결핍빈혈', '철결핍빈혈', 'DIET_LIFE', '철결핍빈혈 환자는 철분이 풍부한 식품(붉은 육류, 간, 굴, 두부, 시금치, 콩류)을 충분히 섭취하고, 철분 흡수를 돕는 비타민 C(오렌지, 키위 등)와 함께 먹는 것이 도움이 됩니다. 반면 철분 흡수를 방해하는 녹차, 커피, 탄닌 함유 식품은 철분제 복용 전후 1~2시간 내에 피하는 것이 좋습니다. 식이요법만으로 부족할 경우 의사의 처방에 따른 철분제 복용이 필요하므로 내과 또는 혈액내과 전문의와 상담하시기 바랍니다.', 3511, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '철결핍빈혈', '철결핍빈혈', 'MEDICATION', '철분제와 함께 복용 시 철분 흡수를 방해하거나 상호작용하는 약물로는 제산제(탄산칼슘, 수산화알루미늄), 양성자 펌프 억제제, H2 차단제, 일부 항생제(퀴놀론계, 테트라사이클린계), 레보티록신, 칼슘제 등이 있습니다. 이러한 약물들은 철분제와 최소 2시간 간격을 두고 복용하는 것이 권장됩니다. 현재 복용 중인 모든 약물과의 상호작용에 대해 담당 의사 또는 약사와 상담하시기 바랍니다.', 3512, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '철결핍빈혈', '철결핍빈혈', 'PREVENTION', '월경 과다 출혈로 인한 철결핍빈혈 예방을 위해서는 월경 과다의 원인(자궁 근종, 자궁내막증 등)을 먼저 산부인과에서 진단받고 적절히 치료하는 것이 가장 중요합니다. 월경 과다를 줄이기 위한 약물로는 호르몬 치료(경구 피임약, 레보노르게스트렐 자궁내장치)나 트라넥삼산 등이 사용될 수 있으며, 이는 반드시 의사의 처방에 따라 복용해야 합니다. 월경 과다 원인 평가와 치료 방향을 산부인과 전문의와 상담하시기 바랍니다.', 3513, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '철결핍빈혈', '철결핍빈혈', 'EXERCISE', '철결핍빈혈로 인한 어지럼증과 무력감이 있을 때는 무리한 고강도 운동보다 가벼운 걷기, 스트레칭, 수영 등 저강도 유산소 운동부터 시작하는 것이 권장됩니다. 규칙적인 적당한 운동은 혈액 순환 개선과 체력 회복에 도움이 될 수 있으나, 어지럼증이 심한 경우에는 낙상 위험이 있으므로 증상이 호전된 후 운동 강도를 점진적으로 늘려야 합니다. 운동 시작 전 철분 수치를 정상화하는 것이 우선이므로 내과 전문의와 상담하시기 바랍니다.', 3514, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '철결핍빈혈', '철결핍빈혈', 'CAUSE', '혈중 철분 수치가 낮아지는 주요 원인으로는 철분 섭취 부족(편식, 채식 위주 식단), 흡수 장애(위장관 수술, 크론병, 만성 위염), 출혈(월경 과다, 소화관 출혈, 잦은 헌혈), 임신·수유로 인한 철분 수요 증가 등이 있습니다. 성장기 아동과 임산부는 철분 요구량이 높아 부족해지기 쉽습니다. 철분 수치 저하의 정확한 원인 파악을 위해 내과 또는 혈액내과 전문의와 상담하시기 바랍니다.', 3515, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '철결핍빈혈', '철결핍빈혈', 'DEFINITION', '철결핍빈혈은 철분 부족으로 헤모글로빈 합성이 저하되어 적혈구의 산소 운반 능력이 감소하고, 이로 인해 뇌로 가는 산소 공급이 줄어 어지럼증이 나타납니다. 철분 영양제나 철분제를 복용하면 혈중 철분이 보충되어 헤모글로빈 수치가 회복되고, 산소 운반 능력이 개선되면서 어지럼증 완화에 도움이 됩니다. 철분제 용량과 복용 기간은 검사 결과에 따라 다르므로 내과 전문의의 처방에 따라 복용하시기 바랍니다.', 3516, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '철결핍빈혈', '철결핍빈혈', 'SYMPTOM', '철결핍빈혈의 증상으로는 창백한 피부 외에도 극심한 피로감과 무기력, 어지럼증, 두통, 심계항진(가슴 두근거림), 호흡 곤란, 손발 저림, 손톱의 숟가락 모양 변형(koilonychia), 이식증(흙·얼음 등 비식품 섭취 욕구), 구내염, 혀 통증(설염) 등이 나타날 수 있습니다. 이러한 증상들이 복합적으로 나타날 경우 내과 또는 혈액내과 전문의를 방문하여 혈액 검사를 받으시기 바랍니다.', 3517, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '철결핍빈혈', '철결핍빈혈', 'DIAGNOSIS', '철결핍빈혈 진단은 내과, 가정의학과, 혈액내과에서 받을 수 있으며, 혈액 검사(전혈구검사, 혈청 페리틴, 혈청 철, 총철결합능)를 통해 진단합니다. 증상이 있다면 가까운 내과나 가정의학과를 먼저 방문하면 되며, 원인이 불명확하거나 치료에 반응하지 않는 경우 혈액내과로 의뢰될 수 있습니다. 빈혈 증상이 있다면 자의적으로 철분제를 복용하기 전에 전문의 진단을 먼저 받으시기 바랍니다.', 3518, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '철결핍빈혈', '철결핍빈혈', 'TREATMENT', '임신성 빈혈(철결핍빈혈)로 인한 부종, 빈맥, 손톱 변형, 어지럼증 증상의 치료로는 경구 철분제 복용이 기본 치료이며, 경구 복용이 어렵거나 흡수 불량이 있는 경우 정맥 주사 철분 요법을 시행합니다. 철분이 풍부한 식단(적색 육류, 콩류, 녹색 채소)과 비타민 C를 함께 섭취하면 흡수에 도움이 됩니다. 임신 중 빈혈 치료는 태아에게도 영향을 미치므로 반드시 산부인과 전문의의 처방과 지도 하에 치료받으시기 바랍니다.', 3519, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '췌장암', '췌장암', 'CHECKUP', '췌장암 진단에서 혈당 관리는 중요한데, 췌장암이 인슐린 분비 기능을 저하시켜 당뇨를 유발하거나 기존 당뇨를 악화시킬 수 있으므로 갑작스러운 혈당 조절 불량은 췌장암의 신호일 수 있습니다. 췌장암 진단에 효과적인 검사로는 복부 CT(3상 CT), MRI/MRCP, 내시경 초음파(EUS), CA 19-9 등 종양표지자 혈액 검사, 내시경 역행성 담췌관 조영술(ERCP) 등이 있습니다. 정확한 진단을 위해 소화기내과 또는 소화기외과 전문의와 상담하시기 바랍니다.', 3520, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '췌장암', '췌장암', 'DIET_LIFE', '췌장암 수술 후에는 소량씩 자주 먹는 방식(하루 5~6회 소식)으로 소화 기능을 보호하고, 저지방·고단백 식이를 유지하면서 소화 효소제를 처방에 따라 복용하는 것이 중요합니다. 알코올과 고지방 음식을 피하고, 혈당 관리를 위해 단순당을 제한하며 당뇨 식이요법이 필요할 수 있습니다. 수술 후 구체적인 식이 계획은 담당 외과 전문의 및 영양사와 상담하시기 바랍니다.', 3521, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '췌장암', '췌장암', 'MEDICATION', '췌장암 치료에서 젬시타빈은 현재 표준 1차 항암제로 내약성이 상대적으로 좋으나, 5-FU 기반 요법(FOLFIRINOX)이 젬시타빈보다 반응률과 생존율 측면에서 더 효과적이라는 연구 결과가 있습니다. 다만 FOLFIRINOX는 부작용(오심, 구토, 신경 독성, 혈액 독성)이 더 강하여 전신 상태가 양호한 환자에게 주로 사용됩니다. 두 약물의 선택은 환자의 전신 상태와 병기에 따라 달라지므로 종양내과 전문의와 상담하시기 바랍니다.', 3522, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '췌장암', '췌장암', 'PREVENTION', '췌장암 가족력이 있는 경우(특히 1촌 내 2명 이상 또는 BRCA2, PALB2 등 유전적 돌연변이 보유자)는 일반인보다 췌장암 발생 위험이 높아 정기적인 췌장 검진이 권장됩니다. 고위험군의 건강 상태 변화로는 체중 감소, 갑작스러운 당뇨 발생, 황달, 복통, 식욕 감소 등의 증상을 주의 깊게 관찰해야 합니다. 가족력이 있는 경우 소화기내과 전문의와 상담하여 적절한 검진 프로그램을 결정하시기 바랍니다.', 3523, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '췌장암', '췌장암', 'CAUSE', '췌장암의 대부분(약 85%)은 외분비 세포 유래 선암종(adenocarcinoma)이며, 원인으로는 흡연(가장 강력한 위험 요인), 만성 췌장염, 당뇨병, 비만, 과도한 음주, 가족력(유전적 돌연변이), 발암 화학물질 노출 등이 있습니다. 내분비 세포 기원 종양(신경내분비종양)은 비교적 드물며 예후가 더 좋습니다. 정확한 원인 평가와 검진에 대해서는 소화기내과 전문의와 상담하시기 바랍니다.', 3524, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '췌장암', '췌장암', 'DEFINITION', '초음파에서 췌장에 발견된 작은 병변은 췌장 낭종, 췌관 내 유두상 점액 종양(IPMN), 낭성 종양, 또는 췌장암의 초기 병변일 가능성이 있으므로 추가 정밀 검사가 필요합니다. 정확한 감별을 위해 복부 CT(3상), MRI/MRCP, 내시경 초음파(EUS) 등의 정밀 검사를 받아야 합니다. 초음파에서 이상 소견이 발견된 경우 즉시 소화기내과 전문의를 방문하여 추가 검사를 받으시기 바랍니다.', 3525, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '췌장암', '췌장암', 'SYMPTOM', '췌장암의 증상으로는 체중 감소 외에도 복부 또는 등 통증(상복부에서 등으로 방사되는 통증), 황달(눈·피부 노랗게 변함), 소화 불량, 식욕 감소, 오심·구토, 새로 발생한 당뇨 또는 기존 당뇨 악화, 지방변(기름진 대변) 등이 나타날 수 있습니다. 체중 감소는 초기부터 나타날 수 있는 증상 중 하나이나 단독으로 췌장암을 시사하지는 않습니다. 이러한 증상들이 복합적으로 나타나면 소화기내과 전문의를 방문하시기 바랍니다.', 3526, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '췌장암', '췌장암', 'DIAGNOSIS', '허리 통증이 정형외과 검사에서 이상이 없는데 지속된다면, 후복막 장기인 췌장의 종양이 등·허리 부위로 통증을 유발하는 췌장암 가능성을 고려해볼 수 있습니다. 췌장암 의심 시 정형외과보다는 소화기내과를 방문하여 복부 CT(3상), CA 19-9 혈액 검사, 복부 초음파 등의 검사를 받는 것이 적절합니다. 지속적인 원인 불명의 허리 통증이 있다면 소화기내과 전문의를 방문하시기 바랍니다.', 3527, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '췌장암', '췌장암', 'TREATMENT', '췌장암 치료에 사용되는 방사선 치료로는 외부 방사선 치료와 정위적 체부 방사선 치료(SBRT)가 있으며, 주로 수술 전·후 보조 치료 또는 수술 불가능한 경우 증상 완화 목적으로 사용됩니다. 방사선 치료 외에도 수술(췌십이지장 절제술/휘플 수술), 항암화학요법(젬시타빈, FOLFIRINOX), 면역 치료, 표적 치료(BRCA 변이 시 올라파립), 완화 치료 등이 병기에 따라 선택됩니다. 치료 방법과 계획은 종양내과 및 외과 전문의와 상담하시기 바랍니다.', 3528, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '파종혈관내응고', '파종혈관내응고', 'CAUSE', '양수색전증은 분만 중 양수가 모체 혈액 순환으로 유입되어 심폐 부전, 과민반응, 파종혈관내응고(DIC)를 유발하는 산과적 응급 상황입니다. 양수색전증에 의해 파종혈관내응고가 발생하면 혈액 응고 인자가 급격히 소모되어 출혈과 혈전이 동시에 발생하고, 이로 인해 신부전, 출혈성 쇼크, 다발성 장기 부전이 초래될 수 있습니다. 이는 생명을 위협하는 응급 상황이므로 즉각적인 산부인과 및 중환자 전문의팀의 처치가 필요합니다.', 3529, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '파종혈관내응고', '파종혈관내응고', 'DEFINITION', '파종혈관내응고(DIC)는 패혈증, 외상, 악성 종양, 산과적 합병증(양수색전증, 태반조기박리) 등의 기저 원인에 의해 전신적으로 응고 시스템이 과활성화되어 미세혈관 내 혈전이 형성되고, 응고 인자와 혈소판이 소모되어 동시에 출혈이 발생하는 상태입니다. 이로 인해 빈뇨, 무뇨(신부전), 호흡 곤란(폐 혈전), 의식 장애(뇌 혈전 또는 저산소증) 등의 증상이 나타납니다. 파종혈관내응고는 응급 상태이므로 즉시 내과 또는 중환자 전문의의 치료가 필요합니다.', 3530, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '파종혈관내응고', '파종혈관내응고', 'SYMPTOM', '파종혈관내응고(DIC) 상태에서는 혈액 내 응고 인자와 혈소판이 과도하게 소모되어 정작 출혈이 있을 때 혈액이 응고되지 않아 지혈이 어렵습니다. 이와 함께 미세혈관 내 혈전으로 인한 장기 허혈, 용혈성 빈혈, 피부 자반 및 괴사, 쇼크 증상이 동반될 수 있습니다. 파종혈관내응고는 심각한 응급 상황이므로 즉시 응급실을 방문하거나 중환자 전문의의 치료를 받으시기 바랍니다.', 3531, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '파종혈관내응고', '파종혈관내응고', 'DIAGNOSIS', '파종혈관내응고(DIC)는 초기에는 증상이 없거나 경미한 경우도 있을 수 있으나, 혈액 검사(혈소판 감소, PT/aPTT 연장, 피브리노겐 감소, D-dimer 상승)에서 이상이 발견됩니다. 증상이 없더라도 검사 수치에 이상이 있다면 진단은 유효하며, 이 경우 기저 원인 질환 치료와 함께 면밀한 모니터링이 필요합니다. 진단에 의문이 있다면 다른 병원에서 재확인할 수 있으나, 이상 수치가 있다면 즉시 혈액내과 또는 내과 전문의의 지도를 받으시기 바랍니다.', 3532, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '파종혈관내응고', '파종혈관내응고', 'TREATMENT', '파종혈관내응고(DIC) 치료에 사용되는 항응고제로는 헤파린이 가장 대표적이며, 저분자량 헤파린도 활용됩니다. 혈소판 수혈, 신선동결혈장(FFP), 냉동침전물 등 혈액 성분 보충도 병행되며, 근본 원인 질환 치료가 핵심입니다. 항응고제 사용 여부와 용량은 출혈과 혈전 상태를 종합 평가하여 혈액내과 전문의가 결정해야 합니다.', 3533, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '폐암', '폐암', 'PREVENTION', '금연이 폐암 예방의 가장 중요한 방법이며, 간접흡연 환경도 피해야 합니다. 라돈 가스 노출을 줄이기 위해 실내 환기를 충분히 하고, 석면 등 발암 물질 노출을 최소화해야 합니다. 채소·과일이 풍부한 식단 유지와 규칙적인 운동도 도움이 되며, 고위험군은 흉부 CT 검진을 주기적으로 받는 것이 권장됩니다.', 3534, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '폐암', '폐암', 'CAUSE', '비흡연자의 폐암 원인으로는 라돈 가스, 석면, 미세먼지 등 대기오염, 요리 시 발생하는 조리 흄(요리 연기) 등이 있습니다. 유전적 소인과 가족력도 중요한 위험 요인이며, 특히 EGFR 등 유전자 변이와 관련된 선암이 비흡연자에게 흔합니다. 정확한 원인 파악과 치료 방향 결정을 위해 폐·흉부 전문의와 상담하시기 바랍니다.', 3535, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '폐암', '폐암', 'DEFINITION', '폐암은 폐 조직 자체에서 발생한 원발성 폐암을 의미하며, 다른 장기에서 생긴 암이 폐로 전이된 경우는 전이성 폐종양으로 구분됩니다. 조직검사와 면역조직화학 염색을 통해 암세포의 기원을 확인하며, PET-CT나 원발 부위 검사로 발생 위치를 추적합니다. 원발암과 전이암은 치료 방법이 달라지므로 정확한 감별이 중요하며 종양 전문의 진료가 필요합니다.', 3536, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '폐암', '폐암', 'SYMPTOM', '폐암 치료 중 식욕 저하와 체력 저하는 흔한 부작용으로, 소량씩 자주 식사하고 고단백·고칼로리 식품을 섭취하는 것이 도움이 됩니다. 구역감이 심할 경우 항구토제 처방을 주치의에게 요청하고, 영양사 상담을 통해 맞춤형 식이요법을 계획하는 것이 좋습니다. 심한 체중 감소나 영양 부족 시에는 경구 영양 보충제나 정맥 영양 요법을 고려할 수 있으므로 담당 전문의와 상의하시기 바랍니다.', 3537, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '폐암', '폐암', 'DIAGNOSIS', '폐 엑스레이(흉부 X선)는 코로나19 이후 지속되는 호흡 곤란의 원인을 평가하는 데 기초적인 검사로 활용됩니다. 폐 섬유화, 흉수, 폐렴 잔존 여부 등을 확인할 수 있으나, 더 세밀한 평가가 필요하면 흉부 CT를 추가로 시행합니다. 증상이 지속된다면 호흡기내과 전문의의 진찰을 받아 정확한 원인을 감별하는 것이 중요합니다.', 3538, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '폐암', '폐암', 'TREATMENT', '폐암 치료는 암의 종류(소세포암·비소세포암), 병기, 환자 상태에 따라 수술, 방사선 치료, 항암화학요법, 표적치료제, 면역항암제 등을 단독 또는 병용합니다. 초기 비소세포폐암은 수술적 절제가 가장 효과적이며, 진행성 폐암은 표적치료제나 면역항암제가 큰 효과를 보이는 경우가 많습니다. 최적의 치료 방법은 조직 검사 및 유전자 검사 결과를 토대로 폐암 전문 종양내과 또는 흉부외과 전문의와 상담하여 결정해야 합니다.', 3539, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '피부암', '피부암', 'CAUSE', '자외선(UV)은 피부암의 가장 주요한 원인으로, 특히 UVB는 DNA 손상을 유발하여 흑색종, 기저세포암, 편평세포암 위험을 높입니다. 자외선 차단제(SPF 30 이상)를 매일 사용하는 것은 피부암 예방에 과학적으로 효과가 입증된 방법입니다. 자외선 차단제 사용과 함께 보호 의류 착용, 강한 햇빛 시간대(오전 10시~오후 2시) 야외 활동 자제도 함께 권장됩니다.', 3540, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '피부암', '피부암', 'DEFINITION', '피부 변색(색소 침착 또는 탈색)은 다양한 원인으로 나타날 수 있으며, 기저세포암·흑색종 등 피부암과 관련될 수 있습니다. 색이 불균일하거나 경계가 불규칙하고 크기가 변하는 색소 병변은 특히 주의가 필요합니다. 정확한 진단을 위해 피부과 전문의 진찰과 필요 시 조직검사를 받으시기 바랍니다.', 3541, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '피부암', '피부암', 'SYMPTOM', '피부암의 주요 증상으로는 기존 점의 색·크기·모양 변화, 출혈하거나 딱지가 생기는 궤양, 잘 낫지 않는 상처, 피부 표면이 반짝이거나 진주빛을 띠는 결절 등이 있습니다. 가렵거나 통증이 있는 피부 병변, 주변 피부와 경계가 불명확한 적색 반점도 피부암 의심 증상에 해당합니다. 이러한 증상이 나타나면 피부과 전문의의 진찰을 받는 것이 중요합니다.', 3542, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '피부암', '피부암', 'DIAGNOSIS', '피부암 진단은 피부과 전문의의 육안 검사 및 더모스코피(피부확대경) 검사를 기본으로 합니다. 의심 병변에 대해서는 조직생검(피부 조직 일부를 채취하는 생검)을 시행하여 병리 조직 검사로 최종 확진합니다. 전이 여부 확인이 필요한 경우 CT, PET-CT 등 영상 검사를 추가로 시행하므로, 피부과 전문의 진료를 받으시기 바랍니다.', 3543, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '피부암', '피부암', 'TREATMENT', '피부암 치료 중에는 자외선 차단이 필수적이므로 외출 시 SPF 50 이상 자외선 차단제를 사용하고 보호 의류를 착용해야 합니다. 항산화 영양소(비타민 C, E, 베타카로틴)가 풍부한 채소·과일 위주의 식단이 피부 건강에 도움이 되며, 금연과 절주도 중요합니다. 피부 건조와 자극을 최소화하기 위해 자극 없는 보습제를 사용하고 치료 부위 관리 방법은 담당 피부과 전문의의 지침을 따르시기 바랍니다.', 3544, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '피부의 양성 종양', '피부의양성종양', 'CAUSE', '피부 양성 종양의 원인으로는 자외선 노출, 바이러스 감염(HPV 등), 유전적 요인, 호르몬 변화, 피부 외상 등이 관련됩니다. 피부 세포의 과도한 성장은 노화, 만성 자극, 면역 기능 이상 등과 연관되어 발생하기도 합니다. 정확한 원인 파악과 악성 여부 감별을 위해 피부과 전문의의 진찰을 받는 것이 중요합니다.', 3545, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '피부의 양성 종양', '피부의양성종양', 'DEFINITION', '피부 양성 종양은 사마귀, 지루각화증, 피부섬유종, 지방종 등 다양한 형태로 나타나며, 사마귀와 유사한 외형을 보이기도 합니다. 악성 종양과의 감별이 중요하므로 사마귀처럼 보이는 병변이라도 크기나 모양이 변하거나 출혈이 있다면 피부과 전문의의 정확한 진단이 필요합니다. 자가 진단보다는 전문의 진찰과 필요 시 조직검사로 확인하는 것을 권장합니다.', 3546, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '피부의 양성 종양', '피부의양성종양', 'SYMPTOM', '피부 양성 종양에서는 병변 부위의 가려움증, 압통, 피부색 변화, 주변 조직의 미세한 융기 등이 동반될 수 있습니다. 사마귀 유사 병변이 커지거나 수가 늘어나고 표면이 거칠어지는 경우도 나타날 수 있습니다. 증상 변화가 있거나 악성 여부가 불확실하다면 피부과 전문의의 진찰을 받아 적절한 치료 방침을 결정하시기 바랍니다.', 3547, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '피부의 양성 종양', '피부의양성종양', 'DIAGNOSIS', '피부 양성 종양의 진단은 조직 생검 외에도 더모스코피(피부확대경 검사), 초음파 검사, 피부 CT 등의 비침습적 영상 검사를 활용할 수 있습니다. 더모스코피는 병변 내부 구조를 확대하여 관찰하는 방법으로, 악성 여부를 비침습적으로 평가하는 데 도움이 됩니다. 정확한 진단 방법의 선택은 피부과 전문의가 병변의 특성에 따라 결정합니다.', 3548, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '피부의 양성 종양', '피부의양성종양', 'TREATMENT', '피부 양성 종양의 치료는 병변의 종류, 크기, 위치, 증상에 따라 경과 관찰, 냉동치료, 레이저 치료, 외과적 절제 등을 선택적으로 시행합니다. 피부과 전문의는 병변의 외형적 특성, 성장 속도, 조직학적 소견을 종합하여 양성 여부를 판단합니다. 치료 여부와 방법은 피부과 전문의의 판단에 따르며, 스스로 제거를 시도하면 감염 및 흉터 위험이 있으므로 전문의 상담을 권장합니다.', 3549, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '항문암', '항문암', 'CHECKUP', '대변이 가늘어지고 색이 변하는 것은 대장이나 항문 부위의 종양, 폴립, 염증성 장질환 등에 의해 장 내강이 좁아지거나 출혈이 발생할 때 나타날 수 있습니다. 흑색변은 상부 소화관 출혈, 밝은 붉은 혈변은 하부 대장·항문 출혈을 시사할 수 있습니다. 이러한 증상이 지속된다면 대장항문외과 또는 소화기내과 전문의를 방문하여 대장내시경 등 정밀 검사를 받으시기 바랍니다.', 3550, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '항문암', '항문암', 'PREVENTION', '항문암은 인유두종바이러스(HPV) 감염과 밀접한 관련이 있으며, HPV는 성 접촉을 통해 전파됩니다. 특히 항문 성교, 다수의 성 파트너, 면역 저하 상태 등이 HPV 감염 및 항문암 발생 위험을 높이는 요인입니다. HPV 예방 접종이 항문암 예방에 효과적이며, 정기 검진과 안전한 성생활을 통해 위험을 줄일 수 있습니다.', 3551, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '항문암', '항문암', 'CAUSE', '치질(치핵)은 항문암의 직접적인 원인이 아니며, 치질 수술 자체가 항문암을 유발하지는 않습니다. 항문암의 주요 원인은 HPV 감염, 흡연, 면역 억제 등으로 치질과는 별개입니다. 다만 항문 출혈 등 치질 증상이 항문암 증상과 유사할 수 있으므로, 치질로 알고 있던 증상이 치료 후에도 지속된다면 대장항문외과 전문의의 정확한 진단을 받는 것이 중요합니다.', 3552, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '항문암', '항문암', 'DEFINITION', '항문암은 항문관 또는 항문 주위 조직에서 발생하는 악성 종양으로, 주요 증상으로는 항문 출혈, 항문 주위 가려움, 통증, 배변 시 잔변감, 항문 주위의 덩어리나 궤양 등이 있습니다. 초기에는 증상이 미미하거나 치질과 유사하여 진단이 늦어질 수 있습니다. 이러한 증상이 지속된다면 대장항문외과 전문의의 진찰과 조직검사를 통한 정확한 진단이 필요합니다.', 3553, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '항문암', '항문암', 'SYMPTOM', '항문암의 가장 흔한 증상은 항문 출혈이며, 그 외에 항문 통증, 주위 가려움증, 잔변감, 항문 주위 덩어리나 종괴, 항문 분비물 등이 나타날 수 있습니다. 진행된 경우에는 배변 습관의 변화, 대변이 가늘어지는 증상, 서혜부(사타구니) 림프절 종대가 동반되기도 합니다. 이러한 증상이 있다면 치질로 자가 판단하지 말고 대장항문외과 전문의의 진찰을 받으시기 바랍니다.', 3554, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '항문암', '항문암', 'DIAGNOSIS', '항문암 진단을 위해서는 대장항문외과에서 항문 직장 수지검사, 항문경 검사, 조직생검을 시행하며 병기 판정을 위해 CT, MRI, PET-CT 등 영상 검사도 합니다. 조직생검 결과는 일반적으로 1~2주 내에 확인 가능하나, 병원과 검사 종류에 따라 다소 차이가 있을 수 있습니다. 증상이 의심된다면 대장항문외과 또는 소화기 전문 의료기관을 방문하여 검사를 받으시기 바랍니다.', 3555, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '항문암', '항문암', 'TREATMENT', '항문암의 치료는 방사선 치료와 항암화학요법(항암제 병용)의 동시 병행 요법(동시항암방사선치료)이 표준 치료입니다. 수술(복회음절제술)은 동시항암방사선치료 후 잔존 종양이 있거나 재발한 경우에 시행합니다. 치료 방법은 암의 병기와 환자 상태에 따라 결정되므로, 정확한 치료 계획은 대장항문외과 및 종양내과 전문의와 상담하시기 바랍니다.', 3556, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '호중구감소증', '호중구감소증', 'CAUSE', '호중구감소증은 항암화학요법의 부작용으로 흔히 발생하지만, 항암 치료 외에도 재생불량성 빈혈, 백혈병, 바이러스 감염, 자가면역 질환, 특정 약물(항생제, 항갑상선제 등) 복용 등 다양한 원인으로 나타날 수 있습니다. 대장암 항암 치료 중 호중구감소증은 감염 위험을 높이므로 즉각적인 관리가 필요합니다. 원인과 중증도에 따른 치료 방침은 담당 종양내과 전문의와 상담하시기 바랍니다.', 3557, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '호중구감소증', '호중구감소증', 'DEFINITION', '호중구감소증은 혈액 내 호중구(백혈구의 일종) 수치가 정상 이하(성인 기준 1,500/μL 미만)로 감소한 상태로, 세균·진균 감염에 취약해집니다. 치료는 원인 제거(원인 약물 중단 등), 항생제·항진균제 투여(감염 발생 시), 과립구 집락 자극인자(G-CSF) 투여 등으로 이루어집니다. 정확한 진단과 치료 방침 결정을 위해 혈액내과 전문의 진료가 필요합니다.', 3558, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '호중구감소증', '호중구감소증', 'SYMPTOM', '호중구감소증의 대표적 증상으로는 38도 이상의 발열, 오한, 반복적인 세균 감염(폐렴, 패혈증 등)이 있습니다. 구내염, 피부 발적, 항문 주위 농양 등 평소에 잘 낫지 않는 감염 증상도 나타날 수 있으며, 심한 경우 패혈증으로 진행될 수 있습니다. 발열과 함께 이러한 증상이 나타나면 즉시 혈액내과 또는 응급실을 방문하여 진단과 치료를 받으시기 바랍니다.', 3559, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '호중구감소증', '호중구감소증', 'DIAGNOSIS', '아이에게 구내염, 피부 발적, 설사 등의 증상이 반복적으로 나타난다면 소아청소년과 전문의를 우선 방문하는 것이 적절합니다. 호중구감소증이 의심될 경우 혈액검사(전혈구 검사)를 통해 호중구 수치를 확인하며, 필요시 소아 혈액종양내과로 의뢰됩니다. 감염이 반복되거나 심하다면 면역 결핍 여부 감별을 위한 추가 검사도 필요할 수 있습니다.', 3560, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '호중구감소증', '호중구감소증', 'TREATMENT', '호중구감소증 환자는 감염 위험이 높으므로 위생 관리가 필수적이며, 손 씻기, 익히지 않은 음식(생선회, 날고기 등) 피하기, 감염자와의 접촉 제한 등이 중요합니다. 균형 잡힌 영양 섭취는 면역 기능 유지에 도움이 되며, 과도한 피로와 스트레스를 피하고 충분한 수면을 취하는 것이 권장됩니다. 식이 및 생활 습관 조절만으로 호중구감소증 자체가 치료되지는 않으므로, 치료 방침은 반드시 전문의 지도하에 따르시기 바랍니다.', 3561, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '만성 치주염', '만성치주염', 'CHECKUP', '만성 치주염 검진에는 치주 탐침(프로브)을 이용한 치주낭 깊이 측정, 치은 출혈 여부 확인, 치아 동요도 검사가 기본적으로 사용됩니다. 방사선 검사(파노라마 또는 치근단 방사선 사진)는 치조골 소실 정도를 평가하는 데 필수적입니다. 정기적인 치과 검진(6개월~1년마다)을 통해 조기 발견과 지속적인 관리를 받는 것이 중요합니다.', 3562, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '만성 치주염', '만성치주염', 'DIET_LIFE', '만성 치주염 관리에 도움이 되는 식단으로는 비타민 C(귤, 키위, 브로콜리 등)와 항산화 식품이 풍부한 채소·과일 섭취가 권장됩니다. 칼슘(유제품, 두부 등)과 오메가-3 지방산(등푸른 생선 등)도 잇몸과 치조골 건강에 도움이 됩니다. 당분이 많은 음식과 탄산음료는 치태 형성을 촉진하므로 줄이고, 식후 물로 입안을 헹구는 습관도 도움이 됩니다.', 3563, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '만성 치주염', '만성치주염', 'MEDICATION', '만성 치주염 치료에 사용되는 항생제(독시사이클린, 메트로니다졸 등)와 클로르헥시딘 구강 세척제는 일반적으로 단기간 사용 시 안전하나, 부작용이 전혀 없는 것은 아닙니다. 항생제는 소화 불량, 구역, 설사, 알레르기 반응 등이 나타날 수 있으며, 클로르헥시딘은 장기 사용 시 치아 착색, 미각 변화가 생길 수 있습니다. 약물 사용 전 치과 전문의와 부작용에 대해 충분히 상담하시기 바랍니다.', 3564, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '만성 치주염', '만성치주염', 'PREVENTION', '만성 치주염 예방을 위해 하루 2회 이상 올바른 칫솔질(바스법 등)과 치실·치간칫솔 사용이 기본입니다. 금연은 치주 건강을 위해 가장 중요한 생활 습관 개선이며, 당뇨병 등 전신 질환의 철저한 관리도 필요합니다. 6개월에 한 번씩 치과 스케일링(치석 제거)을 받고, 설탕이 많은 음식을 줄이며 스트레스 관리도 잇몸 건강에 도움이 됩니다.', 3565, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '만성 치주염', '만성치주염', 'EXERCISE', '만성 치주염으로 항생제를 복용 중일 때는 격렬한 운동으로 인한 과도한 발한과 탈수가 약물 흡수 및 효과에 영향을 줄 수 있으므로 충분한 수분 보충이 필요합니다. 일부 항생제는 햇빛에 대한 민감성을 높일 수 있어 야외 운동 시 자외선 차단에 주의해야 합니다. 항생제 복용 기간 중 운동 강도와 종류에 대해서는 처방 치과 전문의 또는 의사와 상담하여 결정하시기 바랍니다.', 3566, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '만성 치주염', '만성치주염', 'CAUSE', '흡연은 치주 조직의 혈액 순환을 저해하고 면역 기능을 약화시켜 세균 감염에 취약하게 만들며, 치주 조직의 치유 능력을 현저히 떨어뜨립니다. 음주는 구강 건조를 유발하고 타액 분비를 감소시켜 치태 세균의 번식을 촉진하며, 영양 불균형으로 인한 면역력 저하도 치주 질환을 악화시킵니다. 금연과 절주는 만성 치주염 예방 및 치료 효과를 높이는 데 매우 중요합니다.', 3567, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '만성 치주염', '만성치주염', 'REHAB', '만성 치주염으로 인한 잇몸 손상 후 재활에는 스케일링 및 치근 활택술(치석·세균막 제거), 잇몸 수술(심한 경우), 치조골 이식술 등이 포함됩니다. 수술 후에는 올바른 구강 위생 관리와 정기적인 치과 방문(치주 유지 관리)이 구강 건강 회복의 핵심입니다. 잇몸 재활은 장기적인 과정이므로 치주과 전문의의 지속적인 관리하에 체계적으로 진행하시기 바랍니다.', 3568, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '만성 치주염', '만성치주염', 'DEFINITION', '치은염은 치아와 잇몸 경계부에 치태(플라크)가 쌓여 잇몸에 세균성 염증이 생기는 질환으로, 치아를 지지하는 뼈(치조골)는 아직 손상되지 않은 상태입니다. 주요 증상으로는 잇몸 발적, 부종, 칫솔질 시 출혈, 잇몸 압통 등이 있으며, 구취가 동반되기도 합니다. 치은염은 치주염의 전 단계로, 조기에 치과 치료를 받으면 완전한 회복이 가능합니다.', 3569, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '만성 치주염', '만성치주염', 'SYMPTOM', '만성 치주염은 치은(잇몸), 치주인대, 치조골 등 치아를 지지하는 구조물에 만성 염증이 생기는 질환으로, 치은염이 진행된 상태입니다. 양치 시 출혈과 치아 동요는 치조골이 흡수되고 치주인대가 파괴되면서 치아 지지력이 약해지기 때문에 발생합니다. 증상이 있다면 더 이상의 진행을 막기 위해 치과 전문의의 조기 진료와 적극적인 치료가 필요합니다.', 3570, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '만성 치주염', '만성치주염', 'DIAGNOSIS', '치아가 뿌리만 남아 있는 상태라면 일반 치과 또는 치주과가 있는 치과 전문 병원을 방문하는 것이 적절합니다. 대학병원 치과, 치과 전문 병원, 지역 치과 의원 모두 만성 치주염 진단과 치료가 가능하며, 심한 경우에는 치주과 전문의가 있는 병원을 권장합니다. 방문 전 치과 건강보험 적용 여부와 전문의 여부를 확인하시고, 증상 악화 전에 빠른 진료를 받으시기 바랍니다.', 3571, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '만성 치주염', '만성치주염', 'TREATMENT', '만성 치주염의 치료 기간은 질환의 중증도에 따라 다르며, 경증은 스케일링 1~2회로 수 주 내에 호전될 수 있으나 중등도 이상은 치근 활택술, 잇몸 수술 등 수개월 이상 소요될 수 있습니다. 가장 빠른 효과를 위해서는 스케일링 및 치근 활택술(SRP)로 치석과 세균막을 철저히 제거하는 것이 기본이며, 동시에 철저한 구강 위생 관리가 병행되어야 합니다. 정확한 치료 계획과 기간은 치주과 전문의의 진찰 후 결정하시기 바랍니다.', 3572, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '매복 사랑니', '매복사랑니', 'CHECKUP', '매복 사랑니로 인한 통증은 치과에서 진료받아야 하며, 일반 치과 의원에서도 진단과 발치가 가능합니다. 매복 상태가 복잡한 경우(하악 신경관 근접, 깊은 수평 매복 등)에는 구강악안면외과 전문의가 있는 치과 병원이나 대학병원 치과를 방문하는 것이 안전합니다. 파노라마 X선 또는 CT 촬영으로 매복 정도를 평가한 후 발치 여부와 방법을 결정하게 됩니다.', 3573, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '매복 사랑니', '매복사랑니', 'DIET_LIFE', '매복 사랑니 발치 후 회복을 빠르게 하려면 수술 당일은 충분한 휴식을 취하고, 처음 24시간은 거즈를 꽉 물어 지혈하는 것이 중요합니다. 딱딱하거나 자극적인 음식을 피하고 부드러운 음식(죽, 두부 등)을 섭취하며, 발치 부위를 혀나 손가락으로 건드리지 않아야 합니다. 흡연과 음주는 회복을 지연시키므로 최소 수일간 삼가고, 처방받은 항생제와 진통제를 용법에 맞게 복용하시기 바랍니다.', 3574, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '매복 사랑니', '매복사랑니', 'MEDICATION', '매복 사랑니 발치 후 처방되는 진통제(이부프로펜, 아세트아미노펜 등) 과다 복용 시 위장 장애, 간 손상, 신장 기능 저하, 알레르기 반응 등이 나타날 수 있습니다. 항생제 과다 복용은 소화 불량, 설사, 장내 세균 불균형, 항생제 내성 유발 등의 부작용이 생길 수 있습니다. 반드시 처방된 용량과 용법을 지켜야 하며, 부작용이 나타나면 즉시 처방 치과 의사 또는 의사에게 연락하시기 바랍니다.', 3575, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '매복 사랑니', '매복사랑니', 'PREVENTION', '매복 사랑니는 치열과 턱뼈의 공간 부족으로 인해 발생하는 것으로, 구조적 원인이므로 완전한 예방은 어렵습니다. 다만 정기적인 치과 검진(6개월~1년마다)과 파노라마 X선 촬영을 통해 사랑니 맹출 상황을 조기에 파악하면 심각한 매복 전에 대처할 수 있습니다. 사랑니 주위 잇몸 청결 유지로 치관 주위염을 예방하고, 증상 발생 전 예방적 발치를 고려하는 것도 방법입니다.', 3576, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '매복 사랑니', '매복사랑니', 'EXERCISE', '매복 사랑니의 통증 완화를 위한 특정 운동은 없으며, 피곤할 때는 과격한 운동을 피하고 충분한 휴식이 우선입니다. 가벼운 스트레칭이나 산책 정도는 무방하나, 혈압을 높이는 고강도 운동은 통증과 출혈을 악화시킬 수 있습니다. 통증이 심하다면 치과에서 원인을 정확히 진단받고 적절한 치료(발치 또는 약물 치료)를 받는 것이 근본적인 해결책입니다.', 3577, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '매복 사랑니', '매복사랑니', 'CAUSE', '매복 사랑니가 잇몸이나 턱뼈 속에 박히는 주된 이유는 현대인의 턱뼈 크기가 작아져 사랑니가 맹출할 공간이 부족하기 때문입니다. 인접 치아나 턱뼈 구조, 치배의 방향이 비정상적인 경우에도 정상적으로 나오지 못하고 매복됩니다. 유전적 요인, 영양 및 발육 차이 등도 턱뼈 크기와 치열에 영향을 미쳐 매복 사랑니 발생에 관여합니다.', 3578, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '매복 사랑니', '매복사랑니', 'REHAB', '매복 사랑니로 인한 통증과 식사 불편은 근본적으로 발치를 통해 해결되어야 하며, 재활 운동만으로 개선되기 어렵습니다. 발치 후 회복 과정에서 턱관절 운동 범위 회복을 위해 천천히 입 벌리기 연습(개구 운동)을 점진적으로 시행할 수 있습니다. 개구 운동 시기와 방법은 치과 또는 구강악안면외과 전문의의 지도에 따라 시행하시기 바랍니다.', 3579, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '매복 사랑니', '매복사랑니', 'DEFINITION', '치과 진료 중 매복 사랑니가 발견되면 치관 주위염(잇몸 통증·부종), 인접 치아 손상, 낭종 형성 등의 합병증이 발생할 수 있습니다. 증상이 없더라도 미래의 합병증 예방을 위해 예방적 발치를 권고하는 경우가 많으며, 매복 형태와 위험도에 따라 경과 관찰 또는 발치를 선택합니다. 치료 방침은 구강악안면외과 또는 치과 전문의와 충분히 상담하여 결정하시기 바랍니다.', 3580, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '매복 사랑니', '매복사랑니', 'SYMPTOM', '매복 사랑니의 전형적인 증상으로는 잇몸 뒤쪽의 붓기, 통증, 압통, 입 벌리기 불편함, 구취 등이 있습니다. 치관 주위에 음식물이 끼어 세균 감염이 생기면 치관 주위염이 발생하여 턱 아래 림프절이 붓거나 발열이 동반될 수 있습니다. 잇몸 안쪽 통증과 부종이 있다면 매복 사랑니를 의심하고 치과 전문의의 진찰을 받으시기 바랍니다.', 3581, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '매복 사랑니', '매복사랑니', 'DIAGNOSIS', '매복 사랑니 진단에는 파노라마 방사선 촬영이 기본 검사로 전반적인 매복 위치와 방향을 확인하는 데 유용합니다. CT 촬영은 하치조 신경관과의 거리, 인접 구조물과의 관계 등 3차원적 정보가 필요할 때 추가적으로 시행되며, 복잡한 매복 사랑니 발치 전에 더 정확한 정보를 제공합니다. 두 검사 중 어떤 것이 더 적합한지는 매복 상태와 증상에 따라 치과 전문의가 판단합니다.', 3582, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '매복 사랑니', '매복사랑니', 'TREATMENT', '매복 사랑니를 발치하지 않고 방치하면 치관 주위염(반복적 통증·감염), 인접 치아(제2대구치) 치근 흡수 및 충치, 낭종 또는 종양 형성, 치열 변화 등의 합병증이 발생할 수 있습니다. 치관 주위염이 심해지면 감염이 주변 조직으로 퍼져 봉와직염이나 심각한 두경부 감염으로 이어질 수 있습니다. 증상 유무와 관계없이 매복 사랑니가 발견되면 치과 전문의와 발치 시기와 필요성에 대해 상담하시기 바랍니다.', 3583, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치아 우식증[충치]', '치아우식증[충치]', 'CHECKUP', '불소는 치아 법랑질을 강화하고 충치를 유발하는 세균의 활동을 억제하여 치아 우식증 재발을 예방하는 효과가 있습니다. 치료 후 약해진 법랑질 표면에 불소 도포를 시행하면 재광화(재석회화)를 촉진하여 충치 재발 가능성을 낮춥니다. 불소 도포는 특히 어린이와 우식 위험이 높은 성인에게 효과적이며, 치과 전문의의 판단에 따라 주기적으로 시행하는 것이 권장됩니다.', 3584, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치아 우식증[충치]', '치아우식증[충치]', 'DIET_LIFE', '양치질을 잘 해도 치아 사이나 홈 부위의 세균과 음식물 잔여물이 완전히 제거되지 않으면 충치가 생길 수 있습니다. 당분과 산성 음식·음료의 섭취 빈도와 양을 줄이고 식후 빠른 양치 또는 물로 헹구는 습관이 중요합니다. 치실·치간칫솔 사용, 정기적인 치과 검진과 스케일링, 불소 도포 및 치아 홈 메우기(실런트)도 충치 예방에 도움이 됩니다.', 3585, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치아 우식증[충치]', '치아우식증[충치]', 'MEDICATION', '치아 우식증 치료에 직접 사용되는 약물로는 불화나트륨 바니쉬(불소 도포제)가 있으며, 초기 충치 진행 억제와 재광화에 효과적입니다. 실버 다이아민 플루오라이드(SDF)는 충치 진행을 정지시키는 효과가 있으나 치아가 검게 착색되는 부작용이 있습니다. 대부분의 충치 치료는 약물보다 삭제·충전·크라운 등 수복 치료가 주이며, 약물 적용 여부는 치과 전문의가 결정합니다.', 3586, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치아 우식증[충치]', '치아우식증[충치]', 'PREVENTION', '충치 예방을 위해 불소 함유 치약 사용, 불소 도포(치과 시술), 치아 홈 메우기(실런트) 등이 효과적입니다. 당분이 많은 음식과 탄산음료의 섭취를 줄이고 식사 후 물로 입안을 헹구거나 무설탕 껌을 씹는 것도 도움이 됩니다. 6개월마다 정기적인 치과 검진을 통해 초기 충치를 조기에 발견하고 치료하는 것이 중요합니다.', 3587, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치아 우식증[충치]', '치아우식증[충치]', 'EXERCISE', '운동 자체가 치아 우식증을 직접 예방하거나 치료하지는 않습니다. 다만 규칙적인 운동은 전신 면역력 강화와 전반적인 건강 증진에 기여하며, 운동 중 스포츠 음료(당분·산 함유)를 마시는 경우 충치 위험이 높아질 수 있으므로 물로 대체하거나 운동 후 양치를 하는 것이 중요합니다. 치아 우식증의 예방과 치료는 구강 위생 관리와 정기적인 치과 진료가 핵심입니다.', 3588, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치아 우식증[충치]', '치아우식증[충치]', 'CAUSE', '치아 우식증 발생에 가장 큰 영향을 미치는 식습관은 당분(설탕, 과당 등)이 많은 음식과 음료를 자주 섭취하는 것입니다. 특히 하루에 여러 번 당분을 접하거나 취침 전 달콤한 음식을 먹으면 세균이 산을 지속적으로 생성하여 법랑질을 녹입니다. 탄산음료, 과일 주스, 젤리, 캐러멜 등 끈적한 당분 식품은 치아에 오래 달라붙어 충치 위험을 특히 높입니다.', 3589, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치아 우식증[충치]', '치아우식증[충치]', 'REHAB', '치아 우식증이 진행된 경우 재활치료로는 치아 수복(레진, 아말감 충전), 인레이/온레이 수복, 크라운(씌우기), 신경 치료(근관 치료) 후 수복 등이 시행됩니다. 치아가 심하게 손상된 경우 발치 후 임플란트, 브릿지, 틀니 등의 보철 치료로 기능을 회복합니다. 적절한 재활 치료 방법은 우식 진행 정도에 따라 달라지므로 치과 전문의의 진찰 후 결정하시기 바랍니다.', 3590, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치아 우식증[충치]', '치아우식증[충치]', 'DEFINITION', '잘못된 칫솔질(불충분한 시간, 부적절한 방법)은 치태(플라크)를 완전히 제거하지 못하여 충치 발생 위험을 높입니다. 치실을 사용하지 않으면 치아 사이 공간의 세균과 음식물 잔여물이 제거되지 않아 인접면 충치(치아 사이 충치)가 발생하기 쉽습니다. 올바른 칫솔질(2분 이상, 치면 전체 닦기)과 매일 치실 사용은 치아 우식증 예방의 가장 기본적인 방법입니다.', 3591, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치아 우식증[충치]', '치아우식증[충치]', 'SYMPTOM', '치아 우식증은 초기(법랑질 단계)에는 통증이 없는 경우가 많으며, 세균이 상아질까지 진행되면 차갑거나 단 음식에 예민해지고, 신경까지 침범하면 자발통이 발생합니다. 통증 없이도 충치가 진행 중인 경우가 흔하므로, 정기적인 치과 검진과 X선 촬영이 조기 발견에 필수적입니다. 통증이 없어도 치과에서는 시진, 탐침 검사, 방사선 검사 등으로 충치를 확인할 수 있습니다.', 3592, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치아 우식증[충치]', '치아우식증[충치]', 'DIAGNOSIS', '겉으로 멀쩡해 보이지만 치아 통증이 있다면 인접면 충치, 내부 우식, 치수염 등의 가능성이 있으므로 치과에서 정확한 진단을 받아야 합니다. 육안으로 보이지 않는 충치는 X선 촬영과 치과 탐침 검사를 통해 발견할 수 있습니다. 통증을 방치하면 충치가 신경까지 진행되어 신경 치료가 필요해질 수 있으므로 빠른 치과 방문을 권장합니다.', 3593, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치아 우식증[충치]', '치아우식증[충치]', 'TREATMENT', '초콜릿 등 차갑거나 단 음식을 먹을 때 치아 예민함이 느껴진다면 충치가 상아질까지 진행되었을 가능성이 있습니다. 치료 기간은 충치 범위와 깊이에 따라 다르며, 단순 레진 충전의 경우 1회(약 30분~1시간) 방문으로 완료되지만, 인레이, 크라운, 신경 치료가 필요한 경우 2~4주 이상 소요될 수 있습니다. 빠른 치료를 위해 지체하지 말고 치과 전문의를 방문하시기 바랍니다.', 3594, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치은염', '치은염', 'CHECKUP', '칫솔질 시 잇몸 출혈이 있다면 치은염 또는 치주염이 의심되므로 치과에서 치주 검사를 받는 것이 필요합니다. 치과 검진에서는 치주 탐침을 이용한 치주낭 깊이 측정, 치은 발적·부종 평가, 방사선 검사(치조골 소실 확인) 등이 이루어집니다. 조기에 스케일링(치석 제거)과 구강 위생 교육을 받으면 치은염은 완전한 회복이 가능합니다.', 3595, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치은염', '치은염', 'DIET_LIFE', '치은염의 주요 증상으로는 잇몸의 발적(붉어짐), 부종(부어오름), 칫솔질 또는 치실 사용 시 출혈, 잇몸 압통이 있습니다. 심한 경우 구취가 동반되며, 잇몸이 치아 표면에서 살짝 떨어지는 느낌이 들기도 합니다. 치은염은 초기에 치과 치료와 올바른 구강 위생 관리를 통해 비교적 쉽게 회복될 수 있으므로 증상이 나타나면 빨리 치과를 방문하시기 바랍니다.', 3596, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치은염', '치은염', 'MEDICATION', '치은염 치료에 사용되는 클로르헥시딘 구강 세척제는 장기 사용 시 치아 착색, 미각 변화, 구강 점막 자극 등의 부작용이 나타날 수 있습니다. 항생제(메트로니다졸, 독시사이클린 등)는 소화 불량, 구역, 설사, 광과민 반응, 알레르기 반응 등이 발생할 수 있습니다. 부작용 발생 시 즉시 처방 치과 의사에게 알리고, 임의로 약물 복용을 중단하거나 증량하지 마시기 바랍니다.', 3597, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치은염', '치은염', 'PREVENTION', '비타민 C는 콜라겐 합성에 필수적이어서 잇몸 조직 건강 유지와 회복에 도움을 주며, 비타민 C 결핍(괴혈병)은 잇몸 출혈과 치은염을 유발합니다. 일부 연구에서 비타민 C 보충이 치주 건강 개선에 긍정적 효과를 보인다는 결과가 있으나, 치은염 자체의 치료 효과는 충분한 근거가 부족합니다. 비타민 C 섭취는 보조적인 도움이 될 수 있으나, 치은염의 근본 치료는 스케일링과 철저한 구강 위생 관리임을 기억하시기 바랍니다.', 3598, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치은염', '치은염', 'EXERCISE', '격한 운동은 치은염 치료에 직접적인 도움이 되지 않으며, 치과에서 치은염 치료 목적으로 격렬한 운동을 권장하지 않습니다. 오히려 치은염 치료(스케일링, 소수술) 직후에는 혈압과 맥박을 높이는 격한 운동을 피하는 것이 회복에 도움이 됩니다. 치은염은 스케일링, 구강 위생 교육, 올바른 칫솔질이 핵심 치료이므로 치과 전문의의 지시에 따른 치료를 우선시하시기 바랍니다.', 3599, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치은염', '치은염', 'CAUSE', '치은염 치료를 위해 치과에서는 스케일링(초음파 치석 제거)과 치근 활택술을 시행하며, 필요 시 클로르헥시딘 구강 세척제나 항생제를 처방합니다. 예방을 위해서는 하루 2회 이상 올바른 칫솔질, 매일 치실 사용, 금연, 정기 치과 검진(6개월마다)이 중요합니다. 당뇨 등 전신 질환이 있는 경우 혈당 조절도 치은염 예방에 도움이 됩니다.', 3600, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치은염', '치은염', 'REHAB', '치은염으로 인한 붓기와 통증 완화를 위해 치과에서는 스케일링으로 치석을 제거하고 클로르헥시딘 구강 세척제 사용을 권장합니다. 집에서는 미지근한 소금물 가글(0.9% 식염수)이 일시적인 잇몸 염증 완화에 도움이 될 수 있습니다. 근본적인 재활과 회복을 위해서는 치과 전문의의 치료와 함께 철저한 구강 위생 관리(올바른 칫솔질, 치실 사용)를 지속해야 합니다.', 3601, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치은염', '치은염', 'DEFINITION', '치은염은 치아 주변 잇몸 조직(치은)에 세균성 염증이 발생하는 질환으로, 치아와 잇몸 사이 틈새(치은 열구)에 치태(플라크)가 쌓이면서 시작됩니다. 치은 조직에 발적, 부종, 출혈이 발생하며, 치료하지 않으면 치주염으로 진행되어 치주인대와 치조골까지 손상될 수 있습니다. 치은염은 적절한 치료와 구강 위생 관리로 완전한 회복이 가능하므로 증상이 있으면 치과 전문의에게 진료를 받으시기 바랍니다.', 3602, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치은염', '치은염', 'SYMPTOM', '치은염이 진행되거나 치주염으로 이어지면 치조골 흡수와 잇몸 퇴축이 발생하여 치아 뿌리(상아질)가 노출될 수 있습니다. 노출된 치아 뿌리는 외부 자극(차갑거나 뜨거운 음식, 바람 등)에 민감하여 시린 증상(치본민감증)이 나타납니다. 치은염 완치 후에도 잇몸 퇴축이 남아 있다면 지각 과민 처치(불소 도포, 상아질 접착제 등)를 위해 치과 전문의의 진료를 받으시기 바랍니다.', 3603, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치은염', '치은염', 'DIAGNOSIS', '찬물을 마실 때 치아가 시린 증상은 치은염으로 인한 잇몸 퇴축, 충치, 치경부 마모 등으로 상아질이 노출되었을 때 나타납니다. 치과에서는 시린 증상의 원인 파악을 위해 시진, 탐침 검사, X선 촬영, 냉온 자극 검사 등을 시행합니다. 원인에 따라 불소 도포, 상아질 접착제 처치, 충치 치료 등 적절한 치료가 필요하므로 치과 전문의 진찰을 받으시기 바랍니다.', 3604, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치은염', '치은염', 'TREATMENT', '치은염이 있는 부위에 레진이 있는 경우, 레진 변연부에 세균이 축적되면 염증을 악화시킬 수 있어 레진 제거 및 재수복이 필요할 수 있습니다. 그러나 레진 제거 전에 스케일링과 구강 위생 개선으로 치은염을 먼저 치료하는 것이 원칙이며, 염증이 있는 상태에서의 처치는 치료 결과가 좋지 않을 수 있습니다. 레진 제거 및 재처치 여부는 치과 전문의가 구체적인 상태를 평가하여 결정하므로 전문의 상담을 받으시기 바랍니다.', 3605, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치조골염', '치조골염', 'CHECKUP', '치조골염 검진에서는 문진·시진 외에 방사선 검사(치근단 X선, 파노라마)를 통해 발치와 치유 상태와 치조골염 여부를 평가합니다. 감염이 깊거나 주변 조직 침범이 의심될 때는 CT 촬영을 추가로 시행하기도 합니다. 필요에 따라 분비물 배양검사로 원인균을 확인하고 적절한 항생제를 선택하는 절차가 이루어질 수 있습니다.', 3606, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치조골염', '치조골염', 'DIET_LIFE', '발치 후 치조골염 예방을 위해 발치 당일은 부드러운 음식(죽, 두부, 요거트 등)을 섭취하고, 뜨겁거나 자극적인 음식, 탄산음료, 딱딱한 음식은 피해야 합니다. 발치 부위는 혀나 손가락으로 건드리지 말고, 처방된 항생제와 진통제를 정해진 용법으로 복용하며 구강 위생을 유지해야 합니다. 흡연과 음주는 치유를 방해하고 치조골염 위험을 높이므로 수일간 삼가고, 심한 운동도 초기에는 피하는 것이 좋습니다.', 3607, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치조골염', '치조골염', 'MEDICATION', '치조골염 치료에 사용되는 항생제(아목시실린, 메트로니다졸 등)는 소화 불량, 구역, 설사, 알레르기 반응(발진, 두드러기) 등의 부작용이 나타날 수 있습니다. 소염진통제(이부프로펜 등)는 위장 장애, 신장 기능에 영향을 줄 수 있으며, 클로르헥시딘 세척제는 장기 사용 시 치아 착색이 발생할 수 있습니다. 부작용이 나타나면 즉시 처방 치과 의사에게 알리고, 임의로 복용을 중단하지 마시기 바랍니다.', 3608, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치조골염', '치조골염', 'PREVENTION', '사랑니 발치 후 발치와 봉합(봉합사 처치)은 치유 환경을 만들어 음식물 오염과 2차 감염을 줄이는 데 도움이 됩니다. 그러나 봉합 자체만으로 치조골염이 완전히 예방되지는 않으며, 발치 후 금연, 구강 위생 유지, 혈병(피딱지) 보호가 더 중요합니다. 봉합 여부와 방법은 발치 범위와 상태에 따라 치과 전문의가 판단하며, 발치 후 지침을 철저히 따르는 것이 치조골염 예방에 가장 효과적입니다.', 3609, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치조골염', '치조골염', 'EXERCISE', '치조골염(건성 발치와)은 발치 후 혈병이 소실되어 발생하는 상태로, 특정 운동이 치조골염을 직접 개선하지는 않습니다. 발치 후 초기에는 혈압과 맥박을 높이는 운동이 출혈과 혈병 소실 위험을 높이므로 삼가는 것이 좋습니다. 치조골염 치료는 치과에서 발치와 세척, 치유 드레싱 교체 등 처치를 받아야 하며, 운동 재개 시기는 치과 전문의의 지침을 따르시기 바랍니다.', 3610, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치조골염', '치조골염', 'CAUSE', '어금니 부위 고름 주머니(치근단 농양 또는 치주 농양)는 세균에 의한 감염이 주요 원인으로, 치아 내부(신경)나 치주 조직이 세균에 감염되어 고름이 고이는 것입니다. 깊은 충치, 치아 균열, 치주염의 진행, 발치 후 감염 등이 선행 원인이 될 수 있습니다. 고름 주머니를 방치하면 감염이 주변 조직과 뼈로 퍼질 수 있으므로 치과 전문의의 빠른 처치(절개 배농, 항생제 투여, 근관 치료 등)가 필요합니다.', 3611, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치조골염', '치조골염', 'REHAB', '치조골염으로 인한 심한 부종과 고름은 치과에서 절개 배농(고름 제거) 처치와 항생제 투여로 치료합니다. 발치와 내 고름이나 세균을 세척하고 치유 드레싱을 교체하는 처치를 반복적으로 시행하여 감염을 조절합니다. 재활 운동이나 자가 처치로는 고름을 개선하기 어려우므로, 즉시 치과 전문의를 방문하여 적절한 치료를 받으시기 바랍니다.', 3612, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치조골염', '치조골염', 'DEFINITION', '치조골염(건성 발치와, dry socket)은 발치 후 발치와(빈 공간)에 형성된 혈병(혈전)이 조기에 용해되거나 탈락하여 치조골이 직접 노출되는 상태를 말합니다. 노출된 치조골에 음식물과 세균이 접촉하면 심한 통증, 구취, 발치 부위 통증이 귀나 관자놀이 방향으로 방사되는 특징적인 증상이 나타납니다. 흡연, 구강 위생 불량, 외상성 발치 등이 주요 위험 요인이며, 치과 전문의의 적절한 처치가 필요합니다.', 3613, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치조골염', '치조골염', 'SYMPTOM', '사랑니 발치 후 수일이 지나도 통증이 심해지거나 구취가 지속된다면 치조골염(건성 발치와)의 가능성이 높습니다. 치조골염은 발치 후 2~4일째에 가장 흔히 발생하며, 자연 치유되지 않으므로 치과에서 세척과 치유 드레싱 처치를 받아야 합니다. 증상이 있다면 지체하지 말고 발치를 시행한 치과를 방문하여 진찰과 치료를 받으시기 바랍니다.', 3614, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치조골염', '치조골염', 'DIAGNOSIS', '치조골염 진단에서 충치와 관련된 정보(과거 치과 치료 이력, 현재 치아 상태 등)는 감별 진단에 도움이 됩니다. 의사(치과의사)는 문진을 통해 발치 일시, 발치 후 경과, 통증 양상, 흡연 여부 등 병력을 수집하고 시진·촉진으로 발치와 상태를 확인합니다. 필요 시 방사선 검사(치근단 X선)를 시행하여 치조골 상태와 잔존 이물질 여부를 평가합니다.', 3615, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '치조골염', '치조골염', 'TREATMENT', '금연 중이라도 흡연 이력이나 다른 원인(불량한 구강 위생, 외상성 발치 등)으로 치조골염이 발생할 수 있습니다. 항생제와 소염진통제 투여는 2차 세균 감염 예방과 통증 완화에 도움이 되나, 치조골염의 근본 치료는 발치와 세척과 치유 드레싱 교체 등 국소 처치가 필수입니다. 약물 치료만으로는 치조골염이 충분히 치유되지 않는 경우가 많으므로 치과 전문의의 처치를 반드시 받으시기 바랍니다.', 3616, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '턱관절 탈구', '턱관절탈구', 'CHECKUP', '턱관절 탈구를 자가진단하기 위해서는 하품 후 입이 다물어지지 않거나, 턱이 한쪽으로 치우쳐 있거나, 입을 닫을 수 없는 경우를 확인합니다. 하품 시 통증이나 딸깍 소리가 나는 것만으로는 탈구보다 턱관절 장애(TMD)일 가능성이 더 높습니다. 자가진단보다는 구강악안면외과 전문의의 진찰과 방사선 검사를 통한 정확한 진단을 받는 것을 권장합니다.', 3617, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '턱관절 탈구', '턱관절탈구', 'DIET_LIFE', '턱관절 탈구는 입을 크게 벌리는 행동(하품, 큰 음식 물기, 과도한 개구 시술 등)이 유발 원인이 될 수 있습니다. 따라서 입을 과도하게 크게 벌리는 행동을 피하고, 하품 시 손으로 턱을 가볍게 받치는 습관이 도움이 됩니다. 딱딱하고 큰 음식은 작게 잘라 먹고, 턱에 무리가 가지 않도록 일상생활에서 주의를 기울이는 것이 중요합니다.', 3618, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '턱관절 탈구', '턱관절탈구', 'MEDICATION', '턱관절 탈구로 인한 통증과 불편감 완화를 위해 소염진통제(이부프로펜, 나프록센 등)와 근이완제가 처방될 수 있습니다. 턱관절 탈구 자체의 치료는 약물보다 도수 정복(의사가 턱을 제자리로 맞추는 처치)이 우선이며, 재발이 잦은 경우 스플린트(교합 안정 장치)를 사용합니다. 약물 처방과 치료 방법은 구강악안면외과 전문의의 정확한 진찰 후 결정해야 합니다.', 3619, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '턱관절 탈구', '턱관절탈구', 'PREVENTION', '턱관절 탈구 예방을 위해 하품이나 크게 벌리는 행동 시 턱을 손으로 가볍게 받치고, 입을 과도하게 벌리는 동작을 삼가는 것이 중요합니다. 딱딱하고 질긴 음식(오징어, 딱딱한 사탕, 껌 등)과 한쪽으로만 씹는 습관을 피하고, 음식은 작게 잘라 양쪽으로 고루 씹는 것이 좋습니다. 스트레스로 인한 이갈이·이 악물기 습관은 턱관절에 부담을 주므로 스트레스 관리와 필요 시 스플린트 착용을 고려하시기 바랍니다.', 3620, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '턱관절 탈구', '턱관절탈구', 'EXERCISE', '턱관절 탈구 후 붕대(고정) 제거 초기에는 과도한 개구를 유발하는 운동은 피해야 합니다. 가벼운 턱관절 스트레칭(전문의 지도하에 천천히 입 벌리기 연습)과 가벼운 유산소 운동(걷기 등)은 가능하나, 수영이나 접촉 스포츠 등은 치료 경과에 따라 전문의의 허가가 필요합니다. 운동 재개 시기와 종류는 구강악안면외과 전문의의 지침에 따라 단계적으로 결정하시기 바랍니다.', 3621, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '턱관절 탈구', '턱관절탈구', 'CAUSE', '하품, 웃음, 크게 웃는 행동처럼 입을 크게 벌리는 동작은 턱관절 과신전을 유발하여 관절 과두가 관절와에서 이탈하는 탈구를 일으킬 수 있습니다. 특히 턱관절 인대와 주변 근육이 이완되거나 약화된 경우 이러한 행동으로 탈구 위험이 높아집니다. 반복적인 탈구 병력이 있다면 구강악안면외과 전문의의 진찰을 받고 예방적 조치(스플린트 등)를 상담하시기 바랍니다.', 3622, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '턱관절 탈구', '턱관절탈구', 'REHAB', '턱관절 탈구와 관련된 통증 완화를 위한 재활 치료로는 온열 치료, 초음파 치료, 전기 자극 치료 등의 물리치료가 도움이 됩니다. 구강악안면외과 또는 재활의학과에서 시행하는 턱관절 운동 치료(개구 운동, 관절 가동화 기법)도 통증 감소와 기능 회복에 효과적입니다. 재활 치료 방법과 기간은 탈구의 정도와 환자 상태에 따라 전문의가 결정하므로 진료를 받으시기 바랍니다.', 3623, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '턱관절 탈구', '턱관절탈구', 'DEFINITION', '입을 크게 벌릴 때 나는 소리(클릭음 또는 딸깍 소리)는 턱관절 내 관절 원판(디스크)이 정상 위치에서 벗어나 관절 과두와 마찰이 생기거나, 관절 인대와 뼈 구조 사이에서 발생합니다. 이는 턱관절 장애(측두하악관절 장애, TMD)의 흔한 증상으로, 탈구보다는 디스크 전방 변위와 관련이 많습니다. 소리가 통증을 동반하거나 지속된다면 구강악안면외과 전문의의 정확한 진단이 필요합니다.', 3624, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '턱관절 탈구', '턱관절탈구', 'SYMPTOM', '입을 크게 벌리거나 음식을 먹을 때 통증이 나타나면 턱관절 장애(측두하악관절 장애, TMD), 턱관절 탈구, 치아 문제, 턱 근육 긴장(구강안면 근막통) 등을 의심해볼 수 있습니다. 턱관절 탈구 외에도 관절 원판 변위, 관절염, 부정교합 등이 원인일 수 있어 정확한 감별이 중요합니다. 구강악안면외과 전문의의 진찰과 영상 검사(파노라마, MRI 등)를 통한 정확한 진단을 받으시기 바랍니다.', 3625, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '턱관절 탈구', '턱관절탈구', 'DIAGNOSIS', '턱관절 탈구 또는 관련 증상 진단을 위해서는 구강악안면외과가 있는 치과 병원, 대학병원 치과, 또는 구강악안면외과 전문 병원을 방문하는 것이 적합합니다. 일부 종합병원 이비인후과, 재활의학과에서도 턱관절 관련 진료를 받을 수 있습니다. 방사선 검사(파노라마, CT, MRI)를 통해 관절 구조와 탈구 여부를 정밀하게 평가하므로 빠른 전문의 방문을 권장합니다.', 3626, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '턱관절 탈구', '턱관절탈구', 'TREATMENT', '턱관절 탈구 치료에서 통증 완화를 위해 소염진통제(이부프로펜, 나프록센 등)와 근이완제가 주로 사용됩니다. 심한 통증이나 근육 경련이 동반된 경우에는 벤조디아제핀 계열의 단기 근이완제나 국소 마취제 관절강 내 주사가 사용되기도 합니다. 약물 치료는 증상 완화에 보조적인 역할을 하며, 근본 치료(도수 정복, 스플린트 등)는 구강악안면외과 전문의와 상담하여 결정하시기 바랍니다.', 3627, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '건선', '건선', 'CHECKUP', '건선 검진은 피부과 전문의의 시진을 통해 은백색 인설이 덮인 홍반성 구진·판의 특징적 소견을 확인하는 것이 기본입니다. 진단이 불확실한 경우 피부 생검(조직 검사)을 시행하여 조직학적으로 확진하며, 관절 침범(건선성 관절염) 여부 확인을 위해 혈액 검사(염증 수치, HLA-B27 등)와 관절 방사선 검사를 추가로 시행할 수 있습니다. 건선은 다양한 피부 질환과 감별이 필요하므로 피부과 전문의의 정확한 진찰이 중요합니다.', 3628, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '건선', '건선', 'DIET_LIFE', '건선 치료 중에는 피부를 건조하게 하는 환경(낮은 습도, 과도한 냉난방)을 피하고 보습제를 충분히 사용하는 것이 중요합니다. 음주와 흡연은 건선을 악화시키므로 금연·절주가 필요하며, 스트레스도 주요 악화 요인이므로 스트레스 관리(명상, 규칙적인 운동 등)를 권장합니다. 처방받은 약물(스테로이드 연고, 면역조절제 등)을 규칙적으로 사용하고, 과도한 피부 자극과 외상을 피하는 것이 증상 관리에 도움이 됩니다.', 3629, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '건선', '건선', 'MEDICATION', '건선 치료에는 국소 치료제(코르티코스테로이드 연고, 비타민 D 유도체, 레티노이드), 광선 치료(자외선 B, PUVA), 전신 치료제(메토트렉세이트, 사이클로스포린, 아시트레틴) 및 생물학적 제제(TNF-α 억제제, IL-17 억제제 등)가 사용됩니다. 스테로이드 연고의 장기 사용은 피부 위축, 모세혈관 확장 등의 부작용이 있고, 전신 면역억제제는 감염 위험, 간·신장 독성 등이 나타날 수 있습니다. 치료 방법 선택과 부작용 모니터링은 피부과 전문의의 지속적인 관리하에 이루어져야 합니다.', 3630, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '건선', '건선', 'PREVENTION', '건선은 면역 매개 염증성 피부 질환으로 전염성이 없으므로, 건선 환자와 일상적인 접촉(악수, 함께 식사 등)으로는 감염되지 않습니다. 예방을 위해서는 피부를 건조하지 않게 유지하고, 피부 외상(쾨브너 현상 유발 요인)을 피하며, 스트레스 관리와 금연·절주를 실천하는 것이 중요합니다. 건선 환자는 정기적인 피부과 전문의 진료를 통해 악화 요인을 관리하고 치료를 이어가는 것이 권장됩니다.', 3631, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '건선', '건선', 'EXERCISE', '건선 환자에게 규칙적인 운동은 체중 조절, 염증 감소, 심리적 안정 등의 면에서 유익하므로 권장됩니다. 땀을 많이 흘리는 경우 운동 후 즉시 샤워하고 보습제를 충분히 바르면 피부 자극을 줄일 수 있습니다. 수영은 염소 자극이 피부를 건조하게 할 수 있어 수영 후 충분한 보습이 필요하며, 피부 마찰이 심한 접촉 스포츠는 병변 악화(쾨브너 현상)를 유발할 수 있으므로 주의가 필요합니다.', 3632, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '건선', '건선', 'CAUSE', '건선의 피부 가려움증과 붉은 반점은 아토피 피부염, 지루성 피부염, 습진 등과 유사하게 나타날 수 있어 혼동되기 쉽습니다. 건선은 경계가 명확한 은백색 인설(각질)을 동반한 붉은 판이 특징적이며, 아토피는 경계가 불명확하고 진물이 동반되는 경우가 많습니다. 정확한 감별을 위해 피부과 전문의의 진찰을 받으시기 바랍니다.', 3633, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '건선', '건선', 'REHAB', '건선의 붉은 구진과 발진 완화를 위한 재활적 접근으로는 스트레스 관리, 규칙적인 수면, 금연·금주가 도움이 됩니다. 적당한 햇빛 노출(자외선 치료 원리 활용)과 보습제를 꾸준히 사용하면 피부 장벽 강화에 효과적입니다. 재활 방법의 구체적인 적용은 피부과 전문의와 상담하여 개인 상태에 맞게 계획하시기 바랍니다.', 3634, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '건선', '건선', 'DEFINITION', '만성 피부염은 피부 염증이 6주 이상 지속되는 상태를 총칭하며, 건선·아토피 피부염·지루성 피부염 등이 포함됩니다. 건선은 면역 이상으로 인한 각질세포 과증식이 특징이고, 아토피는 피부 장벽 결함과 알레르기 반응이 주된 기전입니다. 각 만성 피부염은 원인·치료법이 달라 피부과 전문의의 정확한 진단이 필요합니다.', 3635, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '건선', '건선', 'SYMPTOM', '가려움이 없는 가슴 부위의 붉은 반점은 건선, 장미색 비강진, 지루성 피부염 등 다양한 원인일 수 있습니다. 정확한 원인 파악을 위해 피부과를 방문하여 육안 검진 및 필요 시 피부 조직 생검 검사를 받는 것이 권장됩니다. 자의적으로 진단하지 마시고 전문의 상담을 통해 적절한 치료를 받으시기 바랍니다.', 3636, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '건선', '건선', 'DIAGNOSIS', '건선 치료는 국소 치료(스테로이드 연고, 비타민 D 유도체), 광선 치료(자외선 B 치료), 전신 치료(메토트렉세이트, 사이클로스포린), 생물학적 제제 등 단계적으로 적용됩니다. 경증은 국소 치료를 우선하고, 중등도 이상에서는 광선 치료나 전신 치료를 고려합니다. 개인의 중증도와 병변 부위에 따라 치료 방법이 달라지므로 피부과 전문의와 상담하시기 바랍니다.', 3637, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '건선', '건선', 'TREATMENT', '건선은 면역계 이상으로 인해 피부 세포가 빠르게 증식하여 경계가 명확한 붉은 판(홍반) 위에 은백색 인설(각질)이 쌓이는 만성 재발성 피부 질환입니다. 발진, 각질 탈락, 붉은 반점이 나타난다는 설명은 건선의 전형적인 특징에 부합합니다. 정확한 진단과 치료를 위해 피부과 전문의 진찰을 받으시기 바랍니다.', 3638, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '기미', '기미', 'CHECKUP', '기미 예방을 위해 자외선 차단제는 SPF 30 이상, PA+++ 제품을 매일 외출 30분 전 충분히 도포하고, 2~3시간마다 덧바르는 것이 중요합니다. 챙이 넓은 모자와 선글라스, 자외선 차단 의류를 함께 사용하면 더욱 효과적입니다. 외출 후에는 즉시 세안하고 보습을 유지하며, 기존 기미는 피부과 전문의와 상담하여 관리하시기 바랍니다.', 3639, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '기미', '기미', 'DIET_LIFE', '자전거 라이딩과 같은 야외 활동은 자외선 노출로 인해 기미와 검버섯을 악화시킬 수 있습니다. 비타민 C가 풍부한 채소·과일(브로콜리, 키위, 파프리카) 섭취와 항산화 식품 위주의 식단이 색소 침착 예방에 도움이 됩니다. 활동 중에는 자외선 차단제를 2~3시간마다 재도포하고, 자외선이 강한 시간대(오전 10시~오후 2시)에는 가급적 야외 활동을 피하시기 바랍니다.', 3640, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '기미', '기미', 'MEDICATION', '기미 치료에 트라넥삼산 외에 하이드로퀴논, 아젤라산, 코직산, 비타민 C 유도체 등이 사용됩니다. 하이드로퀴논은 효과가 강하지만 장기 사용 시 반동성 색소침착 위험이 있으므로 전문의 처방 하에 사용해야 합니다. 어떤 성분이든 농도와 제형에 따라 피부 자극이 발생할 수 있으므로 피부과 전문의의 지도 하에 사용하시기 바랍니다.', 3641, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '기미', '기미', 'PREVENTION', '비타민 C는 멜라닌 합성 효소(티로시나제)를 억제하고 이미 생성된 멜라닌 색소를 환원시켜 기미 예방과 개선에 도움을 줍니다. 비타민 E는 항산화 작용으로 자외선에 의한 피부 산화 손상을 줄여 색소 침착 예방에 기여합니다. 다만 영양제만으로 기미를 완전히 예방하거나 치료하는 데는 한계가 있으므로, 자외선 차단과 병행하고 심한 기미는 피부과 상담을 권장합니다.', 3642, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '기미', '기미', 'EXERCISE', '기미가 진해지는 상황에서 테니스와 같은 야외 운동은 자외선 노출을 증가시켜 색소 침착을 더욱 악화시킬 수 있습니다. 야외 운동을 완전히 피하기보다는 자외선 차단제를 충분히 바르고, 모자와 자외선 차단 의류를 착용하며 자외선이 강한 시간대를 피해 활동하는 것이 현실적입니다. 기미가 심하다면 피부과 전문의와 상담하여 치료와 예방을 병행하시기 바랍니다.', 3643, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '기미', '기미', 'CAUSE', '기미의 주요 원인은 자외선 노출로, 자외선이 멜라닌 세포를 자극해 색소를 과잉 생성시킵니다. 여성 호르몬(에스트로겐)의 변화(임신, 경구피임약 복용 등)도 중요한 원인이며, 유전적 소인, 피부 노화, 염증 후 색소침착, 갑상선 질환 등도 기여합니다. 민감성 피부는 외부 자극에 취약해 염증 후 색소침착이 생기기 쉬우므로 자외선 차단과 피부 자극 최소화가 중요합니다.', 3644, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '기미', '기미', 'REHAB', '기미와 주근깨 관리를 위해 세안 시에는 약산성(pH 5.5 전후) 순한 폼 클렌저를 사용하고, 이중 세안은 피부 장벽을 손상시킬 수 있어 주의가 필요합니다. 보습제는 나이아신아마이드, 비타민 C, 알부틴 등 미백 성분이 포함된 제품이 색소 개선에 도움이 됩니다. 세안 제품과 보습제 선택은 개인 피부 타입에 따라 다르므로 피부과 전문의의 조언을 받는 것이 권장됩니다.', 3645, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '기미', '기미', 'DEFINITION', '기미는 멜라닌 색소가 피부 특정 부위에 과잉 침착되어 나타나는 후천성 과색소 질환으로, 주로 자외선, 호르몬 변화, 유전적 요인이 원인입니다. 형태에 따라 표피형(갈색, 자외선 조사 시 뚜렷해짐), 진피형(청갈색), 혼합형으로 구분되며 치료 반응이 다릅니다. 정확한 유형 감별과 적절한 치료 계획을 위해 피부과 전문의와 상담하시기 바랍니다.', 3646, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '기미', '기미', 'SYMPTOM', '기미의 주요 증상은 뺨, 이마, 코, 입 주위에 대칭적으로 나타나는 불규칙한 갈색~흑갈색 반점이며, 경계는 비교적 명확합니다. 가려움이나 통증은 없고 피부 표면은 정상이지만 색소 침착만 두드러지는 것이 특징입니다. 피부 상태가 건조하거나 장벽이 손상된 경우 색소침착이 더 심해질 수 있으므로 보습 관리가 중요합니다.', 3647, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '기미', '기미', 'DIAGNOSIS', '기미의 진단은 주로 피부과 전문의의 육안 관찰로 이루어지며, 반점의 색깔·형태·분포를 통해 임상적으로 진단합니다. 더모스코피(피부 확대경)를 이용해 표피형과 진피형을 구별하거나, 우드램프 검사를 통해 멜라닌 침착 깊이를 평가하기도 합니다. 악성 병변과 감별이 필요한 경우에는 피부 조직 검사를 시행할 수 있으므로, 의심 시 피부과 전문의 진찰을 받으시기 바랍니다.', 3648, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '기미', '기미', 'TREATMENT', 'IPL 레이저 시술 후 염증후색소침착(PIH) 예방을 위해 시술 후 2주 이상 철저한 자외선 차단(SPF 50+)이 필수적입니다. 시술 부위를 손으로 만지거나 자극하지 않고, 자극이 없는 순한 세안제와 충분한 보습을 유지해야 합니다. 시술 전후 전문의 처방에 따른 미백 외용제 사용과 적절한 에너지 설정이 중요하므로, 피부과 전문의와 충분히 상담 후 시술을 결정하시기 바랍니다.', 3649, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '내향성 손발톱', '내향성손발톱', 'CHECKUP', '내향성 손발톱은 임상적 시진(육안 검진)만으로 진단이 가능하며, 발톱 가장자리가 주변 연조직을 파고들어 발적·부종·통증·화농 여부를 확인합니다. 필요에 따라 방사선 검사(X선)로 뼈나 골수염 여부를 감별할 수 있습니다. 감염이 심하거나 반복 재발하는 경우에는 정형외과 또는 피부과 전문의를 방문하여 정확한 평가를 받으시기 바랍니다.', 3650, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '내향성 손발톱', '내향성손발톱', 'DIET_LIFE', '내향성 손발톱 예방을 위해 발톱은 일자로 잘라 가장자리를 지나치게 짧게 자르지 않는 것이 중요합니다. 음주는 말초 혈액 순환에 영향을 주고 상처 치유를 방해하며, 흡연은 혈액순환 장애로 조직 회복을 저하시키므로 내향성 손발톱 악화 및 감염 위험을 높입니다. 통풍이 잘 되고 발볼이 넉넉한 신발 착용과 청결한 발 위생 관리도 중요한 예방 방법입니다.', 3651, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '내향성 손발톱', '내향성손발톱', 'MEDICATION', '내향성 손발톱의 약물 치료는 주로 세균 감염(주로 황색포도상구균) 동반 시 항생제를 사용하며, 경증에는 국소 항생제, 중등도 이상에는 경구 항생제(세팔렉신 등)를 처방합니다. 투여 기간은 감염 정도에 따라 통상 5~14일이며, 정확한 용량과 기간은 감염 범위와 균 배양 결과에 따라 달라집니다. 적절한 항생제 선택과 기간 결정은 반드시 전문의 처방에 따라야 하며, 임의로 중단하지 않는 것이 중요합니다.', 3652, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '내향성 손발톱', '내향성손발톱', 'PREVENTION', '내향성 손발톱 예방을 위해 발톱을 곧게(일자형으로) 자르고 가장자리를 지나치게 짧게 자르지 않는 것이 핵심입니다. 발에 잘 맞는 넉넉한 신발을 착용하고, 발가락에 압력이 집중되지 않도록 해야 합니다. 증상이 반복되거나 염증이 심해지면 발톱 부분 절제 등의 시술이 필요할 수 있으므로 정형외과 또는 피부과 전문의와 상담하시기 바랍니다.', 3653, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '내향성 손발톱', '내향성손발톱', 'EXERCISE', '운동 중 내향성 손발톱 악화 요인으로는 발 앞부분이 좁거나 꽉 끼는 운동화 착용, 달리기 시 반복적인 발가락 압박, 발톱을 너무 짧게 자르는 습관 등이 있습니다. 축구, 마라톤처럼 발끝에 충격이 가해지는 운동은 특히 위험하며, 양말을 착용하지 않거나 부적절한 양말 착용도 악화 요인이 됩니다. 운동 시에는 발볼이 충분하고 발가락 공간이 넉넉한 운동화를 선택하시기 바랍니다.', 3654, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '내향성 손발톱', '내향성손발톱', 'CAUSE', '내향성 손발톱은 발톱의 가장자리가 주변 피부(조갑주름)를 파고들어 염증을 유발하는 상태로, 주요 원인은 잘못된 발톱 커팅(곡선형으로 너무 짧게 자르기), 꽉 끼는 신발, 유전적 발톱 형태, 외상 등입니다. 파고든 발톱이 피부를 자극해 발적·부종·통증이 생기고 세균 감염 시 화농이 발생합니다. 걷기 불편함과 염증이 지속되면 피부과 또는 정형외과 전문의를 방문하시기 바랍니다.', 3655, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '내향성 손발톱', '내향성손발톱', 'DEFINITION', '내향성 손발톱(내성 발톱)은 발톱의 측면 가장자리가 주변 연조직을 파고들어 통증, 발적, 부종, 화농을 유발하는 질환입니다. 발생 원인으로는 잘못된 발톱 자르기(너무 짧게 또는 곡선형), 앞볼이 좁은 신발, 유전적 발톱 형태(만곡 발톱), 외상 등이 있습니다. 손발톱 모양이 다르게 보이는 것은 원인과 발병 부위에 따라 형태가 다양하기 때문이며, 증상 지속 시 전문의 진찰이 필요합니다.', 3656, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '내향성 손발톱', '내향성손발톱', 'SYMPTOM', '내향성 손발톱의 증상은 중증도에 따라 1~3단계로 구분됩니다. 1단계는 발톱 가장자리 주변 발적·부종·통증이 나타나고, 2단계는 감염으로 고름(농)이 생기며 압통이 심해집니다. 3단계에서는 과립조직(육아조직)이 과잉 형성되어 발톱 가장자리를 덮고 만성 통증과 감염이 반복되므로, 2단계 이상에서는 반드시 전문의 치료가 필요합니다.', 3657, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '내향성 손발톱', '내향성손발톱', 'DIAGNOSIS', '내향성 손발톱 진단과 치료를 위해서는 피부과 또는 정형외과(족부 전문)를 방문하는 것이 적합합니다. 피부과에서는 경증~중등도 관리와 국소 시술을, 정형외과에서는 만성·중증 또는 재발 사례의 발톱 부분/전체 발치술을 시행합니다. 감염이 심하거나 당뇨 등 기저 질환이 있는 경우 빠른 전문의 진찰이 중요합니다.', 3658, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '내향성 손발톱', '내향성손발톱', 'TREATMENT', '내향성 손발톱 치료의 효과는 계절보다는 감염 및 염증 상태에 따라 달라지며, 특정 계절이 치료에 더 효과적이라는 의학적 근거는 없습니다. 다만 겨울에는 발이 통풍이 덜 되고 두꺼운 신발을 착용하므로 수술 후 청결 유지와 통기가 여름보다 불리할 수 있습니다. 증상이 있을 때 시기에 관계없이 피부과 또는 정형외과 전문의에게 조속히 치료받는 것이 권장됩니다.', 3659, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '농가진', '농가진', 'CAUSE', '발병 초기 정상 피부에 자잘한 물집이 생기는 농가진은 주로 황색포도상구균 또는 연쇄상구균에 의한 세균 감염이 원인입니다. 피부의 미세한 상처, 벌레 물린 자국, 습진 등 피부 장벽이 손상된 부위로 세균이 침입하여 수포를 형성합니다. 고온 다습한 환경과 불충분한 위생 관리가 감염을 촉진하므로, 증상 발생 시 피부과 전문의 진찰을 받으시기 바랍니다.', 3660, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '농가진', '농가진', 'DEFINITION', '농가진은 주로 황색포도상구균이나 화농성 연쇄상구균에 의한 피부 표층 세균 감염증으로, 수포·농포·황색 딱지가 특징적입니다. 농축산물 섭취는 농가진의 직접적인 원인이나 악화 요인이 아니며, 감염 경로는 피부 접촉, 불결한 위생, 상처를 통한 세균 침입입니다. 전염성이 강해 특히 소아에서 빠르게 퍼질 수 있으므로 즉시 피부과 전문의 진찰과 항생제 치료가 필요합니다.', 3661, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '농가진', '농가진', 'SYMPTOM', '얼굴과 사타구니의 작은 물집이 농가진으로 의심되는 경우 피부과를 방문하여 임상적 시진으로 일차 진단이 가능합니다. 필요 시 수포액이나 병변 부위의 도말 및 세균 배양 검사로 원인균을 확인하고 항생제 감수성을 파악합니다. 농가진은 전염성이 강하므로 진단 전까지 다른 사람과의 피부 접촉을 피하고 개인 위생을 철저히 하시기 바랍니다.', 3662, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '농가진', '농가진', 'DIAGNOSIS', '아이의 코 밑 심한 딱지와 각질은 농가진의 전형적인 증상으로, 황색 꿀색 딱지가 특징입니다. 농가진이 의심되면 소아과 또는 피부과를 방문하여 정확한 진단을 받아야 합니다. 농가진은 항생제 치료가 필요하고 전염성이 강하므로 빠른 시일 내에 전문의 진찰을 받고, 치료 전까지 손 씻기와 수건·식기 분리 사용 등 위생 관리를 철저히 하시기 바랍니다.', 3663, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '농가진', '농가진', 'TREATMENT', '농가진의 국소 치료에는 무피로신(mupirocin) 연고나 퓨시드산(fusidic acid) 연고가 1차적으로 사용됩니다. 병변 범위가 넓거나 전신 증상이 있는 경우에는 경구 항생제(세팔렉신, 아목시실린-클라불란산 등) 복용이 필요합니다. 연고 선택과 사용 기간은 감염 범위와 균의 항생제 내성 여부에 따라 다르므로, 반드시 피부과 또는 소아과 전문의의 처방을 받아 사용하시기 바랍니다.', 3664, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '단순 포진', '단순포진', 'CAUSE', '단순 포진(헤르페스 바이러스 감염)의 주요 원인은 HSV-1(구순 헤르페스), HSV-2(생식기 헤르페스)이며, 피부 접촉·키스·성접촉을 통해 전파됩니다. 증상은 성기나 항문 부위 발적 외에도 군집성 수포, 궤양, 통증, 작열감, 국소 림프절 비대, 초기 감염 시 발열·근육통 등 전신 증상이 동반될 수 있습니다. 바이러스는 잠복 후 면역 저하, 스트레스, 피로 시 재활성화되므로 전문의 상담이 중요합니다.', 3665, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '단순 포진', '단순포진', 'DEFINITION', '피부에 반복적으로 군집성 수포가 발생한다면 단순 포진(헤르페스)의 가능성이 있습니다. 단순 포진은 HSV 바이러스에 의해 발생하며, 수포가 나타나기 전 따끔거림·가려움·작열감 등의 전구 증상이 있고, 수포가 터진 후 궤양을 형성하다 가피(딱지)로 치유되는 경과를 보입니다. 정확한 진단을 위해 피부과 또는 비뇨기과 전문의를 방문하여 바이러스 검사를 받으시기 바랍니다.', 3666, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '단순 포진', '단순포진', 'SYMPTOM', '입술 주위에 군집성 작은 물집이 생기고 터질 것 같은 느낌(팽만감, 작열감)은 HSV-1에 의한 구순 헤르페스(입술 단순 포진)의 전형적인 증상입니다. 수포 발생 전에 따끔거림이나 가려움이 먼저 나타나는 것이 특징이며, 아프타성 구내염·구순염 등과 감별이 필요합니다. 증상이 자주 재발하거나 심한 경우 피부과 전문의를 방문하여 항바이러스제 치료를 받으시기 바랍니다.', 3667, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '단순 포진', '단순포진', 'TREATMENT', '단순 포진 증상 완화를 위한 생활습관으로는 충분한 수면과 휴식, 스트레스 관리, 균형 잡힌 영양 섭취(면역력 강화)가 중요합니다. 자외선(일광 노출)이 구순 헤르페스를 유발할 수 있으므로 입술에 SPF가 있는 립밤을 사용하는 것이 도움됩니다. 항바이러스제(아시클로버 등) 복용이 치료의 핵심이므로, 증상 초기에 피부과 전문의와 상담하여 적절한 약물 치료를 받으시기 바랍니다.', 3668, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '대상포진', '대상포진', 'CHECKUP', '대상포진 진단에는 임상적 시진 외에도 수포액 바이러스 배양 검사, PCR 검사(수두-대상포진 바이러스 DNA 검출), 형광항체법 등이 사용됩니다. 눈 주변이나 귀 주변 침범 시 안과 또는 이비인후과 협진이 필요하며, 면역 저하 환자에서는 혈액 검사로 원인 확인이 중요합니다. 진단이 불명확하거나 비전형적인 경우 피부과 전문의를 통한 정밀 검사를 받으시기 바랍니다.', 3669, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '대상포진', '대상포진', 'DIET_LIFE', '대상포진 관리를 위해 충분한 수면, 스트레스 감소, 규칙적인 가벼운 운동으로 면역력을 유지하는 것이 중요합니다. 단백질이 풍부한 식품(살코기, 생선, 두부, 달걀)과 비타민 B군, 비타민 C가 풍부한 채소·과일이 신경 회복과 체력 증진에 도움이 됩니다. 급성기에는 충분한 휴식이 우선이며, 식욕이 저하된 경우 소화가 잘 되는 부드러운 음식을 소량씩 자주 드시기 바랍니다.', 3670, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '대상포진', '대상포진', 'MEDICATION', '대상포진 항바이러스제(아시클로버, 팜시클로버 등) 복용 시 속 쓰림 등 위장 부작용이 나타날 수 있으므로, 가능하면 식후 복용하는 것이 권장됩니다. 부작용이 심한 경우 의사나 약사에게 즉시 알리고, 임의로 약을 중단하지 말고 복용 방법 조정(식후 복용, 제산제 병용 등)에 대해 상담하시기 바랍니다. 심한 부작용이나 알레르기 반응(발진, 호흡곤란 등)이 나타나면 즉시 응급처치를 받으시기 바랍니다.', 3671, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '대상포진', '대상포진', 'PREVENTION', '대상포진에 한 번 걸렸다고 해서 영원히 면역이 생기는 것은 아닙니다. 대상포진은 수두-대상포진 바이러스(VZV)가 신경절에 잠복해 있다가 면역력이 떨어질 때 재활성화되는 것으로, 재발이 가능합니다. 특히 면역 저하자, 고령자에서 재발 위험이 높으므로 50세 이상에서는 예방 백신 접종을 피부과 또는 내과 전문의와 상담하여 고려하시기 바랍니다.', 3672, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '대상포진', '대상포진', 'EXERCISE', '대상포진 후 면역력 향상에는 걷기, 수영, 자전거 타기 등 중등도 유산소 운동이 효과적이며, 면역 기능 강화와 신경통 완화에 도움이 됩니다. 급성기에는 통증으로 운동이 어려울 수 있으므로 가벼운 스트레칭과 이완 운동부터 시작하는 것이 좋습니다. 운동 강도와 종류는 개인의 통증 정도와 전반적인 건강 상태에 따라 다르므로 담당 전문의와 상담 후 결정하시기 바랍니다.', 3673, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '대상포진', '대상포진', 'CAUSE', '대상포진이 안면부 신경(삼차신경, 안면신경)을 침범하면 안면마비(람제이-헌트 증후군), 귀 통증, 이명 등이 동반될 수 있습니다. 생활습관 개선으로 충분한 수면, 스트레스 관리, 금연·절주, 균형 잡힌 식사가 면역력 유지에 도움이 되어 대상포진과 안면마비 회복에 긍정적 영향을 줍니다. 안면마비가 동반된 경우 빠른 항바이러스제 치료가 예후에 중요하므로 즉시 신경과 또는 이비인후과 전문의 진찰을 받으시기 바랍니다.', 3674, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '대상포진', '대상포진', 'REHAB', '대상포진은 잠복해 있던 수두-대상포진 바이러스(VZV)가 면역 저하 시 재활성화되어 신경절을 따라 피부에 줄무늬(신경대) 모양의 수포성 발진과 극심한 통증을 유발합니다. 치료는 항바이러스제(아시클로버, 팜시클로버) 조기 투여가 핵심이며, 통증 조절을 위해 진통제, 신경통 치료제(가바펜틴 등)가 사용됩니다. 재활 측면에서는 대상포진 후 신경통 관리를 위해 물리치료, 경피신경전기자극(TENS) 등을 전문의와 상담하여 고려할 수 있습니다.', 3675, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '대상포진', '대상포진', 'DEFINITION', '대상포진은 수두-대상포진 바이러스가 체내 신경절에 잠복했다가 재활성화되는 질환으로, 특징적으로 신체 한쪽(단측성)에만 줄무늬 모양의 수포성 발진이 나타납니다. 양쪽 옆구리에서 동시에 발진이 나타나는 경우는 대상포진의 전형적인 패턴에 맞지 않으므로, 다른 피부 질환과의 감별이 필요합니다. 정확한 진단을 위해 피부과 전문의를 방문하시기 바랍니다.', 3676, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '대상포진', '대상포진', 'SYMPTOM', '대상포진은 초기에 피부 발진 전에 해당 신경 분절을 따른 타는 듯한 통증, 이상 감각이 먼저 나타나는 것이 특징입니다. 붉은 병변에 가려움이나 통증이 없는 경우는 대상포진보다 다른 피부 질환(지루성 피부염, 건선 등)일 가능성이 높습니다. 정확한 감별을 위해 병변이 지속되거나 새로운 증상이 나타나면 피부과 전문의를 방문하시기 바랍니다.', 3677, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '대상포진', '대상포진', 'DIAGNOSIS', '대상포진 진단은 주로 특징적인 임상 양상(단측성 신경통 + 피부 분절을 따른 수포성 발진)으로 이루어집니다. 비전형적이거나 불확실한 경우 수포액 PCR 검사(VZV DNA 검출)가 가장 특이도 높은 확진 방법이며, 혈청 항체 검사(IgM, IgG)도 활용됩니다. 병변이 눈 주위, 귀 주위 등 특수 부위인 경우 협진이 필요하므로 피부과 전문의를 통해 적절한 검사를 받으시기 바랍니다.', 3678, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '대상포진', '대상포진', 'TREATMENT', '대상포진 치료는 피부과, 내과, 신경과 등에서 받을 수 있으며, 발진 발생 후 72시간 이내 항바이러스제 투여가 시작되어야 효과가 좋습니다. 가장 가까운 피부과나 내과 의원을 방문하거나, 증상이 심하면 응급실을 이용하시기 바랍니다. 수두 병변과 구별이 어려울 수 있으므로 전문의가 직접 진찰하여 정확한 진단과 치료 계획을 수립하는 것이 중요합니다.', 3679, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '동상', '동상', 'PREVENTION', '동상 예방을 위해 겨울철에는 손발·귀·코 등 노출 부위를 장갑, 두꺼운 양말, 귀마개, 목도리로 충분히 보온해야 합니다. 젖은 옷이나 신발은 즉시 교체하고, 밀착된 신발보다 약간 여유 있는 신발을 신어 혈액 순환을 유지해야 합니다. 음주 후 야외 활동은 체온 조절 능력을 저하시켜 동상 위험을 높이므로 주의하고, 당뇨·말초혈관질환 등 기저 질환자는 특히 주의가 필요합니다.', 3680, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '동상', '동상', 'CAUSE', '동상은 극한의 추운 환경에 장시간 노출될 때 신체 조직(주로 말초 부위)의 혈관이 수축하고 세포 내외에 얼음 결정이 형성되어 조직 손상이 발생하는 것이 주된 원인입니다. 습한 환경, 바람, 꽉 끼는 의복·신발로 인한 혈액 순환 저하, 탈수, 음주, 피로 등이 동상 발생을 촉진합니다. 당뇨병, 말초혈관질환, 흡연 등으로 혈액 순환이 불량한 경우 동상 위험이 더욱 높습니다.', 3681, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '동상', '동상', 'DEFINITION', '동상은 신체가 영하의 온도에 장시간 노출될 때 조직의 동결로 인해 발생하는 냉손상으로, 주로 손가락, 발가락, 귀, 코, 뺨 등 말초 부위에 발생합니다. 발가락이 얼어 감각이 없어지는 증상은 동상의 전형적인 초기 징후이며, 피부가 창백해지고 딱딱해지는 양상을 보입니다. 중증 동상은 조직 괴사로 이어질 수 있으므로 즉시 따뜻한 장소로 이동하고 전문 의료기관을 방문하시기 바랍니다.', 3682, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '동상', '동상', 'SYMPTOM', '얼음찜질 후 두드러기(한랭 두드러기)는 동상과 별개의 질환으로, 추위·냉각 자극에 대한 알레르기 반응입니다. 동상이 의심되거나 한랭 관련 피부 문제가 있는 경우 피부과 또는 응급의학과를 방문하시기 바랍니다. 한랭 두드러기와 동상은 원인과 치료 방법이 다르므로 전문의의 정확한 감별 진단이 필요합니다.', 3683, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '동상', '동상', 'DIAGNOSIS', '겨울 산행 후 발가락의 피부가 검게 변하고 감각이 없다면 3~4도 동상의 가능성이 높습니다. 즉시 응급의학과 또는 정형외과, 성형외과(창상 전문)를 방문하여 응급 처치를 받아야 하며, 해당 부위를 문지르거나 직접 가열하면 조직 손상이 악화되므로 피해야 합니다. 심한 동상은 조직 괴사로 절단이 필요할 수 있으므로 빠른 전문 의료기관 방문이 매우 중요합니다.', 3684, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '동상', '동상', 'TREATMENT', '동상 치료 기간은 중증도에 따라 크게 다릅니다. 1도 동상은 수일~1주, 2도 동상은 2~4주, 3~4도 심한 동상은 수개월의 치료와 경과 관찰이 필요하며 조직 괴사 여부에 따라 수술(절단)이 필요할 수 있습니다. 통증이 심한 경우 입원 치료를 통해 항응고제, 혈관확장제, 진통제 등을 사용하므로 즉시 응급의학과나 정형외과 전문의를 방문하시기 바랍니다.', 3685, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '두드러기', '두드러기', 'MEDICATION', '화이자 COVID-19 백신 접종 후 두드러기는 주사 부위 외에도 전신 어느 부위에도 나타날 수 있으며, 두피(머리)를 포함한 전신 두드러기 반응이 발생할 수 있습니다. 백신 접종 후 알레르기 반응은 주로 접종 후 수 분~수 시간 내에 나타나며, 발열·두드러기·가려움 등이 동반될 수 있습니다. 접종 후 두드러기나 이상 반응이 지속되면 의료기관을 방문하여 항히스타민제 등 적절한 치료를 받으시기 바랍니다.', 3686, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '두드러기', '두드러기', 'CAUSE', '두드러기의 주요 원인은 음식물 알레르기(견과류, 갑각류, 달걀 등), 약물, 감염, 물리적 자극(압박, 열, 냉기), 곤충 독소 등 다양합니다. 벌레에 물린 후 나타나는 팽진(두드러기 모양의 부종)과 발적은 벌레 독소에 대한 국소 알레르기 반응으로 두드러기와 유사한 기전으로 발생합니다. 반복적·만성적 두드러기는 자가면역 원인도 있을 수 있으므로 피부과 전문의 진찰을 권장합니다.', 3687, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '두드러기', '두드러기', 'DEFINITION', '발효주(와인, 막걸리 등)를 마신 후 두드러기가 생기는 것은 알코올이나 발효 과정의 히스타민, 아황산염(sulfite) 등에 대한 알레르기·불내성 반응으로, 두드러기의 한 유형입니다. 두드러기는 피부에 팽진(wheals)과 발적이 나타나고 심한 가려움이 동반되는 피부 반응으로, 이 증상은 두드러기의 정확한 특징에 해당합니다. 반복적으로 나타난다면 피부과 또는 알레르기내과 전문의를 방문하여 원인을 확인하시기 바랍니다.', 3688, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '두드러기', '두드러기', 'SYMPTOM', '콜린성 두드러기는 운동, 더운 목욕, 발열 등 체온 상승 시 나타나는 두드러기로, 벌레에 물렸을 때의 반응과는 발생 기전이 다릅니다. 벌레 물림으로 인한 팽진은 국소적 알레르기 반응이고, 콜린성 두드러기는 아세틸콜린 자극에 의한 비만세포 탈과립으로 발생하며 2~3mm의 작은 팽진이 광범위하게 나타납니다. 두 증상의 공통점은 히스타민 분비에 의한 가려움과 팽진이므로 항히스타민제가 증상 완화에 도움이 됩니다.', 3689, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '두드러기', '두드러기', 'DIAGNOSIS', '햇빛 알레르기(광알레르기성 두드러기)는 자외선 노출 후 가려움과 두드러기가 나타나는 질환으로, 피부과 또는 알레르기내과에서 진단받을 수 있습니다. 진단을 위해 광첩포 검사(광패치 테스트)나 광유발 검사를 시행하며, 지역 내 피부과 의원·대학병원 피부과에서 진료가 가능합니다. 병원 예약 전 건강보험심사평가원 홈페이지나 건강iN 앱에서 가까운 피부과를 검색하실 수 있습니다.', 3690, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '두드러기', '두드러기', 'TREATMENT', '계곡 등 야외 활동 후 나타난 피부 가려움과 두드러기는 햇빛 알레르기(광 두드러기), 물 두드러기, 콜린성 두드러기, 접촉성 두드러기 등 다양한 원인일 수 있습니다. 정확한 진단을 위해 피부과를 방문하여 광유발 검사, 알레르기 피부 반응 검사(피부 단자 검사), 혈청 특이 IgE 검사 등을 받는 것이 권장됩니다. 증상이 반복된다면 피부과 전문의와 상담하여 원인을 파악하고 적절한 치료를 받으시기 바랍니다.', 3691, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '두부 백선', '두부백선', 'PREVENTION', '두부 백선(머리 백선)은 피부사상균의 감염으로 발생하므로, 자외선 노출보다는 감염원과의 접촉 차단이 핵심 예방 방법입니다. 예방을 위해 타인의 모자·빗·수건 등 공유를 피하고, 두피를 청결하게 유지해야 합니다. 반려동물(고양이, 강아지)과의 접촉 후 손을 씻는 것도 중요하며, 감염이 의심되면 피부과 전문의를 방문하여 조기에 치료받는 것이 확산 예방에 중요합니다.', 3692, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '두부 백선', '두부백선', 'CAUSE', '두부 백선은 음식으로 먹는 두부와는 관계가 없으며, 피부사상균(주로 Microsporum, Trichophyton 속)의 두피 감염으로 발생합니다. 반려동물(고양이, 강아지)은 두부 백선의 주요 감염 경로 중 하나로, 감염된 동물과의 직접 접촉이나 함께 잠자리를 사용하면 사람에게 전파될 수 있습니다. 반려동물을 키우는 환경에서 두피 증상이 나타나면 피부과 전문의 진찰을 받고 반려동물도 수의사에게 검진시키기 바랍니다.', 3693, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '두부 백선', '두부백선', 'DEFINITION', '두부 백선은 피부사상균이 두피와 모발에 감염을 일으키는 진균성 질환으로, 주로 학령기 아동에서 발생합니다. 원형 또는 불규칙한 탈모반, 두피 인설(각질), 모발이 짧게 부러지는 소견, 때로는 가려움이나 염증(저치) 반응이 특징입니다. 전염성이 있어 학교나 집단 시설에서 쉽게 퍼질 수 있으므로 조기 진단과 항진균제 치료가 중요합니다.', 3694, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '두부 백선', '두부백선', 'SYMPTOM', '두부 백선에서 원형 탈모와 가려움증은 함께 나타날 수 있는 증상입니다. 두부 백선은 피부사상균 감염으로 인한 탈모반과 인설이 주된 특징이며, 가려움은 동반될 수 있지만 항상 나타나는 것은 아닙니다. 원형 탈모증(alopecia areata)과의 감별이 필요하므로, 두 증상이 함께 나타난다면 피부과 전문의를 방문하여 진균 검사 등 정확한 진단을 받으시기 바랍니다.', 3695, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '두부 백선', '두부백선', 'DIAGNOSIS', '두부 백선 진단 후 두피 외 다른 부위(체부, 손발)에 유사한 원형 인설 병변이 나타난다면, 체부 백선(완선, 무좀 등) 등으로의 확산이나 다른 진균 감염을 의심할 수 있습니다. 부위별로 원인균이 다를 수 있으며, 진단 방법(KOH 도말 검사, 진균 배양)을 통해 추가 평가가 필요합니다. 다발성 병변이 나타나면 피부과 전문의와 상담하여 전신 항진균제 치료 여부를 결정하시기 바랍니다.', 3696, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '두부 백선', '두부백선', 'TREATMENT', '두부 백선 치료의 핵심은 머리를 자주 감는 것 외에 항진균제 전신 투여(그리세오풀빈, 터비나핀, 이트라코나졸 등 경구제)가 필수적입니다. 국소 항진균 샴푸(케토코나졸, 셀레늄 황화물 등)를 병용하면 전파 차단에 도움이 됩니다. 치료 기간은 수주에서 수개월로 길 수 있으며, 임의로 약을 중단하면 재발 위험이 높으므로 피부과 전문의 지시에 따라 치료를 완료하시기 바랍니다.', 3697, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '땀띠', '땀띠', 'MEDICATION', '땀띠 증상 완화를 위해 칼라민 로션이나 하이드로코르티손 크림(저농도 스테로이드)이 가려움과 피부 자극 완화에 사용됩니다. 탈크 파우더는 수분 흡수에 도움이 될 수 있으나 호흡기에 유해할 수 있어 주의가 필요합니다. 약물 선택과 사용 기간은 연령(특히 영아), 피부 상태에 따라 다르므로 피부과 전문의 또는 소아과 전문의와 상담 후 사용하시기 바랍니다.', 3698, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '땀띠', '땀띠', 'PREVENTION', '땀띠 예방을 위해 흡습성이 좋은 순면 소재 침구류 사용이 권장되며, 합성 섬유는 땀 증발을 방해해 땀띠를 악화시킬 수 있습니다. 시원하고 가벼운 침구를 사용하고, 방 온도와 습도를 적절히 유지하며(에어컨·선풍기 활용), 땀이 날 경우 즉시 씻고 건조시키는 것이 중요합니다. 특히 영아에서는 과도한 포대기나 두꺼운 이불 사용을 피하고 통기성 있는 침구를 사용하시기 바랍니다.', 3699, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '땀띠', '땀띠', 'CAUSE', '땀띠는 땀샘 분비관이 막혀 땀이 피부 내에 저류되어 발생하며, 주로 목, 겨드랑이, 사타구니, 무릎 뒤 등 피부가 겹치는 부위에 자주 나타납니다. 피부 겹침 부위는 통기가 불량하고 땀과 마찰이 지속되어 땀샘 분비관이 막히기 쉽습니다. 고온 다습한 환경에서 땀 분비가 증가할 때 발생 빈도가 높아지며, 특히 영아와 비만인에서 피부 겹침이 많아 발생 위험이 큽니다.', 3700, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '땀띠', '땀띠', 'DEFINITION', '땀띠(한진)는 고온 다습한 환경에서 땀이 과도하게 분비될 때 땀샘의 분비관이 막혀 땀이 피부 내에 고이면서 발생하는 피부 질환입니다. 주로 작은 붉은 구진이나 수포로 나타나며 심한 가려움이 동반되고, 아이들의 목·겨드랑이·기저귀 부위에 많이 발생합니다. 시원한 환경 유지, 목욕 후 건조, 통기성 좋은 옷 착용이 기본 관리이며, 심한 경우 피부과·소아과 전문의 진찰이 필요합니다.', 3701, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '땀띠', '땀띠', 'SYMPTOM', '목과 팔 접힘 부위의 발적과 심한 가려움은 땀띠(홍색한진)의 전형적인 증상에 해당합니다. 땀띠는 작은 붉은 구진이 군집하여 나타나고 따끔거림과 가려움이 동반되며, 시원하게 해주면 증상이 완화되는 특징이 있습니다. 아토피 피부염 등 다른 피부 질환과 감별이 필요할 수 있으므로, 증상이 지속되거나 악화되면 피부과 전문의 진찰을 받으시기 바랍니다.', 3702, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '땀띠', '땀띠', 'DIAGNOSIS', '아이의 붉게 부어오르고 가려운 증상이 있는 경우 가까운 소아과 또는 피부과 의원을 방문하여 진찰을 받으시기 바랍니다. 지역 내 소아과나 피부과는 건강보험심사평가원 홈페이지(www.hira.or.kr)의 병원·약국 찾기 또는 건강iN 앱을 통해 검색하실 수 있습니다. 증상이 광범위하거나 발열이 동반된 경우 빠른 진찰이 필요합니다.', 3703, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '땀띠', '땀띠', 'TREATMENT', '집에서 할 수 있는 땀띠 자가 관리로는 시원한 환경(에어컨·선풍기 활용) 유지, 하루 여러 번 미지근한 물로 목욕 후 물기를 충분히 건조시키는 것이 효과적입니다. 통기성 좋은 순면 의류 착용, 땀이 나는 경우 즉시 닦아내기, 피부 접힘 부위에 베이비 파우더(탈크 제외 옥수수 전분 등) 사용이 도움이 됩니다. 가려움이 심할 경우 칼라민 로션을 바를 수 있으나, 증상이 호전되지 않으면 피부과 전문의 진찰을 받으시기 바랍니다.', 3704, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '만성 두드러기', '만성두드러기', 'MEDICATION', '만성 두드러기 환자에서 약물 알레르기 증상 조절을 위해 비진정성 항히스타민제(세티리진, 로라타딘, 펙소페나딘 등)가 1차 치료제로 사용됩니다. 증상이 충분히 조절되지 않는 경우 항히스타민제 용량 증량, 항류코트리엔제 병용 또는 오말리주맙(항IgE 생물학적 제제)을 전문의 판단 하에 사용할 수 있습니다. 약물 알레르기가 의심되는 경우 원인 약물 회피가 가장 중요하며, 피부과 또는 알레르기내과 전문의와 상담하시기 바랍니다.', 3705, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '만성 두드러기', '만성두드러기', 'CAUSE', '만성 두드러기의 원인은 약 80~90%에서 특발성(원인 불명)이며, 나머지에서 음식물(견과류, 갑각류, 식품첨가물, 살리실산염 등), 약물, 감염, 물리적 자극 등이 관련됩니다. 식품첨가물(방부제, 색소, 아황산염)도 일부 환자에서 악화 요인으로 작용할 수 있습니다. 특정 환경 요인이나 음식과의 연관성을 파악하기 위해 피부과 또는 알레르기내과에서 체계적인 원인 검사를 받는 것이 권장됩니다.', 3706, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '만성 두드러기', '만성두드러기', 'DEFINITION', '만성 두드러기는 원인 불명의 두드러기 증상(팽진과 가려움)이 6주 이상 지속되거나 반복되는 상태를 말합니다. 피부에 갑자기 크기 다양한 붉고 부풀어 오른 팽진이 나타나 극심한 가려움을 유발하고, 수 시간 내에 사라졌다가 다른 부위에 재발하는 양상이 특징입니다. 혈관부종(입술, 눈꺼풀 부종)이 동반될 수 있으며, 정확한 원인 파악과 치료를 위해 피부과 전문의 진찰이 필요합니다.', 3707, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '만성 두드러기', '만성두드러기', 'SYMPTOM', '만성 두드러기의 주요 증상은 피부의 팽진(부풀어 오름)과 심한 가려움이 반복적으로 나타나는 것이며, 홍반(발적)은 팽진에 동반되어 나타납니다. 가려움과 발적이 지속적으로 나타난다면 이는 만성 두드러기의 주요 증상 중 하나로 볼 수 있습니다. 다만 아토피 피부염, 접촉성 피부염 등 다른 피부 질환도 유사한 증상을 보일 수 있으므로 피부과 전문의의 정확한 감별이 필요합니다.', 3708, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '만성 두드러기', '만성두드러기', 'DIAGNOSIS', '만성 두드러기의 알레르기 원인 규명을 위해 혈청 특이 IgE 검사(RAST), 피부 단자 검사(SPT)를 통해 알레르겐을 확인할 수 있습니다. 자가면역성 두드러기 감별을 위해 자가혈청 피부 검사(ASST), 항FcεRIα 항체 검사 등이 시행될 수 있습니다. 전체 혈구 검사, 갑상선 기능 검사, CRP 등 기본 혈액 검사도 원인 감별에 도움이 되므로 알레르기내과 또는 피부과 전문의와 상담하여 적절한 검사를 받으시기 바랍니다.', 3709, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '만성 두드러기', '만성두드러기', 'TREATMENT', '만성 두드러기의 1차 치료는 비진정성 2세대 항히스타민제(세티리진, 펙소페나딘, 로라타딘, 빌라스틴 등) 규칙적 복용이 가장 일반적입니다. 1차 치료에 반응이 불충분하면 용량을 최대 4배까지 증량하거나, 항류코트리엔제(몬테루카스트)를 병용합니다. 이에도 반응이 없는 중증 만성 두드러기에는 오말리주맙(항IgE 단클론항체) 주사 치료를 전문의 처방 하에 고려할 수 있습니다.', 3710, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모공성 각화증', '모공성각화증', 'PREVENTION', '모공성 각화증 예방을 위해 건조한 피부를 유발하는 환경(낮은 습도, 과도한 세안)을 피하고 충분한 보습이 중요합니다. 요소(urea), 젖산, 살리실산 등 각질 연화 성분이 포함된 보습제를 목욕 후 즉시 바르는 것이 효과적입니다. 거친 때수건으로 강하게 문지르는 행위는 피부 자극을 악화시킬 수 있으므로, 일상적으로 부드러운 세안과 규칙적인 보습 습관을 유지하시기 바랍니다.', 3711, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모공성 각화증', '모공성각화증', 'CAUSE', '모공성 각화증은 모공 내 케라틴이 과잉 축적되어 발생하는 유전성 피부 질환으로, 피지 분비 과다와는 직접적인 관련이 없습니다. 팔뚝, 허벅지, 볼 등에 작은 닭살 모양 돌기가 나타나는 것은 모공성 각화증의 전형적인 증상이며, 유전적 소인이 강해 가족력이 있는 경우 나타나기 쉽습니다. 미용적 문제 외에 건강에 큰 영향은 없지만 증상이 심하면 피부과 전문의와 치료 방법을 상담하시기 바랍니다.', 3712, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모공성 각화증', '모공성각화증', 'DEFINITION', '모공성 각화증(keratosis pilaris)은 모공을 둘러싼 케라틴이 과잉 생성되어 모공이 막히고 작은 닭살 모양의 구진이 무수히 발생하는 양성 피부 질환입니다. 주로 팔 바깥쪽, 허벅지, 볼 등에 나타나며 표면이 거칠고 건조하게 느껴지고, 가려움이 동반될 수 있습니다. 유전성이 강하고 완치보다 증상 관리에 초점을 두며, 악화·완화를 반복하는 것이 특징입니다.', 3713, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모공성 각화증', '모공성각화증', 'SYMPTOM', '모공성 각화증은 모공을 막는 각질 플러그에 의한 닭살 모양의 거친 구진이 특징이며, 가려움은 경미하거나 없고 피부 건조가 주된 문제입니다. 아토피 피부염은 피부 장벽 결함과 면역 이상으로 인한 심한 가려움, 습진성 병변(삼출, 가피), 피부 건조가 특징이며 얼굴·팔오금·무릎 뒤에 호발합니다. 두 질환은 동반되는 경우가 많으므로, 정확한 감별과 치료 계획을 위해 피부과 전문의 진찰을 받으시기 바랍니다.', 3714, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모공성 각화증', '모공성각화증', 'DIAGNOSIS', '허벅지나 복부에 가려움이 있고 긁으면 모공이 도드라져 보이는 증상은 모공성 각화증의 특징적 소견에 부합합니다. 모공성 각화증은 모공 내 각질 플러그로 인해 피부가 거칠고 모공이 눈에 띄게 되며, 자극 시 일시적 가려움이 생길 수 있습니다. 그러나 다른 피부 질환과의 감별을 위해 피부과 전문의를 방문하여 정확한 진단을 받는 것이 권장됩니다.', 3715, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모공성 각화증', '모공성각화증', 'TREATMENT', '허벅지의 좁쌀 같은 구진과 가려움증 완화를 위해 요소(urea 10~20%), 젖산(lactic acid), 살리실산 등 각질 연화 성분이 포함된 보습 크림을 목욕 후 즉시 바르는 것이 도움이 됩니다. 뜨거운 물 목욕을 피하고 미지근한 물로 짧게 씻은 후 즉시 보습하며, 거칠게 문지르지 않는 것이 중요합니다. 증상이 지속되거나 개선이 없다면 피부과 전문의와 상담하여 레티노이드 등 전문 치료를 받으시기 바랍니다.', 3716, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모낭염', '모낭염', 'CHECKUP', '모낭염 진단은 임상적 시진으로 모공 중심의 구진과 농포를 확인하는 것이 기본이며, 확대경(더모스코피)으로 모낭 중심의 병변을 더 명확하게 관찰할 수 있습니다. 치료 저항성이거나 재발성인 경우 농포 배양 검사로 원인균(세균, 진균, 헤르페스바이러스 등)을 확인합니다. 피부과 전문의가 임상 소견과 필요 시 검사를 종합하여 진단하므로, 증상이 지속되면 피부과를 방문하시기 바랍니다.', 3717, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모낭염', '모낭염', 'DIET_LIFE', '지방이 많은 음식 섭취를 줄이면 피지 분비 조절에 도움이 될 수 있어 모낭염 예방에 간접적으로 기여합니다. 순한 약산성 세안제로 피부를 청결하게 유지하면 모공 내 세균 번식을 줄여 모낭염 예방에 효과적입니다. 다만 이러한 생활 습관 개선만으로 모낭염을 완전히 예방하기 어려울 수 있으며, 반복 발생 시 피부과 전문의 진찰을 받는 것이 권장됩니다.', 3718, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모낭염', '모낭염', 'MEDICATION', '모낭염 치료에 약물이 권장되는 이유는 원인균(주로 황색포도상구균)의 감염을 제거하여 병변 악화와 주변 피부로의 확산을 막기 위해서입니다. 국소 항생제(무피로신, 클린다마이신 연고)나 항진균제 크림이 경증에 사용되며, 광범위하거나 재발하는 경우 경구 항생제 복용이 필요합니다. 약물 부작용(피부 자극, 항생제 내성 등)이 발생할 수 있으므로 반드시 피부과 전문의 처방에 따라 적절한 약물을 선택하시기 바랍니다.', 3719, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모낭염', '모낭염', 'PREVENTION', '모낭염 예방을 위해 피부 모공 청결 유지 외에도 면도 시 자극 최소화(전동면도기 사용 또는 면도 방향 주의), 꽉 끼는 의류 착용 자제, 운동 후 즉시 샤워가 중요합니다. 면역력 강화를 위한 균형 잡힌 식사, 충분한 수면, 당뇨 등 기저 질환 관리도 예방에 도움이 됩니다. 개인 위생용품(면도기, 수건)을 타인과 공유하지 않는 것도 중요한 예방 수칙입니다.', 3720, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모낭염', '모낭염', 'EXERCISE', '두피 모낭염이나 과도한 발한으로 인한 두피 자극은 일부 탈모를 유발할 수 있으며, 강도 높은 운동 후 땀이 두피에 오래 남아 있는 경우 모낭염 위험을 높입니다. 운동 후 즉시 샴푸로 두피를 청결하게 씻어 땀과 세균을 제거하는 것이 중요합니다. 탈모와 두피 가려움이 지속된다면 과도한 운동보다는 두피 청결 관리와 함께 피부과 전문의를 방문하여 원인을 파악하시기 바랍니다.', 3721, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모낭염', '모낭염', 'CAUSE', '모낭염의 원인은 세균(황색포도상구균, 녹농균) 외에도 진균(칸디다, 말라세지아), 바이러스(헤르페스), 기생충(모낭충) 등이 있습니다. 물리적 자극(면도, 마찰, 꽉 끼는 의류), 면역 저하, 당뇨, 스테로이드 장기 사용, 고온 다습한 환경도 모낭염을 유발하는 비감염성 원인이 됩니다. 원인에 따라 치료 방법이 달라지므로 재발성이거나 치료가 잘 안 되는 경우 피부과 전문의와 정확한 원인 검사를 받으시기 바랍니다.', 3722, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모낭염', '모낭염', 'REHAB', '면역력 저하로 인한 모낭염 재활을 위해 균형 잡힌 식단(단백질, 아연, 비타민 C, D 충분 섭취), 규칙적인 중등도 유산소 운동, 충분한 수면이 면역 기능 회복에 도움이 됩니다. 스트레스 관리와 금연·절주도 면역 기능에 긍정적 영향을 줍니다. 면역 저하의 원인(당뇨, HIV 등)이 있다면 해당 질환 관리가 우선이며, 구체적인 재활 계획은 내과 또는 피부과 전문의와 상담하여 수립하시기 바랍니다.', 3723, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모낭염', '모낭염', 'DEFINITION', '얼굴과 등에 발생하는 붉은 물집(농포·구진)의 주요 원인은 모낭염으로, 황색포도상구균 등의 세균이 모낭에 감염되어 발생합니다. 모낭 중심의 붉은 구진이나 농포가 특징이며, 면도 자극, 과도한 땀, 꽉 끼는 의류, 면역 저하 등이 유발 요인이 됩니다. 여드름과 혼동될 수 있으므로, 치료에 반응이 없거나 반복 발생한다면 피부과 전문의 진찰을 받으시기 바랍니다.', 3724, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모낭염', '모낭염', 'SYMPTOM', '콧수염 부위(구순 주변)에 고름이 나타나는 것은 모낭염의 전형적인 증상 중 하나입니다. 면도 후 세균이 모낭에 침입하거나 기름진 피부, 면역 저하 등으로 황색포도상구균 등이 증식하면 모공 중심의 농포가 발생합니다. 증상이 반복되거나 광범위하게 퍼진다면 피부과 전문의를 방문하여 정확한 진단과 항생제 치료를 받으시기 바랍니다.', 3725, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모낭염', '모낭염', 'DIAGNOSIS', '모낭염이 의심될 때는 피부과를 방문하는 것이 가장 적합합니다. 피부과에서 임상 소견 확인 및 필요 시 균 배양 검사를 통해 정확한 원인을 파악하고 항생제 또는 항진균제 치료를 받을 수 있습니다. 여드름과의 감별이 필요한 경우나 반복 재발하는 경우에도 피부과 전문의 진찰을 받는 것이 권장됩니다.', 3726, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모낭염', '모낭염', 'TREATMENT', '모낭염의 붓기와 통증 치료를 위해 경증에는 국소 항생제(무피로신, 클린다마이신) 연고와 항염 효과가 있는 저농도 스테로이드 연고를 단기간 사용할 수 있습니다. 중등도 이상이거나 광범위한 경우 경구 항생제(세팔렉신, 독시사이클린 등)와 소염진통제를 병용하며, 농양이 형성된 경우에는 절개 배농이 필요할 수 있습니다. 자가 처치로 병변을 짜거나 터뜨리는 행위는 피하고, 피부과 전문의의 정확한 진단과 치료를 받으시기 바랍니다.', 3727, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '무좀', '무좀', 'CHECKUP', '발의 각질과 가려움이 동반된 경우 무좀(족부 백선), 습진, 접촉성 피부염 등의 가능성이 있습니다. 정확한 감별을 위해 피부과를 방문하여 KOH 도말 검사(진균 확인)나 피부과 전문의의 임상 진찰을 받는 것이 권장됩니다. 자가 진단으로 무좀약을 사용하면 습진이나 다른 피부 질환 악화 가능성이 있으므로 전문의 진찰 후 치료를 시작하시기 바랍니다.', 3728, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '무좀', '무좀', 'DIET_LIFE', '무좀 관리를 위한 식이 요법으로 설탕과 정제 탄수화물 섭취를 줄이면 진균 증식 억제에 간접적으로 도움이 되며, 면역력 강화를 위해 비타민 C, 아연이 풍부한 식품 섭취가 권장됩니다. 생활 면에서는 발을 항상 건조하게 유지하고, 발가락 사이를 잘 닦은 후 충분히 건조시키며, 통기성 좋은 양말과 신발을 착용하는 것이 중요합니다. 공공 샤워실이나 수영장 이용 시 슬리퍼를 착용하고, 타인과 신발·양말을 공유하지 않는 것도 필요합니다.', 3729, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '무좀', '무좀', 'MEDICATION', '무좀(족부 백선) 치료에 사용되는 국소 항진균제(테르비나핀, 클로트리마졸, 미코나졸 등)는 발 외에도 손발톱 무좀, 완선(사타구니 백선), 체부 백선 등 다른 부위의 진균 감염에도 효과가 있습니다. 다만 제형(크림, 스프레이, 로션)과 도포 방법이 부위에 따라 다를 수 있습니다. 발 이외 부위에 사용 시 피부과 전문의의 진단 후 적절한 제형과 치료 기간을 안내받아 사용하시기 바랍니다.', 3730, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '무좀', '무좀', 'PREVENTION', '무좀 예방을 위해 신발 선택 시 통기성이 좋은 천연 소재(가죽, 캔버스)의 신발을 선택하고, 발가락이 너무 좁게 압박되지 않는 여유 있는 디자인을 고르는 것이 중요합니다. 발가락 사이의 가려움 예방을 위해 땀 흡수가 잘 되는 면 소재 양말을 매일 교체하며, 같은 신발을 연속으로 신지 않고 충분히 건조시켜 사용하는 것이 도움이 됩니다. 공공 샤워실이나 수영장 이용 시에는 슬리퍼를 착용하시기 바랍니다.', 3731, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '무좀', '무좀', 'CAUSE', '무좀(족부 백선)의 원인은 피부사상균(주로 Trichophyton rubrum, T. mentagrophytes 등)의 진균 감염으로, 발가락 사이가 좁고 습한 환경에서 번식하기 쉽습니다. 꽉 끼는 신발 착용, 오랜 시간 발이 땀에 젖는 환경, 공공 시설(수영장, 목욕탕) 맨발 이용, 면역 저하 등이 감염 위험을 높이며, 진균이 각질층에 침투해 가려움·화끈거림·각질을 유발합니다. 항진균제 치료가 필요하므로 피부과 전문의를 방문하여 정확한 진단과 치료를 받으시기 바랍니다.', 3732, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '무좀', '무좀', 'DEFINITION', '무좀(족부백선)은 발톱뿐 아니라 발가락 사이와 발바닥 피부에도 흔히 발생합니다. 발가락 사이 무좀은 피부가 희게 짓무르고 갈라지거나 각질이 벗겨지는 형태로 나타나며, 심한 경우 2차 세균 감염으로 이어질 수 있습니다. 정확한 진단과 치료를 위해 피부과 전문의 상담을 권장합니다.', 3733, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '무좀', '무좀', 'SYMPTOM', '발가락 사이 가려움, 피부 짓무름, 각질 탈락 등의 증상은 족부백선(무좀)을 강하게 시사합니다. 진단은 피부과에서 피부 병변의 인설(각질)을 채취하여 KOH 직접도말검사 또는 진균 배양검사로 확인합니다. 정확한 진단 후 항진균제 치료를 받으시기 바랍니다.', 3734, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '무좀', '무좀', 'DIAGNOSIS', '발바닥 가려움증과 각질은 무좀의 대표적인 증상으로, 피부과 전문의를 찾아가시면 됩니다. 피부과에서는 KOH 검사 등을 통해 진균 감염 여부를 확인하고 적절한 항진균제를 처방합니다. 자가 진단보다는 반드시 피부과 전문의의 정확한 진단과 치료를 받으시기 바랍니다.', 3735, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '무좀', '무좀', 'TREATMENT', '무좀의 가족 간 전염을 예방하려면 수건, 발수건, 양말, 슬리퍼 등을 개인별로 구분하여 사용해야 합니다. 욕실 바닥, 욕조, 공용 발판 등은 정기적으로 소독하고, 발을 씻은 후 발가락 사이까지 완전히 건조시키는 것이 중요합니다. 통풍이 잘 되는 신발을 착용하고, 감염된 가족은 완치될 때까지 피부과 치료를 받아야 합니다.', 3736, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '봉와직염', '봉와직염', 'CHECKUP', '발 외상 후 열감, 부종, 통증이 나타나면 봉와직염을 포함한 감염성 질환의 가능성이 있으므로 즉시 진료를 받아야 합니다. 봉와직염 확인을 위해 혈액검사(CBC, CRP, ESR), 피부 병변 관찰, 필요 시 초음파 또는 MRI 검사를 시행합니다. 증상이 빠르게 악화될 수 있으므로 내과 또는 피부과 전문의의 신속한 진료를 권장합니다.', 3737, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '봉와직염', '봉와직염', 'DIET_LIFE', '회전근개 파열의 재활을 위해서는 어깨에 과도한 부담을 주는 팔을 머리 위로 드는 동작, 무거운 물건 들기, 던지기 동작 등을 피해야 합니다. 수영(자유형, 접영)이나 테니스, 배드민턴처럼 어깨를 과하게 쓰는 운동도 급성기에는 제한해야 합니다. 재활 운동 계획은 정형외과 또는 재활의학과 전문의의 지도하에 단계적으로 진행하는 것이 중요합니다.', 3738, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '봉와직염', '봉와직염', 'MEDICATION', '봉와직염으로 항생제를 복용 중 열이나 통증이 있는 경우, 아세트아미노펜(타이레놀) 또는 이부프로펜 같은 NSAIDs를 병용할 수 있으나 반드시 처방 의사와 상의해야 합니다. NSAIDs는 항생제 효과에 영향을 주지 않지만, 신장 기능이나 위장 상태에 따라 사용 제한이 있을 수 있습니다. 약물 병용은 담당 전문의의 지시에 따라 결정하시기 바랍니다.', 3739, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '봉와직염', '봉와직염', 'PREVENTION', '겨울철 봉와직염 예방을 위해 피부가 건조하고 갈라지지 않도록 보습제를 꾸준히 바르고, 외상이나 동상을 예방해야 합니다. 발이나 다리의 작은 상처도 즉시 소독하고 청결하게 관리하며, 혈액순환 장애가 있는 경우 따뜻하게 유지하는 것이 중요합니다. 당뇨병, 하지정맥류, 면역저하 환자는 전문의와의 정기적 상담을 통해 예방적 관리를 받으시기 바랍니다.', 3740, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '봉와직염', '봉와직염', 'CAUSE', '다리에 발생하는 봉와직염의 주요 원인으로는 피부 균열, 찰과상, 곤충 자상, 발톱 주변 상처, 무좀에 의한 피부 손상 등을 통한 세균(주로 연쇄상구균, 황색포도상구균) 침입이 있습니다. 하지정맥류, 림프부종, 당뇨병에 의한 혈액순환 장애도 발병 위험을 높이는 중요한 요인입니다. 증상이 의심되면 신속히 내과 또는 피부과 전문의의 진료를 받으시기 바랍니다.', 3741, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '봉와직염', '봉와직염', 'DEFINITION', '봉와직염은 주로 연쇄상구균(Streptococcus)과 황색포도상구균(Staphylococcus aureus) 등의 세균이 피부의 미세한 상처나 균열을 통해 피부 깊숙이 침입하여 발생하는 급성 세균성 피부 연조직 감염입니다. 치료가 지연되면 괴사성 근막염, 패혈증, 화농 관절염, 골수염 등 심각한 합병증으로 진행할 수 있으므로 즉각적인 전문의 진료와 항생제 치료가 필요합니다.', 3742, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '봉와직염', '봉와직염', 'SYMPTOM', '봉와직염의 주요 증상으로 국소적 발적(홍반), 부종, 열감, 통증이 나타나는 것은 사실입니다. 이는 세균 감염에 대한 염증 반응으로, 증상이 빠르게 확산될 수 있으며 발열 등 전신 증상이 동반되기도 합니다. 이러한 증상이 나타나면 내과 또는 피부과 전문의에게 즉시 진료를 받으시기 바랍니다.', 3743, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '봉와직염', '봉와직염', 'DIAGNOSIS', '봉와직염의 전형적인 증상은 피부의 국소적 발적, 부종, 열감, 통증이며, 특정 부위에 국한된 홍반입니다. 피부, 손톱, 입술, 손끝, 발뒤꿈치에 붉은 반점이 산재하는 양상은 봉와직염보다 혈관 질환이나 다른 피부 질환의 가능성을 고려해야 합니다. 정확한 진단을 위해 피부과 또는 내과 전문의의 진찰이 필요합니다.', 3744, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '봉와직염', '봉와직염', 'TREATMENT', '봉와직염의 비수술적 치료로는 항생제(경구 또는 정맥주사) 투여가 핵심이며, 환부 거상(다리를 높이 올리기), 안정, 냉찜질 등으로 부종과 통증을 완화합니다. 경미한 경우 경구 항생제로 치료가 가능하나, 증상이 심하거나 전신 증상이 있으면 입원 정맥 항생제 치료가 필요합니다. 치료 방법은 반드시 내과 또는 피부과 전문의의 판단에 따라야 합니다.', 3745, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '비듬', '비듬', 'DIET_LIFE', '비듬 예방에는 비타민 B군 외에도 아연(zinc)이 중요한 역할을 하며, 비듬 전용 샴푸에도 아연 피리치온이 성분으로 포함됩니다. 오메가-3 지방산은 두피 염증을 줄이는 데 도움이 되며, 비타민 D 결핍도 지루성 피부염과 관련이 있다고 알려져 있습니다. 심한 비듬이나 두피 질환은 피부과 전문의의 정확한 진단을 받으시기 바랍니다.', 3746, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '비듬', '비듬', 'MEDICATION', '비듬과 두피 가려움을 동반한 지루성 피부염에는 항진균 성분이 포함된 샴푸(케토코나졸, 아연 피리치온, 셀레늄 설파이드 성분)가 효과적으로 사용됩니다. 염증이 심한 경우 약한 스테로이드 성분의 두피용 로션이나 국소 칼시뉴린 억제제를 처방받을 수 있습니다. 적절한 약물 선택을 위해 피부과 전문의의 진료를 받으시기 바랍니다.', 3747, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '비듬', '비듬', 'CAUSE', '두피 가려움과 비듬의 주요 원인은 말라세지아(Malassezia) 진균의 과증식으로, 이 균이 두피 피지를 분해하며 염증을 유발합니다. 샴푸를 너무 자주 또는 너무 드물게 사용하거나, 잔여물이 남을 경우 두피 자극으로 비듬이 악화될 수 있습니다. 스트레스, 호르몬 변화, 면역력 저하도 원인이 될 수 있으며, 지속되는 경우 피부과 전문의의 진료를 권장합니다.', 3748, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '비듬', '비듬', 'DEFINITION', '비듬은 두피의 피부 세포가 과도하게 빠르게 탈락하면서 흰 조각 형태로 나타나는 상태로, 주로 말라세지아 진균, 피지 과다 분비, 피부 건조 등이 원인입니다. 두피 가려움증, 각질 탈락, 붉은 발진 등의 증상이 동반될 수 있으며, 지루성 피부염의 일부로 나타나기도 합니다. 비듬이 심하거나 반복될 경우 피부과 전문의의 진료를 받으시기 바랍니다.', 3749, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '비듬', '비듬', 'SYMPTOM', '심한 비듬과 두피 가려움증이 지속되면 긁는 행위로 인한 피부 손상, 2차 세균 감염, 모낭염 등이 발생할 수 있습니다. 만성화되면 지루성 피부염으로 진행하거나, 드물게 탈모를 유발하기도 합니다. 증상이 악화되거나 오래 지속될 경우 피부과 전문의에게 정확한 진단과 치료를 받으시기 바랍니다.', 3750, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '비듬', '비듬', 'DIAGNOSIS', '지루성 피부염 진단에서 두피와 겨드랑이의 홍반, 유분기 있는 노란 인설(비듬 유사 각질)은 매우 중요한 진단 기준입니다. 이러한 증상은 특히 피지 분비가 많은 부위(두피, 얼굴, 가슴 중앙, 겨드랑이)에 나타나는 지루성 피부염의 특징으로, 임상적으로 진단하는 데 핵심적 역할을 합니다. 정확한 진단을 위해 피부과 전문의의 진찰을 받으시기 바랍니다.', 3751, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '비듬', '비듬', 'TREATMENT', '비듬의 주요 원인은 말라세지아 진균 과증식, 피지 과분비, 피부 장벽 이상 등입니다. 치료는 케토코나졸, 아연 피리치온, 셀레늄 설파이드 등 항진균 성분 샴푸를 주 2~3회 사용하는 것이 효과적이며, 심한 경우 스테로이드 두피 용액이 처방되기도 합니다. 증상이 지속되거나 심할 경우 피부과 전문의의 진료를 받으시기 바랍니다.', 3752, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '사마귀', '사마귀', 'MEDICATION', '사마귀 치료 약물은 주로 면역 반응을 유도하거나 감염된 세포를 직접 파괴하는 방식으로 작용합니다. 살리실산 제제는 각질을 용해시켜 바이러스 감염 세포를 제거하며, 이미퀴모드는 면역 반응을 활성화해 HPV 바이러스를 억제합니다. 약물 선택과 사용법은 피부과 전문의의 처방에 따라야 하며, 자가 치료는 권장되지 않습니다.', 3753, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '사마귀', '사마귀', 'PREVENTION', '사마귀를 예방하려면 피부의 미세한 상처나 긁힘을 통한 HPV 바이러스 침입을 차단하는 것이 중요합니다. 공공 수영장, 목욕탕 등 습한 장소에서는 맨발을 피하고, 다른 사람의 사마귀와 직접 접촉을 삼가야 합니다. 또한 면역력을 유지하는 것이 중요하므로 균형 잡힌 식사와 규칙적인 운동을 통해 전반적인 건강을 관리하시기 바랍니다.', 3754, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '사마귀', '사마귀', 'CAUSE', '발바닥 사마귀(족저 사마귀)는 HPV(인유두종바이러스) 감염으로 발생하며, 치료로는 냉동치료(액체질소), 살리실산 도포, 레이저 치료, 전기소작술 등이 사용됩니다. 발바닥은 압력을 받는 부위라 사마귀가 안쪽으로 파고들어 통증이 심할 수 있어 조기 치료가 중요합니다. 정확한 치료 방법은 피부과 전문의와 상담 후 결정하시기 바랍니다.', 3755, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '사마귀', '사마귀', 'DEFINITION', '사마귀는 인유두종바이러스(HPV) 감염에 의해 피부 세포가 과증식하여 피부 표면이 오돌토돌하게 솟아오르는 양성 병변입니다. 발생 부위에 따라 보통 사마귀, 족저 사마귀, 편평 사마귀, 성기 사마귀 등으로 구분되며, 피부 접촉이나 상처를 통해 전파됩니다. 치료 및 정확한 진단을 위해 피부과 전문의의 진료를 받으시기 바랍니다.', 3756, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '사마귀', '사마귀', 'SYMPTOM', '사마귀의 주요 증상은 피부 표면의 과각화된 돌출 병변이며, 부위에 따라 통증이 있을 수 있습니다. 족저 사마귀는 걸을 때 압박으로 인한 통증이 심하고, 편평 사마귀는 얼굴에 여러 개가 군집하여 나타납니다. 사마귀로 인한 심리적 스트레스나 대인 기피 증상이 동반될 수 있으며, 이 경우 적극적인 피부과 치료를 받으시기 바랍니다.', 3757, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '사마귀', '사마귀', 'DIAGNOSIS', '사마귀가 의심되면 피부과를 방문하면 됩니다. 진단은 주로 육안 관찰로 이루어지며, 필요 시 확대경 검사(더모스코피)나 조직 생검을 통해 다른 피부 병변과 구별합니다. 발바닥의 경우 굳은살(胼胝), 티눈과의 감별이 필요하므로 반드시 피부과 전문의의 정확한 진단을 받으시기 바랍니다.', 3758, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '사마귀', '사마귀', 'TREATMENT', '냉동치료는 액체질소(-196°C)를 병변에 분사하거나 접촉시켜 세포 내 얼음 결정을 형성하고, 바이러스에 감염된 사마귀 세포를 파괴하는 원리를 이용합니다. 치료 후 수포가 형성되고 괴사 조직이 탈락하면서 사마귀가 제거되며, 보통 수 주 간격으로 여러 차례 시술이 필요합니다. 냉동치료는 피부과에서 시행하며, 치료 후 관리 방법은 담당 의사의 지시에 따르시기 바랍니다.', 3759, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '사면발이증', '사면발이증', 'CAUSE', '사면발이증의 발병 위험을 높이는 주요 원인은 감염된 사람과의 성접촉이 가장 흔하며, 성 파트너 수가 많을수록 위험이 증가합니다. 감염된 사람의 침구, 수건, 속옷 등을 공유하는 경우에도 전파될 수 있으나, 성접촉이 주된 경로입니다. 사면발이증이 의심되면 피부과 또는 비뇨기과 전문의의 진료를 받으시기 바랍니다.', 3760, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '사면발이증', '사면발이증', 'DEFINITION', '사면발이증(Pediculosis pubis)은 주로 음모 부위에 기생하는 사면발이(Pthirus pubis)에 의한 감염으로, 성접촉을 통해 전파됩니다. 감염 여부는 음모 부위의 강한 가려움증, 긁힌 자국, 속옷에 작은 점(배설물) 등의 증상과 함께 확대경으로 이(성충) 또는 서캐(알)를 직접 확인하거나 피부과 전문의의 진찰로 진단할 수 있습니다.', 3761, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '사면발이증', '사면발이증', 'SYMPTOM', '사면발이증의 주요 증상은 음모 부위의 심한 가려움증으로, 특히 밤에 더욱 심해지는 경향이 있습니다. 긁힘으로 인한 피부 자극, 작은 붉은 반점, 색소 침착(청회색 반점)이 나타날 수 있으며, 시간이 갈수록 증상이 심해지는 양상은 사면발이증의 전형적인 경과입니다. 사면발이증이 의심되면 피부과 또는 비뇨기과 전문의의 진료를 권장합니다.', 3762, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '사면발이증', '사면발이증', 'DIAGNOSIS', '사면발이증이 의심될 경우 피부과 전문의에게 진료를 받는 것이 가장 적합합니다. 여성의 경우 산부인과에서도 진단이 가능하며, 병변 부위 직접 관찰로 사면발이나 서캐를 확인합니다. 성접촉으로 전파되므로 다른 성병 동반 여부 검사도 함께 받으시기 바랍니다.', 3763, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '사면발이증', '사면발이증', 'TREATMENT', '사면발이증 치료의 기본은 퍼메트린 크림이나 말라치온 로션 같은 항기생충 약물을 감염 부위에 도포하는 것으로, 제모 없이도 치료가 가능합니다. 치료 후 침구, 속옷, 수건은 반드시 뜨거운 물로 세탁하고, 성 파트너도 함께 치료를 받아야 재감염을 예방할 수 있습니다. 치료 방법과 용법은 피부과 전문의의 처방에 따라 진행하시기 바랍니다.', 3764, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '섬유종', '섬유종', 'CAUSE', '섬유종의 발생 원인은 완전히 밝혀지지 않았으나, 유전적 요인, 호르몬 영향(에스트로겐), 만성적인 물리적 자극 등이 관여하는 것으로 알려져 있습니다. 구강 섬유종의 경우 치아 교합 시 자극, 틀니나 교정 장치에 의한 만성 자극이 원인이 되기도 합니다. 섬유종이 의심되면 관련 전문의(피부과, 구강외과 등)의 정확한 진단을 받으시기 바랍니다.', 3765, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '섬유종', '섬유종', 'DEFINITION', '신경 섬유종 악성형은 말초 신경초에서 발생하는 악성 종양으로 ''악성 말초신경초종양(MPNST)''으로 분류됩니다. 비악성(양성) 신경 섬유종은 신경 섬유아세포에서 발생하는 양성 종양으로, 단순 절제로 치료가 가능한 경우가 많습니다. 악성 여부는 조직 생검 등 정밀 검사를 통해 확인되므로, 증상이 있으면 신경외과 또는 종양내과 전문의의 진료를 받으시기 바랍니다.', 3766, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '섬유종', '섬유종', 'SYMPTOM', '섬유종은 발생 부위에 따라 증상이 다르며, 단발성 또는 다발성 종괴로 나타납니다. 표재성 섬유종은 피부 아래 단단하고 움직이지 않는 결절로 촉지되며, 크기가 커지면 압박으로 인한 통증, 해당 부위의 기능 제한 등이 발생할 수 있습니다. 섬유종이 의심되는 종괴가 발견되면 피부과, 외과, 또는 관련 전문의의 진찰을 받으시기 바랍니다.', 3767, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '섬유종', '섬유종', 'DIAGNOSIS', '섬유종 진단을 위해 초음파 검사로 종괴의 크기, 위치, 내부 구조를 평가하며, 필요 시 MRI 검사로 주변 조직과의 관계를 확인합니다. 최종 진단은 조직 생검(절제 또는 침 생검)을 통한 병리 조직 검사로 확정하며, 악성 여부도 함께 판별할 수 있습니다. 정확한 진단을 위해 외과 또는 관련 전문의의 진료를 받으시기 바랍니다.', 3768, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '섬유종', '섬유종', 'TREATMENT', '구강 내 반복적인 자극(치아 물기 습관 등)으로 생긴 섬유종은 자극 원인을 제거한 후에도 소실되지 않는 경우 외과적 절제가 표준 치료입니다. 약물로 섬유종 자체를 제거하는 확립된 치료법은 없으며, 자연 요법도 효과가 검증되지 않았습니다. 습관 교정과 함께 구강외과 또는 치과 전문의와 상담하여 적절한 치료 방법을 결정하시기 바랍니다.', 3769, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '소양증', '소양증', 'CAUSE', '스트레스와 공포, 불안 등의 정신적 긴장은 자율신경계를 자극하여 히스타민 분비를 증가시키고 피부 혈관의 투과성을 높여 소양증(가려움증)을 유발하거나 악화시킵니다. 또한 스트레스 호르몬인 코르티솔이 피부 면역 반응에 영향을 미쳐 피부 장벽 기능을 저하시킬 수 있습니다. 심인성 소양증이 의심되면 피부과 및 정신건강의학과 전문의의 협진 진료를 권장합니다.', 3770, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '소양증', '소양증', 'DEFINITION', '임신성 피부 소양증은 임신 중 호르몬 변화(에스트로겐, 프로게스테론 증가)와 피부 건조, 면역 변화 등으로 인해 발생하는 피부 가려움 상태입니다. 주로 배, 허벅지, 가슴 등 피부가 늘어나는 부위에서 가려움증이 나타나며, 담즙 울체에 의한 간내 임신 담즙울체증이 원인인 경우 황달이 동반될 수 있습니다. 임신 중 가려움증이 심하면 산부인과 또는 피부과 전문의의 진료를 받으시기 바랍니다.', 3771, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '소양증', '소양증', 'DIAGNOSIS', '밤에 가려움이 심해지는 야간 소양증은 피부과 전문의를 찾아가시면 됩니다. 밤에 악화되는 가려움증은 피부건조증, 아토피, 옴, 두드러기 등 다양한 원인으로 발생할 수 있어 정확한 원인 파악이 중요합니다. 피부과에서 원인 질환을 진단받고 그에 맞는 치료를 받으시기 바랍니다.', 3772, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '소양증', '소양증', 'TREATMENT', '가을·겨울철 소양증 완화에는 미지근한 물로 짧게 목욕하고 보습제를 충분히 바르는 것이 기본입니다. 실내 습도를 40~60%로 유지하고, 자극적인 비누나 세제 사용을 줄이며, 면 소재 속옷 착용이 도움이 됩니다. 증상이 지속되거나 심할 경우 자연요법만으로는 한계가 있으므로 피부과 전문의의 진료를 통해 적절한 치료를 받으시기 바랍니다.', 3773, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '습진', '습진', 'DIET_LIFE', '습진이 있는 경우 자극적인 음식(매운 음식, 알코올), 알레르기 유발 식품(견과류, 해산물 등)을 파악하여 제한하고, 충분한 수분 섭취가 도움이 됩니다. 생활 습관으로는 비누와 세제를 저자극성으로 교체하고, 목욕 후 즉시 보습제를 바르며, 긁는 습관을 피하고 피부 자극을 최소화해야 합니다. 증상이 지속되거나 악화될 경우 피부과 전문의의 진료를 받으시기 바랍니다.', 3774, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '습진', '습진', 'MEDICATION', '습진은 피부의 염증 반응으로 인해 가려움증, 발적(붉어짐), 건조함, 각질, 수포, 삼출물 등 다양한 증상을 나타내는 피부 질환의 총칭입니다. 급성기에는 수포와 삼출물, 만성기에는 피부 두꺼워짐과 색소 침착이 나타납니다. 습진의 원인과 종류가 다양하므로 피부과 전문의의 진단에 따라 스테로이드 연고 등 적절한 약물 치료를 받으시기 바랍니다.', 3775, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '습진', '습진', 'PREVENTION', '습진 예방을 위한 피부 관리의 핵심은 보습입니다. 목욕 후 3분 이내에 보습제를 충분히 발라 피부 수분 증발을 막아야 하며, 하루 1~2회 규칙적인 보습이 피부 장벽 기능 회복과 자극 물질 침입 차단에 도움이 됩니다. 무향 저자극 보습제를 사용하고, 자극적인 세제나 화학물질 접촉을 피하는 것도 중요하며, 증상이 있으면 피부과 전문의의 진료를 받으시기 바랍니다.', 3776, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '습진', '습진', 'CAUSE', '습진의 발생에는 필라그린 유전자 변이가 중요한 역할을 합니다. 환경적 요인으로는 집먼지진드기, 꽃가루, 화학물질, 저온·건조한 환경이 피부 장벽을 손상시키고 면역 반응을 과도하게 유발합니다. 유발 요인을 파악하고 관리하기 위해 피부과 전문의의 진료를 받으시기 바랍니다.', 3777, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '습진', '습진', 'DEFINITION', '고무장갑 없이 장시간 물이나 세제에 노출된 후 손 피부가 벗겨지고 갈라지는 증상은 주부습진의 전형적인 증상일 수 있습니다. 정확한 진단을 위해 피부과를 방문하여 첩포 검사를 통해 알레르기성 접촉 피부염과의 감별이 필요합니다. 조기에 진료를 받아 적절한 치료를 시작하시기 바랍니다.', 3778, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '습진', '습진', 'SYMPTOM', '밴드 부착 후 해당 부위가 붉어지고 가렵고 붓는 증상은 밴드의 접착 성분에 의한 알레르기성 또는 자극성 접촉 피부염에 해당할 수 있습니다. 같은 부위가 반복적으로 악화된다면 첩포 검사를 통해 유발 물질을 확인할 수 있습니다. 피부과 전문의를 방문하여 정확한 진단과 치료를 받으시기 바랍니다.', 3779, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '습진', '습진', 'DIAGNOSIS', '물에 반복적으로 노출되어 피부염이 발생했다면 자극성 접촉 피부염의 가능성이 높습니다. 피부과에서 병변의 형태와 위치, 발생 경위를 평가하여 습진 여부를 진단하며, 첩포 검사로 알레르기 원인 물질도 확인할 수 있습니다. 진단 확인 전까지는 보습제를 자주 바르고 물 접촉 시 고무장갑을 착용하시기 바랍니다.', 3780, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '습진', '습진', 'TREATMENT', '약물 치료 외에 습진 관리에는 하루 2회 이상 저자극성 보습제를 충분히 바르는 것이 가장 중요합니다. 목욕은 미지근한 물로 짧게 하고 목욕 후 3분 이내에 보습제를 바르는 것이 효과적입니다. 가려움증이 심할 때는 냉찜질이 도움이 되며, 피부과 전문의와 함께 관리 계획을 세우시기 바랍니다.', 3781, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '아토피성 피부염', '아토피성피부염', 'DIET_LIFE', '음식 알레르기가 있는 아토피성 피부염 아이에게 식이요법이 도움이 될 수 있으나, 원인 식품이 확인되지 않은 상태에서 무분별한 식이 제한은 영양 불균형을 초래할 수 있습니다. 음식 알레르기 검사 후 소아청소년과 알레르기 전문의 및 영양사의 지도하에 식이 조절을 하는 것이 권고됩니다.', 3782, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '아토피성 피부염', '아토피성피부염', 'MEDICATION', '아토피성 피부염에서 중등도 이상의 경우 국소 스테로이드 크림이 가장 효과적인 치료제이며, 칼시뉴린 억제제를 얼굴이나 피부 주름 부위에 대안으로 사용합니다. 중증 아토피에는 듀필루맙 등 생물학적 제제와 JAK 억제제도 사용되므로, 피부과 전문의와 상담하여 적합한 치료제를 선택하시기 바랍니다.', 3783, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '아토피성 피부염', '아토피성피부염', 'PREVENTION', '유익균(프로바이오틱스) 섭취는 장내 미생물 환경을 개선하고 면역 조절에 도움을 주어 아토피성 피부염 증상 완화에 일부 효과가 있다는 연구들이 있습니다. 보조 요법으로 고려할 수 있으나 단독 치료로는 한계가 있으므로, 피부과 전문의와 상담하여 기존 치료와 병행 여부를 결정하시기 바랍니다.', 3784, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '아토피성 피부염', '아토피성피부염', 'CAUSE', '아토피성 피부염 환자에서 농피증과 외이염은 아토피로 인해 손상된 피부 장벽과 면역 이상으로 인해 발생하는 흔한 합병증입니다. 황색포도상구균은 아토피 피부에 정착하여 독소를 분비하고 염증 반응을 악화시키는 주요 인자입니다. 피부과 전문의의 정확한 진단과 치료가 아토피 관리에 중요합니다.', 3785, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '아토피성 피부염', '아토피성피부염', 'DEFINITION', '아토피성 피부염은 만성 재발성 피부 질환으로, 피부 장벽 기능 이상과 과도한 면역 반응이 특징입니다. 영아 아토피성 피부염은 주로 뺨, 이마, 팔다리 바깥쪽에 건조하고 붉은 발진이 나타납니다. 소아청소년과 또는 피부과 전문의를 방문하여 정확한 진단과 치료를 받으시기 바랍니다.', 3786, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '아토피성 피부염', '아토피성피부염', 'SYMPTOM', '팔꿈치 안쪽을 자주 긁는 증상은 아토피성 피부염의 전형적인 발생 부위 중 하나입니다. 아토피는 팔꿈치 안쪽, 무릎 뒤쪽에 주로 발생하며, 만성화되면 피부가 두꺼워지는 태선화 소견도 나타납니다. 피부과 전문의를 방문하여 진단 기준에 따라 평가를 받으시기 바랍니다.', 3787, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '아토피성 피부염', '아토피성피부염', 'DIAGNOSIS', '피부 가려움, 뾰루지, 발진 증상은 아토피성 피부염을 포함하여 두드러기, 건선, 접촉 피부염 등 다양한 피부 질환과 연관될 수 있습니다. 피부과 진료과를 방문하는 것이 가장 적합하며, 알레르기 원인 검사가 필요한 경우 알레르기내과를 병행 방문할 수 있습니다. 증상이 반복되거나 광범위하게 나타난다면 피부과 전문의에게 정확한 진단을 받으시기 바랍니다.', 3788, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '아토피성 피부염', '아토피성피부염', 'TREATMENT', '아토피성 피부염의 병원 치료법으로는 국소 스테로이드제, 국소 칼시뉴린 억제제, 생물학적 제제 두필루맙, 항히스타민제 등이 있습니다. 증상의 중증도에 따라 치료 방법이 달라지므로 반드시 피부과 전문의의 진료를 받으시기 바랍니다.', 3789, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '안면 홍조증', '안면홍조증', 'MEDICATION', '안면 홍조증에서 양방 약물 외 대안으로는 레이저·광선치료(IPL), 피부 관리(저자극 세안, 보습), 유발 요인 회피(음주·매운 음식·극단적 온도·스트레스 절제), 한방 치료 등을 고려할 수 있습니다. 개인의 피부 상태와 홍조 원인에 따라 적합한 방법이 다르므로 피부과 전문의와 상담 후 결정하시기 바랍니다.', 3790, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '안면 홍조증', '안면홍조증', 'PREVENTION', '안면 홍조증의 레이저 치료로는 혈관을 선택적으로 파괴하는 PDL과 IPL이 효과적이며, 붉은 혈관을 줄이고 피부 톤을 개선하는 데 도움을 줍니다. 치료 후에도 자외선 차단제 사용과 유발 요인 회피가 중요하며, 본인에게 적합한 치료법은 피부과 전문의 상담을 통해 결정하시기 바랍니다.', 3791, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '안면 홍조증', '안면홍조증', 'CAUSE', '안면 홍조증의 주된 기전은 안면 혈관의 과도한 확장 반응이며, 주사(rosacea), 폐경기 호르몬 변화, 자율신경계 이상, 특정 약물, 감정적 자극 등 다양한 원인이 복합적으로 작용합니다. 정확한 원인 파악을 위해 피부과 전문의의 진찰을 받으시기 바랍니다.', 3792, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '안면 홍조증', '안면홍조증', 'DEFINITION', '얼굴 열감과 볼의 심한 홍조는 안면 홍조증의 대표적 증상일 수 있으며, 확인을 위해 피부과 전문의를 방문하여 시진 및 피부경 검사 등을 받을 수 있습니다. 필요에 따라 혈액검사를 통해 내분비 질환 여부도 감별합니다. 증상이 지속된다면 피부과 전문의의 정확한 진단을 받으시기 바랍니다.', 3793, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '안면 홍조증', '안면홍조증', 'SYMPTOM', '안면 홍조증은 주로 뺨·코·이마·턱 등 얼굴 중심부에 홍조와 열감이 나타나며, 심한 경우 목·가슴·등 상부까지 붉어질 수 있습니다. 동반 증상으로 작열감, 따가움, 혈관 확장, 구진, 농포 등이 나타날 수 있습니다. 피부과 전문의와 상담하시기 바랍니다.', 3794, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '안면 홍조증', '안면홍조증', 'DIAGNOSIS', '안면 홍조증 진단은 피부과 전문의가 가장 적합하며, 건강보험심사평가원 홈페이지(심평원 병원 찾기)를 활용하면 가까운 피부과를 찾을 수 있습니다. 증상에 따라 내분비내과나 산부인과 협진이 필요할 수도 있으므로 피부과 초진 후 안내를 따르시기 바랍니다.', 3795, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '안면 홍조증', '안면홍조증', 'TREATMENT', '에스트로겐 보충 요법은 폐경기 여성에서 호르몬 감소로 유발되는 안면 홍조를 완화하는 데 효과적입니다. 다만 혈전, 유방암 등의 부작용 위험이 있으므로 산부인과 또는 내분비내과 전문의와 상담 후 본인에게 적합한지 판단하시기 바랍니다.', 3796, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '안면홍조', '안면홍조', 'DIET_LIFE', '안면홍조 완화에 도움이 되는 생활습관으로는 음주·매운 음식·카페인 등 혈관 확장 유발 음식 피하기, 극단적인 온도 변화 노출 최소화, 자외선 차단제 사용, 스트레스 관리, 저자극 세안제와 보습제 사용 등이 있습니다. 증상이 지속되거나 심해지면 피부과 전문의의 진료를 받으시기 바랍니다.', 3797, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '안면홍조', '안면홍조', 'CAUSE', '안면홍조의 원인은 폐경기 호르몬 변화, 주사(rosacea) 피부염, 자율신경계 이상, 음주·매운 음식 등 혈관 확장 유발 요인, 갑상선 기능 이상, 스트레스 등 매우 다양합니다. 지속적인 증상이 있다면 피부과 전문의를 방문해 정확한 원인을 파악하시기 바랍니다.', 3798, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '안면홍조', '안면홍조', 'DEFINITION', '안면홍조증이란 얼굴 피부 혈관이 다양한 자극에 과도하게 반응하여 일시적 또는 반복적으로 얼굴이 붉어지고 열감이 느껴지는 상태를 말합니다. 음주, 온도 변화, 스트레스, 폐경기 호르몬 변화 등 여러 원인에 의해 발생합니다. 증상이 반복되거나 일상에 불편을 준다면 피부과 전문의의 진료를 권고합니다.', 3799, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '안면홍조', '안면홍조', 'SYMPTOM', '안면홍조의 주요 증상은 얼굴 중심부가 일시적 또는 지속적으로 붉어지는 것이며, 열감, 따끔거림, 작열감이 동반될 수 있습니다. 반복될 경우 실핏줄이 눈에 띄게 되고, 주사로 진행 시 구진과 농포가 생길 수 있습니다. 증상이 잦거나 심해지면 피부과 전문의 진료를 받으시기 바랍니다.', 3800, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '안면홍조', '안면홍조', 'DIAGNOSIS', '안면홍조는 주로 피부과에서 시진과 피부경 검사로 진단하며, 필요 시 혈액검사로 내분비 질환이나 카르시노이드 종양 등을 감별합니다. 정확한 진단을 위해 피부과 전문의 방문을 권고합니다.', 3801, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '안면홍조', '안면홍조', 'TREATMENT', '안면홍조는 원인에 따라 혈관 레이저나 IPL로 확장된 혈관을 치료하고, 주사가 원인이면 국소 항생제·경구 약물을 사용합니다. 폐경기 홍조에는 호르몬 요법이나 특정 항우울제가 효과적이며, 유발 요인 회피와 생활습관 개선도 중요합니다. 피부과 전문의 상담을 권고합니다.', 3802, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '약물 발진', '약물발진', 'CAUSE', '약물 발진의 원인을 확인하는 알레르기 검사는 피부과 또는 알레르기내과에서 받을 수 있습니다. 피부 단자 검사, 첩포 검사, 약물 유발 검사 등을 시행합니다. 약물 알레르기가 의심된다면 즉시 전문의 진료를 받으시기 바랍니다.', 3803, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '약물 발진', '약물발진', 'DEFINITION', '약물 발진은 특정 약물에 대한 면역 반응으로 피부에 다양한 형태의 발진이 나타나는 것입니다. 발진의 형태는 두드러기·반구진성 발진·수포 등 다양하며, 의심 약물 복용 즉시 중단하고 전문의 진료를 받으시기 바랍니다.', 3804, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '약물 발진', '약물발진', 'SYMPTOM', '항생제 복용 후 발진은 약물 발진의 대표적인 예로, 주로 몸통과 사지에 붉은 반점이 나타납니다. 스티븐스-존슨 증후군 같은 중증 반응으로 진행될 수 있어 주의가 필요합니다. 발진 발생 시 즉시 해당 약물 복용을 중단하고 피부과 또는 응급실을 방문하시기 바랍니다.', 3805, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '약물 발진', '약물발진', 'DIAGNOSIS', '약물 발진은 대부분 원인 약물 중단 후 수일에서 수주 내에 호전됩니다. 진단은 복용 약물 목록 확인, 발진 발생 시점과의 연관성 분석, 피부 생검, 첩포 검사 등을 통해 이루어집니다. 약물 발진이 의심되면 피부과 또는 알레르기내과 전문의를 방문하시기 바랍니다.', 3806, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '약물 발진', '약물발진', 'TREATMENT', '약물 발진의 주요 치료법은 원인 약물 즉시 중단, 항히스타민제, 국소 또는 전신 스테로이드 투여입니다. 중증 반응에는 입원 집중 치료가 필요합니다. 약물 발진이 의심될 경우 피부과 전문의의 진료를 받으시기 바랍니다.', 3807, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '여드름', '여드름', 'CHECKUP', '성인이 되어서도 지속되는 여드름은 자연 소실을 기대하기 어려우며 흉터나 색소침착으로 이어질 수 있어 피부과 치료를 받는 것이 바람직합니다. 피부과에서는 개인 피부 상태에 따라 국소 레티노이드, 항생제 연고, 경구 항생제 또는 이소트레티노인 등 맞춤 치료를 제공합니다.', 3808, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '여드름', '여드름', 'DIET_LIFE', '여드름 예방을 위한 식이요법으로는 혈당 지수가 높은 식품을 줄이고 통곡물·채소·과일을 늘리는 것이 권장됩니다. 식이요법 단독으로 완치는 어려우므로 효과가 없다면 피부과 전문의의 진료를 받으시기 바랍니다.', 3809, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '여드름', '여드름', 'MEDICATION', '여드름을 방치하면 결절·낭종이 형성되고, 이후 함몰 흉터·비후성 흉터·색소침착이 생길 수 있습니다. 약물 치료는 염증을 빠르게 가라앉히고 흉터 형성을 예방하는 데 효과적입니다. 이미 염증이 심하거나 흉터가 생겼다면 피부과 전문의와 조기 상담을 권고합니다.', 3810, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '여드름', '여드름', 'PREVENTION', '음주는 피부 혈관을 확장시키고 면역 기능을 떨어뜨려 여드름 악화에 영향을 줄 수 있습니다. 피부암 예방을 위해서는 자외선 차단제 사용과 정기적인 피부과 검진을 권고합니다.', 3811, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '여드름', '여드름', 'EXERCISE', '운동 중 과도한 땀은 모공을 막고 피부 표면의 세균 증식을 촉진하여 여드름을 악화시킬 수 있습니다. 운동 후 즉시 순한 세안제로 세안하고, 통기성 좋은 소재를 입으며, 얼굴을 손으로 만지지 않는 것이 중요합니다. 증상이 지속되면 피부과 전문의와 상담하시기 바랍니다.', 3812, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '여드름', '여드름', 'CAUSE', '가족력은 여드름 발생에 중요한 유전적 요인으로 작용하며, 부모가 심한 여드름이 있었다면 자녀도 유사한 패턴의 여드름이 발생할 가능성이 높습니다. 유전적 소인이 있더라도 올바른 스킨케어와 피부과 치료를 통해 증상 관리가 가능합니다.', 3813, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '여드름', '여드름', 'REHAB', '여드름 피부 재활 프로그램은 활성 여드름 치료 후 남은 흉터·색소침착·피부 장벽 손상을 회복시키는 데 중점을 둡니다. 레이저 치료, 피부 장벽 강화를 위한 보습 관리, 색소침착 완화를 위한 미백 성분 사용, 자외선 차단 등이 포함됩니다. 재활 치료 방법은 피부과 전문의와 상담하시기 바랍니다.', 3814, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '여드름', '여드름', 'DEFINITION', '두드러기는 피부 표피층의 각질 탈락과 가려움이 주 증상인 반면, 여드름은 모낭과 피지선에 피지가 막혀 세균 감염으로 염증성 구진·농포·결절이 형성되는 만성 피부 질환입니다. 증상 감별이 어렵다면 피부과 전문의의 진단을 받으시기 바랍니다.', 3815, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '여드름', '여드름', 'SYMPTOM', '여드름은 사춘기에 가장 흔하게 발생하며, 많은 경우 20대 후반~30대에 점차 줄어드는 경향이 있습니다. 그러나 30대 이후에도 호르몬 불균형, 스트레스, 화장품 등의 원인으로 성인 여드름이 발생할 수 있습니다. 나이와 관계없이 여드름이 지속된다면 피부과 전문의의 진료를 권고합니다.', 3816, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '여드름', '여드름', 'DIAGNOSIS', '사춘기 여드름은 안드로겐 호르몬 증가로 피지선이 활성화되어 피지가 과다 분비되고, 모낭 입구가 각화되어 막히면서 여드름균이 증식해 염증이 발생하는 모낭 피지선 질환입니다. 적절한 치료 없이 방치 시 흉터가 남을 수 있어 피부과 전문의 진료를 받으시기 바랍니다.', 3817, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '여드름', '여드름', 'TREATMENT', '40대 여드름은 호르몬 변화, 스트레스, 화장품 성분, 내분비 질환 등이 원인일 수 있어 청소년 여드름과 다른 접근이 필요합니다. 성인 여드름은 원인 파악이 중요하므로 피부과 전문의를 방문해 개인 맞춤 치료를 받으시기 바랍니다.', 3818, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '옴', '옴', 'CHECKUP', '밤에 심해지는 가려움증은 옴(개선충 감염)의 특징적인 증상으로, 피부과를 방문하면 진단과 치료를 받을 수 있습니다. 가족이나 밀접 접촉자도 함께 검진을 받는 것이 중요합니다.', 3819, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '옴', '옴', 'PREVENTION', '강아지의 옴은 사람에게 일시적으로 옮겨 가려움을 유발할 수 있습니다. 강아지 옴 예방을 위해서는 정기적인 동물병원 검진, 옴이 의심되는 동물과의 접촉 차단, 진드기 예방약 투여를 권고합니다. 강아지에게 옴 증상이 보인다면 즉시 동물병원을 방문하시기 바랍니다.', 3820, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '옴', '옴', 'CAUSE', '옴의 야간 가려움증은 개선충이 피부 각질층에 굴을 파고 활동하기 때문에 발생하며, 체온이 오르는 밤에 기생충의 활동이 활발해져 가려움이 심해집니다. 밤에 심해지는 가려움증과 피부에 굴 모양의 병변이 있다면 피부과 전문의의 진료를 받으시기 바랍니다.', 3821, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '옴', '옴', 'DEFINITION', '옴은 개선충이라는 기생충이 피부 각질층에 기생하면서 발생하는 전염성 피부 질환입니다. 밤에 심해지는 극심한 가려움증과 손가락 사이, 손목, 겨드랑이 등에 구진·수포·굴 모양 병변이 생기는 것이 특징입니다. 직접 접촉이나 침구·의류를 통해 전파되므로 확인되면 가족 및 접촉자 전체가 동시에 치료를 받아야 합니다.', 3822, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '옴', '옴', 'SYMPTOM', '옴은 전염성 질환으로, 밀접 접촉이 많은 환경에서 집단 감염이 자주 발생합니다. 주 증상은 밤에 심해지는 전신 가려움증, 손발가락 사이·손목·겨드랑이 등의 발진과 굴 형성입니다. 증상이 의심된다면 즉시 피부과 전문의를 방문하고, 접촉자 전원이 함께 검진 및 치료를 받으시기 바랍니다.', 3823, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '옴', '옴', 'DIAGNOSIS', '옴 진단을 위해서는 피부 병변 부위를 긁어 현미경으로 개선충·충란·분변을 확인하는 피부 소파 검사가 표준 진단법입니다. 야간 가려움증과 특징적 병변이 있다면 피부과 전문의를 방문해 정확한 검사를 받으시기 바랍니다.', 3824, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '옴', '옴', 'TREATMENT', '옴 치료의 핵심은 퍼메트린 5% 크림을 전신에 바르고 8~14시간 후 씻어내는 방법이 1차 표준 치료입니다. 침구·의복은 고온 세탁 또는 비닐백 밀봉 보관으로 재감염을 방지해야 합니다. 가족 및 밀접 접촉자 전원이 동시에 치료를 받아야 재감염을 예방할 수 있습니다.', 3825, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '옻 중독', '옻중독', 'MEDICATION', '옻 접촉 후 가려움과 부풀어오름을 완화하는 자연요법으로는 찬물 또는 냉습포 적용, 칼라민 로션 도포, 알로에 베라 겔 사용, 오트밀 목욕 등이 있습니다. 심한 부종·수포·전신 반응이 있는 경우에는 피부과 또는 응급실 방문이 필요합니다.', 3826, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '옻 중독', '옻중독', 'PREVENTION', '옻 중독은 노출 차단이 가장 효과적인 예방법입니다. 산행 시 긴 소매·긴 바지 착용, 옻나무 접촉 회피, 노출 후 즉시 비누와 물로 세척이 핵심입니다. 이미 증상이 나타났다면 피부과 전문의를 방문해 항히스타민제나 스테로이드 처방을 받으시기 바랍니다.', 3827, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '옻 중독', '옻중독', 'CAUSE', '옻 중독의 주요 원인은 옻나무에 포함된 우루시올이라는 수지 성분으로, 피부 접촉 시 지연형 과민 반응을 일으킵니다. 접촉 후 12~72시간 내에 접촉 부위에 발적·부종·구진·수포가 발생하고 심한 가려움이 동반됩니다. 증상 발생 시 피부과 전문의의 진료를 받으시기 바랍니다.', 3828, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '옻 중독', '옻중독', 'DEFINITION', '옻 중독은 피부 직접 접촉뿐 아니라 옻이 들어간 음식 섭취로도 발생할 수 있으며, 민감한 사람에게는 전신적 알레르기 반응이 나타날 수 있습니다. 옻 알레르기가 의심된다면 해당 음식 섭취를 피하고 증상 발생 시 즉시 응급실을 방문하시기 바랍니다.', 3829, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '옻 중독', '옻중독', 'SYMPTOM', '옻 중독으로 발진과 가려움이 있을 때는 긁지 않는 것이 가장 중요하며, 수포가 생겼을 때 터뜨리지 말고 청결하게 유지해야 합니다. 증상이 악화되거나 전신으로 퍼진다면 즉시 피부과 전문의의 진료를 받으시기 바랍니다.', 3830, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '옻 중독', '옻중독', 'DIAGNOSIS', '옻 중독으로 피부에 발진, 진물, 가려움이 있다면 피부과를 방문하는 것이 가장 적절합니다. 증상이 심하거나 전신 반응이 있는 경우 응급실을 방문하시기 바랍니다.', 3831, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '옻 중독', '옻중독', 'TREATMENT', '옻 중독으로 인한 피부 증상은 피부과 전문의의 치료로 효과적으로 완화할 수 있습니다. 치료는 국소 또는 전신 스테로이드제, 항히스타민제 등이 사용됩니다. 전신 반응이 동반된다면 즉시 응급실을 방문하시기 바랍니다.', 3832, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '욕창', '욕창', 'PREVENTION', '장시간 누워 있으면 뼈 돌출 부위에 지속적인 압박이 가해져 혈액 순환이 저하되고 조직 손상이 발생하여 욕창이 생깁니다. 예방을 위해서는 2시간마다 체위 변경, 욕창 예방 매트리스 사용, 피부 청결 및 보습 유지가 중요합니다. 욕창이 발생했다면 외과 또는 피부과 전문의의 진료를 받으시기 바랍니다.', 3833, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '욕창', '욕창', 'CAUSE', '교통사고 후 장기간 와상 상태에서 욕창이 발생하는 주요 원인은 지속적 압박에 의한 허혈성 조직 손상입니다. 예방을 위해 정기적인 체위 변경과 적절한 영양 공급이 필수이며, 욕창 발생 시 전문의 진료를 받으시기 바랍니다.', 3834, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '욕창', '욕창', 'DEFINITION', '욕창이란 오랜 시간 같은 자세로 누워 있을 때 뼈 돌출 부위에 지속적인 압력이 가해져 피부와 피하 조직이 손상·괴사되는 질환입니다. 주로 천골, 뒤꿈치, 엉덩이 등에 발생하며 1~4단계로 진행됩니다. 예방과 조기 치료가 매우 중요하므로 이상 소견 시 전문의 진료를 받으시기 바랍니다.', 3835, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '욕창', '욕창', 'SYMPTOM', '욕창의 증상은 단계별로 다르며, 1단계는 누르면 색이 변하지 않는 붉은 발적, 4단계는 근육·뼈까지 노출된 심부 괴사입니다. 감염 시 악취 나는 분비물, 발열, 통증이 동반될 수 있으며 패혈증으로 이어질 수 있습니다. 욕창이 의심되면 즉시 전문의의 진료를 받으시기 바랍니다.', 3836, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '욕창', '욕창', 'DIAGNOSIS', '오랜 와상으로 피부가 붉게 부어오르고 피부가 튀어나온 증상이 있다면 욕창 초기로 진단될 수 있습니다. 피부과 또는 외과를 방문하면 단계 평가를 통해 욕창 진단이 이루어집니다. 조기에 발견할수록 치료 예후가 좋으므로 전문의 진료를 받으시기 바랍니다.', 3837, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '욕창', '욕창', 'TREATMENT', '욕창 치료를 위한 생활습관으로 가장 중요한 것은 2시간마다 체위 변경, 욕창 예방 특수 매트리스 사용, 피부를 청결하게 유지하는 것입니다. 단백질·비타민 C·아연이 풍부한 식단으로 조직 재생을 돕는 것도 중요합니다. 외과 또는 피부과 전문의의 체계적인 상처 관리와 병행하시기 바랍니다.', 3838, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '주근깨', '주근깨', 'CHECKUP', '주근깨 검진은 일반 피부과 의원에서 받을 수 있으며, 네이버·카카오 등 포털의 병원 예약 서비스를 통해 피부과 예약이 가능합니다. 주근깨는 양성 피부 병변이나 흑색종 등 악성 병변과의 감별이 필요하므로 피부과 전문의의 진찰을 권고합니다.', 3839, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '주근깨', '주근깨', 'DIET_LIFE', '항산화 성분이 풍부한 비타민 C와 비타민 E는 멜라닌 생성 억제와 피부 보호에 도움이 됩니다. 음식 조절보다 자외선 차단이 주근깨 예방에 더 효과적이며, 치료가 필요하면 피부과 전문의와 상담하시기 바랍니다.', 3840, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '주근깨', '주근깨', 'MEDICATION', '주근깨 치료에 사용되는 약물로는 하이드로퀴논, 레티노이드, 아젤라산, 코직산, 트라넥삼산 등이 있으며 멜라닌 생성 효소를 억제하거나 각질 탈락을 돕습니다. 약물 선택은 개인 피부 상태에 따라 다르므로 피부과 전문의와 상담 후 사용하시기 바랍니다.', 3841, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '주근깨', '주근깨', 'PREVENTION', '자외선은 피부의 멜라닌세포를 자극해 멜라닌 생성을 증가시키고 주근깨를 짙게 만드는 주요 원인입니다. 자외선 차단제는 UV를 차단하여 멜라닌 과생성을 억제함으로써 주근깨 악화를 방지하고 예방하는 데 효과적입니다. 2~3시간마다 덧바르는 것이 권장됩니다.', 3842, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '주근깨', '주근깨', 'EXERCISE', '야외 운동 시 자외선 노출은 멜라닌 생성을 자극하여 주근깨를 더 짙게 만들 수 있습니다. 야외 운동 전 SPF 50 이상의 자외선 차단제를 꼼꼼히 바르고, 모자·선글라스를 착용하며 강한 자외선 시간대를 피하는 것이 좋습니다.', 3843, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '주근깨', '주근깨', 'CAUSE', '주근깨는 유전적 요인이 중요한 원인으로, MC1R 유전자 변이와 관련이 있습니다. 유전적 소인이 있더라도 자외선 차단을 철저히 하면 주근깨 악화를 상당히 줄일 수 있으므로 피부과 전문의와 예방 및 치료 방법을 상담하시기 바랍니다.', 3844, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '주근깨', '주근깨', 'REHAB', '보습, 비타민 C·E가 풍부한 식단, 충분한 수분 섭취가 피부 전반의 건강과 혈색 개선에 도움이 될 수 있습니다. 색소 문제 개선을 원한다면 피부과 전문의를 통해 레이저 치료나 미백 성분 사용을 상담하시기 바랍니다.', 3845, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '주근깨', '주근깨', 'DEFINITION', '주근깨는 멜라닌 색소가 피부에 불규칙하게 과잉 침착되어 얼굴에 황갈색~갈색의 작은 반점이 다수 생기는 피부 질환입니다. 유전적 소인이 있고 자외선에 노출되면 짙어지며, 일조량이 줄면 옅어지는 특성이 있습니다. 기미·흑색종 등과 감별이 필요하므로 피부과 전문의의 진단을 받으시기 바랍니다.', 3846, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '주근깨', '주근깨', 'SYMPTOM', '주근깨는 유전적 소인을 가진 피부에 자외선이 지속적으로 작용하여 멜라닌세포가 색소를 과잉 생성함으로써 발생합니다. 자외선 차단을 소홀히 하면 반복적으로 악화됩니다. 지속적이거나 불규칙한 반점이 있다면 악성 병변 감별을 위해 피부과 전문의의 진찰을 받으시기 바랍니다.', 3847, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '주근깨', '주근깨', 'DIAGNOSIS', '얼굴에 반복적으로 점 또는 반점이 생기는 피부 질환의 정확한 진단을 위해서는 피부과 전문의를 방문하는 것이 가장 적절합니다. 피부과에서는 더모스코피를 활용해 주근깨, 기미, 흑색종 등을 감별할 수 있습니다. 변화가 있거나 개수가 늘어난다면 피부과 전문의의 진찰을 받으시기 바랍니다.', 3848, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '주근깨', '주근깨', 'TREATMENT', '알로에 베라 겔에는 알로신 성분이 포함되어 있어 멜라닌 생성 효소를 억제하는 미백 효과가 있다는 연구가 있으나, 주근깨를 완전히 제거하는 효과는 제한적입니다. 보다 확실한 주근깨 치료를 원한다면 피부과 전문의와 상담하시기 바랍니다.', 3849, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '쥐젖', '쥐젖', 'CHECKUP', '쥐젖 조직검사는 국소마취 후 절제 또는 면도 생검을 시행하며, 병리 검사 결과로 연성 섬유종인지 다른 병변인지 확인합니다. 정확한 진단과 안전한 제거를 위해 피부과 전문의에게 조직검사를 받으시기 바랍니다.', 3850, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '쥐젖', '쥐젖', 'DIET_LIFE', '목이나 겨드랑이에 쥐젖이 생기는 생활적 요인으로는 해당 부위의 반복적인 마찰이 가장 중요합니다. 목걸이나 옷깃에 의한 만성 마찰, 겨드랑이의 피부끼리 닿는 접촉 부위, 브래지어 끈 등 의복에 의한 지속적인 자극이 쥐젖 발생을 촉진합니다. 비만으로 인한 피부 주름 증가도 마찰 면적을 늘려 쥐젖 발생을 증가시킬 수 있습니다.', 3851, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '쥐젖', '쥐젖', 'MEDICATION', '쥐젖(연성 섬유종)은 약물만으로 제거되는 확립된 치료법이 없으며, 주로 피부과에서 시행하는 시술적 치료가 효과적입니다. 치료 방법으로는 냉동치료, 전기소작술, 레이저 치료, 가위 절제 등이 있으며, 대부분 간단하고 당일 시술이 가능합니다. 쥐젖으로 일상생활에 불편이 있다면 피부과 전문의와 상담하여 적합한 치료를 받으시기 바랍니다.', 3852, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '쥐젖', '쥐젖', 'PREVENTION', '쥐젖 예방을 위해 마찰이 많은 부위에 자극을 줄이는 것이 중요하며, 목 부위에는 자극이 적은 소재의 의류를 착용하고 목걸이 착용을 줄이는 것이 도움이 됩니다. 비만이 쥐젖 발생 위험을 높이므로 균형 잡힌 식사와 규칙적인 운동을 통해 적정 체중을 유지하는 것이 권장됩니다. 이미 발생한 쥐젖은 자연 소실이 어려우므로 피부과 전문의의 진료를 받으시기 바랍니다.', 3853, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '쥐젖', '쥐젖', 'EXERCISE', '비만 예방을 위한 운동으로는 유산소 운동(걷기, 자전거 타기, 수영 등)을 주 150분 이상 실시하고, 근력 운동을 주 2회 이상 병행하는 것이 권장됩니다. 식이 개선으로는 정제 탄수화물과 포화지방 섭취를 줄이고, 채소, 과일, 단백질 위주의 균형 잡힌 식단을 유지하는 것이 도움이 됩니다. 구체적인 운동 및 식이 계획은 내과 또는 가정의학과 전문의와 상담하시기 바랍니다.', 3854, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '쥐젖', '쥐젖', 'CAUSE', '쥐젖(연성 섬유종)은 주로 피부가 서로 접히거나 마찰되는 부위에서 발생하며, 주된 원인으로는 비만으로 인한 피부 마찰, 임신 중 호르몬 변화, 노화에 따른 피부 변화, 당뇨병 등 대사 질환, 그리고 인슐린 저항성이 관여하는 것으로 알려져 있습니다. 유전적 소인도 일부 영향을 미치며, 피부 섬유아세포의 과증식이 발생 기전으로 제시됩니다.', 3855, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '쥐젖', '쥐젖', 'REHAB', '쥐젖 수술 후 흉터 회복을 위해서는 상처 부위를 청결하게 유지하고 의사가 처방한 흉터 연고(실리콘 겔 또는 시트 등)를 꾸준히 사용하는 것이 중요합니다. 자외선에 의한 색소 침착을 막기 위해 자외선 차단제를 바르고, 흉터 부위를 자극하지 않아야 합니다. 상처 회복 및 흉터 관리에 대해 시술을 받은 피부과 전문의의 지도에 따르시기 바랍니다.', 3856, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '쥐젖', '쥐젖', 'DEFINITION', '쥐젖(연성 섬유종, Acrochordon)은 피부색 또는 갈색의 부드럽고 말랑한 작은 돌출 병변으로, 가는 줄기(경경부)에 의해 피부에 연결된 형태가 특징입니다. 주로 목, 겨드랑이, 사타구니, 눈꺼풀 등 피부가 접히거나 마찰이 있는 부위에 발생하며, 양성 종양으로 악성 변화는 거의 없습니다. 마찰, 호르몬 변화, 비만, 당뇨 등이 발생에 관여합니다.', 3857, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '쥐젖', '쥐젖', 'SYMPTOM', '목, 겨드랑이, 눈꺼풀에 피부색 또는 갈색의 작은 구진이 나타나는 것은 쥐젖(연성 섬유종)의 전형적인 증상에 해당합니다. 쥐젖은 부드럽고 줄기 모양의 연결부가 있는 것이 특징이며, 통증은 없으나 마찰로 인한 자극 시 불편감이 있을 수 있습니다. 정확한 진단을 위해 피부과 전문의의 진찰을 받으시기 바랍니다.', 3858, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '쥐젖', '쥐젖', 'DIAGNOSIS', '눈꺼풀 주변의 쥐젖 제거는 피부과와 안과 모두에서 시행 가능하며, 눈꺼풀 안쪽에 가까운 경우 안과 전문의의 진료가 더 적합할 수 있습니다. 눈꺼풀 바깥쪽 피부 병변은 피부과에서도 안전하게 제거할 수 있습니다. 눈 주변은 민감한 부위이므로, 자가 제거를 시도하지 말고 전문의의 진찰 후 적절한 시술을 받으시기 바랍니다.', 3859, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '쥐젖', '쥐젖', 'TREATMENT', '쥐젖은 피부과에서 냉동치료, 전기소작술, 레이저 치료, 가위 절제 등의 방법으로 당일 치료가 가능합니다. 시술 시간은 병변 수와 크기에 따라 다르지만 대부분 수분 내로 간단히 시행되며, 국소 마취 후 통증 없이 진행됩니다. 치료 후 일상생활로의 복귀가 빠르며, 자세한 사항은 피부과 전문의와 상담하시기 바랍니다.', 3860, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '지루성 피부염', '지루성피부염', 'PREVENTION', '겨울철 지루성 피부염 예방을 위해 가장 효과적인 스킨케어는 피부 보습 유지입니다. 뜨거운 물 세안보다 미지근한 물을 사용하고, 세안 후 보습제를 충분히 발라 피부 건조를 방지하며, 실내 습도를 적절히 유지하는 것이 중요합니다. 항진균 성분이 포함된 두피 샴푸를 사용하고, 스트레스 관리도 재발 예방에 도움이 되며, 증상이 악화되면 피부과 전문의의 진료를 받으시기 바랍니다.', 3861, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '지루성 피부염', '지루성피부염', 'CAUSE', '지루성 피부염은 가족력이 있으면 유전적 소인을 가질 가능성이 높아집니다. 유전적 요인이 피부 지질 구성, 면역 반응, 말라세지아 진균에 대한 감수성에 영향을 줄 수 있는 것으로 연구되고 있습니다. 그러나 지루성 피부염은 유전 외에도 환경, 스트레스, 호르몬, 면역 상태 등 다양한 요인이 복합적으로 작용하므로 피부과 전문의와 상담하시기 바랍니다.', 3862, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '지루성 피부염', '지루성피부염', 'DEFINITION', '두피와 신체 피부의 가려움증과 유분기(기름기) 증가는 지루성 피부염의 특징적인 증상입니다. 지루성 피부염은 피지 분비가 많은 부위에서 말라세지아 진균에 의한 염증 반응으로 기름진 느낌의 각질, 홍반, 가려움이 나타납니다. 이러한 증상이 지속되면 피부과 전문의의 정확한 진단과 치료를 받으시기 바랍니다.', 3863, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '지루성 피부염', '지루성피부염', 'SYMPTOM', '지루성 피부염에서 노란 기름진 인설과 홍반이 심할 경우 2차 세균 감염, 모낭염 등이 동반될 수 있습니다. 드물게 눈꺼풀염(안검염)이 동반되어 눈의 자극감이 나타날 수 있으며, 얼굴 전반의 홍조가 심해지기도 합니다. 증상이 악화되거나 전신으로 퍼지는 경우 피부과 전문의의 신속한 진료를 받으시기 바랍니다.', 3864, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '지루성 피부염', '지루성피부염', 'DIAGNOSIS', '청소년기 얼굴 발진과 가려움증은 지루성 피부염, 여드름, 아토피 피부염 등 다양한 원인이 있을 수 있습니다. 진단을 위해 피부과 전문의의 임상 진찰이 필요하며, 필요 시 알레르기 검사, 피부 패치 검사 등을 시행하기도 합니다. 청소년기 피부 질환은 적절한 치료로 개선이 가능하므로 피부과에서 정확한 진단을 받으시기 바랍니다.', 3865, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '지루성 피부염', '지루성피부염', 'TREATMENT', '지루성 피부염의 가려움, 따가움, 건조함 완화를 위해 항진균 샴푸와 두피 용액(케토코나졸 등), 저강도 국소 스테로이드제, 국소 칼시뉴린 억제제(타크로리무스 등)가 사용됩니다. 보습제로 피부 장벽을 강화하고, 항진균 성분이 포함된 클렌저를 사용하는 것도 도움이 됩니다. 치료 방법과 약물 선택은 피부과 전문의의 처방에 따라 진행하시기 바랍니다.', 3866, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '지방종', '지방종', 'CAUSE', '지방종의 정확한 원인은 명확하지 않으나, 가족성 다발성 지방종증처럼 유전적 요인(상염색체 우성 유전)이 관여하는 경우가 있습니다. 유전적 이상으로 지방세포의 과증식이 발생하거나, 외상 후 해당 부위에 지방종이 생기는 경우도 보고됩니다. 지방종이 의심될 경우 정확한 진단과 필요시 치료를 위해 외과 또는 피부과 전문의의 진료를 받으시기 바랍니다.', 3867, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '지방종', '지방종', 'DEFINITION', '지방종은 지방세포로 이루어진 양성 종양으로, 주로 피부 아래(피하조직)에 위치하며 부드럽고 탄력 있게 만져집니다. 등, 목, 어깨, 팔, 복부 등 어느 신체 부위에나 발생할 수 있으며, 대부분 통증이 없고 천천히 성장합니다. 피부 아래 부드러운 종괴가 만져지면 외과 또는 피부과 전문의의 진찰을 받아 정확히 확인하시기 바랍니다.', 3868, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '지방종', '지방종', 'SYMPTOM', '지방종은 피부 아래 말랑하고 둥근 결절 형태로, 등, 어깨, 목, 팔, 허벅지, 복부 등 체간 및 사지 어디에서도 발생할 수 있습니다. 근육 내 지방종의 경우 심부에서 발생하여 움직임 시 불편감이 있을 수 있으나, 대부분 표재성 지방종은 증상이 없습니다. 크기가 갑자기 커지거나 통증이 있으면 외과 전문의의 진찰이 필요합니다.', 3869, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '지방종', '지방종', 'DIAGNOSIS', '지방종 진단에 초음파 검사가 많이 사용되며, 초음파는 종괴의 에코 특성(지방 조직의 특유 음향 반사 패턴)으로 지방종을 다른 종양과 구별합니다. 크기가 크거나 심부에 위치하는 경우 MRI 검사로 주변 구조물과의 관계를 더 정확하게 파악할 수 있습니다. 확진을 위해 조직 생검이 필요할 수 있으므로 외과 또는 피부과 전문의의 진료를 받으시기 바랍니다.', 3870, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '지방종', '지방종', 'TREATMENT', '지방종의 가장 효과적인 치료는 외과적 절제술로, 재발률이 낮고 완전 제거가 가능합니다. 크기가 작고 증상이 없으면 경과 관찰도 가능하나, 크기가 커지거나 통증, 기능 장애가 있는 경우 수술이 권장됩니다. 지방 흡입을 이용한 최소 침습적 제거도 일부 경우에 가능하며, 치료 방법은 외과 전문의와 상담 후 결정하시기 바랍니다.', 3871, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '켈로이드', '켈로이드', 'CAUSE', '켈로이드는 피부 상처 치유 과정에서 섬유아세포가 과활성화되어 콜라겐이 과도하게 생성·축적됨으로써 발생합니다. 일반 흉터와 달리 원래 상처 범위를 넘어 주변 정상 피부까지 침범하는 것이 특징이며, 귀, 어깨, 가슴 등에 호발합니다. 켈로이드가 의심되면 피부과 전문의의 정확한 진단과 적절한 치료를 받으시기 바랍니다.', 3872, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '켈로이드', '켈로이드', 'DEFINITION', '켈로이드는 피부 손상 후 치유 과정에서 결합조직(콜라겐)이 병적으로 과잉 증식하여 원래 상처 범위를 넘는 단단하고 융기된 흉터를 형성하는 질환입니다. 피부의 결합조직이 비정상적으로 증식하여 단단한 융기를 만드는 것이 맞으며, 켈로이드성 소인이 있는 사람에게서 수술, 예방접종, 외상, 여드름 등 어떤 피부 손상 후에도 발생할 수 있습니다.', 3873, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '켈로이드', '켈로이드', 'SYMPTOM', '켈로이드의 주요 증상은 상처 부위를 넘어 퍼지는 단단하고 융기된 흉터로, 가려움증과 통증이 동반되기도 합니다. 켈로이드 예방을 위해서는 불필요한 피부 절개나 시술을 피하고, 수술 후 흉터 부위에 실리콘 겔 시트 부착, 자외선 차단이 도움이 됩니다. 켈로이드 체질인 경우 상처 후 조기에 피부과 전문의의 진료를 받아 예방적 치료를 시작하는 것이 중요합니다.', 3874, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '켈로이드', '켈로이드', 'DIAGNOSIS', '켈로이드가 의심되면 피부과 전문의가 있는 의원, 종합병원 피부과 또는 성형외과에서 정확한 진단을 받을 수 있습니다. 임상적 소견(상처 범위를 넘는 융기성 흉터)으로 대부분 진단되며, 필요 시 조직 생검으로 확진합니다. 켈로이드는 치료가 어렵고 재발률이 높으므로 전문의의 지도하에 적절한 치료를 받으시기 바랍니다.', 3875, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '켈로이드', '켈로이드', 'TREATMENT', '켈로이드의 가장 일반적인 치료는 스테로이드(트리암시놀론 아세토나이드) 병변 내 주사로, 콜라겐 생성을 억제하고 병변 크기를 줄이는 데 효과적입니다. 냉동치료, 레이저 치료, 압박 치료, 실리콘 겔 시트 등과 병행하기도 하며, 수술적 절제는 단독으로는 재발률이 높아 방사선치료나 스테로이드 주사와 함께 시행됩니다. 치료 방법은 피부과 또는 성형외과 전문의와 상담하시기 바랍니다.', 3876, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '콜린성 두드러기', '콜린성두드러기', 'DIET_LIFE', '콜린성 두드러기는 체온 상승이 주된 유발 인자이며, 추운 환경에서는 일반적으로 증상이 호전되는 경우가 많습니다. 가려움증 완화에 도움이 될 수 있는 식이로는 자극적인 음식, 알코올, 뜨거운 음식 등 체온을 급격히 올리는 식품을 피하는 것이 권장됩니다. 콜린성 두드러기는 치료 및 유발 요인 관리를 위해 피부과 또는 알레르기내과 전문의의 진료를 받으시기 바랍니다.', 3877, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '콜린성 두드러기', '콜린성두드러기', 'MEDICATION', '콜린성 두드러기의 약물 치료로는 항히스타민제(세티리진, 로라타딘, 펙소페나딘 등 2세대 항히스타민제)가 1차 선택 약물로 사용됩니다. 증상이 심한 경우 항콜린제나 면역 조절제(오말리주맙 등)가 추가로 사용될 수 있습니다. 적절한 약물 선택과 용량은 피부과 또는 알레르기내과 전문의의 처방에 따라야 합니다.', 3878, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '콜린성 두드러기', '콜린성두드러기', 'PREVENTION', '콜린성 두드러기 예방을 위해 체온을 급격히 올리는 격렬한 운동, 뜨거운 목욕, 매운 음식, 스트레스 등의 유발 인자를 파악하고 피하는 것이 중요합니다. 운동 전에 미리 항히스타민제를 복용하거나, 체온이 천천히 올라가도록 준비 운동을 충분히 하는 것도 도움이 됩니다. 증상이 반복되면 피부과 또는 알레르기내과 전문의와 상담하여 개인 맞춤형 예방 전략을 세우시기 바랍니다.', 3879, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '콜린성 두드러기', '콜린성두드러기', 'CAUSE', '콜린성 두드러기는 운동, 더위, 목욕, 스트레스 등으로 체온이 상승할 때 콜린성(아세틸콜린 매개) 자율신경 자극에 의해 비만세포(mast cell)에서 히스타민이 분비되어 발생합니다. 1~3mm 크기의 작은 팽진이 몸통과 사지에 나타나고 따가움과 가려움이 동반되는 것이 전형적인 양상입니다. 운동 후 반복적으로 이러한 증상이 나타나면 피부과 전문의의 진료를 받으시기 바랍니다.', 3880, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '콜린성 두드러기', '콜린성두드러기', 'DEFINITION', '콜린성 두드러기는 체온 상승을 유발하는 자극(운동, 더운 환경, 정서적 스트레스, 뜨거운 음식 등)에 의해 콜린성 신경이 활성화되어 비만세포가 히스타민을 분비하고 피부에 두드러기가 발생하는 질환입니다. 스트레스 상황에서는 교감신경 활성화와 발한으로 체온이 오르며 증상이 유발될 수 있습니다. 진단과 치료는 피부과 또는 알레르기내과 전문의와 상담하시기 바랍니다.', 3881, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '콜린성 두드러기', '콜린성두드러기', 'SYMPTOM', '콜린성 두드러기는 체온이 오르기 시작하는 운동 시작 후 수분 이내 또는 뜨거운 목욕 중에 주로 발생하며, 가슴과 복부에서 시작해 전신으로 퍼지는 경향이 있습니다. 초기에는 1~3mm의 작은 팽진(두드러기)과 심한 따가움·가려움이 나타나고, 체온이 낮아지면 보통 30~60분 이내에 자연 소실됩니다. 증상 변화 양상을 의사에게 상세히 설명하면 진단에 도움이 됩니다.', 3882, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '콜린성 두드러기', '콜린성두드러기', 'DIAGNOSIS', '덥고 습한 환경에서 피부가 부풀어 오르고 가려움이 나타나면 콜린성 두드러기를 포함하여 발한 자극 두드러기, 열성 두드러기 등의 가능성을 검토해야 합니다. 의사에게 증상 발생 환경(더위, 운동, 스트레스 등), 병변 크기(1~3mm의 소형 팽진 여부), 지속 시간, 가려움 및 따가움 정도를 상세히 설명하고, 유발 검사(운동 유발 시험, 온수 욕조 시험)를 받을 수 있습니다.', 3883, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '콜린성 두드러기', '콜린성두드러기', 'TREATMENT', '콜린성 두드러기는 체온이 정상화되면 대개 30분~1시간 내에 자연 소실됩니다. 자가 치료로는 시원한 환경에서 안정을 취하고 체온을 낮추는 것이 가장 빠른 완화 방법이며, 사전에 복용한 항히스타민제가 증상 완화를 앞당길 수 있습니다. 증상이 반복되거나 심하면 피부과 또는 알레르기내과 전문의의 처방약을 통한 체계적인 치료가 필요합니다.', 3884, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '탈모증', '탈모증', 'CHECKUP', '탈모증 진단을 위해 모발 당김 검사(pull test), 트리코스코피(모발 확대 검사), 두피 조직 생검 등이 사용됩니다. 원형 탈모는 임상 소견으로 진단하며, 남성형·여성형 탈모는 모발 밀도와 패턴 분석이 중요합니다. 혈액검사(갑상선 기능, 빈혈, 철분 수치 등)로 전신 질환에 의한 탈모 여부를 확인하며, 정확한 진단과 치료는 피부과 전문의를 통해 받으시기 바랍니다.', 3885, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '탈모증', '탈모증', 'DIET_LIFE', '탈모 예방과 모발 건강 유지를 위해 단백질(케라틴의 주원료)은 충분히 섭취하는 것이 중요합니다. 성인 기준으로 체중 1kg당 약 0.8~1.2g의 단백질 섭취를 권장하며, 남녀 공통으로 적용됩니다. 닭가슴살, 생선, 콩류, 달걀 등 良質의 단백질 식품을 균형 있게 섭취하고, 탈모가 심하면 피부과 전문의의 진료를 받으시기 바랍니다.', 3886, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '탈모증', '탈모증', 'MEDICATION', '탈모 예방에 도움이 되는 생활 습관으로는 두피를 청결하게 유지하고, 두피 자극이 적은 저자극 샴푸를 사용하며, 젖은 상태에서 무리하게 빗지 않는 것이 중요합니다. 식이요법으로는 단백질, 철분, 아연, 비타민 D, 비오틴이 풍부한 음식을 섭취하고, 과도한 음주와 흡연은 피하는 것이 권장됩니다. 탈모가 지속되면 반드시 피부과 전문의의 진료를 통해 원인을 파악하고 적절한 치료를 받으시기 바랍니다.', 3887, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '탈모증', '탈모증', 'PREVENTION', '단식(급격한 열량 제한)은 단백질과 필수 영양소 결핍을 유발하여 모발 성장 주기를 방해하고, 수주~수개월 후 휴지기 탈모(telogen effluvium)를 일으킬 수 있습니다. 예방을 위해서는 무리한 단식보다 균형 잡힌 식사를 유지하고, 다이어트 시에도 충분한 단백질, 철분, 아연을 섭취해야 합니다. 단식 후 탈모가 심하면 피부과 전문의의 진료를 받으시기 바랍니다.', 3888, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '탈모증', '탈모증', 'CAUSE', '탈모증의 원인은 유전적 요인과 후천적 요인으로 나눌 수 있습니다. 유전적 요인으로는 남성형·여성형 탈모(안드로겐성 탈모)에서 안드로겐 호르몬 수용체 유전자가 관여하며, 원형 탈모에서도 유전적 소인이 있습니다. 후천적 요인으로는 스트레스, 영양 결핍, 갑상선 질환, 자가면역 질환, 급격한 체중 감소, 약물 부작용 등이 있으며, 피부과 전문의를 통해 정확한 원인을 파악하는 것이 중요합니다.', 3889, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '탈모증', '탈모증', 'DEFINITION', '정상적으로 하루 50~100개의 머리카락이 빠지는 것은 정상 범위이나, 이를 초과하거나 두드러진 두피 부위가 보이면 탈모증을 의심해야 합니다. 탈모증은 두피에 한정되지 않고 눈썹, 속눈썹, 체모 등에도 나타날 수 있으나, 가슴·팔다리 체모 탈락은 내분비 질환 등 전신 질환의 가능성을 확인해야 합니다. 탈모가 의심되면 피부과 전문의의 진료를 받으시기 바랍니다.', 3890, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '탈모증', '탈모증', 'SYMPTOM', '머리를 감는 동안 머리카락이 많이 빠지는 것은 이미 탈락이 진행 중인 휴지기 모발이 세발 시 물리적 자극에 의해 빠지는 것으로, 탈모증의 증상에 포함될 수 있습니다. 정상인도 씻을 때 일부 모발이 빠지지만, 하루 100개 이상이면 이상이 있을 수 있으며, 특히 이 상태가 수주 이상 지속되면 피부과 전문의의 진찰이 권장됩니다.', 3891, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '탈모증', '탈모증', 'DIAGNOSIS', '탈모 자가진단법으로는 하루 빠지는 모발 수를 세어보거나, 양쪽 관자놀이 및 정수리 부위의 모발 밀도를 사진으로 기록하여 비교하는 방법이 있습니다. 50~60개의 머리카락을 집어 가볍게 당겼을 때 6개 이상 빠지면(pull test) 탈모가 활발히 진행되는 것으로 볼 수 있습니다. 자가진단에는 한계가 있으므로 이상이 의심되면 피부과 전문의의 정확한 진단을 받으시기 바랍니다.', 3892, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '탈모증', '탈모증', 'TREATMENT', '출산 후 탈모(분만 후 휴지기 탈모)는 임신 중 높아졌던 에스트로겐이 출산 후 급격히 감소하면서 많은 모발이 동시에 휴지기로 진입하여 발생하는 생리적 현상입니다. 탈모 샴푸는 일반 모발 관리에는 도움이 될 수 있으나, 출산 후 호르몬성 탈모 자체를 치료하는 효과는 제한적입니다. 출산 후 6개월 이상 탈모가 지속되거나 심화된다면 피부과 전문의의 진료를 받으시기 바랍니다.', 3893, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '티눈', '티눈', 'DIET_LIFE', '손가락 티눈은 주로 반복적인 압박이나 마찰이 원인이므로, 원인 자극을 줄이는 것이 우선입니다. 식습관과 영양 섭취가 티눈 자체를 직접 유발하거나 치료하지는 않으나, 쥐는 도구 사용 방식 개선, 손 보호 장갑 착용 등 생활 습관 교정이 재발 방지에 도움이 됩니다. 이미 생긴 티눈은 피부과 전문의의 진료를 통해 적절한 치료를 받으시기 바랍니다.', 3894, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '티눈', '티눈', 'MEDICATION', '티눈 제거에 주로 사용되는 약물은 살리실산(10~40%) 제제로, 각질 용해 작용으로 딱딱해진 티눈 조직을 연화·제거합니다. 시중에 살리실산 패드, 겔, 액체 형태로 판매되나, 당뇨병 환자나 혈액순환 장애가 있는 경우 자가 사용 시 주의가 필요합니다. 정확하고 효과적인 치료를 위해 피부과 전문의의 진료 후 냉동치료, 레이저 등의 시술을 병행하는 것이 권장됩니다.', 3895, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '티눈', '티눈', 'PREVENTION', '발바닥 통증 완화를 위해 쿠션이 충분한 편안한 신발을 착용하고, 필요 시 발바닥 패드나 도넛형 패드로 병변 부위 압력을 분산시키는 것이 도움이 됩니다. 발을 따뜻한 물에 불린 후 부드럽게 각질을 제거하고 보습제를 바르는 것도 증상 완화에 도움이 됩니다. 통증이 지속되거나 걷기가 힘든 경우 피부과 전문의의 진료를 통해 정확한 진단과 치료를 받으시기 바랍니다.', 3896, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '티눈', '티눈', 'CAUSE', '티눈은 특정 부위에 반복적인 압박이나 마찰이 가해질 때 피부가 방어 반응으로 각질을 과도하게 생성하면서 발생합니다. 맞지 않는 신발, 잘못된 보행 자세, 발 변형(무지외반증 등), 직업적 손 사용 등이 지속적으로 같은 부위를 자극하면 티눈이 반복적으로 생길 수 있습니다. 원인 자극 제거 없이는 재발하므로 피부과 전문의의 진료와 함께 원인 교정이 중요합니다.', 3897, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '티눈', '티눈', 'DEFINITION', '티눈은 피부의 특정 부위에 반복적인 압박과 마찰이 가해져 각질이 원뿔형으로 두꺼워진 상태로, 중심에 단단한 핵(corn core)이 있는 것이 특징입니다. 발가락에 튀어나온 딱딱한 각질 덩어리가 압박 시 통증을 유발한다면 티눈의 특징적인 증상에 해당합니다. 단순한 굳은살과 구별이 어려울 수 있으므로 피부과 전문의의 진찰로 확인하시기 바랍니다.', 3898, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '티눈', '티눈', 'SYMPTOM', '발바닥의 동그란 돌출물은 티눈, 굳은살(굳은살은 핵이 없음), 족저 사마귀(HPV 감염)의 세 가지가 주요 감별 대상입니다. 티눈은 압박 시 통증이 있고 중심에 단단한 핵이 있으며, 족저 사마귀는 표면에 작은 검은 점(혈전 모세혈관)이 관찰되고 측면 압박 시 통증이 특징적입니다. 정확한 감별을 위해 피부과 전문의의 진찰과 필요 시 더모스코피 검사를 받으시기 바랍니다.', 3899, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '티눈', '티눈', 'DIAGNOSIS', '티눈은 반복적인 압박에 의해 국소 부위 각질이 원뿔 형태로 깊게 증식하여 통증을 유발하는 상태로, 소범위에 각질 증식이 집중되는 것이 굳은살과 구별되는 특징입니다. 자가 제거 시 감염이나 상처 위험이 있으므로 피부과에서 메스를 이용한 핵 제거, 살리실산 약물 도포, 냉동치료 등 전문적인 치료를 받는 것이 안전하고 효과적입니다.', 3900, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '티눈', '티눈', 'TREATMENT', '발바닥 티눈 치료를 위해 피부과에서는 살리실산 패드 또는 겔 도포, 냉동치료(액체질소), 레이저 치료, 메스를 이용한 핵 절제술 등이 사용됩니다. 치료 후에는 쿠션화 착용, 발바닥 패드 사용, 보행 자세 교정 등을 통해 재발을 예방해야 합니다. 장시간 서있는 직업의 경우 맞춤형 깔창(기능성 인솔) 사용도 도움이 되므로 피부과 전문의와 상담하시기 바랍니다.', 3901, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '피부건조증', '피부건조증', 'MEDICATION', '하이드로코르티손(Hydrocortisone)은 약한 강도의 국소 스테로이드로, 염증 매개체(사이토카인, 히스타민 등) 생성을 억제하여 가려움증, 발적, 부종을 완화합니다. 코르티코스테로이드는 면역 세포의 활성화를 억제하고 혈관 투과성을 감소시켜 염증 반응 전반을 조절하는 역할을 합니다. 스테로이드 제제는 장기간 사용 시 피부 위축 등 부작용이 있으므로 피부과 전문의의 지시에 따라 사용하시기 바랍니다.', 3902, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '피부건조증', '피부건조증', 'PREVENTION', '피부건조증 예방을 위해 하루 수분 섭취 권장량은 성인 기준 약 1.5~2리터(8잔)이나, 운동량, 날씨, 개인 상태에 따라 조절이 필요합니다. 그러나 수분 섭취만으로 피부 건조를 완전히 해결하기는 어려우며, 보습제 사용, 실내 습도 유지(40~60%), 뜨거운 물 목욕 자제 등 외적 관리도 함께 필요합니다. 피부건조증이 심하거나 가려움증이 동반되면 피부과 전문의의 진료를 받으시기 바랍니다.', 3903, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '피부건조증', '피부건조증', 'CAUSE', '날씨(특히 겨울철 낮은 습도와 건조한 환경)로 인한 피부건조증은 외부 피부가 전반적으로 당기고, 미세한 각질, 가려움증이 나타나는 것이 특징입니다. 보습제를 충분히 바른 후 증상이 호전된다면 계절성 피부건조증일 가능성이 높으나, 특정 부위에 국한된 심한 가려움이나 발진 등은 다른 피부 질환과 감별이 필요합니다. 증상이 지속되면 피부과 전문의의 진료를 받으시기 바랍니다.', 3904, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '피부건조증', '피부건조증', 'DEFINITION', '피부건조증이 심한 경우 손바닥, 발바닥, 손등, 발뒤꿈치 등에 피부 균열(열창)이 발생할 수 있으며, 출혈이나 통증을 동반하기도 합니다. 피부가 거칠어지고 가려우며 각질이 일어나는 증상이 전형적이며, 건조한 계절이나 나이가 들수록 악화되는 경향이 있습니다. 균열이 심하거나 회복이 안 되는 경우 피부과 전문의의 치료가 필요합니다.', 3905, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '피부건조증', '피부건조증', 'SYMPTOM', '피부건조증의 주요 증상에는 피부 당김, 각질, 가려움증, 거친 질감이 포함되며, 심한 경우 붉은 반점(발적)과 피부 균열(열창)이 나타날 수 있습니다. 특히 건조한 환경, 과도한 세정, 고온의 물 사용이 피부 장벽을 손상시켜 이러한 증상을 악화시킵니다. 증상이 지속되거나 심할 경우 피부과 전문의의 진료를 통해 적절한 보습 치료와 원인 감별을 받으시기 바랍니다.', 3906, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '피부건조증', '피부건조증', 'DIAGNOSIS', '피부건조증의 자가진단으로는 세안 후 보습제 없이 15~30분 경과 후 당김·가려움·각질이 생기는지 확인하거나, 손등이나 팔뚝 피부를 손톱으로 살짝 긁었을 때 하얀 자국이 남는지 보는 방법이 있습니다. 증상이 지속된다면 피부과 전문의의 정확한 진단을 받으시기 바랍니다.', 3907, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '피부건조증', '피부건조증', 'TREATMENT', '아이 피부의 각질과 가려움 완화를 위해서는 미지근한 물로 짧게 목욕 후 즉시 저자극·무향 보습제를 충분히 발라 수분을 가두는 것이 핵심입니다. 실내 습도 50~60% 유지, 순면 의류 착용, 자극적인 비누 사용 금지도 중요합니다. 증상이 심하거나 아토피 피부염이 의심되면 소아 피부과 전문의의 진료를 받으시기 바랍니다.', 3908, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '피부염', '피부염', 'PREVENTION', '피부염 예방을 위해 자외선 차단제 사용은 광접촉성 피부염 예방에 효과적이나, 모든 종류의 피부염에 효과적인 것은 아닙니다. 알레르기 유발 물질 접촉 피하기, 피부 보습 유지, 순한 세정제 사용 등이 피부염 예방에 중요합니다. 피부염이 반복된다면 피부과 전문의와 상담해 원인 알레르기 물질을 파악하시기 바랍니다.', 3909, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '피부염', '피부염', 'DEFINITION', '피부염은 피부의 바깥층에 발생하는 염증 반응으로, 알레르기 반응·자극 물질·유전적 소인 등 다양한 원인에 의해 발생합니다. 주요 증상으로 가려움증, 발적, 부기, 수포, 진물이 나타날 수 있습니다. 원인과 종류에 따라 치료법이 달라지므로 피부과 전문의의 진단을 받으시기 바랍니다.', 3910, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '피부염', '피부염', 'TREATMENT', '아토피 피부염의 비스테로이드 대안 치료로는 국소 칼시뉴린 억제제, PDE4 억제제, 생물학적 제제(두필루맙), JAK 억제제가 있습니다. 광선치료, 프로바이오틱스 보조 요법도 고려할 수 있습니다. 대안 치료 선택은 피부과 전문의와의 상담을 통해 결정하시기 바랍니다.', 3911, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '흉터', '흉터', 'CAUSE', '상처 부위가 볼록하게 튀어오르는 흉터는 상처 치유 과정에서 콜라겐이 과잉 생성되어 발생합니다. 켈로이드 체질이 있는 경우 더욱 심하게 나타날 수 있으며, 치료는 피부과 또는 성형외과 전문의와 상담하시기 바랍니다.', 3912, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '흉터', '흉터', 'DEFINITION', '흉터는 피부 손상 후 치유 과정에서 콜라겐이 재배열되며 정상 피부와 다른 조직으로 대체될 때 발생합니다. 등의 부풀어오른 병변이 종양인지 흉터인지 감별하기 위해서는 피부과 또는 성형외과 전문의의 진찰이 필요합니다.', 3913, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '흉터', '흉터', 'SYMPTOM', '여드름 치료 후 함몰 흉터는 프락셀 레이저·CO2 레이저·미세침 치료로 콜라겐 재생을 촉진하고, 색소침착은 레이저 토닝·미백 성분으로 개선합니다. 적절한 치료 순서와 방법은 피부과 전문의와 상담 후 결정하시기 바랍니다.', 3914, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '흉터', '흉터', 'DIAGNOSIS', '흉터 진단과 치료는 피부과 또는 성형외과에서 받을 수 있습니다. 단순 흉터 평가나 레이저·주사 치료는 피부과가 적합하고, 수술적 교정이 필요한 경우에는 성형외과가 도움이 됩니다. 먼저 피부과 전문의와 상담 후 필요 시 성형외과로 의뢰받으시기 바랍니다.', 3915, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '흉터', '흉터', 'TREATMENT', '표피만 손상된 상처는 대부분 흉터 없이 치유됩니다. 상처를 청결하게 유지하고 습윤 드레싱, 감염 예방, 자외선 차단, 흉터 테이프 사용 등의 조치를 취하면 흉터를 최소화할 수 있습니다. 깊은 상처의 흉터 최소화를 위한 방법은 피부과 또는 외과 전문의와 상담하시기 바랍니다.', 3916, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '공기가슴증(기흉)', '공기가슴증(기흉)', 'PREVENTION', '기흉 예방을 위한 가장 중요한 습관은 금연입니다. 급격한 기압 변화를 유발하는 활동을 피하고, 기흉 병력이 있다면 흉부외과 전문의의 추적 관리를 받으시기 바랍니다.', 3917, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '공기가슴증(기흉)', '공기가슴증(기흉)', 'CAUSE', '기흉은 폐에 구멍이 생겨 공기가 흉막강으로 누출되는 질환으로, 키가 크고 마른 젊은 남성에서 잘 생기는 원발성 기흉과 폐 기저 질환에 의한 이차성 기흉이 있습니다. 예방을 위해서는 금연, 격렬한 운동 주의, 급격한 기압 변화 회피가 중요합니다. 흉부외과 전문의의 진료를 받으시기 바랍니다.', 3918, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '공기가슴증(기흉)', '공기가슴증(기흉)', 'DEFINITION', '기흉(공기가슴증)은 공기가 흉막강에 차면서 폐가 허탈되는 질환입니다. 크게 자연 기흉, 외상성 기흉, 긴장성 기흉으로 분류됩니다. 증상 발생 시 즉시 흉부외과 진료를 받으시기 바랍니다.', 3919, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '공기가슴증(기흉)', '공기가슴증(기흉)', 'SYMPTOM', '기흉의 주요 증상은 갑작스러운 흉통과 호흡 곤란이며, 폐가 허탈되어 가스 교환이 감소하기 때문입니다. 긴장성 기흉으로 진행 시 응급 상황이 될 수 있으므로, 이러한 증상이 나타나면 즉시 응급실을 방문하시기 바랍니다.', 3920, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '공기가슴증(기흉)', '공기가슴증(기흉)', 'DIAGNOSIS', '기흉과 유사한 증상이 있을 때는 흉부외과 또는 호흡기내과를 방문하면 됩니다. 진단을 위해 흉부 X선 촬영이 1차 검사로 시행됩니다. 증상이 심하거나 갑작스럽게 악화된다면 응급실을 통해 즉각적인 처치를 받으시기 바랍니다.', 3921, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '공기가슴증(기흉)', '공기가슴증(기흉)', 'TREATMENT', '기흉의 치료는 크기와 증상에 따라 다릅니다. 소량의 기흉은 안정과 산소 투여만으로 자연 흡수되기도 하며, 중등 이상이면 흉관 삽입이 필요합니다. 재발이 잦거나 크기가 큰 경우에는 흉강경 수술이 가장 효과적입니다. 치료 방법은 흉부외과 전문의와 상담 후 결정하시기 바랍니다.', 3922, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '급성 기관지염', '급성기관지염', 'DIET_LIFE', '급성 기관지염에 도움이 되는 음식으로는 따뜻한 물·생강차·꿀차 등 수분 보충에 좋은 음료, 항염 효과가 있는 생강·마늘, 비타민 C가 풍부한 과일·채소가 있습니다. 반면 유제품, 찬 음식, 카페인·알코올은 피하는 것이 좋습니다. 증상이 1주 이상 지속되거나 심해지면 호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3923, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '급성 기관지염', '급성기관지염', 'MEDICATION', '급성 기관지염 관리를 위한 일상 습관으로는 충분한 수분 섭취, 실내 습도 50~60% 유지, 금연 및 간접흡연 회피, 손 씻기 등 위생 관리, 충분한 휴식과 수면이 중요합니다. 증상이 지속되거나 악화된다면 내과·호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3924, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '급성 기관지염', '급성기관지염', 'PREVENTION', '급성 기관지염 증상 완화를 위한 수분 섭취는 하루 1.5~2L 이상의 따뜻한 물·차를 규칙적으로 마시는 것이 권장됩니다. 실내 습도는 50~60%로 유지하는 것이 적절하며, 가습기 사용 시 매일 청소하여 세균 오염을 방지해야 합니다. 증상이 2주 이상 지속된다면 내과 전문의의 진료를 받으시기 바랍니다.', 3925, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '급성 기관지염', '급성기관지염', 'CAUSE', '급성 기관지염의 원인은 90% 이상이 바이러스 감염으로, 감기를 유발하는 다양한 호흡기 바이러스가 원인이 됩니다. 세균 감염이 원인인 경우도 있으며, 이 경우 항생제 치료가 필요합니다. 기침이 2~3주 이상 지속되거나 고열·화농성 가래가 있다면 내과 전문의의 진료를 받으시기 바랍니다.', 3926, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '급성 기관지염', '급성기관지염', 'DEFINITION', '급성 기관지염은 기관지 점막에 급성 염증이 발생하는 질환으로, 기침·가래가 주 증상이며 대부분 바이러스 감염에 의해 발생합니다. 증상이 길어지면 만성 기관지염이나 폐렴을 감별해야 합니다. 증상이 심하거나 2주 이상 지속된다면 호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3927, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '급성 기관지염', '급성기관지염', 'SYMPTOM', '급성 기관지염에서 추위나 찬 공기 노출은 기도를 자극하여 기침 발작·기관지 경련을 악화시킬 수 있습니다. 기침이 심하고 호흡 곤란이 동반된다면 천식·폐렴과의 감별을 위해 호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3928, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '급성 기관지염', '급성기관지염', 'DIAGNOSIS', '기침이 지속되고 기관지염이 의심된다면 내과를 방문하면 됩니다. 진단을 위해 청진 검사, 흉부 X선 촬영, 필요 시 폐 기능 검사를 시행합니다. 증상 발생 후 2~3주 이상 기침이 지속된다면 조기에 전문의 진료를 받으시기 바랍니다.', 3929, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '급성 기관지염', '급성기관지염', 'TREATMENT', '급성 기관지염의 가래를 줄이기 위한 치료 방법으로는 충분한 수분 섭취, 거담제, 생리식염수 흡입, 따뜻한 증기 흡입 등이 효과적입니다. 가래가 2주 이상 지속되거나 피가 섞인다면 내과·호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3930, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '농흉', '농흉', 'MEDICATION', '항생제 치료 중에도 농흉에서 균이 검출되지 않는 경우는 배양 검체 채취 전 항생제를 이미 사용했거나 일반 배양에서 잘 자라지 않는 균종이 원인일 때 흔히 발생합니다. 균이 검출되지 않더라도 임상 증상과 영상 소견에 따라 치료를 지속하며 전문의와 상담하시기 바랍니다.', 3931, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '농흉', '농흉', 'PREVENTION', '농흉 예방을 위해 폐렴·흉막염 등 원인 감염을 조기에 치료하는 것이 중요합니다. 인플루엔자·폐렴구균 예방접종으로 감염 자체를 예방하는 것도 효과적입니다. 기침과 흉통이 2주 이상 지속되면 호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3932, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '농흉', '농흉', 'CAUSE', '농흉은 흉막강에 고름이 차는 질환으로, 주로 폐렴·폐농양의 합병증으로 발생합니다. 흉통, 호흡 곤란, 발열, 피로감이 나타납니다. 증상이 의심된다면 흉부외과 또는 호흡기내과 전문의를 통해 진단과 치료를 받으시기 바랍니다.', 3933, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '농흉', '농흉', 'REHAB', '농흉으로 인한 흉막강 감염 후 폐 건강 재활은 흉부 물리치료와 호흡 재활로 폐 용량을 회복시키는 방식으로 이루어집니다. 걷기·가벼운 유산소 운동을 점진적으로 시작해 심폐 기능을 강화합니다. 재활 프로그램은 흉부외과·호흡기내과·재활의학과 전문의의 지도 하에 진행하시기 바랍니다.', 3934, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '농흉', '농흉', 'DEFINITION', '농흉은 흉막강에 고름이 축적되는 감염성 질환으로, 주로 폐렴·폐농양·흉부 외상·수술 합병증으로 발생합니다. 발열, 흉통, 호흡 곤란, 전신 무기력감이 주요 증상이며, 치료는 항생제 및 흉관 배액이 필요합니다. 흉부외과 전문의의 진료를 받으시기 바랍니다.', 3935, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '농흉', '농흉', 'SYMPTOM', '농흉 초기에 감기 몸살과 유사한 증상이 나타나는 이유는 흉막강 내 세균 감염으로 인해 전신 염증 반응이 유발되기 때문입니다. 감기 증상이 2주 이상 호전되지 않거나 흉통이 동반되면 흉부외과 전문의의 진료를 조기에 받으시기 바랍니다.', 3936, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '농흉', '농흉', 'DIAGNOSIS', '농흉 진단을 위한 영상 검사로는 흉부 X선이 1차 검사이며, 흉부 CT는 농흉 범위와 원인 병변을 정확히 평가하는 데 필수적입니다. 흉막 천자로 농흉과 삼출성 흉막염을 감별하고 원인균을 규명합니다. 흉부외과·호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3937, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '농흉', '농흉', 'TREATMENT', '농흉 수술 후에는 항생제 치료를 지속하고, 흉관 관리, 폐 재팽창을 위한 심호흡 운동 및 흉부 물리치료가 필요합니다. 부작용으로는 흉관 주변 통증, 흉터, 드물게 출혈·재감염이 나타날 수 있습니다. 수술 후 경과 관리는 흉부외과 전문의의 지속적인 추적 관찰을 통해 이루어져야 합니다.', 3938, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '늑막염', '늑막염', 'CAUSE', '늑막염의 원인으로는 바이러스 감염, 세균성 폐렴의 합병증, 결핵, 자가면역 질환, 악성 종양, 폐색전증 등이 있습니다. 흉통·호흡 곤란이 있다면 내과·호흡기내과 전문의를 방문하시기 바랍니다.', 3939, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '늑막염', '늑막염', 'DEFINITION', '늑막염은 폐를 감싸는 흉막에 염증이 발생하는 질환으로, 호흡 시 날카로운 흉통, 호흡 곤란, 발열, 기침이 나타납니다. 원인은 감염, 자가면역 질환, 종양 등 다양합니다. 증상이 의심되면 호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3940, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '늑막염', '늑막염', 'SYMPTOM', '늑막염의 주요 증상 중 하나는 호흡 시 악화되는 날카로운 흉통이며, 흉막액이 많이 차면 폐를 압박하여 실제 호흡 곤란이 심해질 수 있습니다. 최근 숨 쉬기 힘든 증상이 있다면 내과·호흡기내과 전문의를 방문해 정확한 진단을 받으시기 바랍니다.', 3941, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '늑막염', '늑막염', 'DIAGNOSIS', '왼쪽 가슴 답답함과 호흡 곤란은 늑막염 외에도 심장 질환·폐렴·기흉 등 다양한 원인으로 발생할 수 있으므로 빠른 진찰이 필요합니다. 증상이 갑작스럽거나 심하다면 응급실을 먼저 방문하시기 바랍니다.', 3942, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '늑막염', '늑막염', 'TREATMENT', '늑막염의 가장 효과적인 치료는 원인 질환을 치료하는 것입니다. 바이러스성은 소염진통제·콜히친으로 통증과 염증을 조절하고, 세균성·결핵성은 항생제·항결핵제를 사용합니다. 흉막액이 많이 찬 경우 흉막 천자로 증상을 완화하며, 호흡기내과 전문의와 상담하시기 바랍니다.', 3943, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 기관지염', '만성기관지염', 'MEDICATION', '거담제는 기관지 점액의 점도를 낮추고 섬모 운동을 활성화하여 가래 배출을 용이하게 합니다. 항생제는 세균의 세포벽 합성 억제, 단백질 합성 차단 등의 기전으로 세균을 사멸하거나 증식을 억제합니다. 두 약물은 기전과 목적이 다르므로 사용 전 의사 또는 약사와 상담하시기 바랍니다.', 3944, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 기관지염', '만성기관지염', 'PREVENTION', '만성 기관지염 예방을 위해 인플루엔자 백신과 폐렴구균 백신 접종이 권장됩니다. 인플루엔자 백신은 매년 접종하며, 폐렴구균 백신은 65세 이상 또는 만성 폐질환자에게 특히 중요합니다. 접종 시기와 종류에 대해서는 호흡기내과 전문의와 상담하시기 바랍니다.', 3945, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 기관지염', '만성기관지염', 'CAUSE', '흡연은 기관지 점막을 지속적으로 자극하고 섬모 기능을 손상시켜 만성 기관지염을 유발합니다. 비흡연자의 경우 장기간 미세먼지·대기오염 노출, 직업성 분진, 반복적인 호흡기 감염, 유전적 요인 등이 원인이 될 수 있습니다. 정확한 원인 파악과 치료를 위해 호흡기내과 전문의 진료를 받으시기 바랍니다.', 3946, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 기관지염', '만성기관지염', 'DEFINITION', '만성 기관지염은 다른 폐질환 없이 2년 연속으로 각 연도에 3개월 이상 기침과 가래가 지속되는 상태로 정의됩니다. 기관지 점막의 만성 염증으로 점액 분비선이 비대해지고 과분비가 일어나는 것이 특징입니다. 증상이 지속된다면 호흡기내과에서 정확한 진단을 받으시기 바랍니다.', 3947, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 기관지염', '만성기관지염', 'SYMPTOM', '만성 기관지염의 대표적인 증상은 오전에 심한 생산성 기침이 수개월 이상 지속되는 것입니다. 호흡 시 쌕쌕거림, 숨 가쁨, 가슴 답답함도 나타날 수 있습니다. 호흡기내과에서 폐기능 검사 등을 받아보시도록 권유해 드립니다.', 3948, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 기관지염', '만성기관지염', 'DIAGNOSIS', '마른 기침과 가래가 지속될 경우 호흡기내과를 방문하시는 것이 적합합니다. 진단을 위해 흉부 X선, 폐기능 검사, 객담 검사 등을 시행합니다. 증상이 8주 이상 지속된다면 지체 없이 전문의 진료를 받으시기 바랍니다.', 3949, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 기관지염', '만성기관지염', 'TREATMENT', '만성 기관지염은 완치보다는 증상 관리와 악화 방지에 초점을 맞추며, 금연이 가장 중요한 첫 번째 조치입니다. 호흡재활운동, 규칙적인 유산소 운동, 충분한 수분 섭취가 도움이 됩니다. 구체적인 치료 계획은 호흡기내과 전문의와 상담하여 개인 상태에 맞게 수립하시기 바랍니다.', 3950, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 기침', '만성기침', 'CAUSE', '알코올은 기도 점막의 섬모 운동을 억제하고 위식도 역류를 악화시켜 만성 기침을 유발할 수 있습니다. 면역 기능을 저하시켜 반복적인 호흡기 감염을 일으키고 기침 반사를 증가시킵니다. 만성 기침이 지속된다면 호흡기내과 전문의를 통해 원인을 정확히 파악하시기 바랍니다.', 3951, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 기침', '만성기침', 'DEFINITION', '만성 기침은 성인에서 8주 이상 지속되는 기침으로 정의되며, 목 이물감, 후비루, 쉰 목소리, 흉부 불쾌감, 야간 기침으로 인한 수면 장애 등이 동반될 수 있습니다. 8주 이상 지속 시 호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3952, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 기침', '만성기침', 'SYMPTOM', '가래가 8주 이상 지속될 경우 만성 기도 질환을 시사하며, 가래의 색, 양, 지속 시간은 원인 질환을 감별하는 데 중요한 단서가 됩니다. 이러한 증상이 지속된다면 호흡기내과 전문의의 진료와 검사를 받으시기 바랍니다.', 3953, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 기침', '만성기침', 'DIAGNOSIS', '8주 이상 기침이 지속된다면 호흡기내과 또는 내과를 방문하시면 됩니다. 방문 전 기침 시작 시점, 동반 증상, 복용 약물 등을 정리해 두시면 진단에 도움이 됩니다.', 3954, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 기침', '만성기침', 'TREATMENT', '만성 기침과 천식이 공존할 경우 기침 유발 원인을 순차적으로 찾아 각각 치료하는 단계적 접근이 기본 원칙입니다. 기침형 천식은 흡입 스테로이드 치료로 효과적으로 관리됩니다. 두 질환의 정확한 감별과 치료 방향은 호흡기내과 또는 알레르기내과 전문의와 상담하시기 바랍니다.', 3955, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 폐쇄성 폐질환', '만성폐쇄성폐질환', 'CHECKUP', '흡연은 COPD의 가장 중요한 위험 인자로, 흡연량이 많고 기간이 길수록 기류 제한이 심해져 호흡곤란, 만성 기침, 가래 등의 증상이 더 뚜렷하게 나타납니다. 금연이 진행을 늦추는 가장 효과적인 방법이므로, 흡연자이거나 호흡기 증상이 있다면 호흡기내과에서 폐기능 검사를 받아보시기 바랍니다.', 3956, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 폐쇄성 폐질환', '만성폐쇄성폐질환', 'DIET_LIFE', 'COPD 환자에게 금연은 가장 중요한 첫 번째 조치이며, 니코틴 대체 요법이나 금연 클리닉을 적극적으로 활용하시기 바랍니다. 인플루엔자·폐렴구균 예방접종으로 급성 악화를 예방하고, 처방된 흡입제를 규칙적으로 사용하며 호흡기내과 전문의의 정기 추적 관찰을 받으시기 바랍니다.', 3957, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 폐쇄성 폐질환', '만성폐쇄성폐질환', 'MEDICATION', 'COPD 치료에 사용되는 기관지확장제와 일부 감기약을 동시 복용하면 기도 분비물이 굳어지거나 소변 저류, 심박수 증가 등의 부작용이 발생할 수 있습니다. 감기약 복용 전 반드시 처방 의사 또는 약사에게 현재 복용 중인 COPD 약물을 알리고 상담하시기 바랍니다.', 3958, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 폐쇄성 폐질환', '만성폐쇄성폐질환', 'PREVENTION', '40대 흡연 남성이 금속 납땜 등 유해 흄에 노출되는 직업 환경이라면 COPD 발생 위험이 매우 높으므로 즉시 금연하는 것이 가장 중요합니다. 작업 시 반드시 방진·방독 마스크를 착용하고, 작업장의 환기 시설을 개선해야 합니다. 호흡기내과 전문의의 정기적인 관리를 받으시기 바랍니다.', 3959, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 폐쇄성 폐질환', '만성폐쇄성폐질환', 'EXERCISE', 'COPD 환자의 호흡 증상 완화에는 복식호흡과 입술 오므리기 호흡이 효과적이며, 전문적인 호흡재활 프로그램 참여가 권장됩니다. 통증이나 심한 호흡 곤란이 동반된다면 호흡기내과 전문의와 상담하여 안전한 운동 처방을 받으시기 바랍니다.', 3960, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 폐쇄성 폐질환', '만성폐쇄성폐질환', 'CAUSE', 'COPD의 가장 주요한 원인은 흡연이며, 전 세계 환자의 약 80~90%가 흡연자입니다. 흡연 외에도 직업적 분진·화학물질 노출, 실내 바이오매스 연료 연기, 반복적인 호흡기 감염, 유전적 요인도 원인이 됩니다. 호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3961, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 폐쇄성 폐질환', '만성폐쇄성폐질환', 'REHAB', 'COPD 재활치료의 핵심은 호흡재활 프로그램으로, 호흡 근육 강화 훈련, 유산소 운동 훈련, 저항 운동이 포함됩니다. 체계적인 재활치료를 위해 호흡기내과 또는 재활의학과 전문의의 지도 하에 개인 맞춤형 프로그램을 시작하시기 바랍니다.', 3962, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 폐쇄성 폐질환', '만성폐쇄성폐질환', 'DEFINITION', 'COPD는 만성 기관지염과 폐기종 두 가지 병리가 혼재하는 경우가 많습니다. 기침·가래는 기도 병변이 더 심할 때, 호흡 곤란은 폐기종이 더 심할 때 두드러지게 나타납니다. 폐기능 검사와 흉부 CT를 통해 확인할 수 있으므로 호흡기내과 전문의의 진료를 받으시기 바랍니다.', 3963, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 폐쇄성 폐질환', '만성폐쇄성폐질환', 'SYMPTOM', '장기 흡연자는 흡연 기간과 흡연량에 비례하여 폐기능이 점차 저하되므로 COPD 증상이 더 심하고 악화 빈도도 높게 나타납니다. 흡연 기간이 길수록 조기에 호흡기내과 전문의를 방문하여 폐기능 검사와 적절한 치료를 받으시기 바랍니다.', 3964, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 폐쇄성 폐질환', '만성폐쇄성폐질환', 'DIAGNOSIS', '흡연자가 폐기능 검사를 받으면 기관지확장제 흡입 후 FEV1/FVC 비율이 0.7 미만으로 나타나는 기류 제한 소견을 받을 수 있으며, 이것이 COPD 진단의 핵심 기준입니다. 흡연자라면 증상이 없더라도 40세 이후부터 정기적인 폐기능 검사를 받아 조기 진단에 힘쓰시기 바랍니다.', 3965, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '만성 폐쇄성 폐질환', '만성폐쇄성폐질환', 'TREATMENT', 'COPD의 기본 치료는 금연이며, 약물 치료로는 흡입 기관지확장제가 1차 약제로 사용되고 중증 이상에서는 흡입 스테로이드가 추가됩니다. 치료 방법과 약제 선택은 중증도와 개인 상태에 따라 다르므로 호흡기내과 전문의와 상담하시기 바랍니다.', 3966, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '백일해', '백일해', 'PREVENTION', '백일해 예방접종을 받았더라도 시간이 지나면 면역이 감소하므로 신생아 주변의 성인은 Tdap 추가 접종을 받는 것이 권장됩니다. 임산부는 임신 27~36주 사이에 Tdap 접종을 받으면 신생아에게 항체를 전달하여 보호 효과를 높일 수 있습니다. 구체적인 접종 일정은 소아과 또는 가정의학과 전문의와 상담하시기 바랍니다.', 3967, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '백일해', '백일해', 'CAUSE', '성인에서 백일해 예방접종 후 시간이 지나면 면역 효과가 감소하여 면역 공백이 생기고, 이것이 성인 백일해 감염의 주요 원인 중 하나입니다. 면역력 유지와 감염 예방을 위해 예방접종 이력을 확인하고 필요 시 Tdap을 접종받으시기 바랍니다.', 3968, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '백일해', '백일해', 'DEFINITION', '백일해는 보르데텔라 퍼투시스균에 의한 급성 호흡기 감염병으로, 경련성 발작 기침이 반복되며 기침 끝에 특징적인 흡기 소리가 들리고 구토가 동반됩니다. 영아에서는 생명을 위협할 수 있으므로 의심 시 즉시 소아과 전문의를 방문하시기 바랍니다.', 3969, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '백일해', '백일해', 'SYMPTOM', '백일해는 호흡기 증상 외에도 기침 발작 후 구토, 식욕 감소, 체중 감소, 심한 피로감이 나타날 수 있습니다. 영아에서는 무호흡이나 청색증만 나타나는 경우도 있어 더욱 위험합니다. 이러한 증상이 보인다면 빠르게 소아과 또는 호흡기 전문의의 진료를 받으시기 바랍니다.', 3970, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '백일해', '백일해', 'DIAGNOSIS', '백일해 진단을 위해서는 소아과, 내과, 또는 감염내과를 방문하시면 됩니다. 진단 검사로는 비인두 분비물의 PCR 검사가 가장 정확합니다. 전문의의 진료 후 적절한 검사를 받으시기 바랍니다.', 3971, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '백일해', '백일해', 'TREATMENT', '영아의 백일해 치료에는 아지스로마이신이나 클라리스로마이신 같은 마크롤라이드 계열 항생제가 1차 치료제로 사용됩니다. 영아는 입원하여 호흡 상태와 산소 포화도를 집중 모니터링하며 치료합니다. 치료 방향은 반드시 소아과 전문의의 처방과 지도에 따르시기 바랍니다.', 3972, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '병원 감염성 폐렴', '병원감염성폐렴', 'PREVENTION', '병원 감염성 폐렴 예방을 위해 손 위생이 가장 중요하며, 면역력이 저하된 환자는 인플루엔자 및 폐렴구균 예방접종을 미리 받고 기저질환을 적절히 관리하는 것이 도움이 됩니다. 입원 중 호흡기 증상이 새로 나타나면 즉시 담당 의료진에게 알리시기 바랍니다.', 3973, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '병원 감염성 폐렴', '병원감염성폐렴', 'CAUSE', '병원 감염성 폐렴은 직접 접촉, 오염된 의료 기구, 의료진의 손을 통해 다른 기저 질환자에게 전파될 수 있습니다. 특히 면역 저하 환자, 중환자실 환자에서 전파 및 발병 위험이 높습니다. 전파 차단을 위해 격리 조치, 보호 장구 착용, 철저한 손 위생이 필수적입니다.', 3974, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '병원 감염성 폐렴', '병원감염성폐렴', 'DEFINITION', '병원 감염성 폐렴은 입원 전에는 없던 폐렴이 입원 후 48시간 이상 경과 후에 발생한 경우를 말합니다. 원인균도 지역사회 폐렴과는 다릅니다. 의심 시 즉시 담당 의료진에게 알려 신속한 진단과 치료를 받으시기 바랍니다.', 3975, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '병원 감염성 폐렴', '병원감염성폐렴', 'SYMPTOM', '고열, 심한 오한, 흉통, 화농성 가래, 호흡 곤란은 병원 감염성 폐렴의 전형적인 증상입니다. 입원 48시간 이후 이러한 증상이 새로 나타나거나 기존 증상이 갑자기 악화된다면 즉시 담당 의료진에게 알리시기 바랍니다.', 3976, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '병원 감염성 폐렴', '병원감염성폐렴', 'DIAGNOSIS', '병원 감염성 폐렴의 주요 원인균은 메티실린 내성 황색포도구균(MRSA), 녹농균, 아시네토박터균 등 항생제 내성이 강한 균이 많습니다. 객담 배양 검사와 항생제 감수성 검사로 원인균을 확인하며, 내성균 감염이 의심될 경우 감염내과 전문의의 협진이 필요합니다.', 3977, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '병원 감염성 폐렴', '병원감염성폐렴', 'TREATMENT', '병원 감염성 폐렴은 내성균 감염 가능성이 높고 중증으로 진행될 위험이 있어 입원하여 정맥 항생제 치료와 집중 모니터링이 필요합니다. 빠른 항생제 시작과 적절한 용량·기간 유지가 예후에 중요하므로 감염내과 전문의의 지도 하에 치료를 받으시기 바랍니다.', 3978, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '성인 호흡곤란 증후군', '성인호흡곤란증후군', 'CAUSE', '성인 호흡곤란 증후군(ARDS)에서 숨이 막히고 호흡이 힘들어지는 이유는 폐포-모세혈관막의 광범위한 손상으로 폐포에 염증성 부종액이 차서 산소 교환이 심각하게 저하되기 때문입니다. 이 증상은 응급 상황이므로 즉시 응급실을 방문하거나 119에 신고하시기 바랍니다.', 3979, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '성인 호흡곤란 증후군', '성인호흡곤란증후군', 'DEFINITION', '폐렴 이후에도 호흡 곤란이 지속되거나 악화된다면 ARDS로의 진행 가능성이 있습니다. ARDS는 심한 저산소혈증, 흉부 X선에서 양측 폐 침윤, 빠른 호흡이 특징입니다. 호흡이 오히려 나빠진다면 즉시 담당 의료진에게 알리거나 응급실을 방문하시기 바랍니다.', 3980, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '성인 호흡곤란 증후군', '성인호흡곤란증후군', 'SYMPTOM', '가슴 압박감과 빠른 호흡이 지속된다면 즉시 119에 신고하거나 응급실을 방문하는 것이 최우선입니다. ARDS는 빠르게 악화될 수 있는 응급 상황으로 자가 치료나 경과 관찰은 매우 위험합니다.', 3981, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '성인 호흡곤란 증후군', '성인호흡곤란증후군', 'DIAGNOSIS', 'ARDS 진단에서 흉부 X선은 양측 폐 침윤 확인에 사용되며, 흉부 CT는 폐 손상의 범위와 분포를 더 정확하게 평가합니다. 정확한 진단과 중증도 판정을 위해서는 중환자의학과 또는 호흡기내과 전문의의 종합적인 판단이 필요합니다.', 3982, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '성인 호흡곤란 증후군', '성인호흡곤란증후군', 'TREATMENT', 'ARDS 치료의 핵심은 중환자실에서의 기계 환기 치료이며, 폐 보호 환기 전략이 표준 치료법입니다. 복와위 환기, 신경근 차단제 사용, 적절한 수액 관리도 중요한 치료 요소입니다. 즉시 응급실을 방문하여 중환자의학과 전문의의 평가와 치료를 받으시기 바랍니다.', 3983, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '신종 플루', '신종플루', 'PREVENTION', '신종 플루 예방을 위해 매년 인플루엔자 예방접종을 받는 것이 가장 효과적입니다. 손을 자주 씻고, 기침 예절을 지키며, 사람이 많은 곳에서 마스크를 착용하고, 호흡기 증상이 있을 경우 외출을 자제하는 것이 중요합니다. 고위험군은 특히 예방접종을 빠짐없이 받으시기 바랍니다.', 3984, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '신종 플루', '신종플루', 'CAUSE', '인플루엔자 바이러스는 주로 동물에서 인간으로 전파되며, 바이러스가 동물과 인간 사이를 넘나들 때 유전자 재조합이 일어나 신종 플루 같은 새로운 변종 바이러스가 생성될 수 있습니다. 감염 예방을 위해 조류·돼지 등 동물과의 직접 접촉을 최소화하시기 바랍니다.', 3985, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '신종 플루', '신종플루', 'DEFINITION', '신종 플루와 A형 독감은 모두 인플루엔자 A 바이러스에 의한 감염병이지만, 신종 플루는 기존 인구 집단에 면역이 없는 새로운 변종 바이러스로 발생한 유행을 지칭합니다. 각 질환의 정확한 진단과 치료를 위해서는 감염내과 또는 내과 전문의의 진료를 받으시기 바랍니다.', 3986, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '신종 플루', '신종플루', 'SYMPTOM', '신종 플루는 일반 감기보다 발열(38°C 이상), 오한, 근육통, 두통 등 전신 증상이 훨씬 심하고 갑작스럽게 나타나는 것이 특징입니다. 두 질환의 구별이 필요하거나 증상이 심하다면 내과 또는 감염내과 전문의의 진료를 받으시기 바랍니다.', 3987, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '신종 플루', '신종플루', 'DIAGNOSIS', '고열, 기침, 근육통 등의 증상이 갑자기 나타난다면 인플루엔자 감염을 의심할 수 있습니다. 증상 발생 48시간 이내에 진단받는 것이 치료 효과를 높이므로, 내과 또는 감염내과를 방문하시기 바랍니다.', 3988, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '신종 플루', '신종플루', 'TREATMENT', '인플루엔자 백신은 접종 후에도 감염될 수 있으나, 접종자는 감염되더라도 증상이 경미하고 합병증 위험이 낮습니다. 감염이 확인되면 증상 발생 48시간 이내에 오셀타미비르 등 항바이러스제를 투여받는 것이 효과적이며, 치료 방향은 내과 전문의와 상담하시기 바랍니다.', 3989, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '인플루엔자', '인플루엔자', 'DIET_LIFE', '인플루엔자 예방을 위해 단백질과 비타민이 풍부한 균형 잡힌 식사, 충분한 수면, 규칙적인 운동으로 면역력을 유지하는 것이 중요합니다. 외출 후 손을 자주 씻고, 사람이 밀집한 공간에서는 마스크를 착용하는 생활 습관이 도움이 됩니다. 고위험군이라면 매년 10~11월 예방접종을 받으시기 바랍니다.', 3990, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '인플루엔자', '인플루엔자', 'MEDICATION', '인플루엔자 치료에 사용되는 항바이러스제로는 오셀타미비르(타미플루), 자나미비르(리렌자), 발록사비르(조플루자) 등이 있으며, 증상 발생 48시간 이내에 복용 시 효과가 가장 큽니다. 처방 없이 임의로 복용하면 내성이 생길 수 있으므로 반드시 내과 전문의의 처방에 따라 복용하시기 바랍니다.', 3991, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '인플루엔자', '인플루엔자', 'PREVENTION', '인플루엔자 예방접종은 감염 확률을 낮추고 중증 합병증을 예방하는 가장 효과적인 수단입니다. 인플루엔자 바이러스는 매년 변이를 일으키므로 매년 새로운 백신을 접종해야 하며, 고위험군은 반드시 접종이 필요합니다.', 3992, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '인플루엔자', '인플루엔자', 'CAUSE', '동물 인플루엔자 인체감염증은 주로 감염된 조류·돼지 등과의 직접적인 접촉을 통해 발생합니다. 감염 예방을 위해 동물 밀집 지역 방문을 자제하고, 호흡기 증상 발생 시 감염내과 전문의를 방문하시기 바랍니다.', 3993, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '인플루엔자', '인플루엔자', 'DEFINITION', '인플루엔자 바이러스는 오르토믹소바이러스과에 속하며, 표면 단백질인 헤마글루티닌(H)과 뉴라미니다아제(N)의 조합에 따라 분류됩니다. A형은 변이가 가장 다양하고 대유행을 일으킬 수 있으며, B형은 주로 계절성 독감을 유발합니다. 더 자세한 정보는 감염내과 또는 내과 전문의와 상담하시기 바랍니다.', 3994, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '인플루엔자', '인플루엔자', 'SYMPTOM', '조류 인플루엔자 인체감염증은 감염된 가금류 또는 오염된 환경에 직접 접촉한 후 발병하며, 고열, 심한 호흡기 증상, 폐렴으로 빠르게 진행되는 것이 특징입니다. 조류 접촉력이 있고 고열·호흡기 증상이 나타난다면 즉시 보건소나 감염내과 전문의를 방문하시기 바랍니다.', 3995, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '인플루엔자', '인플루엔자', 'DIAGNOSIS', '조류 인플루엔자 진단은 비인두 또는 하기도 검체를 이용한 PCR 검사가 가장 정확합니다. 조류 접촉 이력, 유행 지역 방문력, 고열과 빠른 폐렴 진행 여부가 중요한 감별 포인트입니다. 의심 시 감염병 전담 의료기관이나 보건소에 연락하시기 바랍니다.', 3996, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '인플루엔자', '인플루엔자', 'TREATMENT', '인플루엔자 예방접종 후에도 바이러스에 감염될 경우 항바이러스제 치료를 동일하게 시행하며, 증상 발생 48시간 이내 복용이 가장 효과적입니다. 증상이 심하거나 고위험군에 해당한다면 즉시 의료기관을 방문하시기 바랍니다.', 3997, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '중동 호흡기 증후군', '중동호흡기증후군', 'PREVENTION', '중동 호흡기 증후군(MERS) 예방을 위해 중동 지역 방문 시 낙타와의 직접 접촉을 피하고, 손 위생을 철저히 하며 의료기관 방문을 최소화해야 합니다. 중동 방문 후 14일 이내에 발열·호흡기 증상이 나타나면 즉시 1339에 신고하고 감염내과 전문의의 진료를 받으시기 바랍니다.', 3998, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '중동 호흡기 증후군', '중동호흡기증후군', 'CAUSE', 'MERS는 MERS-CoV에 의해 발생하며, 낙타가 주요 동물 숙주입니다. 낙타와의 직접 접촉이나 감염된 환자와의 밀접 접촉으로 전파됩니다. MERS 관련 증상이나 의심 노출이 있다면 즉시 감염내과 전문의 또는 보건 당국에 연락하시기 바랍니다.', 3999, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '중동 호흡기 증후군', '중동호흡기증후군', 'REHAB', 'MERS 회복 후 흉통과 호흡 곤란이 지속된다면 호흡재활 프로그램을 통해 증상을 완화할 수 있으며, 복식호흡과 입술 오므리기 호흡 훈련이 기본적으로 권장됩니다. 증상이 지속된다면 호흡기내과 또는 재활의학과 전문의와 상담하시기 바랍니다.', 4000, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '중동 호흡기 증후군', '중동호흡기증후군', 'DEFINITION', 'MERS와 코로나-19는 모두 코로나바이러스과 바이러스에 의한 호흡기 감염병으로 유사한 감염 경로를 가지고 있습니다. MERS-CoV는 치명률이 약 35%로 높은 반면, COVID-19는 사람 간 전파력이 훨씬 강하고 전 세계적 대유행을 일으켰다는 차이가 있습니다. 의심 시 즉시 의료 당국에 신고하시기 바랍니다.', 4001, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '중동 호흡기 증후군', '중동호흡기증후군', 'SYMPTOM', 'MERS의 주요 증상으로는 고열(38°C 이상), 기침, 호흡 곤란이 대표적이며, 설사 등 소화기 증상도 일부 환자에서 동반될 수 있습니다. 중동 여행 후 14일 이내에 이러한 증상이 나타난다면 즉시 1339에 신고하고 감염내과 전문의의 진료를 받으시기 바랍니다.', 4002, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '중동 호흡기 증후군', '중동호흡기증후군', 'DIAGNOSIS', 'MERS는 최근 14일 이내 중동 방문 또는 확진자와의 밀접 접촉이 가장 중요한 감별 포인트이며, 확진은 PCR 검사로만 가능합니다. 역학적 위험 요인이 있고 고열과 호흡기 증상이 동반된다면 즉시 격리 후 감염내과 전문의 및 보건 당국에 신고하시기 바랍니다.', 4003, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '중동 호흡기 증후군', '중동호흡기증후군', 'TREATMENT', 'MERS의 호흡 곤란 완화를 위해서는 산소 투여와 필요 시 기계 환기 치료가 사용됩니다. 현재까지 MERS에 대한 공인된 특이 항바이러스 치료제는 없으며 대증적·지지적 치료가 중심입니다. 모든 치료는 격리된 의료 환경에서 감염내과 전문의의 지도하에 시행됩니다.', 4004, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '중증 급성 호흡기 증후군', '중증급성호흡기증후군', 'MEDICATION', '중증 급성 호흡기 증후군(SARS) 치료에 사용된 주요 약물로는 리바비린과 스테로이드가 있었으나, 두 약물 모두 명확한 효능 근거가 부족하고 부작용이 보고된 바 있습니다. 현재는 대증·지지 치료가 표준이며, 치료 약물 선택은 반드시 감염내과 전문의의 판단에 따라야 합니다.', 4005, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '중증 급성 호흡기 증후군', '중증급성호흡기증후군', 'PREVENTION', 'MERS 또는 중증 호흡기 감염 이후 지속적인 스트레스와 불안을 완화하기 위해 규칙적인 이완 기법(복식호흡, 점진적 근육 이완법, 명상)을 실천하고 규칙적인 수면과 적절한 신체 활동을 유지하는 것이 도움이 됩니다. 스트레스가 지속적으로 신체 증상과 연결된다면 정신건강의학과 전문의나 심리 상담사의 도움을 받는 것을 권장합니다.', 4006, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '중증 급성 호흡기 증후군', '중증급성호흡기증후군', 'CAUSE', '중증 급성 호흡기 증후군(SARS)은 SARS-CoV 바이러스가 하기도를 침범하면서 발생하며, 기존 만성 폐질환, 면역억제 상태, 흡연력이 있는 경우 더 심한 호흡기 손상으로 이어질 수 있습니다. 바이러스가 폐포 세포를 직접 파괴하고 과도한 면역반응(사이토카인 폭풍)을 유발해 급성 호흡부전으로 진행될 수 있습니다. 호흡기 증상이 있다면 즉시 전문의 진료를 받으시기 바랍니다.', 4007, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '중증 급성 호흡기 증후군', '중증급성호흡기증후군', 'DEFINITION', '중증 급성 호흡기 증후군(SARS)은 SARS-CoV 바이러스에 의한 감염병으로, 고열(38℃ 이상), 기침, 호흡 곤란이 주요 증상이며 잠복기는 2~10일입니다. SARS 발생 국가 여행 후 10일 이내에 발열 및 호흡기 증상이 나타나면 즉시 보건 당국에 신고하고 격리 조치를 취해야 합니다. 자의적 판단보다는 즉시 전문의 또는 감염내과 진료를 받는 것이 중요합니다.', 4008, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '중증 급성 호흡기 증후군', '중증급성호흡기증후군', 'SYMPTOM', 'SARS의 기침, 호흡 곤란, 발열, 근육통은 SARS-CoV 바이러스가 기도 및 폐포 상피세포에 침투해 세포를 파괴하고 염증 매개물질을 대량 분비시키는 과정에서 발생합니다. 발열과 근육통은 면역계가 바이러스에 반응하여 인터류킨 등 사이토카인을 방출할 때 나타나며, 호흡 곤란은 폐포 손상으로 산소 교환이 저하되어 발생합니다. 이러한 증상이 의심될 경우 즉시 감염내과 전문의 진료가 필요합니다.', 4009, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '중증 급성 호흡기 증후군', '중증급성호흡기증후군', 'DIAGNOSIS', 'SARS 진단은 역학적 노출력 확인 후 혈액검사(PCR, 항체검사), 흉부 X선·CT 촬영, 바이러스 배양검사 순으로 진행됩니다. PCR 검사 결과는 통상 6~24시간 내에 확인 가능하며, 항체검사는 발병 후 2~4주가 지나야 양성이 나타날 수 있습니다. 검사 및 결과 확인 절차는 의료기관과 검사 방법에 따라 다르므로 감염내과 전문의의 안내를 따르시기 바랍니다.', 4010, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '중증 급성 호흡기 증후군', '중증급성호흡기증후군', 'TREATMENT', 'SARS 치료는 대증적 치료가 중심이며, 산소 공급 및 인공호흡기 치료 외에도 리바비린 등 항바이러스제와 스테로이드를 병용하는 방법이 시도되었습니다. 중증의 경우 집중치료실(ICU)에서의 체외막산소화(ECMO) 치료가 필요할 수 있으며, 세균 중복 감염 예방을 위한 항생제도 사용됩니다. 구체적인 치료 방침은 반드시 감염내과 전문의와 상담하여 결정하시기 바랍니다.', 4011, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '지역사회성 폐렴', '지역사회성폐렴', 'PREVENTION', '지역사회성 폐렴 예방을 위해서는 폐렴구균 백신 및 인플루엔자 백신 접종이 효과적이며, 특히 65세 이상 고령자와 만성 기저질환자에게 권고됩니다. 일상에서는 손 씻기, 기침 예절 준수, 금연, 과도한 음주 자제, 충분한 수면과 균형 잡힌 영양 섭취로 면역력을 유지하는 것이 중요합니다. 만성 질환이 있거나 면역이 저하된 경우 전문의 상담을 통해 개인별 예방 전략을 수립하시기 바랍니다.', 4012, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '지역사회성 폐렴', '지역사회성폐렴', 'CAUSE', '음주는 기침 반사와 점막 섬모 운동을 억제하고 면역세포 기능을 저하시켜 병원균이 폐로 침투하기 쉬운 환경을 만들며, 흡인성 폐렴의 위험도 높입니다. 흡연은 기관지 점막의 섬모를 손상시키고 폐 방어 기전을 약화시켜 폐렴구균, 인플루엔자균 등이 하기도에 정착하기 쉽게 합니다. 금연과 절주는 지역사회성 폐렴 예방에 직접적인 효과가 있으며, 구체적인 관리는 전문의와 상담하시기 바랍니다.', 4013, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '지역사회성 폐렴', '지역사회성폐렴', 'DEFINITION', '지역사회성 폐렴은 병원 밖에서 획득한 폐렴으로, 폐렴구균(Streptococcus pneumoniae)이 가장 흔한 원인균이며 마이코플라즈마, 헤모필루스 인플루엔자균 등도 원인이 됩니다. 2세 미만 영유아는 면역계가 미성숙하고 노령층은 면역 기능이 저하되어 있어 감염에 특히 취약합니다. 만성 심폐 질환, 당뇨병, 면역억제 상태 등도 발병 위험을 높이므로 전문의 상담을 통한 예방과 관리가 필요합니다.', 4014, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '지역사회성 폐렴', '지역사회성폐렴', 'SYMPTOM', '마이코플라즈마 폐렴 등 비정형 폐렴에서는 마른 기침이 수 주 동안 지속될 수 있으며, 이는 병원체가 기관지 점막을 자극하지만 삼출물 생성이 적기 때문입니다. 증상이 점진적으로 나타나는 것은 비정형 폐렴의 특징으로, 초기에는 두통·피로감·인후통이 먼저 생기고 이후 기침이 악화되는 양상을 보입니다. 마른 기침이 2주 이상 지속된다면 흉부 X선 검사 등을 위해 전문의 진료를 받으시기 바랍니다.', 4015, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '지역사회성 폐렴', '지역사회성폐렴', 'DIAGNOSIS', '지역사회성 폐렴 진단에서 흉부 X선 촬영이 기본 검사이며, X선으로 불명확할 경우 흉부 CT가 보다 정확한 정보를 제공합니다. 원인균 확인을 위해 객담 배양검사, 혈액배양, 소변 항원검사(폐렴구균·레지오넬라)를 시행하며, 중등도 이상의 경우 기관지내시경을 통한 검체 채취도 고려됩니다. 가장 정확한 진단을 위해서는 임상 증상, 영상 소견, 미생물 검사를 종합적으로 평가하는 전문의 진찰이 필수적입니다.', 4016, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '지역사회성 폐렴', '지역사회성폐렴', 'TREATMENT', '지역사회성 폐렴의 주된 치료는 원인균에 따른 항생제 투여이며, 경증은 아목시실린 또는 마크로라이드계 항생제를 경구 투여하고 중증은 입원하여 정맥 주사로 투여합니다. 비정형 폐렴이 의심되면 마크로라이드나 퀴놀론계 항생제를 사용하며, 바이러스성 폐렴은 항바이러스제를 적용합니다. 항생제 종류와 투여 기간은 반드시 전문의 처방에 따라야 하며, 임의 중단 시 내성이 생길 수 있으므로 주의가 필요합니다.', 4017, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '천식', '천식', 'CHECKUP', '천식 검진 전에는 검사 24~48시간 전부터 기관지 확장제 사용을 중단하고(의사 지시에 따라), 격렬한 운동과 흡연을 피해야 정확한 폐기능 검사 결과를 얻을 수 있습니다. 검진 후에는 흡입 스테로이드 등 처방된 약물을 규칙적으로 사용하고, 악화 유발 요인(알레르겐, 찬 공기, 대기오염 등)을 피하는 생활 습관을 유지해야 합니다. 구체적인 검진 전후 주의사항은 담당 전문의의 지침을 따르시기 바랍니다.', 4018, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '천식', '천식', 'DIET_LIFE', '가정에서 천식 관리를 위해서는 집 먼지 진드기를 줄이기 위해 침구를 자주 세탁하고 카펫 사용을 최소화하며, 반려동물 털, 곰팡이, 바퀴벌레 등 알레르겐 노출을 줄이는 환경 관리가 중요합니다. 처방된 흡입기(완화제·조절제)를 올바른 방법으로 규칙적으로 사용하고, 증상 악화 시 즉시 사용할 수 있도록 항상 지참하는 것이 필요합니다. 자녀의 천식 조절 상태는 정기적으로 소아청소년과 또는 호흡기내과 전문의와 확인하시기 바랍니다.', 4019, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '천식', '천식', 'MEDICATION', '기관지 염증과 가래를 동반한 천식에서는 흡입 코르티코스테로이드(ICS)가 1차 조절 약물로 사용되며, 기관지 확장을 위해 지속성 베타2 항진제(LABA)를 병용하기도 합니다. 급성 증상 완화에는 속효성 베타2 항진제(살부타몰 등) 흡입제가 필요 시 사용되고, 가래가 많은 경우 점액용해제 추가를 고려할 수 있습니다. 약물 선택과 용량은 증상의 중증도에 따라 달라지므로 반드시 호흡기내과 전문의의 처방을 받으시기 바랍니다.', 4020, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '천식', '천식', 'PREVENTION', '기관지 천식 환자는 인플루엔자 감염 시 천식이 심하게 악화될 수 있어, 매년 독감 예방접종을 적극 권고합니다. 폐렴구균 백신도 함께 접종하면 하기도 감염 합병증 예방에 도움이 됩니다. 다만 달걀 알레르기 등 금기 사항이 있을 수 있으므로, 접종 전 반드시 담당 전문의와 상담하여 안전하게 접종받으시기 바랍니다.', 4021, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '천식', '천식', 'EXERCISE', '천식 환자는 차갑고 건조한 공기에서 시행하는 격렬한 유산소 운동(마라톤, 겨울 야외 달리기 등)이 운동 유발성 기관지 수축을 일으킬 수 있어 주의가 필요합니다. 수영은 따뜻하고 습한 환경에서 이루어져 천식 환자에게 비교적 안전한 운동으로 알려져 있으며, 운동 전 준비 운동과 처방된 흡입제 사전 사용이 도움이 됩니다. 운동 종류와 강도는 천식 조절 상태에 따라 개인차가 있으므로, 전문의와 상담 후 적절한 운동 계획을 수립하시기 바랍니다.', 4022, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '천식', '천식', 'CAUSE', '천식의 주요 원인으로는 집 먼지 진드기, 꽃가루, 동물 털 등 흡입 알레르겐과 아스피린·진통소염제 등의 약물, 아황산가스 등 직업성 물질이 있습니다. 또한 위식도역류질환, 비만, 심리적 스트레스, 조산 및 저체중 출생 등의 내인성 요인도 천식 발병에 관여합니다. 천식의 원인은 개인마다 다르므로 알레르기 검사를 통해 유발 인자를 확인하고 전문의와 함께 관리 계획을 세우시기 바랍니다.', 4023, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '천식', '천식', 'DEFINITION', '숨을 쉴 때 색색거리는 소리(천명음)와 덩어리진 가래는 기관지 천식의 전형적인 증상으로, 기관지 점막 부종과 평활근 수축으로 기도가 좁아져 공기가 통과할 때 발생합니다. 이와 유사한 증상이 만성폐쇄성폐질환(COPD), 기관지확장증, 심부전으로 인한 심인성 천식에서도 나타날 수 있습니다. 정확한 진단을 위해 폐기능 검사 등을 포함한 호흡기내과 전문의 진료를 받으시기 바랍니다.', 4024, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '천식', '천식', 'SYMPTOM', '기관지 염증으로 인한 천식에서는 발작적인 기침, 천명음(쌕쌕거리는 소리), 흉부 압박감, 호흡 곤란이 주요 증상으로 나타납니다. 특히 밤이나 이른 아침, 운동 후, 찬 공기나 알레르겐 노출 시 증상이 악화되는 경향이 있으며, 점액 분비 증가로 가래가 동반될 수 있습니다. 증상이 지속되거나 악화된다면 호흡기내과 전문의를 통한 정확한 진단과 치료가 필요합니다.', 4025, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '천식', '천식', 'DIAGNOSIS', '천식 진단 후에는 유발 인자(알레르겐, 운동, 찬 공기 등) 노출을 최소화하고 처방된 흡입기를 항상 휴대해야 하며, 정기적인 외래 방문으로 폐기능과 증상 조절 상태를 점검해야 합니다. 금연은 필수이며, 운동 전 준비 운동, 마스크 착용, 환경 개선 등 일상 생활 전반에 걸친 관리가 필요합니다. 천식 행동 계획(Asthma Action Plan)을 전문의와 함께 작성하여 악화 시 대처 방법을 미리 숙지하시기 바랍니다.', 4026, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '천식', '천식', 'TREATMENT', '천식으로 네뷸라이저(호흡기) 치료를 받는 경우, 집에서도 알레르기 비염 관리를 병행하면 기도 염증 조절에 도움이 됩니다. 코 세척(생리식염수 비강 세척), 항히스타민제 또는 비강 스테로이드 스프레이 사용, 침구 세탁 및 환기 등 알레르겐 환경 관리가 비염과 천식 모두에 효과적입니다. 비염과 천식이 동반된 경우 알레르기내과 또는 이비인후과, 호흡기내과의 통합적인 전문의 진료를 권고합니다.', 4027, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '코로나-19', '코로나-19', 'MEDICATION', '코로나-19 발열에는 아세트아미노펜(타이레놀)이 1차 해열진통제로 권고되며, 기침 완화에는 진해거담제가 도움이 될 수 있습니다. 항바이러스제(팍스로비드, 라게브리오 등)는 고위험군(65세 이상, 기저질환자 등)에서 증상 발현 5일 이내에 전문의 처방 하에 사용할 수 있습니다. 호흡 곤란이 심하거나 산소포화도가 저하될 경우 즉시 응급 진료를 받으시기 바랍니다.', 4028, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '코로나-19', '코로나-19', 'PREVENTION', '코로나-19 예방을 위해 예방접종(백신)이 가장 효과적이며, 환기가 잘 안 되는 밀폐 공간 방문을 자제하고 다중이용시설에서의 마스크 착용을 유지하는 것이 중요합니다. 고위험군(노인, 면역저하자, 만성질환자)과의 접촉 시 특히 주의하고, 의심 증상 발생 시 자가격리 및 신속항원검사를 시행해야 합니다. 백신 접종 일정과 추가 예방 수칙은 보건당국 지침을 따르시기 바랍니다.', 4029, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '코로나-19', '코로나-19', 'CAUSE', '코로나-19는 SARS-CoV-2 바이러스의 비말(침방울) 및 에어로졸을 통한 호흡기 전파가 주된 발생 원인이며, 오염된 표면 접촉 후 점막(눈·코·입) 접촉으로도 전파될 수 있습니다. 마스크를 착용하지 않으면 감염자의 비말을 직접 흡입하거나, 바이러스가 포함된 에어로졸에 노출될 위험이 크게 높아집니다. 환기가 불량한 밀집 환경에서 마스크 미착용은 집단 감염의 주요 원인이 될 수 있습니다.', 4030, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '코로나-19', '코로나-19', 'DEFINITION', '고열, 목 부음(인후통·림프절 비대), 관절통은 코로나-19, 인플루엔자, 전염성 단핵구증(EBV 감염) 등 다양한 감염성 질환에서 공통적으로 나타날 수 있는 증상입니다. 특히 전신 발열과 근육·관절 통증이 동반된 경우 인플루엔자나 코로나-19와 유사하며, 인후통과 림프절 비대가 두드러지면 연쇄구균 인두염이나 단핵구증도 감별해야 합니다. 증상이 수일 이상 지속되면 정확한 원인 파악을 위해 내과 또는 감염내과 전문의 진료를 받으시기 바랍니다.', 4031, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '코로나-19', '코로나-19', 'SYMPTOM', '고열, 심한 몸살, 두통은 코로나-19의 전형적인 초기 증상으로, SARS-CoV-2 감염에 의한 전신 염증 반응으로 발생합니다. 코로나-19에서는 이 외에도 인후통, 기침, 후각·미각 소실, 설사 등이 동반될 수 있으며, 증상만으로 인플루엔자 등 다른 호흡기 감염과 구별하기 어렵습니다. 신속항원검사 또는 PCR 검사로 확인하고, 증상이 심하면 즉시 의료기관을 방문하시기 바랍니다.', 4032, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '코로나-19', '코로나-19', 'DIAGNOSIS', '코로나-19 환자에서 입술 물집(수포)이 생기는 경우, 발열과 전신 면역 저하로 인해 잠복해 있던 단순포진 바이러스(HSV-1)가 재활성화된 것일 가능성이 높습니다. 단순포진은 입술 주변에 군집된 작은 수포와 통증, 작열감이 특징이며, 코로나-19 외에도 발열성 질환, 스트레스, 자외선 노출 시 재발할 수 있습니다. 항바이러스제(아시클로버 등) 치료가 필요할 수 있으므로 피부과 또는 내과 전문의와 상담하시기 바랍니다.', 4033, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '코로나-19', '코로나-19', 'TREATMENT', '코로나-19 치료에 사용되는 팍스로비드(니르마트렐비르/리토나비르), 라게브리오(몰누피라비르) 등 항바이러스제는 오미크론 등 변이 바이러스에도 어느 정도 효과를 유지하나, 변이에 따라 감수성 차이가 있을 수 있습니다. 중화항체 치료제는 특정 변이에 효과가 크게 저하될 수 있어 최신 유행 변이에 따라 사용 가능 약물이 달라집니다. 현재 유행 중인 변이에 맞는 치료제 선택은 반드시 전문의 진료를 통해 결정되어야 합니다.', 4034, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐결핵', '폐결핵', 'PREVENTION', 'BCG 백신은 소아의 중증 결핵(결핵성 뇌막염, 속립성 결핵) 예방에 효과적이나, 성인 폐결핵에 대한 예방 효과는 제한적입니다. 백신을 맞지 않더라도 건강한 면역 상태를 유지하면 결핵균 노출 후 발병 위험을 줄일 수 있으나, 결핵균에 지속적으로 노출되는 환경(고위험 직종, 밀집 생활 등)에서는 발병 가능성이 높아집니다. 결핵 고위험군은 잠복 결핵 검사와 예방적 치료에 대해 전문의와 상담하시기 바랍니다.', 4035, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐결핵', '폐결핵', 'CAUSE', '폐결핵 발생에 영향을 미치는 주요 요인으로는 HIV 감염, 당뇨병, 영양 결핍, 면역억제제 사용, 알코올 남용 등 면역 기능 저하 상태가 있습니다. 저단백, 저칼로리 식이로 인한 영양 불량은 면역 기능을 약화시켜 잠복 결핵의 활성화 위험을 높이며, 충분한 단백질과 비타민D 섭취가 결핵 예방에 중요합니다. 결핵 위험 요인이 있는 경우 결핵 검진과 예방적 치료 가능성에 대해 전문의와 상담하시기 바랍니다.', 4036, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐결핵', '폐결핵', 'DEFINITION', '폐결핵은 결핵균(Mycobacterium tuberculosis)이 폐에 감염되어 발생하는 만성 감염성 질환으로, 비말핵을 통해 공기로 전파됩니다. 초기에는 2주 이상 지속되는 기침, 가래(혈담 포함), 미열, 야간 발한, 체중 감소가 나타나며, 진행되면 호흡 곤란과 객혈이 발생할 수 있습니다. 이러한 증상이 2주 이상 지속될 경우 흉부 X선 검사와 객담 검사를 위해 반드시 전문의 진료를 받으시기 바랍니다.', 4037, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐결핵', '폐결핵', 'SYMPTOM', '폐결핵 초기에는 마른 기침과 소량의 점액성 객담이 나타나며, 병이 진행되면 농성·혈성 객담으로 변하고 객혈이 발생할 수 있습니다. 흉통과 호흡 곤란은 폐 조직 손상이 심해지거나 흉막 침범(결핵성 흉막염) 시 두드러지게 나타나며, 대량 객혈은 폐혈관 손상이 심한 경우에 발생하는 응급 상황입니다. 증상 변화 양상은 개인마다 다를 수 있으므로, 흉통이나 객혈이 발생하면 즉시 전문의 진료를 받으시기 바랍니다.', 4038, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐결핵', '폐결핵', 'DIAGNOSIS', '폐결핵 진단에서 객담 항산균 도말 및 배양검사가 확진의 기준이 되며, 신속 분자진단(Xpert MTB/RIF)은 높은 민감도와 특이도로 수 시간 내 결과를 확인할 수 있어 정확도가 높습니다. 흉부 X선과 CT는 병변 범위 파악에 유용하며, 투베르쿨린 검사(TST) 및 인터페론감마 분비검사(IGRA)는 결핵 감염 여부 확인에 사용됩니다. 가장 신뢰도 높은 진단을 위해서는 미생물학적 배양검사와 분자진단을 병행하여 호흡기내과 전문의가 종합적으로 판단합니다.', 4039, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐결핵', '폐결핵', 'TREATMENT', '폐결핵 치료는 이소니아지드, 리팜피신, 에탐부톨, 피라진아미드 등 4가지 항결핵제를 최소 6개월 이상 복용하는 것이 표준 요법입니다. 규칙적인 약물 복용으로 대부분 완치가 가능하며, 치료 완료 시 폐 기능이 상당 부분 회복되나 심한 폐 손상이 있었던 경우 섬유화 흔적이 남을 수 있습니다. 임의로 약을 중단하면 다제내성 결핵으로 진행될 위험이 있으므로, 반드시 전문의 지시 하에 완전한 치료 과정을 이행하시기 바랍니다.', 4040, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐기종', '폐기종', 'PREVENTION', '폐기종 예방을 위해서는 항산화 성분이 풍부한 채소, 과일, 통곡물, 생선 등을 충분히 섭취하고 비타민C, E, 오메가-3 지방산이 포함된 식품을 권장합니다. 반면 가공식품, 과도한 염분, 포화지방이 많은 음식은 전신 염증을 악화시킬 수 있어 제한하는 것이 좋으며, 금연은 폐기종 예방의 가장 중요한 수칙입니다. 기저 폐질환이 있는 경우 영양사 및 호흡기내과 전문의와 함께 개인화된 식이 계획을 수립하시기 바랍니다.', 4041, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐기종', '폐기종', 'CAUSE', '폐기종은 주로 장기간의 흡연으로 폐포 벽이 파괴되어 폐의 탄성이 소실되면서 발생하며, 이로 인해 호기 시 공기가 폐에 갇혀 과팽창이 일어나 호흡 곤란이 나타납니다. 만성 기침과 가래는 반복적인 기도 염증과 점액 분비 과다로 발생하며, 활동 시 악화되는 호흡 곤란은 폐포 파괴로 인한 산소 교환 능력 저하 때문입니다. 증상이 있다면 호흡기내과 전문의를 통해 폐기능 검사를 받아보시기 바랍니다.', 4042, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐기종', '폐기종', 'DEFINITION', '폐기종에서는 호흡 곤란 외에도 만성 기침, 가래, 천명음(쌕쌕거리는 소리), 청색증(입술·손톱 변색), 통 모양 가슴(barrel chest) 변형이 동반될 수 있습니다. 말기로 진행되면 체중 감소, 피로감, 부종(우심부전 동반 시), 수면 중 호흡 장애가 나타날 수 있으며, 급성 악화 시 발열과 가래 색 변화가 관찰됩니다. 이러한 증상들을 종합적으로 관찰하여 호흡기내과 전문의와 정기적으로 상담하시기 바랍니다.', 4043, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐기종', '폐기종', 'SYMPTOM', '기침, 가래, 운동 시 호흡 곤란은 폐기종 외에도 만성기관지염, 천식, 심부전, 간질성 폐질환 등 다양한 호흡기·심혈관 질환에서도 나타날 수 있습니다. 만성폐쇄성폐질환(COPD)은 폐기종과 만성기관지염이 복합된 질환으로 유사한 증상을 보이며, 천식도 기침과 호흡 곤란을 공통적으로 나타냅니다. 따라서 증상만으로 자가 진단하지 말고, 폐기능 검사를 포함한 전문의 진료를 통해 정확한 원인을 감별하시기 바랍니다.', 4044, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐기종', '폐기종', 'DIAGNOSIS', '만성 기침, 가래, 호흡 곤란이 있을 때 폐기종 진단을 위해 폐기능 검사(스파이로메트리)를 시행하여 기류 제한 패턴(FEV1/FVC 감소)을 확인합니다. 흉부 X선으로 폐 과팽창을 확인하고, 흉부 CT로 폐포 파괴 정도와 분포를 정밀하게 평가합니다. 증상이 지속된다면 호흡기내과 전문의를 방문하여 폐기능 검사와 영상 검사를 통한 정확한 진단을 받으시기 바랍니다.', 4045, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐기종', '폐기종', 'TREATMENT', '폐기종에서 호흡기 증상 관리를 위해 기관지 확장제(LABA, LAMA) 흡입제를 규칙적으로 사용하고, 급성 악화 시 속효성 흡입제를 추가 사용합니다. 금연은 질병 진행을 늦추는 가장 중요한 조치이며, 호흡 재활 프로그램(호흡 운동, 유산소 운동)을 통해 운동 능력과 삶의 질을 향상시킬 수 있습니다. 증상 조절이 어렵거나 악화가 반복되면 호흡기내과 전문의와 상담하여 산소 치료 및 치료 계획을 조정하시기 바랍니다.', 4046, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐렴', '폐렴', 'PREVENTION', '독감 예방접종은 인플루엔자 바이러스 감염을 예방하거나 감염 시 증상을 경감시키고 폐렴 등 합병증 위험을 줄이는 데 효과적입니다. 접종 시 계란 단백질 알레르기, 과거 백신 부작용 경력이 있는 경우 전문의에게 사전에 알려야 하며, 접종 후 15~30분간 이상반응 여부를 관찰하는 것이 권장됩니다. 65세 이상 고령자, 만성 질환자, 임산부, 의료진은 매년 접종을 적극 권고합니다.', 4047, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐렴', '폐렴', 'CAUSE', '흡인성 폐렴은 구강 내 세균이나 위 내용물이 기도로 흡인되어 폐에 염증을 유발할 때 발생하며, 호흡 거칠음(수포음)은 염증으로 인한 삼출액이 기도에 차면서 생기는 소리입니다. 미열이 지속되는 것은 폐의 만성 염증 상태를 반영하며, 구강 위생 불량이나 연하 장애가 있는 환자에서 반복적으로 소량씩 흡인이 일어날 때 나타나는 전형적인 양상입니다. 연하 곤란이나 반복적인 호흡기 증상이 있다면 전문의 진료를 통해 흡인 위험을 평가하시기 바랍니다.', 4048, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐렴', '폐렴', 'DEFINITION', '기관지확장증은 기관지 벽이 비가역적으로 늘어난 상태로, 만성적인 가래(하루 수십 mL 이상의 화농성 가래)와 기침이 주요 증상입니다. 체중 감소와 객혈도 기관지확장증의 증상으로 나타날 수 있으나, 이러한 증상들은 폐결핵, 폐암 등 다른 심각한 폐 질환에서도 동반될 수 있습니다. 객혈이나 체중 감소가 동반될 경우 반드시 흉부 CT와 기관지내시경 등을 포함한 호흡기내과 전문의 정밀 검사를 받으시기 바랍니다.', 4049, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐렴', '폐렴', 'SYMPTOM', '폐렴은 기침(초기에는 마른 기침, 이후 화농성·혈성 가래), 38℃ 이상의 발열, 오한, 흉통, 호흡 곤란이 주요 증상으로 나타납니다. 노인 환자에서는 발열이 없거나 미약하고 의식 변화, 식욕 감소 등 비전형적 증상으로 나타날 수 있어 주의가 필요합니다. 이러한 증상이 수일 내 나타나거나 악화된다면 즉시 내과 또는 호흡기내과 전문의 진료를 받으시기 바랍니다.', 4050, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐렴', '폐렴', 'DIAGNOSIS', '폐렴 진단을 의심하게 하는 주요 증상은 발열, 기침, 가래, 흉통, 호흡 곤란이며 이 중 3가지 이상이 함께 나타날 때 적극적으로 의심합니다. 진단에는 청진 소견(폐수포음), 흉부 X선에서의 침윤(consolidation) 확인, 혈액검사(백혈구 증가, CRP·PCT 상승)가 중요한 요소입니다. 흉부 X선 촬영과 혈액검사를 통해 폐렴 여부와 중증도를 평가하여 입원 치료 필요 여부를 결정하므로, 전문의 진료가 필수적입니다.', 4051, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐렴', '폐렴', 'TREATMENT', '폐렴 치료 기간은 원인균과 중증도에 따라 다르며, 경증 지역사회성 폐렴은 항생제 경구 투여로 5~7일, 중등도 이상은 10~14일 치료가 일반적입니다. 마이코플라즈마 폐렴 등 비정형 폐렴은 14일 이상 치료가 필요할 수 있으며, 면역 저하 환자나 중증 폐렴의 경우 3~4주 이상 치료가 요구되기도 합니다. 임의로 항생제를 중단하지 말고, 정확한 치료 기간은 담당 전문의의 지시에 따르시기 바랍니다.', 4052, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '흡인성 폐렴', '흡인성폐렴', 'PREVENTION', '흡인성 폐렴 예방에 마스크 착용은 비말 흡입 차단에 도움이 되지만, 핵심 예방법은 구강 내 이물질이나 위 내용물이 기도로 넘어가지 않도록 하는 것입니다. 연하 장애 환자는 식사 시 상체를 30~45도 이상 세우고, 식후 30분간 눕지 않으며, 구강 위생 관리를 철저히 하는 것이 가장 중요한 예방법입니다. 연하 장애나 반복적인 폐렴이 있는 경우 재활의학과 또는 호흡기내과 전문의와 함께 예방 계획을 세우시기 바랍니다.', 4053, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '흡인성 폐렴', '흡인성폐렴', 'CAUSE', '흡인성 폐렴은 음식물·침·위 내용물의 흡인 외에도 구강 내 세균(혐기성 구강균)의 직접 흡인이 주요 원인이며, 연하 장애, 의식 저하, 전신 마취 후 상태, 알코올 중독이 위험 요인입니다. 위식도역류질환(GERD)으로 위산이 역류하여 기도로 흡인되거나, 위루관 영양 공급 중 내용물이 역류하여 흡인되는 경우도 원인이 됩니다. 반복적인 흡인성 폐렴이 있다면 원인 파악을 위해 내과 또는 재활의학과 전문의 진료를 받으시기 바랍니다.', 4054, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '흡인성 폐렴', '흡인성폐렴', 'DEFINITION', '구강 분비물, 위 내용물 등 이물질이 기도로 흡인되어 폐에 염증이 생기는 경우 흡인성 폐렴에 해당합니다. 흡인성 폐렴은 특히 연하 장애 환자, 의식이 저하된 환자, 고령자, 기관 삽관 중인 환자에서 호발하며, 구강 내 혐기성 세균이 폐 농양으로 진행될 수 있습니다. 흡인 위험 요인이 있는 환자는 내과 또는 호흡기내과 전문의와 함께 예방 및 관리 방법을 상담하시기 바랍니다.', 4055, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '흡인성 폐렴', '흡인성폐렴', 'SYMPTOM', '흡인된 음식물이나 이물질이 기도에 자극을 주면 기도 점막이 염증 반응을 일으켜 백혈구와 삼출액이 축적되고, 이것이 황색 또는 녹색 가래로 배출됩니다. 가슴의 답답함은 흡인 후 기도 및 폐포 내 염증과 분비물로 인해 기도가 부분적으로 막히면서 발생합니다. 이러한 증상이 반복되거나 심해지면 흡인성 폐렴 여부를 확인하기 위해 즉시 전문의 진료를 받으시기 바랍니다.', 4056, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '흡인성 폐렴', '흡인성폐렴', 'DIAGNOSIS', '흡인성 폐렴 진단에서 구강 내 혐기성균, 녹농균, 대장균 등 그람음성간균을 확인하는 것은 원인균 파악과 항생제 선택에 매우 중요합니다. 객담 배양검사 또는 기관지내시경을 통한 하기도 검체의 배양검사가 원인균 확인에 효과적이며, 그람 염색을 통해 균의 형태를 신속하게 파악할 수 있습니다. 다만 구강 상재균의 오염 가능성이 있으므로, 검체 채취 방법과 결과 해석은 전문의의 판단이 필요합니다.', 4057, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '흡인성 폐렴', '흡인성폐렴', 'TREATMENT', '흡인성 폐렴의 치료는 항생제 투여(혐기성균 포함 광범위 항생제)가 핵심이며, 방사선 치료는 흡인성 폐렴 자체의 치료에는 사용되지 않습니다. 그러나 두경부암, 식도암 환자가 방사선 치료를 받을 경우 연하 기능 저하로 흡인 위험이 증가하여 흡인성 폐렴이 합병증으로 발생할 수 있습니다. 방사선 치료 관련 연하 장애나 흡인성 폐렴이 우려될 경우 종양내과, 호흡기내과, 재활의학과의 협진을 통한 관리가 필요합니다.', 4058, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '단순 포진 바이러스', '단순포진바이러스', 'DEFINITION', '단순포진 바이러스(HSV)는 HSV-1과 HSV-2로 구분되며, HSV-1은 주로 구강·얼굴 주변(입술 포진), HSV-2는 주로 성기 부위에 감염을 일으키는 바이러스입니다. 초감염 후 신경절에 잠복하다가 면역 저하, 발열, 스트레스 등의 유발 요인에 의해 재활성화되어 수포성 피부 병변을 일으킵니다. 재발이 잦거나 면역 저하 환자에서는 항바이러스제(아시클로버, 발라시클로버) 치료와 예방적 투여에 대해 피부과 또는 감염내과 전문의와 상담이 필요합니다.', 4059, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('감염성질환', '단순 포진 바이러스', '단순포진바이러스', 'SYMPTOM', '단순포진 바이러스(HSV) 감염의 주요 증상은 감염 부위의 가려움, 작열감, 통증 후 군집된 작은 수포가 나타나고 이후 궤양, 가피 형성 순으로 진행됩니다. HSV-1 구강 포진은 입술 주변에 수포와 통증이, HSV-2 성기 포진은 성기·항문 주변에 유사한 병변이 생기며, 초감염 시 발열, 림프절 비대 등 전신 증상이 동반될 수 있습니다. 증상이 반복되거나 심하다면 피부과 또는 감염내과 전문의 진료와 항바이러스제 치료를 받으시기 바랍니다.', 4060, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('귀코목질환', '이루증', '이루증', 'DEFINITION', '이루증(耳漏症, otorrhea)은 귀에서 분비물이 흘러나오는 상태로, 외이도염, 중이염(급성·만성), 고막 천공, 두개기저골절 등 다양한 원인에 의해 발생합니다. 분비물의 성상(장액성·화농성·혈성)에 따라 원인 질환이 다르며, 화농성 이루는 세균성 중이염, 맑은 이루는 알레르기나 두개내 뇌척수액 누출을 의심할 수 있습니다. 이루가 지속되거나 혈성 분비물, 청력 저하, 통증이 동반되면 이비인후과 전문의 진료를 받으시기 바랍니다.', 4061, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '결정종', '결정종', 'SYMPTOM', '결정종(결절종, ganglion cyst)은 관절 주위나 건초에서 발생하는 젤리 같은 점액이 찬 양성 낭종으로, 주로 손목 등에 단단하고 부드러운 혹으로 만져집니다. 통증 없이 혹만 있는 경우가 많으나, 크기가 커지면 주변 신경이나 혈관을 압박하여 통증, 저림증, 운동 제한이 나타날 수 있습니다. 혹의 크기 변화나 통증이 있다면 정형외과 또는 수부 외과 전문의 진료를 받아 초음파 검사 등으로 정확한 진단을 받으시기 바랍니다.', 4062, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '결정종', '결정종', 'TREATMENT', '결정종(결절종)은 무증상이고 크기가 작으면 경과 관찰이 가능하나, 통증이 있거나 기능 장애가 있을 경우 치료가 필요합니다. 치료 방법으로는 흡인(주사기로 내용물 흡인), 주사 요법, 또는 수술적 절제가 있으며 흡인 후 재발률이 있어 완전 절제 수술이 재발 방지에 더 효과적입니다. 치료 방법의 선택은 위치, 크기, 증상에 따라 달라지므로 정형외과 전문의와 상담하여 결정하시기 바랍니다.', 4063, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '퇴행성 관절염', '퇴행성관절염', 'DEFINITION', '퇴행성 관절염(골관절염)은 관절 연골이 마모·손상되고 그 아래 뼈가 변형되어 발생하는 만성 질환으로, 주로 무릎, 고관절, 손가락, 척추에 호발합니다. 연골 손실로 관절 간격이 좁아지면서 통증, 뻣뻣함(특히 오전에 30분 미만), 관절 부종, 운동 범위 감소가 나타나며, 노화, 비만, 과거 관절 손상, 유전적 요인이 주요 위험 인자입니다. 관절 통증이 지속된다면 정형외과 또는 류마티스내과 전문의 진료를 통해 정확한 진단과 치료 계획을 세우시기 바랍니다.', 4064, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('근골격질환', '퇴행성 관절염', '퇴행성관절염', 'TREATMENT', '퇴행성 관절염 치료는 약물치료(아세트아미노펜, NSAIDs, 관절 내 스테로이드 또는 히알루론산 주사), 물리치료, 운동 치료를 병행하는 보존적 치료가 우선입니다. 체중 감량은 무릎 관절 부하를 줄이는 데 효과적이며, 근력 강화 운동과 유산소 운동을 규칙적으로 시행하는 것이 권고됩니다. 보존적 치료에 반응이 없고 일상생활 장애가 심한 경우 인공관절 치환술 등 수술적 치료를 전문의와 상담하시기 바랍니다.', 4065, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '삼차 신경통', '삼차신경통', 'MEDICATION', '삼차신경통 치료의 1차 약물로는 카르바마제핀(tegretol)이 가장 효과적이며, 옥스카르바제핀도 유사한 효과로 사용됩니다. 카르바마제핀으로 조절이 안 되거나 부작용이 있을 경우 라모트리진, 가바펜틴, 바클로펜 등을 추가하거나 대체할 수 있습니다. 약물 치료에 반응이 없는 경우 미세혈관감압술, 감마나이프 방사선 수술 등 신경외과적 치료를 신경과 또는 신경외과 전문의와 상담하시기 바랍니다.', 4066, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('뇌신경정신질환', '투렛증후군', '투렛증후군', 'DEFINITION', '투렛 증후군은 여러 운동 틱(눈 깜빡임, 얼굴 찡그림, 몸 흔들기 등)과 적어도 하나 이상의 음성 틱(반복적인 소리, 욕설 등)이 1년 이상 지속되는 신경발달 장애입니다. 주로 아동기(평균 6~7세)에 발병하며, ADHD, 강박장애(OCD)가 동반되는 경우가 많고 남아에서 더 흔하게 나타납니다. 틱 증상이 의심될 경우 소아청소년과 또는 소아신경과 전문의 진료를 통해 정확한 진단과 행동치료 및 약물치료 계획을 수립하시기 바랍니다.', 4067, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '식도이완불능증', '식도이완불능증', 'DEFINITION', '식도이완불능증(achalasia)은 하부 식도 괄약근이 적절히 이완되지 않고 식도의 연동 운동이 소실되어 음식물이 위로 내려가지 못하는 식도 운동 장애입니다. 주요 증상은 고형식과 액체 음식 모두에서 나타나는 연하 곤란, 식후 역류, 흉통, 체중 감소이며 증상이 서서히 진행합니다. 연하 곤란이 지속될 경우 식도 내압 검사(마노메트리)와 내시경 검사를 포함한 소화기내과 전문의 진료를 받으시기 바랍니다.', 4068, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '십이지장 궤양', '십이지장궤양', 'DEFINITION', '십이지장 궤양은 헬리코박터 파일로리균 감염 또는 NSAIDs(비스테로이드 항염증제) 장기 복용으로 인해 십이지장 점막이 위산에 의해 손상되어 발생하는 궤양입니다. 주요 증상은 공복 시(식사 2~3시간 후) 악화되고 음식 섭취로 일시적으로 완화되는 상복부 통증이 특징이며, 출혈 시 흑색 변(흑변)이나 토혈이 나타날 수 있습니다. 증상이 있다면 내시경 검사와 헬리코박터 검사를 위해 소화기내과 전문의 진료를 받으시기 바랍니다.', 4069, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '십이지장염', '십이지장염', 'DEFINITION', '십이지장염은 십이지장 점막에 염증이 생긴 상태로, 헬리코박터 파일로리균, NSAIDs, 과도한 음주, 스트레스, 크론병 등이 원인이 됩니다. 증상은 상복부 통증(공복 시 악화, 식사 후 경감), 소화불량, 메스꺼움, 팽만감 등이며 십이지장 궤양과 유사합니다. 소화기내과 전문의 진료를 통해 상부위장관 내시경으로 정확한 진단과 원인 치료(헬리코박터 제균 요법 등)를 받으시기 바랍니다.', 4070, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '역류성 식도염', '역류성식도염', 'DEFINITION', '역류성 식도염은 위산을 포함한 위 내용물이 식도로 역류하여 식도 점막에 염증을 일으키는 질환으로, 하부 식도 괄약근 기능 저하가 주요 원인입니다. 주요 증상은 가슴 쓰림(흉골 하부의 화끈거림), 산 역류(신물 올라옴), 연하 곤란이며, 야간 증상이 두드러질 수 있습니다. 증상이 지속되면 소화기내과 전문의 진료를 통해 내시경 검사와 함께 프로톤 펌프 억제제(PPI) 치료를 받으시기 바랍니다.', 4071, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '용혈성 요독 증후군', '용혈성요독증후군', 'DEFINITION', '용혈성 요독 증후군(HUS)은 미세혈관 병증 용혈성 빈혈, 혈소판 감소증, 급성 신부전의 3가지가 동반되는 중증 질환으로, 소아에서 주로 시가독소 생성 대장균(O157:H7) 감염 후 발생합니다. 설사(혈성 설사) 후 수일 내에 소변량 감소, 부종, 창백함, 출혈 경향이 나타나면 HUS를 의심해야 합니다. 생명을 위협하는 응급 상황으로 진행될 수 있으므로, 의심 증상 발생 시 즉시 소아청소년과 또는 신장내과 전문의의 진료를 받으시기 바랍니다.', 4072, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '위경련', '위경련', 'DEFINITION', '위경련은 위 근육이 갑자기 수축하여 발생하는 상복부의 급격한 통증(쥐어짜는 듯한 느낌)으로, 위염, 소화성 궤양, 위식도역류, 스트레스, 과식, 과음, 헬리코박터 감염 등이 원인이 됩니다. 증상은 일시적일 수 있으나 구역, 구토, 복부 팽만감이 동반될 수 있으며, 통증이 심하거나 반복될 경우 다른 복부 질환(담석증, 췌장염 등)과 감별이 필요합니다. 반복적인 위경련이 있다면 소화기내과 전문의 진료를 받아 정확한 원인을 확인하시기 바랍니다.', 4073, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '위막성 대장염', '위막성대장염', 'DEFINITION', '위막성 대장염은 항생제 사용 후 장내 정상 세균총이 교란되면서 클로스트리디움 디피실(C. difficile)균이 과증식하고 독소를 분비하여 대장 점막에 위막을 형성하는 염증성 질환입니다. 주요 증상은 항생제 투여 중 또는 투여 후 발생하는 수양성 설사(하루 3회 이상), 복통, 발열이며, 중증은 독성 거대결장으로 진행될 수 있습니다. 항생제 복용 후 설사가 지속되면 소화기내과 전문의 진료를 통해 C. difficile 독소 검사와 반코마이신 또는 피다목시신 치료를 받으시기 바랍니다.', 4074, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '위용종', '위용종', 'DEFINITION', '위용종은 위 점막에서 내강 쪽으로 돌출된 병변으로, 염증성 용종, 증식성 용종, 선종성 용종 등으로 분류되며 위 내시경 검사 중 우연히 발견되는 경우가 많습니다. 대부분 무증상이나 출혈(흑색변, 빈혈) 또는 드물게 오심이 나타날 수 있으며, 선종성 용종은 위암으로 진행할 위험이 있어 내시경 절제가 권고됩니다. 위 내시경에서 용종이 발견된 경우 반드시 소화기내과 전문의와 추적 관찰 및 치료 계획을 상담하시기 바랍니다.', 4075, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '윌슨병', '윌슨병', 'DEFINITION', '윌슨병은 ATP7B 유전자 돌연변이로 인해 담즙으로의 구리 배설이 장애되어 간, 뇌, 각막(카이저-플라이셔 고리) 등에 구리가 축적되는 상염색체 열성 유전 질환입니다. 간 증상(황달, 간경변), 신경 증상(떨림, 구음 장애, 보행 이상), 정신 증상(인격 변화, 우울증)이 다양하게 나타나며 주로 5~35세에 발병합니다. 페니실라민이나 트리엔틴 등 구리 킬레이트 치료로 조기에 치료하면 예후가 좋으므로, 의심 증상이 있다면 소화기내과 또는 신경과 전문의 진료를 받으시기 바랍니다.', 4076, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '장 중첩증', '장중첩증', 'DEFINITION', '장 중첩증(intussusception)은 장의 한 부분이 인접한 장 속으로 밀려 들어가 장폐색을 일으키는 질환으로, 2세 이하 영아에서 가장 흔히 발생합니다. 주요 증상은 갑작스러운 심한 복통(주기적, 아이가 다리를 복부 쪽으로 끌어당기며 울음), 담즙성 구토, 혈변(딸기 잼 모양의 점액혈변)이며 복부에 소시지 모양의 종괴가 만져질 수 있습니다. 응급 처치가 필요한 질환이므로 증상이 의심되면 즉시 소아응급 또는 소아외과 전문의 진료를 받으시기 바랍니다.', 4077, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '장염전', '장염전', 'DEFINITION', '장염전(volvulus)은 장이 자체 축을 중심으로 꼬여 장폐색과 혈류 차단이 발생하는 응급 질환으로, 주로 S상결장과 맹장에서 발생합니다. 증상은 갑작스럽고 심한 복통, 복부 팽만, 구토, 배변·가스 배출 불가능이 특징이며, 장 괴사로 진행되면 발열, 복막염 증상이 나타납니다. 즉각적인 외과적 처치가 필요한 응급 상황이므로, 증상 발생 시 즉시 응급실을 방문하시기 바랍니다.', 4078, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '장유착', '장유착', 'DEFINITION', '장유착은 복부 수술, 복막염, 방사선 치료 후 복강 내 장기 사이에 섬유 조직 띠(유착)가 형성되어 장의 정상적인 운동을 방해하는 상태입니다. 증상이 없는 경우도 많으나 심하면 만성 복통, 복부 팽만, 간헐적 장폐색(복통, 구토, 배변 장애)을 일으킬 수 있습니다. 반복적인 장폐색 증상이 있다면 외과 전문의 진료를 통해 수술적 유착 박리 여부를 결정해야 하며, 증상 완화에는 보존적 치료가 우선 적용됩니다.', 4079, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('소화기질환', '장폐색', '장폐색', 'DEFINITION', '장폐색은 소장 또는 대장이 기계적 또는 기능적으로 막혀 장 내용물의 통과가 방해받는 질환으로, 기계적 원인(유착, 탈장, 종양, 장중첩증)과 마비성 원인(수술 후, 복막염, 전해질 이상)으로 구분됩니다. 주요 증상은 심한 복통, 구토(초기 담즙성, 진행 시 분변성), 복부 팽만, 배변 및 가스 배출 불가능이며, 장 천공으로 진행되면 복막염의 응급 상황이 됩니다. 의심 증상 발생 시 즉시 응급 의료기관을 방문하여 복부 X선 및 CT 검사와 외과 전문의 진료를 받으시기 바랍니다.', 4080, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('순환기질환', '기립성 저혈압', '기립성저혈압', 'DEFINITION', '기립성 저혈압은 누운 자세나 앉은 자세에서 일어설 때 수축기 혈압이 20mmHg 이상 또는 이완기 혈압이 10mmHg 이상 감소하는 상태로, 어지럼증, 흐린 시야, 실신 전 증상이 나타납니다. 탈수, 장기간의 침상 안정, 당뇨병성 자율신경병증, 파킨슨병, 일부 혈압약 부작용 등이 원인이 될 수 있습니다. 반복적인 어지럼증이나 실신이 있다면 순환기내과 또는 신경과 전문의 진료를 받아 원인을 확인하고 자세 변경 시 천천히 일어나는 등의 생활 습관 교정을 시행하시기 바랍니다.', 4081, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신장암', '신장암', 'DIET_LIFE', '신장암 진단 후 식이와 생활 관리를 위해서는 충분한 수분 섭취(하루 1.5~2L), 채소와 과일 위주의 균형 잡힌 식사, 저지방 식이를 권장합니다. 흡연은 신장암 재발 및 다른 암 발생 위험을 높이므로 금연이 필수적이며, 비만은 재발 위험 요인이므로 적정 체중 유지와 규칙적인 운동이 중요합니다. 신장 기능 저하가 있는 경우 단백질, 칼륨, 인의 섭취를 제한해야 할 수 있으므로, 구체적인 식이 계획은 신장내과 또는 비뇨의학과 전문의 및 영양사와 상담하시기 바랍니다.', 4082, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신장암', '신장암', 'DEFINITION', '신장암(신세포암)은 신장 세뇨관 세포에서 기원하는 악성 종양으로, 투명세포암이 가장 흔한 조직형입니다. 초기에는 대부분 무증상이며 건강검진 초음파에서 우연히 발견되는 경우가 많고, 진행되면 혈뇨, 옆구리 통증, 복부 종괴의 3대 증상이 나타날 수 있습니다. 위험 요인으로는 흡연, 비만, 고혈압, 장기 혈액 투석, 가족력 등이 있으며, 증상이 의심되면 비뇨의학과 전문의를 통한 영상 검사와 정밀 진단이 필요합니다.', 4083, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신장암', '신장암', 'SYMPTOM', '신장암의 주요 증상은 육안적 혈뇨(소변에 피가 섞임), 옆구리 또는 등 부위의 통증, 복부에서 종괴가 만져지는 것이며, 이 세 가지가 동시에 나타나는 경우는 진행된 병기에서 보입니다. 발열, 체중 감소, 야간 발한 등 전신 증상과 고칼슘혈증, 적혈구 증가증 등 부종양 증후군이 나타날 수 있습니다. 혈뇨나 지속적인 옆구리 통증이 있다면 즉시 비뇨의학과 전문의 진료를 받아 초음파 및 CT 검사로 정확한 진단을 받으시기 바랍니다.', 4084, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신장암', '신장암', 'DIAGNOSIS', '신장암 진단을 위해 복부 초음파로 종괴를 발견한 후, 복부 CT(조영 증강)가 종양의 특성과 병기 결정에 가장 중요한 검사입니다. MRI는 CT로 감별이 어려운 경우, 혈관 침범 평가, 요오드 조영제 금기 환자에서 활용됩니다. 혈액 및 소변 검사(혈뇨, 신기능 확인), 흉부 CT(폐 전이 평가)를 병행하며, 조직 생검은 필요 시 수술 전에 시행하여 확진하고 비뇨의학과 전문의에게 진료를 받으시기 바랍니다.', 4085, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('신장비뇨기질환', '신장암', '신장암', 'TREATMENT', '신장암의 표준 치료는 수술적 절제(근치적 신절제술 또는 부분 신절제술)이며, 종양의 크기와 위치에 따라 복강경 또는 로봇 수술로 시행됩니다. 전이성 신장암에서는 수니티닙, 파조파닙 등의 표적치료제나 니볼루맙 등 면역관문억제제를 사용하며, 방사선 치료는 뼈 전이 통증 완화 등에 보조적으로 활용됩니다. 치료 방법 선택은 병기, 신기능, 전신 상태에 따라 다르므로 비뇨의학과·종양내과 전문의와 충분한 상담 후 결정하시기 바랍니다.', 4086, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경부 이형성증', '자궁경부이형성증', 'CHECKUP', '자궁경부 이형성증 검진을 위해서는 성 경험이 있는 여성은 20세 이후 또는 성 경험 시작 후 3년부터 자궁경부 세포 검사(팹 스미어)를 정기적으로 받아야 합니다. 국가암검진으로 만 20세 이상 여성에게 2년 간격으로 무료 검진이 제공되며, HPV 검사를 병행하면 이형성증과 암 발생 위험을 보다 정확하게 평가할 수 있습니다. HPV 예방 백신 접종도 자궁경부 이형성증 예방에 효과적이므로, 접종 여부와 검진 주기에 대해 산부인과 전문의와 상담하시기 바랍니다.', 4087, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('여성질환', '자궁경부 이형성증', '자궁경부이형성증', 'DEFINITION', '자궁경부 이형성증(자궁경부 상피내 종양, CIN)은 자궁경부 세포가 정상과 암 사이의 이상 변화를 보이는 상태로, 주로 인유두종 바이러스(HPV) 감염에 의해 발생합니다. CIN 1(경증), CIN 2(중등증), CIN 3(중증)으로 분류되며, 일부는 자연 회복되지만 고등급 이형성증은 치료하지 않으면 자궁경부암으로 진행될 수 있습니다. 정기적인 자궁경부 세포 검사와 HPV 검사로 조기 발견이 가능하므로, 산부인과 전문의를 통한 정기 검진을 받으시기 바랍니다.', 4088, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '소화관의 이물질', '소화관의이물질', 'DEFINITION', '소화관 이물질은 음식물이 아닌 물체가 식도, 위, 장에 삽입되거나 삼켜진 상태로, 소아에서 동전, 단추형 배터리, 장난감 부품 등이 흔히 발생합니다. 날카롭거나 독성이 있는 이물질(단추형 배터리 등)은 소화관 손상, 궤양, 천공을 유발할 수 있어 응급 내시경 제거가 필요합니다. 이물질 삼킴이 의심되면 즉시 응급실을 방문하여 복부 X선 촬영과 소화기내과 또는 소아과 전문의의 진료를 받으시기 바랍니다.', 4089, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('응급질환', '외상에 의한 뇌손상', '외상에의한뇌손상', 'DEFINITION', '외상성 뇌손상(TBI)은 외부 충격에 의해 뇌에 손상이 발생하는 것으로, 뇌진탕(경증), 뇌좌상(중등도), 경막외·경막하·뇌내 혈종(중증)으로 분류됩니다. 증상은 의식 소실, 두통, 구역, 구토, 기억 상실, 인지 기능 저하 등이며, 중증의 경우 운동 마비, 언어 장애, 식물인간 상태로 진행될 수 있습니다. 머리를 다친 후 증상이 나타나면 즉시 응급실을 방문하여 뇌 CT 검사와 신경외과 전문의의 평가를 받으시기 바랍니다.', 4090, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '간문부 담관암', '간문부담관암', 'DEFINITION', '간문부 담관암(클라츠킨 종양)은 간 내 좌우 담관이 합류하는 간문부에 발생하는 악성 종양으로, 담관암 중 가장 흔한 위치입니다. 초기에는 무증상이나 진행 시 폐쇄성 황달(무통성 황달), 소양증, 짙은 소변, 회백색 변, 체중 감소, 우상복부 불편감이 나타납니다. 조기 발견이 어려워 예후가 불량하므로, 황달이나 우상복부 불편감이 지속된다면 소화기내과 또는 간담췌외과 전문의를 통한 MRCP, CT, 조직 생검 등 정밀 검사를 받으시기 바랍니다.', 4091, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '갑상선 유두암', '갑상선유두암', 'DEFINITION', '갑상선 유두암은 갑상선암 중 가장 흔한 조직형(약 80%)으로, 대부분 천천히 성장하고 예후가 양호한 편입니다. 주로 목에서 단단하고 통증 없는 결절로 발견되며, 경부 림프절 전이가 흔하나 원격 전이는 드뭅니다. 초음파 검사와 세침 흡인 세포 검사(FNAC)로 진단하며, 수술적 절제(갑상선 절제술)가 주된 치료이고 방사성요오드 치료를 병행하는 경우도 있으므로 내분비내과 또는 외과 전문의 진료를 받으시기 바랍니다.', 4092, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '과오종', '과오종', 'DEFINITION', '과오종(hamartoma)은 해당 조직의 정상 구성 성분이 비정상적으로 혼합·배열된 양성 종양 유사 병변으로, 폐, 간, 신장, 뇌 등 다양한 장기에서 발생할 수 있습니다. 대부분 무증상이며 영상 검사에서 우연히 발견되고, 암으로 진행하는 경우는 드물어 일반적으로 정기 추적 관찰이 권장됩니다. 드물게 출혈, 압박 증상이 발생하거나 악성 가능성 감별이 필요한 경우 외과적 절제를 고려하므로, 해당 장기 전문의와 상담하시기 바랍니다.', 4093, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '다발성 골수종', '다발성골수종', 'MEDICATION', '다발성 골수종 치료에는 보르테조밉(bortezomib), 레날리도마이드(lenalidomide), 탈리도마이드 등이 주요 약물로 사용되며, 덱사메타손과 병용하는 복합 요법이 표준입니다. 자가 조혈모세포 이식이 가능한 환자에서는 이식 전 유도 요법으로 사용되고, 재발·불응성 골수종에는 다라투무맙 등 단클론항체와 카르필조밉 등이 사용됩니다. 약물 선택과 치료 계획은 환자의 나이, 신기능, 병기에 따라 달라지므로 혈액종양내과 전문의와 충분히 상담하시기 바랍니다.', 4094, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '다발성 골수종', '다발성골수종', 'EXERCISE', '다발성 골수종 환자는 뼈 취약성, 빈혈, 피로 등으로 인해 운동이 제한될 수 있으나, 가능한 범위에서의 규칙적인 운동은 삶의 질과 근력 유지에 도움이 됩니다. 무리한 고강도 운동이나 충격이 강한 운동은 골절 위험을 높일 수 있어 피해야 하며, 걷기, 수영, 가벼운 저항 운동이 안전한 선택입니다. 운동 강도와 종류는 치료 단계, 뼈 병변 상태, 혈색소 수치에 따라 달라지므로 혈액종양내과 전문의 및 재활의학과 전문의와 상담하여 안전한 운동 계획을 수립하시기 바랍니다.', 4095, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '다발성 골수종', '다발성골수종', 'CAUSE', '다발성 골수종의 정확한 원인은 밝혀지지 않았으나, 형질세포의 유전자 돌연변이(염색체 전위, 결실 등)가 악성 클론 증식을 일으키는 것으로 알려져 있습니다. 위험 요인으로는 고령(중앙 나이 65~70세), 남성, 흑인, 의미불명의 단클론감마병증(MGUS) 병력, 방사선 노출, 특정 화학물질 노출이 있습니다. 유전적 요인과 환경적 요인이 복합적으로 작용하므로, 의심 증상이나 가족력이 있다면 혈액종양내과 전문의 진료를 받으시기 바랍니다.', 4096, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '다발성 골수종', '다발성골수종', 'SYMPTOM', '다발성 골수종의 주요 증상은 뼈 통증(특히 등, 허리, 흉부), 피로감과 빈혈(창백함, 숨참), 반복적인 감염(면역 저하), 신기능 저하(부종, 소변량 감소)입니다. 고칼슘혈증으로 인한 갈증, 빈뇨, 변비, 의식 변화가 나타날 수 있으며, 척추 골절로 인한 키 감소나 신경 압박 증상도 발생할 수 있습니다. 이러한 증상들이 복합적으로 나타나면 혈액종양내과 전문의 진료를 통해 혈액검사, 단백전기영동, 골수 검사 등 정밀 검진을 받으시기 바랍니다.', 4097, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '다발성 골수종', '다발성골수종', 'DIAGNOSIS', '다발성 골수종 진단을 위해 혈청·소변 단백전기영동(SPEP/UPEP)과 면역고정전기영동으로 M단백(단클론 면역글로불린)을 확인하고, 혈청 유리경쇄 검사(FLC)를 시행합니다. 골수 생검과 흡인 검사에서 형질세포 비율이 10% 이상이면 골수종 진단 기준을 충족하며, 형광제자리교잡법(FISH)으로 유전자 이상을 파악합니다. 전신 PET-CT 또는 저선량 전신 CT로 뼈 병변을 평가하며, 진단 및 치료 계획 수립은 혈액종양내과 전문의와 상담하시기 바랍니다.', 4098, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '다발성 골수종', '다발성골수종', 'TREATMENT', '다발성 골수종의 표준 치료는 보르테조밉·레날리도마이드·덱사메타손 병용요법(VRd) 등으로 관해를 유도한 후, 적합한 환자에서 자가 조혈모세포 이식을 시행합니다. 이식 후 레날리도마이드 유지 치료로 관해 기간을 연장하며, 재발 시 다라투무맙 등 단클론항체나 카르필조밉 기반 요법을 사용합니다. CAR-T 세포 치료와 같은 새로운 치료법도 개발되고 있으므로, 치료 방침은 혈액종양내과 전문의와 충분히 논의하여 결정하시기 바랍니다.', 4099, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '랑거한스세포 조직구식증', '랑거한스세포조직구식증', 'DEFINITION', '랑거한스세포 조직구증(LCH)은 비정상적인 랑거한스세포(수지상세포의 일종)가 과도하게 증식하여 뼈, 폐, 피부, 뇌하수체 등 다양한 장기에 침윤하는 희귀 질환입니다. 소아에서 더 흔하며, 단일 병소(단일계통 단일 병소)부터 다발 장기 침범까지 다양한 임상 양상을 보입니다. 뼈 통증, 두개골 병변, 요붕증(다뇨·다음), 피부 발진, 림프절 비대 등의 증상이 나타날 수 있으며, 소아혈액종양과 또는 내분비내과 전문의를 통한 진단과 치료가 필요합니다.', 4100, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '린치 증후군', '린치증후군', 'DEFINITION', '린치 증후군(유전성 비용종성 대장암, HNPCC)은 DNA 불일치 수복 유전자(MLH1, MSH2, MSH6, PMS2 등)의 생식세포 돌연변이로 인해 대장암, 자궁내막암, 난소암, 위암 등 다양한 암 발생 위험이 현저히 높아지는 유전성 암 증후군입니다. 대장암이 주로 50세 이전에 발생하고 근위부 대장에 많으며, 가족력이 있는 경우 20~25세부터 정기 대장내시경 검사를 권고합니다. 가족 중 린치 증후군이 의심되거나 진단받은 경우, 유전 상담과 유전자 검사를 위해 소화기내과 또는 유전체 전문의와 상담하시기 바랍니다.', 4101, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '망막모세포종', '망막모세포종', 'DEFINITION', '망막모세포종은 망막의 미성숙 신경세포(모세포)에서 발생하는 소아 안구암으로, 5세 이하 어린이에서 주로 발생하며 유전성(RB1 유전자 돌연변이)과 비유전성으로 구분됩니다. 주요 증상은 동공이 흰색으로 보이는 백색 동공반사(고양이 눈 징후)와 사시이며, 진행 시 안구 돌출, 시력 상실, 통증이 나타날 수 있습니다. 조기 발견 시 안구 보존 치료(레이저, 냉동, 항암제 안구 내 주사 등)가 가능하므로, 의심 증상이 있다면 즉시 안과 또는 소아혈액종양과 전문의 진료를 받으시기 바랍니다.', 4102, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '미세혈관병용혈빈혈', '미세혈관병용혈빈혈', 'DEFINITION', '미세혈관병 용혈 빈혈(MAHA)은 미세혈관 내 혈전이나 혈관 손상으로 적혈구가 기계적으로 파괴되는 용혈성 빈혈로, 혈도말에서 파쇄 적혈구(schistocyte)가 특징적으로 나타납니다. 혈전성 혈소판감소성 자반증(TTP), 용혈성 요독 증후군(HUS), 파종혈관내응고(DIC), 악성 고혈압 등에서 발생합니다. 창백함, 황달, 소변 색 변화, 혈소판 감소 증상이 동반될 수 있으며, 생명을 위협하는 응급 상황일 수 있으므로 즉시 혈액내과 전문의 진료를 받으시기 바랍니다.', 4103, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '바터 팽대부 암', '바터팽대부암', 'DEFINITION', '바터 팽대부 암은 췌관과 담관이 십이지장으로 열리는 바터 팽대부에 발생하는 악성 종양으로, 위치적 특성으로 인해 종양이 작아도 폐쇄성 황달이 초기에 나타납니다. 증상으로는 무통성 황달, 소양증, 짙은 소변, 회백색 변, 체중 감소, 상복부 통증이 있으며, 십이지장 출혈로 인한 흑변이 나타나기도 합니다. 췌장암에 비해 비교적 예후가 좋으나 조기 발견과 수술(휘플 수술)이 중요하므로, 황달 증상이 있다면 소화기내과 또는 간담췌외과 전문의 진료를 즉시 받으시기 바랍니다.', 4104, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '발작성야간혈뇨', '발작성야간혈뇨', 'DEFINITION', '발작성 야간 혈뇨증(PNH)은 조혈모세포의 PIG-A 유전자 돌연변이로 인해 보체 억제 단백(CD55, CD59)이 결핍된 혈구가 보체 매개 용혈을 일으키는 희귀 후천성 질환입니다. 주요 증상은 만성 용혈성 빈혈, 야간 또는 이른 아침의 짙은 갈색~흑색 소변(혈색소뇨), 혈전증(특히 비전형 부위), 골수부전이며 피로감, 연하 곤란, 복통이 동반될 수 있습니다. 에쿨리주맙 등 보체 억제제로 효과적인 치료가 가능하므로, 의심 증상이 있다면 혈액내과 전문의 진료를 받으시기 바랍니다.', 4105, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '버킷 림프종', '버킷림프종', 'DEFINITION', '버킷 림프종은 B세포 기원의 고도 악성 비호지킨 림프종으로, c-MYC 유전자 전위(t(8;14) 등)가 특징적이며 세계에서 가장 빠르게 증식하는 종양 중 하나입니다. 풍토형(아프리카형, EBV 관련), 산발형, 면역결핍 관련형으로 구분되며, 복부 종괴, 안면 종양, 림프절 비대, 발열, 체중 감소 등이 증상으로 나타납니다. 집중적인 항암화학요법(CODOX-M/IVAC 또는 R-CHOP 강화 요법)으로 치료 가능성이 있으므로, 조기 진단과 신속한 혈액종양내과 전문의 치료가 중요합니다.', 4106, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '복막 가성점액종', '복막가성점액종', 'DEFINITION', '복막 가성점액종은 복막 내에 다량의 점액성 물질이 축적되는 희귀 질환으로, 주로 충수나 난소의 점액성 종양이 파열되면서 발생합니다. 복부 팽만, 복통, 소화장애 등의 증상이 서서히 나타나며, 진단 시 종양감소수술(세포감소술)과 복강 내 온열항암화학요법(HIPEC)이 주요 치료법입니다. 정확한 진단과 치료 계획은 전문의와 상담하시기 바랍니다.', 4107, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '비장암', '비장암', 'DEFINITION', '비장암은 비장에 발생하는 악성 종양으로, 원발성 비장암은 매우 드물며 대부분 림프종, 혈관육종 등의 형태로 나타납니다. 주요 증상으로는 좌상복부 통증, 비장 비대, 발열, 체중 감소 등이 있으며, 다른 장기에서 전이된 2차성 종양인 경우가 더 흔합니다. 치료 및 예후에 대해서는 혈액종양내과 전문의와 반드시 상담하시기 바랍니다.', 4108, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '비호지킨 림프종', '비호지킨림프종', 'DEFINITION', '비호지킨 림프종은 림프계에서 발생하는 악성 종양으로, 호지킨 림프종을 제외한 다양한 아형을 포함하는 혈액암입니다. 림프절 비대, 발열, 야간 발한, 체중 감소 등의 증상이 나타날 수 있으며, B세포형과 T세포형으로 크게 구분됩니다. 아형에 따라 치료 방법이 달라지므로 혈액종양내과 전문의의 정확한 진단과 상담이 필요합니다.', 4109, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '상대정맥 증후군', '상대정맥증후군', 'DEFINITION', '상대정맥 증후군은 상대정맥이 종양, 혈전, 또는 섬유화 등으로 압박되거나 폐색되어 상체의 정맥 혈류가 저해되는 상태입니다. 안면 부종, 목과 팔의 부종, 호흡 곤란, 두통, 경정맥 확장 등의 증상이 나타나며, 폐암이나 림프종이 주요 원인입니다. 응급 상황일 수 있으므로 즉시 전문의의 진찰과 치료를 받으시기 바랍니다.', 4110, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '소적혈구 빈혈', '소적혈구빈혈', 'DEFINITION', '소적혈구 빈혈은 정상보다 작은 크기의 적혈구(MCV 80fL 미만)가 생성되어 발생하는 빈혈로, 철결핍성 빈혈, 지중해빈혈, 철적모구 빈혈 등이 대표적 원인입니다. 피로감, 창백함, 어지러움, 두근거림, 두통 등의 증상이 나타나며, 원인에 따라 치료 방법이 달라집니다. 정확한 원인 감별을 위해 혈액 검사와 함께 내과 전문의 상담을 권고합니다.', 4111, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '신경 아밀로이드증', '신경아밀로이드증', 'DEFINITION', '신경 아밀로이드증은 비정상적인 아밀로이드 단백질이 말초신경이나 자율신경계에 침착되어 신경 기능을 저해하는 질환입니다. 손발의 저림, 감각 이상, 자율신경 기능 장애(기립성 저혈압, 위장 장애 등), 근력 약화 등의 증상이 점진적으로 진행됩니다. 진단과 치료는 신경과 전문의와 상담하시기 바랍니다.', 4112, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '신생아다혈구증', '신생아다혈구증', 'DEFINITION', '신생아다혈구증은 신생아의 혈중 적혈구 용적률(헤마토크릿)이 65% 이상으로 증가한 상태로, 혈액 점성이 높아져 미세 혈액순환이 저해됩니다. 피부 적색증(다혈증), 호흡 곤란, 저혈당, 무기력, 수유 장애 등의 증상이 나타날 수 있습니다. 신생아 중환자실에서의 집중 모니터링 및 소아과 전문의의 즉각적인 치료가 필요합니다.', 4113, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '신세포암종', '신세포암종', 'DEFINITION', '신세포암종은 신장의 세뇨관 상피세포에서 발생하는 악성 종양으로, 성인 신장암의 가장 흔한 형태입니다. 초기에는 무증상이 많으나 진행 시 혈뇨, 옆구리 통증, 복부 종괴, 체중 감소 등의 증상이 나타납니다. 조기 발견 시 외과적 절제로 완치가 가능하므로 정기적인 검진과 비뇨기과 전문의 상담을 권고합니다.', 4114, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '신우요관암', '신우요관암', 'DEFINITION', '신우요관암은 신장의 신우(콩팥깔때기)나 요관의 이행상피세포에서 발생하는 악성 종양으로, 요로상피암의 일종입니다. 주요 증상으로 혈뇨, 옆구리 통증, 빈뇨, 배뇨 장애 등이 있으며, 흡연이 주요 위험인자입니다. 치료는 수술적 절제가 원칙이며, 비뇨기과 전문의와 정확한 진단과 치료 계획을 상담하시기 바랍니다.', 4115, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '신장 아밀로이드증', '신장아밀로이드증', 'DEFINITION', '신장 아밀로이드증은 비정상적인 아밀로이드 단백질이 신장 조직에 침착되어 신장 기능이 저하되는 질환으로, 전신 아밀로이드증의 일부로 나타나는 경우가 많습니다. 단백뇨, 부종, 신증후군, 신부전 등의 증상이 점진적으로 진행되며, 원발성·이차성 형태로 구분됩니다. 진단 및 치료를 위해 신장내과 전문의와 상담하시기 바랍니다.', 4116, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '악성 뇌종양', '악성뇌종양', 'DEFINITION', '악성 뇌종양은 뇌 또는 뇌를 둘러싼 조직에서 발생하는 악성 종양으로, 교모세포종(GBM)이 가장 흔한 원발성 악성 뇌종양입니다. 두통, 구역, 구토, 경련, 신경학적 결손, 성격 변화 등의 증상이 나타날 수 있으며, 종양의 위치와 크기에 따라 증상이 다양합니다. 신경외과 및 신경종양 전문의와 조속히 상담하여 적절한 치료를 받으시기 바랍니다.', 4117, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '악성 종격동 종양', '악성종격동종양', 'DEFINITION', '악성 종격동 종양은 흉부 중앙의 종격동(심장, 대혈관, 기도 등이 위치한 공간)에 발생하는 악성 종양으로, 흉선암, 악성 림프종, 악성 생식세포종양 등이 포함됩니다. 흉통, 호흡 곤란, 기침, 상대정맥 증후군 등의 증상이 나타날 수 있으며, 진단을 위해 CT, MRI, 조직 생검이 필요합니다. 치료 방침은 흉부외과 및 종양내과 전문의와 상담하시기 바랍니다.', 4118, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '악성 중피종', '악성중피종', 'DEFINITION', '악성 중피종은 흉막, 복막, 심낭 등의 중피세포에서 발생하는 희귀 악성 종양으로, 석면 노출이 가장 중요한 위험인자입니다. 흉통, 호흡 곤란, 흉수 축적, 체중 감소 등의 증상이 나타나며, 잠복기가 수십 년에 달해 진단이 늦어지는 경우가 많습니다. 흉부외과 및 종양내과 전문의와 상담하여 적절한 치료 계획을 세우시기 바랍니다.', 4119, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '악성 흉막 삼출', '악성흉막삼출', 'DEFINITION', '악성 흉막 삼출은 암세포가 흉막을 침범하거나 흉막으로 전이되어 흉막강 내에 비정상적으로 액체가 축적되는 상태입니다. 폐암, 유방암, 림프종 등이 주요 원인이며, 호흡 곤란, 흉통, 기침, 체중 감소 등의 증상이 나타납니다. 흉수천자를 통한 증상 완화와 함께 원발암에 대한 치료가 필요하므로 전문의 상담을 받으시기 바랍니다.', 4120, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '악성 흑색종', '악성흑색종', 'DEFINITION', '악성 흑색종은 피부의 멜라닌 세포에서 발생하는 고악성도 피부암으로, 전이 능력이 높아 조기 발견이 매우 중요합니다. 비대칭, 경계 불규칙, 색조 다양성, 크기 증가, 변화가 있는 점(ABCDE 기준)이 특징적 소견이며, 자외선 노출이 주요 위험인자입니다. 의심 병변 발견 시 즉시 피부과 전문의를 찾아 조직 검사를 받으시기 바랍니다.', 4121, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '양성 뇌종양', '양성뇌종양', 'DEFINITION', '양성 뇌종양은 뇌 또는 주변 조직에서 발생하지만 침윤성이 없고 전이하지 않는 종양으로, 뇌수막종, 청신경초종, 뇌하수체 선종 등이 대표적입니다. 종양의 위치와 크기에 따라 두통, 경련, 신경학적 이상, 시력 변화 등의 증상이 다양하게 나타납니다. 양성이라도 뇌 압박으로 심각한 증상을 유발할 수 있으므로 신경외과 전문의의 진료와 상담이 필요합니다.', 4122, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '양성 종격동 종양', '양성종격동종양', 'DEFINITION', '양성 종격동 종양은 흉부 종격동에 발생하는 비악성 종양으로, 흉선종, 양성 신경원성 종양, 기형종, 낭종 등이 포함됩니다. 대부분 무증상으로 영상 검사에서 우연히 발견되나 크기가 커지면 흉통, 기침, 호흡 곤란 등을 유발할 수 있습니다. 정확한 진단과 치료 방침을 위해 흉부외과 전문의와 상담하시기 바랍니다.', 4123, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '연부조직육종', '연부조직육종', 'DEFINITION', '연부조직육종은 지방, 근육, 신경, 혈관, 섬유조직 등의 연부조직에서 발생하는 악성 종양으로, 지방육종, 횡문근육종, 활막육종 등 다양한 아형이 있습니다. 사지나 후복막에 무통성 종괴로 나타나는 경우가 많으며, 크기가 클수록 악성도가 높을 수 있습니다. 치료는 수술적 절제가 기본이며, 방사선 및 항암 치료를 병행하므로 전문의 상담이 필요합니다.', 4124, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '용혈성 빈혈', '용혈성빈혈', 'DEFINITION', '용혈성 빈혈은 적혈구가 정상 수명(약 120일)보다 일찍 파괴되어 골수의 보상 생성 능력을 초과할 때 발생하는 빈혈입니다. 피로감, 창백, 황달, 비장 비대, 암적색 소변 등의 증상이 나타나며, 유전적 원인(겸상적혈구 빈혈, 지중해빈혈 등)과 후천적 원인(자가면역, 약물 등)으로 구분됩니다. 정확한 원인 진단과 치료를 위해 혈액내과 전문의와 상담하시기 바랍니다.', 4125, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '위말트림프종', '위말트림프종', 'DEFINITION', '위말트림프종(위 MALT 림프종)은 위의 점막연관 림프조직에서 발생하는 저악성도 B세포 림프종으로, 대부분 헬리코박터 파일로리균 감염과 밀접한 관련이 있습니다. 소화불량, 상복부 통증, 오심, 위장 출혈 등의 증상이 나타날 수 있으며, 초기 단계에서는 헬리코박터 제균 치료만으로 완해되는 경우가 많습니다. 정확한 병기 설정과 치료를 위해 소화기내과 및 혈액종양내과 전문의 상담을 권고합니다.', 4126, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '위유암종', '위유암종', 'DEFINITION', '위유암종(위 카르시노이드 종양)은 위의 신경내분비세포에서 발생하는 종양으로, 세로토닌 등의 호르몬을 분비할 수 있습니다. 대부분 증상이 없거나 경미하며, 크기와 위치에 따라 소화불량, 복통, 위장 출혈 등이 나타날 수 있고 드물게 카르시노이드 증후군을 유발합니다. 치료 방침은 종양의 크기와 악성도에 따라 다르므로 소화기내과 또는 외과 전문의와 상담하시기 바랍니다.', 4127, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '위장관 기질 종양', '위장관기질종양', 'DEFINITION', '위장관 기질 종양(GIST)은 위장관의 카할 간질세포에서 발생하는 중간엽 종양으로, 위에서 가장 흔하게 발생합니다. KIT 또는 PDGFRA 유전자 돌연변이가 대부분의 경우에서 확인되며, 복통, 위장 출혈, 복부 종괴 등의 증상이 나타납니다. 수술적 절제와 표적 항암제(이마티닙 등)가 주요 치료법이므로 외과 및 종양내과 전문의 상담을 권고합니다.', 4128, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '유방 파젯트병', '유방파젯트병', 'DEFINITION', '유방 파젯트병은 유두와 유륜의 표피에 악성 세포(파젯트 세포)가 침윤하는 희귀한 유방암의 한 형태입니다. 유두의 습진 같은 피부 변화, 가려움, 발적, 분비물, 궤양 등의 증상이 나타나며, 대부분 내부 유방암과 동반됩니다. 증상 발견 시 즉시 외과 또는 유방 전문의를 찾아 정확한 진단과 치료를 받으시기 바랍니다.', 4129, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '유잉육종', '유잉육종', 'DEFINITION', '유잉육종은 주로 뼈(대퇴골, 골반, 늑골 등)에서 발생하는 악성 종양으로, 소아 및 청소년에게 가장 흔한 골종양 중 하나입니다. EWSR1 유전자와 ETS 계열 전사인자의 융합이 특징적이며, 국소 통증, 종창, 발열, 체중 감소 등의 증상이 나타납니다. 수술, 항암화학요법, 방사선 치료를 병합하는 집중 치료가 필요하므로 소아청소년과 및 정형외과 종양 전문의와 상담하시기 바랍니다.', 4130, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '자궁의 평활근종', '자궁의평활근종', 'DEFINITION', '자궁의 평활근종(자궁근종)은 자궁 평활근 세포에서 발생하는 양성 종양으로, 가임기 여성에서 가장 흔한 골반 내 종양입니다. 월경 과다, 골반 통증·압박감, 빈뇨, 불임 또는 유산 등의 증상이 나타날 수 있으며, 에스트로겐의 영향을 받아 폐경 후 자연히 크기가 감소하는 경향이 있습니다. 증상의 정도와 향후 임신 계획에 따라 치료 방침이 달라지므로 산부인과 전문의와 상담하시기 바랍니다.', 4131, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '재생불량성 빈혈', '재생불량성빈혈', 'DEFINITION', '재생불량성 빈혈은 골수의 조혈모세포가 감소하거나 기능을 잃어 혈액 세포(적혈구, 백혈구, 혈소판) 생성이 전반적으로 저하되는 희귀 혈액 질환입니다. 피로감, 창백, 잦은 감염, 출혈 경향(멍, 점출혈) 등의 증상이 나타나며, 자가면역, 독성 물질 노출, 유전 등이 원인이 될 수 있습니다. 조혈모세포이식이나 면역억제 치료가 필요할 수 있으므로 혈액내과 전문의와 즉시 상담하시기 바랍니다.', 4132, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '전이성 신장암', '전이성신장암', 'DEFINITION', '전이성 신장암은 신세포암종이 림프절, 폐, 뼈, 간, 뇌 등 다른 장기로 퍼진 상태(4기)를 말합니다. 원발 병소의 증상 외에도 전이 부위에 따른 다양한 증상(골통증, 호흡 곤란, 두통 등)이 나타날 수 있습니다. 표적 치료제, 면역항암제 등의 전신 치료가 주요 치료 방법이며, 비뇨기과 및 종양내과 전문의와의 상담을 통해 개인화된 치료 계획 수립이 필요합니다.', 4133, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '지중해빈혈', '지중해빈혈', 'DEFINITION', '지중해빈혈(탈라세미아)은 헤모글로빈을 구성하는 글로빈 사슬의 유전적 결함으로 인해 발생하는 유전성 용혈성 빈혈입니다. 알파형과 베타형으로 구분되며, 중등도 이상의 경우 만성 빈혈, 황달, 비장 비대, 성장 지연, 골격 변화 등의 증상이 나타납니다. 정기적인 수혈과 철 킬레이션 치료, 중증 환자의 경우 조혈모세포이식이 필요하므로 혈액내과 전문의와 상담하시기 바랍니다.', 4134, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '직장 유암종', '직장유암종', 'DEFINITION', '직장 유암종은 직장의 신경내분비세포에서 발생하는 종양으로, 대부분 크기가 작고 증상이 없어 대장 내시경 검사 중 우연히 발견됩니다. 크기가 2cm 이상이거나 심부 침범이 있는 경우 악성 가능성이 높으며, 드물게 출혈, 배변 습관 변화, 항문 통증이 나타납니다. 크기와 침범 정도에 따라 내시경 절제 또는 수술이 필요하므로 소화기내과 및 외과 전문의와 상담하시기 바랍니다.', 4135, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '진행성 위암', '진행성위암', 'DEFINITION', '진행성 위암은 암세포가 위벽의 점막하층을 넘어 근육층 이상으로 침범한 위암으로, 초기 위암에 비해 예후가 불량합니다. 상복부 통증, 체중 감소, 식욕 부진, 구역, 토혈, 흑색변 등의 증상이 나타날 수 있으며, 림프절 및 원격 전이 가능성이 높습니다. 수술, 항암화학요법, 방사선 치료를 병합하는 다학제 치료가 필요하므로 외과 및 종양내과 전문의와 상담하시기 바랍니다.', 4136, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '충수암', '충수암', 'DEFINITION', '충수암은 충수(맹장 끝의 돌기)에 발생하는 악성 종양으로, 카르시노이드 종양, 점액성 선암, 결장형 선암 등 여러 아형이 있습니다. 급성 충수염과 유사한 우하복부 통증, 복부 팽만, 복막 가성점액종 등의 증상이 나타날 수 있으며, 충수염 수술 중 우연히 발견되는 경우가 많습니다. 아형과 병기에 따라 추가 수술이나 항암 치료가 필요할 수 있으므로 외과 및 종양내과 전문의와 상담하시기 바랍니다.', 4137, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '췌장 전이암', '췌장전이암', 'DEFINITION', '췌장 전이암은 다른 장기의 암이 췌장으로 전이된 상태로, 신장암, 폐암, 대장암, 유방암 등이 주요 원발암입니다. 복통, 체중 감소, 황달, 소화 장애 등의 증상이 나타날 수 있으나 초기에는 무증상인 경우도 많습니다. 치료는 원발 종양의 종류와 전반적인 전이 상황에 따라 결정되므로 종양내과 전문의와 상담하시기 바랍니다.', 4138, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '카르시노이드 증후군', '카르시노이드증후군', 'DEFINITION', '카르시노이드 증후군은 신경내분비종양(유암종)이 세로토닌, 히스타민, 브라디키닌 등의 혈관 활성 물질을 과잉 분비할 때 나타나는 증상 복합체입니다. 피부 홍조, 설사, 복통, 기관지 경련, 우심부전(삼첨판 협착/폐동맥 협착) 등의 특징적인 증상이 나타납니다. 소마토스타틴 유사체 투여 및 외과적 치료 등이 필요하므로 내분비내과 및 종양내과 전문의와 상담하시기 바랍니다.', 4139, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '카포시 육종', '카포시육종', 'DEFINITION', '카포시 육종은 인간 헤르페스바이러스 8형(HHV-8) 감염에 의해 발생하는 혈관 기원의 악성 종양으로, HIV/AIDS 환자에서 가장 흔하게 발생합니다. 피부의 자색 또는 갈색 결절이나 반점이 특징적이며, 폐, 위장관, 림프절 등의 내부 장기로 퍼질 수 있습니다. HIV 치료(항레트로바이러스 요법)와 함께 화학요법, 방사선 치료가 사용되므로 감염내과 및 종양내과 전문의와 상담하시기 바랍니다.', 4140, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '캐슬만병', '캐슬만병', 'DEFINITION', '캐슬만병은 림프절에서 비정상적인 림프 조직이 과증식하는 희귀한 림프계 질환으로, 단일 부위형(유니센트릭)과 다부위형(멀티센트릭)으로 구분됩니다. 림프절 비대, 발열, 야간 발한, 체중 감소, 피로감 등의 증상이 나타나며, HHV-8 감염이나 IL-6 과잉 분비와 관련이 있습니다. 치료 방법은 아형에 따라 수술, 항암화학요법, 항IL-6 치료제 등이 사용되므로 혈액내과 전문의와 상담하시기 바랍니다.', 4141, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '타액선암', '타액선암', 'DEFINITION', '타액선암은 귀밑샘(이하선), 턱밑샘(악하선), 혀밑샘(설하선) 등의 타액선에서 발생하는 악성 종양으로, 점액표피양 암종, 선양 낭성 암종, 선방 세포 암종 등이 대표적입니다. 점진적으로 커지는 종괴, 통증, 안면 신경 마비, 피부 고정 등의 증상이 나타날 수 있습니다. 수술적 절제가 주요 치료이며, 방사선 치료를 병행하므로 이비인후과 두경부외과 전문의와 상담하시기 바랍니다.', 4142, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '폐 전이', '폐전이', 'DEFINITION', '폐 전이는 다른 장기의 암세포가 혈류나 림프관을 통해 폐로 이동하여 증식하는 상태로, 대장암, 유방암, 신장암, 골육종 등이 흔한 원발암입니다. 초기에는 대부분 무증상이나 진행 시 기침, 혈담, 호흡 곤란, 흉통 등의 증상이 나타날 수 있습니다. 치료는 원발 종양의 종류와 전이 범위에 따라 다르며, 흉부외과 및 종양내과 전문의와 상담하시기 바랍니다.', 4143, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '포르피린증', '포르피린증', 'DEFINITION', '포르피린증은 헴(heme) 생합성 경로의 효소 결함으로 인해 포르피린 또는 그 전구체가 체내에 과도하게 축적되는 유전 대사 질환입니다. 급성 형태에서는 복통, 구역, 신경 증상, 정신 증상이, 피부형에서는 광과민성 피부 병변이 특징적입니다. 여러 아형이 있으며 치료가 복잡하므로 내과 및 유전대사 전문의와 상담하시기 바랍니다.', 4144, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '폰 빌레브란트병', '폰빌레브란트병', 'DEFINITION', '폰 빌레브란트병은 혈액응고에 필요한 폰 빌레브란트 인자(vWF)의 결핍 또는 기능 이상으로 발생하는 가장 흔한 유전성 출혈 질환입니다. 점막 출혈(코피, 잇몸 출혈), 월경 과다, 경미한 외상 후 지속적 출혈, 수술 후 과도한 출혈 등의 증상이 나타납니다. 데스모프레신(DDAVP) 또는 vWF 농축제 치료가 필요하므로 혈액내과 전문의와 상담하시기 바랍니다.', 4145, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '한랭글로불린혈증', '한랭글로불린혈증', 'DEFINITION', '한랭글로불린혈증은 저온에서 침전하는 비정상 면역글로불린(한랭글로불린)이 혈액 내에 존재하는 상태로, C형 간염 바이러스 감염과 가장 흔히 연관됩니다. 한냉 노출 시 자반증, 관절통, 피로감, 레이노 현상, 신장염 등의 증상이 나타납니다. 원인 질환 치료와 함께 면역억제 치료가 필요하므로 류마티스내과 또는 내과 전문의와 상담하시기 바랍니다.', 4146, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '호산구 감소증', '호산구감소증', 'DEFINITION', '호산구 감소증은 혈중 호산구 수치가 정상 하한치(100/μL) 미만으로 감소한 상태로, 급성 감염, 스트레스 반응, 코르티코스테로이드 투여 등이 주요 원인입니다. 대부분 일시적이며 증상이 없는 경우가 많으나, 면역 기능 이상이나 기저 질환을 시사할 수 있습니다. 지속적인 호산구 감소 시 내과 전문의의 진찰을 통해 원인 감별이 필요합니다.', 4147, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('종양혈액질환', '횡문근육종', '횡문근육종', 'DEFINITION', '횡문근육종은 횡문근(골격근) 세포에서 발생하는 악성 연부조직 종양으로, 소아와 청소년에서 가장 흔한 연부조직 육종입니다. 주로 두경부, 사지, 비뇨생식기 등에 발생하며 통증 없는 종괴, 종양 위치에 따른 기능 장애 등의 증상이 나타납니다. 수술, 항암화학요법, 방사선 치료의 복합 치료가 필요하므로 소아청소년과 및 소아종양 전문의와 상담하시기 바랍니다.', 4148, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '근단 주위 농양', '근단주위농양', 'DEFINITION', '근단 주위 농양은 치아 뿌리 끝(근단부) 주변에 세균 감염으로 인해 고름이 형성된 급성 치과 질환입니다. 심한 치통, 치아 압통, 잇몸 부종, 발열, 턱 부위 부종 등의 증상이 나타나며, 치료하지 않으면 감염이 주변 조직으로 퍼질 수 있습니다. 즉시 치과 전문의를 찾아 배농 처치, 근관 치료 또는 발치 등의 적절한 치료를 받으시기 바랍니다.', 4149, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '급성 치수염', '급성치수염', 'DEFINITION', '급성 치수염은 치아 내부의 신경과 혈관이 있는 치수 조직에 세균 감염이나 자극으로 급성 염증이 발생한 상태입니다. 극심한 자발통, 냉열 자극에 대한 과민 반응, 박동성 통증, 야간에 악화되는 통증이 특징적입니다. 근관 치료(신경 치료)가 필요하므로 즉시 치과 전문의를 찾아 진단과 치료를 받으시기 바랍니다.', 4150, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '설통', '설통', 'DEFINITION', '설통은 혀에 발생하는 통증 또는 작열감으로, 구강 내 감염(칸디다증), 구강 점막 질환, 영양 결핍(철분, 비타민 B12), 전신 질환, 심리적 요인 등 다양한 원인으로 발생합니다. 혀의 따가움, 쓰라림, 작열감이 지속되며, 식사 시 악화되거나 구강 점막 변화가 동반될 수 있습니다. 정확한 원인 규명을 위해 구강내과 또는 이비인후과 전문의 진찰을 권고합니다.', 4151, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('치과질환', '안와골절', '안와골절', 'DEFINITION', '안와골절은 눈 주위를 둘러싸는 뼈(안와)에 외상으로 인해 발생하는 골절로, 안와 바닥(하벽) 골절이 가장 흔하며 ''블로우아웃 골절''이라고도 합니다. 안구 주위 부종·멍, 복시(이중시), 안구 함몰, 안구 운동 제한, 뺨 감각 이상 등의 증상이 나타납니다. 안과 또는 성형외과(두개악안면외과) 전문의의 즉각적인 평가와 치료가 필요합니다.', 4152, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '간찰성 홍반', '간찰성홍반', 'DEFINITION', '간찰성 홍반은 피부가 맞닿는 부위(겨드랑이, 사타구니, 유방 하부 등)에서 지속적인 마찰, 습기, 열 등으로 인해 발생하는 피부염입니다. 붉은 발진, 가려움, 작열감, 진물, 피부 짓무름 등이 특징적이며, 비만인 경우 더 흔하게 발생합니다. 청결 유지, 건조 관리, 항진균제 또는 스테로이드 연고 사용 등이 도움이 될 수 있으며, 증상이 지속되면 피부과 전문의 진찰을 권고합니다.', 4153, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '광선 각화증', '광선각화증', 'DEFINITION', '광선 각화증은 장기간의 자외선 노출로 인해 피부의 각질형성세포에 이형성이 발생하는 전암성 피부 병변입니다. 주로 얼굴, 두피, 손등 등 햇빛에 노출된 부위에 거칠고 각질이 있는 붉은 반점 형태로 나타납니다. 치료하지 않으면 편평세포암으로 진행될 수 있으므로 피부과 전문의를 통해 냉동 치료, 국소 치료제 등의 적절한 치료를 받으시기 바랍니다.', 4154, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '국소 다한증', '국소다한증', 'DEFINITION', '국소 다한증은 손바닥, 발바닥, 겨드랑이, 얼굴 등 특정 부위에서 정상적인 체온 조절에 필요한 양을 훨씬 초과하는 과도한 발한이 발생하는 상태입니다. 정서적 자극이나 열에 반응하여 악화되며, 사회적·직업적 기능을 심각하게 저해할 수 있습니다. 알루미늄계 발한억제제, 이온영동치료, 보톡스 주사, 교감신경 절제술 등의 치료가 있으므로 피부과 전문의와 상담하시기 바랍니다.', 4155, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '기저귀 피부염', '기저귀피부염', 'DEFINITION', '기저귀 피부염은 기저귀 착용 영아에서 소변과 대변에 의한 자극, 마찰, 습기로 인해 기저귀 부위 피부에 발생하는 접촉성 자극 피부염입니다. 기저귀 부위의 발적, 부종, 구진, 드물게 진물 등이 나타나며, 칸디다 감염이 동반될 수 있습니다. 잦은 기저귀 교환, 피부 보습과 건조 유지, 아연 산화물 연고 도포가 도움이 되며, 호전이 없으면 소아과 전문의 진찰을 받으시기 바랍니다.', 4156, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '다모증', '다모증', 'DEFINITION', '다모증은 여성에서 남성 호르몬(안드로겐)에 반응하는 부위(턱, 윗입술, 가슴, 복부, 허벅지 등)에 굵고 검은 털이 과도하게 자라는 상태입니다. 다낭성 난소 증후군(PCOS), 부신 질환, 일부 약물 복용, 종양 등이 원인이 될 수 있습니다. 원인 질환 치료와 함께 호르몬 치료, 레이저 제모 등의 방법을 사용하므로 피부과 또는 내분비내과 전문의와 상담하시기 바랍니다.', 4157, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '단독', '단독', 'DEFINITION', '단독(丹毒)은 주로 연쇄상구균(A군 베타 용혈성 연쇄구균)에 의해 피부 진피와 표재성 림프관에 발생하는 급성 세균성 감염입니다. 경계가 뚜렷한 붉고 부어오른 피부 병변, 발열, 오한, 국소 열감과 통증이 특징이며, 얼굴과 다리에 자주 발생합니다. 페니실린계 항생제 치료가 효과적이므로 즉시 내과 또는 피부과 전문의의 진찰을 받으시기 바랍니다.', 4158, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '대상포진 후 신경통', '대상포진후신경통', 'DEFINITION', '대상포진 후 신경통은 대상포진 발진이 호전된 후에도 해당 부위에 통증이 3개월 이상 지속되는 만성 신경병증성 통증입니다. 작열감, 찌르는 듯한 통증, 이질통(정상 자극에도 통증을 느낌), 감각 이상 등이 나타나며, 고령이나 면역 저하 환자에서 발생 위험이 높습니다. 삼환계 항우울제, 항경련제, 국소 리도카인 패치 등의 약물 치료가 사용되므로 신경과 또는 통증 전문의와 상담하시기 바랍니다.', 4159, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '돌발성 발진', '돌발성발진', 'DEFINITION', '돌발성 발진(장미진)은 인간 헤르페스바이러스 6형(HHV-6) 감염에 의해 주로 영아(6~24개월)에서 발생하는 급성 열성 발진 질환입니다. 3~4일간 고열이 지속된 후 열이 떨어지면서 몸통에서 시작해 팔다리로 퍼지는 분홍색 발진이 나타납니다. 대부분 자연 치유되며 특별한 치료가 필요하지 않으나, 열성 경련 예방과 증상 관리를 위해 소아과 전문의의 진찰을 권고합니다.', 4160, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '동전모양 습진', '동전모양습진', 'DEFINITION', '동전모양 습진(화폐상 습진)은 동전 모양의 원형 또는 타원형 습진 병변이 주로 팔다리에 대칭적으로 나타나는 만성 피부 질환입니다. 가려움증, 진물, 딱지, 피부 건조 등의 증상이 반복되며, 건조한 환경, 피부 자극, 스트레스 등이 악화 요인입니다. 국소 스테로이드, 보습제 사용, 악화 요인 회피가 치료의 기본이며, 증상이 지속되면 피부과 전문의 진찰을 받으시기 바랍니다.', 4161, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '만성 단순 태선', '만성단순태선', 'DEFINITION', '만성 단순 태선(신경피부염)은 반복적인 긁기와 문지르기로 인해 피부가 두꺼워지고(태선화) 가죽처럼 변하는 만성 피부 질환입니다. 극심한 가려움증이 특징이며, 긁으면 일시적으로 해소되지만 가려움-긁기의 악순환이 반복됩니다. 국소 스테로이드, 항히스타민제, 스트레스 관리가 치료에 도움이 되므로 피부과 전문의와 상담하시기 바랍니다.', 4162, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '모반', '모반', 'DEFINITION', '모반(점)은 멜라닌 세포 또는 모반 세포가 국소적으로 증식하여 피부에 형성된 양성 색소성 병변입니다. 선천성과 후천성으로 구분되며, 대부분 양성이나 크기가 크거나 비전형적인 모반은 악성 흑색종으로 변화할 가능성이 있습니다. 비대칭, 불규칙한 경계, 여러 색깔, 6mm 이상의 크기, 변화(ABCDE) 소견이 있는 경우 피부과 전문의의 진찰을 받으시기 바랍니다.', 4163, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '무모증', '무모증', 'DEFINITION', '무모증은 정상적으로 털이 나야 하는 부위(음모, 겨드랑이 등)에 털이 거의 없거나 전혀 없는 상태로, 선천성 또는 후천성으로 발생할 수 있습니다. 유전적 요인, 호르몬 이상(성선기능저하증 등), 자가면역 탈모(원형 탈모), 피부 질환 등이 원인이 됩니다. 정확한 원인 감별을 위해 피부과 또는 내분비내과 전문의의 진찰을 받으시기 바랍니다.', 4164, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '백반증', '백반증', 'DEFINITION', '백반증은 피부의 멜라닌 세포가 파괴되어 경계가 뚜렷한 흰색 탈색 반점이 나타나는 후천성 자가면역 피부 질환입니다. 자가면역 기전, 유전적 소인, 산화 스트레스 등이 발병에 관여하며, 얼굴, 손, 생식기 주변 등 자외선 노출 부위나 마찰이 많은 부위에 호발합니다. 완전한 치유가 어려울 수 있으나 광선 치료, 국소 스테로이드, 면역 억제 연고 등의 치료가 도움이 되므로 피부과 전문의와 상담하시기 바랍니다.', 4165, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '베체트 병', '베체트병', 'DEFINITION', '베체트병은 반복성 구강 궤양, 생식기 궤양, 안구 병변(포도막염)을 3대 주증상으로 하는 전신성 혈관염 질환입니다. 피부 병변(가성 모낭염, 결절성 홍반), 관절염, 신경계 및 혈관 침범 등 다양한 장기를 침범할 수 있습니다. 자가면역 기전이 관여하며 완치보다는 증상 조절을 목표로 치료하므로 류마티스내과 전문의와 상담하시기 바랍니다.', 4166, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '비립종', '비립종', 'DEFINITION', '비립종은 피부 표면 가까이에 케라틴이 포함된 작은 낭종이 형성되어 흰색 또는 황백색의 1~2mm 크기 구진으로 나타나는 양성 피부 질환입니다. 주로 눈 주위, 뺨 등의 얼굴에 발생하며, 신생아의 일차성 비립종은 자연 소실되나 성인의 이차성 비립종은 피부 손상 부위에 발생합니다. 미용적으로 문제가 되는 경우 피부과에서 제거 시술을 받을 수 있습니다.', 4167, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '선천성 색소결핍증', '선천성색소결핍증', 'DEFINITION', '선천성 색소결핍증(알비노증)은 멜라닌 색소 합성에 관여하는 유전자 결함으로 피부, 모발, 눈에 멜라닌 색소가 결핍되는 유전 질환입니다. 흰 피부, 흰머리, 밝은 눈동자, 광과민성, 시각 이상(안진, 약시) 등의 특징이 나타납니다. 자외선 차단과 정기적인 안과 및 피부과 검진이 매우 중요하며, 전문의와 지속적인 추적 관찰이 필요합니다.', 4168, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '수부 습진', '수부습진', 'DEFINITION', '수부 습진은 손에 발생하는 습진성 피부 질환의 총칭으로, 접촉성 피부염, 한포진, 건성 습진, 과각화성 습진 등 다양한 아형이 포함됩니다. 가려움증, 발적, 수포, 각질, 균열, 진물 등의 증상이 나타나며, 잦은 물 접촉, 세제, 화학물질, 알레르겐 등이 주요 악화 요인입니다. 원인 회피, 보습, 국소 스테로이드 치료가 기본이며, 증상이 지속되면 피부과 전문의 진찰을 받으시기 바랍니다.', 4169, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '슈도모나스 감염', '슈도모나스감염', 'DEFINITION', '슈도모나스 감염은 녹농균(Pseudomonas aeruginosa)에 의한 기회 감염으로, 주로 면역 저하자, 화상 환자, 중증 입원 환자 등에서 심각한 감염을 일으킵니다. 폐렴, 요로 감염, 창상 감염, 패혈증 등 다양한 형태로 나타나며, 다약제 내성이 흔해 치료가 어렵습니다. 항슈도모나스 활성을 가진 항생제 치료가 필요하므로 감염내과 전문의의 진단과 치료 지침을 따르시기 바랍니다.', 4170, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '스티븐 존슨 증후군', '스티븐존슨증후군', 'DEFINITION', '스티븐-존슨 증후군은 약물 부작용이나 감염에 의해 피부와 점막에 심각한 수포성 박리가 발생하는 중증 피부 과민 반응입니다. 체표면적의 10% 미만이 침범되면 스티븐-존슨 증후군, 30% 이상이면 독성표피괴사용해로 분류됩니다. 원인 약물 즉시 중단과 집중 치료가 필요한 응급 질환이므로 즉시 응급실이나 피부과 전문의의 치료를 받으시기 바랍니다.', 4171, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '어루러기', '어루러기', 'DEFINITION', '어루러기(전풍)는 말라세지아 효모균의 과증식으로 인해 피부에 색소 변화가 발생하는 표재성 진균 감염입니다. 주로 가슴, 등, 어깨 등에 흰색, 분홍색 또는 갈색의 작은 반점들이 합쳐져 나타나며, 가려움증이 동반될 수 있고 햇빛 노출 후 더 뚜렷하게 보입니다. 항진균제(국소 또는 경구) 치료로 효과적으로 치료 가능하며, 피부과 전문의의 진찰을 권고합니다.', 4172, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '어린선', '어린선', 'DEFINITION', '어린선은 피부의 각질화 이상으로 인해 피부 표면이 물고기 비늘처럼 건조하고 각질화되는 유전성 또는 후천성 피부 질환입니다. 피부 건조, 각질화, 균열, 가려움증 등의 증상이 특징이며, 팔다리와 몸통에 주로 나타납니다. 완치보다는 보습제의 지속적 사용과 각질 용해제를 통한 증상 관리가 중요하며, 피부과 전문의의 지속적인 관리가 필요합니다.', 4173, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '오타 모반', '오타모반', 'DEFINITION', '오타 모반은 삼차신경(주로 안신경, 상악신경)의 지배 부위인 얼굴 한쪽에 청갈색 또는 청흑색의 반점이 나타나는 선천성 색소 질환입니다. 멜라닌 세포가 진피층에 위치하는 것이 특징이며, 공막(흰자위), 결막, 구개 점막 등에도 색소 침착이 나타날 수 있습니다. 악성 흑색종으로 변화할 가능성이 있으므로 정기 검진이 필요하며, 레이저 치료가 효과적이므로 피부과 전문의와 상담하시기 바랍니다.', 4174, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '접촉성 피부염', '접촉성피부염', 'DEFINITION', '접촉성 피부염은 특정 물질과 피부의 접촉으로 인해 발생하는 피부 염증 반응으로, 자극성 접촉 피부염과 알레르기성 접촉 피부염으로 구분됩니다. 접촉 부위에 발적, 가려움, 수포, 진물, 부종 등의 증상이 나타나며, 원인 물질로는 화장품, 세제, 금속(니켈), 라텍스 등이 있습니다. 원인 물질 회피가 가장 중요하며, 국소 스테로이드 및 항히스타민제 치료를 위해 피부과 전문의와 상담하시기 바랍니다.', 4175, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '탄저병', '탄저병', 'DEFINITION', '탄저병은 Bacillus anthracis 세균의 아포(포자)에 의해 발생하는 급성 감염 질환으로, 피부형, 폐형, 소화기형으로 구분됩니다. 피부형은 가려운 구진에서 검은 딱지가 형성되는 탄저성 궤양이 특징이며, 폐형과 소화기형은 치명률이 매우 높습니다. 생물 테러에도 사용될 수 있는 법정 감염병으로, 즉각적인 항생제(시프로플록사신, 독시사이클린) 치료와 감염병 당국 신고가 필요합니다.', 4176, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '탈락 피부염', '탈락피부염', 'DEFINITION', '탈락 피부염(박탈성 피부염)은 전신 피부 표면의 90% 이상이 발적과 각질 탈락으로 덮이는 심각한 염증성 피부 질환입니다. 건선, 아토피 피부염, 약물 반응, 림프종 등이 원인이 될 수 있으며, 체온 조절 장애, 저단백혈증, 2차 감염, 심부전 등의 합병증이 발생할 수 있습니다. 입원 치료가 필요한 경우가 많으므로 즉시 피부과 전문의의 진찰과 치료를 받으시기 바랍니다.', 4177, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '태열', '태열', 'DEFINITION', '태열(영아 아토피 피부염)은 생후 2~6개월부터 시작되는 영아기의 만성 가려움성 습진성 피부 질환으로, 아토피 피부염의 영아기 형태입니다. 뺨, 이마, 두피에서 시작되는 건조하고 가려운 붉은 피부 병변이 특징이며, 유전적 소인과 환경 요인이 복합적으로 작용합니다. 보습 관리, 악화 요인 회피, 국소 스테로이드 치료가 기본이며, 소아과 또는 피부과 전문의와 상담하시기 바랍니다.', 4178, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '편평 태선', '편평태선', 'DEFINITION', '편평 태선은 피부, 점막, 모발, 손발톱 등을 침범하는 만성 염증성 자가면역 피부 질환입니다. 피부형은 자주빛 다각형의 편평한 구진이 특징이며, 구강형은 구강 내 레이스 모양의 흰 선(위컴 줄기)으로 나타납니다. 자연 소실되는 경우도 있으나 국소 스테로이드, 레티노이드 등의 치료가 필요하므로 피부과 전문의와 상담하시기 바랍니다.', 4179, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '표피낭종', '표피낭종', 'DEFINITION', '표피낭종은 표피 세포가 진피 내에 갇혀 케라틴 물질이 축적된 주머니를 형성하는 양성 피부 종양입니다. 피부 아래 움직이는 부드러운 종괴로 나타나며, 중앙에 검은 점(모공 개구부)이 보이는 경우가 많습니다. 감염 시 통증, 발적, 고름이 발생할 수 있으며, 재발 방지를 위해 낭종 벽을 완전히 제거하는 수술적 절제가 필요하므로 피부과 전문의와 상담하시기 바랍니다.', 4180, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '피부 농양', '피부농양', 'DEFINITION', '피부 농양은 피부 내 또는 피하 조직에 세균 감염으로 인해 고름이 집적된 상태로, 주로 황색포도상구균이 원인균입니다. 발적, 종창, 열감, 통증이 있는 종괴가 형성되며, 압통과 파동감(물렁물렁한 느낌)이 나타납니다. 치료는 절개 및 배농이 기본이며, 필요시 항생제를 병용하므로 외과 또는 피부과 전문의의 치료를 받으시기 바랍니다.', 4181, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '피부근육염', '피부근육염', 'DEFINITION', '피부근육염은 피부와 근육에 동시에 염증이 발생하는 자가면역 질환으로, 특징적인 자주빛 눈꺼풀 발적(헬리오트로프 발진)과 손가락 관절 위 구진(고트론 구진)이 진단에 중요합니다. 근위부 근육 약화, 근육통, 연하 장애 등의 근육 증상과 함께 전신 증상이 나타납니다. 성인의 경우 악성 종양이 동반될 수 있으므로 류마티스내과 전문의의 정확한 진단과 치료가 필수적입니다.', 4182, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '피부섬유육종', '피부섬유육종', 'DEFINITION', '피부섬유육종(융기성 피부섬유육종, DFSP)은 피부 진피층에서 발생하는 저악성도 연부조직 육종으로, 서서히 자라는 무통성 융기 결절이 특징입니다. 주로 몸통과 사지 근위부에 발생하며, 국소 재발률이 높으나 전이는 드뭅니다. 넓은 절제연을 확보하는 수술적 절제(모스 미세 수술)가 주요 치료이므로 피부과 또는 외과 전문의와 상담하시기 바랍니다.', 4183, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '한랭 두드러기', '한랭두드러기', 'DEFINITION', '한랭 두드러기는 차가운 공기, 물, 음식 등의 한랭 자극에 노출 후 수 분 내에 두드러기와 혈관부종이 발생하는 물리적 두드러기입니다. 차가운 물에 접촉한 부위에 팽진과 가려움증이 나타나며, 심한 경우 전신에 노출되면 아나필락시스를 유발할 수 있습니다. 한랭 자극 회피와 항히스타민제 예방 투여가 중요하며, 피부과 또는 알레르기 전문의와 상담하시기 바랍니다.', 4184, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '한센병', '한센병', 'DEFINITION', '한센병(나병)은 Mycobacterium leprae 세균에 의해 발생하는 만성 감염 질환으로, 주로 피부와 말초신경을 침범합니다. 피부 반점, 결절, 피부 두꺼워짐, 말초신경 마비로 인한 감각 소실, 근력 약화 등이 특징이며, 조기 발견 시 다제내성 항생제 치료(MDT)로 완치 가능합니다. 법정 감염병으로, 의심 시 피부과 또는 감염내과 전문의를 즉시 찾아 치료를 받으시기 바랍니다.', 4185, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '한포진', '한포진', 'DEFINITION', '한포진은 손바닥, 발바닥, 손발가락 측면에 깊은 수포가 집단으로 발생하는 반복성 습진성 피부 질환입니다. 수포 형성 전에 극심한 가려움과 작열감이 선행되며, 수포는 저절로 건조되고 각질이 벗겨지는 경과를 보입니다. 스트레스, 발한, 금속 알레르기(니켈) 등이 유발 요인이며, 국소 스테로이드 치료와 악화 요인 회피를 위해 피부과 전문의 진찰을 권고합니다.', 4186, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('피부질환', '화염상 모반', '화염상모반', 'DEFINITION', '화염상 모반(포도주색 반점)은 진피의 모세혈관이 비정상적으로 확장되어 피부에 붉은색~자주색의 납작한 혈관 기형이 나타나는 선천성 질환입니다. 주로 얼굴과 목에 발생하며, 나이가 들수록 짙어지고 결절화될 수 있습니다. 스터지-웨버 증후군과 같은 전신 질환과 동반될 수 있으므로 피부과 전문의의 진찰과 함께 레이저 치료를 상담하시기 바랍니다.', 4187, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '객혈', '객혈', 'DEFINITION', '객혈은 기도나 폐에서 기원한 혈액이 기침을 통해 배출되는 증상으로, 폐결핵, 기관지확장증, 폐암, 폐렴 등이 주요 원인입니다. 소량의 혈담에서 다량의 출혈까지 다양하며, 대량 객혈은 기도 폐색으로 생명을 위협할 수 있는 응급 상황입니다. 원인 감별과 적절한 치료를 위해 호흡기내과 또는 흉부외과 전문의의 즉각적인 진찰이 필요합니다.', 4188, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '규폐증', '규폐증', 'DEFINITION', '규폐증은 이산화규소(실리카) 분진을 장기간 흡입하여 폐에 섬유화가 진행되는 직업성 폐질환입니다. 광산, 채석, 건축 등의 직업군에서 호발하며, 만성 기침, 점진적 호흡 곤란, 흉통 등의 증상이 수년에 걸쳐 발생합니다. 폐결핵 합병 위험이 높고 폐암 발생 위험도 증가하므로 분진 노출 차단과 호흡기내과 전문의의 정기 검진이 중요합니다.', 4189, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '기관 협착', '기관협착', 'DEFINITION', '기관 협착은 기관(trachea)의 내강이 좁아져 기류 장애가 발생하는 상태로, 기관 삽관 후 반흔 형성, 종양, 외상, 자가면역 질환 등이 원인입니다. 호흡 곤란, 천명(쌕쌕거리는 호흡음), 기침, 운동 내성 감소 등의 증상이 나타나며, 심한 경우 호흡 부전을 초래할 수 있습니다. 기관지경 확장술, 스텐트 삽입, 수술적 절제 등의 치료가 필요하므로 흉부외과 또는 호흡기내과 전문의와 상담하시기 바랍니다.', 4190, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '기관지확장증', '기관지확장증', 'DEFINITION', '기관지확장증은 기관지 벽이 반복된 감염이나 염증으로 손상되어 기관지가 비가역적으로 늘어나고 변형된 만성 폐 질환입니다. 만성 기침, 다량의 화농성 객담, 반복적인 폐 감염, 혈담 등이 특징적인 증상이며, 낭성 섬유증, 결핵 후유증, 면역 결핍 등이 원인이 됩니다. 기도 분비물 배출 관리, 항생제 치료, 폐재활이 중요하므로 호흡기내과 전문의와 장기적인 관리 계획을 세우시기 바랍니다.', 4191, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '낭종성 폐질환', '낭종성폐질환', 'DEFINITION', '낭종성 폐질환은 폐 내에 얇은 벽을 가진 공기 또는 액체로 찬 공간(낭종)이 형성되는 질환군으로, 폐 림프관평활근종증(LAM), 폐 랑게르한스 세포 조직구증 등이 포함됩니다. 호흡 곤란, 자연 기흉, 만성 기침 등의 증상이 나타날 수 있으며, 영상 검사로 특징적인 낭종 패턴이 관찰됩니다. 정확한 아형 진단과 치료를 위해 호흡기내과 전문의와 상담하시기 바랍니다.', 4192, NOW(), NOW());
INSERT INTO faq (disease_category, disease_name, disease_name_norm, intent, answer, source_faq_id, created_at, updated_at) VALUES ('호흡기질환', '폐색전증', '폐색전증', 'PREVENTION', '폐색전증은 심부정맥혈전증(DVT) 등에서 유래한 혈전이 폐동맥을 막아 발생하는 질환으로, 장기간 부동, 수술 후, 악성 종양, 경구 피임약 복용 등이 위험인자입니다. 예방을 위해 장시간 이동 시 규칙적인 다리 운동, 충분한 수분 섭취, 압박 스타킹 착용이 권장되며, 수술 후 환자에게는 헤파린 등의 항응고제 예방 투여가 사용됩니다. 위험인자가 있는 경우 내과 또는 순환기내과 전문의와 예방 전략에 대해 상담하시기 바랍니다.', 4193, NOW(), NOW());

